window.I18N=window.I18N||{}; window.I18N.q=window.I18N.q||{};
window.I18N.q.ar={"special":{"0":{"q":"أنا أنقل حمولة من الآلات المعبأة في صناديق على شاحنة مسطحة في تكساس، وأقوم بفحص أبعادي قبل مغادرة الساحة حتى لا أحتاج إلى تصريح للحمولة الزائدة الحجم. بدون تصريح خاص، ما هو أقصى عرض يمكن أن تكون عليه مركبتي مع حمولتها بشكل قانوني؟","options":["102 بوصة، شاملاً الحمولة، قبل أن يصبح التصريح مطلوباً","96 بوصة، شاملاً الحمولة، قبل أن يصبح التصريح مطلوباً","108 بوصة، شاملاً الحمولة، قبل أن يصبح التصريح مطلوباً","120 بوصة، شاملاً الحمولة، قبل أن يصبح التصريح مطلوباً"],"explanation":"لا يجوز أن يتجاوز عرض المركبة التجارية، بما في ذلك حمولتها، 102 بوصة (8 أقدام و6 بوصات) بدون تصريح خاص."},"1":{"q":"أنا أنقل مقطورة تبريد طويلة عبر تكساس ويذكّرني المرسل بأنني بحاجة إلى المرور تحت كل جسر علوي على الطريق بدون تصريح خاص للحمولة الزائدة الحجم. وأنا أخطط لرحلتي، ما هو الحد الأقصى للارتفاع الإجمالي لمركبتي وحمولتي المسموح لي به قانونياً؟","options":["13 قدماً و6 بوصات","14 قدماً","13 قدماً","15 قدماً"],"explanation":"الحد الأقصى القانوني لارتفاع المركبة وحمولتها بدون تصريح خاص هو 14 قدماً، ويجب على السائق المرور تحت كل جسر ومعبر علوي على الطريق."},"2":{"q":"أنا أُحمّل شاحنتي القاطرة والمقطورة عند رصيف التحميل ويسألني الشاحن عن مقدار البضائع الإضافية التي يمكنني أخذها قانونياً. شاحنتي ومقطورتي تزنان بالفعل 62,000 رطل على الميزان، وليس لديّ تصريح للوزن الزائد. بدون تصريح، ما هو أقصى وزن إجمالي مسموح به لمركبتي المحمّلة بالكامل (المركبة مع الحمولة) على طرق تكساس السريعة؟","options":["76,000 رطل","34,000 رطل","80,000 رطل","90,000 رطل"],"explanation":"الحد الأقصى القانوني للوزن الإجمالي للمركبة مع حمولتها بدون تصريح خاص للوزن الزائد هو 80,000 رطل."},"3":{"q":"أنا أقود مركبتي التجارية الآلية على طريق سريع ريفي ذي حارتين عندما أقترب من خلف جرّار يعرض مثلثاً عاكساً برتقالي اللون (شعار المركبة بطيئة الحركة) في مؤخرته. عند رؤية هذا الشعار، ما هي السرعة القصوى التي ينبغي أن أفترض أن هذه المركبة قد صُممت للسير بها، حتى أتمكن من التخطيط لاقتراب وتجاوز آمنين؟","options":["20 ميلاً في الساعة أو أقل","45 ميلاً في الساعة أو أقل","35 ميلاً في الساعة أو أقل","25 ميلاً في الساعة أو أقل"],"explanation":"شعار المركبة بطيئة الحركة البرتقالي مطلوب على المركبات المصممة للسير بسرعة 25 ميلاً في الساعة أو أقل لتحذير حركة المرور الأسرع القادمة من الخلف."},"4":{"q":"أنا أقوم بفحص ما قبل الرحلة على شاحنة صندوقية عريضة وأتحقق من أن مصابيح الخلوص والعلامات بالألوان الصحيحة قبل رحلة ليلية. بالنظر إلى مصباحَي الخلوص المثبتين في الأعلى عند الزوايا الأمامية للشاحنة، أي لون يجب أن يظهرا ليكونا قانونيين؟","options":["كهرماني، لأن مصابيح الخلوص الأمامية يجب أن تظهر باللون الكهرماني إلى الأمام","أحمر، نفس اللون الذي يتطلبه القانون لمصابيح الخلوص في الخلف","أبيض، ليتطابق مع المصابيح الأمامية ويبقى ساطعاً لحركة المرور القادمة","أخضر، لأن الأخضر يشير إلى الحافة الأمامية للمركبة المتحركة"],"explanation":"يجب أن تظهر مصابيح الخلوص والعلامات المواجهة لمقدمة المركبة باللون الكهرماني."},"5":{"q":"إنه وقت ما بعد الغسق وأنا أمشي حول مؤخرة شاحنتي الصندوقية ذات العرض الزائد قبل الانطلاق. أحتاج إلى التأكد من أن مصابيح الخلوص المثبتة في الأعلى عند مؤخرة المقطورة باللون المطلوب قانونياً. أي لون يجب أن تظهر مصابيح الخلوص الخلفية هذه؟","options":["كهرماني، نفس اللون المستخدم لمصابيح الخلوص المثبتة في الأمام","أحمر، ليتطابق مع مصابيح الخلوص والعاكسات الخلفية في مؤخرة المركبة","أبيض، حتى تطلق أسطع ضوء وتُرى من أبعد مسافة","أزرق، اللون المخصص لأعلى مصابيح الخلوص والعلامات على الحمولة العريضة"],"explanation":"يجب أن تظهر مصابيح الخلوص والعاكسات المواجهة لمؤخرة المركبة باللون الأحمر."},"6":{"q":"أثناء فحص ما قبل الرحلة عند رصيف التحميل، أتحقق من أجهزة الإضاءة في مؤخرة مقطورتي. ألاحظ أن العاكسَين المثبتين في الخلف مخدوشان وباهتان، لذا أحتاج إلى استبدالهما باللون الصحيح للبقاء قانونياً وفقاً لقواعد الإضاءة في تكساس. أي لون يجب أن يكون عليه هذان العاكسان الخلفيان؟","options":["كهرماني، نفس اللون المستخدم للعاكسات على جانبي المقطورة","أبيض، ليتطابق مع مصابيح الخلوص المثبتة عبر الحافة الخلفية العلوية","أحمر، نفس اللون المطلوب لمصابيح الخلوص الخلفية والمصابيح الخلفية","أخضر، للإشارة بوضوح إلى أن مؤخرة الوحدة آمنة للسير خلفها"],"explanation":"يجب أن تكون جميع العاكسات والمصابيح المطلوبة المواجهة لمؤخرة المركبة باللون الأحمر."},"7":{"q":"أثناء فحص ما قبل الرحلة عند الغسق، أُشغّل أضوائي وأمشي إلى مؤخرة مقطورتي للتأكد من أن المصابيح الخلفية تعمل وقانونية. تشترط تكساس أن تعرض المصابيح المثبتة في المؤخرة والمتجهة إلى الخلف لوناً محدداً. وأنا أنظر إليها من الخلف، أي لون يجب أن تُظهره مصابيحي الخلفية إلى الخلف؟","options":["كهرماني، حتى تقرأها حركة المرور خلفي بنفس طريقة قراءة مؤشرات إشارات الانعطاف","أبيض، حتى تبقى ساطعة ومرئية بوضوح للسائقين خلفي ليلاً","أزرق، حتى تبرز عن المصابيح الأمامية للمركبات القادمة من الأمام","أحمر، حتى يتمكن السائقون القادمون من الخلف من تمييز مؤخرة مركبتي"],"explanation":"يجب أن تُظهر المصابيح الخلفية اللون الأحمر إلى الخلف حتى يتمكن السائقون المتبعون من تمييز مؤخرة المركبة وتقدير المسافة ليلاً."},"8":{"q":"أثناء فحص ما قبل الرحلة عند الفجر، ألاحظ أن أحد مصابيحي الأمامية قد استُبدل بمصباح من غير الشركة المصنّعة يتوهج بلون أزرق خافت، بينما يُظهر الآخر لونه الطبيعي. لاجتياز الفحص والبقاء قانونياً على طرق تكساس، أي لون يجب أن يكون الضوء المنبعث إلى الأمام من مصابيحي الأمامية؟","options":["أبيض","كهرماني","أصفر انتقائي","أزرق بارد"],"explanation":"يجب أن تُطلق المصابيح الأمامية على المركبة التجارية ضوءاً أبيض إلى الأمام؛ ولا يُسمح بالكهرماني أو الأصفر أو الأزرق."},"9":{"q":"أنا أنقل عوارض فولاذية تبرز كثيراً خلف مؤخرة شاحنتي المسطحة، لذا أحضرت راية حمراء من المقصورة لتمييز نهاية الحمولة أثناء النهار. قبل أن أثبتها، أريد التأكد من أنها تستوفي الحد الأدنى للحجم في تكساس. ما هو أصغر حجم يمكن أن تكون عليه الراية الحمراء مع استيفاء المتطلب؟","options":["9 بوصات مربعة على الأقل","12 بوصة مربعة على الأقل","18 بوصة مربعة على الأقل","6 بوصات مربعة على الأقل"],"explanation":"يجب أن تكون الراية الحمراء أو البرتقالية التي تميّز حمولة بارزة خلف المؤخرة 12 بوصة مربعة على الأقل أثناء النهار."},"10":{"q":"أنا أنقل أنابيب فولاذية على شاحنة مسطحة في تكساس، وتبرز الحمولة خلف مؤخرة مقطورتي. وأنا أقوم بفحص ما قبل الرحلة، أحاول معرفة عند أي نقطة أُلزم قانونياً بتثبيت راية حمراء أو برتقالية في مؤخرة هذا البروز. تصبح الراية إلزامية عندما تبرز الحمولة خلف المؤخرة بأكثر من:","options":["قدمين، لأن هذا هو الخلوص القياسي الذي تسمح به الجهات التنظيمية قبل الحاجة إلى أي علامة","3 أقدام، النقطة التي تصبح عندها الحمولة البارزة خطراً على الرؤية لأول مرة","4 أقدام، وبعدها تكون الراية الحمراء أو البرتقالية نهاراً (أو ضوء أحمر ليلاً) مطلوبة","6 أقدام، أقصى بروز مسموح به قبل أن تُعامل الحمولة على أنها زائدة الحجم"],"explanation":"يجب أن تُظهر الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة راية حمراء أو برتقالية نهاراً وضوءاً أحمر ليلاً."},"11":{"q":"أنا أنقل أخشاباً على شاحنة مسطحة وبعض الألواح تبرز أمام المصدّ الأمامي لجرّاري. قبل أن أنطلق، أحتاج إلى التأكد من أن الحمولة قانونية. وفقاً لقواعد تكساس، إلى أي مدى يمكن أن تمتد الحمولة أمام مقدمة مركبتي قبل أن تصبح غير قانونية؟","options":["حتى 4 أقدام أمام المقدمة قبل أن تكون غير قانونية","حتى 10 أقدام أمام المقدمة قبل أن تكون غير قانونية","حتى 6 أقدام أمام المقدمة قبل أن تكون غير قانونية","حتى 3 أقدام أمام المقدمة قبل أن تكون غير قانونية"],"explanation":"لا يجوز أن تمتد الحمولة أكثر من 3 أقدام أمام مقدمة المركبة."},"12":{"q":"تعطلت شاحنتي وسيقوم سائق آخر بسحبها باستخدام سلسلة فولاذية مربوطة بين وحدتينا. قبل أن نخرج إلى الطريق السريع، أحتاج إلى تمييز نقطة الوصل حتى تتمكن حركة المرور الأخرى من رؤية الفجوة بين المركبتين. أي لون راية يجب أن أعلّقها على تلك السلسلة؟","options":["راية بيضاء، لأن وصلة السحب بين المركبتين يجب أن تُميّز باللون الأبيض","راية حمراء، لأن أي سلسلة أو حمولة تبرز يجب أن تُميّز دائماً باللون الأحمر","راية برتقالية، لأن البرتقالي يميّز عملية سحب بطيئة الحركة أو خطرة","راية كهرمانية، لتتطابق مع اللون الكهرماني المستخدم على مصابيح الخلوص في المقطورة"],"explanation":"يجب تمييز سلسلة أو حبل أو كابل السحب بين مركبتين براية بيضاء عند نقطة الوصل حتى تتمكن حركة المرور من رؤية المسافة المفتوحة."},"13":{"q":"تعطلت شاحنتي الصغيرة على طريق سريع ريفي في تكساس، فيقوم صديق بربطها خلف شاحنته المسطحة بسلسلة لسحبها إلى الورشة. أريد ترك مسافة ارتخاء كافية حتى لا تنقطع السلسلة على الطريق الوعر، لكنه يحذرني من أن قانون تكساس يحدّ من طول وصلة السحب بين مركبتين. باستثناء العمود أو القضيب الصلب، ما هو أقصى طول قانوني يمكن أن تكون عليه الوصلة بين المركبتين؟","options":["10 أقدام، نفس المسافة التي تُبقي عندها مثلث التحذير الأول خلف مركبة متوقفة","15 قدماً، تُقاس بين المركبة الساحبة والمركبة المسحوبة","20 قدماً، طالما تم تثبيت راية لتمييز الوصلة","25 قدماً، شريطة أن تكون أضواء التحذير في المركبة المسحوبة مشغّلة"],"explanation":"عند السحب بسلسلة أو حبل أو كابل، لا يجوز أن تتجاوز الوصلة بين المركبتين 15 قدماً."},"14":{"q":"أنا أنهي فحص ما قبل الرحلة ويخبرني سائق زميل أن مقطورتي الخدمية خفيفة بما يكفي بحيث لا تحتاج قانونياً إلى مكابح خاصة بها على المحور الخلفي. فوق أي وزن إجمالي محمّل تشترط تكساس أن يكون للمقطورة نفسها مكابح؟","options":["أكثر من 10,000 رطل — نفس الوزن الذي يعرّف وحدة مسحوبة تحتاج إلى تركيبة من الفئة A","أكثر من 20,000 رطل — مطابق لحد وزن المحور الواحد المسموح به على طرق تكساس","أكثر من 4,500 رطل — أي مقطورة أثقل من ذلك يجب أن يكون لها مكابح خاصة بها","أكثر من 26,001 رطل — النقطة التي تتطلب عندها رخصة قيادة تجارية لتشغيل الوحدة"],"explanation":"يجب أن يكون للمقطورة مكابح خاصة بها بمجرد أن يتجاوز وزنها الإجمالي المحمّل 4,500 رطل."},"15":{"q":"انتقلت للتو إلى تكساس من ولاية أخرى لتولّي وظيفة قيادة محلية، ولا تزال شاحنتي تحمل لوحات ولايتي الأصلية. يخبرني زميل في العمل أنني بحاجة إلى إتمام تسجيل تكساس قبل أن أواصل العمل، لكنني أريد معرفة المدة التي تبقى فيها لوحاتي الحالية من خارج الولاية صالحة هنا حتى لا أُحرّر لي مخالفة. بدءاً من اليوم الذي أثبتُّ فيه الإقامة، ما هي المدة التي يُعترف فيها قانونياً بلوحاتي الحالية من خارج الولاية في تكساس؟","options":["20 يوماً من تاريخ إقامتي أو بدء عملي","60 يوماً من تاريخ إقامتي أو بدء عملي","10 أيام من تاريخ إقامتي أو بدء عملي","30 يوماً من تاريخ إقامتي أو بدء عملي"],"explanation":"تعترف تكساس بلوحات من خارج الولاية لمدة 30 يوماً فقط بعد إثبات الإقامة أو قبول العمل، وبعدها يجب تسجيل المركبة."},"16":{"q":"اشتريت للتو شاحنة مستعملة من تاجر في تكساس وأُرسلت من الساحة بلوحة مشترٍ مؤقتة من الورق المقوى ملصقة في النافذة الخلفية بينما يعالج التاجر لوحاتي الدائمة. قبل أن تنتهي صلاحية تلك اللوحة الورقية وأخاطر بمخالفة، ما هو الحد الأقصى لعدد الأيام التي يمكنني فيها تشغيل المركبة قانونياً بتلك اللوحة المؤقتة؟","options":["60 يوماً من تاريخ إصدار لوحة المشتري المؤقتة","30 يوماً، وبعدها يجب تجديد اللوحة المؤقتة مرة واحدة","45 يوماً، نفس المهلة المسموح بها لتمليك المركبة وتسجيلها","20 يوماً، مطابقة لمهلة سماح ثابتة لمركبة مشتراة حديثاً"],"explanation":"لوحة المشتري المؤقتة من تاجر تكساس صالحة لمدة 60 يوماً من تاريخ إصدارها ولا يمكن تجديدها."},"17":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ أن واقيات الطين خلف محاور القيادة تبدو وكأنها تضررت وأصبحت الآن معلّقة أعلى عن الأرض مما ينبغي. للبقاء قانونياً، يجب أن تصل الحافة السفلية لكل واقي طين إلى مسافة كم من سطح الطريق؟","options":["في حدود 4 بوصات من الطريق","في حدود 8 بوصات من الطريق","في حدود 6 بوصات من الطريق","في حدود 12 بوصة من الطريق"],"explanation":"يجب أن تمتد واقيات الطين إلى مسافة 8 بوصات من سطح الطريق لمنع الماء والطين والحطام المتطاير من الإطارات."},"18":{"q":"أنا أقود شاحنتي القاطرة والمقطورة على طريق سريع ذي حارتين في ظروف نهارية صافية وأقترب من خلف دراجة نارية تسير أبطأ مني. الحارة عريضة وحركة المرور خفيفة. لتجاوز الدراجة النارية بأمان وقانونياً، ماذا ينبغي أن أفعل؟","options":["أبقى في حارتي لكن أنزاح قليلاً لأعطي الراكب مسافة لا تقل عن 3 أقدام أثناء مروري","أمر بجانبها داخل حارتي مع الحفاظ على فجوة 6 أقدام، لأن تغيير الحارة من أجل دراجة نارية غير ضروري","أعامل الدراجة النارية مثل أي مركبة أخرى، وأترك مسافة لا تقل عن 6 أقدام، وأغيّر الحارة بالكامل لتجاوزها","أمر بجانبها عن قرب في حارتي لكن لا أقترب أبداً من الراكب لمسافة أقل من 12 قدماً في أي وقت"],"explanation":"عامل الدراجة النارية مثل أي مركبة أخرى، واترك مسافة خلوص لا تقل عن 6 أقدام، وغيّر الحارة بالكامل لتجاوزها."},"19":{"q":"أنا أستلم شاحنة صندوقية مستقيمة لرحلة توصيل في تكساس. إنها مركبة واحدة (وليست جرّار شاحنة يسحب مقطورة)، ويحذرني المرسل أنها إذا كانت طويلة جداً، فسأحتاج إلى تصريح خاص للحمولة الزائدة الحجم قبل أن أتمكن من تحريكها قانونياً. بدون أي تصريح خاص، ما هو أقصى طول إجمالي مسموح به لهذه المركبة الواحدة؟","options":["53 قدماً، لأن هذا هو الطول الأقصى القياسي المستخدم للمركبات على طرق تكساس السريعة","40 قدماً، لأن المركبة الواحدة تخضع لحد أقصر من المقطورة","65 قدماً، لأن هذا هو الحد الأقصى الذي ينطبق على الطول الإجمالي للوحدة","45 قدماً، لأن المركبة الواحدة (وليست جرّار الشاحنة) لا يجوز أن تتجاوز ذلك الطول"],"explanation":"لا يجوز أن تتجاوز المركبة الواحدة التي ليست جرّار شاحنة 45 قدماً في الطول بدون تصريح خاص."},"20":{"q":"أنا أخطط لرحلة طويلة بجرّار شاحنتي وأريد تعظيم ما يمكنني سحبه، لذا أفكر في إضافة مقطورات إضافية خلفه. بدون تصريح خاص للحمولة الزائدة الحجم، ما هو أكبر عدد إجمالي من المركبات المسموح لي قانونياً بتشغيله في تركيبة واحدة على طريق سريع في تكساس؟","options":["3 مركبات إجمالاً — على سبيل المثال، جرّار الشاحنة بالإضافة إلى مقطورتين","4 مركبات إجمالاً — جرّار الشاحنة بالإضافة إلى ثلاث مقطورات","مركبتان إجمالاً — جرّار الشاحنة بالإضافة إلى مقطورة واحدة فقط","5 مركبات إجمالاً — جرّار الشاحنة بالإضافة إلى أربع مقطورات"],"explanation":"تقتصر التركيبة الواحدة على ما لا يزيد عن 3 مركبات بدون تصريح خاص، بما في ذلك وحدة القدرة — على سبيل المثال جرّار شاحنة بالإضافة إلى مقطورتين."},"21":{"q":"أثناء فحص ما قبل الرحلة، أتحقق من الإضاءة الخلفية لمقطورتي للتأكد من أنها تستوفي متطلبات الرؤية في تكساس. يسألني رئيس عمال الورشة من أي مسافة للخلف يجب أن تكون المصابيح الخلفية مرئية بوضوح ليلاً. ما هي المسافة الدنيا التي ينبغي أن أخبره بها؟","options":["يجب أن تكون مرئية بوضوح من مسافة 500 قدم على الأقل إلى الخلف","يجب أن تكون مرئية بوضوح من مسافة 1,000 قدم على الأقل إلى الخلف","يجب أن تكون مرئية بوضوح من مسافة 750 قدماً على الأقل إلى الخلف","يجب أن تكون مرئية بوضوح من مسافة 300 قدم على الأقل إلى الخلف"],"explanation":"يجب أن تُظهر المصابيح الخلفية ضوءاً أحمر مرئياً بوضوح من مسافة 1,000 قدم على الأقل إلى الخلف ليلاً."},"22":{"q":"أثناء فحص ما قبل الرحلة، يطلب مني ضابط في محطة وزن في تكساس تأكيد معيار الرؤية النهاري لمصابيح التوقف لديّ. يضغط على دواسة المكابح ويسأل: في ضوء النهار العادي، يجب أن تكون مصابيح المكابح (التوقف) مرئية من أي مسافة على الأقل خلف المركبة؟","options":["100 قدم على الأقل، نفس المسافة التي أستخدمها لمثلث التحذير الأوسط على طريق ذي حارتين","200 قدم على الأقل، مطابقة لأبعد مثلث أضعه باتجاه حركة المرور على طريق سريع مقسّم","300 قدم على الأقل خلف المركبة في ظروف النهار العادية","1,000 قدم على الأقل، نفس المسافة التي تتطلب مني تشغيل مصابيحي الأمامية"],"explanation":"يجب أن تكون مصابيح التوقف (المكابح) مرئية من مسافة 300 قدم على الأقل في ضوء النهار العادي."},"23":{"q":"أنا أنقل حمولة من العوارض الفولاذية التي تبرز حوالي 6 أقدام خلف مؤخرة مقطورتي. لقد ميّزت البروز سابقاً براية حمراء، لكن الشمس قد غربت الآن وأصبح الظلام يحلّ على الطريق السريع. أي مما يلي يجب أن أفعله لإبقاء الحمولة البارزة مميّزة قانونياً؟","options":["لا حاجة لأي شيء إضافي؛ الراية الحمراء التي ثبّتُّها بالفعل تبقى قانونية على مدار الساعة","إضافة ضوء كهرماني إلى نهاية البروز حتى يتمكن السائقون الآخرون من رؤية البروز","التحويل إلى راية بيضاء، التي تظهر بشكل أفضل من الحمراء على خلفية السماء المظلمة ليلاً","استبدال الراية بضوء أحمر في نهاية الحمولة، مرئي من مسافة 500 قدم على الأقل"],"explanation":"تُميّز الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة براية نهاراً، لكن ليلاً يجب استبدال الراية بضوء أحمر مرئي من مسافة 500 قدم على الأقل."},"24":{"q":"أنا أقوم بفحص ما قبل الرحلة على شاحنتي المسطحة وأتحقق من العاكسات الخلفية الحمراء لتكون على ارتفاع تركيب قانوني فوق سطح الطريق. أي من الارتفاعات التالية سيكون مقبولاً للعاكسات الخلفية؟","options":["عاكس مثبت على ارتفاع 40 بوصة فوق سطح الطريق","عاكس مثبت على ارتفاع 18 بوصة فوق سطح الطريق","عاكس مثبت على ارتفاع 66 بوصة فوق سطح الطريق","عاكس مثبت على ارتفاع 12 بوصة فوق سطح الطريق"],"explanation":"يجب تثبيت العاكسات الخلفية على ارتفاع يتراوح بين 24 و60 بوصة فوق سطح الطريق، لذا فإن ارتفاع 40 بوصة يقع ضمن النطاق القانوني."},"25":{"q":"أثناء فحص ما قبل الرحلة، لاحظت أن أحد المصابيح الأمامية يبدو وكأنه أُعيد تركيبه منخفضًا أكثر من اللازم بعد إصلاح حديث. للتأكد من استيفائه لمتطلبات التركيب الفيدرالية، ضمن أي نطاق ارتفاع فوق سطح الطريق يجب أن تقع مراكز مصابيحي الأمامية؟","options":["بين 12 و48 بوصة","بين 24 و54 بوصة","بين 24 و60 بوصة","بين 20 و50 بوصة"],"explanation":"يجب تركيب مراكز المصابيح الأمامية على ارتفاع لا يقل عن 24 بوصة ولا يزيد عن 54 بوصة فوق سطح الطريق."},"26":{"q":"أقود مقطورة محمَّلة على طريق سريع ريفي ذي مسارين خارج أي مدينة، وأسير بسرعة الطريق السريع خلف شاحنة جرّار-مقطورة أخرى. للالتزام بالقانون في تكساس، ما الحد الأدنى من المسافة التي يجب أن أتركها بين مركبتي والشاحنة التي أمامي؟","options":["100 قدم، وهي نفس المسافة التي أستخدمها لوضع مثلثات التحذير خلف مركبة متوقفة","200 قدم، لأن ذلك لا يزال يترك مساحة كافية لسائق آخر للتجاوز","300 قدم، مع السماح للسائقين الآخرين بالتجاوز فيما بيننا","500 قدم، لأن الأحمال الثقيلة بسرعة الطريق السريع تحتاج إلى أطول مسافة أمان"],"explanation":"خارج المدينة، لا يجوز لشاحنة أن تتبع شاحنة أخرى على مسافة أقل من 300 قدم، بحيث يبقى فراغ يُسمح للسائقين الآخرين بالتجاوز من خلاله."},"27":{"q":"أقود مركبتي على طريق سريع ذي مسارين مظلم ليلًا والأضواء العالية مشغّلة. ألمح سيارة قادمة نحوي في المسار المقابل. على أي مسافة من تلك المركبة القادمة يُطلب مني خفض الأضواء العالية إلى الأضواء المنخفضة؟","options":["ضمن مسافة 200 قدم من المركبة القادمة","ضمن مسافة 300 قدم من المركبة القادمة","ضمن مسافة 1000 قدم من المركبة القادمة","ضمن مسافة 500 قدم من المركبة القادمة"],"explanation":"يجب خفض الأضواء العالية إلى الأضواء المنخفضة عندما تكون المركبة القادمة ضمن مسافة 500 قدم لتفادي إبهار السائق المقترب."},"28":{"q":"أسحب مقطورة محمَّلة خلف شاحنتي، ويتجاوز وزن المجموعة بالكامل عند الميزان 3000 رطل بكثير. أثناء فحص ما قبل الرحلة، أريد التأكد من أن فرامل الخدمة لديّ تستوفي معيار مسافة التوقف في تكساس. عند السير بسرعة 20 ميلًا في الساعة على رصيف جاف ومستوٍ، ما الحد الأقصى للمسافة التي يجب أن توقف خلالها فراملي هذه المجموعة توقفًا تامًا؟","options":["50 قدمًا، لأن المجموعة التي يتجاوز وزنها 3000 رطل يجب أن تتوقف ضمن تلك المسافة من سرعة 20 ميلًا في الساعة","40 قدمًا، لأن ذلك هو معيار التوقف المطبَّق عند سرعة 20 ميلًا في الساعة","60 قدمًا، لأن المجموعات الأثقل يُسمح لها بمسافة توقف أطول","30 قدمًا، لأن فرامل المجموعة المحمَّلة يجب أن تؤدي بشكل أكثر حدّة"],"explanation":"يجب أن تكون المجموعة التي يتجاوز وزنها 3000 رطل قادرة على التوقف ضمن مسافة 50 قدمًا من سرعة 20 ميلًا في الساعة."},"29":{"q":"أقوم بجولة فحص ما قبل الرحلة حول شاحنتي الجرّار قبل الانطلاق عند الغسق، وألاحظ أن سائقًا سابقًا أضاف بعض المصابيح الإضافية. للالتزام بقواعد الإضاءة، أي مصباح يجب ألّا يظهر باتجاه مقدمة مركبتي؟","options":["مصباح أبيض، لأن اللون الأبيض قد يُبهر السائقين القادمين ولا يكون قانونيًا إلا متجهًا للخلف","مصباح أحمر، لأن اللون الأحمر مخصص للخلف ويجب ألّا يظهر باتجاه المقدمة","مصباح كهرماني، لأن اللون الكهرماني مسموح به على الجوانب فقط وليس أبدًا في المقدمة","لا يهم أي منها، لأنه يجوز لأي لون أن يتجه نحو المقدمة طالما أنه لا يومض"],"explanation":"لا يجوز أن يظهر الضوء الأحمر باتجاه المقدمة لأن اللون الأحمر مخصص لتمييز مؤخرة المركبة؛ ولا يُسمح إلا بالأبيض والكهرماني متجهين للأمام."},"30":{"q":"أنقل حمولة سائل قابل للاشتعال تحمل لوحات تحذير، وأقترب من مزلقان سكة حديد بلا بوابات ولا أضواء إشارة. أي مما يلي يصف كل ما يُطلب مني فعله لعبور هذا المزلقان بشكل قانوني وآمن؟","options":["أُبطئ حتى أكاد أتوقف، وأُخفّض الترس إلى ترس منخفض أثناء مروري فوق القضبان لأحافظ على الزخم، ثم أتابع السير عندما لا أرى قطارًا","أتوقف فقط إذا كان هناك قطار مرئي أو مسموع فعلًا، وإلا أعامل المزلقان المفتوح كأي تقاطع آخر وأمرّ عبره","أتوقف توقفًا تامًا قبل القضبان، وأنظر وأُصغي للتأكد من خلو الطريق، ثم أعبر دون تغيير التروس","أتوقف عند القضبان، لكن أنتظر مرور أي مركبة خلفي أولًا لأنها غير مُلزَمة بالتوقف عند مزلقان مفتوح"],"explanation":"يجب على مركبات المواد الخطرة التي تحمل لوحات تحذير أن تتوقف على مسافة من 15 إلى 50 قدمًا قبل القضبان، وتنظر وتُصغي، ثم تعبر دون تغيير التروس حتى لا يتوقف المحرك في منتصف المزلقان."},"31":{"q":"أُحمّل مركبتي في مركز توزيع بتكساس، ويسلّمني الشاحن بيان شحن يُظهر أن الشاحنة والحمولة معًا ستزن عند الميزان 92000 رطل. ليس لديّ تصريح للحجم الزائد أو الوزن الزائد. قبل أن أتجه نحو محطة وزن الطريق السريع، أي عبارة عن حدود الحجم والوزن في تكساس يجب أن أعتمد عليها؟","options":["أنا بخير دون تصريح، لأن تكساس تسمح بوزن إجمالي يصل إلى 100000 رطل للمركبة المحمَّلة والحمولة معًا.","أنا بخير دون تصريح، لأنه طالما لم يتجاوز أي محور واحد 20000 رطل، فإن الوزن الإجمالي غير مقيّد.","أنا بخير دون تصريح، لأن 92000 رطل أقل من بدل وزن الـ14 قدمًا الذي تمنحه تكساس على الطرق القياسية.","أنا أتجاوز الوزن دون تصريح، لأن تكساس تحدّ الوزن الإجمالي للمركبة عند 80000 رطل ما لم أحصل على تصريح خاص."],"explanation":"تحدّ تكساس الوزن الإجمالي للمركبة عند 80000 رطل دون تصريح خاص، لذا فإن أي وزن يتجاوز ذلك يتطلب تصريح وزن زائد قبل القيادة."},"32":{"q":"إنه عصر يوم صافٍ وأقوم بجولة فحص حول شاحنتي الجرّار-المقطورة، وأتحقق من أن مصابيحي مرئية من المسافات المطلوبة قانونًا. أي عبارة تصف بشكل صحيح المسافة التي يجب أن يكون كل مصباح مرئيًا منها في ضوء النهار العادي؟","options":["يجب أن تكون مصابيح المؤخرة مرئية من 1000 قدم، ومصابيح التوقف من 300 قدم.","يجب أن تكون مصابيح المؤخرة مرئية من 300 قدم، ومصابيح التوقف من 1000 قدم.","يجب أن تكون مصابيح المؤخرة مرئية من 500 قدم، ومصابيح التوقف من 1000 قدم.","يجب أن تكون مصابيح المؤخرة مرئية من 1000 قدم، ومصابيح التوقف من 500 قدم."],"explanation":"يجب أن تكون مصابيح المؤخرة مرئية من 1000 قدم لتمييز المؤخرة من بعيد، بينما يجب أن تكون مصابيح التوقف مرئية من 300 قدم لتحذير حركة المرور القريبة من الكبح."},"33":{"q":"أثناء فحص ما قبل الرحلة، يطلب مني فاحص من إدارة السلامة العامة التأكيد على ارتفاعات التركيب القانونية لأجهزة الإضاءة في مقطورتي. أعلم أن المصابيح الأمامية والعاكسات الخلفية غير مطلوب أن تكون ضمن نفس نطاق الارتفاع. أي عبارة تذكر النطاقين بشكل صحيح؟","options":["تُركَّب المصابيح الأمامية بين 24 و60 بوصة، بينما تُركَّب العاكسات الخلفية بين 24 و54 بوصة فوق الأرض.","تُركَّب المصابيح الأمامية بين 24 و54 بوصة، بينما تُركَّب العاكسات الخلفية بين 24 و60 بوصة فوق الأرض.","تُركَّب كل من المصابيح الأمامية والعاكسات الخلفية ضمن نفس النطاق من 24 إلى 54 بوصة فوق الأرض.","تُركَّب كل من المصابيح الأمامية والعاكسات الخلفية ضمن نفس النطاق من 24 إلى 60 بوصة فوق الأرض."],"explanation":"يجب تركيب المصابيح الأمامية على ارتفاع من 24 إلى 54 بوصة فوق الأرض، بينما يُسمح للعاكسات الخلفية بنطاق أعلى من 24 إلى 60 بوصة."},"34":{"q":"تعطّلت مقطورتي المحمَّلة على طريق ريفي ذي مسارين في تكساس وعليّ سحبها الأميال الأخيرة إلى ورشة باستخدام سلسلة. يخبرني سائق قريب أن المركبة على ما يرام طالما أبقيت السلسلة قصيرة. قبل أن أنطلق على الطريق، أي مجموعة من المتطلبات يجب أن أستوفيها فعلًا للسحب بالسلسلة؟","options":["سلاسل أمان فقط كاحتياط، لأن السلسلة الرئيسية هي الجزء الوحيد الذي يربط ويسحب المركبة المعطَّلة فعلًا","فقط راية بيضاء على نقطة الوصل ووصلة لا يزيد طولها عن 15 قدمًا، لأن الراية تنبّه حركة المرور والوصلة القصيرة تُبقي الوحدة المسحوبة تحت السيطرة","راية بيضاء على نقطة الوصل، ووصلة لا يزيد طولها عن 15 قدمًا، وسلاسل أمان كاحتياط","فقط وصلة لا يزيد طولها عن 15 قدمًا، لأن إبقاء المركبة المسحوبة قريبة هو القاعدة الوحيدة التي تحكم السحب بالسلسلة فعلًا"],"explanation":"يتطلب سحب مركبة معطَّلة بالسلسلة استيفاء جميع الضمانات الثلاثة: راية بيضاء على نقطة الوصل، ووصلة لا يزيد طولها عن 15 قدمًا، وسلاسل أمان احتياطية."},"35":{"q":"أنقل حمولة من الحصى السائب عبر تكساس في شاحنتي القلّابة، وأريد التأكد من أنني لا أخالف أيًا من قواعد التشغيل على طول الطريق. أي من الإجراءات التالية سيكون قانونيًا أن أقوم به أثناء هذه الرحلة؟","options":["توفير الوقود بنقل الترس إلى الوضع المحايد والانزلاق نزولًا على المنحدرات الطويلة","القيادة حول بوابات المزلقان المنخفضة لأنني أرى أن القطار لا يزال بعيدًا","تركيب مصباح أحمر يتجه إلى الأمام لجعل شاحنتي أكثر وضوحًا لحركة المرور القادمة","تثبيت غطاء قماشي فوق الحصى حتى لا تتطاير المواد السائبة على الطريق"],"explanation":"يجب تغطية الأحمال السائبة مثل الحصى أو تثبيتها بحيث لا يمكن للمواد أن تنسكب أو تتطاير على الطريق، ما يجعل الغطاء القماشي إلزاميًا."},"36":{"q":"في تكساس، يجب أن تحتفظ بتصريح المتعلم التجاري لمدة لا تقل عن كم قبل اختبار المهارات؟","options":["يوم واحد","14 يومًا","6 أشهر","لا انتظار على الإطلاق"],"explanation":"يجب الاحتفاظ بتصريح المتعلم التجاري لمدة 14 يومًا على الأقل قبل اختبار المهارات."},"37":{"q":"عمري 19 عامًا، وأحمل رخصة قيادة تجارية صالحة من تكساس، وأنقل البضائع بين هيوستن ودالاس منذ عام دون أي مشاكل. تريد شركتي الآن أن أسلك مسارًا منتظمًا لتوصيل الأحمال من تكساس إلى أوكلاهوما. أي عبارة تصف بشكل صحيح ما إذا كان بإمكاني سلوك هذا المسار الجديد بين الولايات؟","options":["لا يمكنني سلوك مسار أوكلاهوما بعد، لأن عبور حدود الولايات يتطلب أن يكون عمر السائق 21 عامًا على الأقل.","يمكنني سلوك مسار أوكلاهوما الآن، لأن رخصتي التجارية الصالحة من تكساس تخوّلني بالفعل القيادة بين الولايات في أي عمر.","يمكنني سلوك مسار أوكلاهوما الآن، لأن عمري يتجاوز 18 عامًا، وهو الحد الأدنى لعمر القيادة لجميع المركبات التجارية.","لا يمكنني سلوك مسار أوكلاهوما حتى أبلغ 25 عامًا، وهو الحد الأدنى للعمر الذي تحدده القواعد الفيدرالية لنقل البضائع بين الولايات."],"explanation":"يُسمح بقيادة المركبات التجارية داخل الولاية عند سن 18، لكن القيادة بين الولايات عبر حدودها تتطلب أن يكون عمر السائق 21 عامًا على الأقل."},"38":{"q":"أنت تقود مركبتك التجارية بحد السرعة 70 ميلًا في الساعة على طريق سريع بين الولايات في تكساس عندما ترى مركبة متوقفة على الكتف الأيمن أمامك وأضواؤها الوامضة مشغّلة. بموجب قانون 'انتقل/أبطئ' في تكساس، في أي حالة يُطلب منك قانونًا إما تغيير المسار بعيدًا عنها أو الإبطاء؟","options":["سيارة ركاب متوقفة على الكتف وأضواء الخطر فيها تومض","شاحنة صيانة تابعة لإدارة النقل في تكساس متوقفة وأضواؤها التحذيرية الكهرمانية تومض","شاحنة توصيل متوقفة على الجانب وأضواؤها الرباعية مشغّلة","شاحنة جرّار-مقطورة معطَّلة وُضعت خلفها ثلاثة مثلثات تحذير"],"explanation":"يشمل قانون انتقل/أبطئ في تكساس المركبات المتوقفة التابعة لإدارة النقل والطوارئ والشرطة وسحب المركبات التي تعرض أضواء وامضة، بما في ذلك شاحنة إدارة النقل ذات الأضواء الكهرمانية."},"39":{"q":"ينفجر إطار فأسحب شاحنتي الجرّار-المقطورة المحمَّلة إلى الكتف الأيمن لطريق سريع ريفي. أشغّل أضوائي الرباعية على الفور، ثم أبدأ بإخراج مثلثات التحذير من الصندوق الجانبي. بأي وقت بعد التوقف تشترط تكساس وضع أجهزة التحذير تلك على الطريق؟","options":["خلال 30 دقيقة من التوقف، لأن الأضواء الوامضة تغطّي بالفعل النصف ساعة الأول","فقط إذا توقعت أن أبقى متوقفًا أكثر من ساعة واحدة؛ التوقف القصير لا يحتاج إلى أجهزة","خلال 10 دقائق من التوقف، بغض النظر عن المدة التي أتوقع البقاء فيها","خلال 5 دقائق، وهي نفس الفترة المستخدمة لوضعها على مسافات 10 و100 و200 قدم"],"explanation":"يجب وضع مثلثات التحذير خلال 10 دقائق من توقف مركبة تجارية على الطريق، مهما كانت مدة التوقف المتوقعة قصيرة أو طويلة."},"40":{"q":"تتعطّل مركبتي المحمَّلة على طريق مستوٍ ذي مسارين غير مقسوم يحمل حركة المرور في الاتجاهين. أشغّل أضوائي الرباعية وأمسك مثلثاتي العاكسة الثلاثة. أين ينبغي أن أضعها حتى أكون قانونيًا ومرئيًا لكل من يقترب؟","options":["10 أقدام و100 قدم و200 قدم — جميعها موزّعة خلف الشاحنة باتجاه حركة المرور القادمة نحوي","واحد على بُعد 10 أقدام والاثنان الآخران كلاهما على بُعد 100 قدم خلفي، لأن الخطر هو ما يلحق بي من الخلف","10 أقدام و100 قدم و200 قدم، مقيسة باتجاه حركة المرور القادمة من كل اتجاه من الطريق","واحد على بُعد نحو 10 أقدام وواحد على بُعد نحو 100 قدم خلف الشاحنة، بالإضافة إلى واحد على بُعد نحو 100 قدم أمامها"],"explanation":"على طريق ذي مسارين واتجاهين، ضع مثلثًا على بُعد نحو 10 أقدام خلف المركبة، وواحدًا على بُعد نحو 100 قدم خلفها، وواحدًا على بُعد نحو 100 قدم أمامها لحماية الاتجاهين."},"41":{"q":"أثناء فحص ما قبل الرحلة في أماريلو، يطلب مني الفاحص أن أشير إلى معدات الطوارئ التي يُلزم بحملها في مركبتي التجارية قبل أن أتمكن قانونًا من الانطلاق على الطريق. أي مجموعة من العناصر يجب أن تكون موجودة وصالحة للعمل لاستيفاء هذا المتطلب؟","options":["طفاية حريق مشحونة، وفيوزات كهربائية احتياطية (إذا كانت المركبة تستخدمها)، وثلاثة مثلثات تحذير عاكسة حمراء","رافعة هيدروليكية، ومجموعة كاملة من سلاسل الإطارات، وثلاثة مثلثات تحذير عاكسة حمراء","طفاية حريق مشحونة، وحقيبة إسعافات أولية مجهزة، وإطار احتياطي مثبَّت","طفاية حريق مشحونة، وثلاثة شعلات طريق مشتعلة، وسترة سلامة عاكسة"],"explanation":"يجب أن تحمل كل مركبة تجارية ثلاثة عناصر طوارئ: طفاية حريق مشحونة، وفيوزات كهربائية احتياطية (إذا كانت مجهزة بها)، وثلاثة مثلثات تحذير عاكسة حمراء."},"42":{"q":"أقوم بفحص ما قبل الرحلة على شاحنة جرّار-مقطورة قبل مغادرة المحطة في تكساس، ويذكّرني المرسل بالتأكد من اكتمال طقم التحذير للطوارئ في حال اضطررت للتوقف على الكتف لاحقًا. إلى جانب أضوائي الوامضة، كم عدد مثلثات التحذير العاكسة المطلوب أن أحملها على متن المركبة؟","options":["مثلثان — واحد على بُعد 10 أقدام خلف المركبة وواحد على بُعد 100 قدم خلفها","ثلاثة مثلثات عاكسة (أو أجهزة تحذير مكافئة)","ستة مثلثات، حتى يكون لديّ طقم احتياطي في حال تلف بعضها","مثلث واحد، يوضع على بُعد 100 قدم خلف المركبة باتجاه حركة المرور"],"explanation":"يجب أن تحمل كل مركبة تجارية ثلاثة مثلثات تحذير عاكسة (أو أجهزة مكافئة مثل الشعلات) بغض النظر عن نوع الطريق."},"43":{"q":"في تكساس، تُطلب المصابيح الأمامية خلال أي ساعات؟","options":["من حوالي الظهر حتى منتصف الليل","من 30 دقيقة بعد غروب الشمس إلى 30 دقيقة قبل شروقها","فقط حول منتصف الليل تمامًا","من شروق الشمس حتى غروبها"],"explanation":"استخدم المصابيح الأمامية من 30 دقيقة بعد غروب الشمس إلى 30 دقيقة قبل شروقها، وعندما تكون الرؤية منخفضة."},"44":{"q":"في تكساس، يجب أيضًا استخدام المصابيح الأمامية عندما:","options":["فقط على الطرق الترابية الريفية","تكون مساحات الزجاج الأمامي مشغّلة في المطر","لا تُستخدم أبدًا أثناء النهار","فقط أثناء وقوفها"],"explanation":"يشترط قانون تكساس استخدام المصابيح الأمامية عندما يتطلب الطقس تشغيل مساحات الزجاج الأمامي."},"45":{"q":"أقود شاحنتي الجرّار-المقطورة على طريق ذي مسارين، مسار واحد لكل اتجاه ودون فاصل وسطي أو حاجز يفصل بيننا. توقفت حافلة مدرسية على الجانب المقابل من الطريق وشغّلت أضواءها الحمراء الوامضة ومدّت ذراع التوقف. ما المطلوب مني فعله؟","options":["أتابع السير بسرعة مخفّضة، لأن الحافلة على الجانب الآخر من خط المنتصف بالنسبة لي","أتوقف فقط إذا رأيت أطفالًا يخطون فعلًا على الرصيف بالقرب من مساري","أتوقف، لأنه على طريق بلا فاصل وسطي يجب أن تتوقف حركة المرور في الاتجاهين","أُبطئ إلى 20 ميلًا في الساعة دون الحد وأتجاوز بحذر، كما أفعل مع مركبة طوارئ متوقفة"],"explanation":"على طريق بلا فاصل مادي، يجب أن تتوقف حركة المرور في الاتجاهين أمام حافلة مدرسية ذات أضواء حمراء وامضة، لأن خط المنتصف المرسوم ليس فاصلًا."},"46":{"q":"أنقل هيكلًا فولاذيًا مسبق الصنع على شاحنة مسطحة عبر تكساس. بعد التحميل، يبلغ قياس مركبتي 11 قدمًا عرضًا و13 قدمًا ارتفاعًا، وتستقر الحمولة بمحاذاة المقطورة دون أي امتداد خلفي. قبل أن أنطلق، ماذا يلزمني قانون تكساس بفعله بسبب هذه الأبعاد؟","options":["لا شيء إضافي، لأن ارتفاعي البالغ 13 قدمًا لا يزال دون الحد القانوني البالغ 14 قدمًا","فقط أُركّب راية حمراء واحدة على أعرض نقطة من الحمولة وأتابع","أُرتّب مرافقة من الشرطة، وهي إلزامية تلقائيًا في أي وقت تكون فيه الحمولة زائدة الحجم","أحصل على تصريح حجم/وزن زائد من إدارة المركبات الآلية في تكساس قبل التشغيل على الطريق السريع"],"explanation":"أي حمولة تتجاوز حد العرض القانوني البالغ 102 بوصة تُعدّ زائدة الحجم وتتطلب تصريح حجم/وزن زائد من إدارة المركبات الآلية في تكساس قبل التشغيل على الطريق السريع."},"47":{"q":"أنقل حمولة عادية في عربة جافة (دون لوحات تحذير) عندما يُوقفني رجال الشرطة وأُدان بالقيادة تحت تأثير الكحول في شاحنتي. إنها أول مخالفة كبرى لي على الإطلاق. بموجب قواعد تكساس، ما الحد الأدنى للمدة التي ستُسحب فيها رخصتي التجارية؟","options":["سنة واحدة على الأقل، لأن أول مخالفة كبرى تحمل سحبًا لمدة سنة واحدة","ثلاث سنوات على الأقل، لأن أي إدانة بالقيادة تحت تأثير الكحول في مركبة تجارية تُطلِق المدة الأطول","60 يومًا، لأن هذا يُحتسب أول مخالفة مرورية خطيرة","حظر مدى الحياة، لأن القيادة تحت تأثير الكحول تُعامَل كمخالفة كبرى دون عودة"],"explanation":"تؤدي أول مخالفة كبرى دون مواد خطرة تحمل لوحات تحذير إلى سحب الرخصة التجارية لمدة سنة واحدة كحد أدنى."},"48":{"q":"اجتزت اختبار المعرفة العامة التحريري للرخصة التجارية واختبار المهارات خلف المقود في مكتب إدارة السلامة العامة في تكساس، لكن الفاحص يخبرني أنه لا يزال يتعذّر إصدار رخصتي لأن عنصرًا واحدًا مطلوبًا فيدراليًا مفقود من ملفي. أي متطلب هو الأرجح أنه لا يزال مفقودًا لديّ؟","options":["رسالة موثّقة من صاحب عملي تؤكد أن لديّ وظيفة قيادة مضمونة","شهادة فحص طبي (بدني) صالحة من وزارة النقل صادرة عن فاحص معتمد","إثبات إتمامي لدورة قيادة دفاعية أو منع حوادث","فحص للبصر فقط يُجرى بشكل منفصل في عيادة عيون خارجية"],"explanation":"تتطلب الرخصة التجارية في تكساس أيضًا شهادة فحص طبي (بدني) صالحة من وزارة النقل صادرة عن فاحص طبي معتمد."},"49":{"q":"أقود مركبتي التجارية عبر حركة المرور في وسط المدينة وأحتاج إلى الانعطاف يمينًا عند التقاطع التالي. لإعطاء السائقين الآخرين تحذيرًا مناسبًا، متى ينبغي أن أبدأ بالإشارة إلى انعطافي؟","options":["فقط بمجرد وصولي إلى الزاوية وبدئي بالدخول في الانعطاف","بشكل متواصل لمسافة نحو 200 قدم قبل وصولي إلى الانعطاف","بشكل متواصل لمسافة نحو 100 قدم قبل وصولي إلى الانعطاف","لا حاجة للإشارة طالما أن حركة المرور تتحرك ببطء"],"explanation":"أشر إلى الانعطافات بشكل متواصل لمسافة نحو 100 قدم قبل الانعطاف حتى يكون لدى السائقين الآخرين وراكبي الدراجات والمشاة وقت للتفاعل."},"50":{"q":"تعطّل أحد محامل العجلات وتوقّفت شاحنتي المحمّلة مع المقطورة في المسار الأيمن لطريق سريع مزدحم بين الولايات عند الساعة الثانية ظهراً. حركة المرور تقترب بسرعة من الخلف، وسيستغرق الأمر عدة دقائق قبل أن أتمكن من الخروج بمثلثات التحذير. ما الذي يجب أن أفعله أولاً، قبل أي شيء آخر؟","options":["أُشغّل المصابيح الأمامية العالية لكي يرى السائقون خلفي الوهج الساطع فيُبطئون","أترك إشارة الانعطاف اليسرى وحدها وامضة لكي تعلم حركة المرور التالية أن تتجاوزني من اليسار","أُشغّل مصباح القمرة الداخلي وأخرج فوراً للتلويح للمرور كي يلتفّ حول الشاحنة","أُشغّل أضواء التحذير الرباعية (الفلاشر) فوراً لتحذير المرور المقترب بينما أُخرج مثلثاتي"],"explanation":"عند التوقف أو التعطّل على الطريق، شغّل أضواء التحذير الرباعية فوراً لتحذير المرور المقترب، ثم ضع مثلثات التحذير."},"51":{"q":"أنت تخرج من الساحة لنقلة قصيرة من ثلاثة مربعات سكنية إلى محطة الوقود، وتسير بسرعة أقل من 15 ميلاً في الساعة طوال الطريق. بموجب قانون تكساس، ما المطلوب منك ومن أي راكب في المقعد الأمامي خلال هذه النقلة؟","options":["يجب على كليكما ربط حزام الأمان طوال الوقت الذي تكون فيه المركبة متحركة","حزام الأمان اختياري دون 15 ميلاً في الساعة، لذا لا يحتاج أيٌّ منكما إلى ربطه في هذه النقلة القصيرة","السائق وحده يجب أن يربط الحزام؛ أما الراكب الأمامي عند سرعة أقل من 15 ميلاً في الساعة فمُعفى","يمكن تجاوز حزام الأمان لأن القمرة مزوّدة بوسائد هوائية للمقعدين"],"explanation":"يجب على السائق وجميع شاغلي المقاعد الأمامية ربط أحزمة الأمان كلما كانت المركبة متحركة، دون استثناء للسرعة المنخفضة أو الرحلات القصيرة."},"52":{"q":"السائق التجاري الذي يستخدم هاتفاً محمولاً باليد أثناء القيادة يكون:","options":["مسموحاً له تماماً","مخالفاً للقواعد الفيدرالية/قواعد تكساس","ملزماً بذلك قانوناً","لا بأس به داخل المدينة"],"explanation":"يُحظر على سائقي المركبات التجارية استخدام الهاتف المحمول باليد وإرسال الرسائل النصية."},"53":{"q":"تعطّلت شاحنتي مع المقطورة في المسار الأيمن لطريق سريع مقسوم بأربعة مسارات. بعد تشغيل أضواء التحذير، أبدأ بوضع مثلثات التحذير الثلاثة باتجاه حركة المرور القادمة من خلفي. أضع الأول على بُعد 10 أقدام والثاني على بُعد 100 قدم. على أي بُعد يجب أن أضع المثلث الثالث والأبعد؟","options":["نحو 100 قدم إلى الخلف، مثل الطريق ذي المسارين","نحو 200 قدم إلى الخلف باتجاه المرور المقترب","نحو 40 قدماً إلى الخلف، بعد مؤخرة المقطورة بقليل","نحو 500 قدم إلى الخلف كي تتلقى الحركة الأسرع تحذيراً"],"explanation":"على طريق باتجاه واحد أو طريق مقسوم، ضع مثلثات التحذير الثلاثة على نحو 10 و100 و200 قدم باتجاه المرور المقترب."},"54":{"q":"أوقفني شرطي من إدارة السلامة العامة في تكساس (DPS) أثناء تفتيش جانبي وقال: \"أرني ما يثبت أنك قادر على تغطية الأضرار إذا تسببت في حادث\". لديّ عدة وثائق في قمرتي. أي واحدة منها يطلبها الشرطي تحديداً لاستيفاء شرط المسؤولية المالية في تكساس؟","options":["رخصة القيادة التجارية من الفئة A السارية، لأنها تُظهر أن الولاية قد أجازتني بالفعل لتشغيل هذه الشاحنة","شهادة الفاحص الطبي (DOT) السارية، التي تثبت أنني مؤهل بدنياً لقيادة مركبة تجارية","إثبات التأمين ضد المسؤولية، وهو المستند الذي تقبله تكساس كدليل على المسؤولية المالية","إيصال تسجيل المركبة، لأنه يؤكد أن الشاحنة مُسجّلة ومرخّصة قانونياً في تكساس"],"explanation":"تتطلب تكساس إثبات المسؤولية المالية، ويُستوفى عادةً بوثيقة تأمين سارية ضد المسؤولية تُظهر قدرتك على تغطية الأضرار التي تتسبب بها."},"55":{"q":"أصيبت شاحنتي بعطل ميكانيكي واضطررت إلى التوقف والركن على طريق ريفي ذي مسارين مع كتف حصوي عريض. لجعل شاحنتي المركونة آمنة قدر الإمكان لي وللمرور المار، ماذا يجب أن أفعل؟","options":["أتوقف مع بقاء جزء من الشاحنة في مسار السير الأيمن كي يراني السائقون الآخرون مبكراً","أُبقي المحرك يعمل وأبقى في المسار بينما أنتظر وصول المساعدة","أركن في المنعطف القريب أمامي كي يكون لدى السائقين القادمين وقت أطول للتفاعل","أخرج بالكامل من مسار السير وأركن في أقصى الكتف بأمان قدر الإمكان"],"explanation":"اركن المركبة التجارية المتعطّلة أو المتوقفة بعيداً تماماً عن مسار السير وفي أقصى الكتف بأمان قدر الإمكان لإبقائها خارج مسار حركة المرور."},"56":{"q":"أنا سائق رخصة تجارية تم استدعائي لفحص ما بعد حادث، وأخبرني المشرف أن إجراء فحص كيميائي للكحول والمخدرات إلزامي. أنا غير مخمور وأشعر بالإهانة، فأرفض رفضاً قاطعاً تقديم عينة وأنصرف. أي مما يلي يصف بدقة ما يحدث لرخصتي التجارية بسبب رفضي؟","options":["رفض الفحص الإلزامي يُعامل تماماً مثل الرسوب فيه، فيُحتسب مخالفة كبرى وتُسحب رخصتي التجارية لمدة سنة واحدة.","الرفض يُطلق فقط إنذاراً مكتوباً في المرة الأولى، بما أنني لم أتجاوز فعلياً نسبة 0.04% ولم أُسجّل أي نتيجة إيجابية.","الرفض لا يحمل أي عقوبة على الرخصة التجارية طالما كنت غير مخمور حقاً ومستعداً لإعادة الفحص في وقت لاحق.","الرفض مجرد مخالفة مرورية خطيرة، فلا يحدث شيء إلا إذا ارتكبت مخالفة ثانية مماثلة خلال ثلاث سنوات."],"explanation":"بموجب الموافقة الضمنية، يُعامَل رفض الفحص الإلزامي للكحول أو المخدرات تماماً مثل الرسوب فيه — مخالفة كبرى أولى تسحب رخصتك التجارية لمدة سنة واحدة."},"57":{"q":"أثناء فحصي قبل الرحلة، أتفقّد معدات الطوارئ المطلوبة منّي قانوناً. أتأكد من وجود ثلاثة مثلثات تحذير عاكسة وطفّاية حريق ذات تصنيف مناسب. بخصوص المصاهر (الفيوزات) الكهربائية الاحتياطية، أي عبارة تصف بدقة متى لا يُطلب منّي حملها؟","options":["لا أحتاج إلى مصاهر احتياطية طالما أن شاحنتي عمرها أقل من سنة ولا تزال ضمن ضمان الوكيل","لا أحتاج إلى مصاهر احتياطية إذا كان نظام مركبتي الكهربائي محمياً بقواطع دائرة بدلاً من المصاهر","لا أحتاج إلى مصاهر احتياطية إذا كانت جميع أضواء التحذير والمقاييس في لوحة القيادة تعمل حالياً","لا أحتاج إلى مصاهر احتياطية لأن مثلثات التحذير الثلاثة تستوفي قاعدة معدات الطوارئ بالفعل"],"explanation":"تُطلب المصاهر الاحتياطية فقط للمركبات التي تستخدم المصاهر؛ أما المركبة المحمية بقواطع الدائرة فلا تحتاج إليها لأن القواطع تُعاد ضبطها بدلاً من استبدالها."},"58":{"q":"أنا أنقل حمولة في مقطورة مغلقة عبر تكساس وأتوقف في منطقة استراحة لأخذ استراحتي البالغة 30 دقيقة. ترك صديق علبة بيرة مغلقة وقنينة بيرة نصف فارغة في حجرة النوم منذ عطلة نهاية الأسبوع. أنا خارج الخدمة خلال الاستراحة والمحرك مُطفأ. بموجب قواعد تكساس، أي عبارة تصف بدقة وضعي بخصوص الحاوية المفتوحة؟","options":["لأن الشاحنة مركونة والمحرك مُطفأ، فإن القنينة المفتوحة مسموح بها طالما لم أشرب منها قبل القيادة","الحاوية المفتوحة لا بأس بها بما أنني في استراحتي خارج الخدمة ونسبة الكحول في دمي أقل بكثير من حدّ 0.04% للرخصة التجارية","القنينة المفتوحة محظورة في قمرة المركبة التجارية؛ حيازة أو شرب الكحول في مركبة تجارية غير مسموح به، بغض النظر عن حالة الخدمة","مسموح بها فقط إذا بقيت القنينة المفتوحة في حجرة النوم وأُزيلت العلبة المغلقة من القمرة"],"explanation":"حيازة أو شرب الكحول في مركبة تجارية محظور بغض النظر عن حالة الخدمة، لذا فإن وجود حاوية مفتوحة في القمرة غير مسموح به أبداً."},"59":{"q":"أنهيت للتو يوم قيادتي، وركنت الشاحنة مع المقطورة في الساحة، ولاحظت ضبطاً للفرامل بدا غير سليم أثناء رحلتي. يخبرني سائق أحدث منّي أنني أحتاج فقط إلى تقديم تقرير فحص المركبة من السائق (DVIR) عند تعطّل شيء كبير أو عند التجديد السنوي. ما عدد المرات الفعلي المطلوب منّي فيها إكمال تقرير DVIR؟","options":["مرة كل سنة، عند تجديد شهادتي الطبية ورخصتي","في اليوم الذي أكتشف فيه عيباً خطيراً يكفي لإخراج المركبة من الخدمة","عند بيع المركبة أو نقلها إلى ناقل جديد","في نهاية كل يوم قيادة، وفي أي وقت آخر تتطلبه القواعد"],"explanation":"يجب إكمال تقرير فحص المركبة من السائق في نهاية كل يوم قيادة وفي أي وقت آخر تتطلبه القواعد، وليس فقط عند ظهور مشكلة."},"60":{"q":"في وضح النهار تنقل حمولة تمتد 5 أقدام خارج مؤخرة مقطورتك. ماذا تتطلب تكساس؟","options":["لا حاجة لأي شيء إضافي لأن الحمولة تتجاوز المؤخرة بضعة أقدام فقط.","علّم نهاية الحمولة براية حمراء أو برتقالية لا تقل عن 12 بوصة مربعة.","غطِّ الحمولة البارزة بقماش مشمّع كي لا يرى السائقون الآخرون الجزء البارز.","ضع ضوءاً أبيض ساطعاً على نهاية الحمولة حتى أثناء ساعات النهار."],"explanation":"يجب تعليم الحمولة البارزة نهاراً براية حمراء أو برتقالية لا تقل عن 12 بوصة مربعة."},"61":{"q":"أمامك على الكتف شاحنة قطر متوقفة وأضواؤها الطارئة وامضة. بموجب قانون تكساس \"تنحَّ جانباً / أبطئ\"، ماذا يجب أن تفعل؟","options":["حافظ على سرعتك ومسارك لأن القانون يسري فقط على مركبات دوريات الشرطة.","انتقل إلى مسار آخر إن أمكنك ذلك بأمان، أو أبطئ إلى أقل بكثير من الحد المسموح به.","توقف تماماً في مسارك حتى تنتهي المركبة المتوقفة من عملها.","سرّع لتجاوز المنطقة بأسرع ما يمكن وتقضي وقتاً أقل بجانبها."],"explanation":"تنحَّ جانباً إن كان ذلك آمناً؛ وإلا فأبطئ إلى أقل بكثير من حد السرعة."},"62":{"q":"تعطّلت شاحنتي المحمّلة مع المقطورة على طريق مستوٍ مستقيم ذي مسارين، مسار في كل اتجاه. بعد تشغيل أضواء التحذير، أمسك مثلثات التحذير الثلاثة. أين يجب أن أضعها لتحذير المرور القادم من الاتجاهين؟","options":["نحو 10 أقدام خلف المقطورة، و100 قدم خلفها، و100 قدم أمام القمرة.","نحو 10 أقدام خلف المقطورة، و100 قدم خلفها، و200 قدم خلفها باتجاه المرور المقترب.","الثلاثة جميعاً نحو 100 قدم خلف المقطورة، موزّعة بحيث يكون الاقتراب من الخلف معلّماً بوضوح.","نحو 10 أقدام أمام القمرة، و100 قدم أمامها، و100 قدم خلف المقطورة."],"explanation":"على طريق ذي مسارين باتجاهين، ضع مثلثات التحذير على نحو 10 أقدام و100 قدم خلف المركبة و100 قدم أمامها لحماية حركة المرور في الاتجاهين."},"63":{"q":"أنت تقود شاحنة مستقيمة محمّلة على طريق ريفي ذي مسارين باتجاهين، مسار في كل اتجاه وبدون جزيرة فاصلة. على بُعد نحو 150 قدماً أمامك، تنحرف حافلة مدرسية تسير في اتجاهك إلى الكتف الأيمن، وتمدّ ذراع التوقف، وتُشغّل أضواءها الحمراء الوامضة بينما يبدأ الأطفال بالتقدم نحو الباب. حركة المرور خلف الحافلة توقفت بالفعل. ما الإجراء الصحيح؟","options":["انتقل إلى المسار المقابل وتجاوز الحافلة ببطء من اليسار، بما أن الأطفال يصعدون من الجانب الأيمن بعيداً عن مسارك.","توقف توقفاً تاماً وابقَ متوقفاً حتى تُطفئ الحافلة أضواءها الحمراء الوامضة وتبدأ بالتحرك مجدداً.","خفّف سرعتك واستمر في السير متجاوزاً، لأنه على طريق غير مقسوم تُلزَم فقط المركبات التي خلف الحافلة مباشرةً بالتوقف.","توقف لحظة، ثم اضغط على البوق مرتين لتنبيه الأطفال وتابع بعد أن تتأكد أن المدخل خالٍ."],"explanation":"على طريق غير مقسوم باتجاهين، يجب على المرور في الاتجاهين التوقف لحافلة مدرسية ذات أضواء حمراء وامضة والبقاء متوقفاً حتى تنطفئ الأضواء وتتحرك الحافلة."},"64":{"q":"أنت تنقل مواد خطرة موضوعة عليها لافتات (placards) وتصل إلى تقاطع سكة حديد. ماذا يتطلب قانون تكساس؟","options":["أبطئ قليلاً واعبر دون توقف إن لم يكن هناك قطار في الأفق على الإطلاق.","توقف على بُعد 15 إلى 50 قدماً قبل القضبان، انظر وأنصت، ثم اعبر إن كان الطريق خالياً.","توقف على القضبان لحظة للتأكد من أن بوابة العبور تعمل بشكل صحيح.","سرّع لعبور القضبان بسرعة كي تقضي الحمولة الثقيلة وقتاً أقل عليها."],"explanation":"يجب على المركبة التي تحمل لافتات أن تتوقف على بُعد 15 إلى 50 قدماً قبل القضبان، وتنظر وتنصت، ثم تعبر."},"65":{"q":"أنا أنقل حمولة على طريق ريفي تكساسي ذي مسارين بعد حلول الظلام عندما يجبرني تحذير انخفاض الوقود على التوقف وانتظار المساعدة. هناك كتف حصوي عريض على يميني. لكي أركن بأمان كما يتطلب دليل الرخصة التجارية في تكساس، ماذا يجب أن أفعل؟","options":["أبقى في مسار السير الأيمن مع تشغيل المصابيح الأمامية وأضواء التحذير الرباعية كي يتمكن السائقون المقتربون من رؤيتي من بعيد.","أركب على خط الحافة، مع إبقاء القمرة على الإسفلت والمقطورة على الحصى، كي لا أغوص في الكتف الطري.","أخرج بالكامل من الطريق إلى الكتف الحصوي، وأضع فرامل الركن، وأضع مثلثات التحذير الثلاثة.","أترك المحرك يعمل والمركبة في الترس مقابل الكتف كي لا تتدحرج الشاحنة بينما أنتظر وصول شاحنة الوقود."],"explanation":"عند التوقف على جانب الطريق، أخرج المركبة بالكامل إلى الكتف، وضع فرامل الركن، وضع مثلثات التحذير الثلاثة لتنبيه المرور."},"66":{"q":"أثناء قيادتك لمركبتك التجارية في تكساس، يرنّ هاتفك وتريد الرد عليه. ما القانون؟","options":["يمكنك إمساك الهاتف واستخدامه بحرية طالما عادت كلتا يديك إلى المقود.","استخدام الهاتف المحمول باليد أثناء قيادة مركبة تجارية محظور؛ استخدم وضع اليدين الحرّتين فقط.","إرسال الرسائل النصية محظور لكن إمساك الهاتف لإجراء المكالمات مسموح به دائماً.","استخدام الهاتف لا بأس به دون 30 ميلاً في الساعة وهو محظور فقط عند سرعات الطريق السريع الأعلى."],"explanation":"استخدام الهاتف المحمول باليد أثناء قيادة مركبة تجارية محظور؛ استخدم وضع اليدين الحرّتين."},"67":{"q":"عرض شاحنتك 80 بوصة وأنت تفحص المصابيح قبل رحلة ليلية. ما المطلوب في المقدمة؟","options":["مصباح أبيض واحد مثبّت في وسط المصدّ الأمامي هو كل ما تحتاجه.","مصابيح موضع كهرماني (مصابيح جانبية) تُظهر باتجاه مقدمة المركبة العريضة.","مصابيح موضع حمراء على الزوايا الأمامية كي يراك المرور أمامك قادماً.","لا حاجة لأي مصابيح موضع في مقدمة شاحنة بهذا الحجم في أي مكان في تكساس."],"explanation":"تحتاج المركبة العريضة إلى مصابيح موضع كهرمانية تُظهر باتجاه المقدمة."},"68":{"q":"أنت على وشك تجاوز دراجة نارية على طريق سريع في تكساس. كيف يجب أن تتعامل معها؟","options":["تجاوزها عن قرب وبسرعة بما أن الدراجة النارية تشغل جزءاً أقل بكثير من عرض المسار.","امنحها عرض مسار كامل ومقداراً آمناً من المسافة، تماماً كما تفعل مع سيارة.","اركب على خط المسار كي يبقى جزء من شاحنتك بجانب الدراجة النارية لفترة أطول.","اضغط البوق وانتقل إلى مسارها لإجبار السائق على الانحراف إلى الكتف من أجلك."],"explanation":"امنح الدراجة النارية مساراً كاملاً ومسافة آمنة، تماماً كما تفعل مع سيارة."},"69":{"q":"أوقفني للتو ضابط من إدارة السلامة العامة في تكساس (DPS) إثر حادث خطير، وأخبرني بالخضوع لفحص كيميائي للكحول والمخدرات. أنا غير مخمور تماماً وأعلم أن نسبة الكحول في دمي أقل بكثير من حدّ 0.04% للرخصة التجارية، لذا أنا مُغرى برفض الفحص من باب المبدأ. بموجب قواعد الموافقة الضمنية في تكساس، أي مما يلي هو العاقبة الحقيقية للرفض؟","options":["لا يحدث شيء لرخصتي التجارية، لأنه لم يكن لديّ كحول قابل للكشف وقاعدة الموافقة الضمنية تسري فقط على السائقين الذين يتجاوزون فعلياً حدّ 0.04%.","أواجه فقط تعليقاً لمدة 60 يوماً، نفس العقوبة التي تطبّقها تكساس على سائق يرتكب مخالفتين مروريتين خطيرتين خلال نافذة ثلاث سنوات.","رخصتي التجارية لا تتأثر، لكن رخصة سيارتي الشخصية تُعلّق لمدة سنة بينما تبقى رخصتي التجارية سارية تماماً للعمل.","رفض الفحص يُحتسب مخالفة كبرى أولى ويسحب رخصتي التجارية لمدة سنة واحدة، تماماً كما لو رسبت في الفحص."],"explanation":"رفض فحص كيميائي إلزامي بعد حادث هو مخالفة كبرى أولى تحمل سحباً للرخصة التجارية لمدة سنة واحدة — نفس عقوبة الرسوب في الفحص."},"70":{"q":"أثناء فحصي قبل الرحلة، أجد أن أحد مصابيح الخلف المطلوبة في مؤخرة شاحنتي محترق. أعلم أنه يجب إصلاحه، لكن قبل أن أنطلق، أريد أن أتأكد من المعدات العاكسة التي يجب أن تُظهرها مؤخرة مركبتي بغض النظر عن المصباح المعطّل. ما الحد الأدنى المطلوب؟","options":["يجب أن تُظهر المؤخرة عاكسين أحمرين على الأقل","يجب أن تُظهر المؤخرة ثلاثة عاكسات حمراء على الأقل","يجب أن تُظهر المؤخرة عاكساً أحمر واحداً على الأقل","لا حاجة لأي عاكسات طالما أن مصباح الخلف الآخر لا يزال يعمل"],"explanation":"يجب أن تُظهر مؤخرة المركبة التجارية دائماً عاكسين أحمرين على الأقل، وهو شرط منفصل عن مصابيح الخلف."},"71":{"q":"أنا أنهي فحصي قبل الرحلة على مقطورة مسطحة وألاحظ عاكساً متشققاً مثبّتاً في مؤخرة المقطورة، فأُخرج بديلاً من صندوق قطع الغيار. لأبقى ضمن القانون وأجتاز الفحص، ما اللون الذي يجب أن يكون عليه العاكس الذي أركّبه في مؤخرة المركبة؟","options":["كهرماني، نفس اللون المستخدم للعاكسات وأضواء الموضع على جانبي المقطورة","أحمر، مطابقاً للعاكسات الأخرى المتجهة إلى الخلف وأضواء الموضع الخلفية","أخضر، كي يستطيع السائقون الذين خلفك تمييز أنه الطرف الخلفي للشاحنة","شفاف (أبيض)، كي يعكس أكبر قدر من الضوء من المصابيح الأمامية خلفي"],"explanation":"يجب أن تكون جميع العاكسات والأجهزة العاكسة المتجهة إلى مؤخرة المركبة التجارية حمراء اللون."},"72":{"q":"أثناء فحصي قبل الرحلة لشاحنة صندوقية، أتفقّد المصابيح على طول الجزء الأمامي من المقطورة. ألاحظ أن مصابيح الموضع الأمامية والمصابيح الجانبية القريبة من المقدمة كلها تتوهّج بنفس اللون. كي تجتاز الشاحنة الفحص، ما اللون الذي يجب أن تُظهره مصابيح الموضع والمصابيح الجانبية المتجهة إلى الأمام؟","options":["أحمر، نفس اللون المستخدم على مصابيح الموضع والمصابيح الجانبية الخلفية","أبيض، مطابقاً للمصابيح الأمامية كي تبقى العلامات ساطعة ومرئية","كهرماني، اللون الأصفر القياسي المطلوب لمصابيح الموضع الأمامية هذه","أخضر، لتعليم الحافة الأمامية والإشارة إلى أن المركبة تتحرك للأمام"],"explanation":"يجب أن تكون مصابيح الموضع والمصابيح الجانبية المتجهة إلى مقدمة المركبة كهرمانية (صفراء)."},"73":{"q":"أنا في محطة وزن في تكساس مع شاحنتي ونصف المقطورة المحمّلة، دون تصريح للحمولة الزائدة الحجم/الوزن. محوري المفرد يزن 19,500 رطل والمحور المزدوج (التاندم) 33,500 رطل، وكلاهما قانوني. يريد المفتش الآن وزني الإجمالي الكلي من الميزان. دون تصريح خاص، ما الحد الأقصى الذي يمكن أن تزنه مركبتي وحمولتها مجتمعة قانوناً؟","options":["20,000 رطل، لأنه لا يجوز لأي محور مفرد أن يتجاوز هذا الحد","34,000 رطل، بما أن سقف المحور المزدوج يحدد الإجمالي القانوني","102,000 رطل، مطابقاً لمخصص الوزن القياسي بين الولايات","80,000 رطل، الحد الأقصى للوزن الإجمالي القانوني دون تصريح"],"explanation":"تحدّ تكساس الوزن الإجمالي الأقصى (المركبة زائد الحمولة) عند 80,000 رطل دون تصريح خاص، بغض النظر عن أوزان المحاور الفردية."},"74":{"q":"أنا أنقل حمولة من ألواح جدران مسبقة الصنع عبر تكساس ويخبرني الموزّع بالتحقق من عرض الحمولة قبل مغادرة الساحة كي لا يتم إيقافي بسبب مخالفة الحجم الزائد. دون الحصول على تصريح خاص للحجم الزائد، ما الحد الأقصى القانوني لعرض مركبتي وحمولتي؟","options":["102 بوصة (8 أقدام و6 بوصات)","96 بوصة (8 أقدام)","108 بوصة (9 أقدام)","120 بوصة (10 أقدام)"],"explanation":"الحد الأقصى القانوني لعرض المركبة وحمولتها هو 102 بوصة (8 أقدام و6 بوصات) دون تصريح للحجم الزائد."},"75":{"q":"أنا أنقل حمولة من المعدات الزراعية على شاحنة مسطحة وأحاول معرفة ما إذا كنت بحاجة إلى تصريح للأحمال كبيرة الحجم قبل أن أغادر الساحة. أقيس من الأرض إلى أعلى نقطة في أطول قطعة من المعدات. عند أي ارتفاع يتجاوز مجموع ارتفاع مركبتي مع الحمولة الحد القانوني، بحيث يجب علي الحصول على تصريح خاص للتشغيل على طرق تكساس السريعة؟","options":["أي ارتفاع يزيد عن 12 قدمًا يتطلب تصريح الأحمال كبيرة الحجم الخاص","أي ارتفاع يزيد عن 14 قدمًا يتطلب تصريح الأحمال كبيرة الحجم الخاص","أي ارتفاع يزيد عن 16 قدمًا يتطلب تصريح الأحمال كبيرة الحجم الخاص","أي ارتفاع يزيد عن 13 قدمًا و6 بوصات يتطلب تصريح الأحمال كبيرة الحجم الخاص"],"explanation":"الحد الأقصى القانوني لارتفاع المركبة مع الحمولة هو 14 قدمًا، وأي ارتفاع يزيد عن ذلك يتطلب تصريحًا خاصًا للأحمال كبيرة الحجم."},"76":{"q":"أنا أقود شاحنتي المقطورة عبر تكساس في فترة بعد الظهر الصافية عندما تهب عاصفة مطرية غزيرة. تظلم السماء، وأشغّل مساحات الزجاج الأمامي لمواكبة المطر الغزير، ولا زلت أستطيع رؤية الطريق ولكن ليس إلى مسافة بعيدة كما كان من قبل. إنه منتصف النهار، وما زالت هناك ساعات حتى غروب الشمس. بموجب قواعد تكساس، ماذا يجب أن أفعل بشأن مصابيحي الأمامية في هذا الموقف؟","options":["لا شيء بعد، لأن استخدام المصابيح الأمامية نهارًا اختياري حتى لا أعود قادرًا على الرؤية بوضوح لمسافة 500 قدم على الأقل.","لا شيء، لأن المصابيح الأمامية مطلوبة قانونًا فقط بين 30 دقيقة بعد غروب الشمس و30 دقيقة قبل شروقها.","أشغّل مصابيحي الأمامية الآن، لأن تكساس تتطلبها كلما كانت الرؤية ضعيفة أو كانت مساحات الزجاج الأمامي قيد الاستخدام.","أشغّل فقط مصابيح التحذير الرباعية، لأن تشغيل المساحات في المطر يستدعي مصابيح الخطر بدلاً من المصابيح الأمامية."],"explanation":"تتطلب تكساس تشغيل المصابيح الأمامية كلما كنت غير قادر على الرؤية بوضوح لمسافة 1,000 قدم أو كانت مساحات الزجاج الأمامي قيد الاستخدام، وليس فقط بعد حلول الظلام."},"77":{"q":"أنت تقود مركبتك التجارية على طريق تكساس السريع المكون من 4 مسارات عندما تلاحظ مركبة متوقفة على الكتف الأيمن أمامك مع مصابيحها الكهرمانية الوامضة. وعندما تقترب، تدرك أنها شاحنة صيانة تابعة لإدارة النقل في تكساس (TxDOT)، وبعدها مباشرة شاحنة سحب تربط سيارة معطلة، أيضًا بمصابيح وامضة. لا توجد سيارة شرطة أو سيارة إسعاف في الأفق. بموجب قانون الانتقال للمسار الآخر / التباطؤ في تكساس، ماذا يجب أن تفعل؟","options":["لا ينطبق شيء خاص هنا، لأن القانون يتطلب فقط الانتقال للمسار الآخر أو التباطؤ من أجل سيارات دوريات الشرطة ومركبات إنفاذ القانون المميزة.","تابع بسرعتك العادية، لأن القانون يحمي فقط شاحنات الإطفاء وسيارات الإسعاف التي تستجيب فعليًا لحالة طارئة.","حافظ على سرعتك ولكن استخدم بوقك، لأن القانون يغطي فقط الحافلات المدرسية ومركبات الركاب المتوقفة على الكتف.","انتقل إلى مسار بعيد عنهم إذا كان بإمكانك ذلك بأمان، أو تباطأ، لأن القانون يغطي الشرطة والإطفاء والإسعاف وشاحنات السحب ومركبات إدارة النقل في تكساس."],"explanation":"يغطي قانون الانتقال للمسار الآخر / التباطؤ في تكساس أي مركبة متوقفة مع مصابيح وامضة، بما في ذلك الشرطة والإطفاء والإسعاف وشاحنات السحب ومركبات إدارة النقل في تكساس (TxDOT)."},"78":{"q":"يسخن محمل عجلة بشكل مفرط وأُجبر على سحب شاحنتي المقطورة المحملة إلى الكتف الأيمن لطريق سريع ذي مسارين. أشغّل مصابيحي التحذيرية الرباعية، وأمسك مثلثاتي العاكسة من المقصورة، وأبدأ بالسير عائدًا لوضعها. بموجب قواعد تكساس، ما هو الحد الأقصى من الوقت المسموح لي به لوضع أجهزة التحذير الخاصة بي بعد التوقف؟","options":["لدي ما يصل إلى 10 دقائق بعد التوقف لوضع جميع أجهزة التحذير الخاصة بي.","لدي ما يصل إلى 30 دقيقة بعد التوقف لوضع جميع أجهزة التحذير الخاصة بي.","لدي ما يصل إلى دقيقة واحدة بعد التوقف لوضع جميع أجهزة التحذير الخاصة بي.","لدي ما يصل إلى ساعة واحدة بعد التوقف لوضع جميع أجهزة التحذير الخاصة بي."],"explanation":"بعد التوقف على الطريق أو الكتف، يجب عليك تشغيل المصابيح التحذيرية الرباعية فورًا ووضع مثلثات التحذير خلال 10 دقائق."},"79":{"q":"إدانة أولى بالقيادة تحت تأثير الكحول أثناء قيادة مركبة تجارية تؤدي إلى إلغاء أهلية رخصة القيادة التجارية الخاصة بك لمدة لا تقل عن:","options":["30 يومًا","سنة واحدة","6 أشهر","أسبوعين"],"explanation":"المخالفة الكبرى الأولى مثل القيادة تحت تأثير الكحول تلغي أهلية رخصة القيادة التجارية لمدة لا تقل عن سنة واحدة."},"80":{"q":"أنا أنقل حمولة على الطريق السريع I-35 عبر أوستن عندما يتصل بي المرسل بشأن تغيير في موعد التسليم. تتحرك حركة المرور بثبات بسرعة 55 ميلاً في الساعة. بموجب قانون تكساس، أي من هذه هي الطريقة الوحيدة المسموح لي بها للرد على هذه المكالمة أثناء قيادة مركبتي التجارية؟","options":["بإمساك الهاتف بيد واحدة وإبقاء عيني على الطريق، لأنها مجرد مكالمة سريعة","باستخدام نظام يعمل بدون استخدام اليدين، مثل سماعة بلوتوث أو مكبر صوت، بحيث لا أمسك الجهاز أبدًا","بتقريب الهاتف واستخدام تحويل الصوت إلى نص للرد، طالما أنني لا أطلب الرقم يدويًا","بالرد على المكالمة بحرية بمجرد أن تتباطأ حركة المرور دون 20 ميلاً في الساعة في منطقة الإنشاءات"],"explanation":"في تكساس، يجوز للسائق التجاري استخدام الهاتف أثناء القيادة فقط بدون استخدام اليدين، مثل سماعة بلوتوث أو مكبر صوت، ولا يجوز أبدًا إمساك الجهاز."},"81":{"q":"اجتزت اختبارات المعرفة لرخصة المتعلم التجارية قبل أسبوعين، وحصلت على رخصة المتعلم التجارية في تكساس، وأشعر أنني مستعد لاختبار المهارات على الطريق. اتصلت لحجز أقرب موعد ممكن. بموجب قواعد إدارة السلامة العامة في تكساس (DPS)، ما هو الحد الأدنى من الوقت الذي يجب أن أحمل فيه رخصة المتعلم التجارية قبل أن يُسمح لي بإجراء اختبار المهارات؟","options":["يمكنني تحديد موعده فورًا، طالما أن رخصة المتعلم التجارية الخاصة بي صادرة وصالحة في ذلك اليوم","يجب أن أحمل رخصة المتعلم التجارية لمدة 30 يومًا على الأقل قبل السماح باختبار المهارات","يجب أن أحمل رخصة المتعلم التجارية لمدة 14 يومًا على الأقل قبل أن أكون مؤهلاً لاختبار المهارات","يجب أن أحمل رخصة المتعلم التجارية لمدة 90 يومًا على الأقل قبل السماح باختبار المهارات"],"explanation":"تتطلب القواعد الفيدرالية وقواعد تكساس حمل رخصة المتعلم التجارية لمدة 14 يومًا على الأقل قبل أن تكون مؤهلاً لإجراء اختبار مهارات رخصة القيادة التجارية."},"82":{"q":"أنا أنهي فحص ما قبل الرحلة لمقطورتي في الساحة قبل رحلة ليلية على طريق تكساس السريع، وأفحص المصابيح والعاكسات في الجزء الخلفي تمامًا من الوحدة. لكي أبقى ضمن القانون، ما اللون الذي يجب أن تعرضه المصابيح والعاكسات المثبتة على مؤخرة مركبتي التجارية؟","options":["مصابيح خلفية كهرمانية وعاكسات كهرمانية، لأن اللون الكهرماني هو اللون القياسي المستخدم على جوانب المقطورة","مصابيح خلفية حمراء مقترنة بعاكسات كهرمانية، لأن العاكسات دائمًا كهرمانية بغض النظر عن مكان تركيبها","مصابيح خلفية خضراء مع عاكسات حمراء، لأن اللون الأخضر يشير لحركة المرور خلفك إلى أن الوحدة خالية للتجاوز","مصابيح خلفية حمراء مقترنة بعاكسين أحمرين، لأن مؤخرة المركبة يجب أن تكون معلّمة باللون الأحمر"],"explanation":"يجب أن تكون مؤخرة المركبة التجارية معلّمة باللون الأحمر، بمصابيح خلفية حمراء وعاكسين أحمرين."},"83":{"q":"أثناء فحص ما قبل الرحلة، يسلمني المرسل قائمة تحقق بـ\"معدات الطوارئ\" ويخبرني بالتأكد من وجود كل عنصر على متن المركبة قبل أن أغادر الساحة. أريد التأكد من أنني أتحقق فقط من المعدات التي يلزمني القانون فعليًا بحملها على مركبتي التجارية. أي عنصر يجب أن أؤكد وجوده؟","options":["ثلاثة مثلثات تحذير عاكسة حمراء لطقم جهاز التحذير في حالات الطوارئ","سلاح ناري محشو ومؤمَّن في المقصورة للحماية على جانب الطريق","مجموعة من ستة شعلات طريق على الأقل لاستبدال أي مثلثات مستخدمة","إطار احتياطي لمحور القيادة مركّب وجاهز خلف المقصورة"],"explanation":"يجب أن تحمل المركبة التجارية طقم تحذير للطوارئ يتكون من ثلاثة مثلثات تحذير عاكسة حمراء."},"84":{"q":"قبل ثلاث سنوات، فقدت رخصة القيادة التجارية الخاصة بي لمدة سنة بعد إدانة بالقيادة تحت تأثير الكحول في شاحنتي. الأسبوع الماضي تم إيقافي وأُدنت برفض اختبار كيميائي أثناء قيادة المركبة التجارية نفسها. بموجب قواعد تكساس، ماذا يحدث لرخصة القيادة التجارية الخاصة بي الآن؟","options":["أحصل على إلغاء أهلية آخر لمدة سنة، لأن كل مخالفة كبرى تُعامل كعقوبة منفصلة مدتها سنة واحدة.","تُلغى أهليتي مدى الحياة، لأن هذه هي مخالفتي الكبرى الثانية في مركبة تجارية.","أحصل على إلغاء أهلية لمدة 3 سنوات، نفس عقوبة المخالفة الكبرى المرتكبة أثناء نقل مواد خطرة تحمل لوحات تحذير.","أحصل على إلغاء أهلية لمدة 60 يومًا، وهي العقوبة القياسية لتراكم المخالفات المتكررة في مركبة تجارية."],"explanation":"يُعد رفض اختبار كيميائي مخالفة كبرى، والمخالفة الكبرى الثانية تؤدي إلى إلغاء أهلية رخصة القيادة التجارية مدى الحياة."},"85":{"q":"أنا أقود مركبة من الفئة A المركّبة في تكساس واتخذت قرارًا سيئًا واحدًا: استخدمت شاحنتي لنقل مادة خاضعة للرقابة، والمدعون العامون يوجهون إلي تهمة جناية مخدرات تتضمن استخدام مركبتي التجارية. هذه أول مخالفة من أي نوع في سجل رخصة القيادة التجارية الخاصة بي — سجل نظيف قبل هذا. عندما تُعالج قضيتي، ماذا يتطلب قانون تكساس/القانون الفيدرالي بالنسبة لامتياز قيادتي التجارية؟","options":["لأنها مخالفة كبرى أولى، أواجه إلغاء أهلية لمدة سنة ويمكنني إعادة التقديم بعد قضائها","أواجه إلغاء أهلية لمدة 60 يومًا، لأن المركبة التجارية كانت مجرد الوسيلة المستخدمة لنقل المادة","أواجه إلغاء أهلية مدى الحياة دون إمكانية إعادة التأهيل، رغم أنها مخالفتي الأولى","أواجه إلغاء أهلية لمدة 3 سنوات، نفس المخالفة الكبرى الأولى المرتكبة أثناء نقل مواد خطرة تحمل لوحات تحذير"],"explanation":"استخدام مركبة تجارية في جناية تتضمن مواد خاضعة للرقابة يؤدي إلى إلغاء أهلية رخصة القيادة التجارية مدى الحياة دون إعادة تأهيل، حتى في المخالفة الأولى."},"86":{"q":"أنا أقود شاحنتي الجرارة منذ ثلاث سنوات ولدي سجل نظيف باستثناء إدانتين: واحدة لتجاوز السرعة المفرط وواحدة للقيادة المتهورة، وكلاهما تصنفه إدارة السلامة العامة (DPS) كمخالفة مرورية \"خطيرة\"، وكلاهما وقعتا خلال نفس فترة الثلاث سنوات هذه. لقد تلقيت للتو إشعاري من إدارة السلامة العامة في تكساس. لكم من الوقت ستُلغى أهلية رخصة القيادة التجارية الخاصة بي؟","options":["سنة واحدة، لأن أي مزيج من مخالفتين خطيرتين يؤدي إلى نفس عقوبة المخالفة الكبرى الأولى","120 يومًا، لأن فترة إلغاء الأهلية تتضاعف إلى 120 يومًا بمجرد تسجيل مخالفة خطيرة ثانية","30 يومًا، لأن كل مخالفة خطيرة تضيف 15 يومًا ثابتًا من إلغاء الأهلية إلى سجل قيادتي","60 يومًا، لأن مخالفتين مروريتين خطيرتين خلال فترة 3 سنوات تؤديان إلى إلغاء أهلية لمدة 60 يومًا"],"explanation":"مخالفتان مروريتان خطيرتان في مركبة تجارية خلال فترة 3 سنوات تؤديان إلى إلغاء أهلية رخصة القيادة التجارية لمدة 60 يومًا."},"87":{"q":"كان لدي بالفعل مخالفتان مروريتان خطيرتان أُدنت بهما في شاحنتي خلال السنوات الثلاث الماضية. الأسبوع الماضي حصلت على مخالفة لمخالفة خطيرة ثالثة، وجميعها الثلاث تقع ضمن نفس نافذة الثلاث سنوات. عندما تُسجّل هذه الإدانة الثالثة، لكم من الوقت ستُلغى أهلية رخصة القيادة التجارية الخاصة بي؟","options":["120 يومًا، لأن مخالفة خطيرة ثالثة خلال فترة 3 سنوات تؤدي إلى إلغاء أهلية لمدة 120 يومًا","60 يومًا، لأن كل مخالفة خطيرة إضافية خلال 3 سنوات تضيف ببساطة فترة 60 يومًا أخرى","سنة واحدة، لأن ثلاث مخالفات خطيرة تُعامل بنفس معاملة المخالفة الكبرى الأولى","مدى الحياة، لأن الوصول إلى مخالفة خطيرة ثالثة يمنعك بشكل دائم من حمل رخصة قيادة تجارية"],"explanation":"المخالفة المرورية الخطيرة الثالثة في مركبة تجارية خلال فترة 3 سنوات ترفع العقوبة إلى إلغاء أهلية رخصة القيادة التجارية لمدة 120 يومًا."},"88":{"q":"أنا أقود مركبة تجارية في تكساس وحصلت للتو على مخالفة لأول انتهاك لتقاطع السكة الحديدية. سجلي نظيف بخلاف ذلك. عندما أبحث عن العقوبة، أنا قلق بشأن المدة التي سأكون فيها خارج الطريق. ما هو أقل قدر من الوقت الذي ستُلغى فيه أهلية رخصة القيادة التجارية الخاصة بي لهذه المخالفة الواحدة لتقاطع السكة الحديدية؟","options":["30 يومًا، لأنها تُعامل كمخالفة ورقية بسيطة لأول مرة","60 يومًا، لأن حتى أول انتهاك لتقاطع السكة الحديدية يحمل إلغاء أهلية","لا إلغاء أهلية على الإطلاق، لأنها مخالفتي الأولى من هذا النوع","120 يومًا، نفس تراكم ثلاث مخالفات مرورية خطيرة"],"explanation":"أول انتهاك لتقاطع السكة الحديدية هو مخالفة مستقلة تستوجب إلغاء الأهلية وتحمل إلغاء أهلية لمدة لا تقل عن 60 يومًا."},"89":{"q":"لدي بالفعل مخالفة مرورية خطيرة واحدة في سجل رخصة قيادتي التجارية من العام الماضي، وصاحب العمل يحذرني من أن مخالفة خطيرة ثانية خلال ثلاث سنوات ستؤدي إلى إلغاء أهلية لمدة 60 يومًا. خلال رحلتي القادمة، أي من الأفعال التالية من جانبي ستُحتسب كتلك المخالفة \"الخطيرة\" الثانية وتعرّض رخصة قيادتي التجارية للخطر؟","options":["التوقف التام عند إشارة حمراء ثابتة قبل خط التوقف المعلّم","الحفاظ على سرعتي ثابتة عند الحد المسموح خلال منطقة إنشاءات طويلة","القيادة بسرعة 15 ميلاً في الساعة أو أكثر فوق الحد المسموح على الطريق السريع المفتوح","تفعيل إشارة الانعطاف مبكرًا قبل تغيير المسار لتجاوز مركبة بطيئة"],"explanation":"القيادة بسرعة 15 ميلاً في الساعة أو أكثر فوق الحد المسموح تُصنف كمخالفة مرورية خطيرة."},"90":{"q":"تحتسب إدارة السلامة العامة في تكساس (DPS) بعض المخالفات المتحركة كـ\"مخالفات مرورية خطيرة\" — وتراكم اثنتين منها في مركبة تجارية خلال ثلاث سنوات يكلفك إلغاء أهلية لمدة 60 يومًا. أنا أراجع عاداتي في القيادة مؤخرًا لمعرفة أيها قد يضعني على ذلك المسار. من بين الأفعال أدناه، أيها ستصنفه إدارة السلامة العامة كمخالفة مرورية خطيرة؟","options":["ترك مسافة إضافية والكبح مبكرًا حتى لا أضطر أبدًا إلى التوقف فجأة خلف حركة المرور","فحص مرايايي كل 5 إلى 8 ثوانٍ لتتبع المركبات حولي","الانتقال بالكامل إلى الكتف والتوقف بشكل قانوني عندما أشعر بالنعاس","الاقتراب من الشاحنة التي أمامي بشكل كبير لدرجة أنني لا أستطيع التوقف في الوقت المناسب إذا كبحت"],"explanation":"السير على مسافة قريبة جدًا، دون ترك مساحة للتوقف إذا كبحت المركبة التي أمامك، يُعد مخالفة مرورية خطيرة."},"91":{"q":"أنا حامل رخصة قيادة تجارية في تكساس، والأسبوع الماضي أُدنت بتجاوز السرعة في سيارتي الشخصية أثناء عدم العمل. يخبرني صديقي أنني لست مضطرًا للإبلاغ عنها لأنها لم تحدث في الشاحنة. ما هي أطول مدة يمكنني قانونيًا الانتظار قبل أن أُخطر صاحب العمل بهذه الإدانة؟","options":["30 يومًا من تاريخ الإدانة، رغم أنها كانت في مركبتي الشخصية","لست مضطرًا أبدًا للإبلاغ عنها، لأن الإدانة لم تكن في مركبة تجارية","60 يومًا من تاريخ الإدانة، نفس نافذة مراجعة المخالفة الخطيرة","سنة واحدة من تاريخ الإدانة، عندما يحين موعد تجديد رخصة قيادتي التجارية"],"explanation":"يجب على حامل رخصة القيادة التجارية في تكساس إخطار صاحب العمل بأي إدانة مرورية (باستثناء وقوف السيارات) خلال 30 يومًا، حتى لو حدثت في مركبة شخصية."},"92":{"q":"انتقلت للتو إلى تكساس من ولاية أخرى لا زلت أحمل فيها رخصة قيادة صالحة، وأريد البدء بقيادة مركبة تجارية هنا. عندما أذهب للحصول على رخصة القيادة التجارية في تكساس، ماذا يتطلب القانون مني بشأن رخصة الولاية الأخرى التي أحملها بالفعل؟","options":["يجوز لي الاحتفاظ بكلتا الرخصتين طالما أن إحداهما غير تجارية والأخرى هي رخصتي التجارية في تكساس.","يجب أن أسلّم رخصتي القديمة، لأن سائق المركبة التجارية مسموح له بحمل رخصة واحدة فقط.","يجوز لي الاحتفاظ بكليهما لمدة تصل إلى 30 يومًا أثناء نقل سجلاتي إلى تكساس.","يجوز لي حمل رخصتين طالما تم إخطار كلتا الولايتين بالترتيب."],"explanation":"يجوز لسائق المركبة التجارية قانونيًا حمل رخصة قيادة واحدة فقط، لذا يجب تسليم أي رخصة من ولاية أخرى."},"93":{"q":"يوقفني شرطي من إدارة السلامة العامة لفحص على جانب الطريق أثناء قيادتي لمركبتي التجارية عبر تكساس. بالإضافة إلى رخصة القيادة التجارية الصالحة، أي مستند يُطلب مني حمله بحوزتي لتشغيل المركبة قانونيًا؟","options":["نسخة من تقرير الفحص السنوي للمركبة الخاص بصاحب العمل","أحدث نسخة مطبوعة من سجل قيادتي من مكتب إدارة السلامة العامة","شهادة فاحص طبي صالحة (بطاقة طبية)","نسخة موقعة من شهادة اختبار الطريق قبل التوظيف"],"explanation":"يجب على كل سائق مركبة تجارية حمل شهادة فاحص طبي صالحة (بطاقة طبية) تثبت أنه مؤهل بدنيًا للقيادة."},"94":{"q":"اجتزت للتو اختباراتي الكتابية وسلّمني موظف إدارة السلامة العامة رخصة المتعلم التجارية الخاصة بي. أريد البدء بالتدريب في الشاحنة المقطورة الخاصة بشركتي على الطرق العامة فورًا. بموجب قواعد تكساس، أي من التالي يجب أن يكون صحيحًا لكي أشغّل تلك المركبة التجارية قانونيًا؟","options":["يجوز لي القيادة بمفردي طالما بقيت على الطرق السطحية وبعيدًا عن الطرق السريعة بين الولايات","يجوز لي القيادة بمفردي ليلاً فقط، عندما تكون حركة المرور خفيفة وأسهل في التعامل معها","يجوز لي القيادة فقط إذا كنت قد حملت الرخصة لمدة 14 يومًا على الأقل أولاً","يجوز لي القيادة فقط بينما يجلس بجانبي في المقصورة شخص يحمل رخصة قيادة تجارية صالحة"],"explanation":"يجوز لحامل رخصة المتعلم التجارية قيادة مركبة تجارية فقط عندما يرافقه حامل رخصة قيادة تجارية صالحة يجلس في المقعد الأمامي للمركبة."},"95":{"q":"عمري 19 عامًا، أحمل رخصة قيادة تجارية صالحة في تكساس، وأقود طرق الشحن بين دالاس وهيوستن دون أي مشاكل. تريد شركتي الآن تكليفي برحلة منتظمة لنقل شحنات عامة من تكساركانا إلى أركنساس والعودة. بموجب قواعد العمر الفيدرالية، ماذا يجب أن أفعل قبل قبول هذه الرحلة بين الولايات؟","options":["لا يمكنني القيام بالرحلة بعد — يجب أن أكون 21 عامًا على الأقل لقيادة مركبة تجارية عبر حدود الولايات.","يمكنني القيام بالرحلة الآن، لأن رخصة قيادتي التجارية في تكساس صالحة بالفعل للقيادة في سن 18 أو أكبر.","يمكنني القيام بالرحلة بمجرد أن أبلغ 18 عامًا، لأن هذا هو الحد الأدنى لسن تشغيل أي مركبة تجارية.","يمكنني القيام بالرحلة الآن، طالما تقدم شركتي إعفاءً للقيادة بين الولايات لأنني أكبر من 16 عامًا."],"explanation":"تتطلب القيادة التجارية بين الولايات عبر حدود الولايات حدًا أدنى للعمر يبلغ 21 عامًا، لذا لا يمكن لشخص عمره 19 عامًا القيام بتلك الرحلة."},"96":{"q":"بلغت للتو 18 عامًا وأريد رخصة قيادة تجارية في تكساس لنقل الحصى لشركة محلية. جميع طرقي تبقى داخل تكساس — لا أعبر أبدًا حدود ولاية، ولا أنقل مواد خطرة، ولا أقود ركابًا. ما هو الحد الأدنى لمتطلب العمر الذي ينطبق علي؟","options":["21، لأن تشغيل أي مركبة تجارية يتطلب الحد الأدنى الفيدرالي للعمر بين الولايات","18، لأنني أقود داخل الولاية فقط وأبقى بالكامل داخل تكساس","21، لأن نقل مقطورات الحصى المحملة يُحتسب دائمًا كتجارة بين الولايات","16، لأن رخصة المتعلم تتيح لي قيادة مركبة تجارية قبل بلوغ السن الكامل"],"explanation":"تسمح تكساس بالحصول على رخصة قيادة تجارية وقيادة مركبة تجارية داخل الولاية في سن 18 عند البقاء بالكامل داخل الولاية دون مواد خطرة أو ركاب."},"97":{"q":"أثناء قيادة مركبة تجارية، يجب عليك:","options":["ترك رخصة قيادتك التجارية في المنزل","حمل رخصة قيادتك التجارية معك","إرسالها بالبريد إلى إدارة السلامة العامة","مجرد حفظ الرقم"],"explanation":"احمل رخصة قيادتك التجارية معك أثناء قيادة مركبة تجارية."},"98":{"q":"أثناء فحص على جانب الطريق في تكساس، يضع ضابط شاحنتي خارج الخدمة بسبب عيب في الفرامل ويسلمني الأمر. أنا متأخر بالفعل عن التسليم، لذا أشعر بإغراء مواصلة القيادة بمجرد مغادرة الضابط. إذا قدت المركبة على أي حال مخالفًا أمر إيقاف الخدمة ذلك، ما العاقبة التي ينبغي أن أتوقعها؟","options":["فقط تحذير كتابي، لأن أمر إيقاف الخدمة ينتهي تلقائيًا بمجرد مغادرتي موقع الفحص","غرامة بالإضافة إلى 5 نقاط مضافة إلى سجل قيادتي، ولكن دون تأثير على امتيازات رخصة قيادتي التجارية","غرامات مالية بالإضافة إلى إلغاء أهلية رخصة قيادتي التجارية","لا شيء يتجاوز مخالفة العيب الأصلية، لأن الأمر ينطبق فقط على اختصاص الضابط الفاحص"],"explanation":"القيادة مخالفًا أمر إيقاف الخدمة تجلب غرامات مالية وإلغاء أهلية رخصة القيادة التجارية معًا."},"99":{"q":"أنا أنهي رحلة طويلة عندما أصطدم بمرآة سيارة متوقفة عند رصيف تحميل. هناك ضرر طفيف ولكن لا يوجد أحد حولي، لذا أواصل القيادة للبقاء على الجدول الزمني ولا أبلّغ عنها أبدًا. عندما يتم تتبع هذا إليّ لاحقًا، ما هي أخطر عاقبة أواجهها لمغادرة مكان حادث في مركبتي التجارية؟","options":["يُضاف تحذير كتابي إلى ملفي، لكن رخصة قيادتي التجارية تبقى صالحة بالكامل طالما أبلغت عن الضرر خلال 30 يومًا","تُضاف نقطتان وينطبق إلغاء أهلية لمدة 60 يومًا، نفس عقوبة مخالفتين مروريتين خطيرتين","يُعاقَب صاحب العمل فقط، لأن الشركة تحمل التأمين وهي المسؤولة عن المركبة المتوقفة","تُلغى أهلية رخصة قيادتي التجارية لمدة سنة على الأقل، لأن مغادرة مكان حادث تُحتسب كمخالفة كبرى"],"explanation":"مغادرة مكان حادث في مركبة تجارية هي مخالفة كبرى تلغي أهلية رخصة القيادة التجارية لمدة لا تقل عن سنة في المخالفة الأولى."},"100":{"q":"أثناء فحص ما قبل الرحلة، أضغط على بوق السيارة فلا أسمع شيئًا — إنه معطّل تمامًا. أنا متأخر عن موعدي وبقية المركبة سليمة. أي إجراء يبقيني ضمن القانون وآمنًا قبل الانطلاق؟","options":["البقاء متوقفًا وإصلاح البوق، لأن البوق العامل من معدات السلامة المطلوبة التي يجب أن تعمل قبل الرحلة","المتابعة بالقيادة لأن البوق ليس جزءًا من نظام الفرامل أو الإضاءة، ثم تحديد موعد للإصلاح في نهاية مساري","فصل البوق المعطّل كي لا يحدث تماس كهربائي، والاعتماد على وميض المصابيح الأمامية لتحذير السائقين الآخرين","تغطية زر البوق بشريط لاصق كتذكير والمتابعة، لأن البوق لا يهم إلا في حركة المرور داخل المدينة"],"explanation":"البوق العامل من معدات السلامة المطلوبة، لذا يجب عدم قيادة المركبة التجارية ذات البوق المعطّل حتى يتم إصلاحه."},"101":{"q":"أثناء فحص ما قبل الرحلة في صباح تكساسي ماطر ورطب، ألاحظ أن ماسحة الزجاج الأمامي من جهة السائق تترك خطًا عريضًا وبالكاد تنظّف الزجاج عند تجربتها. أنا متأخر بالفعل عن نافذة التسليم. ماذا يفرض عليّ القانون بشأن الماسحة قبل قيادة هذه المركبة التجارية؟","options":["من المقبول تركها كما هي لأن الماسحة من جهة الراكب لا تزال تنظّف الزجاج جيدًا","يجب إصلاح الماسحة أو استبدالها بحيث تعمل بشكل صحيح قبل الرحلة","يجوز لي القيادة الآن وإصلاحها فقط إذا اشتد المطر بما يكفي لتقليل الرؤية","يمكنني تركها كما هي طالما أبقيت مصابيحي الأمامية مضاءة للظروف الرطبة"],"explanation":"ماسحات الزجاج الأمامي من معدات السلامة الحرجة التي يجب أن تعمل بشكل صحيح قبل الرحلة، لذا يجب إصلاح الماسحة التي تترك خطوطًا أو استبدالها أولًا."},"102":{"q":"أثناء فحص ما قبل الرحلة ألاحظ رائحة خفيفة وأكتشف أن كاتم الصوت في جرّاري يحتوي على وصلة متآكلة ومشبك مفكوك حيث يمتد أسفل المقصورة. أي مما يلي هو المشكلة الأخطر التي يمكن أن تسببها هذه الحالة، مما يجعل نظام العادم غير قانوني للتشغيل؟","options":["التآكل سيبطل ضمان كاتم الصوت إن لم أستبدله قبل موعد الصيانة التالي","كاتم الصوت المزعج سيتجاوز حدّ الديسيبل ويمكن أن تُغرّم المركبة بسبب الصوت المفرط","يمكن أن يتسرب غاز العادم إلى المقصورة أو مكان النوم، فيسممني بأول أكسيد الكربون أثناء القيادة","مكونات العادم غير المطلية ستصدأ بشكل أسرع وتقلل من قيمة إعادة بيع الجرّار"],"explanation":"يمكن أن يسمح نظام العادم المتسرب لأول أكسيد الكربون عديم الرائحة بالتسلل إلى المقصورة أو مكان النوم وتسميم السائق."},"103":{"q":"أثناء فحص ما قبل الرحلة، أتفحص إطارات جرّاري وألاحظ عدة أمور في المجموعة. أي من الحالات التالية تعني أنه يجب إخراج الإطار من الخدمة؟","options":["إطار يحمل علامة تجارية أو علامة الشركة المصنّعة بارزة على الجدار الجانبي","إطار توجيه يتبقى فيه حوالي 4/32 بوصة من عمق المداس عند الأخدود","إطار قيادة يُظهر تآكلًا متساويًا وطبيعيًا للمداس على كامل عرضه","جدار جانبي به قطع أو انتفاخ عميق بما يكفي لكشف خيوط الهيكل"],"explanation":"القطع أو الانتفاخ في الجدار الجانبي العميق بما يكفي لكشف خيوط الهيكل هو حالة إخراج من الخدمة بسبب خطر الانفجار."},"104":{"q":"أنهي فحص ما قبل الرحلة على مقطورة مجمّعة بطول 53 قدمًا قبل الخروج من الساحة عند الفجر. أثناء دوراني حول المقصورة، ألاحظ أن المرايا الخارجية ملطخة بأوساخ الطريق ومائلة بحيث بالكاد أستطيع رؤية جانبي شاحنتي. قبل أن أنطلق، ماذا يجب أن أفعل بالمرايا؟","options":["مسحها لتنظيفها وضبطها بحيث يكون لديّ رؤية واضحة على جانبي المركبة","طيّها مسطحة على المقصورة لتقليل مقاومة الرياح وتوفير الوقود على الطريق السريع","تركها كما هي والاعتماد على إدارة رأسي وكاميرا الرجوع للخلف لمراقبة الجانبين","إمالتها بشدة إلى الأسفل بحيث تُظهر الإطارات والطريق المجاور للمقصورة فقط"],"explanation":"يجب مسح المرايا لتنظيفها وضبطها قبل الرحلة لتوفير رؤية واضحة على جانبي المركبة."},"105":{"q":"أقود جرّاري ومقطورته المحمّلين على طريق سريع ريفي في تكساس بعد حلول الظلام. لافتة حدّ السرعة المعلنة تشير إلى 75 ميلًا في الساعة، ولا أرى أي لافتة منفصلة تحدد حدًا أقل للشاحنات. بحكم العادة من ولاية أخرى، أفترض أن الشاحنات الكبيرة تُلزم تلقائيًا بسرعة شاحنات أبطأ على مستوى الولاية. بموجب قانون تكساس، ما أقصى سرعة يمكنني القيادة بها قانونيًا هنا؟","options":["65 ميلًا في الساعة، لأن الشاحنات في تكساس تُقيّد دائمًا بـ 10 أميال في الساعة أقل من الحد المعلن للسيارات","75 ميلًا في الساعة، الحد المعلن، لأنه لا يُعرض حدّ خاص بالشاحنات لهذا الطريق","70 ميلًا في الساعة، لأن هذه أعلى سرعة يمكن أن تسير بها أي شاحنة تجارية في تكساس","55 ميلًا في الساعة، الحد الافتراضي على مستوى الولاية الذي ينطبق دائمًا على المركبات المجمّعة المحمّلة"],"explanation":"عندما يعلن طريق حدًا للسرعة دون عرض حدّ منفصل للشاحنات، يجب على الشاحنة الالتزام بالحد المعلن مثل أي مركبة أخرى."},"106":{"q":"أنت تقود مركبتك المجمّعة المحمّلة عبر منطقة وسط المدينة وتقترب من تقاطع تكون فيه الإشارة خضراء لك. وأنت تقترب، يخطو أحد المشاة من الرصيف إلى ممر المشاة المُعلّم مباشرةً في مسارك. ماذا يجب أن تفعل؟","options":["تطلق بوقك وتتابع المرور، لأن إشارتك الخضراء تمنحك حق الأولوية على المشاة","تسرّع لتجاوز ممر المشاة بسرعة قبل أن يصل المشاة إلى مسار سيرك","تفسح الطريق للمشاة وتسمح له بإتمام العبور قبل أن تتابع","تتقدم قليلًا داخل ممر المشاة لتشير إلى المشاة بأن ينتظر حتى تعبر"],"explanation":"المشاة الموجود بالفعل في ممر المشاة يملك دائمًا حق الأولوية، لذا يجب أن تفسح له الطريق وتدعه يكمل العبور قبل المتابعة."},"107":{"q":"أنت تقود مركبة مجمّعة محمّلة بوزن 80,000 رطل عبر بلدة غير مألوفة في وقت مبكر من بعد الظهر. وأنت تقترب من منطقة مدرسية معلّمة، تكون أضواء التحذير الصفراء الوامضة نشطة وعدة أطفال يمشون قرب الرصيف. حركة المرور أمامك تتحرك بالسرعة العادية للشارع. ما الإجراء الصحيح؟","options":["الحفاظ على السرعة العادية للشارع لأن تدفق المرور أمامك لم يبطئ من أجل المنطقة","إبقاء قدمك فوق الفرامل لكن مع الحفاظ على سرعتك، وتقليلها فقط إذا خطا طفل فعلًا إلى الطريق","إطلاق البوق على دفعات قصيرة وأنت تمر لتحذير الأطفال من الابتعاد عن حافة الرصيف","تقليل سرعتك إلى حدّ سرعة المنطقة المدرسية المعلن طوال مدة سريان المنطقة"],"explanation":"عندما يكون حدّ سرعة المنطقة المدرسية معلنًا ونشطًا، يجب أن تبطئ إلى ذلك الحد الأدنى وتحافظ عليه طوال المنطقة."},"108":{"q":"أنا أنقل حمولة ثقيلة صعودًا على منحدر طويل على طريق تكساسي سريع بأربعة ممرات، وقد تباطأت شاحنتي إلى ما دون السرعة المعلنة بكثير بينما تتكدس خلفي حركة مرور أسرع. لأقود بشكل قانوني وآمن، أي وضعية ممر يجب أن أستخدمها عمومًا؟","options":["البقاء في الممر الأيمن والسماح للمرور الأسرع بالتجاوز من اليسار","الانتقال إلى الممر الأيسر لإبقاء مسار واضح أمامي","ركوب خط الممر بحيث تتمكن المركبات من تجاوزي من أي جانب","التوقف على جانب الطريق بشكل متكرر حتى تنحسر حركة المرور خلفي"],"explanation":"يجب على الشاحنة الأبطأ البقاء في الممر الأيمن كي تتمكن حركة المرور الأسرع من التجاوز بأمان من اليسار."},"109":{"q":"إنه منتصف بعد الظهر وتوقف جرّارك ومقطورته على الكتف الأيمن لطريق سريع مزدحم بسبب تسرب بطيء في أحد الإطارات. قبل أن تنزل لفحص الإطار، أي جهاز يجب أن تشغّله أولًا لتحذير المرور القادم من الخلف بأن شاحنتك متوقفة؟","options":["إشارة الانعطاف اليسرى، تومض بثبات كي يعرف السائقون أن يتجاوزوا من يسارك","أضواء الخطر (الوامضة الرباعية)، بحيث تنبض المصابيح الأمامية والخلفية معًا","الأضواء العالية، موجّهة إلى الخلف عبر مراياك لجذب انتباه السائقين خلفك","أضواء القبة الداخلية ومصابيح المقصورة، مما يجعل الشاحنة أسهل رؤية من الطريق"],"explanation":"عند التوقف على كتف الطريق، شغّل أضواء الخطر الوامضة الرباعية بحيث تنبض جميع مصابيح الزوايا وتحذّر المرور من الاتجاهين."},"110":{"q":"أقود مركبتي المجمّعة المحمّلة وأصل إلى إشارة حمراء عند تقاطع أريد الانعطاف يمينًا فيه. لا توجد لافتة تمنع الانعطاف عند الإشارة الحمراء، وحركة المرور المتقاطعة قادمة من يساري. أي إجراء يجعل انعطافي يمينًا عند الإشارة الحمراء قانونيًا في تكساس؟","options":["المرور ببطء عبر الإشارة الحمراء دون توقف تام، طالما بقيت تحت سرعة المرور المتقاطع","التعامل مع الإشارة الحمراء كإشارة \"أفسح الطريق\" والاندماج كلما ظهرت فجوة معقولة في المرور المتقاطع","إيقاف المركبة توقفًا تامًا أولًا، ثم الانعطاف فقط عندما يخلو الطريق من المرور والمشاة","البدء بالانعطاف فورًا لأن الانعطاف يمينًا عند الإشارة الحمراء مسموح دائمًا في أي تقاطع"],"explanation":"يتطلب الانعطاف يمينًا عند الإشارة الحمراء التوقف توقفًا تامًا أولًا، ثم الانعطاف فقط عندما يخلو الطريق من المرور والمشاة."},"111":{"q":"أنا أنقل حمولة عبر تكساس في وضح النهار ومتدربي يجلس في المقدمة على مقعد الراكب في المقصورة. وبينما نندمج في الطريق السريع، يسألني إن كان عليه فعلًا ربط حزام الأمان، بما أنه \"مجرد راكب\" وليس من يقود. بموجب قانون تكساس، أي عبارة تصف بشكل صحيح من يجب عليه ارتداء حزام الأمان في شاحنتي؟","options":["أنا فقط، السائق، مُلزم قانونيًا بربط الحزام؛ ويمكن لركاب المقعد الأمامي الركوب دون حزام.","حزام الأمان إلزامي فقط بعد حلول الظلام، لذا لا يحتاج أيّ منا إليه خلال هذه الرحلة النهارية.","لا أحد في مركبة بهذا الثقل ملزم بربط الحزام، لأن كتلة الشاحنة توفر الحماية.","كل من السائق وأي ركاب في المقعد الأمامي ملزمون بموجب القانون بارتداء حزام الأمان."],"explanation":"يفرض قانون تكساس على كل من السائق وأي ركاب في المقعد الأمامي داخل المقصورة ارتداء حزام الأمان."},"112":{"q":"أثناء فحص على جانب الطريق، يجد ضابط زجاجة بيرة نصف ممتلئة مع غطائها مُعاد عليها بشكل غير محكم موضوعة في جيب باب مقصورة شاحنتي. أخبره أنها موجودة هناك منذ ليلة أمس وأنني لم ألمسها أثناء الخدمة. كيف يتعامل قانون تكساس مع هذه العبوة المفتوحة في مقصورة مركبتي التجارية؟","options":["من غير القانوني وجود عبوة مشروب كحولي مفتوحة في المقصورة، بغض النظر عما إذا كانت مغطاة أو ممتلئة أو من كان يشرب منها.","إنه قانوني طالما أن الغطاء مُعاد على الزجاجة والعبوة لا يُشرب منها فعليًا.","إنه مسموح لأن نسبة الكحول في دمي أقل من حدّ 0.04% للرخصة التجارية ولست تحت تأثيرها.","يؤدي فقط إلى تحذير عند المخالفة الأولى، لأن الزجاجة لم تكن في متناول السائق المباشر."],"explanation":"وجود عبوة مشروب كحولي مفتوحة غير قانوني في أي مكان داخل مقصورة المركبة التجارية بمجرد كسر الختم أو نفاد المحتوى، حتى لو أُعيد الغطاء."},"113":{"q":"أنا أنقل محوّلًا صناعيًا عريضًا على شاحنة مسطحة، وبمجرد تثبيته بالسلاسل يبلغ عرض شاحنتي 11 قدمًا ووزنها الإجمالي 92,000 رطل — وكلاهما يتجاوز بوضوح الحدود المعتادة في تكساس. الحمولة نفسها تبقى ضمن طول المقطورة ولا تتدلى من الخلف. قبل أن أنطلق، ماذا تفرض عليّ تكساس فعلًا للتشغيل بشكل قانوني؟","options":["لا يلزم شيء إضافي، لأن الحمولة مؤمّنة بالكامل وتركب بالكامل على المقطورة دون تدلٍّ من الخلف","الحصول على تصريح خاص للحجم/الوزن الزائد، لأن الشاحنة تتجاوز حدود العرض والوزن الإجمالي القانونية التي تسمح بها الرخصة التجارية افتراضيًا","مجرد تثبيت علم أحمر أو برتقالي على أعرض نقطة في الحمولة، مما يغطي قانونيًا تجاوز حدود الأبعاد القياسية","الترتيب دائمًا لمرافقة شرطية، لأن أي شاحنة تتجاوز حدّ الوزن الإجمالي 80,000 رطل يجب أن تُقاد أمامها سلطات إنفاذ القانون"],"explanation":"تسمح الرخصة التجارية افتراضيًا فقط بالحجم والوزن القانونيين؛ والحمولة التي تتجاوز 102 بوصة عرضًا أو 80,000 رطل وزنًا إجماليًا تتطلب تصريحًا خاصًا للحجم/الوزن الزائد."},"114":{"q":"أنا أنقل حمولة قانونية بوزن 78,000 رطل وأقترب من جسر معلن عليه حدّ وزن أقل من وزني الإجمالي. يُظهر نظام تحديد المواقع لمساري أن هذا الجسر هو الطريق المباشر الوحيد إلى مكان تسليمي. ماذا يجب أن أفعل؟","options":["العبور ببطء والبقاء في المنتصف، لأن حدود الوزن المعلنة على الجسر مجرد إرشادات استشارية للتخطيط","العبور على أي حال لأن حمولتي البالغة 78,000 رطل أقل من الحد الأقصى للوزن الإجمالي في الولاية البالغ 80,000 رطل","عدم العبور؛ يجب الالتزام بحدّ وزن الجسر المعلن في جميع الأوقات، لذا عليّ إيجاد طريق بديل أو الحصول على تصريح","العبور لأن الحد المعلن يتضاعف للشاحنات والمقطورات المجمّعة"],"explanation":"يجب الالتزام دائمًا بحدّ وزن الجسر المعلن، وهو يلغي الحد الأقصى العام للولاية، لذا يلزم طريق بديل أو تصريح خاص."},"115":{"q":"أنا أنقل حمولة كبيرة الحجم بتصريح من تكساس. مقطورتي عريضة جدًا لدرجة أنها تتجاوز خط المنتصف وتسد جزءًا من الممر المقابل على طريق سريع ذي ممرين، والتصريح يحدد شروطًا يجب أن ألتزم بها قبل الرحلة. أي من هذه الشروط يُرجّح أن تفرضها عليّ حمولة بهذا العرض؟","options":["فرامل عاملة على كل محور من محاور الحمولة","علم أحمر على أي جزء من الحمولة يبرز أكثر من 4 أقدام","لا علامات خاصة، لأن التصريح وحده يخوّلني للتحرك","مركبة مرافقة أو مركبة استطلاع لتحذير السائقين الآخرين من العرض"],"explanation":"الحمولة العريضة بما يكفي للتعدي على الممر المقابل تتطلب قانونيًا مركبة مرافقة أو مركبة استطلاع لتحذير المرور القادم من العرض."},"116":{"q":"أنا أنقل حمولة كبيرة الحجم عبر تكساس بموجب تصريح من الولاية، والتصريح يحدد قيودًا معينة على وقت الحركة خلال اليوم. لأبقى ضمن القانون، متى يُسمح لي عمومًا بتحريك هذه الحمولة؟","options":["فقط خلال ساعات نهارية معينة يحددها التصريح","فقط بين منتصف الليل والفجر، عندما تكون حركة المرور أخف","في أي وقت من النهار أو الليل، طالما أشغّل أضوائي الوامضة","فقط أيام السبت والأحد، عندما تكون الطرق أقل ازدحامًا"],"explanation":"عادةً ما تقتصر حركة الحمولات كبيرة الحجم بموجب تصريح تكساس على ساعات نهارية محددة لأن رؤية الحمولة والمناورة حولها أصعب على الآخرين."},"117":{"q":"أنا أنقل حمولة عريضة تتجاوز عرض 102 بوصة القانوني، وأسافر بموجب تصريح خاص على طريق تكساسي سريع ذي ممرين. لتحذير السائقين الآخرين والبقاء ضمن القانون، أي مجموعة من العلامات يجب أن تعرضها مركبتي وحمولتي؟","options":["أضواء زرقاء ثابتة مركّبة على كل زاوية من الحمولة لتنبيه المرور القادم","أعلام حمراء أو برتقالية عند أعرض النقاط بالإضافة إلى لافتات \"حمولة كبيرة الحجم\" في الأمام والخلف","مثلث برتقالي للمركبات البطيئة على الجزء الخلفي من الحمولة فقط","ثلاثة مثلثات تحذيرية عاكسة مثبتة على خلفية المقطورة"],"explanation":"يجب أن تعرض الحمولة التي يزيد عرضها عن 102 بوصة أعلامًا حمراء أو برتقالية عند أعرض نقاطها بالإضافة إلى لافتات \"حمولة كبيرة الحجم\" في الأمام والخلف."},"118":{"q":"إرسال الرسائل النصية أثناء قيادة مركبة تجارية:","options":["مسموح به عند السرعة المنخفضة","ممنوع","لا بأس به في حركة المرور البطيئة","محظور ليلًا فقط"],"explanation":"إرسال الرسائل النصية أثناء قيادة مركبة تجارية ممنوع."},"119":{"q":"أثناء فحص على جانب الطريق، يجد ضابط عيبًا في فرامل شاحنتي ويلصق عليها ملصق \"خارج الخدمة\". محطتي التابعة لي على بعد 6 أميال فقط على الطريق وحمولتي حساسة للوقت. أي إجراء يمنعني أمر \"خارج الخدمة\" من اتخاذه؟","options":["غسل أوساخ الطريق عن الشاحنة بينما أنتظر وصول طاقم الإصلاح","ترك الشاحنة متوقفة على كتف الطريق حتى يتمكن ميكانيكي من القدوم إليها","قيادة الشاحنة مسافة 6 أميال إلى محطتي قبل إصلاح عيب الفرامل","السماح لضابط ثانٍ بإعادة فحص الشاحنة بعد انتهاء الفحص الأول"],"explanation":"يجب عدم قيادة المركبة الموضوعة خارج الخدمة حتى يتم إصلاح العيب المذكور، بغض النظر عن المسافة أو إلحاح الحمولة."},"120":{"q":"أنا أقود رحلة طويلة عبر تكساس وقد تأخرت في سجلي الورقي لحالة الخدمة (دفتر السجل). لتوفير الوقت، أفكّر في إعادة تكوين الأسبوع كله من ذاكرتي مساء الأحد وكتابته دفعة واحدة. يستوقفني مفتّش لفحص على جانب الطريق يوم الخميس. فيما يتعلق بكيفية الاحتفاظ بدفتر سجلي، أي عبارة صحيحة؟","options":["يكفي إكماله مرة واحدة شهريًا، لذا لا بأس من إظهار صفحات الشهر الماضي المكتملة للمفتّش","طالما أجمع ساعاتي في نهاية كل أسبوع، فإن ترك الشبكة اليومية فارغة في معظمها مقبول","الاحتفاظ بدفتر السجل اختياري في تكساس طالما بقيت تحت الوزن الإجمالي الأقصى البالغ 80,000 رطل","يجب الاحتفاظ به محدّثًا ودقيقًا حتى آخر تغيير في حالة الخدمة، لذا إعادة تكوينه لاحقًا غير مقبولة"],"explanation":"يجب الاحتفاظ بسجل حالة خدمة السائق محدّثًا ودقيقًا حتى آخر تغيير في حالة الخدمة، لذا فإن إعادة تكوينه لاحقًا من الذاكرة غير مسموح بها."},"121":{"q":"أنا أحمّل شاحنتي المسطحة في محجر بتكساس ويقول مرسلي إنه يمكنني السير على طرق تكساس السريعة العادية دون شراء أي تصريح خاص، طالما بقيت ضمن الحدود القانونية القياسية. لأبقى ضمن القانون دون تصريح، أي مما يلي يجب أن ألتزم به؟","options":["يجب أن يبقى وزني الإجمالي، الشاحنة زائد الحمولة، عند 80,000 رطل أو أقل","لا يوجد سقف للوزن الإجمالي طالما أن محاوري متباعدة","يمكن تحميل مقطورتي حتى ارتفاع 102 بوصة قبل أن أحتاج إلى تصريح","يمكن أن يصل عرضي الكلي إلى 14 قدمًا قبل اشتراط التصريح"],"explanation":"تحدّ تكساس الوزن الإجمالي (الشاحنة زائد الحمولة) عند 80,000 رطل دون تصريح خاص، لذا يجب أن تبقى عند ذلك الحد أو أقل."},"122":{"q":"أثناء فحص ما قبل الرحلة، أتحقق من أن جرّاري ومقطورتي يحملان معدات الطوارئ التي تفرضها تكساس قبل مغادرة الساحة. أي مجموعة أدناه تسرد العناصر التي يجب أن تكون لديّ على متن المركبة لأكون قانونيًا؟","options":["ثلاثة مثلثات تحذيرية وطفاية حريق مشحونة، لكن الفيوزات الاحتياطية اختيارية في الشاحنات الأحدث","ثلاثة مثلثات تحذيرية، وطفاية حريق مشحونة، وفيوزات كهربائية احتياطية (ما لم تكن الشاحنة بلا فيوزات)","طفاية حريق مشحونة، وفيوزات احتياطية، ومجموعة شعلات طريق بدلًا من المثلثات","ثلاثة مثلثات تحذيرية، وفيوزات احتياطية، وحقيبة إسعافات أولية بدلًا من طفاية الحريق"],"explanation":"يجب أن تحمل المركبة التجارية ثلاثة عناصر طوارئ مطلوبة: طفاية حريق مشحونة، وفيوزات كهربائية احتياطية (ما لم تكن بلا فيوزات)، وثلاثة مثلثات تحذيرية."},"123":{"q":"أنا أنقل حمولة في مركبة مجمّعة محمّلة عبر طريق ريفي بمقاطعة في تكساس وأصل إلى جسر معلن عليه حدّ وزن أقل من وزني الإجمالي. أي مما يلي يسمح لي قانونيًا بالعبور رغم ذلك؟","options":["يمكنني العبور لأن وزني الإجمالي لا يزال تحت الحد الأقصى المسموح به على طرق تكساس البالغ 80,000 رطل.","يمكنني العبور إذا تمكنت من التحقق من أن الجسر بُني ليتحمل أكثر بكثير من حدّه المعلن.","لا شيء هنا يجعله قانونيًا؛ لا يجوز تجاهل حدّ الوزن المعلن دون تصريح فعلي من السلطة.","يمكنني العبور لأن كوني تحت حدّ المحور المزدوج البالغ 34,000 رطل يعني أن حدّ الجسر المعلن لا ينطبق عليّ."],"explanation":"حدّ الوزن المعلن ملزم قانونيًا ويلغي الحدود القصوى العامة للطرق السريعة؛ ولا يجوز لك تجاوزه إلا بتصريح فعلي من السلطة."},"124":{"q":"قبل ثماني سنوات فقدت رخصتي التجارية في تكساس بموجب إيقاف مدى الحياة لاستخدامي شاحنتي التجارية في تصنيع وتوزيع مادة خاضعة للرقابة. وقد أكملت منذ ذلك الحين برنامج إعادة تأهيل بأمر من المحكمة، وحافظت على سجل نظيف، ودفعت كل الغرامات. أريد استعادة رخصتي التجارية لأعود إلى القيادة بين الولايات. بموجب قواعد تكساس، ماذا يمكنني أن أتوقع فعلًا بشأن إعادة الترخيص؟","options":["بعد 10 سنوات يمكنني تقديم التماس إلى إدارة السلامة العامة لإعادة الترخيص إذا بقي سجلي نظيفًا","إكمال برنامج إعادة التأهيل يعيد تلقائيًا أهليتي للرخصة التجارية","يتحول الحظر مدى الحياة إلى إيقاف لمدة 3 سنوات لأنه شمل حمولة من نوع المواد الخطرة","لا يُعاد الترخيص أبدًا، لأن إيقاف جناية المخدرات مدى الحياة دائم"],"explanation":"إيقاف جناية المخدرات مدى الحياة دائم ولا يُعاد الترخيص أبدًا، بغض النظر عن إعادة التأهيل أو نظافة السجل أو الوقت المنقضي."},"125":{"q":"أنت تقود مركبتك التجارية في المسار الأيمن من طريق سريع تكساسي بأربعة مسارات عندما تلاحظ شاحنة تابعة لإدارة النقل في تكساس (TxDOT) متوقفة على الكتف أمامك مع وميض أضوائها الكهرمانية. حركة المرور الكثيفة في المسار الأيسر تجعل تغيير المسار غير آمن. بموجب قانون تكساس \"تنحَّ جانباً / خفّف السرعة\"، ماذا يجب أن تفعل؟","options":["ابقَ في مسارك ولكن خفّف السرعة، بما أنك لا تستطيع التنحّي جانباً بأمان","حافظ على سرعتك لأن القانون ينطبق فقط على الشرطة وسيارات الإسعاف","حافظ على سرعتك وامنح الشاحنة ببساطة مساحة إضافية ضمن مسارك","توقّف توقفاً تاماً في مسارك حتى تبتعد الشاحنة المتوقفة"],"explanation":"عندما لا تستطيع تغيير المسارات بأمان لمركبة طوارئ أو شرطة أو قطر أو TxDOT متوقفة بأضواء وامضة، يجب أن تخفّف السرعة بدلاً من ذلك."},"126":{"q":"أنا أقود شاحنتي على طريق سريع بأربعة مسارات عندما أرى مركبة متوقفة على الكتف الأيمن مع وميض أضوائها الكهرمانية. ليست سيارة شرطة أو إسعاف أو إطفاء. بموجب قانون تكساس \"تنحَّ جانباً / خفّف السرعة\"، أي مركبة متوقفة لا تزال تتطلب مني الانتقال مساراً واحداً أو تخفيف السرعة؟","options":["سيارة ركاب متوقفة على الكتف مع وميض أضواء الخطر الرباعية","شاحنة قطر أو مركبة TxDOT تعرض أضواء وامضة","شاحنة توصيل بريد متوقفة عند صندوق بريد على جانب الطريق مع إضاءة المصباح الداخلي","شاحنة بيك أب شخصية لعامل بناء متوقفة خارج الرصيف"],"explanation":"يشمل قانون \"تنحَّ جانباً / خفّف السرعة\" أيضاً شاحنات القطر ومركبات TxDOT المتوقفة التي تعرض أضواء وامضة، وليس فقط الشرطة والإطفاء والإسعاف."},"127":{"q":"أنا أقود مركبتي التجارية في المسار الأيمن على طريق سريع بسرعة 65 ميلاً في الساعة عندما أرى شاحنة TxDOT متوقفة على الكتف مع وميض أضوائها الكهرمانية. حركة المرور الكثيفة في المسار الأيسر تجعل التنحّي جانباً غير آمن، لذا عليّ البقاء في مساري عند المرور. بموجب قانون تكساس \"تنحَّ جانباً / خفّف السرعة\"، إلى أي سرعة يجب أن أخفّف قبل الوصول إلى المركبة المتوقفة؟","options":["65 ميلاً في الساعة، بما أنه يحق لي قانونياً الحفاظ على الحد المسموح به عندما لا أستطيع تغيير المسار بأمان","5 أميال في الساعة دون الحد، وهو الهامش المطلوب كلما كان هناك عامل بجانب الطريق","45 ميلاً في الساعة، وهي 20 ميلاً في الساعة دون حد السرعة المسموح به لهذا المقطع من الطريق السريع","25 ميلاً في الساعة، وهي السرعة الدنيا الثابتة للمرور المحددة لجميع مركبات الطوارئ المتوقفة"],"explanation":"عندما لا تستطيع تغيير المسارات بأمان، يجب أن تخفّف السرعة إلى 20 ميلاً في الساعة دون الحد المسموح به، وهو ما يعني على طريق سريع بسرعة 65 ميلاً في الساعة 45 ميلاً في الساعة."},"128":{"q":"أنا أُنهي رحلة توصيل مع حلول المساء في تكساس، وقد غابت الشمس للتو تحت الأفق. لا يزال هناك بعض الضوء، لذا فإن مصابيحي الأمامية مطفأة. بموجب قانون تكساس، بحلول أي وقت يُطلب مني قانونياً تشغيل المصابيح الأمامية؟","options":["لحظة ملامسة الشمس للأفق عند الغروب، ويجب أن تبقى مشغّلة حتى لحظة ظهور الشمس عند الشروق","فقط بمجرد حلول الظلام الكامل وعدم تمكني من الرؤية لمسافة 500 قدم على الأقل أمام مركبتي","خلال 30 دقيقة قبل الغروب، بما أن الغسق يقلل الرؤية قبل غياب الشمس بوقت طويل","في موعد لا يتجاوز 30 دقيقة بعد الغروب، ويجب أن تبقى مشغّلة حتى 30 دقيقة قبل الشروق"],"explanation":"يتطلب قانون تكساس تشغيل المصابيح الأمامية من 30 دقيقة بعد الغروب حتى 30 دقيقة قبل الشروق، وكلما لم تتمكن من الرؤية بوضوح لمسافة 1000 قدم على الأقل."},"129":{"q":"يتدفق ضباب كثيف بينما أنقل حمولة على طريق سريع ريفي ذي مسارين عند منتصف النهار. لا تزال الشمس مرتفعة، لذا تُظهر ساعة لوحة القيادة أن المصابيح الأمامية ليست مطلوبة بعد بموجب قاعدة وقت اليوم. ما هي أقل مسافة رؤية واضحة أمامك يسمح بها قانون تكساس بالقيادة قانونياً دون تشغيل المصابيح الأمامية؟","options":["1000 قدم — دون ذلك يجب أن أشغّل المصابيح الأمامية، بغض النظر عن وقت اليوم","500 قدم — دون ذلك يجب أن أشغّل المصابيح الأمامية، بغض النظر عن وقت اليوم","200 قدم — دون ذلك يجب أن أشغّل المصابيح الأمامية، بغض النظر عن وقت اليوم","100 قدم — دون ذلك يجب أن أشغّل المصابيح الأمامية، بغض النظر عن وقت اليوم"],"explanation":"تُطلب المصابيح الأمامية في أي وقت لا تتمكن فيه من الرؤية بوضوح لمسافة 1000 قدم على الأقل، بصرف النظر عن وقت اليوم، لذا فإن الضباب الذي يقلل الرؤية يتطلبها."},"130":{"q":"أنا أقترب من تقاطع في شاحنتي المقطورة وأخطط للانعطاف يميناً. للامتثال لقواعد الإشارة في تكساس، ما هي أقل مسافة يجب أن أُبقي خلالها إشارة الانعطاف مشغّلة بشكل متواصل قبل أن أبدأ الانعطاف؟","options":["على الأقل 10 أقدام قبل الانعطاف","على الأقل 100 قدم قبل الانعطاف","على الأقل 200 قدم قبل الانعطاف","على الأقل مربع سكني كامل قبل الانعطاف"],"explanation":"يتطلب قانون تكساس الإشارة بشكل متواصل خلال آخر 100 قدم قبل الانعطاف لتحذير مستخدمي الطريق الآخرين."},"131":{"q":"أنا أحمّل مقطورة مسطحة لرحلة عبر تكساس وأريد البقاء قانونياً دون التقدم بطلب للحصول على تصريح للحمولة الكبيرة الحجم. حمولتي موضوعة على المقطورة وأتحقق من مقدار بروزها إلى كل جانب. لتجنّب الحاجة إلى تصريح، يجب ألا يتجاوز العرض الإجمالي لمركبتي وحمولتي مقيساً من الحافة الخارجية إلى الحافة الخارجية:","options":["14 قدماً، وهو نفس الحد الأقصى للارتفاع","8 أقدام بالضبط، مقيساً عند أعرض نقطة","8 أقدام و6 بوصات، مقيساً عند أعرض نقطة","10 أقدام، بما في ذلك أي بروز للحمولة على الجوانب"],"explanation":"الحد الأقصى القانوني لعرض المركبة والحمولة في تكساس هو 102 بوصة، أو 8 أقدام و6 بوصات، مقيساً عند أعرض نقطة؛ وأي شيء أعرض يحتاج إلى تصريح للحمولة الكبيرة الحجم."},"132":{"q":"أنا أنقل حمولة من الآلات المكدّسة على مقطورة مسطحة وأحتاج إلى تخطيط مسار عبر تكساس يتجنّب الجسور العلوية المنخفضة. قبل أن أتقدم بطلب للحصول على تصريح للحمولة الكبيرة الحجم، أريد التأكد من الحد القانوني لأعرف ما إذا كنت بحاجة إليه أصلاً. ما هو الحد الأقصى للارتفاع الإجمالي للمركبة الذي يمكنني تشغيله قانونياً في تكساس دون تصريح خاص؟","options":["12 قدماً و6 بوصات مقيساً من الأرض إلى أعلى نقطة في الحمولة","13 قدماً، بما أن ذلك هو الخلوص القياسي الذي بُنيت عليه معظم الجسور العلوية","8 أقدام و6 بوصات مقيساً عند أعرض نقطة في المركبة والحمولة","14 قدماً مقيساً من الأرض إلى أعلى نقطة في الحمولة"],"explanation":"الحد الأقصى القانوني لارتفاع المركبة في تكساس هو 14 قدماً، مقيساً من الأرض إلى أعلى نقطة في المركبة أو الحمولة؛ وأي شيء أطول يحتاج إلى تصريح للحمولة الكبيرة الحجم."},"133":{"q":"الظلام يحلّ وأنا أنقل عوارض فولاذية تبرز نحو 6 أقدام خلف مؤخرة مقطورتي المسطحة. كان لديّ علم برتقالي على طرف العوارض طوال اليوم. مع انخفاض الرؤية عند الغسق، ماذا أحتاج أن أضيف للبقاء قانونياً في تكساس؟","options":["ضوء أحمر يحدد مؤخرة الحمولة، لأنها تمتد أكثر من 4 أقدام خلف المؤخرة","ضوء كهرماني يحدد المؤخرة، لأن الكهرماني هو لون التحذير القياسي للأحمال البارزة","لا شيء إضافي؛ العلم البرتقالي كافٍ طالما أن العوارض أقل من 8 أقدام بروزاً","ضوء أحمر فقط إذا كان البروز أكثر من 4 بوصات خلف مؤخرة المقطورة"],"explanation":"يجب أن تُحدَّد الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة بضوء أحمر ليلاً أو كلما انخفضت الرؤية."},"134":{"q":"الكتابة على الهاتف أثناء القيادة في تكساس هي:","options":["مسموحة على الطرق السريعة","غير قانونية لجميع السائقين","مقبولة إذا كنت تسير ببطء","ممنوعة فقط ليلاً"],"explanation":"الكتابة على الهاتف أثناء القيادة غير قانونية على مستوى الولاية."},"135":{"q":"في منطقة مدرسية في تكساس، استخدام هاتف محمول باليد أثناء القيادة هو:","options":["مُشجَّع عليه","ممنوع","مطلوب","مُكافأ عليه"],"explanation":"الهواتف المحمولة باليد ممنوعة في المناطق المدرسية النشطة."},"136":{"q":"يتطلب قانون تكساس سلاسل الأمان عندما تكون:","options":["تركن في منحدر صاعد","تقطر مقطورة","تتزوّد بالوقود","متوقفاً في حالة سكون"],"explanation":"سلاسل الأمان مطلوبة عند قطر مقطورة."},"137":{"q":"يوقفني شرطي تكساسي على الطريق I-35 ويطلب مني إثبات أنني أستوفي شرط \"المسؤولية المالية\" الذي تفرضه الولاية للشاحنة التي أقودها. لتلبية هذا القانون، ماذا يجب أن أتمكّن من إظهاره؟","options":["بطاقة ائتمان رئيسية سارية بحد متاح كافٍ لتغطية الأضرار","إثبات تأمين المسؤولية الذي يغطي الإصابة الجسدية والأضرار في الممتلكات","اتفاقية قرض مصرفي موقّعة تُظهر تمويلاً على المركبة التجارية","نقداً كافياً بحوزتي لدفع أي ضرر قد أتسبب فيه في حادث"],"explanation":"تتحقق المسؤولية المالية في تكساس بحمل تأمين المسؤولية الذي يغطي الإصابة الجسدية والأضرار في الممتلكات."},"138":{"q":"أنا أقود شاحنتي المقطورة عبر المدينة عندما تخرج شاحنة إطفاء بصفّارتها وأضوائها مشغّلة إلى الطريق أمامي، تستجيب بوضوح لإنذار. أقرر مواصلة المسار نفسه خلفها. بموجب قانون تكساس، ما هي أقل مسافة يجب أن أبقى خلالها خلف شاحنة الإطفاء المستجيبة؟","options":["على الأقل 50 قدماً خلفها","على الأقل 200 قدم خلفها","على الأقل 500 قدم خلفها","على الأقل 100 قدم خلفها"],"explanation":"يمنع قانون تكساس اتباع شاحنة إطفاء تستجيب لإنذار على مسافة أقرب من 500 قدم."},"139":{"q":"أبحث عن مكان لأركن فيه شاحنتي على شارع في المدينة والفتحة الوحيدة التي أراها هي بجوار صنبور إطفاء مباشرة. للبقاء قانونياً في تكساس، كم خلوص يجب أن أُبقي بين مركبتي وذلك الصنبور؟","options":["على الأقل 50 قدماً، وهو نفس الهامش المستخدم عند معبر السكة الحديدية","على الأقل 5 أقدام، بما يكفي لإبقاء الصنبور في متناول اليد","على الأقل 10 أقدام، مطابقاً لمسافة مثلث التحذير الأول","على الأقل 15 قدماً من صنبور الإطفاء"],"explanation":"يمنع قانون تكساس الركن على مسافة أقل من 15 قدماً من صنبور الإطفاء حتى تتمكن فرق الإطفاء من الوصول إليه في حالة الطوارئ."},"140":{"q":"أنا أنقل حمولة من العوارض الفولاذية تجعل مجموعتي بوزن إجمالي 86000 رطل وعرض 9 أقدام، وهو ما يتجاوز الحدود القانونية لطرق تكساس السريعة. قبل أن أتمكّن قانونياً من القيام بهذه الرحلة، ماذا يجب أن أفعل؟","options":["الحصول على تصريح للحمولة الكبيرة الحجم / الزائدة الوزن قبل الرحلة","ترتيب مرافقة شرطية، وهي مطلوبة دائماً لتجاوز الحدود","لا شيء إضافي، بما أن الشاحنة دون الحد الأقصى للعرض البالغ 102 بوصة","لا شيء إضافي، طالما بقي الوزن الإجمالي دون 80000 رطل"],"explanation":"الحمولة الأعرض من 102 بوصة أو الأثقل من 80000 رطل تتطلب تصريحاً للحمولة الكبيرة الحجم / الزائدة الوزن قبل الرحلة."},"141":{"q":"أثناء تفتيش على جانب الطريق في تكساس، يجد ضابط زجاجة بيرة نصف فارغة محشورة خلف مقعدي. أخبره أن الغطاء موضوع عليها بشكل غير محكم، وأنني لم أشرب منذ أكثر من 6 ساعات، وأنني كنت متوقفاً تماماً في استراحة. بموجب قانون تكساس، ما هو وضعي بخصوص تلك العبوة؟","options":["لا بأس، لأن إعادة وضع الغطاء على الزجاجة يُغلقها قانونياً ويزيل مخالفة العبوة المفتوحة","لا يزال غير قانوني، لأن أي عبوة كحول مفتوحة في مقصورة مركبة تجارية ممنوعة بغض النظر عن وضع الغطاء أو الصحو أو التوقف","لا بأس، لأنني كنت متوقفاً ولست أقود فعلياً عند العثور على العبوة","أحصل على تحذير فقط، بما أن 6 ساعات تتجاوز بكثير نافذة الـ4 ساعات لعدم الشرب لسائقي رخصة القيادة التجارية"],"explanation":"حيازة أي عبوة كحول مفتوحة في مقصورة مركبة تجارية ممنوعة، بغض النظر عن وضع الغطاء أو الصحو أو التوقف."},"142":{"q":"أنا أُجري فحصاً قبل الرحلة على قطعة من معدات الدعم الزراعي تبلغ سرعتها القصوى زحفاً، ويذكّرني شرطي ولاية بأن أي مركبة مُصمَّمة للسير عند سرعة معينة أو دونها يجب أن تعرض شعار المركبة بطيئة الحركة (SMV) المثلث البرتقالي على المؤخرة. عند أي سرعة تصميمية أو دونها يتطلب تكساس ذلك الشعار؟","options":["10 أميال في الساعة، لأن تلك هي سرعة الزحف المستخدمة لتعريف المعدات التي لا تستطيع قانونياً مواكبة حركة المرور","20 ميلاً في الساعة، مطابقاً للسرعة المنخفضة التي يجب أن تخفّف إليها عند المرور بمركبة طوارئ متوقفة","25 ميلاً في الساعة، لأن شعار SMV مطلوب على أي مركبة مُصمَّمة للسير عند تلك السرعة أو دونها","30 ميلاً في الساعة، لأن دون تلك السرعة تُعامَل المركبة كخطر بطيء الحركة على الطرق العامة"],"explanation":"شعار المركبة بطيئة الحركة المثلث البرتقالي مطلوب على أي مركبة مُصمَّمة للسير عند 25 ميلاً في الساعة أو أقل."},"143":{"q":"أنت تقود مركبتك التجارية عبر تقاطع مزدحم في وسط مدينة في تكساس. هناك عدة مشاة قريبون. بموجب قانون تكساس، لأي مشاة يُطلب منك قانونياً إفساح حق الطريق؟","options":["مشاة ينتظر على الرصيف ولم يخطُ بعد إلى الشارع","مشاة يقف بعيداً أسفل المربع السكني على الزاوية المقابلة","مشاة يسير على الكتف عكس اتجاه حركة المرور","مشاة يعبر ضمن ممر مشاة مُعلَّم أمامك"],"explanation":"يجب على السائق إفساح حق الطريق والتوقف لمشاة يعبر ضمن ممر مشاة مُعلَّم في مساره."},"144":{"q":"أنا أنقل حمولة عبر تكساس ويركب معي زميل في شاحنتي. هو جالس في حجرة النوم في الخلف ويخبرني أن قانون الحزام ينطبق فقط على من يقود. بصفتي مشغّل رخصة القيادة التجارية، أي عبارة تعكس بشكل صحيح ما يتطلبه فعلاً قانون حزام الأمان في تكساس منا؟","options":["يجب على كل راكب في المركبة أن يكون مربوطاً بالحزام بشكل صحيح، وليس السائق فقط","السائق وحده هو المطالب قانونياً بارتداء حزام الأمان أثناء سير الشاحنة","أحزمة الأمان مطلوبة فقط للركاب الجالسين في المقعد الأمامي","لا أحد مطالب بربط الحزام طالما أن الشاحنة بها وسائد هوائية تعمل"],"explanation":"يتطلب قانون تكساس أن يكون كل راكب في المركبة مربوطاً بالحزام بشكل صحيح، وليس السائق فقط."},"145":{"q":"أنا أقود مركبتي التجارية على طريق ذي مسارين في تكساس عندما تتوقف حافلة مدرسية أمامي، وتُفعّل أضواءها الحمراء الوامضة المتناوبة، وتمدّ ذراع التوقف. حركة المرور خفيفة وأنا متأخر عن الجدول الزمني. أي عبارة تصف بأفضل شكل ما يحدث إذا تجاوزت الحافلة بينما تومض تلك الأضواء الحمراء؟","options":["لا شيء، طالما أنني خفّفت السرعة إلى 20 ميلاً في الساعة دون الحد المسموح به أثناء المرور بالحافلة","أواجه غرامة كبيرة، لأن التجاوز غير القانوني لحافلة مدرسية متوقفة وأضواؤها الحمراء تومض مخالفة سير خطيرة في تكساس","لا شيء، لأن التوقف ينطبق فقط على سيارات الركاب، وليس على مركبة تجارية في المسار المقابل","أحصل على تحذير مكتوب، بما أن هذا يُعامَل كأول مخالفة سير خطيرة"],"explanation":"التجاوز غير القانوني لحافلة مدرسية متوقفة وأضواؤها الحمراء تومض مخالفة سير خطيرة تترتب عليها غرامات كبيرة في تكساس."},"146":{"q":"أثناء قيادة شاحنتي المقطورة عبر تكساس، أتورّط في اصطدام بسيط في موقف للسيارات وأحاول تحديد ما إذا كان مطلوباً مني قانونياً الإبلاغ عن الحادث للشرطة. في أي من المواقف التالية يُطلب مني تقديم البلاغ؟","options":["فقط عندما تلتقط شاحنتي خدشاً صغيراً في الطلاء وتبقى قابلة للقيادة تماماً بعد ذلك","فقط عندما يكون الاصطدام مدوّياً بما يكفي ليلتفت المارّة إلى الضجيج","عندما يسفر الحادث عن إصابة أو وفاة أو ضرر كبير في الممتلكات","فقط عندما يتعيّن عليّ تبديل إطار قبل أن أتمكّن من متابعة مساري"],"explanation":"يتطلب قانون تكساس الإبلاغ عن الحادث للشرطة كلما تسبب في إصابة أو وفاة أو ضرر كبير في الممتلكات."},"147":{"q":"أنا أقود مجموعة محمّلة بوزن 80000 رطل على طريق سريع في تكساس في حركة مرور كثيفة، والسيارة التي أمامي تواصل الكبح. لإدارة المساحة أمام شاحنتي بأمان، ماذا يجب أن أفعل؟","options":["ابقَ قريباً خلف السيارة حتى لا يتمكن السائقون الآخرون من اقتطاع الفجوة والازدحام عليّ","طابق مصدّمي الأمامي مع المركبة التي أمامي حتى لا أفقد مكاني أبداً في المسار","تراجع بما يكفي فقط لإبقاء أقل من طول سيارة من الطريق المفتوح أمامي","افتح المسافة وحافظ على فجوة اتباع آمنة أمامك حتى يكون لديك متسع للتوقف في الوقت المناسب"],"explanation":"الشاحنة الثقيلة المحمّلة تحتاج إلى مسافة توقف أكبر بكثير، لذا حافظ على فجوة اتباع مفتوحة أمامك مع متسع للتوقف في الوقت المناسب."},"148":{"q":"أنا أُجري فحص ما قبل الرحلة على مقطورة مسطحة عريضة قبل رحلة ليلية عبر تكساس، أتحقق من أن العلامات العاكسة قانونية. عاملاً من مؤخرة المقطورة تماماً، أي عاكسات يجب أن أتأكد من أنها مثبّتة موجّهة نحو الخلف؟","options":["عاكسان أحمران","عاكسان كهرمانيان","عاكس أحمر واحد وعاكس كهرماني واحد","عاكسان أخضران"],"explanation":"يتطلب تكساس أن تعرض مؤخرة الشاحنة أو المقطورة العريضة عاكسين أحمرين حتى يُحدَّد عرضها الكامل ليلاً."},"149":{"q":"أنا أقود مركبة تجارية على مسارات محلية فقط داخل تكساس ولا أغادر الولاية أبداً، لذا عادةً ما أترك رخصة القيادة التجارية في المنزل في مكان آمن وآخذها فقط عندما أتوقّع عبور حدود ولاية. بموجب قواعد تكساس، متى يُطلب مني فعلاً أن تكون رخصة القيادة التجارية معي جسدياً؟","options":["فقط عندما أشغّل المركبة التجارية خارج تكساس أو على مسار بين الولايات","في أي وقت أُشغّل فيه مركبة تجارية، بما في ذلك الرحلات المحلية داخل الولاية","فقط عندما يشير إليّ ضابط من إدارة السلامة العامة (DPS) بالتوقف لتفتيش على جانب الطريق","فقط خلال الساعات بين 30 دقيقة بعد الغروب و30 دقيقة قبل الشروق"],"explanation":"يجب حمل رخصة القيادة التجارية كلما شغّلت مركبة تجارية، بما في ذلك الرحلات المحلية القصيرة داخل تكساس."},"150":{"q":"لقد بلغت للتو 18 عامًا وحصلت على رخصة القيادة التجارية (CDL) في تكساس. عرضت عليّ شركة محلية وظيفة لنقل مواد البناء بين مواقع العمل، لكن كل المسارات تبقى بالكامل داخل تكساس، والحمولة لا تحمل أبدًا مواد خطرة (HazMat) موضوعًا عليها لافتات. يصرّ عمّي على أنني ما زلت صغيرًا جدًا قانونيًا على القيادة. استنادًا إلى قواعد السن في تكساس للقيادة التجارية، أي عبارة صحيحة؟","options":["عمّي محق: يضع قانون الولاية الحدّ الأدنى عند 21 عامًا لأي مركبة تجارية، لذا يجب أن أنتظر ثلاث سنوات أخرى قبل القيادة.","يمكنني القيادة الآن، لكن فقط لأن نقل مواد البناء معفى من شرط السن التجاري المعتاد.","يمكنني قانونيًا قيادة هذه المسارات داخل الولاية الآن، لأن 18 عامًا هو الحد الأدنى للسن لتشغيل مركبة تجارية داخل الولاية (داخل تكساس فقط).","يجب أن أبلغ 25 عامًا قبل أن تتمكن شركة قانونيًا من توظيفي لتشغيل أي مركبة آلية تجارية في تكساس."],"explanation":"تحدد تكساس الحد الأدنى لسن تشغيل مركبة آلية تجارية داخل الولاية، بالكامل ضمن حدود الولاية، عند 18 عامًا."},"151":{"q":"عمري 19 عامًا وأحمل رخصة قيادة تجارية (CDL) سارية من تكساس استخدمتها لمدة عام في نقل البضائع بين هيوستن ودالاس. عرضت عليّ شركة رحلة طويلة المدى تعبر إلى لويزيانا وتعود. هل يمكنني قانونيًا القيام بهذه الرحلة بين الولايات، وإن لم يكن كذلك، فلماذا؟","options":["نعم — بمجرد أن تحمل رخصة قيادة تجارية سارية من تكساس، فهي صالحة للقيادة في أي ولاية بغض النظر عن سنك.","نعم — طالما لديك سنة واحدة على الأقل من خبرة قيادة المركبات التجارية داخل الولاية، يمكنك القيادة عبر حدود الولايات.","لا — يجب أن تبلغ أولًا 18 عامًا، وهو الحد الأدنى للسن الذي يضعه القانون لعبور حدود ولاية أخرى.","لا — تتطلب القيادة التجارية بين الولايات عبر حدود الولايات حدًا أدنى للسن قدره 21 عامًا، رغم أن 18 عامًا كافية للقيادة داخل الولاية في تكساس."],"explanation":"تتطلب القيادة التجارية بين الولايات عبر حدود الولايات حدًا أدنى للسن قدره 21 عامًا، رغم أن 18 عامًا كافية للقيادة داخل الولاية في تكساس."},"152":{"q":"بعد تصادم بسيط في هيوستن، يسأل محامي السائق الآخر عن الحد الأدنى المطلوب قانونيًا لتغطية المسؤولية عن الإصابات الجسدية في وثيقة تأميني التجارية لأي شخص واحد يُصاب في الحادث. للبقاء ممتثلًا للحد الأدنى في تكساس، ما هو أقل مبلغ لكل شخص يمكن أن تحمله وثيقتي؟","options":["30,000 دولار للإصابة الجسدية لأي شخص واحد","10,000 دولار للإصابة الجسدية لأي شخص واحد","5,000 دولار للإصابة الجسدية لأي شخص واحد","100,000 دولار للإصابة الجسدية لأي شخص واحد"],"explanation":"تحدد تكساس الحد الأدنى لتغطية المسؤولية عن الإصابات الجسدية بمبلغ 30,000 دولار للإصابة لأي شخص واحد."},"153":{"q":"تم إيقافي أثناء قيادة مركبتي التجارية في تكساس، ويطلب مني الضابط إجراء فحص التنفس. أعتقد أنني إذا قلت فقط لا، يمكنني تجنب إعطاء الشرطة أي دليل والتعامل مع كل شيء لاحقًا في المحكمة. بموجب قانون الموافقة الضمنية في تكساس، ما هي العاقبة الفورية لرفضي؟","options":["لا يحدث شيء لرخصتي حتى يدينني قاضٍ فعليًا بالقيادة تحت تأثير الكحول في المحكمة","يتم تعليق رخصة قيادتي تلقائيًا بسبب رفض الفحص الكيميائي","أحصل على تحذير مكتوب وفرصة مجانية واحدة لإعادة الفحص في اليوم التالي","يتم تخفيض رخصتي التجارية إلى رخصة من الفئة C لكن قيادتي العادية تبقى قانونية"],"explanation":"بموجب الموافقة الضمنية في تكساس، يؤدي رفض فحص كيميائي مطلوب إلى تعليق إداري تلقائي للرخصة بحد ذاته."},"154":{"q":"أنا أنقل صهريجًا يحمل لافتة لسائل قابل للاشتعال على طريق ريفي سريع في تكساس وأقترب من معبر سكة حديد غير محدد بعلامات، بلا بوابة ولا أضواء وامضة ولا أي حركة مرور أخرى في الأفق. سطح المعبر يبدو خاليًا. ما المطلوب مني فعله عند وصولي إلى القضبان؟","options":["أعامله كأي معبر آخر وأمر عبره بالسرعة المعلنة، بما أنه لا توجد إشارات أو بوابات فعّالة","أبطئ إلى نحو 15 ميلًا في الساعة، وأنتقل إلى ترس أخفض أثناء العبور، وأتابع فقط إذا لم يكن هناك قطار مرئي","أتوقف بين 15 و50 قدمًا قبل القضبان، وأنظر وأستمع، وأعبر دون تغيير التروس بمجرد أن يكون الطريق خاليًا","أفسح المجال فقط إذا كان هناك قطار يقترب، وإلا أتابع بسرعة منخفضة دون التوقف التام"],"explanation":"يجب على الحافلات والمركبات التي تحمل لافتات مواد خطرة التوقف بين 15 و50 قدمًا قبل معبر سكة الحديد، والنظر والاستماع، والعبور دون تغيير التروس بمجرد أن يكون الطريق خاليًا."},"155":{"q":"أنا أقود شاحنتي المحمّلة على طريق سريع في تكساس بحد معلن قدره 70 ميلًا في الساعة عندما يتدحرج ضباب كثيف بحيث بالكاد أرى مسافة 300 قدم أمامي. حركة المرور خفيفة وشاحنتي سليمة ميكانيكيًا. بموجب 'قانون السرعة الأساسي' في تكساس، ما هي السرعة المطلوبة مني قانونيًا للقيادة بها؟","options":["السرعة المعلنة 70 ميلًا في الساعة، لأنها الحد القانوني المحدد لهذا المقطع من الطريق","بالضبط 55 ميلًا في الساعة، لأنه الحد المخفّض الإلزامي لأي مركبة تجارية في الضباب","أي سرعة أختارها، بما أن قانون السرعة الأساسي يحدد فقط حدًا أقصى ولا يحدد أبدًا حدًا أدنى","سرعة معقولة وحكيمة للظروف، وهي هنا تعني أبطأ من 70 ميلًا في الساعة المعلنة"],"explanation":"يتطلب قانون السرعة الأساسي في تكساس سرعة معقولة وحكيمة للظروف، لذا فإن ضعف الرؤية يعني القيادة أبطأ من الحد المعلن."},"156":{"q":"أنا أنقل قطارًا ثقيلًا محمّلًا بالكامل على طريق سريع بمسارين في تكساس بحد معلن قدره 65 ميلًا في الساعة. شاحنتي ضعيفة القوة للمنحدر، وأظل أقود أقل بكثير من تدفق حركة المرور بينما يتكدّس خلفي طابور طويل من السيارات المنزعجة، رغم أن الظروف صافية وجافة. بموجب قواعد تكساس، كيف يجب أن أتعامل مع هذا الموقف؟","options":["القيادة ببطء شديد بحيث أعيق التدفق الطبيعي لحركة المرور غير مسموح بها، لذا يجب أن أواكب حركة المرور أو أتنحّى جانبًا للسماح لها بالمرور","القيادة ببطء مقبولة طالما بقيت في المسار الأيمن وشغّلت أضواء التحذير الرباعية للسيارات خلفي","القيادة أقل من التدفق مطلوبة للحمولة الثقيلة، إذ يجب على المركبة التجارية المحمّلة بالكامل أن تسير دائمًا تحت الحد المعلن","القيادة ببطء مسموح بها لأن شعار المركبة البطيئة الحركة يغطي أي مركبة تجارية تسير تحت الحد الأقصى للسرعة المعلن"],"explanation":"القيادة ببطء شديد بحيث تعيق التدفق الطبيعي لحركة المرور غير قانونية، لذا واكب حركة المرور حيث يكون ذلك آمنًا أو تنحّ جانبًا واسمح لها بالمرور."},"157":{"q":"أنا أنقل حمولة ثقيلة صعودًا على منحدر طويل على طريق سريع بأربعة مسارات في تكساس (مساران في كل اتجاه)، وقد انخفضت سرعة شاحنتي إلى نحو 15 ميلًا في الساعة دون الحد المعلن بينما تتكدّس خلفي سيارات أسرع. للبقاء قانونيًا والحفاظ على تدفق حركة المرور بأمان، ماذا يجب أن أفعل بخصوص موضعي في المسار؟","options":["أنتقل إلى المسار الأيسر حتى تتمكن حركة المرور الأسرع المتكدّسة من تجاوزي على اليمين","أبقى في المسار الأيمن وأدع المركبات الأسرع تتجاوزني على اليسار","أركب فوق خط المسار حتى يتمكن السائقون نافدو الصبر من المرور على أي من الجانبين","أحتفظ بالمسار الأيسر لكن أبطئ أكثر لإجبار الطابور خلفي على الاستقرار"],"explanation":"يجب على المركبة الأبطأ حركة أن تلتزم المسار الأيمن وتدع حركة المرور الأسرع تتجاوزها على اليسار."},"158":{"q":"أنا أقود شاحنتي بمقطورة على طريق متعدد المسارات وقد أبطأت السيارة أمامي للانعطاف يسارًا. هناك رصيف مفتوح على يميني، بما في ذلك كتف معبّد عريض. بموجب قانون تكساس، متى يُسمح لي فعليًا بتجاوز هذه المركبة على اليمين؟","options":["كلما كانت المركبة أمامي تشير أو تستعد للانعطاف يسارًا، بما أن الجانب الأيمن يكون عندها خاليًا","في أي وقت تكون فيه حركة المرور كثيفة ومزدحمة، لأن التجاوز على اليمين يبقي الجميع يتحركون","فقط عندما يمكن فعل ذلك بأمان وأبقى على الطريق، وليس أبدًا بالقيادة على الكتف","كلما كنت متأخرًا عن جدولي وأحتاج إلى تعويض الوقت في توصيلتي"],"explanation":"يُسمح بالتجاوز على اليمين فقط عندما يمكن فعله بأمان وتبقى على الطريق، وليس أبدًا بالقيادة على الكتف."},"159":{"q":"أنا أقود مركبتي التجارية في تكساس وأقترب من تقاطع تحوّلت فيه إشارتي المرورية للتو إلى الأخضر. وبينما أتحرك للأمام، أرى موكب جنازة يعبر أمامي رغم إشارته الحمراء، وأضواء السيارة الأمامية مضاءة وعلى كل مركبة علم صغير. أي إجراء يتطلبه قانون تكساس مني؟","options":["أتابع عبور التقاطع، بما أن الإشارة الخضراء تمنحني دائمًا حق المرور على حركة المرور المتقاطعة","أتحرك للأمام ببطء لأندمج في فجوة بين مركبات الموكب وأتابع مساري","أطلق بوقي لأشير للموكب بأن إشارتي خضراء كي يفسحوا لي المجال","أتوقف وأفسح المجال، سامحًا للموكب بأكمله بالمرور رغم أن إشارتي خضراء"],"explanation":"يجب على السائقين إفساح المجال لموكب الجنازة والسماح للموكب بأكمله بالمرور، حتى عند مواجهة إشارة خضراء."},"160":{"q":"أنا أقود مركبة تجارية لشركة صغيرة في تكساس وأحتاج إلى توصيل ابن زميل يبلغ 7 سنوات إلى منزله من موقع عمل. طول الصبي نحو 4 أقدام و4 بوصات. بموجب قانون تكساس، أين وكيف يُسمح له بالركوب في المقصورة؟ باستثناء إعداد واحد صحيح، كل خيار أدناه غير قانوني.","options":["مثبّتًا في مقعد أمان مناسب لحجمه، لأنه أقل من 8 سنوات وأقصر من 4 أقدام و9 بوصات.","مربوطًا بالحزام في مقعد الراكب الأمامي بحزام الحضن والكتف القياسي، بما أنه أكبر من 4 سنوات.","مربوطًا بالحزام في أي مقعد بحزام قياسي، لأن تكساس تتطلب مقاعد أمان فقط للأطفال دون 4 سنوات.","يركب دون أي تثبيت طالما بقيت المركبة دون 25 ميلًا في الساعة على الطرق المحلية."],"explanation":"يجب أن يركب الطفل الذي يقل عمره عن 8 سنوات وطوله أقل من 4 أقدام و9 بوصات في مقعد أمان للأطفال مناسب لحجمه."},"161":{"q":"أنا أنقل حمولة من الأنابيب على شاحنة مسطّحة عبر تكساس. بعد أميال قليلة، ينزاح جزء من الحمولة وينزلق قسم من الأنابيب على الطريق السريع، ويكاد يصطدم بسيارة أخرى. أتنحّى جانبًا، ويصل ضابط من دورية تكساس (DPS). بموجب قانون تكساس، أي عبارة عن مسؤوليتي عن هذه الحمولة المنسكبة صحيحة؟","options":["لأن الحمولة كانت بشكل قانوني على شاحنة مسطّحة وليست مادة خطرة، فلا أواجه أي عقوبة عن الانسكاب","بصفتي السائق، أنا مسؤول عن تأمين الحمولة ويمكن تغريمي عن الحمولة التي انسكبت على الطريق","تنتقل المسؤولية بالكامل إلى من حمّل المقطورة، لذا لا يمكن للضابط مخالفتي","أنا مسؤول فقط إذا اصطدمت الأنابيب المنسكبة فعليًا بمركبة أخرى وسبّبت ضررًا"],"explanation":"السائق مسؤول عن تأمين الحمولة ويمكن تغريمه عندما تنسكب حمولة غير مؤمّنة على الطريق، بغض النظر عمّن حمّلها."},"162":{"q":"أنت تنقل مبرّدة محمّلة على جدول توصيل ضيّق عندما يشير لك ضابط من دورية تكساس (DPS) عند محطة تفتيش ثابتة أمامك بأن تدخل شاحنتك. سجل قيادتك محدّث وشاحنتك اجتازت تفتيشًا من المستوى الأول قبل أسبوعين فقط. ما المطلوب منك فعله؟","options":["تتابع مرورك متجاوزًا المحطة، بما أن تفتيشًا نظيفًا حديثًا يعفيك قانونيًا لمدة 30 يومًا","تبطئ وتلوّح للضابط، لكن تواصل السير لأن أوراقك سليمة بالفعل","تدخل المحطة، وتتوقف، وتمتثل بالكامل لطلب التفتيش من الضابط","تتوقف فقط إذا دخل الضابط إلى المسار، وإلا تتابع لتجنّب تأخير الجدول"],"explanation":"عندما يشير لك ضابط من دورية تكساس بالدخول إلى محطة تفتيش، يجب أن تتوقف وتمتثل بالكامل للتفتيش."},"163":{"q":"أنا أقترب من تقاطع مزدحم في وسط المدينة في شاحنتي المستقيمة عندما أرى أربعة من المشاة على وشك النزول من الرصيف في الوقت نفسه. مع تثبيت مكابح الهواء وتكدّس حركة المرور خلفي، لأي من المشاة أنا ملزم قانونيًا بإفساح المجال مهما حدث؟","options":["العدّاء المندفع ضد الإشارة وهو ينفخ بصوت عالٍ في صافرة لإخلاء طريقه","راكب الدراجة الذي يقود دراجته سيرًا عبر ممر المشاة ويلوّح بقبعة حمراء زاهية لحركة المرور","الراكض الذي يدفع عربة أطفال ويخطو إلى الطريق في اللحظة التي تتحوّل فيها الإشارة إلى الأصفر","الشخص الذي يعبر ببطء وهو يحرّك عصا بيضاء أمامه، يرشده كلب خدمة"],"explanation":"يجب أن تفسح المجال دائمًا للمشاة الذين يستخدمون عصا بيضاء أو يرشدهم كلب خدمة، لأن ذلك يدل على أنهم مكفوفون أو ضعاف البصر."},"164":{"q":"أنا أقود شاحنتي بمقطورة المحمّلة عبر منطقة سكنية في تكساس خلال ازدحام الصباح. الطريق السريع الذي أسير عليه معلن عادة عند 55 ميلًا في الساعة، لكنني أرى لافتة منطقة مدرسية بأضواء صفراء وامضة تظهر حدًا مخفّضًا، والأطفال يعبرون قريبًا. أي سرعة يجب أن ألتزم بها؟","options":["الحد الأدنى المعلن لسرعة المنطقة المدرسية طالما كانت المنطقة سارية المفعول","الحد العادي للطريق السريع 55 ميلًا في الساعة، بما أن الشاحنات معفاة من لافتات المناطق المدرسية","أي سرعة آمنة للظروف، لأن المناطق المدرسية تلزم سيارات الركاب فقط","الحد القياسي حتى أرى فعليًا حارس عبور يشير لي بالإبطاء"],"explanation":"يجب على السائقين الالتزام بالحد الأدنى المعلن لسرعة المنطقة المدرسية كلما كانت المنطقة سارية المفعول."},"165":{"q":"أنت تنقل مبرّدة محمّلة على طريق سريع بأربعة مسارات في تكساس. حركة المرور خفيفة، والمسار المجاور لك فارغ، وتقرر الانتقال مسارًا واحدًا للتهيؤ لمخرج قادم. بموجب قواعد تكساس، متى يُطلب منك فعليًا استخدام إشارة الانعطاف؟","options":["فقط عند الانعطاف يمينًا، بما أن مناورات اليسار تغطيها مراياك","قبل كل تغيير للمسار وكل انعطاف، بغض النظر عن مدى خلوّ حركة المرور","فقط عندما تكون المركبات الأخرى قريبة بما يكفي لتتأثر بحركتك","فقط عند الانعطاف أو الخروج من الطريق، وليس أبدًا لمجرد تغيير المسار"],"explanation":"يجب أن تشير قبل كل تغيير للمسار وكل انعطاف، بغض النظر عن مدى خلوّ حركة المرور في الظاهر."},"166":{"q":"تكدّست حركة المرور أمامك، والمساحة الوحيدة المفتوحة التي يمكنك رؤيتها هي مباشرة فوق معبر سكة حديد. إشارات المعبر مطفأة ولا ترى أو تسمع قطارًا. لماذا يجب ألا تتقدّم للأمام وتنتظر فوق القضبان؟","options":["التوقف فوق القضبان يضع إجهادًا زائدًا على ناقل الحركة ويهدر الوقود أثناء التباطؤ في الترس","يتطلب قانون تكساس أن تحافظ على مسافة 50 قدمًا خالية على الأقل بين شاحنتك والمعبر في جميع الأوقات","قد تحبسك حركة المرور على القضبان، وقد يصل قطار ويصطدم بك قبل أن تتمكن من الابتعاد","الأمر مقبول طالما توقفت بين 15 و50 قدمًا قبله ولم تغيّر التروس أبدًا أثناء توقفك"],"explanation":"لا تتوقف أبدًا فوق قضبان السكة الحديدية، لأن حركة المرور قد تحبسك دون مساحة للابتعاد، والقطار لا يستطيع التوقف أو الانحراف لتجنّبك."},"167":{"q":"أنا أقود مركبتي التجارية عبر منطقة مزدحمة في وسط المدينة وتتحوّل الإشارة المرورية أمامي إلى الأخضر، لكن المركبات أمامي متكدّسة بحيث لا توجد مساحة على الجانب الآخر من التقاطع. السيارات خلفي تطلق أبواقها ويمكنني التقدّم للأمام إلى وسط الشارع المتقاطع. ماذا يتطلب قانون تكساس مني؟","options":["أتقدّم للأمام عند الإشارة الخضراء لإبقاء طابور حركة المرور متدفقًا، بما أنني كنت أملك حق المرور","أتقدّم جزئيًا لأحجز مكاني، طالما أترك مسارًا واحدًا من الشارع المتقاطع مفتوحًا","أدخل التقاطع لأن السيارات خلفي لها الحق في أن تتوقع تقدّمي عند الإشارة الخضراء","أبقى متأخرًا وأنتظر خلف الخط حتى تتوفر مساحة لأعبر التقاطع بالكامل إلى الجانب الآخر"],"explanation":"لا تدخل التقاطع أبدًا ما لم تتوفر مساحة كافية لعبوره بالكامل إلى الجانب الآخر، حتى عند الإشارة الخضراء، لتجنّب سدّه."},"168":{"q":"أثناء نقل حمولة من الورق المقوّى السائب ومواد التغليف عبر تكساس، يتطاير بعضها عن شاحنتي المسطّحة ويتناثر على الطريق السريع خلفي. يلاحظ ضابط ذلك ويوقفني. بموجب قانون تكساس، ما هي العاقبة الأرجح التي أواجهها عن السماح للحطام بالتسرّب من شاحنتي إلى الطريق؟","options":["غرامة على رمي القمامة، بما أن إسقاط الحطام من مركبة على طريق في تكساس مخالفة","فقط تحذير شفهي، لأن فقدان الحمولة على الطريق السريع يُعامل كحادث وليس مخالفة","تجريد تلقائي من رخصة القيادة التجارية لمدة 60 يومًا، مثل مخالفتين مروريتين خطيرتين","لا عقوبة على الإطلاق، طالما كانت الحمولة مؤمّنة بشكل صحيح قبل أن أبدأ القيادة"],"explanation":"إسقاط الحطام أو رمي القمامة من مركبة على طريق في تكساس مخالفة قد تستوجب غرامة."},"169":{"q":"أنا أنقل مقطورة محمّلة على طريق سريع في تكساس عندما تتكدّس حركة المرور أمامي فجأة وأضغط برفق على دواسة المكابح لأفقد السرعة. يتطلب قانون تكساس أن تكون أضواء مكابحي عاملة لسبب محدّد واحد. ماذا يبلّغ تشغيل تلك الأضواء الحمراء فعليًا للسائق الذي يتبعني عن قرب؟","options":["أنني على وشك الانعطاف أو تغيير المسار، فعليه أن يتجاوزني من الجانب المفتوح","أنني أبطئ أو أتوقف، فعليه أن يكون مستعدًا لتخفيض سرعته","أن مركبتي معطّلة ومتوقفة، فعليه أن يعاملني كعائق ثابت","أنني أسير أقل بكثير من حد السرعة، فيمكنه أن يتجاوزني بأمان في أي وقت"],"explanation":"تحذّر أضواء المكابح السائقين الذين يتبعونك بأنك تبطئ أو تتوقف حتى يخفّضوا سرعتهم ويتجنّبوا اصطدامًا من الخلف."},"170":{"q":"أنا أقود شاحنتي بمقطورة وأصل إلى تقاطع أخطّط للانعطاف فيه يسارًا إلى الشارع المتقاطع. الإشارة خضراء (بلا سهم انعطاف)، وهناك أحد المشاة ينتظر عند الزاوية البعيدة، وسيارة ركاب قادمة مباشرة نحوي من الاتجاه المقابل، وسيارة متوقفة بالفعل خلفي. قبل أن أبدأ انعطافي يسارًا، من له حق المرور الذي يجب أن أفسح له المجال أولًا؟","options":["السيارة المتوقفة خلفي، إذ ينبغي أن ألوّح لها بالمرور قبل أن أشرع في الانعطاف","لا أحد بمجرد أن تكون إشارتي خضراء، لأن الإشارة الخضراء تمنح الانعطاف يسارًا دائمًا حق المرور","سيارة الركاب القادمة التي تسير مباشرة من الاتجاه المقابل","فقط المشاة عند الزاوية البعيدة، بما أن المركبات السائرة مباشرة يجب أن تنتظرني"],"explanation":"عند إشارة خضراء سامحة بلا سهم انعطاف، يجب على السائق المنعطف يسارًا أن يفسح المجال لحركة المرور القادمة السائرة مباشرة قبل أن يعبر مسارها."},"171":{"q":"لقد بلغت للتو 19 عامًا وأنا في مكتب دورية تكساس (DPS) لأبدأ الحصول على رخصة القيادة التجارية كي أقود شاحنة توصيل عبر الولاية. يناولني الموظف حزمة رخصة القيادة التجارية ويخبرني بما يأتي أولًا قبل أي شيء آخر في عملية الترخيص. أي من هذه يجب أن أكمله بنجاح أولًا؟","options":["اجتياز اختبار مهارات القيادة التجارية (القيادة) في المركبة الفعلية","إكمال اختبار طريق خلف المقود مع فاحص من دورية تكساس","تقديم شهادة فاحص طبي معتمد من وزارة النقل (DOT) باللياقة البدنية","اجتياز اختبارات المعرفة (التحريرية) المطلوبة للرخصة التجارية"],"explanation":"الخطوة الأولى في عملية رخصة القيادة التجارية هي اجتياز اختبارات المعرفة (التحريرية) المطلوبة قبل أي اختبار مهارات أو إصدار تصريح تعلّم تجاري."},"172":{"q":"أنا أتقدّم بطلب للحصول على رخصة القيادة التجارية في تكساس ويخبرني الموظف أن عليّ 'التصديق الذاتي' قبل أن يتم إصدار رخصتي. لست متأكدًا مما يعلنه هذا التصديق الذاتي فعليًا. بماذا يجب أن أصدّق ذاتيًا للولاية؟","options":["فئة القيادة التي أنوي القيام بها (مثل بين الولايات أو داخل الولاية)، والتي تحدد متطلبات الفحص الطبي الخاصة بي","فئات المركبات التي أملكها شخصيًا، كي تطابقها الولاية بفئة رخصتي التجارية وتظهيرها","أنواع الحمولة والبضائع التي أخطّط لنقلها، كي تعيّن الولاية تظهير المواد الخطرة الصحيح","الطرق والمقاطعات التي أتوقّع القيادة فيها غالبًا، كي تتحقق الولاية من خبرتي بالمسارات"],"explanation":"يجب أن تصدّق ذاتيًا على فئة قيادتك، مثل بين الولايات أو داخل الولاية، لأنها تحدد متطلبات فحصك الطبي لدى وزارة النقل (DOT)."},"173":{"q":"لقد انتقلت للتو إلى تكساس من ولاية أخرى أحمل فيها بالفعل رخصة قيادة تجارية سارية. يخبرني صديق أنه بما أنني أقود مسارات بين الولايات، يُسمح لي بإبقاء رخصتي التجارية القديمة من الولاية الأخرى سارية والحصول على رخصة تكساس جديدة كي لا يكون لديّ فجوة إذا عدت. قبل أن أفعل أي شيء في مكتب دورية تكساس، أي عبارة تصف بشكل صحيح كم عدد رخص القيادة المسموح لي قانونيًا بحملها؟","options":["رخصتان لا بأس بهما طالما كانت إحداهما للقيادة داخل الولاية والأخرى للقيادة بين الولايات.","يُسمح برخصة واحدة فقط، لذا يجب أن أسلّم الرخصة التجارية من الولاية الأخرى عند حصولي على رخصة تكساس.","يُسمح بما يصل إلى ثلاث رخص طالما كانت كل منها من ولاية مختلفة أعمل فيها.","عدد الرخص الذي أرغب به، بما أن كل ولاية تصدر اعتمادها الخاص بشكل مستقل."],"explanation":"يجوز للسائق التجاري حمل رخصة من ولاية واحدة فقط في كل وقت، لذا يجب أن تسلّم أي رخصة تجارية من ولاية أخرى عند الحصول على رخصة تكساس."},"174":{"q":"أثناء قيادتي لسيارتي الشخصية في عطلة نهاية الأسبوع الماضية، أُدنت بتجاوز إشارة حمراء. أحمل رخصة قيادة تجارية من تكساس وأقود لشركة نقل. بموجب القواعد الفيدرالية وقواعد تكساس، ما هو أطول وقت يُسمح لي بالانتظار قبل أن أبلّغ صاحب عملي بهذه الإدانة؟","options":["يجب أن أخبر صاحب عملي فورًا، خلال 24 ساعة من الإدانة.","ليس عليّ واجب الإبلاغ لأنها حدثت في مركبتي الشخصية، وليس في مركبة تجارية.","يجب أن أبلّغ صاحب عملي خلال 30 يومًا من الإدانة.","لديّ مهلة تصل إلى سنة واحدة للإبلاغ عنها لصاحب عملي."],"explanation":"يجب أن تبلّغ صاحب عملك خلال 30 يومًا من أي إدانة مرورية غير الوقوف، سواء في مركبة تجارية أو شخصية."},"175":{"q":"بعد ظهر يوم الخميس، أتلقى إشعاراً رسمياً بأن رخصتي التجارية (CDL) قد عُلِّقت بناءً على حكم قضائي. أنا أعمل سائقاً لدى شركة نقل في تكساس، وعطلتي يوم الجمعة ولا أعود إلى العمل حتى يوم الاثنين. بموجب قواعد الرخصة التجارية الفيدرالية وقواعد تكساس، ما هو أقصى موعد يجب أن أبلغ فيه صاحب العمل بأن رخصتي معلّقة؟","options":["لديّ مهلة حتى ورديتي المجدولة التالية يوم الاثنين، لأن ذلك هو الوقت الذي سأشغّل فيه مركبة تجارية للشركة","لديّ مهلة 30 يوماً، وهي نفس المدة التي سأحصل عليها للإبلاغ عن تغيير عنوان سكني لدى جهة إصدار الرخص","لست ملزماً بإبلاغ صاحب العمل إطلاقاً، لأن جهة إصدار الرخص تُبلِّغ شركة النقل مباشرةً","يجب أن أبلغ صاحب العمل بنهاية يوم العمل التالي بعد علمي بالتعليق، بغضّ النظر عن جدول عملي"],"explanation":"إذا عُلِّقت رخصتك أو أُلغيت أو سُحبت أو فُقدت أهليتك، فيجب أن تبلغ صاحب العمل بنهاية يوم العمل التالي."},"176":{"q":"يكشف تحقيق للشرطة أنني استخدمت شاحنتي المقطورة في تصنيع وتوزيع مادة خاضعة للرقابة، وأُدانُ بهذه الجناية. بموجب قواعد الرخصة التجارية في تكساس، ماذا يحدث لامتياز القيادة التجاري الخاص بي نتيجة هذه الإدانة؟","options":["أفقد رخصتي التجارية مدى الحياة، دون أي إمكانية لإعادتها","تُسحب أهليتي لقيادة مركبة تجارية لمدة سنة واحدة، ثم يمكنني إعادة التقديم","أحتفظ برخصتي التجارية لكنني أدفع غرامة باهظة وأقضي فترة مراقبة","تُسحب أهليتي لمدة 3 سنوات لأن مركبة تجارية كانت متورطة"],"explanation":"استخدام مركبة تجارية لارتكاب جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة يؤدي إلى سحب الرخصة التجارية مدى الحياة دون إمكانية إعادتها."},"177":{"q":"أنا أقود شاحنة محمَّلة على طريق سريع في تكساس عندما ألاحظ مؤشر الوقود ينخفض بسرعة وأرغب في الخروج من مسارات السير لفحص خزاني. بخصوص التوقف أو الوقوف بمركبتي التجارية على مسارات السير الرئيسية للطريق السريع نفسه، أي العبارات صحيحة؟","options":["مسموح به طالما أنني أشغّل أضواء الخطر الرباعية أولاً.","ممنوع؛ يجب أن أستمر في السير حتى أصل إلى كتف أو منحدر أو مخرج.","مسموح به لفحص ميكانيكي قصير إذا بقيت أقل من 10 دقائق.","مقبول فقط في أقصى المسار الرئيسي الأيمن خلال ساعات النهار."],"explanation":"يحظر قانون تكساس الوقوف أو التوقف في مسارات السير الرئيسية للطريق السريع، لذا يجب أن تستمر في السير إلى كتف أو منحدر أو مخرج."},"178":{"q":"أثناء نقل حمولة على طريق سريع من أربعة مسارات في تكساس، أعلق خلف شاحنة مزرعة بطيئة وتتراكم حركة المرور خلفي. يبدو الكتف الأيمن المعبَّد عريضاً وخالياً. بموجب قواعد تكساس، متى يُسمح لي فعلاً بقيادة مركبتي التجارية على ذلك الكتف؟","options":["كلما تباطأت حركة المرور في مسارات السير بما يكفي ليتيح لي الكتف الاستمرار في الحركة","فقط لتجاوز مركبة تسير بأقل بكثير من السرعة القصوى المحددة","فقط في حالة الطوارئ، عندما لا يكون لديّ بديل آمن","في أي وقت يكون فيه الكتف معبّداً وعريضاً وخالياً من العوائق"],"explanation":"الكتف ليس مساراً للسير ولا يجوز استخدامه إلا في حالة طوارئ حقيقية عندما لا يوجد بديل آمن."},"179":{"q":"أنا أحمّل شاحنتي المقطورة لرحلة تعبر من تكساس إلى أوكلاهوما على الطريق السريع I-35، وليس لديّ تصريح خاص للحمولات كبيرة الحجم أو زائدة الوزن. قبل أن أضيف آخر بضع منصات، أريد التأكد من الحد الأقصى الفيدرالي للوزن الإجمالي. بدون تصريح، ما هو أقصى وزن قانوني لمركبتي المحمَّلة بالكامل وحمولتها معاً على الطريق السريع بين الولايات؟","options":["حتى 34,000 رطل إجمالاً، لأن ذلك هو الحد الأقصى الفيدرالي لوزن مركبة مركّبة محمَّلة","حتى 20,000 رطل إجمالاً، لأن ذلك هو الحد الأقصى الذي تسمح به القواعد الفيدرالية للشاحنة كاملةً","حتى 102,000 رطل إجمالاً، لأن القانون الفيدرالي يسمح بهذا القدر لأي شاحنة بخمسة محاور","حتى 80,000 رطل إجمالاً، لأن ذلك هو الحد الأقصى العام للوزن الإجمالي الفيدرالي على الطريق بين الولايات"],"explanation":"بدون تصريح خاص، الحد الأقصى للوزن الإجمالي المسموح به على الطريق بين الولايات بموجب القواعد الفيدرالية هو 80,000 رطل."},"180":{"q":"أنا محمَّل ومتجه إلى محطة وزن دون تصريح خاص. يذكّرني الموظف بأنه، إلى جانب وزني الإجمالي، يجب أن يبقى كل محور منفرد ضمن الحد القانوني. بالنسبة لمحور منفرد بمفرده، ما هو أقصى وزن يُسمح لي بحمله بموجب الحدود المعتادة في تكساس؟","options":["20,000 رطل على المحور المنفرد","34,000 رطل على المحور المنفرد","12,000 رطل على المحور المنفرد","40,000 رطل على المحور المنفرد"],"explanation":"بدون تصريح خاص، يقتصر المحور المنفرد على 20,000 رطل بموجب قواعد الحجم والوزن في تكساس."},"181":{"q":"أنا أنقل صُلباً وتوقفني محطة وزن على الطريق لفحص مجموعة المحاور. يركّز الضابط على محوري المزدوج (محوران متقاربان في التباعد). بدون تصريح خاص، ما هو أقصى وزن يُسمح لمجموعة المحور المزدوج بحمله في تكساس؟","options":["20,000 رطل، لأن ذلك هو الحد القياسي الذي تحدده تكساس لكل مجموعة محاور منفردة","34,000 رطل، الحد القياسي الذي تسمح به تكساس لمجموعة محاور مزدوجة دون تصريح","80,000 رطل، لأن المحور المزدوج يحمل كامل الوزن الإجمالي المقدَّر للشاحنة المحمَّلة","12,000 رطل، الحد الأقصى المعتاد المسموح به لمجموعة محاور مزدوجة على طرق تكساس"],"explanation":"بدون تصريح خاص، تحدد تكساس الحد الأقصى لمجموعة المحور المزدوج عند 34,000 رطل."},"182":{"q":"أنا أنقل حمولة على الطريق السريع I-35 ويضيق المسار داخل منطقة إنشاءات طرق محددة بعلامات حيث يعمل طاقم فعلياً خلف المخاريط. حركة المرور كثيفة وأشعر بإغراء لزيادة السرعة لاجتياز المنطقة أسرع. بخصوص الغرامات المرورية في هذا الوضع، ماذا يجب أن أتوقع بموجب قانون تكساس؟","options":["تُخفَّض الغرامات لأن حدود السرعة المخفَّضة في مناطق العمل تقلّل أصلاً مبلغ العقوبة","تبقى الغرامات كما هي في أي طريق آخر لأن الحد المحدد هو ما يتحكم في التهمة","غالباً ما تتضاعف غرامات المخالفات المرورية لأن عمال الطرق موجودون في المنطقة","تُلغى الغرامات للسائقين التجاريين الذين يبطئون ويغيّرون المسار بأمان لطاقم العمل"],"explanation":"تتضاعف الغرامات المرورية للمخالفات المرورية في منطقة عمل عندما يكون عمال الطرق موجودين."},"183":{"q":"أنت تنقل مقطورة محمَّلة على طريق ريفي ذي مسارين في تكساس عندما يفقد محرّكك القوة وتبدأ الشاحنة بالانسياب. هناك كتف حصوي عريض قادم على اليمين. ماذا يجب أن تفعل أولاً؟","options":["توقّف في مكانك مباشرةً في مسار السير وضع فوراً مثلثات التحذير الثلاثة","ابقَ متوقفاً في المسار ولوّح لحركة المرور المقتربة لتلتفّ حولك حتى تبطئ","اترك الشاحنة تسدّ المسار وابتعد عنها مشياً لتنتظر المساعدة","وجّه الشاحنة إلى الكتف الحصوي لإخراجها عن الطريق إن أمكنك ذلك بأمان"],"explanation":"عندما تتعطّل المركبة، فإن أولويتك الأولى هي إخراجها بالكامل عن الطريق المسلوك إن أمكنك فعل ذلك بأمان."},"184":{"q":"أنا أقود مركبتي التجارية باتجاه تقاطع في الصباح الباكر وأرى أضواء منطقة المدرسة الصفراء تومض في الأعلى، لكنني لا أرى أي أطفال يمشون قرب الطريق ويبدو مبنى المدرسة مظلماً. ماذا تتطلب مني هذه الأضواء الوامضة قانونياً؟","options":["حد السرعة المخفَّض لمنطقة المدرسة سارٍ الآن، لذا يجب أن أبطئ إليه بغضّ النظر عمّا إذا كنت أرى أي أطفال","ينطبق الحد المخفَّض فقط حالما أرى طلاباً موجودين فعلاً، فيمكنني الحفاظ على السرعة العادية حتى ذلك الحين","الأضواء تنبيه استشاري ولا تحمل حد سرعة قابلاً للتنفيذ ما لم يكن حارس عبور في الطريق","المدرسة مغلقة لذلك اليوم، لذا ينطبق حد السرعة العادي المحدد بالكامل ولا داعي لأن أبطئ"],"explanation":"أضواء منطقة المدرسة الصفراء الوامضة تجعل حد السرعة المخفَّض لمنطقة المدرسة سارياً طوال فترة ومضانها، سواء كان الأطفال مرئيين أم لا."},"185":{"q":"أنا أقود شاحنتي الجرارة المحمَّلة باتجاه منطقة مدرسة في الصباح عندما يخطو حارس عبور إلى الطريق ويرفع إشارة توقف، رغم أن إشارة المرور أمامي لا تزال خضراء. ما هو التصرف الصحيح؟","options":["المتابعة ببطء عبر المعبر لأن الضوء الأخضر يمنحني حق الأولوية القانوني على الحارس","التوقّف والبقاء متوقفاً، مطيعاً إشارة يد حارس العبور كما لو كانت جهاز تحكم مروري","التقدم قليلاً وانتظار أن يلوّح الحارس بالمرور، لأن المشاة لا يمكنهم قانونياً إيقاف مركبة تجارية","نبّه بالبوق لتنبيه الحارس، ثم استمر حالما يبدو أن الأطفال قد خلا منهم المسار"],"explanation":"حارس العبور الذي يوجّه حركة المرور هو سلطة قانونية للتحكم المروري يجب إطاعة إشارات يده، وهي تتجاوز حتى الضوء الأخضر."},"186":{"q":"يجب ألا تبدّل التروس أبداً أثناء وجودك على:","options":["طريق سريع مستوٍ","سكة حديد","جسر طويل","منحدر دخول"],"explanation":"لا تبدّل التروس على سكة الحديد."},"187":{"q":"أنا أقوم بتوصيل سريع وطفلي ذو الأربع سنوات مربوط بحزام في الجزء الخلفي من مركبتي التجارية. الرصيف يبعد نحو 50 قدماً فقط وسأغيب لبضع دقائق فقط والمحرّك يعمل والتكييف مشغّل. بموجب قانون تكساس، أي من هذه العبارات صحيحة عن خطتي؟","options":["مسموح به طالما بقي المحرّك يعمل وحافظ التحكم بالمناخ على راحة المقصورة للطفل.","مسموح به لأن الطفل مربوط وأبقى في مرمى نظري للمركبة طوال الوقت.","من غير القانوني ترك الطفل الصغير وحده في المركبة، بغضّ النظر عن عمل المحرّك أو مدى قربي.","مسموح به للتوقفات القصيرة لأن حد الدقائق القليلة يعني أن الطفل ليس 'بلا مرافق' قانونياً."],"explanation":"يجعل قانون تكساس من غير القانوني ترك طفل صغير وحده في مركبة، دون استثناء لمحرّك يعمل أو تكييف أو وقت قصير أو البقاء قريباً."},"188":{"q":"أنت تقود مركبتك التجارية على شارع مزدحم في مدينة بتكساس عندما يشغّل حافلة نقل عام متوقفة عند موقف رصيف إشارة الانعطاف اليسرى للعودة إلى مسارك. حركة المرور متحركة ولديك مجال للتعديل. أي إجراء يتبع على أفضل وجه قانون المرور في تكساس والقيادة الآمنة؟","options":["حافظ على سرعتك وموضعك في المسار بحيث تبقى الحافلة عند الرصيف حتى يخلو المسار تماماً، لأن حركة المرور المارّة تحتفظ دائماً بحق الأولوية","زِد السرعة لإخلاء المساحة أمام الحافلة قبل أن تخرج، محافظاً على تدفق المرور متماسكاً ومستمراً","نبّه بالبوق لإعلام سائق الحافلة بأنك تنوي المتابعة بجانبها، ثم احتفظ بمسارك أثناء التفافك حولها","ارفع قدمك عن دواسة الوقود وأفسح الطريق، سامحاً لحافلة النقل العام بالاندماج في مسار السير أمامك"],"explanation":"يجب أن تفسح الطريق لحافلة نقل عام أشارت إلى عودتها إلى حركة المرور برفع قدمك عن دواسة الوقود والسماح لها بالاندماج في المسار أمامك."},"189":{"q":"أنا أقود مركبة مركّبة محمَّلة ليلاً على طريق ذي مسارين، وقد قلّل الضباب مسافة رؤيتي بشدة. أحافظ عمداً على فجوة كبيرة من المساحة المفتوحة أمام شاحنتي. اتباعاً لمبدأ 'مسافة التوقف المؤكَّدة'، ما هو السبب الرئيسي لتركي تلك المساحة؟","options":["لكي أتمكن من إيقاف شاحنتي توقفاً كاملاً ضمن المسافة التي يمكنني رؤيتها فعلاً أمامي","لكي يرى السائقون الآخرون الفجوة فيندمجوا أمامي، مما يسهّل تدفق المرور","لكي أدع سرعتي ترتفع تدريجياً مع الحفاظ على هامش زمني آمن في الضباب","لكي يتيح لي التباعد الإضافي حمل حمولة أثقل دون إرهاق فراملي"],"explanation":"احتفظ بمساحة كافية أمامك لإيقاف الشاحنة توقفاً كاملاً ضمن المسافة التي يمكنك فعلاً رؤيتها خالية، والتي تتقلّص ليلاً وفي الضباب."},"190":{"q":"أنا أقود شاحنتي المقطورة عبر بلدة غير مألوفة وأدرك أنني فوّتُّ منعطفي. أرى لافتة منصوبة 'ممنوع الالتفاف على شكل U' عند التقاطع التالي، لكن الطريق عريض وحركة المرور خفيفة ولا توجد مركبة قادمة على مرمى البصر. بموجب قانون تكساس، ما هو وضع القيام بالتفاف على شكل U عند ذلك التقاطع؟","options":["مسموح به، لأن القاعدة تُلغى عندما تكون حركة المرور خفيفة ولا توجد مركبة قادمة","غير قانوني، لأن اللافتة المنصوبة تحظر المناورة بغضّ النظر عن مدى خلوّ الطريق ظاهرياً","مسموح به، طالما أن الطريق عريض بما يكفي لإتمام المركبة المنعطف بأمان","غير قانوني، لكن فقط بين 30 دقيقة بعد غروب الشمس و30 دقيقة قبل شروقها"],"explanation":"لافتة 'ممنوع الالتفاف على شكل U' المنصوبة جهاز تنظيمي يحظر المناورة قانوناً، مهما بدا الطريق خالياً أو فارغاً."},"191":{"q":"أثناء النقل على طريق ريفي ذي مسارين، أرمي زجاجة مشروب فارغة وكيس أغلفة طعام مكوّر من نافذتي لتنظيف المقصورة. يوقفني ضابط من دائرة السلامة العامة (DPS) يتبعني ويخبرني بأنه يحرّر لي مخالفة لإلقاء القمامة من مركبتي. واقعياً، أي نوع من الغرامات يجب أن أتوقعه لإلقاء هذه القمامة من مركبتي التجارية؟","options":["لا شيء على الإطلاق، لأنها كانت مجرد أغلفة طعام خفيفة وليست مادة خطرة","عقوبة رمزية بضعة سنتات فقط، تُعامَل كأي مخالفة معدّات بسيطة","غرامة كبيرة قد تصل إلى عدة مئات من الدولارات لإلقاء القمامة من مركبة","ليس أكثر من تحذير شفهي، لأن إلقاء القمامة غير قابل للتنفيذ ضد حامل رخصة تجارية"],"explanation":"إلقاء أو رمي القمامة من مركبة مخالفة قابلة للتنفيذ قد تكلّف عدة مئات من الدولارات، بغضّ النظر عن حجم الشيء."},"192":{"q":"أنت تنقل حمولة مرتفعة قياسها 13 قدماً و9 إنشات على طريق ولاية في تكساس. مقارنةً بشاحنة ذات مظهر قياسي، ما الذي يجب أن تركّز عليه أكثر للانتباه له أثناء تخطيط مسارك وقيادتك؟","options":["الأكتاف اللينة التي قد تجعل إطاراتك تغوص في الجانب الأيمن من الطريق","الرياح الجانبية في المناطق المفتوحة التي قد تدفع المقطورة نحو الخط الأوسط","نصف قطر الانعطاف الضيق عند التقاطعات الذي قد يكشط إطاراتك بحافة الرصيف","الجسور المنخفضة والجسور العلوية وغيرها من الخلوصات العلوية على طول مسارك"],"explanation":"أكبر خطر على الحمولة المرتفعة هو اصطدامها بالهياكل العلوية، لذا تحقّق باستمرار من الخلوصات المعلنة عند الجسور والجسور العلوية والأنفاق."},"193":{"q":"أنا أقود مركبتي التجارية عبر منطقة مدرسة محددة في تكساس قرابة الساعة 7:45 صباحاً وأريد استخدام هاتفي. بموجب قانون تكساس، متى يسري فعلاً قيد منطقة المدرسة على استخدام الهاتف؟","options":["فقط أثناء ومضان أضواء التحذير لمنطقة المدرسة","فقط عندما تكون أضواء التحذير لمنطقة المدرسة مطفأة ومظلمة","في جميع أوقات اليوم، على مدار السنة، بغضّ النظر عن الأضواء","فقط بعد إعادة طلاء الأضواء أو استبدالها حديثاً"],"explanation":"ينطبق قيد استخدام الهاتف في منطقة المدرسة فقط عندما تكون المنطقة نشطة، وهو ما تشير إليه أضواء التحذير الكهرمانية الوامضة."},"194":{"q":"أنت تقود مركبتك التجارية على طريق سريع مظلم ذي مسارين في تكساس ليلاً والأضواء العالية مشغّلة. تظهر مركبة أمامك، تقترب منك في المسار المقابل. للالتزام بقانون تكساس، ما هي أكبر مسافة من تلك المركبة القادمة يجب أن تكون قد خفّضت عندها أضواءك بالفعل من العالية إلى المنخفضة؟","options":["ضمن 200 قدم من المركبة القادمة","ضمن 500 قدم من المركبة القادمة","ضمن 1,000 قدم من المركبة القادمة","ضمن ميلين من المركبة القادمة"],"explanation":"يتطلب قانون تكساس خفض الأضواء العالية إلى المنخفضة ضمن 500 قدم من مركبة قادمة لتجنّب إعماء السائق المقترب."},"195":{"q":"أنا أنقل بضائع على طريق سريع مظلم ذي مسارين وألحق بشاحنة أبطأ أمامي، تسير في الاتجاه نفسه. أضوائي العالية مشغّلة. وفقاً لقواعد تكساس، إلى أي مدى يمكنني الاقتراب من المركبة التي أمامي قبل أن يُطلب مني خفض أضوائي العالية إلى المنخفضة؟","options":["عليّ فقط الخفض ضمن 500 قدم، لأن تلك هي المسافة التي تصل إليها أضوائي العالية قانونياً على الطريق.","يجب أن أخفض ضمن 30 قدماً، لأن ذلك هو تقريباً هامش التوقف الذي أحفظه خلف الشاحنة.","يجب أن أخفض أضوائي العالية حالما أصبح ضمن 300 قدم من المركبة التي أتبعها.","لست مضطراً أبداً للخفض من أجل مركبة أمامي؛ القاعدة تنطبق فقط على حركة المرور القادمة التي أقابلها."],"explanation":"يتطلب قانون تكساس خفض الأضواء العالية إلى المنخفضة عند الاقتراب لمسافة 300 قدم من مركبة تتبعها لكيلا يُعمي الضوء الساطع ذلك السائق عبر مراياه."},"196":{"q":"أثناء فحص على الطريق، يجد ضابط عيباً حرجاً في الفرامل ويضع ملصق 'خارج الخدمة' على شاحنتي. وجهة توصيلي تبعد 20 ميلاً فقط والحمولة حساسة للوقت. أي مما يلي صحيح بشأن خياراتي القانونية؟","options":["يمكنني القيادة إلى أقرب مخرج أو استراحة لإجراء الإصلاحات، لأن المسافات القصيرة معفاة.","يمكنني المتابعة إلى التوصيل إذا بقيت أقل من 25 ميلاً في الساعة وشغّلت أضواء الخطر طوال الطريق.","يمكنني تحريك المركبة حالما يوقّع مرسّلي إعفاءً خطياً يأذن بالرحلة.","يجب ألا أحرّك المركبة حتى يُصلَح العيب؛ قيادتها كما هي يخالف القانون."],"explanation":"المركبة الموضوعة خارج الخدمة يجب ألا تُحرَّك حتى يُصلَح العيب؛ قيادتها كما هي تخالف القانون دون أي إعفاء يتعلق بالمسافة أو المرسّل."},"197":{"q":"أثناء فحصي قبل الرحلة في تكساس، ألاحظ أن إشارة انعطافي اليسرى تومض لكن أضواء فرملتي لا تضيء عندما أضغط على الدواسة. يقول زميل إنني بخير لإجراء توصيل محلي قصير طالما أن الشاحنة تتحرك وأستخدم إشارات اليد. بموجب متطلبات تكساس، ماذا يجب أن أفعل قبل قيادة هذه المركبة التجارية على الطريق؟","options":["أبقِ المركبة خارج الخدمة حتى تُصلَح أضواء الفرامل، لأن تكساس تتطلب عمل كل من إشارات الانعطاف وأضواء الفرامل","القيادة فقط إذا استخدمت إشارات اليد من النافذة لكل توقّف وانعطاف خلال الرحلة المحلية","القيادة طالما يعمل واحد على الأقل من النظامين، لأن دائرة إضاءة عاملة واحدة كافية قانونياً","القيادة بعد فصل دائرة ضوء الفرامل المعطلة لكيلا تعطي السائقين الآخرين إشارة خاطئة"],"explanation":"تتطلب تكساس عمل كل من إشارات الانعطاف وأضواء الفرامل، لذا فإن أضواء الفرامل المعطلة تضع المركبة خارج الخدمة حتى تُصلَح."},"198":{"q":"أنت تقترب من دوّار متعدد المسارات في تكساس بمركبتك المركّبة المحمَّلة. حركة المرور تتحرك بثبات داخل الدائرة، وسيارة تشير إلى خروجها أمامك، وشاحنة أخرى تنتظر عند المدخل على يسارك. للدخول قانونياً وبأمان، يجب أن تفسح حق الأولوية لأي مما يلي؟","options":["الشاحنة المنتظرة للدخول من المسار على يسارك، لأن المركبات الأكبر تمر أولاً","أي مركبة تدور بالفعل داخل الدوّار، بغضّ النظر عن مسارها","فقط السيارة التي تشير إلى خروجها، لأنها مغادرة وتخلي طريقك","لا أحد، لأن المركبات الداخلة إلى الدوّار تملك دائماً حق الأولوية"],"explanation":"يجب على السائقين الداخلين إلى الدوّار أن يفسحوا الطريق لكل حركة المرور التي تدور بالفعل داخله، في أي مسار."},"199":{"q":"اشتريت للتوّ شاحنة صندوقية مستقيمة مستعملة في تكساس وأتفحّص ملصق الباب لأرى ما إذا كنت بحاجة إلى رخصة تجارية قبل أن أقودها بمفردها (دون مقطورة). عند أي وزن إجمالي مقدَّر من الشركة المصنّعة (GVWR) تتطلب تكساس أولاً أن أحمل رخصة تجارية لهذه المركبة المنفردة؟","options":["10,000 رطل أو أكثر، لأن ذلك هو الوزن الذي يفصل الشاحنات الخفيفة عن الثقيلة","20,000 رطل أو أكثر، لأن ذلك يطابق حد وزن المحور المنفرد المسموح به على طرق تكساس","26,001 رطل أو أكثر، وهو حد الوزن الإجمالي المقدَّر (GVWR) لمركبة منفردة بموجب قانون تكساس","34,000 رطل أو أكثر، وهو نفس الرقم الذي تستخدمه تكساس لحد وزن المحور المزدوج"],"explanation":"تُطلب رخصة تجارية لقيادة مركبة منفردة بوزن إجمالي مقدَّر (GVWR) يبلغ 26,001 رطل أو أكثر بموجب قانون تكساس."}},"general":{"0":{"q":"أثناء فحص ما قبل الرحلة، تقيس عمق المداس فتجد أن أحد إطارات محور التوجيه (الأمامي) قد تآكل إلى 3/32 بوصة، بينما تبلغ جميع إطارات محور الدفع والمقطورة 3/32 بوصة أيضًا. أي عبارة تحدد بشكل صحيح ما إذا كانت مركبتك قانونية للقيادة؟","options":["المركبة غير قانونية للقيادة، لأن إطارات محور التوجيه يجب أن يكون عمق مداسها 4/32 بوصة على الأقل.","المركبة قانونية للقيادة، لأن جميع الإطارات تستوفي الحد الأدنى البالغ 2/32 بوصة لكل إطار.","المركبة قانونية للقيادة، لأن الإطارات الأمامية تحتاج فقط إلى 2/32 بوصة والباقي جيد.","المركبة غير قانونية للقيادة، لأن جميع الإطارات على كل محور يجب أن يكون عمق مداسها 4/32 بوصة على الأقل."],"explanation":"يجب أن يكون لإطارات محور التوجيه عمق مداس لا يقل عن 4/32 بوصة، لذا فإن الإطار الأمامي عند 3/32 بوصة أقل من الحد الأدنى ويجعل المركبة غير قانونية للقيادة."},"1":{"q":"أثناء فحص ما قبل الرحلة، تمرر مقياس عمق المداس على جميع إطاراتك. تقيس إطارات محور التوجيه قيمة صحية تبلغ 5/32 بوصة، لكن أحد إطارات محور الدفع الخلفي قد تآكل إلى قراءة أرفع بشكل ملحوظ. ما هو أقل عمق مداس يمكن أن يكون قانونيًا لذلك الإطار الخلفي (غير الموجِّه) ويظل يجتاز الفحص؟","options":["1/32 بوصة","2/32 بوصة","4/32 بوصة","6/32 بوصة"],"explanation":"يجب أن يكون لجميع الإطارات باستثناء محور التوجيه الأمامي عمق مداس لا يقل عن 2/32 بوصة يُقاس في أحد الأخاديد الرئيسية."},"2":{"q":"أثناء فحص ما قبل الرحلة، تمسك عجلة القيادة وتحركها ذهابًا وإيابًا قبل تشغيل المحرك. على عجلتك التي يبلغ قطرها 20 بوصة، يمكنك تدوير الإطار بضع بوصات في كل اتجاه قبل أن تبدأ العجلات الأمامية بالاستجابة. عند أي نقطة يجب أن يجعلك هذا الخلوص تشك في وجود مشكلة في نظام التوجيه وتسحب المركبة من الخدمة؟","options":["عندما يمكن تدوير العجلة أكثر من حوالي 10 درجات (نحو 2 بوصة على عجلة قطرها 20 بوصة) قبل أن تتحرك العجلات الأمامية","فقط عندما يمكن تدوير العجلة أكثر من حوالي 20 درجة قبل أن تتحرك العجلات الأمامية","عندما يمكن تدوير العجلة أكثر من حوالي 5 درجات، لأن أي خلوص يمكن اكتشافه يُعد غير آمن","فقط عندما يتجاوز الخلوص حوالي 45 درجة، لأن ذلك هو الوقت الذي يصبح فيه التوجيه صعب التحكم حقًا"],"explanation":"أكثر من حوالي 10 درجات من خلوص عجلة القيادة (نحو 2 بوصة على عجلة قطرها 20 بوصة) قبل أن تتحرك العجلات الأمامية يُعد مفرطًا ويشير إلى مشكلة في التوجيه."},"3":{"q":"توقفت شاحنتك المقطورة على كتف طريق سريع غير مقسوم ذي مسارين ولا تعيد التشغيل. تشغّل أضواء التحذير وتمد يدك إلى عدة التحذير الطارئة لتضع مثلثات عاكسة على بُعد 100 قدم خلف المركبة، و100 قدم أمامها، و10 أقدام إلى الخلف منها. لتكون مجهزًا قانونيًا لوضع أجهزة التحذير في كل موضع مطلوب بهذا الشكل، ما هو الحد الأدنى لعدد المثلثات العاكسة التي يجب أن تحملها شاحنتك؟","options":["مثلثان، لأن واحدًا يوضع أمام المركبة وواحدًا خلفها","ثلاثة مثلثات","مثلث واحد يوضع على بُعد 10 أقدام إلى الخلف، بالإضافة إلى أضواء التحذير","ستة مثلثات، للتأكد من تغطية اتجاهي حركة المرور كليهما"],"explanation":"يجب أن تحمل المركبة التجارية ثلاثة مثلثات تحذير عاكسة على الأقل كأجهزة تحذير طارئة."},"4":{"q":"أنت في منتصف نوبتك وكان أحد وصلات خط الديزل يُسرّب الوقود قرب أسلاك المحرك. فجأة يندلع حريق صغير هناك، يغذيه الديزل المتسرب ويطقطق حول ضفيرة الأسلاك الكهربائية الحية. تمد يدك إلى الطفاية المثبتة في مقصورتك. أي تصنيف على تلك الطفاية يخبرك بأنها مصممة لمكافحة كل من هذا الوقود المشتعل والحريق الكهربائي المتصل بالتيار؟","options":["طفاية مصنفة B:C، مخصصة للسوائل المشتعلة والحرائق الكهربائية","طفاية من الفئة A، لأنها التصنيف القياسي المحمول على المركبات التجارية","طفاية من النوع المائي، لتبريد الديزل وإخماد الحريق بسرعة","لا يهم أي تصنيف تمسك به، طالما تفرغها عند قاعدة اللهب"],"explanation":"السائل القابل للاشتعال المشتعل هو حريق من الفئة B، والمعدات الكهربائية المتصلة بالتيار من الفئة C، لذا فإن الطفاية المصنفة B:C مطلوبة لكليهما."},"5":{"q":"الساعة 5:00 صباحًا وأنت تنهي فحص ما قبل الرحلة على شاحنة مقطورة كُلّفت بها للتو. يستعجلك الموزّع للمغادرة، لكنك تتذكر أن القواعد الفيدرالية تلزمك بحمل معدات طوارئ معينة قبل أي رحلة. لم تجد عدة منصهرات كهربائية احتياطية في أي مكان في المقصورة. تحت أي شرط يكون قانونيًا أن تقود دون حمل منصهرات احتياطية؟","options":["فقط إذا كانت الشاحنة مجهزة بقواطع دائرية بدلًا من المنصهرات","فقط إذا كنت تحمل بطارية احتياطية مشحونة بالكامل في المقصورة","فقط إذا كانت المقطورة مزودة بأضواء خلوص ووضع من نوع LED","فقط إذا كان الجرار يحتوي على مولّد احتياطي (ثانٍ) للنظام الكهربائي"],"explanation":"لا تكون المنصهرات الاحتياطية مطلوبة عندما يكون النظام الكهربائي محميًا بقواطع دائرية، لأن القواطع تُعاد ضبطها بدلًا من الحاجة إلى استبدالها."},"6":{"q":"إنه الصباح الباكر وتقترب من شاحنتك لتبدأ فحص ما قبل الرحلة. يذكّرك مدربك باتباع طريقة الفحص ذات الخطوات السبع بالترتيب. قبل أن تصعد إلى المقصورة، أو تفتح غطاء المحرك، أو تلمس أي مفتاح، ما هو أول شيء تتطلبه طريقة الخطوات السبع؟","options":["تشغيل المحرك وتركه يحمى بينما تراقب ضغط الزيت ومقاييس الهواء","المشي إلى الأمام والتحقق من أن المصابيح الأمامية وإشارات الانعطاف وأضواء التحذير الرباعية تعمل جميعها","إجراء استعراض عام للمركبة، ومراجعة تقرير الفحص السابق وتفقد حالتها العامة ومحيطها","النزول تحت مقدمة المركبة والتأكد من أن إطارات محور التوجيه يبلغ عمق مداسها 4/32 بوصة على الأقل"],"explanation":"الخطوة الأولى من الفحص ذي الخطوات السبع هي استعراض المركبة: مراجعة تقرير الفحص الأخير وتفقد الحالة العامة للشاحنة ومحيطها."},"7":{"q":"إنه صباح بارد وأنت على وشك بدء فحص ما قبل الرحلة. محرك شاحنتك مُطفأ وغطاء المحرك مرفوع. أي من العناصر التالية هي المجموعة التي يمكنك ويجب عليك فحصها الآن، بينما المحرك غير قيد التشغيل؟","options":["خلوص عجلة القيادة وعمل جرس تحذير انخفاض ضغط الهواء","مستوى زيت المحرك، ومستوى سائل التبريد، وحالة أحزمة الإدارة","ضغطا تشغيل وإيقاف منظّم ضاغط الهواء","خرج المولّد ومقياس نظام الشحن تحت الحمل"],"explanation":"مع إيقاف المحرك، تفتح غطاء المحرك لفحص مستوى زيت المحرك ومستوى سائل التبريد وحالة أحزمة الإدارة."},"8":{"q":"درجة الحرارة أقل قليلًا من التجمد وقد تشكلت طبقة جليدية خفيفة على منحدر الدخول بينما ترفع سرعة مركبتك المركبة المحملة إلى سرعة الطريق السريع. تشعر بعجلات الدفع في الجرار تبدأ بالدوران وبمؤخرة المقصورة تتحرك جانبيًا. للوصول إلى السرعة بأمان على هذا السطح الزلق، ما هي أفضل طريقة للتعامل مع دواسة الوقود؟","options":["زيادة القوة بسلاسة وتدريج، مع رفع القدم فور أن تبدأ عجلات الدفع بالدوران","ضغط دواسة الوقود بقوة حتى تتمكن الإطارات الدوّارة من الإمساك واختراق الجليد","ضخ دواسة الوقود تشغيلًا وإيقافًا بسرعة لتقطيع القوة المنتقلة إلى عجلات الدفع","الحفاظ على دواسة وقود ثابتة وقوية وترك قوة المحرك تسحبك عبر البقعة الزلقة"],"explanation":"على الأسطح الزلقة، طبّق القوة بسلاسة وتدريج، مع رفع القدم فور أن تبدأ عجلات الدفع بالدوران لتستعيد التماسك."},"9":{"q":"أنت بمفردك ويجب أن ترجع شاحنتك المقطورة إلى رصيف تحميل في زقاق ضيق. يمكنك الاقتراب من الرصيف بحيث ترجع المركبة نحو جانبك الأيسر (جانب السائق)، أو بحيث ترجع نحو جانبك الأيمن، وهو ما سيكون مناورة أقصر قليلًا. للبقاء في أكبر قدر من الأمان، أي طريقة يجب أن تختار، ولماذا؟","options":["الرجوع نحو الجانب الأيمن، لأن المسار الأقصر يعني وقتًا أقل في المناورة عمياء","الرجوع نحو الجانب الأيمن، لكن مع الانحناء خارج نافذة الراكب واستخدام مراقب لتغطية المنطقة العمياء","كلا الجانبين آمن بالتساوي، لذا اختر الجانب الأيمن لأنه المناورة الأسرع","الرجوع نحو جانب السائق (الأيسر)، حتى لو كان أطول، لأنه يمكنك مراقبة مؤخرة المقطورة عبر نافذتك الجانبية بدلًا من الاعتماد على المرايا فقط"],"explanation":"ارجع نحو جانب السائق (الأيسر) كلما أمكن حتى تتمكن من مراقبة مؤخرة المقطورة مباشرة عبر نافذتك الجانبية بدلًا من الاعتماد على المرايا فقط."},"10":{"q":"أنت تنقل مقطورة محملة وتقترب من منحدر طويل وحاد ينتهي بمنعطف حاد في الأسفل. ناقل الحركة لديك حاليًا في ترس عالٍ. ما هو الوقت الصحيح لاختيار الترس المنخفض الذي ستستخدمه للتحكم في سرعتك على هذا المنحدر وعبر المنعطف؟","options":["قبل أن تبدأ النزول على المنحدر وقبل المنعطف، بينما لا تزال على أرض مستوية","تمامًا عند دخولك المنعطف، حتى يكون المحرك عند ذروة قوة الكبح بالضبط حيث تحتاجها أكثر","في منتصف المنحدر بمجرد أن تشعر بالشاحنة تبدأ بزيادة السرعة وتبدأ مكابحك بالضعف","فقط بعد خروجك من المنعطف، حتى تحتفظ عجلات الدفع بالتماسك الكامل خلال الانعطاف"],"explanation":"اختر الترس المناسب قبل البدء بالنزول على المنحدر أو دخول المنعطف، بينما لا تزال على أرض مستوية، لأن تغيير الترس قد يكون مستحيلًا بمجرد بدء النزول."},"11":{"q":"تقود على طريق سريع جاف بسرعة 55 ميلًا في الساعة عندما ينفجر إطار سيارة بعيدة أمامك فتتوقف فجأة في مسارك. من لحظة ظهور الخطر حتى توقف شاحنتك توقفًا كاملًا، ستكون مركبتك قد قطعت تقريبًا طول ملعب كرة قدم بما في ذلك منطقتي النهاية (حوالي 419 قدمًا). أي مجموعة من العوامل تفسّر بالكامل ذلك الإجمالي البالغ 419 قدمًا لمسافة التوقف؟","options":["المسافة التي تبطئ فيها مكابحك الشاحنة فعليًا بعد أن تمسك المكابح الهوائية، بالإضافة إلى التأخر بينما يتراكم ضغط الهواء في النظام","المسافة التي تقطعها أثناء رؤية الخطر وإدراكه، بالإضافة إلى المسافة أثناء تحريك قدمك إلى الدواسة، بالإضافة إلى المسافة التي تستغرقها المكابح لإيقافك","المسافة أثناء رد فعلك وانتقالك إلى الدواسة، بالإضافة إلى المسافة التي تستغرقها المكابح لإيقافك","فقط المسافة التي تحتاجها المكابح لإيقاف الشاحنة بمجرد تطبيقها"],"explanation":"إجمالي مسافة التوقف هو مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الكبح — رؤية الخطر، وتحريك قدمك إلى الدواسة، وإيقاف المكابح للمركبة."},"12":{"q":"تقود فارغًا على طريق سريع بين الولايات جاف ومستوٍ بسرعة ثابتة تبلغ 55 ميلًا في الساعة في طقس جيد. يتوقف السائق أمامك فجأة، وعليك أن تتوقف توقفًا طارئًا كاملًا. من لحظة ظهور الخطر لأول مرة إلى لحظة توقف شاحنتك توقفًا تامًا، كم تقريبًا من إجمالي مسافة الطريق سيستغرقك التوقف؟","options":["حوالي 60 قدمًا، لأن تلك هي المسافة التي تقطعها قبل أن تتمكن من رد الفعل","حوالي 220 قدمًا، تقريبًا طول مرحلة الكبح وحدها","حوالي 320 قدمًا، أكثر قليلًا من طول ملعب كرة قدم أمريكية واحد","حوالي 420 قدمًا، تقريبًا طول ملعب كرة قدم أمريكية زائد منطقتي النهاية كلتيهما"],"explanation":"عند سرعة 55 ميلًا في الساعة في ظروف جيدة، يبلغ إجمالي مسافة التوقف حوالي 420 قدمًا، تقريبًا طول ملعب كرة قدم زائد منطقتي النهاية."},"13":{"q":"تقود عادة على مقطع من طريق سريع جاف ومستوٍ بسرعة 20 ميلًا في الساعة وتعرف أن مركبتك تحتاج مسافة كبح معينة للتوقف من تلك السرعة. الليلة، وأنت متأخر، تسلك الطريق نفسه بسرعة 40 ميلًا في الساعة في الظروف الجيدة نفسها. مقارنة بمسافة الكبح عند 20 ميلًا في الساعة، ستكون مسافة الكبح عند 40 ميلًا في الساعة تقريبًا:","options":["ضعفين، لأن مسافة الكبح تزداد بتناسب مباشر مع السرعة","ثلاثة أضعاف، لأنه يجب إضافة مسافة إضافية لوقت رد الفعل أيضًا","أربعة أضعاف، لأن مسافة الكبح تنمو مع مربع سرعتك","نفسها تقريبًا، طالما أن الطريق جاف ومستوٍ والمكابح جيدة"],"explanation":"تنمو مسافة الكبح مع مربع السرعة، لذا فإن مضاعفة سرعتك من 20 إلى 40 ميلًا في الساعة تجعل مسافة الكبح أطول بحوالي أربعة أضعاف."},"14":{"q":"بلّل مطر ثابت الطريق السريع ويمكنك رؤية طبقة رقيقة من الماء على الرصيف، رغم أن درجة الحرارة أعلى بكثير من التجمد ولا يوجد ثلج أو جليد. للحفاظ على هامش أمان للمسافة الأطول للتوقف التي تخلقها هذه الظروف الرطبة، بأي مقدار تقريبًا يجب أن تخفض سرعتك دون ما كنت ستقوده على الطريق نفسه عندما يكون جافًا؟","options":["بحوالي العُشر","بحوالي الثلث","بحوالي النصف","بحوالي ثلاثة أرباع"],"explanation":"على الطرق الرطبة، خفّض سرعتك بحوالي الثلث مقارنة بسرعتك الآمنة على الطريق الجاف لتعويض فقدان التماسك ومسافة الكبح الأطول."},"15":{"q":"لقد سلّمت للتو حمولتك الكاملة ومقطورتك الآن فارغة تمامًا. الطريق جاف وأنت تسير بنفس سرعة الطريق السريع التي قدت بها طوال الصباح عندما كنت محملًا بالكامل. مقارنة بحالتك عندما كنت محملًا، كيف يجب أن تعدّل توقعك لكيفية كبح هذه المركبة الفارغة وتعاملها؟","options":["ستتوقف في مسافة أقصر لأن هناك وزنًا أقل بكثير لتبطئه المكابح","ستحتاج إلى مسافة أطول للتوقف لأن المحاور الخلفية الخفيفة لديها تماسك أقل ويمكن أن تنغلق العجلات وتنزلق","ستكون مسافة توقفها متطابقة تقريبًا، لأن مسافة الكبح تعتمد على السرعة وليس على الحمولة","لا يمكن أن تنزلق الآن لأن المقطورة الفارغة تمنع عجلات الدفع من الانغلاق أبدًا"],"explanation":"تحتاج الشاحنة الفارغة إلى مسافة توقف أطول لأن المحاور الخلفية الخفيفة لديها تماسك أقل، لذا تنغلق العجلات وتنزلق بسهولة أكبر."},"16":{"q":"تسير بسرعة حوالي 50 ميلًا في الساعة على طريق سريع بين الولايات عندما يبدأ هطول مطر غزير. يصبح توجيهك فجأة خفيفًا ومرتخيًا، وتتوقف الشاحنة عن الاستجابة لمدخلات العجلة الصغيرة، وتدرك أن الإطارات الأمامية قد ارتفعت على طبقة من الماء ولم تعد تمسك بالرصيف. أي إجراء يمنحك أفضل فرصة لاستعادة السيطرة؟","options":["الضغط بقوة على دواسة المكابح لتقليل السرعة بأسرع ما يمكن","رفع القدم عن دواسة الوقود (والضغط على القابض) وترك المركبة تبطئ من تلقاء نفسها دون كبح بقوة","التوجيه بحدة نحو الكتف حتى تعض الإطارات في رصيف أخشن وتستعيد التماسك","الحفاظ على دواسة الوقود أو زيادتها لإبقاء عجلات الدفع تدور و\"اختراق\" الماء بالقوة"],"explanation":"إذا بدأت بالانزلاق المائي، ارفع قدمك عن دواسة الوقود واضغط على القابض دون كبح بقوة حتى تتمكن الإطارات من الإبطاء واستعادة التلامس مع الطريق."},"17":{"q":"تنقل مقطورة محملة بالكامل نازلًا على منحدر جبلي طويل وحاد. اخترت ترسًا منخفضًا في الأعلى وكنت تضغط المكابح بخفة لكن بشكل شبه مستمر طوال الطريق نزولًا. في منتصف الطريق، تلاحظ أن دواسة المكابح تبدو أكثر ليونة وأن الشاحنة لم تعد تبطئ كما كانت في أعلى المنحدر. ما هو السبب الأكثر احتمالًا لهذا الفقدان في الكبح؟","options":["فرملة الأحذية والأسطوانات قد سخنت بشكل مفرط من الاستخدام المفرط بدلًا من الاعتماد على كبح المحرك والترس","ضغط الهواء في خطوط المكابح قد انخفض كثيرًا لأن الضاغط لا يستطيع مواكبة المنحدر","الهواء الجبلي البارد على ارتفاع أعلى قد كثّف سائل المكابح وقلّل من استجابة الدواسة","إطارات المقطورة غير منفوخة بشكل كافٍ، ما يقلل من رقعة التلامس وقوة الكبح عند كل عجلة"],"explanation":"الضغط المستمر على المكابح نزولًا على منحدر طويل يسخّن الأحذية والأسطوانات بشكل مفرط، ما يسبب ضعف المكابح؛ دع كبح المحرك والترس يضبط سرعتك بدلًا من ذلك."},"18":{"q":"تقود شاحنة مقطورة محملة على طريق سريع جاف وتقترب من منحدر خروج نازل بحد سرعة منعطف معلن يبلغ 35 ميلًا في الساعة. الرصيف بحالة جيدة وحركة المرور خفيفة. أي عبارة تصف على أفضل وجه كيف يجب أن تتعامل مع ذلك الرقم المعلن البالغ 35 ميلًا في الساعة؟","options":["إنها السرعة الآمنة لأي مركبة في الظروف الجيدة، لذا فإن 35 ميلًا في الساعة جيدة في مركبتك المحملة","إنها مضبوطة للسيارات في الظروف الجيدة، لذا يجب أن تدخل المنعطف بسرعة أقل بكثير من 35 ميلًا في الساعة","إنها تنطبق فقط على الشاحنات الفارغة، لذا يجوز لشاحنة محملة تجاوزها قانونيًا","إنها تتضمن بالفعل هامش أمان للشاحنات، لذا فإن الحفاظ على 35 ميلًا في الساعة بالضبط هو الخيار الأكثر أمانًا"],"explanation":"سرعات المنعطفات المعلنة مضبوطة للسيارات في الظروف الجيدة، لذا يجب على شاحنة بمركز ثقلها الأعلى أن تدخل بسرعة أقل بكثير من السرعة المعلنة."},"19":{"q":"تقود شاحنة مقطورة بطول 60 قدمًا على طريق سريع جاف، ويقرأ عداد سرعتك سرعة ثابتة تبلغ 55 ميلًا في الساعة في حركة مرور خفيفة. تريد ضبط مسافة اتباع آمنة خلف السيارة أمامك. بناءً على طول مركبتك وسرعتك الحالية، ما هي الحد الأدنى لمسافة الاتباع التي يجب أن تحافظ عليها؟","options":["6 ثوانٍ، لأن مركبة بطول 60 قدمًا تحتاج إلى ثانية واحدة لكل 10 أقدام في أي سرعة","4 ثوانٍ ثابتة، نفسها لأي مركبة ثقيلة بغض النظر عن الطول","7 ثوانٍ، لأن مركبة بطول 60 قدمًا تحتاج إلى 6 ثوانٍ زائد ثانية واحدة إضافية للقيادة فوق 40 ميلًا في الساعة","حوالي ثلاثة أطوال سيارة، وهو ما يكفي تقريبًا كهامش لشاحنة مقطورة"],"explanation":"اترك ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، زائد ثانية إضافية فوق 40 ميلًا في الساعة، لذا تحتاج مركبة بطول 60 قدمًا عند 55 ميلًا في الساعة إلى 7 ثوانٍ."},"20":{"q":"تسير بسرعة 60 ميلًا في الساعة على طريق ريفي مفتوح بحركة مرور خفيفة. الطريق أمامك يصعد بلطف وتريد إدارة مسافتك ورصد المشكلات مبكرًا. للمسح بشكل صحيح، أين يجب أن تتركز عيناك معظم الوقت أثناء القيادة بهذه السرعة؟","options":["على الرصيف بعد مقدمة غطاء محركك مباشرة، حتى تلتقط العوائق على الطريق فورًا","حوالي 4 إلى 6 ثوانٍ أمامك، نفس المسافة التي ستستخدمها لضبط فجوة اتباع آمنة","حوالي 12 إلى 15 ثانية أمامك، حوالي ربع ميل عند سرعة الطريق السريع","حوالي 30 ثانية أمامك، بأبعد ما يمكن أن تصل إليه عيناك على الطريق"],"explanation":"ينظر السائقون الجيدون من 12 إلى 15 ثانية أمامهم، وهو ما يعادل حوالي ربع ميل عند سرعة الطريق السريع."},"21":{"q":"تقترب من انعطاف يميني إلى زقاق ضيق في شارع مدينة مزدحم. حركة المرور كثيفة، وهناك راكب دراجة في مسار الدراجات على يمينك، وعدة سائقين مصطفون قريبًا خلفك. فيما يتعلق بإشارة الانعطاف، أي إجراء هو أفضل ممارسة منفردة؟","options":["الانتظار حتى تبدأ فعليًا بتدوير العجلة قبل الإشارة، حتى لا يبطئ السائقون خلفك مبكرًا جدًا ويسببوا ازدحامًا","الإشارة لفترة وجيزة فقط، لأنه في حركة المرور الكثيفة يمكن للسائقين حولك أن يروا بالفعل أضواء مكابحك تتولى التواصل عنك","تشغيل إشارتك قبل الانعطاف بوقت كافٍ والحفاظ عليها وامضة باستمرار طوال المناورة بأكملها","تخطّي الإشارة الكهربائية واستخدام إشارة يدوية بدلًا منها، لأنها أكثر وضوحًا لراكب الدراجة بجانبك"],"explanation":"أشر قبل الانعطاف بوقت كافٍ وحافظ على الإشارة وامضة طوال المناورة بأكملها حتى يكون لدى الآخرين أقصى وقت لرد الفعل ولا يفترضوا أنك غيّرت رأيك."},"22":{"q":"إذا كان أحدهم يلاحقك من الخلف عن قرب، يجب أن:","options":["تسرع","تفتح مساحة أمامك","تفرمل لتخيفه","تبطئ في المسار الأيسر"],"explanation":"زد المساحة أمامك حتى تتمكن من الإبطاء تدريجيًا؛ تجنب الحركات السريعة."},"23":{"q":"تقود شاحنة مقطورة بطول 70 قدمًا وتحتاج إلى الانعطاف يمينًا إلى شارع جانبي ضيق. حركة المرور خفيفة، وأنت قلق من أن تتسلق العجلات الخلفية للمقطورة الرصيف. لإتمام هذا الانعطاف بأمان وقانونية، أي من التالي يجب ألا تفعله؟","options":["الانحراف يسارًا إلى المسار المجاور قبل الانعطاف حتى يكون لدى المقطورة مساحة أكبر للدوران","بدء الانعطاف ببطء ومواصلة مراقبة مراياك لتتبع مسار المقطورة","إبقاء مؤخرة المركبة قريبة من الرصيف حتى لا يتمكن السائقون الآخرون من المرور بجانبك على يمينك","التوسّع فقط عند إتمام الانعطاف، بعد أن تكون المقصورة قد تجاوزت الزاوية"],"explanation":"الانحراف يسارًا قبل انعطاف يميني يفتح فجوة تدعو المركبات للمرور على يمينك، ما يضعها في مسار مقطورتك المتأرجحة."},"24":{"q":"تنقل شاحنة جافة فارغة ويُظهر مسارك جسرًا علويًا معلنًا بخلوص 13 قدمًا و6 بوصات. الارتفاع المدرج لمقطورتك هو 13 قدمًا و4 بوصات، ما يمنحك هامشًا قدره 2 بوصة. في وقت سابق هذا الشتاء، أعاد طاقم الطريق رصف هذا المقطع، والليلة الماضية كان هناك ثلج خفيف تم ضغطه على الطريق. ما هي الطريقة الأكثر دفاعًا للتعامل مع لافتة الخلوص المعلنة قبل أن تلتزم بالقيادة تحت الجسر العلوي؟","options":["اللافتة معلنة رسميًا، لذا فإن رقم 13 قدمًا و6 بوصات دقيق وهامش الـ 2 بوصة كافٍ قانونيًا للمتابعة.","لأن لافتات الخلوص تنطبق على المركبات المحملة، فإن الشاحنة الفارغة تجلس أخفض من ارتفاعها المدرج، لذا لديك مساحة إضافية ويمكنك المتابعة.","عامل الارتفاع المعلن على أنه غير موثوق: إعادة الرصف والثلج المضغوط يمكن أن يقللا من الخلوص الفعلي، وشاحنتك الفارغة في الواقع ترتفع أعلى، لذا جد مسارًا آخر أو تحقق قبل المتابعة.","أضف هامش الـ 2 بوصة إلى الارتفاع المعلن البالغ 13 قدمًا و6 بوصات، ما يمنحك حوالي 13 قدمًا و8 بوصات من الخلوص القابل للاستخدام، وهو وفير لمقطورتك."],"explanation":"لافتات الخلوص المعلنة قد تكون خاطئة لأن إعادة الرصف والثلج المضغوط يقللان من الخلوص الفعلي والشاحنة الفارغة ترتفع أعلى، لذا تحقق أو غيّر المسار قبل المتابعة."},"25":{"q":"أنت تندمج في طريق سريع مزدحم وتنظر إلى المرآة المحدبة (المنحنية) الكبيرة المثبتة على باب جانبك الأيمن. سيارة تراها في تلك المرآة المحدبة تبدو صغيرة وبعيدة إلى الخلف، فتشعر أن لديك متسعًا كافيًا لتغيير المسار. قبل أن تُقدم على ذلك، ماذا يجب أن تفهم بشأن ما تخبرك به هذه المرآة المحدبة؟","options":["تُظهر مساحة أوسع، لكن الأجسام تبدو أصغر وأبعد مما هي عليه فعليًا، لذا قد تكون تلك السيارة أقرب مما تبدو","تُكبّر منطقة قريبة ضيقة، لذا فإن السيارة في الواقع أبعد مما تبدو ولديك متسع إضافي","تُظهر الصورة نفسها بحجمها الحقيقي ومسافتها الحقيقية مثل المرآة المسطحة، لذا فإن الفجوة التي تراها دقيقة","تعكس فقط جانب مقصورتك ومقطورتك، لذا فإن أي مركبة فيها لا تُعد خطرًا بعد"],"explanation":"المرايا المحدبة تُظهر مساحة أوسع لكنها تجعل الأجسام تبدو أصغر وأبعد، لذا قد تكون المركبة أقرب مما تبدو."},"26":{"q":"أنت تقود على طريق سريع جاف وصافٍ عندما تلاحظ سيارة متوقفة على الكتف الأيمن أمامك وغطاء محركها مرفوع، وشخص يقف بالقرب من المصد الخلفي ينظر نحو حركة المرور. لا يوجد تصادم ولا طقس سيئ، وحركة المرور تسير بشكل طبيعي. لغرض رؤية المخاطر، كيف يجب أن تُصنّف هذه السيارة المتوقفة والشخص؟","options":["خطر، لأنه أي حالة طريق أو مستخدم طريق قد يتحول إلى حالة طارئة ويتطلب منك التصرف","ليس خطرًا، لأنه لا يوجد تصادم أو حالة طارئة تحدث بعد والطريق نفسه صافٍ","ليس خطرًا، لأن المخاطر لا توجد إلا في الطقس السيئ أو الضباب أو الجليد أو غيرها من ظروف القيادة الرديئة","خطر فقط إذا انسحبت السيارة المتوقفة فجأة إلى مسارك وأجبرتك على الفرملة بقوة"],"explanation":"الخطر هو أي حالة طريق أو مستخدم طريق قد يتحول إلى حالة طارئة، يُتعرّف عليه مبكرًا لتكون لديك مهلة للتفاعل."},"27":{"q":"أنت تسير في المسار الأيمن على طريق سريع من أربعة مسارات عندما تندفع سيارة خلفك بسرعة وتلتصق على بُعد بوصات من مقطورتك، ثم تنحرف حولك وتنقطع أمامك وتفرمل بقوة. مركبتك التجارية محمّلة بالكامل ومسافة توقفك طويلة بالفعل. أي مما يلي هو أفضل طريقة للتعامل مع هذا السائق العدواني؟","options":["أومض بأضوائك العالية وأطلق بوقك لتُشير إلى السائق بالتراجع، ثم حافظ على موضع مسارك","انتقل إلى المسار الأيسر وتجاوز السائق لتترك النزاع خلفك","حافظ على سرعتك وابقَ قريبًا خلفه حتى لا يتمكن السائق من قطع الطريق أمامك مرة أخرى","ارفع قدمك عن دواسة الوقود لفتح مساحة أمامك، وتجنّب التواصل البصري، ودع السائق العدواني يتقدم أمامك بمسافة كبيرة"],"explanation":"الاستجابة الآمنة للسائق العدواني هي رفع القدم عن دواسة الوقود لخلق مساحة، وتجنّب التواصل البصري، والسماح له بالتقدم أمامك بمسافة كبيرة."},"28":{"q":"إرسال الرسائل النصية أو الإمساك بالهاتف أثناء قيادة مركبة تجارية:","options":["مسموح تحت سرعة 30 ميلًا في الساعة","ممنوع","لا بأس به في حركة المرور الخفيفة","محظور فقط على السائقين الجدد"],"explanation":"محظور؛ فهو يرفع خطر التصادم بشكل كبير وقد يؤدي إلى استبعادك من الأهلية."},"29":{"q":"إنها ليلة مظلمة بلا قمر على طريق سريع ريفي من مسارين وأنت تستخدم أضواءك المنخفضة، التي تُضيء الطريق نحو 250 قدمًا أمامك. لا توجد حركة مرور قادمة. لتجنّب 'القيادة بسرعة تفوق مدى أضوائك الأمامية'، ما هو الشيء الأهم الذي يجب أن تفعله؟","options":["انتقل إلى الأضواء العالية وحافظ على سرعة ثابتة قدرها 55 ميلًا في الساعة، لأن الأضواء العالية تصل إلى نحو 350 قدمًا وهذه مسافة كافية للتفاعل","اقترب من الأضواء الخلفية لمركبة أمامك واستخدم أضواءها لتمديد المسافة التي يمكنك رؤيتها على الطريق","حافظ على سرعتك النهارية العادية لأن أضواءك الأمامية تُضيء بوضوح علامات المسار والطريق أمامك","قُد ببطء كافٍ بحيث تتمكن من التوقف الكامل ضمن المسافة التي تُضيئها أضواؤك الأمامية فعليًا"],"explanation":"لا تقُد أبدًا بسرعة تفوق مدى أضوائك الأمامية: قُد ببطء كافٍ للتوقف الكامل ضمن المسافة التي تُضيئها أضواؤك الأمامية فعليًا."},"30":{"q":"إنه ما بعد حلول الظلام مباشرة على طريق سريع غير مقسّم من مسارين، وصف من المركبات القادمة يقترب وأضواؤها الأمامية مُشغّلة. أحد السائقين يفشل في خفض أضوائه العالية، والوهج يجعل من الصعب عليك رؤية الطريق أمامك. للحفاظ على تكيّف عينيك والبقاء بأمان في مسارك حتى تمر المركبات، إلى أين يجب أن توجّه نظرك؟","options":["نحو الحافة اليمنى لمسارك، مستخدمًا الخط المرسوم أو علامات الطريق كدليل حتى تمر المركبات","مباشرة نحو الأضواء الأمامية القادمة حتى تتمكن من تقدير الفجوة بينك وبين المركبات الأخرى","نحو الأسفل إلى أدوات لوحة القيادة لتُريح عينيك من الوهج الساطع","بعيدًا نحو الطريق وراء حركة المرور القادمة بكثير للحفاظ على سرعتك ضمن مدى أضوائك الأمامية"],"explanation":"عند إصابتك بالعمى بسبب الأضواء العالية القادمة، انظر نحو الحافة اليمنى لمسارك واتبع الخط المرسوم حتى تبقى عيناك متكيفتين مع الظلام."},"31":{"q":"أنت تنفّذ عملية تسليم قبل الفجر عندما يتدفق حاجز كثيف من الضباب وتنخفض الرؤية إلى أقل من طول شاحنتك ومقطورتها. تقرر أن الأكثر أمانًا هو الاستمرار في التحرك ببطء حتى المخرج التالي بدلًا من التوقف في مسار السير. لرؤية الطريق وأن تُرى دون أن تُعمي نفسك، أي خيار للإضاءة والسرعة هو أفضل ممارسة؟","options":["شغّل أضواءك العالية لأقصى مدى وحافظ على سرعتك حتى لا تعيق حركة المرور","استخدم أضواءك المنخفضة (وأضواء الضباب إن وُجدت) وخفّض سرعتك حتى تتمكن من التوقف ضمن المسافة التي تراها","أطفئ أضواءك الأمامية وشغّل فقط أضواء الطوارئ الرباعية لتحديد موضعك","أبقِ الأضواء العالية مشغّلة لكن خفّف السرعة، لأن الضوء الإضافي أهم من الوهج في الضباب"],"explanation":"في الضباب، استخدم الأضواء المنخفضة (وأضواء الضباب إن وُجدت) وخفّف السرعة بما يكفي للتوقف ضمن المسافة التي تراها، لأن الأضواء العالية تنعكس وتقلل الرؤية."},"32":{"q":"إنه صباح صافٍ بدرجة حرارة نحو 31 درجة فهرنهايت، والطريق المفتوح أمامك يبدو جافًا تمامًا. أنت تسحب مقطورة محمّلة نحو جسر طويل يمتد عبر وادي نهر، مع جسر علوي مظلّل بعده مباشرة. أين يجب أن تتوقع فقدان الجر أولًا وتعدّل سرعتك قبل الوصول إليه؟","options":["على الطريق المفتوح الجاف، لأن وزن الشاحنة يضغط على الإطارات ويُدفئ الرصيف","على الجسر والجسر العلوي المظلّل، لأن الهواء يدور فوق وتحت السطح فيبرد ويتجمد قبل الطريق المحيط","لا مكان بعد، فما دام الرصيف يبدو جافًا لا يمكن أن يكون جليديًا حتى تنخفض درجة حرارة الهواء عن التجمد","فقط بعد الجسر العلوي، حيث أذابت أملاح الطريق والشمس بالفعل أي جليد على المنشآت المرتفعة"],"explanation":"الجسور والجسور العلوية معرّضة للهواء البارد فوق وتحت السطح، فتفقد الحرارة من جميع الجهات وتتجمد قبل الطريق المحيط."},"33":{"q":"إنها درجة حرارة أقل من التجمد بقليل في جولة صباحية مبكرة. الرصيف أمامك يبدو داكنًا ومبللًا، لكنك تلاحظ أن إطارات الشاحنة أمامك لا ترفع أي رذاذ على الإطلاق، وأن مراياك وهوائيك عليهما طبقة رقيقة لامعة. ما الذي يفعله سطح الطريق على الأرجح، وكيف يجب أن تستجيب؟","options":["الرصيف مبلل ببساطة من الصقيع الذائب؛ حافظ على سرعتك لأن المياه الراكدة توفّر جرًا طبيعيًا.","الطريق مجرد في طور الجفاف؛ ضغطة سريعة على الفرامل ستؤكد أن التماسك جيد وتسمح لك بالحفاظ على مسافة المتابعة.","تشكّلت طبقة رقيقة شفافة من الجليد الأسود؛ ارفع قدمك عن دواسة الوقود وتجنّب أي توجيه أو فرملة مفاجئة.","إنه مادة عازلة جديدة للأسفلت تجعل السطح يبدو مبللًا؛ قُد بخفة لكن السرعة العادية مقبولة."],"explanation":"طريق يبدو مبللًا دون رذاذ من الإطارات قرب درجة التجمد يُشير إلى جليد أسود، لذا ارفع قدمك عن دواسة الوقود وتجنّب التوجيه أو الفرملة المفاجئة."},"34":{"q":"إنه منتصف يوليو في غرب تكساس، ودرجة الحرارة الخارجية قرب 105 درجات والأسفلت ينزّ القار بشكل واضح. توقفت قبل ساعتين وكانت إطاراتك تعمل بشكل جيد، لكنك اندمجت للتو في امتداد طويل من الطريق السريع بسرعة الطريق. أي حالة يجب أن تكون أكثر يقظة لمراقبتها خلال هذه الجولة؟","options":["ارتفاع ضغط الإطارات الذي قد يؤدي إلى انفجار مع تراكم الحرارة","البوق يصبح مكتومًا بسبب الغبار والحرارة","انخفاض ضغط الإطارات بسبب تسرّب الهواء البارد من الصمامات","تغميق تظليل النوافذ وتقليل رؤيتك الأمامية"],"explanation":"في الحرارة الشديدة يتمدد الهواء داخل الإطار ويرتفع الضغط، وهو ما قد يؤدي مع الحرارة إلى انفجار."},"35":{"q":"أنت محمّل قرب وزنك الإجمالي المركّب المسموح (GCWR) وعلى وشك النزول على منحدر جبلي طويل وشديد الانحدار. الظروف جافة وصافية. عند وصولك إلى القمة، تبدأ بالتفكير في كيفية إبقاء سرعتك تحت السيطرة طوال الطريق نزولًا. أي نهج هو أفضل طريقة لإدارة سرعتك على هذا المنحدر؟","options":["ابقَ في ترس عالٍ حتى يعمل المحرك بسلاسة، واضغط على فرامل الخدمة باستمرار طوال الطريق لإبقاء السرعة مثبّتة عند مستوى آمن.","انتقل إلى الوضع المحايد وانزلق، مع تطبيق فرامل الخدمة بقوة في كل مرة تتسلل فيها سرعتك حتى تبقى الفرامل باردة بين التطبيقات.","أبقِ ناقل الحركة في ترس طريق عادي واعتمد على فرملة الانتظار (اليدوية) لكبح سرعتك أثناء النزول.","اختر ترسًا منخفضًا قبل أن تبدأ النزول حتى تقوم فرملة المحرك والترس بمعظم العمل، مستخدمًا فقط فرملة خدمة خفيفة وثابتة لتكميلها."],"explanation":"على منحدر طويل وشديد الانحدار اختر ترسًا منخفضًا قبل بدء النزول حتى تقوم فرملة المحرك والترس بمعظم العمل، مستخدمًا فقط فرملة خدمة خفيفة وثابتة."},"36":{"q":"أنت تسحب مقطورة محمّلة نزولًا على منحدر جبلي طويل وشديد الانحدار. اخترت ترسًا منخفضًا في الأعلى وكنت تستخدم تطبيقات فرملة خفيفة وثابتة، لكن دواسة الفرامل تصبح طرية ببطء، وسرعتك تستمر في الزحف، وتشم رائحة احتراق. أمامك على اليمين ترى منحدر هروب من الحصى. أي مما يلي يصف متى يجب أن توجّه مركبتك إلى ذلك المنحدر؟","options":["عندما تتلاشى فراملك أو تتعطل ولم تعد قادرًا على التحكم في سرعتك على المنحدر","عندما تكون فقط أميالًا قليلة في الساعة فوق سرعة الشاحنة المحددة للمنحدر","عندما تصبح حركة المرور على المنحدر كثيفة وتريد مساحة أكبر","عندما تريد استراحة قصيرة لتترك المحرك والفرامل يبردان قبل المتابعة"],"explanation":"استخدم منحدر الهروب فقط عندما تتلاشى فراملك أو تتعطل ولم تعد قادرًا على التحكم في سرعتك على المنحدر."},"37":{"q":"أنت تسير فارغًا في ظهيرة صيف حار بسرعة الطريق السريع عندما تسمع دويًا عاليًا وينحرف التوجيه فجأة بقوة نحو اليمين -- انفجر إطار أمامي. مركبتك الفارغة بلا مقطورة أصبحت الآن أصعب في التحكم. ما هو أول إجراء صحيح؟","options":["أمسك عجلة القيادة بإحكام، وابتعد عن الفرامل، ودع المركبة تتباطأ من تلقاء نفسها قبل الانحراف برفق عن الطريق","افرمل بثبات وقوة لكبح السرعة قبل أن تنحرف الشاحنة عن الطريق","وجّه بحدة بعيدًا عن الانحراف لإبقاء الشاحنة في مركز مسارك","اضغط القابض وانتقل إلى ترس أقل لاستخدام فرملة المحرك للتباطؤ"],"explanation":"بعد انفجار إطار أمامي، أمسك العجلة بإحكام وابتعد عن الفرامل، تاركًا المركبة تتباطأ من تلقاء نفسها قبل الانحراف برفق عن الطريق."},"38":{"q":"أنت تنزل على منحدر معتدل في شاحنة مستقيمة بفرامل هيدروليكية عندما تضغط على دواسة الفرامل فتغوص ببطء نحو الأرضية بقوة توقف شبه معدومة. حركة المرور خفيفة وهناك منحدر هروب للشاحنات الهاربة على بُعد نحو ميل أمامك. ما الذي يجب أن تجرّبه أولًا لإبطاء المركبة؟","options":["أطفئ المحرك فورًا حتى تساعد منظومة نقل الحركة في جرّ الشاحنة إلى التوقف","اضغط فرملة الانتظار بقوة في حركة واحدة حازمة لإقفال العجلات","اسحب مقبض إمداد هواء المقطورة (حماية الجرّار) لتفعيل فرامل المقطورة","اضغط دواسة الفرامل بسرعة وتكرار لمحاولة بناء ضغط هيدروليكي"],"explanation":"عندما تتلاشى دواسة الفرامل الهيدروليكية حتى الأرضية، اضغط عليها بسرعة وتكرار أولًا لإعادة بناء ضغط كافٍ لإبطاء أو إيقاف المركبة."},"39":{"q":"أنت تتسارع خارجًا من منعطف على طريق سريع مبلل من مسارين عندما يبدأ مؤخر جرّارك فجأة في الانزلاق نحو الكتف وتشعر أن عجلات الدفع فقدت تماسكها. أي مما يلي هو أفضل طريقة لاستعادة السيطرة في هذا الانزلاق لعجلات الدفع؟","options":["اضغط دواسة الفرامل بقوة وأبقها مضغوطة لإبطاء مؤخر المركبة وإعادته إلى الخط","توقف عن التسارع، واضغط القابض، ووجّه نحو الاتجاه الذي تريد أن تسير فيه المركبة","حافظ على دواسة وقود ثابتة ووجّه عكسيًا بقوة حتى تسحب قوة المحرك عجلات الدفع باستقامة","أقفل العجلات بالفرامل لإيقاف الانزلاق بأسرع ما يمكن"],"explanation":"لتصحيح انزلاق عجلات الدفع الناتج عن التسارع، توقف عن التسارع، واضغط القابض لقطع قوة المحرك، ووجّه نحو الاتجاه الذي تريد أن تسير فيه."},"40":{"q":"أنت تنزل على منحدر جبلي طويل ومنحنٍ بمقطورة محمّلة عندما يبدو سطح الطريق أمامك مبللًا ومظلّلًا. تبدأ منعطفًا، لكن مقدمة شاحنتك تستمر في الدفع للأمام مباشرة نحو الجهة الخارجية للمنعطف ويبدو التوجيه خفيفًا وغير مستجيب مهما أدرت العجلة. أي مما يلي هو السبب الجذري الأرجح لهذا الانزلاق للعجلات الأمامية؟","options":["أفلتّ الفرامل بلطف زائد عند دخول المنعطف، فلم تتماسك الإطارات الأمامية مع الرصيف أبدًا","انتقل الكثير من الحمولة إلى المحاور الخلفية، مما رفع الوزن عن محور التوجيه","أنت تقود بسرعة مفرطة بالنسبة للظروف الزلقة والمظلّلة (و/أو إطاراتك الأمامية مهترئة أو ناقصة النفخ)","فرملة المحرك في ترس منخفض أقفلت عجلات الدفع وأخرجت المقدمة عن الخط"],"explanation":"انزلاق العجلات الأمامية ينتج عن القيادة بسرعة مفرطة بالنسبة للظروف، إلى جانب إطارات أمامية مهترئة أو ناقصة النفخ."},"41":{"q":"إنها درجة حرارة أقل من التجمد بقليل وأنت تقوم بتوقف طارئ حازم على طريق سريع زلق عندما تنقطع سيارة أمامك. شاحنتك ومقطورتك مجهزتان بفرامل مانعة للانغلاق (ABS)، وأنت تضغط دواسة الفرامل بقوة حتى النهاية. في هذه الحالة، ما هي الفائدة الرئيسية التي توفرها فرامل ABS؟","options":["تمنع العجلات من الانغلاق حتى تتمكن من الاستمرار في التوجيه لتفادي الخطر","تضمن مسافة توقف أقصر بشكل ملحوظ من نفس الشاحنة دون فرامل ABS","توجّه الشاحنة تلقائيًا بعيدًا عن السيارة التي انقطعت أمامك","تسمح لك بالمتابعة بأمان على مسافة أقرب لأن التوقف أصبح الآن أسرع"],"explanation":"فرامل ABS تمنع العجلات من الانغلاق أثناء الفرملة الحازمة حتى تتمكن من التوجيه لتفادي الخطر."},"42":{"q":"أنت أول من يصل إلى موقع تصادم على طريق سريع مزدحم من مسارين. سيارة انقلبت وتسد مسارك؛ السائق واعٍ لكنه منهار على الباب، وحركة المرور لا تزال تقترب من خلف الحطام بسرعة الطريق السريع. توقفت بأمان وشغّلت أضواء الطوارئ. ما الذي يجب أن تفعله أولًا؟","options":["اسحب السائق المصاب بحذر من السيارة وأرقده على الكتف، تحسبًا لاشتعال المركبة","تابع القيادة إلى المخرج التالي للعثور على هاتف والاتصال بالطوارئ 911، لأنك لا تستطيع المساعدة بمفردك","انزل وادفع السيارة المحطّمة جانبًا حتى يخلو المسار وتستمر حركة المرور","ضع مثلثات تحذير عاكسة لتنبيه حركة المرور القادمة قبل فعل أي شيء آخر في الموقع"],"explanation":"في موقع التصادم الأولوية الأولى هي حماية الموقع، لذا ضع مثلثات تحذير عاكسة لتنبيه حركة المرور القادمة قبل فعل أي شيء آخر."},"43":{"q":"أنت تنحرف إلى الكتف بعد رؤية دخان يتصاعد من حجرة المحرك. فعّلت فرملة الانتظار وأمسكت بطفاية الحريق من نوع B:C. أي مما يلي هو الإجراء الأقل ملاءمة وأنت تستعد لمكافحة حريق المحرك هذا؟","options":["أطفئ المحرك في أقرب وقت ممكن","وجّه الطفاية نحو قاعدة النار، وليس نحو قمة اللهب","أبقِ غطاء المحرك مغلقًا قدر الإمكان وأطلق الطفاية عبر الفتحات أو الشقوق","افتح غطاء المحرك بالكامل حتى تتمكن من توجيه الطفاية مباشرة نحو اللهب"],"explanation":"فتح غطاء المحرك على مصراعيه يمدّ النار بأكسجين جديد وقد يجعلها تتأجج بعنف؛ أبقِ الغطاء مغلقًا ووجّه الطفاية عبر الفتحات بدلًا من ذلك."},"44":{"q":"في حفل زفاف الليلة السابقة لرحلة طويلة، تشرب باستمرار لكنك تتوقف قبل ساعات من موعد النوم. في الصباح التالي تشعر بصحو تام، وتتناول فطورًا كبيرًا، وتشرب فنجاني قهوة، وتقوم بمشي سريع في الهواء البارد قبل فحصك المسبق. وأنت تصعد إلى المقصورة، أي عبارة تعكس بشكل أفضل القانون والحقائق حول ما إذا كنت آمنًا لقيادة مركبتك التجارية؟","options":["لا شيء من تلك الخطوات خفّض تركيز الكحول في دمك؛ فقط مرور الوقت يفعل ذلك، ولا يجوز لك تشغيل المركبة التجارية بتركيز كحول 0.04% أو أعلى.","لأنك تشغّل مركبة تجارية، فإن الحد القانوني هو 0.08%، لذا فأنت بالتأكيد بخير ما دمت بقيت تحت ذلك.","القهوة والطعام والهواء البارد سرّعت التخلص من الكحول، لذا فإن تركيز الكحول في دمك الآن صفر فعليًا والحد لم يعد مهمًا.","الشعور بالصحو هو المعيار القانوني لسائق المركبة التجارية، لذا إذا لم تعد تشعر بالضعف فأنت تحت الحد وآمن للقيادة."],"explanation":"فقط مرور الوقت يخفّض تركيز الكحول في الدم، ولا يجوز لك تشغيل مركبة تجارية بتركيز كحول 0.04% أو أعلى."},"45":{"q":"أنهيت ورديتك قبل ساعات وتناولت عدة مشروبات على العشاء. يتصل المرسل ويطلب منك إعادة جرّار فارغ إلى الساحة الآن. شربت قهوة، وقمت بمشي سريع في هواء الليل البارد، وتشعر بصفاء ذهني. أي عبارة تعكس بشكل أفضل ما يحكم فعليًا ما إذا كنت لائقًا قانونيًا للقيادة؟","options":["القهوة والهواء البارد رفعا يقظتك بما يكفي ليصبح تركيز الكحول في دمك الآن تحت حد رخصة القيادة التجارية البالغ 0.04%.","لأنك تشعر بصفاء ذهني ولم تعد ضعيفًا، فأنت آمن وقانوني لتشغيل الجرّار.","فقط مرور الوقت يخفّض تركيز الكحول في دمك؛ لا شيء فعلته يسرّع معدل خروج الكحول من جسمك.","بما أن هذه نقلة فارغة بلا حمولة، فإن حد تركيز الكحول البالغ 0.04% لا ينطبق على هذه الرحلة."],"explanation":"فقط الوقت يخفّض تركيز الكحول في الدم، لأن الكبد يزيل الكحول بمعدل ثابت لا تستطيع القهوة أو الهواء النقي أو الاستحمام البارد تسريعه."},"46":{"q":"أنت تبدأ ورديتك عندما يُجري مفتش على جانب الطريق اختبار نفَس وتظهر نتيجتك 0.02% تركيز كحول -- كحول قابل للكشف، لكنه تحت حد رخصة القيادة التجارية البالغ 0.04%. تشعر بصحو تام ولا يوجد تصادم أو مخالفة أخرى. بموجب قواعد رخصة القيادة التجارية الفيدرالية، ماذا يحدث لك بعد ذلك؟","options":["لا شيء يتغير -- لأنك تحت حد 0.04% فأنت مُصرّح لك بمواصلة القيادة كالمعتاد","تُوقَف عن الخدمة لمدة 24 ساعة، رغم أن قراءتك تحت مستوى الاستبعاد البالغ 0.04%","تُعامَل بنفس معاملة قراءة 0.04% وتُتهم بجريمة القيادة تحت تأثير الكحول","تتلقى تحذيرًا مكتوبًا ويُسمح لك بمتابعة رحلتك بمجرد توقيعه"],"explanation":"أي كحول قابل للكشف تحت 0.04% يُوقف سائق رخصة القيادة التجارية عن الخدمة لمدة 24 ساعة، رغم أنه تحت مستوى الاستبعاد."},"47":{"q":"حمّلت وثبّتت مقطورة مسطحة عند الشاحن، وأكملت فحصك المسبق، وانطلقت إلى الطريق السريع. رحلتك 280 ميلًا دون استراحات مجدولة. مع علمك أن الحمولة تستقر وروابط التثبيت قد تنحلّ بعد بدء التحرك بقليل، عند أي نقطة يجب أن تقوم بأول توقف لفحص الحمولة وإعادة شدّ التثبيت؟","options":["خلال أول 50 ميلًا","خلال أول 150 ميلًا","بعد أول 3 ساعات من القيادة","خلال أول 100 ميل"],"explanation":"يجب أن تفحص الحمولة وأجهزة تثبيتها خلال أول 50 ميلًا، لأن روابط التثبيت تنحلّ مع استقرار الحمولة خلال تلك الأميال الأولى."},"48":{"q":"أثناء فحصك المسبق تقوم بتثبيت عارضة فولاذية واحدة طولها 18 قدمًا وتزن 4,200 رطل على مقطورة مسطحة. تريد استخدام أقل عدد من روابط التثبيت يفي بقواعد التثبيت الفيدرالية. أي عبارة تصف بشكل صحيح الحد الأدنى لعدد روابط التثبيت التي يجب عليك استخدامها؟","options":["رابطان على الأقل، لأنك تحتاج إلى واحد لكل 10 أقدام من الحمولة والقطعة ذات 18 قدمًا تتطلب اثنين","رابط واحد يكفي لأن العارضة قطعة واحدة متوازنة ترتكز مسطحة على السطح","ثلاثة روابط على الأقل، لأن أي قطعة أطول من 5 أقدام تتطلب دائمًا ثلاث نقاط تثبيت منفصلة","لا ينطبق عدد ثابت؛ تحتاج فقط إلى عدد كافٍ من الروابط لبلوغ 50% من وزن الحمولة كحد عمل مسموح"],"explanation":"تحتاج الحمولة إلى رابط تثبيت واحد على الأقل لكل 10 أقدام من الطول، وأي قطعة أطول من 5 أقدام تحتاج إلى رابطين على الأقل، لذا فإن قطعة بطول 18 قدمًا تتطلب رابطين."},"49":{"q":"أنت تحمّل مقطورة مسطحة عند الرصيف والمساحة الوحيدة المتبقية لعدة لفائف فولاذية ثقيلة هي المستوى العلوي من رف من طبقتين، بينما يمكن أن توضع التعبئة الأخف على السطح أسفله. يقول زميل إنه لا فرق أين تركب اللفائف الثقيلة ما دام الوزن الإجمالي يبقى تحت وزنك الإجمالي المسموح (GVWR). وأنت تنطلق، يتضمن المسار طريقًا متعرجًا من مسارين به عدة منعطفات حادة. مقارنةً بوضع اللفائف الثقيلة منخفضة على السطح، ما هي أهم نتيجة لتكديس ذلك الوزن الثقيل في الأعلى؟","options":["ليس له تأثير حقيقي على القيادة لأنك لا تزال ضمن وزن المركبة الإجمالي المسموح قانونيًا","يجعل إيقاف الشاحنة أسهل لأن وزنًا أكبر يضغط على الإطارات","يرفع مركز الثقل، مما يجعل الشاحنة أكثر عرضة بكثير للانقلاب في المنعطفات","يحسّن الثبات والتتبّع عبر المنعطفات لأن الحمولة موضوعة في مركز الإطار"],"explanation":"تحميل الحمولة الثقيلة في الأعلى يرفع مركز الثقل، مما يجعل الشاحنة ثقيلة من الأعلى وأكثر عرضة بكثير للانقلاب في المنعطفات."},"50":{"q":"أنت واقف في ساحة دائرة السلامة العامة في تكساس (DPS) تنظر إلى مركبة تريد الحصول على رخصة لقيادتها: جرار يقطر مقطورة محملة. التصنيف المجمّع المسجّل في الأوراق (الوزن الإجمالي المجمّع للمركبة GCWR) هو 33,000 رطل، والمقطورة وحدها مصنّفة عند 14,000 رطل. يخبرك صديق يحمل رخصة من الفئة B أن رخصته تغطي هذه المركبة 'لأن المجموع كله يتجاوز 26,001 رطل.' أيّ العبارات يحدّد بشكل صحيح الرخصة التي تحتاجها فعلاً ولماذا؟","options":["تكفي الفئة B، لأن التصنيف الإجمالي للتشكيلة المجمّعة 26,001 رطل أو أكثر.","الفئة A، لكن فقط لأن التصنيف الإجمالي للتشكيلة المجمّعة يبلغ 16,001 رطل أو أكثر.","تكفي الفئة B، لأن المقطورة المقطورة مصنّفة بأقل من 16,000 رطل.","الفئة A، لأن التشكيلة المجمّعة مصنّفة عند 26,001 رطل أو أكثر، وكذلك الوحدة المقطورة مصنّفة بأكثر من 10,000 رطل."],"explanation":"رخصة CDL من الفئة A مطلوبة عندما يكون الوزن الإجمالي المجمّع للمركبة (GCWR) 26,001 رطل أو أكثر، وتكون الوحدة المقطورة مصنّفة بأكثر من 10,000 رطل."},"51":{"q":"تحضر لاختبار مهارات رخصة CDL وتخطّط لقيادة جرار بمقطورة كمهنة، حيث كل مركبة ستشغّلها على الإطلاق مزوّدة بمكابح هوائية كاملة. لتوفير المال، يُعيرك صديق شاحنته المستقيمة الأقدم المزوّدة بمكابح هيدروليكية فقط، فتجتاز اختبار المهارات بأكمله فيها دون أي أخطاء. بناءً على كيفية تأثير هذا الخيار على رخصتك، أيّ العبارات صحيحة؟","options":["بما أنك أديت اختبار المهارات في مركبة لا تحتوي على مكابح هوائية، ستحمل رخصة CDL الخاصة بك قيداً على المكابح الهوائية يمنعك من قيادة أي مركبة تجارية مزوّدة بمكابح هوائية.","بما أنك اجتزت اختبار المهارات بنجاح دون أي أخطاء، ستحصل على رخصة CDL كاملة وغير مقيّدة وصالحة للمركبات ذات المكابح الهوائية.","بما أن الشاحنة التي اختُبرت فيها كانت تعمل بمكابح هيدروليكية، يمكن للفاحص ببساطة أن يُعفيك من جزء المكابح الهوائية ويصدر رخصة غير مقيّدة.","بما أنك تنوي قيادة جرارات بمقطورات ذات مكابح هوائية فقط للعمل، ستُصدر لك رخصة مقيّدة بالتشغيل الليلي حتى تعيد الاختبار."],"explanation":"أداء اختبار المهارات في مركبة بدون مكابح هوائية يؤدي إلى فرض قيد على المكابح الهوائية يمنعك من قيادة أي مركبة تجارية مزوّدة بمكابح هوائية."},"52":{"q":"أنت تقود حافلة سياحية على متنها 40 راكباً وتقترب من معبر سكة حديد على طريق سريع ريفي. المعبر مُعلّم بإشارة صليبية فقط، والبوابات مرفوعة، ولا توجد أضواء وامضة، ويمكنك الرؤية بوضوح في كلا الاتجاهين، ولا يوجد قطار في الأفق. ماذا يتوجب عليك فعله قبل العبور؟","options":["أبطئ، وانظر وأنصت، ثم تابع دون توقف لأن البوابات مرفوعة ولا توجد إشارات نشطة","توقّف توقفاً كاملاً، وانظر وأنصت، ثم اعبر فقط عندما تستطيع تجاوز السكة بالكامل دون توقف","حافظ على سرعتك حتى يكون لدى الحافلة زخم كافٍ لتجاوز كل السكك دون أن تتعطّل","توقّف فقط إذا كنت تنقل أيضاً مواد خطرة معلَّمة بالملصقات إضافةً إلى الركاب"],"explanation":"يجب على الحافلات والمركبات الناقلة لمواد خطرة معلَّمة بالملصقات أن تتوقف وتنظر وتنصت عند كل معبر سكة حديد، وألا تعبر إلا عندما تستطيع تجاوز السكة بالكامل دون توقف."},"53":{"q":"أنت تنقل جراراً بمقطورة طولها 53 قدماً محمّل بالكامل وتقترب من معبر سكة حديد أحادي المسار غير مُتحكَّم به على طريق ريفي ذي مسارين. لا توجد أضواء أو بوابات، ورؤيتك على طول السكة محجوبة جزئياً بالأشجار. أنت تعلم أنه يجب ألا تبدأ بالعبور إلا إذا كنت تستطيع تجاوز السكة بالكامل دون توقف. كم من الوقت تقريباً يجب أن تفترض أن مركبة مثل مركبتك تحتاجه لتجاوز سكة أحادية بالكامل، حتى تقدّر ما إذا كان من الآمن البدء بالعبور؟","options":["حوالي 3 ثوانٍ، لأن هذا تقريباً زمن رد فعلك عند سرعة الطريق السريع","الوقت الدقيق لا يهم طالما لا يوجد قطار ظاهر حالياً","حوالي 6 ثوانٍ، نفس زمن توقفك الكلي من سرعة 55 ميلاً في الساعة","14 ثانية على الأقل"],"explanation":"يحتاج جرار بمقطورة نموذجي إلى 14 ثانية على الأقل لتجاوز سكة حديد أحادية بالكامل، لذا اترك هذا القدر من الوقت قبل أن تلتزم بالعبور."},"54":{"q":"إنه منتصف بعد الظهر، لكن زخّة مطر غزيرة قلّلت الرؤية وأصبحت السماء رمادية داكنة. لا تزال تستطيع رؤية الطريق والمركبات الأخرى بوضوح كافٍ للقيادة، لذا تتساءل ما إذا كانت مصابيحك الأمامية ضرورية الآن أصلاً. لماذا يُعدّ تشغيل المصابيح الأمامية المنخفضة (LOW-beam) أفضل إجراء في هذا الموقف؟","options":["تشغيل المصابيح الأمامية يبقي مولّد الكهرباء تحت الحمل، مما يساعد على شحن البطارية أثناء قيادة طويلة وبطيئة في المطر","المصابيح الأمامية تخترق المطر وتحسّن بشكل حاد المدى الذي تستطيع أنت رؤيته أمامك على الطريق","المصابيح الأمامية تجعل شاحنتك أسهل بكثير للرؤية من قبل السائقين الآخرين في الضوء الخافت الممطر، مع أنك لا تزال ترى بوضوح كافٍ بنفسك","التحويل إلى الأضواء العالية في المطر يقذف أكبر قدر من الضوء إلى الأمام وهو الطريقة الأضمن لكي يُلاحَظ من قبل المرور القادم"],"explanation":"في الضوء الخافت أو الممطر يكون الغرض الأساسي من المصابيح الأمامية هو جعل شاحنتك مرئية للسائقين الآخرين، حتى عندما لا تزال أنت ترى بوضوح كافٍ."},"55":{"q":"أثناء فحص ما قبل الرحلة، تمشي حول شاحنة مسطحة محمّلة بأنابيب فولاذية وتتوقف لتفحص اللوح الأمامي ('حامل الصداع/الرف الواقي') المثبّت على مقدمة المقطورة خلف المقصورة. يسألك سائق جديد لماذا لا تسمح الشركة بتسيير الشاحنة دون وجود هذا اللوح في حالة جيدة. أيّ إجابة تذكر بشكل أفضل الغرض المتعلق بالسلامة الذي يخدمه هذا الجهاز؟","options":["يمنع الحصى السائب وحطام الطريق المتطاير من الإطارات الأمامية من الارتطام بالحمولة","يميّز الحمولة على أنها كبيرة الحجم حتى يحافظ المرور الخلفي على مسافة آمنة","يعمل كنقطة تثبيت خلفية يجب أن تتصل بها سلاسل الربط للتأمين القانوني","يحمي السائق بإيقاف الحمولة من الانزلاق إلى الأمام داخل المقصورة أثناء توقف مفاجئ أو حادث"],"explanation":"اللوح الأمامي، أو الرف الواقي، هو حاجز يوقف الحمولة من الانزلاق إلى الأمام داخل المقصورة وإصابة السائق أثناء توقف مفاجئ أو حادث."},"56":{"q":"إنه صباح باكر وأنت تجري فحص دوران حول جرارك بمقطورة قبل رحلة طويلة. أثناء فحصك للمحاور الخلفية، تنحني لتنظر إلى الإطارات المزدوجة. أيّ من الملاحظات التالية يستوجب إخراج المركبة من الخدمة قبل أن تتمكن من القيادة بشكل قانوني وآمن؟","options":["كل إطار من إطارات محور التوجيه يقيس عمق مداس 5/32 بوصة","الإطاران المزدوجان على المحور الخلفي مضغوطان ضد بعضهما وعلى تماس","الإطارات الأربعة على المحور الخلفي كلها من نفس الحجم والعلامة التجارية","إطارات الدفع الخلفية تقيس عمق مداس 3/32 بوصة"],"explanation":"يجب ألا تتلامس الإطارات المزدوجة أبداً، لأن التلامس يدل على عدم تطابق أو نقص في النفخ يولّد حرارة ويمكن أن يسبب انفجاراً."},"57":{"q":"أيّ مما يلي علامة على أنك متعب جداً للقيادة؟","options":["الانحراف داخل مسارك","ثقل الجفون","عدم تذكّر الأميال القليلة الماضية","كل ما سبق"],"explanation":"كل هذه علامات خطر للإرهاق — توقّف واسترح."},"58":{"q":"أنت تنهي فحص ما قبل الرحلة على جرارك بمقطورة قبل رحلة طولها 300 ميل. يخبرك مشرفك عبر اللاسلكي أن ضابطاً على جانب الطريق سيفحص شاحنتك بحثاً عن معدات الطوارئ المطلوبة فدرالياً. وأنت تنظر داخل المقصورة، تدرك أن عنصراً واحداً من عدّتك المعتادة مفقود وتبدأ بالقلق. أيّ مما يلي هو العنصر الذي لا تحتاجه قانونياً على متن المركبة لاجتياز هذا الفحص؟","options":["طفّاية حريق مشحونة ومصنّفة بشكل صحيح","إطار احتياطي منفوخ مخزّن على المركبة","مجموعة من ثلاثة مثلثات تحذيرية عاكسة حمراء","فيوزات كهربائية احتياطية، ما لم تستخدم الشاحنة قواطع دارة كهربائية"],"explanation":"معدات الطوارئ المطلوبة هي طفّاية حريق، وفيوزات احتياطية، ومثلثات تحذيرية؛ أما الإطار الاحتياطي فليس مطلوباً."},"59":{"q":"درجة الحرارة أقل من التجمّد بقليل وأنت تقطر مقطورة محمّلة صعوداً على منحدر خفيف على سطح جسر. تشعر أن عجلات الدفع الخلفية بدأت بالدوران وأن مؤخرة الجرار بدأت تتأرجح إلى اليسار. لإعادة المركبة تحت السيطرة، أيّ إجراء سيجعل الانزلاق أسوأ بدلاً من أن يساعدك على الاستعادة؟","options":["اضغط بقوة أكبر على دواسة الوقود لإعادة عجلات الدفع الدائرة إلى مكانها","ارفع قدمك عن دواسة الوقود واضغط على القابض (الكلتش) لتدع عجلات الدفع تبطئ","وجّه عجلة القيادة في الاتجاه الذي تريد أن يذهب إليه الجرار على المسار","كن مستعداً للتوجيه المضاد عندما تبدأ المقطورة بالاستقامة"],"explanation":"في انزلاق عجلات الدفع، توقّف عن ضخ القوة: ارفع قدمك عن دواسة الوقود واضغط على القابض حتى تستعيد عجلات الدفع التماسك."},"60":{"q":"الساعة الخامسة فجراً وأنت على وشك بدء رحلة طويلة. يخبرك زميل أن الشركة دفعت أصلاً لميكانيكي فاحص الأسبوع الماضي، لذا فإن فحص ما قبل الرحلة الخاص بك هذا الصباح هو في الحقيقة مجرد رصد لأي شيء قد يتركك عالقاً على الطريق السريع. أيّ عبارة تصف بشكل أفضل سبب اشتراط تكساس عليك إجراء فحص ما قبل الرحلة الخاص بك قبل كل رحلة؟","options":["غرضه المشروع الوحيد هو رصد عيوب السلامة الميكانيكية قبل أن تسبب حادثاً على الطريق.","إنه في جوهره إجراء قانوني شكلي يجب عليك تسجيله للبقاء ممتثلاً للقوانين الولائية والفدرالية.","قيمته الرئيسية هي منع الأعطال على جانب الطريق التي تكلّف الشركة وقتاً ومالاً.","إنه يخدم كل هذه الأغراض معاً: إيجاد عيوب السلامة، والوفاء بواجبك القانوني، ومنع الأعطال."],"explanation":"يخدم فحص ما قبل الرحلة ثلاثة أهداف معاً: إيجاد عيوب السلامة، والوفاء بواجبك القانوني كسائق، ومنع الأعطال المكلفة."},"61":{"q":"أنت تقود جراراً بمقطورة محمّلاً بسرعة الطريق السريع عندما تنحرف سيارة فجأة أمامك وتفرمل بشدة، تاركةً خطراً مباشراً في مسارك مع كون الكتف مفتوحاً إلى يمينك. التوقف في الوقت المناسب غير ممكن. أيّ عبارة تفسّر بشكل أفضل لماذا الفرملة الشديدة وحدها ليست دائماً أكثر استجابة طوارئ أماناً هنا؟","options":["غالباً ما يمكنك التوجيه حول الخطر في مسافة أقل مما يتطلبه التوقف، لذا فإن التوجيه نحو الكتف المفتوح قد يتجنّب الحادث عندما لا يستطيع التوقف ذلك.","التوقف غير مسموح به أبداً في حالة الطوارئ لأنه يهدر زمن رد الفعل الذي يلزمك القانون باستخدامه للتوجيه.","يجب تجنّب الفرملة الشديدة أساساً لأن المكابح ستسخن وتتلاشى خلال الثواني القليلة الأولى من أي توقف مفاجئ.","بما أن مقطورتك محمّلة، فإن مسافة توقفك الكلية عند 55 ميلاً في الساعة تنخفض إلى نحو 60 قدماً، لذا فالفرملة لا جدوى منها على ذلك المدى."],"explanation":"يمكنك عادةً التوجيه حول الخطر في مسافة أقل بكثير مما يتطلبه التوقف، لذا فإن التوجيه نحو كتف مفتوح قد يتجنّب الحادث عندما لا تستطيع الفرملة ذلك."},"62":{"q":"أنت تقود جراراً بمقطورة محمّلاً بسرعة 55 ميلاً في الساعة على طريق سريع جاف عندما تتوقف سيارة فجأة في مسارك بعيداً في الأمام. من اللحظة التي يظهر فيها الخطر أول مرة إلى اللحظة التي تتوقف فيها شاحنتك توقفاً كاملاً، تتكوّن مسافة توقفك الكلية من ثلاثة أجزاء منفصلة تحدث الواحد تلو الآخر. أيّ تسلسل يدرج هذه الأجزاء الثلاثة بالترتيب الزمني الصحيح، من الأول إلى الأخير؟","options":["مسافة رد الفعل، ثم مسافة الفرملة، ثم مسافة الإدراك","مسافة الإدراك، ثم مسافة رد الفعل، ثم مسافة الفرملة","مسافة الفرملة، ثم مسافة رد الفعل، ثم مسافة الإدراك","مسافة الإدراك، ثم مسافة الفرملة، ثم مسافة رد الفعل"],"explanation":"تحدث مسافة التوقف الكلية بالتسلسل: أولاً تدرك الخطر، ثم تتفاعل وتحرّك قدمك إلى المكبح، ثم تبطئ المكابح المركبة."},"63":{"q":"لتحذير السائقين خلفك من أنك تبطئ كثيراً، يجب أن:","options":["لا تفعل شيئاً على الإطلاق","تنقر المكبح لتومض الأضواء","تشغّل أضواءك العالية","تطلق البوق مراراً"],"explanation":"انقر المكابح لتومض مبكراً، أو استخدم أضواء التحذير (الهازارد) إذا كنت بطيئاً جداً."},"64":{"q":"حدّ الكحول في الدم لحامل رخصة CDL أثناء قيادة مركبة تجارية هو:","options":["0.08%","0.04%","0.10%","0.02%"],"explanation":"يُعدّ سائق رخصة CDL مخموراً قانونياً عند نسبة كحول في الدم 0.04% — نصف الحدّ المسموح به لسائقي السيارات."},"65":{"q":"أنت تنقل مقطورة محمّلة نزولاً على منحدر جبلي طويل وشديد. في منتصف الطريق للأسفل، تضغط على دواسة المكبح فتغوص إلى الأرضية دون أي مقاومة تقريباً — مكابح خدمتك تعطّلت والشاحنة تزداد سرعة. توجد إشارة إلى منحدر هروب للمركبات الهاربة على بعد نحو نصف ميل في الأمام. ما هو الإجراء الأفضل الوحيد الذي تتخذه؟","options":["انقل ناقل الحركة إلى الوضع المحايد حتى لا يقاومك المحرك بعد الآن، ودع الشاحنة تنزلق إلى توقف مُتحكَّم به","اضخّ دواسة المكبح بسرعة وبشكل متكرر لمحاولة إعادة بناء الضغط بينما تواصل النزول على المنحدر","وجّه المركبة نحو منحدر الهروب الأمامي، المبني لإيقاف مركبة مكابحها معطّلة","افتح باب السائق بسرعة واستعدّ للقفز بعيداً قبل أن تصل الشاحنة إلى الأسفل"],"explanation":"منحدرات الهروب للمركبات الهاربة مبنية لإيقاف مركبة ثقيلة تعطّلت مكابحها على منحدر بأمان، لذا استخدم واحداً متى توفّر."},"66":{"q":"كان المطر يهطل باستمرار خلال العشر دقائق الماضية وأنت تسيّر تشكيلة محمّلة بسرعة 60 ميلاً في الساعة على طريق سريع أملس ومعبّد جيداً. تلاحظ أن التوجيه أصبح خفيفاً وأن الشاحنة لا تستجيب عندما تجري تصحيحاً صغيراً للعجلة. أيّ عامل هو المسؤول الأكبر عن فقدان التماس مع الطريق هذا؟","options":["سطح الطريق جاف، لذا فقدت الإطارات الأمامية تماسكها على الإسفلت الساخن","يوجد ماء على الطريق وأنت تقود بسرعة مفرطة، لذا تركب الإطارات على طبقة من الماء","أنت تقود ببطء شديد، مما يدع الإطارات تغوص في الماء الراكد","إطاراتك جديدة تماماً ومداسها العميق يصرّف الماء بكمية مفرطة"],"explanation":"يحدث الانزلاق المائي (الهيدروبلانينغ) عندما يرفع الماء على الطريق مع السرعة المفرطة الإطارات بحيث تركب على طبقة من الماء بدلاً من الإسفلت."},"67":{"q":"إنها ظهيرة صيف حارة وقد توقفت للتو في منطقة استراحة بعد قيادة 120 ميلاً على الطريق السريع. أثناء فحص الدوران، تريد التأكد من أن إطارات محور الدفع منفوخة بشكل صحيح قبل المتابعة. أيّ طريقة تعطيك قراءة نفخ دقيقة وموثوقة؟","options":["اطرق كل إطار بمطرقة فحص الإطارات أو مطرقة عادية واحكم على النفخ من الصوت والارتداد","افحص الضغط الآن بمقياس بينما الإطارات لا تزال ساخنة من الطريق السريع، لأن ذلك هو ضغط تشغيلها الحقيقي","دع الإطارات تبرد أولاً، ثم افحص كل واحد بمقياس ضغط إطارات معاير بشكل صحيح","انظر بدقة إلى مقدار انتفاخ كل إطار في الأسفل وقارنه بالإطارات الأخرى"],"explanation":"افحص ضغط الإطارات فقط بمقياس معاير بشكل صحيح بعد أن تبرد الإطارات، لأن الحرارة الناتجة عن القيادة ترفع الضغط وتعطي قراءة مرتفعة زائفة."},"68":{"q":"أنت تندمج في طريق سريع مزدحم في جرارك بمقطورة محمّل. تنزوي سيارة قريبة خلف مؤخرتك اليمنى وتختفي من مراياك، بينما تسير سيارة أخرى قبالة جناحك الأيسر مباشرة. أخبرك زميل ذات مرة أن تكون أكثر قلقاً بشأن 'منطقة الـ No-Zone.' في هذا الموقف، ما هي منطقة الـ No-Zone التي يجب أن تديرها؟","options":["وسادة المسافة التي يجب أن تبقيها أمامك، والتي تساوي نحو 419 قدماً عند 55 ميلاً في الساعة","مناطق النقاط العمياء الكبيرة حول شاحنتك حيث يمكن للمركبات الأخرى أن تختفي من مجال رؤيتك","منطقة منع الوقوف على طول الرصيف الأيمن حيث لا يجوز لك التوقف لوضع مثلثات التحذير","المسار الأيسر الأقصى عالي الإشغال الذي يُمنع على الشاحنات دخوله"],"explanation":"تشير منطقة الـ No-Zone إلى مناطق النقاط العمياء الكبيرة المحيطة بالشاحنة من جميع الجوانب الأربعة حيث يمكن للمركبات الأخرى أن تختفي من مجال الرؤية."},"69":{"q":"أنت وحدك في ساحة محطة شاحنات مزدحمة وتحتاج إلى الرجوع بجرارك بمقطورة إلى مكان ضيق بمحاذاة جدار على يمينك. مقطورتك فارغة، والساحة مزدحمة بالمشاة، ولا تستطيع رؤية المنطقة خلف مؤخرتك اليمنى بوضوح. ما هي أكثر الطرق أماناً لإكمال هذا الرجوع؟","options":["ارجع نحو جانبك الأيمن (الأعمى) حتى يبقى الجدار في مجال رؤيتك عبر الزجاج الأمامي، وتابع ببطء","ارجع بسرعة بينما لا يزال لديك فجوة، لأن التلكؤ في الممر يخلق خطراً أكبر على المشاة","اعتمد على مرآتك اليمنى وحدها وتجنّب النزول، لأن التوقف للنظر يهدر الوقت في ساحة مزدحمة","أعد التموضع إذا لزم الأمر حتى تستطيع الرجوع نحو جانبك الأيسر (جانب السائق)، واستعن بمساعد أو مراقب يراقب منطقتك العمياء"],"explanation":"كلما أمكن، ارجع نحو جانب السائق (الأيسر) حتى تتمكن من الرؤية مباشرة على طول المقطورة، واستعن بمساعد أو مراقب يراقب منطقتك العمياء."},"70":{"q":"أنت تقود جراراً بمقطورة محمّلاً بسرعة 55 ميلاً في الساعة في ظروف جيدة وجافة عندما تظهر فجأة سيارة متعطّلة في مسارك على بعد بضعة أطوال شاحنة فقط في الأمام — أقرب بكثير من مسافة توقفك الكلية البالغة نحو 419 قدماً. المسار المجاور لك خالٍ. أيّ إجراء يعطيك أفضل فرصة لتجنّب الحادث؟","options":["وجّه المركبة حول الخطر إلى المسار الخالي، لأنك تستطيع عادةً الانعطاف لتفادي عائق في مسافة أقل مما يتطلبه التوقف","افرمل بأقصى قوة ممكنة واقفل العجلات، لأن الفرملة القصوى هي دائماً أكثر استجابة طوارئ أماناً","حافظ على سرعتك وقد بشكل مستقيم عبر العائق، واثقاً بأن كتلة الشاحنة ستدفع العائق جانباً","ابقَ في مسارك وافرمل بخفة، لأن مسافة توقفك البالغة 419 قدماً عند 55 ميلاً في الساعة ستوقفك في الوقت المناسب"],"explanation":"يمكنك عادةً التوجيه حول عائق في مسافة أقل مما يتطلبه الفرملة حتى التوقف، لذا استخدم مساراً خالياً لتفادي الخطر."},"71":{"q":"أنت تقترب من تقاطع مزدحم حيث يجب أن تنعطف يميناً، وهناك صف من المركبات خلفك. لإيصال نواياك بأمان وإعطاء السائقين الآخرين أكبر وقت للتفاعل، متى يجب أن تشغّل إشارة الانعطاف؟","options":["انقر مكابحك بضع مرات أولاً، ثم أشِر تماماً عند بدء الانعطاف حتى لا يرتبك السائقون خلفك بإشارة مبكرة","أشِر قبل الانعطاف بوقت كافٍ وأبقِ الإشارة مشغّلة حتى يكتمل الانعطاف","فقط بعد أن تبطئ وتتأكد من خلوّ التقاطع، لتجنّب الإشارة المبكرة جداً","أشِر مباشرة بعد إكمال الانعطاف لتأكيد المناورة للسائقين خلفك"],"explanation":"أشِر مبكراً، قبل الانعطاف بوقت كافٍ، وأبقِ الإشارة مشغّلة طوال الانعطاف حتى يكون لدى السائقين الآخرين أكبر وقت للتفاعل."},"72":{"q":"درجة الحرارة أقل من التجمّد بقليل، وقد ترك رذاذ متجمّد خفيف الطريق السريع يبدو رطباً ولامعاً. شاحنتك المحمّلة مزوّدة بمكبح محرك (مهدّئ سرعة / ريتاردر). وأنت تقترب من مقطع طريق قد تحتاج فيه إلى الإبطاء تدريجياً، ما هي أكثر الطرق أماناً للتعامل مع المهدّئ في هذه الظروف؟","options":["اترك المهدّئ مشغّلاً بالكامل، لأنه يقلل تآكل مكابح خدمتك في الطقس السيئ","أطفئ المهدّئ، لأنه يمكن أن يجعل عجلات الدفع تفقد التماسك وتنزلق على السطح الزلق","أبقِ المهدّئ على أعلى إعداد له حتى تتمكن من الإبطاء دون لمس دواسة المكبح","استخدم المهدّئ فقط عندما تتجاوز سرعتك 40 ميلاً في الساعة، ثم أطفئه دون ذلك"],"explanation":"أطفئ المهدّئ على الطرق الرطبة أو المتجمّدة أو الزلقة لأنه يفرمل عجلات الدفع فقط ويمكن أن يجعلها تفقد التماسك وتنزلق."},"73":{"q":"أنت تنقل مقطورة محمّلة بالكامل وقد بدأت بصعود منحدر طويل وشديد في الجبال. يبدأ جرارك بالتثاقل، ودورات المحرك (RPM) في الانخفاض، وسرعتك على الطريق تتناقص بسرعة. أيّ إجراء يبقيك تقود بأمان ويحافظ على أكبر قدر من قوة المحرك أثناء الصعود؟","options":["أبقِ ناقل الحركة في وضع الأوفردرايف واضغط على دواسة الوقود حتى الأرضية لاستعادة السرعة","انتقل إلى ترس أدنى حتى يبقى المحرك في نطاق قوته ويسحب الحمولة بثبات","ضع ناقل الحركة في الوضع المحايد ودع الزخم يحملك فوق قمة المنحدر","حافظ على ترسك الحالي واضخّ مكابح الخدمة بخفة لإبقاء المركبة تحت السيطرة"],"explanation":"على منحدر طويل وشديد صعوداً، انتقل إلى ترس أدنى لإبقاء دورات المحرك في نطاق قوتها حتى يسحب الحمولة بثبات."},"74":{"q":"أنت تسير فارغاً بسرعة 30 ميلاً في الساعة على طريق ريفي جاف وقد تعلّمت أن تترك لنفسك مساحة كافية للفرملة. يخلو المرور أمامك فتتسارع إلى 60 ميلاً في الساعة. مقارنةً بمسافة الفرملة التي احتجتها عند 30 ميلاً في الساعة، ماذا يجب أن تتوقعه الآن من مسافة الفرملة وحدها عند 60 ميلاً في الساعة؟","options":["تتضاعف فقط، لأنك ضاعفت سرعتك — لذا فإن ترك ضعف المساحة يكفي","تزداد نحو أربعة أضعاف، لأن مسافة الفرملة تنمو مع مربّع السرعة","تبقى كما هي تقريباً، لأن الشاحنة الفارغة تتوقف في مسافة أقصر من المحمّلة","تزداد بنحو النصف، لأن مسافة التوقف الكلية تشمل أيضاً مسافة رد الفعل"],"explanation":"تنمو مسافة الفرملة مع مربّع السرعة، لذا فإن مضاعفة سرعتك تجعلها أطول بنحو أربعة أضعاف."},"75":{"q":"الساعة الثانية صباحاً في رحلة ليلية طويلة وتلاحظ أن عينيك ثقيلتان، وأنك انحرفت داخل مسارك، ولا تستطيع تذكر الأميال القليلة الماضية. لا يزال أمامك عدة ساعات من وقت القيادة القانوني المتبقي في سجلك. أي إجراء هو الطريقة الوحيدة الفعّالة حقاً للتعامل مع هذا الإرهاق؟","options":["أنزل النافذة ودع الهواء البارد يهب على وجهك للبقاء يقظاً","اشرب قهوة كبيرة وواصل لإنهاء الرحلة ما دامت لديك ساعات متاحة","غادر الطريق السريع في مكان آمن وتوقف للراحة أو النوم قبل المتابعة","ارفع صوت الراديو واخفض درجة حرارة المقصورة لإبقاء نفسك مستيقظاً"],"explanation":"العلاج الأكيد الوحيد للنعاس هو التوقف عن القيادة والحصول على الراحة أو النوم، لأن لا شيء آخر يستعيد اليقظة حقاً."},"76":{"q":"إرسال الرسائل النصية أثناء قيادة مركبة تجارية:","options":["مسموح به عند الإشارات الحمراء","ممنوع","مطلوب بموجب القانون","لا بأس به على الطريق السريع"],"explanation":"إرسال الرسائل النصية واستخدام الهاتف المحمول باليد ممنوعان على سائقي المركبات التجارية."},"77":{"q":"تقود مقطورة جرار محملة على طريق سريع بأربعة مسارات عندما تحذرك لافتات برتقالية من منطقة عمل أمامك. وعندما تدخلها، ينخفض الحد المسموح ويظهر منظِّم مرور وعدة عمال بالقرب من مسار السير الأيمن. حركة المرور تتدفق بحرية ولا أحد خلفك مباشرة. أي إجراء هو الخيار الأفضل أثناء مرورك عبر المنطقة؟","options":["حافظ على سرعتك على الطريق السريع لأن المرور يتدفق وإخلاء المنطقة بسرعة يقلل من تعرضك للعمال","قلل سرعتك إلى الحد المسموح في منطقة العمل، وزد مسافة اتباعك، وابقَ يقظاً للعمال الذين يدخلون المسار","انتقل إلى المسار الأيسر بسرعتك الحالية وزد السرعة لتجاوز منظِّم المرور قبل أن تتغير الظروف","ابقَ قريباً من المركبة التي أمامك حتى لا يتمكن سائقون آخرون من الاندماج بينك وبينها ويجبروك على الكبح قرب العمال"],"explanation":"في منطقة العمل، خفف السرعة إلى الحد المسموح، وزد مسافة اتباعك، وراقب العمال الذين يدخلون المسار للحفاظ على مسافة توقف كافية."},"78":{"q":"أثناء فحصك قبل الرحلة تشرف على تحميل صناديق خفيفة لكنها ضخمة في شاحنتك الجافة المغلقة. ولإدخالها جميعاً، يكدسها الطاقم عالياً، مما يترك معظم الوزن مرتفعاً في المقطورة بدلاً من توزيعه منخفضاً على الأرضية. الوزن الإجمالي للحمولة ضمن حدود محاورك بشكل جيد والحمولة متمركزة جنباً إلى جنب. وأثناء انطلاقك واقترابك من أول منحنى لمنحدر الدخول إلى الطريق السريع، ما هو التأثير الأهم لكيفية تكديس هذه الحمولة؟","options":["لأن الوزن متمركز وضمن حدود المحاور، فإن المقطورة ستنعطف في الواقع بثبات أكبر من حمولة منخفضة التكديس.","التكديس العالي ليس له تأثير حقيقي على القيادة ما دام وزن الحمولة ضمن حدود محاورك القانونية.","مركز الجاذبية المرتفع يجعل المركبة أكثر عرضة بكثير للانقلاب أو الانقلاب في المنحنى، حتى لو بدت الحمولة آمنة على الطريق المستقيم.","الخطر الرئيسي هو مسافة توقف أطول بكثير، لأن الوزن المكدس عالياً يقلل من قوة احتكاك الكبح."],"explanation":"تكديس الحمولة الخفيفة الضخمة عالياً يرفع مركز الجاذبية، مما يزيد بشدة من خطر الانقلاب في المنحنى."},"79":{"q":"أثناء فحصك قبل الرحلة، تنقل لفافة فولاذية واحدة تزن 8,000 رطل على شاحنتك المسطحة. تبدأ بفحص سلاسل التثبيت ومشدّاتها للتأكد من أن حمولتك مثبتة قانونياً. بصرف النظر عن شرط أن تكون اللفافة الفولاذية مسدودة ومدعّمة، أي عبارة تصف بشكل صحيح الحد الأدنى لحد حمل العمل المجمّع (الإجمالي) الذي يجب أن توفره تثبيتاتك لهذه الحمولة البالغة 8,000 رطل؟","options":["يجب أن يساوي حد حمل العمل المجمّع للتثبيتات الوزن الكامل للحمولة، أي 8,000 رطل على الأقل.","يجب أن يكون حد حمل العمل المجمّع للتثبيتات ربع وزن الحمولة على الأقل، أي 2,000 رطل على الأقل.","يجب أن يكون حد حمل العمل المجمّع للتثبيتات ضعف وزن الحمولة على الأقل، أي 16,000 رطل على الأقل.","يجب أن يكون حد حمل العمل المجمّع للتثبيتات نصف وزن الحمولة على الأقل، أي 4,000 رطل على الأقل."],"explanation":"يجب أن يكون حد حمل العمل المجمّع لجميع التثبيتات نصف وزن الحمولة على الأقل."},"80":{"q":"تقترب من انعطاف يمين ضيق عند تقاطع في المدينة بمقطورة جرارك. أنت تعلم أن مقطورتك ستسير داخل مسار جرارك (الانحراف الداخلي)، وأنت قلق من أن العجلات الخلفية قد تتسلق الرصيف. لمنع مؤخرة المقطورة من اصطدام الرصيف، ما هي أكثر الطرق أماناً لتنفيذ هذا الانعطاف يميناً؟","options":["ابدأ الانعطاف بتوجيه مقدمة المركبة بعيداً إلى اليسار، ثم انعطف بحدة يميناً حتى تتجاوز المقطورة الرصيف","انعطف على نطاق واسع عند إكمال الانعطاف مع إبقاء مؤخرة مركبتك قريبة من الرصيف، حتى لا يتمكن سائقون آخرون من التسلل على يمينك","ابدأ الانعطاف من المسار الأيسر وزد السرعة خلاله لتقليل الوقت الذي تسد فيه التقاطع","التزم باليمين وانعطف على نطاق واسع إلى اليسار فقط عند الضرورة القصوى، متقبلاً أن المرور قد يمر بك على اليمين"],"explanation":"انعطف على نطاق واسع فقط عند إكمال انعطاف يمين مع إبقاء المؤخرة قريبة من الرصيف، حتى لا يتمكن أحد من التسلل على يمينك."},"81":{"q":"تنقل مقطورة محملة بالكامل على طريق سريع تابع للولاية وتقترب من منحنى واسع. تقرأ لافتة على جانب الطريق: 'منحنى — 45 ميلاً في الساعة.' شاحنتك ثقيلة وعالية الارتفاع، لكن الرصيف جاف والطقس صافٍ. أي عبارة تصف بشكل أفضل كيف يجب أن تتعامل مع سرعة المنحنى المعلنة البالغة 45 ميلاً في الساعة؟","options":["اعتبر 45 ميلاً في الساعة حداً أقصى للسيارات في الظروف الجيدة، وخفف السرعة تحته لأن شاحنتك المحملة العالية الارتفاع تحتاج إلى سرعة أقل لتجنب الانقلاب.","اعتبر 45 ميلاً في الساعة السرعة المحسوبة خصيصاً للشاحنات الثقيلة المحملة مثل شاحنتك، فيمكنك أخذ المنحنى بأمان عند 45 ميلاً في الساعة بالضبط.","بما أن الرصيف جاف والطقس صافٍ، يمكنك إضافة هامش وأخذ المنحنى بسرعة أعلى قليلاً من 45 ميلاً في الساعة.","السرعة المعلنة تنطبق فقط في الليل، لذا في وضح النهار الصافي يمكنك تجاهلها والحفاظ على سرعتك على الطريق السريع خلال المنحنى."],"explanation":"سرعات المنحنيات المعلنة محددة للسيارات في الظروف الجيدة، لذا يجب على الشاحنة المحملة العالية الارتفاع أن تخفف السرعة تحت اللافتة لتجنب الانقلاب."},"82":{"q":"تنقل مقطورة محملة بالكامل أسفل منحدر جبلي طويل وشديد الانحدار. في منتصف الطريق نزولاً، تلاحظ أن دواسة الكبح أصبحت أكثر ليونة وأن الشاحنة تكتسب السرعة تدريجياً رغم أنك كنت تضغط على المكابح باستمرار طوال الطريق نزولاً. أي مما يلي هو السبب الأرجح لفقدان قوة الكبح هذا؟","options":["لا تزال المكابح باردة لأنك بدأت النزول للتو، لذا لم تمسك بالكامل بعد","المكابح ارتفعت حرارتها من استخدامها المستمر، مما تسبب في تلاشي قوتها وفقدان قدرتها على التوقف","المقطورة محملة بخفة شديدة، لذا لا يوجد وزن كافٍ يضغط أحذية الكبح على الأسطوانات","أحذية الكبح جديدة تماماً وتحتاج إلى التآكل قبل أن تثبّت المركبة على المنحدر"],"explanation":"الضغط المستمر على المكابح أسفل منحدر طويل يرفع حرارتها، مما يسبب تلاشي الكبح وفقدان قوة التوقف."},"83":{"q":"أنت محمّل وتسير على طريق سريع رطب بأربعة مسارات عندما تنحرف سيارة فجأة أمامك وتكبح بقوة. مصباح نظام الكبح المانع للانغلاق (ABS) في لوحة القيادة مطفأ، إذن النظام يعمل. وعندما تضغط دواسة الكبح حتى الأرض ويتفعّل نظام ABS، ما هي الفائدة الرئيسية التي يجب أن تتوقعها من ABS في هذا التوقف القوي؟","options":["يضمن أنك ستتوقف في مسافة أقصر بشكل ملحوظ من شاحنة بدون ABS","يضخ المكابح تلقائياً حتى لا تحتاج بعد الآن إلى الكبح المتقطع على الرصيف الجاف","يمنع عجلاتك من الانغلاق حتى تتمكن من الاستمرار في التوجيه والبقاء في مسارك أثناء الكبح بقوة","يتيح لك تخطي فحص ضبط المكابح أثناء فحصك قبل الرحلة لأن الحاسوب يراقب المكابح"],"explanation":"يمنع نظام ABS العجلات من الانغلاق أثناء الكبح القوي، فتحتفظ بالتحكم في التوجيه للبقاء في مسارك أو تجنب خطر."},"84":{"q":"لقد أنزلت للتو آخر حمولة لك وتنقل الآن المقطورة الفارغة عائداً إلى الساحة على طريق رطب بمسارين. تكبح سيارة أمامك بقوة وعليك التوقف بسرعة. مقارنةً بما كنت عليه عندما كنت محملاً بالكامل في وقت سابق اليوم، ماذا يجب أن تتوقع من مركبتك الفارغة في هذا الموقف؟","options":["بدون وزن حمولة يضغط للأسفل، تمسك الإطارات الطريق بشكل أفضل، لذا ستتوقف دائماً في مسافة أقصر مما كنت محملاً.","الشاحنة الفارغة تتصرف تماماً مثل المحملة، لذا مسافة توقفك لا تتغير في الحالتين.","لأن الوزن قليل جداً، لا يمكن للعجلات أن تنغلق أو تنزلق، لذا فإن الكبح القوي آمن تماماً الآن.","الشاحنة الفارغة لديها قوة احتكاك أقل ويمكن أن ترتد، لذا قد يستغرق توقفها وقتاً أطول مما كانت محملة."],"explanation":"الشاحنة الفارغة لديها قوة احتكاك أقل وتميل إلى الارتداد، لذا قد يستغرق توقفها وقتاً أطول مما كانت محملة بالكامل."},"85":{"q":"إنها قبل غروب الشمس بنحو ساعة وبدأ مطر خفيف عندما تنطلق على طريق سريع بمسارين. الرؤية لا تزال جيدة إلى حد ما ويمكنك رؤية الطريق بوضوح بدونها، لكن السيارات القادمة أصبح من الصعب تمييزها على خلفية السماء الرمادية. ما هي أفضل ممارسة لمصابيحك الأمامية في هذا الموقف؟","options":["اتركها مطفأة، لأن تشغيلها مطلوب فقط عندما يحل الظلام تماماً ولا تستطيع رؤية الطريق أمامك","شغّلها الآن، لأنها تساعد السائقين الآخرين على رؤيتك عند الغسق وفي المطر أو الضباب أو غيرها من ظروف الإضاءة المنخفضة","استخدم الأضواء العالية فقط، لأن المطر والضوء المتلاشي يعنيان أنك بحاجة إلى أقصى إضاءة أمامية متاحة","انتظر حتى تصل إلى طريق سريع مقسّم عالي السرعة، لأن المصابيح الأمامية تلزم بشكل رئيسي للسرعات العالية"],"explanation":"شغّل المصابيح الأمامية عند الغسق وفي المطر أو الضباب لأنها تجعل مركبتك مرئية للسائقين الآخرين في ظروف الإضاءة المنخفضة."},"86":{"q":"تقوم بإرجاع مقطورتك إلى رصيف تحميل ضيق وتنظر في المرآة المحدبة (المنحنية) الكبيرة في الجانب الذي يجلس فيه الراكب. سيارة تعلم أنها متوقفة على بُعد بضعة أقدام فقط خلف مصدّك الخلفي تبدو صغيرة وبعيدة في تلك المرآة. قبل أن تواصل الإرجاع، ماذا يجب أن تفهم بشأن ما تعرضه عليك هذه المرآة المحدبة؟","options":["إنها تمنحك مجال رؤية أوسع، لكن الأشياء فيها تبدو أصغر وأبعد مما هي عليه حقاً، لذا فإن تلك السيارة أقرب مما تبدو","إنها تكبّر المنظر، لذا تبدو الأشياء فيها أكبر وأقرب مما هي عليه حقاً، مما يعني أن تلك السيارة أبعد فعلاً مما تبدو","إنها تظهر الحجم والمسافة الحقيقيين للأشياء، فيمكنك أن تثق بأن السيارة بعيدة بقدر ما تبدو في المرآة","إنها معطلة، لأن المرآة المضبوطة بشكل صحيح لن تجعل أبداً شيئاً قريباً يبدو صغيراً، والمرايا المحدبة غير قانونية على المركبات التجارية على أي حال"],"explanation":"المرآة المحدبة تمنح مجال رؤية أوسع لكنها تجعل الأشياء تبدو أصغر وأبعد، لذا فهي في الواقع أقرب مما تبدو."},"87":{"q":"تقود مقطورة جرار محملة بسرعة الطريق السريع عندما تكتشف، على بُعد نحو 12 إلى 15 ثانية أمامك، سيارة معطلة تسد جزئياً المسار الأيمن وأضواء الخطر فيها تومض. حركة المرور حولك لا تزال تتحرك بشكل طبيعي ولا توجد حالة طوارئ فورية بعد. ماذا يجب أن يكون أول إجراء لك؟","options":["حافظ على سرعتك وموضعك حتى تقترب السيارة بما يكفي للحكم بالضبط على مدى دخولها إلى مسارك","ابدأ بالاستعداد للتفاعل الآن — ارفع قدمك عن دواسة الوقود، وافحص مراياك، وخطط لمسار هروب حتى تتمكن من التكيف بسلاسة قبل أن تصبح حالة طوارئ","طبّق فوراً كبحاً متقطعاً قوياً ومضبوطاً لتقليل أكبر قدر ممكن من السرعة على الفور","وجّه المركبة إلى المسار الأيسر على الفور وزد السرعة لإخلاء المنطقة قبل أن تتفاعل حركة المرور الأخرى"],"explanation":"اكتشاف الخطر مبكراً يمنحك وقتاً للتفاعل، لذا ارفع قدمك عن دواسة الوقود، وافحص المرايا، وخطط لمسار هروب قبل أن يصبح حالة طوارئ."},"88":{"q":"تسير بمقطورة فارغة بسرعة 55 ميلاً في الساعة على طريق سريع أثناء مطر غزير. تشعر بأن المقود أصبح خفيفاً وأن الشاحنة بدأت تشعر وكأنها تطفو، مع توقف الإطارات الأمامية عن تتبع الطريق بالكامل. تدرك أنك بدأت في الانزلاق المائي. أي إجراء يمنحك أفضل فرصة لاستعادة قوة الاحتكاك بأمان؟","options":["اضغط بقوة على دواسة الكبح للتباطؤ بسرعة وإجبار الإطارات على العودة إلى الرصيف","وجّه بقوة نحو الكتف حتى تغرز الإطارات الأمامية في السطح الأكثر خشونة وتمسك","ارفع قدمك عن دواسة الوقود، وأبقِ المقود مستقيماً، ودع الشاحنة تتباطأ حتى تمسك الإطارات مجدداً","خفّض السرعة بقوة واستخدم كبح المحرك لسحب السرعة بأسرع ما يمكن"],"explanation":"عند الانزلاق المائي تفقد الإطارات تلامسها مع الطريق، لذا ارفع قدمك عن دواسة الوقود وأبقِ المقود مستقيماً حتى تتباطأ وتمسك مجدداً."},"89":{"q":"لقد قدت للتو مركبتك المركّبة المحملة ببطء عبر معبر مائي منخفض غمرته المياه، وارتفع الماء بما يكفي لغمر محاور عجلاتك. وأثناء تسارعك للعودة إلى سرعة الطريق، تنقر المكابح فتشعر بأنها تمسك بضعف وبشكل غير متساوٍ. أي إجراء هو أفضل طريقة لاستعادة الكبح الآمن؟","options":["انعطف إلى الكتف وانتظر حتى تجف أسطوانات الكبح بالهواء قبل المتابعة","اضغط على دواسة الكبح بقوة عدة مرات لإخراج الماء من البطانات","خفّض السرعة واعتمد فقط على كبح المحرك، تاركاً مكابح الخدمة دون مساس للأميال القليلة القادمة","واصل القيادة ببطء وطبّق ضغطاً خفيفاً وثابتاً على المكابح لتجفيفها عبر حرارة الاحتكاك"],"explanation":"جفّف المكابح المبللة بالقيادة ببطء مع تطبيق ضغط خفيف وثابت حتى تبخّر حرارة الاحتكاك الماء وتبقى متحكماً."},"90":{"q":"أنت متأخر عن جدولك على طريق سريع ريفي بمسارين بحد معلن يبلغ 55 ميلاً في الساعة. المركبة التي أمامك تتحرك ببطء، وأنت متلهف لتجاوزها. في أي من المواقف التالية يكون محاولة التجاوز هي الأقل أماناً وبالتالي شيء يجب ألا تفعله؟","options":["تقترب من قمة تل ولا تستطيع رؤية ما إذا كانت أي مركبة قادمة نحوك في المسار المقابل","أنت على امتداد طويل ومستوٍ ومستقيم حيث يمكنك أن ترى بوضوح أن الطريق خالٍ لأكثر من ربع ميل أمامك","لقد دخلت منطقة تجاوز معلّمة بخط أصفر متقطع على جانبك ورؤية واضحة أمامك","يمكنك أن ترى أن المسار المقابل خالٍ ولديك مساحة كافية للعودة إلى مسارك بمسافة وافرة قبل أي مرور قادم"],"explanation":"لا تتجاوز أبداً حيث لا تستطيع الرؤية بعيداً بما يكفي أمامك، مثل قرب قمة تل، لأن المركبات القادمة تبقى مخفية حتى يفوت الأوان."},"91":{"q":"تقود مقطورة جرار محملة على منحدر دخول قصير. الطريق السريع على يسارك يتحرك بسرعة نحو 60 ميلاً في الساعة، وترى فجوة قابلة للاستخدام تنفتح بين سيارتين في المسار الأيمن أمامك. وعندما تصل إلى نهاية مسار التسارع، ما هي أكثر الطرق أماناً للدخول إلى حركة المرور؟","options":["تباطأ حتى التوقف تقريباً عند نهاية المنحدر وانتظر فجوة كبيرة إضافية قبل الخروج","استخدم مسار التسارع لرفع سرعتك قريباً من تدفق حركة المرور، ثم اندمج بسلاسة في الفجوة المفتوحة","أبقِ سرعتك منخفضة وادخل المسار برفق، مجبراً السيارات خلفك على الكبح وإفساح المجال لك","حافظ على زحف بطيء وثابت أسفل المنحدر حتى يكون لديك وقت أكبر للحكم على حركة المرور قبل الاندماج"],"explanation":"استخدم مسار التسارع للوصول إلى سرعة قريبة من تدفق حركة المرور، ثم اندمج في فجوة حتى يكون فرق السرعة مع المركبات الأخرى أصغر ما يمكن."},"92":{"q":"تقود مقطورة جرار محملة في المسار الأيمن من طريق سريع مقسّم بأربعة مسارات عندما تسمع صفارة إنذار وترى سيارة إسعاف تقترب بسرعة في مراياك بأضواء وامضة. حركة المرور معتدلة وهناك كتف مرصوف على يمينك. أي إجراء هو الاستجابة الأفضل؟","options":["حافظ على مسارك وسرعتك حتى تتمكن سيارة الإسعاف من توقع مسارك وتجاوزك من اليسار","زد السرعة للبقاء أمام سيارة الإسعاف حتى تصل إلى المخرج التالي، ثم غادر الطريق السريع","أشّر، ووجّه المركبة نحو الكتف الأيمن، وأوقف مركبتك عندما يكون ذلك آمناً لإخلاء المسار","انتقل يساراً إلى مسار التجاوز لفتح المسار الأيمن والكتف لمركبة الطوارئ"],"explanation":"لمركبة طوارئ مقتربة بأضواء وصفارة، أشّر واتجه إلى الكتف الأيمن وتوقف عندما يكون ذلك آمناً لإفساح الطريق وإخلاء المسار."},"93":{"q":"يندلع حريق كهربائي صغير في حجرة محرك جرارك بعد أن تنعطف إلى الكتف. تمسك طفاية الحريق، وتقف في اتجاه مواجه للريح، وتسحب المسمار، وتوجّه الفوهة. باتباع طريقة PASS بشكل صحيح، بعد أن تضغط المقبض، ما هو الإجراء الأخير الذي يجب أن تتخذه لإطفاء الحريق بفعالية؟","options":["أبقِ الفوهة ثابتة ووجّهها مباشرة نحو قمة اللهب المرئي حتى يخمد","توقف عن التفريغ فوراً بمجرد ظهور الدخان حتى لا تهدر الطفاية","أدِر الطفاية بحركة دائرية فوق الحريق لنشر المادة على مساحة واسعة","حرّك الفوهة من جانب إلى آخر، موجّهاً نحو قاعدة الحريق، حتى يُطفأ"],"explanation":"الخطوة الأخيرة في طريقة PASS هي تحريك الفوهة من جانب إلى آخر عند قاعدة الحريق، حيث يحترق الوقود، لخنقه وإطفائه."},"94":{"q":"تقود على طريق سريع ريفي بمسارين عندما يقترب سائق آخر بجانبك مشيراً وصارخاً بأن أحد إطارات مقطورتك مشتعل. تنعطف إلى الكتف، وتثبّت مكابحك، وتمسك طفاية الحريق وعدة السلامة على الطريق. وأثناء اقترابك من الإطار المشتعل، ما هو الإجراء الأنسب للسيطرة على هذا الحريق؟","options":["اغمر الإطار بكمية وفيرة من الماء لتبريده، لأن حريق الإطار يولّد حرارة شديدة ويحتاج إلى تبريد مستمر لإطفائه","وجّه طفاية الحريق الكيميائية الجافة (B:C) مباشرة نحو قاعدة اللهب وأبقها هناك حتى تفرغ العبوة","اتركه وشأنه ودعه يحترق من تلقاء نفسه من مسافة آمنة، لأن خنق حريق المطاط يجعله يشتعل مجدداً فقط","أضف الهواء بحذر إلى الإطار لمنع الهيكل من الانهيار بينما يخمد اللهب"],"explanation":"حريق الإطار يحتفظ بحرارة شديدة في المطاط، لذا اغمره بكمية وفيرة من الماء للتبريد المستمر وإلا اشتعل مجدداً."},"95":{"q":"الحرارة أقل بقليل من التجمد ومطر خفيف بدأ يكسو الطريق بطبقة جليدية. أثناء حفاظك على سرعتك العادية على الطريق السريع عبر منحنى واسع، تبدأ مؤخرة مقطورة جرارك فجأة في الانزلاق وتشعر بأن المقطورة تدفع المقصورة جانبياً. بالنظر بصدق إلى اللحظة التي بدأ فيها الانزلاق، ما هو السبب الأرجح الوحيد؟","options":["إطارات محور التوجيه الأمامي كانت متآكلة قرب الحد الأدنى البالغ 2/32 بوصة وفقدت قوة احتكاكها أولاً","كنت تسير بسرعة كبيرة جداً بالنسبة لظروف الطريق الزلق القريب من التجمد","استخدمت توجيهاً سلساً ولطيفاً عبر المنحنى بدلاً من التصحيحات الحادة","كانت مقطورتك تسير فارغة، والمقطورات الفارغة تمسك الطريق دائماً بشكل أفضل من المحملة"],"explanation":"معظم الانزلاقات تأتي من القيادة بسرعة كبيرة جداً بالنسبة للظروف، والطرق الزلقة القريبة من التجمد تقلل قوة الاحتكاك فتصبح السرعة الآمنة عادةً مفرطة."},"96":{"q":"الحرارة أقل بقليل من التجمد ومطر خفيف كان يتساقط. أنت في المسار الأوسط من طريق سريع بثلاثة مسارات عندما تبدأ المقطورة خلفك تشعر بالخفة وتبدأ في الانحراف نحو المسار التالي. من بين الإجراءات أدناه، أي واحد يمنحك أفضل فرصة للحفاظ على السيطرة على المركبة وتجنب انزلاق كامل؟","options":["اكبح بقوة وأبقِ الدواسة مضغوطة بثبات لتقليل السرعة بأسرع ما يمكن","نفّذ تصحيح توجيه سريعاً وحاداً نحو وسط مسارك لإيقاف الانحراف","ارفع قدمك عن دواسة الوقود ونفّذ مدخلات توجيه وكبح سلسة ولطيفة للحفاظ على قوة الاحتكاك","حافظ على سرعتك الحالية ووجّه بقوة، لأن الإطارات لا تزال تمسك في المسار الأوسط"],"explanation":"على الطرق الزلقة القريبة من التجمد، قلل الطلب على الإطارات برفع قدمك عن دواسة الوقود وتنفيذ مدخلات توجيه وكبح سلسة ولطيفة للحفاظ على قوة الاحتكاك."},"97":{"q":"إنه منتصف بعد الظهر في أواخر يوليو وكنت تسير محملاً على أسفلت ساخن لعدة ساعات. خلال محطة استراحة تقرر فحص إطاراتك بشكل أكثر تكراراً من المعتاد في هذه الرحلة. ما هو السبب الأفضل لفعل ذلك في هذه الظروف؟","options":["الرصيف الساخن يبرّد الهواء داخل الإطارات، فتفقد الضغط وتعمل بضغط منخفض","الحرارة تليّن مطاط المداس، وهو السبب الرئيسي للانفجار في الصيف","الإطارات تنكمش فيزيائياً في الحرارة، مما يقلل من حجم مساحة التلامس","الحرارة ترفع ضغط الهواء داخل الإطارات، مما قد يؤدي إلى انفجار"],"explanation":"في الطقس الحار يتمدد الهواء المحبوس داخل الإطارات ويرتفع الضغط، مما قد يؤدي إلى انفجار."},"98":{"q":"تنقل بضائع على طريق سريع ريفي بمسارين عندما تدخل في كتلة ضباب كثيف بحيث لم تعد ترى علامات المسار أو أي مركبة أمامك، حتى بعد إبطاء السرعة والتحويل إلى أضوائك المنخفضة. تقليل السرعة أكثر لم يستعد قدرتك على رؤية مسار آمن. ما هو الإجراء الأكثر أماناً؟","options":["حوّل إلى الأضواء العالية لدفع المزيد من الضوء عبر الضباب واستمر في الزحف للأمام ببطء شديد","تباطأ حتى التوقف تقريباً في مسارك، وشغّل أضواء الخطر، واستمر في الزحف للأمام","انعطف بالكامل خارج الطريق، وابتعد جيداً عن حركة المرور، وشغّل أضواءك وأضواء الخطر، وانتظر حتى ينقشع الضباب","حافظ على سرعة بطيئة ثابتة واتبع الأضواء الخلفية للمركبة التي أمامك للبقاء في مسارك"],"explanation":"عندما يكون الضباب كثيفاً جداً بحيث لا ترى مساراً آمناً حتى بسرعة منخفضة، انعطف بالكامل خارج الطريق، وابتعد عن حركة المرور، وشغّل الأضواء وأضواء الخطر، وانتظر حتى ينقشع."},"99":{"q":"أكملت فحصاً شاملاً قبل الرحلة هذا الصباح، وثبّتت حمولتك، وكان كل شيء على ما يرام. بعد ثلاث ساعات من رحلتك تتوقف لاستراحة طعام، ويسألك سائق زميل لماذا تتجول حول مركبتك وتفحص حمولتك مجدداً وقد فحصتها بالفعل قبل المغادرة. ما هو السبب الأفضل لمواصلة الفحص طوال اليوم؟","options":["الفحص السليم عملية مستمرة تُجرى قبل الرحلة وأثناءها (في الطريق) وبعدها، لأن حالة المركبة وتثبيت الحمولة يمكن أن يتغيرا أثناء القيادة.","بمجرد اجتياز المركبة فحصاً كاملاً قبل الرحلة، يعتبرها القانون صالحة للسير لبقية تلك الرحلة، لذا فإن التجول حولها مجرد عادة شخصية وليس متطلباً.","الفحوص في الطريق تلزم فقط إذا أضاء مصباح تحذير أو تعطلت المركبة فعلاً، لأن فحص ما قبل الرحلة المجتاز يغطي بالفعل كل شيء ميكانيكي.","إعادة الفحص مطلوبة فقط لأنه يجب عليك فحص الحمولة ضمن أول 50 ميلاً، وبعد ذلك الفحص الأول لا يلزم أي فحص إضافي للمركبة لبقية اليوم."],"explanation":"الفحص عملية مستمرة — تُجرى قبل الرحلة وأثناءها (في الطريق) وبعدها — لأن ضغط الإطارات وتثبيت الحمولة ومستويات السوائل كلها تتغير أثناء القيادة."},"100":{"q":"حمّلت هذا الصباح مقطورة مسطحة محملة بلفائف الفولاذ وخرجت من الساحة إلى الطريق السريع بين الولايات. بعد نحو 35 ميلاً على الطريق، لاحظت منطقة استراحة واسعة بها متسع للسير حول شاحنتك بالكامل. إجمالي رحلتك يتجاوز 300 ميل. وفقاً للإجراءات السليمة للحمولة، ماذا ينبغي أن تفعل بشأن فحص حمولتك وتثبيتها؟","options":["استمر في القيادة وقم بأول فحص للتثبيت عند علامة 150 ميلاً، لأن ذلك هو فاصل إعادة الفحص القياسي","توقّف وافحص حمولتك وأربطة التثبيت الآن، لأنه يجب عليك إجراء أول فحص خلال أول 50 ميلاً ثم إعادة الفحص كل 3 ساعات أو 150 ميلاً","لا حاجة للفحص حتى تتوقف للتزود بالوقود، ما دامت الحمولة بدت مثبّتة أثناء الفحص قبل الرحلة","انتظر حتى تقطع أول 500 ميل، ثم ابدأ بفحص الحمولة بشكل دوري"],"explanation":"يجب فحص الحمولة وأربطة التثبيت خلال أول 50 ميلاً، ثم إعادة الفحص كل 3 ساعات أو 150 ميلاً وبعد كل استراحة."},"101":{"q":"أثناء فحصك قبل الرحلة، تفحص كيفية تثبيت حمولة من أنابيب الفولاذ في منطقة الحمولة خلف المقصورة. يخبرك زميل أن السبب الحقيقي الوحيد لربط الحمولة بإحكام هو منعها من التعرض للخدش أو الظهور بمظهر غير مرتب أثناء الرحلة. وفقاً لقواعد الحمولة الخاصة بإدارة السلامة العامة في تكساس، ما هو السبب الأساسي للسلامة الذي يوجب تثبيت الحمولة بشكل صحيح؟","options":["كي تبقى الحمولة مرتبة وحسنة المظهر عند وصولك إلى نقطة التسليم","كي تكون الحمولة محميةً من المطر وغبار الطريق وتبقى جافة في الطقس السيئ","كي لا تتمكن الحمولة من الانزلاق أو السقوط عن المركبة أو التحرك لتعيق أدوات تحكم السائق","كي لا تبرد الحمولة وتتجمد عند القيادة في ظروف الشتاء"],"explanation":"يجب تثبيت الحمولة بحيث لا تتمكن من الانزلاق أو السقوط عن المركبة أو الانزلاق إلى المقصورة وإعاقة أدوات تحكم السائق."},"102":{"q":"تقود شاحنة مقطورة محملة باتجاه الغرب في وقت متأخر من بعد الظهر. هبطت الشمس منخفضة على الأفق مباشرة أمامك، وأبهرني وهجها يغمر الطريق ويصعّب تقدير المسافة التي يمكنك رؤيتها. تظهر المركبات أمامك فجأة من وسط الوهج الساطع. ما هي أفضل طريقة للتعامل مع هذا الموقف؟","options":["اخفض حاجب الشمس، وارتدِ نظارة شمسية، وقلّل سرعتك بحيث تتمكن من التوقف ضمن المسافة التي تستطيع رؤيتها فعلاً","شغّل الأضواء العالية كي يخترق ضوؤك الوهج أمامك","حافظ على سرعتك لكن زِد مسافة المتابعة إلى 6 ثوانٍ للتعويض","انتقل إلى المسار الأيسر وزِد سرعتك لتجتاز المقطع المتأثر بالوهج من الطريق بأسرع ما يمكن"],"explanation":"عند وهج الشمس، اخفض الحاجب، وارتدِ نظارة شمسية، وقلّل السرعة بحيث تتمكن من التوقف ضمن المسافة التي تستطيع رؤيتها فعلاً."},"103":{"q":"تقود مقطورة محملة صعوداً على منحدر طويل وشديد على طريق ريفي ذي مسارين. محرّكك يجهد وانخفضت سرعتك إلى نحو 15 ميلاً في الساعة، أي أقل بكثير من الحد المقرر البالغ 55 ميلاً في الساعة، بينما تتكدس السيارات خلفك. في أي من هذه المواقف يكون تشغيل أضواء الطوارئ الرباعية الوامضة الإجراء الأنسب؟","options":["عند انعطافك العادي يميناً عند التقاطع التالي، لأن إشارتك وحدها قد لا تُرى","بمجرد بلوغك القمة واستئناف السير بسرعة 55 ميلاً في الساعة لتنبيه السائقين بأنك مركبة تجارية بطيئة","بعد إيقاف الشاحنة طوال الليل في محطة شاحنات جيدة الإضاءة كي يرى الآخرون هيكلها","الآن، بينما تزحف صعوداً على المنحدر أبطأ بكثير من تدفق المرور، لأنك تتحرك أبطأ بكثير من المركبات حولك"],"explanation":"شغّل الأضواء الرباعية الوامضة كلما كنت تتحرك أبطأ بكثير من المرور المحيط، مثل الزحف صعوداً على منحدر شديد، لتحذير السائقين خلفك."},"104":{"q":"لتحذير السائقين خلفك بأنك تبطئ، ينبغي أن تكون أضواء الفرامل لديك:","options":["مطفأة تماماً","تضيء عند إبطائك","تومض عشوائياً","مفصولة"],"explanation":"الإبطاء باستخدام دواسة الفرامل يضيء مصابيح الفرامل لتحذير الآخرين."},"105":{"q":"تقترب من دوّار متعدد المسارات في مركبتك المركّبة المحملة. هناك سيارة تدور بالفعل في المسار الذي تنوي الدخول إليه، وتنفتح فجوة خلفها مباشرة. أي من الآتي هو الإجراء الصحيح والأكثر أماناً؟","options":["أفسح الطريق للمركبة الموجودة بالفعل في الدوّار، وانتظر فجوة آمنة، ثم ادخل واندمج مع تدفق المرور","حافظ على سرعتك وادخل فوراً، لأن المركبات الموجودة بالفعل في الدوّار ملزمة بإفساح الطريق للشاحنات الداخلة","توقّف داخل المسار الدائر للدوّار وانتظر هناك حتى يخلو كل المرور الآخر","إذا أسأت تقدير الفجوة وبدأت الدخول مبكراً جداً، فارجع للخلف لإعادة إنشاء مسافة متابعة آمنة قبل الاندماج"],"explanation":"للمرور الموجود بالفعل في الدوّار حق الأولوية، لذا أفسح الطريق وانتظر فجوة آمنة ثم ادخل واندمج مع التدفق."},"106":{"q":"تقود مقطورة محملة في المسار الأيمن بالحد المقرر عندما يبدأ سائق خلفك بالالتصاق بك، وميض الأضواء العالية، والإيماء بغضب لأنك لن تزيد سرعتك. المرور أمامك يمنعك من تغيير المسار فوراً. أي استجابة هي الأفضل لإدارة هذا السائق العدواني وحماية سلامتك؟","options":["انقر على فراملك بخفة لتومض أضواء فراملك وتحذّر السائق بالابتعاد","حافظ على سرعتك والتزم بمسارك بحزم كي يتعلم السائق ألا يضايق الشاحنات الكبيرة","حين يكون ذلك آمناً، انتقل جانباً أو خفّف قليلاً لفتح مساحة وتدع السائق الغاضب يمر دون التفاعل مع إيماءاته","زِد سرعتك فوق الحد المقرر حتى تكون قد ابتعدت بما يكفي لإيقاف السائق عن الالتصاق بك"],"explanation":"مع سائق عدواني خلفك، لا تتفاعل معه؛ أفسح له مجالاً للمرور وابقَ هادئاً لنزع فتيل النزاع."},"107":{"q":"تركت عاصفة رعدية شديدة عدة بوصات من المياه الراكدة تتجمع عبر المسار الأيمن من الطريق السريع الذي تقود عليه. أنت فارغ الحمولة وتسير بسرعة 55 ميلاً في الساعة. عند اقترابك من منطقة المياه العميقة المتجمعة أمامك، أي إجراء هو الأفضل لإبقاء مركبتك تحت السيطرة؟","options":["حافظ على 55 ميلاً في الساعة لكن وجّه نحو الكتف، لأن إبعاد المياه عن إطارات التوجيه يستعيد التماسك","قلّل سرعتك قبل بلوغ المياه، لأن المياه المحبوسة بين إطاراتك والطريق قد تسبب الانزلاق المائي وفقدان السيطرة على التوجيه والكبح","سرّع بقوة عبر المياه كي يصرفها نقش إطارك بعيداً ويبقي الإطارات متماسكة مع الرصيف","حافظ على ثبات سرعتك واضغط الفرامل بخفة أثناء وجودك في المياه لاختبار مقدار التماسك المتبقي لديك"],"explanation":"قلّل السرعة قبل بلوغ المياه الراكدة لأن المياه بين إطاراتك والطريق قد تسبب الانزلاق المائي وفقدان السيطرة على التوجيه والكبح."},"108":{"q":"تسير فارغ الحمولة على طريق سريع بين الولايات جاف وصافٍ وتقرر زيادة سرعة سيرك من 30 ميلاً في الساعة إلى 60 ميلاً في الساعة لتعويض الوقت. يسألك متدرب يركب معك كيف يؤثر هذا التغيير في المسافة التي ستحتاجها شاحنتك للتوقف. أي إجابة هي الأفضل لوصف ما يحدث فعلاً؟","options":["لأن الشاحنة فارغة، فإن الحمولة الأخف تجعلها تتوقف عند 60 في مسافة تقارب ما كانت عليه عند 30.","مضاعفة سرعتك تضيف القليل فقط إلى التوقف — تنمو مسافة الكبح بالتناسب مع السرعة، فتتضاعف فقط.","مضاعفة سرعتك تضاعف مسافة الكبح أربع مرات تقريباً، فعند 60 ميلاً في الساعة تحتاج نحو أربعة أضعاف المساحة التي تحتاجها عند 30.","الرصيف المبلل قد يكون مهماً، لكن على هذا الطريق الجاف فإن السرعة الأعلى بالكاد تغيّر مدى المسافة التي تحتاجها للتوقف."],"explanation":"تنمو مسافة الكبح مع مربع السرعة، لذا فإن مضاعفة سرعتك تضاعف المسافة اللازمة للتوقف أربع مرات تقريباً."},"109":{"q":"الجو أقل بقليل من التجمد وقد قام مطر خفيف بتزجيج الطريق. أنت فارغ الحمولة وتبدأ العجلات الخلفية للشاحنة بالانزلاق على منعطف. بمراجعة ما أوقعك في هذا الانزلاق، أيٌّ من الإجراءات التالية التي قمت بها هو الأقل احتمالاً لأن يكون قد سبّبه؟","options":["الضغط بقوة على دواسة الوقود لاجتياز المنعطف بقوة","الضغط المفاجئ على الفرامل بقوة كافية لقفل العجلات عند شعورك بتحرك المؤخرة","إبقاء توجيهك سلساً وتدريجياً خلال المنعطف","الإفراط في السرعة بالنسبة للظروف الجليدية المبللة"],"explanation":"التوجيه السلس التدريجي يبقي قوى الإطارات ضمن التماسك المتاح، لذا فهو لا يسبب الانزلاقات بخلاف الإفراط في السرعة أو الكبح الشديد أو الإفراط في التسارع."},"110":{"q":"الوقت متأخر بعد حلول الظلام على طريق ريفي ذي مسارين وترى أضواء شاحنة قادمة تطل من فوق تلة على بُعد نحو 400 قدم أمامك. أضواؤك العالية مشغّلة حالياً. ما هو الإجراء الصحيح؟","options":["أبقِ أضواءك العالية مشغّلة كي يرى السائق الآخر مركبتك الكبيرة بوضوح","انتقل إلى أضوائك المنخفضة الآن، قبل أن تصبح المركبتان ضمن 500 قدم من بعضهما","أومض بأضوائك العالية إطفاءً وإشعالاً بشكل وجيز لتنبيه السائق الآخر، ثم أبقِها مشغّلة","زِد سرعتك قليلاً كي تتجاوز الشاحنة القادمة قبل أن يصبح الوهج مشكلة"],"explanation":"خفّت إلى الأضواء المنخفضة ضمن 500 قدم من مركبة قادمة كي لا تُعمي أضواؤك العالية السائق الآخر."},"111":{"q":"تقود مقطورة مسطحة محملة على طريق ريفي ذي مسارين عندما يبدأ محرّكك بفقدان القوة، مما يدفعك إلى نحو 30 ميلاً في الساعة على طريق سرعته 55 ميلاً في الساعة. يتكدس المرور خلفك. بينما تقود الشاحنة برفق نحو المخرج التالي كي تتوقف وتفحص المشكلة، أيٌّ من الآتي يُعد استخداماً غير صحيح لأضواء الطوارئ الرباعية الوامضة لديك؟","options":["إبقاؤها مشغّلة لتحذير المرور الأسرع بأنك تتحرك أبطأ بكثير من السرعة العادية للطريق","إطفاؤها واستخدام إشارة الانعطاف اليمنى وحدها عندما تنتقل فعلاً إلى منحدر المخرج","تشغيلها مجدداً بمجرد توقفك على الكتف بينما تفحص المحرّك","استخدامها بدلاً من إشارة الانعطاف للإشارة إلى أنك على وشك الانعطاف يميناً إلى المنحدر"],"explanation":"أضواء الطوارئ الوامضة تحذّر من مركبة متوقفة أو معطّلة أو بطيئة الحركة ويجب ألا تُستخدم أبداً بدلاً من إشارة الانعطاف."},"112":{"q":"تنقل حمولة مستقيمة طولها 40 قدماً على طريق ولاية جاف ومستوٍ وعدّاد سرعتك ثابت عند 45 ميلاً في الساعة في ظروف نهارية جيدة. للحفاظ على هامش أمان أمامك، ما هي أقل مسافة متابعة ينبغي أن تحافظ عليها خلف المركبة أمامك؟","options":["4 ثوانٍ، لأن المركبة بطول 40 قدماً تحتاج ثانية واحدة لكل 10 أقدام من طولها","6 ثوانٍ، لأن أي سرعة فوق 40 ميلاً في الساعة تستدعي تلقائياً 6 ثوانٍ على الأقل","5 ثوانٍ، لأن 40 قدماً تساوي 4 ثوانٍ وتضيف ثانية أخرى لكونك فوق 40 ميلاً في الساعة","3 ثوانٍ، لأن الطريق جاف ومستوٍ والرؤية جيدة"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، فالمركبة بطول 40 قدماً تحتاج 4 ثوانٍ، زائد ثانية واحدة لكونك فوق 40 ميلاً في الساعة، ليكون المجموع 5 ثوانٍ."},"113":{"q":"تنقل شاحنة مقطورة طولها 50 قدماً عبر منطقة عمل حيث خفّ المرور والحد المقرر يتيح لك الاستقرار عند سرعة ثابتة 35 ميلاً في الساعة. تريد ضبط مسافة متابعة آمنة خلف الشاحنة الصغيرة أمامك. باستخدام قاعدة ثانية واحدة لكل 10 أقدام من طول المركبة، أي مسافة متابعة صحيحة لهذا الموقف بالتحديد؟","options":["4 ثوانٍ، لأنه في منطقة عمل بطيئة يمكنك تقصير الهامش بثانية واحدة","7 ثوانٍ، 5 ثوانٍ للطول زائد ثانيتين إضافيتين لمنطقة العمل","6 ثوانٍ، لأنه يجب عليك دائماً إضافة ثانية إضافية إلى العدّ المعتمد على الطول","5 ثوانٍ، لأن 50 قدماً مقسومة على 10 تساوي 5، ولا تُضاف ثانية لأنك دون 40 ميلاً في الساعة"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، فالمركبة بطول 50 قدماً تحتاج 5 ثوانٍ، دون إضافة ثانية لأنك دون 40 ميلاً في الساعة."},"114":{"q":"تنقل شاحنة مقطورة طولها 60 قدماً على طريق سريع بين الولايات جاف ومستوٍ بسرعة ثابتة 55 ميلاً في الساعة في ظروف نهارية صافية. المرور خفيف وتريد ضبط فجوة آمنة خلف السيارة أمامك. استناداً إلى قاعدة مسافة المتابعة، ما هي أقل مسافة متابعة ينبغي أن تحافظ عليها في هذا الموقف؟","options":["7 ثوانٍ","6 ثوانٍ","8 ثوانٍ","5 ثوانٍ"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، فالمركبة بطول 60 قدماً تحتاج 6 ثوانٍ، زائد ثانية واحدة لكونك فوق 40 ميلاً في الساعة، ليكون المجموع 7 ثوانٍ."},"115":{"q":"تقود شاحنة مستقيمة مفردة يبلغ طولها 30 قدماً من مصد إلى مصد. المرور على الشارع المحلي يسير بثبات عند 30 ميلاً في الساعة، مما يبقيك دون علامة 40 ميلاً في الساعة بقليل. لترك مسافة متابعة آمنة لشاحنتك في هذه الظروف، فإن أقل عدد من الثواني ينبغي أن تحافظ عليه بينك وبين المركبة أمامك هو:","options":["ثانيتان، لأنك عند 30 ميلاً في الساعة أقل بكثير من سرعة الطريق السريع والمرور يتدفق بسلاسة","3 ثوانٍ، بإتاحة ثانية واحدة لكل 10 أقدام من طول مركبتك","4 ثوانٍ، لأنه يجب عليك دائماً إضافة ثانية إضافية إلى العدّ المعتمد على الطول","6 ثوانٍ، بما يطابق نحو 6 ثوانٍ يستغرقها التوقف الكامل"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، فالمركبة بطول 30 قدماً تحتاج 3 ثوانٍ، دون إضافة ثانية لأنك دون 40 ميلاً في الساعة."},"116":{"q":"تنقل مركبة مركّبة طولها 70 قدماً على طريق سريع بين الولايات جاف، محافظاً على سرعة ثابتة 50 ميلاً في الساعة في مرور خفيف. سيارة صغيرة تتنقل دخولاً وخروجاً من الفجوة أمامك، وتريد إعادة ضبط مسافة متابعة آمنة لحظة خلو المسار. استناداً إلى قاعدة الثواني المعتمدة على طول مركبتك وسرعتك، كم ثانية من مسافة المتابعة ينبغي أن تعيد إنشاءها؟","options":["7 ثوانٍ، لأن المركبة بطول 70 قدماً تحتاج ثانية واحدة لكل 10 أقدام من الطول","6 ثوانٍ، لأن ذلك هو هامش مسافة التوقف الكلية الموصى به عند سرعة الطريق السريع","8 ثوانٍ، لأن الطول يستدعي 7 ثوانٍ وتضيف ثانية أخرى لكونك فوق 40 ميلاً في الساعة","9 ثوانٍ، لأنه ينبغي إضافة ثانيتين فوق 40 ميلاً في الساعة لمركبة بهذا الطول"],"explanation":"تابِع بثانية واحدة لكل 10 أقدام من الطول دون 40 ميلاً في الساعة، ثم أضف ثانية فوق 40 ميلاً في الساعة، فالشاحنة بطول 70 قدماً عند 50 ميلاً في الساعة تحتاج 8 ثوانٍ."},"117":{"q":"تقود شاحنة مستقيمة طولها 20 قدماً عبر منطقة أعمال في وسط المدينة. المرور ثابت عند حد مقرر 25 ميلاً في الساعة، والرصيف جاف، والرؤية جيدة. للحفاظ على هامش أمان أمامك، ما هي أقل مسافة متابعة ينبغي أن تحافظ عليها خلف المركبة أمامك؟","options":["ثانية واحدة، لأن الشاحنة طولها 20 قدماً فقط","4 ثوانٍ، بإضافة ثانية إلى الأساس وثانية أخرى لمرور المدينة","3 ثوانٍ، لأنه يجب عليك دائماً إضافة ثانية فوق الرقم الأساسي","ثانيتان، ثانية واحدة لكل 10 أقدام من طول المركبة"],"explanation":"دون 40 ميلاً في الساعة تكون مسافة المتابعة ثانية واحدة لكل 10 أقدام من طول المركبة، فالمركبة بطول 20 قدماً تحتاج ثانيتين."},"118":{"q":"تنقل مركبة مركّبة طولها 80 قدماً على طريق سريع بين الولايات جاف، محافظاً على سرعة ثابتة 60 ميلاً في الساعة في مرور خفيف. يخبرك زميل أن تترك فقط 'ثانية واحدة لكل عشرة أقدام' وستكون بخير عند أي سرعة. باستخدام طريقة مسافة المتابعة الصحيحة الخاصة بإدارة السلامة العامة في تكساس وفقاً لطولك وسرعتك، ما هي أقل مسافة متابعة ينبغي أن تحافظ عليها خلف المركبة أمامك؟","options":["9 ثوانٍ — 8 ثوانٍ لطول 80 قدماً، زائد ثانية إضافية لأنك تسير فوق 40 ميلاً في الساعة","8 ثوانٍ — ثانية واحدة لكل 10 أقدام من مركبتك البالغ طولها 80 قدماً، دون تعديل للسرعة","10 ثوانٍ — 8 ثوانٍ للطول، زائد ثانيتين لأنك 20 ميلاً في الساعة فوق عتبة 40 ميلاً في الساعة","7 ثوانٍ — ثانية واحدة لكل 10 أقدام، ثم خصم ثانية لأن الرصيف الجاف يمنحك تماسكاً جيداً"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول دون 40 ميلاً في الساعة وأضف ثانية أخرى فوق 40 ميلاً في الساعة، فالمركبة بطول 80 قدماً عند 60 ميلاً في الساعة تحتاج 9 ثوانٍ."},"119":{"q":"تنقل شاحنة مقطورة طولها 50 قدماً على طريق سريع بين الولايات جاف ومستوٍ وعدّاد سرعتك يقرأ سرعة ثابتة 45 ميلاً في الساعة في مرور خفيف. سيارة صغيرة أمامك تواصل النقر على فراملها، لذا تريد ضبط مسافة متابعة آمنة باستخدام قاعدة الثواني. كم ثانية من المساحة ينبغي أن تحافظ عليها خلف تلك المركبة؟","options":["5 ثوانٍ، لأن شاحنتك طولها 50 قدماً وذلك يعطي ثانية واحدة لكل 10 أقدام","6 ثوانٍ، لأن 50 قدماً تعطيك 5 ثوانٍ وتضيف ثانية أخرى لكونك فوق 40 ميلاً في الساعة","7 ثوانٍ، بإضافة ثانيتين إضافيتين إلى الرقم المعتمد على الطول لأنك على طريق بين الولايات","4 ثوانٍ، لأن 45 ميلاً في الساعة أعلى قليلاً فقط من 40 ميلاً في الساعة وهامش أقصر مناسب على رصيف جاف"],"explanation":"استخدم ثانية واحدة لكل 10 أقدام من الطول دون 40 ميلاً في الساعة وأضف ثانية فوق 40 ميلاً في الساعة، فالمركبة بطول 50 قدماً عند 45 ميلاً في الساعة تحتاج 6 ثوانٍ."},"120":{"q":"تنقل شاحنة مقطورة طولها 60 قدماً عبر المدينة وتستقر خلف شاحنة توصيل أبطأ. عدّاد سرعتك يقرأ سرعة ثابتة 35 ميلاً في الساعة على رصيف جاف. للحفاظ على مسافة متابعة آمنة لشاحنتك بهذه السرعة، كم ثانية من المساحة ينبغي أن تترك بينك وبين المركبة أمامك؟","options":["5 ثوانٍ، لأنك تخصم ثانية على رصيف جاف في ظروف جيدة","8 ثوانٍ، بإتاحة ثانية واحدة لكل 10 أقدام زائد ثانيتين إضافيتين للمقطورة","6 ثوانٍ، ثانية واحدة لكل 10 أقدام من طول المركبة","7 ثوانٍ، ثانية واحدة لكل 10 أقدام زائد ثانية لأنك تتحرك"],"explanation":"دون 40 ميلاً في الساعة تكون مسافة المتابعة ثانية واحدة لكل 10 أقدام من الطول دون إضافة ثانية، فالمركبة بطول 60 قدماً عند 35 ميلاً في الساعة تحتاج 6 ثوانٍ."},"121":{"q":"تنقل حمولة جزئية على طريق ذي مسارين عندما يبدأ رذاذ متجمد خفيف ويبدأ الرصيف بالظهور لامعاً. خلال الميل التالي تفعل ثلاثة أشياء: تحافظ على ثبات سرعة سيرك رغم انخفاض الرؤية والتماسك، وتضغط دواسة الفرامل بقوة عندما يندفع غزال أمامك، وبعد لحظات تضغط دواسة الوقود بقوة لتعود إلى السرعة على ارتفاع طفيف. يجادل زميل لاحقاً بأن إجراءً واحداً فقط من هذه الإجراءات يمكن واقعياً أن يكون قد أوقعك في انزلاق. أي عبارة صحيحة؟","options":["الكبح المفاجئ الشديد فقط هو ما يمكن أن يسبب الانزلاق، لأن قفل العجلات هو الطريقة الوحيدة لفقدان التماسك.","القيادة بسرعة عالية جداً بالنسبة للظروف الجليدية فقط هي ما يمكن أن يسبب الانزلاق، لأن معظم الانزلاقات تأتي من الإفراط في السرعة.","كل من الإجراءات الثلاثة — الإفراط في السرعة بالنسبة للظروف، والكبح المفاجئ الشديد، والتسارع القوي — يمكن أن يسبب الانزلاق بشكل مستقل.","التسارع القوي فقط هو ما يمكن أن يسبب الانزلاق، لأن الحمولة الجزئية (الأخف) تمنح العجلات الدافعة وزناً قليلاً جداً للتماسك."],"explanation":"يحدث الانزلاق كلما فقدت الإطارات التماسك، والقيادة بسرعة عالية جداً بالنسبة للظروف أو الكبح بشدة أو التسارع بشدة يمكن لكل منها أن يسببه بشكل مستقل."},"122":{"q":"تنقل مقطورة محملة على طريق ريفي ذي مسارين. بدأ مطر خفيف للتو والرصيف لامع ومبلل، ويمكنك رؤية منعطف حاد مُعلَّم أمامك، وتستقر بقعة ضباب منخفضة في المنخفض خلف المنعطف بحيث لا تستطيع الرؤية بعيداً على الطريق. أخبرك زميل ذات مرة أنك تحتاج فقط لتقليل السرعة للخطر الأسوأ الواحد الذي تواجهه في كل مرة. أي إجراء يعكس بشكل أفضل الممارسة الآمنة لرخصة القيادة التجارية في هذا الموقف؟","options":["حافظ على سرعة الطريق السريع عبر المقطع المبلل لكن أبطئ فقط بمجرد بلوغك المنعطف فعلاً، لأن المنعطف هو الخطر الواحد الأخطر","حافظ على ثبات سرعتك لأن مسافة المتابعة، وليس سرعتك، هي ما يحميك عند ظهور عدة أخطار طفيفة معاً","أبطئ فقط للضباب في المنخفض، لأن انخفاض الرؤية هو الحالة الوحيدة التي تتطلب قانونياً سرعة أقل","قلّل سرعتك لكل الحالات الثلاث معاً، لأن الرصيف المبلل والمنعطف والرؤية المحدودة يستدعي كلٌّ منها سرعة أقل بشكل مستقل"],"explanation":"الرصيف المبلل والمنعطفات والرؤية المحدودة يقلّل كلٌّ منها سرعتك الآمنة بمفرده، لذا قلّل السرعة لها جميعاً وأكثر عند اجتماعها."},"123":{"q":"الساعة 6:00 صباحاً وتجري الفحص قبل الرحلة على شاحنة مقطورة قبل رحلة طويلة بين الولايات. تفتح صندوق معدات الطوارئ خلف المقعد للتأكد من أنه مجهّز بالكامل تحسباً لتعطلك على الكتف لاحقاً. أي مجموعة من العناصر تمثل معدات الطوارئ الكاملة المطلوب منك حملها؟","options":["ثلاثة مثلثات تحذيرية عاكسة، وفيوزات كهربائية احتياطية (ما لم تكن المركبة مزوّدة بقواطع دائرة)، وطفاية حريق مشحونة ومصنّفة بشكل صحيح","ثلاثة مثلثات تحذيرية عاكسة وطفاية حريق مشحونة ومصنّفة بشكل صحيح، لكن الفيوزات الاحتياطية اختيارية","طفاية حريق مشحونة ومصنّفة بشكل صحيح وفيوزات كهربائية احتياطية، إضافة إلى مجموعة سلاسل إطارات للمسارات الشتوية","ثلاثة مثلثات تحذيرية عاكسة، وحقيبة إسعافات أولية، وطفاية حريق مشحونة ومصنّفة بشكل صحيح"],"explanation":"معدات الطوارئ المطلوبة هي ثلاثة مثلثات تحذيرية عاكسة، وفيوزات احتياطية ما لم تُستخدم قواطع دائرة، وطفاية حريق مشحونة ومصنّفة بشكل صحيح."},"124":{"q":"أنت متأخر 30 دقيقة عن الجدول على طريق سريع مقسوم حده المقرر 65 ميلاً في الساعة. المرور في كل المسارات يتدفق بنحو 72 ميلاً في الساعة، والرصيف جاف، والطريق أمامك صافٍ وفارغ لمسافة ربع ميل. وفقاً لقواعد إدارة السلامة العامة في تكساس، أي من هذه الظروف يجعل من المقبول أن تقود أسرع من الحد المقرر البالغ 65 ميلاً في الساعة؟","options":["عندما يتحرك التدفق العام للمرور المحيط فوق الحد، فتجاري الإيقاع لتجنب أن تكون خطراً","عندما تكون متأخراً عن الجدول والرصيف الجاف الصافي يتيح لك تعويض الوقت الضائع بأمان","لا شيء من هذه الظروف يبرر تجاوز الحد المقرر","عندما يكون الطريق أمامك فارغاً لمسافة ربع ميل، مما يمنحك مسافة توقف كاملة"],"explanation":"الحد المقرر للسرعة هو أقصى سرعة قانونية للظروف المثالية ولا يجوز تجاوزه أبداً، بغض النظر عن المرور أو الجدول أو الطريق المفتوح."},"125":{"q":"أنت تقود مقطورة جرّار محمّلة على طريق سريع ذي مسارين خلف شاحنة مزرعة بطيئة تسير بسرعة 40 ميلاً في الساعة في منطقة حدّها 60 ميلاً في الساعة. أنت متلهف لتجاوزها وترصد أربع فرص قادمة. أي موقع يُعدّ فعلاً مكاناً آمناً لإتمام التجاوز؟","options":["على المنعطف الطويل اللطيف أمامك حيث يمكنك أن ترى جزئياً حول الانحناء","قبل قمة التل مباشرة، بينما لا يزال أمامك بعض الرؤية الأمامية","لا يمنحك أيٌّ من هذه المواقع مسافة رؤية كافية للتجاوز بأمان","عبر التقاطع الريفي القادم، لأنه على حركة المرور العابرة أن تفسح الطريق للطريق السريع"],"explanation":"يتطلب التجاوز الآمن على طريق ذي مسارين مسافة رؤية واضحة كافية أمامك، وهو ما تحجبه المنعطفات وقمم التلال والتقاطعات جميعها."},"126":{"q":"أنت متأخر 40 دقيقة عن الجدول الزمني في عملية تسليم ضيّقة الوقت. اجتازت مقطورة الجرّار نفسها فحص ما قبل الرحلة كاملاً عندما قدتها بالأمس، والطقس صافٍ وجاف، وتُظهر جولة سريعة حول المركبة أنه لا يوجد خطأ واضح. في ظل أيٍّ من هذه الظروف يُسمح لك قانونياً وبأمان بتخطّي فحص ما قبل الرحلة اليوم قبل القيادة؟","options":["عندما تكون متأخراً عن الجدول الزمني وقد يهدد التأخير بتسليم متأخر","عندما تكون المركبة قد اجتازت الفحص في اليوم السابق ولم يُشَر إلى أي مشكلة منذ ذلك الحين","لا يبرّر أيٌّ من هذه الظروف تخطّي فحص ما قبل الرحلة","عندما تُظهر جولة سريعة حول المركبة أنه لا يوجد خطأ مرئي والظروف جيدة"],"explanation":"فحص ما قبل الرحلة مطلوب قبل كل رحلة دون استثناء، لأن حالة المركبة قد تتغير في أي وقت."},"127":{"q":"إنه بُعيد حلول الظلام على طريق مزرعة ضيّق ذي مسارين غير مضاء وأنت تنقل مقطورة محمّلة. تصعد سيارة قادمة من الاتجاه المعاكس مرتفعاً على بعد نحو 400 قدم أمامك بأضوائها العالية مسلَّطة مباشرة في عينيك، فتطمس كل ما أمام غطاء محرّكك. ليس لديك سوى ثانيتين قبل أن تلتقي السيارتان. أي إجراء هو الطريقة الأكثر أماناً للسيطرة على مركبتك حتى تمرّ السيارة؟","options":["حوّل أضواءك إلى الإضاءة العالية حتى يتيح لك مداها الإضافي رؤية الطريق خلف وهج السائق الآخر.","انقل عينيك للأسفل نحو الحافة اليمنى لمسارك وخفّف السرعة حتى تمرّ السيارة القادمة.","أومض بأضوائك العالية بسرعة عدة مرات حتى يدرك السائق الآخر المشكلة ويخفّض أضواءه من أجلك.","ثبّت عينيك على الخط الأوسط مباشرة أمامك وحافظ على سرعتك ثابتة كي لا تنحرف قبل أن تمرّ السيارة."],"explanation":"عندما يُعميك الوهج من الأضواء العالية القادمة، انظر نحو الحافة اليمنى لمسارك كدليل وخفّف السرعة حتى تمرّ المركبة."},"128":{"q":"أنت تنزل منحدراً جبلياً طويلاً وشديد الانحدار بحمولة ثقيلة. كيف ينبغي أن تتحكم في سرعتك؟","options":["اضغط على دواسة الفرامل بثبات طوال الطريق للحفاظ على سرعة منخفضة وثابتة.","انتقل إلى تروس منخفضة واستخدم كبحاً خفيفاً وثابتاً كي لا ترتفع حرارة الفرامل.","ضع ناقل الحركة في الوضع المحايد وانزلق إلى الأسفل لتوفير الوقود وتقليل التآكل.","اضغط على الفرامل بقوة وسرعة طوال الطريق نزولاً على المنحدر الطويل الشديد."],"explanation":"يحافظ الترس المنخفض على سرعتك بحيث لا يؤدي الكبح الخفيف إلى ارتفاع حرارة الفرامل."},"129":{"q":"ينفجر إطار أمامي بينما أنت بسرعة الطريق السريع. ماذا ينبغي أن تفعل أولاً؟","options":["اكبح بقوة على الفور ووجّه المركبة بحدّة نحو الكتف الأيمن للطريق.","أمسك عجلة القيادة بثبات، وابتعد عن الفرامل، ودع المركبة تتباطأ.","سرّع لوهلة قصيرة كي تبتعد عن حركة المرور القريبة خلفك.","ارفع كلتا يديك عن العجلة ودع المركبة تجد طريقها للتوقف بنفسها."],"explanation":"إمساك العجلة والابتعاد عن الفرامل يبقي المركبة مستقيمة."},"130":{"q":"تقترب من مزلَقان سكة حديد بلا حواجز وتبدأ أضواء التحذير بالوميض. ماذا ينبغي أن تفعل؟","options":["سرّع كي تتمكن من عبور القضبان قبل أن يستطيع أي قطار الوصول إليك.","توقف قبل القضبان وانتظر حتى تتوقف الأضواء ويصبح العبور آمناً.","قُد فوق القضبان وتوقف هناك كي تنظر في الاتجاهين بحثاً عن قطار قادم.","انتقل إلى ترس أقل بينما أنت على القضبان ثم تابع عبورها."],"explanation":"الأضواء الوامضة تعني التوقف والانتظار حتى يصبح العبور آمناً."},"131":{"q":"أنت تسير بسرعة نحو 55 ميلاً في الساعة على طريق سريع بين الولايات عندما يترك هطول مطري غزير مفاجئ طبقة من المياه الراكدة على الرصيف. تشعر فجأة بأن عجلة القيادة خفيفة ورخوة في يديك، وتدرك أن الإطارات الأمامية للجرّار فقدت التلامس المُحكم مع الطريق وأصبحت تنزلق فوق المياه. أي استجابة تمنحك أفضل فرصة لاستعادة التماسك بأمان؟","options":["اضغط على الفرامل بثبات وحزم ووجّه المركبة بقوة نحو الكتف لإجبار الإطارات الأمامية على العودة إلى الرصيف.","حافظ على سرعتك لكن اضغط على الفرامل بسرعة متكررة كي تخترق الإطارات طبقة المياه دون أن تُقفل.","ارفع قدمك عن دواسة الوقود، وأمسك عجلة القيادة مستقيمة، ودع الشاحنة تتباطأ تدريجياً حتى تستعيد الإطارات تماسكها.","اضغط على دواسة الوقود بقوة أكبر وأبقِ العجلات الدافعة تدور لدفع المياه الراكدة من تحت الإطارات."],"explanation":"في حالة الانزلاق المائي تكون الإطارات قد فقدت تماسكها، لذا ارفع قدمك عن دواسة الوقود، وأمسك العجلة مستقيمة، ودع الشاحنة تتباطأ حتى يعود التماسك."},"132":{"q":"أنت تندمج في طريق سريع مزدحم من منحدر دخول والمسار الأيمن يتحرك بسرعة. ما هو الأفضل؟","options":["توقف عند نهاية المنحدر وانتظر فجوة كاملة خالية تماماً من أي سيارات.","طابق سرعتك مع حركة المرور واندمج بسلاسة في فجوة آمنة في المسار.","اندمج ببطء بسرعة منخفضة واجعل حركة المرور الأسرع تكبح من أجل شاحنتك.","افرض نفسك في المسار وتوقع أن يتنحى السائقون الآخرون من أجلك."],"explanation":"مطابقة السرعة تتيح لك الاندماج في فجوة بأمان."},"133":{"q":"أنت تنقل مقطورة محمّلة في المسار الأيمن لطريق سريع منقسم من أربعة مسارات، وتسير بالسرعة المعلنة وهي 60 ميلاً في الساعة. اقتربت منك شاحنة بيك أب من الخلف على بعد بضع أقدام فقط من مصدّك، وتومض بأضوائها العالية بشكل متكرر وتتمايل وكأنها تبحث عن التجاوز. يوجد مسار فارغ على يسارك وحركة مرور ثابتة أمامك. أي استجابة هي الأكثر أماناً والأسلم قانونياً؟","options":["انقر على فراملك بخفة عدة مرات لإيماض أضواء الكبح وإشارة السائق الملتصق بالخلف ليتراجع ويترك مسافة خلفك.","حافظ على سرعتك الحالية ووضعك في المسار كي لا يتمكن السائق العدواني من إجبارك على تغيير ما تفعله.","سرّع إلى نحو 70 ميلاً في الساعة لفتح مسافة عن السائق الملتصق، لأن التقدم أمام سائق عدواني يزيل التعارض.","ارفع قدمك عن دواسة الوقود لفتح مسافة اتباع أكبر أمامك، ثم أشر وانتقل إلى المسار الأيسر عندما يكون خالياً كي يستطيع السائق التجاوز."],"explanation":"مع وجود سائق عدواني ملتصق بالخلف، ارفع قدمك عن دواسة الوقود لفتح مسافة أمامك، ثم أشر وانتقل لتسمح له بالتجاوز بأمان."},"134":{"q":"أنت تنقل مقطورة محمّلة على طريق بين الولايات عندما تشمّ رائحة مطاط محترق حادة وتلاحظ دخاناً رمادياً يتصاعد من مؤخرة وحدتك في مرآتك اليمنى. حركة المرور معتدلة وهناك كتف مرصوف عريض على بعد بضع مئات من الأقدام أمامك. ما هو أفضل مسار للعمل؟","options":["أشر مبكراً، واخرج تماماً إلى الكتف بعيداً عن حركة المرور الأخرى، وأطفئ المحرك، وافحص مصدر الدخان قبل أن يتفاقم.","حافظ على السرعة وتابع إلى المخرج التالي، لأن تدفق الهواء بسرعة الطريق السريع سيبرّد المنطقة على الأرجح ويُزيل الدخان من تلقاء نفسه.","توقف على الكتف لكن أبقِ المحرك يعمل، ثم افتح فوراً أبواب المقطورة الخلفية لإخراج الدخان والحرارة المحتبسة.","خفّف السرعة وتابع التحرك على الكتف بسرعة منخفضة بينما يسكب راكب الماء على الإطارات الخلفية لتبريدها دون التوقف الكامل."],"explanation":"قد يعني الدخان أو رائحة الاحتراق نشوب حريق متطوّر، لذا اخرج تماماً عن الطريق بعيداً عن حركة المرور، وأطفئ المحرك، وافحص قبل أن يتفاقم."},"135":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع ريفي ذي مسارين عندما تدخل في كتلة ضباب كثيفة لدرجة أنك بالكاد تستطيع تمييز خطوط المسار على مسافة قصيرة أمامك. حركة المرور خفيفة. أي إجراء هو الأكثر أماناً وصواباً للتعامل مع هذا المقطع؟","options":["حوّل إلى أضواءك العالية كي يخترق الضوء الأقوى الضباب ويتيح لك قراءة خطوط المسار في وقت أبكر.","خفّف سرعتك، وأبقِ أضواءك المنخفضة مضاءة، وإذا كنت لا تزال غير قادر على الرؤية بشكل كافٍ، فاخرج تماماً عن الطريق وانتظر حتى ينقشع الضباب.","حافظ على سرعتك الطبيعية على الطريق السريع لكن ثبّت نظرك على الأضواء الخلفية للمركبة التي أمامك واتبعها كدليل لك عبر الضباب.","سرّع لتجاوز المقطع الضبابي بأسرع ما تسمح به مركبتك المحمّلة بأمان، ثم استأنف سرعة السير."],"explanation":"في الضباب، خفّف السرعة واستخدم الأضواء المنخفضة لأن الأضواء العالية تنعكس عن قطرات الماء وتزيد الوهج سوءاً، واخرج تماماً عن الطريق إذا كنت لا تزال غير قادر على الرؤية."},"136":{"q":"إنه وقت متأخر من نوبتك وعليك أن ترجع مقطورتك بطول 53 قدماً إلى رصيف تحميل ضيّق في ساحة لم تزرها من قبل. لا يتوفر مرشد، والرصيف فارغ حالياً، وأنت متلهف للانتهاء. أي مسار للعمل هو الأكثر أماناً وصواباً؟","options":["بما أن المنطقة خلفك خالية الآن، ارجع فوراً بسرعة ثابتة كي تنتهي قبل وصول أي رافعات شوكية أو عمال.","استوقف عاملاً يمشي قريباً واطلب منه الوقوف مباشرة خلف المقطورة ليراقب ويلوّح لك أثناء رجوعك.","انزل وامشِ المسار الكامل خلف المقطورة للتحقق من العوائق والمسافات، ثم ارجع ببطء مستخدماً مرآتيك على الجانبين.","اعتمد على مرآتيك وحدهما وارجع بسرعة ثابتة دون النزول، لأن التوقف للنظر لن يؤدي إلا إلى إبطائك."],"explanation":"عند عدم وجود مرشد، استخدم طريقة \"انزل وانظر\": امشِ المسار الكامل خلف المقطورة للتحقق من العوائق والمسافات، ثم ارجع ببطء مستخدماً كلتا المرآتين."},"137":{"q":"أنت تنقل مقطورة محمّلة بسرعة 55 ميلاً في الساعة على طريق بين الولايات جاف عندما تظهر فجأة سيارة معطّلة في مسارك بعيداً أمامك. يطلب منك مدرّبك لاحقاً أن تحصر كل جزء من المسافة التي قطعتها مركبتك فعلاً منذ لحظة ظهور الخطر حتى توقفك التام. أي تقسيم يحدّد بشكل صحيح الأجزاء الثلاثة المنفصلة التي تشكّل معاً مسافة توقفك الكلية؟","options":["المسافة المقطوعة خلال زمن ردّ فعلك البالغ 3/4 ثانية بالإضافة إلى مسافة الكبح بمجرد أن تمسك الفرامل — زمن الإدراك مُدرَج بالفعل ضمن زمن ردّ الفعل، لذا لا يُحسب على حدة","مسافة الكبح فقط، لأنها الجزء الذي تتباطأ فيه الشاحنة فعلياً وهي الجزء الوحيد الذي يمكنك التحكم فيه","مسافة الاتباع، ومسافة الإشارة، وفجوة الوقوف التي تتركها عند الرصيف","مسافة الإدراك، ومسافة ردّ الفعل، ومسافة الكبح"],"explanation":"مسافة التوقف الكلية هي مجموع ثلاثة أجزاء: مسافة الإدراك، ومسافة ردّ الفعل، ومسافة الكبح."},"138":{"q":"توقفت لتناول الغداء في رحلة طويلة ويعرض عليك صديق جعة واحدة مع وجبتك. تشعر بأنك صاحٍ تماماً بعدها ولا تجد صعوبة في المشي في خط مستقيم. قبل أن تصعد مجدداً إلى مقطورة جرّارك، أي عبارة عن الحدّ القانوني لتركيز الكحول في الدم (BAC) لتشغيل مركبتك التجارية صحيحة؟","options":["أنت قانونياً فوق الحدّ ولا يجوز لك قيادة المركبة التجارية عند تركيز كحول 0.04 بالمئة، وهو نصف الحدّ المطبّق على سيارة ركاب عادية.","أنت قانونياً فوق الحدّ ولا يجوز لك قيادة المركبة التجارية عند تركيز كحول 0.08 بالمئة، وهو الحدّ نفسه المطبّق على سيارة ركاب عادية.","لا بأس عليك أن تقود ما دام تركيز الكحول في دمك يبقى دون 0.10 بالمئة، لأن المركبات الأكبر تخضع لعتبة أعلى.","الشعور بالصحو هو ما يهم، لذا يجوز لك القيادة بمجرد أن تتوقف عن الشعور بالضعف، بصرف النظر عن أي رقم محدّد لتركيز الكحول."],"explanation":"الحدّ القانوني لتركيز الكحول في الدم لقيادة مركبة تجارية هو 0.04 بالمئة، أي بالضبط نصف حدّ 0.08 بالمئة لسيارة الركاب، لذا عند 0.04 تكون فوق الحدّ."},"139":{"q":"أنهيت للتوّ 10 ساعات متتالية خارج الخدمة في مقصورة النوم وتبدأ نوبة جديدة. يقول لك المرسِل إن الرحلة طويلة ويسألك كم من القيادة الفعلية يمكنك أداؤها قانونياً قبل أن تُلزمك قواعد ساعات الخدمة الفيدرالية بالتوقف عن القيادة لذلك اليوم. باعتبار هذا قيادة محضة (دون تأخيرات مفرطة أثناء الخدمة تغلق نافذة الـ14 ساعة مبكراً)، ما هو الحدّ الأقصى لوقت القيادة المسموح به؟","options":["حتى 8 ساعات من وقت القيادة، لأن عليك أخذ استراحة 30 دقيقة أولاً","حتى 11 ساعة من وقت القيادة","حتى 14 ساعة من وقت القيادة","حتى 16 ساعة من وقت القيادة"],"explanation":"بعد 10 ساعات متتالية خارج الخدمة، تسمح قواعد ساعات الخدمة الفيدرالية بحدّ أقصى 11 ساعة من وقت القيادة."},"140":{"q":"كنت تقود منذ ما قبل الفجر بكثير والآن منتصف بعد الظهر. تضبط نفسك تنحرف داخل المسار، وجفناك ثقيلان، ولا تستطيع تذكّر الأميال القليلة الماضية. لا يزال أمامك ساعات من مسارك ونافذة تسليم عليك الوفاء بها. أي مما يلي هو الإجراء الوحيد الذي سيستعيد فعلاً يقظتك ويصحّح هذه الحالة بأمان؟","options":["توقف عند الخدمات التالية، واشرب كوبين قويين من القهوة، وتابع للبقاء على الجدول الزمني","أنزل النوافذ لهواء بارد منعش وارفع صوت الراديو عالياً لإبقاء ذهنك نشطاً","اخرج عن الطريق بمجرد أن يكون ذلك آمناً، وتوقف عن القيادة، واحصل على قسط كافٍ من النوم الحقيقي قبل المتابعة","افتح مشروب طاقة، وتناول وجبة دسمة، وزِد مسافة الاتباع للتعويض"],"explanation":"النوم الحقيقي الكافي وحده هو ما يسدّد دَين النوم، لذا عند الشعور بالتعب اخرج عن الطريق بأمان، وتوقف عن القيادة، ونم قبل المتابعة."},"141":{"q":"أنت تسير محمّلاً على طريق سريع ريفي مفتوح ومستوٍ بسرعة 55 ميلاً في الساعة في طقس صافٍ وجاف. حركة المرور خفيفة ولديك رؤية طويلة وغير متقطعة للطريق أمامك. لإدارة وقت تقدّمك البصري بشكل صحيح، إلى أي مدى أمامك ينبغي أن تنظر وتمسح بثبات بحثاً عن المخاطر؟","options":["فقط إلى المركبة التي أمامك مباشرة، لأنه بسرعة 55 ميلاً في الساعة فإن أي شيء أبعد ليس تهديداً بعد","نحو 30 إلى 40 ثانية أمامك، كي يكون لديك أقصى وقت ردّ فعل ممكن على الطريق المفتوح","نحو 1 إلى 2 ثانية أمامك، وهو تقريباً مسافة اتباعك الآمنة عند هذه السرعة","نحو 12 إلى 15 ثانية أمامك، وهو بسرعة 55 ميلاً في الساعة نحو رُبع ميل أو نحو مربّع سكني واحد في المدينة"],"explanation":"أبقِ عينيك متحركتين وانظر 12 إلى 15 ثانية أمامك، وهو نحو رُبع ميل بسرعة الطريق السريع أو مربّع واحد في المدينة، لرصد المخاطر مبكراً."},"142":{"q":"أنت تنقل مقطورة محمّلة على طريق بين الولايات مزدحم من أربعة مسارات في تكساس بسرعة الطريق السريع. حركة المرور كثيفة والمركبات تستمر في الدخول إلى نقاطك العمياء والاندماج حولك. للحفاظ على صورة دقيقة ومحدّثة لما يحدث خلف مركبتك وبجانبها، كيف ينبغي أن تستخدم مرآتيك؟","options":["ألقِ نظرة على مرآتيك فقط قبل تغيير المسارات أو الاندماج مباشرة، لأن ذلك هو الوقت الذي تهمّ فيه حركة المرور في النقطة العمياء أكثر","تحقق من مرآتيك كل 12 إلى 15 ثانية تقريباً، بما يطابق إلى أي مدى تنظر أمامك على الطريق","راقب مرآتيك باستمرار وثبات بحيث لا تعود عيناك أبداً إلى الطريق أمامك","امسح مرآتيك بانتظام، نحو كل 5 إلى 8 ثوانٍ، بالإضافة إلى التحقق قبل أي تغيير للمسار"],"explanation":"امسح مرآتيك بانتظام، نحو كل 5 إلى 8 ثوانٍ، بالإضافة إلى التحقق قبل أي تغيير للمسار، للبقاء على وعي بحركة المرور والنقاط العمياء."},"143":{"q":"إنه بعد ظهر رطب ورمادي وعليك أن ترجع مقطورة جرّارك إلى رصيف في زقاق ضيّق. الرؤية ضعيفة، والجانب الأيمن من مقطورتك يتلاشى في الظل، ولا يتوفر لديك مرشد. لإبقاء المناورة آمنة قدر الإمكان، ينبغي أن تُعِدّ نفسك بحيث ترجع نحو أي جانب؟","options":["الجانب الأيمن (الأعمى)، لأن تأرجح المقطورة بعيداً عنك يمنح الجرّار خلوصاً أكبر للالتفاف","الجانب الذي يحمل أكثر حركة مرور، كي يراك السائقون الآخرون ويتوقفوا للمقطورة","أي جانب يجعل الرصيف أقرب، لتقصير المسافة التي عليك قطعها بالرجوع","جانب السائق (الأيسر)، كي تستطيع مراقبة طول المقطورة بالكامل عبر نافذتك"],"explanation":"الرجوع نحو جانبك الأيسر (جانب السائق) يتيح لك مراقبة طول المقطورة الكامل عبر نافذتك، بحيث يبقى المؤخر ومساره في مجال الرؤية طوال الوقت."},"144":{"q":"أثناء فحص ما قبل الرحلة، أنت تثبّت عارضة فولاذية واحدة بطول 38 قدماً على شاحنة مسطّحة. تريد استخدام أقل عدد من أربطة التثبيت بحيث يفي ذلك بالحدّ الأدنى الفيدرالي للتثبيت القائم على الطول (حدّ حمل العمل مستوفى بالفعل). ما أقل عدد من أربطة التثبيت تسمح به القاعدة لهذه الحمولة؟","options":["رباطان، لأن أي قطعة يزيد طولها عن 5 أقدام تحتاج دائماً إلى رباطين بالضبط","3 أربطة، لأنك تعيد التحقق من التثبيت كل 3 ساعات","8 أربطة، لأنك تحتاج إلى واحد لكل 5 أقدام من طول الحمولة","4 أربطة، لأنك تحتاج إلى واحد لكل 10 أقدام من طول الحمولة"],"explanation":"تحتاج الحمولة إلى رباط تثبيت واحد على الأقل لكل 10 أقدام من الطول، لذا تُقرّب عارضة بطول 38 قدماً صعوداً إلى أربعة أربطة تثبيت."},"145":{"q":"إنها أدنى قليلاً من نقطة التجمّد وأنت تقترب من منعطف على جسر في مقطورة جرّارك المحمّلة. وبينما تدير عجلة القيادة لاتباع المنعطف، تفقد العجلات الأمامية تماسكها على الجليد. ما هي النتيجة الأرجح لهذا الانزلاق في العجلات الأمامية، وكيف تستجيب المركبة؟","options":["تستمر المركبة في التحرك مستقيمة وتواصل ذلك مهما كان اتجاه توجيهك، حتى تستعيد الإطارات الأمامية تماسكها.","تتأرجح العجلات الدافعة الخلفية إلى أحد الجانبين وتبدأ المقطورة بالانطواء خلف المقصورة.","تنعطف المركبة في المنعطف بحدّة أكبر مما قصدت، فتسحب مقدّمتها نحو داخل المنعطف.","يصبح التوجيه أصلب وتتشبث العجلات الأمامية بقوة أكبر، مما يجبر الشاحنة على المبالغة في التصحيح في اتجاه توجيهك."],"explanation":"في انزلاق العجلات الأمامية تفقد الإطارات الأمامية تماسكها فلا يكون للتوجيه أي تأثير، وتستمر المركبة مستقيمة حتى تستعيد الإطارات الأمامية تماسكها."},"146":{"q":"أنت تقود مقطورة جرّار بلا نظام مانع لانغلاق الفرامل (ABS) محمّلة بسرعة الطريق السريع عندما تنحرف سيارة فجأة أمامك وتتوقف بشكل مباغت. تحتاج إلى أقصى كبح لكن عليك إبقاء المركبة تحت السيطرة وأن تكون قادراً على التوجيه. باستخدام طريقة الكبح المتحكَّم به، ماذا ينبغي أن تفعل بدواسة الفرامل؟","options":["اضغط الدواسة حتى النهاية لإقفال العجلات لأقصر توقف ممكن","طبّق ضغطاً ثابتاً وحازماً على الدواسة دون الوصول إلى إقفال العجلات، وخفّف فقط إذا بدأت العجلات بالإقفال","اضغط الدواسة بقوة وسرعة مراراً وتكراراً لإبقاء العجلات تدور","اترك فرامل القدم وحدها واستخدم فقط صمام يد المقطورة لإبطاء المركبة"],"explanation":"يعني الكبح المتحكَّم به تطبيق ضغط ثابت وحازم دون الوصول إلى إقفال العجلات، والتخفيف فقط إذا بدأت بالإقفال كي تبقى قادراً على التوجيه."},"147":{"q":"أنت تنزل منحدراً جبلياً طويلاً وشديد الانحدار بمقطورة محمّلة بالكامل. اخترت ترساً منخفضاً عند القمة، لكن في منتصف الطريق نزولاً تشمّ شيئاً ساخناً، وتشعر بدواسة الفرامل ألين مع كل ضغطة، والشاحنة تزداد سرعة تدريجياً رغم الكبح الخفيف والثابت. تقرأ لافتة أمامك \"منحدر هروب الشاحنات على بعد ميل واحد\". بالنظر إلى ما بُني هذا المنحدر لفعله، أي عبارة صحيحة؟","options":["إنه منطقة استراحة إلزامية يجب على كل شاحنة محمّلة أن تتوقف فيها لتبريد الفرامل قبل متابعة النزول على المنحدر.","إنه طريق مختصر مُصان يتيح لك مغادرة المنحدر والوصول إلى الأسفل أسرع بينما تتعافى فراملك التي ارتفعت حرارتها.","إنه منحدر هروب طارئ مصمّم هندسياً لإيقاف المركبة بأمان عندما تتعطل فراملها أو تتلاشى من فرط الحرارة.","إنه مخرج جانبي مرصوف يمكنك فيه مواصلة التحرك ببطء كي تتخلص الفرامل من الحرارة دون الوصول إلى التوقف التام أبداً."],"explanation":"منحدر هروب الشاحنات هو منحدر هروب طارئ مصمّم هندسياً لإيقاف مركبة بأمان عندما تتعطل فراملها أو تتلاشى من فرط الحرارة."},"148":{"q":"أنت تسير بسرعة 55 ميلاً في الساعة على طريق بين الولايات جاف عندما تنحرف سيارة فجأة أمامك وتكبح بقوة. يطلب منك مدرّبك لاحقاً فصل أجزاء مسافة توقفك الكلية. ويذكّرك بأن مسافة توقفك الكلية عند هذه السرعة هي نحو 419 قدماً. من هذا المجموع، كم تقطع شاحنتك خلال زمن ردّ فعلك فقط — الفجوة بين رؤية الخطر وضغط قدمك فعلاً على دواسة الفرامل، قبل أن تكون الفرامل قد أبطأت أي شيء على الإطلاق؟","options":["نحو 419 قدماً، لأن الشاحنة تستمر في التدحرج بالسرعة الكاملة طوال الوقت حتى تتوقف أخيراً","نحو 250 قدماً، لأن ذلك تقريباً مدى وصول أضواءك المنخفضة وإلى أي مدى أمامك يمكنك ردّ الفعل","نحو 6 أقدام، لأنه بسرعة الطريق السريع تحرّك ردود فعلك المدرّبة قدمك على الفور تقريباً","نحو 60 قدماً، وهي تقريباً المسافة المقطوعة في ثلاثة أرباع الثانية التي يستغرقها السائق المتوسط لردّ الفعل"],"explanation":"مسافة ردّ الفعل هي المسافة المقطوعة بعد إدراك الخطر وقبل بدء الكبح، نحو 60 قدماً بسرعة 55 ميلاً في الساعة خلال زمن ردّ الفعل المتوسط البالغ ثلاثة أرباع الثانية."},"149":{"q":"أنت تقترب من تقاطع في المدينة بمركبتك المركّبة المحمّلة عندما تتحول إشارة المرور إلى ضوء أحمر ثابت (غير وامض). حركة المرور خفيفة ولا ترى أي حركة مرور عابرة أو مشاة في هذه اللحظة. أي إجراء مطلوب منك قانونياً كسائق رخصة قيادة تجارية؟","options":["خفّف السرعة إلى الزحف وتابع عبر التقاطع لأنه لا توجد حركة مرور عابرة","تعامل مع الأحمر الثابت تماماً كما تتعامل مع الأحمر الوامض، بأن تفسح الطريق دون التوقف بالضرورة إذا كان الطريق خالياً","توقف توقفاً تاماً وابقَ متوقفاً حتى تتحول الإشارة إلى الأخضر","توقف فقط إذا كانت هناك مركبة أو مشاة فعلاً في مسارك، وإلا فتابع"],"explanation":"يتطلب الضوء الأحمر الثابت أن تتوقف توقفاً تاماً وتبقى متوقفاً حتى تتحول الإشارة إلى الأخضر."},"150":{"q":"أنت تقود شاحنة بمقطورة محمّلة على طريق سريع جاف ومفتوح بسرعة 55 ميلاً في الساعة عندما تلاحظ سيارة متعطلة مرفوعة الغطاء على بُعد حوالي ربع ميل (12-15 ثانية) أمامك في مسارك. حركة المرور في المسار المجاور كثيفة، لذا لا يمكنك تغيير المسار بعد. ما هو أفضل إجراء أول تتخذه؟","options":["حافظ على سرعتك وانتظر حتى تكون على بُعد حوالي 200 قدم قبل أن تتفاعل، لأن ذلك يمنحك مساحة كافية","سرّع لفترة وجيزة لخلق فجوة وافرض دخولك إلى المسار المجاور قبل الوصول إلى السيارة المتعطلة","افرمل بقوة فوراً لتخفيض أكبر قدر ممكن من السرعة قبل أن تصل إلى الخطر","ارفع قدمك عن دواسة الوقود واجعل قدمك مستعدة فوق الفرامل لتتمكن من التباطؤ بسلاسة مع تطور الموقف"],"explanation":"عندما يكون الخطر بعيداً أمامك، ارفع قدمك عن دواسة الوقود واجعلها مستعدة فوق الفرامل حتى تتمكن من التباطؤ بسلاسة دون توقف مفاجئ."},"151":{"q":"أنت تنقل مركبة مركّبة بطول 60 قدماً على طريق سريع جاف وصافٍ بمسارين بسرعة 35 ميلاً في الساعة وتريد ترك مسافة اتباع مناسبة خلف السيارة التي أمامك. بناءً على طول مركبتك، ما هي الحد الأدنى لمسافة الاتباع الآمنة التي يجب أن تحافظ عليها في هذه الظروف الجيدة؟","options":["حوالي 6 ثوانٍ — ثانية واحدة لكل 10 أقدام من طول مركبتك","حوالي 7 ثوانٍ — ثانية واحدة لكل 10 أقدام بالإضافة إلى ثانية إضافية للسرعة","مسافة ثابتة قدرها 4 ثوانٍ، لأن 4 ثوانٍ هي الفجوة القياسية لأي مركبة في الطقس الجيد","لا حاجة لأي فجوة محسوبة عند 35 ميلاً في الساعة لأن هذه السرعة منخفضة بما يكفي للتوقف بسرعة"],"explanation":"اترك ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، لذا تحتاج مركبة مركّبة بطول 60 قدماً إلى حوالي 6 ثوانٍ عند سرعات 40 ميلاً في الساعة أو أقل."},"152":{"q":"إنه الصباح الباكر أثناء فحصك قبل الرحلة. تشغّل المحرك وتراقب المقاييس على لوحة القيادة. خلال اللحظات الأولى بعد بدء التشغيل، ماذا يجب أن يفعله مقياس ضغط زيت المحرك (أو مصباح تحذير ضغط الزيت) قبل أن تقرر أن الشاحنة آمنة للقيادة؟","options":["يجب أن يبقى ضغط الزيت عند الصفر بينما يكون المحرك بارداً، ثم يرتفع فقط بعد أن تكون قد قدت لعدة أميال","يجب أن يرتفع ضغط الزيت إلى قراءة طبيعية خلال وقت قصير بعد بدء التشغيل (وأن ينطفئ أي مصباح تحذير لضغط الزيت)","يجب أن يبقى مصباح تحذير ضغط الزيت مضاءً طوال فترة تشغيل المحرك؛ فهذه هي الطريقة التي تعرف بها أن نظام التزييت يعمل","يجب أن يرتفع ضغط الزيت لفترة وجيزة إلى ما فوق النطاق الطبيعي بكثير ويبقى هناك، لأن القراءة الأعلى من الطبيعي تعني تزييتاً قوياً"],"explanation":"يجب أن يرتفع ضغط الزيت إلى النطاق الطبيعي بعد بدء التشغيل بفترة قصيرة وأن ينطفئ أي مصباح تحذير لضغط الزيت، مما يؤكد أن نظام التزييت يعمل."},"153":{"q":"إنه ظهيرة حارة وأنت تصعد بحمولة ثقيلة على منحدر طويل بترس منخفض. عند النظر إلى لوحة القياس، ترى مؤشر مقياس درجة حرارة سائل التبريد يرتفع إلى ما فوق نطاقه الطبيعي بكثير. بناءً على ما صُمم هذا المقياس المحدد لإخبارك به، ما هي الحالة التي يحذرك منها؟","options":["مستوى الوقود في خزانك أصبح منخفضاً بشكل خطير ويجب أن تعيد التزود بالوقود قريباً","خفتت أضواؤك الأمامية لأن مولد الكهرباء لم يعد يشحن البطارية","المحرك يسخن بشكل مفرط وقد يتعرض للتلف إذا واصلت الصعود بهذا الحمل","انخفض ضغط زيت المحرك إلى أقل من اللازم لتزييت الأجزاء المتحركة بشكل صحيح"],"explanation":"ارتفاع مؤشر درجة حرارة سائل التبريد فوق النطاق الطبيعي يعني أن المحرك يسخن بشكل مفرط وقد يتعرض للتلف إذا واصلت القيادة تحت الحمل."},"154":{"q":"أثناء فحصك قبل الرحلة في صباح بارد، تشغّل المحرك وتراقب مقياس ضغط الهواء. تلاحظ أن ضغط الهواء في خزاناتك يرتفع ببطء شديد نحو نطاق التشغيل، مستغرقاً وقتاً أطول بكثير من المعتاد للتراكم. لم يفصل منظّم الضاغط بعد. أي مما يلي هو التفسير الأكثر احتمالاً لهذا التراكم البطيء؟","options":["الضاغط في حالة ممتازة وهو ببساطة يحمي النظام عن طريق بناء الضغط تدريجياً","خزانات الهواء لديك ممتلئة بالفعل، لذا يُظهر المقياس فقط الضغط المتبقي","فرامل الخدمة لديك في حالة جيدة جداً، مما يبطئ معدل دخول الهواء إلى الخزانات","هناك تسرب للهواء في النظام أو أن الضاغط ضعيف، لذا يتراكم الضغط أبطأ مما ينبغي"],"explanation":"ضغط الهواء الذي يتراكم ببطء شديد يحذر من وجود تسرب للهواء في النظام أو من ضاغط ضعيف لا يستطيع مواكبة الطلب."},"155":{"q":"إن درجة الحرارة أقل من التجمد بقليل في فحص صباحي مبكر قبل الرحلة. ترفع غطاء المحرك وتمرر يدك على أحزمة المحرك وعلى خراطيم المبرّد والمدفأة. أي اكتشاف هو العيب السلامي الفعلي الذي تفحص بحثاً عنه، والذي يجب أن يمنع هذه الشاحنة من دخول الخدمة؟","options":["تشققات أو تهتك أو بقع لينة أو علامات تسرب على الأحزمة والخراطيم","أحزمة وخراطيم فقدت لمعانها المصنعي وأصبحت تبدو باهتة ومغبرّة","خراطيم لم تعد تُظهر بطاقة بعلامة تجارية قابلة للقراءة من الشركة المصنّعة","حزام لونه أغمق من اللون الزاهي الذي كان عليه عندما كان جديداً"],"explanation":"افحص الأحزمة والخراطيم بحثاً عن تشققات أو تهتك أو بقع لينة أو علامات تسرب، لأن هذا التدهور قد يسبب عطلاً أو فشلاً في المحرك."},"156":{"q":"أثناء فحصك قبل الرحلة في صباح بارد، تجد شقاً دقيقاً يمتد عبر أحد أطواق العجلات الفولاذية على محور دفع خلفي، وعلى عجلة مختلفة يكون صامولتان من صواميل التثبيت مرتخيتين بشكل ملحوظ. الإطارات نفسها لا تزال تحتفظ بالهواء ولها مداس جيد. مرسلك يضغط عليك للقيام بالرحلة لأن الحمولة حساسة للوقت. ما هو القرار الصحيح بشأن قيادة هذه المركبة؟","options":["بما أن الإطارات تحتفظ بالهواء ولها مداس جيد، فإن العجلات آمنة بما يكفي؛ يمكنك القيادة بحذر إلى الورشة وفحصها بعد التسليم","الطوق المتشقق وصواميل التثبيت المرتخية هي عيوب توجب إخراج المركبة من الخدمة؛ يجب عدم قيادة المركبة حتى يتم إصلاحها","شدّ صواميل التثبيت المرتخية يدوياً وراقب الطوق المتشقق؛ إذا لم يتسع الشق خلال أول 50 ميلاً، يمكنك متابعة الرحلة","إنها مشكلة فقط على محور التوجيه؛ بما أن هذه عجلات دفع خلفية، فإن الطوق المتشقق والصواميل المرتخية هناك مجرد تآكل بسيط والمركبة جيدة للتشغيل"],"explanation":"الأطواق المتشققة وصواميل التثبيت المرتخية هي عيوب توجب إخراج المركبة من الخدمة، لذا يجب عدم قيادة المركبة حتى يتم إصلاحها."},"157":{"q":"أثناء الفحص الدائر حول المركبة، تفحص وصلة التوجيه بحثاً عن:","options":["طلاء نظيف","ارتخاء أو تلف","ملصق شعار","وزن إضافي مُضاف"],"explanation":"افحص وصلة التوجيه بحثاً عن ارتخاء أو تلف."},"158":{"q":"أثناء فحصك قبل الرحلة في الساحة، تجد بركة طازجة من السائل على الرصيف مباشرة تحت الشاحنة الجرّارة. لا تزال الخزانات تقرأ ضمن نطاقها الطبيعي والشاحنة تشتغل وتعمل بشكل جيد. أنت متأخر بالفعل عن جدول نافذة التسليم. ما هو الإجراء الصحيح؟","options":["لاحظ مستوى السائل، واملأ الخزان للأمان، وتابع الرحلة لأن المقاييس تقرأ بشكل طبيعي","اتركها وشأنها الآن وأعد فحص البركة في أول توقف لك خلال أول 50 ميلاً لترى ما إذا كانت تزداد سوءاً","لا تقد حتى تحدد مصدر التسرب ويتم إصلاحه، حتى لو جعلك ذلك متأخراً","امسح البركة، وسجّل الفحص على أنه مُرضٍ، وراقب المقاييس عن كثب أثناء القيادة"],"explanation":"تسرب السائل المعروف هو عيب قد يفشل بشكل كارثي، لذا لا تقد حتى تجد المصدر ويتم إصلاحه، حتى لو جعلك ذلك متأخراً."},"159":{"q":"إنه قبيل الفجر وأنت تقوم بفحصك الدائر قبل الرحلة. عدة عاكسات خلفية ومصباحان من مصابيح الذيل/الإضاءة الجانبية مغطاة بأوساخ الطريق المجففة، وعدسة أحد مصابيح الذيل تبدو خافتة حتى عند تشغيل الأضواء. الشاحنة بخلاف ذلك محمّلة وجاهزة للانطلاق. أي إجراء يلبي على أفضل وجه معيار الفحص للأضواء والعاكسات قبل أن تغادر؟","options":["اترك العاكسات وشأنها لأنها أجهزة سلبية، لكن استبدل أي لمبة لمصباح ذيل تفشل في الإضاءة","امسح فقط المصابيح التي تعمل بالكهرباء، لأن العاكسات لا تحتاج إلى أن تكون نظيفة لتؤدي عملها","غطِّ العدسات الخافتة أو المتسخة بشريط لاصق حتى لا يُخلط بينها وبين مصباح محترق، ثم قُد إلى الورشة","نظّف الأوساخ عن جميع المصابيح والعاكسات وتأكد من أن كل واحد منها يعمل قبل الرحلة"],"explanation":"يجب أن تكون جميع المصابيح والعاكسات نظيفة وعاملة قبل الرحلة، لأن الأوساخ تمنع العاكس من العكس والمصباح من أن يُرى."},"160":{"q":"تصل إلى شاحنتك في الساحة لبدء فحصك قبل الرحلة. أنت متحمس للانطلاق، لذا تبدأ بسرد ما يجب فعله أولاً ذهنياً: تسخين المحرك، والمشي حول المنطقة، واختبار الفرامل، وفحص الأضواء. قبل أن تلمس أي شيء على المركبة، أي إجراء ينتمي بشكل صحيح إلى الخطوة الأولى تماماً من طريقة الفحص؟","options":["قم بإلقاء نظرة عامة عن طريق الاقتراب من المركبة سيراً على الأقدام، ملاحظاً حالتها العامة ووضعيتها/ميلها وبرك السوائل الطازجة تحتها وأي مخاطر حولها قبل أن تركبها","شغّل المحرك ودعه يسخن إلى درجة حرارة التشغيل حتى تقرأ المقاييس بدقة أثناء سيرك حول المركبة","قم باختبار فرامل الخدمة بالضغط المطبّق عن طريق التقدم للأمام بسرعة حوالي 5 أميال في الساعة والضغط على دواسة الفرامل","امشِ إلى الأمام والخلف وتأكد من أن جميع الأضواء الخارجية والعاكسات نظيفة وبالألوان الصحيحة وتعمل"],"explanation":"ابدأ الفحص قبل الرحلة بإلقاء نظرة عامة عند الاقتراب، مع فحص وضعية المركبة وبرك السوائل والمخاطر المحيطة قبل أن تركبها."},"161":{"q":"أنت تقود شاحنة بمقطورة محمّلة بناقل حركة يدوي قياسي (غير متزامن) وتحتاج إلى الانتقال من الترس الخامس إلى السادس أثناء التسارع على طريق سريع مستوٍ. لإجراء هذا التعشيق الأعلى بنظافة دون طحن التروس، ما هي التقنية الصحيحة لنوع ناقل الحركة الموجود في العديد من الشاحنات؟","options":["اضغط على القابض جزئياً فقط (\"كبح القابض\") وافرض الذراع في الترس التالي","أبقِ القابض مضغوطاً بالكامل طوال التعشيق بأكمله مع التحكم برفق في دواسة الوقود","أبقِ يداً واحدة بثبات على المقود وعشّق دون استخدام القابض على الإطلاق بمجرد أن تكون متحركاً","استخدم القابض المزدوج: ارفع قدمك عن دواسة الوقود، اضغط على القابض، عشّق إلى الوضع المحايد، حرّر القابض، ثم اضغط على القابض مرة أخرى وعشّق إلى الترس الأعلى"],"explanation":"استخدم القابض المزدوج للتعشيق الأعلى: ارفع قدمك عن دواسة الوقود، اضغط على القابض وعشّق إلى الوضع المحايد، حرّر القابض، ثم اضغط عليه مرة أخرى وعشّق إلى الترس الأعلى."},"162":{"q":"أنت تنقل مقطورة محمّلة والطريق أمامك ينحدر إلى منحدر جبلي طويل وحاد. تريد التحكم في سرعتك بأمان أثناء النزول دون أن تسخن فراملك بشكل مفرط. في أي نقطة يجب أن تكمل تعشيقك إلى ترس منخفض؟","options":["قبل أن تبدأ النزول على المنحدر، بينما لا تزال على أرض مستوية في الأعلى","بينما تكون قد بدأت النزول بالفعل، بمجرد أن تشعر بالشاحنة تكتسب سرعة","عند أسفل المنحدر، بمجرد أن يعود الطريق مستوياً","فقط بعد أن يتوقف ضغط الفرامل الخفيف والثابت عن إبطائك"],"explanation":"عشّق إلى ترس منخفض قبل بدء النزول على منحدر طويل وحاد بينما لا تزال على أرض مستوية، لأن كبح المحرك هو وسيلة التحكم الرئيسية بالسرعة وفرامل الخدمة تكمّله فقط."},"163":{"q":"أنت تنقل مقطورة محمّلة على منحدر جبلي طويل. شاحنتك مزودة بمبطّئ، وتشغّله عند بدء النزول. أي عبارة تصف على أفضل وجه ما يفعله المبطّئ من أجلك هنا؟","options":["إنه يزيد من قوة محركك حتى تتمكن من اكتساب السرعة وتجاوز المنحدر بسرعة أكبر","إنه يطبّق قوة كبح إضافية للمساعدة في إبطاء المركبة، مما يقلل من تآكل فرامل الخدمة وتراكم الحرارة فيها","إنه يشدّ استجابة توجيهك بحيث تنعطف الشاحنة بسهولة أكبر عبر المنحنيات على المنحدر","إنه وسيلة التحكم الرئيسية للنزول، لذا لم تعد بحاجة إلى اختيار ترس منخفض قبل بدء النزول"],"explanation":"يطبّق المبطّئ قوة كبح إضافية لإبطاء المركبة، مما يقلل من تآكل فرامل الخدمة وتراكم الحرارة فيها."},"164":{"q":"إن درجة الحرارة أقل من التجمد بقليل وتشكّل طلاء خفيف من الجليد على الجسور على طول مسارك. شاحنتك الجرّارة مزودة بمبطّئ محرك (سرعة) ينخرط مع محاور الدفع عندما ترفع قدمك عن دواسة الوقود. وأنت ترفع قدمك عن دواسة الوقود لتبطئ من أجل منحنى على هذا السطح الزلق، ما هي الطريقة الصحيحة لإدارة ذلك المبطّئ؟","options":["اترك المبطّئ مشغّلاً بالكامل، لأن كبحه يؤثر فقط على عجلات الدفع وبالتالي لا يمكنه أن يخلّ بمحور التوجيه","طبّق المبطّئ بقوة ومبكراً حتى تتجنب لمس الفرامل القدمية على الإطلاق على الجليد","استخدمه بحذر شديد أو أوقفه، لأنه على سطح زلق يمكن أن يتسبب المبطّئ في فقدان عجلات الدفع للجر والانزلاق","أزل المبطّئ أو عطّله أثناء فحصك قبل الرحلة كلما كان هناك جليد في توقعات الطقس"],"explanation":"على سطح زلق، استخدم المبطّئ بحذر أو أوقفه، لأنه يمكن أن يجعل عجلات الدفع تفقد الجر وتنزلق."},"165":{"q":"أنت ترجع بمقطورتك إلى رصيف تحميل ضيق ليلاً. لا يوجد مساعد متاح ليوجهك، ومنطقة الرصيف محجوبة جزئياً عن الرؤية بمقطورات متوقفة. أي إجراء هو الطريقة الأكثر أماناً وصحة لإكمال المناورة؟","options":["ارجع بأسرع ما يمكن لقضاء أقل وقت في إعاقة المسار، مع إبقاء الرحلة قصيرة","ارفع دوران المحرك واستخدم القابض جزئياً حتى تتمكن من الدخول مباشرة دون التراجع","ركّز عينيك فقط على مرآة جانب السائق، لأن جانب الراكب هو جانبك الأعمى ولا يستحق الفحص","ارجع ببطء، مستخدماً كلتا المرآتين، وتقدم للأمام لإعادة التموضع كلما فقدت رؤية المكان الذي تتجه إليه"],"explanation":"ارجع ببطء مستخدماً كلتا المرآتين، وتقدم للأمام لإعادة التموضع كلما فقدت رؤية المكان الذي تتجه إليه."},"166":{"q":"إذا كنت غير متأكد أثناء الرجوع، يجب أن:","options":["تواصل المضي فحسب","تنزل وتنظر (تقدّم للأمام إذا لزم الأمر)","تسرّع للانتهاء","تغمض عينيك لفترة وجيزة"],"explanation":"انزل وانظر؛ تقدم للأمام لإعادة التموضع إذا لزم الأمر."},"167":{"q":"أنت تقترب من تقاطع مزدحم حيث تنوي الانعطاف يميناً إلى رصيف تحميل. حركة المرور كثيفة وسيارة صغيرة بدأت تتسلل بجانب شاحنتك الجرّارة على اليمين. لتوصيل نواياك بأمان ومنع تلك السيارة من أن تُضغط على حافة الرصيف، متى يجب أن تفعّل إشارة انعطافك؟","options":["مبكراً، قبل أن تبدأ الانعطاف بوقت كافٍ، حتى يكون لدى السائقين الآخرين وقت للتفاعل","عندما تبدأ في تدوير المقود في الانعطاف، بحيث يتطابق التوقيت مع حركتك","فقط بعد أن تكمل الانعطاف، لتجنب إرباك السائقين القريبين","فقط في الليل أو في ظروف الرؤية المنخفضة، عندما تكون الإشارات أكثر ما تكون مطلوبة"],"explanation":"أشِر مبكراً، قبل أن تبدأ الانعطاف بوقت كافٍ، حتى يكون لدى السائقين الآخرين وقت للتفاعل."},"168":{"q":"أنت تقوم بانعطاف بطيء وواسع إلى اليسار من شارع في المدينة إلى مدخل رصيف تحميل. في منتصف الانعطاف، يعود المقود إلى المركز جزئياً وتنطفئ إشارة انعطافك من تلقاء نفسها. هناك سيارة تنتظر عند الشارع المتقاطع وراكب دراجة يقترب من الخلف. ما هي الطريقة الصحيحة للتعامل مع إشارتك لبقية هذه المناورة؟","options":["ألغِ الإشارة بمجرد أن يدخل مقدمة شاحنتك الجرّارة إلى المدخل، لأن الانعطاف ملتزم به بشكل أساسي","أعد تفعيل الإشارة وأبقها وامضة حتى تكمل الانعطاف بالكامل وتصبح مركبتك مستقيمة","اترك الإشارة منطفئة الآن واضغط بدلاً من ذلك على فراملك مرتين لتوصيل نيتك لراكب الدراجة","أشِر فقط للثانية الأولى من الانعطاف، وهو كل ما يتطلبه القانون قبل أن تلتزم بالمناورة"],"explanation":"استمر في الإشارة بشكل متواصل حتى يكتمل الانعطاف بالكامل وتصبح مركبتك مستقيمة، لأن المقطورة تحتاج إلى القوس بأكمله لتتبع المسار."},"169":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع مزدحم بأربعة مسارات وترى حركة مرور بطيئة تتراكم على بُعد حوالي ربع ميل أمامك. ستحتاج إلى تخفيض سرعتك قريباً، وهناك صف من السيارات يتبعك عن قرب من الخلف. أي إجراء يوصّل على أفضل وجه للسائقين خلفك أنك على وشك التباطؤ؟","options":["أطفئ أضواءك الأمامية وأضواء الذيل بسرعة وأعد إشعالها لجذب انتباههم","أطلق بوقك مرتين قصيرتين حتى يعرف السائقون التابعون أن يتوقعوا تغييراً","اضغط بخفة على دواسة الفرامل عدة مرات لوميض أضواء الفرامل لديك مبكراً","سرّع لفترة وجيزة لفتح مساحة أمامك، ثم افرمل بقوة بمجرد أن تنغلق الفجوة"],"explanation":"لتحذير السائقين خلفك من أنك تتباطأ، اضغط بخفة على دواسة الفرامل عدة مرات لوميض أضواء الفرامل لديك مبكراً."},"170":{"q":"عندما تقود أبطأ بكثير من حركة المرور، استخدم:","options":["الأضواء العالية","الأضواء الوامضة الرباعية","البوق كثيراً","ماسحات الزجاج الأمامي"],"explanation":"استخدم الأضواء الوامضة الرباعية عندما تكون أبطأ بكثير من حركة المرور."},"171":{"q":"إنه ما بعد الفجر بقليل والشمس منخفضة على الأفق. الضوء خافت ورمادي، وتلاحظ أن السائقين الآخرين والأشكال يصعب تمييزها على خلفية الطريق. أنت في الوقت المحدد والرؤية ليست مفقودة تماماً بعد. لكي ترى الطريق وكذلك، وهو ما لا يقل أهمية، لتُرى من قبل حركة المرور الأخرى في هذا الشفق، أي إجراء هو الخيار الأفضل الوحيد؟","options":["شغّل ضوء قبة المقصورة الداخلي حتى يسهل تقييم الظروف الخافتة خارجاً من الداخل","اترك جميع الأضواء الخارجية مطفأة، لأنه لا يزال هناك ضوء نهار طبيعي كافٍ لرؤية الطريق أمامك","شغّل فقط أضواءك الوامضة الرباعية للخطر لتنبيه السائقين الآخرين إلى أن الرؤية ضعيفة","شغّل أضواءك الأمامية حتى ترى أمامك ويستطيع السائقون الآخرون رؤية مركبتك بوضوح"],"explanation":"عند الفجر أو الغسق، شغّل أضواءك الأمامية حتى ترى الطريق أمامك ويستطيع السائقون الآخرون رؤية مركبتك بوضوح."},"172":{"q":"أنت تنقل مقطورة محمّلة في حركة مرور معتدلة بسرعة 55 ميلاً في الساعة. سيارة صغيرة تقطع فجأة أمامك وتفرمل بقوة، وتدرك أنك قد أغلقت وسادة المساحة أمام مصدّك. لماذا يهم الحفاظ على تلك المساحة أمامك أكثر ما يكون في هذه اللحظة؟","options":["إنها تمنحك المساحة التي تحتاجها إما للفرملة حتى التوقف أو للمناورة حول خطر بأمان","إنها تتيح لك الحفاظ على سرعة انطلاق أعلى دون استخدام فراملك بقدر كبير","إنها توفر الوقود لأنك تفرمل وتسرّع أقل في حركة المرور الثابتة","إنها تثبّط السائقين الآخرين عن القطع أمامك والازدحام في مسارك"],"explanation":"المساحة أمامك هي هامش الهروب لديك، فهي تمنحك المساحة إما للفرملة حتى التوقف الكامل أو للمناورة حول خطر بأمان."},"173":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق سريع مزدحم بمسارين بسرعة 50 ميلاً في الساعة عندما تلاحظ أن سيارة صغيرة قد دخلت عن قرب خلفك وتلاصقك، باقية على بُعد طول سيارة أو سيارتين فقط عن مصدّك. حركة المرور أمامك تتحرك بثبات لكن قد تتباطأ في أي لحظة. أي مما يلي هو أفضل طريقة لإدارة هذا الخطر؟","options":["اضغط بخفة على فراملك لوميض أضواء الفرامل لديك وإشعار الملاصق بالتراجع","افتح مزيداً من المساحة أمامك عن طريق رفع قدمك تدريجياً عن دواسة الوقود وزيادة مسافة اتباعك، حتى تتمكن من الفرملة بلطف إذا تباطأت حركة المرور","حافظ على سرعتك وأبقِ موضع مسارك، لأن الملاصق مسؤول عن المساحة خلف مركبتك","سرّع للابتعاد عن الملاصق وإعادة تأسيس فجوة آمنة"],"explanation":"عندما يلاصقك أحدهم، ارفع قدمك تدريجياً عن دواسة الوقود لفتح مزيد من المساحة أمامك حتى تتمكن من الفرملة بلطف بدلاً من بشكل مفاجئ إذا تباطأت حركة المرور."},"174":{"q":"أنت تسير بسرعة الطريق السريع في المسار الأوسط من طريق سريع بين الولايات بثلاثة مسارات. استقرت سيارة بجانب شاحنتك الجرّارة على اليمين وتحافظ على ذلك الموضع، لا تتجاوز ولا تتراجع، تسير على مستوى مقصورتك. لماذا يكون البقاء في هذا الترتيب جنباً إلى جنب أقل الأوضاع رغبة بالنسبة لك كسائق؟","options":["السير بشكل متوازٍ يجبر المركبتين على حرق وقود أكثر بشكل ملحوظ، لذا فهو يرفع تكاليف تشغيلك على مدى رحلة طويلة","يحظر قانون تكساس تحديداً سير مركبتين جنباً إلى جنب في مسارين متجاورين على طريق سريع محدود الوصول","من المرجح أن تكون السيارة في إحدى نقاطك العمياء، لذا إذا احتجت إلى تغيير المسار فقد لا تراها وقد تندمج فيها","البقاء على مستوى مركبة أخرى يضيع وقتك لأنك لا تستطيع استخدام تغيير المسار لإحراز تقدم للأمام"],"explanation":"المركبة التي تسير بجانبك غالباً ما تكون في نقطة عمياء جانبية حيث لا تستطيع رؤيتها، لذا قد تندمج فيها أثناء تغيير المسار."},"175":{"q":"أنت تقود شاحنة صندوقية محمّلة على طريق غير مألوف عندما ترى لافتة ارتفاع خلوص لجسر علوي تبلغ 13 قدماً و2 بوصة أمامك مباشرة. لكي تقرر بأمان ما إذا كان بإمكانك المرور من تحته دون أن تصطدم بالهيكل، فإن أهم شيء واحد يجب أن تعرفه مسبقاً هو:","options":["تصنيف الوزن الإجمالي للمركبة (GVWR) المختوم على بابك، حتى لا تتجاوز حد وزن الجسر المعلن","مسافة التوقف الكلية لديك عند هذه السرعة، والتي تبلغ نحو 419 قدماً عند 55 ميلاً في الساعة","طول مركبتك، حتى تتمكن من تجاوز الهيكل بالكامل قبل التوقف","ارتفاع مركبتك المحمّلة، بما في ذلك أي حمولة أو معدات مثبّتة في الأعلى"],"explanation":"يجب أن تعرف ارتفاعك الفعلي وأنت محمّل، بما في ذلك الحمولة أو المعدات المثبّتة على السقف، لمقارنته بارتفاع الخلوص المعلن للجسر العلوي."},"176":{"q":"أنت تقود مقطورة بطول 53 قدماً وتحتاج إلى الانعطاف يميناً من شارع داخل المدينة إلى طريق جانبي ضيّق. وأنت تقترب من الزاوية، تدرك أن الانعطاف أحدّ مما توقعت. ما هي الطريقة الأكثر أماناً للحفاظ على مساحة كافية لإتمام هذا الانعطاف؟","options":["ابقَ في مسارك الصحيح أثناء الاقتراب، ثم انعطف بشكل واسع عند إتمام الانعطاف حتى تتمكن المقطورة التي تنحرف مسارها من تجاوز الزاوية، مع إبقاء مؤخرة المقطورة قريبة من الرصيف طوال الوقت","انتقل إلى المسار الأيسر أولاً وابدأ الانعطاف مبكراً حتى تقطع مؤخرة المقطورة الزاوية بإحكام وتبقى قريبة من الرصيف","زِد سرعتك أثناء الانعطاف حتى تقضي وقتاً أقل في عرقلة التقاطع وتتجاوزه بسرعة","أبقِ الشاحنة ملاصقة للرصيف الأيمن طوال الوقت حتى لا تتمكن أي مركبة أخرى من التسلل إلى الفجوة على يمينك"],"explanation":"بما أن العجلات الخلفية للمقطورة تنحرف عن مسارها، ابقَ في مسارك أثناء الاقتراب وانعطف بشكل واسع عند إتمام الانعطاف، مع إبقاء مؤخرة المقطورة قريبة من الرصيف."},"177":{"q":"أنت متوقف عند علامة قف في مركبة مركّبة محمّلة بالكامل، تنتظر عبور طريق سريع مزدحم بمسارين تتحرك فيه حركة المرور بسرعة 55 ميلاً في الساعة في كلا الاتجاهين. تنفتح أمامك فجوة في الحركة المعترضة. وبما أن مركبتك ثقيلة وتتسارع ببطء، فما الذي يجب أن تسمح به تلك الفجوة قبل أن تقرر الانطلاق؟","options":["تحريك المصدّ الأمامي قليلاً بعد الحافة القريبة حتى يراك السائقون القادمون ويبطئون","عبور مركبتك بأكملها عبر الطريق بالكامل، أو الوصول إلى سرعة حركة المرور، قبل أن تصل إليك المركبة التالية","الوصول إلى منتصف التقاطع والتوقف توقفاً تاماً لتقدير المسار الثاني","الدخول والوقوف في المسار لفترة كافية فقط ليتمكن السائق القادم من تغيير مساره وتجاوزك"],"explanation":"اختر فجوة كبيرة بما يكفي لعبور مركبتك بأكملها بالكامل أو الوصول إلى سرعة حركة المرور قبل أن تصل إليك المركبة القادمة."},"178":{"q":"أنت تدمج مقطورتك في طريق سريع بين الولايات مزدحم خلال حركة مرور كثيفة بعد الظهر. يستمر صف من سيارات الركاب في الانجراف على جانبك الأيمن، متمركزاً قرب عجلاتك الخلفية حيث لا تظهر لك المرايا شيئاً تقريباً. يبدو أن عدة سائقين يستقرّون بارتياح في تلك الجيبة بجانب مؤخرة مقطورتك وخلفها. فيما يخص مناطق النقاط العمياء (مناطق اللارؤية 'No-Zones') حول مركبتك، أي نهج يعكس على أفضل وجه ممارسة القيادة التجارية الآمنة؟","options":["تعامل مع مناطق اللارؤية كمسارات سير عادية ودَع السيارات تبقى فيها، فهي اختارت أن تكون هناك والمسؤولية تقع عليها","سرّع بشدة لدفع السيارات خارج منطقة اللارؤية الخلفية اليمنى، لأن إخلاء الجيبة بسرعة هو دائماً الحل الأكثر أماناً","أدرك أنك لا تستطيع رؤية المركبات في مناطق اللارؤية وأدِر قيادتك للحفاظ على خلوّ تلك المناطق من حركة المرور كلما أمكن","انجرف ببطء إلى نقاط السيارات العمياء بالمقابل حتى تُقتسم المخاطرة بالتساوي بينك وبين السيارات الصغيرة"],"explanation":"لا يمكنك رؤية المركبات في مناطق اللارؤية، لذا أدِر سرعتك وموقعك في المسار والمسافة بينك وبينها للحفاظ على خلوّ تلك المناطق العمياء من حركة المرور."},"179":{"q":"أنت تقود مركبة مركّبة محمّلة بالكامل وتدمج في منحدر صاعد طويل وحادّ في المسار الأيمن. وأنت تصعد، يجهد محركك وتنخفض سرعتك باطّراد إلى ما دون الحد المعلن بكثير، بينما تبدأ السيارات الأسرع والمركبات الأخفّ بالتكدّس خلفك. أي مما يلي هو أفضل طريقة لإدارة شاحنتك على هذا المنحدر الصاعد؟","options":["انتقل إلى المسار الأقصى يساراً حتى تتمكن المركبات الأبطأ خلفك من تجاوزك من اليمين دون تغيير المسار","خفّض الترس وسرّع بقوة للحفاظ على سرعتك عند الحد المعلن حتى لا تعيق حركة المرور الأسرع خلفك","حافظ على سرعتك لكن انتقل إلى الكتف الأيمن وتوقف لفترة وجيزة للسماح لصف المركبات بالمرور قبل المتابعة","تقبّل أن الحمولة الثقيلة ستبطئك، وابقَ في المسار الأيمن، ودَع حركة المرور الأسرع تتجاوزك من اليسار"],"explanation":"الحمولة الثقيلة تبطئك طبيعياً على المنحدر الحادّ، لذا ابقَ في المسار الأيمن ودَع حركة المرور الأسرع تتجاوزك من اليسار."},"180":{"q":"أنت تقود مقطورة بطول 53 قدماً على طريق سريع بثلاثة مسارات في حركة مرور معتدلة. تسير سيارة بجانبك في المسار الأيسر، وعلى يمينك منحدر دخول يغذّي الطريق السريع بالمركبات. لا يمكنك التخلي عن مساحة على كلا الجانبين في آنٍ واحد. أي إجراء يدير على أفضل وجه مساحتك على الجانبين في هذا الموقف؟","options":["أبقِ مركبتك في وسط مسارك حتى تحافظ على وسادة مساحة على كلا الجانبين بدلاً من تخصيص كل مساحتك لجانب واحد","انتقل والتصق بخط المسار الأيسر لتضع أقصى مسافة بين مقطورتك وحركة منحدر الدخول المندمجة","ركّب خط المسار داخل المسار الأيسر لفترة وجيزة حتى لا تتمكن أي مركبة من التوقف بجانب نقاطك العمياء","انتقل بهدوء إلى الكتف الأيمن حتى تنتهي حركة منحدر الدخول من الاندماج، ثم عُد إلى مسارك"],"explanation":"إبقاء مركبتك في وسط المسار يحافظ على وسادة مساحة على كلا الجانبين عندما تأتي الأخطار من اليسار واليمين في آنٍ واحد."},"181":{"q":"أنت تقترب من مزلقان سكة حديد في حركة مرور كثيفة متوقفة ومتحركة. لا يوجد في المزلقان بوابة ولا إشارات وامضة، والمركبات أمامك تزحف ببطء. مركبتك المركّبة بطول 73 قدماً هي المركبة التالية للوصول إلى القضبان. ما هي أفضل طريقة وحيدة لتقرر ما إذا كنت ستعبر القضبان؟","options":["تقدّم إلى القضبان وانتظر هناك، بما أنه لا توجد بوابة ولا إشارة تحذّر من قطار","انتظر حتى تتوفر فجوة كبيرة بما يكفي للعبور بالكامل دون توقف، تاركاً مساحة لطولك الكامل بالإضافة إلى نحو 15 قدماً من الخلوص","ادخل المزلقان فور تحرّك المركبة أمامك، لأن إبقاء حركة المرور انسيابية هو الأولوية","ابدأ العبور، وإذا تعطّلت حركة المرور، انتقل إلى ترس أدنى على القضبان لتعبر بقوة بسرعة"],"explanation":"لا تبدأ العبور عبر القضبان أبداً ما لم تسمح الفجوة بتجاوزها بالكامل دون توقف، مع مراعاة طولك الكامل بالإضافة إلى نحو 15 قدماً."},"182":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق سريع جاف بمسارين وترى منعطفاً حاداً معلناً أمامك. أنت تسير حالياً قرب السرعة القانونية وتشعر أن سرعتك الحالية قد تكون أسرع قليلاً مما يلزم للمنعطف. للتعامل مع المنعطف بأمان، ماذا يجب أن تفعل بشأن سرعتك وكبحك؟","options":["حافظ على سرعتك حتى المنعطف، ثم اكبح بقوة بمجرد وصولك إلى منتصف المنعطف حيث يكون أكثر حدّة.","انتظر حتى تخرج من المنعطف، ثم أبطئ لتكون مستعداً للمنعطف التالي.","خفّض إلى سرعة آمنة قبل دخول المنعطف، ثم سرّع بلطف خلاله للحفاظ على ثبات المركبة.","حافظ على سرعة ثابتة عند دخول المنعطف واعتمد على ضغط خفيف وثابت على الكابح طوال الانعطاف للتحكم بالشاحنة."],"explanation":"أبطئ إلى سرعة آمنة قبل دخول المنعطف، ثم سرّع بلطف خلاله، لأن الكبح داخل المنعطف قد يسبب انزلاقاً أو انقلاباً."},"183":{"q":"أنت تنقل حمولة على طريق سريع ريفي بمسارين عندما يبدأ مطر مستمر ويصبح الرصيف لامعاً ومبللاً. تتحرك حركة المرور بالحد المعلن 55 ميلاً في الساعة، وتشعر أن توجيهك أصبح خفيفاً قليلاً خلال منعطف طويل ممتد. أي إجراء هو الاستجابة الأكثر أماناً لانخفاض التماسك؟","options":["حافظ على 55 ميلاً في الساعة لكن زِد مسافة اتّباعك للتعويض، بما أن الحد المعلن لا يزال قانونياً","سرّع بلطف خلال المنعطف لإبقاء الوزن على محاور الدفع وتحسين التماسك","حافظ على سرعتك واضغط على الكوابح بسرعة متكررة لاختبار مقدار التماسك المتبقي","خفّض سرعتك إلى ما دون الحد المعلن لأن الرصيف المبلل يقلّل التماسك ويطيل مسافة التوقف"],"explanation":"التماسك، وليس الحد المعلن، هو ما يحدّد السرعة الآمنة، والرصيف المبلل يقلّل التماسك ويطيل مسافة التوقف، لذا أبطئ إلى ما دون الحد."},"184":{"q":"الجو أقل بقليل من درجة التجمّد وبدأ ثلج خفيف يتراكم على الطريق. أنت تقود مقطورة محمّلة بنفس السرعة على الطريق السريع التي حافظت عليها في طقس صافٍ وجاف في وقت سابق اليوم. مقارنة بتلك الظروف الجافة، ما هو أهم تغيير يجب أن تتوقعه في كيفية تعامل مركبتك، ولماذا؟","options":["التماسك ينخفض كثيراً، لذا تتشبّث إطاراتك بالطريق بدرجة أقل بكثير وتحتاج إلى مسافة أكبر بكثير للتوقف والتوجيه","التماسك ينخفض قليلاً فقط، لذا يكفي الحفاظ على مسافة اتّباع عادية وسرعة ثابتة للبقاء آمناً","التماسك يبقى تقريباً كما هو على الرصيف الجاف لأن وزن المقطورة المحمّلة يضغط الإطارات بقوة على الثلج","التماسك يتحسّن قليلاً في الواقع لأن طبقة الثلج الرقيقة تملأ فجوات السطح وتمنح الإطارات ما تتشبّث به أكثر"],"explanation":"الثلج والجليد يقلّلان التماسك بشدة، لذا تتشبّث إطاراتك بدرجة أقل بكثير وتحتاج إلى مسافة أكبر بكثير للتوقف والتوجيه."},"185":{"q":"لقد أنزلت للتو حمولتك الكاملة عند الرصيف وأنت الآن عائد إلى الساحة بمقطورة فارغة تماماً. على رصيف مبلل، تتقاطع أمامك سيارة دفع رباعي وتضطر إلى الكبح بقوة. مقارنة بحالتك عندما كنت محمّلاً بالكامل في وقت سابق، لماذا قد تحتاج شاحنتك في الواقع إلى مسافة أطول للتوقف الآن وهي فارغة؟","options":["المركبة الفارغة أثقل، لذا يحملها زخمها الإضافي مسافة أبعد قبل أن تتمكن من التوقف","مع وجود وزن قليل يضغط الإطارات على الطريق، يكون للشاحنة الفارغة تماسك أقل، لذا تُقفل العجلات بسهولة أكبر وتزداد مسافة الكبح","المقطورات الفارغة تسير أعلى، مما يرفع مركز الثقل ويطيل مسافة الكبح","الكوابح الفارغة تعمل أبرد وتفقد فعاليتها، مما يضيف نحو 60 قدماً إلى مسافة التوقف عند 55 ميلاً في الساعة"],"explanation":"الشاحنة الفارغة لديها وزن قليل يضغط الإطارات للأسفل، لذا تتشبّث بدرجة أقل، وتُقفل بسهولة أكبر، وتزداد مسافة الكبح."},"186":{"q":"أنت تنقل مقطورة محمّلة بالكامل نزولاً على منحدر جبلي طويل وحادّ. في منتصف النزول، تلاحظ أنك تضغط على دواسة الكابح باستمرار فقط للحفاظ على سرعتك، وبدأت رائحة حرارة تفوح في المقصورة. أي عبارة تصف على أفضل وجه ما يحدث لكوابح الخدمة الرئيسية لديك ولماذا؟","options":["الكوابح تكتسب قوة توقف كلما سخنت، لذا يمكنك تطبيقها بأمان بقوة أكبر لبقية النزول.","الكوابح تبرّد نفسها عبر تدفّق الهواء المستمر، لذا فإن الضغط الثابت على الدواسة هو الطريقة الأساسية الصحيحة للتحكم بسرعتك.","الكوابح تفرط في السخونة وتبدأ بفقدان فعاليتها، ولهذا يجب أن يكون كبح المحرك بترس منخفض هو وسيلة التحكم الأساسية والكوابح مجرد مكمّل.","الكوابح على وشك إقفال عجلات المقطورة، لذا يجب أن تضغط الدواسة بسرعة متكررة لمنع انثناء المقطورة."],"explanation":"على منحدر نزول طويل قد تفرط الكوابح في السخونة وتفقد فعاليتها، لذا يجب أن يقوم كبح المحرك بترس منخفض بالعمل الأساسي مع استخدام الكوابح كمكمّل فقط."},"187":{"q":"أنت في أعلى منحدر جبلي طويل وحادّ تنقل مقطورة ثقيلة محمّلة بالكامل. المطر يتساقط والطريق ينعطف بحدّة عند منتصف النزول تقريباً. قبل أن تحرّر الكوابح وتبدأ نزولك، يجب أن تقرر سرعة آمنة للنزول. أي مما يلي يصف بشكل صحيح ما يجب أن تعتمد عليه سرعة نزولك الآمنة؟","options":["انحدار المنحدر فقط، بما أن الجاذبية هي العامل الوحيد الذي يتحكم في مدى سرعة تدحرج الشاحنة نزولاً","دورات المحرك في الدقيقة (RPM) عند قمة التل بشكل رئيسي، لأن مطابقة قراءة عداد الدوران تحدّد السرعة الصحيحة لأي منحدر","الحد المعلن للسرعة بشكل شبه كامل، بما أن ذلك الرقم محدّد خصيصاً للمركبات التجارية المحمّلة بالكامل على ذلك المنحدر","الوزن الإجمالي لمركبتك وحمولتك، وطول المنحدر وانحداره، وظروف الطريق، والطقس"],"explanation":"تعتمد سرعة النزول الآمنة على الوزن الإجمالي للمركبة والحمولة، وطول المنحدر وانحداره، وظروف الطريق، والطقس."},"188":{"q":"أنت على وشك البدء بالنزول على منحدر جبلي طويل وحادّ بمقطورة محمّلة بالكامل. تريد التحكم بسرعتك دون أن تفرط في تسخين كوابحك وفقدان فعاليتها أثناء النزول. أي نهج هو أفضل طريقة لتقرير الترس الذي ستستخدمه؟","options":["استخدم نفس الترس المنخفض الذي ستحتاجه لصعود المنحدر، واخترْه قبل أن تبدأ النزول.","انتقل إلى ترس أعلى بكثير مما صعدت به حتى يعمل المحرك بسهولة أكبر أثناء النزول.","ضع ناقل الحركة في الوضع المحايد واعتمد على ضغط ثابت على الكابح للحفاظ على سرعتك.","ابقَ في ترسك العادي على الطريق السريع وخفّض الترس فقط إذا بدأت الكوابح بفقدان فعاليتها."],"explanation":"اختر نفس الترس المنخفض الذي ستستخدمه لصعود المنحدر، واخترْه قبل أن تبدأ النزول."},"189":{"q":"إنه الصباح الباكر ومقياس درجة الحرارة الخارجية يقرأ أقل بقليل من درجة التجمّد (نحو 30 فهرنهايت). الطريق السريع بمسارين الذي تقوده يبدو جافاً تماماً، ولم تواجه أي مشاكل في التماسك خلال الساعة الماضية. أنت الآن تقترب من جسر علوي طويل يمتد فوق وادي نهر. أي مما يلي هو الافتراض الأكثر أماناً عند وصولك إلى الجسر العلوي؟","options":["بما أن سطح الطريق بقي جافاً وكان لديك تماسك جيد، فلن يكون الجسر العلوي أكثر زلقاً من الرصيف الذي غادرته للتو","قد يكون الجسر العلوي متجمّداً رغم أن بقية الطريق صافية، لأن الجسور والممرات العلوية تتجمّد قبل أجزاء الطريق الأخرى","الجسر العلوي سيتجمّد آخر الكل، لذا فهو أأمن مكان للكبح أو تخفيض الترس إذا احتجت إلى الإبطاء","الممرات العلوية لا تتجمّد قبل الرصيف العادي، لذا تحتاج فقط لمراقبة الجليد بمجرد أن يدفأ الهواء بعد الظهر"],"explanation":"الجسور والممرات العلوية تتجمّد قبل أجزاء الطريق الأخرى، لذا قد يكون الجسر العلوي متجمّداً حتى عندما تكون بقية الرصيف صافية."},"190":{"q":"بدأ مطر مستمر للتو بعد فترة جفاف طويلة، وطبقة رقيقة من الماء تتجمّع على الطريق السريع فوق الزيت والغبار القديمين. حركة المرور خفيفة، لذا تميل إلى الحفاظ على سرعة أعلى. لإبقاء إطاراتك متشبّثة بالطريق وتجنّب الانزلاق المائي (الهيدروبلانينغ)، عند أي سرعة تقريباً يجب أن تدرك أن الانزلاق المائي قد يبدأ، حتى تبطئ إلى ما دونها في هذه الظروف؟","options":["لا يمكن أن يبدأ الانزلاق المائي حتى تصل إلى نحو 70 ميلاً في الساعة، لذا فإن أي سرعة على الطريق السريع دون ذلك آمنة في المطر.","الانزلاق المائي يصبح مصدر قلق فقط عند سرعات منخفضة جداً، نحو 5 أميال في الساعة، لذا فهو مشكلة مواقف سيارات بشكل رئيسي.","يمكن أن يبدأ الانزلاق المائي عند سرعات منخفضة تصل إلى نحو 30 ميلاً في الساعة، لذا يجب أن تخفّض سرعتك إلى ما دون ذلك على هذه الطبقة المبللة الزلقة.","الانزلاق المائي لن يبدأ حتى تتجاوز نحو 90 ميلاً في الساعة، وهي أعلى بكثير من أي سرعة قانونية للشاحنات."],"explanation":"يمكن أن يبدأ الانزلاق المائي عند سرعات منخفضة تصل إلى نحو 30 ميلاً في الساعة على طبقة مبللة زلقة، لذا خفّض سرعتك إلى ما دون ذلك."},"191":{"q":"أنت تسير بمقطورة محمّلة بسرعة الطريق السريع على طريق سريع بين الولايات في تكساس خلال زخّة مطرية صيفية غزيرة. تجمّعت مياه راكدة في أخاديد مسار السير. فجأة يصبح التوجيه خفيفاً وفضفاضاً، ويبدو أن إطاراتك الأمامية تفقد ملامستها للرصيف، ويرتعش عداد السرعة رغم أنك لم تغيّر دواسة الوقود. تدرك أنك بدأت تنزلق مائياً. ما هو الإجراء الأول الصحيح؟","options":["اضغط على دواسة الكابح بثبات وأبقِها مضغوطة لتقليل السرعة بأسرع ما يمكن، بما أن مسافة التوقف هي الأهم على الطريق المبلل","وجّه بسرعة نحو وسط المسار الأعلى والأجف لإعادة إطاراتك إلى الرصيف ذي التماسك الأفضل","حافظ على سرعتك الحالية لكن خفّض الترس لاستخدام كبح المحرك، بما أن عجلات الدفع لا تزال متماسكة على السطح المبلل","ارفع الضغط عن دواسة الوقود، وأبقِ عجلة القيادة مستقيمة، ودَع المركبة تبطئ حتى تستعيد الإطارات ملامستها الثابتة للطريق"],"explanation":"عند الانزلاق المائي، ارفع قدمك عن دواسة الوقود، وأبقِ عجلة القيادة مستقيمة، ودَع المركبة تبطئ حتى تستعيد الإطارات ملامستها الثابتة للطريق."},"192":{"q":"إنه منتصف يوليو في غرب تكساس والرصيف يتلألأ من الحرارة. كنت تسير بسرعة الطريق السريع لمدة ساعتين وتتوقف لإجراء فحص الحمولة والتثبيت المطلوب. أثناء توقفك، ما هي حالة الإطارات الأهم أن تراقبها في هذه الظروف؟","options":["مداس تآكل إلى ما دون 4/32 من البوصة على إطارات الدفع الخلفية","حروف الجدار الجانبي الباهتة وعلامات العلامة التجارية المفقودة على هيكل الإطار","ضغط منخفض قليلاً يجب أن تكمّله إلى رقم النفخ على البارد الآن","إطارات تعمل ساخنة بضغط ارتفع فوق الإعداد على البارد، مما يشير إلى خطر الانفجار"],"explanation":"في الطقس الحارّ راقب الإطارات التي تعمل ساخنة بضغط ارتفع فوق الإعداد على البارد، لأن الإطارات المفرطة في السخونة والضغط معرّضة للانفجار."},"193":{"q":"الحرارة 28 فهرنهايت في بداية مناوبتك وثلج رطب طوال الليل تجمّد على جرّارك. خلال فحص ما قبل الرحلة، تجد طبقة رقيقة من الجليد فوق النصف السفلي من الزجاج الأمامي وقشرة من الثلج المتجمّد على كلتا مرآتي الساحل الغربي. أنت متأخر عن جدولك بالفعل. قبل أن تنطلق إلى الطريق السريع، ماذا تطلب منك دائرة السلامة العامة في تكساس (DPS) أن تفعل؟","options":["أزِل تماماً كل الجليد والثلج المتجمّد حتى يصبح الزجاج الأمامي وكلتا المرآتين صافيين تماماً قبل القيادة","نظّف فقط منطقة جانب السائق التي تنظر من خلالها واترك المرايا، بما أن مزيل الضباب سيذيبها بمجرد أن تتحرك","اكشط رقعة رؤية صغيرة في الزجاج الأمامي واعتمد على كاميرا الرجوع للخلف وفحوصات الكتف بدلاً من المرايا المغطاة بالجليد","اترك الطبقة في مكانها لأنها عند 28 درجة أعلى من النقطة التي يؤثر فيها الجليد على التماسك، وقُد بسرعة منخفضة"],"explanation":"أزِل تماماً كل الجليد والثلج المتجمّد حتى يصبح الزجاج الأمامي وكلتا المرآتين صافيين تماماً قبل القيادة."},"194":{"q":"الجو أقل بقليل من درجة التجمّد في صباح رطب، وخلال فحص ما قبل الرحلة يبدو الرصيف تحت جرّارك مبللاً ولامعاً فقط وليس متجمّداً. وأنت تنطلق إلى الطريق السريع تشعر أن التوجيه أصبح خفيفاً والشاحنة تنحرف قليلاً. لماذا يكون 'الجليد الأسود' الذي على الأرجح قدت عليه خطيراً جداً في هذا النوع من المواقف تحديداً؟","options":["يشكّل سطحاً خشناً ومتقشّراً بشكل مرئي، لذا يمكنك رصده مبكراً والكبح بقوة قبل الوصول إليه","إنه طبقة رقيقة شفافة تجعل الطريق يبدو مبللاً فقط، لذا لا يمكنك رؤيته وقد لا تدرك أن السطح متجمّد حتى تفقد التماسك","يتجمّع فقط على قمم التلال، لذا يقتصر الخطر على مقاطع قصيرة ويمكن التنبؤ بها من الطريق","يظهر دائماً كطبقة بيضاء سميكة، مما يمنحك تحذيراً كافياً للإبطاء مسبقاً"],"explanation":"الجليد الأسود طبقة رقيقة شفافة تجعل الطريق يبدو مبللاً فقط، لذا لا يمكنك رؤيته وقد لا تدرك أن السطح متجمّد حتى تفقد التماسك."},"195":{"q":"إنه بعد الفجر مباشرة وأنت تنقل مقطورة محمّلة عبر وادي نهر منخفض حيث خفّض ضباب كثيف ومتقطّع الرؤية إلى نحو طول مركبتك. تقرر الاستمرار في التحرك ببطء بدلاً من التوقف في مسار السير. أي خيار إضاءة يمنحك أفضل رؤية ويجعلك أكثر وضوحاً للآخرين؟","options":["بدّل إلى الأضواء العالية، بما أن الضوء الأكثر سطوعاً سيخترق الضباب أعمق أمامك","أطفئ مصابيحك الأمامية وشغّل فقط أضواء التحذير الرباعية لتجنّب الوهج","استخدم أضواءك المنخفضة (مع مصابيح الضباب إن وُجدت)، لأن الأضواء العالية تنعكس عن الضباب وترتدّ الضوء إليك","أبقِ الأضواء العالية مضاءة لكن خفّفها فقط عندما تكون ضمن 500 قدم من مركبة قادمة"],"explanation":"استخدم الأضواء المنخفضة في الضباب لأن الأضواء العالية تنعكس عن قطرات الماء المعلّقة وترتدّ الوهج إليك، مما يقلّل ما يمكنك رؤيته."},"196":{"q":"إنها ليلة مظلمة بلا قمر على طريق سريع ريفي بمسارين دون إنارة شوارع. أضواؤك المنخفضة تنير نحو 250 قدماً من الطريق أمامك. للقيادة بأمان، كيف يجب أن تختار سرعتك؟","options":["طابق الحد المعلن للسرعة النهارية، بما أن الحد محدّد للطريق ولا يتغيّر بعد حلول الظلام","اختر سرعة تتساوى عندها مسافة توقفك الكلية مع ضعف المسافة التي تُظهرها مصابيحك، مما يمنحك وسادة أمان","حافظ على سرعة ثابتة قدرها 55 ميلاً في الساعة واعتمد على أضوائك العالية للتفاعل في الوقت المناسب مع أي شيء أمامك","قُد ببطء كافٍ بحيث يمكنك التوقف توقفاً تاماً ضمن المسافة التي تنيرها مصابيحك"],"explanation":"لا تقُد أبداً أسرع مما تنيره مصابيحك؛ أبقِ سرعتك منخفضة بما يكفي للتوقف ضمن المسافة التي تنيرها مصابيحك فعلاً أمامك."},"197":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق سريع ريفي بمسارين في وقت متأخر بعد الظهر عندما تقطع زخّة مطرية مفاجئة وغزيرة رؤيتك إلى بضع مئات من الأقدام. حركة المرور قليلة لكن المركبات القادمة لا تزال تظهر من حين لآخر، وتريد أن ترى الطريق وأن تُرى. أي إعداد للمصابيح الأمامية هو الخيار الأفضل لهذه الظروف من المطر الغزير؟","options":["الأضواء المنخفضة، لأنها تساعد الآخرين على رؤيتك دون أن تعكس الوهج عن المطر الغزير","الأضواء العالية، لأن المسافة الإضافية التي تنيرها ضرورية للرؤية عبر المطر الغزير","المصابيح الأمامية مطفأة مع تشغيل أضواء الوقوف فقط، حتى لا يُحدث سطح الطريق المبلل انعكاسات مشتّتة","الأضواء العالية تُومض تشغيلاً وإطفاءً لتحذير حركة المرور القادمة بأن الرؤية ضعيفة"],"explanation":"استخدم الأضواء المنخفضة في المطر الغزير حتى يراك السائقون الآخرون مع تجنّب الوهج الذي تُحدثه الأضواء العالية عند انعكاس ضوئها عن المطر."},"198":{"q":"إنه منتصف بعد الظهر في موجة حرّ بتكساس وكانت درجة حرارة الرصيف ترتفع طوال اليوم. وأنت تبطئ عند تقاطع مظلّل، تلاحظ خطوطاً قاتمة ولامعة من القار تنزّ صعوداً عبر شقوق الإسفلت في مسار السير أمامك. بناءً على كيفية تأثير الطقس الحارّ جداً على سطح الطريق، أي خطر يجب أن تكون أكثر استعداداً له وأنت تمرّ فوق هذه الرقع؟","options":["سيكون القار قد تصلّب إلى سطح خشن عالي التماسك، لذا يمكنك الكبح بقوة أكبر من المعتاد","القار النازّ يمكن أن يجعل سطح الطريق زلقاً، لذا خفّض سرعتك وتجنّب الكبح القوي أو التوجيه الحاد فوقه","الرقع تشكّل جليداً أسود، لذا فإن السطح الذي يبدو مبللاً هو في الواقع متجمّد","ستكون الحرارة قد رفعت ضغط الإطارات بما يكفي لتحسين التماسك فوق القار، لذا لا حاجة لتغيير السرعة"],"explanation":"في الطقس الحارّ جداً ينزّ القار إلى السطح ويصبح زلقاً، لذا خفّض سرعتك وتجنّب الكبح القوي أو التوجيه الحاد عبره."},"199":{"q":"إنها فترة بعد ظهر عاصفة ورياحية وأنت على وشك المغادرة بمقطورة صندوقية عالية ومحمّلة بشكل خفيف على مقطع مكشوف من طريق سريع بين الولايات. يخبرك زميل ألا تقلق لأن المقطورة الفارغة العالية 'تتدبّر أمرها بنفسها' بشكل أفضل في الرياح. بالنظر إلى كيفية تأثير الرياح العرضية القوية على مقطورة عالية المظهر الجانبي، ماذا يجب أن تتوقع فعلاً بشأن التحكم بمركبتك؟","options":["ستكون المقطورة العالية أسهل في التحكم، لأن ارتفاعها يبقيها ثابتة ضد الرياح","ستتوقف المقطورة العالية أسرع، بما أن الرياح تساعد في الدفع ضد حركتك إلى الأمام","ستكون المقطورة العالية أصعب في التحكم، لأن الرياح القوية تدفع ضد مساحتها السطحية الكبيرة والعالية","ستستهلك المقطورة العالية وقوداً أقل، لأن الرياح تقلّل الحمل على محور الدفع لديك"],"explanation":"الرياح القوية تدفع ضد السطح الجانبي الكبير والعالي للمقطورة العالية، مما يجعل المركبة أصعب في التحكم، خاصة عندما تكون فارغة أو محمّلة بشكل خفيف."},"200":{"q":"درجة الحرارة أقل بقليل من نقطة التجمد، وكان مطر خفيف يتساقط. وبينما تقترب من جسر مظلَّل، يبدو الرصيف أمامك فجأة مبللاً ولامعاً رغم أن مرآتك وهوائيك قد بدآ يتجمدان. أي إجراء هو الطريقة الأكثر أماناً لقيادة شاحنتك المحمَّلة عبر هذا المقطع؟","options":["حافظ على سرعتك الحالية ولكن اضغط على الفرامل عدة مرات الآن لاختبار مقدار التماسك المتبقي للسطح","حافظ على سرعتك واكتفِ بزيادة مسافة الاتباع، لأن الجسور تذوب أسرع من الطريق المفتوح","تسارع بسلاسة لعبور الجسر بسرعة قبل أن يزداد تجمد السطح صلابة","قلِّل سرعتك قبل الجسر بوقت كافٍ واستخدم توجيهاً وكبحاً وتسارعاً سلساً ولطيفاً"],"explanation":"المظهر المبلل اللامع مع وجود الجليد على المرآة والهوائي يشير إلى وجود جليد أسود، والجسور تتجمد أولاً، لذا أبطئ مبكراً واستخدم مدخلات سلسة ولطيفة."},"201":{"q":"إنها ليلة بلا قمر، وأنت على وشك مغادرة محطة شاحنات ضعيفة الإضاءة لرحلة مدتها 4 ساعات على طريق ريفي ذي مسارين. أثناء جولة الفحص، تلاحظ أن عدستي المصباحين الأماميين مغطاتان بطبقة من أوساخ الطريق وبقايا الحشرات الجافة، ما يقلل سطوعهما بشكل ملحوظ. ما الإجراء الأفضل قبل الانطلاق؟","options":["نظّف عدستي المصباحين الأماميين كي يسلطا ضوءهما الكامل ويمكنك الرؤية لمسافة كافية أمامك للتوقف في الوقت المناسب","انطلق الآن واكتفِ بتقليل سرعتك كي يظل ضوؤك المنخفض يغطي الطريق أثناء القيادة","شغّل الضوء العالي طوال الرحلة لتعويض العدسات المتسخة الباهتة","تجاهل تنظيفهما واعتمد على أضواء العلامات والإيضاح لتحديد مسارك"],"explanation":"تقلل عدسات المصابيح الأمامية المتسخة المسافة التي يصلها ضوؤك المنخفض، لذا نظّفها لاستعادة الضوء الكامل والرؤية لمسافة كافية أمامك للتوقف في الوقت المناسب."},"202":{"q":"أنت تقود مقطورة محمَّلة نزولاً على منحدر جبلي طويل وشديد الانحدار. في منتصف الطريق نزولاً، تضغط دواسة الفرامل فتغوص نحو الأرضية دون أي تأثير يُذكر في الإبطاء، وتشمّ رائحة شيء يحترق. وقد بدأت سرعتك تتزايد. ما الإجراء الأفضل لاتخاذه؟","options":["اضغط دواسة الفرامل بقوة وسرعة لإعادة بناء الضغط، ثم استمر في الانسياب بترسك الحالي","انتقل إلى ترس أدنى لتدع كبح المحرك يبطئك، ووجّه نحو منحدر الهروب التالي","انتقل إلى الوضع المحايد لحماية ناقل الحركة ودع الشاحنة تتدحرج حتى يصبح المنحدر مستوياً","انعطف بقوة إلى الكتف الأيسر وضع ثلاثة مثلثات عاكسة على بُعد 10 و100 و200 قدم"],"explanation":"عندما تفقد فرامل الخدمة فعاليتها على منحدر، انتقل إلى ترس أدنى لاستخدام كبح المحرك ووجّه نحو منحدر الهروب لتبطئ بأمان."},"203":{"q":"أنت تقود شاحنة وقاطرة محمَّلة نزولاً على منحدر جبلي طويل وشديد الانحدار. ورغم اختيارك ترساً منخفضاً قبل النزول واستخدامك كبحاً خفيفاً وثابتاً، تشمّ رائحة احتراق خفيفة وبدأت دواسة الفرامل تبدو طرية وإسفنجية. وأمامك على الكتف الأيمن ترى لافتة لمنحدر هروب. في ظل هذه الظروف، ما الفهم الصحيح لمتى ولماذا ينبغي استخدام ذلك المنحدر؟","options":["إنه موقف مخصص يمكنك أن توقف فيه الشاحنة طوال الليل وتترك فراملك الساخنة تبرد قبل متابعة النزول","إنها منطقة استراحة موضوعة على المنحدرات الشديدة كي يتوقف السائقون المتعبون قليلاً ويستعيدوا نشاطهم قبل إكمال النزول الطويل","صُمم لإيقاف مركبة فقدت السيطرة، لذا إذا فقدت فراملك فعاليتها ولم تعد قادراً على التحكم بسرعتك، فينبغي استخدامه لإيقاف الشاحنة بأمان","إنه مسار مخصص يمكنك فيه التحول بأمان إلى ترس أدنى بينما لا تزال المركبة تتحرك نزولاً على المنحدر"],"explanation":"صُمم منحدر الهروب لإيقاف مركبة فقدت السيطرة بسبب فقدان فعالية الفرامل، لذا استخدمه لإيقاف الشاحنة بأمان عندما لا تعود قادراً على التحكم بسرعتك."},"204":{"q":"أنت تقود مركبة مركَّبة محمَّلة بسرعة الطريق السريع على طريق جاف ذي مسارين عندما تصبح عجلة القيادة رخوة فجأة وتتوقف الشاحنة عن الاستجابة الطبيعية لمدخلات التوجيه. حركة المرور خفيفة والكتف أمامك خالٍ. أي إجراء هو أفضل استجابة أولى؟","options":["حافظ على سرعتك الحالية وحاول تحريك العجلة بقوة ذهاباً وإياباً حتى تعود استجابة التوجيه","اترك العجلة تماماً ودع المركبة تستقر في مسارها الخاص بينما تمد يدك نحو جهاز الراديو","استخدم الفرامل برفق وسلاسة لإيقاف المركبة بطريقة متحكَّم بها وآمنة","اضغط بقوة واقفل الفرامل فوراً لإيقاف المركبة في أقصر مسافة ممكنة"],"explanation":"إذا فشل التوجيه فجأة، فإن السرعة هي كل ما يمكنك التحكم به، لذا اكبح برفق وسلاسة لإيقاف المركبة بأمان وبطريقة متحكَّم بها."},"205":{"q":"أنت أول مركبة تصادف حادث تصادم بين سيارتين على طريق ريفي ذي مسارين. أحد السائقين منحنٍ على المقود ويبدو مصاباً، وهناك زجاج مكسور وسوائل منتشرة عبر المسارين. ولا تزال مركبات أخرى تقترب من الاتجاهين. ما أول ما ينبغي أن تفعله بعد إيقاف شاحنتك بأمان؟","options":["احمِ منطقة الحادث وحذّر حركة المرور المقتربة كي لا تقع حوادث إضافية","اسحب السائق المصاب من السيارة وانقله إلى الكتف","التقط صوراً للمشهد لتوثيق الأضرار من أجل التقرير","ابدأ بفحص كل ضحية بحثاً عن الإصابات وقدّم الإسعافات الأولية"],"explanation":"في أي مشهد حادث تكون الأولوية الأولى منع وقوع تصادم ثانٍ، لذا احمِ المنطقة وحذّر حركة المرور المقتربة قبل فعل أي شيء آخر."},"206":{"q":"أنت تنقل مقطورة مغلقة جافة على طريق ريفي ذي مسارين عندما تشمّ دخاناً وترى ألسنة لهب تتراقص قرب منطقة عجلة المحور الخلفي. تحتاج إلى التوقف بسرعة، لكن أمامك عدة أماكن للتوقف. أين أفضل مكان للانعطاف والتوقف للتعامل مع الحريق؟","options":["بعد مدخل نفق الطريق السريع القادم مباشرة، كي يحمي الهيكل الشاحنة من الرياح","في موقف الحصى عند محطة الشاحنات، بالقرب من مضخات الديزل كي تكون طفاية الحريق في متناول اليد","على الكتف العريض لمقطع مفتوح، بعيداً عن المباني والمركبات الأخرى، قرب صندوق اتصال","تحت الجسر العلوي الخرساني التالي، حيث يمنع الظل من ازدياد سخونة الحمولة"],"explanation":"عند حدوث حريق في المركبة، توقف على كتف مفتوح بعيداً عن المباني وحركة المرور والمواد القابلة للاشتعال ولكن قرب صندوق اتصال كي يكون الحريق معزولاً وتبقى المساعدة في متناول اليد."},"207":{"q":"أنت تقود شاحنة وقاطرة محمَّلة على طريق سريع مبلل عندما تتعرَّض سيارة أمامك فجأة وتتوقف بشكل مفاجئ. تكبح بقوة، وضوء تحذير نظام ABS مطفأ (النظام يعمل)، وعليك الانحراف نحو الكتف الخالي لتفادي التصادم. اعتماداً على نظام ABS في هذه الحالة الطارئة، ما الشيء الأكثر دقة الذي سيفعله فعلاً من أجلك؟","options":["سيقلل مسافة توقفك الإجمالية إلى ما دون نحو 419 قدماً التي تحتاجها الشاحنة من سرعة 55 ميلاً في الساعة، فيمكنك التوقف في الوقت المناسب دون انحراف","سيكبح ويوجّه الشاحنة نحو الكتف نيابة عنك بمجرد أن يستشعر العائق أمامك","يضمن بقاء العجلات مقفلة كي تنغرس الإطارات بقوة أكبر في الرصيف المبلل لأقصى تماسك","سيمنع عجلاتك من القفل كي تحافظ على التحكم بالتوجيه وتنحرف نحو الكتف أثناء الكبح بقوة"],"explanation":"يمنع نظام ABS العجلات من القفل أثناء الكبح القوي كي تحتفظ بالتحكم بالتوجيه وتتمكن من الانحراف نحو الكتف أثناء الكبح."},"208":{"q":"أنت تنقل مقطورة محمَّلة نزولاً على طريق سريع مبلل من أربعة مسارات عندما تتعرَّض سيارة أمامك. تضغط الفرامل بقوة، ويتفعَّل نظام ABS لديك، وتبقي الشاحنة تحت السيطرة وتوجّهها حول الخطر. وبعد ذلك، يخبرك سائق أحدث أنه لأن شاحنتك مزودة بنظام ABS، يمكنك الآن اتباع المركبات الأخرى عن قرب أكبر لأن ABS يتيح لك التوقف في مسافة أقصر بكثير. لماذا يُعد هذا الاستنتاج خاطئاً؟","options":["لا يقلل نظام ABS بالضرورة مسافة توقفك؛ فائدته الرئيسية هي منع العجلات من القفل كي تتمكن من التوجيه أثناء الكبح.","يعمل نظام ABS فقط عندما يكون الطريق جافاً، لذا لم يقدّم أي مساعدة كبح على هذا الطريق المبلل.","يقلل نظام ABS مسافة التوقف فقط على محور التوجيه، فيمكن تقليل مسافة الاتباع إلى النصف لكن ليس كلياً.","يطبّق نظام ABS الفرامل نيابة عنك تلقائياً، لذا لم تعد بحاجة إلى ترك أي مسافة اتباع عند سرعة الطريق السريع."],"explanation":"لا يقلل نظام ABS بالضرورة مسافة التوقف؛ مهمته الرئيسية هي منع العجلات من القفل كي تستمر في التوجيه أثناء الكبح بقوة."},"209":{"q":"شاحنتك وقاطرتها غير مزودة بفرامل مانعة للانغلاق (ABS). على طريق ريفي ذي مسارين، تخرج سيارة فجأة من شارع جانبي مباشرة في مسارك وعليك التوقف بأسرع ما يمكن مع إبقاء الشاحنة تحت السيطرة وفي مسارك. أي طريقة كبح تمنحك أقصر توقف آمن دون فقدان التحكم بالتوجيه؟","options":["اضغط دواسة الفرامل حتى الأرضية وثبّتها كي تنقفل العجلات لأقصى قوة كبح","استخدم الكبح المتحكَّم به (تطبيق ضغط ثابت وقوي أقل بقليل من القفل) أو الكبح المتقطع، مع التخفيف إذا انقفلت العجلات","اضغط الفرامل بسرعة وعشوائية طوال الطريق حتى التوقف","استخدم فقط صمام اليد للمقطورة كي تجر المقطورة الشاحنة إلى التوقف"],"explanation":"بدون نظام ABS، امنع انغلاق العجلات باستخدام الكبح المتحكَّم به (ضغط ثابت وقوي أقل بقليل من القفل) أو الكبح المتقطع، مع التخفيف كلما انقفلت العجلات."},"210":{"q":"أنت تسير محمَّلاً في ظهيرة صيف حارة بسرعة نحو 60 ميلاً في الساعة على طريق سريع مقسوم. وفجأة تسمع دوياً عالياً ويتمايل مقدم شاحنتك وينجذب بقوة إلى أحد الجانبين -- لقد انفجر إطار في محور التوجيه. في تلك اللحظة الأولى، قبل أن تفعل أي شيء آخر، أي استجابة تمنحك أفضل فرصة للحفاظ على السيطرة على المركبة؟","options":["اكبح بقوة وحزم فوراً لخفض سرعة الشاحنة إلى سرعة آمنة قبل أن تنجذب أكثر خارج المسار","اضغط دواسة الوقود لإضافة قوة إلى عجلات الدفع وسحب الشاحنة باستقامة، ثم خفّف الضغط بمجرد أن تستقيم","وجّه بحدة بعيداً عن الجانب المنجذب كي تستقيم الشاحنة عائدة نحو منتصف مسارك","أمسك عجلة القيادة بإحكام بكلتا يديك، وابتعد عن الفرامل في البداية، وحافظ على مسارك، ودع المركبة تبطئ من تلقاء نفسها قبل الكبح برفق"],"explanation":"عند انفجار الإطار، أمسك العجلة بإحكام بكلتا يديك، وابتعد عن الفرامل في البداية، وحافظ على مسارك، ودع المركبة تبطئ قبل الكبح برفق."},"211":{"q":"إذا شعرت بالنعاس أثناء القيادة، ينبغي أن:","options":["تفتح نافذة فقط","تتوقف في مكان آمن وتستريح","تشرب القهوة وتواصل القيادة","تكتفي برفع صوت الراديو"],"explanation":"توقف في مكان آمن واسترح؛ فالنوم وحده يعالج النعاس."},"212":{"q":"أثناء فحص ما قبل الرحلة، تُظهر مستندات الشحن أن مقطورتك محمَّلة بعدة آلاف من الأرطال فوق الوزن الإجمالي المقنن للمركبة (GVWR). أنت متأخر والطريق أمامك فيه منحدر طويل وبعض المنعطفات الضيقة. يخبرك زميل أن الوزن الزائد سيساعدك فعلاً على التماسك بالطريق، فلا داعي للقلق. بناءً على كيفية تأثير الحمل الزائد في التحكم بالمركبة، أي عبارة صحيحة؟","options":["يضغط الوزن المضاف الإطارات نحو الأسفل بقوة أكبر، فتصبح مسافة كبحك أقصر فعلاً مما لو سرت محمَّلاً بشكل قانوني.","لأن الحمل فوق المحاور، يخفض الوزن الزائد مركز ثقلك ويقلل أي خطر انقلاب على المنعطفات.","يجعل الوزن الزائد إيقاف الشاحنة أصعب وتوجيهها أصعب، مما يزيد مسافة توقفك وخطر فقدان السيطرة على المنحدر والمنعطفات.","الحمل الزائد يهم فقط من حيث اقتصاد الوقود وتآكل الإطارات؛ وليس له تأثير حقيقي في كيفية توقف الشاحنة أو توجيهها."],"explanation":"يجعل الوزن الزائد إيقاف الشاحنة أصعب وتوجيهها أصعب، مما يزيد مسافة التوقف وخطر فقدان السيطرة على المنحدرات والمنعطفات."},"213":{"q":"أثناء فحص ما قبل الرحلة، تُحمّل مقطورة مسطحة وتلاحظ أن جميع الآلات الثقيلة تقريباً قد تكدست معاً فوق المحور الخلفي، مرتفعة عالياً على كومة منصات نقالة. قبل الانطلاق، ما أفضل طريقة للتعامل مع هذا الحمل كي تسير شاحنتك بأمان؟","options":["اترك الوزن مكدساً في الخلف فوق محور الدفع، لأن الوزن الزائد هناك يمنح إطارات الدفع تماسكاً أكبر","ادفع الحمل بأكمله إلى الأمام كي يستقر كل الوزن فوق محور التوجيه الأمامي لتحكم أفضل بالتوجيه","أبقِه مكدساً عالياً وفي المنتصف، لأن الحمل المرتفع المتوسط من اليسار إلى اليمين متوازن بما يكفي","أعد توزيع الحمولة كي ينتشر الوزن ويتوازن من الأمام إلى الخلف ومن جانب إلى جانب، مع إبقاء مركز الثقل منخفضاً قدر الإمكان"],"explanation":"وزّع وازِن وزن الحمولة من الأمام إلى الخلف ومن جانب إلى جانب، مع إبقاء مركز الثقل منخفضاً قدر الإمكان لتجنب الحمل الزائد على محور أو التسبب في انقلاب."},"214":{"q":"أثناء فحص ما قبل الرحلة، تُحمّل صهريجاً ممتلئاً جزئياً بالإضافة إلى تكديس عدة منصات نقالة فوق السطح المحمَّل، تاركاً أثقل وزن مرتفعاً عالياً. وأنت تخطط لمسارك، أي خطر ينبغي أن يقلقك أكثر بشأن كيفية تعامل هذه الشاحنة الآن؟","options":["يجعل مركز الثقل المرتفع الشاحنة أكثر عرضة بكثير للانقلاب في منعطف أو عند حركة توجيه مفاجئة.","سيجعل الحمل المرتفع الشاحنة تتوقف في مسافة أقصر بكثير بسبب القوة النازلة الإضافية.","سيحسّن الوزن المرتفع اقتصاد وقودك على الطريق السريع المستوي لأن الحمل يسير بسلاسة أكبر.","سيجعل الحمل المرتفع الثقل التوجيه أسهل وأخف بشكل ملحوظ عند سرعة الطريق السريع."],"explanation":"يضع مركز الثقل المرتفع مزيداً من الوزن عالياً، مما يجعل الشاحنة أكثر عرضة بكثير للانقلاب في منعطف أو أثناء حركة توجيه مفاجئة."},"215":{"q":"أثناء فحص ما قبل الرحلة، تفحص شاحنتك المستقيمة المفردة (دون مقطورة) وتجد لوحة شهادة معدنية على إطار باب السائق مختوماً عليها الرقم 33,000 رطل بجوار الأحرف 'GVWR'. يسألك مرسلك ماذا يخبرك هذا الرقم فعلاً عن هذه المركبة. أي عبارة صحيحة؟","options":["إنه الوزن المحمَّل الأقصى المسموح به لهذه الشاحنة مع أي مقطورة تجرها معاً كوحدة واحدة","إنه الوزن المحمَّل الأقصى، المحدد من الشركة المصنّعة، الذي صُنّفت هذه المركبة المفردة لتزنه","إنه الوزن الإجمالي لكل الحمولة وأدوات الربط التي يجوز لك قانونياً وضعها في صندوق الحمولة","إنه الوزن الأقصى الذي يجوز أن يستقر على أي محور فردي من الشاحنة"],"explanation":"الوزن الإجمالي المقنن للمركبة (GVWR) هو الوزن المحمَّل الأقصى، المحدد من الشركة المصنّعة، الذي صُنّفت مركبة مفردة لتزنه."},"216":{"q":"أثناء فحص ما قبل الرحلة، تجد عارضة فولاذية بطول 12 قدماً موضوعة على المقطورة المسطحة ومثبتة بحبلين باليين متآكلين بشدة، دون أي تدعيم ضد اللوح الأمامي. ولا يزال أمامك مسار طويل على الطريق السريع. قبل أن تتمكن قانونياً وبأمان من الانطلاق، ماذا يتطلب هذا الحمل؟","options":["لا حاجة إلى أي شيء آخر -- فالحبلان المنفصلان يستوفيان بالفعل الحد الأدنى وهو رابطان لقطعة يزيد طولها على 5 أقدام، فالعارضة مؤمَّنة","فقط إعادة ربط الحبال الموجودة بإحكام أكبر، لأن اللوح الأمامي في مقدمة المقطورة سيمنع العارضة من الانزلاق إلى الأمام من تلقاء نفسها","ما يكفي من الروابط والتدعيم المناسب -- روابط سليمة ذات حد عمل آمن كافٍ بالإضافة إلى التدعيم/التثبيت -- لتثبيت العارضة فعلاً ضد الانزياح في أي اتجاه","سلسلة واحدة عبر المنتصف تكفي، لأن رابطاً واحداً هو كل ما يلزم لأي قطعة حمولة على مقطورة مسطحة"],"explanation":"تحتاج الحمولة إلى ما يكفي من الروابط السليمة ذات حد العمل الآمن الكافي بالإضافة إلى التدعيم والتثبيت لتثبيت الحمل ضد الانزياح في أي اتجاه."},"217":{"q":"أنت تحمّل لفائف فولاذية وصناديق ثقيلة على مقطورة مسطحة مزودة بلوح أمامي (حامل واقٍ) خلف المقصورة مباشرة. يسألك زميلك لماذا تنفق شركتك أموالاً على هذه الحوامل بينما الروابط المناسبة مستخدَمة بالفعل. أي إجابة تذكر بشكل صحيح الغرض الأساسي الذي يخدمه هذا اللوح الأمامي؟","options":["يمنحك نقطة تثبيت متينة كي يمكن خفض حد العمل الآمن الإجمالي لروابطك إلى أقل من نصف وزن الحمولة","يحجب اضطراب الرياح ورذاذ الطريق عن مقدمة الحمل كي يتحسن اقتصاد وقودك ووضوح رؤية المرآة","يتيح لك قانونياً تخطي إعادة فحص الحمولة داخل المقصورة حتى تقطع أول 150 ميلاً بعد التحميل","يحميك في المقصورة بمنع الحمل من الانزياح إلى الأمام واختراقه نحو مقصورة السائق أثناء التوقف المفاجئ"],"explanation":"يمنع اللوح الأمامي (الحامل الواقي) الحمولة من الانزياح إلى الأمام نحو المقصورة أثناء التوقف المفاجئ، فيحمي السائق من أن يُصدم أو يُسحق."},"218":{"q":"أنت مسؤول عن:","options":["المحرك فقط","حمل آمن وقانوني","الإطارات فقط","الأضواء فقط"],"explanation":"أنت مسؤول عن حمل آمن وقانوني."},"219":{"q":"لقد وزنت شاحنتك المحمَّلة للتو في ميزان على جانب الطريق، ويسلّمك الضابط مطبوعة تسرد عدة أرقام مختلفة: رقم لكل مجموعة عجلات على الأرض، بالإضافة إلى إجمالي مجمّع واحد. يشير الضابط إلى السطر المعنون \"وزن المحور\" ويطلب منك تأكيد فهمك لما يمثله هذا الرقم تحديداً. للإجابة بشكل صحيح، أي مما يلي يجب أن تخبر الضابط أنه يعنيه رقم وزن المحور؟","options":["مقدار الوزن الذي ينقله كل محور فردي إلى الأرض","الوزن الإجمالي المجمّع للمركبة المحمَّلة بأكملها وكل حمولتها","وزن الحمولة وأدوات التثبيت فقط الموجودة على المقطورة","الوزن الأقصى الذي تصنّف الشركة المصنّعة المركبة لحمله بأمان"],"explanation":"وزن المحور هو مقدار الوزن الذي يحمله محور فردي واحد وينقله إلى الأرض، وليس وزن المركبة بأكملها."},"220":{"q":"الساعة 3 فجراً في رحلة ليلية طويلة وتضبط نفسك تنحرف داخل المسار وتتثاءب مراراً. ولا يزال أمامك عدة ساعات من القيادة في خطة رحلتك. أي إجراء سيصحح فعلاً تعبك كي تتمكن من المتابعة بأمان؟","options":["اشرب قهوة سوداء كبيرة وارفع صوت الراديو عالياً لتجاوز الساعات المتبقية","اخرج عند منطقة استراحة آمنة وتوقف عن القيادة للحصول على نوم حقيقي قبل المتابعة","أنزل النافذة الجانبية للحصول على هواء بارد منعش وتناول بعض الحلوى لدفعة من السكر","تابع القيادة لكن زد مسافة اتباعك إلى ثانية واحدة لكل 10 أقدام من طول المركبة لتمنح نفسك مزيداً من وقت رد الفعل"],"explanation":"النوم الحقيقي وحده يعالج التعب، لذا اخرج عند منطقة استراحة آمنة وتوقف عن القيادة لتنام قبل المتابعة."},"221":{"q":"إنه موسم الحساسية، وأثناء جولة فحص ما قبل الرحلة تشعر بقدوم زكام. تتناول قرص دواء للزكام والحساسية يُصرف دون وصفة من حقيبتك قبل الصعود إلى المقصورة لرحلة نهارية طويلة. أي تأثير لهذا الدواء هو السبب الأهم لإعادة النظر في القيادة الآن؟","options":["سيرفع يقظتك، فيمكنك تمديد ساعات قيادتك بأمان","يزيل أي كحول لا يزال في جسمك، مما يخفض نسبة الكحول في دمك قبل الرحلة","قد يسبب لك النعاس ويضعف قيادتك، لذا ينبغي أن تتحقق من الملصق قبل القيادة","يحسّن وقت رد فعلك ويشحذ تركيزك على الطريق"],"explanation":"تسبب العديد من أدوية الزكام والحساسية التي تُصرف دون وصفة النعاس وتضعف القيادة، لذا اقرأ الملصق دائماً ولا تقد إذا حذّر من تشغيل الآلات."},"222":{"q":"أنهيت زجاجتي جعة مع العشاء قبل ساعتين وتشعر بصحوة تامة قبل الصعود إلى شاحنتك وقاطرتها لرحلة ليلية. تقول لنفسك إن قهوة قوية وهواء الليل البارد سيبقيانك متيقظاً. أي عبارة تفسّر بشكل أفضل الخطر الحقيقي الذي تخاطر به بالقيادة في هذه الحالة؟","options":["لا شيء ذو أهمية -- بعد ساعتين وقهوة، لم يعد للكحول أي تأثير ملموس على سائق بحجمك","الشاغل الحقيقي الوحيد هو البقاء دون حد نسبة الكحول في الدم 0.08% الذي ينطبق على رخصتك التجارية أثناء تشغيل الشاحنة","ستسرّع القهوة والهواء البارد من معدل تخلص جسمك من الكحول، فتعود مهاراتك قبل وصولك إلى الطريق السريع","يضعف الكحول حكمك ووقت رد فعلك حتى عندما تشعر أنك بخير، والوقت وحده -- وليس القهوة أو الهواء المنعش -- هو ما يزيله من جسمك"],"explanation":"يضعف الكحول الحكم ووقت رد الفعل حتى عندما تشعر أنك بخير، ومرور الوقت وحده -- وليس القهوة أو الهواء المنعش -- هو ما يزيله من جسمك."},"223":{"q":"ينبغي ألا تقود إذا كنت:","options":["مرتاحاً جيداً ومتيقظاً","مريضاً أو ضعيفاً للغاية بحيث لا تستطيع القيادة بأمان","هادئاً وجاهزاً تماماً","متيقظاً وتشعر بالنشاط"],"explanation":"لا تقد إذا كنت مريضاً أو ضعيفاً للغاية بحيث لا تستطيع القيادة بأمان."},"224":{"q":"أنهيت مناوبة طويلة في الساعة 2 فجراً ونمت نحو أربع ساعات فقط قبل تكليفك التالي. يضغط عليك مرسلك للانطلاق، وتقول لنفسك إنه يمكنك التعويض بالقهوة ونافذة مفتوحة. بناءً على ما يقوله الدليل عن منع التعب، أي عبارة تعكس ما تحتاجه فعلاً كي تكون مرتاحاً حقاً وآمناً للقيادة؟","options":["يحتاج معظم البالغين إلى نحو 7 إلى 8 ساعات من النوم ليكونوا مرتاحين حقاً، والنوم الحقيقي وحده — وليس القهوة أو الهواء المنعش — يستعيد اليقظة.","نحو 4 إلى 5 ساعات من النوم تكفي للسائق المتمرس، لأن القهوة والهواء المنعش يمكن أن يعوضا الباقي.","نحو 2 إلى 3 ساعات من النوم مقبولة طالما تأخذ استراحة كل 150 ميلاً لإعادة فحص يقظتك.","تحتاج إلى 12 إلى 14 ساعة كاملة من النوم قبل أي رحلة تجارية وإلا فأنت غير لائق قانونياً للقيادة."],"explanation":"يحتاج معظم البالغين إلى نحو 7 إلى 8 ساعات من النوم ليكونوا مرتاحين حقاً، والنوم الحقيقي وحده -- وليس القهوة أو الهواء المنعش -- يستعيد اليقظة."},"225":{"q":"كنت تقود لعدة ساعات على امتداد طويل ورتيب من الطريق السريع وبدأت جفونك تثقل. تفتح النافذة للحصول على هواء منعش وتشرب كوباً كبيراً من القهوة لتبقى متيقظاً. أي عبارة عن هذه الأساليب صحيحة؟","options":["الكافيين مع الهواء البارد المنعش يستعيد يقظتك بشكل دائم لبقية نوبة العمل","قد يساعدان لفترة قصيرة، لكن العلاج الحقيقي الوحيد للنعاس هو التوقف والنوم","الهواء المنعش والقهوة خطران وسيزيدان نعاسك سوءاً","يعيدان ضبط ساعات قيادتك بالكامل، فيمكنك المتابعة بأمان دون توقف"],"explanation":"الكافيين والهواء المنعش يخفيان النعاس لفترة قصيرة فقط؛ والعلاج الحقيقي الوحيد هو التوقف عن القيادة والنوم."},"226":{"q":"كنت تسير في المسار الأيمن من طريق سريع مقسوم عندما اندفع سائق خلفك بسرعة، والتصق بمؤخرة مركبتك عن قرب، وأومض بأضوائه العالية، ثم انحرف إلى المسار الأيسر وأشار بغضب وهو يحاول التجاوز. حركة المرور أمامك متوسطة. أي إجراء هو الاستجابة الأفضل والأكثر أماناً؟","options":["زِد سرعتك لتطابق سرعته حتى يكمل التجاوز بسرعة ويتوقف عن الالتصاق بمؤخرتك","حافظ على موقعك في المسار وأبطئ قليلاً فقط، مجبراً إياه على الانتظار ليتعلم ألا يلتصق بمؤخرة المركبات","ارفع قدمك عن دواسة الوقود لإفساح المجال، وتجنب التواصل البصري، ودعه يبتعد عنك جيداً","انتقل إلى اليسار في مساره لتعيق التجاوز حتى يهدأ ويتراجع"],"explanation":"امنح السائق العدواني مساحة واسعة ولا تتفاعل معه -- ارفع قدمك عن دواسة الوقود، وتجنب التواصل البصري، ودعه يبتعد عنك جيداً."},"227":{"q":"كنت تندمج في طريق سريع بين الولايات مزدحم بمقطورتك المحملة عندما قطع سائق سيارة صغيرة الطريق أمامك، مجبراً إياك على الكبح بقوة. ثم، وقد شعر بالإحباط، التصق السائق الآخر بمؤخرتك، وانحرف حولك، وكبح بشدة أمامك، وأطلق إشارات بذيئة. وفقاً للدليل، أي مصطلح يصف سلوك السائق الآخر بشكل أفضل، وما هي أكثر طريقة آمنة للتفكير في سلوكك أنت حتى لا تصبح مذنباً بالأمر نفسه؟","options":["الاندماج العدواني — جزء طبيعي من حركة المرور الكثيفة يجب أن ترد عليه بزيادة السرعة للحفاظ على موقعك وعدم السماح للسيارات بالاستفادة من بطء الشاحنة","القيادة الدفاعية — السائق الآخر يحمي مساحته فحسب، فعليك أن تحاكي سلوكه بالكبح والإعاقة لتعلّم سائقي السيارات الصغيرة احترام المركبات الكبيرة","القيادة المشتتة — من الواضح أن السائق غير منتبه، فالاستجابة الصحيحة هي زيادة السرعة وتجاوزه بسرعة لإبعاد نفسك عن الخطر","غضب الطريق — قيادة غاضبة وعنيفة؛ تتجنب ارتكابه بنفسك بالبقاء هادئاً، وعدم الرد بالمثل، ومنح السائق الغاضب مساحة للابتعاد"],"explanation":"غضب الطريق هو قيادة غاضبة وعنيفة، وتتجنب ارتكابه بالبقاء هادئاً، وعدم الرد بالمثل، ومنح السائق الغاضب مساحة للابتعاد."},"228":{"q":"كنت تقود مركبة مركّبة محملة عبر حركة مرور كثيفة بعد الظهر على طريق سريع بين الولايات في تكساس. يخبرك زميل عمل أن أفضل طريقة لاكتشاف المخاطر الناشئة مبكراً هي تثبيت تركيزك على مصد الشاحنة التي أمامك مباشرة حتى لا تفوتك أضواء كبحها أبداً. أي نهج يمنحك فعلاً أفضل فرصة لاكتشاف المخاطر في الوقت المناسب للتفاعل بأمان؟","options":["أبقِ عينيك متحركتين وامسح المشهد باستمرار — اكنس بعيداً للأمام (من 12 إلى 15 ثانية)، ثم قريباً، وتفقد مراياك كل 5 إلى 8 ثوانٍ","حدّق إلى الأمام مباشرة وثبّت عينيك على المركبة التي أمامك مباشرة حتى تبقى أضواء كبحها واضحة في رؤيتك دائماً","اعتمد بشكل أساسي على مراياك، لأن معظم المفاجآت في حركة المرور الكثيفة تأتي من المركبات التي تتجاوزك من الخلف","راقب قرص المذياع ومقاييس لوحة القيادة بين نظراتك إلى الأمام حتى لا يفوتك تحذير ميكانيكي ناشئ"],"explanation":"أبقِ عينيك متحركتين وامسح المشهد باستمرار -- اكنس بعيداً للأمام من 12 إلى 15 ثانية، ثم عُد إلى المشهد القريب، وتفقد مراياك كل 5 إلى 8 ثوانٍ."},"229":{"q":"كنت تقود عبر منطقة أعمال في وسط المدينة بسرعة 25 ميلاً في الساعة. على طول الرصيف الأيمن ترى صفاً من السيارات المركونة بشكل متوازٍ. وبينما تمسح المشهد أمامك، تلاحظ أن إحدى تلك السيارات المركونة مضاءة أضواء كبحها ويخرج عادم من أنبوب العادم، وتستطيع رؤية ظل سائق في المقعد. لماذا ينبغي أن تعامل هذه السيارة المركونة تحديداً كخطر نشط وتستعد للإبطاء أو تغيير موقعك في المسار؟","options":["أضواء الكبح تعني أن السيارة مثبتة في مكانها، فلا يمكن أن تتحرك، والسيارات التي بلا أضواء أمامها هي وحدها التي تشكل تهديداً","سيارة مأهولة وعاملة قد تخرج فجأة إلى مسارك أو قد يُفتح باب في طريقك، لذا ينبغي أن تضع قدمك على الكبح وتمنحها مساحة إضافية","المحرك العامل يسخّن الإطارات، مما يطيل مسافة توقفك أنت إلى نحو 419 قدماً ويجبرك على التراجع","العادم وأضواء الكبح المضاءة أمر طبيعي لسيارة مركونة ولا يشير إلى شيء، فلا حاجة لتغيير السرعة أو موقع المسار"],"explanation":"السيارة المركونة المأهولة والعاملة قد تخرج فجأة إلى مسارك أو تفتح باباً في طريقك، لذا ضع قدمك على الكبح وامنحها مساحة إضافية."},"230":{"q":"كنت تقود شاحنتك بسرعة 30 ميلاً في الساعة عبر حي سكني في فترة بعد الظهر الدافئة. أمامك على اليمين ترى عدة أطفال يلعبون بكرة قرب الرصيف، وأحدهم ينظر إلى الكرة لا إلى شاحنتك. لماذا يعامل الدليل هذا الموقف كخطر خاص يتطلب منك أن تكون مستعداً للإبطاء أو التوقف فوراً؟","options":["لأنه عند سرعة 30 ميلاً في الساعة تكون مسافة توقفك الكلية نحو 419 قدماً بالفعل، فلا يمكنك التوقف في الوقت المناسب لأي شيء","لأن الأطفال يبقون دائماً على الرصيف ولن يصبحوا خطراً إلا إذا أمرهم شخص بالغ بالعبور","لأن الأطفال قد يتصرفون فجأة وبشكل غير متوقع، مثل الاندفاع إلى الطريق خلف الكرة دون التحقق من حركة المرور","لأن الأطفال يتحركون ببطء شديد بحيث سيبقون في الطريق وقتاً طويلاً بعد أن تتوقع خروجهم منه"],"explanation":"الأطفال خطر خاص لأنهم قد يتصرفون فجأة وبشكل غير متوقع، مثل الاندفاع إلى الطريق خلف كرة دون التحقق من حركة المرور."},"231":{"q":"كنت تنقل مقطورة محملة على طريق سريع مقسوم من أربعة مسارات بسرعة نحو 55 ميلاً في الساعة. قطعت سيارة صغيرة الطريق أمامك فجأة من اليمين، ثم كبحت بقوة لتسلك مخرجاً كادت أن تفوّته. تقلصت مسافة اتباعك وتشعر بموجة من الغضب. أي استجابة هي الأكثر أماناً ودفاعاً؟","options":["حافظ على موقعك قريباً خلف السيارة وأومض بأضوائك العالية حتى يفهم السائق الخطر الذي تسبب فيه","زِد سرعتك لتصل إلى جانب السيارة حتى لا تبقى محاصراً خلف سائق غير متوقع","اضغط على كبحاتك برفق لإرسال تحذير سريع، ثم عُد إلى مسافة اتباعك الأصلية البالغة 4 ثوانٍ","ارفع قدمك عن دواسة الوقود لإعادة بناء مسافة اتباع آمنة، وابقَ هادئاً، وامنح السائق الآخر المساحة التي يحتاجها"],"explanation":"عندما يرتكب سائق آخر خطأ، ارفع قدمك عن دواسة الوقود لإعادة بناء مسافة اتباع آمنة، وابقَ هادئاً، وامنحه المساحة التي يحتاجها."},"232":{"q":"يجب ألا تبدّل التروس أبداً أثناء:","options":["السير على طريق مستوٍ","عبور سكك الحديد","السير مباشرة إلى الأمام","ركن الشاحنة"],"explanation":"لا تبدّل التروس أثناء عبور سكك الحديد."},"233":{"q":"كنت تقترب من تقاطع غير مألوف ليلاً عندما تلاحظ أن إشارة المرور المعلقة في الأعلى تومض باللون الأحمر في كل الاتجاهات. لا يوجد ضابط شرطة، وحركة المرور من الشارع المتقاطع خفيفة. للتعامل مع هذا التقاطع بشكل صحيح وقانوني، ماذا ينبغي أن تفعل؟","options":["توقّف توقفاً تاماً، ثم تابع عبر التقاطع فقط عندما يكون ذلك آمناً، تماماً كما تفعل عند إشارة قف","أبطئ، وامسح كلا الاتجاهين، واعبر بحذر دون التوقف توقفاً تاماً","عامل الإشارة المعطلة كإشارة إفساح طريق واندمج عبرها كلما ظهرت فجوة، مع الحفاظ على زخمك","حافظ على سرعتك عبر التقاطع لأن الإشارة الوامضة تعني أن الضوء معطل والقواعد لا تنطبق"],"explanation":"الإشارة الحمراء الوامضة تعني نفس معنى إشارة قف: توقّف توقفاً تاماً وتابع فقط عندما يكون ذلك آمناً."},"234":{"q":"كنت تقترب من تقاطع في وقت متأخر من الليل في مركبتك المركّبة المحملة. الإشارة التي كانت خضراء ثابتة خلال النهار تظهر الآن باللون الأصفر الوامض. لا توجد حركة مرور أخرى ظاهرة عند الشارع المتقاطع. أي مما يلي هو الطريقة الصحيحة للتعامل مع هذه الإشارة؟","options":["عاملها تماماً كالأحمر الوامض: توقّف توقفاً تاماً، ثم تابع عندما يخلو الطريق","أبطئ، وابقَ متيقظاً، واعبر التقاطع بحذر بعد التحقق من حركة المرور المتقاطعة","حافظ على سرعتك على الطريق السريع لأن الإشارة الصفراء تمنحك حق الأولوية على الشارع المتقاطع","توقّف توقفاً تاماً عند الخط وانتظر حتى تتحول الإشارة إلى أخضر ثابت قبل التحرك"],"explanation":"الإشارة الصفراء الوامضة تحذير، لذا أبطئ، وابقَ متيقظاً، واعبر التقاطع بحذر بعد التحقق من حركة المرور المتقاطعة."},"235":{"q":"كنت تقترب من تقاطع ريفي بمركبتك المركّبة المحملة. لا توجد إشارات قف أو إشارات إفساح طريق أو إشارات مرور تواجه أي اتجاه، والأدغال تحجب رؤيتك جزئياً إلى اليمين. تقترب شاحنة صغيرة (بيك أب) من المعبر من جهة يمينك في الوقت نفسه تقريباً. ما هو الإجراء الأكثر أماناً وصحة الذي ينبغي أن تتخذه؟","options":["حافظ على سرعتك وتابع أولاً، لأن المركبة التجارية المحملة لها حق الأولوية القانوني على المركبات الأصغر","توقّف توقفاً تاماً في وسط التقاطع وانتظر حتى تعبر الشاحنة الصغيرة قبل التحرك","أبطئ عند اقترابك، وضع قدمك على الكبح، وكن مستعداً لإفساح الطريق للشاحنة الصغيرة حسب الحاجة قبل المتابعة","أطلق بوقك وتابع العبور بالسرعة نفسها حتى يعرف السائق الآخر أنك تنوي العبور أولاً"],"explanation":"عند تقاطع غير منظَّم لا تتمتع أي مركبة بحق الأولوية التلقائي، لذا أبطئ، وضع قدمك على الكبح، وكن مستعداً لإفساح الطريق قبل المتابعة."},"236":{"q":"عندما ترى حافلة مدرسية متوقفة بأضواء حمراء وامضة، يجب عليك أن:","options":["تتجاوزها بسرعة","تتوقف","تطلق البوق بصوت عالٍ","تزيد السرعة"],"explanation":"توقّف للحافلة ذات الأضواء الحمراء الوامضة."},"237":{"q":"كنت تنقل حمولة ثقيلة وتقترب من قمة منحدر جبلي طويل وحاد. المنحدر يمتد عدة أميال، والرصيف جاف، وتريد منع كبحات خدمتك من الضعف أثناء النزول. وفقاً لإجراء القيادة الجبلية الآمن، أي إجراء يمنحك أكثر سيطرة موثوقة على سرعتك أثناء النزول؟","options":["ابقَ في ترسك العادي على الطريق السريع واضغط على كبحات الخدمة برفق طوال الطريق نزولاً للحفاظ على سرعة ثابتة","انتظر حتى تشعر بالشاحنة تتسارع في منتصف الطريق نزولاً، ثم انتقل إلى ترس أدنى لإبطاء المركبة من جديد","أبقِ ناقل الحركة في ترس عالٍ ليرتاح المحرك، واعتمد بشكل أساسي على ضغطات كبح متكررة وقوية للتحكم في السرعة","اختر ترساً منخفضاً قبل أن تبدأ النزول حتى يقوم كبح المحرك والتروس بمعظم العمل، مستخدماً كبحات الخدمة فقط كمكمل خفيف وثابت"],"explanation":"اختر ترساً منخفضاً قبل بدء النزول على منحدر طويل حتى يقوم كبح المحرك والتروس بمعظم العمل، مستخدماً كبحات الخدمة فقط كمكمل خفيف وثابت."},"238":{"q":"كنت تنقل مقطورة محملة بالكامل عبر تضاريس جبلية عندما يحذرك نظام تحديد المواقع من وجود منحدر هروب طارئ أمامك. يسألك سائق أحدث يركب معك عن سبب بناء إدارة الطرق السريعة منحدراً طويلاً مملوءاً بالحصى في هذا الموقع بالذات بدلاً من مكان آخر على طول الطريق. بناءً على الطريقة التي يُقصد بها استخدام هذه المنحدرات، أي موقع يُرجَّح أن تضع فيه الإدارة واحداً؟","options":["في منتصف منحدر طويل وحاد حيث تكون المركبات الثقيلة في أكبر خطر لفقدان كبحاتها بسبب الضعف","على امتداد مستوٍ ومفتوح من الطريق السريع حيث تصل الشاحنات عادة إلى أعلى سرعات سيرها","قبل تقاطع مزدحم في وسط المدينة مباشرة حيث تفرض حركة المرور المدنية توقفات متكررة وحادة","عند مدخل موقف كبير لمنطقة استراحة حيث تركن العديد من الشاحنات طوال الليل"],"explanation":"تُوضع منحدرات هروب الشاحنات في منتصف المنحدرات الطويلة والحادة حيث تكون المركبات الثقيلة الأكثر عرضة لفقدان كبحاتها بسبب الضعف الناجم عن فرط السخونة."},"239":{"q":"إنه وقت متأخر بعد حلول الظلام على طريق ريفي ذي مسارين وأنت تسير على الأضواء المنخفضة، التي تضيء الطريق نحو 250 قدماً أمامك. هناك منعطف حاد قادم ولا تستطيع رؤية ما يقع على الطريق خلفه. أي إجراء يتناسب أكثر مع القاعدة التي تقضي بألا تتجاوز مدى أضواء مصابيحك الأمامية أبداً؟","options":["انتقل إلى الأضواء العالية عبر المنعطف لترى أبعد حول المنحنى، ثم عُد إلى الأضواء المنخفضة بمجرد أن تصبح مستقيماً مرة أخرى","قلّل سرعتك قبل دخول المنعطف حتى تتمكن من التوقف ضمن المسافة التي تضيئها مصابيحك الأمامية فعلاً","حافظ على سرعتك الحالية لكن اتبع المركبة التي أمامك عن قرب أكثر حتى ترشدك أضواؤها الخلفية عبر المنعطف","حافظ على سرعة الطريق السريع لأنه عند 55 ميلاً في الساعة لا تزال مصابيحك الأمامية تغطي مسافة التوقف الكاملة البالغة 419 قدماً التي تحتاجها"],"explanation":"لا تتجاوز مدى مصابيحك الأمامية أبداً: أبطئ قبل المنعطف حتى تتمكن من التوقف ضمن المسافة التي تضيئها مصابيحك الأمامية فعلاً."},"240":{"q":"لقد انتهيت من المشي حول مقطورتك أثناء فحص ما قبل الرحلة وكل شيء يبدو سليماً بصرياً. قبل أن تنطلق إلى الطريق وتندمج في حركة المرور، ما هي الطريقة الصحيحة للتأكد من أن كبحات خدمتك تعمل فعلاً؟","options":["تخطَّ اختبار العمل لأن فحص المشي حولها أكد بالفعل أن مكونات الكبح تبدو سليمة، وأعد الفحص فقط بعد أول 50 ميلاً","انتظر حتى تصل إلى سرعة الطريق السريع، ثم اضغط على الكبحات بقوة لتشعر بما إذا كانت الشاحنة تنجذب بشكل متساوٍ إلى جانب واحد","ابدأ التحرك بسرعة منخفضة واضغط على الكبحات برفق للتأكد من أن المركبة تتوقف ولا تنجذب إلى جانب واحد","اضغط على دواسة الكبح عدة مرات أثناء الركن وراقب انخفاض مقياس ضغط الهواء، مما يثبت أن الكبحات ستوقفك"],"explanation":"بعد فحص المشي حول المركبة، اختبر كبحات الخدمة بالتحرك ببطء والكبح برفق للتأكد من أن المركبة تتوقف ولا تنجذب إلى جانب واحد."},"241":{"q":"كنت تنقل مقطورة محملة على طريق ريفي ذي مسارين بسرعة 50 ميلاً في الساعة عندما دفعت هبّة قوية من الرياح الجانبية مقدمة جرّارك فجأة نحو الكتف. للحفاظ على أفضل سيطرة على المركبة أثناء تصحيح توجيهك، ما هو الوضع الأكثر أماناً لليدين على عجلة القيادة؟","options":["أبقِ يداً واحدة في الأسفل عند أسفل العجلة حتى تتمكن من إجراء دوران سريع وواسع ضد الرياح","وجّه بيد واحدة وأبقِ اليد الأخرى جاهزة على صمام كبح المقطورة اليدوي لإبطاء المقطورة","دع العجلة تنزلق بحرية خلال يديك للحظة حتى تتمركز ذاتياً بعد مرور الهبّة","أبقِ كلتا اليدين بثبات على العجلة، على جانبين متقابلين، حتى تتمكن من التفاعل بسلاسة والحفاظ على سيطرة ثابتة"],"explanation":"أبقِ كلتا اليدين بثبات على العجلة على جانبين متقابلين حتى تتمكن من التفاعل بسلاسة والحفاظ على سيطرة ثابتة أثناء هبّة الرياح الجانبية المفاجئة."},"242":{"q":"أنت وحدك في محطة شاحنات مزدحمة والطريقة الوحيدة للخروج من مكانك تتطلب منك الرجوع للخلف. لديك خيار: يمكنك تهيئة اقترابك للرجوع نحو جانبك الأيسر (جانب السائق)، أو الرجوع نحو جانبك الأيمن (الأعمى)، وهو ما سيكون مناورة أقصر قليلاً. أي نهج هو الأكثر أماناً ولماذا؟","options":["ارجع نحو جانب السائق (الأيسر)، لأنك تستطيع النظر من نافذتك ومراقبة مؤخرة مقطورتك مباشرة طوال الوقت.","ارجع نحو الجانب الأعمى (الأيمن)، لأنه المسار الأقصر ومراياك تمنحك تغطية كاملة لذلك الجانب.","كلا الجانبين آمنان بالتساوي طالما أنك تطلق بوقك مرتين قبل التحرك وتشغّل أضواء التحذير الرباعية.","ارجع بشكل مستقيم فقط ولا تميل المقطورة أبداً، لأن أي رجوع جانبي محظور في محطة الشاحنات."],"explanation":"ارجع دائماً نحو جانب السائق (الأيسر) لأنك تستطيع النظر من نافذتك ومراقبة مؤخرة المقطورة مباشرة بدلاً من الاعتماد على المرايا فقط."},"243":{"q":"كنت تقود جرّاراً ومقطورة محملين على طريق سريع بين الولايات جاف ومستوٍ بسرعة 55 ميلاً في الساعة عندما قررت تجاوز شاحنة أخرى. وللقيام بذلك بأمان تتسارع إلى 65 ميلاً في الساعة. مقارنة بتوقفك عند 55 ميلاً في الساعة، ما هو التأثير الأهم لتغيير السرعة هذا على قدرتك على التوقف في حالة طارئة؟","options":["تبقى مسافة التوقف كما هي تقريباً لأن الطريق جاف وكبحاتك جيدة","تزداد مسافة التوقف بشكل حاد، لأن مسافة الكبح تنمو مع مربع السرعة تقريباً","تنخفض مسافة التوقف قليلاً لأن العجلات الأسرع حركة تتشبث بالطريق بشكل أفضل","لا تتأثر مسافة التوقف بالسرعة وتعتمد فقط على وزن حمولتك"],"explanation":"تزداد مسافة التوقف بشكل حاد مع زيادة السرعة لأن مسافة الكبح تنمو مع مربع السرعة تقريباً."},"244":{"q":"كنت تقود جرّاراً ومقطورة محملين صعوداً على منحدر دخول إلى طريق سريع بين الولايات مزدحم. مسار التسارع قصير نسبياً، وحركة المرور في المسار الأيمن تتحرك بثبات بسرعة نحو 60 ميلاً في الساعة، وتنفتح فجوة ضيقة أمامك مباشرة. لإكمال الاندماج بأكبر قدر ممكن من الأمان، ماذا ينبغي أن تفعل؟","options":["توقّف عند نهاية المنحدر وانتظر حتى تخلو حركة المرور بالكامل قبل الانطلاق","ادخل المسار بسرعة بطيئة وحذرة ودع حركة المرور الأسرع تتكيف حولك","استخدم مسار التسارع للوصول إلى سرعة تدفق حركة المرور، ثم انتقل إلى الفجوة المفتوحة","حافظ على موقعك في المسار وافرض حق أولويتك حتى تفسح لك المركبات في المسار العابر الطريق"],"explanation":"مسار التسارع موجود لمطابقة سرعة حركة المرور على الطريق السريع حتى تتمكن من الاندماج بسلاسة في فجوة مفتوحة دون إجبار الآخرين على الكبح أو الانحراف."},"245":{"q":"كنت تقود جرّاراً ومقطورة محملين في حركة مرور مدنية كثيفة متقطعة. خطا أحد المشاة المشتتين بهاتفه عن الرصيف وبدأ يمشي إلى مسارك على مسافة قصيرة أمامك. لقد رفعت قدمك بالفعل عن دواسة الوقود ووضعتها على الكبح. أي استخدام لبوقك في هذه اللحظة هو الذي تعتبره إدارة السلامة العامة (DPS) مناسباً؟","options":["اضغط على البوق برفق وبشكل متكرر لإبقاء السائقين القريبين متيقظين، لأن الإشارة المستمرة في الازدحام تمنع الاصطدامات","تجنب البوق تماماً واعتمد على الكبح فقط، لأن إطلاق البوق قرب أحد المشاة غير مسموح به أبداً في حركة المرور المدنية","أطلق بوقاً طويلاً وودياً لتُعلم المشاة والسائقين المحيطين بأن شاحنة كبيرة تقترب من التقاطع","أطلق البوق لتحذير المشاة من الخطر الفوري، مستخدماً إياه فقط لتنبيه الآخرين إلى الخطر"],"explanation":"البوق جهاز تحذير يُقصد به فقط تنبيه الآخرين إلى خطر حقيقي وفوري، مثل مشاة مشتت يدخل في طريقك."},"246":{"q":"إنها أقل بقليل من درجة التجمد ويجب أن تركن جرّارك ومقطورتك على الكتف الأيمن لطريق ينحدر بشدة هبوطاً. لقد ضبطت كبحات الركن، لكنك تعلم أنه على هذا المنحدر الجليدي قد لا تمسك الكبحات وحدها بالمركبة إذا بدأت تزحف. لاستخدام الرصيف كحاجز نهائي في حال تدحرجت المركبة، في أي اتجاه ينبغي أن تدير عجلاتك الأمامية؟","options":["أدِر العجلات الأمامية نحو الرصيف (يميناً)، حتى يضغط أي تدحرج للأمام إطاراً أمامياً على الرصيف","أدِر العجلات الأمامية بعيداً عن الرصيف (يساراً، نحو الطريق)، حتى تنحرف المركبة عن الرصيف إذا تدحرجت","اترك العجلات الأمامية موجهة مباشرة إلى الأمام، لأن كبحات الركن وأسافين العجلات تقوم بكل الإمساك","الاتجاه لا يهم على منحدر هبوطي طالما أن كبحات الركن مضبوطة"],"explanation":"عند الركن مواجهاً للهبوط، أدِر العجلات الأمامية نحو الرصيف حتى يضغط أي تدحرج للأمام إطاراً عليه ويوقف المركبة."},"247":{"q":"كنت تقود جرّاراً ومقطورة محملين على طريق ريفي ذي مسارين بسرعة 50 ميلاً في الساعة عندما نظرت للأسفل لتفقد مرآة. وعندما رفعت بصرك، كانت عجلاتك الجانبية اليمنى قد انحرفت عن الرصيف إلى كتف من الحصى الناعم، وجرّارك ينجذب قليلاً إلى اليمين. لا يوجد عائق مباشر أمامك. ما هي أفضل طريقة للعودة إلى الطريق؟","options":["وجّه عائداً إلى الرصيف فوراً بدوران سريع وحازم للعجلة لتصحيح مسارك قبل أن تفقد المزيد من الأرض","ارفع قدمك عن دواسة الوقود، وحافظ على قبضة محكمة، ووجّه عائداً إلى الرصيف تدريجياً بمجرد أن تبطئ الشاحنة وتصبح تحت السيطرة","اضغط على الكبحات بقوة فوراً لتقليل السرعة قبل أن يغادر أي جزء من المركبة الكتف","اضغط على دواسة الوقود لتدفع المركبة عبر الحصى الناعم وتعيدها صعوداً إلى الرصيف الأكثر صلابة"],"explanation":"إذا انحرفت عجلاتك إلى الكتف، ارفع قدمك عن دواسة الوقود دون كبح بقوة ووجّه عائداً إلى الرصيف تدريجياً بعد أن تبطئ الشاحنة."},"248":{"q":"كنت تقود جرّاراً ومقطورة محملين في المسار الأيمن من طريق ذي مسارين بالسرعة المقررة 55 ميلاً في الساعة. منذ عدة دقائق وشاحنة صغيرة تلتصق بمؤخرتك عن قرب شديد بحيث لم تعد تستطيع رؤية مصابيحها الأمامية في مراياك، ولا توجد مركبة أمامك. حركة المرور في المسار الأيسر خفيفة. ما هي أكثر طريقة آمنة للتعامل مع هذا الملتصق بالمؤخرة؟","options":["اضغط على كبحاتك برفق عدة مرات لإيماض أضواء كبحك وتحذير السائق بالتراجع","حافظ على سرعتك لكن قلّل مسافة اتباعك للمركبات التي أمامك حتى يحصل الملتصق على مساحة","افتح مساحة إضافية أمامك، ثم انتقل جانباً ودع الملتصق يتجاوز عندما يكون ذلك آمناً","زِد سرعتك تدريجياً إلى ما فوق 55 ميلاً في الساعة بكثير حتى لا يعود الملتصق يلازم مؤخرتك"],"explanation":"عند وجود ملتصق بمؤخرتك، افتح مساحة إضافية أمامك ثم انتقل جانباً لتدعه يتجاوز بأمان."},"249":{"q":"كنت تقود جرّاراً ومقطورة محملين على طريق متعدد المسارات وتحتاج إلى الانتقال إلى المسار الأيمن قبل مخرجك، الذي يبعد نحو ميل واحد. حركة المرور متوسطة وتجلس سيارة في مكان ما خلفك في نقطتك العمياء الجانبية اليمنى. وفقاً لإرشادات إدارة السلامة العامة (DPS) حول التواصل مع السائقين الآخرين، ما هي الطريقة الأفضل الوحيدة لإعلام السائقين من حولك بما تنوي فعله؟","options":["اضغط على كبحاتك عدة مرات حتى ترى السيارة التي خلفك أضواء كبحك وتفهم أنك على وشك الإبطاء والاندماج","أومض بأضوائك العالية لحركة المرور في المسار الأيمن لتنبههم إلى أنك تنتقل جانباً","زِد سرعتك ونفّذ تغيير المسار بسرعة حتى تقضي أقل وقت ممكن بجانب السيارة في نقطتك العمياء","شغّل إشارة انعطافك اليمنى مبكراً واتركها مضاءة، معلناً نيتك تغيير المسار بوضوح وقبل وقت كافٍ"],"explanation":"تواصل عن نواياك بوضوح بتشغيل إشارتك مبكراً وقبل وقت كافٍ حتى يكون لدى السائقين الآخرين وقت للتفاعل."},"250":{"q":"أنت تقود شاحنة مستقيمة طولها 30 قدماً على طريق سريع جاف، وتسير بثبات بسرعة 50 mph في حركة مرور خفيفة. سيارة صغيرة أمامك تواصل تغيير المسارات، لذا قررت ترك فجوة آمنة للسير خلفها. باستخدام القاعدة المعيارية لمسافة المتابعة، ما هو أقل مقدار من مسافة المتابعة يجب أن تحافظ عليه خلف تلك المركبة؟","options":["4 ثوانٍ","3 ثوانٍ","5 ثوانٍ","6 ثوانٍ"],"explanation":"اترك ثانية واحدة من مسافة المتابعة لكل 10 أقدام من الطول، ثم أضف ثانية واحدة عند تجاوز 40 mph: شاحنة طولها 30 قدماً بسرعة 50 mph تحتاج إلى 3 + 1 = 4 ثوانٍ."},"251":{"q":"أنت تقود شاحنة مستقيمة طولها 40 قدماً عبر المدينة، ويُظهر عداد السرعة ثباتاً عند 35 mph على رصيف جاف. حركة المرور خفيفة، لكنك تريد ترك فجوة آمنة خلف السيارة التي أمامك حتى تتمكن من التفاعل إذا فرملت فجأة. باستخدام قاعدة مسافة المتابعة الموصى بها لطول مركبتك وسرعتك الحالية، ما هي أقل مسافة متابعة يجب أن تحافظ عليها؟","options":["5 ثوانٍ، لأن مركبة طولها 40 قدماً تحتاج تلقائياً إلى ثانية إضافية فوق الرقم الأساسي","4 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من الطول ولا تضيف شيئاً إضافياً تحت 40 mph","3 ثوانٍ، لأن ثلاث ثوانٍ هي الحد الأدنى المعياري للفجوة لأي مركبة تجارية","6 ثوانٍ، لأنه عند هذا الطول يجب عليك دائماً مضاعفة عدّ كل 10 أقدام من أجل السلامة"],"explanation":"اترك ثانية واحدة من مسافة المتابعة لكل 10 أقدام من الطول ولا تضف شيئاً تحت 40 mph، لذا تحتاج شاحنة طولها 40 قدماً بسرعة 35 mph إلى 4 ثوانٍ."},"252":{"q":"أنت تقود مجموعة مقطورة مسطحة يبلغ طولها 50 قدماً من المصد إلى المصد. ازدادت حركة المرور على الطريق السريع وعداد السرعة لديك يثبت عند 55 mph في ظروف جافة وصافية. عندما تستقر خلف المركبة التي أمامك، ما هي أقل مسافة متابعة يجب أن تحافظ عليها، محسوبة بالثواني، للبقاء ضمن الفجوة الآمنة التي يوصي بها الدليل؟","options":["5 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من طول المركبة","7 ثوانٍ، بإضافة ثانيتين إضافيتين لأن سرعتك تتجاوز 40 mph بكثير","6 ثوانٍ، لأن 50 قدماً تمنحك 5 ثوانٍ وتضيف ثانية واحدة لكونك فوق 40 mph","4 ثوانٍ، لأن السرعة الثابتة على الطريق السريع في طقس جاف تتيح لك تقليص الفجوة"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، ثم أضف ثانية واحدة فوق 40 mph: مركبة طولها 50 قدماً بسرعة 55 mph تحتاج إلى 5 + 1 = 6 ثوانٍ."},"253":{"q":"أنت تقود شاحنة مقطورة طولها 60 قدماً على طريق سريع جاف ومستوٍ في ظروف نهارية جيدة، وتحافظ على سرعة ثابتة قدرها 45 mph. حركة المرور خفيفة، لكنك تريد ترك فجوة آمنة للسير خلف السيارة التي أمامك. أي مما يلي يذكر بشكل صحيح أقل مسافة متابعة يجب أن تحافظ عليها، بالثواني؟","options":["6 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من طول المركبة","5 ثوانٍ، لأن المركبة المركبة الطويلة تحتاج فقط إلى نحو نصف ثانية لكل 10 أقدام","8 ثوانٍ، بإضافة ثانيتين إضافيتين لأنك فوق 40 mph","7 ثوانٍ، لأنك تترك 6 ثوانٍ للطول بالإضافة إلى ثانية أخرى لكونك فوق 40 mph"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول، ثم أضف ثانية واحدة فوق 40 mph: مركبة طولها 60 قدماً بسرعة 45 mph تحتاج إلى 6 + 1 = 7 ثوانٍ."},"254":{"q":"أنت تقود مجموعة مركبة طولها 70 قدماً على شارع رئيسي مستوٍ في المدينة، وتحافظ على سرعة ثابتة قدرها 35 mph في ظروف صافية وجافة. حركة المرور أمامك تتحرك بسلاسة وتريد ترك فجوة آمنة للسير. باستخدام معادلة تقدير مسافة المتابعة، فإن الحد الأدنى من الوسادة التي يجب أن تحافظ عليها خلف المركبة التي أمامك هو:","options":["7 ثوانٍ","8 ثوانٍ","6 ثوانٍ","9 ثوانٍ"],"explanation":"اترك ثانية واحدة من مسافة المتابعة لكل 10 أقدام من طول المركبة، وتحت 40 mph لا تُضاف ثانية إضافية، لذا تحتاج شاحنة طولها 70 قدماً إلى 7 ثوانٍ."},"255":{"q":"أنت تنقل حمولة على طريق سريع جاف ويُظهر عداد السرعة ثباتاً عند 45 mph. بإلقاء نظرة على مراياك، تقدّر أن مجموعة شاحنتك ومقطورتك تمتد لمسافة 80 قدماً كاملة من المصد الأمامي إلى مؤخرة المقطورة. حركة المرور تتحرك بسلاسة وتريد ترك فجوة آمنة خلف السيارة التي أمامك. باستخدام قاعدة مسافة المتابعة الموصى بها، كم ثانية من المساحة يجب أن تحافظ عليها؟","options":["8 ثوانٍ، لأن القاعدة هي ببساطة ثانية واحدة لكل 10 أقدام من طول المركبة","9 ثوانٍ، لأن 80 قدماً تعطي 8 ثوانٍ وتضيف ثانية واحدة للسير فوق 40 mph","7 ثوانٍ، لأنه عند هذه السرعة يمكنك حذف ثانية من العدّ المبني على الطول","10 ثوانٍ، لأنه يجب عليك تقريب الطول للأعلى وإضافة ثانيتين كاملتين من الوسادة عند سرعة الطريق السريع"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 8 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 9 ثوانٍ."},"256":{"q":"أنت تقود مجموعة مركبة طولها 90 قدماً على طريق سريع جاف، وتسير بسرعة ثابتة قدرها 50 mph في حركة مرور خفيفة. سيارة صغيرة تندمج أمامك وتحتاج إلى إعادة تأسيس فجوة آمنة. باستخدام قاعدة مسافة المتابعة، ما هو أقل مقدار من المساحة يجب أن تحافظ عليه خلف تلك المركبة؟","options":["9 ثوانٍ، لأن القاعدة هي ببساطة ثانية واحدة لكل 10 أقدام من طول المركبة","8 ثوانٍ، لأنه يمكنك حذف بعض الوقت بمجرد أن تسير بثبات على رصيف جاف","10 ثوانٍ من مسافة المتابعة","11 ثانية، بإضافة ثانيتين إضافيتين لأنك فوق 40 mph بكثير"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 9 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 10 ثوانٍ."},"257":{"q":"أنت تقود مجموعة مقطورة مسطحة يبلغ طولها 100 قدم من المصد الأمامي إلى نهاية مقطورتك. تنفتح حركة المرور وتتسارع إلى 60 mph على طريق سريع جاف. بإلقاء نظرة في مرآتك، تريد ترك مسافة متابعة آمنة خلف السيارة التي تتبعها. بناءً على قاعدة مسافة المتابعة، ما هو الحد الأدنى لعدد الثواني من المساحة التي يجب أن تحافظ عليها؟","options":["10 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من طول المركبة و100 مقسوماً على 10 يساوي 10","12 ثانية، بترك ثانية واحدة لكل 10 أقدام بالإضافة إلى ثانيتين إضافيتين للسرعة الأعلى","9 ثوانٍ، لأن 60 mph سريعة بما يكفي لطرح ثانية من العدّ المبني على الطول","11 ثانية، لأن 100 قدم تعطي 10 ثوانٍ وتضيف ثانية أخرى للسير فوق 40 mph"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 10 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 11 ثانية."},"258":{"q":"أنت تقود شاحنة مستقيمة طولها 40 قدماً على طريق سريع جاف، وتحافظ على سرعة ثابتة قدرها 55 mph في ظروف نهارية جيدة. حركة المرور أمامك تتحرك بحرية. بتطبيق قاعدة الدليل لمسافة المتابعة الآمنة، ما هو الحد الأدنى للفجوة التي يجب أن تحافظ عليها خلف المركبة التي أمامك؟","options":["5 ثوانٍ","4 ثوانٍ","6 ثوانٍ","3 ثوانٍ"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 4 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 5 ثوانٍ."},"259":{"q":"أنت تقود مقطورة مسطحة، وأثناء جولة الفحص قبل الرحلة، تقيس شاحنتك ومقطورتك فتجدها 50 قدماً من المصد إلى المصد. على طريق ريفي جاف يستقر عداد السرعة لديك بثبات عند 50 mph في حركة مرور خفيفة. باستخدام قاعدة تقدير مسافة المتابعة الآمنة خلف المركبة التي أمامك، كم ثانية من المساحة يجب أن تحافظ عليها عند هذه السرعة وهذا الطول؟","options":["5 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من طول المركبة","6 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من الطول وتضيف ثانية أخرى لكونك فوق 40 mph","7 ثوانٍ، لأنك تترك ثانية واحدة لكل 10 أقدام من الطول وتضيف ثانيتين أخريين لسرعة الطريق السريع","4 ثوانٍ، لأن مسافة المتابعة تعتمد على السرعة وحدها وليس على طول المركبة"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 5 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 6 ثوانٍ."},"260":{"q":"أنت تقود شاحنة مقطورة طولها 70 قدماً على طريق سريع جاف ومستوٍ، وتحافظ على سرعة ثابتة قدرها 45 mph في حركة مرور خفيفة. بإلقاء نظرة على مراياك، تقرر تحديد فجوة المتابعة بعدّ الثواني التي تستغرقها للوصول إلى جسم ثابت بعد أن تمر به المركبة التي أمامك. بناءً على طول مركبتك وسرعتك الحالية، ما هو الحد الأدنى لمسافة المتابعة التي يجب أن تحافظ عليها؟","options":["7 ثوانٍ، لأن القاعدة هي ببساطة ثانية واحدة لكل 10 أقدام من طول المركبة","6 ثوانٍ، لأن نحو 6 ثوانٍ من مسافة التوقف الإجمالية تكفي عند سرعة الطريق السريع","8 ثوانٍ، لأنك تحتاج إلى ثانية واحدة لكل 10 أقدام من الطول وثانية إضافية لكونك فوق 40 mph","9 ثوانٍ، بإضافة ثانية للرصيف الجاف فوق ثواني الطول والسرعة"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لأساس قدره 7 ثوانٍ، ثم أضف ثانية واحدة للسرعات فوق 40 mph، ليصبح المجموع 8 ثوانٍ."},"261":{"q":"أنت تقود مجموعة مقطورة مسطحة يبلغ طولها 80 قدماً من المصد الأمامي إلى مؤخرة المقطورة. حركة المرور تتدفق بسلاسة على طريق مستوٍ من حارتين وعداد السرعة لديك ثابت عند 35 mph. للحفاظ على مسافة متابعة آمنة خلف الشاحنة التي أمامك، أي فجوة يجب أن تحافظ عليها؟","options":["9 ثوانٍ، لأنك تأخذ 8 ثوانٍ للطول وتضيف ثانية أخرى لسرعة الطريق السريع","7 ثوانٍ، لأنه عند السرعات الأبطأ يمكن تقليص الوسادة بثانية واحدة","10 ثوانٍ، وهي أقصى وسادة قد تحتاجها أي مجموعة كبيرة على الإطلاق","8 ثوانٍ، لأن كل 10 أقدام من الطول تحتاج إلى ثانية واحدة ولا تُضاف ثانية إضافية تحت 40 mph"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول لتصبح 8 ثوانٍ، وعند 35 mph (تحت 40 mph) لا تُضاف ثانية إضافية، لذا فإن 8 ثوانٍ هي الوسادة."},"262":{"q":"أثناء فحصك قبل الرحلة، تقوم بتثبيت قطعة واحدة من أنبوب فولاذي طولها 15 قدماً على مقطورة مسطحة. الأنبوب ضمن حد الحمل التشغيلي لأربطتك تماماً. لتلبية الحد الأدنى الفيدرالي لتأمين الحمولة، ما هو أقل عدد من أربطة التثبيت يمكنك استخدامه قانونياً على هذه القطعة الواحدة؟","options":["رباطا تثبيت","رباط تثبيت واحد","3 أربطة تثبيت","4 أربطة تثبيت"],"explanation":"تحتاج الحمولة إلى رباط تثبيت واحد على الأقل لكل 10 أقدام من الطول ورباطين على الأقل لأي قطعة يزيد طولها عن 5 أقدام، لذا يتطلب أنبوب طوله 15 قدماً رباطي تثبيت."},"263":{"q":"أثناء جولة الفحص قبل الرحلة، تجد عارضة فولاذية على شكل حرف I طولها 25 قدماً محمّلة بشكل مسطح على مقطورتك ومثبتة برباطي سلسلة فقط. العارضة ضمن حدود وزنك تماماً والسطح في حالة جيدة. قبل أن تتمكن من التحرك قانونياً، ما هو الحد الأدنى لعدد أربطة التثبيت التي يجب أن تحملها هذه القطعة؟","options":["رباطا تثبيت، لأن أي قطعة يزيد طولها عن 5 أقدام تتطلب قانونياً جهازي تأمين على الأقل","3 أربطة تثبيت، لأنك تحتاج إلى رباط تثبيت واحد على الأقل لكل 10 أقدام من الحمولة و25 قدماً تُقرّب إلى 3","4 أربطة تثبيت، لأن الفولاذ الثقيل الطويل يجب تأمينه عند كل 5 أقدام من طوله","رباط تثبيت واحد، لأن العارضة قطعة صلبة واحدة تستقر بثبات على السطح"],"explanation":"تحتاج الحمولة إلى رباط تثبيت واحد على الأقل لكل 10 أقدام من الطول، مع التقريب للأعلى، لذا تتطلب عارضة طولها 25 قدماً 3 أربطة تثبيت."},"264":{"q":"أثناء فحصك قبل الرحلة، تقوم بتثبيت عارضة فولاذية واحدة طولها 35 قدماً تستقر على المقطورة المسطحة. مع معرفتك بالقاعدة المتعلقة بعدد أربطة التثبيت التي تتطلبها حمولة بهذا الطول، ما هو أقل عدد من أربطة التثبيت يمكنك استخدامه قانونياً لتأمين هذه العارضة؟","options":["3 أربطة تثبيت، لأن 35 قدماً مقسومة على 10 تعطيك ثلاثة أقسام كاملة من 10 أقدام","رباطا تثبيت، لأن أي قطعة واحدة تحتاج ببساطة إلى واحد عند كل طرف","4 أربطة تثبيت، لأنك تحتاج إلى واحد على الأقل لكل 10 أقدام و35 قدماً تُقرّب للأعلى","5 أربطة تثبيت، لأن عارضة بهذا الطول تتطلب واحداً إضافياً كهامش أمان"],"explanation":"يتطلب تأمين الحمولة رباط تثبيت واحداً على الأقل لكل 10 أقدام من الطول، مع تقريب أي قسم جزئي للأعلى، لذا تحتاج 35 قدماً إلى 4."},"265":{"q":"أثناء فحصك قبل الرحلة، تقوم بتثبيت عارضة فولاذية واحدة طولها 45 قدماً على مقطورة مسطحة. تزن العارضة 9,000 lb وكل سلسلة من سلاسلك لها حد حمل تشغيلي أعلى بكثير مما تتطلبه الحمولة، لذا فإن تصنيف الوزن ليس مصدر قلقك هنا. بناءً فقط على قاعدة الحد الأدنى لعدد أربطة التثبيت، ما هو أقل عدد من أربطة التثبيت يجب أن تستخدمه لنقل هذه العارضة قانونياً؟","options":["4 أربطة تثبيت، لأنك تعدّ واحداً لكل 10 أقدام كاملة من الطول وتتجاهل الـ 5 أقدام المتبقية","3 أربطة تثبيت، لأن حد الحمل التشغيلي مرتفع بما يكفي بالفعل لتثبيت الحمولة","6 أربطة تثبيت، بإضافة واحد إضافي يتجاوز قاعدة الطول كهامش أمان","5 أربطة تثبيت، لأنك تحتاج إلى واحد على الأقل لكل 10 أقدام و45 قدماً تُقرّب إلى 5"],"explanation":"يُطلب رباط تثبيت واحد على الأقل لكل 10 أقدام من الحمولة، مع تقريب أي بقية للأعلى، لذا تحتاج حمولة طولها 45 قدماً إلى 5."},"266":{"q":"أثناء فحصك قبل الرحلة، تقوم بتثبيت عارضة فولاذية واحدة طولها 55 قدماً على مقطورة مسطحة. تريد تلبية الحد الأدنى من قاعدة التأمين الفيدرالية/التابعة لتكساس لعدد أربطة التثبيت بناءً على طول الحمولة. بحساب متطلب الطول فقط، ما هو أقل عدد من أربطة التثبيت يمكنك استخدامه قانونياً لهذه العارضة؟","options":["6 أربطة تثبيت، لأنك تحتاج إلى واحد على الأقل لكل 10 أقدام من الحمولة و55 قدماً تُقرّب إلى 6","5 أربطة تثبيت، لأن 55 مقسومة على 10 تساوي 5 وتُسقط الباقي","7 أربطة تثبيت، لأنك تحتاج إلى واحد لكل 10 أقدام بالإضافة إلى واحد إضافي لأي قطعة يزيد طولها عن 5 أقدام","4 أربطة تثبيت، لأن رباطي تثبيت عند كل طرف يكفيان لتثبيت أي عارضة واحدة"],"explanation":"يُطلب رباط تثبيت واحد لكل 10 أقدام من الحمولة مع تقريب أي قسم جزئي للأعلى، لذا تحتاج حمولة طولها 55 قدماً إلى 6."},"267":{"q":"أثناء فحصك قبل الرحلة، تقوم بتثبيت عارضة فولاذية واحدة على مقطورتك المسطحة. يبلغ طولها نحو 8 أقدام وتزن نحو 3,000 رطل. تستنتج أنه بما أنها أقل من 10 أقدام بكثير، فإن قاعدة \"رباط تثبيت واحد لكل 10 أقدام\" تعني أن رباطاً واحداً يكفي. أي عبارة تصف بشكل صحيح الحد الأدنى لعدد أربطة التثبيت التي يجب أن تستخدمها؟","options":["رباط تثبيت واحد، لأن العارضة أقصر من 10 أقدام وقاعدة كل 10 أقدام هي المتحكمة","رباطا تثبيت، لأن أي قطعة يزيد طولها عن 5 أقدام تتطلب رباطين على الأقل بغض النظر عن عدّ كل 10 أقدام","رباط تثبيت واحد، لأن العارضة تزن أقل من عتبة الـ 1,100 رطل للرباط الواحد","لا يُطلب أي رباط تثبيت لقطعة واحدة بهذا القصر"],"explanation":"يجب أن تحتوي أي قطعة حمولة واحدة يزيد طولها عن 5 أقدام على رباطي تثبيت على الأقل، بغض النظر عن عدّ كل 10 أقدام."},"268":{"q":"عادةً ما تقود على امتداد طريق ريفي بسرعة 25 mph، ومن الخبرة تعرف أن شاحنتك المحمّلة تحتاج إلى نحو 30 قدماً من مسافة الفرملة هناك بمجرد أن تتمكن الفرامل من الإمساك. الليلة تقود على الطريق نفسه، بالحمولة نفسها والرصيف الجاف نفسه، لكن بسرعة 50 mph. مقارنةً بمسافة الفرملة المعتادة عند 25 mph، ستكون مسافة فرملتك عند 50 mph تقريباً:","options":["نفسها تقريباً، لأن الحمولة والرصيف لم يتغيرا","ضعف الطول تقريباً، لأنك ضاعفت سرعتك","نحو أربعة أضعاف الطول، لأن مسافة الفرملة تنمو مع مربع السرعة","نحو نصف الطول، لأن العجلات تدور أسرع وتتخلص من الطاقة بشكل أسرع"],"explanation":"تنمو مسافة الفرملة مع مربع السرعة، لذا فإن مضاعفة سرعتك تجعل مسافة الفرملة أطول بنحو أربعة أضعاف."},"269":{"q":"أنت تسير على طريق سريع جاف ومستوٍ بسرعة 55 mph في طقس جيد عندما تظهر فجأة سيارة متعطلة في حارتك على مسافة بعيدة. يسألك راكب عن كم من الطريق ستحتاجه فعلياً للتوقف تماماً منذ لحظة رؤيتك للخطر لأول مرة. بحساب الإدراك ورد الفعل والفرملة، أي تقدير لمسافة التوقف الإجمالية هو الأقرب إلى الصحة؟","options":["نحو 60 قدماً — تقريباً المسافة التي تقطعها شاحنتك خلال وقت رد الفعل وحده","نحو 100 قدم — أكثر قليلاً من طول شاحنة واحدة","نحو 250 قدماً — المسافة التي تضيئها مصابيحك المنخفضة ليلاً","نحو 419 قدماً — قريباً من طول ملعب كرة قدم بالإضافة إلى منطقتي النهاية (نحو 6 ثوانٍ من السير)"],"explanation":"مسافة التوقف الإجمالية هي الإدراك بالإضافة إلى رد الفعل بالإضافة إلى مسافة الفرملة، والتي تبلغ عند 55 mph نحو 419 قدماً (نحو 6 ثوانٍ)."},"270":{"q":"عادةً ما تسير بسرعة 30 mph في مسار توصيلك داخل المدينة، لكن اليوم يضعك تحويل على طريق سريع بسرعة 60 mph مع الرصيف الجاف نفسه والمقطورة المحمّلة نفسها. يفترض سائق جديد يركب معك أنه بما أنك ضاعفت سرعتك فقط، فسيستغرق الأمر نحو ضعف المسافة للتوقف. كيف تغيّر مضاعفة سرعتك تقريباً مسافة فرملتك فعلياً؟","options":["تزداد مسافة الفرملة بنحو أربعة أضعاف، لأنها تنمو مع مربع السرعة","تتضاعف مسافة الفرملة فقط، إذ تزداد بتناسب مباشر مع السرعة","تبقى مسافة الفرملة كما هي تقريباً لأن المقطورة المحمّلة تضيف تماسكاً","تزداد مسافة الفرملة قليلاً فقط، لأن مسافة رد الفعل هي ما ينمو فعلاً مع السرعة"],"explanation":"تزداد مسافة الفرملة مع مربع السرعة، لذا فإن مضاعفة سرعتك تجعلها أطول بنحو أربعة أضعاف، وليس ضعفين فقط."},"271":{"q":"أنت تقود بسرعة الطريق السريع عندما يخطو غزال فجأة إلى الطريق على مسافة بعيدة أمامك. المرحلة الأولى من التوقف هي الإدراك: الوقت من اللحظة التي يدخل فيها الغزال مجال رؤيتك لأول مرة حتى يتعرف عليه دماغك فعلياً كخطر. تحدث هذه المرحلة قبل أن تبدأ حتى بتحريك قدمك نحو الفرامل. بالنسبة لسائق منتبه بسرعة نحو 55 mph، كم من الوقت تستغرقه مرحلة الإدراك هذه بحد ذاتها تقريباً؟","options":["نحو 3/4 من الثانية، وهو في الواقع وقت رد الفعل الذي يستغرقه تحريك قدمك إلى الدواسة بعد أن يكون الخطر قد أُدرك بالفعل","نحو 1.75 ثانية، وهو الوقت الذي يعطيه الدليل لإدراك الخطر والتعرف عليه عند سرعة الطريق السريع قبل بدء أي رد فعل","نحو 6 ثوانٍ، وهو في الواقع الوقت الإجمالي للتوقف تماماً من 55 mph، وليس مرحلة الإدراك فقط","نحو عُشر الثانية، لأن السائق المحترف المنتبه يدرك الأخطار على الفور تقريباً"],"explanation":"الإدراك هو الوقت الذي يحتاجه دماغك لرؤية الخطر والتعرف عليه، نحو 1.75 ثانية عند سرعة الطريق السريع قبل بدء أي رد فعل."},"272":{"q":"أنت تسير بسرعة 55 mph على طريق سريع جاف عندما تظهر فجأة سيارة متعطلة في حارتك على مسافة بعيدة. بحلول الوقت الذي تتوقف فيه تماماً، تكون شاحنتك قد قطعت نحو طول ملعب كرة قدم بالإضافة إلى منطقتي النهاية (نحو 419 قدماً). يقسّم المدربون مسافة التوقف الإجمالية هذه إلى ثلاثة أجزاء: المسافة التي تقطعها شاحنتك بينما ترى الخطر (مسافة الإدراك)، والمسافة التي تقطعها بينما تحرّك قدمك إلى الدواسة (مسافة رد الفعل)، وجزء واحد آخر. أي جزء يُكمل مسافة التوقف الإجمالية؟","options":["مسافة التوجيه — المسافة المقطوعة بينما تدير عجلة القيادة للالتفاف حول العائق","مسافة الإشارة — المسافة المقطوعة بينما تشغّل أضواء التحذير لتنبيه حركة المرور","مسافة الفرملة — المسافة التي تقطعها الشاحنة بعد أن تمسك الفرامل حتى تتوقف تماماً","مسافة الركن — المساحة الإضافية التي تتركها عند الرصيف بمجرد أن تكون قد توقفت بأمان"],"explanation":"المكوّن الثالث لمسافة التوقف الإجمالية هو مسافة الفرملة، أي المسافة التي تقطعها الشاحنة بعد تطبيق الفرامل حتى تتوقف تماماً."},"273":{"q":"أنت تقود شاحنتك المستقيمة التي طولها 20 قدماً على طريق سريع مستوٍ في طقس جيد، وتحافظ على سرعة ثابتة قدرها 35 mph عبر حركة مرور خفيفة. تريد ترك الحد الأدنى الصحيح من مسافة المتابعة خلف السيارة التي أمامك. باستخدام قاعدة ثانية واحدة لكل 10 أقدام من طول المركبة، كم ثانية من مساحة المتابعة يجب أن تحافظ عليها عند هذه السرعة؟","options":["4 ثوانٍ، لأنه يجب عليك دائماً إضافة ثانية إضافية كاملة لكل 10 أقدام من طول الشاحنة","3 ثوانٍ، بإضافة ثانية واحدة إلى الرقم المبني على الطول لأن حركة المرور على الطريق السريع غير متوقعة","ثانية واحدة، لأنك عند 35 mph تكون تحت 40 mph ولا تنطبق قاعدة الثانية الإضافية","ثانيتان، لأن طولاً قدره 20 قدماً يعطي ثانيتين ولا تُضاف ثانية تحت 40 mph"],"explanation":"تحت 40 mph تحتاج إلى ثانية واحدة من مسافة المتابعة لكل 10 أقدام من طول المركبة، لذا تحتاج مركبة طولها 20 قدماً إلى ثانيتين."},"274":{"q":"أنت تقود شاحنة مستقيمة طولها 20 قدماً على طريق سريع جاف بسرعة ثابتة قدرها 55 mph في طقس صافٍ. حركة المرور خفيفة وتريد تحديد مسافة متابعة آمنة خلف السيارة التي أمامك. باستخدام قاعدة تقدير مسافة المتابعة حسب طول المركبة والسرعة، كم ثانية من المساحة يجب أن تحافظ عليها؟","options":["3 ثوانٍ","ثانيتان","4 ثوانٍ","6 ثوانٍ"],"explanation":"اترك ثانية واحدة من مسافة المتابعة لكل 10 أقدام من طول المركبة، ثم أضف ثانية أخرى عند السير فوق 40 mph."},"275":{"q":"تقود شاحنة مستقيمة يبلغ طولها 30 قدمًا من المصد إلى المصد. تتحرك حركة المرور بثبات عبر البلدة وتشير سرعتك على العداد إلى 35 ميلًا في الساعة. للحفاظ على مسافة أمان أمامك، ما هي الحد الأدنى لمسافة الاتباع التي ينبغي أن تحافظ عليها خلف المركبة التي أمامك؟","options":["ثانيتان، لأن الطريق مستوٍ وأنت أقل بكثير من سرعة الطريق السريع","3 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول مركبتك عند هذه السرعة","4 ثوانٍ، بإضافة ثانية واحدة إضافية إلى مسافتك المبنية على الطول لأنك في حركة المرور","5 ثوانٍ، مطابقة لمسافة الأمان المستخدمة عند سرعات الطريق السريع الأعلى لمركبة بهذا الحجم"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، دون إضافة ثانية إضافية عند السرعات الأقل من 40 ميلًا في الساعة."},"276":{"q":"تقود شاحنة مستقيمة منفردة طولها 30 قدمًا على طريق سريع بين الولايات جاف، وتحافظ بثبات على 55 ميلًا في الساعة في حركة مرور خفيفة. للحفاظ على مسافة أمان خلف السيارة التي أمامك، تختار جسمًا ثابتًا على جانب الطريق وتعدّ الثواني حتى يصل المصد الأمامي إليه. كم عدد ثواني مسافة الاتباع التي ينبغي أن تحافظ عليها في هذا الموقف؟","options":["3 ثوانٍ، لأن القاعدة هي ثانية واحدة لكل 10 أقدام من طول المركبة","5 ثوانٍ، بإضافة ثانية واحدة إضافية إلى ما تتطلبه قاعدة الطول والسرعة","4 ثوانٍ، لأن 30 قدمًا تعطي 3 ثوانٍ وتضيف ثانية واحدة أخرى لكونك فوق 40 ميلًا في الساعة","ثانيتان، وهي نفس الحد الأدنى للمسافة التي تحافظ عليها سيارة الركاب عند سرعة الطريق السريع"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"277":{"q":"تنقل حمولة طولها 40 قدمًا على طريق سريع مستوٍ وجاف وتستقر سرعتك على العداد عند 50 ميلًا في الساعة في حركة مرور خفيفة. لتترك لنفسك مسافة أمان خلف المركبة التي أمامك، كم عدد ثواني مسافة الاتباع التي ينبغي أن تحافظ عليها في هذا الموقف؟","options":["4 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول مركبتك","6 ثوانٍ، لأنها تطابق مسافة التوقف الإجمالية التي تحتاجها الشاحنة عند سرعة الطريق السريع","3 ثوانٍ، اتباعًا لقاعدة الثلاث ثوانٍ القياسية التي تنطبق على جميع المركبات","5 ثوانٍ، لأنك تضيف ثانية واحدة إضافية إلى العدّ المبني على الطول عندما تسير بأسرع من 40 ميلًا في الساعة"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"278":{"q":"تنقل مركبة مركّبة طولها 60 قدمًا على طريق سريع بين الولايات جاف، وتحافظ بثبات على 50 ميلًا في الساعة في حركة مرور خفيفة. هناك سيارة صغيرة أمامك تحدد سرعتك، وتريد أن تترك مسافة أمان. باستخدام القاعدة الأساسية لمسافة الاتباع من الدليل، كم عدد ثواني المسافة التي ينبغي أن تحافظ عليها خلف تلك المركبة؟","options":["7 ثوانٍ، لأن طول 60 قدمًا يعطي 6 ثوانٍ، زائد ثانية واحدة إضافية للسير بأكثر من 40 ميلًا في الساعة","6 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول المركبة","8 ثوانٍ، لأنك تضيف ثانيتين لسرعة الطريق السريع فوق الـ 6 ثوانٍ للطول","5 ثوانٍ، لأن مركبة طولها 60 قدمًا عند سرعة معتدلة تحتاج إلى نحو نصف ثانية لكل 5 أقدام"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"279":{"q":"تقود مقطورة بجرّار طولها 70 قدمًا على طريق سريع بين الولايات جاف، وتسير بثبات على 55 ميلًا في الساعة في ظروف نهارية صافية. يضغط السائق الذي أمامك على الفرامل بخفة وتدرك أنك انجرفت إلى أقرب مما ينبغي. باستخدام القاعدة التقريبية لمسافة الاتباع، ما هو الحد الأدنى للمسافة التي ينبغي أن تحافظ عليها خلف تلك المركبة؟","options":["7 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول مركبتك","8 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من الطول وتضيف ثانية واحدة أخرى للسير بأكثر من 40 ميلًا في الساعة","6 ثوانٍ، لأن مسافة التوقف الإجمالية عند 55 ميلًا في الساعة تبلغ نحو 6 ثوانٍ","9 ثوانٍ، بحساب ثانية واحدة لكل 10 أقدام زائد ثانيتين إضافيتين لسرعة الطريق السريع"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"280":{"q":"تنقل حمولة عبر ممر إنشاءات بسرعة 35 ميلًا في الساعة في رتل مركّب يبلغ طوله 90 قدمًا من المصد إلى المصد. حركة المرور ثابتة، والرصيف جاف، وتريد تحديد مسافة اتباع آمنة باستخدام قاعدة الثواني المبنية على طول المركبة. كم عدد ثواني مسافة الاتباع التي ينبغي أن تحافظ عليها خلف المركبة التي أمامك في هذا الموقف؟","options":["10 ثوانٍ، لأن أي مركبة مركّبة بهذا الطول تحتاج إلى إضافة ثانية واحدة إضافية بغض النظر عن السرعة","8 ثوانٍ، لأنك تقرّب طول الـ 90 قدمًا للأسفل إلى أقرب فاصل قاعدة كامل","9 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول المركبة وسرعتك أقل من 40 ميلًا في الساعة","11 ثانية، لأنك تحسب ثانية واحدة لكل 10 أقدام وتضيف ثانية كاملة إضافية لمنطقة العمل"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، دون إضافة ثانية إضافية عند السرعات الأقل من 40 ميلًا في الساعة."},"281":{"q":"تنقل مركبة مركّبة طولها 90 قدمًا على طريق سريع مستوٍ بين الولايات وتشير سرعتك على العداد بثبات إلى 60 ميلًا في الساعة في طقس صافٍ وجاف. تتحرك حركة المرور أمامك بحرية. باستخدام قاعدة الدليل لتقدير مسافة اتباع آمنة، كم عدد ثواني المسافة التي ينبغي أن تحافظ عليها بين مقدمة رتلك والمركبة التي أمامك؟","options":["8 ثوانٍ، لأنك عند 60 ميلًا في الساعة تقلّل الرقم الأساسي لمراعاة سرعة الطريق السريع الأعلى","11 ثانية، بإضافة ثانيتين إضافيتين لأنك أعلى بكثير من 40 ميلًا في الساعة","9 ثوانٍ، لأنك ببساطة تحسب ثانية واحدة لكل 10 أقدام من طول المركبة","10 ثوانٍ، بحساب ثانية واحدة لكل 10 أقدام من الطول وإضافة ثانية واحدة أخرى للسرعة فوق 40 ميلًا في الساعة"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"282":{"q":"تنقل مركبة مركّبة طولها 100 قدم على طريق ريفي سريع مستوٍ وجاف وتثبت سرعتك على العداد على 35 ميلًا في الساعة. هناك سيارة صغيرة أمامك تتحرك بنفس السرعة، وتريد تحديد مسافة اتباع آمنة. بعدّ الثواني التي يستغرقها مصدك الأمامي للوصول إلى علامة ثابتة مرّت بها المركبة التي أمامك للتو، ما هو الحد الأدنى لمسافة الاتباع التي ينبغي أن تحافظ عليها؟","options":["10 ثوانٍ","11 ثانية","9 ثوانٍ","7 ثوانٍ"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، دون إضافة ثانية إضافية عند السرعات الأقل من 40 ميلًا في الساعة."},"283":{"q":"تسحب منصة مسطحة ويبلغ طول مقطورتك بجرّارها بالضبط 100 قدم من المصد إلى المصد. استقرت حركة المرور على الطريق الريفي السريع وتثبت سرعتك على العداد على 45 ميلًا في الساعة في ظروف جافة وصافية. بعدّ الثواني عندما تمرّ مركبة أمامك بعلامة ثابتة، كم عدد ثواني مسافة الاتباع التي ينبغي أن تحافظ عليها خلف تلك المركبة؟","options":["10 ثوانٍ، لأنك تحسب ثانية واحدة لكل 10 أقدام من طول مركبتك","11 ثانية، لأن 100 قدم تستلزم 10 ثوانٍ وتضيف ثانية واحدة أخرى لكونك فوق 40 ميلًا في الساعة","12 ثانية، بحساب ثانية واحدة لكل 10 أقدام زائد ثانيتين إضافيتين لسرعة الطريق السريع","9 ثوانٍ، بتقريب الرتل الذي طوله 100 قدم للأسفل بسبب الرصيف الجاف"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"284":{"q":"تنقل مركبة مركّبة طولها 60 قدمًا على طريق سريع بين الولايات جاف، وتحافظ بثبات على 60 ميلًا في الساعة في حركة مرور خفيفة. باستذكار قاعدة مسافة الاتباع من الدليل، ما هو أقل قدر من المسافة الذي ينبغي أن تحافظ عليه بينك وبين المركبة التي أمامك؟","options":["6 ثوانٍ، لأن مركبة طولها 60 قدمًا تحتاج إلى ثانية واحدة لكل 10 أقدام من الطول","5 ثوانٍ، لأن حركة المرور خفيفة والطريق جاف","7 ثوانٍ، بحساب ثانية واحدة لكل 10 أقدام من الطول زائد ثانية واحدة إضافية لكونك فوق 40 ميلًا في الساعة","8 ثوانٍ، بإضافة ثانيتين إلى الرقم الأساسي لأن سرعة الطريق السريع متضمنة"],"explanation":"احسب ثانية واحدة من مسافة الاتباع لكل 10 أقدام من طول المركبة، ثم أضف ثانية واحدة أخرى عند السير بأكثر من 40 ميلًا في الساعة."},"285":{"q":"تقود مقطورة بجرّار محمّلة بسرعة الطريق السريع على طريق جاف من مسارين عند الغسق عندما يندفع غزال كبير من حد الأشجار ويتجمد في مسارك على بعد نحو 150 قدمًا أمامك. يبدو المسار الأيسر خاليًا وهناك كتف مرصوف على يمينك. أي إجراء يعد عادةً الاستجابة الأكثر أمانًا؟","options":["التوجيه بسرعة إلى المسار الأيسر للالتفاف حول الحيوان، لأنه يبدو خاليًا","الانحراف إلى الكتف الأيمن والتسارع لتجاوز الغزال قبل أن يتحرك","رفع يديك عن عجلة القيادة وترك الشاحنة تسير في خط مستقيم من تلقاء نفسها","تطبيق فرملة حازمة ومتحكَّم بها والبقاء في مسارك"],"explanation":"اضغط الفرامل بحزم وابقَ في مسارك، لأن الانحراف الحاد المفاجئ قد يقلب الرتل ذا مركز الثقل المرتفع أو يطويه."},"286":{"q":"تقود مركبة مركّبة محمّلة على طريق سريع مقسوم عندما يتقلص المسار إلى منطقة عمل. تخفّض اللافتات البرتقالية الحد المسموح به إلى ما دون سرعة الطريق السريع بكثير، وهناك عامل إشارات متمركز أمامك، ويتحرك عمال بالقرب من المسار المفتوح. ما زالت حركة المرور من حولك تسير بسرعة قريبة من سرعة الطريق السريع. أي إجراء هو الاستجابة الأكثر أمانًا والصحيحة قانونيًا؟","options":["خفّض سرعتك إلى الحد المسموح به في منطقة العمل وابقَ متيقظًا للعمال والمعدات وإشارات عامل الإشارات","حافظ على مسافة الاتباع وعلى سرعة الطريق السريع لأنك تترك بالفعل مسافة 7 ثوانٍ أمامك","سايِر حركة المرور المحيطة بك حتى لا تخلق فرق سرعة خطيرًا بين المركبات","انتقل إلى المسار الأسرع وتجاوز المركبات المتباطئة لتجتاز منطقة العمل بأسرع ما يمكن"],"explanation":"خفّف السرعة إلى الحد المسموح به في منطقة العمل وابقَ متيقظًا للعمال والمعدات وعامل الإشارات الذي يتحكم في حركة المرور في المنطقة."},"287":{"q":"تخرج من منعطف على طريق رطب من مسارين وتضغط على دواسة الوقود لاستعادة سرعة الطريق السريع. يقفز عداد دوران المحرك فجأة وتشعر بأن مؤخرة جرّارك بدأت تتأرجح للخارج بينما تفقد عجلات الدفع تماسكها وتدور. أي إجراء يمنحك أفضل فرصة لاستعادة السيطرة؟","options":["اضغط الفرامل بحزم لإبطاء عجلات الدفع الدائرة وشدّ خطّ سيرك عبر المنعطف","ارفع قدمك عن دواسة الوقود للسماح لعجلات الدفع بالتباطؤ ووجّه في الاتجاه الذي تريد أن تذهب إليه الشاحنة","وجّه بحدة في الاتجاه المعاكس للمنعطف لمواجهة التأرجح بأسرع ما يمكن","حافظ على ضغط ثابت على دواسة الوقود حتى تسحبك العجلات المدفوعة في خط مستقيم خارج الانزلاق"],"explanation":"للتعافي من انزلاق عجلات الدفع، ارفع قدمك عن دواسة الوقود حتى تستعيد العجلات تماسكها ووجّه نحو حيث تريد أن تذهب الشاحنة."},"288":{"q":"تنقل حمولة جزئية ذات مركز ثقل مرتفع على طريق ريفي سريع من مسارين. عند الخروج من تلة تدرك أن المنعطف القادم يميل أكثر حدة مما حذّرت منه اللافتة، وقد دخلته بسرعة أكبر مما هو مريح. أي إجراء يمنحك أفضل فرصة للبقاء في مسارك دون انزلاق أو انقلاب؟","options":["اضغط الفرامل بقوة وحزم عبر قمة المنعطف لإزالة السرعة الزائدة بسرعة","انتقل إلى ترس أعلى وتسارع لدفع الشاحنة عبر المنعطف قبل أن تتمكن من الميلان","أدرك أنه كان ينبغي عليك التباطؤ قبل المنعطف، لذا ارفع قدمك عن دواسة الوقود واستخدم فرملة خفيفة وتدريجية فقط مع إبقاء الشاحنة ثابتة عبر المنعطف","اضغط على القابض واسحب الشاحنة عبر المنعطف في الوضع المحايد حتى لا تفقد عجلات الدفع تماسكها"],"explanation":"داخل المنعطف، ارفع قدمك عن دواسة الوقود واستخدم فرملة خفيفة وتدريجية فقط، لأن الفرملة القوية تزيح الوزن وقد تكسر التماسك."},"289":{"q":"تتحول إشارة المرور إلى الأصفر بينما تقترب منها شاحنتك الثقيلة. ماذا ينبغي أن تفعل؟","options":["اضغط الفرامل بقوة شديدة","إذا لم تستطع التوقف بأمان، فتابع بحذر","تسارع لما يفوق الحد بكثير","توقّف في وسط التقاطع تمامًا"],"explanation":"إذا لم تستطع التوقف بأمان، فتابع بحذر؛ لا تضغط الفرامل بقوة شديدة."},"290":{"q":"تقود مركبة مركّبة محمّلة بسرعة 60 ميلًا في الساعة على طريق سريع بين الولايات جاف، وتبقى قريبًا خلف شاحنة صندوقية حتى لا تتمكن السيارات من الاندماج أمامك. تومض أضواء فرامل الشاحنة الصندوقية وتتوقف بقوة بسبب حركة مرور متوقفة؛ تضغط الفرامل بقوة وتتوقف على بعد بوصات قليلة فقط. عند مراجعة الحادث الوشيك لاحقًا، أي إجراء كان سيمنحك الوقت والمسافة اللذين كنت تحتاجهما فعلًا للتوقف بأمان؟","options":["الاتباع على مسافة 4 ثوانٍ، لأن هذه هي مسافة التوقف الإجمالية عند 55 ميلًا في الساعة (نحو 419 قدمًا)","البقاء في مكانك تمامًا لكن الفرملة قبل نصف ثانية لحظة وميض أضواء الفرامل","تضييق المسافة أكثر حتى لا تتمكن أي سيارة من الاندماج وإجبارك على الفرملة على الإطلاق","الاتباع بمسافة كافية للخلف للحفاظ على مسافة اتباع آمنة، مما يمنحك الوقت للإدراك ورد الفعل والفرملة قبل الوصول إلى الشاحنة"],"explanation":"حافظ على مسافة اتباع آمنة لأن مسافة التوقف الإجمالية هي مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الفرملة، وتبلغ مجتمعةً مئات الأقدام."},"291":{"q":"لقد تجاوز الوقت الغسق بكثير وانعطفت إلى طريق ريفي ضيق من مسارين لم تقده من قبل قط. لا توجد أضواء شوارع، والأكتاف غير مميزة، ولا يمكنك الرؤية بعيدًا خلف مصابيحك الأمامية. لقيادة هذا المقطع بأكثر أمان، ماذا ينبغي أن تفعل؟","options":["خفّض سرعتك بحيث تستطيع دائمًا التوقف ضمن المسافة التي تضيئها مصابيحك الأمامية، واستخدم الأضواء العالية حيث لا توجد حركة مرور قادمة","سايِر سرعة السيارات القليلة التي أمامك حتى لا تقود أبطأ من تدفق حركة المرور","شغّل أضواءك العالية واتركها مضاءة باستمرار حتى ترى أبعد ما يمكن على الطريق","حافظ على سرعتك النهارية المعتادة لأن تخفيض السرعة ليلًا يجعلك خطرًا على حركة المرور الأسرع"],"explanation":"لا تتجاوز قط مدى مصابيحك الأمامية في القيادة، أبقِ سرعتك منخفضة بما يكفي للتوقف ضمن المسافة المضاءة أمامك، واستخدم الأضواء العالية حيث لا توجد حركة مرور قادمة."},"292":{"q":"ترى أضواء فرامل وحركة مرور متباطئة بعيدًا أمامك. ينبغي أن:","options":["تحافظ على نفس سرعتك بثبات","ترفع قدمك عن دواسة الوقود مبكرًا وتستعد للتباطؤ","تسارع لتجاوزهم جميعًا","تغيّر مسارك بسرعة شديدة"],"explanation":"ارفع قدمك مبكرًا وكن مستعدًا للتباطؤ بسلاسة."},"293":{"q":"تقود مقطورتك بجرّارها عبر منطقة أعمال تجارية في وسط المدينة بسرعة نحو 25 ميلًا في الساعة في حركة مرور خفيفة. بينما تقترب من منطقة غير مميزة في منتصف الكتلة السكنية، يخطو أحد المشاة الذي كان واقفًا على الرصيف فجأة إلى الشارع على بعد عدة أطوال سيارة أمامك، وهو ينظر إلى الأسفل نحو هاتفه وليس نحوك. مسارك على اليمين مسدود بسيارات متوقفة وهناك حركة مرور قادمة على يسارك. أي إجراء هو الاستجابة الأكثر أمانًا والصحيحة قانونيًا؟","options":["أطلق بوقك بحزم وحافظ على سرعتك، لأن لديك حق الأولوية في مسارك والمشاة على الأرجح سيعود للخلف","ارفع قدمك عن دواسة الوقود، واجعل قدمك فوق الفرامل، وأبطئ، وكن مستعدًا للتوقف من أجل المشاة","وجّه قليلًا إلى المسار القادم للالتفاف حول المشاة، ثم عُد إلى مسارك بمجرد أن يصبح خاليًا","تسارع لفترة وجيزة لاجتياز المنطقة قبل أن يدخل المشاة مسارك بالكامل"],"explanation":"بالنسبة للمشاة الذي خطا إلى الطريق، ارفع قدمك عن دواسة الوقود، واجعل قدمك فوق الفرامل، وأبطئ، وكن مستعدًا للتوقف."},"294":{"q":"تقود مركبة مركّبة محمّلة على طريق سريع بين الولايات بأربعة مسارات وتحتاج إلى الانتقال مسارًا واحدًا إلى اليسار للاستعداد لمخرج على بعد نحو ميلين أمامك. تشير، وتفحص مراياك الجانبية اليسرى، وتبدأ بالانتقال، لكنك أثناء ذلك تدرك أن سيارة ركاب تسير بمحاذاة جرّارك في المنطقة التي لا تغطيها مراياك بالكامل. أي إجراء هو الاستجابة الأفضل والأكثر أمانًا؟","options":["تابع انتقالك إلى المسار مع النقر على الفرامل، لأن أضواء فراملك ستنبّه السيارة للتراجع وفتح فجوة لك","تسارع بحزم لسحب جرّارك أمام السيارة حتى تنتهي خلف مقطورتك، ثم أكمل تغيير المسار قبل فحص المرآة التالي","ألغِ تغيير المسار، وحافظ على موضعك، وانتظر فجوة خالية، وأعد فحص المرآة ومنطقة النقطة العمياء قبل محاولة الانتقال مرة أخرى","تابع تغيير المسار لأنك أشرت مبكرًا بالفعل وأكملت فحص المرآة، والسائق الذي يسير بمحاذاتك مسؤول عن إفساح الطريق لشاحنة تشير"],"explanation":"وجود مركبة في نقطتك العمياء يعني أن المسار ليس خاليًا، لذا ألغِ تغيير المسار وأعد فحص المرآة والنقطة العمياء قبل الانتقال."},"295":{"q":"تشعر بالغضب يتصاعد تجاه سائق آخر. الخيار الآمن هو أن:","options":["تواجهه مباشرة الآن","تبقى هادئًا، وتحافظ على المسافة، ولا تتورط","تسد طريقه أمامه","تضغط الفرامل أمامه بقوة شديدة لإفزاعه"],"explanation":"ابقَ هادئًا، وحافظ على مسافتك، ولا تتورط."},"296":{"q":"تقود مقطورة بجرّار محمّلة في المسار الأيمن من طريق سريع مزدحم بأربعة مسارات بسرعة 55 ميلًا في الساعة. تظهر شاحنة صيانة بطيئة الحركة أمامك في مسارك، وتقرر أنك بحاجة إلى الانتقال إلى المسار الأيسر للحفاظ على سرعتك. حركة المرور كثيفة على كلا الجانبين. أي تسلسل هو الطريقة الأكثر أمانًا والصحيحة لإتمام هذا التغيير في المسار؟","options":["تسارع بسرعة لإنشاء فجوة، ثم انتقل إلى المسار الأيسر قبل أن يتمكن أحد من ملئها","افرمل بقوة أولًا لفتح مساحة خلفك، ثم انتقل إلى المسار الأيسر بمجرد أن تتباطأ","ألقِ نظرة واحدة على مرآتك اليسرى وانتقل بسلاسة، لأن الإشارة على طريق مزدحم تربك السائقين الآخرين فقط","شغّل إشارتك اليسرى مبكرًا، وافحص مراياك ونقطتك العمياء اليسرى (المنطقة الميتة 'No-Zone')، ولا تنتقل إلا بعد أن تتأكد من أن المسار خالٍ"],"explanation":"أشِر مبكرًا، وافحص مراياك والنقطة العمياء اليسرى (المنطقة الميتة)، ولا تنتقل إلا بعد التأكد من أن المسار خالٍ."},"297":{"q":"أثناء فحصك قبل الرحلة تكتشف أن السائق السابق استبدل إطارًا تالفًا واحدًا. الإطار الجديد قطري (radial)، لكن الإطار الآخر المجاور له على نفس المحور قطري-قطري متعارض (bias-ply). موضعا المحور المتبقيان متطابقان. أي حالة هي التي يجب أن تصححها قبل أن تصبح هذه الشاحنة قانونية وآمنة للقيادة؟","options":["وجود إطار قطري (radial) مركّب بجانب إطار قطري-قطري متعارض (bias-ply) على نفس المحور","إطار محور التوجيه يُظهر عمق مداس 4/32 بوصة","إطار خلفي (غير توجيهي) يُظهر عمق مداس 2/32 بوصة","وجود إطارين من نفس العلامة التجارية لكن بتواريخ شراء مختلفة على محور واحد"],"explanation":"يجب ألا تُخلط الإطارات القطرية والقطرية المتعارضة (bias-ply) أبدًا على نفس المحور لأن اختلاف بنيتها يسبب تماسكًا وتحكمًا غير متساويين ولا يمكن التنبؤ بهما."},"298":{"q":"أثناء فحصك قبل الرحلة، تجد أن أحد إطارات محور الدفع لديك به جزء ينفصل فيه المداس عن جسم الإطار، إضافة إلى شق طويل عميق بما يكفي لكشف الخيوط (cord) الموجودة تحته. ما زال الإطار يحتفظ بالهواء وعمق المداس في أماكن أخرى يقيس أعلى بكثير من 2/32 بوصة. ما هو القرار الصحيح بشأن هذا الإطار؟","options":["القيادة به قانونية لأن عمق المداس المتبقي ما زال أعلى من الحد الأدنى 2/32 بوصة لإطار غير توجيهي","الإطار خارج الخدمة ويجب استبداله قبل قيادة المركبة، بغض النظر عن عمق المداس أو ضغط الهواء","مقبول لرحلة محلية قصيرة طالما أبقيت سرعتك منخفضة وأعدت فحصه عند أول توقف","إنه عيب طفيف فقط لأن الإطار على محور الدفع وليس على محور التوجيه"],"explanation":"انفصال المداس أو وجود شق عميق يكشف الطبقة (ply) حالة خارج الخدمة، لذا يجب استبدال الإطار قبل القيادة بغض النظر عن عمق المداس أو ضغط الهواء."},"299":{"q":"أثناء فحصك قبل الرحلة تجد إطارًا بسطح معاد كسوته (retreaded) وآخر بعلامات جدار جانبي معاد تخديده (regrooved). لديك موعد تسليم نهائي وتريد إبقاء هذين الإطارين في الخدمة في مكان ما على رتلك بدلًا من استبدالهما. على أي موضع عجلة واحد يكون تركيب إطار معاد تخديده أو معاد كسوته محظورًا، مما يجبرك على وضع إطار جديد مناسب هناك بدلًا منه؟","options":["على محور المقطورة الخلفي، لأن إطارات المقطورة تحمل أثقل حمولة وتتآكل أسرع","على موضع مزدوج داخلي، لأن إعادة الكسوة المخفية هناك هي الأصعب في الفحص","على موضع المحور الأمامي (التوجيه)، حيث لا يُسمح بإطار معاد تخديده أو معاد كسوته","على عجلة الإطار الاحتياطي، لأن الإطار المعاد كسوته لا يُسمح أبدًا بحمله كاحتياطي"],"explanation":"الإطارات المعاد تخديدها أو كسوتها أو تجديد مداسها محظورة على محور التوجيه الأمامي لأن فشل إطار التوجيه هناك يسبب فقدانًا فوريًا للسيطرة على التوجيه."},"300":{"q":"أثناء فحصك قبل الرحلة، تنحني لفحص الإطارات المزدوجة على المحور الخلفي للمقطورة. يبدو أن كلا الإطارين بنفس الحجم والعلامة التجارية، وبعمق نقش جيد. وبينما تنظر عن قرب إلى الفجوة بينهما، عليك أن تقرر أي حالة تجعل هذه المجموعة المزدوجة غير قانونية وغير آمنة للقيادة. أيٌّ مما يلي هو العيب الذي يجب ألّا تسمح به؟","options":["الإطاران بنفس الحجم تماماً ولهما أنماط نقش متطابقة","كلا الإطارين منفوخان بإحكام ويحملان ضغط هواء متساوياً تقريباً","يُظهر كل إطار عمق نقش أعلى بكثير من الحد الأدنى البالغ 2/32 بوصة على المحور الخلفي","الإطاران منتفخان إلى الداخل ويلامس أحدهما الآخر"],"explanation":"يجب ألّا تلامس الإطارات المزدوجة بعضها بعضاً أو أي جزء من المركبة، لأن التلامس يدل على نقص في النفخ أو سوء تركيب، وحرارة الاحتكاك قد تسبب انفجار الإطار."},"301":{"q":"أثناء فحصك قبل الرحلة في صباح بارد، تجد شرخاً ظاهراً يمتد عبر أحد جنوط العجلات على محور الدفع. الإطار يحتفظ بالهواء، والنقش جيد، وأنت متأخر بالفعل عن موعد تسليم. أي إجراء هو الصحيح؟","options":["أخرج المركبة من الخدمة ولا تقُدها حتى يتم إصلاح الجنط المشروخ أو استبداله","قُد بحذر إلى موعد التسليم لأن الإطار لا يزال يحتفظ بالهواء وعمق النقش جيد","قلّل ضغط الإطار ببضعة أرطال لتخفيف الإجهاد على الجنط، ثم تابع بسرعة منخفضة","إنه مجرد شرخ تجميلي بسيط، فسجّله كتآكل طبيعي وأعد فحصه عند أول توقف لحمولتك على بُعد 50 ميلاً"],"explanation":"الجنط المشروخ أو المكسور حالة تستوجب الإخراج التلقائي من الخدمة لأنه قد ينهار تحت الحمل ويفصل الإطار عن العجلة أثناء السرعة."},"302":{"q":"أثناء فحصك قبل الرحلة، تزحف تحت المقطورة وتجد أن إحدى صفائح نابض الورق في التعليق الخلفي مشروخة بالكامل، وأن صفيحة ثانية قد انزاحت من موضع تثبيتها. لا تزال الشاحنة تقف مستوية في الساحة وتسير بشكل جيد في حلقة الاختبار القصيرة. ما الطريقة الصحيحة لتصنيف هذا الاكتشاف والتعامل معه قبل رحلتك؟","options":["لأن الشاحنة تقف مستوية وتسير جيداً، فإن الصفيحة المشروخة عيب تجميلي ويمكنك تشغيلها ومراقبتها أثناء الرحلة","إنه عيب في التعليق يجب إصلاحه قبل إدخال المركبة في الخدمة","إنه مقبول طالما أعدت فحص تثبيت الحمولة خلال أول 50 ميلاً","إنها حالة طبيعية تُحسّن في الواقع جودة القيادة ولا تتطلب أي إجراء"],"explanation":"نوابض الورق المشروخة أو المكسورة أو المفكوكة أو المفقودة أو المنزاحة عيب في التعليق يستوجب الإخراج من الخدمة ويجب إصلاحه قبل إدخال المركبة في الخدمة."},"303":{"q":"إنه صباح باكر وأنت تتجول حول جرارك ومقطورتك أثناء الفحص قبل الرحلة. عند التعليق الخلفي تلاحظ طبقة زيتية رطبة تغطي أحد ممتصات الصدمات، وأثراً رفيعاً من السائل يسيل نزولاً إلى درع الغبار. يبدو كل شيء آخر على ذلك المحور طبيعياً. ما الاستنتاج الصحيح بشأن هذا الجزء، وما الذي يجب عليك فعله؟","options":["الطبقة الزيتية مجرد أوساخ طريق تقذفها الإطارات، لذا فإن ممتص الصدمات بحالة جيدة ويمكن تركه كما هو، ويمكنك متابعة الرحلة.","ممتصات الصدمات مصممة لترشّح كمية قليلة من الزيت لتبقى مزلَّقة، لذا فإن الطبقة الخفيفة مقبولة، ولا يُعدّ عيباً إلا التسريب الكثيف المتقطر.","ممتص الصدمات المسرِّب عيب؛ يجب أن تكون ممتصات الصدمات مثبتة بإحكام وخالية من التسريب، لذا يجب إصلاح هذا قبل أن تصبح المركبة آمنة للقيادة.","ممتصات الصدمات لا تحمل أي حِمل وتؤثر فقط في راحة القيادة، لذا فإن التسريب مشكلة تجميلية بسيطة يمكنك تدوينها ومعالجتها عند فحص الحمولة التالي على بُعد 150 ميلاً."],"explanation":"يجب أن تكون ممتصات الصدمات مثبتة بإحكام وخالية من التسريب، لذا فإن ممتص الصدمات المسرِّب عيب يجب الإبلاغ عنه وإصلاحه قبل أن تصبح المركبة آمنة للقيادة."},"304":{"q":"أثناء فحصك قبل الرحلة، تزحف تحت الجرار وتجد شرخاً جديداً يمتد عبر إحدى قضبان الهيكل بالقرب من علّاقة نابض الورق، وأحد دعامات المحرك مفكوك بشكل واضح. أنت متأخر بالفعل عن موعد تسليم محلي قصير على بُعد 40 ميلاً على شوارع مدينة مستوية. أي إجراء هو الصحيح؟","options":["بما أنها رحلة قصيرة بطيئة على شوارع مستوية، يمكنك القيادة إلى موقع التسليم والإبلاغ عن الشرخ بعد ذلك","لُفّ المنطقة المشروخة بإحكام بشريط لاصق ثقيل وأحكم ما يمكنك يدوياً حتى يثبت إلى نهاية اليوم","قُد بسرعة منخفضة وأعد فحص الهيكل والدعامات خلال أول 50 ميلاً، إذ إن ذلك هو الوقت الذي يجب فيه فحص التثبيت","أخرج المركبة من الخدمة وأصلح الهيكل المشروخ والدعامات المفكوكة قبل أن تقودها على الإطلاق"],"explanation":"الهيكل المشروخ أو الدعامة المفكوكة عيب هيكلي يستوجب الإخراج من الخدمة، لأن الهيكل يحمل كل مسارات الحِمل والشرخ قد يتمدد وينهار بشكل كارثي."},"305":{"q":"إنها درجة حرارة أدنى بقليل من التجمد في رحلة صباحية باكرة، لذا تُبقي نوافذ المقصورة مغلقة والمدفأة تعمل. أثناء فحصك قبل الرحلة لاحظت تسريباً صغيراً حيث يلتقي أنبوب العادم بكاتم الصوت، لكن المحرك ظل يعمل جيداً، فقررت القيادة. بعد ساعة تشعر بالنعاس وبصداع خفيف. أيُّ نتيجة لتسريب العادم ذاك هي السبب الأخطر الذي كان يجب أن تصلحه قبل القيادة؟","options":["يمكن أن تتسرب غازات العادم، بما فيها أول أكسيد الكربون، إلى المقصورة المغلقة وتسممك","التسريب يُدخل هواءً خارجياً بارداً إلى المقصورة ويُجهد المدفأة","العادم المتسرب يقلل قدرة المحرك ويهدر الوقود عند الصعود","التسريب يجعل المحرك يعمل بصوت أعلى وقد يخفي أصوات تحذير أخرى"],"explanation":"نظام العادم المسرِّب خطير لأن غازات العادم، بما فيها أول أكسيد الكربون، يمكن أن تتسرب إلى المقصورة المغلقة وتسمّم السائق."},"306":{"q":"أثناء فحصك قبل الرحلة، تفتح صندوق البطارية وتجد البطارية تتحرك قليلاً مع بِركة صغيرة من السائل في الصينية أسفلها. الكابلات موصولة والشاحنة تدور بشكل جيد. وفق معايير فحص شرطة ولاية تكساس، ما الحالة التي يجب أن تستوفيها البطارية قبل أن تتمكن قانونياً من أخذ هذه المركبة إلى الطريق؟","options":["يكفي أن تكون مشحونة بما يكفي لتشغيل المحرك، إذ إن قدرة التدوير تثبت أن البطارية صالحة للطريق","يجب أن تكون مثبتة بإحكام بمثبّت بحيث لا تتحرك، ويجب ألّا تكون مسرِّبة","تسرّب طفيف للكهرل (الإلكتروليت) مقبول طالما بقي مستوى السائل فوق الألواح","البطارية المفكوكة لا بأس بها في الرحلات القصيرة لأن الكابلات وحدها تمنعها من الحركة"],"explanation":"يجب أن تكون البطارية مثبتة بإحكام بمثبّت بحيث لا تتحرك وألّا تُظهر أي تسريب، لأن البطارية المتحركة أو المسرِّبة قد تحدث دائرة قصر أو تتشقق أو تسكب حمضاً أكّالاً."},"307":{"q":"تتوقف عند جزيرة تزويد بالوقود في نهاية رحلة طويلة. لا تزال وحدة التبريد في مقطورتك تعمل، وبطارية هاتفك عند 8% فتريد إجراء مكالمة سريعة، وزميل سائق ينتظر قريباً أشعل للتو سيجارة على بُعد نحو 20 قدماً من المضخات. قبل أن تبدأ بضخ الديزل في الخزان، أيٌّ مما يلي هو الإجراء الصحيح؟","options":["أبقِ المحرك يعمل ليبقى نظام الهواء ووحدة التبريد مشحونين، لكن أمسك فوهة الوقود بثبات واضخ ببطء","أبقِ الشاحنة تعمل لكن ابتعد لإجراء مكالمتك الهاتفية بينما يمتلئ الخزان، لأن فوهة الإيقاف التلقائي ستوقف التدفق","أطفئ المحرك، ولا تدخّن ولا تسمح بالتدخين قرب نقطة الوقود، وابقَ عند الفوهة أثناء التزويد","اترك السيجارة لأنها على بُعد أكثر من 15 قدماً، وزِد دوران المحرك قليلاً أولاً لتنظيف الخطوط قبل التزويد"],"explanation":"أبخرة الديزل تشتعل بسهولة، لذا يجب أن يكون المحرك مطفأً دون تدخين عند نقطة الوقود، مع وجود شخص يراقب الفوهة طوال الوقت."},"308":{"q":"أثناء التزويد بالوقود، يجب ألّا تترك الفوهة أبداً:","options":["في يدك أنت","دون مراقبة","موجهة إلى أسفل","داخل الخزان"],"explanation":"لا تترك فوهة الوقود دون مراقبة أبداً."},"309":{"q":"إنها درجة حرارة أدنى بقليل من التجمد في صباح شتوي وأنت تجري فحصك قبل الرحلة قبل رحلة طويلة. تعمل عبر حجرة المحرك وتريد التأكد من أن مركبتك لن ترتفع حرارتها أو تتجمد بمجرد انطلاقك في البرد. أي فحص يحمي نظام التبريد مباشرة من ظروف الشتاء التي تواجهها؟","options":["تأكد من امتلاء خزان سائل غسل الزجاج الأمامي حتى تتمكن من إزالة وحل الطريق عن الزجاج","املأ الرادياتير بالماء العادي حتى يصل مستوى سائل التبريد إلى الامتلاء على زجاج المراقبة","أضف زيت محرك إضافياً لأن الطقس البارد يجعل الزيت يثخن ويحترق أسرع","تحقق من أن سائل التبريد يحتوي على ما يكفي من مانع التجمد ليمنعه من التجمد في درجات الحرارة المنخفضة"],"explanation":"مانع التجمد يخفض نقطة تجمد سائل التبريد، لذا في الطقس البارد يجب أن تتأكد من وجود ما يكفي منه لمنع سائل التبريد من التجمد وتشقيق المحرك."},"310":{"q":"إنها درجة حرارة أدنى بقليل من التجمد على ممر جبلي، والثلج يتساقط، ولافتة منصوبة تقول إن السلاسل مطلوبة بعد هذه النقطة. تتوقف وتركّب سلاسل الإطارات على إطارات الدفع. ما السبب الرئيسي في أن السلاسل تساعدك على مواصلة التحرك بأمان صعوداً على المنحدر؟","options":["تعضّ في الثلج والجليد، مانحةً إطارات الدفع التماسك اللازم للإمساك بسطح زلق","تقلل مقاومة الدوران، مما يخفض استهلاك الوقود في الصعود الطويل","تتيح لك قانونياً حمل وزن أكبر على محور الدفع على طريق مغطى بالثلج","تخفف من الاهتزاز وتجعل الشاحنة تسير بصوت أهدأ فوق الثلج المتراص"],"explanation":"سلاسل الإطارات تعضّ في الثلج والجليد ليتمكن إطارا الدفع من الإمساك بسطح زلق ونقل القدرة دون انزلاق."},"311":{"q":"تقود مركبة مركّبة محمّلة على طريق سريع مقسوم ليلاً وتلاحظ سيارة الركاب أمامك تتصرف بشكل غريب. أي ملاحظة هي أقوى علامة على أن السائق أمامك قد يكون ثملاً أو ضعيف القدرة، مما يخبرك بزيادة مسافة المتابعة والاستعداد للسماح له بالابتعاد كثيراً أمامك؟","options":["تحافظ السيارة على سرعة ثابتة وتبقى في وسط مسارها عبر منحنى خفيف","تنحرف السيارة ذهاباً وإياباً عبر خطوط المسار وتستمر في التسارع والتباطؤ دون سبب واضح","تشير السيارة إلى تغيير مسارها مبكراً وتنتظر فجوة خالية قبل الانتقال","تتباطأ السيارة تدريجياً وتنتقل إلى الكتف الأيمن مع تشغيل أضواء الخطر"],"explanation":"الانحراف عبر خطوط المسار مع التسارع والتباطؤ المتقطّع غير المبرَّر علامات كلاسيكية على سائق ضعيف القدرة، لذا امنحه مساحة كبيرة."},"312":{"q":"إرسال الرسائل النصية أثناء القيادة خطير أساساً لأنه:","options":["يستنزف بطارية الشاحنة","يُبعد عينيك عن الطريق","يبطئ المحرك","يخفت أضواءك الأمامية"],"explanation":"إرسال الرسائل النصية يُبعد عينيك عن الطريق وعقلك عن القيادة."},"313":{"q":"تقود جراراً ومقطورة محمّلين على طريق ريفي عندما تلتصق دواسة التسارع فجأة بالأرضية ويستمر المحرك في التسارع حتى بعد رفع قدمك. حركة المرور خفيفة وهناك كتف مرصوف أمامك. أيٌّ هو إجراؤك الأول للأولوية لاستعادة السيطرة على المركبة؟","options":["اضغط على دواسة التسارع بسرعة بقدمك لمحاولة تحريرها، مع إبقاء الترس مشتبكاً حتى لا تفقد كبح المحرك","أطفئ المحرك فوراً بمفتاح الإشعال وأنت لا تزال في الترس حتى تتوقف عجلات الدفع عن سحب الشاحنة للأمام","انقل إلى الوضع المحايد لفصل المحرك عن عجلات الدفع، ثم استخدم الفرامل لإبطاء المركبة وإيقافها بأمان","ابقَ في الترس واعتمد فقط على ضغط فرامل خفيف وثابت للتغلب على المحرك حتى تصل إلى الكتف"],"explanation":"النقل إلى الوضع المحايد يفصل المحرك عن عجلات الدفع حتى تتمكن الفرامل من إبطاء المركبة وإيقافها عند التصاق دواسة التسارع."},"314":{"q":"تشمّ رائحة احتراق وتتوقف على جانب الطريق بأمان. عندما تفتح المقصورة، ترى ألسنة لهب تخرج من خلف لوحة القيادة بالقرب من الأسلاك، ويبدو أن دائرتي البطارية والمولّد متورطتان. لديك طفاية حريق مثبتة في المقصورة. أي إجراء يمنحك أفضل فرصة وأكثرها أماناً للسيطرة على هذا الحريق؟","options":["اترك الطاقة موصولة حتى ترى الأسلاك، ثم وجّه تياراً ثابتاً من الماء إلى قاعدة اللهب لتبريده","افتح غطاء المحرك والأبواب الخلفية على مصراعيها للسماح للحرارة والدخان بالخروج قبل فعل أي شيء آخر","أبقِ المحرك يعمل حتى يستمر المولّد في الشحن، وأخمد اللهب بقطعة قماش مبللة من مقصورتك","إن استطعت، افصل الطاقة الكهربائية (افصل البطارية/أطفئ الإشعال)، ثم أخمده بطفاية حريق من فئة B:C"],"explanation":"بالنسبة للحريق الكهربائي، افصل الطاقة أولاً إن كان ذلك آمناً لإزالة مصدر الإشعال، ثم أخمده بطفاية مصنّفة B:C بدلاً من الماء."},"315":{"q":"بعد أن تتجاوز قمة تل مباشرة، يفقد محركك القدرة وتنزلق حتى التوقف في المسار الأيمن لطريق ريفي ذي مسارين. تُشغّل أضواء الخطر وتمسك مثلثات الطوارئ. يقول زميلك في القيادة لا داعي للعجلة لأن حركة المرور خفيفة. وفق قواعد التوقف على الطريق، ما أقصى مدة يجب أن تنتظرها قبل وضع أجهزة التحذير؟","options":["خلال 10 دقائق من التوقف","خلال ساعة من التوقف، طالما بقيت أضواء الخطر مشغّلة","خلال دقيقة واحدة من التوقف","بحلول نهاية يوم قيادتك، إذ إن أضواء الخطر تحذّر حركة المرور بالفعل"],"explanation":"بعد التوقف على الطريق أو الكتف، شغّل أضواء الخطر فوراً وضع مثلثات التحذير العاكسة الثلاثة خلال 10 دقائق."},"316":{"q":"انطوت مركبتك على طريق ريفي ذي مسارين وسائق السيارة التي صدمتها منكفئ، واعٍ لكنه يشتكي من ألم في الرقبة. حركة المرور خفيفة، والطقس صافٍ، وتشمّ رائحة سائل تبريد لكنك لا ترى دخاناً أو لهباً. وفق إرشادات شرطة ولاية تكساس، متى يجب أن تسحب هذا الشخص المصاب من المركبة؟","options":["على الفور، إذ إن ألم الرقبة يعني إصابة في العمود الفقري تتطلب أن تمدده مسطحاً على الأرض","فقط إذا نشأ خطر حقيقي مثل الحريق؛ وإلا فاتركه حيث هو وانتظر مساعدة مدربة","بمجرد أن تضع مثلثاتك العاكسة الثلاثة على بُعد 10 و100 و200 قدم","كلما بدأت حركة المرور بالتكدس، حتى يُعاد فتح المسار للحفاظ على سلامة بقية السائقين"],"explanation":"لا تحرّك شخصاً مصاباً إلا إذا هدده خطر حقيقي مثل الحريق، لأن تحريك شخص لديه إصابة في الرقبة أو العمود الفقري قد يسبب شللاً دائماً."},"317":{"q":"إنها الساعة 5:30 صباحاً ولديك موعد تسليم نهائي. الليلة الماضية شربت عدة جعات وتوقفت عن الشرب قبل نحو أربع ساعات. لتشعر بأنك مستعد للقيادة، تشرب قهوتين سوداوين كبيرتين، وتمشي بنشاط في هواء الصباح البارد، وتتفقد مقياس الحرارة في المقصورة. أيٌّ من هذه الأمور سيخفض فعلاً الكحول الباقي في مجرى دمك حتى تكون آمناً وقانونياً لتشغيل مركبتك التجارية؟","options":["هواء الصباح البارد، لأن التنفس العميق للهواء النقي يساعد الجسم على طرد الكحول أسرع","القهوتان السوداوان الكبيرتان، لأن الكافيين يسرّع الأيض ويحرق الكحول المتبقي","لا شيء من تلك الأفعال؛ فمرور وقت كافٍ فقط هو ما يزيل الكحول من دمك ويُنزل نسبته دون حد 0.04%","الثلاثة معاً، إذ إن القهوة والهواء البارد واليقظة تجتمع لإفاقتك قبل مناوبتك"],"explanation":"الوقت وحده هو ما يتيح للكبد استقلاب الكحول وخفض نسبته في الدم؛ ولا يمكن للقهوة أو الهواء النقي أو الشعور باليقظة تسريع العملية."},"318":{"q":"أنت في الساعة التاسعة من رحلة طويلة وتبدأ بالشعور بالنعاس. يعرض عليك زميل سائق في محطة شاحنات حبوب كافيين و\"منشطات\"، مدّعياً أنها ستبقيك يقظاً بما يكفي لإنهاء رحلتك بأمان. أيٌّ مما يلي هو أفضل سبب لرفضها والتوقف للراحة بدلاً من ذلك؟","options":["المنشطات لا بأس بها طالما تشرب أيضاً قهوة وتستنشق بعض الهواء النقي لموازنتها","المنشطات تحدّ من زمن رد فعلك وتحسّن رؤيتك الليلية، لكن حملها في المقصورة غير قانوني","المنشطات مقبولة فقط على المنحدرات الأطول من 419 قدماً حيث تحتاج إلى يقظة إضافية","المنشطات لا تجعلك سائقاً آمناً؛ فعندما يزول مفعولها قد تكون أكثر إرهاقاً وخطورة مما كنت قبلها"],"explanation":"المنشطات تُخفي الإرهاق مؤقتاً فقط ولا تجعلك آمناً؛ فعندما يزول مفعولها قد تصبح أكثر إرهاقاً وخطورة مما كنت قبلها."},"319":{"q":"تقود في المسار الأيمن لطريق سريع من أربعة مسارات بسرعة 55 ميلاً في الساعة. على بُعد نحو ربع ميل أمامك، ترى سيارة معطلة متوقفة على الكتف الأيمن مع تشغيل أضواء الخطر، وشخصاً يقف بجانبها قرب صندوق الأمتعة. لماذا يجب أن تعامل هذا كخطر وتبدأ بالتكيّف الآن، بدلاً من الانتظار حتى تقترب أكثر؟","options":["السيارة المتوقفة أو الشخص بجانبها قد ينتقلان فجأة إلى مسارك، لذا عليك أن تبطئ وتزيد مساحة متابعتك وتنتقل يساراً إن كان ذلك آمناً.","الكتف هو منطقة السير القانونية لحركة المرور البطيئة، لذا يجب أن تنتقل إليه لتمنح السيارة المعطلة المسار الكامل.","يكون خطراً فقط إذا أخفق السائق في وضع مثلثات التحذير الثلاثة على بُعد 10 و100 و200 قدم، وإلا يمكنك الحفاظ على سرعتك.","السيارة المعطلة على الكتف لا تشكّل خطراً حقيقياً طالما أضواء الخطر مشغّلة، لذا لا حاجة لتغيير السرعة أو الموضع."],"explanation":"السيارة المتوقفة أو الشخص بجانبها قد يدخلان مسارك فجأة، لذا أبطئ وزِد مساحة متابعتك وانتقل يساراً عندما يكون ذلك آمناً."},"320":{"q":"تتوقف عند منطقة استراحة في منتصف الطريق، وقبل أن تصعد إلى المقصورة تنحني وتلقي نظرة سريعة أسفل جرارك ومقطورتك. بخلاف التأكد من عدم وجود ما يُجرّ، ما السبب الرئيسي للسلامة الذي يوصي الدليل من أجله بهذه النظرة القصيرة على مستوى الأرض تحت المركبة عند التوقف؟","options":["تتيح لك قراءة مقياس عمق نقش الإطار للتأكد من أن إطارات التوجيه لا يزال بها 4/32 بوصة على الأقل","يمكن أن تكشف عن تسريبات سائل جديدة، أو إطار ناقص النفخ أو مثقوب، أو أشخاص أو أشياء قد تكون أسفل المركبة أو خلفها قبل أن تتحرك","تستوفي شرط إعادة فحص حمولتك وإعادة تثبيتها خلال أول 50 ميلاً من الرحلة","إنها طريقة وضع مثلثات التحذير الثلاثة على بُعد 10 و100 و200 قدم قبل الانطلاق"],"explanation":"الفحص على مستوى الأرض قبل التحرك يكشف عن تسريبات سائل جديدة، وإطار مثقوب أو ناقص النفخ، وأشخاص أو أشياء أسفل المركبة أو خلفها."},"321":{"q":"تنقل مقطورة محمّلة وتصل إلى قمة منحدر جبلي طويل وشديد الانحدار. لافتة منصوبة تحذّر من منحدر بنسبة 6% أمامك. لمنع فراملك من التلاشي أثناء النزول، متى يجب أن تختار الترس المنخفض الذي ستستخدمه للنزول؟","options":["عند النقطة التي تشعر فيها لأول مرة بأن الفرامل بدأت بالسخونة الزائدة والتلاشي","في منتصف المنحدر تقريباً، بمجرد أن تتمكن من تقدير مدى انحداره فعلاً","قبل أن تبدأ النزول على المنحدر، بينما لا تزال في القمة","فقط إذا انزاحت الحمولة أو ارتفعت سرعتك فوق مستوى آمن"],"explanation":"اختر ترساً منخفضاً قبل البدء بالنزول على منحدر طويل وشديد الانحدار، بينما لا تزال في القمة."},"322":{"q":"تنقل مقطورة محمّلة نزولاً على منحدر جبلي طويل وشديد الانحدار. في منتصف الطريق تقريباً تلاحظ رائحة فرامل ساخنة وتبدأ الدواسة بالشعور بأنها أكثر ليونة مما كانت في القمة. من بين ما يلي، أي إجراء يمنحك السيطرة الأكثر أماناً على سرعتك لبقية النزول؟","options":["اضغط واستمر بضغط ثابت وقوي على دواسة الفرامل طوال الطريق إلى الأسفل لتثبيت السرعة","انقل إلى الوضع المحايد حتى يبرد المحرك، ثم استخدم الفرامل بخفة حتى القاع","اضغط على دواسة الفرامل بسرعة لإعادة بناء ضغط الهواء واستعادة دواسة قوية","ابقَ في ترس منخفض ليساعد المحرك على كبحك، واستخدم تطبيقات فرامل خفيفة ومتقطعة فقط"],"explanation":"كبح المحرك والترس هو وسيلة التحكم الأساسية في السرعة على المنحدر، لذا ابقَ في ترس منخفض واستخدم تطبيقات فرامل خفيفة ومتقطعة فقط للسماح للفرامل بالتبريد."},"323":{"q":"تنقل مقطورة محمّلة نزولاً على منحدر جبلي طويل وشديد الانحدار. للتحكم في سرعتك، تضغط ضغطاً ثابتاً ومتواصلاً على فرامل الخدمة طوال الطريق إلى الأسفل بدلاً من الاعتماد على ترس منخفض. وأنت تقترب من القاع، ما النتيجة الأكثر احتمالاً لاستخدام فراملك بهذه الطريقة؟","options":["سترتفع حرارة الفرامل وتتلاشى، فاقدةً قوة الإيقاف عندما تحتاج إليها أكثر","ستمسك الفرامل بقوة أكبر كلما طال تطبيقها، مانحةً إياك تحكماً إضافياً","تدفّق الهواء المتواصل فوق الطبول سيبقي الفرامل باردة وتعمل بشكل طبيعي","ستتآكل الفرامل بالتساوي وتدوم أطول لأن الضغط سلس وثابت"],"explanation":"الكبح الثابت المتواصل على منحدر طويل يبني الحرارة أسرع مما يمكن تبديدها، فترتفع حرارة الفرامل وتتلاشى فاقدةً قوة الإيقاف."},"324":{"q":"تنزل على منحدر جبلي طويل وشديد الانحدار بمقطورة محمّلة بالكامل. في منتصف الطريق تشمّ رائحة احتراق خفيفة، ودواسة فراملك تصبح لينة، والشاحنة تواصل اكتساب السرعة رغم ضغطك على الفرامل. أمامك لافتة تقول \"منحدر هروب الشاحنات على بُعد ميل واحد\". ما الغرض الرئيسي من ذلك المنحدر، ولماذا قد تحتاج إليه هنا؟","options":["إنه مكان وقوف مخصص يجب أن تركن فيه وتترك فراملك تبرد لمدة 30 دقيقة قبل متابعة النزول.","إنه مبني لإيقاف مركبة هاربة فقدت القدرة على الكبح بأمان، مثلما يحدث عند تلاشي الفرامل وارتفاع حرارتها على منحدر طويل.","إنه مسار التفافي لمحطة الوزن حيث تؤكد الشاحنات النازلة أوزان محاورها قبل الوصول إلى قاع المنحدر.","إنه نقطة دوران للشاحنات كبيرة الحجم التي لا يمكنها إكمال بقية المنحدر الشديد بأمان."],"explanation":"منحدر الهروب مبني لإيقاف مركبة هاربة فقدت القدرة على الكبح بأمان، مثلاً بسبب ارتفاع حرارة الفرامل وتلاشيها على منحدر طويل."},"325":{"q":"يجب أن تتوقف دائمًا قبل معبر السكة الحديدية إذا كنت تنقل:","options":["مقطورة صندوقية فارغة","مواد خطرة تحمل لوحات تحذيرية","حمولة خفيفة وجافة","بضائع عامة اعتيادية"],"explanation":"توقف عند المعابر عندما تنقل مواد خطرة تحمل لوحات تحذيرية أو ركابًا."},"326":{"q":"يجب ألا تغيّر التروس أبدًا أثناء:","options":["صعود تل طويل","عبور قضبان السكة الحديدية","القيادة فوق جسر","الاندماج في طريق"],"explanation":"لا تغيّر التروس فوق القضبان؛ فقد تتوقف المركبة على المعبر."},"327":{"q":"أنت متوقف عند معبر سكة حديدية متعدد القضبان لا توجد فيه بوابات أو إشارات. يمرّ قطار شحن بقوة على القضيب القريب ثم يبتعد أخيرًا إلى يسارك. الرؤية على طول القضيبين محجوبة جزئيًا بالأشجار، وترى أن لديك مساحة كافية لتجاوز جميع القضبان بالكامل بطول مركبتك كاملًا ونحو 15 قدمًا إضافية. قبل أن تحرر الفرامل وتبدأ العبور، ما أهم شيء يجب فعله؟","options":["انقل إلى أدنى ترس لديك لتحصل على أقصى قوة جر أثناء عبور القضبان","تأكد من أن أذرع البوابة المطلية للمعبر مرفوعة بالكامل قبل المتابعة","افحص القضيب الثاني في الاتجاهين بحثًا عن قطار آخر ربما أخفاه القطار الأول","انتظر 15 ثانية كاملة بعد ابتعاد القطار، ثم تابع دون فحص إضافي"],"explanation":"قد يكون هناك قطار ثانٍ مخفي خلف القطار الذي مرّ للتو، لذا انظر في كلا الاتجاهين على كل قضيب قبل العبور."},"328":{"q":"لم تمطر منطقة توصيلك منذ ما يقارب ثلاثة أسابيع، وبدأ مطر خفيف يتساقط للتو بينما تنعطف إلى طريق مزدحم بحارتين. تشعر فورًا بأن المقطورة تصبح غير مستقرة عند الكبح الخفيف، رغم أن الرصيف يبدو مبتلًا بالكاد. لماذا يكون هذا المطر الخفيف المبكر أكثر خطورة على تماسك مركبتك من هطول غزير لاحق في العاصفة نفسها؟","options":["تبرّد طبقة الماء الرقيقة الرصيف، مما يصلّب مطاط إطاراتك ويقلل من التماسك","لا يستطيع المطر الخفيف غسل الطريق، لذا فإن هطولًا غزيرًا لاحقًا سيمنح إطاراتك تماسكًا أفضل فعليًا","يرفع المطر الخفيف ضغط الإطارات، وتسير الإطارات المفرطة النفخ على مساحة تلامس أصغر","يختلط الماء الأول بالزيت والغبار المتراكمين على الطريق الجاف، فيطفو بهما كطبقة زلقة قبل أن يتمكن مطر أغزر من غسلها"],"explanation":"يكون المطر الأول بعد فترة جفاف زلقًا لأن الماء الخفيف يختلط بالزيت والغبار المتراكمين، مكوّنًا طبقة زلقة قبل أن يتمكن مطر أغزر من غسلها."},"329":{"q":"عبرت للتو معبرًا منخفضًا مغمورًا بالمياه حيث كان الماء عميقًا بما يكفي ليصل إلى محاور عجلاتك. وبينما تتسارع عائدًا إلى الطريق السريع الجاف وتقترب من تقاطع على بُعد ربع ميل، يكشف توقفك الأول عن دواسة فرامل لينة وضعيفة. ما الإجراء الصحيح لاستعادة الكبح قبل أن تعتمد على الفرامل بسرعة؟","options":["قُد بسرعة بطيئة مع الضغط بلطف وخفة على الفرامل لاختبارها وتجفيفها بحرارة الاحتكاك","اضغط على دواسة الفرامل بقوة وسرعة لإخراج الماء من الطبول قبل التوقف التالي","تسارع إلى سرعة الطريق السريع كي يجفف الهواء وحرارة المحرك الفرامل بسرعة","أوقف المحرك وانزلق لتترك الفرامل تجف بالهواء طبيعيًا قبل المتابعة"],"explanation":"بعد أن يبلّل الماء العميق بطانات الفرامل، قُد ببطء مع الضغط بلطف وخفة كي تجففها حرارة الاحتكاك وتعيد الكبح الطبيعي."},"330":{"q":"أنت تنقل حمولة جزئية على طريق سريع بين الولايات أثناء مطر مستمر بسرعة 50 ميلًا في الساعة. يبدو الطريق أمامك كأنه صفيحة ماء متصلة وتشعر بطبقة خفيفة تتكوّن بين إطاراتك والرصيف. فجأة تشعر بأن عجلة القيادة مختلفة في يديك. أي تغيّر سيكون أوضح تحذير بأن إطاراتك فقدت تماسكها وقد تكون بدأت بالانزلاق المائي؟","options":["تقاوم العجلة فجأة وتبدو ثقيلة وقاسية ويصعب تدويرها","تبدو العجلة فجأة خفيفة وسهلة التدوير، كأنها أصبحت مرتخية","تسمع المحرك يصبح أعلى صوتًا بوضوح رغم أن سرعتك ثابتة","تلاحظ رائحة وقود قوية تتسرب عبر فتحات تهوية المقصورة"],"explanation":"عندما تفقد الإطارات تماسكها على سطح مبتل وتسير على طبقة من الماء، تصبح القيادة فجأة خفيفة وسهلة التدوير."},"331":{"q":"خرجت من الخدمة الساعة 6:00 مساءً وأخذت راحة كاملة مدتها 10 ساعات، ثم دخلت الخدمة الساعة 4:00 صباحًا وقدت دون توقف. يضغط عليك مرسل لتواصل القيادة لأنه، حسب قوله، لا تزال لديك ساعات متبقية في نافذة الـ14 ساعة. بصرف النظر عن نافذة الخدمة البالغة 14 ساعة، ما الحد الأقصى لعدد الساعات المسموح لك فعليًا بقضائها في القيادة خلال نوبة العمل هذه؟","options":["8 ساعات قيادة، لأن ذلك هو الوقت الذي تصبح فيه راحة الـ30 دقيقة إلزامية وتنتهي نوبتك فعليًا","14 ساعة قيادة، بما أن نافذة الـ14 ساعة هي ما يتحكم فعلًا في مدة بقائك خلف المقود","11 ساعة قيادة، لأنه بعد 10 ساعات متتالية خارج الخدمة يجوز لك القيادة بحد أقصى 11 ساعة","16 ساعة قيادة، طالما بقيت ضمن نافذة الخدمة البالغة 14 ساعة"],"explanation":"بعد 10 ساعات متتالية خارج الخدمة، يجوز لك القيادة بحد أقصى 11 ساعة، وهي منفصلة عن حد نافذة الخدمة البالغة 14 ساعة."},"332":{"q":"دخلت الخدمة الساعة 6:00 صباحًا. بعد التحميل والانتظار، بدأت القيادة أخيرًا الساعة 9:00 صباحًا. لم تقد سوى نحو 5 ساعات إجمالًا وأخذت راحة مدتها 30 دقيقة، لذا تشعر بأنه لا يزال لديك وقت قيادة قانوني وفير في يومك. مع اقتراب الساعة من 8:00 مساءً، أي عبارة تصف بشكل صحيح متى يجب أن تتوقف عن القيادة لهذه النوبة؟","options":["يجوز لك مواصلة القيادة حتى تسجّل 6 ساعات فعلية خلف المقود، لأن وقت القيادة هو ما يتحكم به الحد فعلًا.","يجوز لك مواصلة القيادة طالما لم تتجاوز 10 ساعات من وقت الخدمة، لأن ساعة الخدمة هي ما يوقفك.","يجوز لك مواصلة القيادة بعد الساعة 8:00 مساءً لأن راحتك البالغة 30 دقيقة أوقفت الساعة ودفعت موعد توقفك إلى وقت لاحق من المساء.","لا يجوز لك القيادة إطلاقًا بعد الساعة 8:00 مساءً، لأن تلك هي الساعة الرابعة عشرة بعد دخولك الخدمة، بغضّ النظر عن قِلّة الساعات التي قدتها فعلًا."],"explanation":"لا يجوز لك القيادة بعد الساعة الرابعة عشرة التي تلي وقت دخولك الخدمة، مهما كان مقدار ما قدته فعلًا قليلًا."},"333":{"q":"أنت تُحمّل شاحنة مسطحة لرحلة طولها 300 ميل. لقد وازنت الوزن فوق المحاور، وغطّيت الحمولة بقماش مشمّع لإبقائها جافة، وتفي روابطك بحد حمولة العمل. وبينما تقوم بجولة تفقد أخيرة، تُذكّر نفسك بأهم سبب منفرد يوجب تأمين الحمولة جيدًا قبل أن تنطلق إلى الطريق السريع. أي عبارة تعبّر عن هذا السبب على أفضل وجه؟","options":["يجب منع الحمولة المؤمّنة من الانزلاق أو السقوط أو حجب رؤيتك للطريق","يجب إبقاء الحمولة المؤمّنة مخفية تمامًا تحت القماش المشمّع كي لا تُرى من خارج المركبة","يجب ترتيب الحمولة المؤمّنة بحيث يمكن وزنها بسرعة في محطة التفتيش التالية","يجب تحميل الحمولة المؤمّنة بحيث تكون الروابط مرئية للضباط من جهة الراكب"],"explanation":"يجب تأمين الحمولة بحيث لا يمكن أن تنزلق أو تسقط أو تحجب رؤيتك للطريق."},"334":{"q":"تستلم حمولة في اللحظة الأخيرة فيحمّلها الشاحن أثقل مما تظهر بيانات شحنتك، مما يجعلك تتجاوز قليلًا الوزن الإجمالي المسموح لمركبتك. يقول المرسل إنها \"زيادة قليلة فقط\" ويطلب منك نقلها. وبينما تنعطف إلى الطريق السريع، أي تأثير لهذا الحمل الزائد يجب أن يقلقك أكثر من ناحية السلامة؟","options":["سيضغط الوزن الزائد على الإطارات بقوة أكبر، مما يمنحك تماسكًا أكثر ومسافة توقف أقصر","ستصبح المركبة أصعب في التوجيه وستستغرق وقتًا أطول للتوقف لأن الوزن المضاف يعمل ضد توجيهك وفرامِلك","يخفض الوزن المضاف مركز الثقل، فتصبح الشاحنة أكثر استقرارًا وأقل عرضة للانقلاب بكثير","يتحسن استهلاك الوقود لأن المحرك يعمل بحمل أكثر ثباتًا عندما تكون الشاحنة محمّلة بالكامل"],"explanation":"يجعل الوزن المفرط المركبة أصعب في التوجيه ويزيد مسافة التوقف لأن الكتلة المضافة تعمل ضد التوجيه والفرامل."},"335":{"q":"أثناء فحص ما قبل الرحلة عند رصيف تحميل في تكساس، تجد أن قطعتين من أنابيب الفولاذ تمتدان نحو أربعة أقدام خلف مؤخرة مقطورتك المسطحة. الحمولة مؤمّنة جيدًا بالروابط، وأوراقك بنظام، وأنت على وشك الانطلاق في رحلة نهارية. فيما يخص الجزء من الحمولة الذي يبرز خلف المؤخرة، ماذا تتطلب اللوائح الفيدرالية/لوائح تكساس منك فعله قبل القيادة؟","options":["لا يلزم شيء إضافي، لأن البروز أقل من خمسة أقدام والحمولة مؤمّنة بالفعل بالعدد الصحيح من الروابط","أضف رابطًا إضافيًا واحدًا للقسم البارز واطلِ الأطراف البارزة بلون داكن كي تكون أقل تشتيتًا لحركة المرور","علّم الحمولة البارزة كي تكون مرئية — استخدم أعلامًا (وأضواء إن كانت الرؤية ضعيفة أو ليلًا) على الجزء الممتد خلف المؤخرة","أعد فحص التأمين خلال أول 50 ميلًا، لكن لا يلزم تعليم البروز لأن الحمولة مربوطة بالكامل"],"explanation":"يجب تعليم الحمولة الممتدة خلف المؤخرة كي تكون مرئية — بالأعلام نهارًا وبالأضواء عندما تكون الرؤية ضعيفة أو ليلًا."},"336":{"q":"عند رصيف شحن، يقوم طاقم المستودع بتحميل وتقييد شاحنة مسطحة من أنابيب الفولاذ من أجلك، ويوقّع مشرف الرصيف على بوليصة الشحن، ويصادف وجود ضابط من إدارة النقل واقفًا قريبًا. تظنّ أن اثنين من الروابط يبدوان مرتخيين. بموجب القواعد الفيدرالية وقواعد تكساس، من المسؤول في النهاية عن التأكد من تأمين هذه الحمولة جيدًا وأنها ضمن حدود الوزن القانونية قبل انطلاقك؟","options":["الشاحن وطاقم المستودع، لأنهم هم من حمّلوا الحمولة وقيّدوها فعليًا","مشرف الرصيف، لأن توقيعه على بوليصة الشحن يصادق على الحمولة","ضابط إدارة النقل الواقف قريبًا، بما أن إنفاذ قواعد التأمين هو عمله","أنت، السائق، لأنك مسؤول عن حمولة آمنة وقانونية بغضّ النظر عمّن حمّلها"],"explanation":"السائق مسؤول عن حمولة آمنة وقانونية بغضّ النظر عمّن قام بالتحميل فعليًا."},"337":{"q":"حمّلت لفائف فولاذية في الساحة وانعطفت للتو إلى الطريق السريع بين الولايات. شعرت بأن الحمولة متماسكة عند تأمينها، لكنك تعلم أن الروابط والحمولة قد تنزلق بمجرد أن تبدأ المركبة بالتحرك وتستقر السلاسل. للبقاء قانونيًا وآمنًا، في غضون كم يجب أن تقوم بأول توقف لإعادة فحص تأمين الحمولة؟","options":["خلال أول 50 ميلًا بعد بدء الرحلة","خلال أول 150 ميلًا بعد بدء الرحلة","خلال أول 3 ساعات من القيادة، بغضّ النظر عن المسافة","فقط بعد أول استراحة أو توقف للتزود بالوقود"],"explanation":"يجب أن تفحص الحمولة وتأمينها خلال أول 50 ميلًا بعد بدء الرحلة."},"338":{"q":"كم تقريبًا تتيح لك المصابيح الأمامية المنخفضة أن ترى المسافة أمامك؟","options":["نحو 100 قدم","نحو 250 قدمًا","نحو 600 قدم","نحو ميل واحد"],"explanation":"تضيء المصابيح المنخفضة نحو 250 قدمًا أمامك."},"339":{"q":"إنها ليلة بلا قمر وأنت تقود شاحنة مسطحة فارغة على طريق ريفي بحارتين بلا أضواء شارع. تضيء مصابيحك المنخفضة نحو 250 قدمًا من الطريق أمامك، لكن لا يمكنك قانونيًا استخدام المصابيح العالية لأن المركبات القادمة تظهر باستمرار. لتجنب الخروج عن الطريق أو الاصطدام بخطر غير مرئي، يجب أن تتحكم في سرعتك أي قاعدة منفردة؟","options":["يجوز لك الحفاظ على السرعة المحددة طالما أن مصابيحك الأمامية وأضواء الفرامل تعمل بشكل سليم","يجب أن تكون سرعتك بطيئة بما يكفي لتتمكن من التوقف ضمن المسافة التي تضيئها مصابيحك أمامك","ينبغي أن تبقي سرعتك بطيئة بما يكفي لقراءة كل لافتة طريق قبل أن تتجاوزها","يمكنك القيادة أسرع لأن المقطورة الفارغة تمنحك مسافة توقف أقصر من المحمّلة"],"explanation":"لا تقُد أبدًا بسرعة تتجاوز مدى مصابيحك — يجب أن تتيح لك سرعتك التوقف ضمن المسافة التي تكشفها أضواؤك أمامك."},"340":{"q":"أنت تقود مقطورة محمّلة على طريق مظلم بحارتين بعد منتصف الليل بقليل. تُبقي سيارة قادمة مصابيحها العالية مضاءة وترفض خفضها، والوهج يفقدك رؤيتك. لقد ومضت بأضوائك بالفعل لتذكير السائق، دون نتيجة. حتى تمرّ تلك السيارة، ما أفضل شيء تفعله بعينيك للحفاظ على السيطرة على حارتك؟","options":["حدّق مباشرة في المصابيح القادمة كي تقدّر بالضبط متى ستمرّ السيارة بجانبك","انظر إلى السماء فوق المصابيح كي يبتعد الضوء الساطع عن خط نظرك المباشر","حوّل نظرك إلى الأسفل وإلى الحافة اليمنى من حارتك واستخدمها للتوجيه حتى تمرّ السيارة","اخفض عينيك إلى لوحة العدّادات الثابتة حتى لا تعود المصابيح أمامك"],"explanation":"عندما تُعمى بمصابيح عالية قادمة، انظر نحو الحافة اليمنى من حارتك واستخدمها للتوجيه حتى تمرّ المركبة."},"341":{"q":"أنزلت للتو حمولتك بالكامل في مستودع وأنت الآن تقود المركبة الفارغة بلا مقطورة عائدًا إلى الساحة. عند الاقتراب من إشارة حمراء، تكبح بالطريقة نفسها التي كنت تكبح بها وأنت محمّل بالكامل، فتُقفل عجلاتك فجأة وتبدأ بالانزلاق. لماذا تتعامل هذه الشاحنة الفارغة مع الكبح بشكل أسوأ مما كانت عليه وهي محمّلة؟","options":["كلما كانت المركبة أثقل، استغرق توقفها وقتًا أطول، لذا يُفترض أن تتوقف الشاحنة الفارغة بسهولة أكبر من المحمّلة","تُزوَّد الشاحنات الفارغة بفرامل أصغر وأضعف لا تستطيع توليد قوة كافية لإبطاء المركبة","مع عدم وجود حمولة، يجعل مركز الثقل الأعلى الشاحنة تتدحرج للأمام وتُثقل الفرامل الأمامية","مع قلة الوزن الضاغط على الإطارات نحو الطريق، يكون للإطارات تماسك أقل وتصبح أكثر عرضة للإقفال والانزلاق"],"explanation":"للشاحنة الفارغة وزن قليل يضغط على الإطارات نحو الطريق، فيقل تماسكها وتُقفل وتنزلق بسهولة أكبر."},"342":{"q":"ظل مطر مستمر يتساقط والرصيف مبتل بوضوح لكنه لم يُغطَّ بعد بمياه راكدة أو وحل. لا تزال حركة المرور حولك تتحرك قرب الحد المسموح البالغ 60 ميلًا في الساعة. للحفاظ على هامش أمان للسيطرة على هذا السطح المبتل، بأي مقدار تقريبًا ينبغي أن تخفض سرعتك دون ما كنت ستقوده بأمان على الطريق نفسه وهو جاف؟","options":["نحو الثلث أبطأ من سرعتك الآمنة على الطريق الجاف","نحو النصف أبطأ من سرعتك الآمنة على الطريق الجاف","نحو ثلاثة أرباع أبطأ من سرعتك الآمنة على الطريق الجاف","لا حاجة لأي تخفيض طالما لم تتكوّن مياه راكدة ووحل"],"explanation":"على الطرق المبتلة، خفّض سرعتك بنحو الثلث مقارنة بسرعتك الآمنة على الطريق الجاف للحفاظ على تماسك كافٍ."},"343":{"q":"أنت تقود مبرّدة محمّلة على طريق ريفي بحارتين عندما تنخفض درجة الحرارة ويبدأ ثلج مستمر بالتراكم، تاركًا طبقة بيضاء مرصوصة بإحكام على الطريق. حركة المرور تسير بشكل جيد، والطريق ليس جليديًا، ولا تزال ترى بوضوح. للحفاظ على هامش أمان على هذا السطح من الثلج المرصوص، بأي مقدار تقريبًا ينبغي أن تخفض سرعتك المعتادة على الطريق الجاف؟","options":["خفّض سرعتك بنحو الربع","خفّض سرعتك بنحو النصف","خفّض سرعتك بنحو العُشر","حافظ على سرعتك المعتادة بما أن الطريق ليس جليديًا والرؤية جيدة"],"explanation":"على الثلج المرصوص، خفّض سرعتك بنحو النصف لأن التماسك يقل بشدة وتزداد مسافة التوقف."},"344":{"q":"إنها درجة حرارة دون التجمد بقليل عند الفجر وأنت تقود مركبة مركّبة محمّلة على جسر. يبدو الرصيف أمامك داكنًا وأملس ومبتلًا، لكنك تلاحظ عدم وجود رذاذ يتطاير من إطارات السيارة أمامك. لماذا يُعدّ هذا النوع من الأسطح من أخطر مخاطر الشتاء؟","options":["إنه ساطع وواضح، لذا يكبح السائقون بقوة مفرطة ويفقدون التماسك على طريق جليدي واضح","يتكوّن فقط في أكثر فترات بعد ظهيرة الصيف دفئًا عندما يرشح القار من خلال الرصيف","يبدو كطريق مبتل غير ضار لكنه في الواقع طبقة رقيقة شفافة من الجليد لا تعطي أي تحذير تقريبًا","يذيب القار تحته، تاركًا طبقة زيتية زلقة يسهل رؤيتها والتوجيه حولها"],"explanation":"الجليد الأسود طبقة رقيقة شفافة من الجليد تجعل الطريق يبدو مبتلًا فحسب ولا تعطي أي تحذير تقريبًا."},"345":{"q":"أنت تقود مقطورة محمّلة على طريق ريفي بحارتين عندما تضرب هبّة رياح جانبية قوية مفاجئة جانب مقطورتك فتنتفض عجلة القيادة في قبضتك. للحفاظ على أفضل سيطرة وللاستعداد للتوجيه المضاد إذا دفعتك الرياح نحو الكتف، كيف ينبغي أن تكون يداك على عجلة القيادة؟","options":["أبقِ يدًا واحدة في أعلى العجلة لأكبر قدرة على الرفع وأرِح اليد الأخرى في حِجرك","أبقِ كلتا اليدين قريبتين من بعضهما قرب أعلى العجلة كي تتفاعل في أي اتجاه بسرعة","أبقِ يدًا واحدة قرب أسفل العجلة واستخدم الأخرى فقط للاستناد إلى الباب","أبقِ كلتا يديك بثبات على العجلة على جانبين متقابلين"],"explanation":"أمسك العجلة بثبات بكلتا اليدين على جانبين متقابلين كي تحافظ على السيطرة وتتمكن من التوجيه المضاد ضد المخاطر المفاجئة."},"346":{"q":"تدخل بمحطة شاحنات مزدحمة وعليك أن ترجع مقطورتك إلى مساحة وقوف ضيقة. لا يوجد مرشد متاح ومركبات أخرى متوقفة قريبًا على كلا الجانبين. لإبقاء المناورة آمنة قدر الإمكان، يجب أن تهيّئ وترجع بحيث تكون راجعًا نحو أي جانب؟","options":["نحو جانب السائق، كي تتمكن من النظر للخلف على طول المقطورة وتراقب مسارك عبر نافذة الجانب","نحو جانب الراكب، لأن المقطورة تنحرف أوسع على ذلك الجانب ويمنحك خلوصًا أكبر","نحو أي جانب يتيح لك الرجوع في خط مستقيم على منحدر الساحة","نحو جانبك الأعمى، ثم اعتمد على مراياك وجولة تفقد سريعة لتغطية ما لا تستطيع رؤيته"],"explanation":"ارجع نحو جانب السائق كي تتمكن من النظر مباشرة للخلف على طول المقطورة وترى مسارك عبر نافذة الجانب."},"347":{"q":"كلما كنت غير متأكد من الخلوص أثناء الرجوع، يجب أن:","options":["ترجع أسرع لتنتهي","تنزل وتنظر أولًا","تطلق البوق وتواصل","تغمض عينيك للحظة"],"explanation":"انزل وانظر (GOAL) قبل الرجوع وأثناءه."},"348":{"q":"تحتاج إلى إرجاع مقطورتك التي يبلغ طولها 53 قدمًا إلى رصيف تحميل ضيق على الجانب الأعمى (الأيمن)، وزميل عمل يقف قريبًا ويعرض المساعدة. وفقًا لإجراءات الرجوع الآمنة، ما السبب المنفرد الأهم لاستخدام هذا الشخص كمساعد؟","options":["يمكنه إعطاؤك إشارات يدوية كي لا تضطر إلى استخدام مراياك إطلاقًا","يمكنه مراقبة المناطق خلف مقطورتك وبجانبها التي لا يمكنك رؤيتها من المقصورة","يمكنه إيقاف حركة المرور القادمة في الشارع كي ترجع دون انتظار","يمكنه أن يتولى ويرجع المقطورة بدلًا منك إذا أصبحت الزاوية صعبة للغاية"],"explanation":"يمكن للمساعد مراقبة مناطق النقطة العمياء خلف المقطورة وبجانبها التي لا يمكنك رؤيتها من المقصورة."},"349":{"q":"أنت تقود مقطورة طولها 53 قدمًا وتقترب من انعطاف حاد إلى اليمين نحو شارع مدينة ضيق. تعلم أن المقطورة ستتعقّب نحو الداخل وقد تصعد على الرصيف إذا انعطفت بحدة مفرطة. وقفت سيارة للتو قريبًا خلفك على جانبك الأيمن. لإتمام هذا الانعطاف بأمان وقانونيًا، ماذا يجب أن تفعل؟","options":["انعطف بشكل واسع إلى اليسار قبل بدء الانعطاف كي تتوفر للمقطورة مساحة لتجاوز الرصيف","تسارع قليلًا خلال الانعطاف كي تتبع المقطورة الجرّار بشكل أضيق","انعطف من أقصى اليمين بأمان، مبقيًا مؤخرة مركبتك قريبة من الرصيف كي لا يتمكن أحد من تجاوزك على يمينك","انتقل إلى أقصى الحارة اليسرى أولًا، ثم انعطف يمينًا من هناك لتمنح المقطورة أكبر مساحة"],"explanation":"انعطف من أقصى اليمين بأمان وأبقِ المؤخرة قريبة من الرصيف كي لا يتمكن أحد من تجاوزك على يمينك."},"350":{"q":"أنت تقود شاحنة بمقطورة طولها 53 قدمًا وتحتاج إلى الانعطاف يسارًا عند تقاطع رباعي مزدحم. تتحول الإشارة إلى الأخضر وقد خلت حركة المرور القادمة. لإكمال هذا الانعطاف يسارًا بأمان ومنع العجلات الخلفية للمقطورة من قطع المسار الذي تنعطف منه، ما هي التقنية الصحيحة؟","options":["ابدأ بتوجيه مقدمة الجرار يسارًا بمجرد دخولك التقاطع حتى تتبع المقطورة مسارًا أضيق","ابقَ في أقصى المسار الأيمن طوال الانعطاف حتى تتبع العجلات الخلفية للمقطورة مسارًا واسعًا بعيدًا عن الرصيف","اقطع قطريًا عبر زاوية التقاطع لتقصير المسافة التي يجب أن تقطعها المقطورة","قُد الجرار للأمام وصل إلى منتصف التقاطع قبل أن تبدأ بإدارة عجلة القيادة يسارًا"],"explanation":"قُد للأمام حتى منتصف التقاطع قبل إدارة عجلة القيادة يسارًا حتى لا تقطع العجلات الخلفية للمقطورة الزاوية."},"351":{"q":"إنه الصباح الباكر وقد صعدت للتو إلى المقصورة لبدء رحلة طويلة. وبينما تستقر، تدرك أن المرآة اليمنى مائلة عاليًا جدًا بحيث لا تُظهر جانب مقطورتك، وتريد إصلاح ذلك. متى يكون الوقت الصحيح لإجراء هذا التعديل؟","options":["الآن، قبل بدء الرحلة، أثناء وقوف المركبة بأمان","بمجرد بلوغك سرعة الطريق السريع، حتى تُضبط المرآة على طريقة سير المقطورة تحت الحمولة","عند أول فحص إلزامي للحمولة، خلال أول 50 ميلًا من الرحلة","فقط بعد انتهائك من القيادة ودخولك ساحة الوجهة"],"explanation":"اضبط مراياك قبل الرحلة أثناء وقوف المركبة بأمان، لأنه لا يمكنك فعل ذلك بأمان أثناء الحركة."},"352":{"q":"لتحذير حركة المرور خلفك من أنك تبطئ، يمكنك:","options":["إطفاء أضوائك","الضغط الخفيف على الفرامل لإيماض الأضواء","تسريع المركبة لفترة وجيزة","التلويح من النافذة"],"explanation":"الضغط الخفيف على الفرامل يُومض أضواء الفرامل كتحذير."},"353":{"q":"انتقلت للتو إلى المسار الأيسر لتجاوز مركبة أبطأ على طريق سريع متعدد المسارات. اكتمل التجاوز وأنت الآن مستقر في المسار الجديد. وبنظرة إلى لوحة العدادات، تدرك أن إشارة الانعطاف اليسرى لا تزال تومض لأن إشارة شاحنتك، بخلاف السيارة، لم تُلغَ تلقائيًا. ماذا يجب أن تفعل أولًا؟","options":["سرّع بقوة لزيادة المسافة بينك وبين المركبة التي تجاوزتها للتو، ثم تحقق من الإشارة لاحقًا","أطفئ إشارة الانعطاف يدويًا حتى لا يُضلَّل السائقون من حولك بشأن نواياك","اكبح لإعادة فحص مراياك قبل أن تقرر ما إذا كانت الإشارة بحاجة إلى الإلغاء","اترك الإشارة مشتغلة حتى تغيّر المسار مجددًا، لأنها تُظهر أنك لا تزال تناور"],"explanation":"معظم الشاحنات الكبيرة تفتقر إلى إشارات تلغى تلقائيًا، لذا أطفئ الإشارة بعد المناورة لتجنب تضليل السائقين الآخرين."},"354":{"q":"لتحذير سائق آخر بوجودك، يمكنك:","options":["إيماض أضوائك العالية طويلًا","الضغط الخفيف على البوق","القيادة قريبًا جدًا منه","الصياح من النافذة"],"explanation":"ضغطة خفيفة على البوق يمكن أن تحذّر الآخرين بأنك قريب."},"355":{"q":"أنت تقود شاحنتك بمقطورة ليلًا على طريق سريع مظلم بمسارين والأضواء العالية مشتغلة. ترى مصابيح مركبة قادمة نحوك في المسار المقابل، لا تزال على مسافة بعيدة أمامك. عند أي نقطة يُطلب منك تخفيت أضوائك العالية إلى منخفضة حتى لا تُعمي السائق القادم؟","options":["ضمن مسافة 250 قدمًا من المركبة القادمة، لأن تلك هي المسافة التي تضيء فيها أضواؤك المنخفضة الطريق","ضمن مسافة 200 قدم من المركبة القادمة، وهي نفس المسافة التي تضع عندها أبعد مثلث تحذير","ضمن مسافة 500 قدم من المركبة القادمة (وأيضًا عند السير خلف مركبة أخرى ضمن 500 قدم)","فقط بمجرد أن تومض المركبة القادمة بأضوائها نحوك للإشارة إلى أن أضواءك ساطعة جدًا"],"explanation":"خفّت أضواءك العالية ضمن مسافة 500 قدم من مركبة قادمة وعند السير خلف مركبة أخرى ضمن 500 قدم لمنع الوهج المُعمي."},"356":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع ريفي بمسارين عندما يجبرك تحذير انخفاض سائل التبريد على التوقف. لا يوجد مخرج لعدة أميال، لكنك ترى كتفًا حصويًا عريضًا أمامك. وقبل أن تمد يدك حتى إلى مثلثات التحذير، ما هو أول شيء يجب أن تفعله لجعل التوقف آمنًا قدر الإمكان؟","options":["توقف في مسار سيرك وانصب فورًا مثلثاتك الثلاثة عند 10 و100 و200 قدم حتى يُحذَّر المرور قبل أن تفعل أي شيء آخر","تدحرج إلى التوقف عند المنعطف التالي حتى تكون مركبتك مرئية من كلا الاتجاهين، ثم شغّل مصابيحك الأمامية","أبطئ وضع المركبة فوق خط المسار حتى يبقى جزء من شاحنتك على الإسفلت، مع إبقاء الكتف خاليًا لمركبات الطوارئ","انتقل تمامًا خارج الإسفلت إلى الكتف الحصوي وشغّل أضواء الخطر الرباعية"],"explanation":"أخرج المركبة تمامًا خارج الطريق المُسلوك إلى الكتف وشغّل أضواء الخطر الرباعية فورًا لتحذير حركة المرور المقتربة."},"357":{"q":"تدخل إلى منطقة استراحة على منحدر هابط طفيف لتقوم بجولة سريعة حول المركبة وتفحص تثبيت الحمولة. لا يزال المحرك يعمل وتخطط للبقاء خارج المقصورة لدقيقة أو دقيقتين فقط. قبل أن تنزل لتخطو خارجًا، ما هو الإجراء الأهم منفردًا لمنع المركبة من التدحرج؟","options":["شغّل فرامل التوقف (اليد).","انقل ناقل الحركة إلى أدنى ترس أمامي واتركه هناك.","أدر العجلات الأمامية بحدة نحو الرصيف وشغّل أضواء الخطر الرباعية.","اضغط بثبات على فرامل الخدمة (القدم) واستمر بالضغط حتى تكون جاهزًا للعودة."],"explanation":"شغّل دائمًا فرامل التوقف قبل مغادرة المقصورة، لأنها الجهاز الوحيد المصمم لتثبيت مركبة متوقفة ميكانيكيًا دون وجود السائق."},"358":{"q":"أنت تقود شاحنة بمقطورة محمّلة على طريق سريع ريفي بسرعة 55 ميلًا في الساعة. حركة المرور خفيفة والطريق مستقيم، لذا تقرر أن تثبّت عينيك بوعي على نقطة بعيدة بما يكفي أمامك بحيث يمكنك رصد المركبات المتعطلة أو الحطام أو حركة المرور المندمجة في الوقت المناسب للتفاعل بسلاسة بدلًا من الكبح بقوة. من حيث الزمن عند هذه السرعة، إلى أي مدى أمامك يجب أن تنظر؟","options":["من 5 إلى 8 ثوانٍ أمامك، وهي نفس الفترة التي يجب أن تستخدمها لفحص مراياك","من 12 إلى 15 ثانية أمامك، وهو ما يعادل تقريبًا ربع ميل عند سرعة الطريق السريع","نحو 6 ثوانٍ أمامك، وهي مسافة التوقف الإجمالية عند سرعة 55 ميلًا في الساعة","ربع ميل كامل مقاسًا بالأقدام فقط وليس بثواني السير"],"explanation":"انظر من 12 إلى 15 ثانية أمامك، أي ما يقارب ربع ميل عند سرعة الطريق السريع، حتى ترصد المخاطر مبكرًا وتستجيب بلطف بدلًا من الذعر."},"359":{"q":"أنت تنقل حمولة من لفائف الفولاذ على مقطورة مسطحة على طريق سريع بين الولايات مزدحم بسرعة الطريق. حركة المرور كثيفة والمركبات تتنقل داخل المسارات وخارجها حولك. تريد أن تبقى مدركًا لما يحدث على جميع جوانب مركبتك حتى تتفاعل مبكرًا مع سيارة تتداخل أو مشكلة في إطار مقطورتك. أي نهج لاستخدام مراياك يناسب أكثر ممارسة القيادة التجارية الآمنة؟","options":["انظر إلى مراياك مرة واحدة بعد كل اندماج أو تغيير مسار، لأن تلك هي اللحظة الأرجح لوجود مركبات أخرى بجانبك","انتظر حتى تشعر بشد المقطورة أو تسمع صوتًا غير عادي قبل الفحص، حتى تبقي عينيك على الطريق أمامك بقية الوقت","افحص مراياك بانتظام، نحو كل 5 إلى 8 ثوانٍ، حتى تتابع باستمرار حركة المرور وحالة مركبتك على جميع الجوانب","افحص مراياك فقط في بداية الرحلة ونهايتها، وركّز بقية الوقت تمامًا على المسار 12 إلى 15 ثانية أمامك"],"explanation":"افحص مراياك بانتظام، نحو كل 5 إلى 8 ثوانٍ، لتبقى مدركًا لحركة المرور والمناطق العمياء وحالة مركبتك وحمولتك."},"360":{"q":"أنت تقود شاحنة بمقطورة محمّلة بسرعة ثابتة 55 ميلًا في الساعة في المسار الأيمن لطريق سريع مقسّم عندما تبدأ سيارة صغيرة بتجاوزك من جهة اليسار. في منتصف التجاوز، تتباطأ السيارة في منطقتك العمياء اليسرى وتبدو مترددة في إكمال المناورة. لإعطاء السائق المتجاوز الوضع الأكثر أمانًا وقابلية للتنبؤ، أي إجراء يجب أن تتخذه؟","options":["خفّف الضغط عن دواسة الوقود واكبح بلطف حتى تتمكن السيارة من تجاوز مصدك الأمامي أسرع","تحرك قليلًا نحو الحافة اليمنى لمسارك لتفتح مساحة أكبر على جانب السائق","سرّع لفترة وجيزة لمساعدة السيارة على إنهاء التجاوز والعودة إلى مسارك أسرع","حافظ على موقعك في منتصف مسارك وحافظ على سرعة ثابتة حتى تتجاوزك السيارة تمامًا وتعود أمامك"],"explanation":"عندما تتجاوزك مركبة أخرى، حافظ على مسارك وعلى سرعة ثابتة حتى يتمكن السائق المتجاوز من تقدير المسافة والتنبؤ بها وإكمال التجاوز بأمان."},"361":{"q":"أنت تتجه نحو ممر سفلي غير مألوف عليه لافتة ارتفاع مسموح معلنة، ومقطورتك محمّلة بكومة طويلة من الآلات المعبأة في صناديق. من بين الأرقام أدناه، أيها تحتاج إلى معرفته بيقين أكثر من غيره قبل أن تقرر القيادة تحت ذلك الجسر؟","options":["الارتفاع الإجمالي لمركبتك المحمّلة، مقاسًا من الأرض إلى أعلى نقطة فيها","الوزن الإجمالي الدقيق للتركيبة المحمّلة على الميزان","كمية الوقود الموجودة حاليًا في خزاناتك","العلامة التجارية وطراز الإطارات المركّبة على محاور الدفع لديك"],"explanation":"اعرف الارتفاع الإجمالي لمركبتك المحمّلة من الأرض إلى أعلى نقطة فيها وقارنه بالارتفاع المسموح المعلن قبل المرور تحت جسر أو ممر سفلي."},"362":{"q":"أنت توجّه مقطورة منخفضة محمّلة بحفّارة عبر حي صناعي قديم. أمامك ينخفض الطريق تحت جسر سكة حديد متهالك وعدة خطوط كهرباء علوية متدلية تعبر الشارع. قبل أن تقرر القيادة تحتها، أي قياس هو الأكثر أهمية للتحقق منه مقابل الحدود المعلنة والمعروفة لتجنب حادث خطير؟","options":["ضغط إطار محور التوجيه لديك، لأن إطارًا أماميًا منخفضًا قد يجعل المركبة تهبط وتعلق بالأسلاك","ارتفاع الخلوص العلوي لديك، بمقارنة الارتفاع الإجمالي المحمّل لمركبتك بالارتفاع المسموح المعلن للجسر والأسلاك فوقه","تصنيف الوزن الإجمالي المركّب (GCWR) لديك، للتأكد من أن الجسر والطريق يتحملان المركبة المحمّلة بأمان","مسافة سيرك خلف المركبة التي أمامك، حتى لا تُجبر على الكبح بقوة تحت المنشأة"],"explanation":"افحص ارتفاع الخلوص الإجمالي المحمّل لديك مقابل الارتفاع المسموح المعلن للجسر وارتفاع الأسلاك العلوية للتأكد من أن المركبة يمكنها المرور بأمان من تحتها."},"363":{"q":"أنت تقترب من تقاطع رباعي في مركبتك المركّبة المحمّلة عندما تتقدم سيارة ركاب على يسارك وتطالب بعدوانية بحق الأولوية الذي هو قانونيًا لك. وقد بدأت بالفعل بالإبطاء. أي إجراء هو الخيار الأفضل في هذا الموقف؟","options":["حافظ على سرعتك وتابع، لأن حق الأولوية قانونيًا لك وعلى السيارة أن تفسح الطريق","اضغط على البوق مرارًا وتابع الدخول إلى التقاطع لتفرض موقعك","افسح الطريق ودع السائق الآخر يمر، حتى لو كان حق الأولوية لك قانونيًا، لتجنب التصادم","سرّع لاجتياز التقاطع قبل أن تتمكن السيارة من دخول مسارك"],"explanation":"واجب السائق المحترف الأول هو تجنب الاصطدام، لذا افسح الطريق ودع السائق الآخر يمر حتى عندما يكون حق الأولوية لك قانونيًا."},"364":{"q":"أنت توجّه مركبتك المركّبة المحمّلة إلى عملية تسليم وجهاز تحديد المواقع يرسلك عبر جسر تابع للمقاطعة عليه حد وزن معلن أقل من وزنك الإجمالي المركّب الفعلي. يوجد مسار بديل قانوني يضيف 12 ميلًا. ماذا يجب أن تفعل؟","options":["اعبر الجسر لكن سرّع حتى يستقر وزنك الكامل على المنشأة لأقصر وقت ممكن","اعبر بزحف بطيء وثابت، لأن حدود وزن الجسور المعلنة استرشادية وتُطبَّق فقط عندما تكون الشاحنة فارغة","توقف على الجسر للتحقق من أوزان محاورك قبل متابعة العبور","لا تعبر الجسر؛ اسلك المسار البديل القانوني حتى لا تتجاوز أبدًا حد الوزن المعلن"],"explanation":"حد وزن الجسر المعلن هو حد قانوني أقصى صارم، لذا إذا تجاوز وزنك الإجمالي ذلك الحد، فلا تعبر أبدًا واسلك المسار البديل القانوني بدلًا من ذلك."},"365":{"q":"أنت تنقل حمولة ثقيلة هابطًا على منحدر جبلي طويل وشديد الانحدار. ورغم أنه يوم بارد، بعد عدة أميال تضغط على دواسة الفرامل وتلاحظ أن الشاحنة تكاد لا تبطئ وأن الفرامل تبدو ضعيفة وإسفنجية. ما هو السبب الأرجح لهذا الفقدان في قوة الكبح؟","options":["ارتفعت حرارة الفرامل من استخدامها بكثرة لفترة طويلة جدًا خلال النزول، مما تسبب في خفوت الفرامل","جمّدت حرارة الهواء الخارجي الباردة الرطوبة في خطوط الفرامل وقللت من قبضتها","بطانات الفرامل جديدة جدًا ولم تُكسَّر بعد لتقبض بشكل صحيح","كبحت بخفة وحذر شديدين، فلم تسخن البطانات بما يكفي للإمساك"],"explanation":"الكبح الثقيل المطول على منحدر طويل يرفع حرارة الفرامل، مما يفقدها الاحتكاك وقوة التوقف حتى مع الضغط على الدواسة."},"366":{"q":"بالنسبة لسائقي رخصة القيادة التجارية، استخدام هاتف محمول باليد أثناء القيادة هو:","options":["مسموح تمامًا","غير مسموح","مُشجَّع عليه","مطلوب"],"explanation":"لا يجوز لسائقي رخصة القيادة التجارية استخدام الهواتف المحمولة باليد أثناء القيادة."},"367":{"q":"أنت تنقل مقطورة محمّلة في المسار الأيمن لطريق سريع مقسّم عند الحد المعلن. سائق خلفك يلاحقك من مسافة قريبة جدًا منذ عدة أميال، ثم ينحرف حولك ويعود بحدة ويكبح ويستمر بالإيماء لك لتسرّع أو تتنحى. حركة المرور أمامك معتدلة. أي إجراء هو الطريقة الأكثر أمانًا والأفضل للتعامل مع هذا السائق العدواني؟","options":["سرّع لتجاري السائق الآخر حتى يتوقف عن ملاحقتك ويبتعد عنك","خفّف الضغط عن دواسة الوقود وزد مسافة سيرك ودع السائق العدواني يتقدم بعيدًا عنك","حافظ على موقعك بالضبط واضغط خفيفًا على فراملك للإشارة للسائق بالتراجع","انتقل يسارًا لمنع السائق العدواني من التجاوز مجددًا حتى يهدأ"],"explanation":"الاستجابة الأكثر أمانًا للسائق العدواني هي البقاء بعيدًا عن طريقه برفع قدمك عن الوقود وزيادة مسافة سيرك حتى يتقدم بعيدًا عنك."},"368":{"q":"أنهيت للتو استراحة طعام مدتها 45 دقيقة في محطة شاحنات وشاحنتك بمقطورتها المحمّلة متوقفة بشكل موازٍ على طول الكتف الأيمن لطريق خدمة. حركة المرور تمر بجانبك على يسارك. أنت جاهز لإعادة الدخول إلى مسار السير. أي تسلسل إجراءات هو الطريقة الأكثر أمانًا والصحيحة لمغادرة موقع التوقف هذا؟","options":["اخرج مباشرة بسرعة لتندمج مع الفجوة في حركة المرور، ثم شغّل إشارتك اليسرى بمجرد أن تكون متحركًا بالفعل","اضغط على البوق لتنبيه السائقين القريبين، وحرّر الفرامل، وسرّع إلى المسار دون تأخير","شغّل إشارتك اليسرى، وافحص مراياك والمنطقة المحيطة بالمركبة بحثًا عن حركة المرور والمناطق العمياء، واخرج فقط عندما يكون الطريق خاليًا","افحص فقط مرآة جانب السائق، وإذا بدت خالية، فاخرج بهدوء إلى المسار مع مراقبة الفجوة"],"explanation":"قبل مغادرة موقع التوقف، أشر أولًا، ثم افحص المرايا وجميع المناطق المحيطة بالمركبة بحثًا عن حركة المرور والمناطق العمياء، واخرج فقط عندما يكون الطريق خاليًا."},"369":{"q":"إذا تعطلت فرامل الخدمة لديك أثناء القيادة، يجب أن:","options":["تطفئ المحرك بسرعة","تخفّض الترس وتستخدم فرامل التوقف","تضغط على دواسة الوقود بشكل متكرر","تقود بيد واحدة فقط"],"explanation":"خفّض الترس واستخدم فرامل التوقف بلطف؛ وابحث عن مسار للهروب."},"370":{"q":"أنت تقود شاحنة بمقطورة محمّلة بسرعة الطريق على طريق غير مقسّم بمسارين. سيارة قادمة انحرفت عبر الخط الأوسط وهي الآن جزئيًا في مسارك وتقترب بسرعة. لا يوجد وقت للتوقف قبل الاصطدام. إلى يمينك كتف معبّد وخندق عشبي ضحل؛ وإلى يسارك المسار المقابل مع حركة المرور. أي إجراء يمنحك أفضل فرصة لتجنب اصطدام وجهًا لوجه؟","options":["توجّه يسارًا إلى المسار المقابل للالتفاف حول السيارة المنحرفة","حافظ على مسارك واكبح بأقصى قوة، مع إقفال العجلات إذا لزم الأمر","ابقَ في المنتصف وأومض بأضوائك العالية مع الحفاظ على سرعتك","توجّه يمينًا نحو الكتف، حتى لو عنى ذلك مغادرة الإسفلت"],"explanation":"عندما تنحرف مركبة قادمة إلى مسارك، توجّه يمينًا نحو الكتف، لأن السائق قد يصحح ويعود والتوجه يسارًا يخاطر باصطدام وجهًا لوجه."},"371":{"q":"أنت تقود محمّلًا بسرعة الطريق في ظهيرة يوليو الحارة عندما تسمع فجأة صوت \"انفجار\" عالٍ من مقدمة جرارك. لم تشعر بأي ارتجاج في المقعد قبل ذلك. وبينما تمسك بعجلة القيادة، أي مما يلي يخبرك بأوضح صورة بأن إطارًا أماميًا هو الذي انفجر وليس إطارًا خلفيًا؟","options":["يصبح التوجيه فجأة صعبًا جدًا وتنجذب الشاحنة بقوة نحو جانب واحد","تشعر باهتزاز ثقيل أو ارتجاج يصعد عبر المقعد وأرضية المقصورة","يبدأ مؤخر المقطورة بالتذبذب والتمايل من جانب إلى آخر","يرتفع مقياس حرارة المحرك وتبدأ الشاحنة بفقدان القوة"],"explanation":"انفجار إطار أمامي يجعل التوجيه فجأة صعبًا جدًا وينجذب بالشاحنة بقوة نحو الإطار المتعطل."},"372":{"q":"أنت تسير محمّلًا على طريق سريع مستوٍ بمسارين بسرعة نحو 50 ميلًا في الساعة عندما تشعر فجأة بمؤخر مقطورتك يبدأ بالتأرجح والتمايل من جانب إلى آخر، رغم أن عجلة القيادة لا تزال تبدو طبيعية ولم تلمس الفرامل. استنادًا إلى هذه الأعراض، أي استنتاج هو الأدق بشأن ما حدث على الأرجح؟","options":["فقد إطار أمامي (محور التوجيه) الهواء، ولهذا أصبح المؤخر يتجول عبر المسار","فشل إطار خلفي، لأن انفجار إطار خلفي عادة ما يجعل المركبة تتمايل أو تتذبذب","قفلت فرامل مقطورتك، مما يجرّ المؤخر جانبيًا","بدأت بانزلاق تسارع لعجلات الدفع ويجب أن توجّه بحدة في الاتجاه الآخر فورًا"],"explanation":"فشل إطار خلفي يجعل المركبة تتمايل أو تتذبذب بينما يظل التوجيه طبيعيًا نسبيًا."},"373":{"q":"أنت تنقل مقطورة فارغة هابطًا على طريق رطب بمسارين عندما تخرج فجأة سيارة من طريق جانبي أمامك. تدوس بقوة على دواسة الفرامل وتشعر بنظام منع انغلاق الفرامل (ABS) يعمل. أي عبارة تصف بأفضل صورة ما يفعله نظام منع انغلاق الفرامل لك في هذه اللحظة؟","options":["إنه يقلّص مسافة توقفك الإجمالية إلى نحو نصف ما كانت عليه دون ABS، حتى تتوقف قبل السيارة بكثير.","إنه يخفّض الترس تلقائيًا ويطبّق كبح المحرك ليوقف المركبة بشكل متحكم به.","إنه يمنع عجلاتك من الانغلاق حتى تتمكن من الاستمرار في التوجيه والحفاظ على السيطرة أثناء الكبح بقوة.","إنه يوزّع ضغط الفرامل حتى تتوقف المقطورة الفارغة في مسافة أقصر مما تتوقفه المحمّلة."],"explanation":"يمنع نظام منع انغلاق الفرامل العجلات من الانغلاق أثناء الكبح بقوة حتى تتمكن من الاستمرار في التوجيه والحفاظ على السيطرة لتجنب الخطر."},"374":{"q":"أنت تقود شاحنة بمقطورة محمّلة مزوّدة بفرامل منع الانغلاق (ABS) عندما تتداخل سيارة فجأة أمامك وتتوقف بشكل مفاجئ. تحتاج إلى توقف طارئ بقوة في مسارك على إسفلت جاف. مع معرفتك بكيفية تصميم نظام منع انغلاق الفرامل للعمل، أي إجراء كبح يمنحك أفضل سيطرة وأقصر توقف آمن؟","options":["اضغط على دواسة الفرامل بشكل متكرر سريع لمنع العجلات من الانغلاق، كما تفعل دون ABS","طبّق كبحًا متحكمًا به بالطعن، محرّرًا الدواسة في كل مرة تبدأ العجلات فيها بالانغلاق","اضغط على الفرامل بخفة فقط وتوجّه حول السيارة، لأن ABS يقصّر مسافة توقفك","اضغط على دواسة الفرامل بثبات للأسفل، وحافظ على ضغط مستقر، وتوجّه حسب الحاجة بينما يعمل نظام ABS"],"explanation":"مع نظام منع انغلاق الفرامل، اكبح بالضغط بثبات والحفاظ على ضغط مستقر ومتواصل أثناء التوجيه، تاركًا النظام يمنع انغلاق العجلات."},"375":{"q":"أنت تقطر مقطورة محمّلة جزئياً (بدون نظام ABS) على طريق سريع تابع للولاية عندما تخرج سيارة فجأة من طريق جانبي مباشرة أمامك. يجب عليك التوقف بأسرع ما يمكن فيزيائياً دون أن تفقد قدرتك على التوجيه لتفادي الخطر إذا لم تتمكن من التوقف في الوقت المناسب. ما طريقة الكبح التي ينبغي عليك استخدامها؟","options":["استخدم الكبح المتحكَّم به أو الكبح المتقطع (stab braking)، مع إبقاء العجلات على وشك القفل من دون أن تقفل","اضغط على المكابح إلى آخرها وثبّتها بقوة لإقفال العجلات للحصول على أقصر مسافة","اضغط على المكابح بخفة وثبات بنفس الطريقة التي تفعلها على منحدر طويل","استخدم صمام (مقبض) المقطورة فقط حتى تبقى عجلات الجرّار حرة للتوجيه"],"explanation":"بدون نظام ABS، فإن الكبح المتحكَّم به أو الكبح المتقطع الذي يُبقي العجلات على وشك القفل من دون أن تقفل يمنح أقصى قوة توقف مع الحفاظ على القدرة على التوجيه."},"376":{"q":"أنت تقود جرّاراً ومقطورة محمّلة بمكابح عادية (بدون نظام ABS) عندما تقطع سيارة طريقك فجأة ويتعيّن عليك الكبح بقوة لتفادي اصطدام. تضغط على المكابح بالكامل وتشعر بأن العجلات قد أُقفلت. لاستخدام الكبح المتقطع (stab braking) بشكل صحيح وإبقاء المركبة تحت السيطرة، ماذا ينبغي أن تفعل في اللحظة التي تُقفل فيها العجلات؟","options":["حافظ على ضغط كامل وثابت على الدوّاسة وأبقِ العجلات مقفلة حتى تتوقف توقفاً تاماً","حرّر المكابح حتى تبدأ العجلات بالدوران مجدداً، ثم أعد الضغط على المكابح بالكامل","اضغط على دوّاسة المكابح بأسرع ما يمكن، من ثلاث إلى أربع مرات في الثانية، حتى تتوقف","ارفع قدمك عن المكابح تماماً، وأطفئ المحرك، وانزلق حتى التوقف"],"explanation":"في الكبح المتقطع، تحرّر المكابح حتى تبدأ العجلات المقفلة بالدوران مجدداً لاستعادة القدرة على التوجيه، ثم تعيد الضغط على المكابح بالكامل."},"377":{"q":"أنت تتبع شاحنة محمّلة بنقل السيارات على طريق سريع جاف بأربعة مسارات بسرعة 55 ميلاً في الساعة، محافظاً على عدة ثوانٍ من الطريق المفتوح بينك وبين الشاحنة التي أمامك. تندمج فجأة شاحنة بيك أب في تلك الفجوة، وتومض أضواء الكبح لشاحنة نقل السيارات. لماذا كان الحفاظ على تلك المسافة الآمنة هو أهم شيء فعلته للتعامل مع هذا الموقف بأمان؟","options":["سمح لك بالحفاظ على سرعة 55 ميلاً في الساعة دون رفع قدمك عن دوّاسة الوقود، فاستمر تدفق حركة المرور بسلاسة خلفك","ضمن توقفاً تاماً ضمن نحو 60 قدماً، وهي مسافة التوقف الكلية عند سرعة 55 ميلاً في الساعة","منحك مساحة ووقتاً إضافيين لإدراك الخطر وردّ الفعل قبل أن تضطر إلى الكبح بقوة","أبقى فجوة الاتباع لديك أقل من ثانية واحدة، وهي المسافة التي يوصي بها الدليل لسرعات الطرق السريعة"],"explanation":"المسافة الآمنة تمنحك مساحة ووقتاً إضافيين لرصد الخطر وردّ الفعل قبل أن تضطر إلى الكبح بقوة، لأن مسافة التوقف عند سرعة الطريق السريع أطول بكثير مما تبدو عليه."},"378":{"q":"أنت تقود جرّاراً ومقطورة محمّلة بالكامل بسرعة 55 ميلاً في الساعة في ظروف جيدة وجافة عندما تكبح سيارة ركاب في المسار المجاور بقوة لتفادي الخطر نفسه الذي تراه أنتما كلاكما في اللحظة نفسها. مع معرفتك بكيفية تصرّف شاحنة محمّلة مقارنة بتلك السيارة، أي عبارة ينبغي أن توجّهك بشأن مقدار المساحة التي تتركها لنفسك؟","options":["ستتوقف الشاحنة المحمّلة والسيارة في مسافة متقاربة تقريباً، لأن كلتيهما تملكان مكابح جيدة","ستتوقف الشاحنة المحمّلة في مسافة أقصر بكثير لأن وزنها الثقيل يضغط الإطارات على الأرض لقبضة أفضل","لا فرق في الأمر، لأنه عند سرعة 55 ميلاً في الساعة تحتاج أي مركبة إلى نحو 60 قدماً للتفاعل والتوقف","تحتاج الشاحنة المحمّلة إلى مسافة أكبر بكثير للتوقف من السيارة، لذا يجب أن تترك مساحة أكبر بكثير وأن تبدأ الكبح مبكراً"],"explanation":"الكتلة والزخم الأكبر بكثير لشاحنة محمّلة يجعلان مسافة توقفها الكلية أطول بكثير من مسافة السيارة، لذا يجب أن تترك مساحة أكبر وأن تبدأ الكبح مبكراً."},"379":{"q":"أنت تسير بسرعة الطريق السريع على طريق ذي مسارين وينتقل سائق دراجة نارية إلى المسار نفسه أمامك مباشرة، راكباً قرب الحافة اليمنى من المسار. حركة المرور معتدلة وهناك منطقة تجاوز مسموح بها قادمة. ما الطريقة الأكثر أماناً لإدارة موقعك خلف هذه الدراجة النارية؟","options":["تعامل مع الدراجة النارية كمركبة كاملة الحجم: اترك لها المسار بأكمله واتبعها بمسافة إضافية لأنها تستطيع التوقف أسرع منك بكثير","اقترب منها في مسارك وشارك الجزء الأيسر المفتوح من المسار مع الدراجة النارية، لأن الدراجة لا تحتاج إلا إلى جزء من المسار","اقترب منها بمسافة اتباع طبيعية بطول سيارة، لأن الدراجة النارية أصغر وتحتاج مساحة أقل من السيارة","ابقَ قريباً واستعد للتجاوز فوراً في منطقة التجاوز، لأن البقاء خلف دراجة نارية بطيئة هو الخطر الحقيقي"],"explanation":"للدراجة النارية الحق في المسار بأكمله ويمكنها التوقف في مسافة أقصر بكثير من شاحنة ثقيلة، لذا اترك لها المسار كاملاً واتبعها بمساحة إضافية."},"380":{"q":"أنت تقترب من تقاطع ريفي في مركبتك المركّبة المحمّلة. إشارة المرور مطفأة (معطّلة تماماً) ولا توجد علامات توقف أو إفساح طريق في أي اتجاه. مع اقترابك من التقاطع، ترى شاحنة بيك أب وصلت قبلك بلحظة وهي متوقفة بالفعل عند الشارع المتقاطع على يمينك، بانتظار المتابعة. ما الإجراء الصحيح؟","options":["تابع أولاً، لأن المركبة المركّبة المحمّلة تحتاج مساحة أكبر ولها حق الأولوية على المركبات الأخف","أفسح الطريق لشاحنة البيك أب، لأنها وصلت إلى التقاطع أولاً وهي أيضاً على يمينك","تعامل مع الإشارة المطفأة على أنها ضوؤك الأخضر وتابع المرور دون إبطاء","توقّف في وسط التقاطع حتى تراك الحركة المتقاطعة قبل أن تباشر الانعطاف"],"explanation":"عند تقاطع غير منظَّم، تفسح الطريق للمركبة التي وصلت أولاً، وإذا كان الوصول متقارباً، فللمركبة التي على يمينك."},"381":{"q":"إنها الساعة 3:15 بعد الظهر في يوم عمل صافٍ وأنت تقود شاحنة مستقيمة محمّلة عبر منطقة سكنية عندما ترى منارة صفراء وامضة وعلامة منشورة لمنطقة مدرسة. حركة المرور حولك لا تزال تسير بحد السرعة الطبيعي البالغ 30 ميلاً في الساعة، والطريق أمامك يبدو خالياً. ما أفضل إجراء تتخذه؟","options":["حافظ على حد السرعة المنشور البالغ 30 ميلاً في الساعة، لأن المسار أمامك خالٍ والمركبات الأخرى لا تبطئ","انتقل إلى المسار الأيسر وتجاوز السيارات الأبطأ بسرعة لتجاوز المنطقة قبل ظهور الأطفال","قلّل سرعتك إلى ما دون الحد المنشور وافحص الأرصفة وممرات العبور بعناية بحثاً عن أطفال قد يندفعون فجأة","حافظ على سرعتك لكن شغّل الأضواء العالية حتى يرى السائقون والمشاة شاحنتك بوضوح أكبر"],"explanation":"المنارة الوامضة تعني أن منطقة المدرسة ذات السرعة المخفّضة نشطة، لذا خفّف سرعتك إلى ما دون الحد وافحص الأرصفة وممرات العبور بحثاً عن أطفال قد يندفعون فجأة."},"382":{"q":"أنت تقترب من منطقة إنشاءات على طريق سريع حيث تُظهر إشارة المسار العلوية سهماً أخضر لمسارك، لكن عامل تنظيم المرور واقفاً في الطريق يحمل لافتة \"قف\" (STOP) موجّهة نحوك. ماذا ينبغي أن تفعل؟","options":["تابع ببطء عبر المنطقة، لأن إشارة السهم الأخضر تأذن قانونياً لمسارك بالمتابعة","توقّف فقط إذا أطلق عامل التنظيم صافرة أيضاً أو لوّح بكلتا ذراعيه، وإلا اتبع السهم الأخضر","تعامل مع التعارض على أنه عطل وتابع بحذر بسرعة لا تتجاوز 15 ميلاً في الساعة","توقّف وأطع عامل تنظيم المرور، لأن توجيهات عامل التنظيم لها الأولوية حتى على الإشارات العادية"],"explanation":"توجيهات عامل تنظيم المرور لها الأولوية على جميع العلامات والإشارات لأن عامل التنظيم لديه معرفة آنية بمخاطر منطقة العمل التي لا يمكن لإشارة ثابتة أن تعكسها."},"383":{"q":"أنت تقود الجرّار والمقطورة في المسار الأيمن من طريق سريع غير مقسوم بأربعة مسارات عندما تسمع صافرة وترى سيارة إسعاف تقترب من خلفك بأضوائها الطارئة الوامضة. حركة المرور أمامك خفيفة والكتف الأيمن واسع وخالٍ. أي إجراء هو الصحيح؟","options":["أشِر، وانتقل إلى الحافة اليمنى من الطريق، وأوقف المركبة حتى تمر سيارة الإسعاف","حافظ على مسارك وسرعتك حتى تتمكن سيارة الإسعاف من التنبؤ بمسارك والالتفاف حولك","انتقل إلى المسار الأيسر وتوقف هناك لترك الجانب الأيمن مفتوحاً تماماً لسيارة الإسعاف","زِد السرعة لتبقى أمام حركة المرور وابحث عن شارع جانبي تنعطف إليه"],"explanation":"عندما تقترب مركبة طوارئ بأضواء وصافرة، أشِر، وانتقل إلى الحافة اليمنى من الطريق، وتوقّف حتى تمر."},"384":{"q":"أُسندت إليك مقطورة فان محمّلة تنقل صناديق خفيفة الوزن مكدّسة من الأرض حتى السقف، تملأ المقطورة إلى أعلاها. مقارنةً بالمقطورة نفسها وهي تنقل بضائع كثيفة وثقيلة مكدّسة على الأرض بارتفاع الركبة فقط، أي عبارة هي الأكثر دقة بشأن كيفية تأثير الحمولة العالية ذات المركز الثقيل المرتفع على قيادتك؟","options":["التكديس الأعلى يخفض مركز الثقل، لذا يمكنك أخذ المنحدرات والمنعطفات بأمان بسرعات الشاحنات المنشورة","مركز الثقل المرتفع يجعل المقطورة أكثر عرضة للانقلاب في المنعطفات وعلى المنحدرات، لذا يجب أن تبطئ جيداً قبل دخولها","لأن الحمولة خفيفة الوزن، فإن مركز الثقل لا يؤثر على خطر الانقلاب ولا يهم إلا في مسافة الكبح","مركز الثقل المرتفع يزيد بشكل أساسي مسافة توقفك، لذا فإن الخطر الحقيقي هو الاصطدام بمؤخرة المركبة التي أمامك"],"explanation":"تكديس الحمولة عالياً يرفع مركز الثقل حتى لو كانت خفيفة، مما يجعل المركبة أكثر عرضة للانقلاب في المنعطفات وعلى المنحدرات، لذا أبطئ جيداً قبلها."},"385":{"q":"أنت تقطر صهريجاً محمّلاً وتقترب من منحدر خروج على شكل ورقة برسيم منشور عليه سرعة استرشادية تبلغ 35 ميلاً في الساعة. حركة المرور خلفك كثيفة وتودّ الاستمرار في الحركة. عند مراجعة ما يتسبب غالباً في انقلاب الشاحنات، أي عامل هو أكبر مساهم منفرد ينبغي أن تقلق منه أكثر على هذا المنحدر؟","options":["حمولة موزّعة منخفضة جداً، تمنح المقطورة مركز ثقل قريباً بشكل خطير من سطح الطريق","اتباع المركبة التي أمامك بثانية كاملة بقرب مفرط أثناء دخولك المنعطف","حمل سرعتك مرتفعة جداً عبر منعطف المنحدر بدلاً من الإبطاء قبل دخوله","الكبح بلطف مفرط بمكابح المقطورة بينما لا تزال على الاقتراب المستقيم قبل المنحدر"],"explanation":"السبب الأكثر شيوعاً لانقلاب الشاحنات هو أخذ منعطف أو منحدر بسرعة مفرطة، لذا أبطئ إلى سرعة آمنة قبل دخول المنعطف، وليس أثناء وجودك فيه."},"386":{"q":"أنت تنقل حمولة عالية من صناديق آلات مكدّسة وتخرج من الطريق السريع بين الولايات إلى منحدر دخول/خروج منحنٍ منشور عليه 30 ميلاً في الساعة. شاحنتك محمّلة بشدة بمركز ثقل مرتفع. أي إجراء يمنحك أفضل حماية من الانقلاب على المنحدر؟","options":["حافظ على 30 ميلاً في الساعة بثبات لأنها سرعة المنحدر المنشورة والعلامة تأخذ الشاحنات في الحسبان بالفعل","حافظ على سرعة الطريق السريع حتى تشعر بأن المقطورة تبدأ بالميل، ثم اكبح بقوة في المنعطف","انزلق عبر المنعطف في الوضع المحايد حتى لا يدفعك المحرك أسرع","أبطئ إلى سرعة أقل بكثير من سرعة المنحدر المنشورة قبل دخولك المنعطف، لأن العلامة مضبوطة للسيارات، لا لحمولة عالية وثقيلة"],"explanation":"علامات سرعة المنحدر مضبوطة للسيارات، لذا يجب على حمولة عالية وثقيلة أن تبطئ إلى ما دون سرعة المنحدر المنشورة بكثير قبل دخول المنعطف لتفادي الانقلاب."},"387":{"q":"تُنهي عملية تسليم وتركن شاحنتك المستقيمة المحمّلة على شارع شديد الانحدار يهبط نزولاً، مقترباً بإحكام من الرصيف الأيمن. قبل أن تشدّ مكبح الركن وتغادر القمرة، تريد أن تكون العجلات الأمامية موضوعة بحيث إذا انفلتت المكابح يوماً، تتدحرج الشاحنة نحو الرصيف ويوقفها بدلاً من أن تنحرف إلى مسار حركة المرور النازل. كيف ينبغي أن تترك العجلات الأمامية ملتفّة؟","options":["ملتفّة نحو الرصيف (إلى اليمين)، حتى يتيح أي تدحرج للرصيف أن يحجز الإطار الأمامي","ملتفّة بعيداً عن الرصيف (إلى اليسار)، حتى تتأرجح مؤخرة الشاحنة نحو الرصيف","مستقيمة إلى الأمام، لأن مكبح الركن المشدود هو ما يثبّت الشاحنة فعلياً على المنحدر","ملتفّة نحو الرصيف فقط إذا لم يكن هناك رصيف، وإلا فمستقيمة إلى الأمام"],"explanation":"عند الركن نزولاً مع وجود رصيف، التفّ بالعجلات الأمامية نحو الرصيف حتى يثبّت أي تدحرج الإطار في الرصيف ويوقف الشاحنة."},"388":{"q":"تتوقف على طريق جبلي شديد الانحدار لفحص حمولتك، راكناً شاحنتك متجهة صعوداً مع وجود رصيف على الجانب الأيمن. قبل أن تبتعد سيراً، تريد أن يتدحرج الرتل نحو الرصيف ويتوقف إذا انفلتت المكابح يوماً. لضبط العجلات الأمامية بشكل صحيح لهذا الوضع (صعوداً مع رصيف)، ينبغي عليك:","options":["التفّ بالعجلات الأمامية نحو الرصيف (إلى اليمين) حتى يتراجع الإطار إليه","التفّ بالعجلات الأمامية بعيداً عن الرصيف (إلى اليسار) حتى يتدحرج الإطار إلى الوراء نحوه","اترك العجلات الأمامية مستقيمة إلى الأمام واعتمد فقط على مكبح الركن","التفّ بالعجلات الأمامية بحدة إلى اليمين، كما تفعل عند عدم وجود رصيف"],"explanation":"عند الركن صعوداً مع وجود رصيف، التفّ بالعجلات الأمامية بعيداً عن الرصيف حتى يحجز أي تدحرج للوراء الإطار في الرصيف ويوقف الرتل."},"389":{"q":"أنت تتبع دراجة نارية على شارع مدينة جاف وتضبط مسافة اتباعك بناءً على كيفية حركة السائق. أي افتراض بشأن تلك الدراجة النارية هو الأهم الذي يجب أن تخطط له حتى لا تصطدم بمؤخرتها؟","options":["ستسير دائماً بسرعة أقل بكثير من حد السرعة، لذا فإن فجوة قصيرة آمنة","تحتاج إلى مساحة مسارين كاملين، لذا يجب ألا تسير بمحاذاتها أبداً","قد يصعب ملاحظتها في حركة المرور وتستطيع التوقف أسرع بكثير من شاحنتك","ستحافظ على سرعة ثابتة واحدة ولن تبطئ فجأة"],"explanation":"يصعب رؤية الدراجات النارية في حركة المرور وتستطيع التوقف في مسافة أقصر بكثير من شاحنة ثقيلة، لذا اترك مساحة اتباع إضافية."},"390":{"q":"أنت تنقل مقطورة محمّلة وتبدأ منحدراً طويلاً وشديد الانحدار في ظروف نهارية جافة. يسألك مبتدئ يركب معك كيف يؤثر هذا الهبوط على المسافة التي سيحتاجها الرتل للتوقف توقفاً تاماً مقارنة بالتوقف على رصيف مستوٍ بالسرعة نفسها. أي عبارة صحيحة؟","options":["لا يُحدث ذلك فرقاً في مسافة توقفك، لأن مسافة التوقف الكلية ثابتة عند نحو 419 قدماً بسرعة 55 ميلاً في الساعة بغض النظر عن ميل الطريق.","تصبح مسافة توقفك أقصر بكثير، لأن الجاذبية تسحب الشاحنة نزولاً فتضغط الإطارات على الطريق بقوة أكبر وتحسّن قبضة الكبح.","تنخفض مسافة توقفك للحظة نحو الصفر بمجرد أن يتولى المحرك والتروس عملية الكبح على المنحدر.","تزداد مسافة توقفك، لأن الجاذبية تضيف إلى زخمك نزولاً على المنحدر ويجب على المكابح أن تعمل بجهد أكبر على مسافة أطول لإيقاف الرتل."],"explanation":"على المنحدر النازل تضيف الجاذبية إلى زخمك، لذا يجب على المكابح أن تعمل بجهد أكبر على مسافة أطول وتزداد مسافة توقفك."},"391":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع ريفي وتقترب من منعطف حاد عليه علامة استرشادية صفراء مكتوب عليها \"السرعة الآمنة 40 ميلاً في الساعة\". الرصيف جاف وحركة المرور خفيفة. أي عبارة تصف على أفضل وجه كيف ينبغي عليك، كسائق يحمل رخصة CDL، أن تتعامل مع تلك السرعة الاسترشادية المنشورة؟","options":["رقم 40 ميلاً في الساعة محسوب لسيارات الركاب، لذا فبصفتك شاحنة محمّلة بمركز ثقل أعلى ينبغي أن تدخل المنعطف بسرعة أقل منه لتفادي الانقلاب.","لأن العلامة استرشادية قانونية، فإن 40 ميلاً في الساعة هي الحد الأقصى القانوني لجميع المركبات، ويمكن للشاحنات أخذ المنعطف بسرعة 40 ميلاً في الساعة تماماً ما دام الطريق جافاً.","تنطبق العلامة الاسترشادية فقط على المقطورات الفارغة؛ وبما أن مقطورتك محمّلة ومستقرة، يمكنك تجاوز 40 ميلاً في الساعة عبر المنعطف.","السرعات الاسترشادية منشورة للشاحنات تحديداً، لذا فإن 40 ميلاً في الساعة تتضمن بالفعل هامش أمان للشاحنات ويمكنك مطابقتها دون إبطاء إضافي."],"explanation":"السرعات الاسترشادية للمنعطفات مضبوطة لسيارات الركاب، لذا ينبغي على شاحنة محمّلة بمركز ثقل أعلى أن تدخل المنعطف بسرعة أقل من المنشورة لتفادي الانقلاب."},"392":{"q":"الكبح بقوة أثناء الانعطاف يمكن أن يتسبب للشاحنة في:","options":["التوقف بسلاسة شديدة","الانزلاق أو الانقلاب","توفير مكابحها","القبض بشكل أفضل بكثير"],"explanation":"الكبح بقوة أثناء الانعطاف يمكن أن يتسبب في انزلاق أو انقلاب."},"393":{"q":"تُنهي رحلة تسليم طويلة وتدخل الساحة. قبل فحصك السابق للرحلة هذا الصباح كان كل شيء سليماً، كما أعدت فحص تثبيت حمولتك خلال أول 50 ميلاً ومرة أخرى كل 150 ميلاً أثناء الطريق. والآن بعد انتهاء الرحلة وركن الشاحنة، أي فحص ينبغي أن تجريه لإكمال دورة الفحص الكاملة التي يتوقعها منك قسم السلامة العامة (DPS)؟","options":["لا حاجة لفحص إضافي لأن فحوصاتك أثناء الطريق كل 150 ميلاً غطّت المركبة بالفعل لذلك اليوم","فحص ما بعد الرحلة، حتى تُوثَّق أي عيوب نشأت أثناء الرحلة قبل السائق التالي أو مناوبتك التالية","فحص سنوي، لأنه الفحص الرسمي الوحيد المطلوب بمجرد انتهاء القيادة اليومية","فحص شهري للمكابح والإطارات لإغلاق تآكل الرحلة وإهترائها"],"explanation":"يُجرى فحص ما بعد الرحلة في نهاية الرحلة حتى تُوثَّق أي عيوب نشأت أثناء القيادة على تقرير قبل المناوبة التالية."},"394":{"q":"أثناء فحص في الطريق عند توقف، ينبغي أن تفحص:","options":["محطة الراديو فقط","الإطارات والمكابح والحمولة والأضواء","مقعد السائق فقط","لا شيء على الإطلاق، تخطَّ الفحص"],"explanation":"افحص الإطارات والمكابح وتثبيت الحمولة والأضواء أثناء الطريق."},"395":{"q":"لقد أنهيت للتو رحلة مدتها 11 ساعة ودخلت الساحة. أثناء الرحلة شعرت بأن مكابحك ليّنة قليلاً ولاحظت أن ضوء علامة جانبية يومض ثم ينطفئ. كجزء من إكمالك الصحيح لفحص ما بعد الرحلة، أي مما يلي يُتوقع منك عموماً ملؤه، وتقديمه عند الاقتضاء، حتى يُحذَّر السائق التالي والناقل من هذه الحالات؟","options":["سجل شراء الوقود والأميال الذي تحتفظ به لإقرار ضريبة IFTA","مذكرة رحلتك الشخصية التي تدوّن كيف سار اليوم وأين توقفت للراحة","تقرير فحص مركبة السائق (DVIR) الذي يوثّق أي عيوب، مثل المكابح الليّنة وضوء العلامة الجانبية المعطّل","تقرير حالة الطقس والطريق على جانب الطريق لسجلات الموزّع"],"explanation":"يتطلب فحص ما بعد الرحلة إكمال تقرير فحص مركبة السائق (DVIR) الذي يوثّق أي عيوب سلامة، مثل المكابح الليّنة وضوء علامة جانبية معطّل."},"396":{"q":"إنه صباح بارد وقد أدرت المحرك للتو لبدء إحماء ما قبل الرحلة. أنت تراقب عدّادات لوحة القيادة للتأكد من أن كل شيء يعمل قبل أن تنطلق. أي مما يلي هو التوقع الصحيح لعدّاد ضغط الزيت، ويدل على أن المحرك آمن للتشغيل؟","options":["ينبغي أن يرتفع المؤشر ببطء ويصل إلى الضغط الطبيعي بعد عدة دقائق من التشغيل في وضع الخمول، بمجرد أن يدفأ الزيت","لأن الصباح بارد، ينبغي أن تتركه نحو ساعة من التشغيل في وضع الخمول قبل أن يصبح ضغط الزيت موثوقاً","لا حاجة أن يسجّل ضغط الزيت حتى تكون متحركاً تحت الحمل على الطريق","ينبغي أن يصل المؤشر إلى ضغط التشغيل الطبيعي خلال ثوانٍ قليلة من بدء تشغيل المحرك"],"explanation":"ينبغي أن يصل ضغط الزيت إلى ضغط التشغيل الطبيعي خلال ثوانٍ قليلة من بدء تشغيل المحرك، وإلا فيجب أن تطفئه لمنع التلف."},"397":{"q":"مرّت 40 دقيقة على رحلتك على طريق ريفي ذي مسارين عندما تنظر إلى عدّاداتك وترى أن عدّاد ضغط الزيت قد انخفض إلى الصفر، رغم أن المحرك لا يزال يبدو ويعمل بشكل طبيعي ولم يصدر جرس إنذار بعد. ما الإجراء الصحيح؟","options":["انعطف عن الطريق بمجرد أن يكون ذلك آمناً، وتوقّف، وأطفئ المحرك","استمر في القيادة بشكل طبيعي إلى أقرب محطة شاحنات لأن المحرك لا يزال يبدو بخير","حافظ على السرعة لكن خفّف عن دوّاسة الوقود وتابع إلى محطة الوقود المجدولة","أطفئ الملحقات غير الأساسية مثل الراديو والتكييف لتقليل حمل المحرك واستمر"],"explanation":"فقدان ضغط الزيت يعني أن المحرك لم يعد يتلقى التزييت، لذا انعطف عن الطريق بمجرد أن يكون ذلك آمناً وأطفئ المحرك فوراً."},"398":{"q":"أنت تصعد منحدراً طويلاً في فترة ظهيرة صيفية حارة، محمّلاً بالكامل قرب الوزن الإجمالي المسموح به (GVWR). مع اقترابك من القمة، يبدأ أحد عدّادات لوحة القيادة بالارتفاع إلى المنطقة الحمراء. قبل أن تقرر كيفية ردّ الفعل، أي عدّاد هو المصمَّم تحديداً لتحذيرك من أن المحرك نفسه يسخن بإفراط؟","options":["عدّاد ضغط الزيت، لأن الطقس الحار يخفّف الزيت ويرتفع المؤشر للتحذير من ارتفاع درجة حرارة المحرك","عدّاد درجة حرارة سائل التبريد، لأنه يقرأ درجة حرارة سائل تبريد المحرك ويحذّرك من أن المحرك يسخن بإفراط","البيرومتر، لأنه يقرأ حرارة غازات العادم، والتي في يوم حار تكون نفس ارتفاع حرارة المحرك","عدّاد الفولتية، لأن صعوداً طويلاً في يوم حار يسخّن نظام الشحن بإفراط ويشير إلى ارتفاع حرارة المحرك"],"explanation":"عدّاد درجة حرارة سائل التبريد يقرأ درجة حرارة سائل تبريد المحرك ويحذّرك عندما يسخن المحرك بإفراط."},"399":{"q":"أثناء فحص ما قبل الرحلة، تبدأ تشغيل المحرك وتراقب عدّادات لوحة القيادة بينما الشاحنة في وضع الخمول. تلاحظ أن مؤشر الأميتر (أو الفولتميتر) يستقر بثبات في النطاق الطبيعي ولا ينخفض أو يتأرجح بشكل غير منتظم. ماذا يخبرك هذا العدّاد فعلياً عن مركبتك؟","options":["ضغط زيت المحرك مرتفع بما يكفي لبدء رحلتك بأمان","درجة حرارة سائل التبريد ضمن نطاق التشغيل الآمن","نظام الشحن يعمل ويُبقي البطارية مشحونة بشكل صحيح","البطارية فيها ماء كافٍ في خلاياها ومثبّتة بإحكام"],"explanation":"قراءة ثابتة للأميتر أو الفولتميتر في النطاق الطبيعي تؤكد أن المولّد ينتج تياراً ويُبقي البطارية مشحونة بشكل صحيح."},"400":{"q":"أثناء فحص ما قبل الرحلة، تمسك عجلة القيادة في الجرار وتحركها ذهابًا وإيابًا دون أن تتحرك العجلات الأمامية. تشعر بقدر ملحوظ من الارتخاء قبل أن تبدأ العجلات في الاستجابة. لتقرر ما إذا كان هذا الخلوص ضمن الحدود الآمنة وأن المركبة قانونية للقيادة، ما هو أقصى مقدار تقريبي لحركة عجلة القيادة الذي ينبغي أن يكون لديك قبل أن تبدأ العجلات الأمامية في الالتفاف؟","options":["حتى نصف دورة لعجلة القيادة، لأن بعض الارتخاء طبيعي في الشاحنات الثقيلة","حتى دورة كاملة لعجلة القيادة قبل أن تتفاعل العجلات","حتى 90 درجة، وهي ربع دورة للعجلة","ما لا يزيد عن نحو 10 درجات من الحركة قبل أن تستجيب العجلات"],"explanation":"ينبغي ألا يتجاوز الخلوص الحر لعجلة القيادة نحو 10 درجات قبل أن تبدأ العجلات الأمامية في الاستجابة؛ والمزيد من ذلك يشير إلى نظام توجيه مهترئ أو مرتخٍ."},"401":{"q":"أثناء فحص ما قبل الرحلة تضغط دواسة القابض (الكلتش) وتجد أن بها خلوصًا حرًا أكبر بشكل ملحوظ (مسافة ارتخاء قبل المقاومة) من المعتاد. أنت متأخر بالفعل والشاحنة لا تزال تسير. أي عبارة تصف على نحو أفضل ما اكتشفته وما ينبغي أن تفعله؟","options":["الخلوص الحر للقابض الزائد أو الناقص هو عيب ميكانيكي يجب إصلاحه قبل أن تكون المركبة آمنة للتشغيل","الخلوص الحر الزائد للقابض هو تآكل طبيعي لا يهم إلا عندما يبدأ القابض في الانزلاق تحت الحِمل","إنها مشكلة، لكن التوجيه والمكابح فقط هما عنصرا فحص يمكن أن يبقيا الشاحنة خارج الخدمة","الخلوص الحر المرتخي للقابض هو في الواقع علامة جيدة على أن الوصلة مشحّمة جيدًا وغير عالقة"],"explanation":"الخلوص الحر للقابض الزائد أو الناقص هو عيب ميكانيكي يجب إصلاحه قبل أن تكون المركبة آمنة للتشغيل."},"402":{"q":"أنت تنقل مقطورة محمّلة نزولًا على منحدر جبلي طويل. لتوفير الوقود وتقليل التآكل، يقترح عليك سائق زميل أن تنقل ناقل الحركة إلى الوضع المحايد وتترك الشاحنة تتدحرج نزولًا، مستخدمًا المكابح فقط عندما تصبح سرعتك مرتفعة جدًا. لماذا يُعد اتباع هذه النصيحة الخيار الخاطئ؟","options":["إنه مقبول على منحدر قصير لأن المكابح وحدها يمكنها التحكم في الشاحنة بأمان طوال الطريق نزولًا","تفقد كبح المحرك وكبح التروس والتحكم في المركبة، ويمكن أن تسخن مكابح الخدمة بإفراط وتفقد فعاليتها، والتدحرج في الوضع المحايد غير قانوني","تصبح مشكلة فقط إذا كان المنحدر أكثر انحدارًا من الترس المنخفض الذي تختاره عادةً قبل النزول","التدحرج يوفر قدرًا كبيرًا من الوقود لدرجة أن الفقدان البسيط للتحكم يُعد مقايضة مقبولة على معظم المنحدرات"],"explanation":"نقل ناقل الحركة إلى الوضع المحايد على منحدر طويل يلغي كبح المحرك وكبح التروس، ويسخّن مكابح الخدمة بإفراط ويفقدها فعاليتها، والتدحرج في الوضع المحايد غير قانوني."},"403":{"q":"أنت تنقل مقطورة محمّلة صعودًا على منحدر طويل في شاحنة قديمة لا يحتوي ناقل حركتها على مؤشر للتروس على لوحة العدادات. بدأ المحرك يتلكأ ويفقد قدرته، وتعلم أنك بحاجة إلى النزول إلى ترس أدنى لمواصلة الصعود. بدون مخطط نقل أو شاشة تروس تعتمد عليها، ما المعلومات التي ينبغي أن تستخدمها فعليًا لتقرر أي ترس هو الصحيح لهذه اللحظة؟","options":["فقط القراءة من مرآتك الجانبية اليمنى وأنت تراقب المقطورة تتعقّب صعودًا على المنحدر","ارتفاع مقعد السائق ومدى انخفاض المنحدر كما يبدو من المقصورة","سرعتك الحالية على الطريق مقترنةً بعدد دورات المحرك المعروضة على عداد الدوران (التاكومتر)","موضع مقبض الباب الأمامي بالنسبة إلى كتفك كمرجع سريع"],"explanation":"يُختار الترس الصحيح بمطابقة سرعتك على الطريق مع عدد دورات المحرك المعروضة على عداد الدوران (التاكومتر)."},"404":{"q":"أنت متوقف عند إشارة حمراء على منحدر صاعد شديد الانحدار مع مقطورة محمّلة بالكامل. تتحول الإشارة إلى الأخضر، وتحتاج إلى تحريك الشاحنة بسلاسة دون السماح لها بالانجراف نحو السيارة المتوقفة على مقربة خلفك. وأنت تستعد لتحرير مكبح الخدمة (مكبح القدم) ورفع دوران المحرك، أي تقنية تمنع المركبة على نحو أفضل من الزحف إلى الوراء أثناء الانطلاق؟","options":["اضغط مكبح الخدمة عدة مرات بسرعة لبناء ضغط هواء إضافي قبل الانطلاق","انقل إلى ترس أعلى ليكون لدى المحرك قدرة سحب أكبر للتغلب على الانحدار","ارفع دوران المحرك ودع القابض ينزلق ببطء حتى تتحرك الشاحنة إلى الأمام بعزم الدوران وحده","أبقِ مكبح الانتظار مفعّلًا، ثم حرّره فقط عندما يبدأ المحرك في السحب وتبدأ بالتحرك إلى الأمام"],"explanation":"عند الانطلاق على منحدر صاعد، أبقِ مكبح الانتظار مفعّلًا وحرّره فقط عندما يبدأ المحرك في السحب وتبدأ بالتحرك إلى الأمام، مما يمنع التدحرج إلى الوراء."},"405":{"q":"الجو أقل بقليل من درجة التجمد وطبقة خفيفة من الجليد تغطي الساحة وأنت تقود مركبتك المركّبة المحمّلة مبتعدًا من إشارة التوقف عند مخرج المستودع. تشعر بأن عجلات الدفع بدأت تفقد تماسكها. أي إجراء يمنحك أفضل فرصة للانطلاق دون أن تدور عجلات الدفع وتُحدث انزلاقًا ناجمًا عن التسارع؟","options":["اضغط على دواسة الوقود برفق وابنِ السرعة تدريجيًا حتى تحافظ إطارات الدفع على تماسكها على السطح الزلق","اضغط دواسة الوقود بقوة حتى النهاية حتى تدفع القدرة الإضافية الشاحنة عبر البقعة الزلقة","أضِف ثانية إضافية لمسافة المتابعة عن كل 10 أقدام من طول المركبة قبل أن تتحرك","أبقِ القابض مشتبكًا جزئيًا وارفع دوران المحرك عاليًا، ثم حرّره بسرعة للحصول على انطلاقة قوية"],"explanation":"على سطح زلق قريب من درجة التجمد، اضغط على دواسة الوقود برفق وابنِ السرعة تدريجيًا حتى تحافظ إطارات الدفع على تماسكها ولا تدور وتنزلق."},"406":{"q":"إنه بعد الفجر مباشرةً وأنت تقوم بفحص ما قبل الرحلة. عندما تفتح غطاء المحرك وتنظر إلى أحزمة إدارة المولّد (الدينامو) ومضخة الماء، أي حالة تخبرك بأن الأحزمة تحتاج إلى عناية قبل أن تتمكن من إخراج الشاحنة بأمان إلى الطريق؟","options":["الأحزمة ذات لون باهت داكن بدلًا من لمعان ساطع","الحزام متشقق ومهترئ، أو ينحرف أكثر مما ينبغي عندما تضغط عليه (شدّ غير سليم)","البوق لا يصدر صوتًا عاليًا بما يكفي عندما تضغط عليه","عداد الوقود لا يُظهر ممتلئًا عندما يكون المفتاح مشغّلًا"],"explanation":"يجب استبدال أحزمة الإدارة إذا كانت متشققة أو مهترئة أو تنحرف أكثر مما ينبغي، لأن الشدّ غير السليم أو التآكل قد يؤدي إلى فشل الحزام."},"407":{"q":"أثناء فحص ما قبل الرحلة تفتح غطاء المحرك وتمرّر يدك على طول خراطيم المُبرّد (الرادييتر) والمدفأة في حجرة المحرك. أنت تفحص هذه الخراطيم بشكل أساسي بحثًا عن أي حالة؟","options":["ما إذا كانت الخراطيم تبدو دافئة، مما يدل على أن المحرك وصل إلى درجة حرارة التشغيل","صوت هسهسة أو طرق عالٍ صادر من منطقة الحزام والبكرة","البقع الطرية والتسريبات والتشققات التي قد تسبب فشل الخرطوم","لمعان ساطع يُظهر أن المطاط نُظّف ومُعالج حديثًا"],"explanation":"يجب فحص خراطيم المحرك بحثًا عن البقع الطرية والتسريبات والتشققات، لأن الخرطوم الضعيف قد ينفجر تحت الحرارة والضغط ويسبب فقدان سائل التبريد."},"408":{"q":"الجو أقل بقليل من درجة التجمد أثناء فحص الصباح لما قبل الرحلة، وبينما تتجول حول حجرة المحرك تقرر فحص نظام التوجيه المعزز (الباور) قبل يوم طويل من القيادة الجبلية. أي مما يلي يصف على نحو أفضل ما ينبغي أن تفحصه في نظام التوجيه المعزز؟","options":["عجلة القيادة بحثًا عن خلوص حر لا يزيد عن 10 درجات (نحو 2 بوصة على عجلة قطرها 20 بوصة) قبل أن تتحرك العجلات","ضجيج صفير أو أنين عالٍ من المضخة، لأن الصوت هو العلامة الموثوقة الوحيدة لوجود مشكلة في التوجيه المعزز","طلاء جديد ساطع على الخزان والخطوط للتأكد من أن النظام خدِم حديثًا","مستوى سائل التوجيه المعزز وأي علامات تسرب في الخراطيم والخزان والوصلات"],"explanation":"افحص نظام التوجيه المعزز للتأكد من مستوى السائل السليم وأي تسريبات في الخراطيم والخزان والوصلات، لأن انخفاض المستوى قد يسبب فقدانًا مفاجئًا لمساعدة التوجيه."},"409":{"q":"أثناء فحص ما قبل الرحلة في صباح بارد ومشرق، تقترب من المقصورة وتلاحظ شقًا يمتد عبر الحافة السفلية للزجاج الأمامي، إضافةً إلى طبقة من أوساخ الطريق وبقايا الحشرات الجافة على معظم الزجاج. ستقود باتجاه شمس الصباح المنخفضة في الساعة الأولى من رحلتك. ما الطريقة الصحيحة للتعامل مع الزجاج الأمامي قبل أن تقود؟","options":["نظّف الزجاج الأمامي جيدًا وتأكد من أن الشق ليس كبيرًا بما يكفي أو في موضع يعيق رؤيتك بشدة قبل القيادة","اترك الأوساخ في مكانها لأن الزجاج المتسخ والضبابي يقلل في الواقع من وهج شمس الصباح المنخفضة ويحسّن رؤيتك","ضع طبقة تظليل داكنة عبر كامل الزجاج الأمامي للتعامل مع وهج الشمس، ثم قُد دون تنظيف الزجاج","تجاهل الزجاج الأمامي تمامًا لأن أي شق، مهما كان طفيفًا، يضع المركبة تلقائيًا خارج الخدمة وينهي الفحص"],"explanation":"يجب أن يكون الزجاج الأمامي نظيفًا وخاليًا من أي شق كبير بما يكفي أو في موضع يعيق رؤيتك بشدة قبل أن تقود."},"410":{"q":"إنه صباح ممطر وأثناء فحص ما قبل الرحلة تكتشف أن ريشة المساحة على جانب السائق ممزقة وأن خزان سائل الغسيل فارغ. أنت متأخر بالفعل عن الجدول والمطر خفيف الآن. أي سبب يفسّر على نحو أفضل لماذا ينبغي أن تصلح هذين العنصرين قبل أن تقود، بدلًا من معاملتهما كأمر ثانوي للراحة؟","options":["إنهما لازمان أساسًا لإبعاد أوساخ الطريق عن الطلاء والحفاظ على قيمة إعادة بيع الشاحنة","المساحات وغاسلات الزجاج العاملة تبقي رؤيتك واضحة في المطر، وبدون رؤية واضحة لا يمكنك أن تقدّر المسافة والمرور والمخاطر أمامك بأمان","إنهما مطلوبان فقط ليجتاز الشاحنة ملصق سلامة الولاية السنوي، وليس للقيادة اليومية","إنهما يساعدان على إزالة الصقيع عن الزجاج الأمامي بشكل أسرع، وهذا هو السبب الحقيقي لكونهما عنصرًا يبقي المركبة خارج الخدمة"],"explanation":"المساحات وغاسلات الزجاج تبقي رؤيتك واضحة في المطر، والرؤية الواضحة ضرورية لتقدير المسافة والمرور والمخاطر أمامك."},"411":{"q":"أنت ترجع بشاحنتك المقطورة إلى الوراء خارجًا من رصيف تحميل ضيق عندما يخطو عامل سائر على قدميه فجأة إلى نقطتك العمياء قرب المؤخرة. أثناء فحص ما قبل الرحلة كنت قد تأكدت من أن بوقك يعمل. في هذه اللحظة، ما السبب الرئيسي لأهمية البوق العامل لك كسائق يحمل رخصة قيادة تجارية؟","options":["يتيح لك إشارة زملائك العمال بأنك انتهيت ومستعد لمغادرة الرصيف","يؤكد أن نظامك الكهربائي به شحنة كافية لتشغيل الملحقات","يتيح لك تحذير العامل والأشخاص الآخرين من خطر وشيك حتى يبتعدوا عن الطريق","يلبي ميزة راحة ورفاهية يفحصها المفتش لجودة القيادة"],"explanation":"البوق جهاز تحذير سلامة يُستخدم لتنبيه العمال والمشاة والسائقين إلى خطر وشيك حتى يتمكنوا من الابتعاد عن الطريق."},"412":{"q":"الجو أقل بقليل من درجة التجمد في فحص صباحي مبكر لما قبل الرحلة، وزجاجك الأمامي يتعرض باستمرار للضباب والصقيع من الداخل. تتأكد من أن مزيل الصقيع والمدفأة يعملان بشكل سليم. ما السبب الرئيسي المتعلق بالسلامة لوجوب عمل هذين النظامين قبل أن تنطلق إلى الطريق؟","options":["لتبقى المقصورة دافئة بما يكفي لإبقائك يقظًا ومرتاحًا في وردية طويلة وباردة","حتى تتمكن من إذابة أي جليد بسرعة على المرايا الخارجية والهوائي قبل القيادة","حتى يبقي الهواء الدافئ ريش المساحات من الالتصاق والتجمد على الزجاج","حتى تبقي الزجاج الأمامي صافيًا وتحافظ على رؤية غير معاقة للطريق في الطقس البارد أو الرطب"],"explanation":"يبقي مزيل الصقيع والمدفأة الزجاج الأمامي صافيًا في الطقس البارد أو الرطب، مما يحافظ على رؤية غير معاقة للطريق."},"413":{"q":"الجو أقل بقليل من درجة التجمد، وأنت تقود مسافة ميلين فقط إلى ساحة إنزال قريبة، وحزام الأمان لديك يبدو متيبسًا وغير مريح على معطفك الشتوي. وأنت تنهي فحص ما قبل الرحلة وتستعد للانطلاق، أي إجراء صحيح بشأن حزام الأمان؟","options":["اربط حزام الأمان وارتدِه طوال الرحلة بأكملها، مهما كانت المسافة قصيرة أو السرعة بطيئة","اترك الحزام غير مربوط لأن الرحلة أقل من ثلاثة أميال وستقود ببطء","ضع الحزام بارتخاء خلفك حتى يتوقف صوت التحذير دون أن يقيّد معطفك حركتك","تجاهل الحزام لأن القيادة منخفضة السرعة في الساحات والمواقف لا تتطلب قانونيًا تقييدًا"],"explanation":"يجب على السائق التجاري ارتداء حزام الأمان كلما كانت المركبة في حركة، مهما كانت الرحلة قصيرة أو بطيئة."},"414":{"q":"أنت تنقل حمولة على طريق ريفي سريع ذي مسارين عندما يفقد محركك قدرته وتنزلق إلى الكتف الأيمن. تشغّل أضواء التحذير الوامضة ويمكنك بالفعل أن تشم رائحة دخان من حجرة المحرك، فتمسك بطفّاية الحريق المشحونة لديك. قبل أن تبدأ بالسير عائدًا لوضع أجهزة التحذير، أي قطعة أخرى من معدات الطوارئ مطالَب قانونيًا بحملها على هذه الشاحنة حتى تتمكن من إكمال إعداد التحذير؟","options":["جهاز راديو CB احتياطي حتى تتمكن من طلب المساعدة وتحذير السائقين الآخرين من الخطر","مثلثات تحذير عاكسة لوضعها على الطريق وتنبيه المرور المقترب","سترة سلامة عالية الوضوح، وهي الجهاز الوحيد الذي تتطلب القواعد حمله","حقيبة من شعلات الطوارئ فقط، لأن المثلثات اختيارية بمجرد تشغيل أضواءك الوامضة"],"explanation":"يجب أن تحمل كل مركبة تجارية ثلاثة مثلثات تحذير عاكسة لوضعها على الطريق وتنبيه المرور المقترب عند التوقف."},"415":{"q":"تصل لورديتك وتصعد إلى جرار أنزله سائق آخر قبل ساعتين. تريد أن تتأكد من أن المكابح والأضواء والإطارات صالحة للسير قبل أن تخرج من الساحة. أي إجراء واحد يمنحك أكثر صورة موثوقة عن أي عيوب اكتُشفت بالفعل في هذه المركبة؟","options":["اعتبر المركبة صالحة للسير لأن السائق السابق أنهى رحلة بها بوضوح دون أن تتعطل","انتقل مباشرةً إلى اختبار على الطريق، لأن قيادة الشاحنة بضعة أميال هي أسرع طريقة للإحساس بأي مشكلة حقيقية","اقرأ تقرير فحص المركبة الأخير للسائق السابق (DVIR) وتحقق من أن أي عيوب مذكورة قد صُدّق على إصلاحها","اتصل بقسم الإرسال واسأل ما إذا كان أي سائق آخر قد اشتكى من هذه الوحدة في الأسبوع الماضي"],"explanation":"قبل القيادة، راجع تقرير الفحص الأخير للسائق السابق (DVIR) وتأكد من أن أي عيوب مذكورة قد صُدّق على إصلاحها."},"416":{"q":"إذا اكتشفت عيبًا خطيرًا أثناء الفحص، فينبغي أن:","options":["تقودها بحذر على أي حال","لا تقودها حتى يتم إصلاحها","تتجاهله في الوقت الحالي","تقود ليلًا فقط"],"explanation":"لا تقُد مركبة بها عيب خطير حتى يتم إصلاحها."},"417":{"q":"مضت ثلاث ساعات على رحلة طويلة ورتيبة على طريق سريع بين الولايات بعد انطلاقة مبكرة. انخفضت سرعتك دون أن تلاحظ، ولا تتذكر تمامًا الأميال القليلة الماضية، وتضبط نفسك تفرك عينيك. وفقًا لإرشادات القيادة الآمنة، أي مما يلي هو أوضح تحذير على أنك أصبحت نعسانًا أكثر من أن تواصل القيادة بأمان؟","options":["يداك تشعران بعدم استقرار على المقود وتريد باستمرار فحص مراياك مرات أكثر","تشعر بيقظة حادة وتركيزك مثبّت على الطريق أمامك","يبدو زمن رد فعلك على دواسة المكبح أسرع وأكثر حدة من المعتاد","جفناك يشعران بالثقل وأفكارك تشرد باستمرار بعيدًا عن الطريق"],"explanation":"الجفون الثقيلة المتدلية مع شرود الأفكار هي علامات تحذير كلاسيكية لإرهاق السائق الخطير."},"418":{"q":"إنها الساعة الثانية صباحًا ومضت ثلاث ساعات على رحلة طويلة عندما تشعر عيناك بالثقل، وتضبط نفسك تنجرف نحو الكتف، ولا تستطيع تذكر الأميال القليلة الماضية. لا يزال أمامك أكثر من 100 ميل إلى المحطة. أي إجراء سيعيد فعليًا قدرتك على القيادة بأمان؟","options":["انعطف إلى منطقة استراحة آمنة ونم أو ارتح قبل المتابعة","افتح النوافذ وارفع صوت الراديو عاليًا لتبقى يقظًا","توقف لشراء قهوة كبيرة وواصل الدفع للوصول إلى المحطة","زِد مسافة المتابعة وواصل القيادة بحذر أكبر"],"explanation":"العلاج الحقيقي الوحيد للنعاس هو النوم، لذا انعطف إلى منطقة استراحة آمنة وارتح قبل المتابعة."},"419":{"q":"إنها الساعة 4:30 صباحًا وأنت على وشك بدء رحلة مدتها 9 ساعات بعد نوم سيئ الليلة الماضية. تشعر بالنعاس. أي مما يلي هو أقل الطرق فعالية للتأكد من أن الإرهاق لن يجعلك تقود متأثرًا في هذه الرحلة الطويلة؟","options":["جدوِل رحلاتك بحيث تقوم بمعظم قيادتك خلال الساعات التي تكون فيها مستيقظًا عادةً","اشرب قهوة كبيرة وأبقِ المقصورة باردة والراديو عاليًا لتبقى يقظًا بدلًا من النوم","احصل على ليلة نوم كاملة قبل الرحلة وخطط للتوقف والراحة عندما تشعر بالنعاس","تجنّب الأدوية التي تسبب النعاس وتعرّف على علامات التحذير مثل ثقل الجفون أو شرود الأفكار"],"explanation":"القهوة والهواء البارد والضوضاء العالية تخفي النعاس مؤقتًا فقط ولا تحل أبدًا محل النوم، العلاج الحقيقي الوحيد للإرهاق."},"420":{"q":"إذا جعلك دواء تشعر بالنعاس، فينبغي أن:","options":["تقود أسرع قليلًا","لا تقود على الإطلاق","تشرب بعض القهوة","تفتح كل النوافذ"],"explanation":"لا تقُد إذا جعلك الدواء نعسانًا."},"421":{"q":"إنها ظهيرة بدرجة حرارة 100 درجة ومضت نحو ثلاث ساعات على رحلة طويلة عبر غرب تكساس. تتوقف على جانب الطريق لإجراء فحص أثناء الطريق مطلوب لحمولتك وإطاراتك. اثنان من إطاراتك يُظهران الآن ضغطًا أعلى بشكل ملحوظ مما كان عليه أثناء فحص الصباح الباكر البارد لما قبل الرحلة. ما السبب الأرجح، وماذا يخبرك عن الخطر الذي تواجهه الآن؟","options":["الرصيف الساخن برّد الهواء داخل الإطارات، مما خفض الضغط ورفع خطر الإطار المثقوب لديك","القطران النازف من الطريق الساخن امتُص في الإطارات، مما أضاف وزنًا وضغطًا","الحرارة زادت من ضغط الهواء داخل الإطارات، مما يرفع خطر الانفجار","لا شيء خاطئ؛ ضغط الإطارات ينخفض طبيعيًا في الحرارة، لذا فإن القراءة الأعلى تعني أن مقياسك معطل"],"explanation":"الطقس الحار يجعل الهواء داخل الإطارات يتمدد ويرفع الضغط، مما يزيد من خطر الانفجار."},"422":{"q":"إنه منتصف بعد الظهر في يوم صيفي شديد الحرارة في تكساس، وبينما تقود مركبة مركّبة محمّلة تلاحظ بقعًا داكنة لامعة من القطران 'تنزف' إلى سطح الأسفلت أمامك. ماذا ينبغي أن تتوقع أن يفعل هذا القطران النازف بالطريق، ولماذا يهم ذلك لتحكمك في المركبة؟","options":["سيمنح القطران الإطارات تماسكًا إضافيًا لأنه لزج، لذا يمكنك بأمان الحفاظ على سرعتك على الطريق السريع عبر البقع.","الخطر الرئيسي هو أن الحرارة سترفع ضغط إطاراتك إلى ما بعد حده، لذا فإن القطران نفسه ليس له تأثير على إحساس الطريق تحت إطاراتك.","ليس له تأثير حقيقي على التماسك ما دامت إطارات محور التوجيه لديك بها على الأقل 4/32 بوصة من المداس.","سيجعل سطح الطريق زلقًا ويقلل من تماسك إطاراتك، لذا ينبغي أن تبطئ وتتجنب التوجيه أو الكبح الحاد على تلك البقع."],"explanation":"القطران النازف يجعل الطريق زلقًا ويقلل التماسك، لذا أبطئ وتجنب التوجيه أو الكبح الحاد على تلك البقع."},"423":{"q":"إنه منتصف يوليو في تكساس وأنت تصعد منحدرًا طويلًا محمّلًا بالكامل. المقصورة حارة، ومحركك يعمل بجهد، وتريد تحذيرًا مبكرًا بأن المحرك على وشك السخونة الزائدة قبل أن تعلق أو تُحدث ضررًا. أي عداد يمنحك هذا التحذير؟","options":["عداد درجة حرارة سائل التبريد","عداد ضغط الزيت","عداد الوقود","عداد الدوران (دورات المحرك RPM)"],"explanation":"عداد درجة حرارة سائل التبريد هو المؤشر الرئيسي والمباشر للسخونة الزائدة للمحرك، ويعطي أبكر تحذير للتحرك."},"424":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق سريع ذي مسارين بعد الفجر مباشرةً عندما تدخل في امتداد من الضباب الكثيف الذي تشتد كثافته لدرجة أنك بالكاد تستطيع تمييز خطوط المسار أمامك. تقرر أنه يجب عليك مواصلة التحرك ببطء حتى تصل إلى المخرج التالي. لرؤية الطريق على أفضل نحو ممكن دون أن تجعل رؤيتك أسوأ، أي إعداد للمصابيح الأمامية هو الخيار الأفضل؟","options":["شغّل أضواءك العالية، لأنها تلقي الضوء نحو 350 إلى 500 قدم وتتيح لك الرؤية أبعد عبر الضباب","استخدم أضواءك المنخفضة، لأن الأضواء العالية تنعكس عن الضباب عائدةً إلى عينيك وتقلل ما يمكنك رؤيته","أطفئ كل الأضواء الأمامية واعتمد فقط على أضواء التحذير الوامضة الرباعية حتى يراك السائقون القادمون","شغّل الأضواء العالية الآن وخفّضها فقط عندما تقترب مركبة قادمة على مسافة 500 قدم"],"explanation":"في الضباب استخدم الأضواء المنخفضة، لأن الأضواء العالية تنعكس عن الضباب وترتد بالوهج إلى عينيك، مما يقلل الرؤية."},"425":{"q":"أنت تقود شاحنة مقطورة محمّلة على طريق سريع بحارتين أثناء الليل عندما تدخل في كتلة ضباب كثيفة لدرجة أنك لم تعد ترى خطوط الحارات أو الأضواء الخلفية للمركبات أمامك. أي مما يلي هو الإجراء الأكثر أماناً الذي يجب اتخاذه؟","options":["بدّل إلى الأضواء العالية حتى يساعدك الضوء الأكثر سطوعاً على الرؤية لمسافة أبعد عبر الضباب","استمر في السير بسرعة منخفضة على الأضواء المنخفضة، لأن التوقف في أي مكان أخطر من المتابعة","اخرج تماماً عن الطريق بعيداً عن حارات السير، وشغّل أضواء التحذير، وانتظر حتى ينقشع الضباب","قلّل السرعة إلى الزحف ثم توقف في حارتك مع تشغيل أضواء التحذير الرباعية حتى تتحسن الرؤية"],"explanation":"عندما يكون الضباب كثيفاً لدرجة تمنع الرؤية، اخرج تماماً عن الطريق بعيداً عن حارات السير، وشغّل أضواء التحذير، وانتظر حتى ينقشع."},"426":{"q":"تم إرسالك في يوم عاصف مع هبّات رياح جانبية مستمرة على امتداد مفتوح من الطريق السريع. أربع مركبات مركّبة تغادر الساحة في نفس الوقت معك. بناءً على كيفية تأثير الرياح على المركبة، أي سائق ينبغي أن يكون الأكثر قلقاً من أن يُدفع خارج الحارة أو حتى أن ينقلب بفعل الرياح الجانبية؟","options":["سائق صهريج محمّل بالكامل، لأن تموّج السائل يجعل الرياح أكبر تهديد","سائق مقطورة مسطّحة عليها حمولة فولاذية منخفضة وثقيلة وموزّعة بالتساوي","سائق مقطورة صندوقية محمّلة تسير بالحد الأقصى القانوني للوزن، لأن المركبات الأثقل تتلقى رياحاً أكثر","سائق مقطورة صندوقية مرتفعة فارغة أو محمّلة بشكل خفيف، لأنها تقدّم مساحة كبيرة بوزن قليل يقاوم الرياح"],"explanation":"المقطورة الصندوقية المرتفعة الفارغة أو المحمّلة بشكل خفيف هي الأكثر عرضة للخطر في الرياح الجانبية لأنها تقدّم مساحة كبيرة بوزن قليل يقاوم الرياح."},"427":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق ريفي بحارتين في تكساس وتريد التخطيط لرحلتك بحيث تقضي أقل وقت ممكن في الظروف التي تكون فيها الغزلان والحيوانات الكبيرة الأخرى أكثر احتمالاً للاندفاع عبر الطريق. أي جزء من اليوم يتطلب أعلى مستوى من اليقظة لعبور الحيوانات؟","options":["فترات الإضاءة الخافتة حول الفجر والغسق","منتصف النهار حوالي الظهيرة، عندما تبحث الحيوانات عن الطعام","أواخر الصباح، بعد أن تكون الشمس قد أشرقت تماماً","منتصف بعد الظهر، خلال أحرّ جزء من اليوم"],"explanation":"تكون الغزلان والحيوانات الكبيرة أكثر نشاطاً عند الفجر والغسق، وهي أوقات الإضاءة الخافتة التي تكون فيها رؤية السائق أيضاً في أضعف حالاتها."},"428":{"q":"أثناء القيادة، ينبغي أن تبقي عينيك:","options":["مثبّتتين إلى الأمام مباشرة","متحركتين وتمسحان الطريق","منخفضتين على العدّادات","مغلقتين عند الأضواء الحمراء"],"explanation":"أبقِ عينيك متحركتين وتمسحان الطريق."},"429":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق سريع بأربع حارات في حركة مرور معتدلة. لوحة إعلانية رقمية على الكتف الأيمن ساطعة ومتحركة، وتجد عينيك مثبّتتين عليها لعدة ثوانٍ بينما تمر بجانبها. أي عاقبة لهذا التحديق الثابت هي أخطر مصدر قلق على السلامة ينبغي أن يدركه سائق رخصة القيادة التجارية؟","options":["ستتكيّف عيناك مع الوهج وستفقد رؤيتك الليلية لحظياً","تتوقف عن مسح الطريق وتفشل في ملاحظة المخاطر الناشئة في أجزاء أخرى من مجال رؤيتك","ستبطئ لا شعورياً إلى ما دون تدفّق حركة المرور بكثير وتعيق المركبات خلفك","ستثبّت نظرك بحدّة على اللوحة لدرجة أنك ترى الطريق أمامك بوضوح أكبر"],"explanation":"التثبيت على شيء واحد يوقف عينيك عن مسح الطريق، فالمخاطر الناشئة في أماكن أخرى من مجال رؤيتك تمرّ دون ملاحظة حتى يفوت الأوان."},"430":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق ريفي بحارتين وتلحق بجرّار بطيء يبقيك أبطأ بـ 15 ميلاً في الساعة عن الحد المسموح. تريد التجاوز، لكن الطريق يتغير باستمرار. في أي من المواقع التالية يكون محاولة التجاوز الأقل أماناً والأكثر احتمالاً لوضعك في موقف اصطدام أمامي؟","options":["على طريق مستقيم طويل ومستوٍ حيث يمكنك أن ترى بوضوح ربع ميل على الأقل من الحارة المقابلة الخالية","على منحدر هابط لطيف حيث تزداد سرعتك طبيعياً ويمكنك إكمال التجاوز بسرعة","عند الاقتراب من قمة تل أو منعطف، حيث ينحني الطريق أمامك أو يرتفع بعيداً عن الأنظار","على امتداد مستقيم بخط مركزي متقطّع ولا حركة مرور مقابلة في الأفق"],"explanation":"لا تتجاوز أبداً عند الاقتراب من قمة تل أو منعطف، حيث يرتفع الطريق أو ينحني بعيداً عن الأنظار وقد تكون حركة المرور المقابلة مخفية."},"431":{"q":"أنت تقود شاحنتك المقطورة المحمّلة على طريق سريع بحارتين وتبدأ بتجاوز سيارة أبطأ. وبينما تتحرك بمحاذاتها، تدرك أنك تقضي عدة ثوانٍ تسير على مستوى الباب الخلفي للسيارة، جالساً تماماً في النقطة العمياء للسائق. لإكمال هذه المناورة بالأمان الذي تتطلبه إدارة السلامة العامة، ماذا ينبغي أن تفعل؟","options":["ارفع قدمك عن دواسة الوقود وابقَ على مستوى السيارة حتى يكون لدى السائق الآخر وقت كافٍ لملاحظتك قبل أن تتقدّم","ابقَ بجانب السيارة بسرعة متطابقة حتى تتأكد من عدم اقتراب حركة مرور مقابلة، ثم عُد إلى حارتك","حافظ على سرعتك الحالية وانحرف تدريجياً نحو حارتك بينما لا تزال بمحاذاة السيارة لتقصير التجاوز الكلي","عجّل حسب الحاجة لتعبر النقطة العمياء للسائق الآخر وتكمل التجاوز بسرعة، ثم عُد إلى حارتك دون التلكّؤ بجانب المركبة"],"explanation":"أكمل التجاوز بسرعة وابتعد عن النقطة العمياء للسائق الآخر، ثم عُد إلى حارتك دون التلكّؤ بجانبه."},"432":{"q":"أنت تقترب من تقاطع به ممر مشاة محدّد. الضوء أخضر لك وتريد الانعطاف يميناً، لكن أحد المشاة قد نزل بالفعل عن الرصيف إلى ممر المشاة الذي أنت على وشك عبوره. ماذا ينبغي أن تفعل؟","options":["أفسح الطريق ودع المشاة يكمل العبور، لأن للمشاة في ممر مشاة محدّد حق الأولوية","تابع انعطافك لأن ضوءك الأخضر يمنحك حق الأولوية على المشاة","أطلق نفير المنبّه لتنبيه المشاة وتابع الانعطاف إن لم يتوقف","توقف فقط إذا كان المشاة في حارة سيرك مباشرة، وإلا فاستمر في الحركة"],"explanation":"للمشاة الموجودين بشكل قانوني في ممر مشاة محدّد حق الأولوية دائماً، لذا يجب على السائق المنعطف أن يفسح الطريق حتى عند الضوء الأخضر."},"433":{"q":"أنت تقود شاحنتك المقطورة على شارع مدينة بحارتين، وراكب دراجة هوائية يسير أمامك في الجزء الأيمن من حارتك. حركة المرور معتدلة وأنت تقترب من منطقة سيارات مركونة قد يحتاج فيها راكب الدراجة للتحرك يساراً. أي إجراء يعكس بشكل أفضل كيف ينبغي أن تتعامل مع راكب الدراجة هذا؟","options":["ابقَ قريباً خلفه وأطلق نفيراً طويلاً ليعرف راكب الدراجة أن عليه الانتقال إلى الكتف","تعامل مع راكب الدراجة كما تتعامل مع أي مركبة أخرى، مانحاً إياه مساحة كاملة وفراغاً آمناً قبل التجاوز","مرّ بجانبه ضمن نفس الحارة لأن الدراجة تشغل مساحة أقل بكثير من السيارة","انتقل إلى الحارة اليسرى القصوى وابقَ فيها لبقية الجزء من الشارع"],"explanation":"لراكب الدراجة الهوائية الحق نفسه في الطريق مثل أي مركبة، لذا امنحه مساحة كاملة وفراغ تجاوز آمناً بدلاً من التضييق عليه."},"434":{"q":"أنت تقترب من دوّار متعدد الحارات في مركبتك المركّبة المحمّلة. حركة المرور تدور بالفعل داخل الدوّار، وفجوة تنفتح على يسارك لكن لا تزال مركبة تقترب من تلك الفجوة. أي إجراء هو الطريقة الصحيحة للدخول؟","options":["عجّل بقوة واندمج قبل أن تصل المركبة المقتربة إلى نقطة دخولك، لأن للمركبة الأكبر حق الأولوية","ادخل إلى الدائرة وتوقف توقفاً تاماً بمجرد دخولك، ثم انتظر هناك حتى تخلو كل حركة المرور المحيطة بك","أفسح الطريق لحركة المرور التي تدور بالفعل في الدوّار، وادخل فقط عندما توجد فجوة كبيرة بما يكفي لطول مركبتك الكامل","ادخل فوراً، وإن لزم الأمر، سِر عكس التدفّق للوصول إلى مخرجك بأقصر طريق"],"explanation":"لحركة المرور التي تدور بالفعل في الدوّار حق الأولوية، لذا ادخل فقط عندما توجد فجوة كبيرة بما يكفي لطول مركبتك الكامل."},"435":{"q":"لقد كانت تمطر بثبات خلال العشرين دقيقة الماضية والرصيف مبلّل تماماً. أنت تسير بسرعتك العادية على الطريق السريع الجاف وتحافظ على فجوة المتابعة المعتادة لديك البالغة 6 ثوانٍ خلف السيارة أمامك. مقارنةً بقيادة نفس هذا الامتداد على رصيف جاف، ما هو الأمر الأكثر أهمية الذي يجب أن تأخذه في الحسبان في كيفية قيادتك الآن؟","options":["لا شيء يتغير بالنسبة للتوقف؛ تطبّق مكابح الشاحنة القوة نفسها، لذا فإن فجوة المتابعة العادية على الطريق الجاف لا تزال كافية","تزداد مسافة ردّ فعلك لأن الطرق المبلّلة تبطئ إدراكك، لكن مسافة الكبح الفعلية تبقى كما هي بمجرد إمساك المكابح","تصبح مسافة التوقف أقصر بكثير لأن طبقة الماء تسمح للإطارات بالتدحرج بحرية أكبر وتقلّل المقاومة على الشاحنة","تصبح مسافة التوقف الكلية أطول لأن انخفاض الالتصاق يطيل مسافة الكبح، لذا يجب أن تبطئ وتزيد مسافة المتابعة"],"explanation":"الرصيف المبلّل يقلّل الالتصاق ويطيل مسافة الكبح، مما يزيد مسافة التوقف الكلية، لذا أبطئ وزِد مسافة المتابعة."},"436":{"q":"الوصول إلى غرض على الأرضية أثناء القيادة محفوف بالمخاطر لأنه:","options":["يوفّر لك بعض الوقت","يبعد عينيك عن الطريق","يبرّد المقصورة","يساعدك على التركيز أكثر"],"explanation":"الوصول إلى الأغراض يبعد عينيك وذهنك عن القيادة."},"437":{"q":"أنت في الدقيقة التسعين من رحلة عندما يبلّغك المرسل عبر اللاسلكي أن عنوان التسليم قد تغيّر وأنك بحاجة إلى مسار جديد في نظام تحديد المواقع. حركة المرور خفيفة وأنت تسير بسرعة الطريق السريع. أي إجراء هو الطريقة الأكثر أماناً للتعامل مع الوجهة الجديدة؟","options":["انتظر حتى تتمكن من الخروج عن الطريق والركن في مكان آمن، ثم أدخِل واضبط المسار الجديد قبل القيادة مجدداً","أدخِل العنوان الجديد عند الضوء الأحمر التالي بينما أنت متوقف، ثم انطلق بمجرد تحميله","ثبّت الجهاز منخفضاً قرب المقود واكتب العنوان هناك لتبقى عيناك قريبتين من الطريق","استمر في القيادة وانظر ذهاباً وإياباً بين نظام تحديد المواقع والطريق أثناء كتابة الوجهة الجديدة"],"explanation":"اضبط نظام تحديد المواقع دائماً قبل القيادة وليس أثناء الحركة، لذا اخرج عن الطريق إلى مكان آمن، وأدخِل المسار الجديد، ثم استأنف القيادة."},"438":{"q":"إذا تورّطت في حادث، يُلزمك القانون بأن:","options":["تقود مبتعداً بسرعة","تتوقف ولا تغادر","تتابع طريقك إلى المنزل","تختبئ من الشرطة"],"explanation":"يجب أن تتوقف ولا تغادر موقع الحادث."},"439":{"q":"تورّطت شاحنتك المقطورة للتو في تصادم وهي متوقفة تسدّ جزءاً من طريق ريفي غير مقسوم بحارتين. تقترب مركبات أخرى من كلا الاتجاهين. بعد أن شغّلت أضواء التحذير الوامضة، ما هي أفضل طريقة لتحذير حركة المرور المقتربة؟","options":["اترك أضواء التحذير الوامضة وحدها، لأن القانون يتطلب الأضواء الوامضة فقط في الحادث","خلال 10 دقائق، ضع مثلثات التحذير العاكسة -- واحد على بعد نحو 100 قدم خلفك، وواحد على بعد نحو 100 قدم أمامك، وواحد على بعد نحو 10 أقدام خلف المركبة مباشرة","قف في حارة السير ولوّح بذراعيك حتى يراك السائقون بوضوح ويبطئوا","استمر في إطلاق نفير المنبّه بشكل متواصل حتى تتوقف كل المركبات المقتربة"],"explanation":"خلال 10 دقائق من التوقف على طريق غير مقسوم، ضع مثلثات التحذير على بعد نحو 100 قدم خلفك، ونحو 100 قدم أمامك، ونحو 10 أقدام خلف المركبة مباشرة."},"440":{"q":"الأكل أثناء القيادة محفوف بالمخاطر بشكل رئيسي لأنه:","options":["يهدر طعامك الجيد","يشتّت انتباهك عن القيادة","يستهلك وقوداً أكثر","يدفّئ المقصورة بشكل جيد"],"explanation":"الأكل يشتّت انتباهك عن مهمة القيادة."},"441":{"q":"أنت تقود شاحنة مقطورة محمّلة بسرعة 60 ميلاً في الساعة على طريق ريفي بحارتين عندما تلاحظ في مرآتك أن شاحنة صغيرة (بيك أب) كانت تلتصق بمؤخرتك عن قرب لعدة أميال. حركة المرور أمامك خفيفة وثابتة. أي إجراء هو الأفضل لتقليل الخطر الذي يسببه هذا الملاصق؟","options":["اضغط على مكابحك بخفة عدة مرات لإشارة الشاحنة الصغيرة بالتراجع وثنيها عن الاتباع بهذا القرب","حافظ على سرعتك لكن انتقل إلى الحافة اليسرى من حارتك حتى تتمكن الشاحنة الصغيرة من رؤية مسافة كافية أمامها لتجاوزك بأمان","زِد تدريجياً مسافة متابعتك للمركبة أمامك حتى يكون لديك مساحة إضافية للإبطاء بسلاسة بدلاً من الكبح بقوة","عجّل لفتح فجوة بينك وبين الشاحنة الصغيرة حتى لا تعود قريبة بما يكفي لتشكّل خطراً"],"explanation":"عند الملاصقة من الخلف، افتح مساحة أكبر أمامك حتى تتمكن من الإبطاء تدريجياً بدلاً من الكبح بقوة، مما يمنح السائق خلفك وقتاً أكبر لردّ الفعل."},"442":{"q":"أنت تقود شاحنة مقطورة محمّلة بسرعة 55 ميلاً في الساعة على طريق جاف بحارتين عندما تبدأ سيارة ركاب بالالتصاق بمؤخرتك عن قرب. السائق نافد الصبر ويريد بوضوح أن تبتعد عن طريقه. تريد تقليل الخطر الذي يسببه هذا الملاصق دون أن تزيد الوضع سوءاً. أي مما يلي هو أسوأ ما يمكنك فعله رداً على ذلك؟","options":["حافظ على سرعة ثابتة ومنتظمة حتى تتمكن السيارة خلفك من تقدير فجوة آمنة وتجاوزك في النهاية","ارفع قدمك عن دواسة الوقود تدريجياً لفتح مساحة أكبر أمامك كحاجز وقاية","التزم باليمين وتجنّب الحركات المفاجئة حتى يكون لدى الملاصق مساحة للالتفاف حولك","زِد سرعتك للابتعاد عن الملاصق ووضع مسافة أكبر بين المركبتين"],"explanation":"زيادة السرعة للتخلّص من ملاصق أمر خاطئ لأنه يبقيه يتبعك عن قرب بينما يرفع السرعة ومسافة التوقف لكلتا المركبتين."},"443":{"q":"الجو أدنى قليلاً من درجة التجمّد في صباح صافٍ وأنت تنقل حمولة على طريق ريفي. يبدو الرصيف أمامك مبلّلاً فحسب، لكنك تقترب من جسر علوي طويل يمتد فوق نهر. أي عبارة ينبغي أن تؤثّر أكثر في كيفية تعاملك مع الجسر العلوي؟","options":["يمكن أن يكون سطح الجسر العلوي مجمّداً وثلجياً قبل الطريق المحيط، لأنه يفقد الحرارة من الأعلى والأسفل.","سيكون الجسر العلوي آخر سطح يتجمّد، لذا فهو أأمن مكان للكبح بقوة إن لزم الأمر.","لا تصبح أسطح الجسور والجسور العلوية زلقة إلا في الصيف عندما يطفو القار عبر الرصيف.","لا تتجمّد الأسطح المرتفعة أبداً طالما أن طريق الاقتراب لا يزال يبدو مبلّلاً بدلاً من أبيض."],"explanation":"تتجمّد الجسور والجسور العلوية قبل الطريق لأنها تفقد الحرارة من الأعلى والأسفل، لذا يمكن أن تكون ثلجية بينما يكون الطريق مبلّلاً فقط."},"444":{"q":"إنه صباح خريفي بارد ورطب وأنت تقود مركبة مركّبة محمّلة على طريق ريفي بحارتين. وأنت تخرج من منعطف، ترى أن الرصيف أمامك مغطّى بطبقة كثيفة من أوراق الشجر المبلّلة المتساقطة تمتد عبر الحارتين. أي عبارة تصف بشكل أفضل كيف ينبغي أن تتعامل مع هذا الامتداد من الطريق؟","options":["تضيف الأوراق التماسك بنفس طريقة الرمل المبلّل، لذا يمكنك الحفاظ على سرعتك الحالية بأمان عبر المنطقة.","تعامل مع الرصيف المغطّى بالأوراق كسطح زلق، مخفّفاً قدمك عن دواسة الوقود ومتجنّباً الكبح أو التوجيه الحاد حتى تتجاوزه.","لأن الأوراق عضوية وطرية، فإنها توسّد الإطارات وليس لها تأثير فعلي على التماسك أو مسافة التوقف.","تفقد الإطارات الأمامية (محور التوجيه) فقط التماسك على الأوراق، لذا فإن الكبح الخفيف بالعجلات الدافعة يبقيك متحكّماً تماماً."],"explanation":"تشكّل الأوراق المبلّلة طبقة زلقة منخفضة التماسك مثل الجليد، لذا خفّف قدمك عن دواسة الوقود وتجنّب الكبح أو التوجيه الحاد حتى تتجاوزها."},"445":{"q":"الجو أدنى قليلاً من درجة التجمّد والشمس مشرقة بينما تقود على طريق ريفي بحارتين. تبدو الامتدادات المفتوحة المشمسة من الرصيف جافة، لكن الطريق يمر مراراً تحت غطاء الأشجار وبمحاذاة سدود مرتفعة موجّهة نحو الشمال تبقى في الظل. وأنت تقترب من أحد هذه الأقسام المظلّلة، ما هو أكبر خطر ينبغي أن تتوقع أن يخفيه الظل؟","options":["قار طافٍ ليّن بفعل الشمس وجعل السطح زلقاً","حصى مفكّك دفعته حركة المرور إلى المنخفضات المظلّلة","رقعة من الجليد، لأن الرصيف المظلّل لم يدفأ أبداً فوق درجة التجمّد رغم أن الامتدادات المشمسة جافة","طلاء علامات رصيف جديد لم يجفّ تماماً بعد في البرد"],"explanation":"لا يتلقّى الرصيف المظلّل ضوء شمس مباشراً، لذا تبقى الرطوبة هناك متجمّدة حتى عندما تكون الامتدادات المشمسة الجافة قد دفئت فوق درجة التجمّد."},"446":{"q":"أنت تقود شاحنتك المقطورة على طريق سريع بين الولايات مبلّل أثناء مطر ثابت. صفّ من الشاحنات يتجاوزك في الحارة اليسرى، وكل واحدة منها ترمي طبقة كثيفة من رذاذ الطريق عبر زجاجك الأمامي وهي تمرّ. وأنت تفكّر في كيفية تأثير هذا الرذاذ عليك وعلى قدرتك على القيادة بأمان، أي عبارة هي أفضل وصف لتأثيره الرئيسي؟","options":["يبرّد أسطوانات مكابحك، لذا يمكنك الاعتماد عليها بشكل أكبر في المنحدر التالي","يزيد عمق مداس إطاراتك، مما يساعدك على البقاء فوق الحد الأدنى للإطار الأمامي البالغ 4/32 من البوصة","يغسل الأوساخ عن الطريق، مما يحسّن التماسك بين إطاراتك والرصيف","يُعميك لحظياً بقطع رؤيتك، لذا ينبغي أن تبطئ وتزيد مسافة متابعتك"],"explanation":"يغطّي رذاذ الطريق من الشاحنات المتجاوزة زجاجك الأمامي لحظياً ويقطع الرؤية بحدّة، لذا أبطئ وزِد مسافة متابعتك."},"447":{"q":"أنت تقود شاحنة مقطورة بطول 53 قدماً وتحتاج إلى الانعطاف يميناً بحدّة من شارع مدينة إلى زقاق ضيق. تلاحظ سيارة مركونة ورصيفاً على الجانب الداخلي (الأيمن) من المنعطف. بسبب الانحراف عن المسار، أي مما يلي يصف بشكل أفضل ما يجب أن تخطّط له وأنت تدير الشاحنة عبر هذا المنعطف؟","options":["ستتبع العجلات الخلفية لمقطورتك مساراً داخل مسار عجلاتك الأمامية، لذا قد تقطع الإطارات الخلفية فوق الرصيف أو تصطدم بالسيارة المركونة على الجانب الداخلي من المنعطف","ستتبع العجلات الخلفية لمقطورتك مساراً أوسع إلى خارج العجلات الأمامية، لذا ستتأرجح مؤخرة المقطورة نحو حركة المرور المقابلة على اليسار","ستتبع عجلاتك الأمامية والخلفية المسار نفسه تماماً، فإن تجاوزت إطارات التوجيه الرصيف فستتجاوزه إطارات المقطورة أيضاً","لا يهم الانحراف عن المسار إلا في سرعة الطريق السريع، لذا في سرعة الانعطاف المنخفضة هذه تتبع كل مجموعات العجلات الأربع نفس الخط أساساً"],"explanation":"بسبب الانحراف عن المسار، تتبع العجلات الخلفية للمقطورة الطويلة مساراً داخل العجلات الأمامية، لذا انعطف بشكل أوسع بما يكفي لإبقاء الإطارات الخلفية بعيدة عن الرصيف الداخلي أو المركبات."},"448":{"q":"أنت تقود شاحنة مقطورة بطول 53 قدماً ويجب أن تنعطف يميناً بحدّة من شارع ضيق بحارتين إلى شارع ضيق آخر. أنت تعلم أنه لأن العجلات الخلفية لمقطورتك تتبع مساراً أقصر وأضيق من العجلات الأمامية لجرّارك (الانحراف عن المسار)، عليك التخطيط لانعطافك بعناية. لإكمال هذا الانعطاف يميناً بأمان دون أن تصعد العجلات الخلفية لمقطورتك فوق الرصيف، ماذا يجب أن تأخذه في الحسبان؟","options":["بسبب الانحراف عن المسار، تتأرجح مؤخرة المقطورة بشكل واسع، لذا تحتاج فقط إلى مساحة إضافية على الجانب الخارجي (الأيسر) من المنعطف","بسبب الانحراف عن المسار، تقطع العجلات الخلفية للمقطورة داخل مسار الجرّار، لذا تحتاج إلى مساحة إضافية على الجانب الداخلي من المنعطف","لا يؤثّر الانحراف عن المسار على منعطف بهذه الحدّة، لذا لا حاجة إلى مساحة إضافية في أي اتجاه","لأن المركبة طويلة، تحتاج إلى مساحة أقل على الجانب الداخلي لأن المقطورة تتبع مساراً مستقيماً خلف الجرّار"],"explanation":"يجعل الانحراف عن المسار العجلات الخلفية للمقطورة تقطع داخل مسار الجرّار، لذا احجز مساحة إضافية على الجانب الداخلي من المنعطف."},"449":{"q":"أنت تندمج في طريق سريع بين الولايات مزدحم في شاحنتك المقطورة، وسيارة صغيرة تختفي عن الأنظار خلف مرآتك الجانبية اليمنى مباشرة، حيث لم تعد تراها على الإطلاق. قبل أن تغيّر الحارة، كيف ينبغي أن تصف وتتعامل بشكل صحيح مع هذه المنطقة المحددة حول شاحنتك؟","options":["إنها منطقة منخفضة التماسك، لذا ينبغي أن أكبح بلطف قبل التوجيه إلى الحارة.","إنها منطقة حاجز وقاية يتحمّل السائقون الآخرون مسؤولية إبقائها خالية عن مقطورتي.","إنها إحدى نقاطي العمياء، وتُسمى أيضاً المنطقة المحظورة (No-Zone)، حيث يصعب عليّ رؤية السائقين الآخرين، لذا يجب أن أتفقّد بعناية قبل الانتقال.","إنها منطقة الخطر التي ينشئها فقط مركز ثقلي المرتفع عندما تكون المقطورة محمّلة."],"explanation":"المناطق حول الشاحنة التي يصعب فيها رؤية السائقين الآخرين هي النقاط العمياء، وتُسمى المناطق المحظورة (No-Zones)، ويجب تفقّدها بعناية قبل تغيير الحارة."},"450":{"q":"أنت تدمج شاحنتك المقطورة في طريق سريع مزدحم. سيارة ركاب كنت تراها بوضوح في مرآتك الجانبية اليمنى قبل لحظة قد اختفت الآن تماماً من تلك المرآة، ولا تراها أمامك أيضاً. قبل أن تواصل تغيير المسار، ماذا يعني هذا الاختفاء على الأرجح؟","options":["السيارة سرّعت وأصبحت الآن بعيدة خلفك، لذا فإن المسار خالٍ","السيارة كبحت بقوة وانحرفت إلى الكتف الأيمن، خارج الطريق تماماً","مرآتك غير مضبوطة وتحتاج إلى إعادة ضبطها أثناء توقفك التالي","انتقلت السيارة إلى منطقة عمياء (\"منطقة محظورة\") بمحاذاة مقطورتك حيث لم تعد مرآتك قادرة على إظهارها"],"explanation":"المركبة التي تختفي من مرآتك من المرجح أنها دخلت منطقة عمياء (منطقة محظورة) بمحاذاة مقطورتك، لذا لا تغيّر المسار أبداً حتى تتمكن من تحديد موقعها مجدداً."},"451":{"q":"أنت تقود شاحنة مقطورة محمّلة على طريق سريع من أربعة مسارات وتقرر الانتقال من المسار الأيمن إلى المسار الأيسر لتجاوز مركبة بطيئة. تتفقد مرآتيك المسطحة والمحدّبة (النقطية)، وتراهما خاليتين على ما يبدو، وتشير مبكراً. وبينما تبدأ بالتحرك جانباً، فإن الخطر الأكبر عليك هو مركبة تقع أين؟","options":["في المنطقة العمياء بمحاذاة مقطورتك، وهي منطقة لا تظهرها مرآتاك","على بُعد مسارين في أقصى المسار الأيسر، ظاهرة جزئياً في مرآتك المحدّبة","خلف مقطورتك مباشرة حيث تكون أضواء الفرامل مرئية","أمامك في مسارك نفسه، وهي المركبة البطيئة التي تنوي تجاوزها"],"explanation":"للشاحنات الكبيرة مناطق عمياء (مناطق محظورة) على الجوانب والخلف لا تظهرها المرايا، لذا يلزم النظر فوق الكتف قبل تغيير المسار."},"452":{"q":"المساحة التي تحتاج إلى إدارتها أكثر من غيرها أثناء القيادة هي المساحة:","options":["خلفك","أمامك","تحتك","فوقك"],"explanation":"المساحة أمامك هي الأهم لإدارتها."},"453":{"q":"أنت على وشك مغادرة المحطة لرحلة طولها 400 ميل تعبر ممراً جبلياً، وتريد التخطيط للرحلة بالطريقة الصحيحة قبل الانطلاق. أي مما يلي هو الأهم للتحقق منه أثناء تخطيطك للرحلة؟","options":["ما إذا كانت قائمة الموسيقى المفضلة لديك محمّلة لتبقى متيقظاً في القيادة الطويلة","مسارك المخطط له وأحوال الطقس الحالية على طول الطريق","أن عاداتك في مسافة المتابعة ستمنحك ثانية واحدة لكل 10 أقدام من طول المركبة","ما إذا كانت محطات الاستراحة على طريقك تقدّم نوع الطعام الذي تحبه للغداء"],"explanation":"التخطيط الجيد للرحلة يعني معرفة مسارك والطقس على طوله مسبقاً، حتى تتمكن من اختيار التروس والسرعة والتوقيت لظروف لا يمكنك التحكم بها."},"454":{"q":"الجو أقل بقليل من درجة التجمد، وقد بدأ مطر خفيف يجمّد سطح الجسور على طريقك، والحد الأقصى للسرعة المعلن هو 55 ميلاً في الساعة. حركة المرور خفيفة وما زال الرصيف يبدو رطباً فقط. بموجب قواعد إدارة السلامة العامة في تكساس، في أي من هذه الحالات يُطلب منك القيادة بسرعة أقل من الحد المعلن؟","options":["عندما يكون الطريق أمامك واضحاً وجافاً، لأن المسار الواضح يتيح لك استخدام كامل السرعة المعلنة وهي 55 ميلاً في الساعة بأمان","عندما تكون حركة المرور حولك خفيفة، لأن عدد المركبات الأقل يعني سبباً أقل لتخفيض سرعتك","عندما تكون الظروف سيئة — مثل السطح الرطب القريب من التجمد والجسور المحتمل تجمّدها التي تواجهها الآن — لأن السرعة الآمنة تتحدد بالاحتكاك والرؤية، لا بالرقم المعلن","عندما تكون متأخراً عن الجدول الزمني، لأن الإسراع في الطقس السيئ يتيح لك تعويض الوقت الضائع"],"explanation":"السرعة الآمنة تتحدد بالاحتكاك والرؤية، لا بالحد المعلن، لذا خفّف السرعة على الطرق الرطبة القريبة من التجمد والجسور المتجمدة حيث يمكن أن يختبئ الجليد الأسود."},"455":{"q":"أنت تنقل مقطورة محمّلة على طريق ريفي سريع حده المعلن 55 ميلاً في الساعة. بدأ رذاذ بارد والرصيف يلمع رطباً. تشعر بالارتياح وحركة المرور خفيفة. أي عبارة تصف بأفضل شكل كيف ينطبق حد الـ 55 ميلاً في الساعة المعلن عليك الآن؟","options":["حد الـ 55 ميلاً في الساعة هو حد أدنى قانوني كما هو حد أقصى، لذا فإن النزول كثيراً تحته يُعد بحد ذاته مخالفة في هذه الظروف","لأن شاحنتك محمّلة ولديها احتكاك جيد، تبقى الـ 55 ميلاً في الساعة المعلنة سرعة هدف آمنة على الرصيف الرطب","تتضمن الحدود المعلنة بالفعل هامش أمان مدمج للمطر، لذا تبقى الـ 55 ميلاً في الساعة مناسبة حتى يغمر الماء الطريق تماماً","الـ 55 ميلاً في الساعة المعلنة هي الحد الأقصى للظروف المثالية فقط، لذا على الطريق الرطب تكون السرعة الآمنة أقل من الحد المعلن"],"explanation":"الحد المعلن هو الحد الأقصى القانوني للظروف المثالية فقط، لذا على طريق رطب، حيث ينخفض الاحتكاك وتزداد مسافة التوقف، قُد بسرعة أقل من الحد المعلن."},"456":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع مزدحم بين الولايات في ساعة الذروة. حركة المرور كثيفة وتتحرك بثبات، مع وجود مركبات تحاصرك من الجانبين. تريد الوصول إلى التسليم في الوقت المحدد لكنك تعرف أيضاً أن مسافة توقفك طويلة. أي إجراء يمنحك أفضل تحكم وأقل خطر اصطدام في هذه الحركة الكثيفة؟","options":["حافظ على سرعة ثابتة تتوافق مع تدفق المرور واحتفظ بمسافة جيدة أمامك لتكون لديك مساحة للتوقف","غيّر المسارات بشكل متكرر للعثور على الفجوة الأسرع حركة وتعويض الوقت الضائع","سِر قريباً خلف المركبة التي أمامك حتى لا تتمكن السيارات الأخرى من اقتحام مساحتك","اكبح بقوة وبشكل متكرر للحفاظ على سرعتك أقل بكثير من تدفق المرور"],"explanation":"في الحركة الكثيفة، حافظ على سرعة ثابتة تتوافق مع تدفق المرور واحتفظ بمساحة كافية أمامك لتكون لديك مساحة لمسافة توقفك الطويلة."},"457":{"q":"إذا كانت حركة المرور تتجاوزك من كلا الجانبين، فأنت على الأرجح تسير:","options":["بسرعة مناسبة تماماً","ببطء شديد","بسرعة كبيرة","بشكل مثالي"],"explanation":"تجاوزك من كلا الجانبين يعني عادة أنك بطيء جداً."},"458":{"q":"أنت تقود شاحنتك المقطورة على طريق ريفي تلّي غير مقسوم من مسارين. تلحق بجرّار زراعي بطيء وتريد تجاوزه، لكن الطريق أمامك يصعد تلة فلا يمكنك رؤية ما يأتي من فوقها. أي مما يلي يصف بأفضل شكل متى يجب ألا تبدأ التجاوز؟","options":["عندما يكون لديك طريق مستقيم طويل وواضح والمسار المقابل خالٍ لمسافة ربع ميل","عندما يصعد الطريق تلة أو منعطفاً ولا يمكنك الرؤية لمسافة كافية أمامك لإكمال التجاوز بأمان","عندما يكون هناك طريق مفتوح واسع ورؤية جيدة لكن المركبة أمامك تتحرك ببطء","فقط عندما تكون مركبة قادمة بالفعل على بُعد 500 قدم وتومض بأضوائها العالية"],"explanation":"لا تتجاوز أبداً عندما تحجب قمة تلة أو منعطف رؤيتك، لأنك لا تستطيع رؤية ما إذا كان المسار المقابل خالياً طوال المناورة."},"459":{"q":"لقد ربطت مقطورتك للتو برصيف تحميل أحد العملاء في ساحة ضيقة غير مألوفة. الرصيف مخفي جزئياً خلف مقطورتك، وهناك منصات نقالة مكدّسة قريبة، ومرآتاك لا تظهران الأقدام القليلة السفلية مباشرة خلف الشاحنة. قبل أن تضع الشاحنة في وضع الرجوع للخلف، ماذا يجب أن تفعل أولاً للرجوع بأمان؟","options":["ابدأ الرجوع ببطء معتمداً على مرآتيك، لأنهما تمنحانك المنظر الأوسع والأكثر موثوقية للمنطقة خلف المقطورة","أطلق بوقك ثلاث مرات ثم ارجع بسرعة ثابتة، واثقاً من أن النفخات ستحذّر أي شخص في المسار خلفك","انزل من المقصورة وامشِ إلى الخلف لتفحص المسار والمساحات الخالية وأي مناطق عمياء قبل أن تبدأ التحرك","ارجع بسرعة لتجتاز المنطقة العمياء قبل أن تتاح الفرصة لأي مشاة أو رافعة شوكية للتحرك إلى مسارك"],"explanation":"انزل وانظر دائماً (G.O.A.L.) قبل الرجوع للخلف لتفحص المسار والمساحات الخالية والمناطق العمياء التي لا تستطيع المرايا إظهارها."},"460":{"q":"أنت بمفردك في ساحة تحميل ضيقة وعليك أن ترجع بشاحنتك المقطورة إلى رصيف يقع نحو الجانب الأيمن (جانب الراكب). لتحريك مؤخرة المقطورة نحو ذلك الرصيف الأيمن، تبدأ بإدارة عجلة القيادة إلى اليمين. في اللحظة الأولى تماماً بعد أن تبدأ الرجوع والعجلة مُدارة إلى اليمين، وقبل أي تصحيح أكبر، في أي اتجاه تتحرك مؤخرة المقطورة في البداية؟","options":["تتأرجح مؤخرة المقطورة فوراً إلى اليمين، الاتجاه نفسه الذي أدرت العجلة إليه، فتوجّه مباشرة نحو الرصيف.","تتتبع المقطورة الرجوع للخلف في خط مستقيم مع الجرّار ولا تبدأ بالميل إلا عندما تضيف وقوداً.","ترتفع مؤخرة المقطورة وتتجه إلى اليمين نحو مدخل الرصيف بينما يدفعها الجرّار.","تتحرك مؤخرة المقطورة أولاً إلى اليسار، عكس الاتجاه الذي أدرت العجلة إليه، قبل أن توجّه عكسياً لتعيدها إلى اليمين."],"explanation":"عند الرجوع للخلف، تتحرك مؤخرة المقطورة أولاً عكس اتجاه توجيهك، فإدارة العجلة إلى اليمين ترسل المؤخرة إلى اليسار قبل أن توجّه عكسياً."},"461":{"q":"أنت تنقل شاحنة جافة طولها 53 قدماً على طريق سريع مزدحم بين الولايات من ثلاثة مسارات وتبدأ بالانحراف نحو المسار المجاور. وبإلقاء نظرة على مرآتيك لا تستطيع رؤية سيارتين تسيران بمحاذاتك. استناداً إلى المناطق المحظورة للشاحنة، في أي منطقة خطر تختبئ هاتان المركبتان على الأرجح الآن؟","options":["في المناطق العمياء الممتدة على طول الجانبين الأيمن والأيسر للمقطورة","أمام المقصورة مباشرة حيث يحجب غطاء المحرك رؤيتك","قريباً خلف مؤخرة المقطورة حيث لا تصل مرآتاك","عالياً في الأعلى، في المنطقة فوق سطح المقطورة"],"explanation":"المركبات التي تسير بمحاذاتك يمكن أن تختبئ في المناطق العمياء الجانبية الممتدة على طول يمين ويسار المقطورة، والجانب الأيمن هو الأكبر."},"462":{"q":"أنت تنقل مقطورة محمّلة على طريق مزدحم بين الولايات من أربعة مسارات بسرعة 60 ميلاً في الساعة. بدأ صف من السيارات يتكدّس قريباً خلفك في المسار الأيمن، وتحس أن عدداً منها يستعد للتجاوز. لإدارة المساحة خلف شاحنتك بشكل صحيح والبقاء على دراية بهذه المركبات، ماذا يجب أن تفعل؟","options":["توقف عن استخدام مرآتيك وركّز فقط على الطريق البعيد أمامك، لأن ما خلفك لا يمكن أن يؤثر على قيادتك","ألقِ نظرة على مرآتيك بانتظام (تقريباً كل 5 إلى 8 ثوانٍ) لتتبّع المركبات المقتربة خلفك وبجانبك","سرّع إلى ما فوق 60 ميلاً في الساعة بكثير حتى تتراجع السيارات خلفك وتنفتح المساحة من تلقاء نفسها","اضغط على فراملك بشكل متكرر لإجبار الملتصقين خلفك على التراجع وخلق مساحة خلفك"],"explanation":"لا يمكنك التحكم بالمساحة خلفك، لذا تفقّد مرآتيك بانتظام، تقريباً كل 5 إلى 8 ثوانٍ، لتتبّع المركبات المقتربة خلفك وبجانبك."},"463":{"q":"أنت تقود شاحنة مقطورة محمّلة بسرعة 55 ميلاً في الساعة على طريق مستوٍ بين الولايات عندما ترى أضواء فرامل تنتشر عبر المسارات على بُعد ربع ميل أمامك وتبدأ كتلة المرور بالانضغاط نحوك. مسافة المتابعة تتقلص. أي استجابة تدير مساحتك وطاقتك بأفضل شكل في هذا الموقف المتطور؟","options":["حافظ على سرعتك ووجّه نحو مسار الكتف لتتمكن من الالتفاف حول الكتلة المتباطئة قبل أن تتوقف تماماً","اكبح بقوة وحزم الآن لتخفيض السرعة بسرعة، لأن التوقف عند 55 ميلاً في الساعة يستغرق بالفعل نحو 419 قدماً","ارفع قدمك عن دواسة الوقود ودع مسافة متابعتك تتسع مجدداً، واكبح بلطف فقط حسب الحاجة بينما تتطور الفجوة أمامك","حافظ على سرعتك الآن واحتفظ بثانية واحدة على الأقل من مسافة المتابعة لكل 10 أقدام من طول المركبة حتى تُضطر إلى رد الفعل"],"explanation":"عندما تتباطأ حركة المرور أمامك، ارفع قدمك عن دواسة الوقود لتدع مسافة متابعتك تتسع مجدداً، واكبح بلطف فقط حسب الحاجة."},"464":{"q":"أنت تنقل حمولة مفرطة العرض على طريق ريفي ضيق من مسارين بلا كتف. الشاحنات الصغيرة القادمة تظل تزاحم خط المنتصف، وحافة الرصيف تنحدر بحدة على يمينك، وصناديق البريد والسيارات المتوقفة تقع قريبة من مسار السير. لإدارة الخطر الأكبر الذي تخلقه مركبتك العريضة هنا، أين يجب أن تركّز معظم انتباهك؟","options":["على سطح الطريق البعيد أمامك، لتتمكن من رصد الحفر قبل أن تصل إليها إطاراتك الأمامية","على المساحة فوق مقطورتك، مراقباً الأغصان المنخفضة والأسلاك العلوية","على المساحة تحت المقطورة، متفقداً ألا يكون شيء يُجَرّ تحت الهيكل","على المساحة على جانبيك، لأن عرض مركبتك يترك مسافة خلوص ضئيلة عن حركة المرور القادمة والانحدار والأجسام على جانب الطريق"],"explanation":"على مركبة عريضة في طريق ضيق بلا كتف، راقب مسافة الخلوص الجانبية أكثر من غيرها، لأن حركة المرور القادمة والانحدارات والأجسام على جانب الطريق تزاحم كلا الجانبين."},"465":{"q":"تنهي رحلة تسليم طويلة وتتوقف عند ميزان على جانب الطريق. يطلب منك ضابط إجراء اختبار نفَس. كنت قد شربت كأسين من البيرة مع العشاء قبل نحو ساعة وتشعر بصحو تام، وتعلم أن الحد لسائق سيارة ركاب عادية في ولايتك هو 0.08. ما أدنى تركيز للكحول في الدم (BAC) تُحرَم عنده من القيادة، وأنت تشغّل مركبتك التي تتطلب رخصة قيادة تجارية؟","options":["0.04 أو أكثر","0.08 أو أكثر","0.10 أو أكثر","0.02 أو أكثر"],"explanation":"بالنسبة لسائق يحمل رخصة قيادة تجارية ويشغّل مركبة تجارية، الحد القانوني هو تركيز كحول في الدم 0.04 بالمئة أو أكثر، وهو نصف الحد للسائقين العاديين."},"466":{"q":"تم إيقافك في تفتيش على جانب الطريق أثناء تشغيلك مركبتك التجارية، ولدى الضابط سبب معقول لطلب خضوعك لاختبار يقيس تركيز الكحول في دمك. تشعر بالتأكد أنك تحت الحد القانوني البالغ 0.04٪ وتقلق من أن الاختبار قد يكون غير دقيق، لذا تخبر الضابط أنك تفضّل ببساطة رفضه. بموجب قواعد رخصة القيادة التجارية، ما عواقب ذلك الرفض؟","options":["لا يحدث شيء لرخصتك التجارية ما دام تركيز الكحول الفعلي لديك أقل من 0.04٪","تُحرَم من تشغيل مركبة تجارية، وتُعامَل تماماً كما لو أنك رسبت في الاختبار","تتلقى فقط غرامة إدارية صغيرة لكنك تحتفظ بكامل امتيازات القيادة","تتلقى تحذيراً مكتوباً عند الرفض الأول وتُعاقَب فقط إذا رفضت مرة أخرى"],"explanation":"رفض اختبار كحول مطلوب قانونياً يحرمك من تشغيل مركبة تجارية، وهي العقوبة نفسها للرسوب في الاختبار."},"467":{"q":"أنت عائد إلى جرّارك بعد العشاء أثناء نقلة ليلية عندما يوقفك شرطي ولاية عند نقطة تفتيش على جانب الطريق. يُظهر اختبار كيميائي أن تركيز الكحول في دمك 0.06٪، أي فوق حد رخصة القيادة التجارية البالغ 0.04٪، وتُدان بتشغيل المركبة التجارية تحت تأثير الكحول. هذه أول إدانة من هذا النوع في سجلك. بافتراض عدم وجود مواد خطرة، ما الحد الأدنى للمدة التي ستُحرَم فيها من رخصتك التجارية؟","options":["60 يوماً، وهي المدة نفسها المستخدمة لنمط من المخالفات المرورية الجسيمة","90 يوماً، وهي الحد الأدنى لمدة الإيقاف عن الخدمة لتزوير سجل القيادة","سنة واحدة من الحرمان","ثلاث سنوات، مثل المخالفة الأولى أثناء نقل مواد خطرة"],"explanation":"الإدانة الأولى بقيادة مركبة تجارية بتركيز كحول في الدم 0.04٪ أو أعلى تحمل حرماناً من رخصة القيادة التجارية لمدة سنة واحدة على الأقل عند عدم وجود مواد خطرة."},"468":{"q":"مغادرة موقع حادث أنت طرف فيه قد تؤدي إلى:","options":["إفلات من العقاب","الحرمان من الرخصة","مكافأة نقدية","لا شيء سيئ"],"explanation":"مغادرة موقع الحادث قد تؤدي إلى الحرمان من الرخصة."},"469":{"q":"تم إيقافك في محطة وزن تابعة لإدارة السلامة العامة في تكساس أثناء تفتيش على جانب الطريق. لقد تأكد الضابط بالفعل من أن رخصة قيادتك التجارية (CDL) صالحة وأن سجل قيادتك منظّم. ثم يطلب منك إبراز مستند آخر تتطلب القواعد الفيدرالية الاحتفاظ به معك كلما شغّلت المركبة، لإثبات أنك مؤهل بدنياً للقيادة. أي مستند يجب أن تسلّمه إياه؟","options":["شهادة تخرّجك من مدرسة تدريب رخصة القيادة التجارية، التي تثبت إكمالك التعليم المطلوب للسائق المبتدئ","شهادة ملكية مركبتك، التي تثبت أن الشاحنة مسجّلة قانونياً ومصرّح لها بالسير على الطريق","شهادة ميلادك الأصلية، التي تثبت هويتك وأهليتك القانونية لحمل الرخصة التجارية","شهادة الفاحص الطبي الخاصة بك، التي تثبت أنك مؤهل بدنياً حالياً لتشغيل مركبة تجارية"],"explanation":"يجب أن تحمل شهادة الفاحص الطبي (البطاقة الطبية) مع رخصة قيادتك التجارية، لأنها تثبت أنك مؤهل بدنياً حالياً للقيادة."},"470":{"q":"أنت متأخر نحو 30 دقيقة عن جدولك على طريق سريع مقسوم من أربعة مسارات. السائق أمامك يتحرك أبطأ مما تريد، لذا تزن خياراتك. بموجب قواعد إدارة السلامة العامة في تكساس، أي من الإجراءات التالية يُعَدّ مخالفة مرورية كبرى قد تعرّض رخصتك التجارية للخطر؟","options":["متابعة المركبة الأبطأ على مسافة آمنة وانتظار فرصة قانونية للتجاوز","النزول لفترة وجيزة تحت الحد الأدنى المعلن لتفقّد مرآتيك قبل تغيير المسار","التعرّج بعدوانية عبر حركة المرور والالتصاق الشديد لإجبار السائق البطيء على الإفساح","الإشارة إلى تغيير مسارك أبكر قليلاً مما تتوقعه المركبة التي أمامك مباشرة"],"explanation":"التعرّج بعدوانية عبر حركة المرور والالتصاق الشديد للضغط على سائق آخر هو قيادة متهورة، وهي مخالفة كبرى قد تؤدي إلى الحرمان من رخصة القيادة التجارية."},"471":{"q":"تتعطّل شاحنتك المقطورة على الكتف الأيمن لطريق سريع مستوٍ ومستقيم غير مقسوم من مسارين. تشغّل أضواء التحذير وتمسك مثلثاتك العاكسة لوضعها قبل أن تنغلق نافذة الـ 10 دقائق. وبينما تمشي نحو مؤخرة شاحنتك لوضع المثلث الأول (الأقرب)، على أي مسافة تقريباً خلف المركبة يجب أن تضعه؟","options":["نحو 10 أقدام خلف المركبة، على جانب حركة المرور","نحو 100 قدم خلف المركبة","نحو 200 قدم خلف المركبة","عند المصد الخلفي مباشرة، ملاصقاً للمركبة"],"explanation":"يوضع مثلث التحذير الأقرب على نحو 10 أقدام خلف المركبة على جانب حركة المرور لتمييز المؤخرة المباشرة للشاحنة."},"472":{"q":"يتعطّل محمل عجلة وتنزلق بشاحنتك المقطورة إلى كتف طريق سريع مستوٍ ومستقيم غير مقسوم من مسارين. بعد تشغيل أضواء التحذير الرباعية، تمسك مثلثات الطوارئ وتبدأ بوضعها نحو حركة المرور القادمة. تضع المثلث الأول بشكل صحيح على بُعد 10 أقدام في الخلف. بالنسبة للمثلث الثاني الذي تضعه خلف شاحنتك على هذا النوع من الطرق، على أي مسافة تقريباً خلف مركبتك يجب أن يوضع؟","options":["نحو 200 قدم في الخلف، ثم مثلث ثالث على بُعد 200 قدم إضافية بعد ذلك","نحو 100 قدم خلف المركبة","نحو 50 قدماً خلف المركبة","نحو 100 قدم أمام المركبة، في المسار المقابل"],"explanation":"على طريق من مسارين أو غير مقسوم، يوضع المثلث الثاني على نحو 100 قدم خلف المركبة لأن حركة المرور يمكن أن تأتي من كلا الاتجاهين."},"473":{"q":"تتعطّل شاحنتك المقطورة في المسار الأيمن لطريق سريع مقسوم مستقيم ومستوٍ (طريق باتجاه واحد بفاصل وسطي يفصل حركة المرور المتقابلة) في رؤية جيدة. تشغّل أضواء التحذير وتمسك مجموعة مثلثات الطوارئ. وبينما تمشي إلى الخلف لوضع المثلث الذي يجب أن يوضع على أبعد مسافة من مؤخرة مركبتك، على أي مسافة تقريباً في الخلف يجب أن تضعه؟","options":["نحو 100 قدم في الخلف، لأن هذا هو مكان المثلث الأوسط","نحو نصف ميل في الخلف، لإعطاء حركة المرور السريعة أكبر تحذير ممكن","نحو 200 قدم خلف المركبة","نحو 10 أقدام في الخلف، بعد المصد الخلفي مباشرة"],"explanation":"على طريق باتجاه واحد أو مقسوم، توضع المثلثات الثلاثة كلها خلف المركبة، ويوضع الأبعد على نحو 200 قدم في الخلف نحو حركة المرور القادمة."},"474":{"q":"لقد توقفت على الكتف الأيمن لطريق سريع باتجاه واحد (مقسوم) بعد قمة تلة بقليل، حيث لا تستطيع المركبات القادمة خلفك رؤية شاحنتك حتى اللحظة الأخيرة. تشغّل أضواء التحذير وتبدأ بوضع مثلثاتك العاكسة الثلاثة. عندما يحين وقت وضع المثلث الأبعد الذي يحمي مؤخرتك من حركة المرور القادمة، ماذا يجب أن تفعل لتراعي حجب التلة للرؤية؟","options":["أبقِ المثلثات الثلاثة كلها على بُعد 10 أقدام من الشاحنة لتبقى مجمّعة ومرئية معاً","ضع المثلث الأبعد على بُعد 200 قدم بالضبط، مثل المقطع المستوي المفتوح، لأن تلك المسافة هي المعيار القانوني","تجاوز المثلث الأبعد تماماً واعتمد على أضواء التحذير، فهي أكثر سطوعاً من مثلث على تلة","انقل المثلث الأبعد إلى ما بعد موضعه المعتاد البالغ 200 قدم (حتى 500 قدم) حتى يصل السائقون إلى قمة التلة وأمامهم تحذير كافٍ للتفاعل"],"explanation":"بالقرب من تلة أو منعطف يحجب خط الرؤية، انقل المثلث الأبعد إلى ما بعد موضعه المعتاد (حتى 500 قدم) حتى يحصل السائقون القادمون على تحذير كافٍ."},"475":{"q":"أثناء فحصك قبل الرحلة في محطة استراحة، تشم رائحة دخان وتجد حريقاً صغيراً قد بدأ في كومة من صناديق الكرتون المهملة وأوراق الشحن وكومة من أغطية النقل بالقرب من الأبواب الخلفية لمقطورتك. تمد يدك إلى طفاية الحريق وتتحقق من تصنيفها قبل التحرك. أي فئة من الطفايات مخصصة تحديداً لنوع المواد المشتعلة هنا؟","options":["الفئة A، وهي مصنفة للمواد القابلة للاحتراق العادية مثل الخشب والورق والقماش","الفئة B، وهي مصنفة للسوائل المشتعلة مثل الوقود والزيت والشحم","الفئة C، وهي مصنفة لحرائق الأسلاك الكهربائية الحية والمعدات المكهربة","الفئة D، وهي مصنفة للمعادن القابلة للاحتراق مثل المغنيسيوم والتيتانيوم"],"explanation":"حرائق المواد القابلة للاحتراق العادية مثل الخشب والورق والقماش مصنفة لطفاية من الفئة A."},"476":{"q":"أثناء فحصك قبل الرحلة تتحقق من طفاية الحريق المثبتة في مقصورتك. أنت تنقل براميل من وقود الديزل، وتريد التأكد من أن الطفاية قادرة فعلاً على التعامل مع الحريق الأكثر احتمالاً لهذه الحمولة. يشتعل تسرب صغير من الوقود بالقرب من البراميل. أي نوع من طفايات الحريق مصنف لمكافحة هذا الحريق الناتج عن سائل مشتعل؟","options":["طفاية من الفئة A، لأنها النوع الأكثر شيوعاً وتعمل على المنصات الخشبية وقوائم التعبئة الورقية الموجودة أيضاً في المقطورة","طفاية من الفئة B، لأنها مصنفة للسوائل المشتعلة مثل الوقود والزيت والشحم","طفاية من الفئة C، لأن الحريق بدأ بالقرب من النظام الكهربائي والبطارية في الشاحنة","طفاية من الفئة D، لأنها مخصصة للحرائق التي تشمل القماش القابل للاحتراق والخرق ومناشف الورشة"],"explanation":"حرائق السوائل القابلة للاشتعال مثل الوقود والزيت والشحم مصنفة لطفاية من الفئة B."},"477":{"q":"أثناء فحصك قبل الرحلة تشم رائحة شيء ساخن بالقرب من لوحة القيادة وتكتشف دخاناً يخرج من خلف لوحة الأسلاك المكهربة في النظام الكهربائي لجرّارك. تمد يدك إلى طفاية الحريق المثبتة في المقصورة. لمكافحة هذا الحريق بأمان، أي فئة من الطفايات يجب أن تستخدم؟","options":["طفاية من الفئة A، لأنها مصنفة للخشب والورق المحيط باللوحة","طفاية من الفئة B، لأنها مصنفة للسوائل القابلة للاشتعال التي تغذي معظم حرائق الشاحنات","طفاية من الفئة C، لأنها مصنفة لحرائق المعدات الكهربائية الحية","أي فئة ستفي بالغرض طالما قطعت مفصل فصل البطارية أولاً"],"explanation":"تتطلب حرائق المعدات الكهربائية الحية طفاية من الفئة C لأن مادتها غير الموصلة لن تنقل التيار رجوعاً إلى المشغّل."},"478":{"q":"الطقس أقل بقليل من درجة التجمد وأنت تنطلق من توقف على منحدر مغطى بالجليد الزجاجي. تشعر بالشاحنة ترتجف ويقفز عداد الدوران بينما تبدأ عجلات الدفع في الدوران دون أن تتحرك المركبة للأمام. للتحرك واستعادة الجر، ما هو أفضل إجراء؟","options":["اضغط بقوة أكبر على دواسة الوقود لدفع العجلات الدوّارة عبر الجليد","اضغط بسرعة على دواسة الفرامل بشكل متقطع لإجبار عجلات الدفع على الالتصاق بالسطح","وجّه المقود بسرعة من جانب إلى آخر لتدع حواف الإطارات تنغرس وتجد قبضة","ارفع قدمك عن دواسة الوقود لتبطئ عجلات الدفع وتستعيد الجر"],"explanation":"في انزلاق عجلات الدفع، ارفع قدمك عن دواسة الوقود لتقليل القوة بحيث تتباطأ العجلات الدوّارة إلى سرعة المركبة وتستعيد الجر."},"479":{"q":"أنت تنزل منحدراً طويلاً وتلاحظ دخاناً ثم لهباً يخرج من أحد إطارات مقطورتك المزدوجة. تتوقف بأمان على الكتف، وتضع مثلثات التحذير، وتأخذ مستلزماتك. مع وجود إطار يحترق فعلاً، أي مما يلي هو أفضل طريقة لتبريد الحريق وإخماده؟","options":["أغمره بكمية وفيرة من الماء، لأن الماء يبرّد الإطار المحترق","أخمده بإهالة الرمل الجاف مباشرة فوق اللهب","دع تدفق الهواء من السير ببطء على طول الكتف يبرّد الإطار","رش زيت المحرك لتغطية سطح الإطار وعزله عن الأكسجين"],"explanation":"أغمر الإطار المحترق بكمية وفيرة من الماء، لأن الماء يبرّد المطاط والهيكل حيث تحتجز الحرارة ويمنع إعادة الاشتعال."},"480":{"q":"إنه صباح بارد وأنت تترك شاحنتك تعمل في وضع الخمول داخل رصيف تحميل مغلق لتسخينها قبل فحصك قبل الرحلة. بعد بضع دقائق تبدأ بالشعور بالدوار وتصاب بصداع، لكنك لا ترى ولا تشم أي شيء غير عادي في الهواء. بناءً على كيفية تصرف أول أكسيد الكربون، ما هو السبب الأكثر احتمالاً لعدم حصولك على تحذير يُذكر قبل بدء هذه الأعراض؟","options":["كان الغاز سيطلق رائحة حادة وحلوة أولاً، لذا لا بد أن نظام العادم محكم الإغلاق وليس هو السبب","أول أكسيد الكربون عديم اللون وعديم الرائحة، لذا لا تستطيع حواسك اكتشافه قبل أن يؤثر فيك","يتحول الغاز إلى لون أحمر ساطع مرئي عند تراكمه، لكن إضاءة الرصيف الخافتة أخفته عنك","أول أكسيد الكربون أثقل من الهواء ويبقى قرب الأرضية، لذا كان الوقوف سيحذرك في الوقت المناسب"],"explanation":"أول أكسيد الكربون عديم اللون وعديم الرائحة، لذا لا تستطيع حواسك اكتشافه قبل أن يؤثر فيك في الأماكن المغلقة."},"481":{"q":"أنت تقود مركبة مركّبة محمّلة على طريق ريفي في تكساس عندما ترى محطة وزن أمامك بلافتتها \"مفتوحة\" مضاءة، وبعض المركبات الصغيرة تمر بجانبها دون أن تبطئ. أنت متعب ولا تبعد سوى ميلين عن مكان التسليم. أي إجراء صحيح قانونياً؟","options":["تجاوزها كما فعلت المركبات الصغيرة، لأن المحطة تفحص بوضوح سيارات الركاب فقط اليوم","اعتبر المحطة اختيارية وتوقف فيها فقط إذا أشار إليك ضابط أو شعرت أن وزنك الإجمالي مرتفع","ادخل محطة الوزن المفتوحة، لأن القانون يلزم الشاحنات بالتوقف في أي محطة وزن مفتوحة تمر بها","تجاوزها لأنك على بعد ميلين من تسليمك النهائي وحمولتك مؤمّنة بالفعل"],"explanation":"يلزم القانون الشاحنات بالتوقف في أي محطة وزن مفتوحة تمر بها، بغض النظر عن التعب أو الحمولة أو ما تفعله السيارات."},"482":{"q":"أثناء فحصك قبل الرحلة عند ميزان على جانب الطريق، يجد مفتش من شرطة ولاية تكساس عيباً في الفرامل على جرّارك، ويدوّنه، ويصدر أمراً بإخراج المركبة من الخدمة. الورشة على بعد 8 أميال ونافذة تسليمك تُغلق خلال ساعة. أي إجراء صحيح قانونياً؟","options":["بما أن الحمولة حساسة زمنياً، يمكنك قيادة الأميال الثمانية مباشرة إلى ورشة الإصلاح بسرعة منخفضة","يمكنك متابعة طريقك طالما بقيت تحت 55 ميلاً في الساعة واستخدمت كبحاً خفيفاً وثابتاً فقط","يمكنك القيادة بمجرد ملء الوقود وقراءة مقياس الفرامل الهوائية للضغط الكامل","لا يجوز لك قيادة المركبة على الإطلاق حتى يُصلح العيب ويُلغى الأمر"],"explanation":"يمنعك أمر الإخراج من الخدمة قانونياً من القيادة على طريق عام حتى يُصلح العيب ويُلغى الأمر."},"483":{"q":"يطلب مفتش على جانب الطريق في محطة وزن مراجعة سجلات حالة خدمتك من جهاز التسجيل الإلكتروني للقيادة (ELD). يدّعي مرسلك أن الجهاز موجود أساساً لإرضاء مصلحة الضرائب وقسم المحاسبة في أسطولك. أي عبارة تصف على نحو أفضل ما تهدف سجلات حالة الخدمة فعلاً إلى توثيقه لهذا التفتيش؟","options":["عدد الساعات التي قدتها وكنت فيها في الخدمة، حتى يتمكن الضابط من تأكيد أنك ضمن حدود ساعات الخدمة القانونية","مشتريات الوقود والأميال حسب الولاية، حتى يتمكن الضابط من التحقق من دقة إقرار ضريبة IFTA الخاص بك","تاريخ صيانة المركبة وإصلاحها، حتى يتمكن الضابط من تأكيد إجراء الفحوصات المطلوبة","وزن الحمولة وفحوصات تأمينها، حتى يتمكن الضابط من تأكيد إعادة فحصك لحمولتك كل 150 ميلاً"],"explanation":"توثّق سجلات حالة الخدمة ساعات قيادتك وساعات عملك حتى يتمكن المفتش من تأكيد أنك ضمن حدود ساعات الخدمة القانونية."},"484":{"q":"أنت تندمج في طريق سريع بجرّارك المحمّل وتريد تسارعاً سريعاً. مؤشر عداد الدوران يرتفع بسرعة وهو الآن يلامس أعلى المنطقة الحمراء، لكنك ما زلت تريد مزيداً من القوة لمواكبة حركة المرور. لحماية محرك الديزل، أي مما يلي يجب ألا تفعله؟","options":["دع المحرك يسخن في وضع الخمول قبل أن تطلب منه قوة كبيرة","ادفع المحرك إلى ما بعد الخط الأحمر في عداد الدوران لانتزاع مزيد من التسارع","ارفع الترس بحيث تنخفض سرعة المحرك إلى ما دون المنطقة الحمراء قبل زيادة الوقود","استخدم نطاق دوران المحرك التشغيلي الطبيعي لبناء السرعة تدريجياً"],"explanation":"لا تدفع المحرك أبداً إلى ما بعد الخط الأحمر في عداد الدوران، لأن الخط الأحمر يحدد أقصى دوران آمن وزيادة الدوران تسبب تلفاً شديداً للمحرك."},"485":{"q":"تركن جرّارك ومقطورتك المحمّلة على منحدر هابط طفيف عند رصيف عميل، وتضبط فرامل الانتظار، وتنزل لتبدأ التفريغ. الأرض ليست مستوية تماماً وستكون بعيداً عن المقصورة لفترة. في ظل هذه الظروف، أي إجراء هو الممارسة الأفضل الوحيدة قبل أن تترك الشاحنة دون مراقبة؟","options":["لا حاجة لشيء إضافي لأن فرامل الانتظار النابضية ستحمل مقطورة محمّلة إلى أجل غير مسمى على أي منحدر","اترك ناقل الحركة في ترس منخفض بدلاً من وضع الحواجز، لأن إشراك الترس يحل محل حواجز العجلات تماماً على المنحدر","ضع حواجز للعجلات، لأن هناك احتمالاً أن تنزلق الشاحنة على السطح المنحدر غير المستوي","تجاوز الحواجز لأن الميل طفيف فقط، والحواجز مطلوبة فقط على المنحدرات الجبلية الحادة"],"explanation":"ضع حواجز للعجلات كلما كان هناك أي احتمال لتدحرج الشاحنة، كما على سطح منحدر غير مستوٍ تقف عليه محمّلة ودون مراقبة."},"486":{"q":"تنهي عملية تسليم ويجب أن تركن جرّارك ومقطورتك متجهاً إلى أسفل المنحدر على كتف ريفي. لا يوجد رصيف على هذا المقطع من الطريق. وأنت تستعد لمغادرة المركبة، كيف يجب أن توجّه عجلاتك الأمامية (محور التوجيه) بحيث، إذا تدحرجت الشاحنة، تتحرك بعيداً عن حركة المرور المارة بدلاً من الدخول إلى مسار السير؟","options":["اترك العجلات الأمامية متجهة للأمام مباشرة، لأن فرامل الانتظار والحواجز تتولى كل التثبيت على المنحدر","أدر العجلات الأمامية بشدة إلى اليسار، تماماً كما تفعل عند الركن صعوداً مقابل رصيف","وجّه العجلات الأمامية للأمام مباشرة واضبطها فقط بعد التحقق من أن مداس الإطار لا يقل عن 4/32 بوصة على محور التوجيه","أدر العجلات الأمامية نحو حافة الطريق، بحيث تنحرف المركبة المتدحرجة خارج الرصيف بعيداً عن حركة المرور"],"explanation":"عند الركن متجهاً إلى أسفل المنحدر دون رصيف، أدر العجلات الأمامية نحو حافة الطريق بحيث تنحرف المركبة المتدحرجة خارج الرصيف بعيداً عن حركة المرور."},"487":{"q":"الطقس أقل بقليل من درجة التجمد أثناء فحصك قبل الرحلة، وتلاحظ أن درجات السلّم والمقابض على جرّارك مغطاة بطبقة رقيقة من الجليد وأوساخ الطريق. تتطلب اللوائح الفيدرالية ولوائح تكساس فحص هذه العناصر. وفقاً للدليل، ما هو السبب الرئيسي لوجوب فحصك لحالة درجات السلّم والمقابض قبل القيادة؟","options":["حتى تتمكن من الدخول والخروج من المقصورة بأمان، خاصة باستخدام نقاط التلامس الثلاث عندما تكون الأسطح زلقة","حتى تتمكن من تأكيد أن هيكل المقصورة يمكنه دعم وزن الحمولة المقدّر المدرج على لوحة الوزن الإجمالي للمركبة (GVWR)","حتى تتمكن من التحقق من أن الإطار وأقواس التثبيت غير متشققة، مما يخرج المركبة من الخدمة","حتى تحافظ على نظافة حذائك وتتجنب نقل الطين إلى أرضية المقصورة والدواسات"],"explanation":"تتيح لك درجات السلّم والمقابض الآمنة والسليمة الدخول والخروج من المقصورة بأمان، مع الحفاظ على نقاط التلامس الثلاث عندما تكون الأسطح زلقة."},"488":{"q":"إنها بداية مناوبتك وأنت تكمل فحصك قبل الرحلة. قد يوقفك ضابط من إدارة النقل (DOT) في نقطة تفتيش على جانب الطريق في أي وقت على مسار اليوم ويطلب رؤية تسجيل مركبتك وإثبات التأمين. للبقاء متوافقاً وجاهزاً لذلك التفتيش، أين يجب أن تكون هذه المستندات في هذه اللحظة؟","options":["محفوظة في خزانة في منزلك أو مكتب محطتك حتى لا تُفقد أو تُسرق على الطريق","داخل المركبة معك، حتى تتمكن من إبرازها لأي ضابط أثناء تفتيش على جانب الطريق","مرسلة بالبريد إلى شرطة ولاية تكساس حتى تحتفظ الولاية بالنسخة الرسمية في سجلاتها لك","مرفوعة إلى بوابة إلكترونية للولاية، لأن السجل الرقمي يغني عن الحاجة لحمل نسخ ورقية"],"explanation":"احتفظ بتسجيلك وإثبات التأمين داخل المركبة حتى تتمكن من تقديمهما لضابط أثناء أي تفتيش أو توقف على جانب الطريق."},"489":{"q":"أنت تقترب من تقاطع ريفي ليلاً في مركبتك المركّبة المحمّلة عندما ترى إشارة المرور العلوية تومض باللون الأحمر في اتجاهك، بينما حركة المرور المتقاطعة تواجه ومضة صفراء. نظراً لكيفية اختلاف هذه الإشارات قانونياً، ما هو الإجراء الصحيح الذي يجب أن تتخذه؟","options":["أبطئ وامرّ بحذر دون توقف، لأن الإشارة الوامضة تحذّرك فقط من أن تكون يقظاً","حافظ على سرعتك لكن كن مستعداً للتنازل، لأن حركة المرور المتقاطعة التي تواجه الومضة الصفراء يجب أن تتوقف لك","توقف توقفاً تاماً كما تفعل عند لافتة توقف، ثم امضِ فقط عندما يكون التقاطع خالياً","اعتبرها إشارة عالقة، وتوقف لفترة وجيزة، ثم امضِ قبل أن تتحول الإشارة إلى أحمر ثابت"],"explanation":"الإشارة الحمراء الوامضة تعني نفس معنى لافتة التوقف: توقف توقفاً تاماً، وتنازل، وامضِ فقط عندما يكون التقاطع خالياً."},"490":{"q":"أنت تقترب من تقاطع مزدحم ليلاً عندما تتحول إشارة المرور العلوية إلى ومضة صفراء ثابتة تواجه مسارك، بينما يواجه الشارع المتقاطع ومضة حمراء. عدة سيارات تنتظر على الشارع المتقاطع للدخول. ما هي الطريقة الصحيحة للمرور عبر هذا التقاطع؟","options":["عامل الومضة الصفراء تماماً كالأحمر الثابت: توقف توقفاً تاماً، ثم امضِ عندما يكون التقاطع خالياً","حافظ على سرعة الطريق السريع لأن الومضة الصفراء تمنحك حق الأولوية المطلق ويجب أن تبقى الحركة المتقاطعة متوقفة","توقف، وانتظر حتى يخلو سائقو الشارع المتقاطع أولاً لأن ومضتهم الحمراء تعمل كتوقف رباعي يتنازل لهم","قلل سرعتك وامضِ عبر التقاطع بحذر، مع البقاء يقظاً للحركة المتقاطعة المتوقفة عند الومضة الحمراء"],"explanation":"الإشارة الصفراء الوامضة هي إشارة تحذير وليست توقفاً: أبطئ وامضِ عبر التقاطع بحذر."},"491":{"q":"أنت تقترب من تقاطع مزدحم في مركبتك المركّبة المحمّلة عندما تلاحظ أن إشارة المرور التي تواجهك مظلمة تماماً، دون أي أضواء مضاءة على الإطلاق بسبب انقطاع واضح للتيار الكهربائي. حركة المرور المتقاطعة تبطئ أيضاً. للمرور بشكل قانوني وآمن، كيف يجب أن تعامل هذا التقاطع؟","options":["كتوقف رباعي: توقف توقفاً تاماً، ثم امضِ بالدور حسب ترتيب وصول المركبات، متنازلاً لمن وصل أولاً","كإشارة تنازل: أبطئ وتوقف فقط إذا كانت مركبة أخرى موجودة بالفعل في التقاطع، وإلا فمرّ من خلاله","كإشارة خضراء للطريق المار، لأن المركبة التجارية الأكبر لها حق الأولوية على الحركة المتقاطعة","كمرور حر: حافظ على سرعتك عبر التقاطع لأن الإشارة المظلمة ليست تقاطعاً منظَّماً"],"explanation":"يجب معاملة إشارة المرور المظلمة أو المعطلة كتوقف رباعي، حيث تمضي المركبات بترتيب الوصول."},"492":{"q":"أنت تنقل مقطورة محمّلة على طريق سريع ذي مسارين خلف جرّار زراعي بطيء. منتصف الطريق معلّم بخط أصفر مزدوج متصل. أنت تخسر وقتاً وتود تجاوزه. بناءً على علامة الرصيف هذه، أي مما يلي هو الإجراء الصحيح؟","options":["يمكنك عبور الخط للتجاوز لأن المسار في جانبك هو المسار الأسرع","يجب ألا تتجاوز، لأن الخط الأصفر المركزي المزدوج المتصل يمنع التجاوز في كلا اتجاهي السير","يمكنك التجاوز طالما لا تظهر حركة مرور قادمة ضمن 500 قدم","العلامة تقيّد الوقوف فقط، لذا يُسمح بالتجاوز عندما يكون الطريق خالياً"],"explanation":"الخط الأصفر المركزي المزدوج المتصل يمنع التجاوز لحركة المرور في كلا الاتجاهين، لذا يجب ألا تعبره للتجاوز."},"493":{"q":"أنت تقود على طريق سريع متعدد المسارات في تكساس في حركة مرور معتدلة عندما تتغير علامات المسار: يتحول الخط الأبيض المتقطع بين مسارك والمسار على يمينك إلى خط أبيض متصل واحد يستمر لمسافة طويلة. حركة المرور في مسارك تتحرك أبطأ قليلاً من المسار المجاور. ماذا يبلّغ هذا الخط الأبيض المتصل، وكيف يجب أن تتجاوب؟","options":["يحدد حافة الطريق، لذا يجب أن تتجه نحو الكتف لتدع حركة المرور الأسرع تمر على يسارك","هو نفس الخط المتقطع، لذا يمكنك التحرك يميناً كلما ظهرت فجوة لمواكبة المسار الأسرع","يثبّط العبور، لذا يجب أن تبقى في مسارك وتغيّر المسارات فقط إذا كان ذلك ضرورياً وآمناً حقاً","يعني أن التجاوز محظور على الجميع، لذا يجب أن تحافظ على موضعك بدقة ولا يجوز لك تغيير المسارات بأي حال"],"explanation":"الخط الأبيض المتصل الواحد يفصل بين مسارات تسير في نفس الاتجاه ويثبّط تغيير المسارات، لذا اعبره فقط عند الضرورة والأمان."},"494":{"q":"أنت تقود جرّارك ومقطورتك على طريق ذي مسارين غير مقسوم في وضح النهار عندما تشغّل حافلة المدرسة أمامك أضواءها الحمراء الوامضة بالتناوب وتمدّ ذراع التوقف. أنت تتبع على مسافة قانونية وحركة المرور خلفك خفيفة. ماذا يُطلب منك أن تفعل؟","options":["أبطئ إلى نحو 15 ميلاً في الساعة، وضع قدمك فوق الفرامل، وتجاوز الحافلة من جانبها الأيسر فقط لأنك على طريق غير مقسوم","استمر بالسير بسرعة زحف منخفضة مع مراقبة الأطفال، لأن التوقف التام مطلوب فقط عندما تُظهر الحافلة أضواء تحذير صفراء (كهرمانية)","انعطف إلى الكتف، وضع مثلثاتك العاكسة، وانتظر حتى يلوّح لك سائق الحافلة للتقدم","توقف توقفاً تاماً وابقَ متوقفاً حتى تتوقف الأضواء الحمراء عن الوميض وتُسحب ذراع التوقف"],"explanation":"الأضواء الحمراء الوامضة مع امتداد ذراع التوقف تعني أن على حركة المرور في كلا الاتجاهين على طريق غير مقسوم التوقف حتى تتوقف الأضواء وتنسحب الذراع."},"495":{"q":"أنت تقترب من مقطع إصلاح طريق مغطى بألواح فولاذية وسطح جسر شبكي معدني على مسارك. تغيرت الظروف عدة مرات اليوم. في أي من المواقف التالية يجب أن تتوقع أن تمنحك هذه الأسطح المعدنية أقل قدر من الجر وتتصرف أشبه بالجليد؟","options":["مطر خفيف بدأ للتو والألواح الفولاذية وشبكة الجسر مبللة","الرصيف والأسطح المعدنية جافة تماماً تحت شمس فترة بعد الظهر الساطعة","الألواح الفولاذية رُكّبت بالأمس فقط وما زالت تبدو جديدة تماماً","انتهى طاقم صيانة للتو من كنس الحصى والغبار المتناثر عن الألواح"],"explanation":"تقدّم الألواح الفولاذية وأسطح الجسور المعدنية القليل من الجر وتصبح زلقة كالجليد عندما تكون مبللة."},"496":{"q":"تخرج من طريق سريع مقسوم وتنعطف إلى شارع تجاري في وسط المدينة في منتصف النهار. حركة المرور كثيفة، وسيارات مركونة تصطف على جانبي الرصيف، وشاحنات توصيل مركونة بشكل مزدوج، وتمرّ بموقف حافلات وعدة واجهات متاجر. مقارنة بالطريق السريع المفتوح الذي غادرته للتو، أي خطر يجب أن يحظى الآن بأكبر نصيب من انتباهك؟","options":["الطرق المستقيمة الطويلة الفارغة حيث يمكنك بأمان زيادة مسافة الأمان خلفك","المشاة الذين قد يخرجون فجأة من بين السيارات المركونة أو الحافلات أو واجهات المتاجر","الحقول المفتوحة الواسعة بجانب الطريق التي تمنحك مساحة إضافية للتعافي من انزلاق","الحصى المتناثر والحطام النموذجي للأكتاف الريفية البعيدة عن هذه المنطقة"],"explanation":"في المدينة، راقب عن كثب المشاة الذين قد يخرجون فجأة من بين السيارات المركونة أو الحافلات أو واجهات المتاجر."},"497":{"q":"إنه منتصف الصباح وأنت تقود مركبة مركّبة محمّلة على طريق ريفي ضيق ذي مسارين عبر منطقة زراعية. السرعة المعلنة 55 ميلاً في الساعة، لكنك تصعد مرتفعاً صغيراً وتنفتح رؤيتك على نحو ربع ميل أمامك. من بين المخاطر التالية، أيها الأكثر احتمالاً أن تصادفه يتحرك أبطأ بكثير من السرعة المعلنة ويجبرك على تعديل مسافة الأمان خلفك وربما تغيير المسار للتجاوز؟","options":["حافلة نقل عام في المدينة تتوقف عند مظلات ركاب معلّمة","سيارات ركاب خفيفة تندمج من منحدر دخول طريق سريع","معدات زراعية بطيئة الحركة مثل جرّار أو حصّادة","قطار أنفاق ركاب يسير موازياً للطريق"],"explanation":"على الطرق الريفية ذات المسارين، راقب المعدات الزراعية بطيئة الحركة مثل الجرّارات والحصّادات التي تسير أبطأ بكثير من السرعة المعلنة."},"498":{"q":"أنت متوقف في مقدمة تقاطع في مركبتك المركّبة المحمّلة، تنتظر للانعطاف يساراً عبر مسارين من حركة المرور القادمة. السهم الأحمر الثابت الذي كان يوقفك يتحول إلى سهم انعطاف يسار أصفر وامض باستمرار. لا تزال المركبات القادمة تقترب من التقاطع بسرعة. أي تجاوب صحيح قانونياً وأكثر أماناً لسائق بحجمك وطولك؟","options":["ابدأ انعطافك فوراً، لأن السهم الأصفر الوامض يعمل تماماً كالسهم الأخضر ويمنحك انعطافاً محمياً بحق الأولوية","ابقَ متوقفاً تماماً وعامل السهم الأصفر الوامض كالسهم الأحمر الثابت، منتظراً سهماً أخضر ثابتاً قبل أن تتحرك","امضِ في الانعطاف لكن خطط للتوقف والبقاء في منتصف التقاطع حتى تخلو فجوة الحركة القادمة","يمكنك المضي في الانعطاف، لكن يجب أن تتنازل لحركة المرور القادمة وتكمل الانعطاف فقط عندما تكون هناك فجوة كبيرة بما يكفي لطولك الكامل ليمر بأمان"],"explanation":"السهم الأصفر الوامض يسمح بالانعطاف لكنه لا يمنح حق الأولوية، لذا تنازل لحركة المرور القادمة وانعطف فقط عندما تكون الفجوة كبيرة بما يكفي للمرور بأمان."},"499":{"q":"تُجبَر على التوقف على الكتف بعد فشل وصلة وبدء الديزل بالتجمع على الرصيف حول مؤخرة مقطورتك. لا يزال عليك تعليم مركبتك المتوقفة لحركة المرور المقتربة. بالنظر إلى الوقود على الأرض، أي جهاز تحذير هو الخيار الأكثر أماناً لوضعه؟","options":["مثلث عاكس، لأنه يحذّر حركة المرور دون أي لهب أو حرارة قد يشعل الوقود المنسكب","شعلة مضاءة، لأن الشعلات هي جهاز التحذير القياسي الأكثر وضوحاً وهي معدات مطلوبة على شاحنتك","شعلة إشارة مشتعلة موضوعة في اتجاه الريح بعيداً عن الانسكاب حتى يبقى اللهب بعيداً عن أبخرة الديزل","شمعة صغيرة مضاءة موضوعة على الرصيف، لأن لهبها منخفض جداً ولا يصل إلى الوقود"],"explanation":"المثلث العاكس لا ينتج لهباً أو شرارة أو حرارة، لذا يحذّر حركة المرور بأمان دون المخاطرة بإشعال الوقود المنسكب."},"500":{"q":"أثناء فحصك قبل الرحلة، تجد أن إطارات التوجيه الأمامية متآكلة بشكل غير متساوٍ. عند أقل نقطة عمقًا يبلغ سُمك المداس حوالي 3/32 بوصة. ما القرار الصحيح؟","options":["لا تَقُد — يجب أن يكون لإطارات محور التوجيه مداس لا يقل عن 4/32 بوصة","قُد — 3/32 بوصة لا تزال تتجاوز الحد الأدنى 2/32 بوصة المطبق على الإطارات","قُد — التآكل غير المتساوي يهم فقط في إطارات الدفع والمقطورة","لا تَقُد — أي إطار أقل من 6/32 بوصة غير قانوني على مركبة تجارية"],"explanation":"يجب أن يكون لإطارات محور التوجيه مداس لا يقل عن 4/32 بوصة — وهو معيار أعلى من 2/32 بوصة المطلوب لجميع الإطارات الأخرى."},"501":{"q":"أكملت فحصًا كاملًا قبل الرحلة، وأمَّنت حمولتك، وقد قطعت الآن 45 ميلًا على الطريق السريع وكل شيء يبدو على ما يرام. بموجب قواعد فحص الحمولة، ما المطلوب منك أن تفعله؟","options":["لا شيء بعد — أول إعادة فحص مطلوبة للحمولة تكون عند 150 ميلًا أو 3 ساعات","لا شيء — بمجرد تأمين الحمولة وفحصها قبل الرحلة، لا حاجة لفحصها مجددًا حتى تتزود بالوقود","توقف خلال الأميال القليلة القادمة — أول إعادة فحص للحمولة مطلوبة خلال أول 50 ميلًا","توقف الآن — يجب إعادة فحص الحمولة كل 25 ميلًا"],"explanation":"تُطلب أول إعادة فحص للحمولة وأجهزة التأمين خلال أول 50 ميلًا، لأن أربطة التثبيت تستقر والحمولات تنزاح أكثر ما تنزاح في البداية."},"502":{"q":"أثناء فحص نظام التوجيه، تجد أن عجلة القيادة تدور أكثر من 10 درجات (حوالي بوصتين من اللعب عند حافة عجلة قطرها 20 بوصة) قبل أن تبدأ الإطارات الأمامية في الحركة. ماذا يعني هذا؟","options":["لعب حر طبيعي موجود في كل شاحنة ثقيلة — لا حاجة لأي إجراء","لعب توجيه مفرط — المركبة غير آمنة للقيادة حتى يتم إصلاحها","نظام التوجيه المعزز يحتاج فقط إلى الإحماء؛ سيشد بمجرد القيادة","عنصر بسيط يمكنك تدوينه في تقرير ما بعد الرحلة ومواصلة القيادة"],"explanation":"اللعب الحر في التوجيه الذي يزيد عن 10 درجات تقريبًا يجعل التحكم في المركبة صعبًا وغير آمن للقيادة حتى يتم إصلاحه."},"503":{"q":"في نهاية مناوبتك تكتشف مشكلة في ضبط الفرامل. فيما يخص تقرير فحص مركبة السائق (DVIR)، أي عبارة صحيحة؟","options":["تقرير DVIR مطلوب فقط قبل الرحلة، وليس بعدها أبدًا","تقرير ما بعد الرحلة اختياري كلما أجريت فحصًا قبل الرحلة في الصباح نفسه","يمكنك الإبلاغ عن العيب شفهيًا فقط؛ لا حاجة لسجل مكتوب","يجب تسجيل العيب في تقرير مكتوب لما بعد الرحلة حتى يُصلح قبل استخدام المركبة مرة أخرى"],"explanation":"يجب تسجيل العيوب المكتشفة أثناء الرحلة في تقرير مكتوب لفحص ما بعد الرحلة حتى تُصلح قبل استخدام المركبة مرة أخرى."},"504":{"q":"درجة الحرارة أقل بقليل من التجمد. يبدو الرصيف رطبًا ولامعًا، ومع ذلك تلاحظ أن رذاذ الإطارات الذي تراه عادةً من المركبات أمامك قد توقف. ما التفسير والإجراء الأكثر أمانًا؟","options":["من المرجح أن الجليد الأسود يتشكل — قلل السرعة وتجنب أي توجيه أو فرملة مفاجئة","الطريق رطب فقط من مطر سابق — حافظ على سرعتك الحالية","إطاراتك أنت تفقد الهواء — توقف جانبًا للتحقق من ضغطها","إنه مجرد صقيع على الزجاج الأمامي — شغّل مزيل الصقيع وواصل القيادة"],"explanation":"الطريق الرطب اللامع مع غياب رذاذ الإطارات قرب درجات حرارة التجمد يشير إلى الجليد الأسود، لذا قلل السرعة وتجنب التوجيه أو الفرملة المفاجئة."},"505":{"q":"تبدأ مركبتك في الانزلاق المائي على مقطع غارق بالمياه من الطريق السريع. يجب عليك فعل كل ما يلي ما عدا:","options":["ارفع قدمك عن دواسة الوقود لتسمح للعجلات بالتباطؤ","اضغط على القابض (الكلتش) حتى تتمكن العجلات من الدوران بحرية","اضغط على الفرامل بقوة لإجبار الإطارات على العودة إلى الطريق","حافظ على عجلة القيادة مستقيمة حتى تشعر بعودة الجر"],"explanation":"أثناء الانزلاق المائي لا تفرمل بقوة أبدًا، فذلك يقفل الإطارات ويزيد الانزلاق سوءًا؛ بدلًا من ذلك ارفع قدمك عن الوقود وأمسك العجلة مستقيمة حتى يعود الجر."},"506":{"q":"تقود مجموعة مركبات طولها 60 قدمًا بسرعة 60 ميلًا في الساعة على طريق جاف في ظروف جيدة. باستخدام قاعدة مسافة الاتباع في تكساس، أقرب حد أدنى للفجوة التي يجب أن تحافظ عليها هو:","options":["حوالي 6 ثوانٍ","حوالي 7 ثوانٍ","حوالي 4 ثوانٍ","حوالي 10 ثوانٍ"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من الطول عند سرعة أقل من 40 ميلًا في الساعة، بالإضافة إلى ثانية إضافية فوق 40 ميلًا في الساعة، لذا تحتاج مركبة طولها 60 قدمًا إلى حوالي 7 ثوانٍ من مسافة الاتباع."},"507":{"q":"يبدأ المطر بالهطول بغزارة بعد عدة أسابيع جافة. لماذا يكون الجزء الأول من هذا المطر خطيرًا بشكل خاص، وكيف يجب أن تتصرف؟","options":["المطر يبرّد المحرك، لذا يمكنك السير أسرع قليلًا بأمان","الخطر الوحيد الحقيقي هو الزجاج الأمامي — شغّل الماسحات وحافظ على سرعتك","المطر الجديد يحسّن الجر فورًا؛ المياه الراكدة العميقة وحدها هي المصدر للقلق","الزيت والغبار على الطريق يرتفعان إلى طبقة زلقة قبل أن تُغسل بعيدًا — قلل السرعة وزد مسافة الاتباع"],"explanation":"عندما يبدأ المطر، يطفو الزيت والغبار مكونين طبقة زلقة تجعل الطريق في أكثر حالاته انزلاقًا، لذا قلل السرعة وزد مسافة الاتباع."},"508":{"q":"أثناء القيادة ليلًا على طريق سريع غير مضاء بالأضواء المنخفضة، تدرك أنك لا تستطيع التوقف ضمن المسافة التي تضيئها مصابيحك الأمامية. الرد الصحيح هو أن:","options":["تبطئ بحيث تتمكن من التوقف ضمن المسافة التي تستطيع رؤيتها أمامك","تتحول إلى الأضواء العالية وتحافظ على سرعتك لتبقى ضمن الجدول الزمني","تقترب خلف شاحنة أخرى وتقود على ضوء مصابيحها","تحافظ على سرعتك لكن تراقب خط الحافة اليمنى عن كثب أكثر"],"explanation":"لا تتجاوز أبدًا مدى مصابيحك الأمامية — يجب أن تسمح لك سرعتك بالتوقف ضمن المسافة التي تراها فعليًا، مما يعني التباطؤ عند استخدام الأضواء المنخفضة."},"509":{"q":"أنت على وشك الدخول في حاجز من الضباب الكثيف. أي مما يلي ليس ممارسة موصى بها؟","options":["أبطئ قبل أن تصل فعليًا إلى الضباب","استخدم الأضواء المنخفضة بدلًا من الأضواء العالية","استخدم الماسحات ومزيل الصقيع للحفاظ على نظافة الزجاج الأمامي","شغّل الأضواء العالية حتى يخترق الضوء الأسطع الضباب"],"explanation":"استخدم الأضواء المنخفضة في الضباب لأن الأضواء العالية تنعكس عن قطرات الماء وترتد الوهج إليك، مما يقلل ما يمكنك رؤيته."},"510":{"q":"درجة حرارة الهواء عند نقطة التجمد تمامًا والطرق تبدو خالية في معظمها. أي سطح يجب أن تعامله على أنه متجمد أولًا، حتى عندما يبدو باقي الطريق سليمًا؟","options":["المقاطع المستقيمة المفتوحة التي تقع تحت أشعة الشمس الكاملة","المنحدرات الصاعدة، لأن المحرك يدفّئ السطح","الأنفاق، التي تحبس الهواء الدافئ وتبقى زلقة لأطول فترة","الجسور والممرات العلوية، التي تتجمد قبل الطريق المحيط بها"],"explanation":"تفقد الجسور والممرات العلوية الحرارة من الأعلى والأسفل، لذا تتجمد قبل الطريق على الأرض الصلبة حتى عندما يكون باقي الرصيف لا يزال خاليًا."},"511":{"q":"في يوم حار جدًا تتوقف وتجد إطاراتك ساخنة بشكل ملحوظ، تسجل ضغطًا أعلى من ضغطها البارد الطبيعي. ما الإجراء الصحيح؟","options":["أخرج الهواء حتى يعود الضغط إلى الإعداد البارد الطبيعي","قُد أسرع حتى يبرّد تدفق الهواء الإطارات","اسكب الماء على الإطارات لتبريدها بسرعة","اترك الإطارات وشأنها؛ لكن إن كان أحدها ساخنًا جدًا بحيث لا يمكن لمسه، توقف عن القيادة حتى يبرد"],"explanation":"الحرارة ترفع ضغط الإطار بشكل طبيعي، لذا اترك الإطارات وشأنها؛ لكن إن كان إطار ساخنًا جدًا بحيث لا يمكن لمسه فهذا يشير إلى مشكلة، فتوقف عن القيادة حتى يبرد لتجنب انفجاره."},"512":{"q":"أنت تعبر مسار سكة حديد بناقل حركة يدوي وحمولة ثقيلة. أهم قاعدة منفردة بشأن اختيار الترس عند المعبر هي:","options":["اختر ترسًا قبل المسارات ولا تغيّر التروس بينما أي جزء من المركبة على المعبر","خفّض الترس في منتصف المسافة عبر المعبر تقريبًا للحفاظ على قوة محرك كافية","انقل إلى الوضع المحايد واترك المركبة تنساب عبر المعبر لتقليل الاهتزاز","استخدم أعلى ترس متاح لتجاوز المسارات بأسرع ما يمكن"],"explanation":"اختر ترسًا يسحبك طوال الطريق عبر المعبر قبل الوصول إلى المسارات ولا تغيّر التروس أبدًا بينما أي جزء من المركبة على المعبر، حتى لا يتوقف محركك على القضبان."},"513":{"q":"أنت تقترب من منحدر طويل وشديد الانحدار. متى وكيف يجب أن تختار ترسك؟","options":["انتظر حتى تبدأ الفرامل في الضعف، ثم خفّض إلى ترس أدنى","انقل إلى الوضع المحايد لتوفير الوقود وتحكّم في سرعتك بالفرامل وحدها","ابقَ في ترس عالٍ واضغط على الفرامل بخفة طوال الطريق نزولًا","اختر ترسًا منخفضًا قبل أن تبدأ النزول — عادةً أدنى من الترس الذي تستخدمه لصعود التل نفسه"],"explanation":"اختر ترسك المنخفض قبل النزول حتى يحافظ كبح المحرك والانضغاط على سرعتك؛ في الشاحنات الحديثة غالبًا ما يكون ترس النزول الآمن أدنى من ترس الصعود."},"514":{"q":"على منحدر طويل أنت بالفعل في الترس المنخفض الصحيح وسرعتك الآمنة 35 ميلًا في الساعة. أي تقنية فرملة تتحكم في سرعتك بشكل صحيح؟","options":["طبّق ضغطًا خفيفًا وثابتًا على الفرامل باستمرار طوال الطريق نزولًا","اضغط على الفرامل بسرعة وباستمرار للحفاظ على برودتها","امسك الفرامل بقوة طوال الطريق حتى القاع","عندما تصل إلى حوالي 40 ميلًا في الساعة، افرمل بقوة حتى حوالي 30 ميلًا في الساعة، ثم اترك، وكرّر"],"explanation":"الفرملة المتقطعة الصحيحة تعني السماح للسرعة بالارتفاع حوالي 5 أميال في الساعة فوق سرعتك الآمنة، ثم الفرملة بقوة حتى حوالي 5 أميال في الساعة تحتها، والإفلات، والتكرار حتى تبرد الفرامل."},"515":{"q":"ضعفت فراملك بشدة على منحدر جبلي وأنت تكتسب سرعة. يجب عليك فعل كل ما يلي ما عدا:","options":["ابحث عن منحدر هروب واستخدمه إن وُجد","انقل إلى الوضع المحايد حتى تنساب الشاحنة نزولًا بسلاسة أكبر","إن لم يوجد منحدر، ابحث عن طريق هروب مثل حقل مفتوح أو طريق جانبي","ابقَ في أدنى ترس واستخدم أي فرملة متبقية لديك للإبطاء قدر الإمكان"],"explanation":"لا تنقل أبدًا إلى الوضع المحايد على منحدر لأن ذلك يزيل كبح المحرك ويجعلك تتسارع؛ أبقِ المركبة في ترس منخفض بدلًا من ذلك."},"516":{"q":"تبدأ عجلات الدفع لديك في الانزلاق على طريق زلق ويبدأ مؤخرة الجرار في الانزلاق نحو اليمين. لاستعادة السيطرة يجب أن:","options":["توقف عن التسارع (واضغط على القابض)، ثم وجّه في الاتجاه الذي تريد أن يتجه إليه مقدمة المركبة","افرمل بقوة لإيقاف الانزلاق فورًا","وجّه بحدة إلى اليسار، عكس اتجاه الانزلاق","تسارع لسحب المقطورة إلى صفها"],"explanation":"في انزلاق عجلات الدفع، أولًا أزل السبب برفع قدمك عن دواسة الوقود والضغط على القابض حتى تستعيد العجلات الجر، ثم وجّه حيث تريد أن تتجه المقدمة."},"517":{"q":"على منعطف حاد تفقد عجلاتك الأمامية الجر وتستمر الشاحنة في السير مستقيمة رغم أن العجلات مُدارة. السبب المعتاد والرد الصحيح هما:","options":["السبب: سرعة قليلة جدًا — تسارع لاستعادة التوجيه","السبب: إطارات خلفية منفوخة أكثر من اللازم — توقف جانبًا وأخرج بعض الهواء","السبب: القيادة بسرعة أكبر مما تسمح به الظروف — ارفع قدمك، وستستعيد العجلات الأمامية الجر مع تباطؤك","السبب: دفع المقطورة — اضغط على صمام يد المقطورة بقوة"],"explanation":"انزلاق العجلات الأمامية يكون عادةً بسبب القيادة بسرعة أكبر مما تسمح به الظروف، وبما أن التوجيه لا يفعل شيئًا فيجب أن ترفع قدمك حتى تستعيد الإطارات الأمامية الجر مع تباطؤك."},"518":{"q":"تتوقف سيارة فجأة في مسارك وليس لديك مساحة للتوقف في الوقت المناسب. في معظم الحالات يكون الإجراء الطارئ الأكثر أمانًا هو أن:","options":["افرمل بأقصى ما تستطيع وآمل أن تتوقف قبلها بقليل","وجّه حول العائق — يمكنك عادةً الانعطاف لتفاديه في مسافة أقل مما يلزم للتوقف","اقفل الفرامل وأمسك العجلة مستقيمة بثبات","افرمل بقوة ووجّه في الوقت نفسه للحصول على أقصى تأثير"],"explanation":"عند سرعة الطريق السريع يمكنك عادةً تغيير الاتجاه في مسافة أقل مما يلزم للتوقف، لذا فإن التوجيه حول خطر ثم إعادة التوجيه يتفادى غالبًا حادثًا حين يتعذر التوقف."},"519":{"q":"عند سرعة الطريق السريع تسمع دويًا عاليًا، وينحرف التوجيه فجأة بقوة إلى جانب واحد، وترتطم المركبة — علامات انفجار إطار أمامي. يجب أن يكون ردك الفوري أن:","options":["افرمل بقوة فورًا لإبطاء السرعة قبل أن تفقد السيطرة","تسارع لفترة وجيزة لاستعادة الثبات، ثم افرمل","وجّه بسرعة إلى الكتف مع الفرملة بقوة","أمسك عجلة القيادة بثبات، وابتعد عن الفرامل، ودع المركبة تبطئ قبل أن تنحرف بلطف إلى جانب الطريق"],"explanation":"بعد الانفجار، أمسك عجلة القيادة بثبات وابتعد عن الفرامل، تاركًا المركبة تبطئ من تلقاء نفسها قبل أن تفرمل بلطف وتنحرف إلى الكتف."},"520":{"q":"أنت تنقل أنبوبًا فولاذيًا واحدًا طوله 9 أقدام. باستخدام قواعد تأمين الحمولة، الحد الأدنى لعدد أربطة التثبيت المطلوبة هو:","options":["اثنان — يُطلب رباطان للتثبيت على الأقل مهما كانت الحمولة قصيرة","واحد — طولها أقل من 10 أقدام، لذا يفي رباط واحد بقاعدة رباط واحد لكل 10 أقدام","لا شيء — الحمولة الأقصر من 10 أقدام معفاة من قواعد أربطة التثبيت","أربعة — رباط تثبيت واحد لكل زاوية من الحمولة"],"explanation":"يُطلب دائمًا رباطان للتثبيت على الأقل لأي قطعة حمولة، مهما كانت قصيرة، بالإضافة إلى رباط تثبيت واحد لكل 10 أقدام من الطول."},"521":{"q":"تزن حمولتك 40,000 رطل. يجب أن يكون حد الحمل الإجمالي العامل (WLL) لجميع أربطة التثبيت التي تستخدمها على الأقل:","options":["10,000 رطل","20,000 رطل","40,000 رطل","80,000 رطل"],"explanation":"يجب أن يساوي حد الحمل العامل الإجمالي لأربطة التثبيت لديك على الأقل نصف وزن الحمولة المؤمَّنة."},"522":{"q":"يمكنك وضع حمولة ثقيلة إما منخفضة وموزعة عبر أرضية المقطورة، أو مكدسة عاليًا ومتمركزة في الوسط. أيهما صحيح، ولماذا؟","options":["كدّسها عاليًا ومتمركزة في الوسط لإبعاد الوزن عن حواف المحاور","كدّسها عاليًا حتى تنزاح الحمولة أقل في المنعطفات","لا فرق طالما أن الوزن الإجمالي ضمن الحدود القانونية","حمّلها منخفضة وموزعة للحفاظ على مركز ثقل منخفض وتقليل خطر الانقلاب"],"explanation":"إبقاء الحمولة منخفضة وموزعة بالتساوي يخفض مركز الثقل، وهو أكبر عامل في مقاومة الانقلاب والبقاء مستقرًا."},"523":{"q":"يمكن لتوزيع الوزن السيئ أن يسبب مشاكل في كلا الطرفين. أي عبارة عن الوزن والتحكم في المركبة صحيحة؟","options":["تحميل محور الدفع بشكل زائد يحسّن دائمًا الجر دون أي جانب سلبي","توزيع الوزن يؤثر فقط على اقتصاد الوقود، وليس على طريقة تعامل المركبة","قلة الوزن على محور التوجيه يمكن أن تجعل الإطارات الأمامية تفقد الجر وتضعف تحكمك في التوجيه","حمل المحور الأثقل يقصّر دائمًا مسافة توقفك"],"explanation":"قلة الوزن على محور التوجيه تقلل جر الإطارات الأمامية وتضعف التحكم في التوجيه، لذا فإن التوازن السليم يهم بقدر أهمية الوزن الإجمالي."}},"airbrakes":{"0":{"q":"أثناء فحصي قبل الرحلة، يطلب مني الفاحص أن أشرح إعداد الفرامل الهوائية على جراري. أخبره أن الفرامل الهوائية هي في الواقع عدة أنظمة فرملة مدمجة في نظام واحد. أي إجابة تذكر بشكل صحيح كم نظام فرملة منفصل يدمجه نظام الفرامل الهوائية فعليًا، وتسمّيها؟","options":["ثلاثة أنظمة: فرامل الخدمة، وفرامل التوقف، وفرامل الطوارئ.","نظامان: النظام الهوائي الأساسي والنظام الهوائي الثانوي بمجموعة واحدة من أدوات التحكم.","أربعة أنظمة: فرامل الخدمة، وفرامل التوقف، وفرامل الطوارئ، ونظام منع انغلاق الفرامل (ABS).","نظام واحد: دائرة واحدة تتولى التوقفات العادية والتوقف والطوارئ معًا."],"explanation":"نظام الفرامل الهوائية هو في الواقع ثلاثة أنظمة منفصلة مدمجة معًا: فرامل الخدمة، وفرامل التوقف، وفرامل الطوارئ."},"1":{"q":"أقوم بفحص ما قبل الرحلة وأرفع سرعة المحرك لبناء ضغط الهواء بينما أراقب مقياس لوحة القيادة. أريد التأكد من أن المنظّم يعمل بشكل صحيح من خلال ملاحظة الضغط الذي يتوقف عنده ضاغط الهواء عن ضخ الهواء إلى الخزانات. عند أي قراءة تقريباً يجب أن تتوقف الإبرة عن الارتفاع لأن المنظّم قد فصل (CUT OUT)؟","options":["حوالي 100 psi، وهو الضغط الذي يتوقف عنده الضاغط عن إضافة الهواء إلى الخزانات","حوالي 125 psi، وعندها يفصل المنظّم ويتوقف الضاغط عن الضخ","حوالي 150 psi، حيث يصل النظام إلى حده الأقصى ويتوقف الضاغط عن العمل","حوالي 60 psi، وهي النقطة التي يوقف عندها المنظّم الضاغط في نظام مشحون"],"explanation":"يفصل المنظّم عند حوالي 125 psi، فيوقف الضاغط عن ضخ المزيد من الهواء إلى الخزانات."},"2":{"q":"أنا متوقف أقوم بفحص ما قبل الرحلة وأراقب مقياس الهواء. كان الضاغط قد فصل سابقاً وتوقف عن الضخ، لذا انخفض الضغط ببطء بينما أختبر النظام. عند أي قراءة على المقياس ينبغي أن أتوقع أن يعيد المنظّم تشغيل الضاغط ليبدأ بضخ الهواء من جديد؟","options":["حوالي 60 psi، وهي النقطة نفسها التي يضيء عندها ضوء وجرس تحذير انخفاض ضغط الهواء","حوالي 125 psi، وهو المستوى الذي يوقف عنده المنظّم الضاغط عن الضخ","حوالي 100 psi، وهي النقطة التي يأمر عندها المنظّم الضاغط باستئناف الضخ","حوالي 150 psi، وهو المستوى الذي يفتح عنده صمام تنفيس الأمان لتصريف الضغط"],"explanation":"نقطة وصل المنظّم (cut-in) هي حوالي 100 psi، حيث يأمر الضاغط باستئناف ضخ الهواء."},"3":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ أن منظّم ضاغط الهواء لا يفصل — فالمقياس يستمر في الارتفاع متجاوزاً نقطة الـ 125 psi العادية التي يجب أن يتوقف عندها الضخ. إذا لم يفصل المنظّم أبداً، فعند أي ضغط تقريباً يجب أن يفتح صمام تنفيس الأمان لحماية النظام من الضغط الزائد؟","options":["عند حوالي 100 psi، وهي النقطة نفسها التي يصل عندها المنظّم عادةً ويستأنف الضخ","عند حوالي 60 psi، وهي العتبة نفسها التي تُشغّل ضوء وجرس تحذير انخفاض ضغط الهواء","عند حوالي 125 psi، مطابقاً لنقطة فصل المنظّم بحيث يعمل الجهازان معاً","عند حوالي 150 psi، فيُصرّف الهواء الزائد لمنع النظام من بناء ضغط خطير"],"explanation":"يفتح صمام تنفيس الأمان عند حوالي 150 psi لتصريف الهواء الزائد وحماية النظام من الضغط الخطير."},"4":{"q":"أقوم بفحص ما قبل الرحلة على جرار مفرد بنظام هواء مشحون بالكامل. والمحرك مُطفأ، أضغط على الفرامل تدريجياً (fan) وأراقب لوحة القيادة. عند أي نقطة يجب أن يكون ضوء وجرس تحذير انخفاض الهواء فعّالين بالفعل — أي يجب أن يكون التحذير قد عمل قبل أن يهبط الضغط دون أي مستوى؟","options":["قبل أن يهبط ضغط الهواء دون 60 psi","قبل أن يهبط ضغط الهواء دون 80 psi","بمجرد أن يكون الضغط قد هبط بالفعل إلى نطاق 20 إلى 45 psi","قبل أن يهبط ضغط الهواء دون 100 psi"],"explanation":"يجب أن يعمل تحذير انخفاض ضغط الهواء قبل أن يهبط ضغط النظام دون 60 psi."},"5":{"q":"أقود جراراً ومقطورة مفردة محمّلة عندما ينفجر خط ويبدأ ضغط الهواء بالتسرب بسرعة. ضوء وجرس تحذير انخفاض الهواء يعملان بالفعل، والإبرة تستمر بالهبوط. عند أي ضغط تقريباً ينبغي أن أتوقع أن تعمل فرامل النابض (الطوارئ) تلقائياً وتوقفني؟","options":["حوالي 60 psi، وهي النقطة نفسها التي يعمل عندها تحذير انخفاض الهواء أول مرة","في مكان ما ضمن نطاق 20 إلى 45 psi، بعد أن يكون التحذير قد عمل بالفعل","حوالي 100 psi، وهي نقطة وصل المنظّم حيث يعيد الضاغط العمل","حوالي 5 إلى 10 psi، فقط عندما تكون الخزانات شبه فارغة تماماً"],"explanation":"تعمل فرامل النابض (الطوارئ/الإيقاف) تلقائياً عندما يهبط ضغط هواء النظام إلى نطاق 20 إلى 45 psi."},"6":{"q":"أثناء فحص ما قبل الرحلة، يشير مدربي إلى الدواسة التي أضغط عليها بقدمي لتطبيق فرامل الخدمة ويسألني عن اسمها الصحيح الآخر. للإجابة بشكل صحيح، إلى أي مكوّن يشير؟","options":["المنظّم، لأنه يتحكم بكمية هواء الكبح الذي تطلقه الدواسة إلى العجلات","مُعدِّل الخلوص (slack adjuster)، لأنه ينقل ضغط قدمي إلى قوة كبح ميكانيكية","الصمام الدواس (foot/treadle valve)، الذي يرسل الهواء إلى فرامل الخدمة عندما أضغط عليه","المقبض الواصل (glad hand)، لأنه الوصلة التي تنقل هواء الكبح إلى الفرامل"],"explanation":"تُسمّى دواسة الفرامل بشكل صحيح الصمام الدواس (foot/treadle valve)، الذي يقيس الهواء إلى فرامل الخدمة عند الضغط عليه."},"7":{"q":"إنه صباح شتوي متجمّد، وأثناء فحص ما قبل الرحلة أفتح صمام التصريف في أسفل خزان الهواء. يتدفق منه سائل حليبي زيتي مع الهواء. يخبرني زميل بأنه لا بد أن لدي مشكلة ميكانيكية خطيرة لأن هذا السائل يجب ألّا يكون في الخزان أبداً. أي عبارة تشرح بشكل صحيح ما أراه ولماذا أصرّف الخزانات يومياً؟","options":["يجب ألّا يتدفق سوى الهواء؛ السائل يعني أن خزاناً متشققاً يُسرّب سائل الفرامل إلى مصدر الهواء","تسرّب سائل التبريد عبر مانع تسرب تالف إلى الخزان، لذا يجب أن أصرّفه قبل أن يصل إلى حجرات الفرامل","سائل فرامل متسرّب اختلط بالهواء، والتصريف اليومي يطرد ذلك السائل من النظام","يجمع الهواء المضغوط عادةً الماء وبعض زيت الضاغط، والتصريف اليومي يزيله لمنع التجمّد والتلف"],"explanation":"يجمع الهواء المضغوط بشكل طبيعي الماء وبعض زيت الضاغط، لذا يجب تصريف الخزانات يومياً لمنع التجمّد والتلف."},"8":{"q":"الجو دون درجة التجمّد في صباح شتوي، وألاحظ أن شاحنتي مزوّدة بمجفِّف هواء مركّب على خزان الإمداد (الرطب). أثناء فحص ما قبل الرحلة، أحاول تذكّر المهمة الرئيسية لهذا المكوّن. أي عبارة تصف على أفضل وجه ما يفعله مجفِّف الهواء لنظام فرامل الهواء لدي؟","options":["يزيل الماء والملوثات من الهواء المضغوط قبل أن يصل ذلك الهواء إلى خزانات التخزين","يرفع الهواء المضغوط فوق نقطة فصل المنظّم بحيث تصل الخزانات إلى ضغط تشغيل أعلى","يُشغّل ضوء وجرس تحذير انخفاض ضغط الهواء قبل أن يهبط ضغط الخزان دون 60 psi","يبرّد طبول وبطانات الفرامل الساخنة بعد منحدر طويل وشديد لمنع تلاشي الكبح"],"explanation":"يزيل مجفِّف الهواء الماء والملوثات من الهواء المضغوط قبل أن يصل إلى خزانات التخزين."},"9":{"q":"أقوم بفحص ما قبل الرحلة على جرار ومقطورة وقد بلغ المحرك للتو نقطة فصل المنظّم. وأنا أتفحّص لوحة القيادة، أرى مقياسي هواء جنباً إلى جنب. للتأكد من أن لدي هواءً مخزّناً كافياً قبل أن أحرّر الفرامل وأنطلق، أي قراءة على مقياس ضغط الإمداد تخبرني بما أحتاج معرفته؟","options":["مقدار الضغط الذي أرسله حالياً إلى حجرات الفرامل عندما أضغط على الدواسة","مقدار ضغط الهواء المخزّن حالياً في خزانات الهواء (حوالي 125 psi عند الفصل)","الضغط الذي ستعمل عنده فرامل النابض تلقائياً إذا انخفض الهواء","الضغط الذي ضُبط صمام تنفيس الأمان على الفتح عنده لحماية النظام"],"explanation":"يُظهر مقياس ضغط الإمداد مقدار ضغط الهواء المخزّن حالياً في خزانات الهواء، حوالي 125 psi عند الفصل."},"10":{"q":"أنزل منحدراً طويلاً في شاحنتي المحمّلة وأضغط على دواسة الفرامل بقوة أكبر للحفاظ على سرعتي. وكلما ضغطت على الدواس أكثر، يرتفع أحد المقاييس على لوحتي كلما ضغطت أكثر، ويهبط نحو الصفر عندما أرفع قدمي. أي مقياس أراقبه وهو يستجيب لقدمي على الدواسة؟","options":["مقياس ضغط الهواء (الإمداد) في الخزان، لأنه يتتبّع كمية الهواء المتبقية في الخزانات","مقياس فصل المنظّم، لأنه يُظهر توقّف الضاغط عند حوالي 125 psi","مقياس ضغط التطبيق، لأنه يُظهر مقدار ضغط الهواء الذي أطبّقه على الفرامل","مقياس تحذير انخفاض ضغط الهواء، لأنه يضيء قبل أن يهبط الضغط دون 60 psi"],"explanation":"يُظهر مقياس ضغط التطبيق مقدار ضغط الهواء الذي ترسله إلى الفرامل عبر دواسة القدم."},"11":{"q":"أثناء فحص ما قبل الرحلة، يشير مدربي إلى الكامة على شكل S (S-cam) في مجموعة فرامل ويطلب مني أن أشرح ما يحدث فعلياً عند ذلك المكوّن في اللحظة التي أضغط فيها على دواسة الفرامل ويُرسَل الهواء إلى حجرة الفرامل. أي إجابة تصف بشكل صحيح وظيفة الكامة على شكل S؟","options":["تُصرّف الماء وزيت الضاغط من خزانات الهواء كي لا تتجمّد الخطوط","تأمر المنظّم بإيقاف الضاغط بمجرد أن تبلغ الخزانات حوالي 125 psi","تسحب مُعدِّل الخلوص للخلف لإزالة الخلوص الحر في مسار قضيب الدفع","تدور وتدفع حذوتي الفرامل للتباعد ضد السطح الداخلي للطبل"],"explanation":"تدور الكامة على شكل S وتتداخل بين حذوتي الفرامل، فتدفعهما للتباعد ضد السطح الداخلي للطبل."},"12":{"q":"أثناء فحص ما قبل الرحلة، أركن على أرض مستوية، وأضع إسفيناً تحت العجلات، وأحرّر فرامل الإيقاف، وأعتمد بقضيب رفع على مُعدِّل خلوص يدوي للتحقق من زيادة مسار قضيب الدفع. تكون الفرامل خارج الضبط إذا تحرّك مُعدِّل الخلوص أكثر من حوالي:","options":["1 inch، لأن الخلوص الحر الأكبر يعني أن الفرامل خارج الضبط وتفقد قوة الكبح","3 inches، وهو أقصى مسار مسموح به قبل أن تكون الفرامل خارج الضبط","5 inches، لأن أي قيمة أقل من ذلك تبقي الفرامل ضمن الضبط الصحيح","يمكنه التحرك بحرية، لأن مُعدِّلات الخلوص مصممة للتأرجح دون أي حد للمسار"],"explanation":"يجب ألّا يتحرك مُعدِّل الخلوص اليدوي أكثر من حوالي 1 inch عند الاعتماد عليه، وإلا فإن الفرامل خارج الضبط."},"13":{"q":"أقود جراراً ومقطورة بفرامل هوائية وأضغط على دواسة الفرامل بقوة للإبطاء بسبب حركة المرور أمامي. مقارنةً بالفرامل الهيدروليكية في سيارتي، هناك تأخير ملحوظ قبل أن تمسك فرامل الهواء فعلياً. كم يبلغ تقريباً هذا التأخر في فرامل الهواء — الزمن الذي يستغرقه الهواء للانتقال عبر الخطوط والتأثير بعد أن أضغط على الدواسة؟","options":["حوالي 1/10 من الثانية، وهي الاستجابة شبه الفورية نفسها التي أشعر بها في نظام كبح هيدروليكي للسيارة","حوالي 1/2 ثانية كي ينتقل الهواء عبر الخطوط وتمسك الفرامل","حوالي 2 ثانية، وهو ما يقارب تأخير مسافة رد الفعل قبل أن يضغط السائق على الدواسة","حوالي 5 ثوانٍ، لأن الهواء يجب أن يشحن كل حجرة بالكامل قبل أن يبدأ أي كبح"],"explanation":"لفرامل الهواء تأخّر يبلغ حوالي نصف ثانية بينما ينتقل الهواء المضغوط عبر الخطوط قبل أن تمسك الفرامل."},"14":{"q":"أحسب مسافة التوقف الكلية لمركبتي ذات فرامل الهواء. بالنسبة لسيارة بفرامل هيدروليكية، تكون مسافة التوقف الكلية مجرد مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الكبح. ولأن شاحنتي تستخدم فرامل هواء، أي عنصر إضافي يجب أن أضيفه إلى ذلك الحساب ولا يملكه سائق السيارة؟","options":["مسافة رد فعل إضافية، لأن أدوات التحكم بفرامل الهواء تستغرق وقتاً أطول كي يشغّلها الدماغ","مسافة إدراك أطول، لأن الشاحنة الأكبر تجعل اكتشاف المخاطر في الوقت المناسب أصعب","مسافة تأخّر الكبح، عن النصف ثانية تقريباً التي يستغرقها الهواء للانتقال عبر الخطوط والتطبيق","لا شيء إضافي، لأن المسافات الأربع الأساسية متطابقة لكل نوع من أنظمة الكبح"],"explanation":"تضيف مسافة التوقف لفرامل الهواء مسافة تأخّر كبح عن النصف ثانية التي يستغرقها الهواء للانتقال عبر الخطوط والتطبيق."},"15":{"q":"أثناء فحص ما قبل الرحلة، أُطفئ المحرك والنظام مشحون بالكامل إلى حوالي 125 psi، وأضع إسفيناً تحت العجلات، وأترك فرامل الإيقاف محرّرة على شاحنتي المستقيمة (المفردة). أراقب مقياس لوحة القيادة لمدة دقيقة لقياس التسرب. يكون فقد الهواء مقبولاً فقط ما دام عند أو أدنى من أي معدل؟","options":["4 psi في الدقيقة، لأن هذا هو الحد عندما يكون المحرك مُطفأً والخزانات ممتلئة","1 psi في الدقيقة، على افتراض أنه يجب ألّا يتسرب أي هواء تقريباً من نظام محكم","3 psi في الدقيقة، وهو الرقم نفسه الذي ينطبق على المركبة المركّبة في هذا الاختبار","2 psi في الدقيقة، وهو الحد الأقصى المسموح لمركبة مفردة بفرامل محرّرة"],"explanation":"بالنسبة لمركبة مفردة بفرامل محرّرة، يجب ألّا يتجاوز فقد الهواء 2 psi في الدقيقة."},"16":{"q":"أثناء فحص ما قبل الرحلة على جرار ومقطورة، أشحن النظام بالكامل إلى حوالي 125 psi، وأُطفئ المحرك، وأترك الفرامل محرّرة لقياس تسرب الهواء. بمراقبة مقياس لوحة القيادة لمدة دقيقة، ما هو أقصى هبوط في الضغط يمكن أن يكون لدي وأظل أنجح في هذا الجزء من الفحص؟","options":["3 psi في دقيقة واحدة","2 psi في دقيقة واحدة","4 psi في دقيقة واحدة","6 psi في دقيقة واحدة"],"explanation":"بالنسبة لمركبة مركّبة بفرامل محرّرة، يجب ألّا يتجاوز فقد الهواء 3 psi في الدقيقة."},"17":{"q":"أثناء فحص ما قبل الرحلة، أشحن نظام الهواء إلى حوالي 125 psi، وأُطفئ المحرك، وأضع إسفيناً تحت العجلات، وأطبّق فرامل القدم بالكامل على شاحنتي المستقيمة المفردة (دون مقطورة). أراقب مقياس لوحة القيادة لمدة دقيقة للتحقق من معدل تسرب الهواء. أي قراءة تعني أن شاحنتي ضمن الحد القانوني وآمنة للقيادة؟","options":["يهبط الضغط بمقدار 4 psi خلال تلك الدقيقة","يهبط الضغط بمقدار 2 psi خلال تلك الدقيقة","يهبط الضغط بمقدار 5 psi خلال تلك الدقيقة","يهبط الضغط بمقدار 6 psi خلال تلك الدقيقة"],"explanation":"بالنسبة لمركبة مفردة بفرامل مطبّقة، يجب أن يبقى فقد الهواء أقل من 3 psi في الدقيقة."},"18":{"q":"أثناء فحص ما قبل الرحلة على نظام فرامل هواء مزدوج، أُشغّل المحرك وأديره عند دورات التشغيل، وأراقب مقاييس لوحة القيادة ترتفع من 85 psi. للنجاح في جزء بناء الهواء من الفحص، خلال أي وقت يجب أن تبلغ المقاييس 100 psi؟","options":["خلال 10 ثوانٍ من التشغيل عند دورات التشغيل","خلال 3 دقائق من التشغيل عند دورات التشغيل","خلال 45 ثانية من التشغيل عند دورات التشغيل","خلال 5 دقائق من التشغيل عند دورات التشغيل"],"explanation":"في نظام فرامل الهواء المزدوج، يجب أن يرتفع الضغط من 85 إلى 100 psi خلال 45 ثانية عند دورات التشغيل."},"19":{"q":"أثناء فحص ما قبل الرحلة، المحرك مُطفأ وخزانات الهواء مشحونة إلى حوالي 125 psi. أريد التأكد من أن جهاز تحذير انخفاض ضغط الهواء يعمل بشكل صحيح قبل أن أقود. أي إجراء يؤدي هذا الفحص فعلياً؟","options":["أدِر المحرك بدورات عالية والنظام مشحون وراقب أن يضيء التحذير عندما يتجاوز الضغط 60 psi صعوداً","افتح صمامات تصريف الخزان على مصراعيها كي يخرج كل الهواء بسرعة من الخزانات، ثم استمع لصوت الجرس","اضغط على دواسة الفرامل مرة واحدة وتأكد من أن جهاز التحذير يبقى مطفأً والضغط فوق 100 psi","والمحرك مُطفأ، اضغط على دواسة الفرامل وأطلقها مراراً لتفريغ الضغط حتى يعمل التحذير فوق 60 psi"],"explanation":"والمحرك مُطفأ، اضغط على الفرامل تدريجياً (fan) لتفريغ الضغط وتأكد من أن تحذير انخفاض الهواء يعمل قبل أن يهبط الضغط دون 60 psi."},"20":{"q":"أثناء فحص ما قبل الرحلة لفرامل الهواء، بنيت النظام إلى الضغط الكامل، وحرّرت فرامل الإيقاف، وأنا مستعد للتحقق من أن فرامل الخدمة ستمسك فعلاً وتوقف المركبة بشكل مستقيم. أي من هذه هو الطريقة الصحيحة لإجراء اختبار توقّف فرامل الخدمة؟","options":["دع المركبة تتحرك للأمام بسرعة حوالي 5 mph، ثم اضغط دواسة الفرامل بحزم وتأكد من أنها تتوقف دون انحراف إلى أحد الجانبين","تسارع إلى سرعة الطريق السريع العادية واكبح بقوة مرة واحدة للتأكد من أن الفرامل تستطيع التعامل مع توقّف كامل","أبقِ المركبة ثابتة، واسحب مقبض فرامل الإيقاف للخارج، واشعر إن كان الجرار يبقى مقفلاً في مكانه","أثناء التحرك بسرعة حوالي 5 mph، اضغط دواسة الفرامل عشر مرات بسرعة للتأكد من أن الضغط يُبنى من جديد في كل مرة"],"explanation":"الفحص الصحيح لفرامل الخدمة: تحرّك للأمام بسرعة حوالي 5 mph، اضغط الدواسة بحزم، ويجب أن تتوقف المركبة بشكل مستقيم دون انحراف إلى أحد الجانبين."},"21":{"q":"أثناء فحص ما قبل الرحلة، أجد شقاً يمتد عبر وجه أحد طبول الفرامل. أحتاج إلى أن أقرر ما إذا كنت سأخرج المركبة من الخدمة. وفقاً لدليل CDL في تكساس، يكون طبل الفرامل المتشقق خارج الخدمة عندما يكون الشق أطول من أي مما يلي؟","options":["أي شق شعري مرئي على وجه الطبل","نصف عرض سطح الاحتكاك للطبل","ربع عرض سطح الاحتكاك للطبل","كامل عرض سطح الاحتكاك للطبل"],"explanation":"يجب إخراج طبل الفرامل من الخدمة عندما يمتد الشق لأطول من نصف عرض سطح الاحتكاك للطبل."},"22":{"q":"أثناء فحص ما قبل الرحلة، أسحب عجلة وأزحف تحت المقطورة لأنظر إلى فرامل الطبل. أجد مشكلة وأقرر أنه يجب استبدال البطانات قبل أن أقود. أي من الحالات التالية على بطانات الفرامل تبرّر بشكل صحيح إخراج هذه المركبة من الخدمة؟","options":["البطانات سميكة وجافة ومثبّتة بإحكام على لوحة الإسناد","البطانات تستقر مستوية على الطبل وتُظهر تآكلاً سطحياً خفيفاً ومتساوياً","البطانات مشبّعة بالزيت أو الشحم، أو متآكلة لدرجة رفيعة بشكل خطير","البطانات رُكّبت للتو وعليها لمعان خفيف من الاستقرار الأولي"],"explanation":"تكون بطانات الفرامل معيبة ويجب إخراج المركبة من الخدمة عندما تكون مشبّعة بالزيت أو الشحم أو متآكلة لدرجة رفيعة بشكل خطير."},"23":{"q":"أنقل مركبة مركّبة محمّلة نزولاً على منحدر طويل وشديد. لقد نقلت إلى غيار منخفض قبل أن أبدأ النزول، والآن أفكّر في كيفية استخدام فرامل الهواء لبقية النزول. أي عبارة تصف بشكل صحيح الدور الذي يجب أن تؤديه فراملي على هذا المنحدر؟","options":["هي وسيلة التحكم الرئيسية بالسرعة، لذا يجب أن أبقي ضغطاً ثابتاً على الدواسة طوال الطريق نزولاً","تعمل بشكل أفضل عند الضغط عليها وتحريرها مراراً، مما يتيح إعادة شحن الهواء بين كل تطبيق","يجب أن تُضغط بحزم وباستمرار لمنع العجلات من اكتساب أي سرعة على الإطلاق","هي مكمّل للكبح بالمحرك، تُستخدم بتطبيقات خفيفة وثابتة لدعم الغيار المنخفض"],"explanation":"على منحدر طويل يكون المحرك في غيار منخفض هو وسيلة التحكم الرئيسية بالسرعة، والفرامل تكمّله فقط بتطبيقات خفيفة وثابتة."},"24":{"q":"أنزل منحدراً طويلاً وشديداً في مركبتي المركّبة المحمّلة، وأنا بالفعل في غيار منخفض، وأريد استخدام تقنية الكبح المتقطّع (snub) الصحيحة للسيطرة على سرعتي. أي إجراء يصف بشكل صحيح ما يجب أن أفعله بالفرامل؟","options":["طبّق الفرامل بحزم حتى تهبط سرعتي حوالي 5 mph دون سرعتي الآمنة، ثم حرّرها بالكامل، وكرّر الدورة حسب الحاجة","أبقِ ضغطاً خفيفاً ثابتاً على دواسة الفرامل باستمرار طوال الطريق نزولاً لتجنّب بناء أي حرارة أبداً","اضغط الفرامل وحرّرها بسرعة طوال النزول لمنع العجلات من الانغلاق","انقل إلى الوضع المحايد واترك المركبة تنزلق، مطبّقاً الفرامل فقط إذا تجاوز عدّاد السرعة سرعتك الآمنة"],"explanation":"استخدم الكبح المتقطّع (snub) على منحدر طويل: طبّق الفرامل بحزم حتى تهبط السرعة حوالي 5 mph دون سرعتك الآمنة، حرّرها بالكامل لتبرد، ثم كرّر."},"25":{"q":"أنزل منحدراً جبلياً طويلاً وشديداً في شاحنة محمّلة بفرامل هواء. يستمر المنحدر وأنا قلق على فراملي، لذا أبدأ بالضغط على دواسة الفرامل وتحريرها بسرعة مراراً وتكراراً للسيطرة على سرعتي. لماذا يكون هذا بالضبط هو الشيء الخاطئ الذي يجب فعله؟","options":["الكبح المتكرر بالضغط والتحرير يُسخّن مُعدِّلات الخلوص ويقفل العجلات الأمامية، مسبّباً انزلاق الشاحنة وفقدان السيطرة على المنحدر","كل تحرير يدع الهواء يتسرب أسرع مما يستطيع الضاغط تعويضه، فقد يهبط الضغط حتى لا يعود لدى الفرامل هواء كافٍ للعمل","تكرار الضغط على الدواسة يُشغّل نظام ABS فيحرّر الفرامل بالكامل، تاركاً فرامل النابض الوسيلة الوحيدة للإبطاء","الضغط على الدواسة يفتح صمام تنفيس الأمان عند 150 psi، مفرّغاً هواء الخزان الذي تحتاجه لبقية النزول"],"explanation":"الضغط على الفرامل وتحريرها مراراً (fanning) يطلق الهواء أسرع مما يستطيع الضاغط تعويضه، فقد يهبط ضغط الهواء حتى لا يعود لدى الفرامل هواء كافٍ للعمل."},"26":{"q":"لقد أنهيت للتو نزولاً طويلاً على منحدر جبلي شديد، مستخدماً الفرامل الهوائية طوال الطريق، وتوقفت في منطقة استراحة لأخذ استراحتي الإلزامية. في أيٍّ من هذه الحالات يجب ألّا أُفعّل فرامل الانتظار (الزنبركية)، وأن أضع بدلاً من ذلك أسافين تحت العجلات؟","options":["أنا أركن على منحدر هابط طفيف حيث يمكن أن تتدحرج الشاحنة إذا تُركت في وضع التعشيق","سأترك الشاحنة دون مراقبة طوال الليل في موقف شاحنات مُحدّد","لا تزال أسطوانات الفرامل وأحذيتها ساخنة جداً من النزول الذي قمت به للتو","صفّارة التحذير من انخفاض ضغط الهواء أطلقت صوتها لفترة وجيزة بينما كنت أتوقف"],"explanation":"لا تُفعّل فرامل الانتظار (الزنبركية) عندما تكون الأسطوانات والأحذية لا تزال ساخنة جداً بعد نزول طويل، لأن ذلك قد يُتلفها ويسبب التصاقها."},"27":{"q":"إذا أضاء تحذير انخفاض الهواء أثناء القيادة، فيجب عليك:","options":["الاستمرار حتى المدينة التالية","التوقف والركن في أقرب مكان آمن","إيقاف تشغيل التحذير","زيادة السرعة لبناء الهواء"],"explanation":"يمكن أن يؤدي فقدان الهواء إلى تفعيل الفرامل الزنبركية فجأة."},"28":{"q":"أنا أقود قاطرة مقطورة موديل 2020 (مزوّدة بنظام ABS عامل) عندما تتوقف سيارة فجأة تماماً في مساري. يجب أن أتوقف بأسرع ما يمكن مع إبقاء الشاحنة في مساري لتجنّب الكتف. أي طريقة كبح تمنحني أفضل تحكّم في هذه الحالة الطارئة؟","options":["ضخّ دواسة الفرامل بسرعة كي يتمكّن نظام ABS من التبديل والإمساك بين كل عملية تحرير","تفعيل صمام يد المقطورة وحده أولاً لمنع عجلات القاطرة من الانزلاق","تخفيف الضغط لحظة شعوري ببدء انزلاق عجلة، ثم الضغط مجدداً","الضغط على دواسة الفرامل بقوة، وإبقاؤها مضغوطة، والاستمرار في التوجيه نحو المسار المفتوح"],"explanation":"مع نظام ABS، اكبح بقوة وأبقِ ضغطاً ثابتاً على الدواسة أثناء التوجيه، لأن نظام ABS يمنع العجلات من الانغلاق فيمكنك التوجيه نحو المسار المفتوح."},"29":{"q":"أنا أقود قاطرة مقطورة أقدم غير مزوّدة بنظام ABS، وفجأة تقطع سيارة الطريق أمامي. أحتاج إلى التوقّف الطارئ القوي مع إبقاء الشاحنة تحت السيطرة. أي طريقة كبح ينبغي أن أستخدم؟","options":["استخدام الكبح المتحكّم به أو الكبح المتقطّع كي تستمر العجلات في الدوران فأتمكّن من التوجيه","الضغط على دواسة الفرامل حتى الأرض وإبقاؤها مضغوطة بقوة حتى أتوقّف","الكبح بقوة كافية لإغلاق العجلات، لأن العجلات المُغلقة تعطي أقصر مسافة توقّف","ضخّ دواسة الفرامل بسرعة طوال الطريق للحفاظ على ضغط الهواء"],"explanation":"بدون نظام ABS، استخدم الكبح المتحكّم به أو الكبح المتقطّع كي تستمر العجلات في الدوران، مما يحافظ على قوة التوقّف والتحكّم في التوجيه معاً."},"30":{"q":"أنا أقود شاحنة محمّلة دون نظام ABS عندما يندفع شيء إلى الطريق، فأضطر إلى الكبح بقوة. أضغط على دواسة الفرامل حتى الأرض، فتنغلق العجلات، وأُحرّر الدواسة لبدء سلسلة كبح متقطّع. لأداء الكبح المتقطّع بشكل صحيح، متى يجب أن أضغط على الدواسة بقوة مجدداً؟","options":["فور رفعي عن الدواسة، دون انتظار أي شيء","فقط بعد أن تبدأ العجلات في الدوران مجدداً","بعد إبقاء الفرامل مُحرّرة لمدة عدّ كامل يبلغ نحو 10 ثوانٍ","لا أضغط إطلاقاً — بمجرد التحرير، عليّ التوجيه والصمود حتى التوقّف"],"explanation":"في الكبح المتقطّع تعيد تفعيل الفرامل فقط بعد أن تبدأ العجلات في الدوران مجدداً، لأن العجلات المُغلقة لا يمكنها التوجيه أو الكبح بفعالية."},"31":{"q":"أنت على بُعد 30 ميلاً في رحلتك عندما يضيء مصباح عطل نظام ABS الكهرماني على لوحة القيادة ويبقى مُضاءً. لم يُفعّل تحذير انخفاض ضغط الهواء ولا تزال الدواسة تبدو ثابتة. أيٌّ مما يلي يصف حالتك ومسار العمل الصحيح بشكل صحيح؟","options":["فرامل الخدمة لديك تعطّلت؛ أوقف الشاحنة بشكل متحكّم على الكتف فوراً واتصل لطلب قاطرة قبل القيادة لمسافة أبعد.","مسافة التوقّف لديك أصبحت الآن أطول من المعتاد، لذا زِد مسافة المتابعة واضخّ دواسة الفرامل للحفاظ على تدفّق الهواء إلى العجلات.","لا تزال لديك فرامل الخدمة العادية ويمكنك الاستمرار في القيادة بحذر؛ فقط وظيفة منع الانغلاق هي المفقودة، لذا اصلح نظام ABS في أقرب وقت ممكن.","فرامل الزنبرك لديك على وشك التفعيل تلقائياً، لذا خفّض السرعة واخرج من المنحدر التالي قبل أن تنغلق العجلات عليك."],"explanation":"يعني مصباح تحذير نظام ABS أن وظيفة منع الانغلاق فقط هي المفقودة؛ تبقى لديك فرامل الخدمة العادية الكاملة، لذا قُد بحذر واصلح نظام ABS قريباً."},"32":{"q":"أنا أشتري قاطرة شاحنة مستعملة وأريد التأكّد من أنها أتت بفرامل مانعة للانغلاق (ABS) من المصنع، بما أن اللوائح الفيدرالية جعلت نظام ABS إلزامياً على مركبات معيّنة ذات فرامل هوائية. يسلّمني التاجر أربع قاطرات صُنعت في سنوات مختلفة. ما هو أقدم تاريخ صنع يُلزم القاطرة بأن تكون مزوّدة بنظام ABS مُركّب من المصنع؟","options":["أي قاطرة صُنعت في أو بعد 1 مارس 1998","أي قاطرة صُنعت في أو بعد 1 مارس 1995","أي قاطرة صُنعت في أو بعد 1 مارس 2000","أي قاطرة صُنعت في أو بعد 1 مارس 1997"],"explanation":"تُلزم اللوائح الفيدرالية بوجود نظام ABS من المصنع على قاطرات الشاحنات المصنوعة في أو بعد 1 مارس 1997."},"33":{"q":"إذا تعطّلت إحدى دوائر النظام المزدوج أثناء القيادة:","options":["تفقد كل قدرة على الكبح","لا تزال الدائرة الأخرى توقفك","يتوقّف المحرّك","تتعطّل الأضواء فقط"],"explanation":"لا تزال الدائرة الأخرى تكبحك؛ ويضيء التحذير."},"34":{"q":"إنه صباح ديسمبر قارس البرودة في أماريلو وأنا أُجري فحص ما قبل الرحلة. شاحنتي مزوّدة بصمامات تصريف يدوية على خزانات الهواء لكنني متأخّر، لذا أنا مُغرٍ بتخطّي تصريفها اليوم. ما هو أفضل سبب يجعلني أفتح مصارف الخزانات قبل الانطلاق رغم ذلك؟","options":["الماء الذي يتجمّع في الخزانات يمكن أن يتجمّد في الطقس البارد ويمنع الفرامل من العمل","يتيح تصريف الخزانات للمنظّم أن يفصل عند ضغط أعلى فيشحن النظام بشكل أسرع","يؤدي فتح المصارف إلى تنفيس الهواء القديم فيعود صمام تخفيف الأمان للاستقرار عند الإعداد الصحيح 150 psi","يؤدي تحرير الهواء إلى إعادة ضبط تحذير انخفاض الهواء فلا يُطلق الجرس صوته دون 60 psi"],"explanation":"صرّف خزانات الهواء يومياً لأن الماء المتجمّع يمكن أن يتجمّد في الطقس البارد ويمنع الفرامل من العمل."},"35":{"q":"أنا أُنهي فحص ما قبل الرحلة على قاطرة مقطورة. كان المحرّك يعمل ببطء وإبرة مقياس ضغط الهواء ترتفع. قبل أن أُحرّر فرامل الانتظار وأخرج من الساحة، إلى أي مستوى ضغط ينبغي أن أترك نظام الهواء يبني؟","options":["حتى نحو 100 psi، لأن هذه هي النقطة التي يبدأ عندها الضاغط بالعمل فأعلم أنه يعمل","حتى النطاق التشغيلي العادي، نحو 125 psi، حيث يفصل المنظّم ويتوقّف عن الضخّ","حتى نحو 150 psi، المستوى الذي يفتح عنده صمام تخفيف الأمان لحماية النظام","حتى نحو 60 psi يكفي، لأنه المستوى الذي يتوقّف عنده تحذير انخفاض ضغط الهواء"],"explanation":"اشحن نظام الهواء إلى نطاقه التشغيلي العادي، نحو 125 psi، حيث يفصل المنظّم، قبل القيادة."},"36":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ أن الحزام الذي يُشغّل ضاغط الهواء أصبح أملس ويمكن دفعه للأسفل ببضع بوصات بإبهامي. يبدأ المحرّك جيداً وراديو المقصورة يعمل. لماذا يهمّ هذا الحزام المُرتخي للتشغيل الآمن؟","options":["الحزام المُرتخي مصدر قلق فقط لأنه قد يصدر صريراً ويُصعّب سماع صفّارة تحذير انخفاض الهواء","يهمّ لأن الحزام يُدير أيضاً المولّد الذي يُبقي بطارية الطوارئ في المقطورة مشحونة","الحزام المنزلق قد يمنع الضاغط من الضخّ بسرعة كافية، فقد لا يبني النظام أو يحافظ على ضغط هواء كافٍ أبداً","يهمّ لأن حزام التشغيل يُوجّه هواء التبريد فوق أسطوانات الفرامل الأمامية لمنع تلاشي الفرامل"],"explanation":"الحزام المنزلق المُشغّل للضاغط يمنع الضاغط من الضخّ بسرعة كافية، فقد لا يبني النظام أو يحافظ على ضغط الهواء المناسب أبداً."},"37":{"q":"أنا أُجري فحص ما قبل الرحلة على مركبة تجميعية مفردة وأريد التأكّد من أنني أكملت كل جزء من قسم الفرامل الهوائية قبل الانطلاق. يخبرني سائق زميل أن بعض الفحوصات التي أدرجتها لا تُحتسب فعلاً جزءاً من اختبار الفرامل الهوائية. أيٌّ من هذه هو فعلاً جزء مطلوب من فحص كامل للفرامل الهوائية ما قبل الرحلة؟","options":["فقط اختبار جهاز تحذير انخفاض الهواء، لأن الجرس والضوء هما الجزء الذي يراقبه الفاحص","فقط توقيت بناء ضغط الهواء، لأنه يُثبت أن الضاغط يقوم بعمله","فقط معدّل تسرّب الهواء الساكن، لأن التسرّب هو أخطر عيب يمكن أن تجده","كلها — تحذير انخفاض الهواء، وتوقيت البناء، ومعدّل تسرّب الهواء كلٌّ منها جزء مطلوب من الفحص"],"explanation":"يتطلّب الفحص الكامل للفرامل الهوائية ما قبل الرحلة كل هذه: تحذير انخفاض الهواء، وتوقيت البناء، ومعدّل تسرّب الهواء."},"38":{"q":"أنا أُجري فحص ما قبل الرحلة على قاطرة بفرامل هوائية وأريد تخطّي أي خطوة لا تفحص فعلاً نظام الفرامل الهوائية نفسه. أيٌّ من البنود في قائمتي ينتمي إلى نظام مختلف ولا يخبرني بشيء عن فراملي؟","options":["تصريف الماء والزيت من المُبرّد للحفاظ على نظام تبريد المحرّك نظيفاً","توقيت المدة التي يستغرقها الضغط للارتفاع من 85 إلى 100 psi لتأكيد معدّل بناء سليم","شحن النظام، وإيقاف المحرّك، ومراقبة المقياس لمعدّل هبوط الضغط","ضرب الدواسة حتى يضيء ضوء تحذير انخفاض الهواء ويُطلق الجرس صوته قرب 60 psi"],"explanation":"تصريف الماء والزيت من المُبرّد هو صيانة لنظام تبريد المحرّك ولا يفحص شيئاً في نظام الفرامل الهوائية."},"39":{"q":"أنا أقود قاطرة مقطورة مزوّدة بنظام ABS وعليّ أن أُجري توقّفاً قوياً مفاجئاً على رصيف جاف. عندما يُفعّل نظام ABS وأشعر بنبض الدواسة، أيُّ عبارة عمّا يفعله نظام ABS فعلاً من أجلي في هذا التوقّف صحيحة؟","options":["إنه يُقصّر مسافة توقّفي مقارنة بالشاحنة نفسها دون نظام ABS","إنه يمنع عجلاتي من الانغلاق كي أتمكّن من التوجيه أثناء الكبح بقوة","إنه يُقلّل تلقائياً زمن تأخّر الفرامل إلى أقلّ من نصف الثانية المعتادة","إنه يُفعّل فرامل الزنبرك (الانتظار) لإضافة قوة توقّف إضافية"],"explanation":"يمنع نظام ABS العجلات من الانغلاق فتستمر في الدوران، مما يتيح لك التوجيه أثناء الكبح بقوة."},"40":{"q":"أنا أُجري فحص الصباح ما قبل الرحلة وألاحظ أن خزانات الهواء في قاطرتي جمّعت مزيجاً من الماء وطبقة من زيت الضاغط في القاع. إنه صباح شتوي بارد في بانهاندل. للحفاظ على عمل نظام الفرامل الهوائية بأمان ومنع التجمّد، ماذا ينبغي أن أفعل حيال هذا التراكم؟","options":["اتركه وشأنه، لأن مُجفّف الهواء وحرارة الفرامل ستحرق الماء والزيت أثناء الرحلة","املأ الخزانات بزيت ضاغط إضافي كي تبقى الرطوبة معلّقة ولا تتمكّن من التجمّد","صرّف خزانات الهواء يومياً باستخدام صمامات التصريف كي لا يُتلف الماء والزيت النظام أو يتجمّدا","صرّف الخزانات مرة واحدة في الأسبوع فقط، لأن الصمامات التلقائية الحديثة تتولّى الباقي بنفسها"],"explanation":"صرّف خزانات الهواء يومياً باستخدام صمامات التصريف كي لا يُتلف الماء والزيت المتجمّعان النظام أو يتجمّدا."},"41":{"q":"أثناء فحص ما قبل الرحلة، أوقفت المحرّك لإجراء اختبار تسرّب الهواء وألاحظ أن مقياس الهواء يتوقّف عن الارتفاع تماماً بينما المحرّك متوقّف. يُصرّ مبتدئ بجانبي على أن الضاغط ينبغي أن يستمر في بناء الضغط من تلقاء نفسه. أيُّ عبارة تشرح بشكل صحيح لماذا توقّف الضغط عن الارتفاع بمجرد إيقافي للمحرّك؟","options":["المنظّم يضخّ خزانات الهواء ميكانيكياً ويعمل فقط بينما تتحرّك الشاحنة إلى الأمام","زنبرك فرامل الانتظار هو ما يشحن نظام الهواء، فيتوقّف بمجرد تفعيل الفرامل","دوران عجلات المقطورة يُدير الضاغط، فيبني الضغط فقط أثناء الحركة","الضاغط يُشغّله المحرّك (بحزام أو مباشرة)، فلا يُضخّ هواء بمجرد إيقاف المحرّك"],"explanation":"يُشغّل المحرّك ضاغط الهواء، فلا يضخّ هواءً بمجرد إيقاف المحرّك."},"42":{"q":"إنه أقلّ بكثير من درجة التجمّد في صباح شتوي وأنا أُجري فحص ما قبل الرحلة على قاطرة مزوّدة بمُجفّف هواء. أريد أن أفهم مما يحميني هذا الجهاز بينما يضخّ الضاغط الهواء في النظام. ما هو العمل الرئيسي لمُجفّف الهواء في هذه الحالة؟","options":["يسحب بخار الماء (وقليلاً من الزيت) من الهواء المضغوط قبل أن يصل إلى الخزانات، فتتجمّع رطوبة أقلّ ولا تُجمّد النظام","يُشير إلى الضاغط ليتوقّف عن الضخّ بمجرد ارتفاع ضغط الخزان إلى نقطة الفصل قرب 125 psi","يُنفّس خزانات الهواء تلقائياً إذا ارتفع الضغط فوق إعداد تخفيف الأمان البالغ نحو 150 psi","يحقن كمية محسوبة من الكحول في الخطوط لمنع صمامات الفرامل من التجمّد في الطقس البارد"],"explanation":"يُزيل مُجفّف الهواء بخار الماء وبعض الزيت من الهواء المضغوط قبل أن يصل إلى الخزانات، مما يُقلّل الرطوبة التي قد تتجمّد وتُعطّل الفرامل."},"43":{"q":"أثناء فحص ما قبل الرحلة، أتسلّق أسفل المقطورة لفحص الفرامل الأساسية. عند كل عجلة أجد أسطوانة فرامل، وأحذية فرامل ببطانات، ومُعدّل خلوص متّصلاً بقضيب دفع يُدير جزءاً على شكل حرف 'S' لدفع الأحذية بعيداً. بناءً على ما أنظر إليه، أيُّ نوع من الفرامل الأساسية مزوّدة به هذه المركبة — النوع الموجود في معظم المركبات الثقيلة ذات الفرامل الهوائية؟","options":["فرامل القرص الهوائية، حيث يضغط فكّ على دوّار — التصميم الأكثر شيوعاً على الشاحنات الثقيلة","فرامل الأسطوانة بكامة S، الفرامل الأساسية الأكثر شيوعاً على المركبات الثقيلة ذات الفرامل الهوائية","فرامل الأسطوانة الإسفينية، حيث يدفع إسفين الأحذية بعيداً عبر غرفة واحدة","فرامل القرص الهيدروليكية، مثل تلك الموجودة في سيارة الركّاب لكن بحجم أكبر للمقطورة"],"explanation":"فرامل الأسطوانة بكامة S هي الفرامل الأساسية الأكثر شيوعاً على المركبات الثقيلة ذات الفرامل الهوائية، وتُعرف بالكامة على شكل حرف S التي يُديرها قضيب الدفع لتفريق الأحذية."},"44":{"q":"عندما تضغط على دواسة الفرامل بقوة أكبر، تصبح الفرامل:","options":["أضعف","تحصل على هواء وقوة أكبر","تتحرّر تماماً","تنطفئ"],"explanation":"يُرسل صمام القدم (الدواسة) ضغط هواء أكبر لقوة كبح أكبر."},"45":{"q":"أنا أقود قاطرة مقطورة محمّلة بفرامل هوائية عندما تتوقّف سيارة فجأة أمامي. في اللحظة التي تضغط فيها قدمي بالكامل على دواسة الفرامل، يكون هناك تأخّر قصير قبل أن تبدأ الشاحنة فعلاً في التباطؤ. يُسمّي مدرّبي هذا 'تأخّر الفرامل'. ما الذي يحدث فيزيائياً أثناء ذلك التأخّر؟","options":["دماغي وجسدي لا يزالان يعالجان الخطر قبل أن تصل قدمي إلى الدواسة","ضاغط الهواء يبني ضغطاً إضافياً في الخزانات لتلبية الطلب","الهواء المضغوط ينتقل عبر خطوط الفرامل قبل أن يتمكّن من تفعيل الفرامل","المركبة تقطع مسافة الإدراك قبل أي إدخال للكبح"],"explanation":"بعد الضغط على الدواسة يستغرق الأمر نحو نصف ثانية كي ينتقل الهواء المضغوط عبر خطوط الفرامل ويُفعّل الفرامل فعلاً عند كل عجلة."},"46":{"q":"أنا أدرس مسافة التوقّف الكلية من أجل اعتماد الفرامل الهوائية في رخصة CDL. أعلم أنه مع الفرامل الهيدروليكية للسيارة، مسافة التوقّف الكلية هي مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الكبح. يقول مدرّبي إن الفرامل الهوائية تضيف عنصراً واحداً إضافياً إلى ذلك المجموع. أي عنصر يضيفه نظام الفرامل الهوائية ولا تملكه الفرامل الهيدروليكية؟","options":["مسافة رد فعل إضافية، لأن دواسات الفرامل الهوائية أثقل وأبطأ في الضغط من الدواسات الهيدروليكية","مسافة إدراك إضافية، لأن مركبات الفرامل الهوائية الأكبر تجلس أعلى وتستغرق وقتاً أطول للحكم على الأخطار","مسافة كبح فعلية أطول، لأن مركبات الفرامل الهوائية أثقل وتحتاج إلى مساحة أكبر للتوقّف","مسافة تأخّر الفرامل، المسافة المقطوعة بينما ينتقل الهواء عبر الخطوط قبل أن تُمسك الفرامل"],"explanation":"تضيف الفرامل الهوائية عنصر توقّف رابعاً، مسافة تأخّر الفرامل، التي تغطّي نصف الثانية تقريباً التي يستغرقها الهواء للانتقال عبر الخطوط قبل أن تُمسك الفرامل."},"47":{"q":"لقد أنهيت فحص ما قبل الرحلة ونظام الهواء مشحون بالكامل. تريد الآن التحقّق من أن فرامل الخدمة توقف الشاحنة فعلاً وأن لا شيء يجرّ أو يسحب. أيٌّ مما يلي هو الطريقة الصحيحة لأداء فحص توقّف فرامل الخدمة؟","options":["حرّر فرامل الانتظار، ودع الشاحنة تزحف إلى الأمام حتى نحو 5 mph، ثم اضغط بثبات على دواسة الفرامل واشعر هل تتوقّف فوراً وباستقامة","أبقِ الشاحنة ثابتة، واضغط على دواسة الفرامل بقوة، وراقب مقياس الهواء للتأكّد من أن الضغط لا يهبط أكثر من 3 psi في دقيقة واحدة","أثناء التوقّف، اسحب وحرّر مقبض فرامل الانتظار الأصفر عدّة مرات للتأكّد من أن فرامل الزنبرك تُفعّل وتتحرّر","قُد حتى نحو 20 mph، ثم أجرِ توقّفاً قوياً وتحقّق من أن العجلات تنغلق بالتساوي على الجانبين"],"explanation":"يُجرى اختبار توقّف فرامل الخدمة أثناء الحركة: دع المركبة تزحف حتى نحو 5 mph، ثم اضغط على الفرامل بثبات واشعر بأنها تتوقّف فوراً دون السحب إلى جانب واحد."},"48":{"q":"أثناء فحص ما قبل الرحلة، يخبرني مدرّب CDL أن أمسك أحد مُعدّلات الفرامل وأسحبه باليد للتحقّق من مدى تحرّك قضيب الدفع قبل أن تنخرط الفرامل. يقول إنه إذا كان هناك خلوص حرّ مفرط هنا، فستنخفض قوة الكبح لديّ. ما المكوّن الذي أفحصه فعلاً عندما أفعل هذا؟","options":["منظّم ضاغط الهواء، الذي يقرّر متى يتوقّف النظام عن ضخّ الهواء ويستأنفه","مُعدّل الخلوص، الذي يحدّد مدى تحرّك قضيب دفع الفرامل قبل أن تُفعّل الفرامل","صمام تخفيف الأمان، الذي يفتح لتحرير الضغط إذا شُحنت الخزانات بإفراط","صمام التحكّم التضميني، الذي يتيح لي تفعيل فرامل الزنبرك تدريجياً في حالة طوارئ"],"explanation":"يحدّد مُعدّل الخلوص مدى تحرّك قضيب دفع الفرامل قبل أن تُفعّل الفرامل، والخلوص الحرّ المفرط — الفرامل غير المضبوطة — هو أكثر عيوب الفرامل الهوائية شيوعاً."},"49":{"q":"أثناء فحص ما قبل الرحلة في طقس متجمّد، ألاحظ أن خزانات الهواء في شاحنتي تطرد الماء والزيت المتجمّعين من تلقاء نفسها، دون أن أحتاج إلى فتح أي شيء باليد. تقول الورشة إن هذا الخزان مزوّد بحيث يحدث التصريف من تلقاء نفسه للمساعدة في منع التجمّد. أي جهاز يقوم بهذا العمل؟","options":["صمام تتابع، يُسرّع إشارة الهواء إلى الفرامل الخلفية لكنه أيضاً ينزح الرطوبة من الخزان من تلقاء نفسه","صمام تصريف يدوي، يتيح للماء والزيت المتجمّعين بالخروج تلقائياً بمجرد أن يصبح ضغط الخزان مرتفعاً بما يكفي","صمام تصريف تلقائي، يطرد الماء وزيت الضاغط من الخزان دون أن يُصرّفه أحد باليد","صمام تخفيف الأمان، الذي يفتح قرب 150 psi ويُزيل الماء والزيت المتراكمين من خزان الإمداد أثناء تنفيسه"],"explanation":"يطرد صمام التصريف التلقائي الماء وزيت الضاغط المتجمّعين من الخزان من تلقاء نفسه، دون تصريف يدوي، مما يساعد على منع التجمّد في الطقس البارد."},"50":{"q":"أثناء فحص ما قبل الرحلة على مركبة تجميعية أحدث، ألاحظ أن مقياس ضغط الهواء يحتوي على إبرتين بدلاً من واحدة، والشاحنة لا تتيح لي بناء الضغط بشكل طبيعي حتى ترتفع القراءتان معاً. يقول مدرّبي إن هذه الشاحنة لديها نظام فرامل هوائية مزدوج. أيُّ عبارة تصف بشكل صحيح كيف بُني هذا النظام المزدوج فعلاً؟","options":["هو نظام هوائي واحد كبير يُغذّيه خزان واحد، مع إبرة المقياس الثانية تُظهر ضغط المقطورة فقط كقراءة مجاملة.","يجمع فرامل الخدمة والانتظار والطوارئ في خطّ هوائي مشترك واحد فتعمل الثلاثة جميعاً من مصدر ضغط واحد.","هو نظام هوائي واحد بضاغط احتياطي يشتغل فقط بعد أن يتعطّل الضاغط الأساسي تماماً.","هما نظامان هوائيان منفصلان تماماً، أساسي وثانوي، يتحكّم فيهما طقم واحد من أدوات التحكّم بالفرامل لمزيد من الأمان."],"explanation":"نظام الفرامل الهوائية المزدوج هو نظامان هوائيان منفصلان تماماً، أساسي وثانوي، لكلٍّ منهما خزاناته وخطوطه الخاصة لكن يُشغّلهما طقم واحد من أدوات التحكّم لأمان احتياطي."},"51":{"q":"أقود شاحنة بمقطورة مزودة بنظام فرامل هوائية مزدوج عندما ينشط فجأة تحذير انخفاض ضغط الهواء للدائرة الأساسية فقط، وتنخفض إبرة عداد ذلك الجانب نحو الصفر. أما عداد النظام الثانوي فلا يزال يقرأ ضمن النطاق الطبيعي. أي عبارة تصف على أفضل وجه ما ينبغي أن أتوقعه وأفعله؟","options":["سيظل النظام الثانوي يشغّل الفرامل، لذا ينبغي أن أفرمل للتوقف بأمان مع إتاحة مسافة توقف أطول، ثم أصلح الشاحنة.","بما أن كلتا الدائرتين تتشاركان مجموعة تحكم واحدة، فإن النظام الثانوي يتعطل مع الأساسي، فلا يبقى لديّ أي قدرة على الفرملة وعليّ أن أتركها تنزلق حتى التوقف.","ينبغي أن أضغط على دواسة الفرامل بسرعة لإجبار الدائرة العاملة على إرسال الهواء إلى جميع العجلات واستعادة الضغط الكامل للجانب المعطل.","ستقفل فرامل النوابض جميع العجلات فوراً لحظة تعطّل إحدى الدائرتين، لذا عليّ أن أستعد لتوقف مفاجئ وعنيف."],"explanation":"إذا تعطلت إحدى دائرتي نظام الفرامل الهوائية المزدوج، فإن الأخرى تظل تشغّل الفرامل، لذا افرمل للتوقف بشكل متحكَّم به مع إتاحة مسافة توقف أطول، ثم أصلحها."},"52":{"q":"أقوم بفحص ما قبل الرحلة لشاحنتي ذات المقطورة والمحرك مطفأ. وبينما يتسرب الهواء من النظام ببطء، أراقب العداد ينخفض دون 60 psi، ثم يستمر في الهبوط نحو 30 psi. وفجأة تنطبق فرامل النوابض (الانتظار) من تلقاء نفسها، رغم أنني لم ألمس أداة التحكم بالانتظار. أي عبارة تفسّر على أفضل وجه سبب بقاء فرامل النوابض محرَّرة حتى تلك اللحظة؟","options":["كانت ممسوكة ميكانيكياً بواسطة مُعدِّلات الخلوص حتى نفد شوط قضيب الدفع","كان ضغط الهواء يبقي النوابض القوية مضغوطة، وفقدان ذلك الضغط جعل النوابض تطبّق الفرامل","كانت مقفولة في وضع مفتوح بواسطة أداة تحكم الانتظار الصفراء المعيّنة الشكل حتى حررها جرس انخفاض الهواء","كانت دواسة فرامل الخدمة تبقيها محرَّرة، ولم تنطبق إلا عندما تلاشى ضغط الدواسة"],"explanation":"يبقي ضغط الهواء فرامل النوابض القوية في وضع التحرير، لذا عندما ينخفض الضغط دون نطاق 20-45 psi تطبّق النوابض الفرامل تلقائياً."},"53":{"q":"أثناء فحص ما قبل الرحلة، لا تتحرر فرامل النوابض وأشتبه في وجود عطل ميكانيكي في حجرة فرامل النوابض. يناولني زميل أداة ويقول إنه يمكن \"حبس\" النوابض القوية (ضغطها) يدوياً كي أتمكن من نقل الشاحنة إلى الورشة. لم أتلقَّ قط تدريباً على هذا الإجراء. ما هو الإجراء الصحيح؟","options":["أحبس النوابض بنفسي هذه المرة فقط، بما أن الشاحنة تحتاج فقط إلى التدحرج لمسافة قصيرة حتى الورشة","أحرر النوابض وأعيد تطبيقها يدوياً مراراً لتحرير الحجرة العالقة تدريجياً","أترك النوابض وشأنها ولا أحاول حبسها، لأن حبس هذه النوابض القوية يجب أن يقوم به أفراد مدرَّبون فقط","أطلي حجرات فرامل النوابض بلون زاهٍ أولاً كي تكون النوابض القوية سهلة الرؤية أثناء حبسها"],"explanation":"حبس فرامل النوابض خطير لأن النوابض تخزّن قوة هائلة، لذا يجب أن يُترك لأفراد مدرَّبين."},"54":{"q":"أنهيت فحص ما قبل الرحلة وأنا أؤدّي فحوص الفرامل الهوائية قبل الانطلاق من الساحة. مع تشغيل المحرك وبناء ضغط الهواء بالكامل، أضبط فرملة الانتظار بسحب المقبض الأصفر المعيّن الشكل. الآن أريد التأكد من أن فرامل النوابض ستثبّت المركبة فعلاً في مكانها. أي إجراء يختبر ذلك بشكل صحيح؟","options":["حرر فرملة الانتظار واضغط على فرملة القدم بقوة لتحسّ بدواسة ثابتة","حرّك دواسة الفرامل عدة مرات وراقب عداد الهواء بحثاً عن أي انخفاض في الضغط","ارفع دوران المحرك واستمع إلى فرامل النوابض وهي تتحرر عند نحو 20-45 psi","اترك فرملة الانتظار مضبوطة، حرر القابض، واسحب للأمام بلطف ضدها"],"explanation":"للتحقق من فرامل الانتظار (النوابض)، أبقها مضبوطة واسحب للأمام بلطف في ترس منخفض للتأكد من أنها تثبّت المركبة."},"55":{"q":"أنقل مركبة مركّبة محمَّلة نزولاً على منحدر جبلي طويل وشديد، وأنا قلق بشأن الحفاظ على السيطرة على فراملي الهوائية. أي أسلوب ينبغي أن أستخدمه لإدارة سرعتي بأمان طوال الطريق حتى الأسفل؟","options":["أختار ترساً منخفضاً قبل النزول وأستخدم ضغط فرملة خفيفاً وثابتاً، مخفِّفاً بمجرد أن أنخفض نحو 5 mph دون سرعتي الآمنة","أطبّق ضغط فرملة قوياً ومستمراً طوال الطريق نزولاً لإبقاء سرعتي ثابتة منخفضة وتحت السيطرة","أضغط دواسة الفرامل وأرفعها في دفعات متكررة كي تحظى الفرامل بفرصة للتبريد بين التطبيقات","أنقل إلى الوضع المحايد لتوفير المحرك وأترك الفرامل تقوم بكل التبطيء حسب الحاجة في طريق النزول"],"explanation":"على المنحدر، اختر ترساً منخفضاً واستخدم ضغط فرملة خفيفاً وثابتاً، وحرر بمجرد أن تبطئ نحو 5 mph دون سرعتك الآمنة."},"56":{"q":"أسير على طريق سريع في تكساس بشاحنتي ذات الفرامل الهوائية بسرعة عادية وأضغط بقوة على دواسة القدم (صمام الدواسة) للتباطؤ بسبب حركة المرور. أي نظام فرملة أطبّقه بتلك الدواسة؟","options":["فرامل الانتظار، التي يبقيها الهواء مفتوحة وتُضبط بالمقبض الأصفر","فرامل الخدمة، التي أستخدمها لكل تباطؤ وتوقف عادي","فرامل الطوارئ، التي تنطبق تلقائياً عندما ينخفض ضغط الهواء","فرامل المقطورة فقط، التي يتم التحكم بها بشكل منفصل عبر صمام اليد للمقطورة"],"explanation":"تشغّل دواسة القدم (صمام الدواسة) فرامل الخدمة، التي تُستخدم لكل تباطؤ وتوقف عادي."},"57":{"q":"أثناء فحص ما قبل الرحلة أفحص طبول وأقراص الفرامل في جرّاري. أي حالة تعني أن الطبل أو القرص خطير ويجب عدم قيادة المركبة حتى يتم إصلاحه؟","options":["الطبل بارد عند اللمس وخالٍ من أي طبقة زيت","يوجد طبقة خفيفة من غبار الطريق على السطح الخارجي","الطبل به شق مرئي أو السطح متآكل بشدة","الطبل يُظهر طلاءً جديداً من خدمة ورشة حديثة"],"explanation":"طبل الفرامل المشقوق أو المتآكل بشدة قد يفشل تحت الحرارة والحمل، لذا يجب إخراج المركبة من الخدمة حتى يتم إصلاحها."},"58":{"q":"أثناء فحص ما قبل الرحلة، تشحن نظام الهواء لديك إلى نحو 125 psi، وتطفئ المحرك، وتراقب عداد لوحة القيادة. ومع تحرير الفرامل، تستمر الإبرة في الهبوط متجاوزة معدل التسرّب المسموح به دون أي مؤشر على التوقف. ولم يضِئ تحذير انخفاض الهواء بعد. ما هو الإجراء الصحيح؟","options":["شغّل المحرك وقُد بشكل طبيعي، بما أن مصباح التحذير والجرس لم يعملا بعد","اضغط دواسة الفرامل بضع مرات لإعادة إغلاق الصمامات، ثم تابع مسارك كما هو مخطط","قُد مباشرة إلى أقرب ورشة إصلاح طالما بقي الضغط فوق 60 psi","أخرج المركبة من الخدمة وأصلح التسرّب قبل القيادة إلى أي مكان"],"explanation":"التسرّب المستمر للهواء بمعدل يتجاوز المسموح به قد يستنزف الخزانات ويعطّل الفرامل، لذا يجب إخراج المركبة من الخدمة حتى يتم إصلاحها."},"59":{"q":"أسير على الطريق السريع بشاحنتي ذات المقطورة عندما يضيء مصباح عطل نظام ABS الأصفر على لوحة القيادة ويبقى مضاءً. لا تزال الشاحنة تفرمل وتنعطف بشكل طبيعي. بناءً على ما يخبرني به هذا المصباح، أي عبارة هي الأدق؟","options":["قد لا يعمل نظامي المانع للانغلاق، لكن فرامل الخدمة العادية لا تزال تعمل وعليّ أن أفحص نظام ABS.","فرامل الخدمة لديّ تعطلت بالفعل، لذا يجب أن أتوقف على الجانب وأضبط فرملة الانتظار فوراً.","نظام ABS لديّ مفعّل بالكامل ويعمل بنشاط على تقصير مسافة التوقف على هذا المقطع من الطريق.","انخفض ضغط الهواء لديّ دون 60 psi وفرامل النوابض على وشك إقفال العجلات."],"explanation":"إضاءة مصباح ABS الأصفر تعني أن الوظيفة المانعة للانغلاق فقط قد تكون معطلة؛ أما فرامل الخدمة العادية فلا تزال تعمل وينبغي فحص نظام ABS."},"60":{"q":"أنقل مركبة مركّبة محمَّلة على مسار طويل، وأبقي عيني على عدادات لوحة القيادة. للتأكد من أن فراملي الهوائية ستنطبق وتتحرر فعلاً في كل مرة أضغط فيها على الدواسة، أي شرط واحد يجب أن أبقي عليه طوال الرحلة؟","options":["خزان وقود ممتلئ، بما أن الفرامل تستمد قوتها مباشرة من إمداد وقود المحرك","ضغط هواء كافٍ في النظام، بما أن الهواء هو ما يطبّق الفرامل ويحررها","ضبط المصابيح الأمامية على الإضاءة المنخفضة، كي تتمكن مستشعرات تحذير الفرامل من قراءة العدادات في وضح النهار","راكب واحد على الأقل على متن المركبة للتأكد من أن مصابيح الفرامل تعمل عند كل توقف"],"explanation":"يحتاج نظام الفرامل الهوائية إلى ضغط هواء كافٍ لأن الهواء المضغوط هو ما يطبّق الفرامل ويحررها."},"61":{"q":"أثناء فحص ما قبل الرحلة، أترك نظام الهواء يشحن حتى نقطة قطع المنظِّم، ثم أشغّل المحرك بسرعة الدوران التشغيلية وأراقب العداد يرتفع من 85 إلى 100 psi. أي من الملاحظات التالية تخبرني بأن ضاغط الهواء سليم وأن معدل البناء مقبول؟","options":["يستغرق العداد عدة دقائق طويلة ليزحف من 85 إلى 100 psi، لكنه يصلها في النهاية","لا يتحرك الضغط على الإطلاق لأن المنظِّم قد قطع الضاغط بالفعل","يرتفع العداد من 85 إلى 100 psi خلال نحو 45 ثانية، أي في غضون ثوانٍ لا دقائق","يقفز الضغط من 85 إلى 100 psi فوراً لحظة ضغطي على دواسة الوقود"],"explanation":"في نظام الفرامل الهوائية المزدوج، ينبغي أن يبني الضغط من 85 إلى 100 psi خلال نحو 45 ثانية، مما يدل على أن الضاغط سليم ويستعيد الهواء بسرعة."},"62":{"q":"أثناء فحص ما قبل الرحلة، أزحف تحت المقطورة وألاحظ أن بطانات الفرامل في إحدى العجلات قد تآكلت حتى أصبحت رقيقة جداً وشبه مستوية مع المسامير. وكل شيء آخر في نظام الفرامل سليم. أي من التالي هو الإجراء الصحيح قبل أن آخذ هذه المركبة على الطريق؟","options":["اترك البطانات كما هي، بما أن شوط قضيب الدفع ومُعدِّلات الخلوص لا تزال ضمن الحد القانوني عند الاختبار","ضع طبقة خفيفة من سائل الفرامل على البطانات الرقيقة لتقليل الصرير حتى أصل إلى الورشة التالية","دوّنها في تقرير الفحص لكن تابع القيادة، طالما بقي تحذير انخفاض الهواء فوق 60 psi","أخرج المركبة من الخدمة واستبدل البطانات المتآكلة بأخرى جديدة قبل القيادة"],"explanation":"بطانات الفرامل المتآكلة حتى أصبحت رقيقة جداً لم تعد قادرة على توليد احتكاك كافٍ، لذا يجب استبدالها قبل قيادة المركبة."},"63":{"q":"أنقل مقطورة محمَّلة نزولاً على منحدر جبلي طويل. للحفاظ على سرعتي تحت السيطرة، أستمر في الضغط على دواسة الفرامل وتحريرها مراراً وتكراراً (\"تحريك\" الفرامل). يحذّرني مدرّبي من التوقف عن فعل ذلك. أي من التالي هو السبب الرئيسي لخطورة التحريك على منحدر طويل؟","options":["قد يستهلك الهواء أسرع مما يستطيع الضاغط إعادة بنائه، مما يستنزف الإمداد","يبرّد طبول الفرامل بسرعة كبيرة وقد يشقّ البطانات بسبب الصدمة الحرارية","يدفع هواءً إضافياً إلى خزان إمداد المقطورة ويُحمِّل صمام التنفيس زيادة","يجعل مُعدِّلات الخلوص تشدّ بحيث يصبح شوط قضيب الدفع قصيراً جداً"],"explanation":"تحريك الفرامل المتكرر يطلق هواءً مع كل تطبيق أسرع مما يستطيع الضاغط إعادة بنائه، مما يستنزف إمداد الهواء."},"64":{"q":"انتقلت للتو من قيادة سيارة إلى شاحنة بمقطورة مزودة بنظام فرامل هوائية. عندما أضغط على دواسة الفرامل، أحاول أن أتخيل ما الذي ينتقل فعلاً عبر الخطوط ليدفع أحذية الفرامل ضد الطبول ويبطئ القاطرة. في نظام الفرامل الهوائية هذا، تُنقل القوة التي أولّدها عند الدواسة إلى العجلات بأي وسيط؟","options":["سائل فرامل هيدروليكي مضغوط يُدفع من أسطوانة رئيسية، تماماً كما في سيارتي","هواء مضغوط مخزَّن في الخزانات ويُطلق عبر خطوط الفرامل إلى الحجرات","كابل فولاذي ثقيل ووصلة ميكانيكية مشدودة من الدواسة إلى كل عجلة","تيار كهربائي يُرسل عبر سلك يشحن مغناطيس فرامل عند كل عجلة"],"explanation":"تنقل الفرامل الهوائية القوة باستخدام هواء مضغوط مخزَّن في الخزانات ويُطلق عبر خطوط الفرامل إلى الحجرات."},"65":{"q":"أقود شاحنة محمَّلة بفرامل هوائية عندما ينفجر خط وينخفض ضغط الهواء لديّ حتى الصفر. يسألني متدرب يركب معي لماذا يُعتبر هذا التصميم أكثر أماناً من الفرامل الهيدروليكية في شاحنته الصغيرة. أي عبارة تفسّر على أفضل وجه الميزة الأمنية الحقيقية لنظام فراملي الهوائية في هذا الموقف بالذات؟","options":["لأن الهواء هو السائل، ستظل فرامل الخدمة لديّ تعمل بشكل طبيعي حتى بعد تسرّب كل الهواء من النظام.","جرس تحذير انخفاض ضغط الهواء هو ما يوقف الشاحنة فعلياً بمجرد أن ينخفض الضغط دون 60 psi.","مع هبوط ضغط الهواء إلى نطاق 20 إلى 45 psi، تنطبق فرامل النوابض (الطوارئ) تلقائياً وتوقف الشاحنة.","الفرامل الهوائية مصممة لتوقف دائماً شاحنة محمَّلة في مسافة أقصر من الفرامل الهيدروليكية بغض النظر عن أي تسرّب."],"explanation":"عندما ينخفض ضغط الهواء إلى نطاق 20 إلى 45 psi، تنطبق فرامل النوابض (الطوارئ) تلقائياً وتوقف المركبة."},"66":{"q":"أسير على الطريق السريع في شاحنة بمقطورة محمَّلة عندما ينفجر خط وينفد ضغط الهواء لديّ تماماً. ومع إفراغ النظام، ماذا سيحدث لفرامل النوابض لديّ؟","options":["لا يحدث لها شيء، لأن فرامل النوابض تعمل فقط كفرامل خدمة عندما أضغط على الدواسة","تبقى محرَّرة، لأن النوابض القوية تحتاج إلى ضغط هواء مخزَّن لإبقائها مطبَّقة","تتحرر بالكامل، لأن فقدان الهواء هو بالضبط ما يحرر النوابض ليتدحرج القاطرة","تنطبق تلقائياً، لأن النوابض تطبّق الفرامل بمجرد زوال الهواء الذي كان يبقيها مفتوحة"],"explanation":"تبقى فرامل النوابض مفتوحة بضغط الهواء، لذا عند فقدان ذلك الهواء تطبّق النوابض الفرامل تلقائياً كإجراء أمان احتياطي."},"67":{"q":"أقوم بفحص الفرامل مع إطفاء المحرك ونظام مشحون بالكامل. أستمر في الضغط على دواسة الفرامل وتحريرها لتفريغ الهواء من الخزانات، مراقباً عداد الهواء يهبط. ومع استمرار هبوط الإبرة، عند أي ضغط تقريباً ينبغي أن أتوقع أن يُغلق صمام حماية الجرّار تلقائياً ويُقطع إمداد هواء المقطورة؟","options":["بين نحو 20 و45 psi، مع هبوط الضغط إلى النطاق المنخفض","بين نحو 60 و80 psi، تماماً عندما يكون تحذير انخفاض الهواء نشطاً","بين نحو 100 و125 psi، قرب نطاق التشغيل الطبيعي للمنظِّم","بين نحو 5 و10 psi، فقط بعد أن يقرأ العداد قرب الفارغ"],"explanation":"يُغلق صمام حماية الجرّار وإمداد هواء المقطورة تلقائياً عندما ينخفض ضغط هواء النظام إلى نطاق 20 إلى 45 psi."},"68":{"q":"أنا موصول بمقطورة محمَّلة وأنهي فحص ما قبل الرحلة داخل المقصورة. لشحن نظام هواء المقطورة وتحرير فراملها قبل الانطلاق، أحتاج إلى دفع أداة تحكم واحدة محددة على لوحة القيادة. أي لون وشكل مقبض يحدد المقبض الذي يجب أن أدفعه لإمداد المقطورة بالهواء؟","options":["المقبض الأصفر المعيّن الشكل، لأن تلك الأداة تغذّي الهواء إلى فرامل المقطورة","المقبض الأحمر ثماني الأضلاع (المثمَّن)، لأن ذلك هو أداة تحكم إمداد هواء المقطورة","المقبض الأزرق المستدير، لأن خط الخدمة إلى المقطورة مرمَّز باللون الأزرق","المقبض الأصفر ثماني الأضلاع (المثمَّن)، لأن إمداد المقطورة يطابق شكل أداة تحكم الانتظار"],"explanation":"أداة تحكم إمداد هواء المقطورة هي المقبض الأحمر ثماني الأضلاع (المثمَّن) الذي يشحن نظام هواء المقطورة ويحرر فراملها."},"69":{"q":"أنهيت ركن شاحنتي ذات المقطورة في محطة استراحة وأنا على وشك إيقاف التشغيل. لضبط فرامل الانتظار (النوابض) كي تبقى القاطرة ثابتة في مكانها، أي أداة تحكم في لوحة القيادة أحتاج إلى سحبها للخارج؟","options":["الزر الأزرق المستدير الذي يحرر ضغط فرامل الخدمة","المقبض الأحمر ثماني الأضلاع (المثمَّن) بجوار عدادات لوحة القيادة","المقبض الأصفر المعيّن الشكل على لوحة التحكم","الذراع المربعة الخضراء بجوار صمام اليد للمقطورة"],"explanation":"أداة تحكم فرملة الانتظار (النوابض) هي المقبض الأصفر المعيّن الشكل، يُسحب للخارج للتطبيق ويُدفع للداخل لتحرير فرامل النوابض."},"70":{"q":"أثناء فحص ما قبل الرحلة، يتوقف المحرك ويتوقف الضاغط عن الدوران، ومع ذلك ألاحظ أن خزان الإمداد يحتفظ بضغطه بدلاً من أن يتسرب عائداً نحو الضاغط المتوقف. أي مكوّن مسؤول عن هذا السلوك؟","options":["صمام تنفيس الأمان، الذي يحبس هواء الخزان كلما استشعر أن الضاغط قد توقف","المنظِّم، الذي يعزل خزان الإمداد بمجرد بلوغه إعداد ضغط القطع","صمام التصريف الأوتوماتيكي، الذي يُغلق بإحكام لحبس الهواء المخزَّن داخل الخزان","صمام الفحص أحادي الاتجاه، الذي يمنع الهواء من التدفق عائداً نحو الضاغط المتوقف"],"explanation":"يسمح صمام الفحص أحادي الاتجاه للهواء بالتدفق إلى الخزان فقط، لذا يمنع الهواء المخزَّن من التسرّب عائداً عند توقف الضاغط."},"71":{"q":"إنه صباح يناير شديد البرودة في أماريلو، ويخبرني المرسِل أن جرّاري مزود بمبخِّر كحول في نظام الفرامل الهوائية. وأثناء فحص ما قبل الرحلة، يُسألني عما يفعله هذا الجهاز فعلاً لي في هذه الظروف. أي عبارة تفسّر على أفضل وجه الغرض منه؟","options":["يضخّ الكحول إلى نظام الهواء لتقليل احتمال تكوّن الجليد في الخطوط والصمامات أثناء الطقس البارد","يحرق الكحول لتدفئة طبول الفرامل كي لا تتجمد فرامل الانتظار في الطقس البارد","يضيف الكحول إلى الهواء لامتصاص الرطوبة كي لا أعود بحاجة إلى تصريف خزانات الهواء يومياً","يطلق بخار الكحول الذي يعزّز إنتاج ضاغط الهواء كي يبني الضغط أسرع في البرد"],"explanation":"يضخّ مبخِّر الكحول الكحول إلى نظام الهواء لتقليل احتمال تكوّن الجليد في الخطوط والصمامات أثناء الطقس البارد."},"72":{"q":"أثناء فحص ما قبل الرحلة، أتتبع مجموعة الفرامل الأساسية عند إحدى عجلات جرّاري ذي الفرامل الهوائية. ومع تطبيق الفرامل، أراقب مُعدِّل الخلوص يدير عموداً يدير حدبة على شكل حرف S، التي تدفع أحذية الفرامل وبطاناتها للخارج ضد داخل الطبل. وبينما أؤكد وجود وعمل كل جزء، أي من التالي ينبغي ألا أتوقع العثور عليه في أي مكان في هذه الفرملة الأساسية ذات حدبة S؟","options":["مُعدِّل الخلوص الذي يحوّل شوط قضيب الدفع إلى دوران حدبة الفرامل","أسطوانة هيدروليكية رئيسية تضغط السائل لدفع الأحذية للخارج","طبل الفرامل الذي تضغط الأحذية ضده لتوليد احتكاك التوقف","أحذية الفرامل وبطاناتها التي تُدفع ضد الطبل عند الفرملة"],"explanation":"الفرملة الأساسية الهوائية ذات حدبة S ميكانيكية-هوائية بحتة بلا سائل، لذا لا تحتوي على أسطوانة هيدروليكية رئيسية."},"73":{"q":"أنقل مقطورة محمَّلة نزولاً على منحدر طويل وشديد عندما تتلاشى فرامل الخدمة لديّ وتصبح الدواسة طرية. قاطرتي مزودة بصمام تحكم تعديلي. في هذا الموقف، ماذا يتيح لي ذلك الصمام أن أفعل فعلاً؟","options":["أضغط فرامل الخدمة مراراً لإعادة بناء ضغط الهواء في الخطوط قبل أن تفشل تماماً","أتجاوز المنظِّم كي يقطع الضاغط عند أعلى من 125 psi ويستعيد قوة فرملتي","أطبّق فرامل النوابض (الطوارئ) تدريجياً بمقبض التحكم بدلاً من أن تطبّق دفعة واحدة","أطفئ نظام ABS كي تتمكن العجلات من الانغلاق وكشط السرعة أسرع على المنحدر"],"explanation":"يتيح صمام التحكم التعديلي تطبيق فرامل النوابض (الطوارئ) تدريجياً بمقبض التحكم لتوقف متحكَّم به إذا فشلت فرامل الخدمة."},"74":{"q":"أقود شاحنة مستقيمة محمَّلة عندما ألاحظ أن مصباح تحذير انخفاض الهواء لديّ يضيء ويصدر الجرس صوتاً. أظهر فحص ما قبل الرحلة في وقت سابق تسرّباً صغيراً للهواء اعتبرته طفيفاً. مقارنة بكيفية تصرّف نظام فرامل هيدروليكي مع تسرّب صغير مماثل، ماذا ينبغي أن أتوقع من فراملي الهوائية الآن؟","options":["ستفشل الفرامل تماماً لحظة بدء التسرّب، تماماً كنظام هيدروليكي، فلا تبقى لديّ فرملة قابلة للاستخدام","لا يعطي فقدان ضغط الهواء أي تحذير على الإطلاق، فلا بد أن المصباح والجرس يشيران إلى عطل آخر غير ذي صلة","لا يمكن فعلاً التأكد من التسرّب أثناء القيادة، لذا ينبغي أن أتابع بسرعة حتى أتمكن من الركن وفحص الخطوط","تظل الفرامل تعمل طالما بقي ضغط الهواء، والتحذير ينبهني للتوقف بأمان قبل أن ينخفض كثيراً"],"explanation":"تظل الفرامل الهوائية تعمل طالما بقي ضغط هواء قابل للاستخدام، ويجب أن يضيء تحذير انخفاض الضغط قبل أن ينخفض الضغط دون 60 psi كي تتمكن من التوقف بأمان."},"75":{"q":"أقوم بالجزء الخاص بالفرامل الهوائية من فحص ما قبل الرحلة على جرّار مفرد. لقد صرّفت الخزانات بالفعل وبنيت الضغط حتى نقطة قطع المنظِّم. قبل أن أنطلق من الساحة، أي مجموعة من وظائف الفرامل يجب أن أتأكد من عملها فعلاً لإكمال جولة فحص الفرامل الهوائية؟","options":["تحذير انخفاض ضغط الهواء، وفرامل النوابض (الانتظار)، وفرامل الخدمة","فقط فرامل النوابض (الانتظار) وفرامل الخدمة، بما أن التحذير يختبر نفسه عند بدء التشغيل","فقط تحذير انخفاض ضغط الهواء وفرامل الخدمة، بما أن فرامل النوابض تُضبط تلقائياً","فقط فرامل الخدمة، لأن دواسة ثابتة عند 5 mph تثبت سلامة النظام بأكمله"],"explanation":"يجب أن يؤكد فحص الفرامل الهوائية الكامل ثلاثة أمور: تحذير انخفاض ضغط الهواء، وفرامل النوابض (الانتظار)، وفرامل الخدمة."},"76":{"q":"اشتريت للتو شاحنة صلبة مجهزة بمكابح هوائية، وأنا أحمل بالفعل رخصة قيادة تجارية (CDL) سارية حصلت عليها في مركبة ذات مكابح هيدروليكية. قبل أن أقود هذه الشاحنة ذات المكابح الهوائية بشكل قانوني، ما الخطوة الإضافية التي تطلبها مني ولاية تكساس والتي لم تكن تنطبق على مركبتي القديمة ذات المكابح الهيدروليكية؟","options":["لا شيء إضافي — فرخصتي الحالية تغطي بالفعل أي نظام كبح، لذا يمكنني قيادتها كما هي","يجب أن أجتاز اختبار المكابح الهوائية (بلا قيد)، وإلا ستحمل رخصتي قيداً على المكابح الهوائية","أحتاج فقط إلى إضافة تصنيف الفئة (Class C) ليتناسب مع حجم الشاحنة الأصغر","يجب أن أحصل على تصديق منفصل لقيادة الدراجات النارية قبل تشغيل أي وحدة بمكابح هوائية"],"explanation":"يجب أن تجتاز اختبار المعرفة والمهارات الخاص بالمكابح الهوائية، وإلا تضع الولاية قيداً على المكابح الهوائية في رخصتك يمنعك من قيادة المركبات ذات المكابح الهوائية."},"77":{"q":"أنا أقود مقطورة محملة على طريق سريع مبلل عندما تقطع سيارة الطريق أمامي وتتوقف فجأة. أضغط على دواسة المكبح بقوة، ويبدأ نظام منع انغلاق المكابح (ABS) في الجرّار-المقطورة بالعمل. في تلك اللحظة من الكبح الشديد، ماذا ينبغي أن أتوقع واقعياً أن يفعله نظام ABS من أجلي؟","options":["يقلّص مسافة التوقف الكلية بشكل كبير لأتوقف قبل السيارة التي أمامي بمسافة جيدة","يطبّق مكابحي تلقائياً نيابة عني حتى قبل أن أضغط على الدواسة","يمنع عجلاتي من الانغلاق حتى أتمكن من توجيه المركبة لتفادي الخطر أثناء الكبح الشديد","يتولى دور المكابح الرئيسية للخدمة بمجرد ضغط الدواسة حتى النهاية"],"explanation":"يمنع نظام ABS انغلاق العجلات أثناء الكبح الشديد حتى تحتفظ بالتحكم في التوجيه وتتمكن من تفادي الخطر بالتوجيه."},"78":{"q":"أنا أقود شاحنة صلبة بنظام مكابح هوائية واحد، ويتوقف المحرك على امتداد هادئ من الطريق السريع. وبينما أنزلق نحو الكتف، أبقي عيني على مقياس ضغط الهواء، عالماً أن الهواء سينخفض ببطء مع توقف الضاغط عن العمل. عند أي ضغط تقريباً ينبغي أن أتوقع أول تفعيل لتحذير انخفاض ضغط الهواء (الضوء والجرس)، مما يشير إلى أنني أفقد احتياطي الهواء؟","options":["حوالي 100 psi، وهي النقطة التي يعيد عندها المنظّم عادةً تشغيل الضاغط","حوالي 125 psi، وهي النقطة التي يفصل عندها المنظّم عادةً الضاغط","حوالي 30 psi، عندما توشك المكابح الزنبركية على الانطباق تلقائياً","حوالي 60 psi، قبل أن يصبح الضغط منخفضاً بشكل خطير بوقت كافٍ"],"explanation":"يجب أن يعمل تحذير انخفاض ضغط الهواء عند حوالي 60 psi، أي قبل أن يصبح الضغط منخفضاً بشكل خطير بوقت كافٍ."},"79":{"q":"أقوم بفحص ما قبل الرحلة وأحاول أن أتصور ما الذي يجعل مكابحي الهوائية تنطبق فعلاً عندما أضغط على الدواسة. ما دامت محركي ومقاييسي وخطوطي سليمة، فإن مكابحي الهوائية ستستمر في إيقاف الشاحنة طالما بقي أي مما يلي كافياً؟","options":["ضغط الهواء المتراكم والمخزّن في الخزانات","سائل المكابح الهيدروليكي في الأسطوانة الرئيسية","ضغط زيت المحرك الذي يغذي دائرة المكابح","شحنة البطارية ذات 12 فولت التي تشغّل صمامات المكابح"],"explanation":"تنطبق المكابح الهوائية وتثبّت باستخدام ضغط الهواء المضغوط المتراكم والمخزّن في الخزانات، وليس السائل."},"80":{"q":"أثناء فحص ما قبل الرحلة، أتتبع نظام أساس المكابح الهوائية على محور ذي مكابح طبلية. أتابع المسار من غرفة المكبح، عبر قضيب الدفع، إلى ضابط الخلوص، الذي يدير عموداً عند العجلة. عند نهاية ذلك العمود أجد جزءاً على شكل حرف S يقع بين فكّي المكبح. عندما أطبّق المكبح، ما آخر حركة ميكانيكية تدفع فعلاً الفكّين إلى الخارج باتجاه الطبلة لإبطاء العجلة؟","options":["يمتد قضيب الدفع خارج غرفة المكبح ويضغط مباشرة على فكّي المكبح باتجاه الطبلة","يدور كام S ويفرّق فكّي المكبح بعيداً عن بعضهما، فيضغط بطاناتهما على السطح الداخلي للطبلة","يدفع السائل الهيدروليكي من الأسطوانة الرئيسية مكبساً عند العجلة يطبق الفكّين على الطبلة","يضغط ضابط الخلوص زوجاً من الوسائد على قرص مثبت على محور العجلة"],"explanation":"يحرّك ضغط الهواء قضيب الدفع وضابط الخلوص لتدوير كام S، الذي يفرّق فكّي المكبح فتضغط بطاناتهما على السطح الداخلي للطبلة."},"81":{"q":"أثناء فحص ما قبل الرحلة ألاحظ أن مركبتي بها عدة خزانات معدنية مثبتة على طول الهيكل، منفصلة عن المحرك ونظام الوقود. يسألني سائق أحدث عهداً عمّا تقدمه هذه خزانات الإمداد (التخزين) فعلاً لنظام المكابح الهوائية. أي إجابة تفسّر مهمتها بشكل صحيح؟","options":["تبني الهواء وتضغطه، وتتولى عمل الضخ كلما وصل الضاغط إلى نقطة فصل المنظّم عند حوالي 125 psi","تزيل الماء والزيت من الهواء حتى لا تحتاج الخطوط أبداً إلى التصريف في نهاية اليوم","تحتفظ باحتياطي الهواء المضغوط حتى يتوافر ضغط كافٍ لتشغيل المكابح","تستشعر انخفاض الضغط وتشغّل ضوء التحذير والجرس قبل أن يهبط الهواء دون حوالي 60 psi"],"explanation":"تحتفظ خزانات الإمداد باحتياطي من الهواء المضغوط حتى يتوافر دائماً ضغط كافٍ لتشغيل مكابح الخدمة والوقوف والطوارئ."},"82":{"q":"أنا أقود شاحنة صلبة محملة عندما ينفجر خط هواء رئيسي. تهبط إبرة مقياس الهواء باطّراد، وقد سبق أن تفعّل ضوء وجرس تحذير انخفاض الهواء، وأنا لا ألمس دواسة المكبح. مع استمرار انخفاض الضغط، ما الذي يجعل شاحنتي تتوقف من تلقاء نفسها؟","options":["تنطبق مكابح الخدمة ذاتياً عبر الصمام القدمي بمجرد أن يتجاوز المقياس نقطة فصل المنظّم","يطلق صمام تنفيس الأمان الهواء من النظام، مما يدفع ميكانيكياً مكابح الخدمة على الطبلات","تشغّل دائرة تحذير انخفاض الهواء المكابح في اللحظة التي يضيء فيها الضوء ويرنّ الجرس","تنطبق المكابح الزنبركية تلقائياً بمجرد أن يصل الضغط المنخفض إلى المدى الذي تتولى فيه الزنبركات السيطرة"],"explanation":"تُبقى المكابح الزنبركية مفتوحة بفعل الهواء، لذا عندما يهبط الضغط المتسرب إلى المدى المنخفض (حوالي 20-45 psi) تنطبق الزنبركات على المكابح تلقائياً."},"83":{"q":"أثناء الكبح الشديد، يمنع نظام ABS العجلات من:","options":["الدوران على الإطلاق","الانغلاق والانزلاق","السخونة","فقدان هوائها"],"explanation":"يمنع نظام ABS انغلاق العجلات حتى تتمكن من التوجيه أثناء الكبح الشديد."},"84":{"q":"في رحلة توصيل، يضيء ضوء تحذير انخفاض الهواء فجأة وألاحظ أن أحد مقياسي ضغط الهواء لديّ يهبط بسرعة بينما يثبت الآخر. مركبتي بها نظام مكابح هوائية مزدوج. أي عبارة تفسّر بشكل أفضل سبب احتفاظي ببعض القدرة على الكبح الآن؟","options":["النظام مقسّم إلى دائرتين منفصلتين، لذا فإن فقدان الدائرة المعطلة لا يعطّل الدائرة التي ما زالت تحتفظ بالضغط","تسحب كلتا الدائرتين من خزان واحد كبير مشترك، لذا فإن المقياس الثابت يعيد ضخ الهواء إلى الجانب المعطل","يتولى مكبح هيدروليكي احتياطي السيطرة تلقائياً كلما فقدت إحدى الدائرتين الهوائيتين الضغط","يلغي النظام المزدوج مكبح الوقوف، فيوجّه كل الهواء المتبقي إلى مكابح الخدمة"],"explanation":"يحتوي نظام المكابح الهوائية المزدوج على دائرتين مستقلتين، لذا فإن التسرب أو العطل في إحداهما لا يفرّغ الأخرى، التي تظل محتفظة بالضغط وتكبح الجزء الخاص بها من المركبة."},"85":{"q":"شغّلت للتو محرك الجرّار-المقطورة في ساحة باردة. ضوء تحذير انخفاض الهواء مطفأ، لكن مقياسي لا يزال يقرأ 65 psi فقط بينما أستعد للخروج من الساحة. وفقاً لإجراءات إدارة السلامة العامة في تكساس (DPS)، ما أدنى ضغط ينبغي أن أتركه يتراكم قبل أن أبدأ القيادة؟","options":["65 psi، لأن ضوء تحذير انخفاض ضغط الهواء قد انطفأ بالفعل","حوالي 100 psi، حتى يكون هناك هواء كافٍ لتشغيل المكابح بأمان","حوالي 60 psi، وهي النقطة التي ينطفئ عندها تحذير انخفاض الهواء","حوالي 125 psi، نقطة فصل المنظّم، قبل تحرير مكبح الوقوف"],"explanation":"اترك ضغط الهواء يتراكم إلى ما لا يقل عن حوالي 100 psi قبل القيادة حتى يتوافر هواء كافٍ لتشغيل مكابح الخدمة والطوارئ بأمان."},"86":{"q":"أثناء فحص ما قبل الرحلة على شاحنة صلبة مفردة، أرفع نظام الهواء إلى حوالي 125 psi، وأطفئ المحرك، وأضع أوتاد العجلات. أترك مقبض مكبح الوقوف مدفوعاً للداخل حتى تبقى المكابح محررة، ثم أراقب مقياس لوحة القيادة. في الدقيقة الأولى تهبط الإبرة أكثر من 4 psi. ما الذي يخبرني به هذا عن المركبة؟","options":["لا يوجد خطأ؛ فمع إطفاء المحرك يبرد الهواء في الخزانات وينكمش، لذا فإن هبوطاً بهذا الحجم في الدقيقة الأولى متوقع.","تثبت القراءة أن المكابح الزنبركية انطبقت من تلقاء نفسها بشكل صحيح، لأن الضغط ينخفض دائماً بسرعة بمجرد انخراط نظام الوقوف.","يتسرب النظام للهواء أسرع من المسموح؛ فمع تحرير المكابح ينبغي ألا تفقد المركبة المفردة أكثر من 2 psi في الدقيقة، وأكثر من 4 psi يعني تسرباً يجب البحث عنه وإصلاحه.","يؤكد هذا أن المنظّم بلغ نقطة الفصل وأوقف الضاغط، وهو السلوك الطبيعي للضغط بعد إطفاء المحرك."],"explanation":"مع تحرير المكابح ينبغي ألا تفقد المركبة المفردة أكثر من 2 psi في الدقيقة، لذا فإن فقداناً أكبر من 4 psi يشير إلى تسرب هواء يجب البحث عنه وإصلاحه."},"87":{"q":"أنا متوقف عند رصيف تحميل عندما يفرّغ تسرب بطيء للهواء خزانات الإمداد لديّ ويستمر ضغط النظام في الهبوط نحو الصفر. مع نزيف الضغط، ماذا يفعل نظام المكابح الهوائية لمنع المركبة من التدحرج، ولماذا؟ اختر العبارة الصحيحة.","options":["تستخدم مكابح الخدمة السائل الهيدروليكي المخزّن لتثبيت العجلات، فتبقى الشاحنة في مكانها حتى دون أي هواء متبقٍ في الخزانات.","لا شيء يثبّت الشاحنة بمجرد نفاد الضغط؛ فذلك التسرب الصغير الواحد يحرّر كل مكبح فوراً وتصبح المركبة حرة للتدحرج.","يضخ الضاغط تلقائياً ليعوّض التسرب حتى 125 psi، فتُبقي مكابح الخدمة بالصمام القدمي المركبة متوقفة من تلقاء نفسها.","تنطبق المكابح الزنبركية (الوقوف) تلقائياً مع هبوط الضغط إلى مدى 20-45 psi، فتثبّت العجلات ميكانيكياً دون أي هواء."],"explanation":"تُبقى مكابح الوقوف الزنبركية مفتوحة بفعل الهواء، لذا مع هبوط الضغط إلى مدى 20-45 psi تنطبق زنبركات قوية على المكابح تلقائياً وتثبّت العجلات دون أي هواء."},"88":{"q":"شغّلت للتو محرك الجرّار ذي المكابح الهوائية ويقرأ مقياس ضغط الهواء 50 psi فقط، مع استمرار رنين جرس تحذير انخفاض الهواء. أنا متوقف ومحمّل ومتأخر عن موعد توصيلي. ماذا ينبغي أن أفعل قبل أن أحرّر مكبح الوقوف وأخرج من الساحة؟","options":["أنتظر، مع إبقاء المحرك يعمل، حتى يتراكم الضغط إلى حوالي 100 psi وينطفئ تحذير انخفاض الهواء","أخرج ببطء عند 50 psi، لأن المكابح ستستمر في بناء الضغط بينما أقود إلى موقع التوصيل","أفتح صمامات تصريف الخزان لتفريغ الهواء المحبوس حتى يعيد الضاغط ملء الخزانات أسرع","أفصل جرس تحذير انخفاض الهواء حتى يتوقف عن الرنين، ثم أقود بمجرد توقف الضجيج"],"explanation":"أبقِ المحرك يعمل وانتظر حتى يتراكم الضغط إلى حوالي 100 psi وينطفئ تحذير انخفاض الهواء قبل القيادة."},"89":{"q":"أنا أنقل تركيبة محملة على منحدر جبلي طويل وأبقي ضغطاً ثابتاً على دواسة المكبح طوال الطريق. قرب الأسفل، ما زالت الدواسة تبدو متماسكة لكن المركبة بالكاد تبطئ عندما أضغط عليها. أي تفسير يفسّر بشكل أفضل سبب فقدان مكابحي لقدرتها على التوقيف؟","options":["دفع الكبح المستمر ضغط هواء النظام فوق نقطة فصل المنظّم، فلم تعد المكابح قادرة على بناء قوة كافية","أدى الكبح المستمر إلى ارتفاع حرارة طبلات المكابح وبطاناتها، وهذه الحرارة تقلل من مقدار الاحتكاك الذي تنتجه المكابح","استنزف الكبح الثابت تدريجياً خزانات الهواء، وتحررت المكابح الزنبركية جزئياً للتعويض","أحكمت ضوابط الخلوص نفسها بفعل الحرارة، فسحبت البطانات بعيداً عن الطبلات"],"explanation":"يؤدي الكبح المستمر المتواصل على منحدر طويل إلى ارتفاع حرارة الطبلات والبطانات، وهذه الحرارة تقلل الاحتكاك الذي تنتجه المكابح، مما يسبب تلاشي الكبح."},"90":{"q":"أقترب من إشارة توقف في شاحنتي ذات المكابح الهوائية وأضغط على دواسة المكبح بحزم. هناك تأخر ملحوظ قبل أن أشعر فعلاً ببدء الشاحنة في الإبطاء، رغم أن قدمي تحركت فوراً. يسمي مدرّبي هذا 'تأخر المكبح'. ما الذي يحدث فعلاً خلال ذلك التأخر؟","options":["ضوابط الخلوص لديّ غير محاذية، فقضبان الدفع بطيئة جداً في إجلاس الفكّين","زمن ردة فعلي كسائق هو ما يولّد التأخر بين القرار والكبح","يستغرق الهواء جزءاً من الثانية ليسري عبر الخطوط ويصل إلى المكابح","هبط ضغط الهواء دون نقطة الوصل، فيجب على المنظّم إعادة الضغط أولاً"],"explanation":"تأخر المكبح هو نحو نصف ثانية يستغرقها الهواء المضغوط ليسري عبر الخطوط من الدواسة إلى غرف المكابح، وهو خاصية طبيعية في كل نظام مكابح هوائية."},"91":{"q":"أثناء فحص ما قبل الرحلة على جرّار قديم ذي مكابح هوائية، أترك الهواء يتراكم، وأطفئ المحرك، وأبدأ بتحريك دواسة المكبح لخفض الضغط. مع هبوط المقياس نحو 60 psi، يتأرجح ذراع ميكانيكي صغير فجأة نازلاً إلى مجال رؤيتي فوق الزجاج الأمامي. يسميه المدرّب 'wig-wag'. ما الغرض من هذا الجهاز؟","options":["إنه المنظّم يشير إلى أن الضاغط بلغ نقطة الفصل وتوقف عن ضخ الهواء إلى الخزانات","إنه صمام التحكم المعدّل ينزل ليسمح لي بتطبيق المكابح الزنبركية تدريجياً في حالة طوارئ","إنه صمام التصريف التلقائي يطلق الماء والزيت المتجمّعين في خزان الإمداد","إنه تحذير ميكانيكي لانخفاض الهواء ينزل فعلياً إلى مجال الرؤية لينبهني إلى أن الضغط أصبح منخفضاً بشكل خطير"],"explanation":"الـ wig-wag هو تحذير ميكانيكي لانخفاض الهواء، يهبط ذراعه المحمّل بزنبرك إلى مجال رؤية السائق ليشير إلى أن ضغط الهواء أصبح منخفضاً بشكل خطير."},"92":{"q":"أثناء فحص ما قبل الرحلة، أضغط على دواسة المكبح وأراقب مكابح الأساس على عجلة. مع امتلاء غرفة المكبح بالهواء، يمتد قضيب الدفع إلى الخارج. في مكبح طبلي بكام S يعمل بشكل سليم، ما الشيء التالي الذي يُفترض أن تفعله حركة قضيب الدفع هذه؟","options":["تدير ضابط الخلوص، الذي يلوي كام S ويدفع فكّي المكبح على الطبلة","تدفع فكّي المكبح مباشرة على الطبلة دون أي كام أو ذراع","تفتح غرفة المكبح الزنبركية حتى تساعد زنبركات الوقوف على تطبيق مكابح الخدمة","تغذي هواءً مضغوطاً إضافياً إلى خزان الإمداد للحفاظ على ضغط النظام"],"explanation":"يدفع الهواء في غرفة المكبح قضيب الدفع، الذي يدير ضابط الخلوص ويلوي كام S، فيفرّق فكّي المكبح باتجاه الطبلة."},"93":{"q":"اشتريت للتو جرّار شاحنة موديل 2020 بمكابح هوائية، وأنا أتتبع أسلاك نظام ABS للتأكد من أن نظام منع الانغلاق يفي بالمتطلب الفيدرالي لمركبة بهذا الحداثة. وبينما أفحص كل محور، على أي عجلات يُطلب مني أن أجد نظام ABS؟","options":["فقط على عجلات التوجيه (الأمامية)، لأن انغلاقها هو ما يسبب فقدان التوجيه","على جميع عجلات الجرّار، لأن الجرّارات الأحدث يجب أن يكون بها ABS على كل عجلة","فقط على العجلات الدافعة الخلفية، لأنها حيث يقع أثقل حمل كبح","لا على أي عجلة، لأن نظام ABS معدة اختيارية يضيفها المشتري لاحقاً"],"explanation":"نظام ABS مطلوب على كل عجلة من جرّارات الشاحنات المصنوعة في أو بعد 1 مارس 1997، لذا يجب أن يكون في الجرّار الأحدث ABS على جميع العجلات."},"94":{"q":"أثناء فحص ما قبل الرحلة لمركبتي المركّبة، تخبرني لوحة القيادة أن نظام ABS الخاص بالجرّار نفسه سليم، لكن لا يزال عليّ التأكد من أن نظام ABS الخاص بالمقطورة يعمل. صُنعت المقطورة عام 1999، لذا لها نظام ABS خاص بها ومصباح عطل منفصل يجب أن أفحصه. أثناء طوافي حول المركبة، أين ينبغي أن أبحث لأجد مصباح عطل ABS الخاص بالمقطورة؟","options":["مثبتاً على مقدمة المقطورة قرب وتد الارتكاز، بحيث يواجه كابينة الجرّار","على لوحة القيادة داخل الكابينة، بجانب ضوء تحذير ABS الخاص بالجرّار مباشرة","على الجانب الأيسر أو المؤخرة اليسرى للمقطورة، حيث يكون مرئياً أثناء الطواف حول المركبة","داخل خزان إمداد الهواء للمقطورة، خلف صمام التصريف اليدوي"],"explanation":"في مقطورة موديل 1999، يكون مصباح عطل ABS مثبتاً على الجانب الأيسر أو المؤخرة اليسرى للمقطورة بحيث يكون مرئياً أثناء فحص الطواف حول المركبة."},"95":{"q":"أنا أقود شاحنة متوسطة الحمولة مجهزة بنظام مكابح هوائية-هيدروليكي (air-over-hydraulic). أثناء فحص ما قبل الرحلة، أريد أن أفهم ما الذي يفعله الجزء الهوائي من هذا النظام فعلاً حتى أعرف ما الذي سأفقده إذا تعطل إمداد الهواء. أي عبارة تصف بشكل صحيح دور ضغط الهواء في هذا الإعداد؟","options":["يدور ضغط الهواء عبر الفرامل (الكاليبر) لتبريد السائل الهيدروليكي ومنعه من ارتفاع الحرارة على المنحدرات الطويلة","يبقي ضغط الهواء السائل الهيدروليكي ممتلئاً، فيعوّض تلقائياً السائل المفقود عبر الأختام البالية","يشغّل ضغط الهواء الضاغط الذي يعيد شحن البطارية حتى يكون للمضخة الهيدروليكية طاقة دائماً","يؤثر ضغط الهواء على النظام الهيدروليكي ليعزز قوة الكبح التي يطبقها السائق عند الدواسة"],"explanation":"في النظام الهوائي-الهيدروليكي، يعزز ضغط الهواء القوة التي يطبقها السائق عند الدواسة، والتي ينقلها السائل الهيدروليكي بعد ذلك إلى مكابح العجلات."},"96":{"q":"أثناء فحص ما قبل الرحلة، تكتشف أن ضوابط الخلوص لديك تُظهر حركة مفرطة لقضيب الدفع، مما يعني أن المكابح خارج الضبط. إذا قدت رغم ذلك وانطلقت نازلاً على منحدر طويل وشديد الانحدار، ما النتيجة الأكثر احتمالاً لهذا الخلل؟","options":["ستنخفض قوة الكبح، وقد تتعطل المكابح تماماً مع ارتفاع حرارتها على المنحدر","ستمسك المكابح أقوى من المعتاد، مما يرفع خطر انغلاق العجلات والانزلاق","سيستهلك النظام ببساطة هواءً أقل، فيمكنك بأمان تحريك دواسة المكبح لفترة أطول على المنحدر","سيتفعّل تحذير انخفاض ضغط الهواء مبكراً، لكن قوة الكبح نفسها تبقى غير متأثرة"],"explanation":"تقلل المكابح الخارجة عن الضبط من قوة الكبح، ويمكن أن تتلاشى وتتعطل تماماً تحت حمل الحرارة، كما على منحدر طويل وشديد الانحدار."},"97":{"q":"أنا أنزل على منحدر طفيف في شاحنتي ذات المكابح الهوائية وأضغط على دواسة المكبح بقوة أكبر قليلاً للإبطاء. وبينما أضغط على الدواسة، يرتفع أحد مقياسي الضغط لديّ أعلى كلما ضغطت بقوة أكبر. أي مقياس أراقبه، وماذا يخبرني؟","options":["مقياس ضغط الإمداد، يخبرني بكمية الهواء الباقية المخزّنة في خزاناتي","مقياس ضغط التطبيق، يخبرني بمقدار ضغط الهواء الذي أطبّقه بدواسة المكبح","مقياس فصل المنظّم، يخبرني متى سيتوقف الضاغط عن الضخ عند 125 psi","مقياس تحذير انخفاض الهواء، يخبرني أن الضغط على وشك الهبوط دون 60 psi"],"explanation":"يُظهر مقياس ضغط التطبيق ضغط الهواء المرسَل إلى المكابح، لذا ترتفع قراءته كلما ضغطت على الدواسة بقوة أكبر وتنخفض عندما تخفف الضغط."},"98":{"q":"أنا أقود جرّار-مقطورة بمكابح هوائية بسرعة 55 mph على طريق سريع جاف عندما أرصد سيارة معطلة أمامي وأضغط على دواسة المكبح بقوة. يصرّ زميل لي على أن نصف الثانية التي يستغرقها الهواء ليسري فعلاً عبر الخطوط ويطبق المكابح بالكاد تهم عند سرعة الطريق السريع. كم تقريباً من مسافة التوقف الإضافية يضيفها تأخر المكبح ذاك عند 55 mph، فوق مسافات الإدراك ورد الفعل والكبح الفعلي؟","options":["لا شيء يستحق الحساب — فتأخر نصف الثانية أقصر من أن يضيف أي مسافة قابلة للقياس عند 55 mph","حوالي 12 قدماً — تقريباً طول الجرّار قبل أن تمسك المكابح","حوالي 32 قدماً — قرابة طول المقطورة تقطعه قبل أن تمسك المكابح","حوالي 60 قدماً — لأن مسافة التأخر تستمر في التضاعف كلما زادت السرعة"],"explanation":"للمكابح الهوائية تأخر يبلغ نحو نصف ثانية، لذا عند 55 mph تقطع المركبة نحو 32 قدماً إضافية قبل أن تمسك المكابح."},"99":{"q":"أثناء فحص ما قبل الرحلة، أطفئ المحرك والنظام مشحون بالكامل وأراقب المقياس. تستمر الإبرة في الزحف نزولاً ولا تستقر، رغم أن جميع أبوابي مغلقة وأنا لا أضغط على دواسة المكبح. قبل أن أقرر ما إذا كانت هذه الشاحنة آمنة للقيادة، أي حالة تخبرني بأن لديّ تسرباً خطيراً بما يكفي لكي لا آخذها على الطريق؟","options":["ارتفع المقياس إلى 125 psi بالضبط أثناء البناء، فالهبوط البطيء بعد ذلك هو مجرد التبريد الطبيعي للخزانات","أستطيع سماع هسيس خفيف من منطقة الضاغط، لكن ما دام جرس تحذير انخفاض الهواء لم يرنّ بعد، فالنظام آمن للقيادة","يهبط الضغط فقط حتى يعاود المنظّم الوصل، مما يثبت أن الضاغط يلبي الطلب","مع إطفاء المحرك وتحرير المكابح، لا يثبت ضغط الهواء ويستمر في الهبوط بما يتجاوز معدل التسرب المسموح"],"explanation":"مع إطفاء المحرك وتحرير المكابح، يجب أن يثبت الضغط؛ فإذا استمر في الهبوط متجاوزاً معدل التسرب المسموح، فإن التسرب أكبر من أن يكون القيادة عليه آمنة."},"100":{"q":"أثناء فحص ما قبل الرحلة، يستمر جرس تحذير انخفاض الهواء في الرنين لأن ضغط الهواء لديّ لا يتراكم فوق 70 psi، حتى مع تشغيل المحرك عند تسارع خامل سريع. يخبرني ميكانيكي أن المكوّن المسؤول عن توليد الهواء وضخه إلى الخزانات قد تعطل ويجب استبداله. أي مكوّن يقصده؟","options":["الضاغط الهوائي، الذي يضخ الهواء إلى خزانات التخزين لتشغيل النظام","المنظّم، الذي يتحكم في متى يُضخ الهواء إلى خزانات التخزين","ضابط الخلوص، الذي ينظم تدفق الهواء إلى غرف المكابح","صمام تنفيس الأمان، الذي يطلق الهواء للحفاظ على ضغط الخزان"],"explanation":"يولّد الضاغط الهوائي الهواء ويضخه إلى خزانات التخزين، لذا عندما لا يستطيع الضغط التراكم، يكون الضاغط هو المكوّن المتعطل."},"101":{"q":"أثناء فحص ما قبل الرحلة، أترك المحرك يعمل وأراقب مؤشر الهواء يرتفع. عند حوالي 125 psi يتوقف الضاغط عن تحميل النظام، وبعد أن أقوم بعدة عمليات ضغط على الفرامل وتنخفض الضغط إلى حوالي 100 psi، يبدأ الضاغط بالضخ مرة أخرى. أي مكوّن مسؤول عن تشغيل وإيقاف الضاغط عند هذه الضغوط؟","options":["صمام تنفيس الأمان، الذي يطلق الهواء بمجرد أن تصل الخزانات إلى حوالي 150 psi","المنظّم، الذي يفصل الضاغط عند حوالي 125 psi ويعيد تشغيله عند حوالي 100 psi","جهاز التحذير من انخفاض ضغط الهواء، الذي ينبّه الضاغط قبل أن ينخفض الضغط دون 60 psi","مكابس التفريغ الخاصة بالضاغط، التي تحدّد ضغط تشغيل النظام بنفسها"],"explanation":"يتحكّم المنظّم في الضاغط، حيث يفصله عند حوالي 125 psi ويعيد تشغيله عند حوالي 100 psi."},"102":{"q":"أثناء فحص ما قبل الرحلة، أُشغّل المحرك وأراقب مؤشر ضغط الهواء يرتفع بينما يضخّ الضاغط. أنا أنتظر أن يصل المنظّم إلى نقطة الفصل، وهي النقطة التي يتوقف عندها الضاغط عن إضافة الهواء إلى الخزانات. عند أي قراءة تقريبية على المؤشر ينبغي أن أتوقع حدوث ذلك؟","options":["حوالي 100 psi، لأن هذا هو المكان الذي يتحكّم فيه المنظّم بالنظام","حوالي 150 psi، تماماً عندما يصل النظام إلى أعلى ضغط آمن له","حوالي 125 psi، عندما يأمر المنظّم الضاغط بالتوقف عن الضخ","حوالي 60 psi، تماماً عندما يتوقف جهاز التحذير وينتهي الضخ"],"explanation":"تحدث نقطة فصل الضاغط، أي النقطة التي يوقف فيها المنظّم الضاغط عن الضخ، عند حوالي 125 psi."},"103":{"q":"أقوم بفحص ما قبل الرحلة على مركبة مفردة مزوّدة بفرامل هوائية. مع إيقاف المحرك، أضغط على دوّاسة الفرامل لتفريغ النظام وأراقب مؤشر الهواء ينخفض. عند أي نقطة ينبغي أن يعمل ضوء التحذير من انخفاض الهواء وجرس الإنذار ليخبرني أن الضغط أصبح منخفضاً بشكل خطير؟","options":["بمجرد أن ينخفض المؤشر دون 100 psi، لأن هذا هو المكان الذي يبدأ فيه المنظّم بإعادة بناء الهواء","عندما ينخفض الضغط إلى نطاق 20 إلى 45 psi، في اللحظة نفسها التي تنطبق فيها فرامل النابض","في اللحظة التي يتجاوز فيها الضغط 125 psi، حيث يفصل المنظّم ويتوقف عن الضخ","قبل أن ينخفض المؤشر دون 60 psi، بينما لا يزال هناك هواء كافٍ للتوقّف بأمان"],"explanation":"يجب أن يعمل التحذير من انخفاض ضغط الهواء قبل أن ينخفض الضغط دون 60 psi، بما يترك هواءً كافياً لإيقاف المركبة بأمان."},"104":{"q":"أثناء فحص ما قبل الرحلة، أُشغّل المحرك وأراقب أحد مؤشرات لوحة القيادة يرتفع بثبات حتى يفصل المنظّم الضاغط عند حوالي 125 psi. وأنا أنظر ذهاباً وإياباً بين هذا المؤشر والمؤشرات الأخرى، أي قراءة يخبرني بها هذا المؤشر تحديداً؟","options":["مقدار ضغط الهواء المخزّن حالياً في خزانات الهواء","مدى قوة ضغطي على دوّاسة الفرامل، معروضاً كضغط تطبيق","النقطة التي سيعمل عندها ضوء التحذير من انخفاض ضغط الهواء","عدد الثواني التي استغرقها الهواء للارتفاع من 85 إلى 100 psi"],"explanation":"يُظهر مؤشر ضغط الهواء مقدار ضغط الهواء المخزّن حالياً في خزانات الهواء."},"105":{"q":"إنه فصل الشتاء، ومركبتي القاطرة-المقطورة مزوّدة بصمامات تصريف يدوية على خزانات الهواء. لقد أنهيت للتو نوبة عمل طويلة وألاحظ أن الماء وزيت الضاغط قد تجمّعا في النظام. مع علمي أن هذا قد يتجمّد ويُتلف المكوّنات طوال الليل، متى ينبغي أن أفتح صمامات التصريف اليدوية هذه لتفريغ الرطوبة؟","options":["مرة واحدة فقط في الأسبوع، لأن مجفّف الهواء يزيل معظم الرطوبة بين عمليات التصريف","في نهاية كل يوم، بتفريغ الخزانات بالكامل قبل أن أركن المركبة","فقط عندما يعمل ضوء التحذير من انخفاض ضغط الهواء دون 60 psi","مرة واحدة تقريباً في الشهر، أو في أي وقت ألاحظ فيه أن الخزانات تُسرّب هواءً بشكل واضح"],"explanation":"قم بتفريغ خزانات الهواء ذات الصمامات اليدوية بالكامل في نهاية كل يوم لإزالة الماء والزيت اللذين يتجمّعان أثناء التشغيل."},"106":{"q":"أثناء جولة فحص ما قبل الرحلة، يطلب مني الفاحص تسمية الأنظمة الثلاثة المنفصلة للكبح التي تُدمج في نظام فرامل هوائية واحد. أقول بشكل صحيح فرامل الخدمة وفرامل الركن. أي نظام يجب أن أسمّيه ثالثاً لإكمال الإجابة؟","options":["نظام المُبطّئ، الذي يُبطئ الشاحنة دون استخدام دوّاسة الفرامل","النظام ثنائي الدائرة، الذي يقسم الهواء إلى إمداد أوّلي وثانوي","نظام فرامل الطوارئ، الذي يوقف الشاحنة في حال تعطّل إمداد الهواء الرئيسي","نظام التعديل، الذي يتيح لي إطلاق فرامل النابض تدريجياً"],"explanation":"يجمع نظام الفرامل الهوائية بين ثلاثة أنظمة: فرامل الخدمة، وفرامل الركن، وفرامل الطوارئ التي توقف المركبة في حال تعطّل إمداد الهواء."},"107":{"q":"أقود شاحنة مستقيمة محمّلة عندما ينفجر خرطوم ويستمر ضغط الهواء لديّ في التسرّب. لقد كان ضوء وجرس التحذير من انخفاض الهواء يعملان منذ فترة، والآن أشعر أن الشاحنة تتباطأ بقوة من تلقاء نفسها بينما تنطبق فرامل النابض (الركن/الطوارئ) ذاتياً. باستثناء القراءة الدقيقة، إلى أي نطاق ضغط تقريبي كان الهواء قد انخفض في اللحظة التي انطبقت فيها فرامل النابض تلك تلقائياً؟","options":["حوالي 100 psi، النقطة التي يعيد عندها المنظّم التشغيل عادة","حوالي 60 psi، النقطة نفسها التي يبدأ عندها التحذير من انخفاض ضغط الهواء أول مرة","حوالي 125 psi، النقطة التي يفصل عندها المنظّم ويتوقف عن الضخ","حوالي 20 إلى 45 psi، حيث تنطبق فرامل النابض تلقائياً"],"explanation":"تُبقى فرامل النابض في وضع التحرير بفعل ضغط الهواء وتنطبق تلقائياً عندما ينخفض الضغط إلى نطاق 20 إلى 45 psi."},"108":{"q":"لقد نزلت للتو بشاحنتي المحمّلة منحدراً طويلاً وشديد الانحدار، مع استخدام الفرامل الهوائية بقوة طوال الطريق. في الأسفل أتوقّف في منطقة استراحة وأشعر أن العجلات تصدر حرارة شديدة. باستثناء أحد هذه الإجراءات، فإن البقية حركات سليمة قبل أن أغادر المقصورة. أي إجراء ينبغي أن أتجنّبه الآن؟","options":["ضبط فرامل الركن (النابض) بينما لا تزال طبول الفرامل ساخنة جداً من النزول","تثبيت العجلات بالحواجز وترك الفرامل تبرد قبل الاعتماد على فرامل النابض للتثبيت","ترك ضغط الهواء يعود ليبني حتى نقطة فصل المنظّم قبل أن أعتمد على النظام للتثبيت","فحص حركة قضيب الدفع لاحقاً، لأن الفرامل غير المضبوطة هي أكثر عيوب الفرامل الهوائية شيوعاً"],"explanation":"لا تضبط فرامل الركن (النابض) أبداً عندما تكون طبول الفرامل ساخنة جداً، كما هو الحال مباشرة بعد منحدر شديد، لأن ذلك قد يُتلفها."},"109":{"q":"أنزل منحدراً طويلاً وشديد الانحدار في مركبة مركّبة محمّلة. للحفاظ على سرعتي تحت السيطرة، أستمر بالضغط على دوّاسة الفرامل وتحريرها مراراً وتكراراً (\"التهوية\"). أي مما يلي هو النتيجة الأكثر احتمالاً للقيام بذلك طوال الطريق إلى أسفل التل؟","options":["ستبقى فراملي أبرد لأنها تحصل على فرصة للتحرير والتنفّس بين كل عملية ضغط","سينخفض ضغط الهواء لديّ لأن كل عملية تحرير تسمح للهواء بالخروج أسرع مما يستطيع الضاغط تعويضه، فينفد الهواء في النهاية","سيضخّ الضاغط أسرع مع كل تحرير، لذا ستبني خزاناتي مزيداً من الهواء كلما طالت مدة التهوية","لا يتغيّر شيء طالما بقيت فوق مستوى تحذير انخفاض الهواء البالغ 60 psi طوال الطريق إلى الأسفل"],"explanation":"لا تقم بتهوية أو ضخّ الفرامل على منحدر طويل لأن كل عملية تحرير تسمح للهواء بالخروج أسرع مما يستطيع الضاغط تعويضه، فينفد الهواء في النهاية."},"110":{"q":"أقود قاطرة-مقطورة مزوّدة بفرامل هوائية وأضغط على دوّاسة الفرامل بقوة، لكنني ألاحظ أن المركبة لا تبدأ بالتباطؤ في اللحظة التي تحرّك فيها قدمي الدوّاسة، بل هناك تأخير قصير يبلغ حوالي نصف ثانية قبل أن يبدأ الكبح فعلياً. هذا التأخير تحديداً، الناتج عن اضطرار الهواء إلى الانتقال عبر خطوط الفرامل إلى الحجرات، يُعرف باسم:","options":["تلاشي الفرامل، أي فقدان قوة الكبح بسبب فرط حرارة الطبول على منحدر طويل","انجراف الفرامل، أي ميل المركبة للانحراف إلى أحد الجانبين عند تطبيق الفرامل","تأخّر الفرامل، أي الوقت الذي يحتاجه الهواء للانتقال عبر الخطوط قبل أن تعمل الفرامل","عدم توازن الفرامل، أي قوة الكبح غير المتساوية بين محاور القاطرة والمقطورة"],"explanation":"تأخّر الفرامل هو التأخير البالغ نحو نصف ثانية الناتج عن حاجة الهواء إلى وقت للانتقال عبر خطوط الفرامل قبل أن تعمل الفرامل."},"111":{"q":"أقارن قاطرتي ذات الفرامل الهوائية بسيارة صديقي ذات الفرامل الهيدروليكية. بافتراض تطابق السرعة والطريق ووقت رد الفعل، كيف يؤثّر تأخّر الفرامل الهوائية البالغ نحو نصف ثانية على مسافة توقّفي الإجمالية مقارنة بالمركبة ذات الفرامل الهيدروليكية؟","options":["ليس له أي تأثير، لأن مسافة التوقّف الإجمالية تتحدّد فقط بمسافة الإدراك ورد الفعل.","يقلّل مسافة التوقّف الإجمالية إلى النصف تقريباً بمجرد وصول الهواء إلى حجرات الفرامل.","يقصّر مسافة التوقّف الإجمالية قليلاً لأن ضغط الهواء يبني قوة الكبح أسرع.","يطيل مسافة التوقّف الإجمالية قليلاً لأن مسافة تأخّر الفرامل تُضاف إلى الإجمالي."],"explanation":"يضيف تأخّر الفرامل البالغ نحو نصف ثانية مقطع مسافة تأخّر الفرامل إلى مسافة التوقّف الإجمالية، وهو حوالي 32 feet عند 55 mph."},"112":{"q":"أثناء فحص ما قبل الرحلة، أستمر في بناء الهواء وأراقب المؤشر يرتفع متجاوزاً نقطة فصل المنظّم. حدث عطل ما ولم يتوقّف الضاغط عن الضخ أبداً، لذا يستمر الضغط في الارتفاع. عند أي ضغط تقريبي ينبغي أن ينفتح صمام تنفيس الأمان في خزان الإمداد (الرطب) لحماية النظام من فرط الضغط؟","options":["حوالي 150 psi","حوالي 125 psi","حوالي 100 psi","حوالي 60 psi"],"explanation":"ينفتح صمام تنفيس الأمان في خزان الإمداد عند حوالي 150 psi لتنفيس الضغط الزائد في حال تعطّل المنظّم."},"113":{"q":"أثناء فحص ما قبل الرحلة، يطلب مني الفاحص أن \"أطبّق ضغطاً ثابتاً على صمام القدم وأثبّته\" بينما نراقب معدّل تسرّب الهواء. أنظر إلى أسفل نحو أدوات التحكّم والدوّاسات في المقصورة. أيها يطلب مني الفاحص أن أضغط؟","options":["المقبض الأصفر المعيّني الشكل على لوحة القيادة، لأن هذا هو ما يتحكّم في إمداد هواء الكبح","دوّاسة الفرامل على أرضية المقصورة، لأنها في نظام الفرامل الهوائية تُسمّى أيضاً صمام القدم أو صمام الدوّاسة","دوّاسة الوقود، لأنه يجب رفع ضغط الهواء قبل أن يبدأ اختبار التسرّب","دوّاسة القابض، لأن الضغط عليها هو ما يحرّر فرامل النابض لتطبيق الضغط"],"explanation":"دوّاسة الفرامل على أرضية المقصورة هي أداة التحكّم بفرامل الخدمة، وتُسمّى أيضاً صمام القدم أو صمام الدوّاسة."},"114":{"q":"أقود قاطرة-مقطورة مزوّدة بنظام فرامل هوائية مزدوج عندما يعمل فجأة ضوء وجرس التحذير من انخفاض ضغط الهواء، ليخبرني أن نظام الهواء الأوّلي قد فقد الضغط. أي مما يلي صحيح بشأن ما يمكن أن أتوقّعه من فراملي في هذه اللحظة؟","options":["يتوقّف النظامان الأوّلي والثانوي معاً، فلا تبقى لديّ أي قوة كبح على الإطلاق","تقفل فرامل النابض جميع العجلات فوراً، وينبغي أن أوجّه بقوة للحفاظ على السيطرة","لا يزال النظام الثانوي مشحوناً وسيستمر في توفير الكبح، فيمكنني الكبح للتوقّف بأمان","تتضاعف قوة توقّفي لأن النظام الثانوي يدفع كامل ضغط هوائه إلى العجلات"],"explanation":"في نظام الفرامل الهوائية المزدوج تبقى الدائرة الثانوية المنفصلة مشحونة عند تعطّل الأوّلي، لذا لا يزال بإمكانها كبح المركبة للتوقّف بأمان."},"115":{"q":"أثناء فحص ما قبل الرحلة، نظام الهواء مشحون بالكامل والمحرك متوقّف. أريد التأكّد من أن جهاز التحذير من انخفاض ضغط الهواء يعمل بشكل صحيح قبل أن أقود. أي إجراء يختبره بشكل صحيح؟","options":["شغّل المحرك ودع المنظّم يضخّ حتى ينفتح صمام تنفيس الأمان، ثم استمع إلى الجرس","اضغط على دوّاسة الفرامل بقوة وثبّتها لمدة دقيقة وراقب المؤشر بحثاً عن ارتفاع مفاجئ في الضغط","اسحب مقبض فرامل الركن الأصفر وتأكّد من أن فرامل النابض تنطبق قبل أن يعمل التحذير","مع إيقاف المحرك، اضغط على دوّاسة الفرامل وحرّرها لتفريغ الهواء وراقب التحذير عند 60 psi"],"explanation":"مع إيقاف المحرك، اضغط على دوّاسة الفرامل لتفريغ الهواء من الخزانات وتأكّد من أن التحذير من انخفاض الهواء يعمل قبل أن ينخفض الضغط دون 60 psi."},"116":{"q":"أقود شاحنة مستقيمة مفردة بنظام فرامل هوائية قياسي عندما يبدأ ضاغط الهواء لديّ بالتعطّل ويستمر الضغط في الانخفاض. لقد كان ضوء وجرس التحذير من انخفاض الهواء يعملان منذ فترة، وأنا أتباطأ للتوقّف على جانب الطريق. عند أي ضغط تقريبي ينبغي أن أتوقّع أن تنطبق فرامل النابض (الركن) من تلقاء نفسها وتوقف الشاحنة، باستثناء ما إذا كنت قد ركنت بالفعل؟","options":["في مكان ما ضمن نطاق 20 إلى 45 psi","أقل بقليل من 60 psi، النقطة نفسها التي يعمل عندها ضوء التحذير","حوالي 100 psi، عندما يعيد المنظّم التشغيل عادة","حوالي 125 psi، عندما يفصل المنظّم عادة"],"explanation":"تُبقى فرامل النابض (الركن/الطوارئ) في وضع التحرير بفعل الهواء وتنطبق تلقائياً عندما ينخفض الضغط إلى نطاق 20 إلى 45 psi."},"117":{"q":"أثناء فحص ما قبل الرحلة، أنا على وشك إجراء اختبار معدّل تسرّب الهواء على مركبتي المفردة. لقد شغّلت المحرك ويقرأ مؤشر الهواء حالياً حوالي 90 psi ولا يزال يرتفع. قبل أن أبدأ توقيت انخفاض الضغط، ما الذي يجب أن أفعله أولاً ليكون الاختبار صالحاً؟","options":["اضغط على دوّاسة الفرامل عدة مرات لتفريغ الخطوط حتى ضغط إعادة التشغيل، ثم ابدأ التوقيت","دع النظام يستمر في البناء حتى يفصل المنظّم عند حوالي 125 psi، ثم أوقف المحرك","فرّغ جميع خزانات الهواء بالكامل لأقيس الفقدان من نظام جديد فارغ","طبّق فرامل الركن وزِد دوران المحرك حتى ينفتح صمام تنفيس الأمان عند حوالي 150 psi"],"explanation":"يجب إجراء اختبار تسرّب الهواء والنظام مشحون بالكامل حتى نقطة فصل المنظّم عند حوالي 125 psi والمحرك متوقّف بحيث لا يستطيع الضاغط إخفاء أي تسرّب."},"118":{"q":"أثناء فحص ما قبل الرحلة على شاحنة مستقيمة (مفردة)، أُوقف المحرك، وأثبّت العجلات بالحواجز، وأشحن نظام الهواء بالكامل حتى نقطة فصل المنظّم. أترك فرامل الركن محرّرة وأراقب مؤشر لوحة القيادة لمدة دقيقة للتحقّق من التسرّبات. أي قراءة تخبرني أن التسرّب لا يزال ضمن الحد القانوني وأنه يمكنني المتابعة؟","options":["انخفاض يصل إلى 3 psi في تلك الدقيقة مقبول، لأن هذا هو حد التحرير لمركبة مفردة","أي انخفاض يُعدّ فشلاً؛ مع إيقاف المحرك وتحرير الفرامل يجب أن يبقى المؤشر ثابتاً تماماً","انخفاض لا يزيد عن 2 psi في تلك الدقيقة ضمن الحدود لهذا الفحص المفرد بفرامل محرّرة","انخفاض يصل إلى 4 psi في تلك الدقيقة جيّد لأن الفرامل محرّرة وليست مطبّقة"],"explanation":"بالنسبة لمركبة مفردة بفرامل محرّرة، فإن فقدان هواء لا يزيد عن 2 psi في الدقيقة يكون ضمن الحد المسموح به."},"119":{"q":"أثناء فحص ما قبل الرحلة على شاحنة صندوقية مستقيمة (مفردة)، شحنت النظام بالكامل حتى حوالي 125 psi، وأوقفت المحرك، وضغطت على دوّاسة الفرامل وثبّتها للأسفل. أنا الآن أراقب مؤشر الهواء لمدة دقيقة كاملة للتحقّق من معدّل التسرّب. لاجتياز هذا الاختبار، ينبغي ألّا يزيد انخفاض الضغط الذي ألاحظه عن:","options":["2 psi في تلك الدقيقة، لأن تثبيت الدوّاسة للأسفل هو المعيار نفسه لفحص الفرامل المحرّرة","4 psi في تلك الدقيقة، وهو الحد المسموح لشاحنة مستقيمة مفردة أن تفقده","10 psi في تلك الدقيقة، طالما لم يعمل تحذير انخفاض الهواء أثناء الاختبار","3 psi في تلك الدقيقة، الحد الأقصى المسموح به للفقدان لمركبة مفردة بفرامل مطبّقة"],"explanation":"مع تطبيق الفرامل، يجوز لمركبة مفردة أن تفقد ما لا يزيد عن 3 psi في الدقيقة وتبقى ضمن الحدود."},"120":{"q":"أثناء فحص ما قبل الرحلة، أسحب مُعدِّل الخلوص وألاحظ أنه يتحرّك أكثر من بوصة من الخلوص الحر، ما يخبرني أن الفرامل غير مضبوطة. إذا قدت دون إصلاح هذا، ما هي العاقبة الأمنية الأكثر مباشرة التي ينبغي أن أتوقّعها؟","options":["ستعمل الفرامل بشكل سيّئ لأن حركة قضيب الدفع الزائدة تقلّل قوة الكبح","سيعمل جرس التحذير من انخفاض ضغط الهواء قبل أن ينخفض الضغط دون 60 psi","سيفشل منظّم ضاغط الهواء في الفصل عند حوالي 125 psi","ستنطبق فرامل النابض تلقائياً بمجرد أن ينخفض الضغط إلى نطاق 20 إلى 45 psi"],"explanation":"تتسبّب مُعدِّلات الخلوص المرتخية أكثر من اللازم في حركة قضيب دفع زائدة، ما يقلّل قوة الكبح الواصلة إلى العجلات ويجعل الفرامل تعمل بشكل سيّئ."},"121":{"q":"أثناء فحص ما قبل الرحلة، أزحف تحت المقطورة وأطلب من مساعدي تثبيت الفرامل للأسفل بقوة بينما أراقب قضيب دفع حجرة الفرامل. أريد أن أعرف ما إذا كان مُعدِّل الخلوص لا يزال ضمن المواصفات. كم تقريباً يمكن أن يتحرّك قضيب الدفع ذاك قبل أن أعتبر الفرامل غير مضبوطة وأطلب صيانتها؟","options":["حوالي نصف قدم من الحركة قبل أن يخرج عن المواصفات","حوالي 1 inch من الحركة قبل أن يخرج عن المواصفات","حوالي 6 inches من الحركة قبل أن يخرج عن المواصفات","حوالي 2 feet من الحركة قبل أن يخرج عن المواصفات"],"explanation":"ينبغي ألّا تتجاوز حركة قضيب الدفع حوالي 1 inch عند تطبيق الفرامل بقوة؛ وضمن ذلك يبقى مُعدِّل الخلوص ضمن المواصفات."},"122":{"q":"أثناء فحص ما قبل الرحلة، أجد شرخاً دقيقاً يمتد عبر أحد طبول الفرامل وألاحظ أن حذاء الفرامل على تلك العجلة متآكل تقريباً حتى المسامير. لا يزال لديّ ضغط هواء كامل وتبدو الفرامل تنطبق جيّداً عندما أضغط على الدوّاسة. ماذا تعني هذه الحالة لمركبتي؟","options":["المركبة صالحة للقيادة طالما يبني الهواء حتى نقطة فصل المنظّم ويعمل تحذير انخفاض الهواء","الأمر مقبول الآن لأن الفرامل لا تزال تنطبق بثبات أثناء اختبار التوقّف عند 5 mph","المركبة خارج الخدمة ويجب عدم قيادتها حتى يتم إصلاح الطبل المشروخ والحذاء المتآكل","الأمر آمن في الظروف الجافة وينبغي تجنّبه فقط عند القيادة في المطر أو على طرق مبتلّة"],"explanation":"الطبل المشروخ أو الأحذية المتآكلة حتى المسامير تُعدّ حالة خروج تلقائي من الخدمة، ويجب عدم قيادة المركبة حتى يتم إصلاح تلك الأجزاء."},"123":{"q":"عندما تضغط على دوّاسة الفرامل بقوة أكبر، فإن الفرامل الهوائية:","options":["تتحرّر بالكامل","تطبّق قوة كبح أكبر","تتوقّف فوراً","تنفخ الإطارات"],"explanation":"الضغط بقوة أكبر يطبّق مزيداً من الهواء ومزيداً من قوة الكبح."},"124":{"q":"أنقل مقطورة محمّلة على طريق سريع مبتلّ بالمطر عندما تتوقّف حركة المرور فجأة أمامي. أضغط على دوّاسة الفرامل حتى الأرض وشاحنتي مزوّدة بنظام ABS. بناءً على ما صُمّم نظام ABS فعلياً للقيام به، ما الفائدة الواقعية التي ينبغي أن أتوقّعها منه في هذا التوقّف القوي؟","options":["سيقلّل مسافة توقّفي الإجمالية إلى ما هو أقل بكثير مما تحتاجه الشاحنة نفسها دون ABS","سيضخّ الفرامل بدلاً مني فلا أضطر أبداً لاستخدام الكبح المتقطّع على هذا السطح الزلق","سيُخفّض السرعة تلقائياً ويحافظ على ضغط الهواء فلا تنطبق فرامل النابض أبداً","سيمنع عجلاتي من القفل فأتمكّن من التوجيه لتفادي حركة المرور المتوقّفة"],"explanation":"لا يقصّر نظام ABS مسافة التوقّف؛ بل يمنع قفل العجلات أثناء الكبح القوي بحيث تحافظ على السيطرة على التوجيه للمناورة حول المخاطر."},"125":{"q":"أثناء فحص ما قبل الرحلة، أتتبّع مسار الهواء المضغوط من الخزانات نحو إحدى العجلات. أريد أن أجد المكوّن الوحيد الذي يتحوّل عنده ضغط الهواء المخزّن أخيراً إلى قوة دفع ميكانيكية تحرّك فعلياً وصلة الفرامل. أي مكوّن أبحث عنه؟","options":["حجرة الفرامل، لأنها تحوّل ضغط الهواء إلى القوة الميكانيكية التي تشغّل الفرامل","مُعدِّل الخلوص، لأنه الجزء الذي يندفع للخارج ليضغط البطانات على الطبل","ضاغط الهواء، لأنه مصدر الضغط الذي يشغّل الفرامل في النهاية","المنظّم، لأنه يتحكّم في ضغط الهواء المُرسَل إلى العجلة"],"explanation":"تحوّل حجرة الفرامل ضغط الهواء المضغوط إلى قوة ميكانيكية تدفع قضيب الدفع للخارج لتطبيق الفرامل."},"126":{"q":"أثناء فحص ما قبل الرحلة، أزحف تحت المقطورة لفحص مسافة حركة قضيب الدفع (pushrod) لأن الفرامل غير المضبوطة هي أكثر عيوب الفرامل الهوائية شيوعًا. أتتبع قضيب الدفع الخارج من حجرة الفرامل وأجده مثبتًا بالبراغي في أحد طرفي مُعدِّل الخلوص (slack adjuster). ولكي أفهم كيف تُحوِّل قوة الكبح فعليًا فرملة العجلة إلى وضع التشغيل، أحتاج أن أعرف ما الذي يُديره الطرف الآخر من مُعدِّل الخلوص. بأي مكوّن يربط مُعدِّل الخلوص قضيب الدفع؟","options":["وصلة دواسة الفرامل، بحيث يؤدي الضغط على الدواسة إلى سحب قضيب الدفع للخلف","الكامة على شكل حرف S (S-cam)، التي يُديرها لتباعد بطانات الفرامل ضد الطنبور","مُجفِّف الهواء، الذي يفتحه لتصريف الرطوبة من الحجرة","المنظِّم (governor)، الذي يُرسل إليه إشارة لإيقاف الضاغط عند 125 psi"],"explanation":"يُدير مُعدِّل الخلوص الكامة على شكل حرف S (S-cam)، التي تباعد بطانات الفرامل ضد الطنبور لإيقاف العجلة."},"127":{"q":"أثناء فحص ما قبل الرحلة، أفحص الفرامل عند كل عجلة من شاحنتي القاطرة والمقطورة وألاحظ كامة على شكل حرف S تدور لتدفع بطانات الفرامل للخارج ضد طنبور دوّار. يسألني الفاحص لماذا يجب أن أكون على دراية بهذا التصميم قبل أي شيء آخر. أي إجابة صحيحة؟","options":["إنه تصميم فرامل الأساس الوحيد الذي لا تزال إدارة FMCSA تسمح به على المركبات المجهزة بفرامل هوائية","إنه فرامل أساس من النوع الإسفيني (wedge-type)، وهو ما تُبنى به معظم المركبات المركّبة الثقيلة اليوم","إنه فرامل الطنبور بالكامة S (S-cam drum brake)، وهو تصميم فرامل الأساس الأكثر شيوعًا في مركبات الفرامل الهوائية","إنه فرامل أساس قرصية هوائية (air disc)، وهو النوع المستخدم في الغالبية الكبرى من الشاحنات على الطرق الآن"],"explanation":"الكامة على شكل حرف S التي تدور لدفع بطانات الفرامل ضد الطنبور تُحدِّد فرامل الطنبور بالكامة S (S-cam drum brake)، وهي فرامل الأساس الأكثر شيوعًا في مركبات الفرامل الهوائية."},"128":{"q":"أثناء فحص ما قبل الرحلة، يخبرني مدرّبي أنه عندما أضغط على دواسة الفرامل، يدفع ضغط الهواء إسفينًا يدفع بطانات الفرامل للخارج ضد جزء دوّار متصل بالعجلة، والاحتكاك بينهما يُبطئ المركبة. على أي جزء تضغط بطانات الفرامل لتوليد احتكاك الإيقاف هذا؟","options":["مُعدِّل الخلوص، الذي تضغط عليه البطانات لنقل قوة الكبح","حجرة الفرامل، التي تطبق عليها البطانات لتثبيت العجلة","خزان تخزين الهواء، الذي تضغط عليه البطانات لتحرير الضغط","طنبور الفرامل، الذي تضغط عليه البطانات لتوليد الاحتكاك"],"explanation":"تضغط بطانات الفرامل للخارج ضد طنبور الفرامل الدوّار، والاحتكاك بينهما يُبطئ المركبة ويوقفها."},"129":{"q":"أثناء فحص ما قبل الرحلة على قاطرة مفردة، أنتهي من شحن النظام الهوائي وأريد ضبط المركبة بحيث لا تتدحرج أثناء سيري حولها. وأنا أمدّ يدي نحو لوحة القيادة، أي مفتاح تحكم يجب أن أُشغِّل، وكيف؟","options":["أسحب للخارج المقبض الأصفر المعيّن الشكل لتطبيق فرامل الركن (الفرامل النابضية)","أسحب للخارج المقبض الأحمر الثُماني الأضلاع لتطبيق فرامل الركن (الفرامل النابضية)","أدفع للداخل المقبض الأصفر المعيّن الشكل لتطبيق فرامل الركن (الفرامل النابضية)","أضغط على دواسة الفرامل وأبقيها مضغوطة، فتقفل الفرامل النابضية ميكانيكيًا"],"explanation":"فرامل الركن (النابضية) هي المقبض الأصفر المعيّن الشكل الذي تسحبه للخارج للتطبيق وتدفعه للداخل للتحرير."},"130":{"q":"أتسلق إلى قاطرتي في أول الصباح، أُشغِّل المحرك، وأنا جاهز للانطلاق. لا يزال مقبض فرامل الركن الأصفر المعيّن الشكل مسحوبًا للخارج. قبل أن أدفع ذلك المقبض للداخل لتحرير فرامل الركن، أي شرط يجب أن أتأكد من تحققه؟","options":["أن يكون المحرك قد بلغ درجة حرارة التشغيل الطبيعية وارتفع مؤشر سائل التبريد خارج النطاق البارد","أن يكون ضغط الهواء قد تراكم إلى مستوى عالٍ بما يكفي ليصبح النظام مشحونًا بالكامل وينطفئ تحذير انخفاض الهواء","أن يكون ضغط الوقود قد استقر وامتلأت خطوط الحقن بالديزل بالكامل","أن يكون ضغط زيت المحرك قد ارتفع إلى النطاق الطبيعي بحيث تكون المحامل مُزيّتة بشكل صحيح"],"explanation":"تُحرَّر الفرامل النابضية بواسطة ضغط الهواء، لذا يجب أن يكون النظام مشحونًا بالكامل وتحذير انخفاض الهواء منطفئًا قبل تحرير فرامل الركن."},"131":{"q":"إذا تسرب الهواء بشدة من النظام أثناء القيادة، فإن الفرامل في النهاية:","options":["تتوقف عن العمل تمامًا","تنطبق من تلقاء نفسها","تزيد من سرعتك","تبقى محرّرة"],"explanation":"يؤدي الفقد الشديد للهواء إلى انطباق الفرامل النابضية من تلقاء نفسها."},"132":{"q":"إذا فقدت ضغط الهواء أثناء القيادة، فيجب أن:","options":["تستمر بزيادة السرعة","تتوقف بينما لا يزال بإمكانك ذلك","تضخّ الدواسة لتبقى متحركًا","تتجاهل التحذير"],"explanation":"توقف بأمان بينما لا يزال لديك قدرة على الكبح."},"133":{"q":"أقوم بفحص الفرامل الهوائية لما قبل الرحلة وأراقب مؤشر لوحة القيادة لاختبار المنظِّم (governor). أُفرغ الهواء بالضغط المتكرر على الفرامل، فيعود الضاغط للعمل ليبدأ إعادة بناء الهواء. عند أي قراءة تقريبية للمؤشر يجب أن أتوقع أن يبدأ المنظِّم بالتشغيل (CUT IN) ويستأنف الضاغط الضخ؟","options":["نحو 60 psi، تمامًا عندما يبدأ تحذير انخفاض الهواء بالظهور","نحو 125 psi، النقطة نفسها التي توقف عندها الضخ سابقًا","نحو 100 psi، أقل بقليل من النقطة التي توقف عندها","نحو 20 psi، تمامًا عندما تبدأ الفرامل النابضية بالانطباق"],"explanation":"يبدأ المنظِّم بالتشغيل لاستئناف الضخ عند نحو 100 psi، أقل بقليل من ضغط الإيقاف البالغ نحو 125 psi."},"134":{"q":"أثناء فحص ما قبل الرحلة على قاطرة ومقطورة بنظام فرامل هوائية مزدوج، أرفع دوران المحرك إلى تباطؤ سريع وأراقب مؤشر لوحة القيادة وهو يصعد. أريد التأكد من أن معدل بناء الهواء ضمن المواصفات. وأنا أراقب المؤشر يتجاوز 85 psi، خلال أي فترة يجب أن يكون قد وصل إلى 100 psi لكي يُعتبر بناء الهواء مقبولًا؟","options":["خلال نحو 3 ثوانٍ من تجاوز 85 psi","خلال نحو 30 ثانية من تجاوز 85 psi","خلال نحو 60 ثانية من تجاوز 85 psi","خلال نحو 45 ثانية من تجاوز 85 psi"],"explanation":"في نظام الفرامل الهوائية المزدوج، يجب أن يرتفع الضغط من 85 إلى 100 psi خلال نحو 45 ثانية، وإلا فإن في النظام مشكلة."},"135":{"q":"أثناء فحص ما قبل الرحلة، شحن الضاغط الهوائي خزان الإمداد (الخزان الرطب)، لكنني ألاحظ تسربًا بطيئًا يتطور في خط أسفل تيار خزان الخدمة. وهناك صمام فحص أحادي الاتجاه (one-way check valve) مُركّب بين الخزانين. مع تسرّب الهواء عبر ذلك الخلل، ما المهمة الرئيسية التي يؤديها صمام الفحص هذا من أجلي؟","options":["يمنع الهواء المخزّن مسبقًا في الخزان أعلى التيار من النزح للخلف خارجًا عبر القسم المتسرب","يمنع ضغط الهواء من التراكم إطلاقًا فوق نقطة التسرب حتى لا يزيد ضغط النظام أبدًا","يمنع الهواء المتسرب من الوصول إطلاقًا إلى حجرات الفرامل حتى تظل الفرامل تنطبق","يمنع الهواء المحبوس من البرودة والتجمّد داخل الخطوط أثناء التسرب"],"explanation":"يسمح صمام الفحص أحادي الاتجاه بتدفق الهواء في اتجاه واحد فقط، فيُغلق التسرب أسفل التيار بحيث لا يمكن للهواء المخزّن في الخزان أعلى التيار أن ينزح للخلف خارجًا."},"136":{"q":"أثناء فحص ما قبل الرحلة، أفتح صمامات التصريف على خزانات الهواء وألاحظ أن خزانًا واحدًا بالذات ممتلئ باستمرار بالماء وحمأة الزيت، أكثر بكثير من البقية. مع معرفتي كيف يوجّه النظام الهواء من الضاغط، أي خزان من المرجّح أن يكون هذا؟","options":["الخزان الجاف، لأنه يقع أسفل التيار وهو المكان الذي تتكثف فيه الرطوبة أخيرًا بعد التبريد","الخزان الرطب (خزان الإمداد)، لأنه يستقبل الهواء مباشرة من الضاغط وهو المكان الذي يتجمع فيه معظم الماء أولًا","خزان الوقود، لأن التكاثف من خطوط الهواء يتصرّف إليه طوال الليل","أي خزان مُركّب في أدنى موضع، لأن الجاذبية تسحب كل الماء المتراكم إليه"],"explanation":"يستقبل الخزان الرطب (خزان الإمداد) الهواء الساخن المحمّل بالرطوبة مباشرة من الضاغط، لذا يتكثف معظم الماء والزيت ويتجمع فيه أولًا."},"137":{"q":"أثناء فحص ما قبل الرحلة، أركن على أرض مستوية، أُسند العجلات بالموانع، أُطبّق فرامل الركن بسحب المقبض الأصفر المعيّن الشكل للخارج، ثم أزيل الموانع وأتحرك للأمام برفق ضد الفرامل بغيار منخفض. إذا كانت فرامل الركن تعمل بشكل صحيح، فماذا يجب أن يحدث؟","options":["يجب أن تزحف المركبة للأمام ببطء، مما يثبت أن الفرامل النابضية تحتفظ بضغط جزئي","يجب أن يُصدر جرس تحذير انخفاض الهواء صوتًا، مؤكدًا انطباق الفرامل النابضية بسبب انخفاض الضغط في موعده","يجب أن تبقى المركبة في مكانها ولا تتحرك، مما يُظهر أن فرامل الركن تثبّت المركبة في موضعها","يجب أن تثبت المركبة فقط بعد أن أضغط أيضًا على دواسة فرامل الخدمة وأبقيها مضغوطة بقوة"],"explanation":"تُطبق فرامل الركن النابضية السليمة قوتها الكاملة ويجب أن تثبّت المركبة ثابتة عندما تتحرك ضدها برفق بغيار منخفض."},"138":{"q":"أثناء فحص ما قبل الرحلة، أُحرّر فرامل الركن، أترك الحافلة تزحف للأمام إلى نحو 5 mph في ساحة مستوية، وأريد التأكد من أن فرامل الخدمة تعمل بشكل صحيح قبل الانطلاق. ماذا يجب أن أفعل عند هذه النقطة؟","options":["أضخّ دواسة الفرامل بسرعة عدة مرات وأستمع إلى تحرير الهواء في كل مرة","أُمسك الدواسة بخفة وأنزلق إلى توقف بطيء، مراقبًا أن مؤشر الهواء يبقى فوق 60 psi","أزيد السرعة أولًا إلى نحو 20 mph حتى أحصل على قراءة أكثر واقعية وشبيهة بالطريق السريع من الفرامل","أضغط على دواسة الفرامل بقوة وأتحقق من أن المركبة تتوقف بشكل مستقيم دون انحراف إلى أي جانب وأن الدواسة تبدو ثابتة"],"explanation":"يُوقِف نظام فرامل الخدمة السليم المركبة بشكل مستقيم دون انحراف إلى أي جانب، وتبدو الدواسة ثابتة وليست إسفنجية."},"139":{"q":"أثناء فحص الفرامل الهوائية لما قبل الرحلة، أتحرك للأمام بنحو 5 mph وأضغط على دواسة الفرامل. تتوقف الشاحنة بشكل مستقيم، لكن الدواسة تغوص منخفضة وتبدو ليّنة وإسفنجية تحت قدمي بدلًا من أن تكون ثابتة. ما الذي يجب أن أستنتجه من إحساس الدواسة هذا؟","options":["من المرجح أنه يشير إلى مشكلة في نظام الفرامل يجب فحصها قبل القيادة","إنه أمر طبيعي لأن الفرامل الهوائية تبدو دائمًا أليَن من الفرامل الهيدروليكية","يعني فقط أن ضغط الهواء فوق نقطة إيقاف المنظِّم البالغة 125 psi","يُظهر أن مُعدِّلات الخلوص قد امتصّت تلقائيًا الحركة الزائدة"],"explanation":"الدواسة الليّنة أو الإسفنجية التي تغوص منخفضة تشير إلى مشكلة في الفرامل مثل وجود هواء في الخطوط أو انخفاض الضغط أو تسرب يجب إصلاحه قبل القيادة."},"140":{"q":"أنهي فحص ما قبل الرحلة وأُشغِّل المحرك. يُضيء مصباح خلل نظام ABS على لوحة القيادة في البداية، لكنه لا ينطفئ أبدًا — يبقى مضاءً أثناء التباطؤ وبعد أن أبني الضغط الكامل. بناءً على هذا، ماذا يجب أن أستنتج عن نظام الكبح المانع للانغلاق لديّ؟","options":["المصباح يؤكد ببساطة أن الفحص الذاتي لنظام ABS قد جرى وأن النظام يعمل بكامل وظائفه","قد لا يعمل نظام ABS بشكل صحيح ويجب فحصه قبل القيادة","يشير المصباح فقط إلى انخفاض ضغط الهواء، لذا يكفي أن أدع المنظِّم يبني المزيد من الهواء","يعني المصباح أن الفرامل النابضية مُطبَّقة، لذا سينطفئ بمجرد تحرير مقبض الركن"],"explanation":"يجب أن يُضيء مصباح خلل ABS لفترة وجيزة عند بدء التشغيل ثم ينطفئ؛ وإذا بقي مضاءً، فقد يكون نظام ABS معطّلًا ويجب فحصه قبل القيادة."},"141":{"q":"أقود قاطرة ومقطورة محمّلة عندما يُضيء مصباح خلل نظام ABS على لوحة القيادة. لا تزال الفرامل تبدو طبيعية، لكنني قلق مما حدث للتو. أي مما يلي هو الوصف الأدق لحالة الكبح لديّ الآن؟","options":["لقد فقدت كل قدرة على الكبح ويجب أن أنزلق إلى توقف باستخدام المحرك والغيارات فقط","أصبحت مسافة توقفي الآن أقصر تلقائيًا، لذا يمكنني الكبح في وقت متأخر أكثر من ذي قبل","لا تزال لديّ فرامل الخدمة العادية ويمكنني إيقاف المركبة، لكن يجب أن أكبح بحذر لتجنب انغلاق العجلات","ستعمل فرامل الركن فقط، لذا يجب أن أسحب المقبض الأصفر للتوقف"],"explanation":"خلل ABS يُعطِّل فقط ميزة منع الانغلاق، لذا تبقى لديك فرامل الخدمة العادية كاملة لكن يجب أن تكبح بحذر لتجنب انغلاق العجلات."},"142":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ حركة مفرطة في قضيب الدفع عند إحدى حجرات الفرامل. قاطرتي مجهّزة بمُعدِّلات خلوص تلقائية، يقول زميل في العمل إنها 'خالية من الصيانة'، فيخبرني أنني لم أعد بحاجة للقلق بشأنها. أي عبارة تعكس الطريقة الصحيحة للتعامل مع مُعدِّلات الخلوص التلقائية؟","options":["لأنها تُعدِّل نفسها ذاتيًا، فإنها تُغني عن الحاجة لأي فحص أثناء فحص ما قبل الرحلة","يجب أن أُرخيها يدويًا أثناء القيادة حتى تختفي الخلوص الزائد","إنها تُلغي الفرامل غير المضبوطة، لذا فإن زميلي محق في أنه يمكن تجاهلها","لا يزال يجب فحصها بانتظام، لأن الفرامل غير المضبوطة عيب شائع حتى معها"],"explanation":"الفرامل غير المضبوطة هي أكثر عيوب الفرامل الهوائية شيوعًا، لذا حتى مُعدِّلات الخلوص التلقائية يجب فحصها بانتظام لأنها ليست معصومة من الخطأ."},"143":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ حركة مفرطة في قضيب الدفع على مُعدِّل خلوص، مما يخبرني أن الفرامل غير مضبوطة. أنا متأخر وأدوات الساحة هناك في المتناول. مَن الذي يجب فعليًا أن يقوم بضبط الفرامل قبل أن تخرج هذه المركبة إلى الطريق؟","options":["فقط شخص مدرّب ومؤهل لضبط الفرامل","أي حامل لرخصة CDL حالية، لأن حمل الرخصة يثبت الكفاءة في الفرامل","أنا، الآن، لأن حركة قضيب الدفع بسيطة لإعادة ضبطها بأدوات الساحة","أي شخص أقرب ومتاح حتى لا تتأخر المركبة أكثر"],"explanation":"لأن الفرامل غير المضبوطة تقلل مباشرة من قوة الكبح، يجب أن يقوم بضبط الفرامل فقط شخص مدرّب ومؤهل للقيام بهذا العمل."},"144":{"q":"أقود قاطرتي ومقطورتي عندما يُضيء ضوء تحذير انخفاض ضغط الهواء، وأدرك بسرعة أن الضاغط الهوائي قد توقف عن الضخ تمامًا. هناك مخرج بكتف آمن قادم خلال نحو ميل واحد. بافتراض أن نظامي كان مشحونًا بالكامل، ما الذي يتيح لي الهواء الاحتياطي في خزاناتي الاعتماد على فعله؟","options":["الاستمرار في القيادة بشكل طبيعي ليوم كامل من الرحلات، لأن الخزانات تخزن إمداد يوم كامل","إجراء عدة عمليات كبح إضافية للتباطؤ والانعطاف بأمان قبل أن ينفد الهواء","القيادة إلى ما لا نهاية، لأن الفرامل النابضية ستستمر في إعادة شحن خزانات الخدمة لي","الحصول على قدرة كبح غير صالحة عمليًا، لذا يجب أن أخرج فورًا عن الطريق في مكاني الحالي"],"explanation":"تحتفظ خزانات الهواء باحتياطي من الهواء المضغوط بحيث يمكنك، حتى بعد توقف الضاغط، إجراء عدة عمليات كبح إضافية للانعطاف بأمان."},"145":{"q":"إنه صباح شتوي متجمد، وتذكّرني قائمة فحص ما قبل الرحلة بتصريف خزانات الهواء يوميًا حتى لا يتجمع الماء وزيت الضاغط ويتجمّد النظام. أقف تحت القاطرة باحثًا عن المكوّنات الصحيحة لفتحها. أي جهاز أُشغّله فعليًا لتصريف الماء المتراكم من خزانات الهواء؟","options":["صمام تنفيس الأمان، الذي أفتحه قليلًا بيدي لتنفيس الرطوبة من خزان الإمداد","المقبض الأصفر المعيّن الشكل في المقصورة، الذي أسحبه للخارج لتحرير الماء من الخزانات","صمامات التصريف، التي تُسمى أيضًا الصنابير الصغيرة (petcocks)، الموجودة في أسفل كل خزان هواء","منظِّم الضاغط الهوائي، الذي أعيد ضبطه فيدفع الماء المحبوس للخارج"],"explanation":"تُصرَّف خزانات الهواء باستخدام صمامات التصريف، التي تُسمى أيضًا الصنابير الصغيرة (petcocks)، الموجودة في أسفل كل خزان لإزالة الماء والزيت المتجمعين."},"146":{"q":"أنت تقود شاحنة مستقيمة محمّلة بفرامل هوائية على طريق ريفي في تكساس عندما يُضيء ضوء تحذير انخفاض الهواء ويدوّي الجرس. المؤشر ينخفض عبر نطاق الضغط المنخفض. أي إجراء صحيح؟","options":["استمر في القيادة بسرعة مخفّضة إلى المخرج التالي، لأن الفرامل النابضية لم تنطبق بعد ولا يزال لديك بعض الهواء","استمر في القيادة لكن اضخّ دواسة الفرامل بضع مرات لمساعدة الضاغط على إعادة بناء ضغط الهواء المفقود أسرع","حافظ على سرعتك وتجاهل الإنذار في الوقت الحالي، لأن التحذير غالبًا ما يظهر للحظة ويزول من تلقاء نفسه بمجرد تشغيل المنظِّم","توقف بمجرد أن يكون ذلك آمنًا واخرج عن الطريق، لأن استمرار انخفاض الضغط قد يؤدي إلى فقد مفاجئ وخطير للكبح"],"explanation":"عندما يظهر تحذير انخفاض الهواء مع انخفاض الضغط، توقف واخرج عن الطريق بمجرد أن يكون ذلك آمنًا، لأن استمرار الفقد قد يسبب فشلًا مفاجئًا في الفرامل."},"147":{"q":"أقوم بفحص ما قبل الرحلة على قاطرتي ومقطورتي، ويذكر ميكانيكي أن أضواء الفرامل (التوقف) لا تُضيء إلا عندما أضغط فعليًا على دواسة الفرامل بقوة كافية. في مركبة بفرامل هوائية، ما الذي يُشغِّل فيزيائيًا مفتاح ضوء التوقف الكهربائي ليُضيء أضواء الفرامل؟","options":["تراكم ضغط الهواء في خطوط الفرامل عند الضغط على الدواسة يُغلق مفتاح ضوء التوقف","الحركة الميكانيكية لدواسة الفرامل تدفع المفتاح للإغلاق مباشرة، تمامًا كما في السيارة","انخفاض ضغط الهواء الذي يحدث عند بدء تحرير الفرامل النابضية يُغلق المفتاح","الحرارة المتولدة عند طنابير الفرامل تُرسل إشارة للمفتاح لتشغيل أضواء التوقف"],"explanation":"في الفرامل الهوائية يكون مفتاح ضوء التوقف كهربائيًا ويعمل بالهواء؛ فارتفاع ضغط الخط عند الضغط على الدواسة يُغلقه ويُضيء أضواء الفرامل."},"148":{"q":"أتسلق إلى قاطرتي ومقطورتي في أول صباح بارد، أُشغِّل المحرك، وأستعد لتحرير الفرامل النابضية والانطلاق. قبل أن أدفع مقبض فرامل الركن الأصفر للداخل لتحرير الفرامل النابضية والقيادة، ما الذي يجب أن يكون صحيحًا بشأن ضغط الهواء في نظامي؟","options":["انطفأ ضوء وجرس تحذير انخفاض الهواء للتو، لذا فإن أي ضغط فوق تلك النقطة يكفي للتحرير والقيادة","يجب أن يتراكم الضغط أولًا إلى مستوى عالٍ بما يكفي، إلى نطاق التشغيل الطبيعي قرب نقطة إيقاف المنظِّم، قبل تحرير الفرامل النابضية","يحتاج الضغط فقط إلى الصعود مجددًا فوق نطاق 20 إلى 45 psi حيث تنطبق الفرامل النابضية، ثم يمكنني التحرير والانطلاق","يجب تخفيض الضغط إلى أدنى مستوى ممكن حتى تنطلق الفرامل النابضية بسهولة، ثم أُحرّر المقبض"],"explanation":"تُبقى الفرامل النابضية محرّرة بواسطة الهواء، لذا يجب أن يتراكم الضغط أولًا إلى نطاق التشغيل الطبيعي قرب نقطة إيقاف المنظِّم قبل أن تتحرر."},"149":{"q":"أنقل مقطورة محمّلة على منحدر طويل وحاد وكنت أعتمد على الفرامل بكثافة طوال الطريق. قرب الأسفل ألاحظ أن طنابير الفرامل قد أصبحت ساخنة جدًا. ما التأثير الأرجح لهذا الإفراط في السخونة على فراملي الهوائية؟","options":["تضغط الطنابير المتمددة بإحكام أكبر ضد البطانات، مما يمنحني كبحًا أقوى بشكل ملحوظ","تُجفِّف الحرارة أي رطوبة في الخطوط، فتستجيب الفرامل بشكل أسرع وأثبت","ستضعف الفرامل (brake fade)، أي أنه عليّ الضغط بقوة أكبر فأكبر للحصول على قوة توقف أقل","لا شيء يتغير أثناء الحركة، لكن الطنابير الساخنة ستتشقق لحظة توقفي وركني"],"explanation":"تفقد طنابير الفرامل شديدة السخونة قدرتها على تحويل الحركة إلى حرارة، فتضعف الفرامل وعليك الضغط بقوة أكبر للحصول على قوة توقف أقل."},"150":{"q":"أقود قاطرة ومقطورة على الطريق السريع عندما تنفصل المقطورة فجأة وتتمزق خطوط الهواء فيها، مُفرِّغة كل الهواء في جانب المقطورة. أي جهاز مُصمَّم لإغلاق وحماية إمداد الهواء في قاطرتي بحيث يبقى لديّ هواء كافٍ للتحكم في القاطرة نفسها وإيقافها؟","options":["صمام التتابع (relay valve)، الذي يُسرّع تطبيق الفرامل بإرسال الهواء إلى الفرامل الخلفية لحظة الضغط على الدواسة","صمام التحرير السريع (quick-release valve)، الذي يُفرّغ الهواء المحبوس بسرعة فتتحرر الفرامل لحظة رفع القدم عن الدواسة","صمام القدم (foot valve / treadle)، الذي يتحكم في مقدار ضغط هواء الكبح الذي أُرسله عند الضغط على الدواسة","صمام حماية القاطرة (tractor protection valve)، الذي يُغلق إمداد هواء القاطرة لإبقاء هواء كافٍ لكبح وتوجيه القاطرة"],"explanation":"إذا انفصلت المقطورة أو تسرّبت بشدة، يُغلق صمام حماية القاطرة تلقائيًا إمداد هواء القاطرة بحيث يبقى لديك ما يكفي لكبحها وتوجيهها."},"151":{"q":"لقد انتهيت للتو من وصل الجرار بمقطورة محملة، ووصلت خطوط الهواء، وبنيت ضغط النظام حتى نقطة فصل المنظم. قبل أن تتمكن من تحريك المقطورة، تمد يدك نحو المقبض الأحمر ثماني الأضلاع الموجود على لوحة القيادة. ماذا يحقق دفع هذا المقبض إلى الداخل؟","options":["يشحن نظام فرامل المقطورة عن طريق إرسال الهواء من الجرار إلى المقطورة","يضبط فرامل النابض في المقطورة لتبقى المقطورة في وضع الركن","يحرر فرامل ركن الجرار فقط بينما تبقى المقطورة مقفلة","يفرغ خطوط هواء المقطورة لاختبار جرس تحذير انخفاض الهواء"],"explanation":"دفع المقبض الأحمر ثماني الأضلاع الخاص بإمداد هواء المقطورة إلى الداخل يفتح خط الإمداد ويرسل الهواء من الجرار لشحن نظام فرامل المقطورة."},"152":{"q":"أنا أقطر مقطورة محملة عندما يبدأ تسرب في خط الإمداد بتفريغ الهواء لدي. مع استمرار انخفاض المقياس، أريد أن أعرف النقطة التي سيُغلق عندها صمام حماية الجرار من تلقاء نفسه ليعزل هواء الجرار ويحمي ما تبقى في النظام. عند أي ضغط تقريبًا يحدث هذا الإغلاق التلقائي؟","options":["عند حوالي 60 psi، وهي نفس النقطة التي يضيء عندها أول مرة ضوء وجرس تحذير انخفاض ضغط الهواء","في نطاق 20 إلى 45 psi، بعد أن يكون التحذير قد استمر لبعض الوقت","عند حوالي 100 psi، وهو المستوى الذي يأمر فيه المنظم الضاغط بالعمل واستئناف الضخ","عند حوالي 150 psi، وهو المستوى الذي يفتح عنده صمام تنفيس الأمان في خزان الإمداد"],"explanation":"يُغلق صمام حماية الجرار تلقائيًا عندما ينخفض ضغط الهواء إلى نطاق 20 إلى 45 psi، بعد أن يكون تحذير انخفاض الهواء قد عمل لبعض الوقت بالفعل."},"153":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن حجرات الفرامل الخلفية في مقطورتي مثبتة بعيدًا إلى الخلف، على مسافة طويلة من خط الهواء بعيدًا عن صمام فرامل القدم في المقصورة. يسألني متدرب لماذا لا يستغرق الضغط على دواسة الفرامل وقتًا أطول بشكل ملحوظ لتطبيق تلك الفرامل الخلفية البعيدة مقارنة بالأمامية، نظرًا لكل تلك المسافة الإضافية التي يجب أن يقطعها الهواء. ما هو التفسير الصحيح؟","options":["تطبَّق الفرامل الخلفية فعليًا بشكل أبطأ بسبب المسافة، ولهذا تستخدم الفرامل الهوائية تأخيرًا مدمجًا قدره 5 ثوانٍ للتعويض عن المسار الطويل لخط الهواء","ترتبط الحجرات الأمامية والخلفية بصمام موازنة يؤخر الفرامل الأمامية عمدًا بحيث يتحرر المحوران في نفس اللحظة بالضبط","يستخدم صمام تتابع مثبت بالقرب من الحجرات الخلفية إشارة هواء محلية لتطبيق تلك الفرامل بسرعة، بدلًا من انتظار الهواء من الدواسة","يحتفظ صمام فرامل النابض بضغط إضافي في الخلف بحيث يمكن تطبيق تلك الفرامل قبل وصول الهواء من الدواسة إلى هناك"],"explanation":"يطبّق صمام التتابع المثبت بالقرب من الحجرات الخلفية تلك الفرامل من إشارة هواء محلية، مما يسرّع الكبح الخلفي بدلًا من انتظار الهواء من الدواسة."},"154":{"q":"أقوم بفحص قبل الرحلة وألاحظ أن نظام الفرامل الهوائية لدي يتضمن صمام تحرير سريع مثبتًا على المحور الأمامي، بالقرب من حجرات الفرامل. يطلب مني ميكانيكي أن أشرح ما الذي يفعله هذا المكوّن فعليًا للفرامل أثناء التشغيل العادي. أي عبارة تصف الغرض منه بشكل صحيح؟","options":["يبطئ معدل وصول الهواء إلى حجرات الفرامل بحيث تُطبَّق الفرامل بلطف وسلاسة أكبر","يحتفظ بضغط الهواء المتبقي في الحجرات بحيث تبقى فرامل النابض مقفلة بعد أن أركن","يصرّف زيت الضاغط والماء من الخطوط لمنع تجمد الفرامل الأمامية","يسمح للهواء بالخروج من حجرات الفرامل بسرعة بحيث تتحرر الفرامل أسرع عندما أرفع قدمي عن الدواسة"],"explanation":"يسمح صمام التحرير السريع للهواء بالخروج من حجرات الفرامل القريبة منه في اللحظة التي ترفع فيها قدمك عن الدواسة، فتتحرر الفرامل أسرع ولا تجرّ."},"155":{"q":"تعطلت حجرة فرامل نابض في شاحنتي المركونة ولن تتحرك الشاحنة، لكن سيارة سحب تحتاج إلى قطرها مسافة قصيرة خارج الطريق السريع. مع عدم توفر هواء لتحرير الفرامل بالطريقة المعتادة، أي إجراء سيحرر العجلات بحيث يمكن قطر الوحدة؟","options":["تقفيص فرامل النابض يدويًا (لفها ميكانيكيًا للخلف) في الحجرة المتأثرة","ضخ النظام حتى يصل المقياس إلى حوالي 125 psi لتحريرها","دفع مقبض الركن الأصفر المعيّن الشكل لإطلاق النوابض","فصل خطوط الهواء وقطعها بحيث لا تستطيع الحجرات الاحتفاظ بالضغط"],"explanation":"تُطبَّق فرامل النابض بواسطة النوابض وتُبقى محررة بواسطة الهواء، لذا عند تعطل الحجرة فإن الطريقة الوحيدة لتحريرها للقطر هي تقفيصها يدويًا بمسمار التقفيص."},"156":{"q":"على طريق سريع مبلل وزلق في جراري ذي الفرامل الهوائية، يخبرني سائق آخر أنه يجب علي فصل أو تخفيف فرامل العجلات الأمامية لأنها تتسبب في انزلاق إطارات التوجيه وتجعل الشاحنة أصعب في السيطرة عليها تحت المطر. وفقًا لدليل CDL في تكساس، كيف ينبغي أن أتعامل مع فرامل عجلاتي الأمامية؟","options":["يجب فصل فرامل العجلات الأمامية على الطرق المبللة لأن كبح إطارات التوجيه يسبب انزلاق المقدمة وفقدان التوجيه","فرامل العجلات الأمامية مهمة وضرورية للتوقف العادي، ولا يوجد خطر انزلاق بسببها","فرامل العجلات الأمامية مفيدة فقط للمظهر وتضيف قوة توقف فعلية قليلة، لذا فإن تركها ضعيفة أمر مقبول","من الأفضل ترك فرامل العجلات الأمامية غير مضبوطة بحيث تقوم الفرامل الخلفية بمعظم العمل وتدوم الإطارات الأمامية لفترة أطول"],"explanation":"توفر فرامل العجلات الأمامية قوة توقف حقيقية وضرورية، والاعتقاد بأنها تسبب الانزلاق خرافة، لذا يجب أن تعمل دائمًا بشكل سليم."},"157":{"q":"أنا أنقل حمولة على طريق سريع مبلل بحارتين وألاحظ أن فراملي الأمامية تعمل بجهد أثناء التوقف. أخبرني سائق مخضرم ذات مرة بفصل أو تجنب استخدام الفرامل الأمامية لأنها تتسبب في انزلاق الشاحنة على الأسطح الزلقة. قبل أن أتصرف بناءً على تلك النصيحة، أي عبارة تعكس ما يقوله دليل CDL في تكساس فعليًا عن كبح العجلات الأمامية؟","options":["إنه محق — الفرامل الأمامية هي السبب الرئيسي للانزلاقات، لذا يجب أن تبقيها مفصولة كلما كان الطريق مبللًا.","إنه محق، لكن فقط فوق 55 mph — تحت تلك السرعة يكون استخدام الفرامل الأمامية آمنًا بشكل طبيعي.","إنه مخطئ — فكرة أن الفرامل الأمامية تسبب الانزلاقات خاطئة، وتحصل على أفضل كبح عندما تعمل جميع الفرامل معًا.","إنه محق جزئيًا — الفرامل الأمامية جيدة على الطرق الجافة لكن لا ينبغي الاعتماد عليها لقوة التوقف في أي ظرف."],"explanation":"الاعتقاد بأن الفرامل الأمامية تسبب الانزلاقات خاطئ؛ تحصل على أفضل قوة توقف وأكثرها توازنًا عندما تعمل جميع الفرامل معًا."},"158":{"q":"أنا أنقل حمولة بسرعة 55 mph على طريق تكساس سريع جاف عندما أرى مركبة متوقفة أمامي وأضغط على دواسة الفرامل بقوة. يذكّرني مدربي بأن فراملي الهوائية بها تأخير مدمج قبل أن تمسك فعليًا، لذا تستمر الشاحنة في التدحرج مسافة إضافية أثناء نصف الثانية من التأخير قبل أن تبدأ العجلات حتى في التباطؤ. كم تقريبًا من مسافة التوقف الإضافية يضيفها تأخير الفرامل هذا عند 55 mph؟","options":["حوالي 2 feet، لأن تأخير نصف الثانية أقصر من أن يهم كثيرًا عند سرعة الطريق السريع","حوالي 300 feet، لأن هذا التأخير هو ما يجعل الفرامل الهوائية تتوقف أبطأ بكثير من الهيدروليكية","حوالي 1 mile، لأن الهواء يجب أن يقطع كامل الطول عبر الخطوط قبل أن يبدأ أي كبح","حوالي 32 feet، وهي المسافة التي تقطعها الشاحنة خلال نصف الثانية من تأخير الفرامل عند 55 mph"],"explanation":"للفرامل الهوائية تأخير قدره حوالي نصف ثانية، لذا عند 55 mph تقطع الشاحنة حوالي 32 feet قبل أن تبدأ الفرامل في الإمساك."},"159":{"q":"أنا أراجع ملاحظاتي لرخصة CDL وقد حسبت بالفعل ثلاثة من الأجزاء الأربعة التي تشكل إجمالي مسافة توقف الفرامل الهوائية: مسافة الإدراك، ومسافة رد الفعل، ومسافة تأخير الفرامل. أي جزء لا يزال ناقصًا من الإجمالي؟","options":["مسافة الكبح الفعلية، وهي المسافة المقطوعة بمجرد أن تمسك الفرامل فعليًا وتبطئ المركبة","مسافة التوجيه الفعلية، وهي المساحة الإضافية التي يحتاجها نظام ABS لمنع العجلات من القفل","مسافة بناء ضغط الضاغط، المقطوعة بينما يضخ المنظم الضغط مرة أخرى حتى نقطة الفصل","مسافة مُعدِّل الخلوص، المقطوعة بينما يُستهلك خلوص قضيب الدفع الزائد قبل الكبح"],"explanation":"إجمالي مسافة توقف الفرامل الهوائية هو الإدراك زائد رد الفعل زائد تأخير الفرامل زائد مسافة الكبح الفعلية، وهي المسافة المقطوعة بعد أن تعمل الفرامل."},"160":{"q":"أنا أقطر شاحنة مركّبة محملة على منحدر جبلي طويل وحاد وأشعر بالجاذبية تدفع الشاحنة أسرع. ترتفع درجات حرارة الفرامل الهوائية كلما طال النزول. للحفاظ على هذه المركبة تحت السيطرة حتى أسفل المنحدر، ما هي تقنية الكبح الصحيحة؟","options":["البقاء في ترس أعلى ليعمل المحرك بسلاسة أكبر، والضغط على دواسة الفرامل بقوة وباستمرار لإبقاء سرعتي منخفضة","اختيار ترس منخفض قبل النزول واستخدام ضغط فرامل خفيف وثابت، مع التحرير عند الانخفاض حوالي 5 mph تحت سرعتي الآمنة ثم إعادة التطبيق","ضخ أو 'تهوية' دواسة الفرامل بسرعة بالتشغيل والإيقاف بحيث تتاح للفرامل فرصة التبريد بين التطبيقات","التحويل إلى الوضع المحايد لتوفير المحرك والضغط الخفيف على الفرامل فقط عندما تبدأ الشاحنة تشعر وكأنها تفلت"],"explanation":"اختر ترسًا منخفضًا قبل النزول واستخدم كبحًا خفيفًا وثابتًا، مع التحرير عند حوالي 5 mph تحت سرعتك الآمنة وإعادة التطبيق مع تزايد السرعة."},"161":{"q":"أنا آخذ شاحنتي المحملة أسفل منحدر جبلي طويل. لقد اخترت بالفعل ترسًا منخفضًا، ويخبرني المدرب باستخدام الكبح 'المتقطع' السليم للتحكم في سرعتي. أي مما يلي يصف بشكل صحيح ما يجب أن أفعله؟","options":["تطبيق ضغط فرامل ثابت ومتواصل والإبقاء عليه طوال الطريق للأسفل للحفاظ على سرعة ثابتة","تهوية الفرامل بخفة بالتشغيل والإيقاف في نقرات سريعة بحيث يتاح لضغط الهواء وقت للتعافي بين الضغطات","تطبيق الفرامل بقوة كافية للتباطؤ حوالي 5 mph تحت سرعتي الآمنة، تحريرها، ثم إعادة التطبيق مع تزايد السرعة","التحويل إلى الوضع المحايد والضغط الخفيف على الفرامل بحيث لا يقاوم المحرك جهد الكبح"],"explanation":"الكبح المتقطع يعني تطبيق الفرامل بثبات للتباطؤ حوالي 5 mph تحت سرعتك الآمنة، تحريرها بالكامل، ثم إعادة تطبيقها مع تزايد السرعة."},"162":{"q":"أنا أقطر شاحنة مركّبة محملة وأرى لافتة تحذر من منحدر جبلي طويل وحاد أمامي. للتحكم بأمان في سرعتي بفراملي الهوائية أثناء النزول، متى ينبغي أن أختار الترس؟","options":["حوالي منتصف الطريق للأسفل، بمجرد أن أشعر بمدى حدة المنحدر فعليًا وبمدى سرعة اكتسابي للسرعة","فقط إذا بدأ المحرك يفرط في الدوران أو بدأت فراملي تتلاشى وأحتاج فعلًا إلى ترس أقل","قرب الأسفل، حيث يستوي الطريق ويمكنني التحويل لترس أقل دون إجهاد ناقل الحركة","قبل أن أبدأ النزول، بينما لا أزال على أرض مستوية ويمكنني التحويل دون إجبار صندوق التروس"],"explanation":"اختر ترسًا منخفضًا قبل أن تبدأ النزول، بينما لا تزال على أرض مستوية، لأن ناقل الحركة يصعب أو يستحيل تخفيضه بمجرد التدحرج بسرعة على منحدر حاد."},"163":{"q":"أثناء فحصي قبل الرحلة، أفحص فرامل شاحنة بمقطورة وألاحظ أن بطانات الفرامل (وسادات الحذاء) في إحدى العجلات قد تآكلت ووصلت إلى رقة خطيرة. كل شيء آخر في المركبة سليم. بموجب قواعد DPS، ماذا ينبغي أن أفعل قبل السماح لهذه المركبة بالعمل؟","options":["إبقاء المركبة خارج الخدمة حتى استبدال البطانات المتآكلة، لأن البطانات الرقيقة بشكل خطير تجعل المركبة غير آمنة للقيادة.","القيادة بشكل طبيعي مع ترك مسافة اتباع إضافية، لأن البطانات الرقيقة تقلل قوة الكبح قليلًا فقط.","ضخ دواسة الفرامل عدة مرات لإجلاس البطانات الرقيقة، ثم المتابعة إذا شعرت الدواسة بالصلابة.","المتابعة طالما بقي معدل تسرب الهواء تحت 3 psi في الدقيقة، لأن سُمك البطانة ليس جزءًا من فحص الفرامل."],"explanation":"البطانات المتآكلة لدرجة الرقة الزائدة هي حالة خارج الخدمة تلقائيًا، لذا يجب عدم قيادة المركبة حتى استبدال البطانات."},"164":{"q":"أثناء فحصي قبل الرحلة، أركن على أرض مستوية، وأضع أسافين تحت عجلاتي، وأحرر فرامل الركن، وأمسك مُعدِّل خلوص يدوي للتحقق من حركة قضيب الدفع الزائدة. أسحبه بقوة باليد. كم ينبغي أن يتحرك قبل أن أستنتج أن الفرامل مضبوطة بشكل سليم؟","options":["حوالي بوصة كاملة من الخلوص الحر هي الحد الأقصى المسموح به قبل الضبط","ينبغي أن يتحرك أقل من حوالي بوصة واحدة عند سحبه باليد","حوالي ست بوصات من الحركة لا تزال تشير إلى فرامل مضبوطة بأمان","ينبغي ألا يتحرك على الإطلاق، لأن أي حركة تعني أنه خارج الضبط"],"explanation":"عند سحبه بقوة باليد، ينبغي أن يتحرك قضيب مُعدِّل الخلوص اليدوي أقل من حوالي بوصة واحدة؛ والخلوص الأكبر يعني أن الفرامل خارج الضبط."},"165":{"q":"أنا أقود شاحنة بمقطورة محملة بفرامل هوائية وأقترب من علامة توقف عند أسفل منحدر طفيف. ألاحظ أنه عندما أضغط على دواسة الفرامل، يوجد تأخير قصير قبل أن تمسك الفرامل فعليًا، مقارنة بالفرامل الهيدروليكية في شاحنتي الصغيرة. لمراعاة هذا الفرق بأمان، متى ينبغي أن أبدأ تطبيق الفرامل؟","options":["عند نفس النقطة التي أفعلها في مركبة ذات فرامل هيدروليكية، لأن تأخير نصف الثانية أصغر من أن يهم","متأخرًا قليلًا عن المعتاد، لأن ضغط الهواء يبني قوة توقف إضافية بمجرد وصوله إلى الفرامل","قبل المعتاد قليلًا، لمراعاة تأخير الفرامل الهوائية البالغ حوالي نصف ثانية قبل أن تمسك الفرامل","فقط بعد أن تعمل فرامل المقطورة من تلقاء نفسها، ثم أضيف ضغط الدواسة لإنهاء التوقف"],"explanation":"بسبب تأخير الفرامل الهوائية البالغ حوالي نصف ثانية، ابدأ الكبح قبل المعتاد قليلًا بحيث لا يضيف التأخير إلى مسافة توقفك."},"166":{"q":"أنا آخذ شاحنة مركّبة محملة أسفل منحدر جبلي طويل وحاد وأبقي ضغطًا خفيفًا وثابتًا على دواسة الفرامل طوال الطريق للأسفل بدلًا من استخدام ترس منخفض. إبقاء الفرامل مطبقة باستمرار هكذا طوال النزول سيتسبب على الأرجح في أن فراملي:","options":["تبقى أبرد، لأن الضغط الثابت يوزع عبء العمل بالتساوي على جميع الأسطوانات","تكبح الشاحنة بشكل أفضل كلما طال إبقائها مطبقة على المنحدر","تتآكل ببطء أكبر لأن البطانات لا تتحرر تمامًا من الأسطوانات","تفرط في التسخين وتتلاشى، فاقدةً قوة التوقف التي أحتاجها قبل الأسفل"],"explanation":"جرّ الفرامل باستمرار طوال الطريق أسفل منحدر طويل يفرط في تسخينها ويسبب تلاشي الفرامل، فاقدةً قوة التوقف قبل الوصول إلى الأسفل."},"167":{"q":"لقد خضت للتو معبرًا مغمورًا منخفض المياه في شاحنتي المستقيمة ذات الفرامل الهوائية، وعلى الطريق الجاف أمامي ألاحظ أن فراملي تشعر بالضعف وتمسك بشكل غير متساوٍ عند أول توقف. ما هي الطريقة الصحيحة للتعامل مع الفرامل المبللة؟","options":["مواصلة الحركة بسرعة بطيئة مع تطبيق ضغط فرامل خفيف بلطف بحيث تجفّفها حرارة الاحتكاك","سحب مقبض فرامل الركن الأصفر وإبقاء فرامل النابض مضبوطة لدقيقة لعصر الماء منها","التسارع بقوة حتى الحد الأقصى بحيث يدور المحرك وسرعة العجلات لطرد الماء عن البطانات بسرعة","ضخ دواسة الفرامل بسرعة عدة مرات لدفع الماء المحتبس خارج الحجرات"],"explanation":"جفّف بطانات الفرامل المبللة بالقيادة ببطء مع تطبيق ضغط فرامل خفيف وثابت بحيث تبخّر حرارة الاحتكاك الماء وتستعيد الكبح المتساوي."},"168":{"q":"لقد سحبت شاحنتي إلى كتف حاد لانتظار إغلاق طريق. لقد ضبطت فرامل الركن، لكني قلق من أنها قد لا تثبت على هذا المنحدر لتوقف طويل. وفقًا للممارسة الآمنة للفرامل الهوائية، ما الخطوة الإضافية التي ينبغي أن أتخذها لمنع المركبة من التدحرج؟","options":["ترك المحرك يعمل في ترس منخفض بحيث يساعد ناقل الحركة في تثبيت الحمولة","وضع أسافين أمام الإطارات لمنع العجلات فيزيائيًا من التدحرج","ضخ دواسة الفرامل عدة مرات لبناء ضغط إضافي في فرامل النابض","سحب مقبض إمداد هواء المقطورة الأحمر لقفل عجلات المقطورة بقوة أكبر"],"explanation":"على المنحدر قد تتسرب فرامل الركن ببطء، لذا ضع أسافين تحت العجلات لمنع الإطارات فيزيائيًا كدعامة احتياطية ميكانيكية."},"169":{"q":"أثناء فحص المشي حول المركبة، تنصت عند الفرامل بحثًا عن:","options":["موسيقى صاخبة","تسربات هواء","الراديو","تغريد الطيور"],"explanation":"أنصت بحثًا عن تسربات الهواء عند الفرامل."},"170":{"q":"أثناء فحصي قبل الرحلة، أنحني عند العجلات لفحص مكونات الفرامل الهوائية في جراري. وبينما أتفحص أسطوانات الفرامل وأحذيتها، أي حالة ينبغي أن تجعلني أُخرج المركبة من الخدمة بدلًا من قيادتها؟","options":["يُظهر سطح الأسطوانة لمعانًا معدنيًا ناعمًا ولامعًا في كامل محيطه","لا تزال بطانات حذاء الفرامل تحتفظ بسُمك وافر متبقٍ عليها","يوجد في أسطوانة الفرامل تشققات تمتد عبر سطحها","يوجد طبقة خفيفة من غبار الطريق والأوساخ على وجه الأسطوانة"],"explanation":"أسطوانة فرامل بها تشققات عبر سطحها هي عيب يمكن أن يفشل تحت حرارة الكبح وقوته، مما يجعل المركبة غير آمنة للقيادة."},"171":{"q":"أقوم بفحص قبل الرحلة على جرار صُنع عام 2015. أثناء تتبع خطوط الفرامل، أجد صمامًا ينبض ويحرر ضغط الهواء تلقائيًا إلى عجلة فردية مئات المرات في الثانية لمنع تلك العجلة من القفل أثناء الكبح القوي. يصرّ زميل على أن هذا المكوّن ينتمي إلى نظام مختلف تمامًا في الشاحنة. إلى أي نظام ينتمي صمام المُعدِّل هذا فعليًا؟","options":["نظام الإمداد الهوائي المزدوج، لأنه يدوّر ضغط الهواء بين الخزانين الأساسي والثانوي","نظام فرامل الركن، لأنه يتحكم في كيفية عمل وتحرر فرامل النابض في كل عجلة","نظام فرامل الخدمة، لأنه يقيس مباشرة الهواء الذي يرسله السائق بدواسة الفرامل","نظام ABS (الكبح المانع للانغلاق)، لأن صمام المُعدِّل ينبض الضغط لمنع العجلات من القفل بحيث يمكنك التوجيه"],"explanation":"الصمام الذي ينبض الهواء إلى عجلة عدة مرات في الثانية لمنع القفل أثناء الكبح القوي هو صمام مُعدِّل ABS، الذي يحافظ على التوجيه."},"172":{"q":"أنا أصل جراري بمقطورة ولدي خطا هواء (وصلتا كف) لتوصيلهما: خط الخدمة وخط الإمداد/الطوارئ. للتأكد من أنني أمسك خط الإمداد الصحيح ولا أعبر وصلاتي، أي لون ينبغي أن أبحث عنه على خط الإمداد (الطوارئ)؟","options":["أحمر","أزرق","أصفر","أخضر"],"explanation":"خط هواء الطوارئ (الإمداد) للمقطورة أحمر، مطابقًا للمقبض الأحمر ثماني الأضلاع الخاص بإمداد هواء المقطورة في المقصورة."},"173":{"q":"أنا أصل جراري بمقطورة وأمد يدي نحو خطي الهواء الممتدين بين الوحدتين. أحدهما يحمل الإشارة التي تطبّق وتحرّر فرامل المقطورة عندما أضغط على دواسة الفرامل (خط الخدمة/التحكم)، والآخر يمدّ الهواء باستمرار لشحن خزانات المقطورة والتحكم في خط الطوارئ. أحتاج إلى إمساك الخط الصحيح لتوصيله بوصلة كف الخدمة. أي لون يحدد خط الخدمة (التحكم) الذي ينبغي أن أبحث عنه؟","options":["الخط الأحمر، لأن الأحمر يميّز الدائرة التي تحمل إشارة الكبح من دواستي إلى المقطورة","الخط الأزرق، لأن الأزرق يميّز خط الخدمة (التحكم) الذي يطبّق ويحرّر فرامل المقطورة","الخط الأسود، لأن الخرطوم محايد اللون هو المرتبط بفرامل القدم في معظم المركبات المركّبة","الخط البرتقالي، لأن اللون الأكثر سطوعًا يعلّم الخرطوم الذي يستجيب لدواسة الفرامل"],"explanation":"خط الخدمة (التحكم)، الذي يحمل إشارة دواسة الفرامل لتطبيق وتحرير فرامل خدمة المقطورة، أزرق اللون."},"174":{"q":"أنا أقطر مقطورة محملة على الطريق السريع بين الولايات عندما تنفصل المقطورة فجأة عن جراري ويتمزق خط إمداد الهواء. وبينما تتدحرج المقطورة بحرية من تلقاء نفسها، ماذا ينبغي أن يحدث لفرامل المقطورة؟","options":["تبقى محررة بالكامل، فتواصل المقطورة الانزلاق حتى يبطئها الاحتكاك","تتحرر فقط بعد أن أسحب مقبض إمداد هواء المقطورة الأحمر من المقصورة","تُطبَّق تلقائيًا لأن فقدان إمداد الهواء يفعّل فرامل الطوارئ في المقطورة","تنبض بالتشغيل والإيقاف بسرعة بنفس الطريقة التي يتفاعل بها نظام ABS"],"explanation":"إذا انفصلت المقطورة، فإن فقدان إمداد الهواء يجعل فرامل الطوارئ المحمّلة بالنوابض تُطبَّق تلقائيًا، فتوقف المقطورة الهاربة."},"175":{"q":"أنت تقود شاحنة بمقطورة مزودة بنظام ABS يعمل عندما تنحرف سيارة أمامك وتتوقف فجأة. تضغط على دواسة الفرامل بأقصى قوة لتجنب اصطدام من الخلف. ومع قيام نظام ABS بعمله أثناء هذا التوقف القوي، ما الذي يمكنك واقعيًا أن تتوقع القدرة على فعله؟","options":["الضغط على الدواسة حتى الأرضية والثقة بأن ABS سيقصّر بشكل ملحوظ مسافة توقفك الإجمالية","ضخ دواسة الفرامل بسرعة بحيث يدور ABS أسرع ويمسك بالطريق بقوة أكبر","إبقاء الدواسة مضغوطة لكن مع إبقاء عجلة القيادة مستقيمة تمامًا، لأن التوجيه أثناء التوقف القوي سيُبطل ABS","إبقاء الدواسة مضغوطة بثبات مع الاستمرار في التوجيه حول الخطر، لأن العجلات لن تقفل"],"explanation":"مع نظام ABS يمكنك الضغط على دواسة الفرامل بثبات والاستمرار في التوجيه حول الخطر، لأن النظام يمنع العجلات من القفل."},"176":{"q":"أقود مقطورة جرار قديمة بدون نظام منع انغلاق المكابح (ABS) عندما توقفت سيارة فجأة أمامي تماماً. لقد بدأت بالفعل بجهد كبح بالضغط القوي المتقطع (stab braking)، لكنني أحتاج إلى أسلوب ثانٍ لإيقاف الشاحنة بسرعة دون فقدان السيطرة. بخلاف الكبح بالضغط المتقطع، أي طريقة ينبغي أن أستخدمها للتوقف بأسرع ما يمكن؟","options":["الكبح المتحكم به، أي تطبيق المكابح بثبات دون السماح للعجلات بالانغلاق","الكبح بانغلاق العجلات، أي الضغط على الدواسة حتى النهاية بحيث تنزلق الإطارات إلى التوقف","ضخ المكابح بسرعة طوال الطريق للحفاظ على أقصى ضغط على العجلات","الكبح بالمحرك فقط، أي خفض السرعة بتعشيق غيار أقل وترك الدواسة بحيث تبطئك مجموعة نقل الحركة"],"explanation":"الكبح المتحكم به يعني تطبيق المكابح بأقصى قوة ممكنة دون انغلاق العجلات، لأن انغلاق العجلات يسبب الانزلاق وفقدان القدرة على التوجيه."},"177":{"q":"أقوم بفحص دوراني حول مركبتي المركبة وأريد التأكد من أن المقطورة تحتوي على نظام ABS يعمل قبل أن أنطلق إلى الطريق السريع. أصعد للفحص، لكن زميلاً يخبرني أنني أبحث في المكان الخاطئ عن مصباح مؤشر عطل نظام ABS. أين على المقطورة ينبغي أن أبحث فعلياً للعثور على مصباح تحذير ABS هذا؟","options":["في الأمام بالقرب من مسمار الارتكاز (kingpin)، حيث يضيء مصباح أخضر كلما كان نظام ABS للمقطورة مُفعّلاً وجاهزاً","في الجهة الخلفية اليسرى من المقطورة، حيث يشير مصباح عطل أصفر إلى وجود مشكلة في نظام ABS","على الباب الخلفي، حيث يضيء مصباح أحمر ليُظهر أن نظام ABS للمقطورة قد تعطل بالكامل","في الأعلى على سقف المقطورة، حيث يكون مصباح أزرق مرئياً للسائق في المرايا"],"explanation":"يُشار إلى عطل نظام ABS في المقطورة بمصباح أصفر مثبت في الجهة الخلفية اليسرى من المقطورة."},"178":{"q":"أنت تنقل مقطورة محمّلة على الطريق السريع I-35 عندما يضيء فجأة مصباح عطل ABS على المقطورة. الجرار الذي تقوده أحدث ونظام ABS الخاص به لا يزال يعمل بشكل طبيعي. مصباح العطل يخبرك فقط بأن نظام ABS للمقطورة قد تعطل. أي عبارة تصف على أفضل وجه ما يمكنك الاعتماد عليه لبقية هذه الرحلة؟","options":["بسبب تعطل نظام ABS للمقطورة، فقدت مكابح الخدمة في المقطورة ويجب أن تتوقف فوراً لتجنب انثناء المركبة (jackknife).","بسبب تعطل نظام ABS للمقطورة، أصبحت مسافة التوقف الآن أقصر مما كانت عليه قبل أن يضيء مصباح التحذير.","لأن نظام ABS فقط هو الذي تعطل، فلا تزال لديك مكابح خدمة طبيعية على المركبة بأكملها، لكن عجلات المقطورة قد تنغلق الآن أثناء الكبح الشديد.","لأن نظام ABS للمقطورة فقط هو الذي تعطل، فإن نظام ABS العامل في الجرار سيتولى تلقائياً التحكم في كبح عجلات المقطورة."],"explanation":"عطل نظام ABS يعطل وظيفة منع الانغلاق فقط، لذا تظل مكابح الخدمة الطبيعية تعمل، لكن العجلات المتأثرة قد تنغلق أثناء الكبح الشديد."},"179":{"q":"يُظهر مقياس ضغط التطبيق مقدار الهواء الذي:","options":["تخزّنه في الخزانات","ترسله إلى المكابح","تفقده بسبب التسريبات","تضيفه مع الزيت"],"explanation":"يُظهر ضغط الهواء المُطبّق على المكابح."},"180":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن لوحة المكابح الهوائية لديّ تحتوي على إبرتي ضغط منفصلتين بدلاً من واحدة. وبينما أترك المحرك يعمل، ترتفع كلتا الإبرتين حتى يفصل المنظّم (governor)، وتثبت كل واحدة عند قراءتها الخاصة. ماذا يخبرني وجود هاتين الإبرتين عن كيفية بناء هذه المركبة؟","options":["تحتوي على ضاغطي هواء، كل واحد يغذّي إبرة بشكل مستقل","إبرة تقرأ مكابح الخدمة والأخرى تقرأ مكابح الركن","تحتوي على منظّمين، فيفصل كل نظام عند ضغط مختلف بوحدة psi","إنه نظام مكابح هوائية مزدوج: نظام هواء أساسي ونظام ثانوي"],"explanation":"وجود إبرتين على اللوحة يعني نظام مكابح هوائية مزدوجاً مع نظامي هواء منفصلين، أساسي وثانوي، يتشاركان مجموعة واحدة من أدوات التحكم."},"181":{"q":"أنا أنقل مقطورة محمّلة عبر حركة المرور المتقطعة في المدينة، وبحكم العادة أُبقي قدمي اليسرى ترتكز بخفة على دواسة المكابح بين التوقفات لأتفاعل أسرع. يخبرني مدربي أن أرفع قدمي تماماً عن الدواسة كلما لم أكن أكبح فعلياً. ما السبب الرئيسي الذي يقدمه لهذا؟","options":["حتى الضغط الخفيف المستمر يُبقي المكابح مطبّقة جزئياً، مما يسخّنها ويُبليها قبل أوانها","إبقاء القدم على الدواسة يعطّل مكابح الزنبرك التلقائية إذا انخفض ضغط الهواء كثيراً","الارتكاز على الدواسة ينزف الهواء ببطء من خزان الإمداد ويُطلق تحذير انخفاض الهواء مبكراً","الضغط الخفيف على الدواسة يتجاوز المنظّم ويمنع الضاغط من إعادة العمل عند 100 psi"],"explanation":"ارتكاز قدمك على الدواسة يُبقي المكابح مطبّقة بخفة، مما يولّد احتكاكاً مستمراً يُسخّن البطانات ويُبليها قبل أوانها."},"182":{"q":"انتهى ميكانيكي للتو من استبدال غرفة مكابح متسربة في جراري، وأنا متوقف في ساحة الورشة بحمولة كاملة موصولة وعملية تسليم متأخرة. يقرأ مقياس الهواء حوالي 125 psi وتحذير انخفاض الهواء مُطفأ. قبل أن أنطلق إلى الطريق السريع، ماذا ينبغي أن أفعل أولاً؟","options":["أثق بعمل الميكانيكي وأندمج مباشرة في الطريق السريع، بما أن المقياس يقرأ بالفعل حوالي 125 psi","أختبر المكابح بسرعة منخفضة قبل القيادة، بما في ذلك توقف بدحرجة بطيئة عند حوالي 5 mph للتأكد من أنها تمسك وتسحب باستقامة","أنطلق وأركب المكابح بخفة لأول ميل لأترك الغرفة الجديدة تستقر في مكانها","أضخ دواسة المكابح عدة مرات في الساحة لنزف أي هواء من الخط الذي تم إصلاحه حديثاً"],"explanation":"بعد أي إصلاح للمكابح يجب أن تتحقق من المكابح بنفسك، بما في ذلك توقف بدحرجة بطيئة عند حوالي 5 mph للتأكد من أنها تمسك وتسحب باستقامة."},"183":{"q":"أثناء فحص قبل الرحلة، أزحف تحت جراري وألاحظ أن أحد مُعدّلات الخلوص (slack adjuster) على المحور الخلفي لديه حركة حرة (مسافة حركة عمود الدفع) أكبر بشكل ملحوظ من مُعدّل الخلوص على العجلة المقابلة لنفس المحور. أي مما يلي صحيح بشأن كيفية ضبط مُعدّلي الخلوص على ذلك المحور؟","options":["ينبغي ترك مُعدّل الخلوص على الجانب الأثقل حمولة أكثر ارتخاءً لموازنة وزن المقطورة","الاختلاف في الحركة الحرة بينهما أمر طبيعي وليس شيئاً يلزمني تصحيحه","يجب ضبط كلا مُعدّلي الخلوص على نفس المحور بشكل متساوٍ، لذا يجب تصحيح الحركة الحرة غير المتساوية","ينبغي إزالة أحدهما حتى يقوم المكبح المتبقي على ذلك المحور بكل العمل بالتساوي"],"explanation":"يجب أن يكون لكلا مُعدّلي الخلوص على نفس المحور حركة حرة متساوية، لذا فإن الحركة غير المتساوية عيب يجب تصحيحه قبل القيادة."},"184":{"q":"أثناء فحصي قبل الرحلة في صباح تكساس البارد، ألاحظ أن نظام المكابح الهوائية لديّ يحتوي على مُجفّف هواء مثبت بين الضاغط وخزانات الهواء. يحذّرني ميكانيكي أنه إذا تعطل هذا المكوّن يوماً، فسأكون أكثر عرضة بكثير لتجمّد خطوط المكابح والخزانات خلال الشتاء. بناءً على الوظيفة الرئيسية لمُجفّف الهواء، لماذا قد يسبب عطله مشكلة التجمّد هذه؟","options":["مُجفّف الهواء يضيف كمية صغيرة من الزيت لتشحيم الخطوط، وبدون ذلك الزيت ستتوقف الخطوط عن الحركة وتتجمد في الطقس البارد","مُجفّف الهواء يُسخّن الهواء المضغوط قبل وصوله إلى الخزانات، لذا إذا تعطل يتجمد الهواء البارد في النظام","مُجفّف الهواء يضغط الهواء حتى فصل المنظّم، وبدون ضغط كافٍ يتجمد الهواء المتبقي في الخطوط","مُجفّف الهواء يزيل الرطوبة من الهواء، لذا إذا تعطل يتجمع الماء في الخزانات والخطوط ويمكن أن يتجمد في درجات الحرارة الباردة"],"explanation":"مُجفّف الهواء يزيل الرطوبة من الهواء المضغوط، لذا إذا تعطل يتجمع الماء في الخزانات والخطوط ويمكن أن يتجمد في الطقس البارد."},"185":{"q":"لقد أنزلت للتو مقطورتي المحمّلة في الساحة وأقود جراري عائداً عبر المدينة بدون مقطورة موصولة (bobtailing). مقارنة بوقت كانت فيه المقطورة المحمّلة موصولة، ماذا ينبغي أن أتوقع بشأن كيفية تصرف هذه المركبة عندما أضطر للتوقف بشكل مفاجئ؟","options":["قد يكون التوقف أصعب بشكل مفاجئ، لذا أحتاج إلى مزيد من الحذر والمسافة لأن الجرار بدون مقطورة (bobtail) يتصرف بشكل مختلف أثناء الكبح","سيتوقف بشكل أسرع بكثير وفي مسافة أقصر، لذا يمكنني بأمان أن أتبع المركبات الأخرى عن قرب أكثر من السابق","لا يحتاج إلى أي انتباه خاص أثناء التوقف، بما أن إنزال المقطورة أزال الوزن وأصبحت مهمة المكابح سهلة الآن","سيتطلب جهد توجيه وتصحيحاً أقل أثناء التوقف لأن الجرار أصبح أخف وزناً بكثير بشكل عام"],"explanation":"الجرار بدون مقطورة (bobtail) قد يكون أصعب في التوقف لأن محاور الدفع لديه تحمل وزناً وثباتاً أقل بدون مقطورة، لذا اترك مزيداً من الحذر ومسافة التوقف."},"186":{"q":"أثناء فحص قبل الرحلة أزحف تحت جراري وأجد أن أحد خزانات الهواء يتحرك قليلاً على حامله لأن حزام تثبيت قد ارتخى. قبل أن آخذ هذه المركبة إلى الطريق، ما الطريقة الصحيحة لتثبيت خزان الهواء ذلك، ولماذا يهم ذلك؟","options":["بشكل مرتخٍ على أحزمة مرنة، حتى لا يتسبب اهتزاز الطريق والتواء الهيكل في تشقق لحامات الخزان","بإحكام على الإطار، حتى يبقى ثابتاً في مكانه ولا تتعرض الخطوط والوصلات للإجهاد أو الفشل","مع توجيه صمام التصريف للأعلى، حتى يبقى الماء والزيت المتجمعان بعيدين عن أجهزة التثبيت","عالياً على قضيب الإطار أو خلف المقصورة، حتى يصرّف الخزان للأمام بعيداً عن خطوط المكابح"],"explanation":"يجب تثبيت خزانات الهواء بإحكام على الإطار حتى تبقى ثابتة ضد الاهتزاز ولا تتعرض الخطوط والوصلات المتصلة بها للإجهاد أو التلف."},"187":{"q":"أثناء فحصي قبل الرحلة أنظر إلى مكبح أسطواني (drum brake) على المقطورة وألاحظ أنه يحتوي على مؤشر تآكل مكابح ميكانيكي. عندما يعطي هذا الجهاز قراءته، ماذا يخبرني فعلياً عن حالة بطانات المكابح؟","options":["أن البطانات امتصت الرطوبة وتحتاج إلى التجفيف قبل أن تمسك المكابح","أن مُعدّلات الخلوص قد وصلت إلى أقصى مسافة حركة مسموح بها لعمود الدفع وتحتاج إلى الضبط","أن البطانات قد تآكلت إلى الحد الذي تحتاج فيه إلى الاستبدال","أن البطانات مستقرة بشكل صحيح والمكابح آمنة للتشغيل في هذه الرحلة"],"explanation":"يُظهر مؤشر تآكل المكابح متى تآكلت بطانات المكابح إلى الحد الذي تحتاج فيه إلى الاستبدال."},"188":{"q":"انتهيت للتو من منحدر جبلي طويل وشديد بمركبتي المركبة المحمّلة، وأريد أن أتوقف في منطقة استراحة لأخذ قسط من الراحة. مكابحي ساخنة جداً ويتصاعد منها الدخان من النزول. أي مما يلي هو أفضل سبب لعدم تفعيل مكابح الركن (الزنبرك) الآن؟","options":["تفعيل مكابح الزنبرك وهي ساخنة قد يتسبب في انخفاض ضغط إمداد هواء المقطورة دون 60 psi وإطلاق تحذير انخفاض الهواء","المكابح الساخنة تزيد مسافة حركة عمود الدفع، لذا ستكون مُعدّلات الخلوص خارج الضبط حتى تبرد","مكابح الزنبرك تمسك بشكل صحيح فقط بعد أن ينخفض ضغط الهواء إلى نطاق 20 إلى 45 psi، وهو ما تمنعه المكابح الساخنة","تثبيت مكونات المكابح الساخنة جداً بمكابح الزنبرك يمكن أن يتلفها، لذا ينبغي أن أترك المكابح تبرد أولاً قبل الركن"],"explanation":"تطبيق مكابح الزنبرك (الركن) على مكابح ساخنة جداً يمكن أن يتلف المكونات، لذا اترك المكابح تبرد قبل الركن بعد منحدر طويل."},"189":{"q":"أثناء فحص قبل الرحلة، وصّلت جراري بمقطورة محمّلة، وشحنت النظام إلى حوالي 125 psi، وأطفأت المحرك، وضغطت على دواسة المكابح وأبقيتها مضغوطة للتحقق من التسريبات بينما أراقب مقياس اللوحة. خلال دقيقة كاملة، ما الحد الأقصى لانخفاض ضغط الهواء الذي يمكنني رؤيته وما زلت أجتاز فحص التسريب هذا؟","options":["4 psi","3 psi","2 psi","0 psi"],"explanation":"مع تطبيق المكابح، يجب أن يبقى فقدان الهواء في المركبة المركبة أقل من 4 psi في الدقيقة لاجتياز فحص التسريب."},"190":{"q":"أثناء فحصي قبل الرحلة، أتحقق من تسريب الهواء في مركبتي المركبة من جرار ومقطورة. المحرك مُطفأ، والنظام مشحون بالكامل إلى حوالي 125 psi، وقد تركت المكابح محرّرة (صمامات الركن مسحوبة للخارج، والقدم بعيدة عن الدواسة). أراقب مقياسي لمدة دقيقة، ما الحد الأقصى لفقدان الهواء الذي ينبغي أن أسمح به قبل أن يكون التسريب خارج المواصفات؟","options":["2 psi في الدقيقة، لأن ذلك هو حد التسريب عندما تكون المكابح محرّرة","3 psi في الدقيقة، لأن المركبة المركبة مع تحرير المكابح قد تتسرب قليلاً أكثر","4 psi في الدقيقة، لأن ذلك هو حد التسريب للمركبة المركبة","أي فقدان مقبول طالما لم يضِئ تحذير انخفاض الهواء بعد"],"explanation":"مع تحرير المكابح، قد تتسرب المركبة المركبة حتى 3 psi في الدقيقة، أي أكثر قليلاً من المركبة المفردة."},"191":{"q":"أثناء فحصي قبل الرحلة على جرار ومقطورة، أُطفئ المحرك، وأحرّر المكابح، وأبدأ بضخ دواسة المكابح لتفريغ الهواء. أراقب مقياس اللوحة، منتظراً تفعيل مصباح وجرس تحذير انخفاض ضغط الهواء لأتمكن من التأكد من أنهما يعملان. وفقاً لدليل CDL في تكساس، يجب أن يأتي التحذير قبل أن ينخفض ضغط الهواء في مركبتي المركبة دون أي مستوى؟","options":["قبل أن ينخفض الضغط دون 45 psi، النقطة التي تبدأ عندها مكابح الزنبرك بالتطبيق","قبل أن ينخفض الضغط دون 100 psi، النقطة التي يعيد عندها المنظّم تشغيل الضاغط","قبل أن ينخفض الضغط دون 60 psi، أي قبل أن تفقد المكابح قدرتها الفعلية على التوقف بوقت كافٍ","قبل أن ينخفض الضغط دون 20 psi، النقطة التي تُفعّل عندها مكابح الطوارئ بالكامل"],"explanation":"يجب أن يأتي تحذير انخفاض ضغط الهواء قبل أن ينخفض الضغط دون 60 psi لإعطاء تنبيه مبكر مع بقاء هواء كافٍ للتوقف بأمان."},"192":{"q":"أُجري فحصي قبل الرحلة وأراقب مقياس الهواء وهو يرتفع بينما يضخ الضاغط. عند حوالي 125 psi يتوقف الضاغط عن إضافة الهواء إلى النظام ويثبته عند ذلك المستوى. يطلب مني المدرب أن أسمّي إعداد المنظّم الذي أوقف للتو الضاغط عن الضخ. أي مصطلح يسمّي ذلك الإعداد بشكل صحيح؟","options":["إعداد التشغيل (Cut-in) — الإعداد قرب 100 psi حيث يستأنف الضاغط ضخ الهواء إلى النظام","إعداد الإيقاف (Shut-off) — الإعداد الذي يعطّل الضاغط بالكامل حتى يُعاد تشغيل المحرك","إعداد الاستعداد (Stand-by) — الإعداد الذي يُبطئ الضاغط كلما طُبّقت مكابح الركن","إعداد الفصل (Cut-out) — الإعداد قرب 125 psi حيث يوقف المنظّم الضاغط عن ضخ الهواء"],"explanation":"إعداد الفصل (cut-out)، حوالي 125 psi، هو حيث يوقف المنظّم الضاغط عن ضخ مزيد من الهواء إلى النظام."},"193":{"q":"أنا أنقل مركبة مركبة محمّلة نزولاً على منحدر جبلي طويل. للتحكم في سرعتي، أختار غياراً منخفضاً بحيث يقوم المحرك وناقل الحركة بمعظم عمل إبطائي، وألمس مكابح الخدمة بخفة بين الحين والآخر فقط. مقارنة بركوب المكابح طوال الطريق نزولاً، ما الميزة الرئيسية لترك المحرك والغيار المنخفض يحدّان من سرعتي؟","options":["تبقى مكابح الخدمة باردة، فتحتفظ بكامل قدرتها على التوقف إذا احتجت إلى توقف مفاجئ في الأسفل","تسخن مكابح الخدمة بما يكفي فقط لتمسك الأسطوانات بشكل أفضل وتقصّر مسافة توقفي","يبني ضاغط الهواء ضغطاً إضافياً أسرع لأن المكابح بالكاد تُستخدم على المنحدر","تتشارك مكابح الزنبرك (الركن) الحمل مع مكابح الخدمة وتبطئ المركبة تلقائياً"],"explanation":"الغيار المنخفض يترك المحرك يمتص طاقة المركبة، مما يُبقي مكابح الخدمة باردة فتحتفظ بكامل قدرتها على التوقف لتوقف مفاجئ."},"194":{"q":"أنا أنزل على منحدر طويل وشديد في شاحنة محمّلة بمكابح هوائية، وبدأت المركبة تتجاوز سرعتي الآمنة. يخبرني صديق عبر جهاز اللاسلكي (CB) أن أضخ دواسة المكابح وأحرّرها بشكل متكرر للحفاظ على سرعتي. لماذا يكون اتباع تلك النصيحة خطيراً على هذا النوع من المنحدرات؟","options":["الضخ المتكرر للدواسة يُسخّن الضاغط ويُطلق صمام التنفيس الأماني عند 150 psi","الضخ المتكرر للدواسة ينزف الهواء أسرع مما يستطيع الضاغط استبداله، فقد ينخفض الضغط حتى تفقد الكبح","الضخ المتكرر للدواسة يدفع الماء والزيت خارج الخزانات ويلوّث خطوط المكابح","الضخ المتكرر للدواسة يبني هواءً زائداً يُغلق مكابح الزنبرك بينما لا تزال تتحرك"],"explanation":"ضخ المكابح بشكل متكرر على منحدر طويل يطلق الهواء أسرع مما يستطيع الضاغط استبداله، فقد ينخفض الضغط حتى تفقد الكبح."},"195":{"q":"لقد أدخلت مركبتي المركبة إلى منطقة استراحة لأخذ استراحة مدتها 30 دقيقة. لتثبيت الوحدة في مكانها بينما أكون بعيداً عن المقصورة، أمد يدي إلى صمام يد المقطورة (trailer hand valve) وأُفعّله. لماذا تكون هذه الطريقة الخاطئة لتأمين المركبة؟","options":["صمام اليد يُفعّل مكابح الزنبرك للمقطورة، التي يمكن أن تسخن وتنغلق بينما تجلس المركبة متوقفة","صمام اليد يحرّر مقبض إمداد هواء المقطورة الأحمر، فينجرف الجرار للأمام من تلقاء نفسه","صمام اليد يطبّق فقط هواء الخدمة على مكابح المقطورة، وهذا الهواء يمكن أن يتسرب مع الوقت ويترك المركبة تتدحرج","صمام اليد يرسل الهواء إلى محور التوجيه فقط، فتُترك عجلات الدفع والمقطورة بدون كبح تماماً"],"explanation":"صمام يد المقطورة يطبّق هواء الخدمة فقط، والذي يتسرب مع الوقت ويترك المركبة تتدحرج، لذا اركن دائماً بمكابح الزنبرك."},"196":{"q":"أثناء فحصي قبل الرحلة على جرار مفرد، أرفع نظام الهواء إلى حوالي 125 psi، ثم أُطفئ المحرك وأحرّر المكابح. لقد وضعت أسافين العجلات بالفعل وتحذير انخفاض الهواء مُطفأ. ما الهدف الكامل من إطفاء المحرك في هذه الخطوة؟","options":["ليتيح لي ضخ دواسة المكابح عدة مرات والتأكد من أن ضغط الهواء يُعاد بناؤه بسرعة","لإجبار مكابح الزنبرك على التطبيق تلقائياً حتى أتمكن من التأكد من أنها تستقر في نطاق 20 إلى 45 psi","لتصريف الخزان الرطب دون أن يدور الضاغط ويدفع مزيداً من الزيت والماء إلى الداخل","لإيقاف الضاغط عن إضافة الهواء حتى أتمكن من توقيت انخفاض الضغط والتحقق من معدل التسريب"],"explanation":"إطفاء المحرك يوقف الضاغط عن إضافة الهواء حتى تتمكن من توقيت انخفاض الضغط وقياس معدل التسريب بدقة."},"197":{"q":"أثناء فحصي قبل الرحلة، يطلب مني مدربي أن أشرح ما الذي يدفع فعلياً أحذية المكابح ضد الأسطوانات عندما أضغط على دواسة المكابح. المحرك يعمل والنظام مشحون بالكامل. أي إجابة تصف بشكل صحيح شكل الطاقة المخزّنة التي تعتمد عليها مكابحي للقيام بذلك العمل؟","options":["الهواء المضغوط المحتجز في الخزانات، والذي يُطلق لتطبيق المكابح","السائل الهيدروليكي المضغوط بواسطة الأسطوانة الرئيسية، مثل مكابح السيارة","التيار الكهربائي من البطارية المُرسل إلى مغناطيسات عند كل عجلة","ضغط زيت المحرك الموجّه من نظام التزييت إلى المكابح"],"explanation":"نظام المكابح الهوائية يخزّن الطاقة كهواء مضغوط في الخزانات، والذي يُطلق لتطبيق المكابح."},"198":{"q":"أثناء فحصي قبل الرحلة، أُشغّل المحرك وأراقب مقياس اللوحة. نظام الهواء المزدوج لديّ يستغرق وقتاً أطول بكثير من المطلوب للوصول إلى 85 حتى 100 psi في 45 ثانية للوصول إلى الضغط، ويستمر في الارتفاع ببطء وكسل. من بين ما يلي، ما السبب الأكثر احتمالاً لهذا البناء البطيء؟","options":["جرس تحذير انخفاض ضغط الهواء يصدر صوتاً مبكراً جداً، دون 60 psi","ضاغط هواء يفشل أو تسريب هواء في مكان ما في النظام","فصل المنظّم (cut-out) مضبوط على مستوى عالٍ جداً، قرب إعداد التنفيس 150 psi","مُعدّلات الخلوص لديها مسافة حركة عمود دفع وحركة حرة زائدة"],"explanation":"ضغط الهواء الذي يُبنى ببطء شديد للوصول إلى 85-100 psi خلال 45 ثانية يشير إلى ضاغط يفشل أو تسريب في النظام."},"199":{"q":"أثناء فحصي قبل الرحلة، أسمع فحيح هواء عالياً يتسرب من صمام التنفيس الأماني على خزان الإمداد (الرطب) بينما يعمل المحرك ويبني الضاغط الهواء. من بين ما يلي، ما الحالة التي صُمّم هذا الصمام تحديداً لحماية الخزانات منها؟","options":["فشل تحذير انخفاض ضغط الهواء في الإضاءة قبل أن ينخفض الضغط دون 60 psi","فشل المنظّم في إعادة تشغيل الضاغط بمجرد انخفاض الضغط إلى حوالي 100 psi","ارتفاع ضغط الهواء إلى مستوى عالٍ جداً في النظام، مع ضبط الصمام للفتح عند حوالي 150 psi","فشل الضاغط في بناء الضغط من 85 إلى 100 psi خلال 45 ثانية"],"explanation":"صمام التنفيس الأماني (pop-off) في خزان الإمداد يفتح عند حوالي 150 psi لحماية النظام من ضغط الهواء المفرط."},"200":{"q":"أنتقل من قيادة شاحنتي الصغيرة الشخصية، التي لها مكابح هيدروليكية، إلى شاحنة من الفئة B مزوّدة بنظام مكابح هوائية. أثناء الفحص قبل الرحلة، أحاول فهم الفرق الجوهري في كيفية وصول قوة التوقف الفعلية إلى المكابح عند كل عجلة. أي عبارة تحدد بشكل صحيح ما الذي ينقل فيزيائياً القوة التي تطبّق المكابح في مركبتي ذات المكابح الهوائية؟","options":["السائل الهيدروليكي في الأسطوانة الرئيسية يُضغط أكثر، ثم يُوجّه إلى غرف المكابح لتثبيت الأحذية","ضغط زيت المحرك يتراكم ويُحوّل عبر خطوط المكابح لدفع مُعدّلات الخلوص ضد الأسطوانات","إشارة كهربائية من دواسة المكابح تُنشّط مغناطيسات عند كل عجلة تسحب أحذية المكابح للخارج","الهواء المضغوط، المخزّن في الخزانات والمُطلق بواسطة الدواسة، ينتقل عبر الخطوط لتطبيق القوة عند غرف المكابح"],"explanation":"المكابح الهوائية تستخدم الهواء المضغوط المخزّن في الخزانات، المُطلق بواسطة الدواسة عبر الخطوط إلى غرف المكابح لتطبيق قوة الكبح."},"201":{"q":"لقد انتقلت للتو من شاحنة بيك أب ذات مكابح هيدروليكية إلى شاحنة بمقطورة ذات مكابح هوائية. في المرة الأولى التي أضغط فيها على دواسة المكابح بقوة، ألاحظ أن الشاحنة لا تبدأ بالتباطؤ في اللحظة التي تتحرك فيها قدمي، كما كانت تفعل شاحنتي القديمة. أي عبارة تفسر بأفضل شكل هذا الفرق بين المكابح الهوائية والمكابح الهيدروليكية؟","options":["تتميز المكابح الهوائية بتأخير مدمج يبلغ نحو نصف ثانية لأن الهواء يجب أن ينتقل عبر الخطوط قبل أن تعمل المكابح.","لا توفر المكابح الهوائية أي قوة توقف على الإطلاق حتى يصل النظام إلى ضغط القطع الكامل للمنظم البالغ 125 psi.","تستجيب المكابح الهوائية فورًا مثل الهيدروليكية، لذا فإن التأخير الذي شعرت به كان فقط بسبب موازنات الخلوص المهترئة وغير المضبوطة.","ليس للمكابح الهوائية أي ارتجاع في الدواسة، لذا فإن التباطؤ بدأ في الواقع فورًا رغم أنني لم أستطع الشعور به."],"explanation":"تتميز المكابح الهوائية بتأخير يبلغ نحو نصف ثانية لأن الهواء يجب أن ينتقل عبر الخطوط قبل أن تعمل المكابح."},"202":{"q":"إذا انخفض ضغط الهواء أثناء القيادة، فقد تلاحظ أولًا:","options":["انقطاع الراديو","تحذير انخفاض الهواء","انفتاح الباب فجأة","تحرك المقعد إلى الخلف"],"explanation":"تحذير انخفاض الهواء ينبهك أولًا."},"203":{"q":"أنت تنقل حمولة على طريق سريع ريفي في تكساس عندما يضيء مصباح تحذير انخفاض ضغط الهواء ويبدأ الصافرة بالصدور. توجد محطة شاحنات على بعد نحو 12 ميلًا للأمام حيث تعرف أن هناك ميكانيكيًا في الخدمة. باستثناء واحدة من الخيارات التالية، فإن الإجراءات أدناه هي استجابات غير آمنة لهذا التحذير. أي منها هو الإجراء الصحيح؟","options":["حافظ على سرعة الطريق السريع وتابع إلى محطة الشاحنات على بعد 12 ميلًا للأمام حتى يتمكن ميكانيكي من فحص النظام","اكبح بلطف لتقليل السرعة وأخرج المركبة عن الطريق وأوقفها بأمان في أقرب وقت ممكن","اضغط دواسة المكابح بشكل متكرر لإعادة بناء الضغط في الخزانات وتابع القيادة بشكل طبيعي","استمر بالسير لكن اسحب مقبض مكبح الركن الآن حتى تساعدك المكابح الزنبركية على التوقف لاحقًا"],"explanation":"عندما يضيء تحذير انخفاض الهواء، اكبح بلطف وأخرج المركبة عن الطريق وأوقفها بأمان قبل أن تعمل المكابح الزنبركية تلقائيًا."},"204":{"q":"تتوقف عند إشارة حمراء في شاحنتك المستقيمة ذات المكابح الهوائية. مصباح تحذير انخفاض الهواء والصافرة يعملان، ويُظهر مقياس لوحة القيادة أن الضغط قد انخفض إلى ما دون نطاق التشغيل الطبيعي بكثير. تتحول الإشارة إلى الأخضر وتبدأ حركة المرور خلفك بالتزمير. ما هو الإجراء الصحيح؟","options":["تقدم ببطء عبر التقاطع، بما أن المكابح الزنبركية لا تُقفل إلا عند 20 psi وأنت لا تزال أعلى من ذلك","قم بتغيير سريع للمسار إلى الكتف ما دام لديك هواء كافٍ لتدوير العجلات","ابقَ متوقفًا ولا تحرك الشاحنة حتى يعود ضغط الهواء إلى البناء ضمن النطاق الطبيعي","اضغط دواسة المكابح بخفة عدة مرات لمساعدة الضاغط على إعادة ملء الخزانات بسرعة قبل الانطلاق"],"explanation":"إضاءة تحذير انخفاض الهواء تعني أن الكبح لم يعد موثوقًا، لذا ابقَ متوقفًا حتى يعود ضغط الهواء إلى البناء ضمن النطاق الطبيعي."},"205":{"q":"أنا أنقل مركبة مركّبة محمّلة على منحدر طويل وحاد، وفي منتصف الطريق إلى الأسفل ألاحظ أن دواسة المكابح أصبحت طرية وأن الشاحنة بالكاد تتباطأ عندما أضغط عليها. من الواضح أن مكابحي تتلاشى. أي مما يلي هو أفضل إجراء يمكنني اتخاذه؟","options":["اضغط دواسة المكابح بقوة أكبر وحافظ على ضغط ثابت طوال الطريق إلى الأسفل لتعويض قوة الكبح المفقودة","اضغط دواسة المكابح بسرعة لإعادة بناء الإحساس بالدواسة واستعادة قوة التوقف التي فقدتها","انتقل إلى ترس أعلى حتى يدور المحرك بحرية وتنزلق الشاحنة بسلاسة إلى الأسفل","انتقل إلى ترس أدنى للكبح بالمحرك وابحث عن أقرب مكان آمن للانعطاف وإيقاف الشاحنة"],"explanation":"إذا بدأت المكابح الهوائية بالتلاشي على منحدر طويل، فانتقل إلى ترس أدنى للكبح بالمحرك وانعطف عند أقرب مكان آمن للتوقف."},"206":{"q":"لقد أوقفت شاحنتي ذات المقطورة المحمّلة على منحدر طفيف وضبطت مكبح الركن بالمقبض الأصفر. بينما أقوم بأوراقي، يكون المحرك متوقفًا وضغط الهواء في الخزانات يتسرب ببطء إلى ما دون 45 psi نحو الصفر. ما الذي يمنع شاحنتي فعليًا من الانزلاق بعيدًا، ولماذا يستمر بالإمساك حتى مع تسرب الهواء؟","options":["زنبركات قوية في غرف المكابح تثبّت المكابح ميكانيكيًا، فتبقى قوة الإمساك مفعّلة مع تسرب الهواء","الهواء المحبوس داخل غرف المكابح يبقي الأحذية مضغوطة على الطبول","المحرك وناقل الحركة يمسكان العجلات عبر الانضغاط بمجرد إيقافه","المقبض الأصفر يثبّت وصلة صمام القدم ميكانيكيًا للحفاظ على قوة الدواسة"],"explanation":"يتم إبقاء مكابح الركن والطوارئ مفعّلة بواسطة زنبركات قوية في غرف المكابح الزنبركية، لذا تستمر بالإمساك حتى مع تسرب الهواء."},"207":{"q":"أنا أسير على الطريق السريع ونظام الهواء لدي مشحون بالكامل عند ضغط التشغيل الطبيعي، وأشعر أن المكابح الزنبركية لا تسحب أو تعمل. أي عبارة تفسر بشكل صحيح دور ضغط الإبقاء (hold-off) في هذا الموقف؟","options":["ضغط الإبقاء يبقي المكابح الزنبركية مثبّتة جزئيًا حتى تستجيب أسرع عندما أضغط الدواسة.","ضغط الإبقاء يبقي المكابح الزنبركية محررة أثناء قيادتي، فتبقى غير مفعّلة حتى ينخفض الهواء إلى مستوى منخفض جدًا.","ضغط الإبقاء يبقي المكابح الزنبركية مفعّلة بالكامل طوال الوقت لتدعم مكابح الخدمة لدي.","تمت إزالة ضغط الإبقاء بالكامل من الغرف، وهذا سبب شعوري بأن المكابح الزنبركية غير مفعّلة."],"explanation":"ضغط هواء الإبقاء يضغط الزنبركات لإبقاء المكابح الزنبركية محررة أثناء القيادة، وتعمل فقط إذا انخفض الهواء إلى مستوى منخفض جدًا."},"208":{"q":"أوقف شاحنتي في نهاية نوبتي، أُطفئ المحرك، وأشعر بالمكابح الزنبركية تقفل العجلات مع تسرب الهواء. يسألني متدرب عن أي وظيفة كبح في النظام الهوائي اعتمدت عليها للتو لإمساك الشاحنة. أي إجابة صحيحة؟","options":["وظيفة كبح الخدمة، لأن دواسة القدم هي ما يمسك مركبة متوقفة بمجرد إطفاء المحرك","الوظيفة التعديلية، لأن المكابح الزنبركية تعمل تدريجيًا مع انخفاض ضغط الهواء دون 60 psi","وظيفة الركن/الطوارئ، لأن المكابح الزنبركية تُضبط تلقائيًا لإمساك المركبة بمجرد فقدان ضغط الهواء","وظيفة تحذير انخفاض الهواء، لأن الصافرة والمصباح هما ما يثبّتان العجلات فعليًا"],"explanation":"تُضبط المكابح الزنبركية تلقائيًا لإمساك المركبة عند فقدان ضغط الهواء، وهي وظيفة الركن/الطوارئ."},"209":{"q":"التسرب الذي يمكنك سماعه أثناء الفحص يعني:","options":["كل شيء على ما يرام","الهواء يتسرب","قوة كبح أكبر","مكابح أفضل الآن"],"explanation":"التسرب المسموع (الفحيح) يعني أن الهواء يتسرب."},"210":{"q":"أثناء فحصي قبل الرحلة، أفتح غطاء المحرك وألاحظ أن ضاغط الهواء لدي يُدار بحزام بدلًا من توصيله مباشرة بالمحرك. لأنه يُدار بحزام، ما العنصر الإضافي الذي يجب أن أفحصه تحديدًا والذي لن أحتاج لفحصه على ضاغط يُدار بالتروس؟","options":["أن ضغط قطع المنظم يقرأ نحو 125 psi على المقياس","أن خزانات الهواء قد تم تصريف الماء وزيت الضاغط منها","أن مصباح تحذير انخفاض ضغط الهواء يضيء قبل 60 psi","أن حزام الإدارة مشدود بشكل صحيح ولا تظهر عليه علامات التآكل"],"explanation":"على الضاغط الذي يُدار بحزام، افحص أن حزام الإدارة مشدود بشكل صحيح وغير مهترئ، لأن الضاغط الذي يُدار بالتروس لا حزام له."},"211":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن أحد خزانات تخزين الهواء أسفل المقطورة لم يعد مثبتًا بإحكام على دعامته ويتحرك عندما أدفعه. لماذا يُعد هذا الخزان المرتخي عيبًا يجب إصلاحه قبل القيادة؟","options":["يمكن للخزان أن يحتك بأجزاء من المركبة أو يرتخي ويسقط من الشاحنة","سيسحب الخزان هواءً إضافيًا من الضاغط ويجبر المنظم على القطع مبكرًا","سيحتفظ الخزان بهواء مضغوط أقل، فيصدر تحذير انخفاض الهواء أسرع","سيدع الخزان الماء والزيت يتصرفان من تلقاء نفسهما، فلا يبقى شيء لإزالته يوميًا"],"explanation":"يمكن لخزان الهواء المرتخي أن يهتز ويحتك بأجزاء المركبة أو يرتخي ويسقط من الشاحنة."},"212":{"q":"لقد أدخلت شاحنتك المستقيمة ذات المكابح الهوائية إلى أرض مستوية ومعبّدة عند جزيرة الوقود وأطفأت المحرك. تُظهر المقاييس ضغط النظام الكامل وأنت على وشك الخروج من المقصورة لبدء التزود بالوقود. أي إجراء يجب أن تكمله قبل أن تغادر المقصورة؟","options":["اترك الشاحنة في أدنى ترس أمامي واعتمد على انضغاط المحرك لإمساكها","اسحب المقبض الأصفر المعيّن الشكل لضبط مكابح الركن (الزنبركية)","أمسك الشاحنة بإبقاء ضغط ثابت وقوي على دواسة مكبح الخدمة","اسحب المقبض الأحمر المثمّن الشكل لقفل خط إمداد هواء المقطورة"],"explanation":"اضبط دائمًا مكابح الركن (الزنبركية) بسحب المقبض الأصفر المعيّن الشكل قبل مغادرة المقصورة."},"213":{"q":"أنا سائق جديد أختار بين شاحنتين مستعملتين: شاحنة ثقيلة بمقطورة مصنّفة لنقل حمولة قريبة من وزنها الإجمالي الأقصى، وشاحنة توصيل خفيفة. يخبرني ميكانيكي أن الشاحنة الكبيرة تستخدم مكابح هوائية بينما تستخدم الشاحنة الصغيرة مكابح هيدروليكية. أريد أن أفهم لماذا تُبنى المركبات التجارية الثقيلة بمكابح هوائية في المقام الأول. أي عبارة تفسر بأفضل شكل لماذا تكون المكابح الهوائية الخيار القياسي للشاحنات الكبيرة المحمّلة بشدة؟","options":["تقصّر المكابح الهوائية مسافة التوقف الإجمالية للشاحنة، فتتوقف الشاحنة المحمّلة بالكامل في مساحة أقل مما يمكن بالمكابح الهيدروليكية","يتم اختيار المكابح الهوائية أساسًا لأنها أرخص نظام كبح للتركيب ولا تحتاج أبدًا إلى تصريف الخزانات أو صيانتها","تستخدم المكابح الهوائية هواءً مضغوطًا بدلًا من كمية ثابتة من السائل، فتستمر بالعمل بفعالية حتى على المركبات الكبيرة التي تحمل أحمالًا ثقيلة","تلغي المكابح الهوائية تأخير الكبح بالكامل، فتسمح للشاحنة المحمّلة بالاستجابة لحظة الضغط على الدواسة دون أي تأخير في الخطوط"],"explanation":"تستخدم المكابح الهوائية هواءً مضغوطًا يُجدَّد باستمرار بدلًا من كمية ثابتة من السائل، فتستمر بالكبح بفعالية على المركبات الثقيلة المحمّلة بالكامل."},"214":{"q":"أنا متوقف على منحدر وأقرر ضبط مقبض مكبح الركن الأصفر (تفعيل المكابح الزنبركية) بينما لا أزال أضغط دواسة مكبح الخدمة بقوة. يحذرني سائق بجانبي بأن أرفع قدمي عن الدواسة أولًا. لماذا يُعد تفعيل مكابح الخدمة والمكابح الزنبركية بقوة في الوقت نفسه مشكلة؟","options":["لا يسبب ذلك أي ضرر على الإطلاق ويمنحني في الواقع قوة إمساك إضافية، فلا داعي لرفع القدم عن دواسة الخدمة أولًا","يتسبب في إضاءة تحذير انخفاض ضغط الهواء مبكرًا، تحت نقطة 60 psi، ويفرّغ خزان الإمداد أسرع","يوفّر كمية كبيرة من الهواء لأن كلا النظامين يتشاركان الضغط المخزّن نفسه عند تفعيلهما معًا","تتجمع قوى الكبح وتتضاعف، ويمكن لتلك القوة المتراكمة أن تضع إجهادًا كبيرًا وتُلحق الضرر بمكونات المكابح"],"explanation":"يسمح تفعيل مكابح الخدمة بقوة بينما المكابح الزنبركية مضبوطة بأن تتجمع القوتان، مما يضع إجهادًا زائدًا قد يُلحق الضرر بمكونات المكابح."},"215":{"q":"أنا أركن شاحنتي وأسحب المقبض الأصفر لضبط المكابح الزنبركية (مكابح الركن). بحكم العادة، لا تزال قدمي تضغط بقوة على دواسة المكابح، فيُرسَل الهواء أيضًا إلى غرف المكابح نفسها في الوقت ذاته. حذرني الميكانيكي بأنه بدون صمام معيّن، يمكن لتفعيل القوتين معًا أن يتجمع ويُلحق الضرر بالمكابح. أي صمام يحمي من هذا الأمر؟","options":["صمام منع التراكم، الذي يمنع قوة المكابح الزنبركية وقوة تطبيق الهواء من التجمع على المكابح نفسها","صمام التحكم التعديلي، الذي يسمح بتفعيل المكابح الزنبركية تدريجيًا حتى لا تتداخل القوتان أبدًا","صمام تخفيف الأمان، الذي يفتح عند نحو 150 psi لتصريف الضغط الزائد الناتج عن التطبيق المزدوج","صمام إمداد هواء المقطورة، المقبض الأحمر المثمّن الذي يقطع الهواء عن المكابح الخلفية عند تفعيل كليهما"],"explanation":"يطلق صمام منع التراكم ضغط تطبيق الهواء عند ضبط المكابح الزنبركية حتى لا تتجمع قوتا الكبح معًا."},"216":{"q":"أثناء فحصي قبل الرحلة، أُجري فحوصات المكابح الهوائية على شاحنة بمقطورة. أريد التأكد من الجهاز المطلوب لتنبيهي في اللحظة التي ينخفض فيها هواء النظام إلى مستوى منخفض جدًا (قبل أن يهبط دون 60 psi) حتى أعرف أن أتوقف بينما لا تزال لدي قدرة على الكبح. أي ميزة يُطلب من النظام استخدامها لإعطائي ذلك التحذير؟","options":["مقياس ضغط الهواء الذي يهبط ببطء، والذي يُتوقع مني مراقبته عن كثب طوال الرحلة","مصباح تحذير و/أو صافرة تُفعَّل قبل أن ينخفض الضغط دون 60 psi","المكابح الزنبركية (مكابح الركن) التي تُفعَّل تلقائيًا لإجباري ماديًا على التوقف","صمام تخفيف الأمان الذي يصرّف الهواء بفحيح عالٍ بمجرد انخفاض الضغط كثيرًا"],"explanation":"يجب أن تحتوي مركبة المكابح الهوائية على مصباح تحذير انخفاض ضغط الهواء، وعادةً صافرة، يُفعَّل قبل أن ينخفض الضغط دون 60 psi."},"217":{"q":"أنا متوقف في وضع الخمول في محطة شاحنات أراقب مقياس ضغط الهواء بعد شحن كامل. تستمر الإبرة في الدوران: ترتفع، يقطع المنظم، تستقر الإبرة قليلًا ببطء، ثم يعود المنظم للعمل ويضخّها للأعلى مجددًا. أريد التأكد من أن ضاغط الهواء لدي يواكب الطلب. أي سلوك للمقياس يخبرني أن الضاغط يؤدي عمله؟","options":["يستمر المقياس بالارتفاع متجاوزًا 150 psi ويصرّف صمام تخفيف الأمان، مما يثبت أن الضاغط لديه سعة فائضة كثيرة","يهبط المقياس ببطء طوال الطريق نحو الصفر، ثم يعيد الضاغط ملأه في دفعة سريعة واحدة","تبقى الإبرة ضمن نطاق التشغيل الطبيعي، تدور بين قطع المنظم وتشغيله مع استخدام الهواء واستبداله","يثبت المقياس عند ضغط واحد ثابت ولا يتحرك أبدًا، مما يُظهر أن المنظم قد قفل ضغط النظام"],"explanation":"يبقي الضاغط العامل الضغط ضمن النطاق الطبيعي، يدور بين قطع المنظم (نحو 125 psi) وتشغيله (نحو 100 psi) مع استخدام الهواء واستبداله."},"218":{"q":"إذا ضغطت على المكبح وانخفض الضغط كثيرًا، فقد يكون هناك:","options":["قوة كبح أكبر","تسرب","قبضة أفضل الآن","لا مشكلة على الإطلاق"],"explanation":"الانخفاض الكبير في الضغط قد يعني وجود تسرب."},"219":{"q":"أنا أُجري فحصي قبل الرحلة على شاحنة جر مفردة وأترك المحرك في وضع الخمول لبناء الهواء. أريد النظام مشحونًا بالكامل قبل أن أنطلق، لذا أراقب مقياس لوحة القيادة يرتفع وأنتظر منظم الضاغط ليقطع ويتوقف عن الضخ. عند أي ضغط تقريبًا يجب أن أتوقع حدوث ذلك؟","options":["نحو 100 psi، النقطة التي يبدأ عندها المنظم بالعمل والضخ مجددًا","نحو 60 psi، حيث ينطفئ مصباح وصافرة تحذير انخفاض ضغط الهواء","نحو 150 psi، حيث يفتح صمام تخفيف الأمان لتصريف الهواء الزائد","نحو 125 psi، حيث يقطع المنظم ويتوقف الضاغط عن الضخ"],"explanation":"يستقر النظام المشحون بالكامل عند ضغط قطع المنظم، نحو 125 psi، حيث يتوقف الضاغط عن ضخ الهواء."},"220":{"q":"أنت تقود مركبة مركّبة عندما تنفصل مقطورتك فجأة عن شاحنة الجر ويتمزق خط إمداد الهواء الخاص بها، مما يفرّغ كل الهواء من نظام مكابح المقطورة. ماذا سيحدث للمقطورة الهاربة؟","options":["ستُفعَّل مكابحها الزنبركية (مكابح الطوارئ) تلقائيًا مع انخفاض ضغط الهواء، فتبطئ المقطورة وتوقفها","ستمسك مكابح خدمتها فقط ما دمت تُبقي قدمك على دواسة المكابح في شاحنة الجر","ستنطلق بحرية دون أي كبح، لأن فقدان الهواء يحرر أيضًا مكابح ركن المقطورة","لن يحدث لها شيء حتى تسحب المقبض الأحمر لإمداد هواء المقطورة لضبط المكابح"],"explanation":"تُبقى المكابح الزنبركية محررة بواسطة ضغط الهواء، لذا عندما تفقد مقطورة منفصلة الهواء تُفعَّل تلقائيًا وتوقف المقطورة."},"221":{"q":"أنت تقود شاحنة مستقيمة مفردة بنظام مكابح هوائية عندما يفرّغ عطل كبير في الخط كل الهواء من النظام وتهبط مقاييس الضغط إلى الصفر. أنت لم تلمس دواسة المكابح أو مقبض الركن. ماذا تفعل الشاحنة؟","options":["تنزلق بحرية دون أي كبح، لأن فقدان الهواء يحرر أيضًا المكابح الزنبركية ويتركك تتدحرج.","تتوقف من تلقاء نفسها، لأن المكابح الزنبركية تُفعَّل تلقائيًا بمجرد انخفاض ضغط الهواء بما يكفي.","تستمر بالحركة بشكل طبيعي وتفقد فقط مكابح الخدمة، لكن التوجيه ومكبح الركن لا يزالان يعملان.","تفقد فقط المساعدة الآلية، فتبقى المكابح تعمل لكن الدواسة تصبح أصعب بكثير في الضغط."],"explanation":"تُبقى المكابح الزنبركية محررة بواسطة ضغط الهواء، لذا فإن الفقدان الكامل للهواء يُفعّلها تلقائيًا ويوقف المركبة."},"222":{"q":"أثناء فحصي قبل الرحلة على شاحنة بمقطورة، ألاحظ أن موازن الخلوص لأحد المكابح الأمامية لديه حركة قضيب دفع أكبر من البقية، فيؤدي ذلك المكبح عملًا أقل بينما تؤدي البقية عملًا أكثر. يقول صديق إن ذلك لن يهم كثيرًا. ما هو أهم شيء أفقده عندما تكون مكابحي خارج الضبط ولم تعد تتقاسم عمل الكبح بالتساوي؟","options":["اقتصاد أفضل في الوقود، لأن المكابح التي تعمل بالتساوي تقلل من سحب المحرك","بناء أسرع لضغط الهواء من 85 إلى 100 psi أثناء الاختبار","توازن جيد للمكابح، فتتوقف المركبة بشكل مستقيم دون الانحراف إلى جانب واحد","قوة كبح أكبر بالمحرك عندما أنتقل إلى ترس أدنى على منحدر طويل"],"explanation":"عندما تكون كل المكابح مضبوطة بشكل صحيح وتتقاسم العمل بالتساوي، يحافظ توازن المكابح على توقف المركبة بشكل مستقيم دون الانحراف إلى جانب واحد."},"223":{"q":"أنا أُجري فحصًا قبل الرحلة على شاحنتي بمقطورة. كان المحرك يعمل والهواء يتراكم في الخزانات. قبل أن أحرر مكابح الركن وأخرج من الساحة، ما هو الحد الأدنى لضغط الهواء الذي يجب أن يكون لدي في النظام لأقود بأمان؟","options":["على الأقل نحو 60 psi، لأن تلك هي النقطة التي ينطفئ عندها تحذير انخفاض ضغط الهواء","على الأقل نحو 20 psi، لأن تلك هي النقطة التي تتحرر عندها المكابح الزنبركية وتدع الشاحنة تتدحرج","على الأقل نحو 125 psi، لأن الشاحنة غير آمنة للقيادة حتى يصل المنظم إلى نقطة القطع","على الأقل نحو 100 psi، لأن تلك هي أدنى ضغط مطلوب للكبح والقيادة بأمان"],"explanation":"يجب أن تبني على الأقل نحو 100 psi قبل القيادة، لأن تلك هي أدنى ضغط هواء مطلوب للكبح والقيادة بأمان."},"224":{"q":"أقود الشاحنة الموثوقة نفسها ذات المقطورة على حلقة توصيل قصيرة طولها 40 ميلًا أكررها عدة مرات يوميًا. اجتازت الوحدة فحص المكابح الهوائية الكامل بنظافة هذا الصباح، ولم ألمسها منذ الغداء. وأنا أصعد لأبدأ رحلتي بعد الظهر، أي نهج لفحص المكابح الهوائية هو الصحيح؟","options":["أجرِ فحوصات المكابح الهوائية مجددًا قبل هذه الرحلة بعد الظهر، تمامًا كما قبل أي رحلة","تجاوز الفحوصات هذه المرة، بما أن فحصًا كاملًا قد اجتاز بالفعل في وقت سابق اليوم على المركبة نفسها","كرر الفحوصات فقط إذا أضاء مصباح أو صافرة تحذير انخفاض الهواء أثناء رحلة الصباح","انتظر وأعد فحص المكابح مرة واحدة في الأسبوع أو بعد كل 1000 ميل تقريبًا من القيادة"],"explanation":"يجب إجراء فحوصات المكابح الهوائية قبل كل رحلة، لأن حالة المكابح وتسرب الهواء وضبط الخلوص يمكن أن تتغير بين الرحلات."},"225":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن موازنات الخلوص على شاحنة الجر لدي بها خلوص حر أكبر مما ينبغي، مما يعني أن المكابح خارج الضبط. إذا قدت رغم ذلك دون إصلاح هذا، فما الذي يجب أن أتوقع حدوثه على الطريق في الغالب؟","options":["ستمسك المكابح في الواقع بقوة أكبر وتوقف الشاحنة في مسافة أقصر","ستكون للمكابح قوة منخفضة ولن تتوقف الشاحنة بنفس الجودة","سيوفر النظام الهواء، فيعمل الضاغط بشكل أقل بكثير","ستهترئ بطانات المكابح والطبول ببطء أكبر بكثير بمرور الوقت"],"explanation":"حركة قضيب الدفع المفرطة من موازنات الخلوص خارج الضبط تقلل قوة الكبح، لذا لن تتوقف الشاحنة بنفس الجودة."},"226":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن خرطوم الفرامل قد تم توجيهه بحيث يضغط على دعامة حادة في الهيكل، والسطح الخارجي مخدوش حيث يلامس المعدن. لماذا يهم هذا الاكتشاف بالنسبة لنظام الفرامل الهوائية الخاص بي؟","options":["التلامس يُحكم التوصيلة بمرور الوقت، فهو في الواقع يقلل من احتمال انفكاك التوصيلة","الاحتكاك يجعل المطاط أكثر صلابة، مما يتيح للخرطوم تحمّل ضغط أعلى من بقية النظام","الاحتكاك المستمر يمكن أن يبري الخرطوم حتى يفشل ويتسرب منه الهواء","لا يتغير شيء بالنسبة للفرامل، لكن الاحتكاك قد يُسرّع التبريد في تلك النقطة فقط"],"explanation":"خرطوم الفرامل الذي يحتك بقطعة ما يتآكل بسبب الاحتكاك المستمر حتى يبرى ويتسرب منه الهواء."},"227":{"q":"أثناء فحصي قبل الرحلة، تكون جرّارتي المنفردة مشحونة بالكامل إلى نحو 125 psi. أُطفئ المحرك، وأترك الفرامل مُحرَّرة، وأراقب المقياس. ينخفض الضغط أكثر من 2 psi في دقيقة واحدة، وأتتبّع صوت هسهسة خافت إلى حجرة فرامل حيث يوجد تمزق صغير في الحجاب المطاطي. ماذا يفعل هذا الحجاب الممزق بنظامي الهوائي؟","options":["إنه يعزز القوة الدافعة لقضيب الدفع، مما يمنح تلك العجلة قوة كبح إضافية","إنه يهم فقط عند ضغط الفرامل، لذا عند تحرير الفرامل ليس له تأثير فعلي","إنه يساعد بطانات الفرامل على الإمساك بالطبلة بإحكام أكبر عند تلك العجلة أثناء التوقف","إنه يسمح للهواء المضغوط بالتسرب، ولهذا فإن معدل التسرب لدي مرتفع جدًا"],"explanation":"الحجاب الممزق في حجرة الفرامل يسمح للهواء المضغوط بالتسرب عبر الثقب بدلًا من تطبيق الفرامل، مما يرفع معدل التسرب."},"228":{"q":"أثناء فحصي قبل الرحلة، يفشل معدل تسرب الهواء في جرّارتي ومقطورتي، حيث ينخفض الضغط أسرع بكثير من الحد المسموح حتى مع إطفاء المحرك وتحرير الفرامل. ألاحظ هسهسة خافتة عند النقطة التي تتصل فيها خطوط هواء الجرّار والمقطورة معًا. أي حالة هي السبب الأرجح لما أسمعه ولفشل اختبار التسرب؟","options":["أختام الكفّ المتصافحة (glad-hand) البالية تسمح للهواء بالتسرب عند نقطة الاتصال بين الجرّار والمقطورة","ضابط الخلوص غير مضبوط، مما يسمح بمسافة دفع مفرطة عند إحدى حجرات الفرامل","صمام التنفيس الأماني فُتح لأن ضغط الخزان تجاوز 150 psi أثناء الشحن","فشل المنظّم في الوصول إلى نقطة القطع، فلم يتوقف الضاغط عن ضخ الهواء في النظام"],"explanation":"أختام الكفّ المتصافحة البالية تسمح للهواء بالتسرب حيث تتصل خطوط هواء الجرّار والمقطورة، مما يسبب الهسهسة والتسرب المفرط."},"229":{"q":"لقد ربطت للتو جرّاري بمقطورة محمّلة ووصّلت خطوط الهواء. لا تزال خزانات هواء المقطورة فارغة، وأحتاج إلى إرسال الهواء إلى المقطورة لشحن نظام فراملها قبل أن أتمكن من إجراء فحوصات الفرامل. وأنا جالس في الكابينة، أي عنصر تحكم أُشغّل لإرسال الهواء إلى المقطورة؟","options":["أسحب المقبض الأصفر المعيّن الشكل لتحرير الضغط إلى المقطورة","أضغط المقبض الأحمر ثماني الأضلاع إلى الداخل لإرسال الهواء إلى المقطورة","أضغط دواسة فرامل الخدمة وأبقيها مضغوطة لضخّ الهواء عبر الخطوط","أسحب المقبض الأحمر ثماني الأضلاع لفتح خط الإمداد إلى المقطورة"],"explanation":"ضغط المقبض الأحمر ثماني الأضلاع الخاص بإمداد هواء المقطورة إلى الداخل يرسل الهواء من الجرّار إلى المقطورة لشحن نظام فراملها."},"230":{"q":"أقود جرّارًا ومقطورة عندما يتسبب تسرب في النظام في انخفاض ضغط الهواء لديّ إلى ما دون المستوى اللازم لإبقاء صمام إمداد هواء المقطورة مفتوحًا. دون أن ألمس أي شيء على لوحة القيادة، ماذا ينبغي أن أتوقع أن يفعله المقبض الأحمر ثماني الأضلاع الخاص بإمداد هواء المقطورة؟","options":["يبقى في مكانه ومضغوطًا إلى الداخل، لأن فرامل المقطورة تستجيب فقط للدواسة","يُضيء ويُطلق صفّارة لكنه يبقى مضغوطًا إلى الداخل حتى أسحبه بيدي","يخرج من تلقاء نفسه ويُغلق، فيطبّق فرامل الطوارئ في المقطورة تلقائيًا","يضغط نفسه إلى الداخل أكثر لعزل المقطورة والحفاظ على ضغط الهواء المتبقي"],"explanation":"إذا انخفض ضغط الهواء بشدة، يخرج المقبض الأحمر ثماني الأضلاع من تلقاء نفسه ويُغلق، فيطبّق فرامل الطوارئ في المقطورة تلقائيًا."},"231":{"q":"أثناء فحصي قبل الرحلة، يذكر ميكانيكيّي أن أحد المحاور في شاحنتي مزوّد بحجرات فرامل أكبر من الأخرى، ويسألني طالب جديد يرافقني عن الفرق الذي يحدثه ذلك عند ضغط دواسة الفرامل. مقارنةً بالحجرات الأصغر، ماذا تُنتج حجرة الفرامل الأكبر على ذلك المحور فعليًا؟","options":["تجعل ملمس الدواسة أكثر ليونة لأن الحجرة الأكبر تحتوي على هواء أكثر قبل أن يتحرك قضيب الدفع","تقلل من ناتج الكبح لأن الحجرة الأكبر تُسرّب ضغط الهواء بعيدًا عن ضابط الخلوص","لا تُنتج أي تغيير في الكبح، لأن حجم الحجرة يؤثر فقط على سرعة إعادة ملء الهواء","تُنتج قوة كبح أكبر لأن الحجرة الأكبر تدفع ضابط الخلوص بجهد أكبر"],"explanation":"حجرة الفرامل الأكبر لها مساحة سطح أكبر يعمل عليها الهواء، فتدفع ضابط الخلوص بقوة أكبر لمزيد من قوة الكبح."},"232":{"q":"أثناء فحصي قبل الرحلة، أضغط دواسة الفرامل وأراقب فرامل القاعدة ذات الكامة S على أحد محاور الدفع وهي تدور. أثناء دوران الكامة S، ماذا تفعل فعليًا داخل تجميعة الفرامل تلك لإبطاء العجلة؟","options":["تدفع بطانات الفرامل إلى الخارج بحيث تضغط أسطحها على الجزء الداخلي من طبلة الفرامل","تسحب بطانات الفرامل إلى الداخل بعيدًا عن الطبلة، حتى تتمكن نوابض الإرجاع من تحريرها","تُدير ضابط الخلوص ليتدارك الخلوص الحر في قضيب الدفع قبل بدء الكبح","تُفرّغ الهواء من حجرة الفرامل حتى تتمكن نوابض الفرامل من الضغط على الطبلة"],"explanation":"الكامة S الدوّارة تنحشر بين بطانات الفرامل، فتدفعها إلى الخارج بحيث تضغط أسطحها على الجزء الداخلي من طبلة الفرامل الدوّارة لإبطاء العجلة."},"233":{"q":"أثناء فحصي قبل الرحلة، أفحص فرامل القاعدة على جرّار مزوّد بفرامل قرصية هوائية بدلًا من النوع الطبليّ الأكثر شيوعًا. وبينما أنظر إلى تجميعة العجلة، أرى الفكّ (caliper) يحيط بمكوّن معدني مسطّح دوّار يضغط عليه الفكّ لإبطاء العجلة. لأصف نظام الفرامل القرصية الهوائية هذا بشكل صحيح في فحصي، فإن القطعة التي يطبق عليها الفكّ هي:","options":["طبلة الفرامل التي تضغط البطانات عليها إلى الخارج","القرص (rotor) الذي يضغط عليه الفكّ لإحداث الاحتكاك","حجرة فرامل النابض التي تطبّق الضغط","ضابط الخلوص الذي يتحرك قضيب الدفع عليه"],"explanation":"تستخدم الفرامل القرصية الهوائية فكًّا يطبق بطانات الاحتكاك على قرص دوّار (rotor) مثبّت على صرة العجلة لإحداث الاحتكاك الذي يبطئ العجلة."},"234":{"q":"أثناء فحصي قبل الرحلة، يشير ميكانيكيّ إلى حجرة فرامل كبيرة في شاحنتي ويسميها حجرة الـ'maxi'، ويخبرني أنها لا تستخدم ضغط الهواء لدفع القضيب إلى الخارج وإيقاف العجلة كما تفعل الحجرة الأصغر. بناءً على كيفية عمل هذا المكوّن فعليًا، ما هي حجرة الـ'maxi'؟","options":["إنها فرامل الخدمة، لأن حجرة الـmaxi هي الجزء الذي يطبّق قوة الكبح في كل مرة أضغط فيها دواسة القدم أثناء القيادة العادية","إنها صمام التحكم بالتعديل، لأن حجرة الـmaxi هي ما يتيح لي تطبيق الضغط تدريجيًا على المحور الخلفي في حالة الطوارئ","إنها فرامل النابض، لأن حجرة الـmaxi تحتوي على نابض قوي يطبّق الفرامل عند تحرير ضغط الهواء أو فقدانه","إنها وحدة إمداد هواء المقطورة، لأن حجرة الـmaxi هي ما يغذّي ويشحن الهواء إلى خزانات المقطورة أثناء القيادة"],"explanation":"حجرة الـmaxi (فرامل النابض) تحتوي على نابض مضغوط قوي يطبّق الفرامل كلما تم تحرير ضغط الهواء أو فقدانه، بدلًا من دفع القضيب بالهواء المطبّق."},"235":{"q":"أنا متوقف عند رصيف تحميل وشاحنتي مشحونة بالكامل بالهواء عند نحو 125 psi دون أي تسرب. بخلاف انخفاض ضغط الهواء إلى نطاق 20-45 psi، ما هي الطريقة الأخرى التي يمكن بها جعل فرامل النابض لديّ تُطبَّق؟","options":["بضغط دواسة فرامل الخدمة وإبقائها مضغوطة حتى الأرضية","بتشغيل مفتاح تحذير نظام منع انغلاق الفرامل (ABS)","بزيادة دوران المحرك حتى يصل المنظّم إلى نقطة القطع عند 125 psi","بسحب مقبض فرامل الركن الأصفر المعيّن الشكل إلى الخارج"],"explanation":"تُطبّق فرامل النابض يدويًا بسحب مقبض فرامل الركن الأصفر المعيّن الشكل إلى الخارج."},"236":{"q":"إنه صباح شتوي متجمد في منطقة بانهاندل، وجرّاري ومقطورتي مزودان بمبخّر كحول في نظام الفرامل الهوائية. وأنا أُجري فحصي قبل الرحلة وأبدأ القيادة، ما هي المهمة الرئيسية التي يقوم بها هذا الجهاز من أجلي في هذا الطقس البارد؟","options":["إضافة الكحول إلى نظام الهواء لمنع تكوّن الجليد وانسداد خطوط الفرامل الهوائية وصماماتها","إبقاء طبلات الفرامل وبطاناتها دافئة حتى لا تفقد فرامل الخدمة قوة إيقافها","إزالة الماء وزيت الضاغط من الخزانات حتى لا أعود مضطرًا إلى تصريفها يوميًا","رفع ضغط قطع المنظّم حتى يبني الضاغط الهواء أسرع في البرد"],"explanation":"يضيف مبخّر الكحول الكحول إلى نظام الهواء لخفض نقطة تجمّد الرطوبة ومنع تكوّن الجليد وانسداد خطوط الفرامل وصماماتها في الطقس البارد."},"237":{"q":"يتراكم ضغط الهواء فقط بينما:","options":["الراديو مُشغَّل","المحرك يعمل","الأبواب مفتوحة","الأضواء مُشغَّلة"],"explanation":"يتراكم الضغط فقط بينما يعمل المحرك."},"238":{"q":"أثناء فحصي قبل الرحلة، أترك المحرك يعمل وأراقب مقياس الهواء وهو يرتفع. يصل إلى نحو 125 psi وتتوقف الإبرة عن الارتفاع رغم استمرار عمل المحرك. لقد وصل المنظّم للتو إلى ضبط القطع لديه. ماذا يفعل الضاغط نفسه في هذه اللحظة بالضبط؟","options":["لقد توقف تمامًا مع المحرك، ولن يعمل مجددًا إلا عندما ينخفض الضغط إلى نحو 60 psi","يستمر في العمل لكنه يتوقف عن ضخ الهواء إلى الخزانات (أصبح غير مُحمَّل) حتى ينخفض الضغط إلى نحو 100 psi","يضخّ بقوة أكبر لدفع الضغط نحو ضبط صمام التنفيس الأماني عند 150 psi","يتعطّل ويُفرّغ الهواء الزائد عبر صمام التنفيس الأماني لحماية الخزانات"],"explanation":"عند نقطة قطع المنظّم (نحو 125 psi) يستمر الضاغط في الدوران لكنه يصبح غير مُحمَّل، فيتوقف عن إيصال الهواء إلى الخزانات حتى ينخفض الضغط إلى نقطة الوصل عند نحو 100 psi."},"239":{"q":"لقد فصلت للتو مقطورتي في الساحة وأقود الجرّار عائدًا إلى المحطة دون مقطورة (بوبتيل). يحتوي الطريق إلى المنزل على مقطع مستوٍ طويل، وساحة حصى مفتوحة أعبرها، وعدد من منحدرات الدخول إلى الطريق السريع، ومنعطف واسع قرب المخرج. أين ينبغي أن أكون أكثر حذرًا في إبطاء السرعة، لأن الجرّار البوبتيل يتعامل بشكل سيئ هناك؟","options":["على المقطع المستوي الطويل، لأن الشاحنة الأخف تتيح لي القيادة أسرع من المعتاد","في ساحة الحصى المفتوحة، لأن الأسطح غير الثابتة هي المكان الوحيد الذي يفقد فيه البوبتيل الإمساك","على المنعطفات ومنحدرات الدخول، حيث يمكن للجرّار البوبتيل أن يتعامل بشكل سيئ","لا مكان معيّن، لأن البوبتيل دون فرامل مقطورة وينعطف بشكل أفضل"],"explanation":"يفتقر الجرّار البوبتيل إلى وزن المقطورة فوق محاور الدفع ويتعامل بشكل سيئ، لذا أبطئ بقدر إضافي على المنعطفات ومنحدرات الدخول حيث تكون القوى أكبر."},"240":{"q":"أُنهي فحصي قبل الرحلة على جرّار ومقطورة في الساحة. لقد صرّفت بالفعل خزانات الهواء، وتأكدت من أن المنظّم يقطع عند نحو 125 psi، وتحققت من أن تحذير انخفاض الهواء يعمل قبل 60 psi. قبل أن أخرج إلى الطريق، أي مما يلي يجب أن أفعله بعد بخصوص الأضواء في مؤخرة مركبتي؟","options":["التأكد من أن العاكسات الخلفية مطليّة حديثًا حتى يراها السائقون الآخرون ليلًا","التأكد من أن أغلفة المصابيح الخلفية مغطّاة لحماية اللمبات من حطام الطريق","التأكد من أن أضواء العلامات الخلفية قد أُزيلت لتقليل الحمل الكهربائي","التأكد من أن أضواء الفرامل تعمل فعليًا عند ضغط دواسة الفرامل"],"explanation":"يتطلب الفحص قبل الرحلة التأكد من أن أضواء الفرامل تعمل فعليًا عند ضغط دواسة الفرامل، حتى تحصل حركة المرور الخلفية على إشارة بأنك تبطئ أو تتوقف."},"241":{"q":"أثناء اختبار التوقف عند 5 mph في فحصي قبل الرحلة، أضغط دواسة الفرامل فتنحرف الشاحنة بقوة إلى اليمين وتمسك الدواسة بشكل غير متساوٍ قبل التوقف. أي استنتاج صحيح؟","options":["الفرامل معيبة وتحتاج المركبة إلى الصيانة قبل أن يمكن قيادتها","هذا سلوك تأخّر طبيعي للفرامل ويمكنني التحرير ومتابعة الرحلة","ضغط الهواء مرتفع جدًا فقط، لذا ينبغي أن أُصرّف الخزانات وأعيد الاختبار","نظام ABS يقوم بعمله بالإمساك بعجلة واحدة، فلا حاجة لأي إجراء"],"explanation":"في اختبار الفرامل عند 5 mph، تكون الفرامل التي تنحرف إلى جانب واحد أو تمسك بشكل غير متساوٍ معيبة ويجب عدم قيادة المركبة حتى تُصان وتُصلَح."},"242":{"q":"أثناء فحصي قبل الرحلة، أزحف تحت المقطورة لفحص فرامل القاعدة عند كل عجلة. لقد تأكدت بالفعل من أن طبلات الفرامل وبطاناتها في حالة جيدة. لإكمال فحص مكوّنات فرامل القاعدة نفسها، أي قطعة ينبغي أن أفحص بعد ذلك؟","options":["مقبض فرامل الركن الأصفر المعيّن الشكل في الكابينة","ضوابط الخلوص المتصلة بقضيب دفع كل حجرة فرامل","المنظّم الذي يتحكم في وصل وقطع الضاغط","صمام التنفيس الأماني المثبّت على خزان الإمداد (الرطب)"],"explanation":"تربط ضوابط الخلوص قضيب دفع كل حجرة فرامل بآلية الفرامل، فتحوّل مسافة دفع القضيب إلى قوة كبح عند العجلة."},"243":{"q":"أثناء فحصي قبل الرحلة، أربط الكفّ المتصافح (glad hand) للجرّار والمقطورة، وأشحن نظام الهواء إلى نحو 125 psi، ثم أُطفئ المحرك. وبينما أنحني قرب نقطة الربط، أسمع بوضوح صوت هسهسة ثابت قادمًا من إحدى توصيلات الكفّ المتصافح. ماذا تخبرني هذه الهسهسة على الأرجح عن تلك التوصيلة؟","options":["الختم محكم تمامًا واجتازت التوصيلة الاختبار","يتم توجيه ضغط هواء إضافي لتعزيز فرامل المقطورة","الهواء يتسرب من التوصيلة بسبب وجود تسرب","خط الإمداد قد انتهى للتو من تصريف الماء المحتبس"],"explanation":"الهسهسة الثابتة عند توصيلة الكفّ المتصافح تعني أن الهواء المضغوط يتسرب عبر تسرب في الختم."},"244":{"q":"أقود جرّارًا ومقطورة مزودين بنظام ABS يعمل عندما تتوقف سيارة فجأة تمامًا في مساري. أحتاج إلى التوقف بأقصى قوة ممكنة مع إبقاء الشاحنة تحت السيطرة. ما هي الطريقة الصحيحة لاستخدام فراملي في هذه الحالة الطارئة؟","options":["أضغط دواسة الفرامل وأرفعها بسرعة بشكل متكرر حتى يتاح لنظام ABS وقت للتفاعل بين الضغطات","أضغط بقوة، ثم أُخفّف فور شعوري بنبض الدواسة، وأكرر ذلك في دفعات قصيرة","أضغط الدواسة مرة واحدة لتشغيل ABS، ثم أُناور حول الخطر دون كبح إضافي","أضغط الدواسة بقوة وأبقي الضغط ثابتًا، تاركًا نظام ABS يمنع انغلاق العجلات حتى أتمكن من التوجيه"],"explanation":"مع نظام ABS، اضغط دواسة الفرامل بقوة وأبقِ الضغط ثابتًا حتى يمنع النظام انغلاق العجلات وتحافظ على التحكم في التوجيه."},"245":{"q":"إنه صباح شتوي متجمد وأُجري فحصي قبل الرحلة على جرّار ومقطورة بفرامل هوائية. أدرك أنني نسيت تصريف خزانات الهواء خلال الأيام الماضية، وألاحظ رطوبة حول صمامات التصريف. لماذا يهم هذا بالنسبة لنظام الفرامل؟","options":["الماء وزيت الضاغط اللذان يتجمعان في الخزانات يمكن أن يُتلفا نظام الفرامل وقد يتجمدا في الطقس البارد، لذا يجب تصريف الخزانات يوميًا","كمية صغيرة من الماء والزيت في الخزانات تساعد في الواقع على تشحيم وإحكام صمامات الفرامل، فتخطّي التصريف أحيانًا غير ضار","لا يؤثر الماء والزيت على الكبح لأن صمام التنفيس الأماني سيُنفّسهما تلقائيًا عند نحو 150 psi","الرطوبة تهم فقط بالنسبة لفرامل الركن، فطالما تمسك فرامل الخدمة يمكنني تأجيل تصريف الخزانات بأمان حتى الربيع"],"explanation":"يجب تصريف خزانات الهواء يوميًا لأن الماء وزيت الضاغط يتجمعان فيها ويمكن أن يُتلفا نظام الفرامل أو يتجمدا في الطقس البارد."},"246":{"q":"إنه صباح متجمد وأثناء فحصك قبل الرحلة تلاحظ أن الماء وقليلًا من الحمأة الزيتية قد تجمّعا في خزان الإمداد (الرطب) خلال الليل. لإخراج هذا التلوث قبل أن يتجمد ويُتلف النظام، أي جهاز تُشغّل على ذلك الخزان؟","options":["صمام التنفيس الأماني، بدفعه ليفتح وينفّس الخزان","صمام التصريف (petcock) في أسفل الخزان","المنظّم، بقطعه لتحرير التراكم","إعادة ضبط صفّارة تحذير انخفاض الهواء، لتنظيف الخط"],"explanation":"يُزال الماء والزيت بفتح صمام التصريف، أو الـpetcock، الموجود في أسفل خزان الهواء."},"247":{"q":"أثناء فحصي قبل الرحلة، أترك نظام الهواء يبني الضغط حتى يمتلئ. أسمع فجأة دفعة هواء صاخبة تتسرب من صمام التنفيس الأماني على خزان الإمداد (الرطب). قبل القيادة، ماذا يخبرني هذا على الأرجح عن نظامي؟","options":["تحذير انخفاض ضغط الهواء فشل، فانخفض ضغط الخزان بهدوء إلى ما دون 60 psi.","المنظّم وصل مبكرًا فتوقف الضاغط عن إرسال الهواء إلى الخزانات.","فشل المنظّم في القطع، فارتفع الضغط متجاوزًا نحو 150 psi وأفرغ الصمام الزائد.","تسرب بطيء جعل الضغط ينخفض إلى نطاق 20 إلى 45 psi وفعّل فرامل النابض."],"explanation":"إذا فشل المنظّم في قطع الضاغط، يرتفع الضغط متجاوزًا نحو 150 psi ويفتح صمام التنفيس الأماني لإفراغ الهواء الزائد."},"248":{"q":"أثناء فحصي قبل الرحلة، يخبرني ميكانيكي الورشة أن أذهب لأتحقق من أن 'maxi-brakes' تمسك بشكل صحيح بينما المقطورة متوقفة. لست معتادًا على ذلك المصطلح العامّي. أي مكوّن في مركبتي ذات الفرامل الهوائية يقصده فعليًا؟","options":["فرامل الخدمة التي أطبّقها بدواسة القدم أثناء التوقف العادي","صمام التعديل الذي أستخدمه لتطبيق الفرامل تدريجيًا في حالة الطوارئ","ضوابط الخلوص التي تتحكم في مدى مسافة دفع القضيب","فرامل النابض التي تثبّت المركبة وتُطبَّق عند فقدان ضغط الهواء"],"explanation":"الـmaxi-brakes اسم آخر لفرامل النابض، التي تثبّت المركبة المتوقفة وتُطبَّق تلقائيًا عند فقدان ضغط الهواء."},"249":{"q":"أنتقل من سيارة إلى جرّار ومقطورة محمّلين مزودين بفرامل هوائية، ويسألني مدربي لماذا يهم إتقان نظام الفرامل الهوائية أكثر شيء بالنسبة لسائق CDL. أي إجابة تجسّد على أفضل وجه الغرض الأساسي من تعلّم الفرامل الهوائية؟","options":["إيقاف مركبة ثقيلة محمّلة بشكل آمن ومُتحكَّم فيه","السماح للشاحنة بالانزلاق والتسارع إلى سرعات قيادة أعلى","تقليل استهلاك الوقود بإبقاء ضاغط المحرك خاملًا","تقصير مسافة التوقف الإجمالية مقارنةً بالفرامل الهيدروليكية"],"explanation":"الغرض الرئيسي من نظام الفرامل الهوائية هو إيقاف مركبة ثقيلة محمّلة بشكل آمن ومُتحكَّم فيه."}},"combination":{"0":{"q":"تقود جرّارًا ومقطورة بطول 53 قدمًا وتقترب من منعطف يمين ضيق عند تقاطع في المدينة. وبينما تبدأ بتوجيه الجرّار عبر المنعطف، أين ستسير العجلات الخلفية لمقطورتك بالنسبة للمسار الذي تتبعه عجلاتك الأمامية (الجرّار)؟","options":["ستسير العجلات الخلفية في مسار داخلي أضيق من العجلات الأمامية، لذا يجب أن أنعطف بشكل واسع حتى تتجاوز المقطورة حافة الرصيف.","ستسير العجلات الخلفية في مسار خارجي أوسع من العجلات الأمامية، لذا ينبغي أن ألتصق بداخل المنعطف.","ستتبع العجلات الخلفية نفس مسار العجلات الأمامية تمامًا، لذا يمكنني الانعطاف كأنني أقود شاحنة مستقيمة.","لن تتبع العجلات الخلفية أي مسار يمكن التنبؤ به، لذا ينبغي أن أكبح بقوة في منتصف المنعطف للبقاء تحت السيطرة."],"explanation":"تسير العجلات الخلفية للمقطورة في مسار داخلي أضيق من العجلات الأمامية (الانحراف الداخلي للمسار)، لذا انعطف بشكل واسع بما يكفي حتى تتجاوز المقطورة الزاوية."},"1":{"q":"أنا أقود شاحنة بمقطورة وأحتاج إلى الانعطاف يميناً بشكل حاد عند تقاطع داخل المدينة. أعرف أن العجلات الخلفية للمقطورة تنحرف عن المسار وتتبع مساراً أضيق من محور التوجيه، وأريد منع المقطورة من صعود الرصيف. ما هي أفضل طريقة للتوجيه خلال هذا الانعطاف؟","options":["أوجِّه الجرار بعيداً نحو اليسار أولاً لفتح مساحة، ثم أكمل الانعطاف","أُبقي مؤخرة المقطورة قريبة من الرصيف وأتوسّع نحو الخارج فقط عند إنهاء الانعطاف","أبدأ بإدارة عجلة القيادة بحدة ومبكراً حتى تدور المركبة بأكملها قبل الوصول إلى الزاوية","أنحرف نحو الخط الأوسط قبل الزاوية كي تتوفر للمقطورة مساحة للقطع من الداخل"],"explanation":"بسبب انحراف المسار، أبقِ مؤخرة المقطورة قريبة من الرصيف وتوسّع نحو الخارج فقط عند إكمال الانعطاف كي تتجاوز الزاوية."},"2":{"q":"أنا أُجري فحص ما قبل الرحلة على شاحنتي ذات المقطورة وأتتبّع خراطيم الهواء الممتدة من خلف المقصورة إلى مقدمة المقطورة. وأنا أتتبّعها حتى وصلات اليد المتشابكة (glad-hand)، كم خط هواء ينبغي أن أتوقّع أن أجده يربط بين الوحدتين؟","options":["ثلاثة خطوط: خط الخدمة، وخط الطوارئ، وخط منفصل لنظام ABS","خط واحد، لأن خرطوم إمداد واحد يغذّي نظامي الخدمة والطوارئ معاً","خطان: خط الخدمة (التحكّم) وخط الطوارئ (الإمداد)","أربعة خطوط، خط لكل زوج من وصلات اليد المتشابكة على الوحدتين"],"explanation":"يُربط الجرار والمقطورة بخطّي هواء بالضبط: خط الخدمة (التحكّم) وخط الطوارئ (الإمداد)."},"3":{"q":"أثناء فحص ما قبل الرحلة، أقوم بوصل خطّي الهواء بين الجرار والمقطورة عند وصلات اليد المتشابكة. أعرف أن أحد الخطين يحمل إشارة الخدمة (التحكّم) والآخر هو خط الطوارئ (الإمداد) الذي يشحن خزانات المقطورة ويُطبّق فرامل النابض إذا فُقد هواؤه. ولكي أتأكّد من عدم خلطهما، أي لون من وصلات اليد المتشابكة يجب أن أطابقه مع خط الطوارئ (الإمداد)؟","options":["الأزرق، لأن خط الإمداد الذي يشحن خزانات المقطورة هو الخط ذو الأولوية الأعلى ويستخدم رمز اللون البارد","الأخضر، لأن ذلك الخط يغذّي هواء الطوارئ للمقطورة ويطابق دائرة أضواء التحديد على الوصلة المرنة","الأصفر، لأن الخط الذي يُشغّل فرامل النابض للمقطورة مُرمّز بلون التحذير أو الطوارئ","الأحمر، لأن خط الطوارئ (الإمداد) أحمر بينما خط الخدمة (التحكّم) أزرق"],"explanation":"وصلات اليد المتشابكة مُرمّزة بالألوان: الأحمر هو خط الطوارئ (الإمداد) والأزرق هو خط الخدمة (التحكّم)."},"4":{"q":"أنا أُجري فحص ما قبل الرحلة على شاحنة بمقطورة وأدفع المقبض الأحمر ثماني الأضلاع على لوحة القيادة إلى الداخل بالكامل. ثم أخرج وأمشي إلى الخلف لفحص المركبة. ماذا فعل دفع ذلك المقبض الأحمر للتو؟","options":["فتح إمداد هواء المقطورة، فشحن خزانات المقطورة وحرّر فرامل النابض (الطوارئ) للمقطورة كي تتمكّن المركبة من التحرّك","ضبط فرملة انتظار الجرار بتطبيق فرامل النابض على المحور الدافع","طبّق فرامل الخدمة للمقطورة عبر خط التحكّم الأزرق لإجراء اختبار فرامل","حرّر فرملة انتظار الجرار كي يتمكّن الجرار وحده من التدحرج إلى الأمام"],"explanation":"دفع المقبض الأحمر لإمداد هواء المقطورة إلى الداخل يشحن خزانات المقطورة ويحرّر فرامل النابض (الطوارئ) للمقطورة كي تتمكّن المركبة من التحرّك."},"5":{"q":"أنا أنقل مقطورة محمّلة على طريق ريفي سريع في تكساس عندما تنفصل المقطورة فجأة ويتسبّب عطل في الوصلة بتسرّب كبير للهواء في مؤخرة المركبة. ومع اندفاع الهواء إلى الخارج، ماذا صُمّم صمّام حماية الجرار ليفعله من أجلي في هذه اللحظة بالذات؟","options":["يُطبّق تلقائياً فرامل النابض للمقطورة كي توقف المقطورة الهاربة نفسها","يُغلق الخطوط للحفاظ على هواء كافٍ في نظام الجرار كي تبقى لديّ فرامل على وحدة القوة","يُعيد ضغط خزانات هواء المقطورة عبر خط الطوارئ كي أتمكّن من إعادة الوصل بأمان","يُحكم إغلاق فكّي العجلة الخامسة حول المسمار الملكي لمنع المقطورة من الانفصال"],"explanation":"إذا انخفض ضغط هواء المقطورة بشدّة، يُغلق صمّام حماية الجرار الخطوط للحفاظ على هواء كافٍ في نظام الجرار لفرملة وحدة القوة."},"6":{"q":"أنا أنقل مقطورة محمّلة على منحدر جبلي طويل، وأنا مُغرى باستخدام صمّام يد المقطورة (\"عتلة جونسون\") بلطف للمساعدة في إبطاء المركبة وإبقاء الجرار مستقيماً. أي استخدام لصمّام يد المقطورة صحيح فعلاً؟","options":["تطبيقه بثبات على كل منحدر لتخفيف الحرارة عن فرامل الخدمة للجرار.","استخدامه لتثبيت المركبة في مكانها بمجرّد أن أركن على الكتف لفحص حمولتي.","استخدامه فقط للتأكّد من أن فرامل المقطورة تعمل، لا للتحكّم في المركبة أثناء القيادة.","سحبه بدلاً من فرملة القدم لحظة بدء المقطورة بالانحراف، لإيقاف الانكسار الانحرافي."],"explanation":"صمّام يد المقطورة يُطبّق فرامل المقطورة فقط، لذا استخدمه حصراً لاختبار أنها تعمل، لا للتحكّم في المركبة أثناء القيادة، وإلا فقد يسبّب انزلاق المقطورة."},"7":{"q":"لقد رجعتُ بالجرار للتو تحت المقطورة وزحفتُ تحت المركبة بمصباح يدوي لفحص الوصلة قبل اختبار الشدّ. أستطيع رؤية أن الفكّين القافلين قد أُغلقا وأمسكا بالمسمار الملكي. ولتأكيد أن هذا وصل آمن وصحيح وليس وصلاً جزئياً قد يسمح للمقطورة بالسقوط، حول أي جزء من المسمار الملكي يجب أن يلتفّ الفكّان بالكامل؟","options":["حول الرأس العلوي للمسمار الملكي، لأن على الفكّين أن يمسكا بأعرض جزء كي لا ترتفع المقطورة","حول لوح القاعدة حيث يلتقي المسمار الملكي بالمقطورة، لأن ذلك يثبّت المقطورة بإحكام في العجلة الخامسة","حول طرف المسمار الملكي تماماً، طالما أن مزلاج الأمان وذراع التحرير في الوضع المقفل أيضاً","حول الساق، العنق الضيّق للمسمار الملكي، كي يكون الفكّان مغلقين بالكامل وليسا مجرّد مستقرّين فوقه"],"explanation":"يجب أن يُغلق الفكّان القافلان بالكامل حول ساق المسمار الملكي، العنق الضيّق، لا أن يستقرّا فوقه أو يمسكا بالطرف فقط، وإلا فإن الوصلة تبقى مفتوحة."},"8":{"q":"أثناء فحص ما قبل الرحلة لشاحنة بمقطورة موصولة حديثاً، أنحني وأسلّط مصباحي اليدوي على النقطة التي يلتقي عندها نصفا العجلة الخامسة العلوي والسفلي. أستطيع رؤية شريط رفيع من ضوء النهار بينهما. أيٌّ مما يلي هو الاستنتاج الصحيح حول هذه الفجوة؟","options":["يجب ألا تكون هناك أي فجوة على الإطلاق؛ فأي مساحة بين نصفي العجلة الخامسة تعني أن المسمار الملكي قد لا يكون مقفلاً بالكامل في الفكّين، لذا يجب ألا أقود حتى يُصحَّح ذلك.","فجوة بنحو 1 إنش (1 inch) مقبولة لأنها تترك مساحة كي تنثني الفكّان القافلان مع تحرّك المركبة فوق المطبّات.","فجوة صغيرة لا بأس بها طالما أن مزلاج الأمان مُشتبك وذراع التحرير في الوضع المقفل.","فجوة بنحو 2 إنش (2 inches) طبيعية لأن لوح العجلة الخامسة مُصمّم ليرتكز قليلاً فوق مئزر المقطورة."],"explanation":"يجب ألا تكون هناك أي فجوة بين نصفي العجلة الخامسة؛ فأي مساحة تعني أن المسمار الملكي قد لا يكون مقفلاً بالكامل، لذا لا تقد حتى يُصحَّح ذلك."},"9":{"q":"لقد رجعتُ بالجرار للتو تحت المقطورة ويبدو من صوت فكّي العجلة الخامسة أنهما أُغلقا على المسمار الملكي. وقبل أن أثق بالوصلة وأخرج إلى الطريق، أريد إجراء اختبار الشدّ لإثبات أن الوصلة مقفلة فعلاً. ولإجراء هذا الاختبار بشكل صحيح، ماذا ينبغي أن أفعل؟","options":["أترك فرامل المقطورة محرّرة وأتدحرج إلى الخلف بضعة إنشات لأشعر بالوصلة وهي تستقرّ في العجلة الخامسة","أقفل فرامل المقطورة، ثم أسحب إلى الأمام بلطف في ترس منخفض كي تشدّ المركبة على المقطورة المثبّتة","أضبط فرملة انتظار الجرار فقط، ثم أهزّ عجلة القيادة يميناً ويساراً لأرى ما إذا كانت المقطورة تتحرّك","أحرّر كل الفرامل وأنقر دواسة الوقود كي تتدحرج المقطورة بحرية، مستمعاً إلى صوت إغلاق الفكّين القافلين"],"explanation":"تأكّد من وصلة مقفلة باختبار الشدّ: أقفل فرامل المقطورة، ثم اسحب إلى الأمام بلطف في ترس منخفض كي تشدّ المركبة على المقطورة المثبّتة."},"10":{"q":"لقد أنهيتَ وصل شاحنتك بالمقطورة وتُجري جولة فحص ما قبل الرحلة النهائية قبل الخروج من الساحة. وأنت تفحص العجلات الداعمة (الهوائي)، أي حالة تخبرك أنها مضبوطة بشكل صحيح لبدء القيادة؟","options":["السيقان مُنزَلة حتى تلامس الأرض بالكاد، رافعةً قليلاً من الوزن عن العجلة الخامسة","السيقان مُنزَلة جزئياً كي يكون المقبض في متناول اليد بسهولة إذا احتجته على الطريق","السيقان مرفوعة بالكامل ومقبض الرفع مطويّ إلى الخلف ومقفل في وضعه المؤمّن","السيقان متروكة مرتكزة بخفّة على الرصيف كي لا تسقط المقطورة إذا فشلت الوصلة"],"explanation":"قبل القيادة، ارفع العجلات الداعمة بالكامل واطوِ مقبض الرفع واقفله كي لا يعلق أحدهما بشيء أو يصطدم به على الطريق."},"11":{"q":"لجعل المقطورة تتجه يميناً أثناء الرجوع للخلف، أَدِر عجلة القيادة أولاً نحو:","options":["اليمين","اليسار، ثم اتبعها","مستقيماً","لا يمكن التوجيه أثناء الرجوع للخلف"],"explanation":"الرجوع بمقطورة معاكس؛ أَدِر يساراً أولاً، ثم اتبعها."},"12":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ أن أختام المطاط لوصلات اليد المتشابكة، حيث يتصل خطّا الهواء للخدمة والطوارئ بالمقطورة، تبدو متشقّقة وبالية. أنا في عجلة. أي إجراء يُبقي نظام الهواء لديّ يعمل بشكل صحيح؟","options":["أنزع الأختام للحصول على تماس معدن بمعدن أكثر إحكاماً بين الوصلات","أربط خطّي الخدمة والطوارئ بشكل متقاطع كي يصل الهواء إلى المقطورة","ألطّخ طبقة من الزيت على الأختام لتليين التشقّقات وتحسين الإحكام","أستبدل الأختام البالية كي تبقى الوصلات محكمة وفي حالة جيدة"],"explanation":"استبدل أختام وصلات اليد المتشابكة البالية أو المتشقّقة لأنها تسرّب الهواء، مما يقلّل قوة فرملة المقطورة وقد يُطبّق فرامل النابض بشكل غير متوقّع."},"13":{"q":"أنا أنقل مقطورة صهريج محمّلة وأقترب من منحدر خروج منحنٍ على طريق سريع وحمولتي مُحمّلة بالفعل منخفضة وفي المنتصف. ولفعل الشيء الآخر الذي يمنع الانقلاب، أي إجراء ينبغي أن أتّخذه وأنا أتعامل مع هذا المنحدر؟","options":["أبطئ جيداً قبل دخولي المنحنى، لأن القيادة بسرعة كبيرة خلال المنعطف هي ما يقلب معظم المركبات","أحافظ على سرعتي على الطريق السريع خلال المنحدر كي يُبقي زخم المقطورة تتبّعها مستقيماً وثابتاً","أنتظر حتى أكون داخل المنحنى، ثم أفرمل بقوة لتقليل السرعة حيث يكون المنعطف أشدّ حدّة","أُجري تصحيحاً سريعاً وحازماً للتوجيه عند قمة المنعطف لإعادة المقطورة بسرعة إلى مساري"],"explanation":"أبطئ جيداً قبل دخول المنحنى، لأن القيادة بسرعة كبيرة خلال المنعطفات هي ما يقلب معظم المركبات المركّبة."},"14":{"q":"عادةً أقود شاحنتي ذات المقطورة فارغة في رحلات العودة بالجرار وحده، لكنني اليوم أنقل حمولة كاملة من الشحن المُرصّص على منصّات مكدّسة عالياً في الصندوق. وأنا أقترب من منحدر خروج معلوم على الطريق السريع، يخبرني زميل أنه يمكنني أخذ المنحنى بسرعتي المعتادة للمقطورة الفارغة لأن الحمولة الأثقل ستثبّت المركبة وتُبقيها مستقرّة. مقارنةً بقطع هذا المنحدر نفسه فارغاً، كيف تغيّر الحمولة الكاملة المكدّسة عالياً خطر الانقلاب لديّ فعلاً؟","options":["تقلّل خطر الانقلاب لديّ إلى نحو النصف، لأن الوزن المضاف يخفض المركبة على نظام تعليقها ويدفع مركز الثقل إلى الأسفل.","تجعلني أكثر عرضة للانقلاب بنحو 10 أضعاف، لأن الحمولة المكدّسة عالياً ترفع مركز الثقل وخطر الانقلاب يتصاعد بحدّة مع مقطورة محمّلة.","تترك خطر الانقلاب لديّ دون تغيير في الأساس، لأن الانقلاب يعتمد فقط على سرعة المنحدر ومدخلات التوجيه، لا على كيفية تحميل المقطورة.","تزيل خطر الانقلاب تقريباً بالكامل، لأن مقطورة محمّلة بالكامل أثقل من أن ترفع عجلة وتنقلب على منحدر عادي."],"explanation":"المركبة المحمّلة بالكامل أكثر عرضة للانقلاب بنحو 10 أضعاف من المركبة الفارغة لأن الحمولة ترفع مركز الثقل."},"15":{"q":"أنا أقود مركبة مركّبة محمّلة على الطريق السريع الولائي عندما يقتطع سيارة فجأة مساري أمامي مباشرةً. غريزتي هي أن أُدير عجلة القيادة بقوة للتفادي. وفقاً لدليل CDL في تكساس، لماذا تكون حركة التوجيه السريعة الحادة خطيرة بشكل خاص في هذا الموقف؟","options":["مدخل التوجيه المفاجئ سيقفل العجلات الدافعة، مسبّباً انكسار الجرار الانحرافي إلى الأمام","الانعطاف الحاد يُجبر العجلات الخلفية للمقطورة على اتباع مسار أعرض، فتندفع إلى المسار المجاور","التضخيم الخلفي يجعل مؤخرة المقطورة تنحرف أعرض بكثير من المقصورة، مما قد يقلب المقطورة","الحركة المفاجئة تُفرّغ الهواء من خط الخدمة، فتقطع قوة الفرملة عن عجلات المقطورة"],"explanation":"التضخيم الخلفي، تأثير \"طقطقة السوط\"، يجعل مؤخرة المقطورة تنحرف أعرض بكثير من المقصورة وقد يقلبها، لذا وجّه بلطف وغيّر المسارات ببطء."},"16":{"q":"أنت تنقل مقطورة محمّلة على منحدر مبتلّ وتنقر الفرامل لمركبة أبطأ أمامك. وعند النظر في مرآتك، ترى المقطورة تبدأ بالانحراف نحو الجانب خلف مقصورتك. ولإعادة المركبة تحت السيطرة، ماذا ينبغي أن تفعل؟","options":["اسحب صمّام يد المقطورة لتطبيق قوة فرملة إضافية على عجلات المقطورة وتقويمها","اضغط دواسة الفرامل بقوة أكبر لإبطاء المقطورة أسرع وإيقاف الانحراف الجانبي","وجّه بحدّة في الاتجاه المعاكس للانحراف لمواجهة حركة المقطورة","ارفع قدمك عن الفرامل كي تتمكّن عجلات المقطورة المقفلة من التدحرج واستعادة التماسك"],"explanation":"عندما تنحرف المقطورة نحو الخارج في انكسار انحرافي، حرّر الفرامل كي تتمكّن عجلات المقطورة المقفلة من التدحرج مجدّداً واستعادة التماسك."},"17":{"q":"أنا أفرمل بقوة على منحدر في شاحنتي المحمّلة ذات المقطورة عندما أشعر فجأة بمقدمة الجرار تبدأ بالانزلاق والانحراف نحو جانب المقصورة، فتبدأ بالانطواء على المقطورة. بناءً على ما يحدث، ما الذي تسبّب على الأرجح ببدء انكسار الجرار الانحرافي هذا؟","options":["فرملتُ بقوة مفرطة فأقفلتُ العجلات الدافعة للجرار، ففقدت التماسك وانحرف الجرار.","عجلات المقطورة أُقفلت، مما سحب مؤخرة المقطورة إلى الخارج ودفع الجرار جانبياً.","أخفقتُ في تطبيق صمّام يد المقطورة (عتلة جونسون) في الوقت المناسب لإبقاء مؤخرة المركبة مستقيمة.","إطارات التوجيه لديّ بالية، فقد المحور الأمامي تماسكه على سطح الطريق أثناء الفرملة."],"explanation":"يبدأ انكسار الجرار الانحرافي عندما تقفل الفرملة بقوة مفرطة العجلات الدافعة، فتفقد التماسك وينحرف الجرار نحو الخارج."},"18":{"q":"لقد أنزلتُ للتو مقطورتي المحمّلة في الساحة وأقود الجرار عائداً وحده (دون مقطورة موصولة). وأنا أقترب من إشارة حمراء، أيٌّ مما يلي ينبغي أن أتوقّعه مقارنةً بحين كنتُ أسحب المقطورة المحمّلة؟","options":["المحور الدافع عليه وزن أكبر، لذا ستكون الفرملة سريعة وأكيدة","سيستغرق الجرار على الأرجح وقتاً أطول للتوقّف لأن هناك وزناً قليلاً على العجلات الدافعة","لا يمكن للجرار أن ينزلق الآن، لذا يمكنني الفرملة بالكامل دون فقدان التماسك","الجرار لديه أفضل تماسك وهو وحده، لذا يمكنني المتابعة عن قرب أكبر"],"explanation":"الجرار الذي يسير وحده عليه وزن قليل على عجلاته الدافعة، مما يعطي تماسكاً ضعيفاً، لذا يستغرق عادةً وقتاً أطول للتوقّف ويحتاج مساحة توقّف إضافية."},"19":{"q":"أنا أقود مركبتي المركّبة على طريق سريع في تكساس عندما يعلق خرطوم هواء مقطورة بشيء ويمزّق خط الطوارئ (الإمداد) كلياً عن وصلة اليد المتشابكة، مُفرّغاً كل الهواء منه. أيٌّ مما يلي ينبغي أن أتوقّع حدوثه كنتيجة مباشرة؟","options":["لا يتغيّر شيء حتى أضغط دواسة الفرامل، لأن خط الطوارئ يحمل الهواء لفرملة الخدمة العادية فقط","تتدحرج المقطورة بحرية أكبر وقد تدفع الجرار إلى الأمام، لأن قطع ذلك الخط يحرّر فرامل المقطورة","تُطبّق فرامل النابض (الطوارئ) للمقطورة تلقائياً، لأن فقدان هواء خط الطوارئ يُشغّلها من تلقاء نفسها","تنقطع فقط أضواء المقطورة ودائرة تحذير ABS، لأن ذلك الخط يغذّي أيضاً الوصلة الكهربائية المرنة للمقطورة"],"explanation":"فقدان هواء خط الطوارئ يُطبّق تلقائياً فرامل النابض للمقطورة كإجراء أمان احتياطي."},"20":{"q":"أنا أصل جراري بمقطورة وأتتبّع خطّي الهواء بينهما. يُشير مدرّبي إلى خط الخدمة (التحكّم) ويسأل عن وظيفته بمجرّد أن أكون منطلقاً على الطريق السريع. أي إجابة تصف وظيفة خط الخدمة بشكل صحيح؟","options":["يشحن خزانات هواء المقطورة ويُطبّق فرامل النابض تلقائياً إذا فُقد ضغط الخط","يغذّي الهواء لإبقاء ضغط إطارات المقطورة ممتلئاً عبر وصلات اليد المتشابكة","يحمل التيار الكهربائي الذي يُشغّل أضواء فرامل المقطورة وإشارات الانعطاف","يحمل الإشارة من دواسة الفرامل أو صمّام اليد لتطبيق فرامل الخدمة للمقطورة"],"explanation":"خط الخدمة (التحكّم) يحمل الإشارة من دواسة الفرامل أو صمّام اليد لتطبيق فرامل الخدمة للمقطورة."},"21":{"q":"أنا أقود شاحنة محمّلة بمقطورة عندما يستمرّ تسرّب هواء بطيء لم أكتشفه في خفض ضغط نظامي. ومع هبوط المؤشّر، عند أي ضغط هواء تقريباً ينبغي أن أتوقّع خروج المقبض الأحمر لإمداد هواء المقطورة من تلقاء نفسه، مغلقاً صمّام حماية الجرار ومُطبّقاً فرامل الطوارئ للمقطورة؟","options":["في مكان ما ضمن نطاق 20 إلى 45 psi، مع انخفاض الضغط الذي يُشغّل صمّام حماية الجرار","حول 55 إلى 60 psi مباشرةً، حيث يظهر أول مرة جرس وضوء تحذير انخفاض الهواء","قرب 5 إلى 10 psi، فقط بعد أن يكون معظم الهواء القابل للاستخدام قد نفد بالفعل","عند نحو 100 psi، ضغط القطع العادي حيث يوقف المنظّم الضاغط"],"explanation":"يُغلق صمّام حماية الجرار تلقائياً ضمن نطاق 20 إلى 45 psi عندما ينخفض ضغط الهواء بشكل خطير."},"22":{"q":"أثناء فحص ما قبل الرحلة، أصِل بالخطأ وصلة اليد المتشابكة الزرقاء للخدمة بوصلة الطوارئ الحمراء والعكس، ثم أشحن النظام وتتدحرج المقطورة بشكل جيد دون ضوء تحذير. وعلى الطريق أضغط دواسة الفرامل بقوة للإبطاء عند إشارة. ما هي النتيجة الأرجح لخلط وصلتي اليد المتشابكتين؟","options":["ستقفل فرامل النابض للمقطورة تلقائياً وتسحب العجلات","لن أحصل على أي فرملة من المقطورة عندما أضغط دواسة فرامل الخدمة","ستتوهّج أضواء تحديد وأضواء جوانب المقطورة أكثر سطوعاً من المعتاد","ستُشحن خزانات هواء الجرار والمقطورة فوق ضغطها المضبوط"],"explanation":"خلط وصلتي اليد المتشابكتين يرسل إشارة فرملة الخدمة عبر الخط الخاطئ، فلا تتلقّاها فرامل المقطورة أبداً."},"23":{"q":"أنا أصل جراري بمقطورة في ساحة ضيّقة، والمقطورة مركونة بزاوية طفيفة بالنسبة للممرّ المفتوح خلفها. ولوضع جراري بشكل صحيح قبل أن أبدأ بالرجوع تحت المقطورة، ماذا ينبغي أن أفعل؟","options":["أرجع نحو المقطورة من الجانب بزاوية، ثم أقوّم الجرار تحت المسمار الملكي خلال الأقدام القليلة الأخيرة","أُمرّر الجرار إلى الأمام فوق المسمار الملكي أولاً، ثم أرجع مستقيماً إلى الخلف كي تسقط العجلة الخامسة عليه","أُعيد التموضع كي يكون الجرار مصطفّاً مباشرةً أمام المقطورة، ثم أرجع مستقيماً تحتها في خط مستقيم","أقترب من جانب السائق كي أستطيع مراقبة المسمار الملكي في مرآتي بينما أنحني بالجرار تحت المقطورة"],"explanation":"اصطفّ بالجرار مباشرةً أمام المقطورة وارجع مستقيماً تحتها كي تستقرّ العجلة الخامسة بالتساوي على المسمار الملكي."},"24":{"q":"أنا أصل جراري بمقطورة سأتركها في الساحة وأضبط ارتفاع المقطورة بالعجلات الداعمة قبل أن أرجع تحتها. ولأحصل على وصلة سليمة، أين ينبغي أن تكون مقدمة المقطورة بالنسبة لعجلتي الخامسة قبل أن أبدأ بالرجوع تحتها؟","options":["مستوية تماماً مع العجلة الخامسة كي ينزلق المسمار الملكي مباشرةً دون أن يضطرّ الجرار لرفعها","أعلى قليلاً من العجلة الخامسة كي تستقرّ المقطورة نزولاً على الفكّين القافلين وأنا أرجع","مرتكزة بالكامل على العجلات الداعمة كي يثبّتها الوزن بثبات أثناء إغلاق الفكّين","أخفض قليلاً من مركز العجلة الخامسة كي يرفع الجرار المقطورة قليلاً وهو يرجع تحتها"],"explanation":"اضبط المقطورة أخفض قليلاً من مركز العجلة الخامسة كي يرفعها الرجوع تحتها قليلاً لتماس محكم."},"25":{"q":"بعد الرجوع بالجرار تحت المقطورة ووصل خطوط الهواء، أخرج لفحص الوصلة عند العجلة الخامسة قبل اختبار الشدّ. وأنا أنظر إلى ذراع التحرير، أي حالة تخبرني أن العجلة الخامسة موصولة بشكل صحيح وآمنة للقيادة؟","options":["ذراع التحرير مرتدّ بالكامل إلى الوضع المقفل ومزلاج الأمان مُغلق فوقه","ذراع التحرير مسحوب إلى الوضع المفتوح كي يتمكّن الفكّان القافلان من الحركة بحرية","ذراع التحرير منزوع ومخزّن في المقصورة كي لا يعلق بالمسمار الملكي","ذراع التحرير مرتخٍ بقليل من اللعب كي يمتصّ اهتزاز الطريق"],"explanation":"الوصلة السليمة يكون فيها ذراع التحرير مرتدّاً بالكامل إلى الوضع المقفل ومزلاج الأمان مُغلقاً فوقه."},"26":{"q":"أثناء الفحص قبل الرحلة، ألاحظ أن جراري مزود بصحن خامس منزلق، وقد أعدت ضبط موضعه للتو لموازنة أوزان المحاور. قبل أن أنطلق إلى الطريق السريع، ما الذي يجب أن أتأكد منه بشأن المنزلق نفسه؟","options":["أن يكون منزلقًا إلى أقصى الأمام قدر الإمكان حتى تسير المقطورة أقرب ما يكون إلى المقصورة","أن تكون مسامير القفل فيه مثبتة بالكامل بحيث لا يمكن للمنزلق أن يتحرك أثناء القيادة","أن يُترك حرًا للانزلاق حتى يضبط نفسه تلقائيًا مع تحولات الوزن في الحمولة","أن يكون موضعه قد ضُبط فقط حسب أوزان المحاور المحملة ولا يحتاج إلى قفل"],"explanation":"يجب أن تكون مسامير قفل الصحن الخامس المنزلق مثبتة بالكامل بحيث لا يمكن للمنزلق أن يتحرك أثناء القيادة."},"27":{"q":"أثناء الفحص قبل الرحلة، ألاحظ أن الصحن الخامس المنزلق مقفل في موضع أبعد إلى الأمام بكثير مما أشغّله عادة، مما يجعل مقدمة المقطورة قريبة جدًا من مؤخرة مقصورتي. قبل أن أخرج من الساحة، أي عاقبة ينبغي أن تقلقني أكثر من غيرها بشأن القيادة والصحن الخامس مضبوط بهذا البعد إلى الأمام؟","options":["إنه ينقل الوزن بعيدًا عن محور التوجيه، مما يجعل المقدمة تبدو خفيفة والتوجيه غير دقيق عند سرعة الطريق السريع","ليس له تأثير حقيقي على تحميل المحاور طالما أن مسمار الارتكاز مقفل واختبار الشد ناجح","إنه يكدّس وزنًا زائدًا على محور التوجيه ويقلل المسافة الفاصلة بين المقطورة والمقصورة","إنه يحسّن جودة القيادة بتوزيع الحمولة بشكل أكثر تساويًا بين محور التوجيه ومحاور الدفع"],"explanation":"إن إزلاق الصحن الخامس بعيدًا جدًا إلى الأمام يثقل محور التوجيه بشكل زائد ويقلل المسافة الفاصلة بين المقطورة والمقصورة."},"28":{"q":"أثناء فحصك قبل الرحلة، تنتهي من توصيل خطي الهواء للخدمة والطوارئ والوصلة الكهربائية بين الجرار والمقطورة. قبل أن تصعد إلى المقصورة، ما الشرط الذي يجب أن تستوفيه هذه الخطوط لاجتياز الفحص؟","options":["يجب أن تتدلى بارتخاء إضافي حتى تجرّ قليلًا على الأرض، مما يمنع الشد عند انعطاف الشاحنة بحدة","يجب أن تُلف في لفات محكمة بجانب المقصورة حتى لا يبقى أي طول مكشوف بين الوحدتين","يجب أن تُترك غير موصولة في الطرق ذات المنعطفات الحادة حتى لا تتعرض الأيدي والوصلة للإجهاد أثناء الانعطاف","يجب أن تُثبّت إلى الأعلى وتُدعَم بحيث لا يمكنها أن تحتك أو تُجرّ على الأرض أو الممشى أو عمود الإدارة"],"explanation":"يجب تثبيت خطوط الهواء والوصلة الكهربائية إلى الأعلى ودعمها بحيث لا يمكنها أن تحتك أو تُجرّ على الأرض أو الممشى أو عمود الإدارة."},"29":{"q":"أثناء فحصي قبل الرحلة لجرار ومقطورة في صباح ممطر، ألاحظ أن واقيات الطين خلف عجلات المقطورة الخلفية تتدلى بارتخاء، مع فقدان أحد براغي الحامل. قبل أن أقود، ما الشرط الصحيح الذي يجب أن تستوفيه واقيات الرذاذ هذه؟","options":["يجب أن تكون موجودة ومثبتة بإحكام بحيث تحدّ من الرذاذ المتطاير على المركبات التي تتبعني من الخلف","يجب أن تكون في مكانها فقط إذا كنت أنقل حمولة ثقيلة على طريق سريع مبلل","يمكن أن تتدلى بارتخاء طالما أنها لا تجرّ فعليًا على سطح الرصيف","يجب إزالتها في الطقس الممطر حتى لا يتراكم الماء والطين المحتجزان خلفها"],"explanation":"يجب أن تكون واقيات الطين موجودة ومثبتة بإحكام للحدّ من الرذاذ المتطاير على المركبات التي تتبع من الخلف."},"30":{"q":"أنت تترك مقطورتك المحملة في الساحة كي يأخذها سائق آخر لاحقًا. ما زالت فكا الصحن الخامس مقفلين على مسمار الارتكاز وما زالت خطوط الهواء موصولة. قبل أن تفعل أي شيء آخر لفصل الوصلة، ما الخطوة التي يجب أن تتخذها أولًا لمنع المقطورة من السقوط على مقدمتها بمجرد أن تسحب الجرار من تحتها؟","options":["اسحب مقبض تحرير الصحن الخامس حتى يُفتح فكا القفل ويتحرر مسمار الارتكاز","أنزل العتاد السفلي حتى يلامس الأرض بالكاد، ثم لفّه بضع لفات إضافية لتحميل بعض الوزن عليه","لفّ العتاد السفلي إلى الأسفل بالكامل حتى يرفع المقطورة عن الصحن الخامس","حرر مكابح ركن المقطورة حتى لا تقاوم مكابح الزنبرك الجرار وأنت تسحبه للخارج"],"explanation":"عند فك الوصلة، أنزل أولًا العتاد السفلي حتى يلامس الأرض بالكاد، ثم لفّه بضع لفات إضافية لتحميل بعض الوزن عليه."},"31":{"q":"لقد ركّبت للتو على مقطورة غير مألوفة وأقوم بفحصي قبل الرحلة. أريد أن أتأكد من أن نظام المكابح المانع للانغلاق في المقطورة يعمل قبل أن أنطلق. أين أنظر لأجد المؤشر الذي يخبرني بوجود عطل في نظام المكابح المانع للانغلاق في المقطورة؟","options":["مصباح تحذير أحمر مثبت على لوحة القيادة داخل المقصورة، بجانب مصباح نظام منع الانغلاق في الجرار","عداد على مسمار ارتكاز المقطورة يضيء عندما لا يكون فكا القفل مغلقين بالكامل","مصباح عطل أصفر على الجانب الأيسر من المقطورة يبقى مضاءً إذا كان نظام منع الانغلاق معطلًا","لا يوجد مؤشر منفصل للمقطورة؛ فلوحة عدادات الجرار تغطي جميع أعطال نظام منع الانغلاق"],"explanation":"مصباح عطل نظام منع الانغلاق في المقطورة أصفر اللون ويقع على الجانب الأيسر؛ إذا بقي مضاءً فإن نظام منع الانغلاق في المقطورة معطل."},"32":{"q":"أنا أقود جرارًا ونصف مقطورة محملًا بسرعة الطريق السريع عندما تتجاوزني سيارة فجأة وتقطع طريقي أمامي، تاركةً كتفًا مفتوحًا على يميني. لا توجد مسافة كافية للتوقف في الوقت المناسب. أي استجابة تمنحني أفضل فرصة لتجنب الاصطدام دون فقدان السيطرة على الشاحنة؟","options":["أضغط على دواسة المكابح بأقصى ما أستطيع حتى تتوقف الشاحنة في أقصر مسافة ممكنة قبل الوصول إلى السيارة","أسحب صمام يد المقطورة وأبقيه لتفعيل مكابح المقطورة فقط، لأن ذلك يبقي المقطورة مستقيمة خلفي","أُقفل عجلات الدفع وأترك الجرار ينزلق حتى يتوقف في خط مستقيم خلف السيارة","أتوجه بسلاسة حول الخطر ثم أعكس التوجيه للعودة إلى مساري، مع إبقاء الكبح خفيفًا لتجنب الانزلاق"],"explanation":"إن التوجيه بسلاسة حول الخطر ثم عكس التوجيه يبقي العجلات دائرة، بينما يمكن للكبح الشديد أن يُقفل العجلات ويسبب انكسار الشاحنة."},"33":{"q":"لقد رجعت بجراري للتو تحت المقطورة وانزلق مسمار الارتكاز داخل الصحن الخامس. قبل أن أصعد وأنطلق إلى الطريق السريع، أي مما يلي يصف ما يجب أن أتأكد منه للتيقن من أن الوصلة آمنة فعلًا؟","options":["لا توجد فجوة بين الصحن الخامس العلوي والسفلي، وفكا القفل مغلقان بالكامل حول مسمار الارتكاز، واختبار الشد في غيار منخفض يثبت مع قفل مكابح المقطورة.","فكا القفل مغلقان حول مسمار الارتكاز واختبار الشد يثبت، لأن أي فجوة صغيرة عند الصحن الخامس ستُغلق بمجرد استقرار الوزن على المقطورة.","اختبار الشد في غيار منخفض يثبت ولا توجد فجوة عند الصحن الخامس، لذا فإن إلقاء نظرة سريعة تحت المقطورة للتأكد من الفكين غير ضروري.","فكا القفل مغلقان حول مسمار الارتكاز ولا توجد فجوة عند الصحن الخامس، لذا فإن اختبار الشد مطلوب فقط عندما تكون المقطورة محملة بشدة."],"explanation":"تتطلب الوصلة الآمنة الأمور الثلاثة جميعها: عدم وجود فجوة بين الصحنين الخامسين، وانغلاق فكي القفل بالكامل حول مسمار الارتكاز، واختبار شد يثبت."},"34":{"q":"أنا في الساحة أربط جراري بمقطورة محملة، وأريد أن أمر بإجراءات التركيب بالترتيب حتى لا أفوّت أي شيء. يقرأ لي شريكي قائمة مهام. كل بند ينتمي إلى عملية التركيب باستثناء واحد، وهو في الحقيقة مهمة منفصلة لصيانة المكابح ولا مكان لها في التركيب. أي مهمة يجب أن أشطبها من قائمة التركيب؟","options":["ارجع ببطء تحت المقطورة حتى يستقر مسمار الارتكاز وينغلق فكا القفل حوله","صرّف الماء والزيت من خزانات الهواء باستخدام صمامات تصريف الخزان","وصّل خطي هواء الخدمة والطوارئ عبر الأيدي دون تقاطعهما","اصطفّ بالجرار بشكل مستقيم أمام المقطورة قبل الرجوع تحتها"],"explanation":"إن تصريف الماء والزيت من خزانات الهواء مهمة تتعلق بنظام المكابح، وليست جزءًا من تركيب الجرار بالمقطورة."},"35":{"q":"أنت تنقل تركيبة مسطحة منخفضة الارتفاع، وعلقت بطن مقطورتك على مزلقان قطار محدّب — توقفت الشاحنة تمامًا متمددة فوق القضبان، ولا يمكنك الانحراف بعيدًا. قد يكون قطار على بعد دقائق. ماذا يجب أن تفعل أولًا؟","options":["هزّ الجرار للأمام والخلف في غيار منخفض لترتدّ المقطورة وتتحرر من القضبان","اسحب صمام يد المقطورة، ثم أنزل العتاد السفلي لإسقاط المقطورة بعيدًا","اخرج من المقصورة فورًا واتصل برقم الطوارئ المعلق عند المزلقان","ابقَ مربوطًا بحزام الأمان في المقصورة وانتظر، راقبًا مراياك حتى تستقر المقطورة بحرية"],"explanation":"إذا علقت على مزلقان قطار، أخرج جميع من في المركبة فورًا واتصل برقم الطوارئ المعلق عند المزلقان."},"36":{"q":"لقد حصلت للتو على رخصتي التجارية، ويسلّمني المرسل أربع مهام قيادة مختلفة للأسبوع. واحدة منها فقط تُعدّ قانونيًا تشغيل \"مركبة مركّبة\" كما هي معرّفة في الدليل. أي مهمة هي المركبة المركّبة؟","options":["قيادة حافلة نقل عام واحدة طولها 40 قدمًا على مسار مدينة ثابت طوال اليوم","تشغيل شاحنة صندوقية مستقيمة حيث يكون جسم الحمولة مثبتًا بشكل دائم على نفس الهيكل الذي يحمل المحرك","نقل حمولة ثقيلة في شاحنة قلابة لا تحتوي على مقطورة متصلة خلفها","سحب نصف مقطورة محملة خلف جرار مركّب عند الصحن الخامس"],"explanation":"المركبة المركّبة هي وحدة قدرة منفصلة، مثل الجرار، مركّبة بمقطورة واحدة أو أكثر عند الصحن الخامس."},"37":{"q":"أنا أرجع بجراري تحت مقطورة للتركيب. وبينما ينزلق الصحن الخامس تحت مئزر المقطورة، أسمع نقرة وأشعر باستقرار الشاحنة. لكي تكون الوصلة مقفلة فعلًا وآمنة للسحب، ما الذي يجب تحديدًا أن يكون قد حدث لمسمار ارتكاز المقطورة عند تلك النقرة؟","options":["انغلق فكا قفل الصحن الخامس تمامًا حول ساق مسمار الارتكاز","هبط مسمار الارتكاز خلف المصد الخلفي ليرتكز على هيكل المقطورة","استقر مسمار الارتكاز على حامل واقي الطين لمنعه من الانزلاق للخارج","اتصل مسمار الارتكاز بمقبس الوصلة الكهربائية لإكمال دائرة القفل"],"explanation":"يحدث التركيب الصحيح عندما ينغلق فكا قفل الصحن الخامس تمامًا حول ساق مسمار الارتكاز، وليس فقط حول طرفه أو أعلاه."},"38":{"q":"أثناء فحصي قبل الرحلة، أفحص لوح الصحن الخامس حيث يلامس الجزء السفلي من المقطورة. يبدو السطح جافًا وصدئًا قليلًا، وألاحظ أن الجرار كان يتجه بصعوبة عبر المنعطفات الحادة. لإبقاء الصحن الخامس يعمل بشكل صحيح وتقليل التآكل على الوصلة، ماذا يجب أن أفعل بسطح ذلك اللوح؟","options":["امسحه نظيفًا وجافًا، ثم اتركه عاريًا حتى لا يلتصق به حصى الطريق","أبقِه مشحّمًا بشكل صحيح (مزيّتًا) حتى يتمكن من الدوران بحرية تحت المقطورة","اطلِه بطلاء لامع لإغلاق المعدن ومنع الصدأ من الانتشار","اترك السطح مرتخيًا ومتآكلًا قليلًا حتى ينثني اللوح أثناء المنعطفات"],"explanation":"أبقِ الصحن الخامس مشحّمًا بشكل صحيح حتى يتمكن من الدوران بحرية تحت المقطورة، مما يقلل التآكل ويمنع صعوبة التوجيه."},"39":{"q":"أثناء فحصي قبل الرحلة، أزحف تحت مقدمة مقطورتي لفحص الوصلة. أرى اللوح الفولاذي المسطح الذي يجلس مباشرة فوق الصحن الخامس، وأتتبع مسمار الارتكاز نزولًا منه إلى فكي القفل. أي مكوّن من مكونات المقطورة أنظر إليه عندما أحدد ذلك اللوح المسطح المستقر على الصحن الخامس؟","options":["فكا القفل، اللذان يمسكان اللوح من الأسفل","العتاد السفلي، الذي يحمل اللوح عند الركن","المئزر، الذي يمتد منه مسمار الارتكاز نزولًا","اللوح الواقي، الذي يحمي الجزء السفلي من المقصورة"],"explanation":"المئزر هو اللوح المسطح الذي يستقر على الصحن الخامس، ويمتد مسمار الارتكاز نزولًا مباشرة منه إلى فكي القفل."},"40":{"q":"لقد رجعت بجرارك للتو تحت المقطورة وسمعت صوت اصطدام عند تعشيق الصحن الخامس. قبل أن تثق بالوصلة، تريد أن تتأكد من أن فكي القفل قد انغلقا فعلًا تمامًا حول ساق مسمار الارتكاز، وليس فقط أمسكا بطرفه. أي إجراء يمنحك دليلًا قاطعًا على أن الفكين مغلقان؟","options":["راقب مرايا المقطورة وأنت تشد للأمام وتأكد من أن لا شيء يتأرجح إلى الجانب","اسحب صمام يد المقطورة (العتلة) واستمع إلى تفعيل مكابح المقطورة","اصعد وتحسس الفجوة بين لوحي الصحن الخامس العلوي والسفلي","انحنِ وسلّط ضوء مصباح يدوي مباشرة تحت المقطورة لترى الفكين مغلقين حول مسمار الارتكاز"],"explanation":"انحنِ وسلّط ضوء مصباح يدوي مباشرة تحت المقطورة لتؤكد بصريًا أن فكي القفل مغلقان حول مسمار الارتكاز."},"41":{"q":"أنا أركّب جراري بمقطورة متروكة في الساحة وأستعد للرجوع تحتها. للتأكد من أن الصحن الخامس ينزلق بشكل صحيح وأن فكي القفل ينغلقان حول مسمار الارتكاز، كيف يجب أن أضبط ارتفاع المقطورة قبل أن أبدأ الرجوع؟","options":["اضبطه أخفض قليلًا من مركز الصحن الخامس، حتى يرفع الجرار المقطورة قليلًا عند رجوعه تحتها","اضبطه أعلى قليلًا من الصحن الخامس، حتى يهبط مسمار الارتكاز إلى فكي القفل عند رجوعك تحتها","اضبطه بمستوى الصحن الخامس تمامًا، حتى يلتقي اللوحان مسطحين دون رفع أو احتكاك","اضبطه عاليًا بما يكفي ليتجاوز المقطورة الصحن الخامس تمامًا حتى يصطف مسمار الارتكاز"],"explanation":"اضبط المقطورة أخفض قليلًا من مركز الصحن الخامس حتى يرفعها الجرار قليلًا عند رجوعه تحتها، مما يضمن انغلاق الفكين بالكامل."},"42":{"q":"أثناء فحصي قبل الرحلة على جرار ومقطورة، أوصّل كلا خطي هواء الأيدي وأشغّل المحرك. قبل أن أتمكن من بناء الضغط في المقطورة والتحرك، أحتاج إلى أن أتأكد من فهمي لوظيفة كل خط. ما الوظيفة المحددة لخط الهواء الإمدادي (الطوارئ)؟","options":["يفعّل مكابح خدمة المقطورة كلما ضغطت على دواسة مكابح القدم","يرسل الهواء من الجرار لملء وشحن خزانات هواء المقطورة","يحرر مكابح زنبرك المقطورة فقط عندما أسحب صمام يد المقطورة","يحمل الإشارة الكهربائية التي تشغّل أضواء مكابح المقطورة"],"explanation":"يحمل خط الإمداد (الطوارئ) الهواء من الجرار لملء وشحن خزانات هواء المقطورة، وفقدان ذلك الهواء يفعّل تلقائيًا مكابح زنبرك المقطورة."},"43":{"q":"أنت تقود جرارًا ومقطورة محملًا عندما تنفلت خرطوم على خط الطوارئ (الإمداد) ويتسرب هواء المقطورة. أي حدث سيؤدي إلى تفعيل مكابح زنبرك (الطوارئ) في المقطورة؟","options":["يفقد خط الخدمة (التحكم) الضغط بينما تبقي قدمك بعيدًا عن دواسة المكابح","تحرر صمام يد المقطورة بعد فحص المكابح","يفقد خط الطوارئ (الإمداد) هواءه","يرشح ختم يد الهواء الأزرق قليلًا لكن الخط ما زال يحتفظ بالهواء"],"explanation":"عندما يفقد خط الطوارئ (الإمداد) هواءه، تُفعّل مكابح زنبرك المقطورة تلقائيًا وتوقف المقطورة."},"44":{"q":"أنا عادة أقود جرارًا ومقطورة واحدة، لكن اليوم أسحب مجموعة مزدوجة أطول وأثقل على نفس مسار الطريق السريع وبنفس السرعة. وأنا أتبع حركة المرور أمامي، كيف يجب أن أعدّل المسافة التي أحتفظ بها أمامي مقارنة بما أستخدمه عادة؟","options":["أبقي نفس مسافة الاتباع، لأن سرعة الطريق السريع هي التي تحدد المسافة، لا طول الشاحنة أو وزنها","أقلل مسافة الاتباع قليلًا، لأن المقطورة الإضافية خلفي تساعد على دفع الشاحنة للتوقف أسرع","أبقي نفس الفجوة لكن أعتمد على كبح أشد، لأن مكابح التركيبة الأطول مصممة لتعويض الفرق","أزيد مسافة الاتباع عما أستخدمه عادة، لأن التركيبة الأطول والأثقل تحتاج إلى مساحة ووقت أكثر للتوقف"],"explanation":"تحمل المركبات المركّبة الأطول والأثقل زخمًا أكبر وتحتاج إلى مسافة اتباع ومساحة توقف إضافية."},"45":{"q":"أنت تنقل مقطورة محملة طولها 53 قدمًا وتحتاج إلى الانعطاف بحدة إلى اليمين عند تقاطع في المدينة. الرصيف على يمينك مصطفّة عليه سيارات مركونة، وأنت تعلم أن عجلات مقطورتك الخلفية تنحرف عن المسار. لإدارة الشاحنة حول الزاوية دون أن تتسلق المقطورة الرصيف أو تصطدم بالسيارات المركونة، كيف يجب أن توقّت بداية انعطافك؟","options":["ابدأ التوجيه بعد قليل مما تفعله في سيارة، ثم انعطف بشكل واسع وأنت تكمل المنعطف حتى يتجاوز المسار الداخلي للمقطورة الرصيف","ابدأ التوجيه أبكر مما تفعل سيارة حتى يكون لمقدمة الجرار مساحة إضافية لتدوير الزاوية أولًا","ابدأ المنعطف في نفس اللحظة التي تبدأ فيها سيارة، لأن المقطورة تتبع ببساطة نفس المسار الذي يتبعه الجرار تمامًا","ابدأ التوجيه بحدة وباكرًا، ثم استقم بسرعة حتى تنطلق الشاحنة بأكملها بنظافة عبر المنعطف"],"explanation":"بسبب الانحراف عن المسار، تتبع عجلات المقطورة الخلفية مسارًا داخليًا أضيق، لذا ابدأ المنعطف متأخرًا وانعطف بشكل واسع حتى تتجاوز الرصيف."},"46":{"q":"لقد أوقفت جراري ومقطورتي المحملين على منحدر هابط طفيف في ساحة وأحتاج إلى تركهما مركونين بينما أدخل لإحضار الأوراق. للتأكد من بقاء الشاحنة في مكانها، ماذا يجب أن أفعل؟","options":["اسحب صمام يد المقطورة (العتلة) إلى الأسفل واتركه مفعّلًا لتثبيت الشاحنة","فعّل مكابح الركن وضع حواجز تحت العجلات بسبب المنحدر","اترك ناقل الحركة في غيار منخفض ودع المحرك يدور حتى يثبت نفسه","فعّل مكبح ركن الجرار فقط، لأن ذلك يقفل كل محور في الوحدة"],"explanation":"للركن بأمان على منحدر، فعّل مكابح الركن وضع حواجز تحت العجلات حتى تكون الشاحنة مؤمّنة بشكل مستقل عن ضغط الهواء أو المحرك."},"47":{"q":"لقد أوقفت شاحنتي المركّبة على منحدر هابط طفيف في ساحة وأحتاج إلى الخروج من المقصورة لعدة دقائق. أمدّ يدي إلى صمام يد المقطورة (العتلة/العتلة اليدوية) لمنع الشاحنة من التحرك بينما أكون بعيدًا. وفقًا لتدريب الرخصة التجارية، لماذا تُعدّ هذه خطوة خاطئة؟","options":["لأن صمام اليد يفعّل مكابح محور دفع الجرار فقط، وهي أضعف من أن تثبّت شاحنة محملة على أي منحدر","لأن استخدام صمام اليد أثناء الركن يقاطع خطي الهواء للخدمة والطوارئ ويمكن أن يتلف أختام الأيدي","لأن الهواء يمكن أن يتسرب بمرور الوقت ويحرر مكابح المقطورة، مما يجعل المقطورة تتدحرج","لأن صمام اليد يجب أن يُقرن بمكبح الركن، واستخدامه وحده يفرط في ضغط مكابح زنبرك المقطورة"],"explanation":"لا تركن أبدًا باستخدام صمام يد المقطورة، لأن هواءه يمكن أن يتسرب بمرور الوقت، مما يحرر مكابح الخدمة ويجعل المقطورة تتدحرج."},"48":{"q":"أنا أقود جرارًا ومقطورة محملًا نزولًا على منحدر طويل وتدفعني الشاحنة أسرع مما أريد. بدلًا من استخدام مكبح القدم، أمدّ يدي إلى صمام يد المقطورة (\"العتلة اليدوية\") وأفعّل مكابح المقطورة فقط للإبطاء. على الرصيف المبلل، ما النتيجة الأكثر احتمالًا للكبح بهذه الطريقة؟","options":["تسحب مكابح المقطورة الشاحنة في خط مستقيم وتمنحني توقفًا أكثر سلاسة وتحكمًا مما يفعله مكبح القدم","تُقفل عجلات دفع الجرار أولًا، فتدفع مقدمة المقصورة للخارج في انكسار للجرار","لا يتغير شيء، لأن صمام اليد يطبّق نفس قوة الكبح التي يطبّقها مكبح قدمي على جميع المحاور","يمكن لعجلات المقطورة أن تنغلق وتتأرجح المقطورة إلى الجانب في انزلاق أو انكسار"],"explanation":"يفعّل صمام يد المقطورة مكابح المقطورة فقط، والتي يمكن أن تنغلق وتجعل المقطورة تتأرجح إلى الجانب في انزلاق أو انكسار."},"49":{"q":"لقد أنزلت حمولتي الكاملة للتو عند الرصيف وأعود بمقطورة فارغة على نفس الطريق الوعر الذي جئت منه. مقارنة بالرحلة المحملة، ماذا يجب أن أتوقع من المقطورة الفارغة وكيف يجب أن أقودها؟","options":["المقطورة الفارغة لديها جر أقل وعجلاتها ترتد أكثر، لذا يمكن أن تنزلق بسهولة — يجب أن أكبح بلطف وباكرًا","المقطورة الفارغة لديها جر أكثر لأن الوزن الأخف يجعل الإطارات تتشبث بقوة أكبر، لذا يمكنني الكبح متأخرًا وبقوة","المقطورة الفارغة تتوقف في مسافة أقصر بكثير، لذا يمكنني بأمان تقليص مسافة اتباعي على الطريق الوعر","المقطورة الفارغة خفيفة جدًا لدرجة أنها لا يمكن أن تنقلب، لذا يمكنني أخذ المنعطفات والمنحدرات بسرعتي المعتادة عند التحميل"],"explanation":"للمقطورة الفارغة أو المحملة خفيفًا جرٌّ أقل وترتد عجلاتها وتنغلق بسهولة، لذا اكبح بلطف وباكرًا لتجنب الانزلاقات."},"50":{"q":"أثناء فحصي قبل الرحلة، أتتبع السلك الكهربائي الملفوف (الوصلة) الممتد من مؤخرة جراري إلى المقبس في مقدمة المقطورة. يسألني متدرب عما سيتوقف عن العمل إذا انفلت هذا السلك وانفصل بينما أنا أقود. أي إجابة صحيحة؟","options":["ستُفعّل مكابح زنبرك (الطوارئ) المقطورة تلقائيًا","ستفقد أضواء المقطورة ونظام المكابح المانع للانغلاق الطاقة","سيفقد خط هواء الخدمة الضغط وستحتك المكابح","سيتحرر فكا قفل الصحن الخامس من مسمار الارتكاز"],"explanation":"الوصلة هي الاتصال الكهربائي الذي يشغّل أضواء المقطورة ونظام المكابح المانع للانغلاق، لذا فإن فصلها يقطع الطاقة عن كليهما."},"51":{"q":"أثناء فحص ما قبل الرحلة، أزحف تحت مؤخرة القاطرة لفحص مجموعة العجلة الخامسة حيث تُثبَّت بالبراغي على الهيكل. بخلاف التأكد من أن الوحدة مشحَّمة وأن الفكوك القافلة تعمل، ما الحالة المحددة التي أفحص من أجلها تثبيت العجلة الخامسة نفسها؟","options":["أن العجلة الخامسة موضوعة في أقصى الأمام بحيث تسير المقطورة أقرب ما يمكن إلى الكابينة","أن المنصة لها سطح لامع مطلي حديثًا دون أي بقع باهتة أو صدئة ظاهرة","أن براغي التثبيت كلها موجودة ومُحكمة وأنه لا توجد شقوق في القاعدة أو الهيكل","أن فجوة صغيرة ومتساوية تبقى مرئية بين النصفين العلوي والسفلي للعجلة الخامسة"],"explanation":"افحص تثبيت العجلة الخامسة للتأكد من وجود جميع البراغي وإحكامها وعدم وجود شقوق في القاعدة أو الهيكل، لأنها تحمل حمولة المقطورة."},"52":{"q":"في محطة وزن، يخبرني المفتش أن محاور الدفع لديّ محمَّلة بزيادة بضع مئات من الأرطال رغم أن وزني الإجمالي قانوني. قاطرتي مزودة بعجلة خامسة منزلقة. كيف يمكن لتعديل تلك العجلة الخامسة المنزلقة أن يساعدني على اجتياز الميزان؟","options":["إزلاقها إلى الخلف يقفل مسمار الارتكاز بإحكام أكبر داخل الفكوك، فيرى المفتش اقترانًا أكثر أمانًا","إزلاقها إلى الأمام يرفع المقطورة قليلًا عن العجلة الخامسة، مما يقلل الوزن الذي يقرأه الميزان","إزلاقها يضبط انحراف مؤخرة المقطورة بحيث تتجاوز المحاور المزدوجة منصة الميزان","إزلاقها إلى الأمام أو الخلف ينقل جزءًا من وزن الحمولة بين محاور القاطرة الأمامية ومحاور الدفع"],"explanation":"إزلاق العجلة الخامسة إلى الأمام ينقل وزن الحمولة إلى محور التوجيه ويبعده عن محاور الدفع، والإزلاق إلى الخلف يعكس ذلك، فيمكنك جعل أحمال المحاور قانونية."},"53":{"q":"أقوم بفحص ما قبل الرحلة على مركبتي المركبة وأصل إلى خزانات الهواء في المقطورة. للحفاظ على عمل نظام فرامل الهواء في المقطورة بأمان وموثوقية، ماذا ينبغي أن أفعل بتلك الخزانات؟","options":["أُفرغها من الماء والزيت المتراكمين، تمامًا كما أُفرغ خزانات القاطرة","أتركها مغلقة ومضغوطة كي لا تتمكن الملوثات من الدخول إليها","أملؤها بالماء النظيف للحيلولة دون جفاف الأختام الداخلية","أفصلها وأزيلها لأن خزانات القاطرة تغذي الفرامل أصلًا"],"explanation":"أفرغ خزانات هواء المقطورة من الماء والزيت المتراكمين تمامًا كما تفعل بخزانات القاطرة، لأن الرطوبة قد تتجمد أو تسبب التآكل والزيت قد يفسد صمامات فرامل الهواء."},"54":{"q":"انتهيت من اقتران قاطرتي بالمقطورة في الساحة: العجلة الخامسة مقفلة، ووصلات اليد المتشابكة موصولة، وفتحت للتو إمداد الهواء لشحن خزانات هواء المقطورة والسماح بتحرير فرامل النابض في المقطورة. ارتفع ضغط هواء المقطورة إلى المستوى الطبيعي. قبل أن أخرج من الساحة وأنطلق على الطريق، ما الخطوة الصحيحة التالية التي ينبغي أن أتخذها؟","options":["أسحب صمام يد المقطورة وأتركه مضبوطًا كي تثبّت فرامل المقطورة المركبة في وضع الوقوف بينما أُنجز الأوراق","أختبر فرامل الخدمة وفرامل الطوارئ للمقطورة للتأكد من أن كلتيهما تثبّتان فعلًا قبل القيادة","أفصل خط الإمداد (الأحمر) للطوارئ الآن بعد أن شُحنت الخزانات وتحررت فرامل النابض","أُنزل قائمة الهبوط جزئيًا مرة أخرى لتخفيف بعض الوزن عن العجلة الخامسة قبل الطريق"],"explanation":"بعد شحن الهواء وتحرير فرامل النابض، اختبر أن كلًّا من فرامل الخدمة وفرامل الطوارئ للمقطورة تثبّتان فعلًا قبل القيادة."},"55":{"q":"أنت تقود قاطرة ومقطورة محمّلة عبر مسار وسط المدينة غير المألوف للوصول إلى رصيف تسليم. أمامك ترى نفقًا قديمًا لسكة حديد عليه لافتة ارتفاع مسموح، كما أن مسارك يضم عدة إشارات مرور منخفضة ومظلة محطة خدمة مغطاة قرب الرصيف. لأن مركبتك المركبة أعلى بكثير من السيارة التي تقودها عادة، أي خطر ينبغي أن تركّز عليه أكثر من غيره وأنت تقترب من هذه الإنشاءات؟","options":["انحراف العجلات الخلفية للمقطورة نحو الرصيف عندما تستقيم بعد النفق","فقدان ضغط هواء المقطورة، مما يطبّق فرامل النابض تلقائيًا تحت الجسر","اصطدام إنشاء علوي لأن المركبة قد تكون أطول من أن تمر تحت الارتفاع المسموح","انقلاب ناتج عن ارتفاع مركز الثقل وأنت تمر تحت النفق"],"explanation":"المركبة المركبة أطول بكثير من السيارة، لذا اقرأ دائمًا الارتفاع المسموح المعلَن ولا تفترض أبدًا أن المركبة ستمر تحت الجسور أو اللافتات أو المظلات."},"56":{"q":"اقترنت قاطرتي للتو بمقطورة ليلًا ووصلت الضفيرة الكهربائية. أثناء جولتي حول المركبة ألاحظ أن مؤخرة المقطورة تتوهج بالأحمر، لكن ضوءين كهرمانيين للخلوص على الزوايا العلوية مطفأان، وعلامة جانبية واحدة بها عدسة متشققة تسرّب ضوءًا أبيض من الجانب. ما الذي يجب أن يتحقق قبل أن يحق لي قانونيًا وضع هذه المقطورة على الطريق؟","options":["يجب أن تعمل فقط الأضواء الخلفية وأضواء الفرامل في المؤخرة؛ أما أضواء الخلوص والعلامات فاختيارية بمجرد توصيل الضفيرة.","يجوز أن تبقى كل المصابيح مطفأة ما دامت المقطورة تحمل شريطًا عاكسًا، إذ يحلّ الشريط محل أضواء العلامات والخلوص.","الألوان لا تهم ما دام كل ضوء علامة وخلوص وخلفي يضيء ويكون مرئيًا عند تشغيلها.","يجب أن تعمل جميع أضواء العلامات والخلوص والخلفية وأن تُظهر الألوان الصحيحة، لذا يجب أولًا إصلاح المصابيح الكهرمانية المطفأة والعلامة التي تسرّب الضوء الأبيض."],"explanation":"يجب أن تعمل جميع أضواء العلامات والخلوص والخلفية وأن تُظهر اللون الصحيح، لذا يجب إصلاح المصابيح المطفأة والعدسة التي تسرّب الضوء الأبيض من الجانب."},"57":{"q":"رجعت للتو بقاطرتي تحت المقطورة وتبدو العجلة الخامسة مستقرة، لكن عندما أفحص أسفلها أرى أن الفكوك القافلة ليست مغلقة حول ساق مسمار الارتكاز — لقد التقطت طرفه فقط. إذا تجاهلت هذا وخرجت إلى الطريق السريع، ما أخطر شيء يمكن أن يحدث؟","options":["يمكن أن تنفصل المقطورة وتنفك عن القاطرة بينما أقود","ستُقفل فرامل المقطورة وتُجبر المقطورة على الانثناء عند أول منعطف","سترفض قائمة الهبوط الارتفاع، فتجرّ أرجل القاعدة على الرصيف","ستنحرف المقطورة بشدة وتتأرجح عجلاتها الخلفية بعيدًا إلى المسار المجاور"],"explanation":"يجب أن تُغلق الفكوك القافلة تمامًا حول ساق مسمار الارتكاز، لا أن تلتقط طرفه فقط، وإلا فقد تنفصل المقطورة وتنفك عن القاطرة أثناء القيادة."},"58":{"q":"أقود قاطرة ومقطورة محمّلة بالكامل على طريق سريع، وتندمج سيارة ركاب أمامي مباشرة، ونتحرك كلانا بالسرعة نفسها. إذا ضغطنا كلانا على الفرامل في اللحظة نفسها تمامًا لتوقف طارئ، ماذا ينبغي أن أتوقع بشأن مسافة توقف مركبتي المركبة مقارنة بتلك السيارة؟","options":["ستكون أقصر، لأن مركبتي الأثقل لها تلامس إطارات أكبر وقوة كبح أكبر للإمساك بالطريق","ستكون أطول، لذا أحتاج إلى ترك مسافة اتباع إضافية للتعويض عن ذلك","ستكون متقاربة تقريبًا، لأن فرامل الهواء لديّ أقوى بكثير من فرامل السيارة","ستكون أقصر، لأن نظام ABS يقصّر المسافة التي تحتاجها المقطورة المحمّلة للتوقف"],"explanation":"المركبة المركبة المحمّلة أثقل وأطول وتحمل زخمًا أكبر، لذا تحتاج إلى مسافة اتباع إضافية ومسافة توقف أطول."},"59":{"q":"انتهيت للتو من ربط قاطرتي بالمقطورة، وأجريت اختبار الشد، وأطوف حول المركبة لفحصي النهائي قبل الخروج من الساحة. أي مما يلي هو الجزء الذي يجب أن أغطيه والذي سيتخطاه السائق الذي يفحص القاطرة فقط؟","options":["مقاييس الكابينة وخلوص عجلة القيادة، لأنها تتحكم في كيفية قيادة المركبة بأكملها","فقط إطارات محور الدفع في القاطرة والمصابيح الأمامية، لأن المقطورة كانت مربوطة بالفعل","إطارات المقطورة وأضواؤها وفراملها وكذلك وصلات الاقتران والهواء والكهرباء","مجرد مسحة سريعة لزجاج المرآة الجانبية للسائق كي أرى المقطورة خلفي"],"explanation":"بعد الاقتران، افحص العناصر الخاصة بالمقطورة: إطاراتها وأضواؤها وفراملها بالإضافة إلى اقتران العجلة الخامسة/مسمار الارتكاز ووصلات الهواء والكهرباء."},"60":{"q":"أنت تنعطف يمينًا بشكل ضيق عند تقاطع بمركبتك المركبة. كيف ينبغي أن تنفّذ الانعطاف؟","options":["انحرف بعيدًا إلى اليسار عند البدء كي تتمكن سيارة من الانسلال إلى جانبك الأيمن.","أبقِ المؤخرة قريبة من الرصيف وانعطف عريضًا فقط عند إتمام الانعطاف.","انعطف بحدة وباكرًا، تاركًا عجلات المقطورة ترتفع فوق ركن الرصيف.","انتقل إلى المسار الأيسر أولًا ونفّذ الانعطاف بالكامل من أقصى المسار الأيسر."],"explanation":"أبقِ المؤخرة قرب الرصيف وانعطف عريضًا في النهاية كي لا تستطيع السيارات المرور من اليمين."},"61":{"q":"أثناء الاقتران، رجعت تحت المقطورة. كيف تتأكد من أن العجلة الخامسة مقفلة؟","options":["افترض أنها قُفلت إذا سمعت نقرة ثم انطلق دون أي فحص آخر.","أجرِ اختبار شد: مع قفل فرامل المقطورة، اسحب للأمام برفق مقابل مسمار الارتكاز.","هزّ المقطورة باليد وراقب قائمة الهبوط بحثًا عن أي علامة حركة.","انظر فقط إلى الجانب الخارجي للعجلة الخامسة وثق بأن الفكوك قد أُغلقت."],"explanation":"اختبار الشد مقابل مسمار الارتكاز يؤكد أن الفكوك قد أُقفلت."},"62":{"q":"أنت تجرّ مقطورة محمّلة على منحدر مبلّل وتكبح بقوة وأنت تقترب من تباطؤ. بإلقاء نظرة على مرآتك، ترى مؤخرة المقطورة تنحرف نحو المسار المجاور، وهي بداية انثناء المقطورة. أي إجراء يمنحك أفضل فرصة لإعادة المقطورة إلى مسارها؟","options":["اسحب صمام يد المقطورة لتطبيق فرامل المقطورة بقوة أكبر، فتجرّ المقطورة خلف القاطرة.","وجّه المقود بحدة في الاتجاه المعاكس وحافظ على ضغط ثابت على الفرامل حتى تستقيم المركبة.","تسارع بسلاسة كي تسحب القاطرة المقطورة لتستقيم خلفها وتمدد المركبة لتعود إلى مسارها.","خفّف الضغط عن الفرامل كي تبدأ عجلات المقطورة بالدوران وتستعيد الثبات، ثم نفّذ تصحيحات توجيه لطيفة."],"explanation":"يبدأ انثناء المقطورة عندما تُقفل عجلاتها وتفقد الثبات، لذا خفّف الضغط عن الفرامل كي تدور العجلات وتستعيد التماسك، ثم وجّه بلطف."},"63":{"q":"أنت تقود مركبة مركبة فارغة في يوم عاصف. كيف تتصرف المركبة الفارغة؟","options":["تتماسك مع الطريق أفضل من المحمّلة، فيمكنك الانعطاف والكبح بقوة أكبر.","ترتد ويمكن أن تنزلق أو تنقلب بسهولة أكبر، لذا استخدم كبحًا وتوجيهًا لطيفًا.","تتصرف تمامًا كما المركبة المحمّلة، فلا حاجة لتغيير في القيادة.","هي ثقيلة جدًا في المقدمة بحيث لا يمكن للمقطورة أن ترتد أو تغادر الطريق إطلاقًا."],"explanation":"المركبات الفارغة ترتد وتفقد التماسك؛ قُد بلطف."},"64":{"q":"أنت على وشك فك اقتران المقطورة. ماذا ينبغي أن تفعل قبل سحب القاطرة للخارج؟","options":["اسحب القاطرة أولًا ثم أنزل قائمة الهبوط بمجرد أن تستقر المقطورة عليها.","أنزل قائمة الهبوط، وافصل الخطوط، وافتح قفل العجلة الخامسة أولًا.","اترك خطوط الهواء موصولة كي تبقى فرامل المقطورة مطبّقة بينما تسحب للخارج.","حرّر فرامل المقطورة كي تتمكن من الدحرجة بحرية وأنت تقود للأمام."],"explanation":"أنزل قائمة الهبوط، وافصل الخطوط، وافتح قفل العجلة الخامسة قبل السحب للخارج."},"65":{"q":"أنا أجرّ مركبة مركبة محمّلة على منحدر طريق فرعي بين الطرق السريعة يضيق إلى منعطف يميني حاد، وتبدأ المقطورة بالشعور بالخفة والميل وأنا أنحني داخله. مع العلم أن الانقلابات هي ما يقتل كثيرًا من سائقي المركبات المركبة، أي خيار يفعل الأكثر للحيلولة دون انقلاب المركبة هنا؟","options":["أبقِ الحمولة محمّلة منخفضة وموسّطة جنبًا إلى جنب، وأخفّض سرعتي جيدًا قبل دخول المنعطف.","أحافظ على سرعتي ثابتة عبر المنعطف كي أجتازه بسرعة وأقضي أقل وقت في الميل.","أنتظر حتى أصل إلى أضيق جزء من المنعطف، ثم أكبح بقوة لأدفع المقطورة لتعود مسطّحة.","أحمّل أثقل البضائع مكدّسة عاليًا فوق المحاور كي يضغط وزنها مباشرة نحو الطريق."],"explanation":"معظم انقلابات المركبات المركبة تنتج عن السرعة الزائدة في المنعطفات، لذا أبقِ الحمولة محمّلة منخفضة وموسّطة جنبًا إلى جنب وأبطئ قبل المنعطف."},"66":{"q":"اقترنت للتو بقاطرتك بمقطورة ووصلت كلا خطي الهواء عند وصلات اليد المتشابكة. قبل أن تخرج من الساحة، تدرك أنك ربما وصلت الخط الأزرق (الخدمة) بمنفذ الطوارئ في المقطورة والخط الأحمر (الطوارئ) بمنفذ الخدمة. إذا كانت وصلات اليد متقاطعة فعلًا بهذا الشكل، أي نتيجة من الأرجح أن تكتشفها عندما تذهب للتوقف؟","options":["ستمسك فرامل المقطورة بقوة أكبر من الطبيعي في كل مرة تضغط فيها الدواسة، مما يمنحك توقفًا أقصر لكن بخطر انزلاق مقطورة أكبر.","قد ينتهي بك الأمر دون أي كبح للمقطورة إطلاقًا، لأن هواء الإمداد وهواء الخدمة معكوسان ولم تعد دواسة القدم ترسل هواءً لتطبيق فرامل المقطورة.","ستبقى فرامل النابض في المقطورة مقفلة وترفض التحرر، فلن تكاد المركبة تتحرك من الساحة إطلاقًا.","لن يتغير شيء في كيفية توقفك، لأن كلا الخطين يحملان الهواء نفسه والموصلات تعمل بالطريقة نفسها بغض النظر عن أي منفذ تلتقيان عنده."],"explanation":"إذا تقاطع خطا هواء الخدمة والإمداد، فإن الضغط على دواسة الفرامل لا يرسل هواءً إلى فرامل خدمة المقطورة، فقد لا يكون لديك أي كبح للمقطورة إطلاقًا."},"67":{"q":"تدفع قاطرتك ومقطورتك المحمّلة برفق إلى كتف طريق ذي مسارين يمتد على منحدر هابط طفيف، وتُطفئ المحرك، وتحتاج إلى ترك المركبة دون مراقبة بينما تفحص ضوء علامة مقطورة يومض. أي مما يلي هو الطريقة الصحيحة لتأمين المركبة المركبة كي تبقى ثابتة؟","options":["اسحب صمام يد المقطورة (صمام العربة) إلى الأسفل بالكامل واتركه مضبوطًا، إذ يقفل فرامل المقطورة وسيثبّت المركبة كلها في مكانها على المنحدر.","اترك ناقل الحركة في الوضع المحايد مع صمام حماية القاطرة مسحوبًا، كي يبقى الهواء مشحونًا وتسهل دحرجة المركبة للأمام عند عودتك.","شغّل فرامل الوقوف، وضع حواجز تثبيت عند العجلات، ووجّه العجلات الأمامية نحو الرصيف قبل أن تخرج لفحص الضوء.","أبقِ فرامل الخدمة مطبّقة بوضع شيء يدفع دواسة الفرامل، ثم ضع مثلثًا عاكسًا خلف المقطورة كاحتياط."],"explanation":"على المنحدر، شغّل فرامل الوقوف، وضع حواجز تثبيت عند العجلات، ووجّه العجلات الأمامية نحو الرصيف كي تبقى المركبة آمنة إذا تسرّب الهواء."},"68":{"q":"وأنت ترجع بمقطورتك نحو رصيف، تريد أن تتجه المقطورة إلى يمينك. بأي اتجاه تدير المقود أولًا؟","options":["أدر المقود إلى اليمين، الاتجاه نفسه الذي تريد أن تتجه إليه المقطورة.","أدر المقود إلى اليسار أولًا، ثم اتبع المقطورة واستقم.","أبقِ المقود مستقيمًا تمامًا وادفع للخلف فقط حتى تنحرف المقطورة إلى اليمين.","أدر المقود يمينًا بأقصى قوة وأبقه هناك طوال مسافة الرجوع كاملة."],"explanation":"لتوجيه المقطورة يمينًا أثناء الرجوع، أدر المقود أولًا إلى اليسار."},"69":{"q":"أنت تجرّ مقطورة محمّلة منخفضة الخلوص عندما تعلق على مزلقان سكة حديد مرتفع وتتوقف فوق القضبان مباشرة. تبدأ أضواء المزلقان بالوميض وترى قطارًا يقترب في البعيد. أي من الإجراءات التالية يمنحك أفضل فرصة للنجاة من هذا الموقف؟","options":["ابقَ في الكابينة واستمر في تشغيل دواسة الوقود لتهز القاطرة والمقطورة ذهابًا وإيابًا حتى تتحرر المقطورة من المزلقان.","ضع مثلثات عاكسة باتجاه القطار وقف قرب المزلقان ملوّحًا بذراعيك كي يراك السائق ويكبح في الوقت المناسب.","اسحب مفتاح تحرير المقطورة، وافصل القاطرة، وحاول دفع المقطورة بعيدًا عن القضبان قبل وصول القطار.","اخرج من الكابينة فورًا، وابتعد كثيرًا عن القضبان، واتصل برقم الطوارئ المعلَن أو 911 طلبًا للمساعدة من مسافة آمنة."],"explanation":"إذا علقت مركبتك على مزلقان سكة حديد مع اقتراب قطار، فاخرج وابتعد كثيرًا عن القضبان واتصل برقم الطوارئ المعلَن أو 911، لأنه لا توجد حمولة تستحق حياتك."},"70":{"q":"أقوم بفحص ما قبل الرحلة على قاطرتي ومقطورتي، وأتتبع الخرطومين الممتدين من مؤخرة كابينتي إلى المقطورة، الموصولين بوصلات يد متشابكة. يسألني متدرّب عن ماهية خطي الهواء هذين فعلًا. أي إجابة تسمّي كلا الخطين بشكل صحيح؟","options":["خط الخدمة (التحكم) وخط الطوارئ (الإمداد)","خط الخدمة (التحكم) وخط الإمداد لخزان سائل الفرامل","خط الطوارئ (الإمداد) وخط منفصل لتحرير فرامل الوقوف","خط واحد لفرامل الجانب الأيسر وخط لفرامل الجانب الأيمن"],"explanation":"تتصل القاطرة والمقطورة بخطي هواء بالضبط: خط الخدمة (التحكم) الذي يطبّق فرامل المقطورة وخط الطوارئ (الإمداد) الذي يشحن خزانات المقطورة."},"71":{"q":"أثناء فحص ما قبل الرحلة، يشير مدربي إلى خط وصلة اليد الأحمر الذي يشحن خزانات هواء المقطورة ويتحكم في فرامل النابض فيها، ويطلب مني تسميته. أحدده بشكل صحيح بأنه خط الطوارئ. ثم يسأل: \"ما الاسم الشائع الآخر الذي يستخدمه الفنيون لهذا الخط نفسه تمامًا؟\" أي إجابة ينبغي أن أعطيها؟","options":["خط التحكم، لأنه يرسل الإشارة التي تتحكم في مدى قوة تطبيق فرامل المقطورة","خط الإمداد، لأنه يمد ويشحن خزانات هواء المقطورة","خط الخدمة، لأنه يحمل الهواء في كل مرة أضغط فيها دواسة الفرامل أثناء الخدمة","خط الإشارة، لأنه يحمل إشارة الكبح عائدة إلى صمام التتابع في المقطورة"],"explanation":"الخط الذي يشحن خزانات هواء المقطورة ويتحكم في فرامل الطوارئ/النابض فيها هو خط الطوارئ، ويُسمى أيضًا خط الإمداد."},"72":{"q":"أقترن بقاطرتي بمقطورة وأصل إلى وصلتي اليد المتشابكتين لخطي الهواء المعلّقتين عند مؤخرة الكابينة. وفقًا لممارسة الترميز اللوني الشائعة، أريد توصيل خط الخدمة (التحكم) أولًا كي لا أتقاطع في خطوطي. أي وصلة يد ينبغي أن أمسك من أجل خط الخدمة؟","options":["وصلة اليد الحمراء، لأن الأحمر يميّز خط التحكم الذي يرسل إشارة فرامل المقطورة","وصلة اليد السوداء، لأن اللون المحايد محجوز لخط الخدمة في القاطرات","وصلة اليد الزرقاء، لأن الأزرق هو اللون الشائع لخط الخدمة","وصلة اليد الخضراء، لأن الأخضر يحدد إشارة الخدمة منخفضة الضغط"],"explanation":"وفقًا للترميز اللوني القياسي، الأزرق يميّز خط الخدمة (التحكم) والأحمر يميّز خط الطوارئ (الإمداد)."},"73":{"q":"أثناء فحص الاقتران في ما قبل الرحلة، أنحني خلف القاطرة وأنظر إلى المكان الذي ترتكز فيه مقدمة المقطورة المحمّلة بكامل وزنها. أحتاج إلى التأكد من أن الفكوك القافلة على هذه اللوحة المسطحة المشحَّمة مغلقة تمامًا حول مسمار المقطورة وأنه لا توجد فجوة. أي مكوّن أفحصه والذي ترتكز عليه المقطورة فعلًا؟","options":["مسمار الارتكاز، المسمار تحت المقطورة الذي ينزل وتُغلق الفكوك حوله لقفل الاقتران","قائمة الهبوط، الأرجل التي تحمل وزن المقطورة عندما تكون موضوعة دون ربط بقاطرة","خطّاف الجر، أداة الخطّاف والعروة التي تستخدمها القاطرة لسحب الوحدة الخلفية في القطارات المزدوجة","العجلة الخامسة، اللوحة المسطحة المشحَّمة المثبتة على القاطرة والتي يرتكز عليها وزن المقطورة"],"explanation":"العجلة الخامسة هي اللوحة المسطحة المشحَّمة المثبتة على القاطرة والتي يرتكز عليها وزن مقدمة المقطورة والتي تُغلق فكوكها القافلة حول مسمار الارتكاز."},"74":{"q":"أثناء فحص ما قبل الرحلة، أنا تحت المقطورة أفحص الاقتران وأرى أن الفكوك القافلة للعجلة الخامسة قد أُغلقت بإحكام حول ساق معدنية. أي جزء من المقطورة يُفترض أن يكون مستقرًا مقفلًا داخل تلك الفكوك؟","options":["مسمار الارتكاز","قائمة الهبوط","وصلة اليد المتشابكة","ذراع مقبض التحرير"],"explanation":"يتطلب الاقتران السليم أن تُغلق الفكوك القافلة للعجلة الخامسة تمامًا حول ساق مسمار ارتكاز المقطورة."},"75":{"q":"أقود مركبتي المركبة على الطريق السريع عندما يقفز فجأة من تلقاء نفسه المقبض الأحمر لإمداد هواء المقطورة للخارج. وأنا أشعر بالمركبة تبدأ في التباطؤ، ماذا ينبغي أن أتوقع أن يحدث لفرامل مقطورتي؟","options":["تتحرر فرامل المقطورة بالكامل، تاركة المقطورة تتدحرج بحرية خلف القاطرة","تُطبّق فرامل النابض في المقطورة، لأن المقبض المقفوز يقطع الهواء عن خط الطوارئ","تصبح فرامل المقطورة أضعف بكثير لكنها لا تزال تسحب قليلًا حتى أضغط المقبض للداخل مجددًا","لا يتغير شيء في المقطورة؛ هذا المقبض يؤثر فقط على فرامل وقوف القاطرة"],"explanation":"عندما يقفز المقبض الأحمر لإمداد هواء المقطورة للخارج، يُقطع الهواء عن خط الطوارئ وتُطبّق فرامل النابض في المقطورة تلقائيًا كإجراء أمان."},"76":{"q":"أقود مقطورة طولها 48 قدماً وأحتاج إلى الانعطاف يميناً بشكل حاد من شارع مدينة ضيق إلى مدخل رصيف تحميل. وبينما أتتبع مسار العجلات الأمامية للجرار حول الزاوية، أعلم أن العجلات الخلفية للمقطورة لن تتبع المسار نفسه تماماً. لمنع المقطورة من الاصطدام بالرصيف أو بسيارة متوقفة على الجانب الداخلي للمنعطف، ما الذي يحدث لتلك العجلات الخلفية للمقطورة والذي يجب أن أخطط له؟","options":["العجلات الخلفية للمقطورة تتأرجح إلى مسار أوسع من الأمامية، لذا يجب أن ألتصق بالرصيف بإحكام قبل بدء المنعطف","العجلات الخلفية للمقطورة ترتفع قليلاً عن سطح الطريق، لذا يكون لتوجيه المقود تأثير أقل على الخلف","العجلات الخلفية للمقطورة تتبع مساراً أضيق وأكثر داخلية من العجلات الأمامية للجرار، لذا يجب أن أتسع بما يكفي أثناء إكمال المنعطف","العجلات الخلفية للمقطورة تبقى في مسار الجرار تماماً، لذا يمكنني التوجيه كما لو كنت أقود شاحنة مستقيمة"],"explanation":"في المنعطف تتبع العجلات الخلفية للمقطورة مساراً أضيق وأكثر داخلية من العجلات الأمامية للجرار (الانحراف عن المسار)، لذا يجب أن تتسع بما يكفي لتجاوز الرصيف الداخلي."},"77":{"q":"لقد رجعت بالجرار للتو تحت المقطورة وزحفت تحته بمصباح يدوي لفحص الوصلة قبل اختبار الشد. وبينما أنظر إلى المكان الذي تستقر فيه اللوحة العلوية للمقطورة على العجلة الخامسة لدي، أيّ من الملاحظات التالية يجب أن يخبرني أن الوصلة صحيحة وآمنة للقيادة؟","options":["توجد فجوة صغيرة ومتساوية بمقدار بوصة واحدة تقريباً بين لوحتي العجلة الخامسة العلوية والسفلية","الفكوك القافلة مغلقة حول قمة مسمار الملك بدلاً من ساقه","ذراع التحرير غير مقفل لكن المقطورة لا تزال تبدو مستقرة بثبات على اللوحة","لوحتا العجلة الخامسة العلوية والسفلية متلاصقتان تماماً دون أي فجوة بينهما"],"explanation":"الوصلة الصحيحة تُظهر لوحتي العجلة الخامسة العلوية والسفلية متلاصقتين دون أي فجوة، ما يؤكد أن مسمار الملك مستقر تماماً وأن الفكوك مقفلة."},"78":{"q":"لقد انتهيت للتو من وصل الجرار بمقطورة محمّلة وأقوم بجولة التفقد النهائية قبل الخروج من الساحة. عندما أصل إلى عجلات الهبوط، أيّ حالة تعني أنها جاهزة للطريق؟","options":["عجلات الهبوط مرفوعة بالكامل إلى الأعلى ومقبض الرافعة مطوي ومثبّت في حامله","عجلات الهبوط مُنزَلة بما يكفي فقط لتلامس سطح الطريق بخفة وتثبّت المقطورة","عجلات الهبوط متروكة على بُعد بضع لفات من الأسفل لتنزل بسرعة إذا انفصلت المقطورة","عجلات الهبوط تستقر على كتل خشبية بحيث يكون وزن المقطورة بعيداً عن العجلة الخامسة"],"explanation":"قبل القيادة، يجب رفع عجلات الهبوط بالكامل إلى الأعلى مع طي مقبض الرافعة وتثبيته في حامله بحيث لا يهتز نازلاً أو يعلق."},"79":{"q":"لقد أنزلت مقطورتي المحمّلة في الساحة للتو وأقود الجرار عائداً بدون مقطورة (بوبتيل) على الطريق نفسه الذي أتيت منه. وبينما أقترب من إشارة التوقف التالية، أيّ مما يلي يجب أن أتوقعه بشأن كيفية تعامل الجرار الآن مقارنة بحين كان يسحب المقطورة المحمّلة؟","options":["بدون وزن المقطورة، سيتوقف الجرار الأخف دائماً على مسافة أقصر بكثير، لذا يمكنني الكبح في وقت متأخر","يمكن للجرار بدون مقطورة (بوبتيل) أن يحتاج فعلياً إلى مسافة أطول للتوقف مما احتاجه عند التحميل، لذا يجب ألا أفترض أنه يتوقف على مسافة أقصر","تبقى مسافة التوقف كما هي تماماً لأن مكابح الجرار وإطاراته لم تتغير","بدون مقطورة لا يستطيع الجرار بناء ضغط هواء كافٍ للتوقف وسيتدحرج عبر الإشارة"],"explanation":"يمكن للجرار بدون مقطورة (بوبتيل) أن يحتاج إلى مسافة أطول للتوقف مما يحتاجه عند التحميل لأن قلة الوزن على محور القيادة يعطي الإطارات قبضة أقل وتقفل العجلات بسهولة أكبر."},"80":{"q":"لقد رفعت المقطورة بحيث تستقر لوحتها أسفل مركز العجلة الخامسة مباشرة، وأنا على وشك أن أرجع بالجرار تحتها للوصل. للتأكد من أن مسمار الملك مقفل فعلاً في الفكوك قبل أن أعتمد على الوصلة وأخرج إلى الطريق، ما الطريقة الصحيحة لإكمال هذه الوصلة؟","options":["ارجع تحتها بسرعة ثابتة بحيث ينزلق مسمار الملك بسلاسة عبر الفكوك، ثم ألقِ نظرة على الفجوة وانطلق بمجرد أن تبدو مغلقة","ارجع تحتها بقوة وسرعة بحيث تنغلق الفكوك القافلة تماماً حول مسمار الملك، ثم ارفع عجلات الهبوط جزئياً قبل التحرك","ارجع تحتها ببطء حتى يتعشق مسمار الملك، ثم مع قفل مكابح المقطورة اسحب للأمام بلطف في ترس منخفض للتأكد من أن الفكوك ممسكة","ارجع تحتها ببطء، ثم افصل وصلات اليد القافزة وأعد عبور خطي الخدمة والطوارئ بحيث تنطبق مكابح المقطورة قبل أن تختبر"],"explanation":"أكمل الوصل بالرجوع تحتها ببطء حتى يتعشق مسمار الملك، ثم مع قفل مكابح المقطورة اسحب للأمام بلطف في ترس منخفض للتأكد من أن الفكوك ممسكة."},"81":{"q":"لجعل المقطورة تتجه يميناً أثناء الرجوع للخلف، عليك أولاً:","options":["إدارة المقود نحو اليسار","إدارة المقود بشدة نحو اليمين والثبات عليه","إبقاء المقود مستقيماً تماماً","لا شيء مما سبق"],"explanation":"إدارة المقود نحو اليسار أولاً هي الصحيحة، لذا فإن 'لا شيء مما سبق' خاطئة."},"82":{"q":"دخلت ساحة لأنزل مقطورتي المحمّلة وأعود إلى المنزل بدون مقطورة (بوبتيل) لقضاء الليلة. الساحة فيها انحدار طفيف نحو الأسفل قرب الرصيف، لكن توجد منطقة مستوية على بُعد ثلاثين قدماً تقريباً إلى اليسار. قبل أن ألمس رافعة عجلات الهبوط أو أمدّ يدي إلى مقبض تحرير العجلة الخامسة، ما أول شيء يجب أن أفعله على الإطلاق؟","options":["أنزل عجلات الهبوط حتى ترفع المقطورة قليلاً عن العجلة الخامسة لتحمل الوزن قبل أن أفعل أي شيء آخر","أفصل الوصلة الكهربائية وخطي الهواء حتى لا يتلف شيء أثناء عملي","أسحب مقبض تحرير العجلة الخامسة أولاً بحيث تكون الفكوك القافلة مفتوحة بالفعل عند إنزالي للعجلات","أعيد التموضع إلى المنطقة المستوية، وأشغّل مكابح الانتظار للجرار والمقطورة، وأضع كتل التثبيت حسب الحاجة قبل بدء فصل الوصلة"],"explanation":"افصل الوصلة دائماً على أرض مستوية، لذا أعد التموضع أولاً إلى المنطقة المستوية، وشغّل مكابح الانتظار للجرار والمقطورة معاً، وضع كتل التثبيت حسب الحاجة قبل تحرير الوصلة."},"83":{"q":"خلال فحص ما قبل الرحلة زحفت تحت الوصلة ولاحظت أن الفكوك القافلة للعجلة الخامسة قد علقت فوق لوحة مسمار الملك بدلاً من الانغلاق حول ساق مسمار الملك، تاركة فجوة مرئية بين العجلة الخامسة العلوية والسفلية. رغم أن كل شيء لا يزال يبدو موصولاً، لماذا يكون من الخطر قيادة هذه التركيبة؟","options":["الفكوك لم تنغلق أبداً حول ساق مسمار الملك، لذا فإن المقطورة ليست مقفلة فعلاً ويمكن أن تنفلت وتنفصل عن الجرار بمجرد أن أتحرك","الوصلة المرتفعة تخفض مركز ثقل المقطورة، لذا ستسير المقطورة منخفضة قليلاً وتحتك بسطح الطريق عند المطبات","مسمار الملك يجلس مرتفعاً جداً في الفكوك، لذا ستمسك مكابح المقطورة وتكبح بشدة مفرطة كلما أبطأت","العجلة الخامسة غير المتمركزة تعيد التغذية عبر مسمار الملك، لذا ستوجّه المقطورة نفسها بنفسها وتنحرف عن مساري"],"explanation":"الوصلة المرتفعة تعني أن الفكوك أُغلقت فوق لوحة مسمار الملك بدلاً من حول الساق، لذا فإن المقطورة ليست مقفلة ويمكن أن تنفلت وتنفصل بمجرد التحرك."},"84":{"q":"انتهيت من وصل الجرار بمقطورة، ووصلت خطي الهواء عند وصلات اليد القافزة، ووصلت الكابل الكهربائي ('الذيل الصغير'). وعندما عدت لفحص الأضواء، لاحظت أن الأضواء الخلفية وأضواء التحديد للمقطورة مطفأة تماماً، رغم أن أضواء الجرار لدي تعمل جيداً. سألني متدرب معي عن سبب تركيزي على ذلك الكابل الواحد. ما الذي يوصله الذيل الصغير فعلاً إلى المقطورة، مما يفسر لماذا قد يطفئ خلل في تلك الوصلة تلك الأضواء؟","options":["الهواء المضغوط الذي يشحن خزانات الهواء في المقطورة ويطبّق مكابح المقطورة.","الطاقة الكهربائية التي تشغّل أضواء المقطورة وأجهزتها الكهربائية الأخرى.","إشارة التحكم التي تحرر مكابح الزنبرك (الانتظار) في المقطورة للسير.","الشحم المضغوط الذي يبقي العجلة الخامسة ومسمار الملك مزيتين بشكل سليم."],"explanation":"الذيل الصغير الكهربائي هو الكابل الذي ينقل الطاقة الكهربائية من الجرار لتشغيل أضواء المقطورة وأجهزتها الكهربائية الأخرى."},"85":{"q":"لقد رجعت بالجرار للتو تحت المقطورة، وأحكمت الفكوك القافلة، ووصلت خطي الهواء. قبل أن أصعد إلى المقصورة لرفع عجلات الهبوط والانطلاق، أريد أن أتأكد من أن العجلة الخامسة قد أمسكت بمسمار الملك فعلاً. ماذا ينبغي أن أفعل للتأكد من أن الوصلة مقفلة؟","options":["أطلق بوق الهواء في الشاحنة مرتين بنفخات قصيرة للإشارة إلى اكتمال الوصلة","أصرّف كل الهواء من خزانات المقطورة بحيث تنطبق مكابح الزنبرك قبل أن أتحرك","مع بقاء مكابح المقطورة مقفلة، اسحب للأمام بلطف في ترس منخفض واشعر بثبات المقطورة","أفصل الذيل الصغير الكهربائي وأتحقق من انطفاء كل أضواء تحديد المقطورة"],"explanation":"اختبار الشد يؤكد أن الوصلة آمنة: مع قفل مكابح المقطورة، اسحب للأمام بلطف في ترس منخفض ويجب أن تثبت المقطورة دون أن تتدحرج."},"86":{"q":"أنا على وشك أن أرجع بالجرار تحت مقطورة للوصل. قبل أن أبدأ الرجوع، أفحص العجلة الخامسة نفسها. أيّ حالة تخبرني أن العجلة الخامسة مهيأة بشكل صحيح لإجراء الوصلة؟","options":["العجلة الخامسة مائلة لأعلى من الأمام بحيث ينزلق مسمار الملك فوق قمة الفكوك القافلة","الفكوك القافلة مغلقة بالفعل بحيث يغلقها مسمار الملك عند الملامسة","العجلة الخامسة منزلقة إلى أقصى الأمام بحيث تسير المقطورة قريبة من المقصورة","العجلة الخامسة مائلة لأسفل نحو الخلف بحيث تكون مهيأة لاستقبال مسمار الملك بشكل صحيح"],"explanation":"قبل الرجوع تحتها، يجب أن تكون العجلة الخامسة مائلة لأسفل نحو الخلف بحيث ينزلق مسمار الملك إلى الفتحة وتنغلق الفكوك حول ساقه."},"87":{"q":"لقد وصلت للتو كلا موصلي اليد القافزة في جراري ومقطورتي، مع التأكد من أن خطي الخدمة والطوارئ غير متقاطعين. عجلات الهبوط مرفوعة والذيل الصغير مثبّت. قبل أن أخرج من الساحة، ما الشيء التالي مباشرة الذي يجب أن أفعله للتأكد من أن المركبة صالحة للطريق؟","options":["اشحن نظام هواء المقطورة، ثم طبّق المكابح للتحقق من أن مكابح المقطورة تمسك فعلاً","اسحب للأمام بلطف في ترس منخفض فوراً لإجراء اختبار شد على الوصلة","أنزل عجلات الهبوط بضع لفات لإبعاد الوزن عن العجلة الخامسة قبل التحرك","راقب مؤشر الهواء وهو يرتفع إلى الضغط الكامل، ثم انطلق ما دامت الخطوط موصولة"],"explanation":"بعد وصل خطوط الهواء، اشحن نظام هواء المقطورة ثم طبّق المكابح للتحقق من أن مكابح المقطورة تمسك فعلاً قبل القيادة."},"88":{"q":"خلال فحص ما قبل الرحلة، أزحف تحت الجرار بمصباح يدوي للتأكد من أن العجلة الخامسة وصلت بشكل صحيح على مسمار الملك للمقطورة. أنا قلق من أن تكون الفكوك القافلة قد انغلقت فقط على طرف مسمار الملك بدلاً من الانغلاق الكامل حول ساقه. إذا لم يكن مسمار الملك مقفلاً بشكل صحيح، ما الأرجح أن أراه عند النظر إلى الوصلة؟","options":["الفكوك القافلة ملتفة بإحكام تماماً حول ساق مسمار الملك","فجوة أو مسافة بين لوحتي العجلة الخامسة العلوية والسفلية","ذراع التحرير مستقر في وضع القفل مع تعشيق مزلاج الأمان","المقطورة تجلس منخفضة قليلاً لأن العجلة الخامسة رفعتها عندما رجعت تحتها"],"explanation":"الوصلة الصحيحة لا تُظهر أي فجوة بين لوحتي العجلة الخامسة العلوية والسفلية، لذا فإن أي مسافة مرئية تعني أن مسمار الملك ليس مقفلاً بالكامل."},"89":{"q":"تكون عربة التحويل (الدولي) لازمة عندما تسحب:","options":["مقطورة نصفية واحدة","مقطورة ثانية أو ثالثة","جراراً بدون مقطورة","شاحنة صندوقية مستقيمة"],"explanation":"تُستخدم عربة التحويل (الدولي) لإضافة مقطورة ثانية أو ثالثة."},"90":{"q":"خلال فحص ما قبل الرحلة لجرار ومقطورة، ألاحظ مؤخرة المقطورة قرب المحور الخلفي. أيّ حالة تخبرني أن واقيات الطين (دروع الرذاذ) مقبولة وأن المركبة قانونية للقيادة؟","options":["تمت إزالة الواقيات من المحور الخلفي لتقليل المقاومة وتحسين استهلاك الوقود","الواقيات مصنوعة بالكامل من صفائح الفولاذ، لأن المطاط غير مسموح به على المقطورات","الواقيات موجودة خلف العجلات الخلفية وتتدلى قريبة من سطح الطريق","الواقيات مطلية بالبرتقالي الزاهي حتى يراها السائقون الآخرون ليلاً"],"explanation":"يجب أن تكون واقيات الطين موجودة خلف العجلات الخلفية وأن تتدلى قريبة من الطريق بحيث تلتقط رذاذ الطريق والحطام."},"91":{"q":"في صباح بارد ورطب وأنت تقوم بفحص ما قبل الرحلة لجرار ومقطورة. تفتح صنبور التصريف على خزان هواء المقطورة لإجراء التصريف المطلوب. أيّ مما يلي هو المادة التي تصرّفها، والسبب الذي يلزمك بإزالتها؟","options":["سائل تبريد المحرك الزائد الذي يرتد إلى نظام الهواء ويمكن أن يجمّد الخطوط طوال الليل","بخار وقود الديزل المتبقي الذي يتكثف في الخزان ويمكن أن يلوّث غرف المكابح","ضغط الهواء المحبوس الذي يجب نزفه بالكامل حتى يمكن فحص مكابح الزنبرك","الماء والزيت اللذان يتجمعان في الخزان ويمكن أن يتلفا نظام المكابح الهوائية إذا تُركا يتراكمان"],"explanation":"يتكثف الماء والزيت ويتجمعان في خزانات هواء المقطورة، لذا يجب تصريفهما قبل القيادة لحماية نظام المكابح الهوائية."},"92":{"q":"أقود جراراً ومقطورة طويلة طولها 53 قدماً وأحتاج إلى الانعطاف يميناً من شارع مدينة ضيق إلى طريق جانبي فيه شاحنة توصيل متوقفة وصنبور إطفاء قرب الرصيف الأيمن. وبينما أبدأ المنعطف، أيّ خطر يجب أن أكون الأكثر قلقاً بشأنه؟","options":["العجلات الخلفية للمقطورة تنحرف للداخل وتصطدم بشاحنة التوصيل المتوقفة أو صنبور الإطفاء أو الرصيف على اليمين","العجلات الأمامية للجرار تنحرف للداخل وتصطدم بشاحنة التوصيل المتوقفة على اليمين","المقطورة تنجرف بعيداً إلى اليسار وتعبر إلى المسار المقابل عند المنعطف يميناً","العجلات الخلفية للمقطورة تتبع المسار نفسه تماماً لمحور التوجيه في الجرار"],"explanation":"عند الانعطاف يميناً تنحرف العجلات الخلفية للمقطورة للداخل نحو الرصيف الأيمن، لذا يمكن أن تصطدم بمركبة متوقفة أو صنبور إطفاء أو الرصيف."},"93":{"q":"أقود مقطورة محمّلة نازلاً منحدراً رطباً وأكبح بقوة عند الاقتراب من صف بطيء من حركة المرور. أشعر بمؤخرة الجرار تبدأ بالانزلاق جانبياً وأدرك أن عجلات القيادة لدي قد قُفلت في انزلاق. لاستعادة السيطرة على الجرار، ما أول شيء يجب أن أفعله؟","options":["اضغط دواسة المكابح بقوة أكبر لإجبار عجلات القيادة على الإمساك بالطريق مجدداً","توقف عن الكبح للسماح لعجلات القيادة بالدوران مجدداً، ثم وجّه للتعافي","تسارع بقوة لشد الجرار مستقيماً والإفلات من الانزلاق","اسحب صمام يد المقطورة لتطبيق مكابح المقطورة والاستقامة"],"explanation":"في انثناء الجرار تكون عجلات القيادة مقفلة، لذا يجب أن تتوقف عن الكبح للسماح لها بالدوران واستعادة القبضة، ثم وجّه للتعافي."},"94":{"q":"أقود جراراً ومقطورة محمّلة نازلاً منحدراً مبللاً عندما تبدأ المركبة بالانزلاق. بدافع العادة، أمدّ يدي إلى صمام يد المقطورة (قضيب الترولي/جونسون) وأسحبه لأسفل بقوة لمحاولة إيقاف الانزلاق. لماذا تكون هذه بالضبط الحركة الخاطئة؟","options":["صمام اليد يطبّق مكابح محور القيادة في الجرار، ما يقفل عجلات التوجيه ويفقدني السيطرة على التوجيه","صمام اليد يحرر مكابح الزنبرك في المقطورة، فتنطلق المقطورة بحرية وتدفع الجرار للأمام داخل الانزلاق","صمام اليد يطبّق مكابح المقطورة فقط، لذا فإن قفل تلك العجلات يجعل المقطورة تتأرجح للخارج وتنثني","صمام اليد يقطع الهواء عن كلا خطي اليد القافزة دفعة واحدة، فيلغي كل الكبح ويطيل مسافة توقفي"],"explanation":"صمام يد المقطورة يطبّق مكابح المقطورة فقط، لذا فإن استخدامه أثناء الانزلاق يقفل عجلات المقطورة ويجعلها تتأرجح للخارج وتنثني."},"95":{"q":"خلال فحص ما قبل الرحلة، أفحص موصلات اليد القافزة التي تربط خطي هواء الخدمة والطوارئ بين جراري ومقطورتي. للحصول على إحكام هوائي سليم عند هذه الوصلات، في أيّ حالة يجب أن تكون الأختام المطاطية داخل وصلات اليد القافزة؟","options":["مطلية بطبقة من الشحم حتى تلتصق الوصلات المعدنية معاً بسهولة أكبر","التشقق الطفيف مقبول، لأن وصلات اليد المقفلة تثبّت الوصلة بإحكام","مطلية بلون زاهٍ حتى أميّز خطي الخدمة والطوارئ عن بعضهما","نظيفة وفي حالة جيدة، دون تشققات أو تآكل، بحيث تشكّل إحكاماً هوائياً محكماً"],"explanation":"يجب أن تكون الأختام المطاطية لوصلات اليد القافزة نظيفة وخالية من التشققات أو التآكل بحيث تشكّل إحكاماً هوائياً محكماً وخالياً من التسرب عند وصلة الخط."},"96":{"q":"أقود جراراً ومقطورة محمّلة بالكامل نازلاً منحدراً عندما تقطع سيارة طريقي، مجبرة إياي على الكبح بقوة. تندفع المقطورة الثقيلة للأمام وتدفع ضد الجرار. إذا واصلت الكبح بقوة شديدة حتى تُقفل عجلات القيادة لدي، ما الأرجح أن تكون نتيجة دفع المقطورة هذا؟","options":["عجلات القيادة المقفلة تفقد القبضة فيدور الجرار وينثني","عجلات المقطورة تُقفل أولاً وتتأرجح المقطورة وحدها للخارج خلفي","الدفع للأمام يضغط العجلات لأسفل ويقصّر مسافة توقفي فعلاً","مكابح المقطورة تنطبق تلقائياً وتسحب المركبة إلى خط مستقيم وثابت"],"explanation":"أثناء التوقف الحاد يمكن لمقطورة محمّلة أن تُقفل وتدفع عجلات القيادة في الجرار، فتفقد القبضة فيدور الجرار وينثني."},"97":{"q":"انتهيت من الوصل وأقوم بجولة التفقد النهائية. أرفع عجلات الهبوط إلى الأعلى بالكامل بحيث تصبح أرجل العربة خالية تماماً عن الأرض. قبل أن أصعد إلى المقصورة وأنطلق، ما الذي يجب أيضاً أن أفعله بعجلات الهبوط؟","options":["أنزل الأرجل بضع لفات بحيث تخلو الطريق بخفة","أثبّت مقبض الرافعة بحيث لا يسقط لأسفل أثناء القيادة","أترك مقبض الرافعة مرتخياً بحيث يتأرجح بعيداً عن الهيكل","أفصل أرجل عجلات الهبوط وأخزّنها في صندوق عدّة المقطورة"],"explanation":"بعد رفع عجلات الهبوط بالكامل، ثبّت مقبض الرافعة بحيث لا يهتز فينحلّ ويسقط لأسفل ويصطدم بالعوائق أثناء القيادة."},"98":{"q":"لقد انتقلت للتو من قيادة شاحنة مستقيمة أحادية الوحدة إلى سحب جرار ومقطورة محمّلة على الطريق السريع نفسه في تكساس. وبينما أخطط لمسافة التتبع ونقاط الكبح للمركبة المركّبة، كيف يجب أن أتوقع أن تقارن مسافة توقفها بالوحدة الأحادية التي اعتدت قيادتها؟","options":["ستكون أقصر بشكل ملحوظ، لأن أسطوانات مكابح المقطورة الإضافية تضيف قوة توقف تتغلب على الوزن المضاف","ستكون متماثلة تقريباً، لأن معايير المكابح الفيدرالية تتطلب أن تتوقف كل مركبة تجارية ضمن مسافة ثابتة واحدة","ستكون أطول، لأن الطول والوزن المضافين للمركبة المركّبة يتطلبان مزيداً من المساحة والوقت للتوقف","ستكون أقصر فقط إذا كانت المقطورة مزوّدة بنظام ABS، الذي يقلل فعلياً المسافة اللازمة للتوقف"],"explanation":"المركبة المركّبة أثقل وأطول، لذا تحتاج كتلتها وطولها المضافان إلى مزيد من المساحة والوقت للتوقف مقارنة بالوحدة الأحادية."},"99":{"q":"لقد رجعت بالجرار للتو تحت المقطورة ومسمار الملك مستقر. وبينما أتجول لفحص الوصلة قبل الانطلاق، أيّ حالة تخبرني أن العجلة الخامسة مقفلة بشكل صحيح وأن المركبة آمنة للسحب؟","options":["ذراع التحرير (رافعة القفل) مسحوب إلى وضع الفتح، بحيث يمكن للفكوك أن تتحرك بحرية حول مسمار الملك","صمام يد المقطورة (الترولي) مضبوط، لأنه يثبّت الوصلة بإحكام أثناء قيادتي","عجلات الهبوط متروكة بضع لفات للأسفل لإبقاء الوزن بعيداً عن العجلة الخامسة أثناء الرحلة","ذراع التحرير (رافعة القفل) في وضع القفل مع تعشيق مزلاج الأمان"],"explanation":"الوصلة الآمنة تتطلب أن يكون ذراع التحرير (رافعة القفل) في وضع القفل مع تعشيق مزلاج الأمان بحيث تنغلق الفكوك حول مسمار الملك."},"100":{"q":"خلال فحص ما قبل الرحلة، أنحني بجانب الجرار وأسلّط مصباحي اليدوي لأعلى نحو النقطة التي تلتقي فيها العجلة الخامسة بقاع المقطورة. أريد التأكد من أن الوصلة متينة. ما الذي أتحقق منه عند تلك النقطة بالضبط؟","options":["ما إذا كانت تظهر أي فجوة أو ضوء نهار بين لوحتي العجلة الخامسة العلوية والسفلية، إذ ينبغي ألا توجد أي منها","ما إذا كانت الفكوك القافلة ملتفة فقط حول طرف مسمار الملك بدلاً من ساقه","ما إذا كانت المقطورة تجلس أعلى قليلاً من مركز العجلة الخامسة قبل أن أنطلق","ما إذا كانت عجلات الهبوط مرفوعة بالكامل ومقبض الرافعة مثبّتاً ضد الهيكل"],"explanation":"الوصلة الصحيحة لا تُظهر أي فجوة أو ضوء نهار بين لوحتي العجلة الخامسة العلوية والسفلية؛ وأي فجوة مرئية تعني أن مسمار الملك ليس مستقراً بالكامل."},"101":{"q":"إذا رأيت ضوء النهار يظهر بين العجلة الخامسة والمقطورة، فإن الوصل يكون:","options":["آمن تماماً","غير آمن","قوي جداً","جديد تماماً"],"explanation":"ظهور ضوء النهار يعني أن الوصل غير آمن."},"102":{"q":"لقد رجعت للتو بالجرار تحت المقطورة وبدا أن الوصل قد استقر في مكانه، لكن أثناء الفحص أزحف تحته وأسلّط ضوءاً على نقطة الاتصال. يبدو كل شيء متوازياً تقريباً، لكنني أشك في وجود 'ربط مرتفع'. أي ملاحظة تؤكد وجود ربط مرتفع وتخبرني أن هذا الوصل غير آمن للقيادة؟","options":["الفكان القافلان مغلقان تماماً حول ساق المسمار الملكي دون أي فجوة مرئية","المسمار الملكي مستقر فوق العجلة الخامسة بدلاً من أن يكون مقفولاً داخل الفكين","كانت المقطورة أخفض قليلاً من مركز العجلة الخامسة قبل أن أرجع تحتها","ذراع التحرير في وضع القفل مع تعشيق مزلاج الأمان"],"explanation":"يحدث الربط المرتفع عندما تكون المقطورة عالية جداً فيستقر المسمار الملكي فوق العجلة الخامسة بدلاً من أن يُقفل داخل الفكين، فينفصل الوصل."},"103":{"q":"أثناء فحص الوزن قبل الرحلة ألاحظ أن المحور الموجِّه (الأمامي) للجرار خفيف بعض الشيء بينما المحاور الدافعة على ما يرام. جراري مزود بعجلة خامسة منزلقة. إذا أزلقت العجلة الخامسة إلى الأمام (نحو المقصورة)، أي محور يكتسب وزناً أكبر؟","options":["المحور الخلفي (التوأمي) للمقطورة، لأن تحريك العجلة الخامسة إلى الأمام يسحب الحمل إلى الخلف على عجلات المقطورة","المحور الدافع، لأن العجلة الخامسة تقع فوق المحاور الدافعة والحركة إلى الأمام تزيد تحميلها","المحور الموجِّه (الأمامي)، لأن تحريك العجلة الخامسة إلى الأمام ينقل المزيد من حمل المقطورة إلى الأمام عليه","لا يتغير أي محور، لأن العجلة الخامسة تقفل المسمار الملكي فقط ولا تؤثر أبداً على توزيع الوزن"],"explanation":"إزلاق العجلة الخامسة إلى الأمام ينقل نقطة تحويل الحمل إلى الأمام، فيضع المزيد من وزن المقطورة على المحور الموجِّه (الأمامي)."},"104":{"q":"في محطة وزن، تجاوزت المحاور الدافعة لجراري الحد القانوني للوزن بينما لا يزال لدى المحور الموجِّه متسع. قررت إزلاق العجلة الخامسة لإعادة توزيع الحمل قبل العودة إلى الطريق السريع. لإزالة الوزن عن المحاور الدافعة المحمّلة بشكل زائد، في أي اتجاه ينبغي أن أزلق العجلة الخامسة، وما التأثير؟","options":["أزلقها إلى الخلف، مما ينقل الوزن إلى المحاور الدافعة ويصحح الحمل الزائد","اتركها في المنتصف، لأن موضع العجلة الخامسة لا يؤثر على كيفية توزيع وزن المحاور","أزلقها إلى الخلف، مما ينقل الوزن إلى الأمام على المحور الموجِّه وبعيداً عن المحاور الدافعة","أزلقها إلى الأمام، مما ينقل الوزن عن المحاور الدافعة وعلى المحور الموجِّه"],"explanation":"إزلاق العجلة الخامسة إلى الأمام ينقل الوزن عن المحاور الدافعة المحمّلة بشكل زائد وعلى المحور الموجِّه، فيخفف عن المحاور الدافعة."},"105":{"q":"في محطة وزن، تجاوزت المحاور الدافعة لجراري حدها القانوني بينما لا يزال لدى المحاور التوأمية للمقطورة متسع. يخبرني مشغّل الميزان أن أعيد توزيع الحمل بإعادة تموضع المحاور التوأمية المنزلقة بدلاً من المساس بالبضاعة. إذا حررت مسامير القفل وأزلقت المحاور التوأمية للمقطورة إلى الأمام، أي مجموعة محاور ستكتسب الوزن الإضافي؟","options":["المحاور التوأمية للمقطورة، لأن إزلاقها إلى الأمام يضعها تحت جزء أكبر من الحمل","المحاور الدافعة للجرار، لأن وزن المقطورة يضغط بقوة أكبر على العجلة الخامسة","المحور الموجِّه للجرار، لأن الحركة إلى الأمام تنقل الوزن نحو مقدمة المركبة","جميع مجموعات المحاور بالتساوي، لأن تحريك المحاور التوأمية يعيد توازن الوزن عبر المركبة بأكملها"],"explanation":"إزلاق المحاور التوأمية للمقطورة إلى الأمام يضعها تحت جزء أكبر من البضاعة، مما يزيد الوزن الذي تحمله ويخفف عن الجرار."},"106":{"q":"في محطة وزن، يُظهر الميزان أن محاوري الدافعة تجاوزت الحد القانوني بينما لا يزال لدى المحاور التوأمية للمقطورة متسع. البضاعة مربوطة بالفعل ولا يمكنني تفريغ أي منها هنا. أي تعديل يصحح هذا مباشرة كي أتمكن من اجتياز الميزان؟","options":["إنزال أرجل الإسناد جزئياً لنقل بعض الحمل عن المحاور الدافعة","إزلاق المحاور التوأمية للمقطورة إلى الأمام لنقل الوزن عن المحاور الدافعة وعلى محاور المقطورة","تفريغ قليل من الهواء من نظام التعليق لخفض المقطورة وموازنة القراءة","إزلاق المحاور التوأمية للمقطورة إلى الخلف لإطالة قاعدة العجلات وتثبيت الحمل"],"explanation":"مع تجاوز المحاور الدافعة للوزن ونقص حمل المحاور التوأمية للمقطورة، فإن إزلاق المحاور التوأمية إلى الأمام ينقل الوزن عن المحاور الدافعة إلى محاور المقطورة لموازنة الأحمال."},"107":{"q":"أنا أنقل حمولة من الآلات المكدّسة، وقد رصّها الطاقم عالياً في المقطورة بحيث تجلس البضاعة مرتفعة عن الأرضية بدلاً من أن تنتشر منخفضة عبر الأرض. عند اقترابي من منحدر خروج منحنٍ على الطريق السريع، أي مما يلي هو الخطر الأكبر الذي ينبغي أن أقلق منه أكثر بسبب طريقة تكديس هذه الحمولة؟","options":["ستنحرف العجلات الخلفية للمقطورة وتتبع مساراً أوسع من الجرار، فتنحرف إلى المسار المجاور","سيحسّن التكديس العالي استهلاك الوقود لكنه سيضعف الفرامل ويطيل مسافة التوقف","الحمولة العالية ترفع مركز الثقل، فأصبح أكثر عرضة بكثير لقلب المركبة إذا أخذت المنحدر بسرعة كبيرة","ستُقفل عجلات المقطورة أولاً وتسبب انكسار المقطورة إلى الجانب خلفي"],"explanation":"الحمولة الطويلة العالية التكديس ترفع مركز الثقل، مما يجعل المركبة أكثر عرضة بكثير للانقلاب إذا أُخذ منحنى أو منحدر بسرعة كبيرة."},"108":{"q":"أنا أحمّل مركبة مدمجة ولدي بعض الصناديق الثقيلة بالإضافة إلى الكثير من الشحنات الأخف لأضعها في المقطورة. أريد تقليل خطر الانقلاب على منحدرات الطريق السريع التي سأسلكها الليلة. عند تحديد مكان وضع الصناديق الأثقل داخل المقطورة، أي خيار تحميل يحميني أكثر من الانقلاب؟","options":["كدّس الصناديق الأثقل قرب أعلى الحمولة كي تبقى الشحنات الأخف تحتها ولا تُسحق","ادفع الصناديق الأثقل نحو أحد جدران المقطورة الجانبية كي تتحمّل بقية الشحنات بالتساوي بجانبها","انشر الصناديق الأثقل عبر المقدمة والمؤخرة كي يبدو وزن المقطورة متوازناً من طرف إلى طرف","أبقِ الصناديق الأثقل منخفضة على أرضية المقطورة كي يبقى مركز ثقل الحمولة منخفضاً قدر الإمكان"],"explanation":"إبقاء الصناديق الأثقل منخفضة على أرضية المقطورة يبقي مركز الثقل منخفضاً قدر الإمكان، وهي أكثر طريقة فعالة لمقاومة الانقلاب."},"109":{"q":"عادةً ما أقود شاحنة مستقيمة مفردة، لكنني اليوم أنقل مركبة جرار-مقطورة محمّلة بالكامل. عند اقترابي من إشارة حمراء بنفس السرعة وعلى نفس الطريق الجاف الذي أستخدمه عادةً، كيف ينبغي أن أتوقع تغيّر احتياجات التوقف لدي مقارنةً بشاحنتي المفردة؟","options":["سأحتاج إلى مسافة أطول ووقت أكثر للتوقف، لذا ينبغي أن أبدأ الكبح مبكراً","سأتوقف في نفس المسافة تقريباً لأن الفرامل مصممة بما يناسب الحمل","سأتوقف في مسافة أقصر لأن الوزن الإضافي يضغط الإطارات بقوة أكبر","لن أحتاج إلى مسافة إضافية طالما أن مقطورتي مزودة بنظام ABS"],"explanation":"المركبة المدمجة المحمّلة أثقل وأطول، لذا تحتاج إلى مسافة ووقت أكبر للتوقف، مما يعني أنه يجب على السائق أن يبدأ الكبح مبكراً."},"110":{"q":"أنا أسير على مسار إقليمي أنقل مقطورة واحدة، وعلى مدار اليوم أقوم بعدة عمليات تسليم. وبحلول فترة بعد الظهر ألاحظ أن المقطورة تتأرجح وتتمايل خلف الجرار أكثر بكثير مما كانت عليه في الصباح، رغم أن الطريق والسرعة ومدخلاتي على المقود تبدو كما هي. أي حالة هي السبب الأرجح لكون المقطورة الآن أكثر عرضة لهذا التأرجح والتمايل؟","options":["المقطورة محمّلة بالكامل، فالوزن الإضافي يدفع مؤخرة المقطورة من جانب إلى جانب","المقطورة الآن فارغة أو محمّلة بشكل خفيف بعد عمليات التسليم، لذا تتأرجح وتتمايل بسهولة أكبر","انزاحت بضاعة المقطورة إلى الأمام فوق المسمار الملكي، مما رفع مركز الثقل في المؤخرة","بدأ نظام ABS في المقطورة بالتشغيل المتقطع على المحور الخلفي، مما أضعف تماسك العجلات بالطريق"],"explanation":"المقطورة التي أُفرِغت أو خُفّفت بفعل عمليات التسليم لديها وزن أقل يثبّت عجلاتها، لذا تتأرجح وتتمايل بسهولة أكبر بكثير خلف الجرار."},"111":{"q":"لقد رجعت بالجرار تحت المقطورة وأقوم بفحص الوصل قبل اختبار الشد. أنحني بمصباحي اليدوي لأتأكد من أن الوصلة قد أمسكت فعلاً بالمسمار الملكي. أي جزء من العجلة الخامسة يجب أن أراه مغلقاً تماماً حول ساق المسمار الملكي كي أعرف أن المقطورة مقفولة حقاً؟","options":["مقبض التحرير، الذي ينبغي أن يكون مدفوعاً بالكامل نحو المسمار الملكي","مزلاج الأمان، الذي ينبغي أن يكون ملتفاً بإحكام حول ساق المسمار الملكي","الفكان القافلان، اللذان ينبغي أن يكونا مغلقين تماماً حول ساق المسمار الملكي","لوح العجلة الخامسة المحوري، الذي ينبغي أن ينطبق فوق رأس المسمار الملكي"],"explanation":"يتطلب الوصل الآمن أن يكون الفكان القافلان للعجلة الخامسة مغلقين تماماً حول ساق المسمار الملكي، وليس فوقه أو ممسكين بطرفه فقط."},"112":{"q":"لقد رجعت للتو بالجرار تحت المقطورة وسمعت الفكين القافلين ينطبقان على المسمار الملكي. قبل أن أصعد لفحص الوصلة وإجراء اختبار الشد، أتفقّد مقبض تحرير العجلة الخامسة. كي يُعتبر الوصل صحيحاً، أين ينبغي أن يكون مقبض التحرير ذاك؟","options":["مسحوباً بالكامل للخارج كي يبقى مزلاج الأمان بعيداً عن الفكين","متروكاً في منتصف المسافة كي أتمكن من إعادة الوصل بسرعة إذا فشل اختبار الشد","مُزالاً ومخزّناً في المقصورة حتى أنهي بقية الفحص","مدفوعاً للداخل إلى وضع القفل (المغلق) مع تعشيق مزلاج الأمان"],"explanation":"الوصل الآمن يكون فيه ذراع التحرير مدفوعاً للداخل إلى وضع القفل (المغلق) مع تعشيق مزلاج الأمان، مما يؤكد أن الفكين مغلقان حول المسمار الملكي."},"113":{"q":"لقد أنهيت رحلتك وتحتاج إلى ترك مقطورتك المحمّلة في الساحة. عند اختيارك مكاناً لفك الوصل، أي موقع يحميك على نحو أفضل من انزياح المقطورة أو تدحرجها أو غوص أرجل الإسناد بمجرد إنزالها؟","options":["أرض صلبة ومستوية حيث يستطيع السطح تحمّل وزن المقطورة على أرجل الإسناد","منحدر هابط خفيف كي يتمكن الجرار ببساطة من التدحرج إلى الأمام خارجاً من تحت المقطورة","تربة لينة مرصوصة تخفف عن وسادات أرجل الإسناد عند تحمّلها الوزن","أي مكان على كتف مسار سير نشط كي تبقى بعيداً عن حركة مرور الساحة"],"explanation":"افكك الوصل فقط على أرض صلبة ومستوية كي لا تغوص وسادات أرجل الإسناد ولا تتدحرج المقطورة المركونة أو تنزاح."},"114":{"q":"أنا أترك مقطورتي المحمّلة في ساحة. لا يزال المسمار الملكي مقفولاً في العجلة الخامسة وأنا أدير أرجل الإسناد للأسفل لأضع وزن المقطورة عليها قبل أن أسحب مقبض التحرير. إلى أي مدى ينبغي أن أنزل أرجل الإسناد؟","options":["حتى تصل الأرجل إلى الأرض ثم أستمر بالإدارة حتى ترتفع المقطورة عن العجلة الخامسة","حتى تلامس الأرجل الأرض بالكاد، ثم بضع لفات إضافية لتحمّل بعض وزن المقطورة","حتى تقترب الأرجل من الأرض لكنها لا تزال معلّقة قليلاً كي تحمل العجلة الخامسة الحمل الكامل","حتى تستقر الأرجل بثبات ثم أترك فرامل المقطورة معطّلة كي يستقر الوزن بالتساوي"],"explanation":"عند فك الوصل، أنزل أرجل الإسناد حتى تلامس الأرض بالكاد، ثم أدِر بضع لفات إضافية لتحمّل بعض وزن المقطورة عن العجلة الخامسة دون رفعها."},"115":{"q":"أنا أترك مقطورة محمّلة في ساحة. لقد ثبّتّ عجلات المقطورة بالحاشيات وانتهيت للتو من إدارة أرجل الإسناد للأسفل حتى لامست الرصيف وتحمّلت قليلاً من الوزن عن العجلة الخامسة. قبل أن أسحب مقبض تحرير العجلة الخامسة وأقود جراري خارجاً، ماذا ينبغي أن أفعل بعد ذلك؟","options":["أدير أرجل الإسناد عدة لفات إضافية لرفع المقطورة بالكامل عن العجلة الخامسة كي ينزلق جراري خارجاً بسلاسة","أسحب مقبض التحرير على الفور، بما أن العجلات المثبّتة بالحاشيات وأرجل الإسناد المحمّلة جزئياً تثبّت المقطورة","أفصل خطوط الهواء والوصلة الكهربائية عن المقطورة وأخزّنها كي لا تنجرّ على الأرض","أستخدم صمام يد المقطورة لقفل فرامل المقطورة للركن قبل أن أفك أي شيء"],"explanation":"قبل سحب مقبض التحرير، افصل خطوط الهواء والوصلة الكهربائية عن المقطورة وأمّنها كي لا تنجرّ على الأرض."},"116":{"q":"لقد تركت للتو مقطورتي في الساحة وفصلت خطّي الهواء ذوي القبضة عن الجرار. قبل أن أعود بالجرار وحده إلى الورشة، ما السبب الرئيسي وراء حاجتي إلى تعليق خطوط الهواء المفصولة أو تأمينها بشكل صحيح؟","options":["كي تبدو الخطوط مرتبة ومنظّمة للسائق التالي الذي يصلها","كي يستمر هواء المحرك الدافئ بالتدفق خلالها فلا تتجمد","كي تصدر طقطقة مسموعة عند احتكاكها بالهيكل وتنبّهني إلى انفكاكها","كي لا تنجرّ على الأرض حيث يمكن أن تتلف أو تتسخ"],"explanation":"يجب تأمين خطوط الهواء المفصولة بعيداً عن الأرض كي لا تُخدش أو تتلف أو تمتلئ بالأوساخ التي قد تسبب تسريبات أو تلوّث نظام الهواء."},"117":{"q":"عند سحب الجرار بعيداً عن المقطورة، افعل ذلك:","options":["بسرعة كبيرة","ببطء","وعيناك مغمضتان","في رجوع عنيف"],"explanation":"اسحب الجرار خارجاً ببطء."},"118":{"q":"أنا أقود جراراً بمقطورة فارغة تماماً على طريق سريع جاف عندما تتوقف حركة المرور أمامي فجأة فأضطر إلى الكبح بقوة. مقارنةً بنقل مقطورة محمّلة بالكامل، ماذا ينبغي أن أتوقع من عجلات المقطورة الفارغة في هذا الموقف من الكبح الشديد؟","options":["عجلات المقطورة الفارغة أكثر عرضة للقفل، لأن هناك وزناً قليلاً جداً يضغطها على الطريق.","عجلات المقطورة الفارغة تتماسك بالطريق على نحو أفضل، لأن الحمل الأخف يتيح للإطارات أن تعضّ بقوة أكبر عند الكبح.","عجلات المقطورة الفارغة تحتاج إلى قوة كبح أكبر بكثير، لأن المقطورة الخفيفة تستغرق دائماً وقتاً أطول للتوقف من المحمّلة.","تتصرف عجلات المقطورة الفارغة تماماً كما لو كانت محمّلة، بما أن تماسك الكبح لا يتغير مع الوزن المحمول."],"explanation":"المقطورة الفارغة لديها وزن قليل جداً يضغط عجلاتها على الطريق فتُقفل بسهولة عند الكبح الشديد، مما قد يسبب انزلاق المقطورة."},"119":{"q":"أنا أكبح بقوة وأنا أنزل منحدراً طويلاً بجرار-مقطورتي المحمّل، وأشعر بأن مؤخرة المقصورة بدأت تنحرف إلى أحد الجانبين، مما يعرّضني لخطر انكسار الجرار. أي من هذه الحالات هو السبب الأرجح لما يحدث؟","options":["المقطورة تسير فارغة، فترتد على المطبات","كبحت بقوة شديدة حتى قُفلت العجلات الدافعة للجرار وانزلقت","كان المحرك لا يزال بارداً عندما بدأت النزول","قُفلت عجلات مقطورتي، فانحرفت المقطورة خلفي"],"explanation":"يحدث انكسار الجرار عندما يؤدي الكبح بقوة شديدة إلى قفل العجلات الدافعة للجرار، فتنزلق وتفقد التماسك حتى تنحرف مؤخرة المقصورة."},"120":{"q":"أنت تقود جرار-مقطورة محمّلاً وأنت تنزل منحدراً طويلاً عندما تتباطأ حركة المرور أمامك فجأة. تضغط دواسة الفرامل بقوة وتشعر بأن مؤخرة الجرار بدأت تنزلق نحو الجانب. لمنع الجرار من الانكسار، ماذا ينبغي أن تفعل؟","options":["استمر بالضغط على الفرامل بقوة كي تتوقف العجلات الدافعة عن الدوران وتتوقف المركبة بشكل أسرع","اسحب صمام يد المقطورة بالكامل لقفل فرامل المقطورة وتقويم المركبة","ارفع قدمك عن الفرامل بما يكفي لإبقاء العجلات الدافعة تدور، ثم اكبح بسلاسة دون قفلها","أدِر المقود بقوة في الاتجاه المعاكس بيد واحدة مع إبقاء الضغط الكامل على دواسة الفرامل"],"explanation":"لتصحيح انزلاق العجلات الدافعة، ارفع قدمك عن الفرامل بما يكفي لإبقائها تدور وتستعيد التماسك والتوجيه، ثم اكبح بسلاسة دون قفلها."},"121":{"q":"أنا أقود جرار-مقطورة وأحتاج إلى الانعطاف يميناً من شارع ضيق إلى شارع ضيق آخر. هناك سيارة متوقفة عند الرصيف بعد الزاوية مباشرةً على الشارع الذي أنعطف إليه. عند بدء الانعطاف، أي سلوك لمقطورتي يجب أن آخذه بالحسبان لتجنّب الاصطدام بتلك السيارة أو بالرصيف؟","options":["ستنحرف العجلات الخلفية للمقطورة على نطاق واسع نحو اليسار، لذا ينبغي أن ألتصق بالرصيف الأيمن بإحكام طوال الانعطاف","سترتفع المقطورة وتميل للخارج بعيداً عن الانعطاف، لذا ينبغي أن أكبح بقوة لإبقائها ثابتة","ستتأخر المقطورة مستقيمةً قبل أن تتبع، لذا يمكنني بدء الانعطاف مبكراً عما يحتاجه الجرار","ستتبع العجلات الخلفية للمقطورة مساراً داخل مسار جراري، فتقطع نحو الرصيف والسيارة المركونة، لذا يجب أن أنعطف على نطاق أوسع لإفساح المجال لها"],"explanation":"عند الانعطاف يميناً تنحرف العجلات الخلفية للمقطورة إلى داخل مسار الجرار نحو الرصيف، لذا يجب أن تنعطف على نطاق أوسع لإفساح المجال لها كي تمرّ."},"122":{"q":"أنا أقود جرار-مقطورتي عبر انعطاف يميني ضيّق عند تقاطع في المدينة. وأنا أدير المقصورة حول الزاوية، ألقي نظرة على مرآتي وأحاول تصوّر المسار الذي ستسلكه العجلات الخلفية لمقطورتي مقارنةً بالعجلات الأمامية لجراري. لماذا أحتاج إلى الانعطاف على نطاق واسع كفاية لإتمام هذا الانعطاف بأمان؟","options":["لأن العجلات الخلفية للمقطورة تتبع مساراً داخلياً (أضيق من) مسار العجلات الأمامية للجرار، فقد تقطع الزاوية وتصطدم بالرصيف أو بجسم ما","لأن العجلات الخلفية للمقطورة تتبع مساراً خارجياً (أوسع من) مسار العجلات الأمامية للجرار، فقد تنحرف إلى المسار المجاور","لأن العجلات الخلفية للمقطورة تتبع نفس مسار العجلات الأمامية للجرار تماماً، فأحتاج فقط إلى إفساح المجال للمقصورة","لأن العجلات الخلفية للمقطورة ترتفع عن الأرض في الانعطاف الحاد، فيجب أن أنعطف ببطء لإبقائها ملامسة للأرض"],"explanation":"بسبب الانحراف تتبع العجلات الخلفية للمقطورة مساراً داخلياً أضيق من مسار العجلات الأمامية للجرار ويمكن أن تقطع الزاوية إلى الرصيف أو الأجسام."},"123":{"q":"أثناء فحصي قبل الرحلة، أنا جاثٍ على ركبة واحدة أنظر للأعلى حيث تلتصق العجلة الخامسة بهيكل الجرار. لاجتياز هذا الجزء من الفحص، في أي حالة يجب أن يكون تثبيت العجلة الخامسة؟","options":["ينبغي أن يكون لدى أذرع التثبيت قليل من الخلخلة كي تتمكن العجلة الخامسة من الانثناء عند انزياح المقطورة في الانعطافات","مثبّتة بإحكام في الهيكل، مع وجود جميع مسامير التثبيت ودون أي شقوق في التثبيت أو الهيكل","مطلية حديثاً فوق المسامير والأذرع لعزل أوساخ الطريق ومنع تراكم الصدأ","منفصلة تماماً عن الهيكل كي يتسنى فحص العجلة الخامسة وإعادة تشحيمها قبل الوصل"],"explanation":"يجب أن تكون العجلة الخامسة مثبّتة بإحكام بالمسامير في هيكل الجرار مع وجود جميع مسامير التثبيت ودون أي شقوق في التثبيت أو الهيكل."},"124":{"q":"أثناء فحصي قبل الرحلة أزحف تحت المقطورة للتحقق من أن الوصل آمن. أرى الفكين القافلين مغلقين حول المسمار الملكي ولا توجد فجوة بين العجلة الخامسة العلوية والسفلية. الآن أتفقّد مزلاج الأمان على العجلة الخامسة. ما المهمة المحددة التي يؤديها هذا المزلاج؟","options":["يحكم إغلاق موصّلَي القبضة كي لا يتسرب من خطّي الهواء الخدمي والطارئ","يثبّت مقبض إدارة أرجل الإسناد كي لا تسقط أرجل الدولي أثناء القيادة","يثبّت ذراع التحرير (رافعة القفل) في وضع القفل كي لا تنفتح فجأة أثناء النقل","يقفل صمام يد المقطورة كي تبقى فرامل نوابض المقطورة مفعّلة أثناء الركن"],"explanation":"يثبّت مزلاج الأمان رافعة القفل (ذراع التحرير) في وضع القفل كي لا تهتز أو تنفتح فجأة أثناء القيادة."},"125":{"q":"أنا أصل جراري بمقطورة في الساحة. المقطورة عند الارتفاع الصحيح، وعجلتي الخامسة مشحّمة، وقد اصطففت مباشرةً أمام المسمار الملكي. عند بدء الرجوع بالجرار تحت المقطورة، أي مما يلي يصف كيف ينبغي أن أؤدي هذه المناورة؟","options":["ارجع بسرعة طالما أن المسار خالٍ، ثم خفّف السرعة قبل وصول المسمار الملكي إلى العجلة الخامسة مباشرةً","ارجع بسرعة ثابتة مع توجيه الجرار قليلاً كي تتمكن العجلة الخامسة من التقاط المسمار الملكي","ارجع بسرعة كافية للارتقاء فوق المسمار الملكي، بما أن المقطورة مضبوطة منخفضة قليلاً عمداً","ارجع ببطء وفي خط مستقيم كي ينزلق المسمار الملكي بسلاسة إلى داخل الفكين القافلين"],"explanation":"ارجع تحت المقطورة ببطء وفي خط مستقيم كي ينزلق المسمار الملكي بسلاسة إلى داخل الفكين القافلين ويتمكنا من الإغلاق تماماً حول ساقه."},"126":{"q":"أقوم برجوع الجرّار للخلف تحت المقطورة في الساحة. وأنا أصطفّ وأنظر في مرآتي قبل الرجوع تحتها، أيُّ وضعٍ لمسمار الارتكاز (الكينغ بِن) يدلّني على أن الجرّار في الموضع الصحيح لإتمام الوصل؟","options":["مسمار الارتكاز متمركز من الجانب إلى الجانب على العجلة الخامسة بحيث يمكن للفكّين القافلين أن ينغلقا حول ساقه","مسمار الارتكاز منزاح قليلًا إلى أحد جانبي العجلة الخامسة بحيث يلتقط الفكّان القافلان الساق أثناء رجوعي","مسمار الارتكاز مرتفع فوق اللوح العلوي للعجلة الخامسة بحيث يمكن للفكّين أن ينزلا عليه","مسمار الارتكاز يصطفّ خلف مؤخرة العجلة الخامسة مباشرةً بحيث تتجاوز المقطورة قمرة القيادة"],"explanation":"يجب أن يكون مسمار الارتكاز متمركزًا من الجانب إلى الجانب على العجلة الخامسة بحيث ينغلق الفكّان القافلان تمامًا حول ساقه لتحقيق وصلٍ سليم."},"127":{"q":"أقوم بوصل الجرّار بالمقطورة في ساحة دائرة السلامة العامة (DPS). المقطورة على الارتفاع الصحيح، ومسمار الارتكاز مصطفّ، وأوشك على إرجاع الجرّار ببطء تحت المقطورة. وبينما أُجري فحصًا أخيرًا للعجلة الخامسة نفسها، كيف يجب أن تكون موضوعةً لتلتقط لوح المقطورة بشكلٍ صحيح أثناء رجوعي تحتها؟","options":["مائلةً إلى الأعلى من الأمام بحيث ترتفع حافتها الأمامية فوق اللوح وتنزلق فوقه","مائلةً إلى الأسفل نحو المؤخرة بحيث تنخفض حافتها الأمامية وتلتقط لوح المقطورة","مستويةً تمامًا بحيث يلتقي اللوح بصفيحةٍ مسطّحة بشكلٍ مستقيم عند التلامس","مائلةً جانبيًا بحيث يمكن لمسمار الارتكاز أن يدخل في الفكّين القافلين من أحد الجانبين"],"explanation":"يجب أن تكون العجلة الخامسة مائلةً إلى الأسفل نحو المؤخرة بحيث تنزلق حافتها الأمامية المنخفضة أسفل لوح المقطورة وتلتقطه، موجِّهةً مسمار الارتكاز إلى داخل الفكّين."},"128":{"q":"لقد أرجعتُ الجرّار للتوّ تحت المقطورة وتأكّدتُ من أن فكّي العجلة الخامسة قد انغلقا حول مسمار الارتكاز. قبل أن أصعد مجددًا لأقود، ماذا يجب أن أفعل لرفع أرجل دعم المقطورة بحيث تبتعد عن الأرض؟","options":["أسحب مقبض تحرير العجلة الخامسة لإسقاط أرجل الدعم بعيدًا عن الرصيف","أُنزل أرجل الدوللي بضع دورات إضافية بحيث تستقرّ المقطورة على العجلة الخامسة","أُدير معدات الهبوط للأعلى بالكامل وأُثبّت مقبض الإدارة قبل القيادة","أفصل خط إمداد الهواء بحيث تُمسك مكابح زنبرك المقطورة بأرجل الدعم"],"explanation":"بمجرد التأكد من الوصل وحمل العجلة الخامسة للوزن، أَدِر معدات الهبوط للأعلى بالكامل وثبّت المقبض قبل القيادة."},"129":{"q":"لقد وصلتُ للتوّ الجرّار بمقطورةٍ محمّلة وأنهيتُ ربط خطّي الهواء الخدمي والطارئ عند وصلات اليد المتصافحة (glad-hand). قبل أن أصعد إلى القمرة لإجراء اختبار الجذب والانطلاق إلى الطريق السريع، ماذا يجب أن تؤكّده هذه الخطوة المباشرة بعد توصيل الخطوط؟","options":["أن معدات هبوط المقطورة ما زالت منخفضة جزئيًا بحيث تدعم الحمولة أثناء قيادتي","أن جهاز اللاسلكي (CB) مضبوط على قناةٍ صافية بحيث يستطيع المُرسِل الوصول إليّ على الطريق","أن وصلات اليد متقاطعة بحيث يغذّي الخط الخدمي الأزرق مكابح المقطورة الطارئة","أنه لا توجد تسرّبات للهواء عند الوصلات وأن الوصل محكم"],"explanation":"بعد توصيل خطوط الهواء عند وصلات اليد المتصافحة مباشرةً، تأكّد من عدم وجود تسرّبات للهواء عند الوصلات وأن الوصل محكم."},"130":{"q":"لقد وصلتُ للتوّ الجرّار بالمقطورة وربطتُ خطّي الهواء عند وصلتي اليد دون أن أُقاطعهما. لا تزال خزانات هواء المقطورة فارغة، ومكابح زنبرك المقطورة تُمسكها في مكانها. قبل أن أُجري فحوصات مكابح الهواء، ماذا يجب أن أفعل لشحن نظام هواء المقطورة؟","options":["أضغط على صمام إمداد هواء المقطورة للداخل بحيث يتدفّق الهواء عبر الخط الطارئ ويملأ خزانات المقطورة","أسحب صمام إمداد هواء المقطورة للخارج لإغلاق الخط حتى يُظهر المقياس امتلاء الضغط","أسحب صمام يد المقطورة (عتلة جونسون) للأسفل لإرسال الهواء إلى خزانات المقطورة","أفتح وصلة اليد للخط الخدمي للمقطورة بحيث يخرج الهواء ويعيد ضبط النظام"],"explanation":"اضغط على صمام إمداد هواء المقطورة للداخل لفتح الخط الطارئ، وملء خزانات المقطورة، وتحرير مكابح زنبرك المقطورة."},"131":{"q":"لقد أرجعتُ للتوّ الجرّار تحت المقطورة، ورفعتُ معدات الهبوط، ووصلتُ خطوط الهواء والكهرباء. قبل أن أثق بهذه المركبة على الطريق السريع، أُفعّل مكابح المقطورة وأريد التأكد من أن فكّي العجلة الخامسة مقفلان فعلًا على مسمار الارتكاز. ماذا يجب أن أفعل للتحقق من أن الوصل سيصمد؟","options":["أُعلي دورات المحرك بقوة وهو في الوضع المحايد وأُصغي لصوت استقرار الفكّين القافلين على مسمار الارتكاز","مع تفعيل مكابح المقطورة، أتقدّم للأمام بلطف في الترس المنخفض للتأكد من بقاء الوصل متصلًا","أُحرّر مكابح ركن الجرّار وأتدحرج للخلف بضع بوصات لدفع مسمار الارتكاز أعمق في الفكّين","أُفعّل صمام يد المقطورة فقط وأتركه مضبوطًا بحيث تُمسك المكابح المقطورة في مكانها"],"explanation":"بعد الوصل، أقفل مكابح المقطورة وتقدّم للأمام بلطف في الترس المنخفض؛ فإذا بقيت المركبة متصلة، فهذا يعني أن العجلة الخامسة مقفلة على مسمار الارتكاز."},"132":{"q":"أثناء فحصي قبل الرحلة لمركبةٍ مركّبة قُبيل رحلةٍ ليلية، ألاحظ أن أضواء المقطورة الخلفية والعاكسات مغطّاة بأوساخ الطريق وأن إحدى العدسات خافتة. أيٌّ مما يلي يصف ما يجب أن أفعله قبل أن أتمكّن قانونيًا وبأمان من أخذ هذه المركبة إلى الطريق؟","options":["أترك الأوساخ كما هي ما دامت ضفيرة الكهرباء موصولة وتُغذّي الدائرة، وهو كلّ ما يفحصه التفتيش فعليًا","أتجاوز تنظيفها لأن العاكسات سلبية ولا يلزم فحص سوى المصابيح المُغذّاة بالكهرباء قبل الرحلة الليلية","أُنظّف الأضواء والعاكسات وأتأكد من أنها تعمل، لأنها يجب أن تكون نظيفةً وعاملةً بصرف النظر عن وقت اليوم","أُغطّي العدسة الخافتة بشريطٍ لاصق كي لا تُشتّت السائقين الآخرين وأعتمد على المصابيح المتبقية للرؤية"],"explanation":"يجب أن تكون أضواء المقطورة والعاكسات نظيفةً وعاملةً في كل الأوقات، بصرف النظر عن الساعة، لذا نظّفها وتحقق من أنها تُضيء فعلًا قبل القيادة."},"133":{"q":"أقوم بجولة الفحص قبل الرحلة على شاحنتي ومقطورتها وأصل إلى مؤخرة المقطورة. وأنا أنظر إلى واقي الانزلاق الخلفي (مصدّ ICC)، أيٌّ من الحالات التالية يعني أنه مقبول وأنه يمكنني قانونيًا أخذ هذه المركبة المركّبة إلى الطريق؟","options":["مثنيٌّ قليلًا إلى الداخل لكنه لا يزال مثبّتًا بالبراغي على الهيكل، فيمكن إبقاؤه كما هو للرحلة","تمّ فكّه وإزالته للإبقاء على المقطورة تحت حدّ وزنها الإجمالي","متدلٍّ بشكلٍ مفكوك من أحد الجانبين لكنه مطليّ بطلاءٍ عاكس بحيث يراه السائقون الآخرون","مثبّت بإحكام في مكانه، مربوط بالبراغي على الهيكل، وخالٍ من أي تلفٍ أو شقوق"],"explanation":"يجب أن يكون واقي الانزلاق الخلفي (مصدّ ICC) مثبّتًا بإحكام على الهيكل وخاليًا من التلف أو الشقوق ليوقف قانونيًا مركبةً أصغر من الانزلاق تحته في حال اصطدامٍ خلفي."},"134":{"q":"أُنهي فحصي قبل الرحلة لمقطورةٍ صندوقية محمّلة قبل الخروج من رصيف التحميل. عدّة أمورٍ تمّ الاعتناء بها بالفعل، لكن وأنا أمشي عند مؤخرة المقطورة ألاحظ أن أبواب الحمولة لا تزال مفتوحة بينما يأخذ عامل الساحة منصّةً نقّالة أخيرة. قبل أن أنطلق، ما الحالة الصحيحة لأبواب حمولة المقطورة؟","options":["مغلقةً تمامًا ومُقفلةً بإحكام بحيث لا يمكن أن تنفتح أثناء النقل","مُقفلةً لكن متروكةً مفتوحةً بضع بوصات لأتأكد من أن السدّادة لا تعلق","مغلقةً لكن غير مُقفلة، لأن مزلاج الباب قد يعلق على الإطار عند المطبّات","مفتوحةً بالكامل ومربوطةً للخلف بحيث تبقى البضاعة مهوّاة على الطريق"],"explanation":"يجب أن تكون أبواب الحمولة مغلقةً تمامًا ومُقفلةً بإحكام قبل القيادة بحيث لا تنفتح أثناء النقل فتُسقط الحمولة أو تزيحها."},"135":{"q":"أثناء جولة الفحص قبل الرحلة لشاحنةٍ ومقطورة، أصل إلى مؤخرة المقطورة وأفحص واقيات الطين (واقيات الرذاذ) خلف الإطارات الخلفية. لاجتياز الفحص والبقاء قانونيًا على الطريق، في أي حالةٍ يجب أن تكون واقيات الطين هذه؟","options":["مطويةً للأعلى ومربوطةً فوق الإطارات بحيث لا تعلق بالأرصفة أو أرصفة التحميل","مثبّتةً بإحكام، متدلّيةً في مكانها، وخاليةً من التمزّقات أو الأجزاء المفقودة","مُزالةً بالكامل، لأنها ملحقاتٌ اختيارية وليست جزءًا من الفحص المطلوب","مطليةً بطلاءٍ جديد لإحكامها، حتى لو كانت حافتها السفلية مشقوقةً أو ممزّقة"],"explanation":"يجب أن تكون واقيات الطين موجودةً، ومثبّتةً بإحكام، ومتدلّيةً في مكانها، وخاليةً من التمزّقات أو الأجزاء المفقودة بحيث تحجب رذاذ الطريق والحطام الذي تقذفه الإطارات الخلفية."},"136":{"q":"أثناء فحصي قبل الرحلة لمركبةٍ مركّبة، أنحني لأفحص إطارات المقطورة واحدًا تلو الآخر. للتأكد من أن كل إطارٍ آمنٌ وصالحٌ للطريق، أيُّ حالةٍ يجب أن أقيّمها في كل إطارٍ من إطارات المقطورة؟","options":["أن تكون الجدران الجانبية بلونٍ داكنٍ موحّد دون بقعٍ باهتة أو متلاشية بفعل الشمس","أن يُصدر كل إطارٍ صوتًا صلبًا منخفض النبرة عندما أضربه بمطرقة الإطارات","أن يكون الإطار منفوخًا بشكلٍ صحيح وذا عمق نقشٍ كافٍ","أن تكون الإطارات دافئةً عند اللمس، مما يدلّ على أن المحامل مستقرّة بشكلٍ صحيح"],"explanation":"افحص كل إطارٍ من إطارات المقطورة للتأكد من النفخ السليم وعمق النقش الكافي، لأن نقص النفخ والنقش المهترئ يسبّبان الانفجارات وفقدان التماسك."},"137":{"q":"أثناء فحصي قبل الرحلة، أكون على الأرض أفحص منطقة العجلة الخامسة ومسمار الارتكاز قبل الوصل. ألاحظ عدّة أمورٍ وعليّ أن أقرّر أيٌّ منها يعني أن المقطورة غير آمنةٍ للوصل والقيادة. أيٌّ من الحالات التالية يجب أن يدفعني إلى إخراج هذه المقطورة من الخدمة؟","options":["مسمار الارتكاز مغطّى بالشحم حيث تنزلق صفيحة العجلة الخامسة عليه","مسمار الارتكاز يستقرّ متمركزًا فوق العجلة الخامسة أثناء رجوعي ببطء تحته","الفكّان القافلان ينغلقان تمامًا حول ساق مسمار الارتكاز أثناء الوصل","مسمار الارتكاز مثنيٌّ بشكلٍ ظاهر أو متآكلٌ عن شكله وحجمه الأصلي"],"explanation":"مسمار الارتكاز المثنيّ بشكلٍ ظاهر أو المتآكل عن شكله الأصلي لا يمكن للفكّين القافلين أن يُمسكا به بإحكام، لذا يجب إخراج المقطورة من الخدمة."},"138":{"q":"أثناء فحصٍ قبل الرحلة، يلاحظ سائقٌ جديد أن التوجيه يبدو متصلّبًا ويرتجّ بشكلٍ غير متساوٍ كلّما دار الجرّار حول المنعطفات الضيقة والمقطورة موصولة. يؤكّد ميكانيكيٌّ أن مكوّنات الوصل سليمة عدا ذلك. أيُّ خطوة صيانةٍ هي الأرجح أنها أُغفلت وتسبّب هذا العَرَض؟","options":["لم تُشحّم العجلة الخامسة، فلا يمكن للصفيحة أن تنزلق بسلاسة على المقطورة","لم يستقرّ مسمار الارتكاز بالكامل في الفكّين القافلين قبل اختبار الجذب","لم تُثبَّت ذراع إدارة معدات الهبوط بعد رفع أرجل الدوللي","لم تُوصَل ضفيرة الكهرباء، مما قطع الطاقة عن أضواء المقطورة"],"explanation":"يجب تشحيم العجلة الخامسة بحيث تنزلق الصفيحة العلوية بسلاسة على المقطورة؛ فبدون الشحم تلتصق الأسطح، مما يسبّب توجيهًا صعبًا ومرتجًّا."},"139":{"q":"لقد أنهيتُ للتوّ وصل الجرّار بالمقطورة وأعمل على توصيلاتي. أُوصّل سلك الكهرباء (الضفيرة) في مقبس المقطورة، لكن هناك حلقةً طويلةً من السلك المرتخي تتدلّى قرب الهيكل بين الجرّار والمقطورة. لإتمام هذا التوصيل بشكلٍ صحيح، ماذا يجب أن أفعل بذلك الجزء المرتخي؟","options":["أترك السلك الزائد متدلّيًا بشكلٍ مفكوك بحيث يكون له متّسعٌ للالتواء عند انعطاف المركبة وتأرجح المقطورة","أُثبّت السلك بحيث يُمسَك الجزء المرتخي للأعلى ولا يمكن أن يُجَرّ على الأرض أو يعلق أثناء القيادة","أفصل الضفيرة حتى أصل إلى الطريق السريع، لأن أضواء المقطورة مطلوبةٌ ليلًا فقط","ألفّ الجزء المرتخي بإحكام وأدسّه تحت وصلات خط هواء اليد المتصافحة لأُبعده عن الطريق"],"explanation":"ثبّت ضفيرة الكهرباء بحيث يُمسَك الجزء المرتخي منها للأعلى ولا يمكن أن يُجَرّ على الأرض أو يعلق بالأجزاء المتحركة، مما يُتلف السلك ويُطفئ أضواء المقطورة."},"140":{"q":"بعد إرجاع الجرّار تحت المقطورة، أزحف تحتها بمصباحي اليدوي لأفحص وصل العجلة الخامسة قبل اختبار الجذب. وأنا أنظر إلى كيفية استقرار الفكّين القافلين بالنسبة لمسمار الارتكاز، أيٌّ من هذه يدلّني على أن الوصل صحيح وآمنٌ للقيادة؟","options":["التقط الفكّان طرف مسمار الارتكاز الضيّق فقط، ممسكَين به بإحكام عند القمّة تمامًا","لا يزال الفكّان مفتوحَين ويستقرّان فوق مسمار الارتكاز، جاهزَين للنزول عليه بمجرد تقدّمي للأمام","الفكّان منغلقان تمامًا حول ساق مسمار الارتكاز، مع وجود ذراع القفل في وضع القفل","الفكّان متباعدان على نطاقٍ واسع بحيث يستطيع مسمار الارتكاز التحرّك بحرّية داخلهما للالتواء عند المنعطفات"],"explanation":"يتطلّب الوصل السليم أن يكون الفكّان القافلان منغلقَين تمامًا حول ساق مسمار الارتكاز مع وجود ذراع القفل في وضع القفل."},"141":{"q":"لقد أنهيتُ للتوّ إرجاع الجرّار تحت المقطورة وأُجري فحصًا بصريًا للوصل قبل اختبار الجذب. عندما يستقرّ لوح المقطورة بالطريقة التي ينبغي، ماذا سأرى حيث يلتقي اللوح بالعجلة الخامسة؟","options":["اللوح مائلًا إلى الأعلى بعيدًا عن العجلة الخامسة بحيث يتجاوز مسمار الارتكاز الفكّين القافلين","اللوح مستقرًّا على إطارات الجرّار الخلفية لتوزيع وزن المقطورة","اللوح منخفضًا على الأرض حتى تُرفَع معدات الهبوط بالكامل","اللوح مستقرًّا بشكلٍ مسطّح على العجلة الخامسة دون أي فراغٍ بينهما"],"explanation":"يُظهر الوصل الصحيح لوح المقطورة مستقرًّا بشكلٍ مسطّح ومُحكَم على العجلة الخامسة دون أي فراغ، مما يعني أن مسمار الارتكاز قد نزل بالكامل في الفكّين القافلين."},"142":{"q":"لقد أنهيتُ وصل الشاحنة بالمقطورة، وأجريتُ اختبار الجذب، ووصلتُ خطوط الهواء والضفيرة. وأنا أستعدّ للخروج من الساحة، ما الطريقة الصحيحة للتعامل مع معدات الهبوط قبل أن أنطلق؟","options":["أُدير معدات الهبوط للأعلى بالكامل وأُثبّت مقبض الإدارة قبل تحريك المركبة","أرفع معدات الهبوط نحو المنتصف بحيث تبتعد عن الرصيف لكنها تبقى جاهزةً للنزول بسرعة","أترك معدات الهبوط تلامس الأرض بخفّة لتقاسم وزن المقطورة أثناء القيادة","أرفعها قليلًا فقط بحيث ترتفع عن السطح، ثم أُخزّن مقبض الإدارة وأنطلق"],"explanation":"ارفع معدات الهبوط بالكامل وثبّت مقبض الإدارة قبل القيادة، لأن أي جزءٍ يُترك منخفضًا قد يعلق بالمعابر أو الرصيف الوعر ويتمزّق."},"143":{"q":"لقد أنهيتُ للتوّ وصل الجرّار بالمقطورة وأدرتُ معدات الهبوط للأعلى بالكامل. قبل أن أخرج من الساحة، ماذا يجب أن أفعل بمقبض الإدارة كي لا يرتخي بالاهتزاز، أو يتأرجح للخارج، أو يتلف أثناء قيادتي؟","options":["أتركه معلّقًا على صندوق التروس بحيث يستطيع السائق التالي إنزال الأرجل بسرعة","أُثبّته في حامله أو مشبكه بحيث يكون مخزّنًا ولا يمكن أن يتحرّك أثناء القيادة","أُسقطه داخل صندوق قفازات القمرة حيث يبقى بعيدًا عن الطريق","أضعه بشكلٍ مسطّح على أرضية المقطورة قرب مسمار الارتكاز حتى أفكّ الوصل مجددًا"],"explanation":"خزّن مقبض الإدارة في حامله أو مشبكه المخصّص بحيث لا يرتخي بالاهتزاز، أو يتأرجح إلى حركة المرور، أو يتلف أثناء تحرّك المركبة."},"144":{"q":"أقوم بوصل الجرّار بمقطورةٍ في الساحة وألاحظ أن وصلات اليد المتصافحة مرمّزة بالألوان: وصلةٌ وخطٌ باللون الأزرق، والآخر باللون الأحمر. وأنا أمدّ يدي لربطهما بخطوط هواء المقطورة، ما الطريقة الصحيحة لتوصيلهما؟","options":["أوصّل أيّ وصلة يدٍ تصل بسهولة أكبر، لأن الهواء سيتوازن بين الخطّين بمجرد الشحن","أوصّل الخط الخدمي الأزرق بالوصلة الطارئة الحمراء بحيث يعبر هواء الإمداد إلى جانب التحكّم","أوصّل الألوان المتطابقة معًا — وصلة اليد الزرقاء بالزرقاء، والحمراء بالحمراء — ولا أُقاطعهما أبدًا","أوصّل الأحمر بالأزرق، لأن الإمداد الطارئ يجب أن يُغذّي الخط الخدمي لتحرير المكابح"],"explanation":"وصّل وصلات اليد المرمّزة بالألوان كلٌّ بمثيله — الخط الخدمي الأزرق بالأزرق، والخط الطارئ الأحمر بالأحمر — ولا تُقاطعهما أبدًا."},"145":{"q":"أقوم بفحصٍ قبل الرحلة على مركبتي المركّبة وأنا منحنٍ أنظر إلى هيكل المقطورة والعوارض المتقاطعة. عدّة أمورٍ تلفت نظري وأحاول أن أقرّر أيٌّ منها هو عيبٌ يستوجب الإخراج التلقائي من الخدمة ويعني أنني لا أستطيع القيادة قانونيًا. أيٌّ من هذه، إذا وجدتُه على الهيكل أو عارضةٍ متقاطعة، هو العيب الذي يجب ألّا أتجاهله؟","options":["طلاءٌ باهتٌ أو متقشّر على طول قضبان الهيكل","براغي تثبيتٍ تربط بوضوحٍ العوارض المتقاطعة بالهيكل","عاكساتٌ مثبّتة على مؤخرة وجانب هيكل المقطورة","شقوقٌ ممتدّة عبر قضبان الهيكل أو عارضةٍ متقاطعة"],"explanation":"الشقوق في قضبان الهيكل أو في عارضةٍ متقاطعة هي عيبٌ بنيوي يمكن أن يتفاقم تحت الحمل ويسبّب فشلًا كارثيًا، لذا يجب إخراج الوحدة من الخدمة."},"146":{"q":"لقد أنهيتُ وصل الجرّار بالمقطورة، ورفعتُ معدات الهبوط، ووصلتُ خطوط الهواء وضفيرة الكهرباء. قُبيل أن أصعد إلى القمرة وأخرج من الساحة، ما آخر شيءٍ ينبغي أن أفعله للتأكد من أن المركبة آمنةٌ للقيادة؟","options":["أُجري جولةً أخيرة حول المركبة بأكملها، متأكّدًا من أن التوصيلات محكمة ولا شيء يعترض الطريق","أسحب صمام يد المقطورة لإمساك مكابح المقطورة بينما أنقل الترس","أُعلي دورات المحرك لبناء ضغط الهواء أسرع قبل تحرير مكابح الركن","أُمسح قنوات اللاسلكي (CB) بحثًا عن تقارير حركة المرور لأعرف أحوال الطريق أمامي"],"explanation":"الخطوة الأخيرة قبل الانطلاق هي جولة فحصٍ كاملة حول المركبة للتأكد من أن الوصل، وخطوط الهواء، والخط الكهربائي، ومعدات الهبوط، والمحيط كلّها محكمة وخالية."},"147":{"q":"أثناء فحصي قبل الرحلة لشاحنةٍ ومقطورة، أفحص خطّي الهواء ووصلتيهما المتصافحتين قبل الوصل. أيُّ حالةٍ ستُجبرني على إخراج هذه المركبة من الخدمة بدلًا من أن تكون مجرّد ملاحظةٍ روتينية؟","options":["الخط الخدمي مرمّزٌ باللون الأزرق والخط الطارئ مرمّزٌ باللون الأحمر","خطوط الهواء تُظهر أجزاءً مقطوعة، أو متشقّقة، أو متآكلة في الغطاء الخارجي","خطّا الهواء موصولان بإحكام بوصلتيهما المتصافحتين","خطوط الهواء مُمرَّرة ومثبّتة بحيث لا يمكن أن تعلق أو تحتكّ بالأجزاء المتحركة"],"explanation":"خطوط الهواء المقطوعة، أو المتشقّقة، أو المتآكلة في الغطاء يمكن أن تفشل تحت الضغط وتسبّب فقدان الهواء، مما يجعل المركبة غير آمنةٍ للتشغيل."},"148":{"q":"دخلتُ ساحة إنزالٍ لأفكّ وصل مقطورتي المحمّلة على منحدرٍ بسيط. قبل أن أزحف تحتها لأسحب مقبض التحرير وأُخرج الجرّار، أضع أسافين أمام عجلات المقطورة. ما السبب الرئيسي لوضعي الأسافين أمام تلك العجلات؟","options":["لرفع وزن المقطورة عن العجلة الخامسة بحيث يتحرّر الفكّان القافلان بسهولةٍ أكبر عندما أسحب المقبض","لمنع مكابح زنبرك المقطورة من التفعيل بمجرد فصل خطوط الهواء عن الجرّار","لمنع المقطورة من التدحرج بمجرد أن لم يعد الجرّار يُمسكها","لإمساك المقطورة بثباتٍ بحيث لا تنثني معدات الهبوط وهي تتحمّل الحمل"],"explanation":"ضع الأسافين أمام العجلات عند فكّ الوصل بحيث لا تتدحرج المقطورة بمجرد أن لم تعد مكابح الجرّار ووزنه يُمسكانها، وخاصةً على منحدر."},"149":{"q":"كُلّفتُ برحلة مقطورتين مزدوجتين ويخبرني المُرسِل أن آخذ دوللي تحويل (converter dolly) من الساحة قبل أن أنطلق. وأنا أربط كل شيء، ماذا يفعل دوللي التحويل فعليًا في مركبتي؟","options":["يشحن خزانات هواء المقطورة ويُفعّل مكابح الزنبرك إذا فقد الخط الطارئ الهواء","يُقفل على مسمار الارتكاز بحيث يمكن وصل المقطورة الأولى بالعجلة الخامسة للجرّار","يرفع ويُنزل معدات الهبوط بحيث تستطيع المقطورة الخلفية الاستراحة عند ركنها وفكّ وصلها","يوفّر عجلةً خامسة وقضيب جرّ بحيث يمكن وصل مقطورةٍ ثانية خلف الأولى"],"explanation":"دوللي التحويل هو وحدةٌ من محورٍ وهيكل لها عجلتها الخامسة الخاصة وقضيب جرّ، يوفّر نقطة الوصل لإضافة مقطورةٍ ثانية خلف الأولى."},"150":{"q":"أُرجِع شاحنتي ومقطورتي بشكلٍ مستقيم إلى رصيف تحميل، مراقبًا مرآتي. تبدأ مؤخرة المقطورة بالانحراف نحو جانب السائق وأحتاج إلى دفعها مجددًا نحو جانب الراكب لأبقى مصطفًّا مع الرصيف. لتحريك مؤخرة المقطورة نحو جانب الراكب، أيُّ توجيهٍ للقيادة هو الصحيح؟","options":["أُدير عجلة القيادة نحو جانب السائق، أي الاتجاه المعاكس للمكان الذي أريد أن تذهب إليه المقطورة","أُدير عجلة القيادة نحو جانب الراكب، أي الاتجاه نفسه الذي أريد أن تذهب إليه المقطورة","أُمسك العجلة مستقيمةً وأرفع قدمي عن الوقود بحيث تنحرف المقطورة للخلف من تلقاء نفسها","أُدير عجلة القيادة نحو جانب الراكب، ثم أستقيم بسرعة لأقلب المقطورة إلى الجانب الآخر"],"explanation":"عند الرجوع للخلف، تتحرّك المقطورة عكس توجيهك، لذا أَدِر العجلة نحو جانب السائق لإرسال مؤخرة المقطورة نحو جانب الراكب."},"151":{"q":"أقوم برجوع مقطورتي التي يبلغ طولها 53 قدمًا إلى رصيف تحميل يقع خلفي وإلى يساري، لذا أحتاج إلى أن يتأرجح مؤخرة المقطورة نحو جانب السائق. وكلتا يديّ في أسفل عجلة القيادة وعيناي على المرايا، إلى أي اتجاه ينبغي أن أدير العجلة أولًا لأبدأ بتحريك المقطورة نحو اليسار؟","options":["أدير العجلة إلى اليسار، لأن المقطورة تتبع دائمًا الاتجاه نفسه الذي توجّه به الجرّار.","أدير العجلة إلى اليمين أولًا، حتى يبدأ مؤخرة المقطورة بالتحرك إلى اليسار.","أبقي العجلة مستقيمة وأترك المقطورة تنحرف يسارًا من تلقاء نفسها قبل التوجيه.","أدير العجلة إلى أقصى اليسار لإجبار المقطورة على الانتقال بسرعة."],"explanation":"تدور المقطورة في الاتجاه المعاكس لعجلة القيادة، لذا وجّه إلى اليمين أولًا لجعل مؤخرة المقطورة تتأرجح إلى اليسار."},"152":{"q":"أقوم برجوع الجرّار والمقطورة إلى رصيف تحميل ضيق، والمقطورة تنحرف قليلًا عن الخط الذي أريده. لإعادة المركبة إلى مسارها دون أن أزيد الوضع سوءًا، أي أسلوب توجيه ينبغي أن أستخدم؟","options":["أدير العجلة بقوة في اتجاه واحد لإعادة المقطورة إلى الخط بسرعة","أبقي العجلة ثابتة تمامًا وأترك المقطورة تستقيم بنفسها أثناء استمراري في الرجوع","أجري تصحيحات توجيه صغيرة وأتقدم إلى الأمام لإعادة التموضع كلما ابتعدت المقطورة كثيرًا","أدير العجلة بحدة في الاتجاه المعاكس للإفراط في التصحيح، ثم أعيدها بقوة لإلغاء الانحراف"],"explanation":"عند رجوع المقطورة، أجرِ تصحيحات توجيه صغيرة وتقدّم إلى الأمام لإعادة التموضع كلما انحرفت كثيرًا عن مسارها."},"153":{"q":"إذا ابتعدت المقطورة كثيرًا عن الخط أثناء الرجوع، عليك أن:","options":["تجبرها على العودة بقوة","تتقدم إلى الأمام لإعادة الضبط","تسرّع في الرجوع","تستسلم تمامًا"],"explanation":"تقدّم إلى الأمام لتعديل المسار وحاول مجددًا."},"154":{"q":"أنا عند رصيف استلام مزدحم وأحتاج إلى رجوع مقطورتي التي يبلغ طولها 53 قدمًا إلى مرفأ تحميل ضيق مع رؤية محدودة على الجانب الأعمى (الأيمن). يقف زميل قريب ويعرض أن يكون مرشدًا لي. لأقوم بذلك بأكبر قدر من الأمان، ماذا ينبغي أن أفعل؟","options":["أصرف المساعد بإشارة، وأنزل نافذتي، وأرجع بسرعة ثابتة حتى أنتهي قبل أن تحتاج الشاحنات الأخرى إلى الممر","أطلب من المساعد أن يقف خلف المقطورة مباشرة في نقطتي العمياء حتى يكون بالضبط حيث ستنتهي المقطورة","أتخلى عن المساعد لكنني أرجع بسرعة طالما لديّ صورة ذهنية واضحة للمرفأ، وأتوقف فقط إذا سمعت شيئًا","أرجع ببطء مستعينًا بالمرشد متموضعًا حيث أستطيع رؤيته، وأتوقف فور أن تغيب رؤيته عني"],"explanation":"ارجع ببطء مستعينًا بمرشد تستطيع رؤيته، وتوقف فورًا في اللحظة التي تفقد فيها رؤيته."},"155":{"q":"أنقل مقطورة محمّلة على طريق سريع ريفي وأرى منعطفًا أمامي بسرعة استرشادية معلنة قدرها 45 ميلًا في الساعة. معظم السيارات حولي تأخذ المنعطف بالضبط عند علامة الـ 45 ميلًا في الساعة. للتعامل مع مركبتي المركّبة بأمان، كيف ينبغي أن تكون سرعتي عبر المنعطف مقارنة بهم؟","options":["ينبغي أن آخذ المنعطف أبطأ من السيارات، لأن المركبة المركّبة المرتفعة والمحمّلة قد تنقلب إذا سارت بسرعة كبيرة في المنعطف","ينبغي أن أوازي السيارات عند السرعة الاسترشادية البالغة 45 ميلًا في الساعة، لأن هذا الرقم المعلن يأخذ مركبتي بالحسبان مسبقًا","ينبغي أن أحمل سرعة أكبر قليلًا من السيارات للحفاظ على الزخم وتجنب إجهاد المحرك في المنعطف","ينبغي أن أحافظ على أي سرعة ثابتة عبر المنعطف طالما أكبح بقوة حالما أشعر بأن المقطورة تدفع"],"explanation":"تتمتع المركبة المركّبة المحمّلة بمركز ثقل مرتفع وقد تنقلب، لذا خذ المنعطفات أبطأ من السيارات وخفّف السرعة قبل الدخول."},"156":{"q":"أقود مركبتي المركّبة على منحدر مبتل ومتجمد عندما تتباطأ حركة المرور أمامي فجأة. بدافع الغريزة أضغط دواسة الفرامل بقوة فتُقفل عجلات المقطورة. على هذا السطح الزلق، ما النتيجة الأرجح لهذا الكبح القوي؟","options":["تنغرز عجلات المقطورة المقفلة وتمنحني تماسكًا إضافيًا، فتقصّر مسافة توقفي","تفقد عجلات المقطورة تماسكها وتتأرجح المقطورة إلى الجانب، فتبدأ بالانثناء","تدفع المقطورة مباشرة إلى الأمام وتتدحرج فعليًا أسرع على المنحدر","تتتبع المقطورة بشكل مثالي خلف الجرّار وتتوقف بسرعة"],"explanation":"على سطح زلق، قد يقفل الكبح القوي عجلات المقطورة، ما يجعلها تفقد التماسك وتدفع المقطورة إلى الجانب في حالة انثناء."},"157":{"q":"أقود مقطورة صندوقية فارغة عائدًا إلى الساحة على امتداد مفتوح من الطريق السريع عندما تهبّ رياح جانبية قوية على الجانب المسطح الطويل للمقطورة. من بين ما يلي، ما أكبر مصدر قلق ينبغي أن أخطط له في هذا الوضع؟","options":["المقطورة الفارغة أخف وزنًا، لذا ستتماسك مع الطريق بشكل أفضل وتسير مستقيمة خلفي","ستضغط الرياح على السقف وتخفض مركز ثقلي، مما يساعد على الثبات","يمكن للرياح أن تدفع المقطورة المرتفعة الخفيفة الحمولة جانبًا أو حتى تقلبها","المقطورة الفارغة لا تتأثر بالرياح لأنه لا توجد حمولة لتلتقط الهبّات"],"explanation":"يمكن للرياح القوية أن تدفع مقطورة مرتفعة خفيفة الحمولة جانبًا أو حتى تقلبها، لأنها تقدم مساحة كبيرة بوزن قليل لا يثبّتها."},"158":{"q":"أقود جرّارًا ومقطورة محمّلة على طريق سريع جاف بسرعة الطريق السريع، وحركة المرور أمامي تسير بثبات. مقارنة بالمسافة التي كنت سأتركها لو كنت أقود سيارتي الخاصة بالسرعة نفسها، كيف ينبغي أن أدير مسافة التتابع خلف المركبة التي أمامي؟","options":["المسافة نفسها، لأن مسافة التتابع تعتمد فقط على السرعة وحالة الطريق، وليس على ما تقوده.","مسافة أقل، لأن الفرامل الهوائية للمقطورة ونظام منع الانغلاق يتيحان للمركبة المركّبة التوقف في مسافة أقصر من السيارة.","مسافة أقل في البداية، ثم أقلّص الفجوة تدريجيًا حتى لا يستطيع السائقون الآخرون التقدم أمام المقطورة.","مسافة أكبر، لأن المركبة المركّبة المحمّلة أثقل وأطول وتحتاج إلى مساحة إضافية للتوقف بأمان."],"explanation":"المركبة المركّبة المحمّلة أثقل وأطول من السيارة، لذا تحمل زخمًا أكبر وتحتاج إلى مسافة تتابع وتوقف أكبر."},"159":{"q":"أسحب مركبة مركّبة طويلة على طريق سريع في تكساس، وأريد تحديد مسافة تتابع آمنة خلف المركبة التي أمامي. باستثناء حركة المرور والسرعة، أي خاصية من خصائص مركبتي تتطلب مني أكثر من غيرها إضافة مسافة تتابع إضافية؟","options":["طولها، لأن المركبة الأطول تحتاج إلى مساحة أكبر للتوقف وإخلاء حركة المرور","لون طلائها، لأن المقطورات الأغمق أصعب على السائقين الآخرين في تقدير المسافة","ماركة جرّارها، لأن بعض الصناعات مصنّفة لمسافة توقف أقصر","مستوى صوت الراديو، لأن الصوت العالي يؤخّر سرعة رد فعلي تجاه المخاطر"],"explanation":"المركبة الأطول تشغل مساحة أكبر من الطريق وتحتاج إلى مساحة إضافية للتوقف وإخلاء حركة المرور، لذا يتطلب الطول مسافة تتابع أكبر."},"160":{"q":"أقود جرّارًا ومقطورة محمّلين بالكامل وأرى منحدرًا طويلًا وحادًا أمامي. للحفاظ على مركبتي المركّبة تحت السيطرة طوال الطريق إلى الأسفل، ماذا ينبغي أن أفعل قبل أن أبدأ النزول؟","options":["أنتظر حتى تزداد سرعتي، ثم أنقل إلى غيار أدنى ليمسك المحرك ويكبحني","أختار غيارًا منخفضًا قبل النزول وأكبح مبكرًا للسيطرة على سرعتي","أبقى في غيار مرتفع وأترك الحمولة الثقيلة تتدحرج، وأكبح فقط إذا اقتربت من الأسفل","أتركها في الوضع المحايد لتوفير الوقود وأضغط الفرامل باستمرار طوال الطريق نزولًا"],"explanation":"على منحدر، اختر غيارًا منخفضًا واكبح مبكرًا حتى يساعد المحرك على كبح المركبة وتبقى الفرامل باردة، مما يحافظ على السيطرة على السرعة."},"161":{"q":"أقترب بجرّاري ومقطورتي من منعطف يمين عند تقاطع في المدينة. لأن مركبتي تنحرف عن مسار العجلات، أُغرى بالانحراف يسارًا وتوسيع مقدمة مقصورتي قبل أن أبدأ المنعطف لتترك العجلات الخلفية للمقطورة مساحة لتجاوز الرصيف. وفقًا لإدارة السلامة العامة في تكساس، ما الخطر الرئيسي للانحراف الواسع مبكرًا بهذا الشكل بدلًا من الانتظار حتى إكمال المنعطف؟","options":["ستقفز العجلات الخلفية للمقطورة فوق الرصيف لأنها تتبع مسارًا خارجيًا أوسع","عجلاتي الدافعة أكثر عرضة للقفل وقذف الجرّار في انثناء","يمكن لسيارة أن تنزلق إلى المساحة المفتوحة على يميني وتُحاصر أثناء انعطافي","ستنقلب المركبة نحو داخل المنعطف بسبب حركة التوجيه المفاجئة"],"explanation":"يفتح توسيع المقصورة قبل المنعطف فجوة على يمينك يمكن لسيارة أن تنزلق إليها وتُحاصر بينما تكتسح المقطورة عائدة نحو الرصيف."},"162":{"q":"أقود جرّارًا ومقطورة وأحتاج إلى الانعطاف يمينًا عند تقاطع في المدينة. أعلم أن عليّ الانحراف بشكل واسع حتى تتجاوز العجلات الخلفية لمقطورتي الرصيف. وبينما أبدأ المنعطف، يبدو أن سائقًا فاقد الصبر خلفي مستعد للاندفاع في المساحة المفتوحة على جانبي الأيمن. لمنع تلك السيارة من التسلل بين مقطورتي والرصيف أثناء المنعطف، ماذا ينبغي أن أفعل؟","options":["أنحرف بالجرّار بعيدًا إلى اليسار قبل الانعطاف حتى تسدّ المركبة بأكملها الممر خلفي","أبقي مؤخرة المقطورة مرفوعة عن الرصيف بقيادتها فوق الرصيف وأنا أدور","أنحرف بمؤخرة المقطورة بعيدًا إلى اليسار حتى تغطي الممر الأيمن الذي تريده السيارة","أبقي مؤخرة المقطورة قريبة من الرصيف حتى لا تبقى مساحة لسيارة تمر على يميني"],"explanation":"إبقاء مؤخرة المقطورة قرب الرصيف يغلق الفجوة على يمينك حتى لا تتمكن السيارات من المرور والاصطدام أثناء إكمالك المنعطف الواسع."},"163":{"q":"أنا في رحلة فارغة بمقطورتي الصندوقية الخالية تمامًا، وأصل إلى امتداد طويل من الرصيف المتكسر والمموّج. مقارنة بحين أكون محمّلًا، كيف ينبغي أن أتعامل مع سرعتي على هذا الطريق الوعر، ولماذا؟","options":["أخفّف السرعة قبل المقطع الوعر، لأن المقطورة الفارغة ترتد أكثر وتفقد التماسك فوق المطبّات","أحافظ على سرعتي المعتادة عند التحميل، لأن المقطورة الفارغة أخف وأسهل في التحكم فوق المطبّات","أسرّع قليلًا حتى أنزلق فوق المطبّات قبل أن تبدأ المقطورة بالارتداد","أحافظ على السرعة لكنني أكبح بقوة كلما بدأت المقطورة بالارتداد لتهدئتها"],"explanation":"المقطورة الفارغة تحمل وزنًا قليلًا على إطاراتها، لذا ترتد وتفقد التماسك فوق المطبّات؛ خفّف السرعة قبل المقاطع الوعرة لإبقاء الإطارات ملتصقة بالطريق."},"164":{"q":"أسحب مقطورة محمّلة على طريق سريع متجمد عندما يبدأ مؤخرة المقطورة بالتذبذب والتأرجح خلفي. لإعادة المركبة تحت السيطرة، ماذا ينبغي أن أفعل؟","options":["أضغط الفرامل بقوة أكبر لإبطاء عجلات المقطورة وإيقاف الانزلاق","أرفع قدمي عن دواسة الوقود وأوجّه برفق لتقويم المقطورة","أسرّع بحزم لسحب المقطورة عائدة إلى الخط خلف الجرّار","أسحب صمام يد المقطورة لتطبيق فرامل المقطورة وحدها وتثبيتها"],"explanation":"تذبذب المقطورة على الجليد هو انزلاق للمقطورة، لذا توقف عن الكبح، وارفع قدمك عن دواسة الوقود لتدع العجلات تدور وتستعيد التماسك، ثم وجّه برفق لتقويم المركبة."},"165":{"q":"تقود جرّارًا ومقطورة محمّلين نزولًا على منحدر مبتل وتكبح بحزم لحركة مرور متباطئة أمامك. تشعر بأن مؤخرة الجرّار تبدأ بالانحراف إلى جانب واحد وتبدأ العجلات الدافعة بالانزلاق. لإعادة المركبة تحت السيطرة، ماذا ينبغي أن تفعل أولًا؟","options":["تضغط دواسة الفرامل بقوة أكبر لقفل العجلات وإيقاف الانزلاق أسرع","تسحب صمام يد المقطورة لتطبيق فرامل المقطورة وحدها وتقويم المركبة","توقف الكبح، وترفع قدمك عن دواسة الوقود، وتدع العجلات الدافعة تدور مجددًا لاستعادة التماسك","توجّه بقوة في الاتجاه المعاكس مع الحفاظ على ضغط ثابت على الفرامل"],"explanation":"ينتج انزلاق العجلات الدافعة عن الإفراط في الكبح الذي يقفل العجلات، لذا فالإجراء الأول هو رفع الفرامل أو دواسة الوقود وترك العجلات الدافعة تدور مجددًا لاستعادة التماسك."},"166":{"q":"أُحمّل مقطورة بصناديق على منصات نقالة تملأ الثلثين الأماميين فقط من منطقة الحمولة، تاركة مساحة مفتوحة نحو المؤخرة. وبينما أخطط لكيفية تأمين الحمولة وترتيبها قبل الانطلاق، أي مما يلي هو السبب الأهم لتثبيت الحمولة ودعمها وربطها بشكل صحيح؟","options":["حتى يمكن رؤية الحمولة وفحصها بسرعة عبر الأبواب الخلفية عند محطة الوزن التالية","حتى تتبع العجلات الخلفية للمقطورة مسارًا داخليًا أضيق من العجلات الأمامية للجرّار في المنعطفات","حتى تبقى الحمولة منخفضة بما يكفي لإبقاء وزن المقطورة دون الحد الإجمالي القانوني","حتى لا تتحرك الحمولة، لأن ذلك سيغيّر التوازن ويجعل الانقلاب أو الانزلاق أكثر احتمالًا"],"explanation":"يجب تأمين الحمولة حتى لا تتحرك، لأن الحمولة التي تنزلق تغيّر توازن المركبة ومركز ثقلها، مما يجعل الانقلاب أو الانزلاق أكثر احتمالًا."},"167":{"q":"أُحمّل بضائع في مقطورتي التي يبلغ طولها 53 قدمًا وينتهي معظم المنصات النقالة الثقيلة مكدّسًا قرب الأبواب الخلفية، تاركًا مقدمة المقطورة شبه فارغة. قبل أن أنطلق، يحذرني شريكي من أن هذا خطير. على الطريق السريع، كيف يؤثر هذا التحميل الثقيل في المؤخرة على سلوك المقطورة على الأرجح؟","options":["ستميل المقطورة إلى عدم الثبات وتتمايل من جانب إلى آخر، مما يجعلها أصعب في التحكم بسرعة الطريق السريع","ستتتبع المقطورة بأمان أكبر وتقاوم التمايل لأن الوزن يستقر فوق المحاور الخلفية","ستتوقف المقطورة في مسافة أقصر بشكل ملحوظ لأن وزنًا أكبر يضغط على الفرامل","ستسير المقطورة أكثر انخفاضًا وتستهلك وقودًا أقل لأن الحمولة مركّزة فوق محاور أقل"],"explanation":"الوزن المحمّل بعيدًا جدًا نحو المؤخرة يجعل المقطورة غير مستقرة ويسبب تمايلها من جانب إلى آخر، مما يقلل التحكم بسرعة الطريق السريع؛ أبقِ الحمولة موزّعة من الأمام إلى الخلف."},"168":{"q":"أنقل مقطورة محمّلة على الطريق السريع وألاحظ أنها أثقل من بضائعي المعتادة، مما يضعني قرب حدي الأقصى للوزن الإجمالي. وبينما أقترب من منحدر طويل وحركة مرور مندمجة، ماذا ينبغي أن أتوقع أكثر من غيره من الوزن الإضافي، وكيف ينبغي أن يغيّر طريقة قيادتي؟","options":["يضغط الوزن الإضافي الإطارات للأسفل لتماسك أفضل، لذا يمكنني الكبح متأخرًا والتتابع عن قرب أكثر من المعتاد","ستكون المقطورة أصعب في التوقف والتحكم، لذا أحتاج إلى مساحة توقف أكبر ومسافة تتابع إضافية","تستقر الحمولة الأثقل أكثر انخفاضًا، لذا أصبحت أفضل توازنًا ويمكنني أخذ منحدر الطريق بسرعتي المعتادة","يجعل الوزن الإضافي المركبة أسهل في السحب والتوجيه، لذا يمكن أن يبقى الكبح والتباعد على حالهما"],"explanation":"المقطورة الأثقل أو الزائدة التحميل لديها زخم أكبر وأصعب في التوقف والتحكم، لذا تحتاج إلى مسافة تتابع إضافية ومساحة أكبر للتوقف، خاصة على المنحدرات."},"169":{"q":"أقود جرّارًا ومقطورة محمّلين على طريق سريع مزدحم وأحتاج إلى الانتقال قبل مخرجي. حركة المرور ثابتة على الجانبين. مقارنة بقيادة شاحنة مفردة مستقيمة، ما السبب الرئيسي الذي يجعل مركبتي المركّبة تغيّر كيفية تعاملي مع هذه المناورة؟","options":["لأنها أثقل، ينبغي أن أكبح بحزم في اللحظة التي تظهر فيها فجوة حتى تقفل عجلات المقطورة وتثبّت موضعي في الممر.","لأنها أثقل وزنًا، يمكنني المرور عبر الاندماج بسرعة أعلى لأن الكتلة الإضافية تبقي المركبة مستقرة في المنعطف.","لأنها أطول بكثير، يجب أن أترك مساحة إضافية ووقتًا أكثر لتغيير الممرات والاندماج حتى تعبر المركبة بأكملها بأمان.","لأنها أطول ارتفاعًا، ينبغي أن أوسّع المقصورة مبكرًا قبل الفجوة حتى يكون للمقطورة مساحة لتتبعها إلى الممر الجديد."],"explanation":"المركبة المركّبة أطول بكثير، لذا تحتاج إلى مساحة أكبر ووقت أكثر لتعبر المركبة بأكملها فجوة عند تغيير الممرات أو الاندماج."},"170":{"q":"أقود جرّاري ومقطورتي المحمّلين على طريق سريع مبتل أثناء مطر غزير. وبينما أفحص مراياي قبل تغيير الممر، ألاحظ سحابة كثيفة من الرذاذ تتطاير من عجلات مقطورتي الخلفية. لماذا يهمّ هذا الرذاذ أكثر من غيره لقراري بتغيير الممر؟","options":["يغطي مراياي بالأوساخ، لذا ينبغي أن أخفّف السرعة وأنظفها عند التوقف التالي قبل الاندماج","يشير إلى أن إطاراتي تنزلق على الماء، مما يعني أن عليّ الكبح بحزم فورًا لاستعادة التماسك","يحجب رؤيتي للافتات الطرق العلوية، لذا قد أفوّت المخرج الذي أخطط لأخذه","يمكن أن يخفي مركبة تتبعني عن قرب خلفي، لذا قد لا أراها قبل أن أنتقل"],"explanation":"يمكن للرذاذ المتطاير من المقطورة في المطر أن يخفي مركبة تتبعك عن قرب، لذا قد لا تراها وقد تنتقل فوقها أثناء تغيير الممر."},"171":{"q":"أقود مركبة مركّبة طويلة وأحتاج إلى الانعطاف يمينًا بحدة عند تقاطع ضيق في المدينة. مقارنة بمركبة أقصر، ماذا ينبغي أن أتوقع من مركبتي الأطول وأنا أوجّه عبر هذا المنعطف؟","options":["ستتتبع عجلات المقطورة الخلفية مسارًا داخل مسار عجلاتي الأمامية بكثير، لذا يجب أن أنحرف واسعًا بما يكفي لتتجاوز المقطورة","ستتبع عجلات المقطورة الخلفية المسار نفسه لعجلاتي الأمامية، لذا يمكنني الانعطاف بشكل طبيعي والبقاء قريبًا من الرصيف","ستتأرجح عجلات المقطورة الخلفية بعيدًا خارج عجلاتي الأمامية، لذا ينبغي أن ألتصق بداخل المنعطف للبقاء بعيدًا","تقصّر قاعدة عجلاتي الأطول مسافة توقفي، لذا يمكنني الكبح متأخرًا والمرور عبر المنعطف أسرع"],"explanation":"بسبب انحراف المسار، تتبع العجلات الخلفية للمقطورة مسارًا داخليًا أضيق من العجلات الأمامية، لذا يجب أن تنحرف واسعًا بما يكفي لتتجاوز المقطورة الزاوية."},"172":{"q":"أنقل جرّارًا ومقطورة بطول 70 قدمًا على طريق سريع ثلاثي الممرات بالحد المعلن، وحركة المرور خفيفة. باستثناء حين أحتاج إلى تجاوز مركبة أبطأ أو الاستعداد لمخرج يسار، أي ممر ينبغي أن أبقي مركبتي فيه، ولماذا؟","options":["الممر الأقصى يسارًا، لأن تأرجح مقطورتي الطويل أقل احتمالًا أن يخدش المركبات في المساحة المفتوحة على طول الجزيرة الوسطية","الممر الأيمن، لأن المركبة المركّبة الطويلة تتعامل بشكل أفضل هناك ويتيح لحركة المرور الأسرع أن تمرّ دون الالتفاف حول مركبتي","الممر الأوسط، لأن البقاء نحو المنتصف يبقيني على مسافة متساوية من حركة المرور المندمجة على الجانبين","أي ممر يكون أكثر فراغًا في اللحظة، لأن تغيير الممرات باستمرار يبقيني بعيدًا عن أي تجمّع واحد من السيارات"],"explanation":"على طريق متعدد الممرات، ينبغي للمركبة المركّبة الطويلة أن تلتزم بالممر الأيمن حتى تتمكن حركة المرور الأسرع من المرور دون الالتفاف حول المركبة."},"173":{"q":"تنقل مقطورة محمّلة والطريق أمامك يهبط إلى منحدر طويل وحاد محدّد بلافتة منحدر الهروب. تريد إبقاء المركبة المركّبة تحت السيطرة طوال الطريق نزولًا. أي إجراء ينبغي أن تتخذ قبل أن تبدأ النزول على المنحدر؟","options":["تبني سرعة إضافية على المقترب حتى يحملك الزخم فوق المنخفضات، ثم تكبح بقوة قرب الأسفل","تنقل إلى الوضع المحايد عند القمة حتى لا يقاومك المحرك، ثم توجّه وتكبح لإدارة النزول","تختار سرعة آمنة وتحدد غيارًا منخفضًا قبل المنحدر، حتى يساعدك المحرك على الكبح نزولًا","تبقى في غيار مرتفع وتستخدم صمام يد المقطورة وحده للتحكم بفرامل المقطورة طوال الطريق نزولًا"],"explanation":"اختر سرعة آمنة وغيارًا منخفضًا قبل البدء بالنزول على منحدر حتى يساعد كبح المحرك والضغط على كبح المركبة الثقيلة ويمنع فرامل الخدمة من السخونة الزائدة."},"174":{"q":"أنقل مقطورة صندوقية فارغة عائدًا إلى الساحة على طريق سريع مبتل ذي ممرين عندما تتباطأ حركة المرور أمامي فجأة وأضطر إلى الكبح بقوة. مقارنة بالرحلات المحمّلة التي أقوم بها عادة، ماذا ينبغي أن أتوقع من هذه المركبة الفارغة وكيف ينبغي أن أتعامل مع كبحي؟","options":["بدون وزن حمولة، تضغط المقطورة على إطاراتها بقوة أكبر، لذا يمكنني الكبح متأخرًا والتوقف في مسافة أقصر من المحمّل","تتصرف المقطورة الفارغة تمامًا كالمحمّلة في الكبح، لذا يمكنني استخدام مسافة التتابع المعتادة وضغط الفرامل نفسه","تتماسك المقطورة الخفيفة مع الطريق المبتل بشكل أفضل، لذا فأأمن خطوة هي الكبح بحزم والحفاظ على ضغط ثابت حتى التوقف","يمكن أن تقفل عجلات المقطورة الفارغة وتنزلق بسهولة أكبر، لذا ينبغي أن أكبح بسلاسة ولطف لإبقاء المقطورة تسير مستقيمة"],"explanation":"المقطورة الفارغة لديها وزن قليل على إطاراتها، لذا تقفل العجلات وتنزلق بسهولة؛ اكبح بسلاسة ولطف لإبقاء المقطورة تسير مستقيمة."},"175":{"q":"أثناء فحصي قبل الرحلة، أحرّك العجلة الخامسة إلى الأمام على قضبانها لنقل الوزن بعيدًا عن المحاور الخلفية. قبل أن أعود إلى المقصورة وأنطلق، في أي حالة يجب أن تكون مسامير قفل المنزلق؟","options":["مثبّتة بالكامل ومستقرة في فتحات القضيب، حتى لا تتمكن العجلة الخامسة من التحرك على القضبان","متروكة فضفاضة قليلًا حتى يتمكن المنزلق من التكيّف ذاتيًا مع تحركات الطريق أثناء القيادة","مسحوبة بالكامل، لأن مسمار الملك والفكوك القافلة تثبّت المقطورة بالفعل","مثبّتة نصفيًا، مع بقاء مقبض التحرير مفتوحًا في حال احتاجت الحمولة إلى تحريك آخر"],"explanation":"بعد تحريك العجلة الخامسة، يجب أن تكون مسامير قفل المنزلق مثبّتة بالكامل ومستقرة في فتحات القضيب حتى لا تتمكن من التحرك على قضبانها أثناء القيادة."},"176":{"q":"في محطة الوزن قمت بإزلاق محاور المقطورة (التاندم) إلى الأمام لنقل الوزن بعيداً عن محاور الدفع. وأصبح الميزان الآن يُظهر وزناً قانونياً، لذا أنا مستعد للعودة إلى الطريق السريع. قبل أن أنطلق، ما الذي يجب أن أتأكد منه بشأن مسامير قفل التاندم؟","options":["أنها مسحوبة للخارج وأن مقبض التحرير يبقى في وضع عدم القفل بحيث يمكن للمزلاق أن يستمر في الضبط من تلقاء نفسه","أنها مثبتة ومقفولة بالكامل داخل فتحات السكة بحيث لا يمكن للتاندم أن ينزلق أثناء القيادة","أنها مُشحَّمة ومتروكة غير مشتبكة بحيث يتدحرج المزلاق بحرية إذا احتجت لإعادة ضبط الوزن لاحقاً","أنها مُزالة ومخزّنة في الكابينة لأن نظام الإزلاق الهوائي يثبّت التاندم في مكانه من تلقاء نفسه"],"explanation":"بعد إزلاق التاندم، يجب أن تكون مسامير القفل مثبتة ومقفولة بالكامل داخل فتحات السكة بحيث لا يمكن للتاندم أن ينزلق أثناء القيادة."},"177":{"q":"خلال فحص ما قبل الرحلة في محطة وزن في تكساس، أحتاج إلى إزلاق العجلة الخامسة إلى الأمام لنقل مزيد من الوزن إلى محور التوجيه ومحاور الدفع واجتياز الميزان. وبينما أُدير المجموعة إلى الأمام، أي وضع لمسمار الارتكاز (الكينغبن) يجب أن أعامله كحد قاطع لن أتجاوزه بالإزلاق؟","options":["يجب أن أتوقف بمجرد أن يستقر مسمار الارتكاز تقريباً فوق مركز محاور الدفع، لأن هذا هو المكان الذي يتوازن فيه الوزن","يجب أن أستمر في الإزلاق حتى يصبح مسمار الارتكاز مباشرة فوق محور التوجيه لتحميل مقدمة القاطرة","يجب ألا أُزلِقه أبداً إلى الحد الذي ينتهي فيه مسمار الارتكاز خلف الحافة الخلفية لهيكل القاطرة","يجب أن أُزلِقه حتى يستقر مسمار الارتكاز على ميزاب المقطورة (الأبرون) لأمتن دعم"],"explanation":"لا تُزلِق العجلة الخامسة أبداً إلى الحد الذي ينتهي فيه مسمار الارتكاز خلف الحافة الخلفية لهيكل القاطرة، وإلا فقد الاقتران الدعم الهيكلي للهيكل."},"178":{"q":"أنا على وشك إدخال قاطرتي بالرجوع إلى الخلف تحت مقطورة كانت متوقفة غير مقترنة في ساحة الإنزال. قبل أن أبدأ إجراء الاقتران، أيٌّ مما يلي يُعد الخطوة الأولى الأفضل لمنع تلك المقطورة من التدحرج أو الحركة عليّ أثناء العمل؟","options":["املأ خزانات هواء المقطورة أولاً بحيث تثبّتها مكابح الزنبرك بإحكام في مكانها أثناء الاقتران","ارفع عتاد الهبوط جزئياً بحيث تستوي المقطورة مع العجلة الخامسة قبل أن أرجع تحتها","أنزِل المقطورة قليلاً بحيث يكون مقدّمها أعلى قليلاً من مركز العجلة الخامسة","تأكد من أن المقطورة مُسنَدة بالكوابح ومستعدة بحيث لا يمكنها التدحرج بينما أرجع تحتها"],"explanation":"قبل الاقتران، تأكد من أن المقطورة مُسنَدة بالكوابح ومستعدة بحيث لا يمكنها التدحرج بينما تُدخِل القاطرة تحتها بالرجوع."},"179":{"q":"أقوم باقتران قاطرتي بمقطورة في الساحة. لقد أسندتُ عجلات المقطورة بالكوابح، وضبطتُ المقطورة على الارتفاع الصحيح، وحاذيتُ مسمار الارتكاز مباشرة أمام العجلة الخامسة. وبينما أبدأ بالرجوع بالقاطرة نحو المقطورة، إلى أي مدى يجب أن أرجع قبل أن أتوقف للتحقق من وضعيتي؟","options":["حتى تلامس العجلة الخامسة المقطورة بالكاد","حتى ترفع العجلة الخامسة المقطورة قليلاً عن دعاماتها","حتى أسمع فكّي القفل ينطبقان حول مسمار الارتكاز","حتى يستقر مسمار الارتكاز بإحكام مقابل الجزء الخلفي من العجلة الخامسة"],"explanation":"ارجع بالقاطرة ببطء حتى تلامس العجلة الخامسة المقطورة بالكاد، ثم توقف لإعادة فحص المحاذاة وارتفاع المقطورة قبل الرجوع بالكامل تحتها."},"180":{"q":"لقد أرجعتُ قاطرتي تحت المقطورة وأستطيع أن أرى أن فكّي القفل يبدوان مغلقين حول مسمار الارتكاز. قبل أن أنزل لتوصيل خطوط الهواء والضفيرة (البِغتيل) وإنهاء الاقتران، أريد أن أتأكد من أن العجلة الخامسة مقفولة فعلاً على مسمار الارتكاز. مع بقاء مكابح المقطورة مُفعَّلة، ماذا يجب أن أفعل لاختبار القفل؟","options":["اترك القاطرة في الوضع المحايد، وانزل، وحاول هز المقطورة من جانب إلى آخر يدوياً لتحسّ بأي حركة","ضع القاطرة في الترس المنخفض واسحب للأمام بلطف ضد مكابح المقطورة المقفولة للتأكد من أن الاقتران ثابت","حرّر مكابح المقطورة، ثم تراجع برفق بضع بوصات لدفع مسمار الارتكاز أعمق داخل فكّي القفل","ارفع عتاد الهبوط بالكامل أولاً، ثم اسحب للأمام بسرعة عادية لتحسّ ما إذا كانت المقطورة تتبع"],"explanation":"قم باختبار الشد بوضع القاطرة في الترس المنخفض والسحب للأمام بلطف ضد مكابح المقطورة المقفولة للتأكد من أن الاقتران ثابت."},"181":{"q":"أقوم باقتران قاطرتي بمقطورة محمّلة في الساحة. لقد رجعتُ تحت مسمار الارتكاز، ووصّلتُ خطوط الهواء والضفيرة الكهربائية، وأنا متلهف للانطلاق. قبل أن أتسلق لرفع عتاد الهبوط بالكامل، أي خطوة يجب أن أكون قد أكملتها أولاً؟","options":["يجب أن أحرّر مكابح المقطورة بحيث تتحرك المركبة بحرية لحظة رفع العتاد","يجب أن أشحن خزانات هواء المقطورة بالكامل وأتأكد من أن تحذير انخفاض الهواء على لوحة القيادة قد انطفأ","يجب أن أتحقق من أن الاقتران آمن، بما في ذلك اختبار شد في الترس المنخفض مع مكابح المقطورة مقفولة","يجب أن أُزلِق تاندم المقطورة إلى الأمام بحيث تستقر الحمولة أقرب إلى مسمار الارتكاز"],"explanation":"ارفع عتاد الهبوط فقط بعد التحقق من أن الاقتران آمن، بما في ذلك اختبار شد في الترس المنخفض مع مكابح المقطورة مقفولة."},"182":{"q":"لقد أنزلتُ للتو مقطورة محمّلة في الساحة وفصلتُ قاطرتي. مع كون القاطرة مفصولة تماماً وقد ابتعدتُ بها، ما الذي يمنع المقطورة المتوقفة من التدحرج من تلقاء نفسها؟","options":["لا شيء على المقطورة يثبّتها؛ فقط مكابح القاطرة يمكنها إيقاف المقطورة من الحركة، لذا يجب أن أترك القاطرة مقترنة","صمّام اليد للمقطورة (عمود الترولي/جونسون) يبقي مكابح المقطورة مُفعَّلة بينما تكون متوقفة","الكوابح وحدها هي نظام الكبح الوحيد للمقطورة، لأن المقطورات ليس لها مكابح هوائية خاصة بها","المقطورة لها مكابح ركن (زنبرك) خاصة بها تثبّتها في مكانها بشكل مستقل عن القاطرة"],"explanation":"المقطورة لها مكابح ركن (زنبرك) خاصة بها تُفعَّل ميكانيكياً عندما ينفد الهواء، فتثبّتها في مكانها دون حاجة لقاطرة أو إمداد هواء."},"183":{"q":"خلال فحص مكابح الهواء ما قبل الرحلة على قاطرتي ومقطورتي، رفعتُ ضغط الهواء حتى نقطة قطع المنظّم، وأطفأتُ المحرك، وأسندتُ العجلات بالكوابح، وحرّرتُ مكابح الركن. ثم أُفعِّل دواسة المكبح القدمية بالكامل وأُبقيها وأراقب المؤشر لمدة دقيقة واحدة. أيٌّ من قراءات فقدان الهواء المُفعَّل التالية يعني أن مركبتي المركّبة ضمن الحد المسموح به وليست فوق الحد الأقصى للتسرب؟","options":["ينخفض الضغط 3 psi خلال الدقيقة الواحدة، لأن التسرب المُفعَّل لمركبة مركّبة يجب أن يبقى تحت 4 psi في الدقيقة","ينخفض الضغط 6 psi خلال الدقيقة الواحدة، لأن التسرب المُفعَّل لمركبة مركّبة مسموح به حتى 10 psi في الدقيقة","ينخفض الضغط 4 psi بالضبط خلال الدقيقة الواحدة، لأن ذلك هو معدل التسرب المطلوب لمركبة مركّبة","يثبت الضغط بفقدان 0 psi، لأن أي انخفاض ملموس على الإطلاق يُفشل المركبة المركّبة"],"explanation":"بالنسبة للمركبة المركّبة، يجب أن يبقى تسرب الهواء المُفعَّل (المكابح مُفعَّلة) تحت 4 psi في الدقيقة، لذا فإن انخفاض 3 psi ضمن الحد المسموح به."},"184":{"q":"خلال فحص ما قبل الرحلة على قاطرة ومقطورة، أرفع ضغط الهواء حتى نقطة قطع المنظّم، وأُطفئ المحرك، وأُحرّر مكبح الخدمة، وأوقّت انخفاض الضغط على المؤشرات المزدوجة بينما تكون المركبة ساكنة. أي معدل تسرب يخبرني أن فقدان الهواء الساكن ضمن الحد القانوني لهذه المركبة المركّبة؟","options":["10 psi أو أقل في دقيقة واحدة","3 psi أو أقل في دقيقة واحدة","30 psi أو أقل في دقيقة واحدة","60 psi أو أقل في دقيقة واحدة"],"explanation":"بالنسبة للمركبة المركّبة، يجب أن يبقى تسرب الهواء الساكن (المحرك مُطفأ، المكابح محرَّرة) عند 3 psi أو أقل في الدقيقة."},"185":{"q":"أنا أقود مقطورة محمّلة على طريق سريع بين الولايات مبلل عندما تتوقف حركة المرور أمامي فجأة، فأضغط دواسة المكبح بقوة وأشعر بنبض نظام منع انغلاق المكابح (ABS). في هذا التوقف الطارئ، ما الذي يفعله نظام ABS لي فعلاً؟","options":["يقلّص مسافة توقفي إلى ما دون ما كانت ستكون عليه بدون ABS بكثير","يقفل جميع العجلات بالتساوي بحيث تتوقف المركبة في خط مستقيم","يمنع العجلات من الانغلاق بحيث ما زال بإمكاني التوجيه حول الخطر","يتيح لي الكبح بقوة أكبر بكثير وحمل وزن محمّل أكبر في هذه الرحلة"],"explanation":"يمنع نظام ABS العجلات من الانغلاق أثناء الكبح الشديد بحيث تحتفظ بقوة الجر ويبقى بإمكانك التوجيه حول الخطر."},"186":{"q":"لقد شغّلتُ للتو قاطرتي ومقطورتي لرحلة الصباح. تومض جميع أضواء لوحة القيادة عند بدء التشغيل، لكن مصباح عطل نظام ABS الأصفر للمقطورة يبقى مضاءً ولا ينطفئ بعد دوران المحرك. بناءً على ما يخبرني به هذا المصباح، ما المعنى الأرجح؟","options":["مكابح الزنبرك للمقطورة قد تفعّلت تلقائياً وتثبّت المركبة في مكانها","نظام ABS للمقطورة قد أنهى للتو فحصاً ذاتياً ناجحاً وهو جاهز تماماً للاستخدام","نظام ABS للمقطورة يقصّر مسافة توقفي بحيث يمكنني الكبح متأخراً قبل المنعطفات","نظام ABS للمقطورة قد لا يعمل ويجب فحص النظام قبل القيادة"],"explanation":"يجب أن ينطفئ مصباح ABS للمقطورة بمجرد دوران المحرك؛ فإذا بقي مضاءً، فقد يكون نظام ABS للمقطورة معطلاً ويجب فحصه قبل القيادة."},"187":{"q":"أنا أفصل مقطورتي في ساحة حصوية بعد المطر، وأحد المواضع التي قد أُنزل فيها عتاد الهبوط هو بقعة من التراب الرطب الموحل. قبل أن أُدير الأرجل للأسفل، ماذا يجب أن أفعل بشأن تلك البقعة للحفاظ على المقطورة المتوقفة مستقرة وآمنة؟","options":["أعد التموضع بحيث ينزل عتاد الهبوط على أرض صلبة وثابتة بدلاً من البقعة الطرية الموحلة","أنزل عتاد الهبوط على البقعة الموحلة لكن أدِر الأرجل للأسفل أكثر للتعويض","أنزل عتاد الهبوط على البقعة الطرية لكن اترك وزن المقطورة بالكامل على العجلة الخامسة","أنزل عتاد الهبوط على الوحل، ثم أسنِد عجلات القاطرة بالكوابح قبل الانطلاق"],"explanation":"لا تُنزِل عتاد الهبوط أبداً على أرض طرية؛ أعد التموضع بحيث تستقر الأرجل على أرض صلبة وثابتة قادرة على تحمّل وزن المقطورة."},"188":{"q":"لقد انتهيتُ للتو من فصل مقطورتي في ساحة حصوية. سحبتُ خطوط الهواء عن مقابض المقطورة (الغلاد هاندز)، والآن أُمسك بخطّي القاطرة المرتخيين (الخدمة والطوارئ) في يدي قبل أن أُبعد القاطرة. لحماية النظام قبل أن أنطلق، ماذا يجب أن أفعل بمقابض الهواء هذه؟","options":["اعبر خط الخدمة وخط الطوارئ معاً بحيث تُحكِم النهايتان المفتوحتان إغلاق بعضهما","علّقهما على القارنات الوهمية أو غطّهما بحيث يبقى الأوساخ والماء خارج الخطوط","اتركهما يستقران على ممشى القاطرة بحيث يمكن للسائق التالي إعادة توصيلهما بسرعة","اتركهما معلّقين بحرية بحيث يمكن لأي هواء محتبس أن ينفد قبل أن أتحرك"],"explanation":"بعد الفصل، علّق مقابض الهواء على القارنات الوهمية أو غطّها لإبقاء الأوساخ والماء خارج خطوط مكابح الهواء."},"189":{"q":"لقد أنزلتُ للتو مقطورتي وأنا على وشك العودة بالقاطرة وحدها (بوبتيل) إلى الساحة، تاركاً مقبضي خطوط هواء القاطرة معلّقين ومفتوحين. يخبرني مشرف الورشة بتركيب القارنات الوهمية (المسدودة النهاية) عليهما قبل أن أنطلق. لماذا يريدني أن أفعل ذلك؟","options":["لإبقاء ضغط الهواء المتبقي محتبساً في خطّي الخدمة والطوارئ بحيث تبقى مكابح المقطورة مقفولة","لتفريغ أي هواء متبقٍ من الخطوط بحيث لا يمكن لمكابح الزنبرك أن تتفعّل بالخطأ أثناء القيادة","لإبقاء النهايات المفتوحة لخطوط الهواء نظيفة ومُحكَمة بحيث لا يدخلها الأوساخ والماء","لإبقاء أختام مطاط مقابض الهواء دافئة ومرنة بحيث لا تتشقق في الطقس البارد"],"explanation":"يغطي المقبض الوهمي النهاية المفتوحة لخط هواء مفصول لإبقاء الأوساخ والغبار والماء خارج نظام مكابح الهواء."},"190":{"q":"لقد ترقّيتُ للتو من قيادة شاحنة مستقيمة مفردة إلى سحب مركبة مركّبة من قاطرة ومقطورة محمّلة على طرق تكساس السريعة. مقارنة بالشاحنة المفردة التي اعتدتُ قيادتها، أيٌّ مما يلي يصف على أفضل وجه كيف ستتصرف هذه المركبة المركّبة، وما الذي يجب أن أتكيّف معه؟","options":["إنها أقصر وأكثر تماسكاً، لذا يمكنني تقصير مسافة المتابعة والتوقف في مساحة أقل","إنها بنفس الوزن تقريباً لكن أسهل في الرجوع، لذا ستنتقل عاداتي القديمة في التوقف مباشرة","إنها أخف عموماً لأن الحمولة موزّعة على محاور أكثر، لذا تتوقف أسرع من الشاحنة المستقيمة","إنها أطول وأثقل، لذا تحتاج إلى مسافة متابعة أكبر ومساحة أكبر للتوقف من الشاحنة المستقيمة"],"explanation":"المركبة المركّبة أطول وأثقل من الشاحنة المستقيمة، لذا تحتاج إلى مسافة متابعة أكبر ومساحة أكبر للتوقف."},"191":{"q":"خلال فحص ما قبل الرحلة، أنا على وشك الرجوع بقاطرتي تحت مقطورة إنزال وربط في رصيف تحميل مزدحم. ألاحظ أن هيكل المقطورة قرب منطقة مسمار الارتكاز يُظهر شرخاً جديداً وأن لوحة العجلة الخامسة العلوية تبدو منثنية. المرسِل يضغط عليّ لأخذ هذه الحمولة لأنها متأخرة بالفعل. أي إجراء هو الصحيح؟","options":["ارفض الاقتران بهذه المقطورة، لأنه يجب ألا تقترن أبداً بمقطورة غير آمنة أو متضررة","اقترن على أي حال لكن أجرِ اختبار شد إضافياً، لأن اختبار الشد الناجح يثبت أن المقطورة المتضررة آمنة للسحب","اقترن وقُد، طالما تُبقي سرعتك منخفضة وتضيف مسافة متابعة إضافية للتعويض عن الضرر","اقترن بها إذا كان فكّا القفل لا يزالان ينطبقان بالكامل حول جذع مسمار الارتكاز، لأن الشرخ في الهيكل فقط"],"explanation":"لا تقترن أبداً بمقطورة غير آمنة أو متضررة؛ العيوب الهيكلية مثل مسمار ارتكاز متشقق أو لوحة عجلة خامسة منثنية تستوجب رفض الاقتران."},"192":{"q":"لقد انتهيتُ للتو من اقتران قاطرتي بمقطورة محمّلة ورفعتُ ضغط النظام بالكامل، لكن عندما أعود إلى الداخل وأحاول السحب للأمام، لا تتحرك المركبة قيد أنملة—تبقى مكابح المقطورة مقفولة وترفض التحرر. أيٌّ مما يلي هو السبب الأرجح؟","options":["كانت المقطورة مزوّدة بأحذية مكابح جديدة تحتاج إلى الاستقرار قبل أن تتحرر","لا يصل هواء إلى مكابح المقطورة، لذا تبقى مكابح الزنبرك مُفعَّلة","ضغط هواء زائد في النظام يُجبر حجرات مكابح المقطورة على الإمساك","خط الهواء إلى المقطورة نظيف وخالٍ، مما يتيح للمكابح أن تتحرر بالكامل"],"explanation":"تُبقي مكابح الزنبرك (الطوارئ) للمقطورة مُحرَّرةً بواسطة ضغط الهواء، لذا عندما لا يصلها هواء تبقى مُفعَّلة ميكانيكياً."},"193":{"q":"إذا انفصل إمداد هواء المقطورة فجأة أثناء القيادة، فإن مكابح المقطورة سوف:","options":["تتحرر بالكامل","تُفعَّل","تتسارع","لا تفعل شيئاً"],"explanation":"تُفعَّل مكابح المقطورة إذا انفصل إمداد الهواء فجأة."},"194":{"q":"لقد انتهيتُ من اقتران قاطرتي ومقطورتي، وأكملتُ اختبار شد ناجحاً، ورفعتُ عتاد الهبوط، ووصّلتُ كلا خطّي الهواء والضفيرة الكهربائية. تُظهر مؤشرات الهواء لديّ ضغطاً كاملاً وأنا مستعد للانطلاق من الساحة. فيما يتعلق بمكابح المقطورة، في أي حالة يجب أن تكون قبل أن أحرّك المركبة فعلاً؟","options":["مقفولة، بنفس الطريقة التي كانت عليها أثناء اختبار الشد، بحيث لا يمكن للمقطورة أن تنجرف","مُفعَّلة عبر صمّام اليد للمقطورة (الترولي) ومُبقاة كذلك حتى أصل إلى سرعة الطريق السريع","محرَّرة (مشحونة بالهواء بالكامل) بحيث تكون مكابح الزنبرك مُطفأة ويمكن للعجلات أن تتدحرج بحرية","مفصولة عند مقبض هواء الطوارئ (الإمداد) بحيث لا تجرّ أثناء التسارع"],"explanation":"بمجرد شحن خزانات هواء المقطورة بالكامل عبر خط الإمداد، تتحرر مكابح الزنبرك ويمكن للعجلات أن تتدحرج بحرية."},"195":{"q":"خلال فحص ما قبل الرحلة على قاطرة ومقطورة، ألاحظ أن الضفيرة الكهربائية المتجهة إلى المقطورة مهترئة والموصّل متشقق. إذا فشل هذا السلك تماماً بينما أقود ليلاً على طريق سريع في تكساس، أيٌّ مما يلي من الأرجح أن أفقده؟","options":["إمداد الهواء الذي يُبقي مكابح الزنبرك للمقطورة محرَّرة","الضغط الهيدروليكي الذي يشغّل مكابح الخدمة على المقطورة","القفل بين فكّي العجلة الخامسة ومسمار ارتكاز المقطورة","أضواء المكابح وإشارات الانعطاف للمقطورة التي تحذّر السائقين خلفي"],"explanation":"تُغذّي الضفيرة الكهربائية إضاءة المقطورة، لذا فإن فشل السلك يُعطّل أضواء المكابح وإشارات الانعطاف وأضواء التحديد."},"196":{"q":"لقد حصلتُ للتو على رخصة الفئة A وأتدرّب على الرجوع بقاطرتي ومقطورتي في موقف سيارات. ألاحظ أنه أصعب بكثير الرجوع في خط مستقيم من الشاحنة المستقيمة التي تدرّبتُ عليها، وأنها تستمر في الانحراف عن الخط. أي خاصية في مركبتي المركّبة هي السبب الرئيسي في كون الرجوع بهذه الصعوبة؟","options":["المركبة مفصّلة عند الاقتران، لذا تدور حول محورها في المنتصف وتتأرجح المقطورة في الاتجاه المعاكس لتوجيهي","المركبات المركّبة ليس لها مكابح خدمة على المقطورة، لذا لا يمكنني التحكم في سرعتها أثناء الرجوع","العجلات الخلفية للمقطورة تتبع المسار نفسه تماماً للقاطرة، لذا تسير في خط مستقيم تماماً","تضيف المقطورة وزناً يكاد لا يُذكر، لذا تنزلق بحرية ويستحيل توجيهها في الرجوع"],"explanation":"تدور المركبة المركّبة حول محورها عند الاقتران، لذا تتأرجح المقطورة عكس التوجيه وتتضخم الأخطاء الصغيرة عند الرجوع."},"197":{"q":"أنا على وشك الرجوع بقاطرتي تحت مقطورة في ساحة عميل، ولي حرية اختيار المكان الذي أفعل فيه ذلك. عدة مواضع متاحة. أي سطح يجب أن أختاره للاقتران عليه بحيث تبقى المركبة مستقرة ويستقر مسمار الارتكاز بشكل صحيح؟","options":["موضع على منحدر هابط خفيف، بحيث تساعد الجاذبية على تدحرج القاطرة تحت المقطورة","موضع صلب ومستوٍ، بحيث لا تنزلق أو تستقر أي من المركبتين أثناء الرجوع تحتها","بقعة من التراب الطري، لأنها تخفّف الإطارات وتمنع المقطورة من الارتداد","منطقة حصى مفكّك، لأن الحصى يتيح للمقطورة أن تنزلق إلى الموضع الصحيح"],"explanation":"اقترن على أرض صلبة ومستوية بحيث لا تغوص أي من المركبتين أو تتدحرج وتبقى العجلة الخامسة ومسمار الارتكاز على الارتفاع الصحيح ليُغلق الفكّان."},"198":{"q":"لقد رجعتُ للتو بقاطرتي تحت المقطورة، وفكّا قفل العجلة الخامسة يبدوان مغلقين حول مسمار الارتكاز، ومزلاج الأمان يبدو مشتبكاً. قبل أن أثق بالوصلة وأنطلق إلى الطريق السريع، ماذا يجب أن أفعل لأتأكد فعلياً من أن الاقتران مقفول فعلاً؟","options":["فعّل صمّام اليد للمقطورة فقط (عمود جونسون) وراقب مؤشر مكابح المقطورة لانخفاض ضغط يُثبت أن الفكّين يمسكان بمسمار الارتكاز","ارفع عتاد الهبوط بالكامل، ثم هزّ عجلة القيادة يميناً ويساراً لتحسّ ما إذا كانت المقطورة تقاوم الحركة عند العجلة الخامسة","اقفل مكابح المقطورة واسحب للأمام بلطف في الترس المنخفض (اختبار شد)؛ إذا لم تستطع القاطرة الانسحاب من تحت المقطورة، فالاقتران مقفول","حرّر جميع المكابح ودع المركبة تتدحرج للأمام بضع أقدام على أرض مستوية لترى ما إذا كانت المقطورة تتبع القاطرة بسلاسة"],"explanation":"يعني اختبار الشد قفل مكابح المقطورة والسحب للأمام بلطف في الترس المنخفض؛ فإذا لم تستطع القاطرة الانسحاب، فالفكّان مقفولان على مسمار الارتكاز."},"199":{"q":"لقد رجعتُ للتو بقاطرتي تحت المقطورة وأنا أقوم بفحص اقتراني قبل اختبار الشد. أريد أن أركّز أولاً على الفحص الوحيد الأكثر أهمية لإبقاء المقطورة متصلة بالقاطرة. من بين الأشياء التي يمكنني التحقق منها، أيٌّ منها هو فحص الاقتران الأكثر أهمية؟","options":["أن الضفيرة الكهربائية للمقطورة موصّلة بحيث تعمل جميع أضواء المقطورة","أن عتاد الهبوط مرفوع بالكامل وأن مقبض الإدارة مُثبَّت","أن خطّي هواء الخدمة والطوارئ موصّلان وغير متقاطعين","أن فكّي القفل مغلقان بالكامل حول جذع مسمار الارتكاز"],"explanation":"يجب أن ينغلق فكّا القفل بالكامل حول جذع مسمار الارتكاز، لأن ذلك هو ما يثبّت المقطورة بالقاطرة فعلياً."}},"hazmat":{"0":{"q":"لقد حصلتُ للتو على تصريح H ويسألني سائق جديد لماذا توجد أصلاً كل قواعد اللصاقات (البطاقات التحذيرية) وأوراق الشحن والتعبئة. أيٌّ مما يلي يصف على أفضل وجه الغرض الرئيسي وراء لوائح المواد الخطرة؟","options":["احتواء المادة بحيث لا يمكنها التسرب، وإيصال معلومات الخطر بحيث يمكن للآخرين البقاء بعيدين والاستجابة بأمان","ضمان نوافذ تسليم أسرع بمنح الحمولات الموسومة بالبطاقات أولوية الوصول إلى مسارات وطرق الطريق السريع","توثيق كل شحنة بحيث يستطيع الناقل أن يفوتر العميل رسماً إضافياً صحيحاً لمناولة المواد الخطرة","تقليل تكاليف وقود الناقل بتوجيه الحمولات الخطرة الثقيلة إلى أقصر الطرق المتاحة"],"explanation":"توجد قواعد المواد الخطرة لاحتواء المادة بحيث لا يمكنها التسرب ولإيصال معلومات الخطر بحيث يمكن للآخرين البقاء بعيدين والاستجابة بأمان."},"1":{"q":"تم توظيفي للتو لتشغيل خط نقل لحمولة تحمل لافتات من مادة أكّالة (مسببة للتآكل)، وأنا أحمل بالفعل رخصة قيادة تجارية من الفئة (أ) مع تصديق على نقل الصهاريج. قبل أن أتمكن قانونياً من القيام بهذه الرحلة، أيٌّ مما يلي يجب عليّ فعله؟","options":["لا شيء إضافي — رخصتي من الفئة (أ) مع تصديق الصهاريج تغطي بالفعل أي حمولة تحمل لافتات أنقلها","الحصول على تصديق المواد الخطرة (H)، الذي يتطلب اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA) وأخذ البصمات","إضافة تصديق المقطورات المزدوجة/الثلاثية، لأن الحمولات التي تحمل لافتات يجب توزيعها على عدة مقطورات","إضافة تصديق نقل الركاب، لأن الحمولات التي تحمل لافتات تُنظَّم بنفس طريقة نقل الركاب"],"explanation":"نقل أي كمية تتطلب لافتات من المواد الخطرة يستلزم تصديق المواد الخطرة (H)، الذي يتطلب تقييم تهديد أمني من إدارة أمن النقل (TSA) وأخذ البصمات."},"2":{"q":"أحمل بالفعل رخصة قيادة تجارية تكساس من الفئة (أ) وشهادة طبية سارية من وزارة النقل (DOT). يريد صاحب عملي الجديد أن أبدأ بسحب حمولات تتطلب لافتات من المواد الأكّالة، لذا أحتاج إلى إضافة تصديق (H). عندما أسأل موظف دائرة السلامة العامة (DPS) عن الخطوة الإضافية التي يتطلبها هذا التصديق ولم تكن رخصتي الحالية تتطلبها، أيٌّ مما يلي على الأرجح أن تخبرني به؟","options":["لا حاجة لأي شيء إضافي؛ بمجرد أن تحمل رخصة من الفئة (أ) مع بطاقة طبية سارية من وزارة النقل، يُطبع تصديق (H) ببساطة على رخصتك دون أي متطلبات إضافية","يجب أن تجتاز فحصاً بدنياً ثانياً أكثر تفصيلاً من وزارة النقل وتقدّم شهادة محدّثة من الفاحص الطبي قبل إصدار التصديق","يجب أن تجتاز تقييم تهديد أمني من إدارة أمن النقل (TSA)، يشمل فحص السوابق وأخذ البصمات، قبل إصدار التصديق","ما عليك سوى إعادة إجراء واجتياز فحص النظر القياسي للرخصة التجارية للتأكد من أنك ما زلت قادراً على قراءة اللافتات من مسافة بعيدة"],"explanation":"يتطلب تصديق المواد الخطرة اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA)، يشمل فحص السوابق وأخذ البصمات، قبل إصداره."},"3":{"q":"تم توظيفي لنقل حمولة من مادة أكّالة وأنا أراجع الأوراق على الرصيف قبل المغادرة. لاحظت أن فئة الخطر والاسم الصحيح للشحنة ورقم التعريف الأممي (UN) مُدخَلة بالفعل في أوراق الشحن، لكنني أريد التأكد من أن الجهة الصحيحة هي من تولّت ذلك. بموجب قواعد المواد الخطرة، من كانت مهمته تحديد المادة على أنها خطرة وإعداد أوراق الشحن تلك في المقام الأول؟","options":["شركة النقل، لأنها تملك الرحلة وهي المسؤولة عن نقل الحمولة والإبلاغ عن أي حادث","السائق، لأنني أنا من يجب أن يبقي الأوراق في متناول يده ويرفض الحمولة إذا بدا أي شيء خاطئاً","المستلِم، لأن الشركة التي تقبل التسليم تؤكد المحتويات وتوقّع على المادة الخطرة","الشاحن، لأن الشاحن يصنّف المادة ويسمّيها ويعبّئها ويضع عليها الملصقات ويعدّ أوراق الشحن"],"explanation":"الشاحن هو من يصنّف المادة الخطرة ويسمّيها ويعبّئها ويضع عليها الملصقات ويعدّ أوراق الشحن قبل وصول الحمولة إلى السائق."},"4":{"q":"أنقل حمولة تحمل لافتات من المواد الأكّالة عبر تكساس وقد اندمجت للتو في الطريق السريع بين الولايات. للالتزام بقواعد أوراق شحن المواد الخطرة أثناء القيادة، أين يجب أن تكون أوراق الشحن الآن؟","options":["في متناول يدي مع ربط حزام الأمان، أو في جيب على باب السائق، وفوق أوراقي الأخرى","مؤمَّنة في مقصورة النوم بحيث لا تتمكن الرياح من نافذة مفتوحة من تبعثرها","محفوظة في صندوق المستندات المثبت على الجانب الخارجي للمقطورة قرب اللافتات","مدسوسة تحت الشحنة في المقطورة لتبقى مع البضاعة الفعلية"],"explanation":"أثناء حركة المركبة، يجب أن تكون أوراق شحن المواد الخطرة في متناول يد السائق مع ربط حزام الأمان، أو في جيب باب السائق، وفوق الأوراق الأخرى."},"5":{"q":"أنا سائق جديد أحمّل مقطورة بضائع مختلطة تتضمن صنفاً واحداً من المواد الخطرة إلى جانب عدة سلع غير خاضعة للتنظيم. عند مراجعتي لورقة الشحن المجمّعة قبل مغادرة الرصيف، كيف يجب أن تُحدَّد المادة الخطرة في تلك الوثيقة لتكون الأوراق قانونية؟","options":["تُدخَل أخيراً في الصفحة لتبقى منفصلة عن أسطر البضائع العادية","تُدخَل أولاً، أو تُميَّز بلون، أو تُعلَّم بعلامة 'X' في عمود المواد الخطرة (HM)","تُكتَب فقط في صفحة خلفية منفصلة مدبَّسة خلف قائمة البضائع","تُترَك بخط عادي لأن اللافتات على المقطورة تشير بالفعل إلى الخطر"],"explanation":"في ورقة شحن مختلطة، يجب جعل مدخلة المادة الخطرة مميزة بإدخالها أولاً، أو تمييزها بلون، أو وضع علامة 'X' في عمود المواد الخطرة (HM)."},"6":{"q":"أنقل حمولة من الجدول 2 من المواد الأكّالة، وقد ثبّتُّ للتو اللافتات الأربع ذات الشكل المعيّن على جميع جوانب مقطورتي قبل الخروج من المحطة. يسألني سائق جديد لماذا تهمّ تلك المعيّنات إلى درجة أنني أرفض الانطلاق بدونها. أي تفسير يبيّن بشكل صحيح الغرض الأساسي الذي تخدمه تلك اللافتات؟","options":["إنها تشهد بأن الشاحن صنّف وعبّأ الحمولة بشكل صحيح، فلا أحتاج إلى فحص الشحنة بنفسي","إنها تثبت أنني أحمل تصديق (H) سارياً واجتزت فحص السوابق من إدارة أمن النقل المطلوب لنقل هذه الشحنة","إنها تحذّر كل من حول المركبة من الخطر الذي تشكّله البضاعة حتى يتمكن المستجيبون والجمهور من التصرف بأمان","إنها تسجّل الوزن الإجمالي للمادة الخاضعة للتنظيم حتى يتمكن موظفو الميزان من التأكد من أنني تحت 1,001 رطل"],"explanation":"تحذّر اللافتات كل من حول المركبة من الخطر الذي تشكّله البضاعة حتى يتمكن المستجيبون والجمهور من التصرف بأمان."},"7":{"q":"أنقل حمولة تحمل لافتات من المواد الأكّالة، ويخبرني مشرف الساحة أن زميلاً قد ثبّت بالفعل اللافتات المطلوبة على جانبي المقطورة وعلى مؤخرتها. قبل خروجي من البوابة، أي عبارة تخبرني بشكل صحيح بما يجب عليّ فعله بعد لأكون ملتزماً قانونياً بوضع اللافتات؟","options":["لا حاجة لشيء آخر؛ مع تغطية الجانبين والمؤخرة، فإن ثلاث لافتات تستوفي قاعدة وضع اللافتات لحمولة أكّالة.","أضف لافتة إلى سقف المقطورة لتكون مرئية من الأعلى، لكن المقدمة غير مطلوبة لأن المقصورة تحجب الرؤية.","انقل اللافتة الخلفية إلى المصد الأمامي، لأن المقدمة والجانبين هي المواضع الوحيدة التي يفحصها الموظف فعلاً.","أضف لافتة إلى مقدمة المركبة أيضاً، بحيث تكون الحمولة محمَّلة بلافتات على المقدمة والمؤخرة والجانبين."],"explanation":"يجب عرض اللافتات على جميع جوانب المركبة الأربعة — المقدمة والمؤخرة والجانبين — وكل منها مقروء من الاتجاه الذي يواجهه."},"8":{"q":"أنقل حمولة تحمل لافتات من المواد الأكّالة عندما يبدأ أحد براميلي بالتسرب على كتف الطريق. لقد حذّرتُ المارة واتصلتُ بالمستجيبين، لكن المرسِل يخبرني أن أقرأ على رجال الإطفاء الرقم المرجعي من الوثيقة التي تحدد كيفية التعامل مع تسرب هذه المادة بالذات. أي بند في مقصورتي يُفترض أن أستخدمه؟","options":["دليل الاستجابة للطوارئ (ERG)، الذي يتيح للمستجيبين مطابقة المادة مع خطرها وإجراءات الحماية","أوراق الشحن، لأن الاسم الصحيح للشحنة ورقم الأمم المتحدة/أمريكا الشمالية (UN/NA) مدرجان بالفعل فيها للحمولة","دليل مالك المركبة، الذي يغطي أنظمة الشاحنة وإجراءات الطوارئ الخاصة بالشركة المصنّعة","بوليصة الشحن، لأنها توثّق البضاعة وتفاصيل جهة الاتصال للإبلاغ عن الحوادث لدى شركة النقل"],"explanation":"يجب على كل سائق مواد خطرة حمل دليل الاستجابة للطوارئ (ERG)، الذي يتيح للمستجيبين مطابقة المادة مع خطرها وإجراءات الحماية."},"9":{"q":"أنا على وشك مغادرة المحطة وأنا أنقل حمولة تحمل لافتات من سائل قابل للاشتعال من الفئة 3. يضغط عليّ المرسِل للانطلاق لأنني متأخر عن الجدول. لأقوم بعملي بأمان وقانونية قبل الانطلاق، أيٌّ مما يلي يجب أن أفعله؟","options":["أنزع اللافتات عن المقطورة حتى لا ألفت انتباه السائقين الآخرين على الطريق السريع","أفحص المركبة والإطارات وتثبيت الحمولة بعناية قبل أن أبدأ الرحلة","أتخطى فحص ما قبل الرحلة هذه المرة فقط لأعوّض الوقت الذي أضعته بالانتظار على الرصيف","أفصل فرامل المقطورة حتى تسير الوحدة بسهولة أكبر وأستهلك وقوداً أقل في الرحلة"],"explanation":"يتطلب نقل المواد الخطرة فحص المركبة والإطارات وتثبيت الحمولة بعناية قبل بدء الرحلة، وضغط الجدول لا يبرر أبداً تخطي ذلك."},"10":{"q":"أثناء قيادة حمولة تحمل لافتات، يجب فحص الإطارات:","options":["مرة واحدة فقط في البداية","في البداية وعند كل توقف","أبداً طوال الرحلة كلها","مرة واحدة في الأسبوع تكفي"],"explanation":"افحص الإطارات قبل الرحلة وفي كل مرة تتوقف فيها؛ وأزِل أي إطار متسرب أو فارغ من الهواء."},"11":{"q":"أثناء فحص إطارات إلزامي في أثناء الطريق لحمولة المواد الخطرة التي تحمل لافتات، وجدتُ أن أحد إطارات المقطورة شديد السخونة بشكل خطير. وفقاً لقواعد المواد الخطرة في تكساس، ماذا يجب أن أفعل قبل أن أتابع؟","options":["أصبّ الماء على الإطار لتبريده، ثم أتابع القيادة إلى محطة الخدمة التالية لفحصه","أضيف هواءً لاستعادة الضغط الصحيح، ثم أقود بحذر حتى يبرد الإطار من تلقاء نفسه","أزيل الإطار شديد السخونة وأضعه على مسافة آمنة من المركبة، ولا أقود حتى يُصلَح","أخفّض سرعتي وأتابع القيادة حتى يبرّد تدفّق الهواء الإطار قبل الفحص الإلزامي التالي"],"explanation":"الإطار شديد السخونة في حمولة تحمل لافتات يشكّل خطر حريق وانفجار، لذا أزِله وضعه بعيداً عن المركبة، ولا تقُد حتى يُصلَح."},"12":{"q":"أحمل لافتات لحمولة من المواد المؤكسِدة وتوقّفتُ في منطقة استراحة لأخذ استراحتي. يريد صديق في شاحنة أخرى أن يأتي ويدخّن سيجارة معي. لأبقى ملتزماً قانونياً، كم يجب أن نبتعد كلانا عن مقطورتي أثناء التدخين؟","options":["على الأقل 5 أقدام، نفس الحاجز المطلوب عند الركن خارج الطريق المسلوك","على الأقل 10 أقدام، بعيداً بما يكفي لئلا يصل أي لهب إلى المقطورة","على الأقل 100 قدم، نفس الحاجز المستخدم للمتفجرات قرب مبنى","على الأقل 25 قدماً من المركبة، لأنها تحمل مواد مؤكسِدة"],"explanation":"يجب أن يبقى التدخين أو أي لهب مكشوف على بُعد 25 قدماً على الأقل من مركبة تحمل لافتات تنقل متفجرات أو مواد مؤكسِدة أو مواد قابلة للاشتعال."},"13":{"q":"توقّفتُ عند رصيف تحميل لتحميل متفجرات من الشعبة 1.2 في مقطورتي. طاقم الرصيف ينتظرني لأجهّز الشاحنة قبل أن يبدؤوا بنقل الصناديق إلى المتن. قبل تحميل أي من المتفجرات، ماذا يجب أن أفعل بمركبتي؟","options":["إطفاء المحرك وتفعيل فرامل الركن لتأمين المركبة قبل بدء التحميل","إبقاء المحرك يعمل في وضع الخمول حتى تبقى الفرامل الهوائية مشحونة ويعمل تكييف المقصورة أثناء التحميل","ترك المحرك يعمل مع تفعيل فرامل الركن، لأن المحرك نفسه ليس مصدر اشتعال حقيقي","فتح جميع النوافذ وإطلاق البوق مرتين لتنبيه طاقم الرصيف إلى بدء التحميل"],"explanation":"قبل تحميل المتفجرات أو تفريغها، أطفئ المحرك لإزالة مصدر الاشتعال وفعّل فرامل الركن لتأمين المركبة."},"14":{"q":"أنا أستلم حمولة من البنزين في براميل في محطة وقود، ويخبرني المرسِل أن أتأكد من فئة الخطر على أوراق الشحن قبل أن أضع اللافتات. بناءً على كيفية تعريف فئات المواد الخطرة، أي رقم فئة خطر يجب أن يظهر بجانب حمولة البنزين هذه؟","options":["الفئة 1، لأن السوائل القابلة للاشتعال تحمل أعلى خطر انفجار وتُجمَع مع المتفجرات","الفئة 3، لأن البنزين سائل قابل للاشتعال وهذا بالضبط ما تغطيه هذه الفئة","الفئة 8، لأن البنزين يمكن أن يحرق الجلد ويتلف المواد عند التلامس مثل المادة الأكّالة","الفئة 2، لأن البنزين يطلق أبخرة قابلة للاشتعال ويُتعامَل معه كغاز قابل للاشتعال"],"explanation":"البنزين سائل قابل للاشتعال، وهذا بالضبط ما تغطيه فئة الخطر 3."},"15":{"q":"أنا عند الرصيف أحمّل شحنة، وتدرج ورقة الشحن الاسم الصحيح للشحنة وفئة الخطر ورقم الأمم المتحدة (UN) لحمولة من المتفجرات. قبل أن أضع لافتات على مقطورتي وأنطلق، أحتاج إلى تأكيد رقم فئة الخطر الذي يحدد هذه الحمولة على أنها متفجرات. أي فئة خطر صحيحة؟","options":["الفئة 8، التي تغطي المواد الأكّالة مثل حمض البطارية","الفئة 3، التي تغطي السوائل القابلة للاشتعال مثل البنزين","الفئة 1، التي تغطي المتفجرات مثل الديناميت","الفئة 7، التي تغطي المواد المشعّة مثل اليورانيوم"],"explanation":"المتفجرات مثل الديناميت تقع في فئة الخطر 1، الأولى من بين فئات الخطر التسع."},"16":{"q":"أنا أستلم حمولتين من المواد الخطرة في المحطة. الأولى برميل صغير من مادة أكّالة من الجدول 2 يزن 300 رطل فقط؛ والثانية أسطوانة واحدة من غاز سام (الفئة 2.3). يخبرني المرسِل أنني \"سأحتاج إلى لافتات للكمية التي تتطلب لافتات\". ماذا تخبرني هذه العبارة فعلاً عن متى تكون اللافتات مطلوبة؟","options":["أي مركبة تنقل مواد خطرة يجب أن تعرض لافتات دائماً، لذا فإن المادة الأكّالة 300 رطل والغاز السام كلاهما يتطلبان لافتات بغض النظر عن الوزن أو الفئة","اللافتات مطلوبة قانونياً فقط عندما تتحرك المركبة على طريق عام بعد حلول الظلام أو في ظروف الرؤية المنخفضة","لا حاجة لأي لافتات لأي من الحمولتين لأن كلتا الشحنتين أقل من عتبة الإجمالي 1,001 رطل للرحلة","اللافتات مطلوبة فقط لكميات أو فئات معينة — الغاز السام يحتاجها بأي كمية، بينما المادة الأكّالة تحتاجها فقط عند 1,001 رطل أو أكثر"],"explanation":"مواد الجدول 1 مثل الغاز السام تتطلب لافتات بأي كمية، بينما مواد الجدول 2 مثل المواد الأكّالة تحتاج لافتات فقط عند 1,001 رطل أو أكثر."},"17":{"q":"أنا أستلم حمولة تحمل لافتات من المواد الأكّالة. يسلّمني الشاحن أوراق الشحن ويخبرني أن كل شيء قد صُنِّف وعُبِّئ ووُضِعت عليه الملصقات بشكل صحيح. قبل أن أنقل هذه الحمولة، ما الذي يخبرني بأن الشاحن قد شهد رسمياً بأن الشحنة موصوفة ومعبّأة ومُعلَّمة وموسومة بشكل صحيح؟","options":["بيان شهادة الشاحن الموقَّع الظاهر على ورقة الشحن نفسها","تأكيد شفهي من الشاحن أُعطي لي عند رصيف التحميل","وجود لافتات فئة الخطر الصحيحة مثبتة بالفعل على جميع الجوانب الأربعة","فحصي الخاص للأختام والملصقات الذي يؤكد عدم وجود أي تسرب"],"explanation":"يشهد الشاحن بأن شحنة المواد الخطرة مسمّاة ومعبّأة ومُعلَّمة وموسومة بشكل صحيح بتوقيعه على بيان شهادة في ورقة الشحن."},"18":{"q":"إذا اكتشفتَ تسرب مادة خطرة، فيجب أن:","options":["تلمسه لتحديد ماهيته","لا تلمسه وتبقي الناس بعيدين","تقود بسرعة أكبر إلى ورشة","تخفي اللافتات"],"explanation":"لا تلمس التسرب أبداً؛ أبقِ الناس بعيدين، وتجنّب مصادر الاشتعال، واطلب المساعدة."},"19":{"q":"انقلبت صهريجي المحمّل بالمواد الأكّالة والذي يحمل لافتات على طريق ريفي، ومنتج الفئة 8 يتسرب على كتف الطريق. بعد أن أبعدتُ الناس، وأوقفتُ التدخين، وأمسكتُ بدليل الاستجابة للطوارئ، تحتاج شركتي إلى الإبلاغ عن الحادث الخطير هاتفياً. أي جهة اتصال هي تلك الموجودة تحديداً لتلقّي بلاغ عن حادث مواد خطرة خطير؟","options":["كيمتريك (CHEMTREC)، التي أتصل بها أولاً لأنها الوكالة الوحيدة المخوَّلة بتلقّي بلاغ حادث رسمي","المركز الوطني للاستجابة، الخط الساخن الفيدرالي الموجود لتلقّي بلاغات حوادث المواد الخطرة الخطيرة","الشاحن المدرج في أوراقي، لأن الشركة التي عبّأت الحمولة يجب أن تقدّم البلاغ","الخط الساخن للشركة المصنّعة للمركبة، حتى يُوثَّق الانقلاب وفشل الصهريج رسمياً"],"explanation":"يجب الإبلاغ عن حوادث المواد الخطرة الخطيرة إلى المركز الوطني للاستجابة، الخط الساخن الفيدرالي على الرقم 1-800-424-8802."},"20":{"q":"الساعة 2:30 صباحاً يوم أحد وقد بدأ أحد براميلي التي تحمل لافتات بتسريب مادة أكّالة في محطة استراحة. لقد حذّرتُ المارة بالفعل، وأبقيتُ الناس بعيدين، ومنعتُ التدخين. أريد الآن الاتصال بكيمتريك (CHEMTREC) (1-800-424-9300) للحصول على إرشادات طوارئ للتعامل مع المواد الكيميائية، لكنني قلق من ألا يجيب أحد في هذه الساعة في عطلة نهاية الأسبوع. أي عبارة صحيحة؟","options":["تجيب كيمتريك فقط على المكالمات خلال ساعات العمل العادية، لذا يجب أن أنتظر حتى صباح الاثنين للحصول على إرشاد.","كيمتريك مزوَّدة بالموظفين في أيام الأسبوع فقط، لذا يجب أن أتصل بمكتب شركتي بدلاً من ذلك لأن اليوم أحد.","كيمتريك مزوَّدة بالموظفين على مدار 24 ساعة، كل يوم، لذا يمكنني الاتصال الآن والوصول إلى خبير طوارئ.","كيمتريك متاحة فقط خلال ساعات الليل، لذا فإن الاتصال في 2:30 صباحاً هو النافذة الوحيدة التي تعمل."],"explanation":"كيمتريك (CHEMTREC) (1-800-424-9300) مزوَّدة بالموظفين على مدار 24 ساعة، كل يوم، لتقديم معلومات الاستجابة للطوارئ."},"21":{"q":"أنقل حمولة تحمل لافتات من المواد الأكّالة (وليست متفجرات) وأحتاج إلى التوقف لإجراء مكالمة هاتفية ومراجعة أوراقي. لا توجد منطقة استراحة قريبة، لذا أنظر إلى كتف طريق سريع من مسارين. لأبقى ملتزماً قانونياً بموجب قواعد ركن المواد الخطرة، أيٌّ مما يلي يجب أن أفعله؟","options":["أركن قريباً قدر الإمكان من حافة المسار المسلوك لأترك أكبر مساحة على الكتف لحركة المرور الأخرى","أركن على بُعد 300 قدم من الطريق لكن أترك الحمولة دون مراقبة لبضع دقائق فقط","أصعد بالمركبة على رصيف الكتف وأتوقف مباشرة بجانب الخط الأبيض الحافّ للمسار","أبقي المركبة على بُعد 5 أقدام على الأقل من الجزء المسلوك من الطريق قبل أن أتوقف وأركن"],"explanation":"يجب ألا تُركن مركبة تحمل لافتات أبداً على بُعد أقل من 5 أقدام من الجزء المسلوك من الطريق."},"22":{"q":"أنقل متفجرات من الشعبة 1.2 وأتوقف لإجراء فحص إطارات إلزامي. على الكتف أمامي أرى حريق مركبة، وحشداً من الناس متجمعين قريباً يشاهدون. لأركن بشكل قانوني وآمن بهذه الحمولة، ما الحد الأدنى للمسافة التي يجب أن أحافظ عليها بين شاحنتي وذلك الحشد المتجمع في موقع الحادث؟","options":["على الأقل 300 قدم من تجمّع الناس","على الأقل 25 قدماً من تجمّع الناس","على الأقل 50 قدماً من تجمّع الناس","على الأقل 5 أقدام من تجمّع الناس"],"explanation":"يجب ألا تُركن حمولات المتفجرات (الشعبة 1.1، 1.2، 1.3) أبداً على بُعد أقل من 300 قدم من مكان يتجمع فيه الناس."},"23":{"q":"أنقل حمولة تحمل لافتات من متفجرات الشعبة 1.2 وأحتاج إلى الابتعاد عن شاحنتي في منطقة استراحة لبضع دقائق. تقول اللوائح إن هذه الحمولة يجب ألا تُترَك أبداً دون مراقبة. لكي تُعتبر مركبتي قانونياً 'مراقَبة'، أيٌّ مما يلي يجب أن يتحقق في الشخص الذي يراقبها؟","options":["يجوز له أن يستريح في مقصورة النوم ما دام يستطيع سماع الشاحنة والاستجابة إذا حدث شيء","يكون مستيقظاً، على بُعد 100 قدم من المركبة، ويراها بوضوح، وقادراً على تحريكها بسرعة عند الحاجة","يمرّ ويفحص المركبة مرة واحدة على الأقل كل ساعتين، نفس الفاصل المستخدم لفحوص الإطارات","يبقى في أي مكان داخل منطقة الاستراحة ويظل قابلاً للوصول عبر الهاتف المحمول في حالة الطوارئ"],"explanation":"تُعتبر حمولة المتفجرات مراقَبة فقط إذا كان الشخص مستيقظاً، على بُعد 100 قدم، يراها بوضوح، وقادراً على تحريكها بسرعة."},"24":{"q":"أنا سائق رخصة تجارية أنقل حمولة تحمل لافتات من المواد الأكّالة. عند الرصيف، يسلّمني موظف لوحة مشبكية ويسرد ما يشمله \"عملي\" قبل الانطلاق. لأبقى ضمن مجالي القانوني الفعلي كسائق، أحتاج إلى تحديد المهمة الوحيدة في هذه القائمة التي ليست من مسؤولية السائق بل تخص شخصاً آخر في السلسلة. أيٌّ من هذه هي تلك المهمة؟","options":["رفض قبول طرد أجده متسرباً أو موسوماً بشكل غير صحيح","وضع اللافتات المطلوبة على جميع الجوانب الأربعة قبل أن أقود","إنتاج المادة الخطرة المشحونة وصياغتها كيميائياً","إبقاء أوراق الشحن في متناول يدي أثناء القيادة"],"explanation":"واجبات السائق هي الفحص، ورفض الشحنات السيئة، ووضع اللافتات، وإبقاء أوراق الشحن في المتناول، والقيادة بأمان — وليس أبداً إنتاج المادة."},"25":{"q":"الطقس تحت درجة التجمد وأنا أحمّل مقطورة لرحلة طويلة. شاحنتي بها سخّان حيز شحن يعمل، وأود تشغيله لحماية الحمولة من البرد. من بين الشحنات الأربع المنتظرة على الرصيف، لأيها يجب أن أبقي سخّان الشحن مُطفأً؟","options":["منصة من علب الحساء وزجاجات المياه التي قد تتجمد وتنفجر في البرد","أثاث منزلي معبّأ ومواد تغليف تحتفظ بالرطوبة في الطقس البارد","منتجات مبرَّدة يريد المستلِم إبقاءها من التجمد أثناء النقل","براميل من سائل قابل للاشتعال من الفئة 3 محمَّلة مع صناديق من المتفجرات"],"explanation":"يجب أن تبقى سخّانات الشحن مُطفأة عند نقل المتفجرات أو السوائل القابلة للاشتعال لأن اللهب أو الحرارة قد يشعل الأبخرة أو يفجّر المتفجرات."},"26":{"q":"مرت ثلاثة أسابيع منذ أن سلّمت حمولة مواد أكّالة موضوعة عليها لافتات، وانتهت الرحلة منذ زمن. يخبرني مسؤول التوزيع أن الشركة لا تزال تحتفظ بأوراق شحن المواد الخطرة الخاصة بتلك الشحنة في ملف. أي مما يلي هو أفضل سبب لاحتفاظ الناقل بتلك الأوراق المكتملة في الملف بعد انتهاء الرحلة؟","options":["قد يطلب المنظمون الفيدراليون والولائيون السجلات للتفتيش، لذا يجب على الناقل الاحتفاظ بها للمدة المطلوبة","يُلزَم السائق الذي نقل الحمولة بالاحتفاظ شخصيًا بتلك الأوراق الأصلية في ملف طوال بقية حياته المهنية","بمجرد تأكيد التسليم ونزول الحمولة عن الشاحنة، لم تعد الأوراق ذات فائدة ويمكن التخلص منها","يكفي الاحتفاظ بالأوراق فقط أثناء وجود المادة في النقل ويجب أن تصل إلى جيب باب السائق"],"explanation":"يجب على الناقل الاحتفاظ بأوراق الشحن المكتملة للمدة المطلوبة لأن المنظمين الفيدراليين والولائيين قد يطلبونها للتفتيش."},"27":{"q":"أنا أُجهّز أوراق الشحن لحمولة وأفتح جدول المواد الخطرة في اللوائح لاستخراج تفاصيل إدخال منتجي. وبينما أقرأ عبر الصف الخاص بمادتي، يأتي كل عمود أراه مباشرة من ذلك الجدول باستثناء معلومة واحدة سأضطر للحصول عليها من مكان آخر غير الجدول. أي مما يلي لن أجده بقراءة جدول المواد الخطرة؟","options":["اسم الشحن الصحيح الذي يجب أن أستخدمه لوصف المادة على أوراق الشحن","عنوان منزلي كسائق، والذي لا يظهر في أي مكان في الجدول","فئة الخطر أو الشعبة المخصّصة للمادة التي أنقلها","رقم التعريف (UN/NA) الذي يجب إدراجه مع الإدخال"],"explanation":"يصف جدول المواد الخطرة المادة نفسها — اسم الشحن، وفئة الخطر، ورقم التعريف، ومجموعة التعبئة، والملصقات — وليس أبدًا المعلومات الشخصية للسائق."},"28":{"q":"أنا أستلم حمولة من سائل قابل للاشتعال من الفئة 3 في رصيف الشاحن. تحدّد أوراق الشحن المادة بشكل صحيح وتُظهر أنها تتطلب لافتات، لكن الشاحن يسلّمني الشاحنة دون عرض أي لافتات ويقول إن مخزونهم منها قد نفد. قبل أن أنطلق إلى الطريق، ماذا يجب أن أفعل؟","options":["أن أقود إلى أول محطة مجدولة لي وأطلب من المستلم توفير اللافتات المفقودة، بما أن الحمولة محمّلة بالفعل والأوراق صحيحة","أن أتابع دون لافتات لكن أُبقي أوراق الشحن في الأعلى ضمن متناول يدي، لأن الأوراق الصحيحة تحل محل اللافتات المفقودة قانونيًا","أن أحصل على اللافتات الصحيحة وأضعها على جميع الجوانب الأربعة قبل أن أُحرّك المركبة إلى الطريق","أن أرفض الشحنة بأكملها صراحةً وأتركها على الرصيف، بما أن غياب اللافتة يجعل الحمولة غير قانونية للقبول"],"explanation":"إذا لم يوفّر الشاحن أي لافتات، يجب على السائق الحصول على اللافتات الصحيحة ووضعها على جميع الجوانب الأربعة قبل تحريك المركبة إلى الطريق."},"29":{"q":"أنا أُحمّل مادة أكّالة معبّأة في صناديق داخل مقطورتي، وقد وضع الشاحن علامة على كل عبوة على حدة. عند الرصيف يخبرني سائق آخر أن علامات العبوات هذه هي نفسها تمامًا اللافتات التي سأعلّقها على جميع الجوانب الأربعة لمركبتي. لفحص الحمولة بشكل صحيح، أي عبارة ينبغي أن أعتمد عليها؟","options":["علامات العبوات هي لافتات بالحجم الكامل، وتسمح لي اللوائح الفيدرالية بنقلها إلى جوانب المركبة لتلبية متطلب وضع اللافتات على الجوانب الأربعة","علامات العبوات هي ملاحظات اختيارية من الشاحن، لذا فإن لافتات المركبة هي العلامات الماسية الوحيدة التي تحمل وزنًا قانونيًا فعليًا","يُعالَج الإبلاغ عن المخاطر في الولايات المتحدة بواسطة اللافتات فقط، لذا فأي معيّنات على الصناديق هي مجرد زينة ويمكن تجاهلها","المعيّنات على كل عبوة هي ملصقات خطر يضعها الشاحن، وهي منفصلة عن اللافتات الأكبر التي توضع على المركبة"],"explanation":"الملصقات هي المعيّنات الأصغر التي يضعها الشاحن على العبوات الفردية، بينما اللافتات هي المعيّنات الأكبر التي توضع على جميع الجوانب الأربعة للمركبة."},"30":{"q":"أنا أُجهّز حمولة تتضمن خزانًا مبردًا من الأمونيا اللامائية وأسطوانة من الأكسجين المضغوط. على أوراق الشحن، الإدخالان مُعلّمان كفئة خطر 2. وبينما أتحقق من الأوراق مقابل ما أُحمّله فعليًا، أي حالة فيزيائية ينبغي أن أتوقع أن تكون عليها كل مادة من الفئة 2؟","options":["غاز (تشمل الفئة الغازات القابلة للاشتعال وغير القابلة للاشتعال والسامة)","سائل قابل للاشتعال يطلق أبخرة عند درجة حرارة منخفضة","مادة صلبة تصبح خطرة فقط عندما تبتل","مادة أكّالة يمكن أن تكون إما في صورة سائلة أو صلبة"],"explanation":"فئة الخطر 2 هي فئة الغازات، وتشمل الغازات القابلة للاشتعال وغير القابلة للاشتعال والسامة."},"31":{"q":"أنا سائق مواد خطرة جديد أُحمّل منتج تنظيف أكّال. يُظهر الملصق على البراميل الاسم التجاري للشركة المصنّعة بأحرف كبيرة، وقد سلّمني الشاحن الأوراق، ومسؤول التوزيع يظل يسمّي الحمولة باسم المنتج في الكتالوج. عندما أتحقق من أن اسم الشحن الصحيح على أوراق الشحن صحيح، أي اسم يجب أن يطابقه؟","options":["الاسم التجاري المطبوع بأحرف كبيرة على ملصقات البرميل، بما أن هذا ما يُعرّف المنتج الفعلي","اسم الشحن الصحيح المدرَج في جدول المواد الخطرة لتلك المادة، وليس أي اسم تجاري أو علامة تجارية","اسم المنتج في الكتالوج الذي يستخدمه مسؤول التوزيع، لأن هذه هي طريقة تتبّع الشركة للحمولة","أي اسم شائع للمنتج، طالما أن فئة الخطر ورقم التعريف على الأوراق صحيحان"],"explanation":"يجب أن تُدرج أوراق الشحن اسم الشحن الصحيح تمامًا كما يظهر في جدول المواد الخطرة، وليس اسمًا تجاريًا أو علامة تجارية."},"32":{"q":"أنا أُجري فحصًا قبل الرحلة على شاحنتي الصهريجية الموضوعة عليها لافتات قبل نقل حمولة سوائل قابلة للاشتعال. أتسلّق إلى منطقة المقصورة وأفحص طفاية الحريق المثبتة بجانب الباب. أي حالة تعني أن الطفاية مقبولة وأنني قانوني للانطلاق؟","options":["الطفاية مثبتة ومختومة، لذا لا أحتاج إلى فحص المقياس أو تصنيفها قبل المغادرة","الطفاية بالحجم الذي اعتدت عليه، رغم أن إبرة مقياس الضغط تقع في المنطقة الحمراء","الطفاية مشحونة بالكامل وتحمل تصنيفًا مرتفعًا بما يكفي للخطر الذي أنقله","الطفاية موجودة في المقصورة، بما أن حمل أي طفاية صالحة للعمل يلبّي المتطلب"],"explanation":"يجب أن تحمل المركبة الموضوعة عليها لافتات طفاية حريق مشحونة بالكامل ومصنّفة بدرجة مرتفعة بما يكفي للخطر الذي يُنقل."},"33":{"q":"أنا أنقل حمولة موضوعة عليها لافتات من سائل قابل للاشتعال وأتوقف عند جزيرة وقود لملء خزاني. يعرض زميلي في القيادة المساعدة كي ننتهي بشكل أسرع. لتزويد الشاحنة بالوقود بشكل صحيح وآمن، أي مما يلي يجب أن يحدث؟","options":["يمكنني ترك الفوهة مثبتة مفتوحة والابتعاد لتنظيف الزجاج الأمامي، طالما بقي المحرك يعمل لتشغيل الأضواء","ينبغي أن أُبقي المحرك في وضع الخمول كي تتهيأ مضخة الوقود بشكل أسرع، وأقف على بعد نحو 25 قدمًا أثناء الملء","يمكنني البدء بالتزويد والمشي للداخل للدفع، بما أن الإيقاف التلقائي في المضخة سيوقف التدفق عند امتلاء الخزان","يجب أن أُطفئ المحرك، وعلى أحدنا أن يبقى عند الفوهة متحكمًا في تدفق الوقود طوال الوقت"],"explanation":"عند تزويد مركبة موضوعة عليها لافتات بالوقود، يجب أن يكون المحرك مُطفأً وأن يبقى شخص ما عند الفوهة متحكمًا في تدفق الوقود طوال الوقت."},"34":{"q":"أنا أنقل حمولة موضوعة عليها لافتات من متفجرات الشعبة 1.1 ويقترح جهاز تحديد المواقع أسرع طريق، وهو يقطع مباشرة عبر منطقة أعمال وسط المدينة ونفق نهري رئيسي خلال فترة بعد الظهر. وفقًا لمسارات المواد الخطرة المطلوبة، ماذا ينبغي أن أفعل؟","options":["أن أخطّط لمسار يتجنب المناطق المأهولة والأنفاق حيثما يُطلب ذلك، حتى لو أضاف أميالًا","أن أسلك مسار جهاز تحديد المواقع بما أن النفق يُبعدني عن الشوارع السطحية المزدحمة ويوفّر الوقت","أن أستخدم مسار وسط المدينة لكن فقط إذا بقيت متوقفًا على بعد 5 أقدام على الأقل من الطريق المسلوك أثناء التوقفات","أن أتبع أسرع طريق طالما عبرت سكة الحديد دون تبديل التروس"],"explanation":"يجب على السائق الذي ينقل متفجرات موضوعة عليها لافتات اتباع مسارات المواد الخطرة المحددة، متجنبًا الأنفاق والمناطق المأهولة حتى لو أضاف ذلك أميالًا."},"35":{"q":"أنا أُحمّل مقطورتي لرحلة مواد خطرة موضوعة عليها لافتات، وتدرج أوراق الشحن لدي مادتين يُظهر جدول الفصل أنهما قد تتفاعلان بشكل خطير إذا تلامستا. طاقم الرصيف في عجلة من أمره ويريدونني أن أنطلق فحسب. أي إجراء يبقيني قانونيًا وآمنًا؟","options":["أن أُثبّت المادتين غير المتوافقتين على المنصة نفسها كي تركبا بإحكام ولا تنزلقا أثناء الرحلة","أن أُبقي المادتين محمّلتين بشكل منفصل كما تتطلب قواعد الفصل كي تبقى العناصر التفاعلية متباعدة","أن أدمج المادتين في صندوق واحد محكم الإغلاق كي لا يستطيع انسكاب واحد الانتشار إلى بقية الحمولة","أن أُحمّل كلتا المادتين بشكل عادي وأتجاوز فحص الفصل بما أنني أُجري رحلة قصيرة ومباشرة"],"explanation":"يجب تحميل المواد غير المتوافقة المدرجة في جدول الفصل وإبقاؤها متباعدة كي لا تتفاعل في حال تلامسها."},"36":{"q":"أنا أُحمّل براميل من حمض البطاريات للنقل. تدرج أوراق الشحن الحمولة برقم فئة خطر، وأريد أن أتأكد من أنني طابقت فئة الخطر الصحيحة لهذه المادة الأكّالة قبل أن أضع اللافتات. أي رقم فئة خطر يخص اللافتات لمادة أكّالة مثل الحمض؟","options":["الفئة 3، لأن السوائل القابلة للاشتعال في البراميل والأحماض مُجمّعة معًا","الفئة 5، لأن الأحماض تتفاعل بقوة وتتصرف كمؤكسِدات","الفئة 8، لأن المواد الأكّالة مثل الأحماض تندرج تحت تلك الفئة من الخطر","الفئة 1، لأن براميل الحمض المضغوطة تُعامَل كمتفجرات"],"explanation":"المواد الأكّالة مثل الأحماض تنتمي إلى فئة الخطر 8."},"37":{"q":"عند رصيف الشاحن أُسلَّم أوراق شحن لحمولة، ويدرج الإدخال فئة خطر 7 بجانب اسم الشحن الصحيح ورقم تعريف UN. قبل أن أضع اللافتات على مقطورتي وأنطلق، أي نوع من المواد يخبرني به تعيين الفئة 7 أنني أحمله فعليًا؟","options":["سوائل قابلة للاشتعال، من النوع الموجود في حمولات الوقود والمذيبات","غازات مضغوطة ومُسيّلة تحت الضغط في الأسطوانات","مواد أكّالة مثل الأحماض القوية والسوائل الكاوية","مواد مشعّة تُطلق إشعاعًا مؤيّنًا أثناء النقل"],"explanation":"فئة الخطر 7 هي المواد المشعّة، التي تُطلق إشعاعًا مؤيّنًا أثناء النقل."},"38":{"q":"عند رصيف التحميل، يسلّمني الشاحن أوراقًا تصف مادة مدرجة كـ«فئة خطر 6». قبل أن أضع اللافتات وأنطلق، أريد أن أتأكد من فهمي لنوع الخطر الذي أنقله. ماذا يخبرني تعيين الفئة 6 عن هذه الحمولة؟","options":["إنها مادة سامّة، لذا يجب أن أحمي نفسي من مخاطر التعرّض والاستنشاق","إنها مادة مؤكسِدة يمكن أن تُكثّف الحريق، لذا يجب أن أُبقيها بعيدًا عن المواد القابلة للاشتعال","إنها مادة أكّالة يمكن أن تحرق الجلد والمعدن، لذا يجب أن أتفحّص وجود تسريبات","إنه غاز مضغوط غير قابل للاشتعال، لذا يجب أن أحترس من انطلاق الضغط"],"explanation":"تغطّي فئة الخطر 6 المواد السامّة، لذا احترس من مخاطر التعرّض والاستنشاق."},"39":{"q":"أنا أُجهّز شحنة واسم الشحن الصحيح على أوراقي متبوع برقم فئة الخطر «5.1»، مع رقم تعريف بصيغة UN. يسلّمني الشاحن لافتة لأعلّقها على جميع الجوانب الأربعة. أي لافتة تطابق بشكل صحيح مادة من فئة الخطر 5؟","options":["لافتة CORROSIVE (أكّال)، لأن الفئة 5 تغطّي الأحماض وسائل البطاريات التي تأكل المعدن","لافتة OXIDIZER (مؤكسِد)، لأن الفئة 5 تغطّي المؤكسِدات والبيروكسيدات العضوية","لافتة EXPLOSIVES (متفجرات)، لأن الفئة 5 تغطّي عوامل التفجير والمفجّرات","لافتة RADIOACTIVE (مشع)، لأن الفئة 5 تغطّي المواد التي تُطلق إشعاعًا"],"explanation":"تغطّي فئة الخطر 5 المؤكسِدات والبيروكسيدات العضوية، لذا تتطلب حمولة من الفئة 5.1 لافتة OXIDIZER (مؤكسِد)."},"40":{"q":"أنا أُحمّل مقطورة واحدة بعدة عبوات غير سائبة تندرج تحت فئتي خطر مختلفتين، وأُفضّل تعليق لافتة «DANGEROUS» واحدة على جميع الجوانب الأربعة بدلًا من لافتة منفصلة لكل فئة. وفقًا لقواعد المواد الخطرة لدى DPS، متى يُسمح فعليًا باستخدام لافتة «DANGEROUS»؟","options":["فقط عندما تنتمي كل عبوة في الحمولة إلى فئة خطر واحدة فقط","فقط عندما تكون الشحنة حصريًا منتجات غذائية معبّأة في صناديق أو على منصات","عندما تحتوي الحمولة على فئتي خطر أو أكثر تسمح القواعد بمشاركتها لافتة واحدة","في أي موقف تقريبًا، كبديل شامل مريح للافتات الخاصة بكل فئة"],"explanation":"يمكن أن تحل لافتة DANGEROUS واحدة محل اللافتات الفردية عندما تحمل الحمولة فئتي خطر أو أكثر تسمح القواعد بدمجها."},"41":{"q":"أنا أنقل شاحنة صهريجية موضوعة عليها لافتات عندما يوقفني شرطي ولاية ويشير إلى الرقم المكوّن من أربعة أرقام المعروض على اللافتة، سائلًا عمّا يخبره به. بناءً على كيفية استخدام هذا الرقم في حالة طوارئ، ماذا يُعرّف رقم التعريف المكوّن من أربعة أرقام فعليًا؟","options":["الوزن الإجمالي الكلي للخزان المحمّل كي يعرف المستجيبون حجم الانسكاب","شعبة فئة الخطر، مثل 3 للسوائل القابلة للاشتعال، بصيغة رقمية","مسار المواد الخطرة المحدد الذي عيّنه الناقل لي لأتبعه إلى المحطة","المادة الخطرة المحددة التي يجري نقلها، التي يبحث عنها المستجيبون في دليل الاستجابة للطوارئ"],"explanation":"رقم UN/NA المكوّن من أربعة أرقام يُعرّف المادة الخطرة المحددة، التي يبحث عنها المستجيبون في دليل الاستجابة للطوارئ."},"42":{"q":"أنا أراجع أوراق الشحن لحمولتي وألاحظ أن كل إدخال مادة خطرة يدرج مجموعة تعبئة I أو II أو III. يسألني سائق أحدث ماذا يخبرنا به هذا الرقم الروماني فعليًا. بناءً على تدريبي على المواد الخطرة، ماذا تُشير مجموعة التعبئة بشأن المادة؟","options":["مدى الخطر الذي تشكّله المادة، حيث المجموعة I هي الأكثر خطورة","رقم فئة الخطر الذي يُعرّف نوع الخطر، مثل القابلية للاشتعال أو التآكل","الوزن الأدنى الذي يجب عنده وضع اللافتات على الحمولة من جميع الجوانب الأربعة","الترتيب الذي يجب أن تُدرج به الإدخالات على ورقة الشحن"],"explanation":"تُصنّف مجموعة التعبئة درجة خطورة المادة، حيث المجموعة I هي الأكثر خطورة، والمجموعة II متوسطة، والمجموعة III الأقل."},"43":{"q":"أنا أنقل حمولة موضوعة عليها لافتات من المواد الأكّالة عبر تكساس عندما يطلب مني شرطي ولاية عند محطة وزن أن أُشير إلى أين يُوثَّق رقم هاتف الاستجابة للطوارئ على مدار 24 ساعة لشحنتي. أي موقع ينبغي أن أُريه للضابط؟","options":["على اللافتات المثبتة على جميع الجوانب الأربعة للمقطورة","على ورقة الشحن المحفوظة ضمن متناول يدي في المقصورة","على بطاقة تصديق المواد الخطرة (H) الخاصة بي","في دليل الاستجابة للطوارئ المخزّن في المقصورة"],"explanation":"يُدوَّن رقم هاتف الاستجابة للطوارئ على مدار 24 ساعة على ورقة الشحن، التي يجب أن تبقى ضمن متناول يد السائق في المقصورة."},"44":{"q":"أنا أراجع أوراق الشحن لحمولة وأحد الإدخالات مدرج بفئة خطر 4. قبل أن أضع اللافتات وأفحص، أريد أن أتأكد من نوع الخطر الذي أنقله فعليًا. أي مما يلي يصف بشكل صحيح ما هي مواد فئة الخطر 4؟","options":["غازات قابلة للاشتعال يمكن أن تشتعل إذا أُطلقت من أسطوانة مضغوطة","سوائل قابلة للاشتعال مثل البنزين تُطلق أبخرة قابلة للاشتعال","مواد صلبة قابلة للاشتعال، بما في ذلك المواد القابلة للاشتعال التلقائي والخطرة عند الابتلال","مواد أكّالة يمكن أن تحرق الجلد أو تأكل الحاويات المعدنية"],"explanation":"تغطّي فئة الخطر 4 المواد الصلبة القابلة للاشتعال، بما في ذلك المواد القابلة للاشتعال التلقائي والخطرة عند الابتلال."},"45":{"q":"أنا أُحمّل مادة من الفئة 4.3 مُعلَّمة كـ«خطرة عند الابتلال» في مقطورتي، والمطر متوقع طوال المسار. قبل أن أُغلق الأبواب، أي احتياط يهم أكثر لهذا الخطر المحدد؟","options":["الحفاظ على الحمولة من أن تبرد كثيرًا، بما أن التبريد هو ما يُزعزع استقرار هذه المواد الصلبة","التأكد من أن الصناديق محكمة الإغلاق ضد الغبار، لأن الجسيمات المحمولة جوًا تُحفّز التفاعل","التأكد من أن الحمولة مطلية ومحكمة الإغلاق حديثًا كي لا تتمكن الأبخرة من التسرّب أثناء النقل","إبقاء المادة جافة تمامًا ومحكمة الإغلاق، لأن التلامس مع الماء يمكن أن يجعلها تشتعل"],"explanation":"تتفاعل المواد الخطرة عند الابتلال مع الماء ويمكن أن تشتعل، لذا يجب إبقاؤها جافة تمامًا ومحكمة الإغلاق ضد الرطوبة."},"46":{"q":"أنا أُحمّل عدة أسطوانات غاز مضغوط في مقطورتي لرحلة مواد خطرة. قبل أن أُغلق الأبواب وأنطلق، أي ممارسة تحميل تُبقيني ملتزمًا والحمولة آمنة؟","options":["أن أضع كل أسطوانة قائمة وأُدعّمها كي لا تتمكن من الميل أو التدحرج أو الانزياح أثناء النقل","أن أمدّد الأسطوانات بشكل مسطّح وأحزمها بشكل رخو كي يكون لديها مساحة للاستقرار على الطرق الوعرة","أن أفتح كل صمام قليلًا قبل المغادرة كي يتمكن الضغط الداخلي من التعادل أثناء الطريق","أن أكدّسها على جوانبها فقط إذا كانت أرضية المقطورة مستوية، وإلا فأضعها قائمة"],"explanation":"يجب وضع أسطوانات الغاز المضغوط قائمة ودعمها كي لا تتمكن من الميل أو التدحرج أو الانزياح أثناء النقل."},"47":{"q":"أنا أُحمّل مقطورتي بشحنة من الفئة 6.1 (سم/سام)، ولا يزال لدي مساحة أرضية فائضة. لتوفير رحلة ثانية، أريد أن أُكمّل الحمولة بشحنات أخرى متّجهة إلى المحطة نفسها. أي حمولة هي التي يجب ألا أضعها في المركبة نفسها مع السم؟","options":["منصة من كراتين مقوّى محكمة الإغلاق تحتوي على قطع غيار سيارات","طعام كلاب جاف معبّأ في أكياس وحبوب إفطار معبّأة في صناديق لمتجر بقالة","صندوق من أدوات الميكانيكي اليدوية ومعدات التثبيت","عدة أكياس من رمل البناء النظيف الجاف"],"explanation":"يجب ألا تُحمّل المواد السامّة (الفئة 6.1) أبدًا مع الطعام المعدّ للبشر أو الحيوانات بسبب خطر التلوث."},"48":{"q":"أثناء فحصي قبل الرحلة، أجد برميلًا على حمولتي الموضوعة عليها لافتات مُعلَّمًا بالفئة 8، وقد تسرّبت كمية صغيرة من السائل على الأرض بالقرب منه. وبينما أُقرّر كيفية التعامل مع هذا التسريب، أي مما يلي هو الخطر الأهم الذي يجب أن أأخذه بالحسبان قبل الاقتراب منه؟","options":["ستخفض المادة درجة الحرارة داخل المقطورة بسرعة، لذا ينبغي أن أُهوّي أولًا","المادة شديدة الانفجار عند ملامسة الهواء، لذا ينبغي أن أُخلي منطقة نصف قطرها 300 قدم","يمكن أن تحرق المادة جلدي وعينيّ كيميائيًا عند الملامسة، لذا يجب أن أتجنب لمسها وأحمي نفسي","المادة خاملة في الأساس في صورتها السائلة، لذا يمكنني مسحها بقطعة قماش ومتابعة رحلتي"],"explanation":"يمكن لمواد الفئة 8 الأكّالة أن تحرق الجلد والعينين كيميائيًا عند الملامسة، لذا يجب على السائق تجنب لمسها وحماية نفسه."},"49":{"q":"أنا على وشك تحميل شحنة من سوائل قابلة للاشتعال من الفئة 3 في مقطورتي. قبل أن أبدأ التحميل، ألاحظ أن مساحة الشحن لا تزال تحتوي على بعض البقايا المتبقية وقطع معدنية مكشوفة تتقعقع من الرحلة السابقة. وفقًا لقواعد المواد الخطرة، أي حالة يجب أن تستوفيها مساحة الشحن قبل أن أبدأ التحميل؟","options":["رطبة في كل أنحائها، بما أن الرطوبة تُقلّل من فرصة الاشتعال العرضي أثناء التحميل","محمّلة بأدواتي اليدوية أولًا كي تركب مثبّتة مقابل الجدار الأمامي","محكمة الإغلاق وغير مهوّاة كي لا تتمكن الأبخرة القابلة للاشتعال من التسرّب إلى منطقة المقصورة","نظيفة وخالية من أي مخاطر مولّدة للشرر قبل دخول الشحنة"],"explanation":"يجب أن تكون منطقة الشحن نظيفة وخالية من المخاطر المولّدة للشرر قبل تحميل السوائل القابلة للاشتعال، لأن المعدن المتناثر يمكن أن يُشعل الأبخرة."},"50":{"q":"أنا أُجهّز شاحنتي الصهريجية الموضوعة عليها لافتات قبل رحلة وأُثبّت اللافتات الماسية الشكل على المقطورة. إلى جانب التأكد من أن كل واحدة تبقى نظيفة وقابلة للقراءة من الاتجاه الذي تواجهه، كيف يجب أن أضع كل لافتة فعليًا كي تستوفي متطلبات DPS؟","options":["أن أضعها كمربّع مُدار بحيث تواجه إحدى زواياها الأعلى مباشرة، مثل المعيّن","أن أمدّها بشكل مسطّح بحيث تجلس إحدى حوافها الكاملة مستوية على طول القاع","أن أُثبّتها على جانبي السائق والراكب فقط، وليس على الأمام أو الخلف","أن أُغطّيها بغشاء شفاف حتى أصل إلى رصيف التحميل"],"explanation":"تُعرَض اللافتات كمعيّنات على شكل مربّع مُدار على زاويته، مع توجيه إحدى الزوايا للأعلى مباشرة، وتُبقى نظيفة وقابلة للقراءة."},"51":{"q":"أثناء تحميل مقطورتي التي تحمل لافتات الخطر عند رصيف الشاحن، لاحظت أن أحد براميل المواد الأكّالة عليه بقعة رطبة جديدة تسيل على جانبه وأن ملصق العبوة ممزق جزئياً. يصرّ الشاحن على أنها 'كمية قليلة فقط' ويطلب مني تحميله حتى تبقى الرحلة في موعدها. ماذا ينبغي أن أفعل؟","options":["أحمّله كما هو لأن الشاحن أعدّ العبوة وصدّق عليها، وأي إبلاغ هو مسؤولية الناقل بعد التسليم","أرفض العبوة ولا أنقلها، لأنه يجب على السائق رفض أي شحنة مواد خطرة مسرّبة أو تالفة","أحمّله لكن أدفنه في عمق وسط بقية البضائع حتى يُحتوى التسرّب ويكون بعيداً عن جدران المقطورة","أحمّله لكن أكتب ملاحظة على مستندات الشحن حتى يُحذَّر المستلم من التسرّب عند الوصول"],"explanation":"يجب على السائق فحص الشحنات ورفض نقل أي عبوة مواد خطرة مسرّبة أو تالفة."},"52":{"q":"لقد سلّمت للتو حمولة صهريج من سائل قابل للاشتعال ويُظهر مقياس الخزان أنه 'فارغ'. قبل أن أعود إلى المحطة، أحاول تحديد ما إذا كان بإمكاني نزع لافتات الخطر. تحت أي شرط يكون لديّ أقل مبرر لإزالتها بينما لا يزال الخزان في حالة 'الفراغ' هذه؟","options":["عندما يكون الخزان قد نُظّف بالبخار وطُهّر وصُدّق على خلوّه من أي منتج","عندما يؤكد كل من مستندات الشحن والناقل أن الخزان أصبح يستوفي معيار 'نظيف ومطهّر'","عندما لا يزال الخزان يحتوي على بقايا عالقة أو أبخرة خطرة من الحمولة السابقة","عندما يكون الخزان قد شُطف ثلاث مرات في المحطة وأُعيد وزنه فارغاً"],"explanation":"يُعدّ الخزان 'فارغاً' فقط عندما لا تتبقى فيه أي بقايا عالقة أو أبخرة خطرة من الحمولة السابقة، لذا يجب أن تبقى لافتات الخطر حتى يصبح نظيفاً فعلاً."},"53":{"q":"أنا بصدد استلام حمولة صنّفها الشاحن على أنها نفايات خطرة، وليست مجرد مواد خطرة عادية، وأريد التأكد من أنني أغادر المنشأة ومعي المستند الوحيد الذي تتطلبه اللوائح تحديداً لهذا النوع من الشحنات. أي مستند يجب أن يرافق حمولة النفايات الخطرة هذه؟","options":["بوليصة شحن قياسية أُعدّت لشحنة بضائع تجارية عادية","فقط دليل الاستجابة للطوارئ المحفوظ في المقصورة للرجوع إليه عند الحوادث","صحيفة بيانات السلامة التي تصف خصائص المادة الكيميائية وخطوات التعامل معها","بيان النفايات الخطرة الموحّد الذي يرافق شحنة النفايات"],"explanation":"يجب أن ترافق شحنات النفايات الخطرة بيان نفايات خطرة موحّد يتتبع النفايات من نشأتها مروراً بالنقل وحتى التخلص النهائي منها."},"54":{"q":"أنا أنقل حمولة تحمل لافتات الخطر من متفجرات الشعبة 1.1 ولاحظت أن دعامة تثبيت داخل المقطورة قد ارتخت. أحتاج إلى شدّ المثبّتات قبل أن أتمكن من المتابعة بأمان. أيّاً مما يلي ينبغي أن أستخدمه لإنجاز المهمة؟","options":["أدوات غير مولّدة للشرر مصنوعة من النحاس الأصفر أو البرونز، لتجنّب أي شرارة قد تشعل المتفجرات","أدوات فولاذية عادية، لأنها تمسك المثبّتات بأقوى شكل وتنهي العمل بأسرع وقت","أي قضيب فولاذي ثقيل قريب مني، لأن المزيد من العزم يعني انتهائي بشكل أسرع","أي أداة مطلية بعلامة سلامة حمراء، لأن الأدوات ذات العلامة الحمراء معتمدة لأعمال المواد الخطرة"],"explanation":"يجب أن يُنفّذ العمل قرب متفجرات الفئة 1 بأدوات غير مولّدة للشرر من النحاس الأصفر أو البرونز، لأن شرارة واحدة بين معدن ومعدن قد تشعل المتفجرات."},"55":{"q":"وضعت لافتات الخطر على جوانب مقطورتي الأربعة عند رصيف التحميل وتأكدت من أن كل واحدة منها مقروءة قبل الانطلاق. بعد ثلاث ساعات من رحلة طويلة، توقفت للتزود بالوقود وأخبرت سائقي المرافق أن لافتات الخطر 'تم التعامل معها بالفعل'. فيما يتعلق بمتى أكون مسؤولاً عن التحقق من وجود لافتات الخطر، أي عبارة صحيحة؟","options":["تنتهي مسؤوليتي بمجرد تأكيد لافتات الخطر عند الرصيف، لأن فحص ما قبل الرحلة هو وقت التحقق من اللافتات.","يجب أن أتحقق من وجود لافتات الخطر قبل الرحلة ومرة أخرى أثناءها وأنا أسير.","يكفي أن أعيد فحص لافتات الخطر فقط عند وصولي إلى نقطة التسليم لإرضاء المستلم.","وضع لافتات الخطر هو واجب الشاحن، لذا فإن التحقق منها أثناء الطريق ليس جزءاً من مسؤوليتي في القيادة."],"explanation":"يجب أن تتأكد من وجود لافتات الخطر قبل الرحلة ومرة أخرى أثناءها، لأنها قد ترتخي أو تسقط أو تُحجَب أثناء القيادة."},"56":{"q":"أنا أنقل حمولة تحمل لافتات الخطر من المواد الأكّالة عندما بدأ أحد البراميل يتسرب على كتف الطريق. وبينما أُخرج مستندات الشحن البعيدة عن متناولي على المقعد، لاحظت أن الشاحن أرفق بها معلومات الاستجابة للطوارئ. عند وصول رجال الإطفاء وفريق المواد الخطرة إلى موقع الحادث، ما هو الغرض الأساسي من معلومات الطوارئ الخاصة بالشاحن؟","options":["تسرد القيمة التجارية للبضائع حتى يحدد المستجيبون أولوية الحمولات التي يجب حمايتها أولاً","تخبرني بنوع الوقود وضغط الإطارات الذي يفضّله الناقل للرحلات الطويلة في الطقس الحار","تعطي المستجيبين التفاصيل التي يحتاجونها للتعامل بأمان مع التسرب أو الحريق الناتج عن هذه المادة بالتحديد","تشهد بأنني أكملت فحص خلفيتي الأمنية لدى TSA وأحمل تصديق H صالحاً للقيادة"],"explanation":"ترافق معلومات الاستجابة للطوارئ مستندات الشحن لتزويد المستجيبين بالبيانات المحددة اللازمة للتعامل بأمان مع تسرب أو رشح أو حريق من تلك المادة."},"57":{"q":"أنا أحمّل عدة عبوات من مواد مشعّة من الفئة 7، وأشار الشاحن إلى رقم مطبوع على ملصق كل عبوة وأخبرني أنه يجب أن أجمع هذه الأرقام معاً وأبقي المجموع ضمن حد معين لمركبتي. ما الغرض من هذا الرقم الذي يُطلب مني تتبّعه؟","options":["إنه رمز لوني يخبرني بأي جانب من المقطورة أضع اللافتة المطابقة","إنه تصنيف للسرعة يحدد السرعة القصوى التي يمكنني القيادة بها أثناء وجود الحمولة المشعّة على متن المركبة","إنه مؤشر للمسار يخبرني بأي الطرق السريعة المخصصة يُسمح لي باستخدامها","إنه مؤشر نقل يحدّ من إجمالي التعرض الإشعاعي المسموح به على مركبتي"],"explanation":"تحمل كل عبوة مشعّة مؤشر نقل، ويجب على السائق جمع هذه المؤشرات وإبقاء المجموع تحت حد معين للتحكم في التعرض الإشعاعي على المركبة."},"58":{"q":"أنا أنقل حمولة تحمل لافتات الخطر من المواد الأكّالة عندما أجبرني عطل في محمل العجلة على التوقف على كتف الطريق وانتظار جرّار بديل. أبلغني المرسل عبر اللاسلكي أن شاحنة أخرى للشركة قريبة واقترح أن أضخّ المنتج إليها حتى لا يتأخر التسليم. أي استجابة تتوافق بشكل أفضل مع ممارسات المواد الخطرة الصحيحة؟","options":["أرفض النقل على الطريق؛ فالمواد الخطرة لا تُنقل بين المركبات إلا في حالة طوارئ حقيقية، لذا ينبغي أن أنتظر الإصلاح أو الترتيبات المناسبة","أمضي قدماً في نقل الحمولة، لأن الحفاظ على موعد التسليم هو أولوية الناقل الأولى","أنقلها فقط بعد إعادة وضع لافتات الخطر على المركبتين، مما يجعل النقل على جانب الطريق مقبولاً تماماً","أُجري النقل لأن الحمولة متوقفة بالفعل ومركونة بأمان خارج الجزء المستخدَم من الطريق"],"explanation":"لا تُنقل المواد الخطرة بين المركبات إلا في حالة طوارئ حقيقية، لذا فإن عطلاً روتينياً أو تأخّر تسليم ليس سبباً للنقل على جانب الطريق."},"59":{"q":"أنا أحمّل شحنة تحدّدها مستندات الشاحن على أنها ملوّث بحري قبل رحلتي إلى الميناء. بصفتي السائق الذي يُكمل فحصه، أي من هذه الشروط يجب أن يتحقق قبل أن أوافق على نقل هذه الحمولة؟","options":["يمكن تغطية ملصقات الملوّث البحري حتى أصل إلى المحطة البحرية","يجب أن تُظهر العبوة علامات الملوّث البحري المطلوبة قبل أن أنقلها","يمكن ترك علامات الملوّث البحري لأنه يُنقل عبر الطريق أولاً","يجب إخفاء الحاوية عن الأنظار للحفاظ على أمان الحمولة على الطريق"],"explanation":"يجب أن يُظهر الملوّث البحري العلامات المطلوبة على العبوة قبل النقل، وعلى السائق رفض أي شحنة مواد خطرة موسومة بشكل غير صحيح."},"60":{"q":"أثناء الطريق تكتشف تسرّب مواد خطرة من عبوة في مقطورتك. ماذا ينبغي أن تفعل؟","options":["تواصل القيادة إلى الوجهة بسرعة حتى يتعامل المرسَل إليه مع التسرّب هناك.","توقّف، وأمّن المنطقة، وأبقِ الناس بعيدين، ولا تحرّك المركبة دون داعٍ.","افتح جميع أبواب المقطورة وواصل القيادة حتى تتطاير الأبخرة منها أثناء سيرك.","اغسل المادة المتسرّبة عن الطريق بالماء ثم تابع مسارك."],"explanation":"توقّف، وأمّن المنطقة، وأبقِ الناس بعيدين، ولا تحرّك المركبة دون داعٍ."},"61":{"q":"أنت تحمّل مواد خطرة ويجب أن تتحقق من الشحنة. على من تقع مسؤولية وصف المواد الخطرة بشكل صحيح في المستندات؟","options":["الميكانيكي الذي صان الشاحنة آخر مرة قبل إرسالها في هذه الرحلة اليوم.","الشاحن، الذي يجب أن يسمّي المواد الخطرة ويصفها بشكل صحيح في مستندات الشحن.","المستلم في الوجهة، الذي يفحص الحمولة فقط بعد تسليمها.","أي سائق آخر في المحطة يصادف وجوده قريباً في تلك اللحظة."],"explanation":"الشاحن يسمّي المواد الخطرة ويصفها بشكل صحيح في المستندات."},"62":{"q":"أنت تنقل متفجرات تحمل لافتات الخطر (الشعبة 1.1) وتحتاج إلى التوقف للتزود بالوقود والطعام. أين ينبغي أن تركن؟","options":["في موقف سيارات مزدحم لمطعم مباشرةً بجوار المدخل الأمامي للمبنى هناك.","بعيداً عن النار المكشوفة والجسور والأنفاق والحشود، مع مراقبتها حيثما يُطلب ذلك.","في شارع مزدحم وسط المدينة حتى يسهل مراقبة الشاحنة من داخل مقهى قريب.","بجوار شاحنات أخرى مركونة بمحركات تعمل حتى تبقى حمولتك دافئة بشكل جيد."],"explanation":"اركن بعيداً عن النار والجسور والأنفاق والحشود؛ وراقبها حيثما يُطلب ذلك."},"63":{"q":"أنا أُجري فحص ما قبل الرحلة على جرّار-مقطورة يحمل لافتات الخطر لحمولة سائل قابل للاشتعال. أريد التأكد من أن طفاية الحريق لديّ تستوفي المتطلب الفيدرالي قبل أن أنطلق. أي من هذه الخيارات سيفي بالقاعدة فعلاً؟","options":["يمكن أن تبقى الطفاية مقفلة داخل المقطورة المختومة مع البضائع، لأن هذا هو المكان الأرجح لبدء الحريق.","طفاية مشحونة بالكامل تفي بالغرض حتى لو كانت مدفونة خلف أحزمة البضائع، طالما أنها بالتصنيف المناسب للحمولة.","يجب أن تكون الطفاية مصنّفة بشكل مناسب للحمولة، ومشحونة بالكامل، ومثبّتة حيث أستطيع الوصول إليها بسرعة.","أي طفاية صغيرة مشحونة تفي بالغرض، لأن التصنيف يهم فقط لمعدات رصيف المستلم، وليس للشاحنة."],"explanation":"يجب أن تكون طفاية الحريق في مركبة تحمل لافتات الخطر مصنّفة بشكل مناسب للحمولة، ومشحونة بالكامل، ومثبّتة حيث يستطيع السائق الوصول إليها بسرعة."},"64":{"q":"تصل إلى مزلقان سكة حديد أثناء نقلك لمواد خطرة تحمل لافتات الخطر. ماذا يجب أن تفعل؟","options":["تعبر ببطء دون توقف طالما أنك لا ترى قطاراً مقترباً الآن.","توقّف على بُعد 15 إلى 50 قدماً قبل القضبان، وتأكد من خلوّها، ثم اعبر دون تغيير التروس.","توقّف فوق القضبان مباشرةً لتنظر في الاتجاهين بعناية قبل أن تتابع العبور.","أسرع لتعبر القضبان بسرعة حتى تكون الحمولة ذات اللافتات على السكة لمدة أقل."],"explanation":"توقّف على بُعد 15 إلى 50 قدماً قبل القضبان، ثم اعبر دون تغيير التروس."},"65":{"q":"أثناء فحص مستندات الشحن، تجد أن المواد الخطرة ليست مدرجة أولاً وليست موسومة. ماذا يخبرك هذا؟","options":["الأوراق صحيحة، لأن المواد الخطرة يمكن أن تظهر في أي مكان على مستند الشحن.","الأوراق خاطئة؛ فالمواد الخطرة يجب أن تُدرَج أولاً أو تُوسَم أو تُظلَّل بوضوح.","يعني ذلك أنه لا توجد مواد خطرة على متن المركبة، لذا يمكنك إزالة لافتات الخطر من الشاحنة.","يهم ذلك فقط بالنسبة للمستلم، لذا يمكنك بدء الرحلة وتسوية الأمر لاحقاً."],"explanation":"يجب أن تُدرَج المواد الخطرة أولاً أو تُوسَم/تُظلَّل بوضوح على الورق."},"66":{"q":"أنت على وشك نقل حمولة ويجب أن تقرر ما إذا كانت لافتات الخطر مطلوبة. من المسؤول عن وضع لافتات الخطر؟","options":["الشرطة فقط، الذين يضيفون لافتات الخطر عند فحص على جانب الطريق إذا قرروا أنها مطلوبة.","يجب على السائق والناقل وضع لافتات الخطر على المركبة عندما تتطلب الحمولة ذلك.","المستلم يضع لافتات الخطر على الشاحنة بعد تسليم الشحنة.","لافتات الخطر زينة اختيارية ولا أحد بعينه مسؤول عنها على الإطلاق."],"explanation":"السائق والناقل يضعان لافتات الخطر على المركبة عندما تتطلب الحمولة ذلك."},"67":{"q":"أنت تنقل حمولة تحمل لافتات الخطر من سائل قابل للاشتعال وتتوقف في منطقة استراحة لفحص الإطارات كل ساعتين. تجد أن أحد إطارات مقطورتك ساخن عند لمسه ومن الواضح أنه يفرط في السخونة. أي من الإجراءات التالية هو الصحيح؟","options":["تسكب الماء على الإطار الساخن لتبريده بسرعة، ثم تتابع إلى وجهة التسليم حتى تبقى الشحنة في موعدها.","تضيف الهواء لإعادة الإطار الساخن إلى ضغطه المناسب، ثم تتابع القيادة على المسار المخطط.","تترك الإطار في مكانه وتتابع القيادة، لأن بعض تراكم الحرارة طبيعي على مقطورة محمّلة بالكامل وتحمل لافتات الخطر.","تنزع الإطار المفرط في السخونة وتضعه على مسافة آمنة من المركبة، ثم تفحصه قبل المتابعة."],"explanation":"إذا أفرط إطار في السخونة على حمولة تحمل لافتات الخطر فهو خطر حريق، لذا انزعه وضعه على مسافة آمنة من المركبة وافحصه قبل المتابعة."},"68":{"q":"أنت تخطط لمسار حمولة مواد خطرة تحمل لافتات الخطر عبر منطقة حضرية. ما هي أفضل ممارسة؟","options":["تقود دائماً عبر أكثر مراكز وسط المدينة ازدحاماً للوصول إلى الوجهة بأسرع وقت.","تتجنب المناطق المكتظة بالسكان والحشود والأنفاق حيثما يُطلب ذلك، وتخطط مسبقاً.","تستخدم دائماً أطول جسر متاح حتى تبقى الحمولة الثقيلة على سطح أملس.","لا تخطط للمسار مسبقاً أبداً؛ فقط اتبع تطبيق الملاحة منعطفاً بمنعطف في كل مرة."],"explanation":"تجنّب الحشود والأنفاق حيثما يُطلب ذلك وخطّط للمسار مسبقاً."},"69":{"q":"لقد أنزلت للتو آخر منصة مواد خطرة عند المرسَل إليه، والمقطورة الآن فارغة تماماً وخالية من البقايا، لكن لافتات الخطر الأربع لا تزال مثبّتة بالبراغي. أنا على وشك العودة فارغاً إلى الساحة عبر الطريق السريع بين الولايات. أي إجراء يبقيني ملتزماً بالقانون في هذه الرحلة الفارغة؟","options":["أزِل لافتات الخطر أو غطّها الآن، لأن المقطورة لم تعد تحمل حمولة تتطلبها.","اترك لافتات الخطر معروضة طوال طريق العودة، لأن المقطورة التي تحمل لافتات الخطر يعاملها السائقون الآخرون دائماً على أنها أكثر أماناً.","اتركها مرفوعة فقط حتى أصل إلى أول مزلقان سكة حديد، ثم أنزلها عند التوقف.","لا فرق حقيقياً في كلتا الحالتين، لذا يمكنني ترك لافتات الخطر على المقطورة الفارغة إذا كان ذلك يوفّر الوقت."],"explanation":"يجب إزالة لافتات الخطر أو تغطيتها بمجرد أن تتوقف المركبة عن حمل حمولة تتطلبها قانوناً، حتى لا تعطي معلومات مضللة عن البضائع."},"70":{"q":"أنا أُجري فحص ما قبل الرحلة لحمولة تحمل لافتات الخطر وأقارن مستند الشحن بالعبوة قبل أن أوقّع على استلامها. يُظهر القيد بالفعل اسم الشحن الصحيح وفئة الخطر. لكي يكون مكتملاً وقانونياً، أي معلومة متبقية يجب أن تظهر في القيد نفسه؟","options":["إجمالي المسافة التي سأقطعها على مسار المواد الخطرة المخصص لي","رقم التعريف (UN/NA) للمادة","رقم هاتف CHEMTREC المتاح على مدار 24 ساعة للناقل","حرف مجموعة التعبئة المختوم على البرميل الخارجي"],"explanation":"يسرد قيد مستند الشحن المكتمل اسم الشحن الصحيح وفئة الخطر ورقم التعريف UN/NA بهذا الترتيب."},"71":{"q":"أنا متوقف عند محطة وزن ويشير المفتش إلى اللوحة البرتقالية أسفل لافتة الخطر المعيّنية على مقطورتي، والتي تُظهر الرقم الأسود العريض \"1203\". يسألني عمّا يخبر به هذا الرقم المكوّن من أربعة أرقام المستجيبين. أي تفسير صحيح؟","options":["إنه الوزن الإجمالي، بالأرطال، للمواد الخطرة المحمّلة في ذلك المقصورة","إنه رمز شعبة فئة الخطر الذي يصنّف مدى خطورة الحمولة من 1 إلى 9","إنه رقم التعريف UN/NA الذي يحدّد المادة المنقولة تحديداً","إنه رمز هاتف الطوارئ الذي يطلبه المستجيبون للاتصال بـ CHEMTREC بشأن الحمولة"],"explanation":"الرقم المكوّن من أربعة أرقام على لافتة الخطر أو اللوحة البرتقالية هو رقم التعريف UN/NA الذي يحدّد المادة المنقولة تحديداً."},"72":{"q":"يعرض عليّ وسيط شحن حمولة من مادة أكّالة ستتطلب وضع لافتات الخطر على جوانب مقطورتي الأربعة. أحمل بالفعل رخصة القيادة التجارية الخاصة بي مع تصديقي الصهريج (N) والمقطورات المزدوجة/الثلاثية (T)، وقد جدّدت للتو بطاقتي الطبية. قبل أن أتمكن قانونياً من قبول ونقل هذه الشحنة، ما الذي يجب أن أكون قد أنجزته؟","options":["لا شيء إضافي — لأن حمولتي أكّالة (الفئة 8) وليست متفجرة، فإن لافتات الخطر وحدها تفي بالمتطلب القانوني ولا حاجة لأي تصديق خاص.","فقط تصديق الصهريج (N)، الذي أحمله بالفعل، لأن أي مادة تحمل لافتات الخطر تُعتبر خطر سائل بالجملة بموجب القواعد الفيدرالية.","تصديق ركاب (P) ساري المفعول، لأن نقل حمولة منظّمة تؤثر على السلامة العامة يُعامل بنفس معاملة نقل الركاب.","تصديق المواد الخطرة (H)، الذي يتطلب اجتياز فحص التهديد الأمني لدى TSA مع أخذ البصمات قبل أن يُسمح لي بنقل أي مواد خطرة تحمل لافتات الخطر."],"explanation":"يتطلب نقل أي مواد خطرة تحمل لافتات الخطر تصديق المواد الخطرة (H)، الذي يستلزم فحص تهديد أمني لدى TSA مع أخذ البصمات."},"73":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة A واجتزت اختبار القيادة، لكنني أريد البدء في نقل مواد خطرة تتطلب لافتات الخطر. إلى جانب اجتياز اختبار المعرفة التحريري للمواد الخطرة، ما هو المتطلب الإضافي الوحيد الذي يجب أن أستوفيه قبل إضافة تصديق H إلى رخصتي؟","options":["يجب أن أُكمل فحص تهديد أمني لدى TSA، يشمل أخذ البصمات وفحص الخلفية","يجب أن أجتاز اختبار قيادة ثانياً منفصلاً في مركبة تحمل لافتات الخطر","يجب أن أحصل أولاً على تصديق مركبة الصهريج (N) كشرط مسبق","يجب أن أضيف تصديق المقطورات المزدوجة/الثلاثية (T) إلى رخصتي"],"explanation":"يتطلب تصديق المواد الخطرة (H) بشكل فريد أن يجتاز المتقدمون فحص تهديد أمني لدى TSA يشمل أخذ البصمات وفحص الخلفية."},"74":{"q":"أين يجب أن تحتفظ بمستندات شحن المواد الخطرة أثناء القيادة؟","options":["مقفلة بعيداً داخل المقطورة","في متناول اليد، في جيب الباب أو على المقعد","داخل منطقة حجرة المحرك","مُرسَلة مسبقاً إلى المستلم أولاً"],"explanation":"احتفظ بمستندات الشحن في متناول اليد (جيب الباب) أو على المقعد أثناء القيادة."},"75":{"q":"إذا لم تكن متأكداً مما إذا كانت المادة خطرة، فعليك أن:","options":["تفترض أنها آمنة وتحمّلها","تتحقق من الشاحن قبل التحميل","تتجاهلها وتبدأ القيادة الآن","تزيل جميع لافتات الخطر أولاً"],"explanation":"عند عدم التأكد، تحقق من الشاحن قبل التحميل."},"76":{"q":"أنا متوقف في منطقة استراحة وعلى متن شاحنتي حمولة من السائل القابل للاشتعال تحمل لافتات تحذيرية. يقترب مني سائق زميل يريد الدردشة ويشعل سيجارة وهو يقترب من شاحنتي. للحفاظ على سلامتنا، ما هي أقرب مسافة يُسمح له بالتدخين عندها قرب مركبتي التي تحمل اللافتات التحذيرية؟","options":["لا أقرب من حوالي 15 قدماً، وهي نفس المسافة العازلة المستخدمة قبل سكك الحديد","لا أقرب من حوالي 25 قدماً من المركبة التي تحمل اللافتات التحذيرية","لا أقرب من حوالي 5 أقدام، وهي نفس مسافة الوقوف العازلة عن الطريق","أي مكان خارج المقصورة مقبول لأن الحمولة محكمة الإغلاق"],"explanation":"يُحظر التدخين على مسافة تقل عن حوالي 25 قدماً من مركبة تحمل لافتات تحذيرية تنقل متفجرات أو مؤكسدات أو مواد قابلة للاشتعال."},"77":{"q":"أنا بصدد استلام حمولة، وورقة الشحن تُدرج المادة على أنها من فئة الخطر 7. قبل أن أضع اللافتات التحذيرية وأفحص الطرود، أريد أن أتأكد من نوع الخطر الذي سأنقله فعلياً. بناءً على فئة الخطر الموضحة، ما الموجود في مقطورتي؟","options":["سائل قابل للاشتعال مثل البنزين أو وقود الديزل","سائل أكّال يمكن أن يحرق الجلد ويتلف المعدن","مادة مشعّة","غاز مضغوط تحت ضغط عالٍ"],"explanation":"في نظام فئات الخطر الفيدرالي، الفئة 7 تعني دائماً المواد المشعّة."},"78":{"q":"أنا بصدد تجهيز حمولة تحمل لافتات تحذيرية، وورقة الشحن تُدرج فئة خطر الحمولة على أنها 'الفئة 1'. لكي أركن المركبة وأتعامل معها بشكل صحيح، أحتاج إلى معرفة نوع المادة التي أنقلها فعلياً. تصنيف الفئة 1 يُخبرني أن الحمولة هي:","options":["سوائل قابلة للاشتعال، مثل البنزين أو الديزل التي تندرج تحت الفئة 3","سوائل أكّالة، وهي الأحماض والقواعد المجمّعة تحت الفئة 8","غازات مضغوطة أو قابلة للاشتعال، وهي تنتمي إلى الفئة 2","متفجرات، وهي المواد التي تندرج تحت الفئة 1"],"explanation":"في ترقيم فئات الخطر الثابت، الفئة 1 تعني دائماً المتفجرات."},"79":{"q":"أنا أراجع أوراق الشحن لحمولتي، وأحد البنود يُدرج فئة الخطر على أنها \"2.1\" مع رقم أممي (UN) للمادة. بناءً على نظام ترقيم فئات الخطر، ما نوع المادة التي أنقلها فعلياً؟","options":["غاز قابل للاشتعال، لأن الفئة 2 تشمل الغازات (مع كون 2.1 قابلة للاشتعال)","سائل قابل للاشتعال، لأن هذه أكثر فئات الحمولات القابلة للاشتعال شيوعاً","متفجر، لأن رقم الفئة المنخفض يعني أنه يشتعل بعنف","مادة مشعّة، لأنها تحمل رقم تعريف أممي خاص"],"explanation":"الفئة 2 تشمل الغازات، والشعبة 2.1 تدل تحديداً على غاز قابل للاشتعال."},"80":{"q":"أنا بصدد استلام شحنة، وورقة الشحن تُدرج البند على أنه \"أسيتون، 3، UN1090\". يطلب مني المرسِل أن أؤكد نوع الخطر الذي يدل عليه الرقم الأوسط لأنقله حتى أختار اللافتات التحذيرية الصحيحة. بناءً على فئة الخطر الموضحة، ماذا أنقل؟","options":["مادة صلبة قابلة للاشتعال يمكن أن تشتعل بالاحتكاك","سائل قابل للاشتعال يُطلق أبخرة قابلة للاشتعال","غاز مضغوط قابل للاشتعال تحت ضغط","عامل مؤكسِد يزيد من شدة الحريق"],"explanation":"الفئة 3 تعني دائماً السوائل القابلة للاشتعال، التي تُطلق أبخرة قابلة للاشتعال."},"81":{"q":"أنا بصدد تجهيز أوراق الشحن لحمولة، وفئة الخطر المدوّنة على البند تنص على \"الفئة 4\". قبل أن أضع اللافتات التحذيرية، أريد أن أتأكد من الفئة العامة التي تندرج تحتها هذه المادة لكي أُطابق اللافتة الصحيحة. بموجب نظام فئات الخطر، يتم تحديد مادة الفئة 4 على أنها أيٌّ مما يلي؟","options":["سائل أكّال يمكن أن يتلف الجلد والمعدن","سائل قابل للاشتعال مثل البنزين أو زيت الوقود","مادة صلبة قابلة للاشتعال، بما في ذلك المواد القابلة للاشتعال التلقائي والخطرة عند البلل","مادة متفجرة تنفجر تحت الصدمة أو الحرارة"],"explanation":"الفئة 4 تشمل المواد الصلبة القابلة للاشتعال، بما في ذلك المواد القابلة للاشتعال التلقائي والخطرة عند البلل."},"82":{"q":"أنا أراجع أوراق الشحن لحمولتي القادمة، والبند يُدرج مادة خطرة من الفئة 5 في عمود فئة الخطر. قبل أن أقبل الشحنة وأضع اللافتات التحذيرية، أحتاج إلى التأكد من نوع المادة التي سأنقلها فعلياً. أيُّ وصف يطابق بشكل صحيح مادة الفئة 5؟","options":["سوائل قابلة للاشتعال مثل البنزين ومضافات الديزل والمذيبات","مواد أكّالة مثل حمض البطاريات والسوائل القوية الأخرى","سموم وسوائل سامة تشكّل خطر استنشاق","مؤكسدات وبيروكسيدات عضوية"],"explanation":"الفئة 5 هي مجموعة المؤكسدات والبيروكسيدات العضوية."},"83":{"q":"أنا أراجع أوراق الشحن لحمولة قبل أن أغادر المحطة، وأحد البنود مُعلّم على أنه من الفئة 6. لم يكتب المرسِل بعد اسم الشحن الصحيح ويطلب مني أن أؤكد نوع المادة التي تغطيها لافتة الفئة 6 حتى تتطابق الأوراق مع الخطر. أيُّ وصف يحدد بشكل صحيح ما يندرج تحت الفئة 6؟","options":["السموم (المواد السامة) والمواد المُعدية","سوائل قابلة للاشتعال مثل البنزين والمذيبات الشائعة","سوائل أكّالة يمكن أن تحرق الجلد والمعدن","مؤكسدات وبيروكسيدات عضوية تزيد من شدة الحريق"],"explanation":"الفئة 6 تشمل المواد السامة (السموم) والمواد المُعدية."},"84":{"q":"أنا أقوم بالفحص قبل الرحلة وأراجع أوراق الشحن لحمولة تُدرج خطراً من الفئة 8. قبل أن أتعامل مع الحاويات وأختار القفازات وواقي العينين المناسبين، أحتاج إلى معرفة نوع الخطر الذي تشكّله هذه المادة فعلياً. أيُّ عبارة تصف بشكل صحيح ما هي مادة الفئة 8؟","options":["إنها سائل قابل للاشتعال يمكن أن يشتعل من شرارة، لذا فإن همّي الرئيسي هو إبعاد جميع مصادر الإشعال عن الحمولة.","إنها مادة أكّالة يمكن أن تسبب حروقاً كيميائية للجلد والعينين والمعدن، لذا فإن همّي الرئيسي هو منع التلامس وحماية الأسطح.","إنها غاز مضغوط تحت ضغط يمكن أن ينفجر بعنف، لذا فإن همّي الرئيسي هو إبقاء الأسطوانات باردة ومثبّتة.","إنها مادة مشعّة تُطلق إشعاعاً ضاراً، لذا فإن همّي الرئيسي هو الحد من مدة تعرّضي قرب الحمولة."],"explanation":"الفئة 8 هي المواد الأكّالة، التي تسبب حروقاً كيميائية للجلد والعينين والمعدن عند التلامس، لذا فإن منع التلامس وحماية الأسطح هما الأولوية."},"85":{"q":"أنا أراجع أوراق الشحن لحمولة وأرى بنداً مصنفاً على أنه مادة خطرة من الفئة 9. يسألني مدرّبي عمّا يخبرني به هذا التصنيف فعلاً عن الحمولة. أيُّ عبارة تصف بشكل صحيح ما يعنيه تصنيف الفئة 9؟","options":["إنه يحدد منتجاً من الشعبة 2.3، أي أن الحمولة غاز سام يتطلب لافتات تحذيرية بأي كمية","إنه يحدد سائلاً قابلاً للاشتعال، وهي نفس الفئة التي تغطيها فئة الخطر 3 في ورقة الشحن","إنه يحدد بضاعة خطرة متنوعة لا تندرج بشكل دقيق ضمن فئات الخطر الثماني الأخرى","إنه يحدد بضاعة متفجرة، وهي نفس عائلة الحمولة التي تغطيها قواعد لافتات فئة الخطر 1"],"explanation":"الفئة 9 هي الفئة الجامعة للبضائع الخطرة المتنوعة التي لا تتناسب مع أي من فئات الخطر الثماني الأخرى."},"86":{"q":"أنا أنقل حمولة من المواد الأكّالة تتطلب لافتات تحذيرية، ويُشير لي ضابط ولاية للدخول إلى محطة وزن. يخبرني أنه لم يستطع رؤية سوى لافتة واحدة من حيث كان يقف ويطلب مني أن أؤكد كيف يُفترض أن تُوضع اللافتات على شاحنتي. أيُّ عبارة تصف بشكل صحيح الوضع الصحيح للافتات؟","options":["اللافتات مطلوبة فقط على مؤخرة المقطورة، لأن هذا ما تقرؤه حركة المرور والمفتشون خلفي","لافتة واحدة على جانب السائق كافية ما دامت قابلة للقراءة من الاتجاه الذي تواجهه","تُوضع اللافتات على مقدمة الجرّار ومؤخرة المقطورة فقط، حتى تكون مرئية من الأمام والخلف","يجب عرض اللافتات على جميع الجوانب الأربعة للمركبة، وكل لافتة قابلة للقراءة من الاتجاه الذي تواجهه"],"explanation":"يجب عرض اللافتات التحذيرية على جميع الجوانب الأربعة للمركبة، وكل لافتة قابلة للقراءة من الاتجاه الذي تواجهه."},"87":{"q":"أنا أقوم بالفحص قبل الرحلة وأحتاج إلى التأكد من أن العلامات التحذيرية على مقطورتي صحيحة قبل أن أنقل حمولة من المواد الخطرة تتطلب لافتات تحذيرية. عندما أنظر إلى لافتة مواد خطرة معروضة بشكل صحيح على كل جانب من الوحدة، ما الشكل العام الذي يجب أن أتوقعه؟","options":["شكل المعيّن، وهو مربع مُدار ليرتكز على إحدى زواياه","مثلث، نفس شكل المثلثات التحذيرية العاكسة التي أحملها","مستطيل أعرض من ارتفاعه، مثل لوحة رقم التعريف","دائرة محاطة بحلقة ملوّنة، مثل رمز لافتة الطريق"],"explanation":"لافتة المواد الخطرة على شكل معيّن - مربع موضوع على إحدى زواياه بحيث يرتكز على ركن واحد."},"88":{"q":"أنا أنقل حمولة تحمل لافتات تحذيرية وألاحظ أثناء الفحص قبل الرحلة أن اللافتة على الجانب الأيمن من مقطورتي ملطّخة بأوساخ الطريق ومغطاة جزئياً بحامل حزام، بينما اللافتات الثلاث الأخرى نظيفة. قبل أن أقود، ماذا تتطلب مني إدارة السلامة العامة في تكساس (DPS) أن أفعل بخصوص تلك اللافتة على الجانب الأيمن؟","options":["لا شيء إضافي، لأنه ما دامت لافتتا المقدمة والمؤخرة واضحتين، فإن لافتات الجانب غير منظّمة من حيث الرؤية","تنظيفها وإعادة وضع الحزام بحيث تكون اللافتة قابلة للقراءة وغير محجوبة، لأن اللافتات على جميع الجوانب الأربعة يجب أن تكون مرئية من الاتجاه الذي تواجهه","إزالة تلك اللافتة بالكامل، لأن اللافتة المتسخة جزئياً تُعامَل كأنها بلا لافتة والثلاث الباقية لا تزال تغطي الحمولة","تركها كما هي وتدوين حالتها على أوراق الشحن فقط حتى يعرف المفتش أنني على علم بها"],"explanation":"بما أن اللافتات على جميع الجوانب الأربعة يجب أن تكون قابلة للقراءة من الاتجاه الذي تواجهه، فإن اللافتة المتسخة أو المحجوبة يجب تنظيفها وكشفها قبل القيادة."},"89":{"q":"أنا أحمّل شحنة بضائع مختلطة، وأحد المنصّات (البالات) هو مادة خطرة مُدرجة في الجدول 2 من قواعد اللافتات التحذيرية. يخبرني زميل: 'المواد الخطرة هي مواد خطرة - في اللحظة التي يصعد فيها أيٌّ منها إلى المقطورة، عليك وضع اللافتات.' قبل أن أعلّق أي شيء على الجوانب الأربعة، كيف ينبغي أن أقرر ما إذا كانت اللافتات مطلوبة فعلاً لهذه الحمولة؟","options":["أي كمية تستوجب اللافتات، لذا في اللحظة التي يكون فيها طرد واحد من المواد الخطرة على المتن يجب أن أضع اللافتات على جميع الجوانب الأربعة","تستند اللافتات إلى التغليف فقط، لذا أضع اللافتات لمجرد أن المواد الغذائية وغير الغذائية مُحمّلة معاً","يعتمد الأمر على فئة المادة وكميتها - بعض الفئات تتطلب لافتات بأي كمية، بينما مواد الجدول 2 هذه تتطلبها فقط عند 1,001 رطل أو أكثر من إجمالي الوزن القائم","اللافتات غير مطلوبة قانوناً أبداً لحمولة بضائع مختلطة، لذا يمكنني تخطيها كلياً في هذه الرحلة"],"explanation":"يعتمد وضع اللافتات على الفئة والكمية - بعض الفئات تتطلب لافتات بأي كمية، بينما مواد الجدول 2 تتطلبها فقط عند 1,001 رطل أو أكثر من إجمالي الوزن القائم."},"90":{"q":"أنا أحمّل مقطورتي عند رصيف تحميل بعدة طرود غير سائبة من فئات خطر مختلفة في الجدول 2. لا تبلغ أيُّ فئة خطر واحدة على المتن 1,001 رطل، لكن مجموع بضائع الجدول 2 مجتمعة يتجاوز ذلك الحد. يقول زميل إنه يمكنني استخدام لافتة واحدة مكتوب عليها DANGEROUS للحمولة المختلطة بأكملها بدلاً من لافتة منفصلة لكل فئة. بموجب قواعد اللافتات، متى يُسمح فعلاً باستخدام لافتة DANGEROUS؟","options":["فقط عندما تكون المقطورة بأكملها حمولة كاملة واحدة من مادة واحدة من الجدول 2 يبلغ وزنها 1,001 رطل أو أكثر","أبداً، لأن كل فئة خطر على المتن يجب أن تعرض دائماً لافتتها الخاصة بها دون استثناء","فقط عندما تتكون الحمولة من متفجرات الفئة 1 التي تتطلب لافتات بأي كمية","عندما أنقل بعض الحمولات غير السائبة المكوّنة من فئتين أو أكثر من فئات خطر الجدول 2، يجوز استخدام لافتة DANGEROUS لتلك الحمولة الصغيرة المختلطة"],"explanation":"يجوز استخدام لافتة DANGEROUS لحمولة غير سائبة تخلط بين فئتين أو أكثر من فئات خطر الجدول 2 بدلاً من لافتات الفئات المنفصلة."},"91":{"q":"أنا أحمّل سائلاً قابلاً للاشتعال من الفئة 3، واللافتات الوحيدة المتبقية في صندوق إمداداتي هي لافتات الفئة 8 (أكّالة) المتبقية من رحلتي السابقة. قبل أن أنطلق، أيُّ عبارة تعكس بشكل صحيح ما يُطلب مني فعله بخصوص اللافتات على مركبتي؟","options":["يجب أن تحدد اللافتات التي أعرضها فئة خطر المادة التي أنقلها فعلياً، لذا لا يمكنني استخدام لافتات الفئة 8 لحمولة من الفئة 3.","أيُّ لافتة على طراز وزارة النقل (DOT) مقبولة ما دامت على شكل معيّن ومعروضة على جميع الجوانب الأربعة للمركبة.","يمكنني استخدام لافتات الفئة 8 ما دمت أحتفظ بأوراق شحن الفئة 3 الصحيحة في متناول اليد داخل المقصورة.","لا تحتاج اللافتات إلى مطابقة الحمولة إلا عند عبوري لحدود ولاية، لذا فإن لافتات الفئة 8 مناسبة لرحلة داخل الولاية."],"explanation":"يجب أن تطابق اللافتات فئة الخطر الفعلية للمادة التي تنقلها، لذا فإن حمولة الفئة 3 تحتاج إلى لافتات الفئة 3."},"92":{"q":"أنا أنهي الفحص قبل الرحلة على مقطورتي المغلقة المحمّلة بسائل قابل للاشتعال من الفئة 3 يتطلب لافتات تحذيرية، وأريد أن أتأكد من أن لافتاتي معروضة بشكل صحيح قبل أن أنطلق. أيٌّ من هذه الشروط يجب أن يتحقق لكي أبدأ الرحلة بشكل قانوني؟","options":["لافتات على المقدمة والمؤخرة فقط، لأن هذين هما الجانبان اللذان يقرؤهما السائقون الآخرون فعلاً","لافتة على كل جانب من الجوانب الأربعة للمركبة، مثبّتة بحيث تكون كل واحدة قابلة للقراءة من الاتجاه الذي تواجهه","لافتات على جانبي المقطورة بالإضافة إلى نسخة من أوراق الشحن ملصقة بجانب كل واحدة","لافتة واحدة مثبّتة بشكل مسطّح على سقف المقطورة حتى تبقى مرئية ومحمية من رذاذ الطريق"],"explanation":"يجب أن تعرض مركبة المواد الخطرة التي تحمل لافتات لافتةً على جميع الجوانب الأربعة، كل واحدة مثبّتة وقابلة للقراءة من الاتجاه الذي تواجهه."},"93":{"q":"أثناء فحصي قبل الرحلة لحمولة تحمل لافتات تحذيرية، ألاحظ أن إحدى اللافتات الأربع المطلوبة باهتة جداً بسبب الشمس لدرجة أن قراءة رقم فئة الخطر صعبة، رغم أنني ما زلت بالكاد أتمكن من تمييزه. ما الإجراء الصحيح قبل أن أبدأ الرحلة؟","options":["تركها في مكانها، لأن اللافتة لا تزال مقروءة بشكل خافت إذا نظرت إليها عن قرب","تغطية اللافتة الباهتة بشريط لاصق شفاف لحمايتها من المزيد من البهتان","استبدال اللافتة الباهتة بأخرى جديدة قابلة للقراءة تماماً قبل بدء الرحلة","المتابعة واستبدالها في المحطة التالية، ما دامت اللافتات الثلاث الأخرى واضحة"],"explanation":"يجب استبدال اللافتة الباهتة أو التالفة بأخرى قابلة للقراءة تماماً قبل بدء الرحلة."},"94":{"q":"أنا بصدد استلام حمولة تحمل لافتات تحذيرية، ويسلّمني المرسِل أوراق الشحن. قبل أن أوقّع وأنطلق، ماذا يجب أن أتأكد منه بخصوص تلك الأوراق؟","options":["أنها تُدرج اسم الشحن الصحيح فقط، حتى يمكن إضافة فئة الخطر ورقم التعريف لاحقاً","أنه تُرك نسخة في المحطة، لأن الأصل اختياري في الرحلات القصيرة داخل الولاية","أن بنداً واحداً على الأقل مُعبّأ، حتى لو كانت بعض تفاصيل المواد الخطرة لا تزال مفقودة","أن كل بند من بنود المواد الخطرة دقيق وكامل قبل أن أنقل الحمولة"],"explanation":"يجب أن تكون أوراق شحن المواد الخطرة دقيقة وكاملة قبل أن تنقل الحمولة، مع إظهار كل بند لاسم الشحن الصحيح وفئة الخطر ورقم التعريف."},"95":{"q":"أنا أسير على الطريق السريع بين الولايات وأنقل حمولة من المواد الأكّالة تحمل لافتات تحذيرية، وحزام الأمان مربوط. يمكن لضابط أن يوقفني عند أي علامة ميل. وفقاً لقواعد إدارة السلامة العامة في تكساس (DPS)، أين يجب أن تكون أوراق شحن المواد الخطرة الآن بينما أقود؟","options":["في متناول يدي مع ربط حزام الأمان، أو في جيب على باب السائق، فوق أوراقي الأخرى","مغلقة داخل المقطورة مع البضائع حتى تبقى نظيفة وتسافر مع الحمولة الفعلية","موضوعة في صندوق القفازات على جانب الراكب حتى لا تنزلق عن المقعد عند التوقف المفاجئ","يحتفظ بها المرسِل فقط، الذي يرسل نسخة بالفاكس إلى قسم التوزيع لدى الناقل قبل كل رحلة"],"explanation":"أثناء القيادة، احتفظ بأوراق شحن المواد الخطرة في متناول يدك مع ربط حزام الأمان، أو في جيب باب السائق، فوق أوراقك الأخرى."},"96":{"q":"أنا أحمّل شحنة تحمل لافتات تحذيرية وأراجع ورقة الشحن قبل أن أغادر الرصيف. المادة الخطرة مختلطة مع عدة بنود بضائع غير خطرة على نفس الصفحة. لكي تكون الورقة مقبولة، كيف يجب أن يظهر بند المواد الخطرة بين البنود الأخرى؟","options":["يمكن إدراجه في أي مكان بين البضائع ما دام اسم الشحن الصحيح وفئة الخطر ورقم التعريف كلها موجودة","يجب إدراجه أولاً، أو تمييزه بوضوح بالتظليل أو بعلامة 'X' في عمود المواد الخطرة (HM) حتى يبرز عن البضائع غير الخطرة","يجب وضعه أخيراً في الصفحة حتى يُحسب الوزن الإجمالي للبضائع غير الخطرة فوقه","يحتاج فقط إلى التعليم بشكل منفصل إذا طلب ذلك المرسِل أو منشأة الاستلام تحديداً"],"explanation":"في ورقة شحن مختلطة، يجب أن يبرز بند المواد الخطرة بإدراجه أولاً أو تمييزه بالتظليل أو بعلامة 'X' في عمود المواد الخطرة (HM)."},"97":{"q":"أنا أنقل حمولة من المواد الأكّالة تحمل لافتات تحذيرية عندما يبدأ وصلة على أحد براميلي بالتسرّب وتنتشر الأبخرة عبر الكتف. أتوقف بأمان، وأحذّر الآخرين، وأمدّ يدي إلى دليل الاستجابة للطوارئ (ERG) الذي أحتفظ به في المقصورة. أيٌّ مما يلي صُمّم دليل ERG فعلاً لمساعدتي على فعله في هذه اللحظة؟","options":["تحديد أسرع طريق التفافي يتجنّب محطات الوزن وطرق الرسوم القادمة","تأكيد اسم الشحن الصحيح وفئة الخطر ورقم التعريف لأوراقي","تحديد مسافة العزل الأولية والإجراءات الوقائية للمادة المتسرّبة","التحقق من اللافتات المطلوبة وعلى أي جوانب من المقطورة يجب أن تكون"],"explanation":"يقدّم دليل الاستجابة للطوارئ (ERG) مسافة العزل الأولية والإجراءات الوقائية لمادة متسرّبة أو مسرّبة."},"98":{"q":"أنا بصدد استلام حمولة من المواد الأكّالة تحمل لافتات تحذيرية، وأوراق الشحن التي في يدي تُدرج اسم الشحن الصحيح وفئة الخطر ورقم التعريف مع بيان شهادة موقّع في الأسفل. بصفتي سائق رخصة القيادة التجارية (CDL)، أعرف أن مهمتي هي فحص الحمولة، ورفض أي شيء متسرّب، ووضع اللافتات على المركبة، وإبقاء هذه الأوراق في متناول اليد. لكن عندما أتحقق من ذلك السطر الموقّع الذي يشهد بأن المادة موصوفة بشكل صحيح ومُجهّزة بشكل سليم للنقل، شهادة مَن أنظر إليها فعلاً؟","options":["شهادة الناقل، لأن شركة النقل تُرسل الحمولة وهي مسؤولة عن الإبلاغ عن أي حادث يقع أثناء النقل","شهادتي بصفتي السائق، لأنني أنا من يفحص الشحنة ويضع اللافتات على الشاحنة ويبقي الأوراق في متناول يدي أثناء القيادة","شهادة لا أحد بالتحديد، لأن سطر الشهادة مجرد إجراء شكلي والمسؤولية القانونية الحقيقية تقع بالكامل على من يستلم الحمولة","شهادة المرسِل، لأن المرسِل يُصنّف المادة ويغلّفها ويعلّمها ويُعدّ أوراق الشحن، ثم يشهد بأن المادة موصوفة بشكل صحيح"],"explanation":"المرسِل يُصنّف المادة ويغلّفها ويعلّمها ويُعدّ أوراق الشحن، ثم يشهد بأن المادة موصوفة بشكل صحيح."},"99":{"q":"أنا عند رصيف التحميل على وشك قبول برميل من السائل الأكّال، وقبل أن أوقّع ورقة الشحن أريد أن أتأكد من أن بند المواد الخطرة موصوف بشكل صحيح. أيُّ مجموعة من التفاصيل يجب أن تظهر فعلاً على ذلك السطر لكي يكون البند وصفاً سليماً للمواد الخطرة؟","options":["اسم الشحن الصحيح، وفئة الخطر، ورقم التعريف (UN/NA)، مدرجة بهذا التسلسل","لون ملصق فئة الخطر، ونص اللافتة، والرقم المكوّن من أربعة أرقام الموضّح على اللافتة","القيمة التجزئية للحمولة، ووزنها الإجمالي القائم، والرمز البريدي للوجهة","علامة 'X' في عمود المواد الخطرة (HM) وحدها، لأن تلك العلامة هي كل ما يحدّد قانونياً البند الخطر"],"explanation":"يجب أن يُدرج بند المواد الخطرة اسم الشحن الصحيح، وفئة الخطر، ورقم التعريف (UN/NA) بهذا التسلسل بالضبط."},"100":{"q":"أنا أنقل حمولة من المواد الأكّالة تحمل لافتات تحذيرية وأتوقف في منطقة استراحة لاستخدام دورة المياه. سأغادر المقصورة وأبتعد عن شاحنتي لبضع دقائق. وفقاً لقواعد المواد الخطرة، أين ينبغي أن أترك أوراق الشحن أثناء وجودي خارج المركبة؟","options":["مطوية داخل صندوق القفازات، مغلقة حتى تبقى بعيدة عن الأنظار","على مقعد السائق أو في جيب باب السائق","مقفلة في المقطورة مع الحمولة التي تصفها","موضوعة خلف واقي الشمس على جانب الراكب"],"explanation":"عند الخروج من الشاحنة، اترك أوراق شحن المواد الخطرة على مقعد السائق أو في جيب باب السائق حتى يتمكن المستجيبون من العثور عليها بسرعة."},"101":{"q":"أنا في محطة وزن مع حمولة تحمل لافتات تحذيرية، ويطلب مني المفتش أن أبيّن له، من مستندات الشحن وحدها، الكمية الإجمالية للمواد الخطرة التي أنقلها. بخلاف اسم الشحن الصحيح وفئة الخطر ورقم التعريف، ما القيمة التي ستظهرها مستندات الشحن فعلياً لذلك البند؟","options":["الوزن المجمّع لجميع محاور شاحنتي","ضغط الإطارات البارد الموصى به للحمولة","الكمية الإجمالية للمواد الخطرة التي يجري شحنها","ساعات تشغيل المحرك المسجّلة منذ بدء الرحلة"],"explanation":"تُدرج مستندات الشحن الكمية الإجمالية للمواد الخطرة لكل بند، لذا فإن الكمية الموجودة على متن المركبة تأتي مباشرة من ذلك الرقم."},"102":{"q":"لقد رجعت بصهريجي الذي يحمل لافتات تحذيرية إلى الرصيف، وطاقم الشاحن جاهز لبدء ضخ المنتج إلى المقطورة. قبل أن أسمح ببدء أي تحميل، ما الإجراء الأكثر أهمية الذي يجب أن أتخذه لمنع المركبة من التحرك من تلقاء نفسها؟","options":["أترك المحرك يعمل عند تباطؤ سريع لكي يتوفر لي ضغط الهواء الكامل طوال الوقت","أنزع اللافتات التحذيرية من الأمام والخلف ليتمكن طاقم الرصيف من الوصول إلى صمامات التعبئة بسهولة أكبر","أفتح صمامات التفريغ والتنفيس في المقطورة أولاً ليتعادل الضغط أثناء النقل","أُشغّل فرامل الانتظار وأضع إسفينات الإيقاف أمام العجلات لكي تبقى الشاحنة ثابتة أثناء التحميل"],"explanation":"قبل تحميل أو تفريغ المواد الخطرة يجب أن تُشغّل فرامل الانتظار وتضع إسفينات الإيقاف عند العجلات لكي لا تتحرك المركبة."},"103":{"q":"أنا في محطة وأحمّل براميل من سائل قابل للاشتعال من الفئة 3 على مقطورتي التي تحمل لافتات تحذيرية. يقترب زميل في العمل وهو يحمل سيجارة مشتعلة ويسأل إن كان من المقبول أن يُنهي تدخينه بينما يساعدني في التحميل. أي رد هو الصحيح؟","options":["لا — التدخين غير مسموح به قرب تحميل المواد القابلة للاشتعال، وعليه أن يُبقي أي سيجارة مشتعلة بعيدة تماماً عن العملية","نعم — لا بأس بالتدخين ما دام يبقى على بُعد 5 أقدام على الأقل من أبواب المقطورة المفتوحة","نعم — القاعدة تقيّد فقط اللهب المكشوف مثل الشُّعَل أو الشموع المضيئة، وليس السجائر","نعم — التدخين مسموح به لأن البراميل لا تزال محكمة الإغلاق حتى يتم تحميلها ووضع اللافتات التحذيرية عليها"],"explanation":"التدخين محظور قرب تحميل المواد القابلة للاشتعال، لذا يجب إبقاء أي سيجارة مشتعلة بعيدة تماماً عن العملية."},"104":{"q":"أنا في مستودع أُحمّل صناديق من متفجرات الشعبة 1.1 على أرضية مقطورتي يدوياً. أثناء تجهيز منطقة الحمولة وتحريك كل صندوق، أي ممارسة تُبقي الحمولة الأكثر أماناً وتتوافق مع قواعد مناولة المواد الخطرة؟","options":["أجرّ الصناديق عبر الأرضية الفولاذية العارية وأشدّها بإحكام مستخدماً خطاف حمولة معدنياً مسنوناً","أضع بطانة أرضية غير قابلة لإحداث الشرر في منطقة الحمولة وأضع كل صندوق برفق، مع مناولة كل صندوق بعناية","أتجاهل أي غطاء للأرضية وأرمي الصناديق في مكانها بسرعة لكي يتسنى إغلاق الأبواب أبكر","أمرّ برافعة شوكية فوق الصناديق المحمّلة مباشرة لأضغطها بإحكام قبل إغلاق المقطورة"],"explanation":"تحتاج متفجرات الشعبة 1.1 إلى بطانة أرضية غير قابلة لإحداث الشرر ومناولة لطيفة لكل صندوق لتجنّب الاحتكاك أو الشرر أو الصدمة التي قد تُفجّر الحمولة."},"105":{"q":"أُحمّل صناديق من مادة أكّالة في شاحنتي المغلقة الجافة لرحلة مواد خطرة. العبوات معلّمة بشكل صحيح ولافتاتي التحذيرية مرفوعة. أثناء ترتيب الحمولة في منطقة الحمولة، أيٌّ من هذه يصف على نحو أفضل كيف ينبغي أن أتعامل مع العبوات نفسها؟","options":["أكدّسها بشكل غير محكم نحو الأمام لكي تستقر في مكانها أثناء التوقفات الأولى القليلة","أضعها قرب الأبواب من دون أحزمة لكي يتمكن المستجيبون للطوارئ من الوصول إليها بسرعة","أُسندها وأدعّمها وأُثبّتها لكي لا تنزاح أو تنزلق أو تسقط أثناء سير الشاحنة","أُعلّقها من القضبان العلوية للمقطورة لإبقائها بعيدة عن الأرضية تماماً"],"explanation":"يجب إسناد عبوات المواد الخطرة ودعمها وتثبيتها لكي لا تنزاح أو تنزلق أو تسقط أثناء النقل."},"106":{"q":"أنا في محطة سائبة أُحمّل صهريجاً بالبنزين، وهو سائل قابل للاشتعال من الفئة 3. خط النقل متصل بمضخة المحطة الخاصة بها، لذا لن أحتاج إلى محرك شاحنتي لتحريك المنتج. أثناء توصيل الخراطيم وبدء تدفق المنتج، ماذا ينبغي أن أفعل بمحركي؟","options":["أُبقيه يعمل بتباطؤ في غيار منخفض لكي أتمكن من التقدم للأمام لحظة انتهاء التحميل","أتركه يعمل عند تباطؤ سريع للحفاظ على ضغط الهواء وشحن البطاريات عبر المولّد","أتركه يعمل فقط إذا أخبرني موظفو المحطة بأن المنطقة جيدة التهوية","أُطفئ المحرك، لأنني لا أحتاج إليه لتشغيل مضخة منتج أثناء هذا النقل"],"explanation":"عند تحميل أو تفريغ السوائل القابلة للاشتعال يجب أن يكون المحرك مُطفأً ما لم يكن لازماً لتشغيل مضخة المنتج."},"107":{"q":"أنا في محطة على وشك نقل سائل قابل للاشتعال من الفئة 3 من صهريج الحمولة إلى خزان تخزين. قبل أن أفتح أي صمام أو أبدأ التدفق، أوصل سلك ربط بين الشاحنة وخزان التخزين وأركّب توصيلاً أرضياً. ما السبب الأساسي لقيامي بهذا قبل مناولة السائل القابل للاشتعال؟","options":["لمعادلة الشحنة الكهربائية بين الشاحنة والخزان لكي لا تتكوّن شرارة ساكنة تُشعل الأبخرة","لإنشاء مسار كهربائي احتياطي يُبقي أضواء الشاحنة وعداداتها مزوّدة بالطاقة بينما المحرك مُطفأ","لخفض درجة حرارة السائل أثناء تدفقه لكي لا يتمدد الوقود ويفيض من الخزان المستقبِل","لإبطاء معدل التدفق لكي يُفقَد قدر أقل من المنتج بالتبخر والانسكاب أثناء النقل"],"explanation":"يعمل الربط والتأريض على معادلة الشحنة الكهربائية بين الشاحنة والخزان لكي لا تتكوّن شرارة ساكنة تُشعل الأبخرة القابلة للاشتعال."},"108":{"q":"أنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة في رحلة طولها 380 ميلاً مع محطتي استراحة مقررتين. تمشّيت حول المقطورة وفحصت جميع أحزمة التثبيت والدعامات في الساحة قبل انطلاقي، وكان كل شيء مثبتاً. للبقاء متوافقاً مع قواعد حمولة المواد الخطرة، ماذا تتطلب اللائحة مني أن أفعل بشأن فحص الحمولة وأجهزة تثبيتها لبقية هذه الرحلة؟","options":["لا حاجة لشيء إضافي بعد أن يؤكد فحص ما قبل الرحلة في الساحة أن الحمولة وأحزمة التثبيت مؤمّنة، لأن إعادة الفحص أثناء الطريق إلزامية فقط للحمولات كبيرة الحجم أو زائدة الوزن.","أستمر في فحص الحمولة وأجهزة تثبيتها قبل الرحلة ومرة أخرى في نقاط أثناء الرحلة، وليس مرة واحدة فقط في البداية.","أُعيد فحص أجهزة التثبيت فقط عند نقطة التسليم النهائية، لأن الفحوص التي تتم قبل التفريغ هي التي تهم قانونياً لمطالبات الحمولة.","أُكرّر فحصاً كاملاً للحمولة وأحزمة التثبيت وفق جدول سنوي صارم يوثّقه الناقل، منفصلاً عن أي فحص ما قبل الرحلة في رحلة واحدة."],"explanation":"يجب أن تفحص الحمولة وأجهزة تثبيتها قبل الرحلة ومرة أخرى في نقاط أثناءها، وليس مرة واحدة فقط في البداية."},"109":{"q":"أنقل حمولة تحمل لافتات تحذيرية من متفجرات الشعبة 1.1 وانفكّ حزام، لذا أحتاج إلى إعادة وضع صندوق في المقطورة. أيٌّ مما يلي هو القاعدة الأهم بشأن الأدوات التي أستخدمها للقيام بهذا العمل قرب المتفجرات؟","options":["ينبغي أن تكون الأدوات مصنوعة من فولاذ ثقيل لتمسك الصناديق بإحكام دون انزلاق","ينبغي ترك الأدوات في المقصورة وتحريك الصندوق باليد لتجنّب أي تلامس","يجب ألّا تكون الأدوات قادرة على إحداث الشرر أو إتلاف عبوات المتفجرات","ينبغي أن تكون للأدوات حافة حادة لأتمكن من قطع الحزام المنفكّ وإعادة تثبيته بسرعة"],"explanation":"يجب أن تكون الأدوات المستخدمة قرب المتفجرات غير قابلة لإحداث الشرر وغير قادرة على إتلاف العبوات، لأن الشرر أو الصدمة قد يفجّر الحمولة."},"110":{"q":"أنا في رصيف تسليم أُفرّغ مقطورة تحمل لافتات تحذيرية من سائل قابل للاشتعال من الفئة 3 في براميل. يريد مشغّل رافعة شوكية أن يُبقي رافعته العاملة بغاز البروبان تعمل بتباطؤ بجوار أبواب المقطورة المفتوحة مباشرة، وعامل قريب على وشك إشعال سيجارة، ويسألني مشرف الرصيف أين ينبغي أن تكون اللهب المكشوف والمحركات العاملة أثناء العملية. ما التعليمات الصحيحة التي ينبغي أن أعطيها؟","options":["أُبقي مصادر الاشتعال عند أبواب المقطورة مباشرة لكي تعمل الرافعة الشوكية بكفاءة وتُنهي التفريغ أسرع","أسمح بالتدخين والمحركات العاملة بالتباطؤ ما داموا يبقون على بُعد 5 أقدام على الأقل من الجزء المخصّص للسير من الطريق","أضع الرافعة الشوكية العاملة داخل المقطورة لتسريع التحميل، لأن البراميل محكمة الإغلاق ولن تشتعل","أُبقي جميع مصادر الاشتعال، بما في ذلك اللهب المكشوف والمحركات العاملة، بعيدة تماماً عن منطقة التفريغ"],"explanation":"عند تحميل أو تفريغ المواد القابلة للاشتعال، أبقِ جميع مصادر الاشتعال، بما في ذلك اللهب المكشوف والمحركات العاملة، بعيدة تماماً عن المنطقة."},"111":{"q":"أُحمّل شحنة مواد خطرة تتطلب لافتات تحذيرية عند رصيف عميل. أثناء فحصي للعبوات قبل التوقيع على استلامها، أي حالة تخبرني بأنه يمكنني قانونياً قبول هذه الحمولة ونقلها؟","options":["كل عبوة معلّمة بشكل صحيح ولا تُظهر أي علامات تسرّب","فُتحت كل عبوة لكي أتمكن من تأكيد المحتويات بنفسي","العبوات مطلية بلون زاهٍ لكي تبرز للسائقين الآخرين","العبوات مكدّسة عالياً فوق المقصورة حيث يمكنني مراقبتها"],"explanation":"لا يجوز قبول شحنة مواد خطرة إلا عندما تكون كل عبوة معلّمة بشكل صحيح ولا تُظهر أي علامة تسرّب."},"112":{"q":"أُحمّل مقطورة مختلطة عند رصيف توزيع. تُدرج مستندات الشحن عدة براميل من مادة سامة من الفئة 6.1 سأنقلها عبر البلاد. يريد مشرف الرصيف ملء المساحة المتبقية في المقطورة لتوفير رحلة ثانية. من الحمولات التي يعرضها، أيٌّ منها يُحظر عليّ تحميله بجانب براميل المادة السامة؟","options":["منصات نقالة من الأسمدة الزراعية المعبّأة في أكياس المتجهة إلى المنطقة ذاتها","صناديق من الأغذية المعبّأة للبشر وأعلاف الحيوانات لمستودع بقالة","براميل إضافية محكمة الإغلاق من المادة السامة نفسها من الفئة 6.1","صناديق من حاويات شحن بلاستيكية فارغة وغير معلّمة"],"explanation":"يجب ألّا تُحمّل المواد السامة من الفئة 6.1 أو تُنقل أبداً في المركبة نفسها مع الأغذية أو الأعلاف للبشر أو الحيوانات."},"113":{"q":"أُحمّل شحنة مواد خطرة مختلطة من المواد الأكّالة والمؤكسِدات على مقطورتي، وأحتاج إلى تأكيد ما إذا كان يُسمح لهاتين المادتين بالسير بجانب بعضهما أم يجب إبقاؤهما متباعدتين. أي مرجع يخبرني بالمواد الخطرة التي لا يجوز تحميلها معاً في المركبة نفسها؟","options":["عمود HM في مستند الشحن، لأن علامات 'X' تشير إلى الحمولات التي يجب إبقاؤها متباعدة","دليل الاستجابة للطوارئ، لأنه يُدرج المواد التي تتفاعل مع بعضها","جدول الفصل (الإبعاد)، لأنه يحدد المواد التي لا يمكن تحميلها معاً","الجدول 1 من قواعد اللافتات التحذيرية، لأنه يُدرج المواد التي تتطلب لافتات بأي كمية"],"explanation":"يخبر جدول الفصل (الإبعاد) السائق بالمواد الخطرة الممنوع تحميلها ونقلها معاً."},"114":{"q":"أُحمّل مقطورة تحتوي بالفعل على عدة براميل من مؤكسِد من الفئة 5، ويناولني مشرف الرصيف أربع منصات نقالة إضافية لأركّبها في المساحة ذاتها. للحفاظ على أمان الحمولة، أيٌّ من هذه العناصر ينبغي أن أتأكد من عدم تخزينه بجانب براميل المؤكسِد مباشرة؟","options":["منصة نقالة من عبوات مياه محكمة الإغلاق","منصة نقالة من براميل بلاستيكية فارغة","منصة نقالة من الرمل المعبّأ في أكياس","منصة نقالة من عبوات مذيب قابل للاشتعال"],"explanation":"تُطلق مؤكسِدات الفئة 5 الأكسجين ويمكن أن تُكثّف الحريق أو تُشعله، لذا يجب إبقاؤها بعيدة عن المواد القابلة للاشتعال."},"115":{"q":"أثناء تحميل مقطورتي التي تحمل لافتات تحذيرية، يناولني الشاحن بندَي مواد خطرة يقول جدول الفصل إنه يجب أن أُبقيهما متباعدين، ويسأل لماذا لا يمكنهما السير جنباً إلى جنب. وفقاً للدليل، ما السبب الأفضل لوجوب فصل هاتين المادتين غير المتوافقتين؟","options":["إذا وُضعتا معاً فقد تتفاعلان مع بعضهما، أو تشتعلان، أو تُطلقان غازاً خطيراً","إبقاؤهما معاً سيدفع الحمولة فوق عتبة اللافتات التحذيرية البالغة 1,001 رطل","خلطهما سيُلطّخ اسم الشحن الصحيح وفئة الخطر على المستندات","تكديسهما معاً سيحجب المثلثات العاكسة المخزّنة في الخلف"],"explanation":"تُبقى المواد الخطرة غير المتوافقة متباعدة لأنها، إذا اجتمعت، قد تتفاعل أو تشتعل أو تُطلق غازاً خطيراً."},"116":{"q":"أُحمّل شحنة مواد خطرة مختلطة وتُدرج أوراقي برميلاً من مركّب سيانيد وعدة عبوات من حمض أكّال (الفئة 8) متجهة إلى العميل نفسه. أي قرار تحميل يُبقيني متوافقاً وآمناً؟","options":["أُحمّلها جنباً إلى جنب في الحجرة ذاتها لكي تبقى مع مستندات الشحن المطابقة","أُبقي السيانيدات والأحماض متباعدة ولا أُحمّلها معاً أبداً في الحمولة نفسها","أُحمّلها معاً فقط إذا ثبّتُّ الاثنين في حاوية خارجية واحدة محكمة الإغلاق","أُحمّلها معاً ما دمت أعبر قضبان السكة الحديد دون تغيير الغيارات"],"explanation":"يجب ألّا تُحمّل السيانيدات والأحماض معاً أبداً لأن تلامسهما يُطلق غاز سيانيد الهيدروجين القاتل."},"117":{"q":"أنت تنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة عندما تشمّ رائحة نفّاذة وتلاحظ بقعة مبللة تنتشر تحت برميل في مقطورتك. تنحرف إلى الكتف وتؤكد أن العبوة تتسرب. قبل أن تفعل أي شيء آخر، ما أولويتك الأولى؟","options":["تفتح البرميل المتسرب لتحديد المادة الكيميائية بداخله، ثم تتحقق من دليل الاستجابة للطوارئ لمعرفة اسم الشحن الصحيح","تستخدم الماء من مخزونك لتخفيف المنتج المنسكب وغسله نحو أقرب بالوعة لتصريف الأمطار قبل أن ينتشر أكثر","توقف المركبة، وتؤمّن المنطقة حول التسرب، وتُبقي المارة والآخرين بعيدين تماماً عن الموقع","تتابع ببطء إلى موقع التسليم حيث يستطيع الموظفون المدرّبون والمعدات المناسبة احتواء البرميل المتسرب وتفريغه"],"explanation":"عند أي تسرّب لمواد خطرة، الإجراء الأول هو التوقف وتأمين المنطقة وإبقاء الناس بعيدين تماماً عن الموقع."},"118":{"q":"أنت تنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة عندما يبدأ أحد براميلك بالتسرب وينفّس بخاراً في محطة توقف على جانب الطريق في فترة ظهيرة عاصفة. بعد أن حذّرت الآخرين وأبقيت الناس بعيدين، أين ينبغي أن تضع نفسك بينما تنتظر وصول المستجيبين للطوارئ ومركز CHEMTREC؟","options":["في اتجاه الريح من المقطورة مباشرة لكي تتمكن من مراقبة البرميل المتسرب عن كثب","بجانب أبواب الحمولة مباشرة لكي تتمكن من تسليم مستندات الشحن للمستجيبين بسرعة","أسفل الانسكاب على المنحدر لكي ينصرف السائل المتسرب بعيداً عن مكان وقوفك","عكس اتجاه الريح من المركبة وعلى مسافة آمنة بعيداً عن الحمولة المتسربة"],"explanation":"في حالة طوارئ المواد الخطرة، ابقَ عكس اتجاه الريح وعلى مسافة آمنة لكي تهبّ الأبخرة بعيداً عنك بدلاً من أن تتجه نحوك."},"119":{"q":"أنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة عندما يبدأ أحد البراميل بالتسرب وتبدأ الأبخرة بالانتشار على طول الكتف. حذّرت الآخرين بالفعل، وأبقيت الناس بعيدين، وأوقفت أي تدخين قريب. الآن أحتاج إلى توجيه فني متخصص حول كيفية التعامل مع هذه المادة الكيميائية تحديداً. بمن ينبغي أن أتصل للحصول على تلك المساعدة المتخصصة؟","options":["مركز CHEMTREC أو المستجيبون المحليون للطوارئ، الذين يمكنهم تقديم توجيه متخصص في مناولة المواد الكيميائية","مكتب توزيع الناقل التابع لي، لأن الناقل هو الملزَم بمعالجة الإبلاغ عن الحادث","الشاحن الذي صنّف البراميل وعبّأها، لأنه هو من أعدّ مستندات الشحن","لا أحد عبر الهاتف — فدليل الاستجابة للطوارئ وحده يغطي كل خطوة أحتاج إلى اتخاذها"],"explanation":"للحصول على توجيه متخصص فوري حول مناولة مادة كيميائية متسربة، اتصل بمركز CHEMTREC أو المستجيبين المحليين للطوارئ."},"120":{"q":"أنت تنقل حمولة تحمل لافتات تحذيرية من سائل قابل للاشتعال على طريق سريع ريفي في تكساس عندما تلاحظ ألسنة لهب تخرج من أسفل مقطورتك. تنحرف إلى الكتف والحريق ينتشر بوضوح. لديك طفاية حريق مصنّفة للحرائق الصغيرة، لكن اللهب يصل بالفعل إلى منطقة الحمولة. ماذا ينبغي أن تفعل أولاً؟","options":["تفتح أبواب المقطورة لفحص الحمولة وتسمح للحرارة والدخان بالتنفيس قبل أن يكبر الحريق","تبتعد مسافة آمنة عن المركبة، ثم تتصل بالمستجيبين للطوارئ وتُبلغ مركز CHEMTREC","تُفرغ طفاية الحريق على ألسنة اللهب في منطقة الحمولة وتبقى قريباً تحسّباً لاشتعال النار مجدداً","تبقى عند المقصورة وتُبقي المحرك يعمل لكي تتمكن من إبعاد الشاحنة عن اللهب المنتشر"],"explanation":"لا تكافح حريق حمولة المواد الخطرة بمفردك أبداً؛ ابتعد مسافة آمنة عن المركبة، ثم اتصل بالمستجيبين للطوارئ وأبلغ مركز CHEMTREC."},"121":{"q":"أنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة عندما ألاحظ سائلاً يقطر من برميل ويتجمّع تحت مقطورتي في منطقة استراحة. أبعدت الناس بالفعل، وأوقفت التدخين، وأبلغت المستجيبين للطوارئ. أي إجراء هو الشيء الوحيد الذي ينبغي أن أفعله بخصوص تحريك المركبة المتسربة؟","options":["أقودها ببطء إلى أقرب محطة توقف للشاحنات لكي يُعيد ميكانيكي إغلاق البرميل المتسرب","أُعيد وضعها بعيداً بما يكفي فقط لإخلاء منحدر مخرج منطقة الاستراحة","أتركها حيث هي ما لم يوجّهني مسؤول إلى تحريكها لحماية الأرواح","أنقلها من الموقف بسرعة لإبعاد الانسكاب عن الشاحنات الأخرى المتوقفة"],"explanation":"لا تُحرّك أبداً مركبة مواد خطرة متسربة بناءً على تقديرك الشخصي؛ اتركها في مكانها ما لم يوجّه مسؤول بتحريكها لحماية الأرواح."},"122":{"q":"أنقل مواد أكّالة تحمل لافتات تحذيرية عندما ألاحظ منتجاً يتسرب من برميل ويتجمّع على الكتف حيث انحرفت وتوقفت. لديّ دليل الاستجابة للطوارئ وهاتف. أيٌّ من هذه ينبغي أن يكون أولويتي الأولى بينما أنتظر المستجيبين للطوارئ؟","options":["أهيل التراب والحصى السائب فوق البركة لكي تمتص المادة الأكّالة وتتوقف عن التحرك","أغسل الانسكاب بالماء لتخفيفه ودفعه إلى الخندق وبعيداً","أُشعل مثلثات عاكسة حول البركة وأضع شعلة عكس اتجاه الريح لتعليم التسرب","أُبقي المارة بعيدين عن المنطقة وأعمل على منع التسرب من الانتشار أكثر"],"explanation":"في حادث مواد خطرة، أبقِ الناس بعيدين واحتوِ الانسكاب من الانتشار حتى يصل المستجيبون المدرّبون للطوارئ؛ لا تحاول التنظيف بنفسك."},"123":{"q":"أنقل حمولة مواد خطرة تحمل لافتات تحذيرية عندما يندلع حريق تحت مقطورتي في محطة استراحة. قبل أن أتصرف أو أتحدث مع طاقم الإطفاء المستجيب، ما الاستخدام الصحيح لمستندات الشحن ودليل الاستجابة للطوارئ (ERG)؟","options":["لتحديد المادة التي أحملها بالضبط والمخاطر المحددة التي تشكّلها لكي يستطيع المستجيبون التصرف بأمان","لإثبات للناقل أن الشحنة حُمّلت ووُثّقت بشكل صحيح قبل الرحلة","للعثور على أقرب مسار معتمد لركن المواد الخطرة لكي أتمكن من نقل المقطورة المحترقة خارج الموقع","لتأكيد أن الحمولة تزن 1,001 رطل أو أكثر وبالتالي تتطلب لافتات تحذيرية قانونياً"],"explanation":"تُحدد مستندات الشحن ودليل ERG المادة بالضبط ومخاطرها المحددة لكي تتمكن أنت والمستجيبون للطوارئ من التصرف بأمان."},"124":{"q":"انشقّ برميل على مقطورتك التي تحمل لافتات تحذيرية ويتسرب على الكتف. لقد انحرفت وتوقفت بالفعل، ووضعت مثلثاتك العاكسة، وتُبقي المارة بعيدين بينما تنتظر المستجيبين للطوارئ. يُشعل أحد المارة سيجارة، ويسأل سائق آخر توقف للمساعدة إن كان من المقبول أن يدخّن بسرعة بما أنهم يقفون خلف شاحنتك جيداً. ما الإجراء الصحيح بخصوص التدخين في هذا الحادث؟","options":["تسمح بتدخينة سريعة ما دام الجميع يبقون على بُعد 25 قدماً على الأقل خلف المقطورة المتسربة","تمنع التدخين تماماً وتطلب من كل من حولك إطفاء أي سيجارة على الفور","تسمح بالتدخين فقط للسائق الذي توقف للمساعدة، لأن المساعدين معفون من القاعدة","تسمح بالتدخين فقط في الجهة المعاكسة لاتجاه الريح، بعيداً عن مكان تسرّب المنتج على الكتف"],"explanation":"التدخين غير مسموح به أبداً في حادث مواد خطرة لأن المنتج المتسرب أو أبخرته قد تكون قابلة للاشتعال، لذا يجب إيقاف أي لهب أو جمرة على الفور."},"125":{"q":"أنقل حمولة تحمل لافتات تحذيرية من المواد الأكّالة عندما تنفجر حاوية ويبدأ المنتج بالتسرب على كتف طريق سريع ريفي. بعد أن حذّرت الآخرين، وأبقيت الناس بعيدين عن الانسكاب، ومنعت أي شخص من التدخين قريباً، يتطلب القانون الإبلاغ عن الحادث. لمن يجب الإبلاغ عن هذا الحادث كما هو مطلوب؟","options":["إلى الشاحن فقط، لأنه صنّف الحاوية وعبّأها وأعدّ مستندات الشحن وبالتالي هو الطرف المسؤول عما بداخلها","إلى لا أحد، ما دمت أحتوي التسرب شخصياً، وأبرّد المنطقة، وأوثّق الضرر بالصور قبل أن أتابع نحو نقطة التسليم","إلى الجهات المختصة، مثل المستجيبين للطوارئ أو مركز CHEMTREC، مع تولّي الناقل تقديم تقرير الحادث المطلوب إلى الجهات المعنية","إلى أقرب محطة أخبار أو راديو محلية فقط لكي يُحذَّر السائقون الآخرون في المنطقة من تجنّب المقطع المتأثر من الطريق"],"explanation":"أبلغ الجهات المختصة مثل المستجيبين للطوارئ أو مركز CHEMTREC، بينما يقدّم الناقل تقرير الحادث المطلوب إلى الجهات المعنية."},"126":{"q":"أنت تنقل حمولة سائل قابل للاشتعال تحمل لافتات تحذيرية عبر المدينة، ويقترح عليك نظام تحديد المواقع (GPS) طريقاً سريعاً يمر عبر نفق طويل على الطريق السريع ومنطقة وسط مدينة مكتظة لتوفير 20 دقيقة. أي خيار يتبع على أفضل وجه ممارسات تخطيط مسار المواد الخطرة الآمنة؟","options":["اسلك طريق النفق ووسط المدينة، لأنه الأقصر ويوفر أكبر قدر من الوقت","ابقَ على الطريق ولكن تخطَّ محطة الوزن المطلوبة لتجنب لفت الانتباه إلى الحمولة","اسلك الطريق ولكن خطط للتوقف داخل منطقة وسط المدينة لإعادة فحص لافتاتك التحذيرية","ارفض ذلك الطريق واختر مساراً يتجنب النفق ومنطقة وسط المدينة المكتظة بالسكان"],"explanation":"عند تخطيط مسار المواد الخطرة، تجنب الأنفاق والمناطق المكتظة بالسكان لأن أي تسرب أو حريق هناك يضاعف الخطر على العامة."},"127":{"q":"أنا أنقل حمولة سائل قابل للاشتعال تحمل لافتات تحذيرية عبر مقاطعة ريفية في تكساس على طريق به عدة أنواع من المعابر. للالتزام بقواعد المواد الخطرة الخاصة بإدارة السلامة العامة (DPS)، عند أيٍّ من التالي يُطلب مني إيقاف مركبتي توقفاً تاماً قبل المتابعة؟","options":["معبر سكة حديد، حيث يجب أن أتوقف على مسافة 15 إلى 50 قدماً قبل أقرب قضيب","إشارة تحذير صفراء وامضة عند تقاطع ريفي رباعي الاتجاهات","محطة وقود مفتوحة، قبل الدخول لملء خزان الديزل","كل ممر خاص ومدخل حقل أمر به على طول الطريق"],"explanation":"يجب على المركبة التي تحمل لافتات تحذيرية أن تتوقف توقفاً تاماً على مسافة 15 إلى 50 قدماً قبل أقرب قضيب عند معبر السكة الحديد وألا تبدل التروس أبداً أثناء العبور."},"128":{"q":"أنا أنقل حمولة متفجرات من الشعبة 1.2 تحمل لافتات تحذيرية عبر تكساس وأحتاج إلى التوقف سريعاً لتناول الغداء. لا يوجد سائق مرافق معي. بموجب قواعد إدارة السلامة العامة (DPS)، ما الذي يُطلب مني فعله بهذه الحمولة؟","options":["يمكنني ترك الشاحنة متوقفة ومقفلة في ساحة المطعم بينما أتناول الطعام في الداخل، طالما أن الأبواب مؤمَّنة","يجب أن أُبقي حمولة المتفجرات تحت المراقبة في جميع الأوقات، لذا لا يمكنني تركها دون مراقبة بينما أدخل لتناول الطعام","يمكنني تركها دون مراقبة في التوقفات القصيرة طالما أنني أركن على بعد أكثر من 300 قدم من أي مبنى","يمكنني تركها دون مراقبة إذا أطفأت المحرك وشددت فرامل الركن قبل المغادرة"],"explanation":"يجب ألا تُترك متفجرات الشعب 1.1 و1.2 و1.3 دون مراقبة أبداً؛ على السائق أو مراقب مؤهل البقاء مع المركبة في جميع الأوقات."},"129":{"q":"أنا أنقل حمولة سائل قابل للاشتعال تحمل لافتات تحذيرية وأحتاج إلى التوقف لقضاء الليل. أمامي ألمح نار معسكر على جانب الطريق تركها أحدهم مشتعلة قرب منطقة استراحة. قبل أن أختار مكاناً للركن، ما الحد الأدنى للمسافة التي يطلب الدليل مني الإبقاء عليها بين مركبتي التي تحمل لافتات تحذيرية وتلك النار المكشوفة؟","options":["على الأقل 25 قدماً، وهي المسافة نفسها المطلوبة لمنع التدخين قرب الحمولة","على الأقل 50 قدماً، بما يطابق أقصى مسافة توقف قبل سكك القطار","على الأقل 300 قدم بين المركبة والنار المكشوفة","لا توجد مسافة محددة مطلوبة طالما أن المحرك مطفأ"],"explanation":"يجب ركن المركبة التي تحمل لافتات تحذيرية على بعد 300 قدم على الأقل من أي نار مكشوفة لأن اللهب المكشوف خطر اشتعال مباشر على الحمولة."},"130":{"q":"أنا أنقل حمولة مواد خطرة تحمل لافتات تحذيرية على طريق سريع بين الولايات غير مألوف عندما يعيد نظام تحديد المواقع (GPS) توجيهي إلى طريق لم أقده من قبل. على طول هذا المقطع سأمر بمحطة شاحنات مزدحمة، ومحطة وزن مفتوحة، وممر طويل تحت الأرض محفور عبر جبل. أي من هذه يُرجح أكثر أن أُمنع قانونياً من دخوله بحمولة المواد الخطرة، ما يجبرني على إيجاد طريق بديل؟","options":["محطة الشاحنات، لأن المركبات التي تحمل لافتات تحذيرية لا يمكنها الركن حيث يتجمع العامة","محطة الوزن المفتوحة، لأن حمولات المواد الخطرة يجب أن تتجاوز كل موازين التفتيش","لا شيء هنا مقيّد، لأن طريقاً بين الولايات معلناً يسمح دائماً بالمواد الخطرة","الممر تحت الأرض، لأن بعض المواد الخطرة ممنوعة من أنفاق معينة"],"explanation":"تجنب الأنفاق على مسار المواد الخطرة لأن السلطات يمكنها قانونياً منع مواد خطرة معينة من أنفاق محددة منعاً تاماً."},"131":{"q":"أنا أنقل حمولة مواد أكّالة تحمل لافتات تحذيرية عبر المدينة عندما أصطدم بأعمال إنشاء غير متوقعة على الطريق السريع أغلقت مسارين وكدّست حركة المرور لأميال على مسار المواد الخطرة المخصص لي. تشير لافتة تحويل نحو طريق أقصر عبر منطقة الأعمال في وسط المدينة، ويقترح نظام تحديد المواقع (GPS) طريقاً مختصراً أسرع فوق جسر منخفض. أي خيار ينبغي أن يوجه قيادتي؟","options":["ابقَ على مسار المواد الخطرة المخصص أو المطلوب، واعثر على طريق العودة إليه بمجرد أن تسمح ظروف الطريق","اسلك تحويل وسط المدينة لأن اتباع لافتات التحويل المعلنة يتجاوز دائماً قواعد توجيه المواد الخطرة","اتبع الطريق المختصر لنظام تحديد المواقع فوق الجسر المنخفض لأنه يوفر أكبر قدر من الوقت ويتجنب أسوأ الازدحام","اختر أي طريق أقصر مادياً، لأن القانون يطلب فقط تقليل إجمالي الأميال المقطوعة"],"explanation":"يجب على سائقي المواد الخطرة اتباع المسار المخصص أو المطلوب والعودة إليه بمجرد أن تسمح ظروف الطريق، بغض النظر عن الطرق المختصرة أو الازدحام."},"132":{"q":"أنا أنقل حمولة تحمل لافتات تحذيرية وأحتاج إلى التوقف للرد على مكالمة هاتفية ومد ساقيّ لبضع دقائق. أربعة أماكن في متناولي خارج مساري. أيها ينبغي أن أتجنب اختياره مكاناً للركن؟","options":["منطقة جانبية واسعة مغطاة بالحصى على مقطع ريفي لا تظهر فيه أي منشآت","الرصيف المجاور مباشرة لمدخل نفق حيث يتجمع المشاة","ساحة محطة شاحنات محددة بعيدة جيداً عن المدخل الرئيسي للمبنى","كتف طريق بجانب حقل مكشوف على بعد أكثر من 5 أقدام من الطريق المسلوك"],"explanation":"يجب إبقاء الحمولات التي تحمل لافتات تحذيرية بعيداً عن الأنفاق والجسور والحشود، لذا فإن مدخل نفق يتجمع عنده المشاة يجمع بين خطرين يجب تجنبهما."},"133":{"q":"أنت تنقل متفجرات من الشعبة 1.2 ومؤشر الوقود لديك منخفض، فتدخل محطة شاحنات للتزود بالوقود. أثناء امتلاء الخزان، أي من التالي يلبي على أفضل وجه مسؤولياتك تجاه هذه الحمولة؟","options":["اترك المحرك دائراً عند المضخة لتتمكن من إكمال التعبئة والانطلاق سريعاً، ثم ادخل للدفع","اركن بجوار مدخل المتجر المزدحم تماماً تحت الأضواء كي تبقى المقطورة المحمَّلة على مرأى الموظفين","ابقَ مع المركبة طوال الوقت وأبقها بعيدة عن الحشود وأماكن التجمع","أقفل المقصورة، واترك الشاحنة عند المضخة، وادخل لتناول القهوة بينما ينهي الإيقاف التلقائي التعبئة"],"explanation":"لا يجوز ترك متفجرات الشعب 1.1 و1.2 و1.3 دون مراقبة أبداً، لذا يجب على السائق البقاء مع المركبة وإبقائها بعيدة عن الحشود وأماكن التجمع."},"134":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة A وقد عُيّنت للتو لنقل حمولات سائل أكّال تحمل لافتات تحذيرية. يقول صديقي إن كل ما عليّ فعله قبل أن أبدأ قانونياً هو اجتياز اختبار تحريري سريع في مكتب إدارة السلامة العامة (DPS) لإضافة المصادقة. أي من التالي هو المتطلب الوحيد الذي لا يمكنني تخطيه للحصول على مصادقة المواد الخطرة (H) التي أحتاجها؟","options":["إتمام اختبار قيادة على الطريق تحديداً بمقطورة صهريج تحمل لافتات تحذيرية","حيازة المصادقة لمدة 30 يوماً على الأقل قبل نقل أي حمولة تحمل لافتات تحذيرية","تجديد شهادتي الطبية لوزارة النقل (DOT) خلال الأسبوع نفسه الذي أضيف فيه المصادقة","اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA)، بما في ذلك فحص الخلفية وأخذ البصمات"],"explanation":"تتطلب مصادقة المواد الخطرة اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA) يشمل فحص الخلفية وأخذ البصمات، وليس مجرد اختبار تحريري."},"135":{"q":"أنا أنقل حمولة سائل قابل للاشتعال تحمل لافتات تحذيرية وأحتاج إلى التوقف سريعاً عند مطعم على جانب الطريق لتناول الغداء. أي من الإجراءات التالية يضعني في مخالفة لقواعد المواد الخطرة؟","options":["ترك المركبة التي تحمل لافتات تحذيرية دون مراقبة في الساحة بينما أجلس داخل المطعم لتناول الطعام","الاحتفاظ بأوراق الشحن في جيب الباب في متناول اليد أثناء الركن","فحص الإطارات قبل العودة إلى الطريق السريع","الركن على بعد أكثر من 5 أقدام من الجزء المسلوك من الطريق"],"explanation":"يجب ألا تُترك المركبة التي تحمل لافتات تحذيرية للمواد الخطرة دون مراقبة أبداً، لذا فإن الابتعاد عن الشاحنة بينما تكون الحمولة دون مراقبة مخالفة محظورة."},"136":{"q":"أنا أنقل حمولة مواد أكّالة تحمل لافتات تحذيرية وأتوقف ليلاً في محطة شاحنات. عندما أعود إلى شاحنتي في الصباح لأبدأ فحص أثناء الطريق، أي من الملاحظات التالية ينبغي أن يقلقني أكثر باعتباره مشكلة أمنية دُرّبت تحديداً على مراقبتها؟","options":["تشكّلت طبقة رقيقة من الصقيع على الزجاج الأمامي خلال الليل","قُطع ختم بضاعة وتبدو إحدى اللافتات التحذيرية مقشّرة جزئياً للخلف","يقرأ مؤشر الوقود قراءة أقل قليلاً من الليلة السابقة","تركن الآن شاحنة أخرى في المكان المجاور لشاحنتي"],"explanation":"إن قطع ختم البضاعة ولافتة تحذيرية مقشّرة جزئياً للخلف علامتان كلاسيكيتان على العبث أو السرقة دُرّب سائقو المواد الخطرة على مراقبتهما."},"137":{"q":"عُيّنت للتو من قبل شركة نقل تنقل حمولات مواد خطرة تستلزم لافتات تحذيرية، وأثناء التوجيه يسلمني المرسل مجلداً من مستندات الشركة ويقول إن القواعد الفيدرالية تلزم العديد من شركات النقل مثل شركتنا بالاحتفاظ بأحد هذه المستندات مكتوباً في الملف. أي مستند يُرجح أنه يشير إليه باعتباره متطلباً تنظيمياً؟","options":["جدول مكتوب للغداء واستراحات التوقف اليومية يجب أن يوقّعه كل سائق قبل مغادرة الساحة","قائمة مكتوبة بمحطات الوقود المفضلة للشركة المعتمدة للمركبات التي تحمل لافتات تحذيرية","خطة أمنية مكتوبة تتناول كيفية حماية الشركة من سرقة المواد الخطرة وإساءة استخدامها","سجل مكتوب بالمحطات الإذاعية التي يجوز للسائقين الاستماع إليها أثناء نقل الحمولة"],"explanation":"يجب على العديد من شركات النقل التي تنقل مواد خطرة وضع خطة أمنية مكتوبة والاحتفاظ بها، تشمل العاملين، والوصول غير المصرح به، والأمن أثناء الطريق."},"138":{"q":"إنه فصل الشتاء ومقطورتي مزودة بسخان بضاعة تلقائي. قبل أن أغادر المحطة، يسلمني المرسل حمولة ويطلب مني إبقاء البضاعة دافئة أثناء الطريق. من بين الحمولات التالية، مع أي واحدة يجب أن أمتنع تماماً عن تشغيل سخان البضاعة؟","options":["حمولة صندوق جاف مغلق من الأطعمة المعلبة قد تتجمد في البرد","مقطورة فارغة أعيد توزيعها إلى نقطة الاستلام التالية","حمولة على منصات نقالة من مياه الشرب المعبأة الحساسة للتجمد","حمولة براميل سائل قابل للاشتعال تطلق أبخرة عند تسخينها"],"explanation":"يجب عدم استخدام سخان البضاعة مع حمولات السوائل القابلة للاشتعال لأن الأبخرة التي تطلقها عند تسخينها يمكن أن تشتعل، ما يسبب حريقاً أو انفجاراً."},"139":{"q":"عندما تكتشف عبوات مواد خطرة تالفة أو متسربة، ينبغي عليك:","options":["تحميلها على أي حال","عدم قبولها أو نقلها","لصقها بشريط بسرعة لإغلاقها","إخفاؤها في الخلف"],"explanation":"لا تقبل أو تنقل العبوات المتسربة أو التالفة."},"140":{"q":"أنا أحمّل شحنة تستلزم لافتات تحذيرية، وتُدرج أوراق الشحن بنداً صنّفته شركة النقل التابع لها على أنه مادة \"محظورة\" بموجب لوائح المواد الخطرة. قبل أن أوقّع على الحمولة، أي عبارة تخبرني بشكل صحيح ما هو التزامي بشأن هذا البند؟","options":["يجب ألا أنقل هذه المادة على الإطلاق، لأن المواد المحظورة لا يجوز نقلها أبداً على أي مركبة تحت أي ظرف.","يمكنني نقلها طالما أعرض اللافتات التحذيرية الصحيحة على الجوانب الأربعة جميعها وأبقي الأوراق في متناول اليد.","يمكنني نقلها فقط إذا بقي وزنها الإجمالي المجمّع أقل من 1,001 رطل للرحلة.","يمكنني نقلها بمجرد أن يضيف الشاحن اسم الشحن الصحيح وفئة الخطر ورقم التعريف إلى الأوراق."],"explanation":"لا يجوز نقل المواد المحظورة أبداً تحت أي ظرف، لذا فإن الإجراء الصحيح الوحيد هو رفض نقلها على الإطلاق."},"141":{"q":"أنا أجهّز حمولة ويخبرني الشاحن أن جزءاً منها يُصنَّف كشحنة \"كمية محدودة\". قبل أن أوقّع عليها، أي من التالي ينبغي أن أتوقع أن يكون صحيحاً بشأن ذلك الجزء من الحمولة؟","options":["لأنها فئة خاصة، فهي معفاة من كل قواعد المواد الخطرة ويمكنني نقلها دون أي أوراق","تتضمن كميات أصغر من المادة، لذا تحمل متطلبات تعبئة ووسم مخففة","تتطلب دائماً أقصى عدد من اللافتات التحذيرية على الجوانب الأربعة جميعها بغض النظر عن الوزن","ينطبق المصطلح فقط على السوائل، لذا فإن أي مواد صلبة في الحمولة لا يمكن أن تكون كمية محدودة"],"explanation":"تُشحن الكمية المحدودة بكميات أصغر تقل عن حدود معينة، ولهذا تتأهل لمتطلبات تعبئة ووسم مخففة."},"142":{"q":"أنا أقوم بفحص ما قبل الرحلة لحمولة مواد خطرة وأفتح الجزء الخلفي لمقارنة كل صندوق بأوراق الشحن. ختم الشاحن وعبّأ كل شيء، لكنني ما زلت بحاجة إلى تأكيد ما يفترض أن يحمله كل عبوة على حدة. لمطابقة الصناديق باسم الشحن الصحيح وفئة الخطر ورقم التعريف على أوراقي، ما الذي ينبغي أن أتوقع وجوده مطبوعاً على كل عبوة نفسها؟","options":["نسخة من أوراق الشحن ملصقة بكل صندوق كي تنتقل العبوة والأوراق معاً دائماً","اسم شركة النقل واسمي الكامل، كي يعرف المستجيبون أي سائق وأي شركة تنقل الحمولة","ملصق خطر ووسوم تحدد المادة، كي أتمكن من التحقق من العبوة مقابل البنود على أوراق الشحن","بطاقة سعر تجزئة بتكلفة المنتج، كي يؤكد المستلم قيمة الشحنة عند التسليم"],"explanation":"يضع الشاحن على كل عبوة ملصقات ووسوماً بفئة خطرها واسم شحنها كي تتمكن من المطابقة المرجعية لكل عبوة مع أوراق الشحن."},"143":{"q":"أنا أحمّل شحنة مواد مشعة من الفئة 7 ويراجع الشاحن معي ملصقات العبوات قبل أن أوقّع على الأوراق. يشير إلى رقم مطبوع على الملصق سأحتاج إلى مراعاته عندما أحسب كم من هذه المادة يمكن أن يوضع في مقطورتي معاً. أي من التالي هو هذا الرقم الحاكم الذي قد تحمله العبوات المشعة؟","options":["تصنيف خطر السمية بالاستنشاق يعفي الحمولة من اللافتات التحذيرية بأي كمية","رمز تصريح يتيح للحمولة تجاوز محطات الوزن وقيود المسار","حد كمية يجب الإبلاغ عنها (RQ) يلغي الحاجة إلى أي وسوم على العبوة","حد لمؤشر النقل يقيّد كم يمكن نقله معاً"],"explanation":"تحمل عبوات الفئة 7 المشعة مؤشر نقل يتحكم حدّه في كم من المادة المشعة يمكن تحميله ونقله معاً."},"144":{"q":"أنا أحمّل شحنة تحمل لافتات تحذيرية تحددها أوراق الشحن على أنها مادة تفاعلية، وأقرر أين في المقطورة وكيف أخزّنها للرحلة. للتعامل معها بأمان، أي من التالي يجب أن أُبقي هذه المادة التفاعلية بعيدة عنه؟","options":["مصادر الحرارة، والماء أو الرطوبة، وأي مواد تفاعلية أخرى يجري نقلها","البطانيات أو الحشوات الدافئة الناعمة المستخدمة لتثبيت الحمولة أثناء النقل","أي مساحة كبيرة فارغة مكشوفة في المقطورة قد تنزلق فيها العبوة","التعرض المباشر للضوء الساطع جداً القادم عبر أبواب المقطورة"],"explanation":"يجب إبقاء المواد التفاعلية بعيدة عن الحرارة، والماء أو الرطوبة، والمواد التفاعلية الأخرى، لأن التلامس قد يثير تفاعلاً عنيفاً."},"145":{"q":"كُلّفت باستلام حمولة صهريج من النيتروجين السائل المبرّد، وهو سائل مبرّد جداً (كرايوجيني)، لرحلة طويلة. أثناء فحصي للمقطورة قبل قبول الشحنة، أي حالة تخبرني أن الحمولة يجري التعامل معها بشكل صحيح لهذا النوع من البضائع؟","options":["الصهريج مغلق تماماً بلا فتحة تهوية كي لا يستطيع البرد الهروب ويبقى المنتج مجمداً","يستخدم الصهريج معدات معزولة خاصة وله فتحة تهوية تعمل لتصريف الضغط المتراكم بأمان","وحدة تسخين صغيرة مثبتة داخل الصهريج لمنع السائل من تجميد الصمامات لإغلاقها","الصهريج ناقل سوائب جافة قياسي بلا تجهيزات إضافية لأن البرد لا يحتاج إلى عناية خاصة"],"explanation":"تمتص السوائل المبرّدة (الكرايوجينية) الحرارة باستمرار وتبني ضغطاً، لذا تتطلب معدات معزولة خاصة وفتحة تهوية تعمل لتصريف ذلك الضغط بأمان."},"146":{"q":"تنقلب مقطورتي التي تحمل لافتات تحذيرية على طريق سريع ريفي في تكساس ويبدأ أحد البراميل بالتسرب. يصل أول طاقم إطفاء قبل أن أتمكن من قول الكثير، يمسك بأوراق الشحن خاصتي، ويقرأ فوراً فئة الخطر ورقم تعريف الأمم المتحدة/أمريكا الشمالية (UN/NA) المدرج للحمولة. ما السبب الرئيسي الذي يجعل فئة الخطر ورقم التعريف بهذه الأهمية لأولئك المستجيبين في موقع الحادث؟","options":["تتيح لهم حساب ما إذا كانت حمولتي تتجاوز عتبة 1,001 رطل التي استلزمت اللافتات التحذيرية في المقام الأول","تثبت أنني، السائق، قد اتصلت بالفعل بـ CHEMTREC وأن شركة النقل قدّمت تقرير الحادث قبل وصول المساعدة","تتيح للمستجيبين تحديد ماهية الخطر بدقة وبسرعة كي يتعاملوا مع المادة بشكل صحيح","تؤكد أن اللافتات التحذيرية كانت مثبتة على الجوانب الأربعة جميعها وقابلة للقراءة من الاتجاه الذي تواجهه"],"explanation":"يتيح اسم الشحن الصحيح وفئة الخطر ورقم التعريف للمستجيبين للطوارئ تحديد الخطر بدقة وبسرعة والتعامل مع المادة بشكل صحيح."},"147":{"q":"إذا كنت غير متأكد من معنى لافتة تحذيرية، ينبغي عليك:","options":["التخمين والمتابعة في القيادة","التحقق من أوراق الشحن ودليل الاستجابة للطوارئ (ERG)","إزالة اللافتة التحذيرية","تجاهلها تماماً الآن"],"explanation":"تحقق من أوراق الشحن ودليل الاستجابة للطوارئ (ERG)."},"148":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة A في تكساس وأنقل بضائع جافة منذ عامين. الشهر القادم تريد مني شركة النقل أن أبدأ بسحب حمولات تستلزم لافتات تحذيرية على الجوانب الأربعة جميعها للمقطورة. قبل أن أتمكن قانونياً من قبول تلك الرحلة الأولى التي تحمل لافتات تحذيرية، ما الذي يجب أن أكمله؟","options":["لا شيء إضافي — رخصة الفئة A وحدها تخوّل بالفعل أي حمولة مواد خطرة تحمل لافتات تحذيرية","فقط مصادقة الصهريج (N)، لأن البضائع التي تحمل لافتات تحذيرية تُنقل في صهاريج سائبة","فقط مصادقة المقطورات المزدوجة/الثلاثية (T) لتغطية وزن المقطورة الإضافي","مصادقة المواد الخطرة (H)، التي تتطلب اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA) مع أخذ البصمات"],"explanation":"يتطلب نقل كمية تستلزم لافتات تحذيرية من المواد الخطرة مصادقة المواد الخطرة (H)، التي لا تُصدر إلا بعد اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA) مع أخذ البصمات."},"149":{"q":"استلمت للتو حمولة مواد أكّالة تحمل لافتات تحذيرية. أوراق الشحن بها خطأ في فئة الخطر، وألاحظه قبل أن أغادر المحطة. يقول لي المرسل: \"تلك الأوراق هي مشكلة الشاحن بنسبة 100% — وظيفتك الوحيدة هي القيادة.\" بموجب قواعد المواد الخطرة، أي عبارة صحيحة؟","options":["النقل الآمن مسؤولية مشتركة — للشاحن وشركة النقل والسائق كلٌّ منهم واجبات محددة، ويجب ألا أنقل عن علم شحنة مُوسومة بشكل غير صحيح.","لأن الشاحن وحده يصنّف ويُعِدّ الأوراق، فإن السائق لا يتحمل أي مسؤولية عن أخطاء الأوراق ويجوز له قانونياً نقل الحمولة كما هي.","بمجرد أن ترسل شركة النقل الحمولة، تنتقل المسؤولية القانونية الكاملة عن الشحنة إلى شركة النقل، لذا يمكن للسائق الاعتماد كلياً على الإرسال.","واجب السائق الوحيد هو القيادة الآمنة، لذا فإن دقة الأوراق هي مهمة الشاحن وحده وليست شيئاً يحتاج السائق إلى التحقق منه أبداً."],"explanation":"سلامة المواد الخطرة مسؤولية مشتركة بين الشاحن وشركة النقل والسائق، ويجب أن ترفض عن علم نقل شحنة متسربة أو مُوسومة بشكل غير صحيح."},"150":{"q":"أنا أستلم حمولة أسطوانات بروبان مضغوط ويسلمني مشرف الرصيف أوراق شحن تُظهر المادة على أنها فئة خطر 2. قبل أن أضع اللافتات التحذيرية، أريد تأكيد ما تمثله الفئة 2 فعلاً. أي عبارة صحيحة؟","options":["تغطي الفئة 2 المواد الأكّالة، مثل حمولات حمض البطاريات وهيدروكسيد الصوديوم التي أنقلها أحياناً.","تغطي الفئة 2 الغازات، بما في ذلك المواد القابلة للاشتعال وغير القابلة للاشتعال والغازات السامة مثل البروبان لديّ.","تغطي الفئة 2 المتفجرات، لذا تقع هذه الحمولة تحت القواعد نفسها للديناميت والألعاب النارية.","تغطي الفئة 2 المواد المشعة، ولهذا تحتاج هذه الأسطوانات إلى تدريع إضافي."],"explanation":"فئة الخطر 2 هي الغازات، مقسّمة إلى 2.1 قابل للاشتعال، و2.2 غير قابل للاشتعال، و2.3 غاز سام، والبروبان غاز قابل للاشتعال في هذه الفئة."},"151":{"q":"أنا أحمّل براميل من حمض البطاريات لأجل عملية تسليم، وأوراق الشحن تذكر أن فئة الخطر هي 8. قبل أن أضع لافتات التحذير على المقطورة، أحتاج إلى تأكيد نوع الخطر الذي تمثله هذه الحمولة فعليًا. أيٌّ مما يلي يصف بشكل صحيح ما هي مادة فئة الخطر 8؟","options":["غاز مضغوط أو مُسال يمكن أن يتسرب ويُسبب خطرًا على التنفس","مادة سامة يمكن أن تُسمم الشخص عبر ملامسة الجلد أو الاستنشاق","مادة أكّالة يمكن أن تحرق الجلد أو المعدن أو غيرها من المواد كيميائيًا","مادة متفجرة يمكن أن تنفجر بفعل الحرارة أو الصدمة أو الاحتكاك"],"explanation":"فئة الخطر 8 هي المواد الأكّالة، مثل حمض البطاريات، التي تحرق أو تأكل الجلد والمعدن وغيرها من المواد كيميائيًا."},"152":{"q":"أنا أحمّل مقطورتي عندما يسلّمني الشاحن أوراقًا لشحنة مُعلَّمة بـ«فئة الخطر 7» مع رقم UN والاسم الصحيح للشحن. قبل أن أضع لافتات التحذير، أحتاج إلى أن أفهم بالضبط نوع الخطر الذي أنقله. بناءً على نظام فئات الخطر، ماذا تخبرني الفئة 7 عن هذه الحمولة؟","options":["إنها مادة أكّالة، لذا قد تحرق الحاويات المتسربة الجلد وتأكل الأسطح المعدنية","إنها سائل قابل للاشتعال، لذا يجب أن أُبعد جميع مصادر الإشعال واللهب المكشوف عنها","إنها غاز مضغوط أو سام، لذا قد يُسبب تسرّب الضغط خطرًا على التنفس عند الاستنشاق","إنها مادة مشعّة، لذا أنا أنقل حمولة تُصدر إشعاعًا وتحتاج إلى مناولة خاصة"],"explanation":"فئة الخطر 7 تعني دائمًا المواد المشعّة، لذا فإن الحمولة تُصدر إشعاعًا وتحتاج إلى مناولة خاصة بغض النظر عن اسم الشحن المعروض."},"153":{"q":"أنا أحمّل مقطورة وأوراق الشحن لديّ تذكر مادة من فئة الخطر 5. قبل أن أضع لافتات التحذير، أريد تأكيد نوع الخطر الذي تمثله هذه الحمولة فعليًا. مادة الفئة 5 هي مادة:","options":["مؤكسِدة أو بيروكسيد عضوي يمكن أن تُكثّف الحريق عن طريق إطلاق الأكسجين","أكّالة يمكن أن تُدمّر نسيج الجلد أو تأكل الفولاذ والألمنيوم","متفجرة قادرة على انفجار شامل إذا تعرّضت للحرارة أو الصدمة","غاز مضغوط يمكن أن يكون قابلًا للاشتعال أو غير قابل للاشتعال أو سامًا"],"explanation":"مؤكسِدات فئة الخطر 5 والبيروكسيدات العضوية تُطلق الأكسجين، الذي يمكن أن يُشعل حريقًا أو يُكثّفه حتى من دون مصدر إشعال خارجي."},"154":{"q":"أنا أحمّل كمية صغيرة من مادة ذات خطر بالاستنشاق سام (PIH) عند الرصيف، والوزن الإجمالي أقل بكثير من 1,001 رطل. يخبرني المرسِل أن الحمولة خفيفة جدًا فأستطيع نقلها كأي شحنة بضائع عادية. أيٌّ مما يلي هو الطريقة الصحيحة للتعامل مع شحنة PIH هذه؟","options":["بما أن الحمولة أقل من 1,001 رطل، فلا يلزم وضع لافتات تحذير ويمكنني نقلها كبضائع عادية","يجب أن أتعامل معها بحذر إضافي وأعرض لافتات التحذير المناسبة، لأن مواد PIH تتطلب وضع لافتات التحذير بأي كمية","لا أحتاج إلى وضع لافتات التحذير إلا إذا عبرت حدود ولاية؛ حمولات PIH داخل الولاية الأقل من 1,001 رطل لا تحتاج إلى مناولة خاصة","ينبغي أن أُقلّل أوراقي وأتخطى أوراق الشحن لأن الكمية صغيرة جدًا"],"explanation":"مواد الخطر بالاستنشاق السام (PIH) هي خطر من الجدول 1 يجب وضع لافتات التحذير له بأي كمية، من دون أي حد أدنى للوزن."},"155":{"q":"أنا أحمّل مقطورتي بعدة صناديق من صنف تذكره ورقة الشحن تحت فئة الخطر 9. وهو ليس قابلًا للاشتعال، وليس أكّالًا، وليس غازًا مضغوطًا، ومع ذلك تطلّب لافتة تحذير. أيُّ عبارة تصف على نحوٍ أفضل ما تشمله فئة الخطر 9؟","options":["الغازات المضغوطة والمُسالة غير القابلة للاشتعال تحت الضغط","السوائل والمواد الصلبة الأكّالة التي يمكن أن تضرّ الجلد أو المعدن","المواد الخطرة المتنوعة التي لا تنطبق عليها الفئات الثماني الأخرى","المتفجرات التي تتراوح من عوامل التفجير إلى الألعاب النارية والمفجّرات"],"explanation":"فئة الخطر 9 هي الفئة الجامعة «المتنوعة» للمواد المنظَّمة التي تُشكّل خطرًا أثناء النقل لكنها لا تنطبق عليها الفئات من 1 إلى 8."},"156":{"q":"أنا أُجهّز أوراق الشحن لحمولة، والإدخال يُظهر فئة الخطر 4. قبل أن أضع لافتات التحذير، أريد تأكيد نوع المادة التي أنقلها فعليًا لكي آخذ لافتة التحذير الصحيحة. أيٌّ مما يلي يصف بشكل صحيح ما هي مادة الفئة 4؟","options":["سائل قابل للاشتعال مثل البنزين أو وقود الديزل","غاز مضغوط، سواء كان قابلًا للاشتعال أو غير قابل للاشتعال","مادة أكّالة يمكن أن تضرّ الجلد والمعدن","مادة صلبة قابلة للاشتعال يمكن أن تشتعل أو تحترق بسهولة"],"explanation":"تشمل فئة الخطر 4 المواد الصلبة القابلة للاشتعال، بما فيها المواد القابلة للاشتعال التلقائي والخطرة عند البلل، التي يمكن أن تشتعل أو تحترق بسهولة."},"157":{"q":"أنا أحمل لافتات تحذير وأتوقف عند محطة وزن في تكساس عندما يُشير مفتّش إلى رقم من 4 أرقام، 1203، معروض على لوحة برتقالية على مقطورتي ويسألني عمّا يخبره به هذا الرقم. أيٌّ هو الجواب الصحيح؟","options":["إنه رقم التعريف (UN/NA) الذي يُحدّد المادة المحددة التي أنقلها","إنه رمز الاسم الصحيح للشحن الذي خصّصته شركة النقل للحمولة","إنه رقم فئة الخطر الذي يُبيّن أيّ من الفئات التسع ينطبق","إنه رقم جدول لافتات التحذير الذي يُظهر ما إذا كانت قاعدة 1,001 رطل تنطبق"],"explanation":"الرقم المكوّن من 4 أرقام على أوراق الشحن أو على لافتة التحذير هو رقم التعريف UN/NA الذي يُحدّد المادة الدقيقة التي يجري نقلها."},"158":{"q":"أثناء فحصي قبل الرحلة، يطلب مني شرطي ولاية أن أقرأ له رقم التعريف UN/NA المكوّن من 4 أرقام للحمولة التي أنقلها لكي يتحقق منه في دليل الاستجابة للطوارئ. أمشي إلى جانب مقطورتي التي تحمل لافتات التحذير لأجده. من أين يُسمح لي قراءة رقم التعريف المكوّن من 4 أرقام بشكل صحيح؟","options":["فقط من الاسم الصحيح للشحن المطبوع على أوراق الشحن؛ فهو لا يظهر أبدًا على خارج المقطورة","إمّا معروضًا مباشرة على لافتة التحذير نفسها أو على لوحة برتقالية مثبّتة بجانب لافتة التحذير","فقط من رقم فئة الخطر المعروض في الزاوية السفلية للافتة التحذير المعيّنة","فقط من لوحة بيانات الشركة المصنّعة المختومة على إطار المقطورة قرب أرجل الاستناد"],"explanation":"يمكن عرض رقم التعريف UN/NA المكوّن من 4 أرقام إمّا في وسط لافتة التحذير نفسها أو على لوحة برتقالية مثبّتة بجانب لافتة التحذير."},"159":{"q":"عند فحص على جانب الطريق، يُشير ضابط إلى لافتة التحذير ذات الشكل المعيّن في مؤخرة مقطورتي ويطلب مني قراءة رقم فئة الخطر الذي يُحدّد ما أنقله. تُظهر لافتة التحذير رمزًا في الأعلى، وكلمات مكتوبة في الشريط الأوسط، ورقمًا واحدًا. أين على لافتة التحذير ينبغي أن أنظر لأجد رقم فئة الخطر هذا؟","options":["في وسط لافتة التحذير، تمامًا حيث يُطبع الاسم المكتوب للمادة","في القمة العليا للشكل المعيّن، مباشرة فوق رمز الخطر أو الصورة التوضيحية","في الزاوية السفلية للشكل المعيّن، أسفل الرمز والاسم المكتوب للمادة","على طول الحافة اليسرى أو اليمنى للشكل المعيّن، بجانب رمز الخطر"],"explanation":"على لافتة التحذير، يقع رقم فئة الخطر المكوّن من رقم واحد في الزاوية السفلية للشكل المعيّن، أسفل الرمز واسم الخطر المكتوب."},"160":{"q":"أنا أحمّل مقطورتي في محطة شحن بعدة طرود غير سائبة، كل منها من فئة خطر مختلفة من الجدول 2، ولا يبلغ أيٌّ منها بمفرده حد 1,001 رطل الذي يفرض لافتة تحذير منفصلة. بدلًا من تعليق لافتة تحذير مختلفة لكل فئة، أودّ استخدام لافتة «خطر» (DANGEROUS) واحدة للشحنة المختلطة كلها. تحت أيّ شرط يُسمح فعليًا باستخدام تلك اللافتة «خطر» الواحدة؟","options":["فقط عندما ينتمي كل طرد على المقطورة إلى الفئة المفردة نفسها بالضبط","فقط عندما لا تحمل المقطورة أي مادة خطرة منظَّمة على الإطلاق","فقط عندما تقتصر الحمولة على مواد غذائية استهلاكية مشحونة إلى جانب البضائع","عندما تحتوي الحمولة على فئتين أو أكثر مختلفتين من فئات الخطر في الجدول 2 يُنقلان معًا"],"explanation":"يمكن استخدام لافتة «خطر» (DANGEROUS) بدلًا من لافتات منفصلة عندما تجمع حمولة غير سائبة فئتين أو أكثر من فئات الخطر في الجدول 2."},"161":{"q":"أنا أحمّل برميلًا صغيرًا واحدًا من مادة من الجدول 1 (غاز سام من الشُّعبة 2.3) لأجل رحلة محلية قصيرة. الوزن الإجمالي للمادة الخطرة أقل بكثير من 1,000 رطل. قبل أن أنطلق، كيف يجب أن أضع لافتات التحذير على المركبة؟","options":["يجب أن أعرض لافتات التحذير على جميع الجوانب الأربعة بغض النظر عن قلّة ما أنقله، لأن مواد الجدول 1 تتطلب لافتات تحذير بأي كمية.","لا أحتاج إلى لافتات تحذير في هذه الرحلة، لأنني أنقل أقل من الوزن الإجمالي الكلي البالغ 1,001 رطل الذي يستوجب لافتات التحذير.","لا أحتاج إلى لافتات تحذير إلا عندما تبلغ حمولتي الخطرة المجمّعة 1,001 رطل أو أكثر، لذا فإن برميلًا صغيرًا واحدًا مُعفى.","لا أحتاج إلى لافتات تحذير إلا إذا كانت الرحلة بين الولايات أو تعبر منطقة مأهولة، لأن رحلة محلية قصيرة لا تتطلبها."],"explanation":"الغاز السام من الشُّعبة 2.3 مادة من الجدول 1 يجب وضع لافتات التحذير لها على جميع الجوانب الأربعة بأي كمية، بغض النظر عن الوزن."},"162":{"q":"أنا أحمّل مقطورة بضائع مختلطة، والمادة الخطرة الوحيدة على متنها هي منتج من الجدول 2. تُظهر أوراق الشحن لديّ أن الوزن الإجمالي الكلي يبلغ بالضبط 900 رطل. بموجب قواعد لافتات التحذير لدائرة السلامة العامة (DPS)، ماذا يجب أن أفعل قبل أن أنطلق؟","options":["أضع لافتات التحذير على جميع الجوانب الأربعة، لأن أي كمية من مادة خطرة مدرجة في الجدول 2 تستوجب دائمًا لافتات التحذير","لا يلزم وضع لافتات تحذير، لأن مواد الجدول 2 لا تحتاج إلى لافتات تحذير إلا عند بلوغ وزن إجمالي كلي قدره 1,001 رطل أو أكثر","أضع لافتات التحذير على جميع الجوانب الأربعة، لأن الحمولة فوق حد الإبلاغ البالغ 100 رطل لشحنات الجدول 2","أضع لافتة تحذير على المؤخرة فقط، لأن 900 رطل كافية لاستيجاب لافتات تحذير جزئية وليس على جميع الجوانب الأربعة"],"explanation":"تتطلب مواد الجدول 2 لافتات تحذير فقط عندما يبلغ وزنها الإجمالي الكلي 1,001 رطل أو أكثر."},"163":{"q":"أنا أحمّل مقطورة عند رصيف شاحن وألاحظ بطاقات تحذير الخطر ذات الشكل المعيّن التي وضعها الشاحن للدلالة على ما بالداخل. أين يُطلب عرض بطاقات تحذير الخطر هذه؟","options":["على جميع الجوانب الأربعة للمقطورة، بحيث تُقرأ من الاتجاه الذي يواجهه كل منها","على أوراق الشحن، في عمود المواد الخطرة (HM) بجانب كل إدخال","على الطرود والحاويات الفردية نفسها","في جيب باب السائق حيث تُحفظ الأوراق"],"explanation":"يضع الشاحن بطاقات تحذير الخطر مباشرة على كل طرد وحاوية فردية للدلالة على فئة خطر المحتويات."},"164":{"q":"أنا أحمّل شحنة من المواد الأكّالة تتطلب لافتات تحذير، ويسلّمني السائق المرافق أربع لافتات تحذير ذات شكل معيّن مكتوب عليها «أكّال» (CORROSIVE). يخبرني أين يظن أنها يجب أن توضع، لكنني أريد فعل ذلك بشكل صحيح قبل أن ننطلق. أين يجب فعليًا عرض لافتات التحذير هذه؟","options":["مثبّتة على كل طرد ولفافة خارجية فردية داخل المقطورة لكي يرى المفتّشون الخطر عند فتح الأبواب","مرفقة بأوراق الشحن في عمود المواد الخطرة (HM) بجانب الاسم الصحيح للشحن وفئة الخطر ورقم التعريف","مُثبّتة في جيب على باب السائق بجانب الأوراق لكي تبقى في متناولي أثناء القيادة","مثبّتة على جميع الجوانب الأربعة للمركبة، بحيث تُقرأ كل واحدة من الاتجاه الذي تواجهه"],"explanation":"تُعرض لافتات التحذير على جميع الجوانب الأربعة للمركبة، ويجب أن تكون كل واحدة قابلة للقراءة من الاتجاه الذي تواجهه."},"165":{"q":"أثناء تحميل مقطورتي، أمسك بطرد محكم الإغلاق مُعلّم بزوج من الأسهم السوداء العمودية المتجهة إلى أعلى على جانبين متقابلين. أوراق الشاحن سليمة، لكنني أريد التأكد من أنني أضعه بشكل صحيح. ماذا تتطلب مني أسهم التوجيه هذه أن أفعل بهذا الطرد؟","options":["إبقاء الطرد منتصبًا في كل الأوقات، مع توجيه الأسهم إلى أعلى، لكي تبقى السدادات في الأعلى","وضع الطرد على جانبه بحيث تُشير الأسهم أفقيًا نحو جدار المقطورة","تكديسه بأي وضع يناسب، لأن الأسهم تُبيّن فقط أين ينبغي للرافعة الشوكية أن ترفع","قلب الطرد رأسًا على عقب بحيث يستقر الطرف المغلق على أرضية المقطورة"],"explanation":"تعني أسهم توجيه الطرد أنه يجب إبقاء الطرد منتصبًا مع توجيه الأسهم إلى أعلى لكي تبقى السدادات في الأعلى."},"166":{"q":"أنا سائق مواد خطرة جديد أُجري مراجعتي قبل الرحلة لورقة الشحن لحمولة أكّالة. أستطيع أن أرى بوضوح الاسم الصحيح للشحن وفئة الخطر المدرجين لكل إدخال. لتأكيد أن الوصف كامل ومتوافق مع المتطلبات الفيدرالية قبل أن أنطلق، أيُّ معلومة متبقية يجب أن تظهر أيضًا في ذلك الوصف الأساسي للشحن؟","options":["إجمالي القيمة المعلنة بالدولار للبضائع الأكّالة","رقم التعريف (UN أو NA) للمادة","تصنيف الوزن الإجمالي للمركبة المبيَّن على رخصة القيادة التجارية (CDL)","تاريخ انتهاء صلاحية تصديق المواد الخطرة لديّ"],"explanation":"يُدرج الوصف الأساسي الكامل للشحن الاسم الصحيح للشحن وفئة الخطر ورقم التعريف UN أو NA بهذا الترتيب."},"167":{"q":"أنا أُراجع أوراق الشحن لحمولة وألاحظ رقمًا رومانيًا «II» مدرجًا بجانب إدخال المادة بوصفه مجموعة التعبئة الخاصة بها. يسألني سائق أحدث عمّا يخبرنا به ذلك «II» فعليًا عن الشحنة. أيٌّ مما يلي هو التفسير الصحيح لما تُشير إليه مجموعة التعبئة؟","options":["تذكر رقم فئة الخطر (من 1 إلى 9) المخصَّص للمادة","تُعطي الحد الأدنى للوزن الإجمالي الذي يستوجب متطلب لافتات التحذير","تُظهر الدرجة النسبية للخطر الذي تمثله المادة (I أو II أو III)","تُدرج رقم التعريف UN/NA الذي يلي اسم الشحن"],"explanation":"مجموعة التعبئة، المعروضة كرقم روماني I أو II أو III، تُشير إلى الدرجة النسبية للخطر الذي تمثله المادة."},"168":{"q":"أنا أحمّل شحنة مواد خطرة، وتُدرج ورقة الشحن مجموعة تعبئة المادة بأنها «PG I». يخبرني سائق أحدث أن الرقم الروماني «I» يعني فقط أنه أول صنف مدرج وأنه يمثل أدنى مستوى خطر من مجموعات التعبئة الثلاث. قبل أن أوقّع على استلام الحمولة وأضع لافتات التحذير، ماذا تخبرني «مجموعة التعبئة I» فعليًا عن درجة خطر هذه المادة؟","options":["تُشير إلى أدنى درجة خطر، لأن مجموعة التعبئة I هي المستوى الأدنى ومجموعة التعبئة III هي الأكثر خطورة","تُشير إلى درجة خطر متوسطة فقط، تأتي بين مجموعة التعبئة II ومجموعة التعبئة III","تُشير إلى عدم وجود خطر حقيقي وتُستخدم فقط لبيان موضع الصنف على ورقة الشحن","تُشير إلى أعلى درجة خطر، لأن مجموعة التعبئة I هي الأكثر خطورة بين مجموعات التعبئة الثلاث"],"explanation":"تُشير مجموعة التعبئة I إلى أعلى درجة خطر، لأنها الأكثر خطورة بين مجموعات التعبئة الثلاث."},"169":{"q":"أنا أحمّل مقطورة مواد خطرة مختلطة وألاحظ أن طردين من طرودي لهما فئتا خطر مختلفتان. قبل أن أكدّسهما جنبًا إلى جنب، أُخرج جدول الفصل. ماذا يخبرني هذا الجدول فعليًا؟","options":["أيُّ المواد غير متوافقة ويجب ألّا تُحمّل معًا في الحمولة نفسها","أيُّ المواد يجب أن تُحمّل دائمًا معًا لكي تتطابق لافتات تحذيرها","أيُّ المواد ينبغي بيعها أو تسليمها أولًا لتقليل مسؤوليتي","أيُّ المواد تحتاج إلى وضع بطاقات عليها مرة ثانية قبل أن أُغلق الأبواب"],"explanation":"يُبيّن جدول الفصل أيَّ المواد غير متوافقة ويجب ألّا تُحمّل معًا في الحمولة نفسها."},"170":{"q":"أنا عند رصيف الشاحن على وشك تحميل عدة براميل من مادة أكّالة من الفئة 8 على مقطورتي التي تحمل لافتات التحذير. وأنا أحرّك البرميل الأول، ألاحظ غشاءً رطبًا لامعًا حول حافة قاعدته وبركة صغيرة على المنصّة. قبل أن أُحمّل أيًّا من هذه الطرود، ما هو الشيء الأهم الوحيد الذي يجب أن يؤكّده فحصي قبل التحميل؟","options":["أن كل برميل مطلي بلون زاهٍ عالي الوضوح لكي يُرصد بسهولة في المقطورة","أن الطرود لا تتسرب ولا تالفة، لأنه يجب أن أرفض أي حاوية تُظهر تسربًا أو خرقًا","أن البراميل مكدّسة بأعلى ارتفاع ممكن لإبقاء الحمولة متراصة ومنع انزياحها أثناء النقل","أن السدادات متروكة مرتخية أو مفتوحة لكي يتنفّس الضغط الداخلي أثناء الرحلة"],"explanation":"قبل التحميل، افحص كل طرد للتأكد من أنه لا يتسرب ولا تالف، وارفض أي حاوية تُظهر تسربًا أو خرقًا."},"171":{"q":"أنا سائق أُحمّل سائلًا قابلًا للاشتعال (فئة 3) على مقطورتي في ساحة محطة مزدحمة. تجري عدة أمور حولي في الوقت نفسه، وأريد التحميل بأمان. أيٌّ مما يلي يجب أن أتأكد من إبعاده عن منطقة الشحن أثناء تحميل هذه المادة الخطرة؟","options":["رافعة منصّات يستخدمها طاقم الرصيف","شاحنة تسليم تعمل بالمحرّك في الرصيف المجاور","لهب مكشوف أو مصدر يُولّد الشرر","كومة من المنصّات الخشبية الفارغة"],"explanation":"أبعِد اللهب المكشوف ومصادر توليد الشرر عن المواد الخطرة أثناء التحميل، لأن المواد القابلة للاشتعال يمكن أن تشتعل من أي مصدر إشعال."},"172":{"q":"أنا أُحمّل عدة براميل وصناديق من مواد خطرة تحمل لافتات تحذير في شاحنتي الجافة لأجل رحلة طويلة بين الولايات. بعد أن أُدخلها إلى متن المقطورة، ماذا يجب أن أفعل بهذه الحاويات قبل أن أُغلق الأبواب وأنطلق؟","options":["أضعها بإحكام بمواجهة مقدمة المقطورة وأعتمد على الجدار الأمامي ليُثبّتها في مكانها أثناء الرحلة","أوزّعها بالتساوي على الأرضية بحيث يتوازن الوزن، ثم أترك احتكاك الأرضية العادي ليُبقيها مستقرة","أكدّسها بأعلى ارتفاع ممكن بمحاذاة أحد الجدران الجانبية لتوفير مساحة أرضية لبقية الحمولة","أُسنِد وأُثبّت كل حاوية بحيث لا يمكنها الانزياح أو الانزلاق أو الانقلاب أثناء حركة المركبة"],"explanation":"أُسنِد وأُثبّت كل حاوية مواد خطرة بحيث لا يمكنها الانزياح أو الانزلاق أو الانقلاب أثناء حركة المركبة."},"173":{"q":"أنا أنقل حمولة نفايات خطرة، ويسلّمني الشاحن بيان نفايات خطرة (manifest) إلى جانب بقية أوراقي قبل أن أُغادر المحطة. للبقاء متوافقًا مع قواعد المواد الخطرة، ماذا يجب أن أفعل بهذا البيان؟","options":["أُوقّعه وأحتفظ بنسخة منه مع أوراق الشحن في متناول يدي","أتركه موقَّعًا في المحطة لكي تُقدّمه شركة النقل نيابةً عني","أحمله غير موقَّع حتى يوقّعه المرفق المستلم عند التسليم","أُرسل النسخة الموقَّعة بالبريد إلى الوكالة الحكومية بعد انتهاء الرحلة"],"explanation":"يجب أن يوقّع السائق بيان النفايات الخطرة وأن يحتفظ به مع أوراق الشحن في متناول اليد أثناء القيادة."},"174":{"q":"أنا سائق جديد حاصل على تصديق المواد الخطرة (H)، ويسلّمني شاحن أوراقًا لمادة تُدرجها اللوائح تحديدًا بوصفها مادة لا يمكن نقلها بأي مركبة تجارية تحت أي ظرف من الظروف. قبل أن أفعل أي شيء آخر، ما هي الطريقة الصحيحة للتفكير في هذه الحمولة؟","options":["يمكن نقلها بأي كمية ما دمت أضع لافتات التحذير على جميع الجوانب الأربعة للمقطورة","إنها محظورة من النقل، لذا لا يجوز لأي سائق نقلها قانونيًا على الإطلاق","يمكن نقلها بحرية لأن تصديق H لديّ يغطّي كل فئات الخطر","إنها لا تحتاج أبدًا إلى لافتات تحذير، لذا يمكنني نقلها من دون إبلاغ أي أحد"],"explanation":"بعض المواد خطرة لدرجة أنها محظورة من النقل تمامًا ولا يجوز لأي أحد نقلها قانونيًا."},"175":{"q":"أنا أُحمّل شحنة مُعلَّمة بأنها متفجرات من الفئة 1، وتُدرج ورقة الشحن المادة برقم شُعبة مباشرة بعد الفئة. يخبرني زميل أن الفئة 1 فئة واحدة غير مقسّمة، لذا فلا بد أن رقم الشُّعبة خطأ مطبعي. أيُّ عبارة تصف بشكل صحيح كيف تُنظَّم الفئة 1؟","options":["الفئة 1 فئة واحدة غير مقسّمة، لذا فأي رقم شُعبة بعدها هو خطأ","الفئة 1 مقسّمة إلى مجموعتين بالضبط بناءً على رموز ألوان التعبئة","الفئة 1 مقسّمة إلى عدة شُعب، مرقّمة من 1.1 إلى 1.6","الفئة 1 ليس لها مجموعات فرعية؛ الشُّعب موجودة فقط للغازات في الفئة 2"],"explanation":"فئة الخطر 1 (المتفجرات) مقسّمة إلى عدة شُعب مرقّمة من 1.1 إلى 1.6."},"176":{"q":"في محطة شحن، يسلّمني المُرسِل أوراق الشحن لحمولة موسومة بـ \"الشعبة 1.1\" ويسألني عن مدى الجدية التي ينبغي أن أتعامل بها مع احتمال الانفجار قبل أن أضع اللافتات وأحدّد مسار الرحلة. استنادًا إلى ما تخبرني به شعبة الخطر، أي عبارة ينبغي أن توجّه قراري؟","options":["إنها تحمل خطر التطاير فقط، لذا أُخطّط أساسًا للشظايا المتطايرة بدلًا من انفجار كامل","إنها تشكّل خطر حريق طفيف فقط، لذا فإن طفّاية حريق قياسية والتزوّد بالوقود بحذر هما كل ما أحتاجه فعلًا","لها خطر انفجاري بسيط يقتصر على العبوة نفسها، لذا فإن المسافة عن المباني ليست أمرًا مهمًا","إنها تمثّل خطر انفجار كتلي، أي أن الحمولة بأكملها يمكن أن تنفجر دفعة واحدة، لذا يجب أن أتعامل معها بوصفها أخطر شعبة من شعب المتفجرات"],"explanation":"تمثّل متفجرات الشعبة 1.1 خطر انفجار كتلي حيث يمكن أن تنفجر الحمولة بأكملها دفعة واحدة، مما يجعلها أخطر شعبة من شعب المتفجرات."},"177":{"q":"أنا أنقل حمولة متفجرات من الشعبة 1.2 موضوعًا عليها اللافتات وأحتاج إلى التوقف لتناول وجبة في بلدة صغيرة. بصفتي السائق، أي إجراء يبقيني ملتزمًا بالقانون وفق القواعد الخاصة بهذه الحمولة؟","options":["البقاء مع المركبة، أو أن يراقبها شخص مؤهّل، بحيث لا تُترك الحمولة دون مراقبة أبدًا","قفل المقصورة، وشدّ الفرامل، وتركها في موقف المطعم بينما أتناول الطعام في الداخل","ركنها على بُعد 5 أقدام من الطريق المسلوك حتى أتمكّن من مراقبتها من النافذة","تركها دون مراقبة لمدة تصل إلى ساعتين طالما أنها موضوعة بجوار مبنى"],"explanation":"يجب ألّا تُترك متفجرات الشعب 1.1 و1.2 و1.3 دون مراقبة أبدًا؛ إذ يجب أن يبقى السائق أو شخص مؤهّل آخر مع الحمولة ويراقبها في جميع الأوقات."},"178":{"q":"أنا أنقل متفجرات من الشعبة 1.1 عندما يتعطّل مقطورتي ميكانيكيًا على طريق عام ثنائي الحارات. تصل شاحنة ثانية تابعة للشركة، ويريد مني المُرسِل نقل الشحنة المتفجرة إلى المركبة الأخرى حتى تتمكّن الحمولة من مواصلة السير. وفقًا لقواعد المواد الخطرة، أين يُسمح لي بإجراء هذا النقل بين المركبتين؟","options":["هناك مباشرة على كتف الطريق السريع، بما أن الشاحنة الثانية موجودة في الموقع وجاهزة لاستلام الحمولة","ليس على الطريق العام إطلاقًا ما لم تكن حالة طارئة حقيقية — يجب إجراء النقل في موقع آمن خارج الطريق مثل محطة أو مستودع","في أي مكان على المسار، طالما أنني أعرض اللافتات المناسبة على الجوانب الأربعة لكلتا المركبتين أثناء التبديل","النقل على الطريق مقبول هنا، لأن المُرسِل أعطى الأمر المباشر لمواصلة سير الشحنة"],"explanation":"لا يجوز نقل متفجرات الفئة 1 بين المركبات على طريق عام إلا في حالة طارئة حقيقية؛ إذ يجب أن يتم النقل في موقع آمن خارج الطريق مثل محطة."},"179":{"q":"أنا أنقل متفجرات من الشعبة 1.2 وأحتاج إلى التوقف للراحة. أرى أمامي منطقة استراحة حيث يوجد شخص أشعل نار مخيّم على جانب الطريق. تدور في ذهني قواعد التباعد. ما الحد الأدنى للمسافة التي يجب أن أحافظ عليها بين حمولة المتفجرات المركونة وتلك النار المكشوفة؟","options":["5 أقدام، وهي نفس الحد الأدنى الذي يجب أن أحافظ عليه عن الجزء المسلوك من الطريق","10 أقدام، وهي بعيدة بما يكفي للابتعاد عن أي جمرات متطايرة","300 قدم، وهي المسافة المطلوبة للفصل بين المتفجرات والنار المكشوفة","قدم واحدة، بما أن النار محتواة داخل حلقة نار المخيّم"],"explanation":"يجب ركن المركبة التي تحمل متفجرات على بُعد 300 قدم على الأقل من أي نار مكشوفة."},"180":{"q":"أنا أراجع أوراق الشحن لحمولة غاز من الفئة 2 قبل انطلاقي، محاولًا تأكيد أي شعبة أنقلها. أعلم أن الفئة 2 تغطي أكثر من نوع واحد من الغاز، وأخبرني الناقل أن الشعب الثلاث المعترف بها للفئة 2 هي الغاز القابل للاشتعال (2.1)، والغاز غير القابل للاشتعال (2.2)، وشعبة ثالثة عليّ تحديدها لأغراض اللافتات. أي مما يلي هو تلك الشعبة الثالثة المعترف بها لغازات الفئة 2؟","options":["الغاز الصلب القابل للاشتعال، بما أن بعض غازات الفئة 2 يمكن أن تستقر في صورة صلبة قابلة للاحتراق","الغاز الأكّال، لأن الغازات المضغوطة في الخزانات تتصرّف مثل المواد الأكّالة من الفئة 8","الغاز السائل فقط، بما أن الغازات المخزّنة تحت الضغط تُنقل دائمًا في الحالة السائلة","الغاز السام، وهو الشعبة 2.3 وقد يتطلّب لافتات بأي كمية"],"explanation":"تشمل غازات الفئة 2 الغاز السام (السمّي) بوصفه الشعبة 2.3، وهو مادة من الجدول 1 تتطلّب لافتات بأي كمية."},"181":{"q":"أثناء توقّف للراحة، ألاحظ أن إحدى أسطوانات الغاز المضغوط في حمولتي الموضوع عليها اللافتات قد بدأت تتسرّب ببطء، مع صوت هسهسة قرب الصمام. هناك مسافرون يتجوّلون في منطقة الموقف القريبة. أي مما يلي هو الإجراء الفوري الأنسب؟","options":["إبعاد الناس عن الأسطوانة، وإبقاء المنطقة خالية، وطلب المساعدة الطارئة","شدّ الصمام وإغلاق التسرّب بنفسك حتى يتوقّف خروج الغاز","تدفئة الأسطوانة قليلًا حتى يتعادل الضغط وتتوقّف الهسهسة","دحرجة الأسطوانة وهزّها لإعادة استقرار الصمام وتقليل الضغط"],"explanation":"عند وجود أسطوانة غاز مضغوط متسرّبة، أبعد الناس، وأبقِ المنطقة خالية، وامنع مصادر الاشتعال، واطلب المساعدة الطارئة بدلًا من محاولة إصلاحها بنفسك."},"182":{"q":"أنا أُحمّل شحنة مشعّة من الفئة 7، ويسلّمني المُرسِل عبوات تحمل ملصقات إشعاعية. يُظهر كل ملصق رقمًا يخبرني بمستوى الإشعاع في العبوة. أي نظام ترقيم سأراه على ملصقات الفئة 7 هذه؟","options":["الملصقات مرقّمة A أو B أو C، بما يطابق مؤشر النقل للعبوة","الملصقات مرقّمة I أو II أو III، للدلالة على مستوى إشعاع العبوة","الملصقات مرقّمة من 1 إلى 9، بما يطابق نظام فئة الخطر","الملصقات مرقّمة X أو Y أو Z، بما يطابق حرف مجموعة التعبئة"],"explanation":"تستخدم المواد المشعّة من الفئة 7 ثلاث فئات من الملصقات تُعلَّم بالأرقام الرومانية I أو II أو III للدلالة على مستوى إشعاع العبوة."},"183":{"q":"أنا أُحمّل عدة عبوات مشعّة من الفئة 7، ويشير المُرسِل إلى رقم 'مؤشر النقل' المطبوع على كل ملصق. لتحميل مقطورتي بأمان وقانونية، ماذا تخبرني قيمة مؤشر النقل هذه فعلًا؟","options":["القيمة المالية الإجمالية للمحتويات المشعّة لأغراض التأمين","الوزن الإجمالي المجمّع لجميع العبوات المشعّة على متن المركبة","درجة التحكّم في الإشعاع المطلوبة عند مناولة العبوة ونقلها","رقم التعريف UN/NA المخصّص لتلك المادة المشعّة"],"explanation":"يخبرك مؤشر النقل على عبوة مشعّة من الفئة 7 بدرجة التحكّم في الإشعاع المطلوبة عند مناولتها وتحميلها."},"184":{"q":"أنا أنقل حمولة مواد أكّالة موضوعًا عليها اللافتات عبر المدينة، ويعرض عليّ نظام الملاحة ثلاثة مسارات محتملة إلى الوجهة نفسها، جميعها بنفس المسافة تقريبًا. باتباع إرشادات تسيير المواد الخطرة في تكساس، أيًّا من هذه ينبغي أن أبذل أقصى جهد لاختياره؟","options":["المسار الذي يمرّ عبر نفق طويل تحت الأرض، بما أنه يتجنّب إشارات المرور السطحية ويوفّر بضع دقائق","المسار الذي يمرّ مباشرة بجوار استاد مكتظ وسط المدينة في اللحظة التي ينفضّ فيها حدث ما","المسار الذي يلتفّ بجوار عدة مجمّعات تسوّق مزدحمة للبقاء على شوارع أوسع جيدة الإضاءة","المسار الذي يبقى على الشوارع العابرة المفتوحة ويتجنّب كلًّا من النفق ومناطق الأحداث المزدحمة"],"explanation":"يجب على سائقي المواد الخطرة اتباع المسارات المخصّصة التي تتجنّب الأنفاق والمناطق المكتظّة بالسكان أو المزدحمة كلما أمكن ذلك."},"185":{"q":"أنا مُكلّف بنقل حمولة متفجرات من الشعبة 1.1 عبر الولاية. يقول مدرّبي إنه قبل هذه الرحلة، تتطلّب القواعد الفيدرالية من الناقل إعداد وثيقة مكتوبة محدّدة يجب أن أحملها وأتبعها. أي وثيقة يقصدها؟","options":["خطة مسار مكتوبة يجب أن تتبعها الرحلة","سجل يومي مكتوب لوقود السائق وأمياله","عقد بيع مكتوب للحمولة المتفجرة","توقّع طقس مكتوب على جانب الطريق لمدة 72 ساعة"],"explanation":"يجب نقل حمولات المتفجرات (الشعب 1.1 و1.2 و1.3) بموجب خطة مسار مكتوبة يعدّها الناقل ويحملها السائق."},"186":{"q":"أنا في الساعة الثالثة من رحلة طويلة بحمولة مواد أكّالة موضوعًا عليها اللافتات، وقد توقّفت للتو في منطقة استراحة لاستخدام دورة المياه. كانت الشاحنة تعمل بشكل جيد منذ فحص ما قبل الرحلة، وبدت إطاراتي جيدة عند مغادرتي. قبل أن أعود إلى الطريق السريع، ماذا ينبغي أن أفعل بشأن إطاراتي؟","options":["لا شيء — فحص الإطارات الشامل قبل الرحلة يغطّيني طوال الرحلة ما لم ينفجر إطار فعلًا","فحص الإطارات الآن، بما أنه ينبغي عليّ فحصها في بداية الرحلة ومرة أخرى كل ساعتين أو 100 ميل","فحصها فقط إذا أضاء ضوء التحذير من ضغط الإطارات أو شعرت بانجذاب الشاحنة إلى جانب واحد","الانتظار وفحص الإطارات مرة واحدة في اليوم، وهو كافٍ لحمولة موضوع عليها اللافتات في رحلة طويلة"],"explanation":"يجب على السائق الذي ينقل حمولة مواد خطرة موضوعًا عليها اللافتات فحص الإطارات في بداية الرحلة ومرة أخرى عند كل توقّف، أي كل ساعتين أو 100 ميل."},"187":{"q":"أُدخل صهريجي الموضوع عليه اللافتات إلى محطة وقود لملء الديزل قبل المرحلة التالية من رحلتي. وأنا أستعدّ لبدء الضخّ، أي مما يلي يصف كيف يجب أن أتعامل مع المحرك وعملية التزوّد بالوقود للبقاء ملتزمًا؟","options":["ترك المحرك يدور بسرعة منخفضة حتى يبقى نظام الهواء مشحونًا، وتشغيل الفوّهة بنفسي","إطفاء المحرك، وقفل الفوّهة على الوضع التلقائي، والدخول لدفع الحساب أثناء امتلائه","إطفاء المحرك وإبقاء شخص بجوار الفوّهة يتحكّم في تدفّق الوقود طوال الوقت","إبقاء المحرك يعمل بسرعة عالية لتشغيل مضخّة الرفع، دون حاجة لأحد عند الفوّهة"],"explanation":"عند تزويد مركبة موضوع عليها اللافتات بالوقود، يجب أن يكون المحرك مُطفأً وأن يبقى شخص عند الفوّهة يتحكّم في تدفّق الوقود طوال الوقت."},"188":{"q":"إذا وجدت تسرّبًا لمادة خطرة، فلا ينبغي أن:","options":["تحذّر الآخرين","تلمسها أو تستنشقها","تُبقي الناس بعيدين","تطلب المساعدة"],"explanation":"لا تلمس أبدًا مادة متسرّبة ولا تستنشقها."},"189":{"q":"أنت تنقل حمولة سائل أكّال موضوعًا عليها اللافتات عندما يبدأ أحد البراميل بالتسرّب بشدة على كتف الطريق السريع، مما يُحدث تسرّبًا خطيرًا لمادة خطرة. بعد أن حذّرت الآخرين، وأبقيت الناس بعيدين، ومنعت التدخين، يوجّهك الناقل لإجراء الإبلاغ المطلوب عن هذا الحادث الخطير إلى مركز الاستجابة الوطني. أي رقم تتصل به للإبلاغ عنه؟","options":["411، خط الاستعلامات، لتوصيلك بأقرب وحدة استجابة للمواد الخطرة","911، خط الطوارئ المحلي، الذي يفي تمامًا بمتطلّب مركز الاستجابة الوطني","1-800-555-1212، الخط المجاني الذي يوجّه البلاغ إلى الجهة الفيدرالية المختصة","1-800-424-8802، خط مركز الاستجابة الوطني للإبلاغ عن حوادث المواد الخطرة الخطيرة"],"explanation":"يجب الإبلاغ عن حوادث المواد الخطرة الخطيرة إلى مركز الاستجابة الوطني على الرقم 1-800-424-8802."},"190":{"q":"يبدأ برميل على مقطورتي الموضوع عليها اللافتات بتسريب سائل أكّال على كتف ناءٍ، وليست لديّ أي فكرة عمّا أفعله بالمادة الكيميائية أو كيفية معادلتها. بعد أن أحذّر الآخرين وأبقي الناس بعيدين، أي رقم ينبغي أن أتصل به للوصول إلى إرشادات الطوارئ على مدار 24 ساعة بشأن التعامل مع هذه المادة الخطرة تحديدًا؟","options":["1-800-424-9300، خط طوارئ CHEMTREC","1-800-275-8777، الخط الوطني للشحن والبريد","1-888-275-8255، خط البلاغ الفيدرالي لسلامة الطرق السريعة","1-800-829-1040، خط معلومات الجهة الفيدرالية"],"explanation":"يدير CHEMTREC خط طوارئ على مدار 24 ساعة على الرقم 1-800-424-9300 يوفّر للسائقين إرشادات فنية فورية للتعامل مع مادة خطرة في حادث."},"191":{"q":"أنا أنقل حمولة مواد أكّالة موضوعًا عليها اللافتات عبر تكساس مع ربط حزام الأمان. يوقفني شرطي من دائرة السلامة العامة ويسألني عن أوراق شحن المواد الخطرة. وفقًا لقواعد الدليل، أين كان ينبغي أن تكون تلك الأوراق أثناء قيادتي؟","options":["مختومة في مظروف مقاوم للماء ومخزّنة في المقطورة مع الشحنة","في متناول يدي وفي مرأى واضح، موضوعة فوق أوراقي الأخرى","مزرّرة داخل ملف سجلّي على السرير خلف مقعد السائق","مقفلة في صندوق القفّازات حتى تبقى آمنة إذا اقتُحمت المقصورة"],"explanation":"أثناء القيادة، يجب أن تكون أوراق شحن المواد الخطرة في متناول يد السائق وموضوعة فوق الأوراق الأخرى في مرأى واضح."},"192":{"q":"أنا أنقل حمولة مواد خطرة موضوعًا عليها اللافتات وأُدخل إلى منطقة استراحة لاستخدام دورة المياه. سأغادر المقصورة لبضع دقائق والمحرك مُطفأ. وفقًا لقواعد دائرة السلامة العامة في تكساس، أين ينبغي أن تكون أوراق الشحن أثناء غيابي عن الشاحنة؟","options":["مقفلة داخل صندوق القفّازات حتى لا يتمكّن أحد من العبث بها أثناء غيابي","مطوية في جيب قميصي ومحمولة معي إلى منطقة الاستراحة","متروكة في مرأى واضح على مقعد السائق أو في جيب باب السائق","مخزّنة في حجيرة الشحن الجانبية بجوار دليل الاستجابة للطوارئ"],"explanation":"عندما يغادر السائق المقصورة، يجب ترك أوراق شحن المواد الخطرة في مرأى واضح على مقعد السائق أو في جيب باب السائق حتى يتمكّن المستجيبون من العثور عليها."},"193":{"q":"أنا مركون في منطقة استراحة ومقطورتي موضوع عليها لافتات للسوائل القابلة للاشتعال من الفئة 3. يقف بعض السائقين قرب شاحنتي يتحدّثون، ويشعل أحدهم سيجارة. للبقاء ضمن القاعدة الفيدرالية للتدخين الخاصة بحمولتي الموضوع عليها اللافتات، ما الحد الأدنى للمسافة التي يجب أن يبقيها الجميع بين تلك السيجارة المشتعلة ومركبتي؟","options":["5 أقدام على الأقل، وهو نفس الفاصل المطلوب عند الركن بعيدًا عن الجزء المسلوك من الطريق","قدمان على الأقل، بما أن السائل القابل للاشتعال محكم داخل الخزان ويشكّل خطرًا ضئيلًا","100 ياردة على الأقل، وهي نفس المسافة المحفوظة عن المتفجرات المتروكة دون مراقبة عند معبر سكة حديد","25 قدمًا على الأقل عن المركبة، إذ لا يُسمح بالتدخين ضمن هذا النطاق من حمولة قابلة للاشتعال"],"explanation":"يُمنع التدخين على بُعد أقل من 25 قدمًا من مركبة موضوع عليها لافتات تحمل متفجرات أو مواد مؤكسِدة أو مواد قابلة للاشتعال، لذا يجب أن تبقى السيجارة المشتعلة على هذه المسافة على الأقل."},"194":{"q":"أنا سائق جديد مُكلّف بنقل حمولة متفجرات من الشعبة 1.1 عبر تكساس. أنهى المُرسِل تصنيف الحمولة ووسمها، وخصّص لي الناقل الرحلة. قبل أن أخرج من الساحة، أي مما يلي يجب أن يكون لديّ بالفعل بصورة مكتوبة في المقصورة؟","options":["خطة مسار مكتوبة للرحلة بالإضافة إلى أوراق الشحن للحمولة","تذكرة وزن موقّعة من الميزان ونسخة من إيصال الوقود","سجل مكتوب بقنوات الراديو التي سأراقبها على طول المسار","توقّع طقس موثّق يغطّي كل مقاطعة سأمرّ بها"],"explanation":"قبل نقل متفجرات الشعبة 1.1، يجب أن يحمل السائق خطة مسار مكتوبة مع أوراق الشحن للحمولة."},"195":{"q":"أنا أُحمّل شحنة مواد خطرة موضوعًا عليها اللافتات عند رصيف تحميل وأفحص كل عبوة قبل وضعها على مقطورتي. يسلّمني المُرسِل أربع حاويات. أي واحدة يجب أن أرفض نقلها؟","options":["برميل محكم الإغلاق دون ضرر ظاهر في اللحام أو الغطاء","دلو يتسرّب منه منتج أكّال ببطء من شقّ عند قاعدته","صندوق كرتوني عليه ملصق فئة الخطر الصحيح مطبّق على السطح الخارجي","صندوق مغلق بشكل صحيح ويطابق الوصف الموجود في أوراق الشحن"],"explanation":"يجب على السائق رفض أي شحنة مواد خطرة متسرّبة، مثل عبوة يتسرّب منها المنتج من شقّ."},"196":{"q":"أنا أحمل بالفعل رخصة قيادة تجارية من الفئة A وأريد الآن إضافة تصديق H حتى أتمكّن من نقل حمولات مواد أكّالة موضوعًا عليها اللافتات. قبل أن تصدر دائرة السلامة العامة في تكساس هذا التصديق، أي متطلّب إضافي يجب أن أستوفيه وهو غير مطلوب لرخصتي التجارية الأساسية؟","options":["اجتياز فحص طبي ثانٍ من وزارة النقل وتقديم شهادة فاحص طبي محدّثة","إكمال اختبار مهارات قيادة منفصل خلف عجلة القيادة باستخدام مركبة صهريج موضوع عليها اللافتات","اجتياز تقييم تهديد أمني من إدارة أمن النقل، يتضمّن أخذ البصمات وفحص السوابق","إعادة اجتياز فحص النظر للرخصة التجارية واختبار المعرفة العامة التحريري لدى الدائرة"],"explanation":"يتطلّب تصديق المواد الخطرة بشكل فريد اجتياز تقييم تهديد أمني من إدارة أمن النقل، يشمل أخذ البصمات وفحص السوابق."},"197":{"q":"أحمل رخصتي التجارية من تكساس مع تصديق المواد الخطرة (H) منذ عدة سنوات وأجتاز كل فحص طبي في موعده. يخبرني سائق أحدث أنه بمجرد حصولي على تصديق H باجتياز تقييم تهديد أمني من إدارة أمن النقل، يصبح هذا الجزء من رخصتي دائمًا ولا أحتاج إلى التعامل معه مجددًا أبدًا طالما بقيت رخصتي التجارية الأساسية صالحة. أي عبارة عن تصديق المواد الخطرة صحيحة؟","options":["إنه مثبّت مدى الحياة بمجرد اجتياز تقييم تهديد إدارة أمن النقل، لذا لا يلزم أي إجراء آخر بشأن هذا الجزء أبدًا.","يبقى صالحًا فقط طالما واصلتُ اجتياز فحصي الطبي من وزارة النقل، وهو ما يتحكّم في التصديق.","ينتقل تلقائيًا ولا تنتهي صلاحيته أبدًا طالما أبقيتُ رخصتي التجارية الأساسية في تكساس نشطة.","يجب تجديده دوريًا، مما يتطلّب الخضوع لتقييم تهديد أمني / فحص سوابق جديد من إدارة أمن النقل."],"explanation":"تصديق المواد الخطرة محدود زمنيًا ويجب تجديده دوريًا باجتياز تقييم تهديد أمني وفحص سوابق جديد من إدارة أمن النقل."},"198":{"q":"أنا أنقل حمولة مواد أكّالة موضوعًا عليها اللافتات عندما يتعطّل صمام ويبدأ المنتج بالتسرّب على الكتف. أمسك دليل الاستجابة للطوارئ (ERG) من مقصورتي. في هذا الموقف، ما الذي صُمّم الدليل فعلًا لمساعدتي في فعله؟","options":["تحديد مخاطر المادة والإجراءات الأولية الصحيحة للتسرّب حتى أحمي نفسي والجمهور","حساب القيمة المالية للمنتج المفقود حتى يتمكّن الناقل من تقديم مطالبة تأمين دقيقة","تحديد مسار التفافي الأكثر توفيرًا للوقود حول الحادث لتجنّب إهدار الديزل","تحديد موقع أقرب مكان إقامة ومنطقة استراحة معتمدين أثناء انتظاري طاقم التنظيف"],"explanation":"يتيح دليل الاستجابة للطوارئ للسائق تحديد مخاطر المادة والإجراءات الأولية الصحيحة للتسرّب لحماية نفسه والجمهور."},"199":{"q":"يوجد تسرّب من صهريجي الموضوع عليه اللافتات في موقع حادث. يهرع إليّ رجل إطفاء ويطلب مني قراءة رقم التعريف المكوّن من أربعة أرقام من أوراق الشحن. باستثناء واحد، تفسّر كل الخيارات التالية لماذا يهمّه هذا الرقم. أي خيار هو الذي يحتاجه فعلًا لأجله؟","options":["يخبره بالقيمة المالية للشحنة حتى يتمكّن من تقديم مطالبة الضرر للناقل","يتيح له البحث عن المادة في دليل الاستجابة للطوارئ لإيجاد إجراءات الاستجابة الصحيحة","يؤكّد أن تصديق H وفحص السوابق من إدارة أمن النقل ساريان لهذه الحمولة","يُظهر اسم الشحن الصحيح حتى يقرأه بصوت عالٍ عبر الراديو للمرسل"],"explanation":"يتيح رقم التعريف UN/NA المكوّن من أربعة أرقام للمستجيب البحث عن المادة في دليل الاستجابة للطوارئ لإيجاد إجراءات الاستجابة الصحيحة."},"200":{"q":"أنا أنقل حمولة موضوعًا عليها اللافتات عندما يبدأ الدخان بالتصاعد من أسفل مقطورتي وأرى ألسنة اللهب تنتشر على طول الإطارات. لديّ طفّاية حريق صغيرة في المقصورة، لكن الحريق كبير بالفعل لدرجة لا أستطيع السيطرة عليه بأمان. باستثناء خيار واحد أدناه، كل إجراء مدرج من شأنه أن يجعل هذا الموقف أكثر خطورة. أيها الإجراء الذي ينبغي أن أتخذه فعلًا؟","options":["فتح أبواب الشحن للتحقّق من البراميل المحترقة بالضبط حتى أتمكّن من وصفها للمستجيبين","إمساك طفّايتي ومواصلة مكافحة الحريق بنفسي حتى يُطفأ تمامًا أو تصل المساعدة أخيرًا","إبقاء المارّة بعيدين، والبقاء في عكس اتجاه الريح، والاتصال بمستجيبي الطوارئ للمساعدة فورًا","قيادة الشاحنة المشتعلة إلى أقرب بلدة حتى تكون المسافة أقصر لرجال الإطفاء للوصول إليّ"],"explanation":"عندما تشتعل حمولة مواد خطرة موضوع عليها اللافتات وتخرج عن سيطرتك، أبقِ المارّة بعيدين، وابقَ في عكس اتجاه الريح، واتصل بمستجيبي الطوارئ فورًا بدلًا من مكافحتها."},"201":{"q":"أنت تنقل حمولة مواد خطرة تحمل لافتات، ويوجهك نظام تحديد المواقع (GPS) مباشرة عبر نفق طويل على الطريق السريع من شأنه أن يوفر عليك ما يقارب الساعة. ولست متأكدًا مما إذا كانت مادتك مسموحًا بها في ذلك النفق. قبل أن تصل إلى مدخل النفق، ما الذي يجب أن تفعله أولًا؟","options":["خفّض سرعتك وأبقِ كلا المسارين خاليين كي تتمكن من المرور عبر النفق بسرعة وأمان","انزع اللافتات قبل الدخول كي لا يوقفك عمال النفق في الداخل","توقف عند مدخل النفق مباشرةً واتصل بشركة النقل لتسأل عما إذا كان يمكنك المتابعة","تحقق من قواعد المسار المخصص، لأن بعض المواد الخطرة ممنوعة من الأنفاق وقد يلزم اتباع مسار مختلف"],"explanation":"بعض المواد الخطرة ممنوعة من الأنفاق، لذا يجب على السائق التحقق من قواعد المسار المخصص أولًا لأنه قد يلزم اتباع مسار مختلف."},"202":{"q":"سلّمتني شركة النقل للتو خطة أمنية مكتوبة قبل رحلة لنقل مواد خطرة تحمل لافتات، وطلبت مني اتباع إجراءاتها لتأمين مستندات الشحن، والتحقق من مساري، والحد من الوصول غير المصرح به إلى المقطورة. من منظور دائرة السلامة العامة في تكساس (Texas DPS)، ما الغرض الأساسي الذي صُممت هذه الخطة الأمنية لتحقيقه؟","options":["تقليل احتمال سرقة المواد الخطرة أو إساءة استخدامها من قِبل أشخاص غير مصرح لهم","تسريع التحميل والتفريغ كي يصل التسليم قبل موعده المحدد","تقليل استهلاك الوقود عن طريق رسم أقصر مسار ممكن بين التوقفات","إبقاء منطقة الشحن نظيفة كي لا تتلوث المواد أثناء النقل"],"explanation":"توجد الخطة الأمنية للمواد الخطرة لتقليل احتمال سرقة المواد الخطرة أو إساءة استخدامها من قِبل أشخاص غير مصرح لهم."},"203":{"q":"أنا أنقل حمولة من المواد الأكّالة تحمل لافتات عبر مدينة لا أعرفها، وأتوقف في الليلة السابقة لأخطط لرحلتي. وفقًا لدليل رخصة القيادة التجارية في تكساس، ما السبب الرئيسي الذي يجعل التخطيط لمساري مسبقًا بالغ الأهمية لسائق المواد الخطرة؟","options":["يتيح لي تخطي فحوصات الإطارات أثناء الطريق لأنني أعرف مسبقًا كم ستستغرق الرحلة","يساعدني على تحديد المناطق المحظورة التي يُمنع فيها مرور حمولتي ذات اللافتات والابتعاد عنها","يسمح لي بنزع لافتاتي على امتدادات الطريق السريع المفتوح لتوفير الوقود","يضمن لي إيجاد أرخص محطات الوقود وأماكن الاستراحة على طول الطريق"],"explanation":"يساعد التخطيط للمسار مسبقًا السائق على تحديد المناطق المحظورة التي يُمنع فيها مرور حمولة تحمل لافتات والابتعاد عنها."},"204":{"q":"أنا أحمّل مقطورة في محطة شحن، وتتضمن قائمة بضائعي عدة منصات نقالة من متفجرات الفئة 1 (الشعبة 1.1) إلى جانب مواد خطرة أخرى تنتظر على الرصيف. قبل أن أسمح لطاقم الرصيف بتكديس كل شيء معًا، ما الذي يجب أن يوجّه قراري بشأن المنتجات التي يمكن أن تُنقل في الحمولة نفسها مع المتفجرات؟","options":["يجوز أن تشترك المتفجرات في الحمولة مع أي فئة خطر طالما أن كل منصة نقالة مثبّتة ومدعّمة على حدة بحيث لا يمكن أن تتحرك أثناء النقل","يمكن تحميل المتفجرات مع أي شيء شريطة أن تبقى البضائع المجتمعة دون عتبة 1,001 رطل التي تستوجب وضع اللافتات للمقطورة","يحظر جدول الفصل (التحميل/التفريغ) تحميل المتفجرات مع بعض المواد الخطرة الأخرى، لذا يجب أن أتحقق منه قبل دمجها","يجب تحميل المتفجرات وحدها تمامًا ولا يجوز أبدًا أن تشترك في مقطورة مع أي بضائع أخرى مهما كانت"],"explanation":"استشر دائمًا جدول الفصل (التحميل/التفريغ) قبل دمج المتفجرات مع مواد خطرة أخرى، لأن بعض المنتجات يُمنع تحميلها معًا."},"205":{"q":"أنا عند رصيف التحميل وعلى وشك أن أحمّل يدويًا عدة براميل وعلب من سائل أكّال من الفئة 8 إلى مقطورتي. يسألني عامل الرصيف عن الكيفية التي أريد أن توضع بها كل حاوية قبل أن نربطها. لتعبئة الحمولة بأمان بحيث يبقى السائل محكم الإغلاق في الداخل، كيف ينبغي أن أضع كل حاوية؟","options":["مستلقية على جوانبها كي تتلاصق البراميل بإحكام وتتحرك أقل أثناء النقل","مع توجيه الفتحات إلى الأسفل كي يتسرب أي تسرب بعيدًا عن السدادة","مع توجيه ملصقات الخطر نحو الجدار للحفاظ عليها من الخدش","واقفة بشكل عمودي مع توجيه الفتحات إلى الأعلى كي تبقى السدادات فوق السائل"],"explanation":"حمّل السوائل الخطرة في وضع عمودي مع توجيه السدادات إلى الأعلى كي تبقى الفتحات فوق مستوى السائل ولا تتسرب الأختام."},"206":{"q":"أنا أحمّل مقطورة يدويًا بكراتين من مادة أكّالة (الفئة 8)، ويناولني عامل الرصيف خطاف شحن معدنيًا لجرّ الصناديق الثقيلة إلى مكانها بشكل أسرع. قبل أن أمسك أي شيء، أي قاعدة ينبغي أن تمنعني من استخدام ذلك الخطاف على هذه الطرود؟","options":["يجب ألا أستخدم أي خطاف أو أداة قد تثقب طرود المواد الخطرة أو تمزقها أو تتلفها بأي شكل","يمكنني استخدام الخطاف بحرية طالما أبقيت الكراتين عمودية والملصقات متجهة للخارج","لا يُسمح بالخطافات على الفئة 8 إلا بعد أن أضع اللافتات على جميع جوانب المقطورة الأربعة","لا يُسمح بالخطافات إلا إذا فحصت الإطارات خلال أول 100 ميل بعد التحميل"],"explanation":"لا تستخدم أبدًا خطافًا أو أي أداة قد تثقب تغليف المواد الخطرة أو تمزقه أو تتلفه، لأن أي خرق قد يطلق المحتويات."},"207":{"q":"أنا أحمّل أسطوانات غاز مضغوط (الفئة 2) في مقطورتي في فترة ظهيرة حارة. للتعامل معها بشكل صحيح بموجب القواعد، ما الذي ينبغي أن أفعله بهذه الأسطوانات قبل أن أنطلق؟","options":["أضعها مستلقية بشكل غير مثبّت كي تستقر بشكل طبيعي وتتحرك مع تكيّف الحمولة على الطريق","أثبّتها بإحكام بحيث لا تتحرك وأبقيها محمية من مصادر الحرارة","أوقفها عموديًا مع فتح الصمامات قليلًا كي يتنفّس الضغط الداخلي ببطء","أكدّسها عاليًا على الجدار الدافئ للمقطورة وأسند الصف السفلي فقط"],"explanation":"ثبّت أسطوانات الغاز المضغوط بحيث لا تتحرك أو تسقط وأبقِها بعيدًا عن الحرارة، لأن الحرارة ترفع الضغط الداخلي وقد تسبب انفجارًا."},"208":{"q":"أنا أضع اللافتات على شاحنة صهريج قبل رحلة في تكساس وألاحظ أنها تحمل لافتتين: لافتة رئيسية كبيرة لفئة خطرها الأساسية بالإضافة إلى لافتة ثانية أصغر دون رقم فئة مطبوع في زاويتها السفلية. يسميها مدربي اللافتة \"الثانوية\". ما الذي تخبرني به عن هذه الحمولة؟","options":["تؤكد التصنيف المتبقي أو \"القديم\" الذي استخدمه الشاحن قبل إعادة تحميل البضائع","تشير إلى أن الصهريج فارغ ولا يتبقى بداخله سوى الرواسب","تحذّر من خطر إضافي تشكّله المادة بخلاف فئة خطرها الأساسية","تحدد مستوى الوقود الحالي كي يعرف المستجيبون كم من المنتج موجود على متنها"],"explanation":"تحذّر اللافتة الثانوية من خطر إضافي تشكّله المادة بخلاف فئة خطرها الأساسية."},"209":{"q":"أنا أستعد لنقل حمولة من المواد الأكّالة تحمل لافتات، ويناولني الشاحن مستندات شحن تتضمن رقم هاتف للاستجابة الطارئة قرب أعلى الصفحة. قبل أن أوقّع وأنطلق، أي شرط يجب أن يستوفيه رقم الاستجابة الطارئة هذا؟","options":["يكفي أن يكون قابلًا للوصول خلال ساعات عمل الشاحن العادية في أيام الأسبوع فقط","يمكن أن يحوّل إلى صندوق بريد صوتي مسجّل طالما أن أحدهم يعاود الاتصال لاحقًا","يُسمح بأن يكون رقم هاتف محمول شخصي للسائق المدرج في المستندات","يجب أن يكون رقمًا مزوّدًا بطاقم ومراقبًا في جميع الأوقات أثناء نقل المادة الخطرة"],"explanation":"يجب أن يكون رقم هاتف الاستجابة الطارئة على مستندات الشحن مزوّدًا بطاقم ومراقبًا في جميع الأوقات أثناء نقل المادة الخطرة."},"210":{"q":"أنت تنقل حمولة من المواد الأكّالة تحمل لافتات عندما يتعطل وصلة وتبدأ بركة بالانتشار من تحت مقطورتك على كتف طريق سريع ذي مسارين. ما زالت مركبات أخرى تمر بالقرب منك. بعد أن تنزاح تمامًا عن الطريق، ما أولويتك الأولى قبل فعل أي شيء آخر؟","options":["أبقِ المارة بعيدين عن التسرب وحذّر حركة المرور المقتربة من الخطر","اغسل المادة المنسكبة عن الرصيف كي تتوقف عن الانتشار نزولًا","انزع اللافتات أو غطّها كي لا يصاب الفضوليون بالذعر بشأن الحمولة","عُد إلى المقصورة وقُد إلى المخرج التالي لإخلاء الموقع بسرعة"],"explanation":"في حادث مواد خطرة، يكون واجب السائق الأول إبعاد الناس عن التسرب وتحذير حركة المرور المقتربة من الخطر."},"211":{"q":"لقد دخلت منطقة استراحة بحمولتي ذات اللافتات وأريد الخروج لأخذ استراحة تدخين. بالقرب من أي من هذه يجب ألا أشعل سيجارة على الإطلاق؟","options":["بجانب المقطورة الفارغة المطهّرة تمامًا التي أنزلتها للتو","بجانب المقطورة التي تحمل لافتة سائل قابل للاشتعال","بجانب سيارة ركاب متوقفة في الموقف المجاور","بجانب مقصورة جرّاري النظيفة المكنوسة"],"explanation":"لا تدخّن أبدًا على بُعد 25 قدمًا من مركبة تحمل لافتة مواد قابلة للاشتعال، لأن الأبخرة يمكن أن تشتعل من لهب مكشوف أو سيجارة مشتعلة."},"212":{"q":"تنقلب شاحنة صهريجك التي تحمل لافتات وتنقل سائلًا قابلًا للاشتعال على طريق ريفي ذي مسارين، وتشم رائحة كيميائية قوية تتجمع قرب المقطورة. توقف سائقان وهما يسيران نحو الحطام، وأحدهما يشعل سيجارة. أي إجراء ينبغي أن تتخذه أولًا؟","options":["عُد إلى المقصورة وأعِد وضع المقطورة بعيدًا عن الطريق قبل أن ينتشر التسرب","اجمع مستندات الشحن ودليل الاستجابة الطارئة وابدأ بتنظيف الانسكاب","أبقِ المارة بعيدين تمامًا، وامنع أي تدخين، وأبلغ المستجيبين للطوارئ ومركز CHEMTREC","ضع شُعلًا مشتعلة خلف الحطام لتحذير حركة المرور المقتربة من الخطر"],"explanation":"بعد حادث مواد خطرة، أبقِ المارة بعيدين تمامًا، وامنع أي تدخين، وأبلغ فورًا المستجيبين للطوارئ ومركز CHEMTREC."},"213":{"q":"أنا أجري فحصًا قبل الرحلة على مقطورتي التي تحمل لافتات في ساحة لاريدو، وألاحظ أن اللافتة الموجودة في الخلف قد بهتت بشدة وأن إحداها على الجانب الأيمن مخفية جزئيًا خلف حامل واقي الطين. يقول شريكي إن الأمر على ما يرام طالما أن اللافتتين الأمامية والخلفية نظيفتان، لأن تلك هي ما تراه حركة المرور المقابلة والشرطي خلفي فعليًا. استنادًا إلى قواعد وضع اللافتات لدائرة السلامة العامة (DPS)، أي عبارة صحيحة؟","options":["شريكك محق في أن الأمامية والخلفية فقط هي المهمة، لأنها تواجه الاتجاهات التي يقترب منها السائقون الآخرون، لذا يمكن تجاهل اللافتة الجانبية الباهتة قبل القيادة.","يكون الأمر مقبولًا طالما أن لافتة واحدة على الأقل على المركبة تبقى مقروءة تمامًا من الخارج، لذا فإن لافتة أمامية نظيفة واحدة تكفي لتتيح لك القيادة اليوم.","يلزم فقط أن تكون اللافتات مرئية بوضوح للسائق من داخل المقصورة لتأكيد أن الحمولة مميزة، لذا فإن البهتان أو الإعاقة الخارجية لا يهمان قبل القيادة.","يجب أن تكون جميع اللافتات الأربع موجودة ومقروءة من الاتجاه الذي تواجهه كل منها، لذا فإن اللافتة الخلفية الباهتة والجانبية المخفية جزئيًا يجب إصلاحهما معًا قبل القيادة."],"explanation":"اللافتات مطلوبة على جميع الجوانب الأربعة ويجب أن تكون كل منها مقروءة من الاتجاه الذي تواجهه، لذا يجب إصلاح أي لافتة باهتة أو محجوبة قبل القيادة."},"214":{"q":"أنا أجري فحصي قبل الرحلة على حمولة تحمل لافتات وأريد أن أتأكد من أن اللافتات مثبّتة بالطريقة التي تتطلبها اللوائح. بصرف النظر عن الرمز المطبوع ورقم الفئة في الداخل، ما الشكل العام الذي ينبغي أن تكوّنه كل لافتة معروضة بشكل صحيح على جانب مقطورتي؟","options":["مربع موضوع على إحدى زواياه بحيث يُقرأ كمعيّن قمته للأعلى","مربع موضوع مسطحًا على إحدى حوافه المستقيمة، مثل لوحة إشارة مرور","قرص دائري، كي يكون التحذير مرئيًا من كل زاوية","مثلث قائم، مطابق لأجهزة التحذير العاكسة في عدّتي"],"explanation":"اللافتة عبارة عن مربع مُدار بزاوية 45 درجة وموضوع على إحدى زواياه، مكوّنًا معيّنًا قمته للأعلى."},"215":{"q":"أنا أحمّل شحنة مواد خطرة تحمل لافتات وأتحقق مرتين من أن كل طرد مميّز بشكل صحيح قبل أن أوقّع على استلامه. إلى جانب اسم الشحن الصحيح المطبوع على الطرد، أي معلومة يجب أن تظهر أيضًا على علامة الطرد؟","options":["اسمي بصفتي السائق الذي قبل الحمولة","رقم التعريف (UN/NA) الخاص بالمادة","رمز اللون المطابق للافتة الموجودة على المقطورة","نوع الوقود الذي يحرقه جرّار شركة النقل"],"explanation":"يجب أن تتضمن علامات الطرد رقم تعريف المادة (UN/NA) إلى جانب اسم الشحن الصحيح."},"216":{"q":"أنا أراجع مستندات الشحن لحمولة قبل أن أغادر المحطة، وألاحظ الحرفين \"RQ\" مُدخلين في عمود المواد الخطرة (HM) بجوار إحدى المواد المدرجة مباشرةً. قبل أن أوقّع وأضع المستندات في متناول يدي، ماذا يخبرني فعليًا هذا الرمز \"RQ\" عن ذلك المُدخل؟","options":["يحدد المسار قليل الازدحام المقترح الذي ينبغي أن أتبعه لإبقاء تلك المادة بعيدة عن المناطق المأهولة","يؤكد أن الشاحن فحص الطرد مرتين وصدّق على خلوّه من التسرب للتحميل","يشير إلى أن المادة موجودة بكمية يجب الإبلاغ عنها، لذا يجب الإبلاغ عن أي انسكاب لها","يعني أن المُدخل قد تمت مراجعته وإجازته، لذا يمكنني نقله إلى أسفل أوراقي"],"explanation":"يعني \"RQ\" الكمية الواجب الإبلاغ عنها (Reportable Quantity)، مما يشير إلى أن المادة موجودة بكمية تستلزم الإبلاغ عن أي انسكاب إذا تسربت."},"217":{"q":"أنا أحمّل شحنة مختلطة، ويناولني مشرف الرصيف عدة طرود مميّزة كسموم من الفئة 6 (الشعبة 6.1). لدي مقطورة فارغة وأحتاج أن أقرر أين توضع هذه الطرود بالنسبة لبقية بضائعي. لتحميل هذه السموم بأمان وقانونية، عن أي شيء يجب أن أتأكد تمامًا من إبقائها بعيدة؟","options":["مثلثات التحذير العاكسة التي أحملها للطوارئ","طفاية الحريق المثبّتة قرب أبواب الشحن","الإطار الاحتياطي المخزّن أسفل جسم المقطورة","أي طعام أو مواد غذائية أو منتجات صالحة للأكل في الحمولة"],"explanation":"يجب ألا تُحمّل مواد السموم (الشعبة 6.1) أبدًا مع أي طعام أو مواد غذائية أو منتجات صالحة للأكل أو بالقرب منها لمنع التلوث."},"218":{"q":"أنا أنقل حمولة من مؤكسدات الفئة 5 تحمل لافتات عندما يندلع حريق كهربائي صغير قرب مقطورتي. وأنا أقيّم الموقف، لماذا من الملحّ بشكل خاص أن أبقي هذه المادة بعيدة عن أي لهب؟","options":["تطلق المؤكسدات الأكسجين، لذا ستجعل الحريق يحترق أشد حرارة وأكثر شدة","ستخمد المؤكسدات اللهب وتطفئه، لكن الأبخرة المنبعثة سامة","تتجمد المؤكسدات عند ملامسة الحرارة، مما قد يشقق المقطورة ويسكب الحمولة","المؤكسدات غير ضارة قرب الحريق، لكن اللافتات نفسها قابلة للاشتعال"],"explanation":"تطلق المؤكسدات أكسجينًا يغذّي الحريق، مما يجعله يحترق أشد حرارة وأكثر شدة."},"219":{"q":"أنا أنقل حمولة من سائل قابل للاشتعال من الفئة 3، ويدرج مستند الشحن نقطة وميض المادة. أثناء مراجعتي للسلامة قبل الرحلة، يسألني مدربي عما يخبرني به فعليًا رقم نقطة الوميض هذا عن هذه البضائع. أي عبارة تصف بشكل صحيح ما تشير إليه نقطة الوميض؟","options":["هي درجة الحرارة التي يتجمد عندها السائل ويتوقف عن التموّج في الصهريج","هي أدنى درجة حرارة يطلق عندها السائل بخارًا كافيًا لتكوين خليط قابل للاشتعال","هي درجة الحرارة التي يشتعل عندها السائل ذاتيًا دون أي شرارة أو لهب مكشوف","هي درجة الحرارة التي يتمدد عندها السائل بما يكفي ليبدأ بالتسرب من الحاوية"],"explanation":"نقطة الوميض هي أدنى درجة حرارة يطلق عندها السائل بخارًا كافيًا لتكوين خليط قابل للاشتعال."},"220":{"q":"أنا أنقل صهريج سائب جاف محمّلًا بمسحوق الإسمنت، وأقترب من منحدر خروج على شكل ورقة البرسيم به منعطف مُحدد سرعته. بسبب الطريقة التي تتصرف بها هذه البضائع، أي عامل ينبغي أن يحدد أكثر من غيره كيفية اجتيازي لهذا المنعطف؟","options":["تستقر الحمولة منخفضة وثابتة، لذا يمكنني اجتياز المنعطف بسرعة الطريق السريع المُحددة دون تعديل","الصهريج مزود بحواجز كصهريج السوائل، لذا فإن التموّج مضبوط تمامًا ولا تهم سوى مسافة التوقف","تركب الحمولة عاليًا وتتحرك مع حركة المركبة، لذا ينبغي أن أبطئ قبل المنعطف بوقت كافٍ وأن أوجّه بسلاسة","يتماسك المسحوق صلبًا بمجرد التحرك، لذا فإن تصحيحات التوجيه المفاجئة في المنعطف آمنة تمامًا"],"explanation":"للصهاريج السائبة الجافة مركز ثقل مرتفع وحمولات متحركة، لذا أبطئ قبل المنعطف بوقت كافٍ ووجّه بسلاسة."},"221":{"q":"إذا لم تكن متأكدًا مما إذا كانت الحمولة تحتاج إلى لافتات، فينبغي أن:","options":["تخمّن وتنطلق","تتحقق من الجداول","تتخطى اللافتات","تسأل راكبًا"],"explanation":"تحقق من جداول اللوائح."},"222":{"q":"لقد قبلت للتو حمولة يجب وضع لافتات لها على جميع الجوانب الأربعة، ويستعجلني موزّع شركة النقل للانطلاق. قبل أن أغادر الساحة، أي وثيقة اعتماد يجب أن أحملها شخصيًا كي أقود هذه الحمولة ذات اللافتات بشكل قانوني؟","options":["شهادة فحص طبي سارية من وزارة النقل (DOT)، والتي تخوّلني وحدها نقل أي شحنة تحمل لافتات","تصديق صهاريج (N)، لأن الحمولات ذات اللافتات تُنقل دائمًا في مقطورات صهاريج سائبة","لا شيء إضافي على رخصتي، لأن الشاحن قد أعدّ المستندات ووضع اللافتات بالفعل","تصديق مواد خطرة (H) ساري، يُحصل عليه بعد اجتياز فحص خلفية وبصمات أصابع لدى إدارة أمن النقل (TSA)"],"explanation":"يتطلب نقل حمولة مواد خطرة تحمل لافتات تصديق مواد خطرة (H) ساريًا، يُكتسب باجتياز فحص خلفية وبصمات أصابع لدى إدارة أمن النقل (TSA)."},"223":{"q":"أنا أنقل حمولة من المواد الأكّالة تحمل لافتات وأريد أن أعدّ مستندات الشحن بشكل صحيح قبل أن أنطلق. أستغرق بضع دقائق لوضع علامات تبويب على مُدخلات المواد الخطرة ووسمها بوضوح. عندما يطلبها مفتش أو مستجيب أول، ما الهدف الكامل من وضع علامات التبويب ووسم تلك المستندات بهذه الطريقة؟","options":["كي يمكن العثور على مستندات المواد الخطرة بسرعة وسهولة في حالة طارئة أو تفتيش","كي تبقى مستندات المواد الخطرة مطوية ومخزّنة بعيدًا عن الأنظار حتى تُطلب تحديدًا","كي تُفصل مُدخلات المواد الخطرة وتُنحّى جانبًا عن بقية أوراق الحمولة","كي يمكن التخلص من مستندات المواد الخطرة بمجرد إتمام التسليم والتوقيع عليه"],"explanation":"يجب وضع علامات تبويب على مستندات شحن المواد الخطرة أو وسمها كي يمكن العثور عليها بسرعة وسهولة أثناء حالة طارئة أو تفتيش."},"224":{"q":"أنت تنقل حمولة من المواد الأكّالة تحمل لافتات عندما يتعطل وصلة وتبدأ المادة بالتسرب على كتف طريق سريع مزدحم. يبدأ المارة بالتجمع قرب مقطورتك. من بين الإجراءات أدناه، أيها ينبغي أن يكون أولويتك الأولى قبل أي شيء آخر؟","options":["أخرج مستندات الشحن واتصل بمركز CHEMTREC للإبلاغ عن المنتج وكميته بالضبط","ابقَ بعيدًا عن التسرب وأبعِد المارة لحماية الجميع من التعرض","افتح دليل الاستجابة الطارئة للبحث عن إجراء تنظيف الانسكاب لرقم التعريف ذاك","اتصل بشركة النقل كي تتمكن الشركة من تقديم تقرير الحادث المطلوب للسلطات"],"explanation":"في أي حادث مواد خطرة، احمِ الأرواح أولًا بالبقاء بعيدًا عن التسرب وإبعاد المارة عن التعرض."},"225":{"q":"تقود شاحنتك الصهريجية إلى منصة التحميل لتحميل سائل قابل للاشتعال. قبل أن يبدأ أي منتج بالتدفق إلى صهريج الشحن، أي خطوة هي الأهم لمنع شرارة كهرباء ساكنة من إشعال الأبخرة؟","options":["اترك محرك الشاحنة في وضع الخمول كي يبقي المولّد مستشعرات مستوى الصهريج مزوّدة بالطاقة أثناء التحميل","ضع مثلثات التحذير العاكسة حول منصة التحميل تحسبًا لاقتراب مركبات أخرى","اربط الصهريج بمعدات التحميل وأرّض كليهما قبل فتح خط التعبئة","افتح غطاء القبة مبكرًا كي تتنفّس الأبخرة المتراكمة وتنخفض الضغط في الداخل"],"explanation":"يؤدي الربط والتأريض قبل فتح خط التعبئة إلى تصريف الكهرباء الساكنة التي يولّدها تدفق السائل القابل للاشتعال، مما يمنع شرارة قد تشعل البخار."},"226":{"q":"أثناء التحميل/التفريغ، يجب أن يبقى المراقب ضمن مسافة:","options":["ميل واحد","25 قدمًا","ميلين","نصف ميل"],"explanation":"ابقَ ضمن مسافة 25 قدمًا مع رؤية واضحة."},"227":{"q":"أنا أنقل حمولة تحمل لافتات تتطلب وجود مراقب، وقد توقفت في موقف مخصص لقضاء الليل. وافق زميلي السائق على البقاء مع المركبة كمراقب بينما أستريح في فندق قريب. أي مما يلي يصف أفضل وصف كيف يجب على زميلي السائق أداء واجب المراقبة هذا لكي يُعتدّ به؟","options":["يمكنه أن يغفو في مقصورة النوم طالما بقي ضمن 100 قدم من الحمولة","يمكنه الجلوس في مطعم مغلق عبر الموقف، ما دام لا يزال يرى المقطورة","يمكنه المغادرة لفترة وجيزة لتزويد سيارته الخاصة بالوقود إذا لم يكن أحد موجودًا","يجب أن يبقى مستيقظًا ويقظًا، ضمن 100 قدم من المركبة، مع رؤية غير معاقة لها"],"explanation":"يجب على مراقب الحمولة التي تحمل لافتات أن يبقى مستيقظًا ويقظًا، ضمن 100 قدم من المركبة، وأن يحافظ على رؤية غير معاقة لها."},"228":{"q":"أنا أنقل حمولة تحمل لافتات من سائل قابل للاشتعال في رحلة طويلة بين الولايات وانتهيت للتو من فحص الإطارات قبل الرحلة قبل مغادرة المحطة. للالتزام بقاعدة الفحص أثناء الطريق، كم مرة يجب أن أتوقف لإعادة فحص إطاراتي خلال الرحلة؟","options":["مرة واحدة على الأقل كل ساعتين أو كل 100 ميل، أيهما يأتي أولاً","مرة واحدة على الأقل كل 100 ميل، لكن مهلة الساعتين لا تنطبق بمجرد أن أكون على الطريق السريع","مرة واحدة على الأقل كل 3 ساعات أو كل 150 ميلاً، أيهما يأتي أولاً","فقط عندما أتوقف لتزويد الوقود أو أخذ استراحة 30 دقيقة المطلوبة"],"explanation":"أثناء نقل حمولة تحمل لافتات يجب أن تفحص الإطارات أثناء الطريق مرة واحدة على الأقل كل ساعتين أو كل 100 ميل، أيهما يأتي أولاً."},"229":{"q":"أنا أول من يصل إلى موقع انقلاب لمركبة تنقل حمولة تحمل لافتات. لا يستطيع مركز الإرسال قراءة اسم الشحن الصحيح عبر الدخان، لكنهم أبلغوني لاسلكيًا برقم الأمم المتحدة المكوّن من 4 أرقام المطبوع على العبوة. للبحث عن معلومات الاستجابة للطوارئ بأسرع طريقة باستخدام هذا الرقم فقط، أي قسم من دليل الاستجابة للطوارئ (ERG) يجب أن ألجأ إليه؟","options":["صفحات الدليل ذات الحدود البرتقالية، التي تصنّف المواد حسب لون الخطر المخصص لها","الصفحات ذات الحدود الصفراء، التي تسرد المواد بترتيب رقمي حسب رقم التعريف","الصفحات ذات الحدود الزرقاء، التي تسرد المواد أبجديًا حسب اسم الشحن","الصفحات ذات الحدود البيضاء، التي تسرد المواد حسب وزن العبوة والكمية"],"explanation":"الصفحات ذات الحدود الصفراء في دليل ERG تسرد المواد بترتيب رقمي حسب رقم التعريف، لذا فهي الأسرع عندما تعرف رقم التعريف المكوّن من 4 أرقام فقط."},"230":{"q":"أنا في موقع تسرب من حمولتي التي تحمل لافتات. تلفت أوراق الشحن، لذا لا أملك رقم تعريف الأمم المتحدة/أمريكا الشمالية، لكن الحاوية مطبوع عليها بوضوح \"CHLORINE\" (كلور). للبحث عن هذه المادة بسرعة في الصفحات ذات الحدود الزرقاء من دليل ERG، على ماذا أعتمد للعثور على المُدخل؟","options":["رقم تعريف الأمم المتحدة/أمريكا الشمالية المكوّن من أربعة أرقام المطبوع على الحاوية","رقم فئة الخطر الموجود على اللافتة المعروضة على الخزان","اسم الشحن الصحيح للمادة، المُدرج أبجديًا","رمز اللون التابع لوزارة النقل المطبوع على ملصق العبوة"],"explanation":"الصفحات ذات الحدود الزرقاء في دليل ERG تسرد المواد أبجديًا حسب اسم الشحن الصحيح، لذا فهي الأداة التي تُستخدم عندما تعرف الاسم وليس رقم التعريف."},"231":{"q":"أنا أنقل حمولة تحمل لافتات من مواد أكّالة عندما يفشل أحد الوصلات ويبدأ المنتج بالتسرب على كتف الطريق. أمسك دليل الاستجابة للطوارئ (ERG)، وأبحث عن رقم تعريف المادة، وأحتاج إلى معرفة كيفية حماية الناس والاستجابة بأمان في الموقع. أي قسم من دليل ERG يجب أن ألجأ إليه للحصول على تلك المعلومات؟","options":["الصفحات ذات الحدود الزرقاء، لأن أدلة إجراءات الاستجابة لكل مادة مرتبة هناك أبجديًا حسب اسم الشحن الصحيح","الصفحات ذات الحدود الخضراء، لأنها تسرد مسافات إجراءات الحماية وتخبرني بالضبط كيفية التعامل مع التسرب","الصفحات ذات الحدود الصفراء، لأن الأدلة المرقّمة التي تصف ما يجب فعله في الموقع مفهرسة هناك حسب رقم الأمم المتحدة/أمريكا الشمالية","الصفحات ذات الحدود البرتقالية، لأنها تحتوي على أدلة إجراءات الاستجابة المرقّمة التي تخبرني كيفية حماية الناس والسيطرة على الحادث"],"explanation":"تحتوي الصفحات ذات الحدود البرتقالية في دليل ERG على أدلة الاستجابة المرقّمة التي تشرح المخاطر وإجراءات السلامة العامة لحماية الناس والسيطرة على الحادث."},"232":{"q":"انقلبت صهريج أمامي وهي تسرّب غازًا سامًا. أثناء اتصالي بـ CHEMTREC، أفتح دليل الاستجابة للطوارئ على الصفحات ذات الحدود الخضراء لأقرر إلى أين يجب أن أنقل الناس. ما المعلومات التي صُممت هذه الصفحات الخضراء لتزويدي بها؟","options":["مسافات العزل الأولي وإجراءات الحماية التي تخبرني إلى أي مدى يجب إخلاء الناس وإبعادهم عن مصدر الانبعاث","قائمة أسماء الشحن الصحيحة مقترنة بأرقام تعريف الأمم المتحدة/أمريكا الشمالية المكوّنة من أربعة أرقام","دليل الاستجابة العام الذي يصف إجراءات الحريق والتسرب والإسعافات الأولية لرقم دليل تلك المادة","أرقام CHEMTREC وأرقام هواتف الطوارئ التي يجب الاتصال بها للحصول على المساعدة الفنية أثناء الحادث"],"explanation":"الصفحات ذات الحدود الخضراء في دليل ERG تعطي مسافات العزل الأولي وإجراءات الحماية التي تخبرك إلى أي مدى يجب إخلاء الناس وإبعادهم عن مصدر الانبعاث."},"233":{"q":"أنا أحمّل مقطورتي في محطة ويسلّمني مشرف الرصيف أوراق شحن تتضمن رمزًا حرفيًا (حرف \"مجموعة التوافق\") مطبوعًا مباشرة بعد قسم الخطر في أحد المُدخلات. يقول إن هذا الحرف يخبرني أي العناصر الأخرى في نفس فئة الخطر يمكن أو لا يمكن تحميلها معًا في نفس المركبة. بناءً على كيفية تنظيم المواد الخطرة، أي فئة من المواد يشير إليها حرف مجموعة التوافق هذا؟","options":["الفئة 8 المواد الأكّالة، حتى أتمكن من منع الأحماض والقواعد من التفاعل مع بعضها في المقطورة","الفئة 1 المتفجرات، حتى أتمكن من معرفة أي الأقسام والأنواع يمكن تحميلها ونقلها معًا","الفئة 2 الغازات، حتى أتمكن من فصل الغازات القابلة للاشتعال عن الغازات السامة أثناء التحميل","الفئة 7 المواد المشعة، حتى أتمكن من إبقاء مجاميع مؤشر النقل ضمن حدود المركبة الواحدة"],"explanation":"أحرف مجموعة التوافق تخص فقط الفئة 1 المتفجرات، حيث تبيّن أي أقسام وأنواع المتفجرات يمكن تحميلها ونقلها معًا بأمان."},"234":{"q":"أنا أُعدّ أوراق الشحن لحمولة تتطلب لافتات وألاحظ أن أحد المُدخلات يسرد رقم تعريف يبدأ بالحرفين 'NA' بدلاً من 'UN'. يسألني سائق أحدث عمّا يشير إليه هذا البادئة بشأن أين يكون الرقم صالحًا. أي مما يلي هو الصحيح أن أخبره به؟","options":["إنه رقم منسّق دوليًا معترف به للشحنات في أي مكان في أوروبا وآسيا","إنه يشير إلى أن الحمولة يمكن نقلها فقط على طرق التصدير المخصصة للخارج، وليس محليًا أبدًا","إنه رقم تعريف مخصص للاستخدام داخل أمريكا الشمالية، بما في ذلك الولايات المتحدة وكندا","إنه يعني 'غير منطبق'، لذا لا يلزم فئة خطر أو اسم شحن صحيح لذلك السطر"],"explanation":"البادئة 'NA' تشير إلى رقم تعريف مخصص للاستخدام داخل أمريكا الشمالية فقط، أي الولايات المتحدة وكندا."},"235":{"q":"أنا أنقل حمولة تحمل لافتات من سائل قابل للاشتعال من هيوستن باتجاه ميناء للتصدير إلى الخارج، وتسرد أوراق شحني المادة باسم شحن صحيح وفئة خطر ورقم تعريف 'UN'. يجادل سائق جديد يركب معي بأن رقم 'UN' هذا يهم فقط هنا في تكساس ويمكن تجاهله بمجرد أن تغادر الشحنة الولاية. أي عبارة عن رقم تعريف 'UN' هذا صحيحة؟","options":["ينطبق رقم 'UN' فقط داخل تكساس، لذا فالسائق الجديد محق في أنه يتوقف عن الأهمية عند حدود الولاية","رقم 'UN' صالح فقط للشحنات المنقولة بحرًا، لذا ينطبق بمجرد وصول الشحنة إلى الميناء","رقم 'UN' صالح فقط للشحنات المنقولة جوًا، لذا يلزم رمز مختلف لهذه الشاحنة","رقم 'UN' معترف به دوليًا، لذا فهو يعرّف المادة بنفس الطريقة بغض النظر عن أين تسافر الشحنة"],"explanation":"رقم تعريف 'UN' معترف به دوليًا، لذا فهو يعرّف المادة بنفس الطريقة بغض النظر عن أين تسافر الشحنة."},"236":{"q":"أنا أقوم بفحص ما قبل الرحلة وألاحظ أن إحدى عبواتي تحمل ملصقًا على شكل معيّن لا أتعرف عليه. للتأكد مما إذا كان يشير إلى مادة سامة قبل أن أقبل الحمولة، أي رمز على ذلك الملصق يجب أن أبحث عنه؟","options":["جمجمة وعظمتان متقاطعتان داخل المعيّن","رمز لهب فوق رقم فئة الخطر","كرة سوداء تحترق بأشعة داخل المعيّن","رمز ثلاثي الشفرات على شكل مروحة (شبه نبات النفل)"],"explanation":"يُعرّف عن المادة السامة (القسم 6.1) برمز جمجمة وعظمتين متقاطعتين داخل الملصق المعيّن."},"237":{"q":"أنا أفحص البضائع في رصيف تحميل وألتقط عبوة موسومة بملصق خطر من الفئة 7 على شكل معيّن بلونين أصفر وأبيض. للتأكد من المحتويات قبل التوقيع على استلام الحمولة، أتفحص الكتابة داخل المعيّن. أي كلمة واحدة مطبوعة على ذلك الملصق المعيّن تؤكد أن هذه شحنة من الفئة 7؟","options":["FRAGILE (قابل للكسر)، لأن العبوة تحتوي على حاويات مصادر محكمة هشة يمكن أن تنكسر","RADIOACTIVE (مادة مشعة)، لأن الكلمة المطبوعة على معيّن الفئة 7 تذكر الخطر مباشرة","CORROSIVE (مادة أكّالة)، لأن مصادر الفئة 7 المحكمة تُخزن في أغلفة خارجية مقاومة للحمض","OXIDIZER (مادة مؤكسدة)، لأن المادة المشعة تطلق طاقة يمكن أن تدعم الاحتراق"],"explanation":"يطبع ملصق الفئة 7 حرفيًا كلمة RADIOACTIVE (مادة مشعة) داخل المعيّن، مما يذكر فئة الخطر مباشرة."},"238":{"q":"أنا عند رصيف التحميل أملأ خزان حمولتي بالبنزين في ظهيرة تكساس الحارة، ويسألني عامل التحميل إلى أي ارتفاع أريد رفع المنتج قبل أن يوقف المضخة. لنقل هذا السائل القابل للاشتعال بأمان وقانونيًا، كيف يجب أن أُحمّل الخزان؟","options":["مملوءًا حتى القمة تمامًا كي لا يتمكن السائل من التموج والاندفاع ضد الحواجز أثناء الكبح","مملوءًا فقط حتى علامة المنتصف، إذ لا يجوز قانونيًا تشغيل خزان سائل قابل للاشتعال بأكثر من 50 بالمئة من سعته","متوقفًا قبل الامتلاء بحيث يبقى مساحة فارغة لتمدد المنتج عند ارتفاع حرارته أثناء الرحلة","مملوءًا حتى الأعلى تمامًا، ثم مختومًا مع تطبيق ملصق الخطر الصحيح فوق القبة كي يُحتسب ممتلئًا"],"explanation":"يجب ألا يُملأ خزان حمولة السائل القابل للاشتعال بالكامل لأن السائل يتمدد عند ارتفاع حرارته ويحتاج إلى مساحة فارغة."},"239":{"q":"أنا أحمّل خزان حمولة بسائل قابل للاشتعال في صباح بارد مبكر، وأخطط للقيادة جنوبًا إلى طقس أكثر دفئًا بكثير مع تقدم النهار وارتفاع الحرارة. لتحديد إلى أي مدى يمكنني ملء الخزان بأمان، أي حقيقة عن الحمولة يجب أن تحكم قراري؟","options":["يمكنني ملء الخزان بالكامل حتى الأعلى، لأن السائل ينكمش ويشغل مساحة أقل مع ارتفاع درجة الحرارة الخارجية خلال النهار","لا يهم مستوى الملء بالنسبة للسوائل، لأن الغازات المضغوطة فقط هي التي تتغير في الحجم عندما تتغير درجة الحرارة حول الخزان","يجب أن أملأه حتى الأعلى الآن وهو بارد، لأن السائل الأبرد يتمدد وقد يفيض إذا انتظرت حتى منتصف النهار لتحميله","يجب أن أترك مساحة فارغة (فراغ تمدد) في الخزان، لأن السائل سيتمدد عند ارتفاع حرارته ويحتاج إلى مساحة كي لا يفيض"],"explanation":"اترك مساحة فارغة (فراغ تمدد) في الخزان لأن السائل يتمدد عند ارتفاع حرارته ويحتاج إلى مساحة لمنع الفيضان."},"240":{"q":"أنا أحمّل صندوقين من المواد الخطرة التي تحمل لافتات عند رصيف عندما تحذّر أوراق الشاحن من أن المادتين يمكن أن تتفاعلا بشكل خطير إذا تلامستا. المقطورة نصف فارغة وأريد أن أنتهي بسرعة. لتحميل هذه الشحنة بأمان، ماذا يجب أن أفعل؟","options":["أحمّل المادتين بحيث تبقيان منفصلتين عن بعضهما في المقطورة","أحمّل المادتين جنبًا إلى جنب كي يسهل تفريغهما معًا","أمزج المنتج السائب من كليهما كي يستقر بالتساوي أثناء النقل","أرصّ المادتين بإحكام كي لا تتحرك أي منهما على الطريق"],"explanation":"يجب تحميل المادتين الخطرتين اللتين يمكن أن تتفاعلا مع بعضهما بحيث تبقيان منفصلتين في المقطورة."},"241":{"q":"أنا عند الرصيف على وشك تحميل شحنة مواد خطرة تتطلب لافتات، وأقوم بجولتي النهائية حول المركبة قبل تحميل البضائع. أثناء مراجعتي للحالة التي يجب أن تكون عليها المعدات قبل تحميل أي مواد خطرة على مقطورتي، أي مما يلي يجب أن يكون صحيحًا؟","options":["يمكنني التحميل الآن والتحقق من ضبط الفرامل وعمل المصابيح عند أول فحص إطارات كل ساعتين على الطريق","يجب أن تكون الفرامل والمصابيح قد فُحصت وتأكد عملها بشكل صحيح قبل تحميل أي مواد خطرة","فقط فرامل خدمة المقطورة يجب أن تعمل؛ يمكن فحص المصابيح لاحقًا بما أن التحميل يتم في وضح النهار عند الرصيف","الفرامل والمصابيح لا تهم إلا بعد تركيب اللافتات، لذا يمكنني التحميل أولاً والفحص بعد وضع اللافتات"],"explanation":"يجب فحص الفرامل والمصابيح والتأكد من عملها بشكل صحيح قبل تحميل أي مواد خطرة."},"242":{"q":"أنا أحمّل منصة من عبوات المواد الأكّالة يدويًا عند رصيف شاحن، وعدة صناديق ثقيلة وصعبة الإمساك بها. للتعامل معها بأمان وتجنب إتلاف الحاويات، أي جزء من كل عبوة يجب أن أستخدمه للرفع والنقل؟","options":["أمسكها من ملصقات الخطر المطبوعة، لأن تلك الألواح مقوّاة لتحمّل المناولة","أسحبها من الألسنة المُثبّتة بالشريط أو الأشرطة المرتخية، لأنها تعطيني أمتن قبضة على الصندوق","أرفعها من جزء صلب وقوي من العبوة، وليس أبدًا من الأجزاء الضعيفة أو الملصقات","أجرّها عبر الرصيف من أقرب حافة، لأن المادة الأكّالة يمكنها مقاومة الخدوش"],"explanation":"ارفع عبوات المواد الخطرة من جزء صلب وقوي، وليس أبدًا من الأجزاء الضعيفة أو الملصقات، للحفاظ على سلامة الحاوية."},"243":{"q":"لقد عُيّنت للتو لنقل مواد خطرة تحمل لافتات، ويسلّمني مرسلي مجلدًا سميكًا من إجراءات الشركة الخاصة بالتحميل والتوجيه. أثناء قراءتي له، ألاحظ أن قواعد الشركة تذهب أحيانًا أبعد مما تعلمته للحصول على التصريح. للبقاء قانونيًا في كل رحلة، إلى جانب اتباع قواعد شركة الناقل، ماذا يُطلب مني أيضًا أن أطيع في جميع الأوقات؟","options":["فقط القواعد الداخلية لشركة الناقل، لأن مجلد الشركة يتضمن بالفعل كل ما يتطلبه القانون مني","تعليمات التوجيه الشفهية التي يعطيني إياها مرسلي عبر اللاسلكي، والتي تتجاوز أي إجراء مكتوب","ما تخبرني به علامات الطرق المحلية والحدود المعلنة، لأنها تحل محل القواعد الفيدرالية للمواد الخطرة","اللوائح الفيدرالية ولوائح الولاية للمواد الخطرة (HMR)، التي تنطبق فوق قواعد شركة الناقل الخاصة"],"explanation":"يجب على السائق اتباع اللوائح الفيدرالية ولوائح الولاية للمواد الخطرة (HMR)، التي تنطبق فوق قواعد شركة الناقل الخاصة."},"244":{"q":"أنا أستلم حمولة مواد خطرة تحمل لافتات وتتضمن أوراق الشحن شهادة شاحن موقّعة. قبل أن أوقّع كسائق، أريد أن أتأكد مما تخبرني به هذه الشهادة فعليًا. ماذا تمثّل شهادة الشاحن الموقّعة على ورقة الشحن قانونيًا؟","options":["أن الشحنة صُنّفت ووُصفت وعُبئت ووُسمت وُلصقت بشكل صحيح وفقًا للوائح","أن الناقل قد تحقق من صحة رسوم الشحن وأن العميل قد دفع بالفعل مقابل الشحنة","أن السائق قد فحص شخصيًا كل عبوة وقبل المسؤولية الكاملة عن أي تسربات تُكتشف أثناء الطريق","أن الحمولة وُزنت بشكل مستقل مرتين وأن الوزن الإجمالي يطابق بوليصة الشحن بالضبط"],"explanation":"تنص شهادة الشاحن الموقّعة قانونيًا على أن الشحنة صُنّفت ووُصفت وعُبئت ووُسمت وُلصقت بشكل صحيح وفقًا للوائح."},"245":{"q":"أثناء جولتي حول المركبة قبل الرحلة ألاحظ أن اللافتات الأربع على المقطورة برتقالية زاهية، بينما الملصقات المعيّنة الأصغر على العبوات الفردية في الداخل حمراء داكنة. يخبرني سائق زميل أن الألوان موجودة فقط لمساعدة الشاحنين على تتبع المخزون. بناءً على قواعد الإبلاغ عن المخاطر، ماذا يخبرني به فعليًا لون الملصق المعيّن للخطر؟","options":["إنه يحدد الناقل والشاحن المسؤولين عن الحمولة","إنه يشير إلى النوع أو الفئة العامة للخطر الذي تشكّله المادة","إنه يدل على الوزن الإجمالي للمنتج المُحمّل في تلك العبوة","إنه يبيّن رقم تعريف الأمم المتحدة/أمريكا الشمالية المخصص للمادة"],"explanation":"لون الملصق المعيّن للخطر يشير إلى النوع أو الفئة العامة للخطر، مثل الأحمر للمواد القابلة للاشتعال والأصفر للمواد المؤكسدة."},"246":{"q":"أنا أحمّل مقطورتي عند الرصيف وتُظهر أوراق الشحن عبوة صغيرة من غاز سام من القسم 2.3 تزن نحو 40 رطلاً فقط، بالإضافة إلى عدة براميل من مادة أكّالة من الجدول 2 يبلغ مجموعها 600 رطل. يخبرني مشرف الرصيف أنني لست بحاجة لوضع لافتات على أي شيء لأن حمولتي بأكملها أقل بكثير من حد 1,001 رطل. ماذا يجب أن أفعل بشأن اللافتات قبل أن أنطلق؟","options":["أتخطى اللافتات تمامًا، بما أن الوزن المجمّع للمادتين أقل من 1,001 رطل.","أضع لافتات للبراميل الأكّالة فقط، لأنها تشكّل الحصة الأكبر من وزن الحمولة.","أضع لافتة للغاز السام بغض النظر عن وزنه، لأن تلك المادة تتطلب لافتات بأي كمية.","أنتظر حتى تبلغ الحمولة 1,001 رطل إجمالاً قبل إضافة أي لافتات إلى المقطورة."],"explanation":"يجب وضع لافتات لمواد الجدول 1 مثل الغاز السام من القسم 2.3 بأي كمية، مهما كانت العبوة خفيفة."},"247":{"q":"لقد سلّمت للتو حمولة من سائل قابل للاشتعال ويقرأ مقياس خزان حمولتي فارغًا، لذا أتوجه إلى محطة شاحنات لتناول الغداء. يخبرني صديق أنه بما أن الخزان فارغ، يمكنني نزع جميع اللافتات الأربع والتعامل مع المركبة كأي مقطورة غير حاملة للمواد الخطرة. قبل أن ألمس أي شيء، ما هو أكثر افتراض آمن يجب أن أتخذه بشأن خزاني 'الفارغ'؟","options":["لأن المقياس يُظهر فارغًا، لم يعد الخزان يحتوي على أي مادة خطرة وآمن تمامًا للتعامل معه.","لأن المنتج قد ذهب، يمكنني قانونيًا نزع اللافتات فورًا، لأن اللافتات تنطبق فقط أثناء نقل السائل فعليًا.","لأن الحمولة سُلّمت، فإن البقايا في الداخل قد تبخرت بالكامل ولا يمكنها خلق أي بخار قابل للاشتعال أو خطر.","لأن البقايا والأبخرة يمكن أن تبقى في الداخل، قد يظل الخزان خطيرًا ويجب التعامل معه كما لو كان لا يزال يحمل مادة خطرة."],"explanation":"يمكن أن يظل الخزان المُفرّغ يحتوي على بقايا سائلة وأبخرة خطرة، لذا يجب التعامل معه ووضع لافتات عليه كما لو كان محمّلاً حتى يُطهّر بشكل صحيح."},"248":{"q":"أنا أحصل على تصريح X ويطلب مني الفاحص أن أبيّن الفرق بين 'خزان الحمولة' والخزان المحمول في المحطة. أثناء سيري في الساحة، أرى عدة خزانات تحمل مواد خطرة سائلة. أيها يجب أن أُعرّفه بشكل صحيح بأنه 'خزان الحمولة'؟","options":["الخزان الكبير المثبّت بشكل دائم والذي يشكّل جزءًا من الشاحنة أو المقطورة نفسها","خزان فولاذي قائم بذاته حُمّل على المقطورة برافعة شوكية ويمكن رفعه مجددًا","أي خزان يحمل 1,001 رطل أو أكثر من السائل، بغض النظر عن كيفية وضعه على المركبة","برميل سعة 55 غالونًا مربوط بإحكام داخل صندوق المقطورة للنقل"],"explanation":"خزان الحمولة مثبّت بشكل دائم ويشكّل جزءًا أساسيًا من الشاحنة أو المقطورة، بخلاف الخزان المحمول القابل للإزالة."},"249":{"q":"أنا أقوم بفحص ما قبل الرحلة على حمولة مواد خطرة تحمل لافتات وأفحص طفاية الحريق المثبّتة في مقصورتي. يقرأ المقياس ممتلئًا وهي مثبّتة بإحكام، لكنني أريد أن أؤكد أن الوحدة نفسها تستوفي المتطلب قبل أن أنطلق. ما هو أدنى تصنيف لطفاية الحريق يستوفي المتطلب لمركبتي التي تحمل لافتات؟","options":["تصنيف 1 A، لأن الطفاية يجب أن تتعامل مع المواد القابلة للاحتراق العادية مثل الخشب والورق","تصنيف 10 B:C على الأقل","أي طفاية عاملة مقبولة ما دام المقياس يقرأ ممتلئًا وهي مثبّتة بإحكام","طفاية من النوع المائي مصنّفة لعدد الغالونات من الوقود التي يمكن لخزاني حملها"],"explanation":"يجب أن تحمل المركبة الحاملة لمواد خطرة تحمل لافتات طفاية حريق مصنّفة 10 B:C على الأقل."},"250":{"q":"أنا أنقل حمولة تحمل لافتات من سائل قابل للاشتعال على طريق ريفي ذي مسارين وأقترب من مزلقان سكة حديد غير محكوم بلا بوابات أو أضواء أو علامة توقف. أي مما يلي يصف ما يتطلبه قانون تكساس مني أن أفعله؟","options":["أستمر بسرعة الطريق بما أنه لا توجد إشارة أو علامة توقف تجبرني على التوقف","أبطئ حتى شبه التوقف، وأخفّض السرعة أثناء وجودي على القضبان، وأمر للحفاظ على الزخم","أتوقف على بعد 15 إلى 50 قدمًا قبل أقرب قضيب، وأعبر فقط إذا كان بإمكاني تجاوز القضبان بالكامل دون توقف","أتوقف ضمن 5 أقدام من أقرب قضيب، ثم أتابع بمجرد أن أتأكد من خلو الطريق"],"explanation":"يجب على المركبة الحاملة للافتات أن تتوقف دائمًا على بعد 15 إلى 50 قدمًا قبل أقرب قضيب وتعبر فقط عندما يمكنها تجاوز القضبان بالكامل دون توقف."},"251":{"q":"أنا أنقل حمولة من السائل القابل للاشتعال تحمل لافتات تحذيرية، وقد توقفت كما هو مطلوب على مسافة 15 إلى 50 قدمًا قبل معبر السكة الحديدية. الأضواء مطفأة، ولا يوجد قطار قادم، وأستطيع أن أرى أن الجانب الآخر خالٍ وفيه مساحة كافية لمركبتي بالكامل. عندما أتقدم لعبور السكة، ما هي الطريقة الصحيحة للمتابعة؟","options":["خفّض إلى ترس أدنى في منتصف العبور حتى يكون لدى المحرك قوة سحب أكبر على القضبان","انتقل تصاعديًا عبر التروس أثناء العبور لأكتسب سرعة وأقضي وقتًا أقل على السكة","أبطئ إلى ما يشبه الزحف فوق القضبان لأتحسس أي أماكن وعرة قبل المتابعة","اعبر بترس واحد دون تغيير التروس في أي لحظة حتى أتجاوز السكة تمامًا"],"explanation":"اعبر قضبان السكة الحديدية بترس واحد مختار ولا تغيّر التروس أبدًا أثناء وجودك على السكة لتجنب توقف المحرك على القضبان."},"252":{"q":"أنا أنقل حمولة من المتفجرات من الشعبة 1.1 تحمل لافتات تحذيرية وأحتاج إلى التوقف ليلة كاملة. أثناء تجوّلي في الساحة لاختيار مكان، أي من هذه الظروف يجب أن يجعلني أرفض الموقع وأنتقل إلى غيره؟","options":["مكان مباشرة بجانب برميل لحرق القمامة حيث يلقي العمال فيه حطامًا متوهجًا","منصة حصوية مستوية وممهدة جيدًا على بُعد أكثر من 5 أقدام من الطريق المستخدم","ركن مظلل في الساحة يبقى باردًا بفعل صف من الأشجار الطويلة","مكان بأسفلت أملس مرصوف حديثًا وذو تصريف جيد للمياه"],"explanation":"يجب إبقاء المتفجرات بعيدًا عن مصادر الاشتعال النشطة مثل برميل حرق القمامة الذي يقذف اللهب والشرر."},"253":{"q":"أنا أحمّل عدة براميل محكمة الإغلاق من سائل أكّال من الفئة 8 في مقطورتي المغلقة عند رصيف الشاحن. يسألني مشغّل الرافعة الشوكية كيف أريد وضعها لأجل النقل. لكي أتعامل مع هذه الحمولة بأمان وبشكل صحيح، كيف يجب أن تُحمل البراميل؟","options":["مستلقية على جوانبها لتتراص بإحكام أكبر وتتحرك أقل أثناء النقل","واقفة معتدلة بجانبها الصحيح للأعلى، بالطريقة التي مُلئت وأُغلقت بها","مكدّسة مقلوبة رأسًا على عقب بحيث يُحتجز أي تسرب عند القاع المغلق","موضوعة على جوانبها لكن مثبّتة بإحكام بحيث لا يمكنها أن تتدحرج"],"explanation":"يجب حمل براميل المواد الخطرة منتصبة بجانبها الصحيح للأعلى، لأن أغطيتها وسدّاداتها مصممة لتكون متجهة للأعلى."},"254":{"q":"أنا أجهّز خزان شحن سائب يحمل الكبريت المنصهر، الذي يُشحن عند درجة حرارة عالية بما يكفي ليُعتبر مادة ذات درجة حرارة مرتفعة. قبل أن أنطلق، أريد أن أتأكد من أن الخزان يظهر العلامة الإضافية الوحيدة التي تتطلبها القواعد لهذا النوع من الحمولات. ما هي العلامة التي أبحث عنها؟","options":["علامة \"COLD\" (بارد)، لأن التحذير يخبر المستجيبين بأن المحتويات يجب أن تبقى مبردة دون درجة الحرارة المحيطة","علامة \"MOLTEN\" (منصهر) مكتوبة بجانب اسم الشحن الصحيح للإشارة إلى الحالة السائلة للحمولة","علامة \"HOT\" (ساخن)، التي تُعرّف الحمولة بأنها مادة ذات درجة حرارة مرتفعة لأي شخص يقترب منها","علامة \"WET\" (مبلل)، لأن القواعد تعامل أي سائل شديد السخونة كمادة خطرة عند ملامسة الماء"],"explanation":"يجب أن تظهر على المواد ذات درجة الحرارة المرتفعة كلمة HOT (ساخن) لتحذير أي شخص يقترب من خطر الحروق والحرارة."},"255":{"q":"أثناء فحصي قبل الرحلة، أراجع وثائق الشحن لبرميل من مادة يحذّر الشاحن من أنها ضارة بالأسماك والمجاري المائية إذا انسكبت قرب نهر. أحتاج إلى التأكد من أن العبوة موسومة بشكل صحيح قبل أن أقبل الحمولة. أي علامة يجب أن تظهر على هذه العبوة لتعريفها بأنها مادة ضارة بالبيئة المائية؟","options":["KEEP DRY (احفظه جافًا)، لأن ملامسة الماء تجعل هذا النوع من المواد أكثر خطورة","DANGEROUS WHEN WET (خطر عند البلل)، لأن الخطر يتعلق بالماء والمجرى المائي","THIS SIDE UP (هذا الجانب للأعلى)، لمنع السائل الضار من التسرب نحو الماء","MARINE POLLUTANT (ملوّث بحري)، التي تُعرّف المادة بأنها ضارة بالبيئة المائية"],"explanation":"تُعرّف المادة الضارة بالمجاري المائية والكائنات المائية بعلامة MARINE POLLUTANT (ملوّث بحري)."},"256":{"q":"أنا سائق رخصة قيادة تجارية جديد أدرس للحصول على تصريح المواد الخطرة، ويخبرني مرسلي بأنني ملزم قانونيًا بمعرفة القواعد التي تحكم كيفية تصنيف المواد الخطرة وتعبئتها ووسمها ونقلها. عندما أسأل أين تُكتب هذه القواعد الملزمة فعليًا، أي مصدر هو المرجع القانوني الصحيح الذي يجب أن أدرسه؟","options":["اللوائح الفيدرالية (49 CFR)، التي تحتوي على لوائح المواد الخطرة الملزمة قانونيًا","دليل الاستجابة للطوارئ (ERG)، الذي يحتوي على قواعد تصنيف المخاطر الملزمة قانونيًا","دليل رخصة القيادة التجارية في تكساس (DL-7C)، وهو المصدر القانوني الرسمي لجميع قواعد نقل المواد الخطرة","بوليصة الشحن ووثائق الشحن، حيث يكتب الناقل القواعد الحاكمة للمواد الخطرة"],"explanation":"لوائح المواد الخطرة هي القواعد الملزمة قانونيًا والمدوّنة في الباب 49 من مدونة اللوائح الفيدرالية (49 CFR)."},"257":{"q":"لقد التقطت للتو حمولة من المواد الأكّالة تحمل لافتات تحذيرية وتوقفت عند محطة شاحنات لتنظيم أوراقي قبل الانطلاق في رحلة طويلة على الطريق السريع بين الولايات. أين يُطلب مني أن أحتفظ بدليل الاستجابة للطوارئ (ERG) لأكون ملتزمًا بمجرد أن أنطلق؟","options":["محفوظًا في مكتب محطة الناقل حتى يتمكن المرسل من الرجوع إليه أثناء حادث","داخل المركبة، حيث يمكنني الوصول إليه أثناء قيادة الحمولة ذات اللافتات التحذيرية","مع أوراق الشاحن، لأن الشاحن هو من يعدّ معلومات المخاطر","مقفلًا في المقطورة مع المواد الأكّالة حتى يبقى مع المنتج الفعلي"],"explanation":"احمل دليل الاستجابة للطوارئ داخل المقصورة حيث يمكنك الوصول إليه أثناء القيادة، لأنه لا يكون مفيدًا إلا إذا كان معك."},"258":{"q":"أنت تنقل حمولة تحمل لافتات تحذيرية عندما تلاحظ كمية صغيرة من السائل تتقطر من أحد براميلك المحكمة الإغلاق على أرضية المقطورة. التسرب طفيف ولا توجد حياة أحد في خطر فوري. أي إجراء يتبع بشكل أفضل إجراءات المواد الخطرة لإدارة السلامة العامة (DPS)؟","options":["تابع طريقك إلى محطة الشاحنات التالية، حيث يمكن لميكانيكي فحص البرميل وإعادة إحكامه","قُد ببطء إلى أقرب ورشة تصليح حتى يُصلَح التسرب قبل أن ينتشر أكثر","اترك المركبة حيث هي، ولا تحركها، واطلب مساعدة مؤهلة للتعامل مع التسرب","غطِّ التقطير بخرق ماصّة، واستمر في القيادة، وأبلغ عن التسرب عند انتهاء الرحلة"],"explanation":"إذا اكتُشف تسرب لمادة خطرة، فلا تحرك المركبة أبدًا، بل اطلب مساعدة مؤهلة، لأن تحريكها قد ينشر التلوث."},"259":{"q":"أنا على وشك أن أبدأ رحلة طويلة وأنا أنقل سائلًا قابلًا للاشتعال يحمل لافتات تحذيرية، وأريد أن يستوفي فحصي قبل الرحلة معيار المواد الخطرة قبل الانطلاق. أي مما يلي يصف بشكل أفضل ما يجب أن أفحصه قبل بدء هذه الرحلة؟","options":["فقط وثائق الشحن واللافتات الأربع، لأن المركبة نفسها فُحصت في الرحلة السابقة","فقط الإطارات، لأنها العنصر الوحيد الذي تتطلب القواعد إعادة فحصه كل ساعتين أو 100 ميل","فقط نظام الفرامل، لأن الفرامل هي المكوّن الأكثر أهمية على وحدة مواد خطرة محمّلة","الفرامل والمركبة بأكملها، بإجراء فحص كامل قبل الرحلة للوحدة بالكامل"],"explanation":"نقل المواد الخطرة التي تحمل لافتات تحذيرية يضيف إلى واجباتك، لذا أجرِ فحصًا كاملًا قبل الرحلة للفرامل والمركبة بأكملها قبل الرحلة."},"260":{"q":"أنا أنقل حمولة من الكلور تحمل لافتات تحذيرية (غاز سام من الفئة 2.3) على طريق سريع ريفي في تكساس عندما أقترب من معبر سكة حديدية غير مميّز بلا بوابة ولا أضواء وامضة ولا حركة مرور أخرى حولي. ماذا يتطلب مني القانون أن أفعل هنا؟","options":["توقف على مسافة بين 15 و50 قدمًا قبل أقرب قضيب، ثم اعبر فقط إذا استطعت تجاوز السكة بالكامل","أبطئ وعامله كإشارة \"أفسح الطريق\"، وتابع المرور بما أنه لا توجد إشارات ولا قطارات قادمة","توقف فقط إذا رأيت إشارة STOP أو RxR منصوبة، وإلا فتابع بالسرعة المسموح بها على الطريق","انتقل إلى ترس أدنى قبل القضبان وأبقِ المحرك يسحب بثبات طوال العبور"],"explanation":"يجب أن تتوقف حمولة الغاز السام التي تحمل لافتات تحذيرية على مسافة 15 إلى 50 قدمًا قبل أقرب قضيب عند كل معبر، وأن تعبر فقط إذا استطاعت تجاوز السكة بالكامل."},"261":{"q":"لقد حصلت على تصريح المواد الخطرة (H) وأنا أنقل حمولات تحمل لافتات تحذيرية منذ ذلك الحين. يقول صديقي إنك بمجرد اجتياز تقييم التهديد الأمني والاختبار التحريري، تكون قد انتهيت مدى الحياة ولن تحتاج أبدًا إلى التعامل مع مادة المواد الخطرة مجددًا. ما الفترة التي تتوقع فيها إدارة السلامة العامة في تكساس (DPS) فعليًا أن أكرر تدريبي على المواد الخطرة للبقاء محدّثًا؟","options":["كل سنة واحدة تقريبًا، مرتبطة بكل تجديد سنوي للشهادة الطبية","كل 3 سنوات تقريبًا","كل 10 سنوات تقريبًا، بما يطابق دورة تجديد رخصة القيادة التجارية القياسية","أبدًا مرة أخرى — بمجرد اجتياز التصريح وفحص إدارة أمن النقل (TSA)، لا يُطلب أي إعادة تدريب"],"explanation":"يجب تكرار تدريب المواد الخطرة كل 3 سنوات تقريبًا للحفاظ على تحديث السائق بشأن التعامل الآمن ووضع اللافتات وإجراءات الطوارئ."},"262":{"q":"أنا أجري فحصي قبل الرحلة ووثائق الشحن تُدرج حمولة من الفئة 6.1؛ والمقطورة تُظهر بالفعل لافتة معينية مكتوبًا عليها 'POISON' (سُم/سام). يسألني سائق أحدث عمّا تحذّر منه تلك اللافتة فعليًا. أي عبارة يجب أن أعطيه إياها؟","options":["إنها تحذّر من أن الحمولة سائل قابل للاشتعال، فالخطر الحقيقي هو الحريق إذا اشتعلت قرب لهب مكشوف","إنها تحذّر من أن الحمولة أكّالة، فالخطر الحقيقي هو الحروق الكيميائية للجلد والعينين عند الملامسة","إنها تحذّر من أن المادة ضارة أو مميتة للبشر، فالتعرض لها يمكن أن يسمّم أو يقتل","إنها تحذّر من أن الحمولة مادة مؤكسِدة، فالخطر الحقيقي هو أنها تجعل المواد الأخرى تحترق أسرع"],"explanation":"تحذّر لافتة POISON أو TOXIC من أن المادة ضارة أو مميتة للبشر ويمكن أن تسمّم أو تقتل عند التعرض لها."},"263":{"q":"أنا أنقل حمولة تحمل لافتة 'OXYGEN' (الأكسجين، الفئة 2.2) عندما ألاحظ دخانًا يخرج من أحد إطاراتي عند نقطة تفتيش على جانب الطريق. وأنا أقيّم الموقف، أي مما يلي يجب أن يؤثر أكثر في كيفية تعاملي مع الحرارة وأي لهب قرب هذه الحمولة؟","options":["سيخنق الأكسجين أي حريق صغير ويطفئه قبل أن ينتشر، فيكون لديّ وقت إضافي للتفاعل.","لكونه غازًا غير قابل للاشتعال، لا يمكن للأكسجين أن يؤثر على الحريق بأي حال، فالإطار هو همّي الوحيد.","سيبرّد الأكسجين الحمولة المحيطة ويخفض درجة الحرارة، مقللًا الخطر من الإطار الساخن.","يمكن للأكسجين أن يغذّي الحريق ويكثّفه، لذا يجب أن أعامل حتى اللهب الصغير قرب هذه الحمولة كتهديد خطير."],"explanation":"الأكسجين يغذّي الحريق ويكثّفه، لذا يجب التعامل مع أي لهب أو ارتفاع حرارة قرب حمولة الأكسجين كتهديد خطير."},"264":{"q":"أنت تنقل حمولة من متفجرات الشعبة 1.2 تحمل لافتات تحذيرية وتحتاج إلى التوقف لأخذ استراحتك الإلزامية فيدراليًا. وأنت تبحث عن مكان وقوف قانوني، أي موقع يجب أن تبقى على بُعد 300 قدم على الأقل منه قبل أن تتوقف؟","options":["مستودع على جانب الطريق حيث يتجمع العمال والزبائن بانتظام","خط الضباب المرسوم عند حافة الطريق المستخدم","مجموعة قضبان سكة حديدية تعبر الطريق السريع أمامك","مركبة تجارية أخرى متوقفة بشكل قانوني في منطقة الاستراحة"],"explanation":"لا يجوز أبدًا وقوف متفجرات الشعب 1.1 و1.2 و1.3 على بُعد أقل من 300 قدم من مبنى يتجمع فيه الناس، مثل مستودع على جانب الطريق."},"265":{"q":"أنا أنقل حمولة تحمل لافتات تحذيرية وأحتاج إلى ترك مركبتي متوقفة على كتف طريق ريفي سريع لبضع دقائق بينما أتفقد مشكلة على جانب الطريق. تنص اللوائح على أن المركبة يجب أن تكون مراقَبة. لكي أُحتسب قانونيًا كمراقب، إلى أي مسافة يُسمح لي أن أبتعد عن مركبتي المتوقفة التي تحمل لافتات تحذيرية؟","options":["ضمن 5 أقدام من المركبة، وهي نفس المسافة التي يجب أن أبقيها بعيدًا عن الطريق المستخدم","ضمن 100 قدم من المركبة، مع رؤيتها بوضوح والقدرة على تحريكها عند الحاجة","ضمن 300 قدم من المركبة، وهو نفس الحاجز المطلوب حول الجسور والأنفاق","ضمن ربع ميل، طالما أنني ما زلت أرى اللافتات التحذيرية"],"explanation":"يجب أن يبقى مراقب المركبة المتوقفة التي تحمل لافتات تحذيرية ضمن 100 قدم منها، وأن يبقيها في مرمى نظره بوضوح، وأن يكون قادرًا على تحريكها في حالة الطوارئ."},"266":{"q":"أثناء فحصي قبل الرحلة، يخبرني مرسلي بأن أحد خزانات الشحن على مركبتي هو \"خزان محمول\" وليس شاحنة خزان شحن. وأنا أفحصه للتأكد، أي ميزة تُعرّفه بشكل صحيح كخزان محمول؟","options":["إنه ملحوم بشكل دائم بهيكل المركبة ولا يمكن إزالته","إنه جزء بنيوي لا يتجزأ من إطار المقطورة نفسه","إنه حاوية سائبة غير مثبتة بشكل دائم بالمركبة","إنه خزان ثابت مبني مباشرة داخل مقصورة الشاحنة وهيكلها"],"explanation":"الخزان المحمول هو حاوية سائبة غير مثبتة بشكل دائم بالمركبة، لذا يمكن تحميله وإزالته."},"267":{"q":"أنا أحمّل شحنة غاز مضغوط من الفئة 2 في مستودع كيميائي ويسألني مشرف الرصيف كيف يجب أن يكون المنتج معبَّأً بالفعل قبل أن أوقّع عليه وأنقله. لكي أقبل الحمولة بشكل قانوني وآمن، في أي نوع من الحاويات يجب أن يكون الغاز المضغوط معبَّأً؟","options":["محكم الإغلاق في صناديق كرتونية ثقيلة مربوطة معًا على منصة ملفوفة بالبلاستيك المنكمش","محمّلًا بشكل سائب في صندوق مكشوف لمقطورة مسطحة ومثبتًا بأحزمة الشحن","مصبوبًا في مقطورة قادوس مبطّنة بنفس طريقة نقل المواد السائبة الجافة","معبأً في أسطوانات مضغوطة أو محمولًا في مقطورة أنابيب مصممة للغاز"],"explanation":"الغاز المضغوط محفوظ تحت ضغط ويجب حمله في أسطوانات مصممة هندسيًا أو في مقطورة أنابيب مبنية للغاز."},"268":{"q":"أنا أنقل خزان شحن من الغاز السائل القابل للاشتعال في ظهيرة تكساس الحارة، وبينما تسخن الحمولة في الشمس أسمع صفيرًا قصيرًا وأرى نفثة صغيرة من البخار تخرج من جهاز ذي زنبرك على قمة الخزان، ثم يتوقف من تلقاء نفسه. ماذا يفعل صمام تخفيف الضغط هذا، وكيف يجب أن أتعامل معه؟","options":["إنه يطلق تلقائيًا الضغط الداخلي المتراكم لمنع تمزّق الخزان، لذا أتركه وشأنه وأدعه يعمل كما صُمّم.","إنه علامة على أن الخزان معبأ زيادة عن سعته المقدّرة، لذا يجب أن أتوقف وأنزح المنتج حتى يتوقف الصفير.","إنه يضيف ضغطًا إلى الخزان لإبقاء الغاز مضغوطًا، لذا يجب أن أتوقع استمراره في العمل دوريًا وأتجاهل البخار تمامًا.","إنه يتعطّل ويُطلق الحمولة، لذا يجب أن أشدّ الصمام أو أغطّيه في توقفي التالي لإغلاق الخزان بإحكام وإيقاف الفقد."],"explanation":"يطلق صمام تخفيف الضغط تلقائيًا الضغط الداخلي المتراكم لمنع تمزّق الخزان، لذا دعه يعمل كما صُمّم."},"269":{"q":"إذا وجدت عبوة مواد خطرة تالفة، فعليك أن:","options":["تقبلها على أي حال","لا تنقلها","تخفي الضرر","ترميها فحسب"],"explanation":"لا تنقل عبوة تالفة."},"270":{"q":"لقد انتهيت للتو من تفريغ توصيلة مواد خطرة تحمل لافتات تحذيرية، وبينما أقوم بجولتي التفقدية ألاحظ أن إحدى العبوات المتروكة على الرصيف بها بقعة رطبة متغيرة اللون تنتشر عبر القاع ورائحة كيميائية خفيفة. وقد وقّع المرسَل إليه بالفعل على استلام الحمولة. بموجب قواعد المواد الخطرة لإدارة السلامة العامة (DPS)، ما الشيء الصحيح الذي يجب أن أفعله؟","options":["لا يُطلب مني شيء آخر — لقد وقّع المرسَل إليه على الشحنة، فانتقلت إليه مسؤولية العبوة المتسربة بالكامل","أبلغ عن التسرب فورًا وأتأكد من احتواء العبوة والتعامل معها بأمان، رغم أن التسليم قد اكتمل تقنيًا","أنحّي العبوة جانبًا بعيدًا عن الأنظار وأصمت، لأن الإبلاغ عن تسرب بعد تسليم موقّع لن يجلب إلا أوراقًا وتأخيرًا لي","أعيد إغلاق العبوة بالشريط اللاصق، وأسجّل القيمة، وأرتّب للتخلص من المحتويات أو إعادة بيعها بخصم لاسترداد الخسارة"],"explanation":"يجب الإبلاغ عن أي تسرب يُكتشف فورًا واحتواء العبوة والتعامل معها بأمان، حتى بعد اكتمال التسليم."},"271":{"q":"برميل من السائل الأكّال (الفئة 8) في مقطورتي ينفجر أثناء توقف للتسليم وبركة تنتشر عبر الساحة. لقد حذّرت بالفعل المارّة، وأبقيت الناس بعيدًا، وأبلغت CHEMTREC. من الذي يجب أن يقوم فعليًا بالتنظيف المادي لهذه المادة المنسكبة؟","options":["يجب أن أمسك قفازاتي والمادة الماصّة وأنظّفها بنفسي، لأنني السائق المتحكم بالحمولة","يجب أن يأتي الشاحن وينظّفها، لأن الشاحن هو من صنّف المادة وعبّأها","يجب أن يتولى التنظيف مستجيبو طوارئ مدرّبون أو متعهدو تنظيف مؤهلون","يمكن توجيه أي شخص متاح من المارّة للمساعدة في احتواء المادة وإزالتها بسرعة"],"explanation":"تنظيف الانسكاب مهمة متخصصة لمستجيبي الطوارئ المدرّبين أو متعهدي التنظيف المؤهلين القادرين على التعامل مع المادة بأمان."},"272":{"q":"لقد أكملت للتو تدريب الوعي الأمني المطلوب لتصريح المواد الخطرة الخاص بي، ويسألني زميل عمّا كان الهدف الفعلي من ذلك التدريب. بناءً على ما صُمّم التدريب لتحقيقه، أي مما يلي هو أفضل وصف لما علّمني إياه؟","options":["حفظ فئات الخطر الأربع التي تتطلب دائمًا لافتات تحذيرية حتى أضع اللافتات أسرع عند الرصيف","تعديل مسافة المتابعة ونقاط الفرملة حتى أتمكن من تحريك حمولة ذات لافتات تحذيرية أسرع عبر حركة المرور","تخطّي الفحوصات المكررة أثناء الطريق بمجرد التحقق من أوراقي بالفعل في المحطة","التعرف على السلوك المريب أو المخاطر الأمنية المحتملة حول حمولتي والإبلاغ عن تلك التهديدات للسلطات المختصة"],"explanation":"يعلّم تدريب الوعي الأمني السائقين التعرف على السلوك المريب أو التهديدات الأمنية لحمولتهم والإبلاغ عنها للسلطات المختصة."},"273":{"q":"أنا أنقل حمولة من المواد الأكّالة تحمل لافتات تحذيرية ويطلب مني شرطي ولاية عند محطة وزن أن أشير إلى \"الوصف الأساسي\" للمادة على وثائق الشحن الخاصة بي. أي مجموعة من الإدخالات يجب أن أُريها للشرطي كالوصف الأساسي؟","options":["اسم الشحن الصحيح، وفئة الخطر، ورقم التعريف، ومجموعة التعبئة","اسم الشحن الصحيح، والوزن الإجمالي، ورقم هاتف الطوارئ، ورقم صفحة دليل ERG","فئة الخطر، ولون اللافتة، وتوقيع الشاحن، وعدد العبوات","رقم التعريف، وتسجيل المركبة، واسم الناقل، وخطة الطريق"],"explanation":"الوصف الأساسي للمادة الخطرة هو اسم الشحن الصحيح، وفئة الخطر، ورقم التعريف، ومجموعة التعبئة."},"274":{"q":"أنا أنقل حمولة من السائل القابل للاشتعال من الفئة 3 تحمل لافتات تحذيرية عندما يندلع حريق صغير قرب برميل متسرب في منطقة الشحن. لديّ عدة خيارات للإطفاء متاحة. لإخماد هذا الحريق بأكثر فعالية، ماذا يجب أن أستخدم؟","options":["أغمره بتيار ثابت غزير من الماء لتبريد السائل المحترق","أخنقه بالرغوة أو أستخدم مطفأة مصنّفة B:C لقطع الأكسجين","أجرف رملًا غير مثبّت من جانب الطريق فوق اللهب حتى يُدفن","أتركه يحترق حتى يخمد بينما تتراجع للخلف وتنتظر المستجيبين"],"explanation":"يجب خنق حريق السائل القابل للاشتعال (الفئة 3) بالرغوة أو بمطفأة مصنّفة B:C لقطع الأكسجين، ولا يُبرَّد أبدًا بالماء."},"275":{"q":"أنا أنقل سائلًا قابلًا للاشتعال من الفئة 3 (براميل بنزين) عندما يُشعل أحد البراميل حريقًا صغيرًا في منطقة الشحن بعد تسرب. يركض أحد المارّة نحوي بدلو ماء ويعرض أن يساعدني في إخماد اللهب قبل أن يكبر. قبل أن أسمح له بإلقائه، ماذا يجب أن أتوقع أن يفعله الماء بحريق السائل القابل للاشتعال هذا؟","options":["يخنق اللهب بسرعة لأن الماء يقطع إمداد الحريق بالأكسجين","يبرّد البنزين المحترق دون نقطة وميضه ويطفئ الحريق على الفور","ينشر الحريق، لأن السائل المحترق يطفو على الماء ويُحمل به","لا يفعل شيئًا يُذكر في أي اتجاه، فهو أأمن شيء نجرّبه أثناء انتظار المساعدة"],"explanation":"الماء ينشر السائل القابل للاشتعال المحترق مثل البنزين لأن السائل يطفو فوق الماء ويُحمل معه."},"276":{"q":"أنا أنقل حمولة تحمل لافتة لمادة مؤكسِدة من الصنف 5 عندما يندلع حريق صغير في الشحنة. يمسك أحد المارة بطفاية ويقول: \"لا تقلق، فإطفاؤه بحجب الهواء عنه سيخمده بسرعة.\" استناداً إلى التركيب الكيميائي لما أحمله، لماذا هذا الافتراض خاطئ؟","options":["لأن المواد المؤكسِدة آكِلة، فتأكل الطفاية قبل أن تتمكن من خنق اللهب","لأن الحريق بارد جداً بحيث لا يتأثر، بما أن المواد المؤكسِدة لا تحترق إلا في درجات حرارة التجمد","لأن المواد المؤكسِدة تمتص الماء، فإضافة أي رطوبة من الطفاية تجعل الحريق ينتشر أسرع","لأن المادة المؤكسِدة تُطلق الأكسجين الخاص بها، فيمكن للحريق أن يستمر في الاشتعال حتى مع وجود قليل من الهواء حوله"],"explanation":"المادة المؤكسِدة (الصنف 5) تُزوّد نفسها بالأكسجين، لذا يمكن للحريق أن يستمر في الاشتعال حتى مع وجود قليل من الهواء حوله ولا يمكن خنقه."},"277":{"q":"أثناء فحص ما قبل الرحلة عند الرصيف، ألاحظ بقعة رطبة صغيرة ورائحة كيميائية خفيفة تنبعث من إحدى العبوات الآكِلة (الصنف 8) التي حمّلها المُرسِل للتو. تبدو بوليصة الشحن كاملة والتسليم مرتبط بوقت محدد. ما هو أفضل سبب يدفعني لرفض نقل هذه العبوة؟","options":["العبوة المُسرّبة يمكن أن تؤذي الناس وتلوّث المنطقة المحيطة، لذا يجب عدم نقلها","التسرب الصغير يؤثر فقط على التسليم في الوقت المحدد، فيمكنني نقله ما دمت أقود أسرع لتعويض الجدول الزمني","المُرسِل وقّع بالفعل على بوليصة الشحن، فيصبح التسرب مشكلة أوراق تخص الناقل وليس أنا","البقعة الطفيفة أمر طبيعي لشحنات الصنف 8، فيمكنني مسح العبوة وتحميلها دون أي إجراء إضافي"],"explanation":"العبوة المُسرّبة لمادة خطرة يمكن أن تؤذي الناس وتلوّث المنطقة، لذا يجب على السائق رفضها وعدم نقلها."},"278":{"q":"تتعرض صهريجي الذي يحمل لافتة لتسرب مادة آكِلة بينما أنا متوقف في منطقة استراحة على جانب الطريق. الاستجابة الصحيحة هي ترك المركبة في مكانها، وإبعاد الناس، وإخطار فرق الطوارئ. في أي ظرف يكون لي مبرر فعلاً لتحريك المركبة المُسرّبة؟","options":["للوصول إلى أقرب محطة وقود قبل أن يفرغ الصهريج","لإبعاد الناس عن الخطر المباشر من الخطر المنتشر","للوصول إلى ورشة الإصلاح أسرع وتجنب تأخير طويل","لوضع الشاحنة أقرب إلى مبنى لتسهيل التنظيف"],"explanation":"يجب عدم تحريك مركبة المواد الخطرة المُسرّبة إلا عند الضرورة لإبعاد الناس عن الخطر المباشر من الخطر المنتشر."},"279":{"q":"أنا أنقل حمولة تحمل لافتة من المواد الآكِلة عندما يتسبب فشل في وصلة الاقتران بإطلاق المادة على كتف الطريق. بعد أن سيطرت على الخطر المباشر، وأبعدت المارة، ومنعت التدخين، واتصلت بفرق الطوارئ وبـ CHEMTREC، لا تزال القواعد الفيدرالية تتطلب الإبلاغ عن الحادث. أي طرف أنا مسؤول عن إخطاره ليتم تقديم تقرير الحادث المطلوب هذا؟","options":["المُرسِل، لأنه هو من صنّف وعبّأ وأعدّ أوراق الشحن للمواد الآكِلة","مفوّض الإطفاء المحلي، الذي يجب أن يقدّم تقرير الحادث الرسمي المكتوب عن أي تسرب على الطريق","صاحب العمل/الناقل، وهو الطرف المسؤول عن نقل الحمولة والإبلاغ عن الحادث","مفتش محطة الوزن في إدارة السلامة العامة بالولاية الأقرب للتسرب، لأن الحمولات التي تحمل لافتات تُتتبّع عند الموازين"],"explanation":"الناقل هو الطرف المسؤول عن نقل الحمولة وتقديم تقرير حادث المواد الخطرة المطلوب."},"280":{"q":"أنا أمشي حول مقطورتي أُجري فحص ما قبل الرحلة على حمولة تحتاج لافتة سائل قابل للاشتعال من الصنف 3. للتأكد من أن اللافتة صحيحة، أتفقد المعيّن بحثاً عن رقم صنف الخطر. أين على اللافتة يجب أن أنظر لقراءة ذلك الرقم؟","options":["عند القمة العليا للمعيّن، فوق الرمز مباشرة","في وسط المعيّن، داخل الرمز","على طول الزاوية اليمنى القصوى للمعيّن","عند القمة السفلى للمعيّن، أسفل الرمز"],"explanation":"على لافتة وزارة النقل (DOT) يوضع رقم صنف أو شعبة الخطر عند القمة السفلى للمعيّن، أسفل الرمز."},"281":{"q":"أنا أُجري فحص ما قبل الرحلة وأتفقد لافتة على شكل معيّن على المقطورة للتأكد من أنها الصحيحة. للتعرّف بسرعة على نوع الخطر بنظرة واحدة، أي جزء من اللافتة يجب أن أنظر إليه لرؤية رمز الخطر (مثل اللهب أو الجمجمة أو رمز الإشعاع المثلثي)؟","options":["الزاوية العليا للافتة، فوق اسم صنف الخطر المكتوب","الزاوية السفلى للافتة، حيث يُطبع رقم صنف الخطر","الحافة اليمنى للافتة، بجانب رقم التعريف المكوّن من أربعة أرقام","وسط اللافتة، فوق الانقسام اللوني القُطري مباشرة"],"explanation":"على لافتة وزارة النقل (DOT) يوضع رمز الخطر في الزاوية العليا للمعيّن، فوق اسم صنف الخطر المكتوب."},"282":{"q":"عند رصيف التحميل، يخبرني موزّع المهام أن حمولتي التالية ستُشحن في \"عبوة سائبة\" وأنني بحاجة للتحقق منها قبل توقيع الأوراق. أثناء سيري حول المقطورة، أي من هذه الحاويات يطابق بشكل صحيح تعريف العبوة السائبة؟","options":["منصة نقالة محمّلة بصناديق ألياف مُحكمة الإغلاق، كل منها يحتوي على عدة زجاجات صغيرة داخل حشوة واقية","خزان محمول كبير مُحمّل مباشرة بالمنتج، دون عبوة داخلية تحتجز المحتويات","برميل بلاستيكي واحد سعة 5 غالونات بغطاء لولبي موضوع قرب جدار المقطورة","كيس صغير مُحكم الإغلاق من الحبيبات مدسوس داخل علبة كرتونية تحمل ملصقاً"],"explanation":"العبوة السائبة هي حاوية كبيرة، مثل خزان محمول، مُحمّلة مباشرة بالمنتج دون عبوة داخلية تحتجز المحتويات."},"283":{"q":"أنا أُحمّل مقطورتي في مستودع كيميائي ويخبرني المُرسِل أن أوقّع على استلام عدة عبوات 'غير سائبة' من مادة آكِلة من الصنف 8. أثناء فرز الشحنة على رصيفي، أي حاوية يجب أن أتوقع أن تطابق وصف 'غير السائبة' هذا؟","options":["الصهريج الشحني سعة 6,000 غالون المثبّت بشكل دائم على مقطورة منفصلة","عربة الخزان السكّية المحمولة التي يُجرى تحويلها إلى الخط الفرعي للمستودع","البراميل الفولاذية المُحكمة سعة 55 غالوناً المكدّسة معاً على منصة نقالة واحدة","حجرة صندل النهر التي تنتظر استقبال المنتج نفسه"],"explanation":"العبوة غير السائبة هي الحاويات الأصغر المستخدمة لشحن المواد الخطرة، مثل البراميل والصناديق والجراكن والأكياس."},"284":{"q":"أثناء فحص ما قبل الرحلة على صهريج شحني مُحمّل بسائل قابل للاشتعال، أتسلّق لأتفقد منطقة القبة أعلى الصهريج. قبل أن أنطلق إلى الطريق السريع، في أي حالة يجب أن تكون أغطية فتحات الدخول لإبقاء الحمولة آمنة وخالية من التسرب؟","options":["مفتوحة قليلاً حتى يتمكن ضغط البخار الداخلي من التنفيس أثناء الرحلة","مُزالة ومخزّنة في المقصورة حتى لا تهتز وتنفلت على الطريق","متروكة مفتوحة بالكامل حتى أصل إلى محطة الفحص التالية على الطريق","مغلقة تماماً ومُحكمة الإغلاق بشكل صحيح قبل تحريك المركبة"],"explanation":"يجب أن تكون أغطية فتحة الدخول (القبة) في الصهريج الشحني مغلقة تماماً ومُحكمة الإغلاق بشكل صحيح قبل تحريك المركبة لإبقاء الحمولة محتواة."},"285":{"q":"أنا سائق صهريج على وشك تحميل سائل قابل للاشتعال من الصنف 3 عبر خرطوم نقل، وأثناء فحص ما قبل التحميل ألاحظ أن أحد الخراطيم له طبقة خارجية بالية مع شق صغير على السطح قرب وصلة الاقتران. قبل أن أربطه وأبدأ تدفق المنتج، ماذا يتطلب مني الدليل أن أفعل بشأن الخراطيم المستخدمة في التحميل أو التفريغ؟","options":["استخدم فقط خراطيم بحالة جيدة، لذا يجب أن أُنحّي هذا الخرطوم المشقوق جانباً وأختار خرطوماً غير تالف قبل التحميل","تابع التحميل بهذا الخرطوم لأن الشق على الطبقة الخارجية فقط والمحرّك سيبقى يعمل للحفاظ على ثبات الضغط","استخدم الخرطوم المشقوق لكن خفّض معدّل التدفق، لأن النقل الأبطأ يمنع فشل خرطوم بحالة هامشية","اربط الخرطوم كما هو وضع ببساطة شخصاً ثانياً على بُعد 25 قدماً ليراقب التسربات أثناء النقل"],"explanation":"يجب أن تكون الخراطيم المستخدمة في تحميل أو تفريغ المواد الخطرة بحالة جيدة، لذا يجب تنحية الخرطوم المشقوق جانباً واستخدام خرطوم غير تالف."},"286":{"q":"أنا في محطة أُجهّز مقطورتي التي تحمل لافتة، وتتراكم عدة مهام: عليّ تزويد الجرّار بالوقود، واستبدال مصباح إنارة محترق، والتوقيع على أوراق الشحن، والإشراف على طاقم ينقل براميل سائل قابل للاشتعال من الصنف 3 إلى المقطورة. خلال أي من هذه المهام يجب أن أكون أشد صرامة في إبقاء كل مصادر الاشتعال — السجائر المشتعلة، اللهب المكشوف، الأدوات المُحدِثة للشرر — بعيدة تماماً عن العملية؟","options":["أثناء تزويد الجرّار بالوقود، لأن المحرّك يبقى يعمل حتى أتمكن من مراقبة مؤشر الوقود أثناء امتلاء الخزان","أثناء قيام الطاقم بتحميل براميل السائل القابل للاشتعال من الصنف 3 إلى المقطورة، لأن الأبخرة قد تشتعل أثناء النقل","أثناء استبدال مصباح الإنارة المحترق، لأنني سأعمل بالأسلاك الكهربائية قرب الحمولة","أثناء مراجعة وتوقيع أوراق الشحن، لأنني يجب أن أبقيها في المتناول فوق غيرها قبل القيادة"],"explanation":"أبقِ كل مصادر الاشتعال بعيدة أثناء تحميل السوائل القابلة للاشتعال من الصنف 3، لأن الأبخرة المتسربة قد تشتعل أثناء النقل."},"287":{"q":"أنا أُجري فحص ما قبل الرحلة على شاحنة مُحمّلة بمتفجرات من الشعبة 1.1 قبل الانطلاق على مسار مخصص للمواد الخطرة. عدة أمور تلفت نظري أثناء الجولة. أي من النتائج التالية من شأنها وحدها أن تجعل هذه المركبة غير آمنة للتشغيل وتتطلب مني إصلاحها قبل نقل هذه الحمولة؟","options":["أحد رفارف الطين الخلفية مشقوق ومنحنٍ قليلاً عند حافته السفلية","مثلث عاكس في عدّة الطوارئ سطحه باهت وغير لامع","هناك تسرب وقود يقطر باستمرار من وصلة قرب الخزان","المرآة الجانبية للراكب مثبّتة بشكل مرتخٍ وتهتز أثناء التعطيل"],"explanation":"المركبة التي تنقل متفجرات يجب ألا يكون فيها أي تسرب للوقود أو الزيت، لأن أي تسرب يمثّل خطر حريق واشتعال غير مقبول قرب الحمولة."},"288":{"q":"يوقفني ضابط على جانب الطريق ويطلب إثباتاً بأنني مخوّل لنقل صهريج يحمل لافتة من المواد الآكِلة. لقد أكملت تقييم تهديد الأمن لدى TSA وبصمات الأصابع منذ أشهر ونجحت في كل شيء. أي وثيقة واحدة أُسلّمها تُظهر فعلاً أن تظهير المواد الخطرة (H/X) الخاص بي صالح حالياً؟","options":["خطاب الموافقة على تقييم تهديد الأمن من TSA الذي استلمته بالبريد بعد اجتياز فحص خلفيتي","شهادة فاحص وزارة النقل الطبية الحالية، لأنها ما يُثبت أنني مؤهّل بدنياً للقيادة","إيصال البصمات وحزمة الطلب التي قدّمتها في مكتب الترخيص للحصول على التظهير","رخصة القيادة التجارية الخاصة بي، لأن تظهير H أو X مطبوع مباشرة على الرخصة نفسها"],"explanation":"تظهير المواد الخطرة هو رمز (H، أو X للصهريج مع المواد الخطرة) مطبوع مباشرة على وجه رخصة القيادة التجارية."},"289":{"q":"أنا أنقل حمولة تحمل لافتة من المواد الآكِلة وأحتاج لتوقّف قصير لمراجعة أوراقي. الأماكن الوحيدة التي أجدها كلها قريبة من طريق سريع ذي مسارين. بموجب قواعد إيقاف مركبة تحمل لافتة، أي من هذه المواقع يضعني في مخالفة؟","options":["جانب طريق منعطف حيث ستقف شاحنتي على بُعد 3 أقدام فقط من الجزء المسلوك من الطريق","ساحة حصى تبعد نحو 20 قدماً عن حافة الجزء المسلوك من الطريق","مكان في منطقة استراحة يبعد 10 أقدام عن الجزء المسلوك من الطريق","منعطف واسع يُبقي شاحنتي على بُعد 8 أقدام كاملة عن الجزء المسلوك من الطريق"],"explanation":"يجب عدم إيقاف مركبة تحمل لافتة على بُعد أقل من 5 أقدام من الجزء المسلوك من الطريق."},"290":{"q":"أنا أستلم حمولة تحمل لافتة ويُسلّمني المُرسِل أوراقاً تُظهر اسم الشحن الصحيح وصنف الخطر ورقم التعريف. وقد جهّز الناقل الإرسال وسيُبلّغ عن أي حادث. وأنا أفكّر في من غيرهم مسؤول قانوناً عن النقل الآمن لهذه المواد الخطرة، أي طرف يُكمل سلسلة المسؤولية المشتركة إلى جانب المُرسِل والناقل؟","options":["العميل المستلم للشحنة، لأنه يستلم الحمولة عند الرصيف","السائق، الذي يفحص الحمولة، ويرفض التسربات، ويضع اللافتات، ويقود بأمان","وكيل TSA الذي أصدر موافقة فحص خلفيتي","موزّع المهام، الذي يُسنِد المسار فقط ولا يلمس الشحنة أبداً"],"explanation":"يُكمل السائق سلسلة سلامة المواد الخطرة بفحص الحمولة، ورفض الشحنات المُسرّبة أو غير المُعلَّمة بشكل صحيح، ووضع اللافتات على كل الجوانب، والقيادة بأمان."},"291":{"q":"أنا أُحمّل شحنة مشعّة من الصنف 7، ويخبرني المُرسِل أن أتحقق من تطابق الملصقات مع مؤشر النقل قبل توقيع الأوراق. بالنظر إلى العبوة، أرى ملصقين مطبوعَين بفئة بالأرقام الرومانية تخبرني بمستوى الإشعاع. أي مجموعة من تسميات الفئات يجب أن أتوقع أن أجدها على تلك الملصقات المشعّة؟","options":["الفئات A أو B أو C، مرقّمة بالحروف لتطابق مجموعة العبوة","الفئات 1 أو 2 أو 9، مطابقة لأرقام صنف الخطر","الفئات I أو II أو III، الدالة على مستوى الإشعاع","الفئات X أو Y أو Z، الدالة على نطاق مؤشر النقل"],"explanation":"تحمل ملصقات المواد المشعّة (الصنف 7) فئة بالأرقام الرومانية — I أو II أو III — تدل على مستوى الإشعاع ومؤشر النقل."},"292":{"q":"أنا أُحمّل مقطورة بعبوتين مختلفتين من المواد الخطرة، وتُظهر أوراق الشحن أنهما متفاعلتان مع بعضهما. لم يطلب مني المُرسِل إبقاءهما منفصلتين، وهناك متّسع لوضعهما جنباً إلى جنب. قبل أن أُثبّتهما بجانب بعضهما، ما هو القلق الأمني الحقيقي الذي عليّ أن أوازنه؟","options":["وضعهما جنباً إلى جنب لا بأس به لأن العبوة وحدها مصمّمة لمنع أي مادتين من التفاعل أبداً","القلق الوحيد هو أن الوزن المجمّع قد يدفعني فوق عتبة 1,001 رطل التي تستوجب اللافتات","لا يحدث شيء ذو معنى؛ المواد المتفاعلة تُحيّد ببساطة بعضها بعضاً عند تخزينها في المكان نفسه","تحميل المادتين الكيميائيتين المتفاعلتين معاً قد يُشعل حريقاً أو تفاعلاً كيميائياً، لذا يجب إبقاؤهما متباعدتين"],"explanation":"يجب إبقاء المواد المتفاعلة غير المتوافقة منفصلة أثناء التحميل لأن التلامس قد يُحدث حريقاً أو تفاعلاً كيميائياً خطراً."},"293":{"q":"برميل على مقطورتي التي تحمل لافتة يُسرّب سائلاً مجهولاً على كتف الطريق، وأوراق الشحن غير واضحة بشأن ماهيته بالضبط. لمعرفة ما هي المادة حتى أُعطي فرق الاستجابة معلومات دقيقة، أي من هذه يجب ألا أفعله أبداً؟","options":["تذوّق المادة أو لمسها للمساعدة في تحديد ما هي","التحقق من اسم الشحن الصحيح ورقم التعريف على أوراق الشحن","البحث عن رقم التعريف المكوّن من أربعة أرقام في دليل الاستجابة للطوارئ","ملاحظة صنف الخطر المبيّن على اللافتة والملصقات"],"explanation":"لا تتذوق أو تلمس مادة أبداً لتحديدها، لأن حتى كمية ضئيلة قد تسبب إصابة خطيرة أو تسمماً أو حروقاً كيميائية."},"294":{"q":"أنت تنقل حمولة تحمل لافتة من سائل قابل للاشتعال وتتوقف في منطقة استراحة على جانب الطريق. وبينما أنت خارج المقصورة، تلاحظ ألسنة لهب تخرج من مؤخرة مقطورتك قرب الشحنة. الحريق كبير جداً بالفعل بحيث لا يمكن إخماده بطفايتك الصغيرة. ماذا يجب أن تفعل أولاً؟","options":["تصعد وتحاول قيادة المقطورة المشتعلة إلى حقل مفتوح بعيداً عن منطقة الاستراحة","أبقِ الناس بعيدين عن المركبة وأخطِر فرق الطوارئ طلباً للمساعدة","افتح أبواب المقطورة لتنفيس الدخان والوصول إلى الشحنة المشتعلة بالداخل","ضع أوراق الشحن جانباً في المقصورة حتى لا يُتلفها الحريق"],"explanation":"بالنسبة لحريق مواد خطرة يفوق قدرة طفاية يدوية، احمِ الأرواح أولاً بإبعاد الناس وإخطار فرق الطوارئ."},"295":{"q":"أنا أُجري فحص ما قبل الرحلة على مقطورة تحمل لافتة حمّلها طاقم الرصيف ليلاً، والأوراق الموضوعة على مقعد السائق تُدرج حمولة آكِلة من الصنف 8. قبل أن أنطلق، ما هو الشيء الواحد الذي يجب أن أتأكد منه بشأن اللافتات المعلّقة بالفعل على الجوانب الأربعة؟","options":["أن لون اللافتة يطابق طلاء وكتابة جانب جرّاري","أن لافتة معروضة على كل من الجوانب الأربعة بحيث تكون قابلة للقراءة من كل اتجاه","أن اللافتات تُعرّف بشكل صحيح المادة الفعلية التي أحملها كما هو مبيّن في أوراق الشحن","أن اللافتات تطابق نوع الوقود الذي يحرقه الجرّار الذي يسحب الحمولة"],"explanation":"يجب على السائق التحقق من أن اللافتات تُعرّف بشكل صحيح المادة الفعلية التي يحملها، بمراجعتها مع أوراق الشحن."},"296":{"q":"أنا أُحمّل شحنة تستوجب لافتة من المواد الآكِلة (الصنف 8)، لكن نفدت لافتات الصنف 8 من صندوق إمداداتي. لديّ لافتات صنف 3 (قابل للاشتعال) متبقية من رحلة سابقة، والشاحنة متأخرة بالفعل عدة ساعات عن الجدول. أي من التالي هو الطريقة الصحيحة للتفكير في وضع اللافتات على هذه الحمولة قبل المغادرة؟","options":["استخدام لافتات الصنف 3 مقبول لرحلة قصيرة، لأن عرض أي لافتة لا يزال يحذّر السائقين الآخرين بأنني أنقل مادة خطرة","يمكنني السير دون أي لافتات ما دمت أُبقي أوراق الشحن التي تُظهر الصنف 8 في المتناول على المقعد","خلط لافتات الصنف 3 على جانبين وترك الجانبين الآخرين فارغين مسموح به لأن الحمولة موضوع عليها لافتات جزئياً","عرض اللافتات الخاطئة (الصنف 3) غير قانوني وغير آمن، لذا يجب ألا أحرّك الحمولة حتى أحصل على لافتات الصنف 8 الصحيحة"],"explanation":"يجب أن تكون اللافتات صحيحة على الجوانب الأربعة، لذا لا يجوز تحريك الحمولة بلافتات خاطئة؛ المادة الآكِلة من الصنف 8 تحتاج لافتات صنف 8."},"297":{"q":"أنت تنقل حمولة تحمل لافتة من سائل قابل للاشتعال عبر تكساس وساعة ساعات الخدمة الخاصة بك تُجبرك على استراحة خلال الدقائق العشرين القادمة. أمامك، يمكنك رؤية ساحة مركز تسوق مكتظة، ومنطقة استراحة على جانب الطريق مزدحمة بالعائلات، ومنعطف حصى هادئ بعيد تماماً عن أي حشد. أين يجب أن تخطط لتوقّفك؟","options":["عند منعطف الحصى الهادئ، باختيار مكان آمن بعيداً عن الناس كلما توقفت بحمولة تحمل لافتة","عند منطقة الاستراحة المزدحمة، لأن مناطق الاستراحة هي النقاط الوحيدة المعتمدة قانونياً لتوقّف المركبات التي تحمل لافتات","عند ساحة مركز التسوق المكتظة، لأن البقاء في منطقة مزدحمة جيدة الإضاءة بها شهود يُبقي الشحنة أكثر أماناً من السرقة","حيثما تصادف وجودك عند انتهاء الساعة، بالتوقف عند حافة الجزء المسلوك من الطريق حتى لا تخسر وقت القيادة"],"explanation":"عند نقل حمولة تحمل لافتة، خطّط دائماً للتوقف في مكان آمن بعيداً عن الناس لتقليل التعرّض إذا حدث خطأ ما."},"298":{"q":"لقد حصلت للتو على تظهير H وأنا أراجع لماذا توجد كل أنظمة المواد الخطرة قبل أول رحلة لي تحمل لافتة. يخبرني زميل سائق أن القواعد تتلخص في ثلاثة أهداف جوهرية: احتواء المنتج، والإبلاغ عن الخطر، وهدف آخر. باستثناء أي هدف أدناه، كل هذه تعكس الغرض الفعلي من أنظمة المواد الخطرة. أي خيار لا ينتمي لأنه يسيء صياغة الهدف الثالث؟","options":["احتواء المادة بحيث يُمنع التسرب أو يُحدّ منه","نقل الشحنة أسرع وخفض تكاليف التسليم للناقل","الإبلاغ عن الخطر عبر اللافتات والملصقات وأوراق الشحن","ضمان وصول المنتج إلى وجهته بأمان ودون ضرر"],"explanation":"أهداف قواعد المواد الخطرة هي احتواء المنتج، والإبلاغ عن الخطر، وضمان النقل الآمن، وليس تسريع التسليم أو خفض التكاليف."},"299":{"q":"أنا سائق مواد خطرة جديد أستلم حمولة من المواد الآكِلة. تبدو البراميل مُحكمة الإغلاق، لكنني ألاحظ أن أوراق الشحن مُلئت قبل وصولي ولم يكن لي رأي في كيفية تصنيف المنتج أو تعبئته. وأنا أرتّب من يملك أي واجب، أي من التالي هو مسؤولية المُرسِل وليس مسؤوليتي كسائق؟","options":["التوقف على بُعد 15 إلى 50 قدماً قبل أي معبر سكة حديد وعدم تبديل التروس أثناء العبور أبداً","وضع اللافتات على الجوانب الأربعة للمقطورة وإبقاء الأوراق في متناولي أثناء القيادة","التحديد الصحيح لاسم الشحن الصحيح واختيار العبوة المناسبة للمادة","رفض الشحنة إذا كان أحد البراميل يُسرّب وفحص الشحنة قبل نقلها"],"explanation":"يُصنّف المُرسِل المادة، ويُحدّد اسم الشحن الصحيح، ويختار العبوة الصحيحة قبل وصول الحمولة إلى السائق."}},"tanker":{"0":{"q":"أنا أقود عدة حمولات مختلفة كل أسبوع، وأحاول معرفة أي وظيفة تتطلب مني إضافة تظهير مركبة صهريج (N) إلى رخصتي التجارية. لأي من الحمولات التالية يكون تظهير N مطلوباً؟","options":["نقل سوائل أو غازات داخل صهريج سائب مثبّت بشكل دائم على المركبة","سحب شاحنة جافة مُحمّلة بشحنة مُعبّأة على منصات نقالة تتحرك أثناء النقل","نقل مقطورة مبرّدة من المنتجات الطازجة التي يجب أن تبقى باردة","قيادة مقطورة صهريج فارغة عائداً إلى الساحة بعد تفريغها بالكامل"],"explanation":"تظهير N (مركبة الصهريج) مطلوب لنقل السوائل أو الغازات في صهريج سائب مثبّت بشكل دائم بسبب ارتفاع مركز الثقل ومخاطر اندفاع السائل."},"1":{"q":"أنا أنقل صهريجاً سائلاً محمّلاً جزئياً وأتوقف عند إشارة حمراء أسفل منحدر هابط. عندما تتحول الإشارة إلى الأخضر وأبدأ بالانطلاق، يجب أن أكون مستعداً بشكل خاص للعامل الوحيد الذي يجعل صهريج السائل أصعب في التحكم من حمولة جافة مماثلة. ما هو هذا العامل؟","options":["الطلاء العاكس اللامع للصهريج يجعل تقدير المسافات في الليل أصعب","تدفق السائل ذهاباً وإياباً داخل الصهريج، والذي يمكن أن يدفع الشاحنة إلى الأمام","التآكل الأسرع للإطارات الناتج عن نقل السوائل بدلاً من البضائع الجافة","الوزن الإجمالي الخفيف بشكل غير عادي لحمولة السائل مقارنة بالحمولة الجافة"],"explanation":"في الصهريج المملوء جزئياً يتدفق السائل ذهاباً وإياباً، ويمكن أن يدفع التدفق الأمامي بعد التوقف الشاحنة إلى الأمام."},"2":{"q":"أنا أحمّل مقطورة صهريج بسائل بارد في محطة في ظهيرة حارة في تكساس، ويخبرني عامل التحميل أنه سيترك أعلى الصهريج فارغاً جزئياً بدلاً من ملئه حتى الأعلى تماماً. يقول إن لهذه الفجوة اسماً محدداً وسبباً محدداً. ماذا تُسمى هذه المساحة الفارغة المقصودة، ولماذا تُترك؟","options":["مساحة التدفق، وتُترك ليكون لدى السائل مجال للتمايل ذهاباً وإياباً وتقليل الدفع الأمامي عند الكبح","مساحة التوازن، وتُترك فارغة لأتمكن من إضافة وزن لاحقاً للحفاظ على ثبات مركز الثقل المرتفع في المنعطفات","الفجوة (Outage)، وتُترك ليكون لدى السائل مجال للتمدد عندما يسخن أثناء الرحلة","الفائض، ويُترك فارغاً ليتمكن الصهريج من تنفيس البخار الزائد عبر فتحة الرجل دون تسرب"],"explanation":"تُسمى المساحة الفارغة المتروكة في أعلى صهريج السائل الفجوة (Outage)، وهي تمنح السائل مجالاً للتمدد عندما يسخن."},"3":{"q":"أنا أنقل حمولة كاملة من السائل في مقطورة صهريج وأقترب من منحدر خروج معلن على الطريق السريع بسرعة 35 ميلاً في الساعة. مقارنة بمقطورات الصناديق الجافة التي أقطرها عادة، لماذا يجب أن أسلك هذا المنحدر بسرعة أقل بكثير من السرعة المعلنة؟","options":["لأن المساحة الفارغة (الفجوة) المتروكة فوق السائل تنقل الحمولة إلى الخلف، مما يخفف وزن محور التوجيه","لأن السائل أخف وزناً من البضائع الجافة، لذا فإن فراملي تملك جراً أقل بكثير لإبطاء المركبة","لأن الصهريج الممتلئ يلغي التدفق، فلا يبقى لدى نظام التعليق شيء ليمتص قوة الانعطاف","لأن السائل يستقر عالياً في الصهريج، مما يمنح المركبة مركز ثقل مرتفعاً ينقلب بسهولة"],"explanation":"تستقر حمولة السائل عالياً في الصهريج، مما يمنح المركبة مركز ثقل مرتفعاً يجعلها تنقلب بسهولة."},"4":{"q":"أنت تنقل صهريجاً محمّلاً جزئياً من السائل على طريق سريع وترى أمامك منحدر خروج معلناً عليه '35 ميلاً في الساعة'. لأن مركبتك الصهريجية ذات مركز ثقل مرتفع، ما هي أكثر طريقة آمنة للتعامل مع المنحدر؟","options":["خفّض سرعتك إلى ما دون السرعة المعلنة 35 ميلاً في الساعة بكثير قبل دخولك المنحدر","حافظ على السرعة المعلنة 35 ميلاً في الساعة خلال المنحدر لأن ذلك الحد مُحدّد للسير الآمن","انتظر حتى تصبح في المنعطف، ثم اكبح بقوة لتقليل السرعة","حافظ على سرعتك عند دخول المنحدر ووجّه بحدّة للبقاء في مسارك"],"explanation":"لأن المركبات الصهريجية ذات مركز ثقل مرتفع، خفّض السرعة إلى ما دون السرعة المعلنة بكثير واكبح بلطف قبل دخول منحدر أو منعطف لمنع الانقلاب."},"5":{"q":"أنا أنقل حمولة في مقطورة صهريج، وأثناء فحص ما قبل الرحلة ألاحظ أن الداخل مقسّم إلى عدة أقسام منفصلة تماماً بجدران صلبة تمتد عرضياً عبر الصهريج، دون فتحات بين الأقسام. عندما يطلب مني الممتحن تحديد هذه الميزة التصميمية الداخلية، أي مصطلح يصف بشكل صحيح تلك الجدران الفاصلة الصلبة؟","options":["الحواجز التوجيهية (Baffles)، لأنها الجدران الداخلية الموضوعة داخل الصهريج للتحكم في كيفية تحرك السائل","الحواجز الفاصلة (Bulkheads)، لأنها جدران صلبة تقسّم الصهريج إلى مقصورات منفصلة تماماً","تصميم التجويف الأملس، لأن داخل الصهريج لا يحتوي على أي معدات داخلية تعيق السائل","الفتحات التنفيسية، لأنها التركيبات الداخلية التي تفصل الصهريج إلى أقسام ضغط محكمة"],"explanation":"الحواجز الفاصلة (Bulkheads) هي جدران صلبة تقسّم الصهريج إلى مقصورات منفصلة تماماً دون فتحات بينها."},"6":{"q":"أنا أنقل صهريجاً مزوّداً بحواجز توجيهية ومحمّلاً جزئياً. عندما أكبح للتوقف عند إشارة حمراء، أشعر بالسائل يدفع شاحنتي إلى الأمام، وعندما أدور حول منعطف خفيف أشعر بتمايل جانبي قوي يكاد يقلبني. يقول مدربي إن الحواجز التوجيهية داخل الصهريج تؤدي وظيفة محددة. أي عبارة تصف بشكل صحيح ما تتحكم به تلك الحواجز فعلاً؟","options":["الحواجز التوجيهية تقلل التمايل الجانبي الذي شعرت به في المنعطف، ولهذا لم أنقلب","الحواجز التوجيهية تلغي كل التدفق في جميع الاتجاهات، لذا لا ينبغي أن يحدث الدفع الأمامي ولا التمايل الجانبي","الحواجز التوجيهية تقلل التدفق الأمامي-الخلفي الذي يدفع شاحنتي إلى الأمام، لكنها لا توقف التدفق الجانبي الذي شعرت به في المنعطف","الحواجز التوجيهية تتحكم بشكل رئيسي في مقدار تمدد الحمولة عندما تسخن، ولهذا شعرت بالحركة في كلا الاتجاهين"],"explanation":"تقلل الحواجز التوجيهية التدفق الأمامي-الخلفي لكنها لا تتحكم في التدفق الجانبي الذي يسبب الانقلاب في المنعطفات."},"7":{"q":"أنا أنقل حمولة من الحليب في صهريج من الفولاذ المقاوم للصدأ. يخبرني الشاحن أنه صهريج ذو تجويف أملس، وألاحظ أن التدفق الأمامي أقوى بكثير من صهريج الماء المزوّد بحواجز توجيهية الذي قدته الأسبوع الماضي. بناءً على كيفية بناء هذا الصهريج، أي عبارة تشرح بشكل صحيح لماذا التدفق قوي جداً؟","options":["الصهريج يحتوي على حواجز فاصلة داخلية بها ثقوب تقلل التدفق الجانبي لكنها تسمح بالتدفق الأمامي","الصهريج مقسّم إلى عدة مقصورات منفصلة تسمح للسائل بالانتقال بينها","الصهريج يحتوي على أرضية حاجز توجيهي مرتفعة توجّه السائل إلى الأمام عند الكبح","الصهريج لا يحتوي على حواجز توجيهية أو فواصل داخلية، لذا لا يوجد ما يبطئ السائل أثناء تدفقه"],"explanation":"الصهريج ذو التجويف الأملس لا يحتوي على حواجز توجيهية أو فواصل داخلية، لذا لا شيء يبطئ السائل ويكون التدفق قوياً جداً."},"8":{"q":"أنا أنقل صهريجاً سائلاً محمّلاً جزئياً وأسلك منحدر خروج منحنياً على الطريق السريع بسرعة أعلى قليلاً مما ينبغي. أثناء توجيهي عبر المنعطف، يتمايل السائل بقوة نحو الجهة الخارجية من الدوران. باستثناء نتيجة واحدة أدناه، فإن البقية خاطئة بشأن ما يرجح أن يفعله هذا التدفق الجانبي. أي عبارة صحيحة؟","options":["يمكن أن يدفع التدفق الجانبي مركز الثقل المرتفع إلى ما بعد نقطة الانقلاب ويقلب الصهريج.","سيدفع التدفق الجانبي الشاحنة مباشرة إلى الأمام وخارجاً إلى التقاطع التالي.","ستمتص الحواجز التوجيهية في الصهريج التدفق الجانبي، لذا يكون تأثيره ضئيلاً في المنعطف.","سيساعد التدفق الجانبي الصهريج على الانعطاف، مما يتيح لي بأمان الحفاظ على السرعة المعلنة للمنحدر."],"explanation":"يدفع التدفق الجانبي وزن السائل نحو الجهة الخارجية من المنعطف ويمكن أن يدفع مركز الثقل المرتفع إلى ما بعد نقطة الانقلاب، فيقلب الصهريج."},"9":{"q":"أنا أنقل صهريجاً ذا تجويف أملس محمّلاً نصفياً وأتوقف توقفاً تاماً عند إشارة حمراء قبل تقاطع مزدحم بقليل. توقفت عجلاتي عن الدوران وتبدو الشاحنة ساكنة. بناءً على سلوك تدفق السائل، لماذا ينبغي أن أكون مستعداً أكثر في هذه اللحظة؟","options":["استقرت الشاحنة تماماً، لذا يمكنني تحرير الفرامل والسماح لها بالزحف قليلاً للأمام","يمكن للتدفق الأمامي للسائل أن يدفع الشاحنة إلى الأمام إلى داخل التقاطع رغم توقف عجلاتي","سيسحب التدفق الشاحنة إلى الخلف، لذا ينبغي أن أخفف الفرامل للبقاء في مساري","غياب الحواجز التوجيهية سيبرّد الفرامل بشكل أسرع، مما يتيح لي التوقف في مسافة أقصر"],"explanation":"يستمر السائل في التمايل بعد توقف العجلات، ويمكن للتدفق الأمامي أن يدفع الشاحنة إلى داخل التقاطع."},"10":{"q":"أنا أنقل صهريجاً ذا تجويف أملس محمّلاً نصفياً بمنتج غذائي سائل وأقترب من إشارة حمراء عند تقاطع مزدحم. مع معرفتي بكيفية تصرف السائل في هذا الصهريج، أي نهج يحميني أفضل من الاندفاع إلى الأمام إلى داخل التقاطع بعد أن أظن أنني توقفت؟","options":["انتظر حتى اللحظة الأخيرة، ثم اكبح بقوة مرة واحدة ليُمتص التدفق في توقف ثابت واحد","قلّص المسافة إلى السيارة التي أمامي وانتقل إلى الوضع المحايد حتى لا يقاوم المحرك التدفق","اترك مسافة اتباع إضافية وابدأ بالكبح بلطف وبشكل مبكر، مع البقاء متيقظاً للتدفق الأمامي بعد التوقف","حافظ على مسافة الاتباع العادية واكبح عند النقطة المعتادة، لأن الحواجز التوجيهية ستحجز السائل"],"explanation":"يسمح الصهريج ذو التجويف الأملس غير المزوّد بحواجز توجيهية للسائل بالتدفق إلى الأمام بعد التوقف، لذا اترك مسافة اتباع إضافية واكبح بلطف وبشكل مبكر."},"11":{"q":"أنا أنقل صهريجاً مملوءاً نصفياً فقط بالسائل. وأنا أقترب من إشارة حمراء وأكبح للتوقف التام، ما هو الخطر الأهم الذي يجب أن أديره بسبب طريقة تحميل الصهريج؟","options":["الصهريج نصف الفارغ أخف، لذا تسخن فراملي بشكل أسرع وينبغي أن أضخها للحفاظ على برودتها","الوزن المنخفض يزيد مسافة توقفي بشكل كبير، لذا يجب أن أكبح بقوة أكبر بكثير من الحمولة الكاملة","قشرة الصهريج اللامعة تعكس ضوء الشمس إلى المرايا، لذا فإن الوهج هو الشيء الرئيسي الذي يجب التحكم به عند التوقف","يتدفق السائل إلى الأمام بعد توقفي ويمكن أن يدفع الشاحنة إلى الأمام، لذا أكبح بلطف وبشكل مبكر وأترك مساحة إضافية"],"explanation":"يتدفق السائل في الصهريج المملوء جزئياً إلى الأمام بعد التوقف ويمكن أن يدفع الشاحنة إلى الأمام، لذا اكبح بلطف وبشكل مبكر واترك مساحة إضافية."},"12":{"q":"أنا أجري فحص ما قبل الرحلة على صهريج سائل محمّل قبل نقله عبر المدينة. إلى جانب العناصر العادية التي أفحصها على أي مركبة تجارية، أي مجموعة من العناصر الخاصة بالصهاريج يجب أن أفحصها للتأكد من أن حمولتي لن تتسرب أو تهرب على الطريق؟","options":["الفتحات التنفيسية والخراطيم وأغطية فتحة الرجل/القبة، مع التأكد من أن الأغطية مغلقة ومحكمة ولا توجد تسريبات حولها","سخان المقصورة وضوء القبة وضبط المقعد، مع التأكد من أن الداخل مريح للرحلة الطويلة","عادم الجرار وخطوط تكييف الهواء، مع التأكد من استجابة جميع أنظمة التحكم في مناخ المقصورة","رفارف الطين الخلفية والشريط العاكس فقط، لأن هذه هي الأجزاء التي يركز عليها المفتشون أكثر"],"explanation":"تتطلب المركبة الصهريجية فحص الفتحات التنفيسية والخراطيم وأغطية فتحة الرجل/القبة للتأكد من أنها مغلقة ومحكمة وخالية من التسرب."},"13":{"q":"أثناء فحص ما قبل الرحلة لصهريج محمّل، ألاحظ أن الفتحة التنفيسية في أعلى الصهريج تبدو مسدودة جزئياً ببقايا جافة وأوساخ الطريق. أنا متأخر عن الجدول والحمولة محكمة. أي إجراء صحيح قبل أن أقود؟","options":["اترك الفتحة التنفيسية كما هي لأن غطاء فتحة الرجل والحمولة محكمان بالفعل","نظّف الفتحة التنفيسية حتى تصبح خالية وتعمل قبل القيادة، لمنع تفريغ يمكن أن يطوي الصهريج","أغلق الفتحة التنفيسية أيضاً حتى لا يتسرب أي سائل أو بخار أثناء النقل","قُد ببطء ودع تدفق الهواء أثناء الرحلة ينظّف الفتحة التنفيسية من تلقاء نفسه"],"explanation":"يجب إبقاء الفتحة التنفيسية خالية وتعمل حتى يدخل الهواء عند خروج السائل، مما يمنع تفريغاً يمكن أن يطوي الصهريج."},"14":{"q":"أنا أنقل صهريجاً محمّلاً جزئياً وأقترب من منحدر خروج على الطريق السريع بسرعة إرشادية معلنة قدرها 35 ميلاً في الساعة. الرصيف جاف وفرامل في حالة جيدة. لإدارة مركز ثقلي المرتفع وتجنب الانقلاب، بأي سرعة ينبغي أن أسلك هذا المنحدر؟","options":["بسرعة 35 ميلاً في الساعة تماماً، لأن السرعة الإرشادية المعلنة تأخذ بالفعل صهريجي المحمّل في الحسبان","أعلى قليلاً من 35 ميلاً في الساعة، لأن الرصيف الجاف والفرامل الجيدة يمنحانني جراً إضافياً","أقل من 35 ميلاً في الساعة، لأن سرعات المنحدر المعلنة محددة للمركبات العادية وينبغي أن يسير الصهريج أبطأ","35 ميلاً في الساعة بالضبط، مع الحفاظ على الثبات طوال المنعطف لمنع تدفق السائل"],"explanation":"يمنح السائل المركبات الصهريجية مركز ثقل مرتفعاً، وسرعات المنحدر المعلنة محددة للمركبات العادية، لذا اسلك المنحدرات بسرعة أقل بكثير من السرعة المعلنة."},"15":{"q":"أنا على وشك تحميل صهريج ذي تجويف أملس بمادة كيميائية كثيفة في محطة في تكساس، وأحسب بالضبط كمية المنتج التي سأضعها. عند حساب الحجم المسموح لي بتحميله، كل عامل أدناه يحدّ هذه الكمية بشكل مشروع باستثناء أي واحد؟","options":["كثافة (وزن) السائل، لأن المنتج الثقيل يمكن أن يبلغ الحد الأقصى لحمل المحور قبل أن يمتلئ الصهريج حتى","حدود الوزن الإجمالي وحدود وزن المحور القانونية التي يجب أن أبقى دونها للطرق التي سأسلكها","الفجوة التي يجب أن أتركها لأن السائل سيتمدد عندما يسخن أثناء النقل","طولي ومدى وصولي في المقصورة، لأنه لا يزال عليّ التسلق وتشغيل صمامات التعبئة العلوية"],"explanation":"كمية السائل التي يمكن أن يحملها الصهريج محددة بوزن السائل وحدود الوزن القانونية والفجوة المتروكة للتمدد، وليس بحجم جسد السائق."},"16":{"q":"تم توظيفي للتو لقيادة مقطورة صهريج ويخبرني الموزّع أن مركبتي تحتوي على صهريج ذي تجويف أملس (بدون حواجز توجيهية) ولا توجد به حواجز فاصلة داخلية. بناءً على كيفية تصميم الصهاريج وتنظيمها، أي نوع من الحمولة يرجّح أن أنقله؟","options":["الحليب وغيره من المنتجات الغذائية السائلة، لأن الصهاريج الغذائية عادةً ما تكون ذات تجويف أملس حتى يمكن تنظيفها وفق المعايير الصحية","البنزين وغيره من المواد القابلة للاشتعال، لأن الصهريج ذا التجويف الأملس يقلل التدفق الأمامي-الخلفي أثناء التوقفات السريعة","النفط الخام والسوائل الصناعية الثقيلة، لأن غياب الحواجز التوجيهية يتيح للحمولة الكثيفة الاستقرار بالتساوي عبر القشرة","البضائع الجافة المختلطة كالرمل والحصى، لأن الجدران الداخلية الملساء تتيح للحمولة الانسكاب أسرع عند موقع التفريغ"],"explanation":"عادةً ما تكون الصهاريج الغذائية كتلك المخصصة للحليب ذات تجويف أملس لأن الحواجز التوجيهية يصعب تنظيفها وفق المعايير الصحية."},"17":{"q":"أنا أنقل صهريجاً سائلاً محمّلاً جزئياً وأقترب من منحدر خروج منحنٍ على الطريق السريع معلن بسرعة 35 ميلاً في الساعة. نظراً لمركز الثقل المرتفع وتدفق السائل في صهريجي، أي إجراء هو الأهم لمنع الانقلاب على هذا المنحدر؟","options":["حافظ على سرعتي عند السرعة المعلنة 35 ميلاً في الساعة تماماً لأن ذلك الحد يأخذ بالفعل صهريجي في الحسبان","خفّف السرعة إلى ما دون 35 ميلاً في الساعة بكثير قبل دخول المنحدر ووجّه بسلاسة عبر المنعطف","ابقَ على سرعة الطريق السريع عند الدخول، ثم اكبح بقوة في منتصف المنعطف لتقليل السرعة","أبقِ الحمولة مستقرة عالياً في الصهريج واعتمد على مرآتي الخارجية لتتبع المنعطف"],"explanation":"يسبب مركز الثقل المرتفع للصهريج المحمّل والتدفق الجانبي الانقلابات في المنعطفات، لذا خفّف السرعة إلى ما دون السرعة المعلنة بكثير ووجّه بسلاسة."},"18":{"q":"أنا أنقل صهريجاً ذا تجويف أملس محمّلاً جزئياً وأقترب من إشارة حمراء على منحدر هابط طفيف. وأنا أتوقف، أشعر بالسائل يتمايل إلى الأمام خلفي، وتريد الشاحنة الزحف إلى الأمام رغم أنني أكبح. ما هي أفضل طريقة لمنع هذا التدفق الأمامي من دفعي إلى ما بعد خط التوقف وإلى داخل التقاطع؟","options":["اضخّ الفرامل بسرعة أثناء توقفي حتى يبقى التدفق محصوراً خلف الحاجز الفاصل الأمامي","توقّف بأقرب مسافة ممكنة من المركبة التي أمامي حتى لا توجد فجوة تزحف إليها الشاحنة","اترك مساحة إضافية أمامي عند التوقف حتى يُمتص أي دفع أمامي من التدفق قبل أن أصل إلى الخط","اكتسب سرعة إضافية قليلة عند الاقتراب حتى أتمكن من المرور عبر التمايل واستقرار الحمولة أسرع"],"explanation":"يمكن للتدفق الأمامي بعد التوقف أن يدفع الشاحنة إلى الأمام، لذا اترك مساحة إضافية أمامك حتى يُمتص التدفق قبل أن تصل إلى خط التوقف."},"19":{"q":"أنا أنقل صهريجاً سائلاً محمّلاً جزئياً به حواجز فاصلة تقسّمه إلى مقصورات منفصلة. وأنا أقترب من إشارة حمراء وأخفف الفرامل، أشعر بالحمولة تدفع المقصورة إلى الأمام إلى داخل التقاطع. بناءً على كيفية عمل الحواجز الفاصلة، ماذا ينبغي أن أتوقع من هذه الفواصل عند التعامل مع هذه المركبة؟","options":["تلغي كل أنواع التدفق، لذا يمكنني التوقف والانعطاف تماماً مثل حمولة صلبة دون أي دفع على الإطلاق","تبرّد السائل أثناء قيادتي، مما يخفض وزن الحمولة بما يكفي لرفع حدّ التعبئة القانوني","تقلل التمايل الجانبي، لذا لن تدفعني المنعطفات الحادة نحو الانقلاب","تقلل التدفق الأمامي-الخلفي بين المقصورات، لكنها لن توقف التمايل الجانبي"],"explanation":"تقلل الحواجز الفاصلة والحواجز التوجيهية التدفق الأمامي-الخلفي بين المقصورات لكنها لا تتحكم في التمايل الجانبي."},"20":{"q":"أنا أحمّل سائلاً في مقطورة صهريج مزوّدة بحواجز توجيهية ولها عدة مقصورات بحواجز فاصلة. لتوفير الوقت عند رصيف التحميل، أنا مُغرٍ بملء المقصورتين الأماميتين فقط وتخطي الخلفيتين. قبل أن أفعل ذلك، أي اعتبار ينبغي أن يؤثر أكثر على كيفية توزيعي للمنتج بين المقصورات؟","options":["ملء المقصورات الأمامية فقط يمكن أن يضع وزناً زائداً على مجموعة واحدة من المحاور، لذا يجب أن أوزّع المنتج للحفاظ على توازن الوزن عبر جميع المحاور.","لأن الصهريج مزوّد بحواجز توجيهية، فإن الحواجز الفاصلة توقف تدفق السائل، لذا لا يهم أي مقصورات أملؤها.","ينبغي أن أملأ كل مقصورة بالكامل حتى الأعلى حتى لا توجد فجوة ولا يمكن للحمولة أن تنزاح أثناء قيادتي.","ينبغي أن أحمّل كل الوزن نحو المحاور الخلفية، لأن الوزن الخلفي الإضافي يمنح إطارات التوجيه قبضة وجراً أفضل."],"explanation":"يجب توزيع المنتج عبر جميع المقصورات حتى يبقى الوزن متوازناً على كل محور ولا تُحمّل أي مجموعة محاور بشكل زائد."},"21":{"q":"أنت تنقل صهريجاً محمّلاً جزئياً من السائل على طريق سريع غير مألوف ذي مسارين وتقترب من منحدر خروج معلن بسرعة 35 ميلاً في الساعة، مع إشارة حمراء أسفل المنحدر. نظراً لكيفية تصرف هذه الحمولة، أي إجراء يبقيك في أكثر أمان أثناء خروجك؟","options":["حافظ على السرعة المعلنة 35 ميلاً في الساعة خلال المنحدر، لأن السرعة محددة للمنعطف، ثم اكبح بقوة بمجرد أن يستقيم الطريق","ادخل المنحدر بسرعة أقل بكثير من 35 ميلاً في الساعة وابدأ بالكبح بلطف وبشكل مبكر، مع ترك مساحة إضافية قبل الإشارة الحمراء","حافظ على سرعة الطريق السريع عند دخول المنحدر لأن الحمولة الجزئية تجعل المركبة أخف وأسهل في التحكم","اكبح بقوة ووجّه بحدّة عند ذروة المنعطف لتقليل السرعة بسرعة قبل الإشارة الحمراء"],"explanation":"يعني مركز الثقل المرتفع والتدفق في صهريج السائل أنه يجب أن تسلك المنحدرات بسرعة أقل بكثير من السرعة المعلنة وتكبح بلطف وبشكل مبكر مع مساحة إضافية."},"22":{"q":"أنا أحمّل مقطورة الصهريج في ظهيرة حارة في تكساس بمنتج سائل يحذّر موزّعي من أنه 'يتمدد كثيراً' عند ارتفاع درجات الحرارة. وأنا أحدد كمية ما سأضعه في الصهريج، ماذا ينبغي أن أفعل بسبب ذلك التمدد؟","options":["املأ الصهريج حتى الأعلى تماماً حتى لا توجد مساحة فارغة تتمايل فيها الحمولة","أحكم إغلاق كل فتحة تنفيسية وغطاء فتحة رجل بإحكام حتى يبقى السائل المتمدد محبوساً داخل الصهريج","اترك فجوة في الصهريج حتى يكون لدى السائل الذي يسخن مجال للتمدد بأمان","اختر صهريجاً بسطح مسطح حتى ينتشر السائل المتمدد بدلاً من تراكم الضغط"],"explanation":"تتمدد السوائل عندما تسخن، لذا يجب أن تترك فجوة (مساحة فارغة) في الصهريج لمنح السائل المتمدد مجالاً دون تراكم ضغط خطير."},"23":{"q":"أنا أحمل بالفعل رخصة قيادة تجارية مع تصديق المركبة الصهريجية (N)، وغداً يكلّفني موزّعي بنقل حمولة من السائل القابل للاشتعال تتطلب لافتات على المقطورة. قبل أن أتمكن قانونياً من قيادة هذه الرحلة، ماذا يجب أن أحصل عليه أيضاً؟","options":["لا شيء إضافي، لأن تصديق N يغطي بالفعل أي سائل أحمّله في الصهريج","تصديق الركاب (P)، لأن الحمولة ذات اللافتات تجعل المركبة وسيلة نقل منظمة","تصنيف دراجة نارية منفصل، لأن الحمولات ذات اللافتات تُعامل كنقل بمعدات خاصة","تصديق المواد الخطرة (H)، بالإضافة إلى تصديق المركبة الصهريجية (N) الذي أحمله بالفعل"],"explanation":"يتطلب الصهريج الذي ينقل سائلاً خطراً يحمل لافتات تصديق المواد الخطرة (H) بالإضافة إلى تصديق المركبة الصهريجية (N)."},"24":{"q":"أنا أنقل صهريجاً ذا تجويف أملس محمّلاً جزئياً من السائل وتقطع سيارة الطريق فجأة أمامي، لذا أرغب غريزياً في إدارة المقود بحدّة للانحراف حولها. لماذا يُعدّ هذا الإدخال التوجيهي الخيار الأخطر لمركبتي؟","options":["يمكن لحركة توجيه حادة ومفاجئة أن تثير تدفقاً جانبياً للسائل يقلب مركز الثقل المرتفع إلى انقلاب.","تُسخّن حركة التوجيه الحادة مضخة التوجيه المعزز، التي تتعطل وتقفل العجلات مستقيمة إلى الأمام.","تضغط حركة التوجيه الحادة المساحة الهوائية للفجوة، مما يبني ضغطاً يمكن أن يمزّق غطاء فتحة الرجل.","حركة التوجيه الحادة مقبولة على صهريج ذي تجويف أملس لأن الحواجز التوجيهية داخله تلغي تماماً أي تدفق جانبي."],"explanation":"يُحدث التوجيه الحاد المفاجئ تدفق السائل جانباً، والذي يمكن مع مركز الثقل المرتفع أن يقذف الصهريج إلى انقلاب."},"25":{"q":"أنا أنقل حمولة كاملة من السائل في شاحنتي الصهريجية على طريق سريع في تكساس، أتبع صفاً من حركة المرور الأبطأ. مقارنة بمسافة الاتباع التي سأحافظ عليها لو كنت أقود مقطورة صندوق فارغة بنفس السرعة، كيف ينبغي أن أحدد مسافة اتباعي خلف المركبة التي أمامي، ولماذا؟","options":["حافظ على نفس المسافة، لأن الصهريج الممتلئ ليس به مساحة هوائية فلا يمكن للسائل أن يتدفق ويطيل توقفي","حافظ على مسافة أطول من المعتاد، لأن تدفق السائل يطيل مسافة توقفي ويمكن أن يدفعني إلى الأمام بعد أن أظن أنني توقفت","حافظ على مسافة أقصر من المعتاد، لأن حمولة السائل الثقيلة تمنح فراملي جراً أكبر وتساعدني على التوقف أسرع","طابق المسافة مع وقت اليوم، مع إبقائها أطول ليلاً فقط وعادية في ساعات النهار"],"explanation":"حافظ على مسافة اتباع أطول من المعتاد لأن تدفق السائل يطيل مسافة التوقف ويمكن أن يدفع الشاحنة إلى الأمام بعد أن تظن أنك توقفت."},"26":{"q":"أثناء الفحص قبل الرحلة لصهريجي، أكون منحنياً وأمرّر يدي على طول خطوط المنتج (الرطبة) والصمامات حيث تتصل الخراطيم بالصهريج. وأنا أتفقد هذا الجزء من النظام، ما هو العيب المحدد الذي أفحص خطوط المنتج والصمامات بحثاً عنه؟","options":["ما إذا كانت الخطوط تصدر أي أصوات فحيح أو طرق عالية أثناء عمل المحرك في وضع الخمول","ما إذا كانت الخطوط مصنّفة لتتناسب مع سرعتي الحالية على الطريق وحدود السرعة المعلنة على المنحدرات","ما إذا كانت الخطوط وصماماتها تُظهر أي علامات تسرّب أو تلف مادي","ما إذا كانت الخطوط مطلية باللون التنظيمي الصحيح للمنتج الذي يتم نقله"],"explanation":"يجب فحص خطوط المنتج وصماماتها بحثاً عن التسربات والتلف المادي، لأن النضح أو التشققات قد تطلق سائلاً خطراً أو تنهار تحت الضغط."},"27":{"q":"أنا أنهي الفحص قبل الرحلة على مقطورة صهريج محمّلة بمنتج سائل. وأنا أمشي على سطح الصهريج، أصل إلى غطاء فتحة الدخول والأغطية القبّابية. وفقاً لإجراءات سلامة مركبات الصهاريج في تكساس، ما هي الحالة الصحيحة التي يجب أن تكون عليها هذه الأغطية قبل أن أنطلق إلى الطريق السريع؟","options":["مفتوحة قليلاً كي يتمكن السائل الآخذ في التسخّن من التنفيس ويتمكن الصهريج من تحرير الضغط","مزالة بالكامل حتى يكتمل التحميل تماماً، ثم تُوضع فوقها بشكل غير محكم","مغلقة لكن غير محكمة الإغلاق كي يتمكن المفتّش من فحص مستوى المنتج بسرعة","مغلقة ومحكمة كي يبقى الصهريج خالياً من التسرب أثناء تحرّك المركبة"],"explanation":"يجب أن تكون أغطية فتحات الدخول وصمامات الأبخرة/التنفيس مغلقة ومحكمة كي يبقى الصهريج المحمّل خالياً من التسرب ولا يسكب المنتج على الطريق أثناء الحركة."},"28":{"q":"أنا في محطة وأستعد لتحميل البنزين في صهريج حمولتي لأول مرة. المنتج قابل للاشتعال وسوف يتناثر ويتدفق وهو يدخل الصهريج. قبل أن أفتح الصمام وأبدأ التحميل، أي خطوة هي الأهم لمنع شرارة كهرباء ساكنة من إشعال الأبخرة؟","options":["تأريض صهريج الحمولة وربطه بمنصة التحميل كي لا تتراكم أي شحنة ساكنة","ملء الصهريج تماماً حتى الأعلى كي لا يبقى حيز هواء تتجمع فيه الأبخرة","ضخ هواء دافئ في الصهريج أولاً لتجفيف أي رطوبة قبل وصول الوقود","ترك الصهريج معزولاً كهربائياً كي لا يصل أي تيار شارد من المنصة إلى الوقود"],"explanation":"تتراكم الشحنة الساكنة في السوائل القابلة للاشتعال أثناء تدفقها، لذا يجب تأريض صهريج الحمولة وربطه بمنصة التحميل لتفريغ الشحنة ومنع شرارة مشتعلة."},"29":{"q":"أنا أنقل صهريج سائل محمّلاً جزئياً وأقترب من إشارة حمراء، وأكبح بالطريقة نفسها التي أكبح بها في الشاحنة الجافة المغلقة التي أقودها عادة. مقارنة بتلك الشاحنة الجافة تحت الظروف نفسها، ماذا ينبغي أن أتوقع من سلوك التوقف لصهريجي؟","options":["سيتوقف في مسافة أقصر بشكل ملحوظ لأن الحمولة السائلة تضيف وزناً يحسّن التماسك فوق محاور القيادة","سيستغرق مسافة أطول للتوقف، وقد يدفع الاندفاع الشاحنة إلى الأمام حتى بعد أن أظن أنني توقفت تماماً","سيتوقف في المسافة نفسها تقريباً، لأن مسافة التوقف تعتمد فقط على السرعة وحالة الفرامل، لا على نوع الحمولة","سيتوقف بشكل أسرع لأن السائل المتمايل يدفع عكس الحركة الأمامية ويساعد على إبطاء الشاحنة"],"explanation":"يستغرق الصهريج السائلي المحمّل مسافة أطول للتوقف، وقد يدفع الاندفاع الأمامي الشاحنة إلى الأمام حتى بعد أن تبدو وكأنها توقفت تماماً."},"30":{"q":"تتوقف بصهريجك عند منصة محطة لأخذ حمولة من منتج سائل. يشير إليك عامل المضخة نحو موضع التعبئة ويطلب منك أن تكون سريعاً لأن الشاحنات متراكمة خلفك. قبل أن تصل الخطوط وتبدأ التحميل، ما الذي ينبغي أن تفعله أولاً؟","options":["اترك المحرك يعمل عند خمول سريع كي يبقى نظام الهواء مشحوناً للحركة التالية","تقدّم ببطء أثناء التعبئة كي يستقر المنتج بالتساوي عبر الصهريج","أوقف الشاحنة توقفاً كاملاً، واركنها، واضبط فرامل الركن قبل بدء الخطوات","افتح كل صمامات التفريغ والتنفيس دفعة واحدة كي يتعادل الضغط بشكل أسرع"],"explanation":"الحمولة السائلة ثقيلة، لذا يجب أن تكون الشاحنة متوقفة تماماً ومركونة وأن تُضبط فرامل ركنها قبل بدء التحميل أو التفريغ."},"31":{"q":"أثناء التسارع أو الكبح، يؤثر الاندفاع بشكل رئيسي على:","options":["مذياع المقصورة","تحكّمك في المركبة","طلاء الشاحنة","لون المرآة"],"explanation":"يمكن أن يؤثر الاندفاع على التحكم عندما تتسارع أو تتباطأ."},"32":{"q":"أُسند إليّ صهريج محمّل جزئياً وأُعطى خياراً في كيفية توزيع وزن الحمولة الإجمالي نفسه داخل الصهريج. مع العلم أن مركبات الصهاريج أصلاً ذات مركز ثقل مرتفع وتنقلب بسهولة، أي خيار تحميل يفعل الأكثر لتقليل خطر الانقلاب لديّ؟","options":["حمل الوزن مكدّساً عالياً في القسم العلوي من الصهريج كي يكون للاندفاع حيز أقل للتراكم","نقل معظم الوزن إلى جانب واحد كي تميل الشاحنة نحو المنعطفات وتبقى ثابتة","توزيع الوزن بالتساوي عبر أعلى الصهريج تماماً لموازنته يساراً ويميناً","إبقاء الوزن منخفضاً قدر الإمكان في الصهريج كي يبقى مركز الثقل منخفضاً"],"explanation":"إبقاء وزن الحمولة منخفضاً قدر الإمكان في الصهريج يخفض مركز الثقل، مما يقلل مباشرة من خطر الانقلاب."},"33":{"q":"لقد حصلت للتو على تصريح الصهاريج وأنا أنقل حمولة سائلة على طريق سريع به منحدر خروج منحنٍ معلنة سرعته 35 ميلاً في الساعة. يخبرني زميل أنه لأنني أقود صهريجاً بدلاً من مقطورة صندوق جاف عادية، عليّ أن أكون أكثر حذراً في المنعطفات وعلى المنحدرات من السائقين الآخرين. لماذا تكون نصيحته صحيحة؟","options":["مركبات الصهاريج لها مركز ثقل أعلى بسبب الحمولة السائلة، مما يعطيها معدل انقلاب أعلى، لذا عليّ أن آخذ المنحدر بسرعة أقل بكثير من 35 ميلاً في الساعة المعلنة","مركبات الصهاريج لها مركز ثقل أدنى بسبب الوزن السائل، لكن مسافة توقفها الأطول تجعل المنحدرات خطرة عند 35 ميلاً في الساعة","مركبات الصهاريج لها معدل الانقلاب نفسه الذي للشاحنات الجافة، لذا السبب الحقيقي هو أن الحمولات السائلة تتجاوز حدود الوزن القانونية على المنحدرات","مركبات الصهاريج لها معدل انقلاب أعلى فقط عندما تكون محمّلة بالكامل، لذا يمكن لصهريج فارغ أو معبأ جزئياً أن يأخذ المنحدر بأمان عند 35 ميلاً في الساعة"],"explanation":"تركب الحمولة السائلة عالياً، مما يعطي مركبات الصهاريج مركز ثقل مرتفعاً ومعدل انقلاب أعلى، لذا يجب أخذ المنعطفات والمنحدرات بسرعة أقل بكثير من السرعة المعلنة."},"34":{"q":"أُسندت إليّ مقطورة صهريج ويخبرني المرسِل فقط أنها 'محمّلة' دون أن يقول بماذا. قبل أن أوقّع على استلام الحمولة، لماذا يهم فعلاً أن أعرف بالضبط أي سائل بداخلها؟","options":["لا يغيّر ذلك شيئاً بالنسبة لي حقاً، لأن كل حمولة سائلة تُقاد وتُكبح بالطريقة نفسها بمجرد إغلاق أغطية فتحات الدخول.","يجب التعامل مع السوائل المختلفة بطرق مختلفة، لأن الكثافة والتمدد والاندفاع وفئة الخطر يغيّر كل منها كيف أحمّل الصهريج وأقوده وأكبحه بأمان.","يهم فقط كي أختار لون اللافتة المطابق، لكن لا تأثير له على كيفية قيادتي فعلاً أو على مدى امتلائي للصهريج.","يهم فقط للفوترة والأوراق في المحطة، لأن التعامل الفعلي مع أي صهريج سائل مغلق متطابق على الطريق."],"explanation":"تغيّر كثافة السائل وتمدده واندفاعه وفئة خطره كلٌ منها كيف يُحمّل الصهريج ويُقاد ويُكبح، لذا يجب التعامل مع السوائل المختلفة بطرق مختلفة."},"35":{"q":"أنت تنقل حمولة كاملة من السائل نزولاً على منحدر طويل وشديد الانحدار بصهريجك. تنتهي قاعدة التل بمنعطف حاد. أي إجراء يمنع الاندفاع ووزن المركبة من الإفلات من سيطرتك قبل أن تصل إلى المنعطف؟","options":["انتقل إلى ترس أعلى واضغط على فرامل الخدمة باستمرار للحفاظ على سرعة ثابتة","ارفع سرعتك مبكراً كي تحمل عبء كبح أقل إلى المنعطف عند الأسفل","قلّل سرعتك واختر ترساً منخفضاً قبل بدء النزول، تاركاً كبح المحرك يتحكم في الهبوط","أبقِ ناقل الحركة في وضع محايد كي تتولى الفرامل وحدها إدارة الهبوط بالكامل بسلاسة"],"explanation":"الإبطاء واختيار ترس منخفض قبل المنحدر يتيح لكبح المحرك التحكم في الهبوط كي لا يدفع الاندفاع صهريجاً ذا مركز ثقل مرتفع خارج السيطرة."},"36":{"q":"أثناء الفحص قبل الرحلة، تلاحظ تنقيطاً ثابتاً للمنتج يتسرب من صمام قرب فتحة الدخول لمقطورة صهريجك المحمّلة. أنت متأخر بالفعل 30 دقيقة عن الجدول وساحة الصيانة التالية تبعد 40 ميلاً على المسار. أي إجراء هو الصحيح؟","options":["تابع إلى ساحة الصيانة لأنها أقرب مكان يمكنه إصلاح التسرب","قلّل حمولتك لخفض الضغط على الصمام، ثم أكمل الرحلة","أحكم غطاء فتحة الدخول وصمامات التنفيس وقُد ببطء إلى نقطة التسليم","لا تقُد المركبة وأصلح التسرب قبل تحريك الصهريج"],"explanation":"يجب ألا يُقاد صهريج مُسرّب أبداً ويتعين إصلاحه قبل تحريك المركبة."},"37":{"q":"أنا أحمّل صهريجاً بسائل كثيف في المحطة، وأراقب كلاً من مقياس المستوى وتذكرة الميزان. الصهريج ممتلئ نحو ثلاثة أرباعه فقط، لكن أوزان محاوري بالفعل عند الحد القانوني. ماذا يخبرني هذا عن كمية المنتج الإضافية التي يمكنني أخذها بأمان؟","options":["ينبغي أن أتوقف عن التحميل الآن، لأن السائل الكثيف يمكن أن يصل بي إلى الوزن القانوني قبل أن يُملأ الصهريج حتى أعلاه","يمكنني مواصلة التحميل حتى يمتلئ الصهريج بشكل مرئي، لأن الحد القانوني يستند إلى سعة الصهريج لا إلى وزن الميزان","يمكنني مواصلة التحميل لأن حيز الفراغ في الأعلى يثبت أنني ما زلت دون الحد القانوني للوزن","ينبغي أن أملأ الصهريج تماماً، لأن الصهريج المعبأ جزئياً أخطر من الثقيل"],"explanation":"يمكن للسائل الكثيف أن يبلغ الحد القانوني للوزن قبل أن يمتلئ الصهريج، لذا يجب التوقف عن التحميل بمجرد أن يُظهر الميزان أنك عند الحد القانوني."},"38":{"q":"لقد سلّمت للتو معظم حمولتي والآن أنقل صهريجاً ناعم التجويف ممتلئاً نحو الربع فقط عائداً إلى الساحة. وأنا أقود على الطريق السريع الخالي، أي سلوك ينبغي أن أتوقعه من هذا الصهريج المحمّل بخفة والذي يجب أن أقوده بحذر دفاعي لإدارته؟","options":["الوزن الخفيف يضغط الإطارات على الأرض بقوة أكبر، فيتماسك الصهريج مع الطريق وينعطف بأمان أكثر مما حين يكون ممتلئاً","يرتد السائل ويندفع جيئة وذهاباً، لذا يجب أن أكبح بلطف ومبكراً لأن الاندفاع يمكن أن يدفع الشاحنة إلى الأمام","مع وجود سائل قليل جداً بالداخل، يتوقف الصهريج أسرع بشكل ملحوظ ويتيح لي الكبح متأخراً مقارنة بحمولة كاملة","الصهريج شبه الفارغ خفيف جداً على أن يتحرك من تلقاء نفسه، فلا يكون الاندفاع مصدر قلق حتى يكون ممتلئاً نصفه على الأقل"],"explanation":"يتمايل السائل في صهريج معبأ جزئياً ويندفع إلى الأمام، لذا يجب زيادة مسافة الاتباع والكبح بلطف ومبكراً."},"39":{"q":"أنا أحمّل مقطورة صهريجي بسائل خطر قابل للاشتعال لرحلة عبر تكساس. قبل أن أنطلق من المحطة، أيٌّ مما يلي يجب أن تعرضه مركبة صهريجي كي تكون قانونية على الطريق؟","options":["علم تحذير واحد مثبّت في مؤخرة الصهريج","فقط لافتة شركة تعرّف بالناقل الذي يحمل الحمولة","لافتات المواد الخطرة المطلوبة للسائل الذي أحمله","لا علامات خاصة، لأن أغطية فتحات الدخول المغلقة كافية"],"explanation":"يجب أن يعرض الصهريج الذي يحمل سائلاً قابلاً للاشتعال أو خطراً اللافتات المناسبة التي تعرّف بفئة خطر المادة كي يكون قانونياً للتشغيل."},"40":{"q":"أثناء فحصي قبل الرحلة لصهريج حمولة، أجد أن صمام الإغلاق الطارئ قد رُبط بسلك في الوضع المفتوح كي لا ينغلق عرضاً أثناء التحميل، وكومة من أحزمة الحمولة مسندة إليه. أيٌّ مما يلي يصف على نحو أفضل الحالة التي يجب أن يكون عليها هذا الصمام قبل أن أقود؟","options":["يمكن أن يبقى الصمام مربوطاً مفتوحاً طالما أستطيع الوصول إليه، لأن هذا يمنع الإغلاق العرضي أثناء النقل","لا يحتاج الصمام إلى أن يكون متاحاً إلا إذا كان الصهريج يحمل حمولة قابلة للاشتعال أو خطرة تتطلب لافتات","ينبغي ترك الصمام في أي وضع ضبطه الشاحن عليه، لأنه يعرف المنتج على نحو أفضل","يجب أن يكون الصمام في حالة عمل سليمة ويبقى خالياً كي أتمكن من الوصول إليه وتشغيله في حالة طارئة"],"explanation":"يجب أن يكون صمام الإغلاق الطارئ لصهريج الحمولة في حالة عمل سليمة ويبقى خالياً كي يتمكن السائق من الوصول إليه وتشغيله في حالة طارئة."},"41":{"q":"لقد توقفت للتو بصهريجي المحمّل على كتف منحدر شديد لمعالجة مسألة أوراق، وسأخرج من المقصورة لعدة دقائق. نظراً لمركز الثقل المرتفع ووزن الحمولة السائلة خلفي، أي إجراء يؤمّن الشاحنة على أفضل وجه ضد التدحرج؟","options":["اضبط فرامل الركن بإحكام واسند الإطارات بأسافين قبل مغادرة المقصورة","اترك ناقل الحركة في وضع محايد كي لا تتقيد منظومة نقل الحركة على المنحدر","أبقِ المحرك يعمل كي يحافظ نظام الهواء على ضغط كامل على الفرامل","اخفض دعامات هبوط المقطورة جزئياً لرفع الوزن عن نظام التعليق"],"explanation":"تتطلب الحمولة السائلة الثقيلة لصهريج محمّل ومركز ثقله المرتفع ضبط فرامل الركن وإسناد الإطارات بأسافين كنسخة احتياطية ميكانيكية قبل مغادرة المقصورة."},"42":{"q":"أنا أنقل صهريجاً ناعم التجويف ممتلئاً نحو النصف فقط، وأقترب من إشارة حمراء عند تقاطع رباعي مزدحم. وأنا أتوقف توقفاً كاملاً، لأي شيء ينبغي أن أكون مستعداً على أفضل وجه وأنا أوقف الشاحنة؟","options":["الحمولة نصف الفارغة تجعل الشاحنة أخف، فتمسك فراملي بقوة أكبر وأتوقف على بُعد بضعة أقدام أقصر مما خططت له.","يتمايل السائل إلى الأمام وأنا أتباطأ، وبعد أن أظن أنني توقفت يمكن لذلك الاندفاع أن يدفع الشاحنة إلى الأمام داخل التقاطع، لذا ينبغي أن أكبح مبكراً وبلطف وأترك مسافة.","لأن الصهريج ممتلئ نصفه فقط، فإن حيز الهواء المحبوس يخفف الحمولة وسيكون الكبح كأنه سحب مقطورة صندوق جاف محمّل.","يتيح الصهريج غير المزوّد بحواجز للسائل أن يستقر بسرعة، فتبقى الحمولة في مكانها ويمكنني الكبح بقوة عند الخط دون أي دفع أمامي."],"explanation":"يندفع السائل في صهريج معبأ جزئياً إلى الأمام ويمكن أن يدفع الشاحنة إلى الأمام بعد التوقف، لذا زِد مسافة الاتباع واكبح بلطف ومبكراً."},"43":{"q":"أنت تحمّل صهريج سائل ويجب أن تقرر مدى امتلائه. لماذا قد تترك بعض الحيز (الفراغ)؟","options":["لجعل الشاحنة أخف كي تتمكن قانونياً من حمل صناديق أكثر فوق الصهريج.","تتمدد السوائل بالحرارة، لذا تترك حيز فراغ كي لا يفيض الصهريج.","كي يتمايل السائل قدر الإمكان ويبقي الحمولة ممتزجة جيداً أثناء النقل.","لا يوجد سبب لترك حيز؛ املأ صهريج السائل دائماً تماماً حتى الأعلى."],"explanation":"تتمدد السوائل وهي تسخن، لذا يجب أن تترك حيز فراغ."},"44":{"q":"تأخذ حمولة من الحليب في صهريج ناعم التجويف لا حواجز بداخله. الصهريج ممتلئ نحو النصف فقط، ومسارك إلى مصنع الألبان يمر عبر عدة تقاطعات مزدحمة بإشارات مرور. وأنت تقترب من إشارة حمراء، أيٌّ مما يلي يصف على أفضل وجه كيف ينبغي أن تقود ولماذا؟","options":["لأن الصهريج ناعم التجويف، لا يمكن للسائل أن يتحرك، فيمكنني الكبح في اللحظة الأخيرة والتوقف في مسافتي المعتادة دون حيز إضافي.","الاندفاع في هذا الصهريج جانبي فقط، لذا توقفي غير متأثر؛ ما عليّ سوى توجيه المركبة بلطف عبر التقاطع.","سيكون الاندفاع الأمامي-الخلفي قوياً، لذا ينبغي أن أكبح بلطف ومبكراً، وأترك مسافة اتباع إضافية، وأتوقع أن يدفعني السائل إلى الأمام بعد التوقف.","بما أن الصهريج فارغ نصفه، فإن الحمولة أخف من أن تُحدث اندفاعاً، فيمكنني الاتباع عن قرب والكبح بقوة كشاحنة فارغة."],"explanation":"لا تحتوي الصهاريج ناعمة التجويف على حواجز لإبطاء السائل، لذا يكون الاندفاع الأمامي-الخلفي قوياً؛ اكبح بلطف ومبكراً، واترك مسافة اتباع إضافية، وتوقّع أن تُدفع إلى الأمام بعد التوقف."},"45":{"q":"أنا أنقل حمولة كاملة من السائل على طريق سريع بين الولايات وأقترب من منحدر خروج بسرعة استرشادية معلنة 35 ميلاً في الساعة. صهريجي محمّل حتى سعته، والمنحدر ينحني بإحكام إلى اليمين، والرصيف جاف. أي نهج يحميني على أفضل وجه من الانقلاب؟","options":["خذ المنحدر تماماً عند 35 ميلاً في الساعة المعلنة، لأن السرعة الاسترشادية مصممة لتكون آمنة لكل مركبة تستخدم المنحدر.","حافظ على 35 ميلاً في الساعة ثابتة وتسارع بلطف عبر المنعطف كي يضغط السائل إلى الخارج ويساعد على تثبيت الإطارات على الطريق.","حافظ على السرعة المعلنة لكن اكبح بقوة في منتصف المنعطف لمنع أي اندفاع للسائل إلى الأمام نحو المقصورة.","أبطئ إلى ما دون 35 ميلاً في الساعة المعلنة بكثير قبل الدخول، لأن مركز الثقل المرتفع لصهريج محمّل يجعله ينقلب أسهل بكثير من المركبات الأخرى."],"explanation":"مركز الثقل المرتفع لصهريج محمّل ينقلب بسهولة، لذا أبطئ إلى ما دون السرعة المعلنة بكثير قبل المنعطف أو المنحدر، لأن السرعات المعلنة تُحدد للمركبات النموذجية."},"46":{"q":"أنت تفحص صهريج حمولة قبل رحلة. ما الذي ينبغي أن تتفقده مما هو خاص بالصهاريج؟","options":["فقط المذياع وضبط المقعد، لأن الصهاريج تُقاد كأي شاحنة أخرى.","الصمامات والمنافس والخراطيم وأغطية فتحات الدخول بحثاً عن التسربات والتأكد من إغلاقها بشكل صحيح.","فقط لون الطلاء الخارجي كي يطابق الصهريج بقية أسطول الشركة.","لا شيء إضافي على الإطلاق؛ يحتاج الصهريج إلى نفس فحوص مقطورة منصة مسطحة فارغة."],"explanation":"تفقّد الصمامات والمنافس والخراطيم وأغطية فتحات الدخول بحثاً عن التسربات والتأكد من إغلاقها الصحيح."},"47":{"q":"أنت تنقل صهريج سائل محمّلاً جزئياً وتدخل منحدر خروج طريق سريع محدداً بعلامات. رغم أنك شعرت أنك تقود بحذر، تميل المقطورة بشدة وتكاد تنقلب وأنت تدور حول المنعطف. أيٌّ مما يلي هو التفسير الأرجح لما حدث؟","options":["تركب الحمولة السائلة عالياً، مما يعطي الصهريج مركز ثقل مرتفعاً، وأضاف الاندفاع الجانبي قوة دفعت المقطورة نحو الانقلاب على المنعطف.","كان الصهريج يعمل شبه فارغ، فمع وجود وزن قليل جداً على متنه لم تكن هناك فعلياً أي طريقة لأن تميل المقطورة أو تنقلب على منعطف.","تتماسك الإطارات الجديدة تماماً مع الطريق بقوة شديدة حتى أنها تجر الصهريج إلى الميل وتجعل الانقلاب أكثر احتمالاً بكثير على أي منعطف.","يزيل سطح الرصيف الجاف الناعم على المنحدر كل خطر الانقلاب تقريباً، لذا لا بد أن الميل جاء من عيب ميكانيكي، لا من الحمولة."],"explanation":"يركب السائل عالياً، مما يعطي الصهريج مركز ثقل مرتفعاً، وعلى المنعطف يضيف الاندفاع الجانبي قوة جانبية يمكن أن تدفع المقطورة إلى الانقلاب."},"48":{"q":"أنا أقود صهريج سائل محمّلاً جزئياً نحو إشارة حمراء عند تقاطع مزدحم. أكبح وتتوقف الشاحنة توقفاً كاملاً على بُعد بضعة أقدام خلف معبر المشاة. أيٌّ مما يلي ينبغي أن أتوقعه، وكيف كان يجب أن أقود للتعامل معه بأمان؟","options":["يضغط السائل الإطارات أكثر على الرصيف، فيتوقف صهريجي فعلاً في مسافة أقصر مما تتوقف فيه مقطورة صندوق جاف محمّل.","بعد أن أتوقف، يمكن للاندفاع الأمامي أن يدفع الشاحنة إلى الأمام داخل معبر المشاة، لذا كنت بحاجة إلى مسافة اتباع إضافية وتوقف سلس مبكر لطيف.","لأن الصهريج ممتلئ جزئياً فقط، فهناك وزن أقل على متنه، فلا يمكن للاندفاع أن يؤثر على توقف بطيء كهذا.","يحمّل السائل المندفع الفرامل تلقائياً ويثبت الشاحنة في مكانها، فلا أحتاج إلى ترك أي مسافة إضافية أمامي."],"explanation":"بعد التوقف، يمكن للاندفاع الأمامي أن يدفع الشاحنة داخل معبر المشاة، لذا حافظ على مسافة اتباع إضافية ونفّذ توقفاً سلساً مبكراً لطيفاً."},"49":{"q":"أنت تنقل عدة مقصورات صهريج صغيرة مزودة بحواجز فاصلة. لماذا تُستخدم هذه؟","options":["لجعل الصهريج يبدو أكثر أناقة ولإضافة وزن إضافي إلى مؤخرة المقطورة.","تقسّم الحمولة كي يتوازن الوزن ويُقلَّل الاندفاع الأمامي-الخلفي بشكل جيد.","تتيح لك ملء الصهريج بأكمله بما يتجاوز حده القانوني بكثير دون أي مشكلة حقيقية.","ليس لها غرض حقيقي وتجعل الصهريج فقط أثقل وأصعب في التنظيف."],"explanation":"تقسّم الحواجز الفاصلة الحمولة لموازنة الوزن وتقليل الاندفاع."},"50":{"q":"أنت تنقل صهريجاً ناعم التجويف محمّلاً نصفه على طريق سريع بين الولايات مبلل بالمطر عندما تظهر أمامك سيارة متعطلة في مسارك. لديك مساحة ووقت للانتقال مساراً واحداً إلى اليسار. بالنظر إلى كيفية تصرف السائل في صهريجك، أي إجراء يمنحك أفضل فرصة للبقاء مسيطراً؟","options":["أدِر المقود فجأة وأكمل تغيير المسار بأسرع ما يمكن، كي لا يكون للسائل وقت ليندفع جانبياً قبل أن تعود إلى الاستقامة.","اكبح بقوة أثناء توجيهك للمركبة، كي يثبّت الاندفاع الأمامي السائل على الحاجز الأمامي ويثبّت الصهريج أثناء الانتقال.","وجّه المركبة بسلاسة وتدريجياً، لأن حركة سريعة أو حادة مقترنة بالاندفاع الجانبي على السطح المبلل يمكن أن تقذف بك إلى انزلاق.","تسارع بثبات عبر تغيير المسار للحفاظ على تقدّم الشاحنة أمام السائل، كي يبقى الاندفاع خلفك ولا يستطيع دفع الصهريج."],"explanation":"في صهريج معبأ جزئياً، يمكن للاندفاع الجانبي أن يسبب انزلاقاً، وعلى سطح مبلل يكون هذا أسوأ، لذا غيّر المسار بسلاسة وتدريجياً."},"51":{"q":"هذه أول رحلة لك لنقل الحليب في صهريج أملس (بدون حواجز داخلية) ممتلئ بنحو الثلثين. وبينما تقترب من إشارة حمراء في حركة مرور متقطعة، تحاول أن تقرر كيف تدير المسافة والكبح مقارنةً بالشاحنة الجافة التي تقودها عادةً. أي نهج يناسب هذه الحمولة على أفضل وجه؟","options":["حافظ على مسافة أقصر من الشاحنة الجافة، لأن الحمولة السائلة الثقيلة تمنحك ثباتًا أكبر وتجعل الشاحنة تتوقف أسرع.","حافظ على المسافة نفسها التي تستخدمها مع الصندوق الجاف، لأن الصهريج المملوء جزئيًا يتوقف تقريبًا مثل المقطورة المعبّأة.","قلّل المسافة لكن اضغط على الفرامل بقوة في اللحظة الأخيرة، تاركًا وزن الحمولة يستقر بالشاحنة في توقف سريع.","افتح مسافة أمان إضافية وابدأ الكبح بلطف وفي وقت مبكر، لأن الاندفاع الأمامي يطيل مسافة التوقف وقد يدفعك للأمام بعد أن تظن أنك توقفت."],"explanation":"الصهريج الأملس يندفع بقوة، ما يطيل مسافة التوقف ويدفعك للأمام بعد توقف العجلات، لذا زِد مسافة الأمان واكبح بلطف وفي وقت مبكر."},"52":{"q":"أنا أنقل صهريجًا مزودًا بحواجز ومحمّلًا جزئيًا وألاحظ أن السائل لا يزال يدفع الشاحنة في الاتجاهات. بناءً على كيفية عمل الجدران الفاصلة المثقوبة في الصهريج المزود بالحواجز، أي عبارة تصف بدقة ما تفعله هذه الحواجز فعليًا لي على الطريق؟","options":["تقلّل الاندفاع الأمامي والخلفي، لكنها لا تفعل شيئًا للتحكم في الاندفاع الجانبي.","تزيل كل اندفاع في جميع الاتجاهات، فأستطيع التوجيه والتوقف كأنني أنقل حمولة جافة.","تتحكم في الاندفاع الجانبي لكنها تترك الاندفاع الأمامي والخلفي قائمًا بالكامل.","لا تُحدث فرقًا حقيقيًا، لأن الثقوب تسمح للسائل بالحركة بحرية تمامًا مثل الصهريج الأملس."],"explanation":"الحواجز تقلّل الاندفاع الأمامي والخلفي لكنها لا تفعل شيئًا للتحكم في الاندفاع الجانبي."},"53":{"q":"أنا أنقل صهريجًا مزودًا بحواجز ومحمّلًا جزئيًا، ويصرّ زميل لي في دورة رخصة القيادة التجارية على أن الجدران الفاصلة تحميني من كل أنواع اندفاع السائل. وبينما أتوجه إلى منعطف حلزوني ضيق، تصطدم الحمولة بقوة بأحد الجدران وتميل الشاحنة بشكل خطير نحو الانقلاب. بناءً على ما يمكن للحواجز فعله وما لا يمكنها، أي نوع من الاندفاع لا تفعل الحواجز في صهريجي شيئًا للتحكم فيه؟","options":["الاندفاع الأمامي الذي يدفع الشاحنة للأمام بعد توقفي.","الاندفاع الجانبي الذي يدفع الحمولة جانبيًا وقد يقلب الشاحنة.","الاندفاع الأمامي الخلفي الذي يطيل مسافة توقفي على المنعطف.","الاندفاع الذهاب والإياب بينما يتمايل السائل بين ثقوب الجدران الفاصلة."],"explanation":"الحواجز لا تفعل شيئًا للاندفاع الجانبي الذي يمكن أن يدفع الحمولة جانبيًا ويقلب الشاحنة على منعطف ضيق."},"54":{"q":"أنا أحمّل صهريجي في محطة، وأعلم أنني يجب أن أترك مساحة فارغة (outage) كي يتمدد السائل عند ارتفاع حرارته. لكن المرسل يحذرني من أن هذه الحمولة بالذات ثقيلة وقد أصل إلى حد الوزن القانوني قبل أن يبدو الصهريج ممتلئًا. إلى جانب المساحة الفارغة، ما الذي أحتاج إلى معرفته أيضًا لأحمّل بأمان ضمن حدود وزني؟","options":["لون السائل ودرجة صفائه، لأقدّر مدى امتلاء الصهريج بالنظر.","قناة راديو CB الخاص بالمحطة، لأتأكد من اكتمال التحميل.","وزن السائل (كثافته)، لأن المنتج الكثيف قد يصل إلى حد وزني القانوني قبل أن يمتلئ الصهريج.","ماركة الإطارات وتصنيف مدادها، لأعرف كم من الوزن الإضافي يمكنها حمله."],"explanation":"لأن السائل الكثيف قد يصل إلى حد الوزن القانوني قبل أن يمتلئ الصهريج فعليًا، فإن الكمية القابلة للتحميل تعتمد على كثافة السائل."},"55":{"q":"أنا أنقل حمولة سائلة كاملة في مقطورتي الصهريجية وأقترب من منحدر خروج عليه لافتة بسرعة 35 ميلاً في الساعة. مقارنةً بشاحنة مسطحة محمّلة بشحنات معبّأة في صناديق، فإن شاحنتي أكثر عرضةً بكثير للانقلاب إذا سلكت المنحدر بسرعة عالية. أي خاصية في مركبتي الصهريجية تفسّر على أفضل وجه لماذا يجب أن أبطئ إلى ما دون سرعة المنحدر المعلنة بكثير؟","options":["غلاف الصهريج الفولاذي الفارغ ثقيل جدًا لدرجة أنه يثقل محاور الدفع ويسحب المقطورة للخارج في المنعطف.","إطارات صهريجي كبيرة الحجم ذات جدران جانبية عالية تنثني وتميل بالمقطورة بشدة عند الانعطاف.","مقصورة الجرار منخفضة بشكل غير معتاد، ما يرفع مؤخرة المقطورة المحمّلة ويخفف وزنها في المنعطفات.","تركب الحمولة السائلة عاليًا داخل الصهريج المرتفع، ما يمنح المركبة مركز ثقل مرتفعًا يميل بسهولة."],"explanation":"يركب السائل عاليًا في الصهريج المرتفع، ما يرفع مركز ثقل المركبة ويجعلها تنقلب بسهولة، لذا اسلك المنعطفات بسرعة أقل بكثير من السرعة المعلنة."},"56":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة A والآن عُرضت عليّ وظيفة لنقل الحليب السائل في مقطورة صهريجية. يقول المسؤول عن توظيفي إنني بحاجة إلى إضافة تظهير مركبة الصهريج (N) إلى رخصتي قبل أن أبدأ. في مكتب السلامة العامة (DPS)، ما الذي يجب أن أفعله للحصول فعليًا على تظهير N؟","options":["اجتياز اختبار المعرفة الخاص بمركبة الصهريج لتظهير N.","اجتياز اختبار قيادة عملي منفصل على الطريق في مقطورة صهريجية.","اجتياز فحص أمني للخلفية الخاص بالمواد الخطرة قبل الإصدار.","اجتياز اختبار المعرفة الخاص بالمقطورات المزدوجة/الثلاثية (T) كشرط مسبق."],"explanation":"تظهير N (مركبة الصهريج) قائم على المعرفة فقط، لذا فإن نقل السوائل غير الخطرة يتطلب فقط اجتياز اختبار المعرفة الخاص بمركبة الصهريج."},"57":{"q":"أنا أحمّل سائلًا كثيفًا في محطة، ويُظهر الميزان أنني وصلت بالفعل إلى حد الوزن الإجمالي القانوني رغم أنه لا تزال هناك مساحة فارغة مرئية داخل الصهريج. يصرّ عامل التحميل على أن أملأه للنهاية لاستغلال الصهريج كله. بناءً على كيفية عمل تحميل الصهاريج، ما الوصف الصحيح لحالتي؟","options":["يجب أن يكون صهريجي ممتلئًا تمامًا بالسائل، لذا عليّ أن أواصل التحميل حتى لا يعود قادرًا على استيعاب المزيد فعليًا.","قد يكون صهريجي ممتلئًا جزئيًا فقط بشكل قانوني، لأن الحمولة الكثيفة تصل إلى حد الوزن قبل أن يمتلئ الصهريج.","ينبغي أن يكون صهريجي مملوءًا بشكل زائد قليلًا لأضمن الحصول على أقصى حمولة مدفوعة في الرحلة.","يحتاج صهريجي إلى ترك القسم الأوسط فارغًا كي توازن بقية السائل أوزان المحاور بالتساوي."],"explanation":"يصل السائل الكثيف إلى حد الوزن القانوني قبل أن يمتلئ الصهريج فعليًا، لذا فإن الصهريج المحمّل قانونيًا حتى الحد قد يكون ممتلئًا جزئيًا فقط."},"58":{"q":"أنت تنقل حمولة سائلة كاملة على طريق سريع ذي مسارين ويقترب منك منعطف معلن بسرعة 35 ميلاً في الساعة بسرعة. وبما أن صهريجك يركب عاليًا وينقلب بسهولة، متى ينبغي أن تكبح للوصول إلى سرعة آمنة؟","options":["اكبح بثبات أثناء مرورك عبر المنعطف، ثم خفّف الضغط بمجرد بلوغك قمة المنعطف.","انتظر بالكبح حتى تبدأ المقطورة بالشعور بالخفة أو الميل على الجانب الخارجي.","أنهِ كبحك قبل دخول المنعطف، ثم اسلكه بسرعة أقل بكثير من السرعة المعلنة.","حافظ على سرعتك عند الدخول، ثم اكبح بقوة فور خروجك من المنعطف لاستعادة السيطرة."],"explanation":"الصهريج المحمّل له مركز ثقل مرتفع وينقلب بسهولة، لذا أنهِ الكبح قبل المنعطف واسلكه بسرعة أقل بكثير من السرعة المعلنة."},"59":{"q":"عُيِّنت لي مقطورة صهريجية ليس بداخلها أي حواجز أو جدران فاصلة، فالداخل عبارة عن مقصورة واحدة مفتوحة وملساء. بناءً على طريقة بناء الصهريج، أي نوع من البضائع صُممت هذه المقطورة على الأرجح لنقله؟","options":["الغازات الصناعية المضغوطة، لأن الداخل الأملس المحكم الإغلاق يحافظ على الضغط على أفضل وجه.","النفط الخام وزيت الوقود، لأن حمولات البترول الثقيلة تحتاج إلى صهريج مفتوح بسبب الوزن.","المواد الكيميائية الخطرة الأكّالة، لأن الحواجز قد تتلف بفعل السائل.","السوائل الصالحة للأكل مثل الحليب، لأن الداخل الأملس سهل التنظيف والتعقيم."],"explanation":"الصهاريج الملساء (بدون حواجز) ليس بداخلها حواجز تحتجز الرواسب، ما يجعلها سهلة التنظيف والتعقيم للسوائل الصالحة للأكل مثل الحليب."},"60":{"q":"أنا أحمّل صهريجًا أملس بسائل مبرّد في محطة تبريد. الصهريج مصمم لتحمّل وزن الحمولة وأنا أقل بكثير من حدّي الإجمالي القانوني، ومع ذلك يوقفني عامل التحميل قبل أن يمتلئ الصهريج تمامًا ويصرّ على أن أترك مساحة فارغة في الأعلى. لماذا يُشترط ترك هذه المساحة الفارغة (outage) رغم أن لديّ سعة وزن فائضة؟","options":["لأن السائل سيتمدد عند ارتفاع حرارته أثناء النقل، وبدون مساحة فارغة سيفيض.","لأن الصهريج الأملس الممتلئ تمامًا يُحدث اندفاعًا جانبيًا عنيفًا يسبب الانقلاب.","لأن الملء للنهاية يرفع مركز الثقل فوق حد الارتفاع القانوني لمركبات الصهاريج.","لأن الملء حتى القمة تمامًا يجعل إحكام أغطية فتحات الرجل ومنافذ البخار مستحيلًا."],"explanation":"تتمدد السوائل عند ارتفاع حرارتها أثناء النقل، لذا يجب ترك مساحة فارغة (outage) لإعطاء السائل المتمدد مجالًا ومنع الفيضان."},"61":{"q":"أنا أحمّل سائلين مختلفين في صهريجين منفصلين في ظهيرة تكساس الدافئة. يخبرني المرسل أن أحد السائلين سيتطلب مني ترك مساحة فارغة (outage) أكبر بشكل ملحوظ في أعلى صهريجه مقارنةً بالآخر. لماذا قد يحتاج سائل إلى مساحة فارغة أكبر من الآخر؟","options":["لأن السائلين يختلفان في الوزن، والسائل الأثقل يشغل مساحة رأسية أكبر في الصهريج.","لأن بعض السوائل تتمدد أكثر من غيرها عند ارتفاع حرارتها، وتلك المساحة الإضافية تمنح السائل مجالًا للتمدد.","لأن السوائل الأفتح لونًا تعكس الحرارة وبالتالي تحتاج إلى مساحة إضافية لتنفيس البخار.","لأن السوائل التي تندفع بعنف أكبر تحتاج إلى مساحة إضافية في الأعلى لمنع تمايل الحمولة."],"explanation":"المساحة الفارغة هي المجال المتروك للتمدد، ولأن بعض السوائل تتمدد أكثر من غيرها عند تسخينها فإنها تحتاج إلى مجال أكبر للتمدد."},"62":{"q":"أنا أحمّل سائلًا ثقيلًا شديد الكثافة في صهريجي الأملس وأراقب وزني أثناء التحميل. أريد أن أنقل أكبر كمية يسمح بها القانون من المنتج دون أن أتجاوز الوزن عند الميزان. وأنا أحمّل هذا السائل الكثيف، متى سأصل على الأرجح إلى حد وزني القانوني؟","options":["في اللحظة التي يمتلئ فيها الصهريج تمامًا، لأن أقصى وزن قانوني وأقصى حجم يتطابقان دائمًا.","فقط بعد أن أملأه فوق طاقته وأترك المنتج يفيض قليلًا من المنافذ.","قبل أن يمتلئ الصهريج، بينما لا يزال ممتلئًا جزئيًا فقط، لأن الحمولة الكثيفة تثقل بسرعة.","أبدًا بناءً على الوزن وحده؛ فمع السائل الكثيف يمتلئ حجم الصهريج أولًا ويوقفني."],"explanation":"يصل السائل الكثيف إلى أقصى وزن قانوني بينما لا يزال الصهريج ممتلئًا جزئيًا فقط، لذا فإن الحجم القابل للتحميل محدود بالوزن لا بالسعة."},"63":{"q":"أنا أنقل صهريجًا سائلًا محمّلًا جزئيًا وأتوقف عند إشارة حمراء. في اللحظة التي أتوقف فيها تمامًا، أشعر أن الحمولة تدفع الجرار قليلًا للأمام، فتكاد تتجاوز الخط. يقول مدرّبي إن هذه الحركة الذهاب والإياب نفسها هي ما يمكن أن يهز الشاحنة جانبيًا ويقلبها في المنعطف. ما الاسم الصحيح لهذه الحركة من السائل؟","options":["المساحة الفارغة (outage)، أي تنقّل المساحة الفارغة المتروكة في الصهريج بينما يتحرك السائل في الداخل.","الكثافة، أي تغيّر وزن السائل الذي يقذف المركبة للأمام ومن جانب إلى جانب.","التحويج (baffling)، أي تمايل السائل عبر ثقوب الجدران الفاصلة أثناء حركته.","الاندفاع (surge)، أي حركة السائل الذهاب والإياب ومن جانب إلى جانب في صهريج ممتلئ جزئيًا."],"explanation":"حركة السائل الذهاب والإياب ومن جانب إلى جانب في صهريج ممتلئ جزئيًا تُسمى الاندفاع، الذي يمكن أن يدفع الشاحنة للأمام أو يسبب الانقلاب."},"64":{"q":"أنا أنقل حمولة جزئية من السائل في صهريج بدون حواجز وألاحظ أن التمايل يبدو عنيفًا كلما كبحت أو وجّهت. أريد أن أفهم متى تكون قوة الاندفاع هذه في أسوأ حالاتها كي أخطط لمسافة الأمان. عند أي مستوى تعبئة يكون اندفاع السائل أقوى عادةً؟","options":["عندما يكون الصهريج محمّلًا بنحو نصف سعته، ما يترك سطحًا حرًا كبيرًا للسائل كي يتمايل.","عندما يكون الصهريج ممتلئًا تمامًا، لأن الوزن الكامل يضغط على الجدران الفاصلة.","عندما يكون الصهريج فارغًا تمامًا، لأنه لا يوجد وزن يبقي المقطورة ثابتة.","عندما يكون الصهريج محمّلًا بنحو ثلاثة أرباعه، لأن ذلك يضع أكبر قدر من السائل قرب القمة."],"explanation":"الصهريج الأملس الممتلئ للنصف يترك أكبر سطح حر، لذا يتمايل السائل بأقصى قوة ويكون الاندفاع أقوى."},"65":{"q":"أنا أنقل حمولة سائلة في صهريج ممتلئ حتى القمة تقريبًا بلا مساحة فارغة تُذكر في الداخل. وبينما أكبح للتوقف عند تقاطع، كيف ينبغي أن أتوقع أن يتصرف اندفاع السائل مقارنةً بصهريج ممتلئ جزئيًا؟","options":["سيكون الاندفاع قويًا جدًا، لأن الحمولة الكاملة الأثقل تبني زخمًا أكبر وتدفع الشاحنة للأمام بقوة أكبر.","سيكون الاندفاع ضئيلًا، لأن السائل ليس لديه سوى مجال قليل جدًا للتحرك ذهابًا وإيابًا داخل الصهريج.","سيكون الاندفاع غير متوقع، لأن الصهريج المملوء للنهاية قد يتمايل في أي اتجاه دون سابق إنذار.","سيكون الاندفاع جانبيًا فقط، لأن الحركة الرأسية تُحجب بمجرد امتلاء الصهريج تمامًا."],"explanation":"الصهريج الممتلئ تمامًا يترك للسائل مجالًا ضئيلًا للتحرك، لذا يكون الاندفاع ضئيلًا."},"66":{"q":"أنا أنقل صهريجًا أملس محمّلًا جزئيًا وأقترب من إشارة حمراء أسفل منحدر. مقارنةً بالجرار المنفرد (bobtail) خلفي، كيف ينبغي أن يغيّر اندفاع السائل طريقة تقديري لتوقفي؟","options":["لا تأثير للاندفاع بمجرد ضغطي على الفرامل، فأستطيع استخدام نقطة توقفي المعتادة.","يساعد الاندفاع على إبطاء الشاحنة أسرع، فأستطيع الكبح متأخرًا عن المركبة خلفي.","يستمر الاندفاع في دفع الشاحنة للأمام، فأحتاج إلى بدء الكبح مبكرًا وإتاحة مسافة أكبر للتوقف.","الاندفاع مهم فقط في المنعطفات، فأخطط للتوقف المستقيم بالمسافة نفسها لأي شاحنة محمّلة."],"explanation":"اندفاع السائل في الصهريج الأملس الممتلئ جزئيًا يستمر في دفع الشاحنة للأمام ويطيل مسافة التوقف، لذا اكبح مبكرًا وأتح مسافة أكبر للتوقف."},"67":{"q":"لقد سلّمت للتو حمولتي الكاملة وأنا الآن أقود الصهريج نفسه عائدًا فارغًا على مقطع طريق سريع مبلل ووعِر. مقارنةً بحالة الصهريج المحمّل، كيف سيتصرف هذا الصهريج الفارغ على الأرجح على هذا السطح؟","options":["سيتشبث بالرصيف المبلل بشكل أفضل لأن هناك وزنًا أقل يضغط الإطارات إلى الطريق.","سيتوقف في مسافة أقصر بشكل ملحوظ لأن المقطورة الأخف تحتاج إلى قوة كبح أقل بكثير.","سيسير في خط أكثر استقامة عبر المنعطفات لأن انخفاض الوزن يخفض مركز الثقل.","سيرتد ويفقد الثبات بسهولة أكبر لأن الصهريج الفارغ يسير أخف على المطبّات."],"explanation":"الصهريج الفارغ يسير أخف، لذا يرتد ويفقد الثبات بسهولة أكبر على الطرق المبللة والوعِرة."},"68":{"q":"أنا عند رصيف التحميل على وشك بدء ملء صهريج البضائع بحمولة سائلة. قبل أن يبدأ المنتج بالتدفق، أي من الآتي هو العنصر الوحيد الذي يجب أن أتحقق منه كجزء من فحص ما قبل التحميل؟","options":["أن الصمامات والمنافذ تعمل بشكل صحيح وأنها مغلقة ومحكمة في مواضعها الصحيحة.","أن الصهريج من النوع الأملس كي يبقى المنتج الغذائي الذي أنقله صحيًا.","أن مساحة فارغة (outage) كافية قد حُسبت كي يكون للسائل الدافئ مجال للتمدد.","أن مسافة الأمان وخطة الكبح اللطيف معدّان لمركز الثقل المرتفع."],"explanation":"قبل التحميل، تأكد من أن الصمامات والمنافذ تعمل وأنها مغلقة ومحكمة في مواضعها الصحيحة لمنع الانسكاب ومشاكل الضغط."},"69":{"q":"أثناء فحص ما قبل الرحلة لصهريج محمّل، ألاحظ تسربًا ثابتًا يقطر من حول أحد صمامات التفريغ، وحشية غطاء فتحة الرجل تبدو مبللة. وجهتي على بُعد نحو 20 ميلاً فقط وأنا متأخر بالفعل عن الجدول. ماذا ينبغي أن أفعل؟","options":["بما أن الرحلة قصيرة والتسرب طفيف، أسجّله كعيب بسيط وأراقبه أثناء الرحلة.","أعامل التسرب كحالة عدم صلاحية للخدمة وأُصلح الصمام وغطاء فتحة الرجل قبل أن أقود المركبة على الطريق.","أُحكم ربط مسامير غطاء فتحة الرجل، وأمسح الصمام، وأتابع لأن التسرب صار مسيطرًا عليه.","أُقلل الحمولة قليلًا إلى ما دون مستوى الصمام المتسرب كي لا يتسرب، ثم أُكمل التسليم."],"explanation":"الصمام أو غطاء فتحة الرجل المتسرب عيب يخص السلامة يجب إصلاحه قبل القيادة، مهما كانت الرحلة قصيرة."},"70":{"q":"أنا أفرّغ صهريجًا مغلق القمة عبر ضخ المنتج من صمام السفلي، وتخبرني قائمة فحص المشغّل بفتح منفذ التهوية في الصهريج قبل أن أبدأ سحب السائل للأسفل. لماذا يكون فتح هذا المنفذ هو الخطوة الصحيحة في هذه المرحلة؟","options":["لأن فتح المنفذ يتيح للهواء الخارجي بالاندفاع إلى الداخل لإضافة ضغط يساعد على دفع المنتج المتبقي خارجًا أسرع.","لأن المنفذ يجب أن يبقى مفتوحًا ليتيح لمنطقة المضخة والمحرك الساخنة تنفيس الحرارة المتراكمة أثناء التفريغ الطويل.","لأنه مع خروج المنتج من الصهريج المحكم لا يمكن للحيز الهوائي أن يعيد ملء نفسه، والمنفذ المفتوح يمنع تكوّن فراغ.","لأن المنفذ المفتوح يتيح لك شطف وغسل الرواسب المتبقية خارج الصهريج أثناء تصريف السائل."],"explanation":"مع خروج المنتج من صهريج محكم سيتكوّن فراغ يوقف التدفق، لذا يتيح فتح المنفذ دخول الهواء للحفاظ على توازن الضغط."},"71":{"q":"أنا أنقل صهريجًا سائلًا محمّلًا جزئيًا وأقترب من منحدر خروج حلزوني معلن بسرعة 35 ميلاً في الساعة. بالنظر إلى كيفية توزع وزن هذه المركبة، ما الطريقة الأكثر أمانًا للتعامل مع هذا المنحدر؟","options":["حافظ على 35 ميلاً في الساعة لأن تلك السرعة المعلنة تأخذ مركبات الصهاريج في الحسبان بالفعل.","أسرِع قليلًا قبل المنعطف كي تتمكن من الانزلاق عبره دون استخدام الفرامل.","حافظ على سرعتك المعتادة على الطريق السريع واكبح بقوة بمجرد دخولك المنعطف.","أبطئ إلى ما دون السرعة المعلنة 35 ميلاً في الساعة بكثير قبل دخول المنعطف، ثم وجّه بسلاسة عبره."],"explanation":"مركز الثقل المرتفع للصهريج السائل يجعله ينقلب بسهولة، لذا أبطئ إلى ما دون السرعة المعلنة بكثير قبل المنعطف ووجّه بسلاسة عبره."},"72":{"q":"أنا أنقل حمولة سائلة كاملة في صهريج وأقترب من منحدر خروج على طريق سريع به منعطف. للمنحدر سرعة إرشادية معلنة قدرها 35 ميلاً في الساعة. كي أمنع شاحنتي ذات مركز الثقل المرتفع من الانقلاب على المنعطف، كيف ينبغي أن أتعامل مع سرعتي؟","options":["أبطئ واسلك المنعطف بسرعة أقل بكثير من السرعة المعلنة 35 ميلاً في الساعة.","حافظ على سرعة ثابتة قدرها 35 ميلاً في الساعة عبر المنعطف لأن تلك السرعة معلنة كآمنة.","حافظ على سرعتي على الطريق السريع واكبح بقوة بمجرد دخولي المنعطف.","أسرِع قليلًا قبل المنعطف كي أنزلق عبره بسلاسة."],"explanation":"مركز الثقل المرتفع للصهريج يجعله عرضة للانقلاب، لذا اسلك المنعطفات والمنحدرات بسرعة أقل بكثير من السرعة المعلنة."},"73":{"q":"أنا أنقل صهريجًا أملس محمّلًا جزئيًا واضطررت إلى التوقف بقوة عند إشارة حمراء أسفل منحدر هابط. وأنا أتوقف، لماذا ينبغي أن أكون قلقًا بشكل خاص من حدة كبحي؟","options":["الكبح الحاد سيُسخّن أسطوانات الفرامل ويُضعفها قبل أن تتحول الإشارة إلى الأخضر.","يمكن لاندفاع السائل أن يدفع الشاحنة للأمام متجاوزًا خط التوقف وخارجًا إلى التقاطع.","التوقف المفاجئ سيحسّن ثبات الإطارات فتتشبث الشاحنة وتستقر بثبات في مكانها.","الكبح القوي يحرق وقودًا أقل، فيوفّر المال لكنه لا يضيف شيئًا إلى السلامة العامة."],"explanation":"بعد التوقف القوي يمكن للاندفاع الأمامي في صهريج أملس ممتلئ جزئيًا أن يدفع الشاحنة متجاوزة خط التوقف إلى داخل التقاطع."},"74":{"q":"أنا أنقل صهريجًا أملس محمّلًا جزئيًا على طريق سريع مقسّم عندما تعبر سيارة فجأة مساري واضطر إلى التوقف بقوة لتفادي الاصطدام. شاحنتي لا تحتوي على نظام الكبح المانع للانغلاق (ABS). للتوقف بأسرع ما يمكن مع إبقاء الشاحنة مستقيمة وتحت السيطرة، أي تقنية كبح ينبغي أن أستخدمها؟","options":["أضغط على دواسة الفرامل بأقصى قوة وأبقيها مضغوطة حتى تتوقف الشاحنة.","أستخدم فرامل المقطورة فقط بالصمام اليدوي لمنع الجرار من الانزلاق.","أستخدم الكبح المتحكَّم به أو الكبح المتقطع (stab braking)، مع تخفيف الضغط إذا انغلقت العجلات، مع إبقاء المركبة مستقيمة.","أضغط الفرامل برفق بشكل متقطع وأترك اندفاع السائل يساعد على إبطاء الشاحنة."],"explanation":"بدون نظام ABS، استخدم الكبح المتحكَّم به أو الكبح المتقطع وخفّف الضغط إذا انغلقت العجلات للحفاظ على التحكم في التوجيه والبقاء مستقيمًا."},"75":{"q":"أنا أنقل صهريجًا مزودًا بحواجز ومحمّلًا جزئيًا وألاحظ أن السائل لا يزال يصطدم من اليسار إلى اليمين عندما أوجّه عبر منعطف، رغم أنني توقعت أن تتعامل الجدران الفاصلة الداخلية مع التمايل. لماذا لا أزال أشعر بهذه الحركة الجانبية، وأي اندفاع تتحكم فيه الحواجز فعليًا من أجلي؟","options":["الحواجز رسبت في الفحص، لأن الصهريج المزود بحواجز سليمة يوقف حركة السائل في كل اتجاه.","الحواجز تتحكم في الاندفاع الجانبي، وهذا بالضبط سبب شعورك بالمنعطف أسوأ من الكبح في خط مستقيم.","تركت مساحة فارغة (outage) كبيرة جدًا، فلا تستطيع الحواجز بلوغ السائل؛ وهي مخصصة لإيقاف الاندفاع الجانبي.","الحواجز لا تفعل شيئًا للاندفاع الجانبي؛ إنها تقلّل فقط الاندفاع الأمامي والخلفي الذي تشعر به عند الانطلاق والتوقف."],"explanation":"الحواجز تقلّل فقط الاندفاع الأمامي والخلفي؛ ولا تفعل شيئًا للاندفاع الجانبي الذي يُشعر به في المنعطفات."},"76":{"q":"لقد تم توظيفي للتو لنقل الحليب ومنتجات غذائية سائلة أخرى، وأخبرني المرسل أن مقطورتي عبارة عن خزان من نوع 'الجدار الأملس' (smooth-bore). بناءً على ذلك، ماذا ينبغي أن أتوقع بشأن داخل الخزان وكيف سيتصرف على الطريق؟","options":["لا يحتوي على حواجز أو جدران فاصلة داخلية، لذا يندفع السائل بحرية ويجب أن أبدأ التحرك وأتوقف وأوجه المركبة بلطف شديد","يحتوي على حواجز بها فتحات في الداخل تقلل من اندفاع السائل للأمام والخلف، لذا يمكنني الفرملة في وقت متأخر قليلاً عن المعتاد","يحتوي على جدران فاصلة صلبة تقسمه إلى مقصورات محكمة الإغلاق، لذا يُلغى الاندفاع ويصبح التحكم مشابهاً لشاحنة الصندوق الجاف","يحتوي على جدران مزدوجة سميكة إضافية في الداخل، لذا يخفض البناء الأثقل مركز الثقل ويقاوم الانقلاب"],"explanation":"الخزان ذو الجدار الأملس لا يحتوي على حواجز أو جدران فاصلة، لذا يندفع السائل بحرية ويجب أن تبدأ التحرك وتتوقف وتوجه المركبة بلطف شديد."},"77":{"q":"أنا أنقل حمولة في شاحنة خزان ويشير المفتش إلى أن مقطورتي تحتوي على فواصل صلبة ملحومة داخل غلاف الخزان، وليست النوع الذي به فتحات. ويسألني عما تفعله هذه الجدران الداخلية الصلبة فعلياً داخل الخزان. أي إجابة صحيحة؟","options":["تحول الخزان إلى مساحة واحدة مفتوحة متصلة حتى يستقر السائل بالتساوي على طول الخزان بالكامل","تقسم غلاف الخزان إلى مقصورات منفصلة محكمة الإغلاق على طوله","تقلل من اندفاع السائل من الأمام إلى الخلف بينما تسمح له بالتحرك من جانب إلى آخر","تبقي الحمولة بجدار أملس تماماً حتى يمكنها قانونياً نقل المنتجات الغذائية"],"explanation":"الجدران الفاصلة (bulkheads) هي جدران داخلية صلبة تقسم غلاف الخزان إلى مقصورات منفصلة محكمة الإغلاق على طوله."},"78":{"q":"أنا أحمّل شاحنة خزان متعددة المقصورات في محطة في أماريلو. الحمولة الإجمالية أقل بكثير من حد وزني الإجمالي، لذا أملأ المقصورات الخلفية أولاً لتوفير الوقت عند منصة التحميل. وبينما أتقدم نحو الميزان، يلوّح لي المشغل بالعودة. أي مما يلي هو الشيء الأهم الذي كان ينبغي أن أراقبه أثناء تحميل المقصورات؟","options":["الوزن الإجمالي الكلي فقط، لأن البقاء تحت الحد الإجمالي هو كل ما يهم قانونياً عند الميزان","عدد المقصورات الممتلئة، مع التأكد من استخدام كل مقصورة قبل المغادرة من منصة التحميل","الوزن على كل محور، مع موازنة الحمولة من الأمام إلى الخلف حتى لا يتحمّل أي محور وزناً زائداً","الفراغ المتروك في المقصورات الأمامية، مع إبقاء المساحة الفارغة متساوية في كل قسم من الخزان"],"explanation":"عند تحميل مقصورات متعددة، وازِن الوزن على كل محور من الأمام إلى الخلف حتى لا يتحمّل أي محور وزناً زائداً."},"79":{"q":"لقد تم توظيفي للتو لنقل الحليب الطازج في مقطورة خزان، وألاحظ أن الخزان ذو جدار أملس (بدون حواجز) بدلاً من احتوائه على الجدران الفاصلة التي رأيتها في خزانات الوقود. أعلم أن الخزانات ذات الجدار الأملس تجعل السائل يندفع بقوة أكبر بكثير، فلماذا قد تختار شركة النقل عمداً هذا التصميم الأكثر خطورة لمنتج غذائي مثل الحليب؟","options":["لأن الحواجز تضيف وزناً كبيراً جداً، ويجب أن تبقى شاحنة الخزان الغذائية تحت الحد القانوني لتحمل حمولة كاملة من الحليب","لأن الحواجز تجعل اندفاع السائل أسوأ بكثير، وتقليل الاندفاع يحافظ على الحليب من الفساد أثناء النقل","لأن الحواجز غير قانونية في أي مركبة خزان تنقل منتجاً مخصصاً للاستهلاك البشري","لأن الحواجز يصعب جداً تنظيفها، والمنتجات الغذائية مثل الحليب تتطلب خزاناً يمكن تعقيمه بالكامل بين الحمولات"],"explanation":"تُستخدم الخزانات ذات الجدار الأملس للمنتجات الغذائية مثل الحليب لأن الحواجز يصعب جداً تنظيفها ويجب تعقيم الخزان بالكامل بين الحمولات."},"80":{"q":"لقد حصلت للتو على وظيفة لنقل الحليب في خزان شحن يتسع لأكثر من 1000 جالون بكثير، وستقوم إدارة التوزيع بتحميله يوم الاثنين. رخصتي تحمل بالفعل تصريح المواد الخطرة (H) من وظيفة سابقة. قبل أن أقود هذه الحمولة قانونياً، أي تصريح ما زلت بحاجة إلى إضافته إلى رخصتي التجارية؟","options":["تصريح مركبة الخزان (N)، لأنني أنقل سائلاً بكميات كبيرة داخل خزان شحن مثبّت بشكل دائم","لا شيء إضافي، لأن تصريح المواد الخطرة (H) لدي يخوّلني بالفعل تشغيل أي مركبة خزان","تصريح المقطورات المزدوجة/الثلاثية (T)، لأن خزان الشحن الكبير يُحتسب كمقطورات متعددة","تصريح الركاب (P)، لأن تصنيف الوزن الإجمالي للمركبة مرتفع بما يكفي لاشتراطه"],"explanation":"يتطلب نقل سائل بكميات كبيرة في خزان شحن مثبّت بشكل دائم تصريح مركبة الخزان (N)."},"81":{"q":"أحمل بالفعل رخصة تجارية صالحة مع تصريح N (مركبة الخزان)، وغداً أُكلَّف بشاحنة خزان محمّلة بسائل قابل للاشتعال يتطلب ملصقات المواد الخطرة على المقطورة. قبل أن أتمكن قانونياً من قيادة تلك الحمولة المعلَّمة بالملصقات، أي مما يلي صحيح بشأن التصريح (التصاريح) التي يجب أن أحملها؟","options":["تصريح N لدي يغطي بالفعل أي سائل في خزان، لذا لا يلزم تصريح إضافي لهذه الحمولة.","يجب أن أحمل كلاً من تصريح N (الخزان) وتصريح H (المواد الخطرة)، لأن السائل الخطر المعلَّم بالملصقات يتطلب صلاحية المواد الخطرة بالإضافة إلى تصريح الخزان.","أحتاج فقط إلى إضافة تصريح H (المواد الخطرة)، ولم يعد تصريح N ذا صلة بمجرد وضع الملصقات.","الحمولة القابلة للاشتعال المعلَّمة بالملصقات تتطلب فقط رخصة قيادة من الفئة C، لذا لا ينطبق هنا تصريح N ولا H."],"explanation":"يتطلب السائل الخطر المعلَّم بالملصقات في خزان كلاً من تصريح N (الخزان) وتصريح H (المواد الخطرة)."},"82":{"q":"أنا أحمّل مقطورة خزان بسائل دافئ في محطة في ظهيرة تكساس الحارة، ويذكّرني مدربي بألّا أملأ الخزان حتى أعلاه تماماً. يخبرني أن أترك عمداً مقداراً محدداً من المساحة الفارغة في الخزان قبل أن أحكم إغلاق غطاء فتحة الدخول. ما المصطلح الصناعي الصحيح لهذه المساحة الفارغة المطلوب مني تركها؟","options":["الاندفاع (Surge)، لأن المساحة غير الممتلئة هي ما يسمح للسائل بالتمايل للأمام والخلف داخل الخزان","الحجز (Baffling)، لأن المساحة الفارغة في الأعلى تعمل كجدار فاصل للتحكم في الحركة من جانب إلى آخر","الفراغ (Outage أو ullage)، وهو المساحة الفارغة التي يجب أن أتركها حتى يتوفر للسائل مجال للتمدد عند تسخّنه","الكثافة (Density)، لأنه كلما كان السائل أثقل زادت المساحة الفارغة التي يفرض القانون تركها في الأعلى"],"explanation":"الفراغ (Outage أو ullage) هو المساحة الفارغة التي يجب تركها في خزان السائل حتى يتوفر للسائل مجال للتمدد عند تسخّنه."},"83":{"q":"أنا أجري فحص ما قبل الرحلة على شاحنة خزان محمّلة بسائل قبل أن أغادر المحطة. وبينما أتسلق إلى الأعلى لفحص منطقة القبة، في أي حالة يجب أن تكون أغطية فتحات الدخول قبل أن أتمكن قانونياً وبأمان من بدء القيادة؟","options":["مفتوحة قليلاً حتى يتمكن البخار المتمدد من الخروج وتخفيف الضغط الداخلي على الطريق","مفكوكة ومستندة بشكل غير محكم حتى أتمكن من فحص التسربات بسهولة أكبر بمجرد التحرك","مزالة بالكامل ومخزّنة لتقليل الوزن في الأعلى وخفض مركز الثقل","مغلقة ومحكمة الإغلاق تماماً، مع إغلاق صمامات التنفيس ووجود جميع الصمامات في الوضع الصحيح"],"explanation":"في فحص ما قبل الرحلة، يجب أن تكون أغطية فتحات الدخول وصمامات التنفيس مغلقة ومحكمة الإغلاق تماماً مع وجود جميع الصمامات في الوضع الصحيح."},"84":{"q":"أثناء فحص ما قبل الرحلة على شاحنة خزان تنقل حمولة سائلة، ألاحظ أن أحد خراطيم تفريغ الشحن بالٍ ومركّب بشكل غير محكم عند الوصلة. مكان التسليم على بُعد بضعة أميال فقط وأنا متأخر بالفعل عن جدولي. ماذا ينبغي أن أفعل قبل بدء الرحلة؟","options":["إصلاح أو استبدال الخرطوم البالي غير المحكم قبل القيادة، لأن عيوب خراطيم الشحن يجب تصحيحها قبل الرحلة","القيادة بحذر بسرعة منخفضة لأن المسافة القصيرة تجعل الخرطوم البالي مخاطرة مقبولة","لف الوصلة غير المحكمة بإحكام بشريط لاصق قوي لإغلاقها طوال مدة الرحلة","المتابعة كما هو مخطط لأن الخرطوم غير المحكم يهم فقط في الطرق الطويلة، وليس في عمليات التسليم المحلية"],"explanation":"عيوب خرطوم الشحن مثل التآكل أو الارتخاء يجب إصلاحها قبل الرحلة، ولا يجوز أبداً حملها والتعامل معها على الطريق."},"85":{"q":"أنا أنقل حمولة سائلة في مقطورة الخزان وأقترب من منحدر خروج على الطريق السريع مُحدَّد بسرعة 35 ميلاً في الساعة. مقارنة بمقطورة صندوق محمّلة تحمل شحناً معبّأً في صناديق، لماذا يجب أن أبطئ أكثر قبل الدخول إلى هذا المنعطف؟","options":["الحمولة السائلة تجعل فراملي تفقد فعاليتها أسرع، لذا أحتاج إلى مساحة إضافية للتوقف قبل المنعطف","مركز الثقل المرتفع لخزاني يجعله عرضة للانقلاب، لذا ينبغي أن آخذ المنحدر بسرعة أقل بكثير من السرعة المحددة","الحمولة السائلة تجعل التوجيه يبدو خفيفاً جداً، لذا أفقد التماسك وأنزلق عبر المنعطف","الخزان الممتلئ بالسائل يتوقف أسرع بكثير، لذا يجب أن أفرمل في وقت متأخر لتجنب التوقف المفاجئ في المنعطف"],"explanation":"مركز الثقل المرتفع للخزان يجعله ينقلب بسهولة، لذا يجب أخذ المنعطفات والمنحدرات بسرعة أقل بكثير من السرعة المحددة."},"86":{"q":"أنا أقود شاحنة خزان محمّلة جزئياً نازلاً من منحدر على طريق سريع مُحدَّد بسرعة 35 ميلاً في الساعة، وفجأة تميل المقطورة على عجلتين وتنقلب. عندما يكتب محقق الحادث السبب الأكثر شيوعاً لانقلاب مركبات الخزان مثل مركبتي، أي إجراء من السائق سيشير إليه التقرير باعتباره السبب الجذري؟","options":["متابعة المركبة التي أمامي بمسافة كبيرة جداً، مما أجبر على تغييرات مفاجئة في المسار قرب المنحدر","نقل حمولة بجدار أملس (بدون حواجز) تراكم منها اندفاع للأمام والخلف أثناء الفرملة","الدخول إلى المنحدر المنعطف بسرعة عالية جداً بالنسبة لخزان ذي مركز ثقل مرتفع بدلاً من سرعة أقل بكثير من السرعة المحددة","تحرير الفرامل بلطف ومبكراً جداً، مما ترك الشاحنة تنساب عبر المنحدر بوزنها الخاص"],"explanation":"السبب الأكثر شيوعاً لانقلاب الخزانات هو أخذ المنعطف أو المنحنى أو المنحدر بسرعة عالية جداً بالنسبة لمركز الثقل المرتفع."},"87":{"q":"أنت تنقل شاحنة خزان محمّلة جزئياً وتصل إلى إشارة توقف عند تقاطع مزدحم. تتوقف الشاحنة، فتحرر الفرامل لتتسلل إلى الفجوة في حركة المرور المتقاطعة. لماذا يكون هذا التحرير المبكر خطيراً؟","options":["الفرامل المحررة تقفل العجلات الخلفية فوراً، فتنزلق بك جانبياً إلى المسار","السائل البارد ينكمش ويسحب الشاحنة إلى الخلف بعيداً عن التقاطع","تحرير الفرامل يفرّغ خزانات الهواء، فتبقى بلا فرامل في التوقف التالي","اندفاع السائل للأمام يدفع الشاحنة إلى الأمام، فيدفعك إلى داخل التقاطع"],"explanation":"في الخزان الممتلئ جزئياً يستمر السائل في التمايل، ويمكن للاندفاع للأمام أن يدفع الشاحنة إلى الأمام داخل التقاطع إذا حررت الفرامل في وقت مبكر جداً."},"88":{"q":"أنا أنقل شاحنة خزان محمّلة جزئياً على طريق سريع عندما يبدأ المطر بالهطول، ويوجّهني نظام الملاحة إلى منحدر خروج على شكل ورقة البرسيم أمامي. مقارنة بقيادة المسار نفسه في شاحنة صندوق جاف محمّلة، أين تتطلب مركبة الخزان هذه أقصى قدر من الحذر الإضافي؟","options":["على الرصيف المبلل والمنحدر المنعطف وأي منعطفات مائلة على الطريق السريع، لأن مركز الثقل المرتفع واندفاع السائل يجعلان الانقلاب أكثر احتمالاً بكثير","فقط على الامتدادات المستقيمة الطويلة بين المخارج، حيث يبني الاندفاع أكبر سرعة على المسافة","بشكل أساسي في المناطق المفتوحة الفارغة مثل مواقف الاستراحة، حيث يوجد مجال ليستقر الاندفاع","على الأقسام المسطحة الجافة من الطريق السريع، لأن التماسك يكون أعلى ما يكون وتنتقل الحمولة بأشد ما يكون هناك"],"explanation":"مركز الثقل المرتفع للخزان واندفاع السائل يجعلان الانقلاب أكثر احتمالاً بكثير على الطرق المبللة والمنعطفات والمنحدرات، لذا توخَّ حذراً إضافياً هناك."},"89":{"q":"أنا أنقل شاحنة خزان سائل محمّلة جزئياً على طريق داخل المدينة. وبينما أقترب من إشارة حمراء، أبدأ الفرملة في وقت أبكر وأبطئ بلطف أكبر بكثير مما كنت سأفعل في شاحنة صندوق جاف محمّلة. السبب الرئيسي في أن شاحنة الخزان هذه تتطلب فرملة وتوجيهاً أكثر سلاسة وأبكر من شاحنة صندوق جاف بوزن مماثل هو:","options":["شاحنة الخزان مزوّدة بفرامل أقوى، لذا تبطئ بشكل مختلف","السائل يندفع ذهاباً وإياباً، فيدفع الشاحنة إلى الأمام ويهدد بالانقلاب","شاحنة الخزان تسير أخف بكثير، لذا تتوقف وتستجيب أسرع","المرايا الأعرض تغيّر كيفية تقديري لمسافة المتابعة والتباعد"],"explanation":"في الخزان الممتلئ جزئياً يندفع السائل ذهاباً وإياباً ومن جانب إلى آخر، فيدفع الشاحنة إلى الأمام ويهدد بالانقلاب، لذا افرمل بسلاسة ومبكراً."},"90":{"q":"أنا أحمّل مقطورة خزان بسائل كثيف في محطة، وألاحظ أن الخزان يصل إلى حد الوزن القانوني بينما لا تزال هناك مساحة فارغة في الداخل. وبينما أنهي التحميل، أي مما يلي ينبغي أن يوجّه كيفية تعاملي مع الحمولة؟","options":["الاستمرار في الملء حتى يمتلئ الخزان تماماً حتى يُلغى اندفاع السائل، حتى لو تجاوز الوزن القانوني","نقل المنتج المتبقي نحو مقدمة الخزان حتى يحمل محور التوجيه الجزء الأثقل","التوقف عند حد الوزن القانوني والتأكد من بقاء الحمولة ضمن ذلك الحد وأنها متوازنة بشكل صحيح","حشر الوزن المتبقي فوق المحاور الخلفية حتى تحصل عجلات الدفع على أقصى تماسك"],"explanation":"يمكن للسائل الكثيف أن يصل إلى حد الوزن القانوني قبل أن يمتلئ الخزان، لذا توقف عن التحميل عند ذلك الحد وأبقِ الحمولة قانونية ومتوازنة بشكل صحيح."},"91":{"q":"أنت تنقل حمولة من السماد السائل على طريق ريفي في تكساس عندما تشم رائحة غريبة، فتتوقف على الكتف، وتلاحظ تسرباً مستمراً للسائل من حول صمام على الجانب السفلي من خزانك. أنت على بُعد نحو 20 دقيقة فقط من موقع التسليم. ماذا ينبغي أن تفعل؟","options":["الاستمرار في القيادة إلى موقع التسليم لأنه قريب، ثم الإبلاغ عن التسرب بعد إفراغ الخزان","فتح صمامات الخزان الأخرى لتخفيف الضغط الداخلي وإبطاء التسرب قبل المتابعة","الإسراع للوصول إلى العميل أسرع حتى يضيع منتج أقل على الطريق","البقاء متوقفاً، وتأمين المنطقة لإبعاد الآخرين، والاتصال طلباً للمساعدة قبل القيام بأي شيء آخر"],"explanation":"إذا كان السائل يتسرب من خزانك، توقف، وأمّن المنطقة لإبعاد الآخرين، واتصل طلباً للمساعدة قبل القيام بأي شيء آخر."},"92":{"q":"أنا أفرّغ البنزين من خزان الشحن في محطة سائبة عندما تنفجر فجأة وصلة خرطوم ويبدأ المنتج بالرش على الأرض. خزاني مزوّد بنظام إيقاف طارئ. ما الغرض من تفعيله في هذه الحالة؟","options":["إيقاف تدفق المنتج حتى يُقطع التسرب بأسرع ما يمكن","تشغيل مضخة المنتج لدفع الشحنة المتبقية بشكل أسرع","تنفيس ضغط الخزان عبر صمام التخفيف وخفض درجة حرارة الشحنة","إحكام إغلاق أغطية فتحات الدخول ومنافذ البخار قبل انتشار التسرب"],"explanation":"يوجد نظام الإيقاف الطارئ لإيقاف تدفق المنتج، وقطع التسرب بأسرع ما يمكن أثناء حالة طارئة في التحميل أو التفريغ."},"93":{"q":"لقد أوقفت شاحنة خزاني عند منصة تحميل البنزين. أثناء تدفق المنتج، أي مما يلي هو الإجراء الوحيد الذي يحميني فعلياً من انفجار ناتج عن شرارة كهرباء ساكنة؟","options":["ترك المحرك يعمل في وضع الخمول وتشغيل مدفأة الكابينة للبقاء دافئاً","ربط الخزان وتأريضه وإبقاء جميع مصادر الاشتعال بعيدة جداً","الابتعاد بضعة أقدام إلى الجانب والرد على مكالمة سريعة على هاتفي","فتح فتحة جانبية قليلاً حتى تتنفّس الأبخرة بحرية بينما أكمل الملء حتى الأعلى"],"explanation":"يبني تحميل السوائل القابلة للاشتعال شحنة كهربائية ساكنة، لذا اربط الخزان وأرّضه لمعادلتها وأبقِ جميع مصادر الاشتعال بعيدة جداً."},"94":{"q":"أنا أنقل شاحنة خزان محمّلة جزئياً وأقترب من منحدر خروج على الطريق السريع مُحدَّد بسرعة 35 ميلاً في الساعة. ينعطف المنحدر بحدة نحو اليمين. نظراً لكيفية تصرف الخزان المحمّل، ما السرعة التي ينبغي أن أحملها فعلياً عبر هذا المنعطف؟","options":["بالضبط 35 ميلاً في الساعة، لأن سرعة المنحدر المحددة موضوعة لجميع المركبات بما فيها الشاحنات","أعلى قليلاً من 35 ميلاً في الساعة، لأن الحفاظ على الزخم يساعدني على الخروج بسلاسة من المنعطف","عدة أميال في الساعة أقل من 35 ميلاً في الساعة، لأن مركز الثقل المرتفع يجعل الخزان ينقلب بسهولة","أي سرعة تمنع الاندفاع من دفع الشاحنة، حتى لو كانت أعلى من 35 ميلاً في الساعة"],"explanation":"الحمولة السائلة للخزان تستقر في الأعلى، مما يعطي مركز ثقل مرتفعاً ينقلب بسهولة، لذا خذ المنحدرات والمنعطفات بسرعة أقل بكثير من السرعة المحددة."},"95":{"q":"أنا أنقل شاحنة خزان سائل محمّلة جزئياً على طريق داخل المدينة. يصرّ زميل لي على أن اندفاع السائل يُقلق فقط عندما أُسرّع بقوة بعيداً عن إشارة خضراء، لذا لا ينبغي أن أفكر فيه فيما عدا ذلك. في أي من هذه الحالات ينبغي أن أتوقع فعلياً أن يدفع الاندفاع مركبتي ويهدد سيطرتي؟","options":["فقط بينما أكون متوقفاً عند الرصيف والمحرك مطفأ، قبل أن أتحرك على الإطلاق","فقط عندما يكون صوت الراديو مرتفعاً بما يكفي لإخفاء صوت السائل المتحرك في الخزان","فقط في الأيام الحارة عندما أكون قد تركت فراغاً إضافياً وتمدد السائل الدافئ ليملأ المساحة","في أي وقت أغيّر فيه المسار أو أبطئ أو أتوقف، لأن السائل يستمر في التحرك ويمكن أن يدفع الشاحنة للأمام أو جانبياً"],"explanation":"في الخزان الممتلئ جزئياً يستمر السائل في التحرك ويندفع كلما غيّرت المسار أو أبطأت أو توقفت، فيدفع الشاحنة للأمام أو جانبياً."},"96":{"q":"أنا أحمّل شاحنة خزان مقسَّمة بمقصورات منفصلة، وبعد ملء المقصورتين الأوليين في الخلف ألاحظ أن البقية ما زالت فارغة. قبل أن أغادر، كيف ينبغي أن أقرر أي المقصورات أملأ وإلى أي مدى أملؤها؟","options":["توزيع السائل عبر المقصورات حتى تبقى أوزان المحاور قانونية وتكون الحمولة متوازنة","وضع أثقل ملء في المقصورات الخلفية حتى تحصل محاور الدفع على أقصى تماسك","ملء المقصورات الأمامية بالكامل أولاً حتى يحمل محور التوجيه أكبر وزن","ملء أي مقصورات أسهل في الوصول إليها حتى تبدو الشاحنة محمّلة بالتساوي فحسب"],"explanation":"في الخزان المقسَّم بمقصورات، وزّع السائل عبر المقصورات لإبقاء أوزان المحاور قانونية والمركبة متوازنة."},"97":{"q":"الطريقة الأكثر أماناً للتعامل مع الاندفاع أثناء الفرملة عند إشارة هي:","options":["الفرملة بقوة في اللحظة الأخيرة","البدء بالفرملة مبكراً وبسلاسة","ضخ الفرامل بسرعة","الانسياب في وضع الحياد"],"explanation":"ابدأ الفرملة مبكراً وبسلاسة للتعامل مع الاندفاع."},"98":{"q":"أنا أنقل سائلاً في مركبة خزان وأقترب من منحدر خروج على الطريق السريع بسرعة محددة 35 ميلاً في الساعة. مقارنة بمقطورة صندوق نموذجية تحمل الوزن نفسه، تبدو شاحنتي أكثر احتمالاً بكثير للانقلاب على هذا المنحدر. أي عامل يفسّر أفضل تفسير سبب كون شاحنة الخزان لدي أكثر عرضة لخطر الانقلاب هنا؟","options":["الحمولة السائلة تخفض مركز ثقلي، لذا يمكنني أخذ المنحدر بأمان بالسرعة المحددة 35 ميلاً في الساعة","الشحنة السائلة تستقر في الأعلى وتعطي الخزان مركز ثقل مرتفعاً، لذا يجب أن آخذ المنحدر بسرعة أقل بكثير من السرعة المحددة","الاندفاع للأمام والخلف في خزان ذي حواجز يدفع المقطورة جانبياً وهو السبب الرئيسي لانقلاب الخزانات","الخزان الممتلئ تماماً لا يمكن أن يندفع على الإطلاق، لذا لا يوجد خطر انقلاب إلا عندما يكون الخزان فارغاً جزئياً"],"explanation":"تستقر الشحنة السائلة في أعلى الخزان، مما يعطي مركز ثقل مرتفعاً ينقلب بسهولة، لذا خذ المنحدر بسرعة أقل بكثير من السرعة المحددة."},"99":{"q":"أنت تنقل شاحنة خزان ذات جدار أملس محمّلة جزئياً بسائل نازلاً على طريق سريع في تكساس وترى إشارة حمراء أمامك عند تقاطع. مع معرفتك بكيفية تصرف اندفاع السائل في خزانك، أي من هذه العادات هي الأقل ذكاءً للاعتماد عليها أثناء اقترابك من التوقف؟","options":["زيادة مسافة المتابعة قبل وصولك إلى الإشارة بوقت كافٍ","رفع قدمك عن دواسة الوقود مبكراً والانسياب نحو الخط","الانتظار حتى الفرملة بقوة وفي وقت متأخر حتى تتوقف عند الخط تماماً","تطبيق الفرامل بلطف وسلاسة أثناء إبطائك"],"explanation":"افرمل بلطف ومبكراً لأن اندفاع السائل يطيل مسافة التوقف ويمكن أن يدفع الشاحنة للأمام حتى بعد توقفك."},"100":{"q":"أنا أنقل حمولة كاملة من السائل في شاحنة خزاني وأقترب من منحدر خروج على الطريق السريع مُعلَّم بسرعة محددة 35 ميلاً في الساعة. لأن شاحنتي تتصرف بشكل مختلف عن شاحنة الصندوق الجاف، ما الشيء الأهم الذي ينبغي أن أضعه في اعتباري أثناء أخذي هذا المنحدر؟","options":["وزن الخزان المنخفض والموزّع بالتساوي يبقيني مستقراً، لذا يمكنني بأمان مطابقة السرعة المحددة 35 ميلاً في الساعة عبر المنعطف","الحمولة السائلة تجعل الشاحنة تفرمل أسرع، لذا يمكنني الانتظار حتى المنعطف للإبطاء وأكون بخير","الخزان الممتلئ يُلغي الاندفاع، لذا السرعة المحددة للمنحدر هي الشيء الرئيسي الذي أحتاج إلى احترامه","السائل يستقر في الأعلى ويعطيني مركز ثقل مرتفعاً، لذا ينبغي أن أبطئ إلى سرعة أقل بكثير من السرعة المحددة 35 ميلاً في الساعة قبل المنعطف"],"explanation":"يستقر السائل في الأعلى ويخلق مركز ثقل مرتفعاً، لذا أبطئ إلى سرعة أقل بكثير من السرعة المحددة قبل الدخول إلى منعطف لمنع الانقلاب."},"101":{"q":"أنا أقود صهريجاً ذا جدار أملس (بدون حواجز) ممتلئاً جزئياً. بعد أن أتوقف توقفاً تاماً عند الإشارة الحمراء، أشعر بأن الشاحنة تُدفع إلى الأمام داخل التقاطع بينما يستمر السائل في الحركة داخل الخزان. ماذا تُسمى حركة السائل هذه ذهاباً وإياباً؟","options":["الاندفاع (Surge) — يتمايل السائل إلى الأمام والخلف ويمكن أن يدفع الشاحنة بعد توقفك","الانجراف (Drift) — يُجَرّ السائل جانبياً ويسحب الشاحنة خارج مسارها عند الانعطاف","الفراغ العلوي (Outage) — الحيز الفارغ المتروك في الخزان يسمح للحمولة بالتحرك وقلب المركبة","الدوران (Spin) — يدور السائل في الخزان ويرفع مركز ثقل المركبة"],"explanation":"تُسمى حركة السائل ذهاباً وإياباً في خزان ممتلئ جزئياً بالاندفاع (Surge)، والذي يمكن أن يدفع الشاحنة إلى الأمام بعد توقفك."},"102":{"q":"أنا أقود صهريجاً سائلاً محمّلاً جزئياً وأقترب من إشارة حمراء عند تقاطع مزدحم. في أي لحظة يجب أن أكون أكثر استعداداً لأن يدفع اندفاع السائل شاحنتي فجأة إلى الأمام، وربما إلى داخل حركة المرور المتقاطعة؟","options":["أثناء حفاظي بثبات على سرعة ثابتة عبر الإشارة الخضراء قبل التقاطع","بعد توقفي توقفاً تاماً عند الخط مباشرةً، بينما لا تزال قدمي على الفرامل","أثناء تسارعي بعيداً عن الخط بعد أن تتحول الإشارة إلى الأخضر أخيراً","أثناء رفعي لقدمي عن دواسة الوقود والانزلاق نحو الخط قبل أن ألمس الفرامل"],"explanation":"يستمر اندفاع السائل في الحركة إلى الأمام ويصطدم بمقدمة الخزان بعد توقف الشاحنة مباشرةً، مما قد يدفعها عبر الخط إلى داخل التقاطع."},"103":{"q":"أنا أقود خزاناً ذا حواجز محمّلاً جزئياً وألاحظ السائل يدفع ويسحب أثناء تسارعي وكبحي. وفقاً لتصميم الخزان ذي الحواجز، أي نوع من الاندفاع صُممت هذه الحواجز للحد منه؟","options":["الاندفاع من جانب إلى جانب، وهو الاندفاع الأكثر احتمالاً لقلب الخزان","كل أنواع الاندفاع بالتساوي، لأن الحواجز تعزل السائل في حجرات منفصلة","الاندفاع إلى الأمام والخلف، مع فعل القليل للتحكم في الحركة من جانب إلى جانب","الاندفاع الناتج عن حرارة المحرك التي تُدفئ حمولة السائل وتُمددها"],"explanation":"تقلل الحواجز من الاندفاع إلى الأمام والخلف الذي يُشعَر به أثناء التسارع والكبح، لكنها تفعل القليل للتحكم في الحركة من جانب إلى جانب."},"104":{"q":"أنا أقود صهريجاً ذا حواجز محمّلاً جزئياً عبر منحدر خروج ضيق على الطريق السريع. أوجّه بسلاسة وأبقى أقل بكثير من السرعة المحددة للمنحدر، لكنني ما زلت أشعر بالسائل يدفع مقطورتي بقوة نحو خارج المنحنى، مهدداً بقلبي. أي نوع من الاندفاع أشعر به والذي لم تُصمم الحواجز في خزاني للتحكم فيه؟","options":["الاندفاع إلى الأمام والخلف، لأن الحواجز تُبطئ السائل فقط ولا تستطيع منعه من التمايل في أي اتجاه","الاندفاع بعد التوقف التام، لأن الحواجز تعمل فقط بينما لا تزال المركبة تتحرك إلى الأمام","الاندفاع الأمامي الذي يدفع الشاحنة للأمام، لأن فتحات الحواجز تسمح للسائل بالمرور مباشرةً عبرها","الاندفاع من جانب إلى جانب، لأن الحواجز تقلل من الحركة من الأمام إلى الخلف لكنها لا تفعل شيئاً لمنع السائل من التمايل جانبياً"],"explanation":"تقلل الحواجز من الاندفاع من الأمام إلى الخلف لكنها لا تفعل شيئاً لمنع الاندفاع من جانب إلى جانب، الذي يتمايل بالحمولة المرتفعة نحو الخارج في المنحنى ويمكن أن يسبب الانقلاب."},"105":{"q":"أنا أنقل الحليب في خزان من الفولاذ المقاوم للصدأ ليس به حواجز داخلية (جدار أملس) بسبب قواعد سلامة الأغذية. الخزان ممتلئ إلى النصف تقريباً فقط. عندما أقترب من علامة التوقف، ماذا ينبغي أن أتوقع من السائل في هذا الخزان تحديداً؟","options":["اندفاع قوي، لأنه بدون حواجز لا يوجد ما يُبطئ السائل المتحرك إلى الأمام والخلف","لا اندفاع، لأن الجدار الداخلي الأملس يسمح للسائل بالبقاء ساكناً بدلاً من التمايل","اندفاع من جانب إلى جانب فقط، لأن الحواجز هي الجزء الذي يخلق الحركة إلى الأمام والخلف","اندفاع أمامي مُخفّض، لأن الخزانات ذات الجدار الأملس مُصممة للأغذية وأكثر أماناً عند التوقف"],"explanation":"الخزان ذو الجدار الأملس ليس به حواجز لإبطاء السائل، لذا فإن الحمولة الجزئية تندفع بقوة إلى الأمام والخلف."},"106":{"q":"أنا ألتقط مقطورة خزان لمسار جديد وألاحظ أنها خزان ذو جدار أملس (بدون حواجز) ليس به حواجز داخلية. بناءً على كيفية تصميم هذه الخزانات، أي نوع من الحمولة من المرجح أن تنقله هذه المقطورة؟","options":["الحصى المسحوق، لأن الداخل المفتوح يسمح للحمولة بالاستقرار بالتساوي عبر الخزان","المنتجات الغذائية السائلة، لأن الأسطح الداخلية الملساء أسهل في الحفاظ على نظافتها بين الحمولات","الرمل الجاف، لأن غياب الحواجز يجعل الخزان أسرع في الملء والتفريغ","عوارض فولاذية مربوطة، لأن الجدران الملساء تمنع الحمولة من التحرك"],"explanation":"الخزانات ذات الجدار الأملس ليس بها حواجز، مما يجعل الداخل أسهل في التنظيف والتعقيم، لذا تُستخدم للمنتجات الغذائية السائلة."},"107":{"q":"أنا أحمّل صهريجاً بسائل بارد في صباح شتوي ويخبرني الشاحن بألا أملأه بالكامل حتى القمة، تاركاً بعض الحيز الفارغ المسمى \"الفراغ العلوي\" (Outage). بينما أفكر في سبب أهمية هذا الحيز لحمولتي، ما السبب الرئيسي الذي يلزمني بتركه؟","options":["كي يستطيع أي هواء محتجز الهروب ويسمح للسائل بالتصريف أسرع عند تفريغي في المحطة","كي يكون للسائل مجال للتمايل والاندفاع بأمان دون دفع شاحنتي إلى الأمام","كي يكون للسائل مجال للتمدد عند تدفئته أثناء النقل","كي تتجمد طبقة من السائل على طول الجدران دون أن تشقق غلاف الخزان"],"explanation":"الفراغ العلوي هو الحيز الفارغ الذي تتركه في خزان السائل لأن السوائل تتمدد عند تدفئتها أثناء النقل."},"108":{"q":"أنا في محطة أحمّل صهريجاً بمنتج سائل بارد، ويوقفني مشغّل التحميل قبل امتلاء الخزان بكثير، تاركاً فجوة فارغة في الأعلى. أعترض بأنني أهدر السعة وأريد ملأه حتى الحافة. لماذا يكون ترك ذلك الحيز الفارغ (الفراغ العلوي) في الواقع هو الممارسة الصحيحة؟","options":["لأن الخزان الممتلئ جزئياً يندفع أقل من الممتلئ بالكامل، والاندفاع هو ما يسبب الانقلابات","لأن الخزان الممتلئ سيتجاوز تصنيف مركز الثقل المرتفع للمركبة وينقلب على المنحدرات","لأن المنتج الأبرد أكثر كثافة وسيفقد حجماً عند استقراره أثناء النقل","لأن السائل سيتمدد عند تدفئته أثناء النقل، وبدون تلك الفجوة لن يكون له مكان يذهب إليه"],"explanation":"يجب أن تترك فراغاً علوياً في خزان السائل لأن السائل يتمدد عند تدفئته أثناء النقل ويحتاج إلى مجال."},"109":{"q":"أنا مُكلَّف بنقل حمولة من سائل كثيف وثقيل في مقطورة خزاني. ولأن هذا السائل يزن أكثر لكل غالون مما أحمله عادةً، ماذا تُجبرني كثافته العالية على فعله على الأرجح؟","options":["تحميل منتج أقل من الحجم الكامل للخزان للبقاء ضمن حدود الوزن القانونية","ملء الخزان أعلى من المعتاد لأن السوائل الكثيفة تترك مساحة فراغ علوي أكثر","إضافة الماء إلى الحمولة كي تنخفض الكثافة قبل أن أقود","القيادة أسرع على المنحدرات لأن الحمولة الأثقل تُبقي الخزان أكثر استقراراً"],"explanation":"يمكن أن يصل السائل الكثيف الثقيل إلى حد الوزن القانوني قبل أن يمتلئ الخزان فعلياً، لذا تُحمّل أقل من الحجم الكامل."},"110":{"q":"أنا أقود صهريجاً ذا جدار أملس محمّلاً جزئياً نحو إشارة حمراء عند أسفل منحدر طفيف. أعلم أن السائل سيندفع بينما أُبطئ. للحفاظ على الشاحنة تحت السيطرة والتوقف حيث أنوي، كيف ينبغي أن أطبّق فراملي؟","options":["أنتظر حتى أكون قريباً من الإشارة، ثم أكبح بقوة كي يكون أمام الاندفاع مسافة أقل ليدفعني إلى الأمام","أبدأ الكبح مبكراً وأطبّق الضغط بسلاسة، تاركاً مسافة اتباع إضافية كي لا يدفعني الاندفاع عبر خط التوقف","أضغط على الفرامل تشغيلاً وإيقافاً بسرعة طوال الطريق إلى الإشارة لامتصاص الحركة ذهاباً وإياباً","أنزلق في الترس دون كبح وأعتمد على كبح المحرك وحده كي يبقى السائل مستقراً"],"explanation":"اكبح بلطف ومبكراً وحافظ على مسافة اتباع إضافية كي لا يدفعك اندفاع السائل الأمامي عبر خط التوقف."},"111":{"q":"أنا أقود صهريجاً محمّلاً جزئياً وأرى منحنىً حاداً بسرعة استرشادية محددة قادماً. ولأن مركبتي ذات مركز ثقل مرتفع وتنقلب بسهولة، متى تكون النقطة الصحيحة للقيام بإبطائي كي لا أفقد السيطرة؟","options":["أنتظر حتى أكون داخل المنحنى بالفعل، ثم أرفع قدمي عن دواسة الوقود وأدع الشاحنة تنزلق حوله","أكبح بقوة في منتصف المنحنى فقط إذا شعرت بأن المقطورة تبدأ في الميل","أُخفّض سرعتي قبل دخولي المنحنى كي آخذه أقل بكثير من السرعة المحددة","أُبقي سرعتي مرتفعة عند دخول المنحنى وأكبح بحزم فقط عند خروجي منه"],"explanation":"يتمتع الخزان بمركز ثقل مرتفع ينقلب بسهولة، لذا أبطئ قبل المنحنى وخذه أقل بكثير من السرعة المحددة."},"112":{"q":"لقد سلّمت للتو معظم حمولة حليب من صهريجي ذي الجدار الأملس، ولم يتبقَّ سوى بضع مئات من الغالونات تتمايل في الخزان بينما أعود على طريق سريع ذي مسارين به علامات توقف ومنحنيات ضيقة. وبما أن الخزان فارغ في معظمه، كيف ينبغي أن أتعامل مع رحلة العودة؟","options":["أتعامل معها كرحلة شاحنة فارغة عادية، فما تبقى من سائل قليل جداً لا يمكن أن يؤثر على التحكم.","أكبح بقوة ومتأخراً عند علامات التوقف لإبقاء السائل المتبقي مضغوطاً بثبات على الحاجز الأمامي.","أُسرع في المقاطع المستقيمة لتعويض الوقت الضائع، لأن الخزان شبه الفارغ أقل احتمالاً للانقلاب بكثير.","أقود بلطف وسلاسة، كابحاً مبكراً وموجّهاً دون حركات مفاجئة، لأن الحمولة الجزئية لا تزال تندفع."],"explanation":"حتى الخزان الفارغ أو الممتلئ جزئياً يحتوي على سائل يندفع، لذا قُد بسلاسة مع كبح مبكر لطيف ودون توجيه مفاجئ."},"113":{"q":"أنا أُنهي فحص ما قبل الرحلة على صهريج سائل محمّل قبل الخروج من المحطة. لتقليل احتمال حدوث انسكاب ومخالفة تسرب بمجرد تحركي، أي عنصر هو الأهم لي لفحصه فعلياً على الخزان نفسه؟","options":["أن أغطية فتحات الدخول وصمامات البخار/التنفيس مغلقة ومُحكمة وأن صمامات التصريف في الوضع الصحيح","أن الخزان ممتلئ بالكامل حتى القمة كي لا يُترك حيز فراغ علوي ليندفع السائل","أن ضغط الإطارات مُحدّد عالياً بما يكفي للتعويض عن مركز الثقل المرتفع للخزان","أن جهاز اللاسلكي والمرايا مضبوطة كي أتمكن من رد الفعل بسرعة إذا دفعتني حركة الحمولة إلى الأمام"],"explanation":"قبل قيادة صهريج، تأكد من أن أغطية فتحات الدخول وصمامات البخار/التنفيس مغلقة ومُحكمة وأن صمامات التصريف في وضعها الصحيح."},"114":{"q":"أثناء فحص ما قبل الرحلة لصهريج محمّل، أجد سائلاً يتسرب من صمام في أسفل الخزان. الحمولة ليست خطرة، ونافذة التسليم لدي ضيقة، والتسرب يبدو بطيئاً. ما الإجراء الصحيح قبل أن أبدأ الرحلة؟","options":["أُحكم الصمام يدوياً وأراقبه في أول محطة مجدولة لي، لأن التسرب بطيء والحمولة غير خطرة","أُبقي المركبة خارج الخدمة وأُصلح الصمام المتسرب قبل القيادة، بغض النظر عن مدى بطء التسرب","ألفّ وصلة الصمام بإحكام كي يُحتوى الرشح، ثم أتابع وأُبلغ عنه عند التسليم","أُخفّض الحمولة لتقليل الضغط على الصمام، ثم أقود بحذر إلى الوجهة"],"explanation":"يجب إصلاح أي تسرب يُكتشف أثناء الفحص قبل القيادة، لذا فإن الصمام المتسرب يضع المركبة خارج الخدمة بغض النظر عن معدل التسرب."},"115":{"q":"لقد تم توظيفي للتو لنقل 3000 غالون من السماد السائل المُصنّف كمادة خطرة في خزان حمولة. أحمل بالفعل رخصة قيادة تجارية صالحة من الفئة A. قبل أن أتمكن قانونياً من التقاط هذه الحمولة، أي اعتماد (اعتمادات) في رخصة القيادة التجارية يجب أن أحمله؟","options":["اعتماد H (المواد الخطرة) فقط، لأن الخطر يأتي من المادة الخطرة نفسها وليس من الخزان","اعتماد N (مركبة الخزان) فقط، لأن الحمولة تُنقل داخل خزان حمولة","كلا اعتماد N (مركبة الخزان) واعتماد H (المواد الخطرة)، لأن الحمولة سائل خطر في خزان","لا يلزم أي اعتماد إضافي ما دمت أُبقي الحمولة أقل من حد وزن لافتات التحذير"],"explanation":"نقل سائل خطر في خزان حمولة يُطلق شرطين منظَّمين معاً، لذا فإن اعتماد الخزان (N) واعتماد المواد الخطرة (H) كلاهما مطلوب."},"116":{"q":"لقد حصلت للتو على رخصة قيادة تجارية من الفئة A ويعرض عليّ مُوزّع أربع حمولات مختلفة للغد. لا أحمل بعد اعتماد مركبة الخزان (N)، لذا يمكنني قانونياً قبول حمولة لا تتطلبه فقط. أي من الحمولات التالية يمكنني نقلها قانونياً دون إضافة اعتماد N أولاً؟","options":["خزان مُثبّت بشكل دائم سعة 1500 غالون من السماد السائل مربوط بإطار الشاحنة بالبراغي","شاحنة مسطحة تحمل حاوية وسيطة واحدة (IBC) سعة 1200 غالون من السائل مربوطة كحمولة","مقطورة تنقل خزان حمولة كبير من الغاز المضغوط إلى مستودع وقود","شاحنة جافة قياسية محمّلة بصناديق مغلقة من الماء المعبأ على منصات نقّالة"],"explanation":"ينطبق اعتماد الخزان (N) فقط على السوائل أو الغازات السائبة المنقولة في خزان، وليس على المنتجات السائلة المعبأة المحمولة كحمولة معبأة في صناديق."},"117":{"q":"أنا أقود صهريجاً ذا جدار أملس محمّلاً جزئياً وأقترب من إشارة حمراء، كابحاً حتى أشعر بأن الشاحنة توقفت توقفاً تاماً. مقارنةً بقيادة نفس المقطورة الصندوقية المحمّلة، ماذا ينبغي أن أتوقع أن يفعله اندفاع السائل بقدرتي على التوقف عند هذه الإشارة؟","options":["سيُطيل الاندفاع مسافة توقفي ويمكن أن يدفع الشاحنة إلى الأمام حتى بعد أن أظن أنني توقفت","سيُقصّر الاندفاع مسافة توقفي لأن السائل المتحرك يضيف قوة جذب للكبح عند العجلات","ليس للاندفاع تأثير على مسافة التوقف ما دمت أكبح بحزم وأُبقي المركبة مستقيمة","سيقلّص الاندفاع مسافة توقفي إلى النصف تقريباً بمجرد أن تستقر الحواجز السائل"],"explanation":"يُطيل اندفاع السائل في خزان ممتلئ جزئياً مسافة التوقف ويمكن أن يدفع الشاحنة إلى الأمام حتى بعد أن تظن أنك توقفت."},"118":{"q":"أنت تقود صهريجاً محمّلاً جزئياً على الطريق السريع بين الولايات عندما يبدأ مطر ثابت وتصبح طبقة الإسفلت زلقة. لا تزال حركة المرور حولك تتحرك بالسرعة المحددة وهي 65 ميلاً في الساعة. بالنظر إلى مركز ثقلك المرتفع واندفاع السائل، ما أفضل طريقة للتعامل مع الظروف الرطبة؟","options":["الحفاظ على السرعة المحددة 65 ميلاً في الساعة للبقاء مع تدفق حركة المرور المحيطة","تخفيض سرعتك إلى أقل بكثير من الحد المحدد وزيادة مسافة اتباعك","الحفاظ على سرعتك العادية على الطريق الجاف لكن مع تطبيق الفرامل بقوة أكبر وأبكر من المعتاد","الانزلاق خلف مركبة قائدة عن قرب كي تُزيل إطاراتها الماء من مسارك"],"explanation":"الخزان المحمّل جزئياً ينقلب بسهولة ويندفع، لذا على الطريق الرطب أبطئ إلى أقل بكثير من السرعة المحددة وزِد مسافة اتباعك."},"119":{"q":"أنا أقود صهريجاً ذا جدار أملس (بدون حواجز) محمّلاً جزئياً وأقترب من إشارة صفراء عند تقاطع سأحتاج فيه إلى التوقف، ثم التسارع بعيداً بمجرد أن تتحول إلى الأخضر. بالنظر إلى كيفية تصرف السائل في هذا الخزان، كيف ينبغي أن أتعامل مع كبحي وتوجيهي وتسارعي خلال هذا التسلسل بأكمله؟","options":["أكبح بقوة ومبكراً للتوقف قبل الاندفاع، ثم أتسارع بنشاط كي لا يستطيع التمايل الأمامي دفعي إلى التقاطع","أوجّه بحدة إذا تحركت الحمولة كي أُصحّح الشاحنة بسرعة قبل أن يتراكم الاندفاع من جانب إلى جانب","أجعل كل إدخال تدريجياً، كابحاً بلطف ومبكراً، وموجّهاً ومتسارعاً بسلاسة، لأن الإجراءات المفاجئة تُضخّم اندفاع السائل ويمكن أن تدفع الشاحنة أو تسبب الانقلاب","أستخدم إدخالات سريعة وحاسمة على الفرامل وعجلة القيادة للبقاء متقدماً على الاندفاع والحفاظ على سيطرة محكمة على الخزان"],"explanation":"اجعل كل إدخال تدريجياً — تسارع واكبح ووجّه بسلاسة ومبكراً — لأن الإجراءات المفاجئة تُضخّم اندفاع السائل ويمكن أن تدفع الشاحنة أو تسبب الانقلاب."},"120":{"q":"أنا أنقل خزاناً سائلاً محمّلاً جزئياً على الطريق السريع خلف شاحنة أخرى. مقارنةً بقيادة شاحنة صندوقية جافة نموذجية، أي تعديل هو الأهم لي للقيام به لقيادة هذا الصهريج بأمان؟","options":["تخفيض مسافة اتباعي كي يكون أمام الاندفاع مجال أقل لبناء الزخم بين التوقفات","تخفيض ضغط إطاراتي لتحسين الجذب وتعويض مركز الثقل المرتفع","التسارع قليلاً عبر المنحنيات كي أتجاوزها قبل أن يتمايل السائل","زيادة مسافة اتباعي لأن الاندفاع يُطيل مسافة توقفي ويمكن أن يدفعني إلى الأمام"],"explanation":"زِد مسافة اتباعك لأن اندفاع السائل يُطيل مسافة التوقف ويمكن أن يدفع الشاحنة إلى الأمام بعد توقفك."},"121":{"q":"أنا أنقل خزاناً سائلاً ممتلئاً جزئياً على طريق سريع ذي مسارين. بينما أمرّ فوق سلسلة من المنخفضات والإسفلت غير المستوي، أشعر بالحمولة تتمايل وترتد داخل الخزان. وفقاً لإرشادات إدارة السلامة العامة (DPS)، هذا السائل المتحرك من المرجح أن يؤثر على أي مما يلي أثناء قيادتي؟","options":["قدرتي على توجيه المركبة وكبحها بسلاسة وبشكل يمكن التنبؤ به","دقة مقاييس الضغط ودرجة الحرارة في الخزان","استهلاك الوقود وأداء محرك الجرّار","موثوقية جهاز اللاسلكي وجهاز التسجيل الإلكتروني لدي"],"explanation":"الحمولة السائلة المتحركة تُحرّك وزن المركبة ذهاباً وإياباً ومن جانب إلى جانب، مما يؤثر أكثر على قدرتك على التوجيه والكبح بسلاسة."},"122":{"q":"أنا أنقل خزاناً سائلاً محمّلاً جزئياً وأتوقف توقفاً تاماً عند إشارة حمراء، خلف خط التوقف مباشرةً عند تقاطع مزدحم. بينما أجلس هناك منتظراً، لماذا ينبغي أن أكون أكثر استعداداً أن يفعله اندفاع السائل؟","options":["يستقر ويسحب الشاحنة بلطف إلى الخلف بعيداً عن الخط","يدفع الشاحنة إلى الأمام، وربما يدفعني إلى داخل التقاطع","يضغط دواسة الفرامل لأسفل بقوة أكبر ويُقصّر مسافة توقفي","يُخفّض مركز ثقلي كي يصبح الخزان أكثر استقراراً"],"explanation":"عند الكبح للتوقف، يمكن لاندفاع السائل الأمامي المرتد أن يدفع الشاحنة إلى الأمام ويدفعك عبر خط التوقف إلى داخل التقاطع."},"123":{"q":"أنا أنقل صهريجاً محمّلاً جزئياً ومنحدر الخروج من الطريق السريع أمامي محدد بسرعة 35 ميلاً في الساعة. ولأن خزاني المحمّل يسير بمركز ثقل مرتفع، كيف ينبغي أن آخذ هذا المنحدر المنحني؟","options":["الحفاظ على سرعة ثابتة 35 ميلاً في الساعة عبر المنحدر، لأن السرعة المحددة تأخذ الشاحنات في الحسبان بالفعل","الانزلاق عبره في الوضع المحايد كي لا يدفعني المحرك إلى المنحنى","الإبطاء إلى أقل بكثير من السرعة المحددة 35 ميلاً في الساعة قبل دخول المنحدر","البقاء قريباً من المركبة التي أمامي ومطابقة سرعتها عبر المنحنى"],"explanation":"الخزان المحمّل له مركز ثقل مرتفع وينقلب بسهولة، لذا أبطئ إلى أقل بكثير من السرعة المحددة للمنحدر قبل دخول المنحنى."},"124":{"q":"أنا أنقل صهريجاً سائلاً محمّلاً جزئياً وأقترب من منحدر خروج من الطريق السريع محدد بسرعة 35 ميلاً في الساعة. من بين كل المخاطر التي أواجهها في هذه المناورة، أي واحد يمثل أكبر خطر منفرد يجب أن أحترس منه؟","options":["انفجار إطار أمامي بينما أغادر الطريق السريع","اندفاع السائل الذي يدفعني إلى الأمام عبر علامة التوقف في المنحدر","فقدان التواصل اللاسلكي مع مُوزّعي في منتصف المنحدر","انقلاب المركبة بسبب مركز ثقلها المرتفع"],"explanation":"مركز الثقل المرتفع للصهريج السائل يجعل الانقلاب أكبر خطر له، ومعظم الانقلابات تحدث على المنحنيات والمنحدرات المأخوذة بسرعة كبيرة."},"125":{"q":"لقد أوقفت صهريجي عند رصيف التحميل وأنا على وشك البدء في ملئه بالحمولة. قبل أن يبدأ المنتج بالتدفق إلى الخزان، أي مما يلي يجب أن أفعله أولاً كجزء من إجراء التحميل الآمن؟","options":["التأكد من أن جميع صمامات الخزان مغلقة قبل أن يبدأ أي منتج بالتدفق","فتح جميع صمامات الخزان كي يستطيع الهواء الهروب بينما يرتفع السائل","تشغيل المحرك بقوة لإبقاء نظام الهواء والمضخة مهيأين أثناء التحميل","فصل وإزالة خرطوم التحميل كي لا ينثني تحت الضغط"],"explanation":"قبل التحميل، تأكد من أن جميع صمامات الخزان مغلقة كي لا يستطيع المنتج الانسكاب أو الهروب عندما يبدأ بالتدفق."},"126":{"q":"لقد انتهيت للتو من تفريغ جزء من حمولة سائلة في محطة عميل وأستعد للمغادرة. قبل أن أبتعد عن رصيف التحميل، أي من الإجراءات التالية هو الصحيح بخصوص صمامات الخزان؟","options":["أترك صمامات التفريغ مفتوحة قليلاً حتى يتسنى لأي سائل متبقٍ أن يتسرب أثناء قيادتي إلى المحطة التالية","أغلق وأثبت جميع الصمامات بحيث لا يتسرب أو يتنفس شيء على الطريق، ثم أتأكد من أنها في الوضع الصحيح","أترك صمام التنفيس العلوي فقط مفتوحاً لتخفيف الضغط مع تسخّن الخزان الفارغ أثناء الرحلة","أتجاوز فحص الصمامات هذه المرة لأن الخزان فارغ ولم يتبقَّ بداخله شيء يمكن أن ينسكب"],"explanation":"بعد التفريغ، أغلق وأثبت كل صمام وتأكد من أنه في الوضع الصحيح، لأن الخزان الفارغ لا يزال يحتوي على بقايا منتج وأبخرة يمكن أن تتسرب."},"127":{"q":"أقوم بتحميل صهريجي بمادة كيميائية كثيفة وثقيلة في المحطة. ألاحظ أن الخزان يبلغ وزنه القانوني قبل أن يبدو ممتلئاً بأي شكل. إلى جانب وزن السائل، ما الذي يحدد كمية المنتج المسموح لي بتحميلها فعلياً؟","options":["مقدار مساحة الفراغ المتبقية لتمدد السائل عندما يسخن","ما إذا كان الخزان مزوداً بحواجز أم بتصميم أملس الجدار","حدود الوزن القانونية المطبَّقة على المركبة والمحاور","ارتفاع مركز ثقل الحمولة في الخزان"],"explanation":"كمية السائل التي يمكنك تحميلها محدودة بوزن السائل وبحدود الوزن القانونية للمركبة ومحاورها."},"128":{"q":"أقوم بتحميل سائل في خزان مقسّم يحتوي على ثلاثة مقصورات منفصلة. لقد ملأت المقصورة الخلفية بالكامل لكنني تركت الأمامية والوسطى فارغتين لأكمل التحميل في المحطة التالية. وعندما انعطفت إلى منحدر الطريق السريع، شعرت بأن الشاحنة غير مستقرة وأن المؤخرة تميل للانحراف بشكل واسع. أي قرار تحميل كان ينبغي أن أتخذه للحفاظ على قيادة المركبة بأمان؟","options":["ملء المقصورة الأمامية فقط بالكامل وترك الخلفية فارغة بحيث يحمل المحور الموجِّه وزناً أكبر","ضخ كل المنتج في مقصورة واحدة لخفض مركز الثقل الإجمالي","ترك كل مقصورة فارغة تماماً حتى المحطة النهائية ونقل الحمولة في رحلة واحدة","توزيع المنتج بحيث تكون المقصورات متوازنة، مع الحفاظ على الوزن متساوياً من الأمام إلى الخلف ومن جانب إلى جانب"],"explanation":"حمّل الخزان ذا المقصورات بحيث يكون الوزن متوازناً من الأمام إلى الخلف ومن جانب إلى جانب، لأن التحميل غير المتساوي يزيح مركز الثقل ويزيد من خطر الانقلاب."},"129":{"q":"أنقل حمولة سائلة جزئية وألاحظ أن الوزن قد انزاح بحيث يستقر معظمه في مؤخرة خزاني. أثناء القيادة، أي مشكلة في التحكم ينبغي أن أتوقعها أكثر من هذه الحالة المثقلة من الخلف؟","options":["يحمل المحور الأمامي وزناً أقل، مما يجعل التوجيه يبدو خفيفاً وأصعب في التحكم","يُضغط المحور الأمامي بقوة أكبر، مما يمنحني تماسكاً إضافياً وتوجيهاً أكثر إحكاماً","يقصّر الوزن الخلفي مسافة توقفي، مما يتيح لي الكبح متأخراً والتوقف أسرع","يقلل انزياح الحمولة المتساوي عبر المحاور من تآكل الإطارات ويحسّن التماسك"],"explanation":"الوزن الزائد في المؤخرة يرفع الحمل عن المحور الأمامي الموجِّه، فتفقد الإطارات تماسكها ويبدو التوجيه خفيفاً وصعب التحكم."},"130":{"q":"لقد سلّمت للتو حمولتي الكاملة من الحليب والآن أصبح صهريجي أملس الجدار فارغاً تماماً وأنا عائد إلى المحطة. عندما أقترب من علامة التوقف وأضغط على الفرامل بنفس الطريقة التي اتبعتها وأنا محمّل، ماذا ينبغي أن أتوقع من المركبة الفارغة؟","options":["ستتوقف أفضل بكثير مما كانت عليه عند التحميل، لأن الوزن الأخف يجعل الفرامل تتشبث أسرع","ستتوقف بشكل سيئ، لأن الخزان الفارغ يضع وزناً أقل على الإطارات ويقلل التماسك","ستتوقف على الفور تقريباً، إذ لم يتبقَّ اندفاع سائل يدفع الشاحنة إلى الأمام","لن تتمكن من التوقف على الإطلاق، لأن الخزانات الفارغة تفقد قدرتها على الكبح بالكامل"],"explanation":"الخزان الفارغ يضع وزناً أقل بكثير على الإطارات، مما يقلل التماسك، فتتوقف المركبة في الواقع بشكل سيئ بدلاً من أن تتوقف أسرع."},"131":{"q":"أنقل صهريجاً أملس الجدار محمّلاً جزئياً بالسائل على طريق سريع رباعي المسارات عندما تظهر أمامي مركبة بطيئة في مساري. للبقاء آمناً نظراً لطريقة تصرّف الحمولة، أي إجراء ينبغي أن أكون أكثر حرصاً على تجنّبه؟","options":["رفع قدمي تدريجياً عن دواسة الوقود قبل أن أصل إلى المركبة البطيئة","ترك مسافة اتباع إضافية بيني وبين المركبة التي أمامي","إدارة المقود بسرعة لتغيير المسار فجأة من أجل الالتفاف حول المركبة","الضغط على الفرامل مبكراً وبشكل سلس وثابت"],"explanation":"تجنّب تغييرات المسار السريعة والمفاجئة، لأن اندفاع السائل من جانب إلى جانب في خزان ممتلئ جزئياً يمكن أن يدفع مركز ثقله العالي بما يكفي لقلب المركبة."},"132":{"q":"أثناء فحصي قبل الرحلة لصهريج سائل محمّل، أريد التأكد من أن الحمولة لا تتسرب من أي مكان قبل أن أنطلق. وأنا أدور حول الخزان، أي منطقة ينبغي أن أركّز عليها لاكتشاف تسرب؟","options":["الطلاء الخارجي والملصقات العاكسة ولوحات وزارة النقل، لأن العلامات الباهتة أو المتقشرة كثيراً ما تشير إلى المكان الذي تآكل فيه جسم الخزان","أذرع مرآة المقصورة وبراغي تثبيت المقعد، لأن اهتزاز الحمولة المتمايلة يفكّ هذه أولاً ويسمح للمنتج بالنضح","راديو لوحة القيادة وأسلاك البوق، لأن حدوث ماس كهربائي هناك هو أكثر علامات الإنذار المبكر شيوعاً على اختراق الخزان","الصمامات وأغطية فتحات الصيانة والتنفيسات واللحامات الملحومة لجسم الخزان، حيث يشق السائل المضغوط أو المتحرك طريقه للخارج غالباً"],"explanation":"افحص بحثاً عن التسربات حول الصمامات وأغطية فتحات الصيانة والتنفيسات واللحامات الملحومة لجسم الخزان، حيث يتسرب السائل المتحرك أو المضغوط غالباً."},"133":{"q":"أقوم بفحص قبل الرحلة لصهريجي قبل نقل حمولة سائلة. عندما أتسلّق لفحص أعلى الخزان، في أي حالة ينبغي أن تكون تنفيسات الأبخرة كي يُعتبر الخزان آمناً للتشغيل؟","options":["تعمل بحرية ودون عوائق، بحيث يمكن للضغط أن يتنفّس ويتعادل مع انزياح الحمولة","مُغلقة بإحكام تام بحيث لا يستطيع أي بخار أو سائل التسرب أثناء النقل","مُزالة بشكل دائم لأن غطاء فتحة الصيانة يتولى بالفعل كل تخفيف الضغط","مغطاة بشريط لاصق لمنع غبار الطريق والحطام من دخول داخل الخزان"],"explanation":"يجب أن تعمل تنفيسات الأبخرة بحرية وأن تبقى دون عوائق حتى يمكن للضغط الداخلي أن يتنفّس ويتعادل مع تسخّن الحمولة وانزياحها، مما يمنع ضغطاً أو تفريغاً خطيراً."},"134":{"q":"أقوم بالفحص قبل الرحلة لمقطورة الخزان قبل نقل حمولة سائلة، وأريد التركيز على المعدات الخاصة بمركبات الخزانات والأكثر عرضة للتسرب. بصرف النظر عن العناصر القياسية التي يفحصها كل سائق رخصة قيادة تجارية، أي عنصر هو الذي أحتاج تحديداً إلى فحصه لأنه جزء من المعدات الخاصة بالخزان؟","options":["حامل هوائي راديو الاتصال على المقصورة، للحفاظ على عمل الاتصال مع غرفة التحكم خلال الرحلات الطويلة","الخراطيم والوصلات، مع فحصها بحثاً عن تسربات حيث يُنقل السائل من وإلى الخزان","مثبّت حزام أمان السائق، لأنه القيد الوحيد الذي يثبّتني أثناء توقف اندفاع مفاجئ","حامل الأكواب وتجهيزات المقصورة الداخلية، حتى لا تنزاح الأشياء المفكوكة أثناء اندفاع السائل للأمام"],"explanation":"افحص الخراطيم والوصلات بحثاً عن تسربات عند النقاط التي يُحمَّل ويُفرَّغ فيها السائل من الخزان وإليه، لأنها نقاط تسرب رئيسية."},"135":{"q":"كُلّفت بنقل غاز البترول المسال في خزان شحن مضغوط. يحذّرني الشاحن من أن الحمولة ستسخن وسيرتفع الضغط الداخلي أثناء الرحلة. أثناء فحصي قبل الرحلة، أي خاصية تصميمية ينبغي أن أتأكد من وجودها وعملها في هذا النوع من الخزانات للتعامل مع ارتفاع الضغط بأمان؟","options":["قبة مفتوحة على مصراعيها في الأعلى تتيح للبخار الهروب إلى الهواء بحرية","غطاء فتحة صيانة مرتخٍ ينفتح من تلقاء نفسه عندما يسخن","صمام تخفيف ضغط يُنفّس الضغط الزائد قبل أن يصبح غير آمن","ختم ورقي رقيق ينفصل ويتمزق بمجرد ارتفاع الضغط الداخلي"],"explanation":"خزانات الشحن المضغوطة مثل ناقلات غاز البترول المسال تحتوي على صمام تخفيف ينفتح لتنفيس الضغط الزائد مع تسخّن السائل وتمدده، ثم يُحكم الإغلاق مرة أخرى لإبقاء الخزان ضمن الحدود الآمنة."},"136":{"q":"أنا في استراحة على جانب الطريق بجوار صهريجي المتوقف وأريد إشعال سيجارة. بموجب قواعد إدارة السلامة العامة، بالقرب من أي من هذه الحمولات يكون التدخين أكثر خطورة وممنوعاً؟","options":["خزان حليب بارد يُنقل في مقطورة طعام أملس الجدار","خزان ماء عادي مملوء بالكامل لمهمة غسيل","خزان رمل جاف نظيف محمّل لموقع بناء","خزان سائل قابل للاشتعال لا يزال يحمل لوحات وقود"],"explanation":"لا تدخّن أبداً بالقرب من حمولة سائل قابل للاشتعال، لأن أبخرتها يمكن أن تشتعل من أي شرارة أو لهب مكشوف."},"137":{"q":"أنقل خزاناً ممتلئاً بالسائل والطريق أمامي ينحدر إلى منحدر طويل وحاد. للحفاظ على سرعتي وكبحي تحت السيطرة طوال النزول، أي ترس ينبغي أن أختاره قبل أن أبدأ النزول؟","options":["ترس منخفض، بحيث يساعد كبح المحرك على الحفاظ على سرعتي ولا أعتمد على فرامل الخدمة وحدها طوال النزول","ترس مرتفع، بحيث يدور المحرك بدورات أقل وتنزل الحمولة الثقيلة بسلاسة","لا ترس محدد، لأن الوزن المحمّل سيبطئ الشاحنة طبيعياً ويمكن للفرامل أن تتولى الباقي","ترس الرجوع للخلف مهيّأ في القمة، جاهز للتعشيق إذا بدأت الحمولة بالاندفاع للأمام أثناء النزول"],"explanation":"اختر ترساً منخفضاً قبل المنحدر بحيث يساعد كبح المحرك على التحكم في سرعتك ولا تضغط على فرامل الخدمة طوال النزول، مما يسبب تلاشي الفرامل أو تعطلها."},"138":{"q":"تهبّ رياح جانبية قوية وأنا أقود على مقطع من طريق سريع مكشوف. بمقارنة المركبات من حولي، أي مركبة ينبغي أن أتوقع أن تدفعها الهبّات أكثر من غيرها، مما يجبرني على تصحيح توجيهي؟","options":["مقطورة مسطحة فارغة منخفضة قرب الأرض بجواري","صهريجي الطويل الذي يحمل حمولة سائلة كاملة في الأعلى","سيارة سيدان صغيرة تسير في المسار المجاور","شاحنة صغيرة فارغة لا يوجد شيء في صندوقها"],"explanation":"الصهريج الطويل المحمّل هو الأكثر تأثراً بالرياح لأن الحمولة السائلة العالية تمنحه مركز ثقل مرتفعاً وسطحاً عمودياً كبيراً تدفع عليه الهبّات."},"139":{"q":"أنقل حمولة سائلة جزئية في مركبة خزان وأقترب من منحدر مخرج طريق سريع عليه لافتة استشارية بسرعة 35 ميلاً في الساعة. الطريق جاف والمرور خفيف. للتعامل مع هذا المنحدر بأمان، ما السرعة التي ينبغي أن أستخدمها؟","options":["يمكنني أخذه تماماً بالسرعة المعلنة 35 ميلاً في الساعة، لأن السرعات الاستشارية تتضمن بالفعل هامش أمان لجميع المركبات","السرعة لا تهم كثيراً هنا لأن الرصيف الجاف والمرور الخفيف يزيلان خطر الانقلاب","ينبغي أن أبطئ إلى ما دون السرعة المعلنة 35 ميلاً في الساعة بكثير، لأن السرعة الاستشارية موضوعة للسيارات ومركز ثقلي العالي يجعل الصهريج ينقلب بسهولة أكبر","يمكنني بأمان تجاوز 35 ميلاً في الساعة طالما أبقيت توجيهي سلساً وكبحت بلطف عبر المنحنى"],"explanation":"سرعات المنحنيات والمنحدرات المعلنة موضوعة للسيارات، لذا أبطئ إلى ما دونها بكثير في الصهريج لأن الحمولة السائلة العالية تمنحه مركز ثقل مرتفعاً ينقلب بسهولة."},"140":{"q":"أنقل صهريجاً أملس الجدار محمّلاً جزئياً بالسائل عبر تقاطع طريق سريع. وأنا أوجّه المركبة إلى المنحنى، أشعر بالحمولة تتمايل جانبياً وتضغط بقوة على الجدار الأيمن للخزان. إذا لم أعدّل طريقة تعاملي مع المركبة، ما النتيجة الأكثر احتمالاً لهذا الاندفاع من جانب إلى جانب؟","options":["سيدفع الاندفاع الأمامي الشاحنة لتتجاوز نقطة توقفي","ستمتص الحواجز الحركة وتبقي الحمولة مستقرة","ستتيح مساحة الفراغ للسائل أن يتمدد ويخفف الضغط","يمكن للسائل المنزاح أن يدفع المركبة لتنقلب"],"explanation":"في خزان ممتلئ جزئياً يندفع السائل من جانب إلى جانب، وبالاقتران مع مركز ثقل مرتفع في منحنى يمكن لهذا الاندفاع أن يدفع المركبة إلى الانقلاب."},"141":{"q":"تقود صهريجك حتى رصيف التفريغ في محطة. خرطوم المنتج جاهز ومشرفك يلوّح لك بالدخول. قبل أن تفعل أي شيء آخر بالحمولة، ما إجراؤك الأول؟","options":["أوقف المركبة توقفاً تاماً وشدّ فرملة الركن قبل توصيل أي شيء","افتح صمامات القبة وتنفيس الأبخرة كي يتعادل الضغط قبل أن تتوقف","وصّل خرطوم المنتج أولاً، ثم توقف وضع الإسفين لتوفير الوقت عند الرصيف","تقدّم بلطف بترس منخفض لمنع اندفاع السائل من دفع الشاحنة أثناء التوصيل"],"explanation":"قبل التفريغ، أوقف المركبة توقفاً تاماً وشدّ فرملة الركن حتى لا يتحرك الصهريج قبل أن توصّل أي خراطيم أو خطوط."},"142":{"q":"لقد أوقفت صهريجي عند نقطة التسليم ووصّلت خرطوم التفريغ بصمام تصريف الخزان. الخراطيم مثبتة والمنطقة خالية وأنا جاهز لبدء النقل. أي خطوة تالية صحيحة قبل أن يبدأ المنتج بالتدفق؟","options":["افتح الصمامات على مصراعيها بسرعة كي تتهيأ المضخة أسرع وتُفرَّغ الحمولة قبل أن تسخن وتتمدد","افتح الصمامات ببطء وعناية، مع مراقبة الوصلة كي تتمكن من رصد تسرب أو اندفاع قبل أن يتفاقم","اترك الصمامات على حالها، واصعد، وأعد توضيع الشاحنة بضعة أقدام كي يُشد الخرطوم بإحكام على التجهيزة","افتح فتحة الصيانة وصمامات التنفيس في الأعلى أولاً لكسر التفريغ، ثم عُد وافتح صمام التصريف بالكامل"],"explanation":"افتح الصمامات ببطء وعناية مع مراقبة الوصلة، كي تتمكن من رصد تسرب أو التحكم في اندفاع السائل قبل أن يتفاقم."},"143":{"q":"لقد انتهيت للتو من تفريغ المنتج السائل من صهريجي أملس الجدار في المحطة، وأشار مشغّل الاستلام إلى اكتمال النقل. قبل أن أحرّك المركبة عن رصيف التحميل، أي إجراء مطلوب كي لا أنطلق والمنتج لا يزال يتدفق أو الخرطوم لا يزال متصلاً؟","options":["اترك صمامات التصريف مفتوحة كي يتسرب أي منتج متبقٍ بينما أتقدم للأمام عن الرصيف","أضف كمية صغيرة من السائل إلى الخزان للحفاظ على ترطيب الحواجز قبل أن أغادر المحطة","أغلق الصمامات وافصل الخراطيم قبل تحريك المركبة بعيداً عن رصيف التحميل","انطلق مسرعاً عن الرصيف كي يتمكن السائق التالي من استخدام رصيف التحميل دون تأخير"],"explanation":"عند الانتهاء من التفريغ، أغلق الصمامات وافصل الخراطيم قبل التحرك، لأن الانطلاق بصمامات مفتوحة أو خرطوم متصل يمكن أن يمزّق الخطوط ويسكب المنتج."},"144":{"q":"أقوم بتحميل سائل قابل للاشتعال في صهريجي في محطة جملة، ويسلّمني المشغّل كابلاً ثقيلاً بملقط ويطلب مني توصيله بين الشاحنة ورصيف التحميل قبل أن أفتح أي صمامات. أثناء تدفق السائل، ما الذي تفعله وصلة الربط والتأريض هذه فعلياً للحفاظ على سلامتي؟","options":["تعادل ضغط الإطارات كي يبقى الخزان مستوياً ولا يندفع السائل ضد جانب واحد أثناء التعبئة","تنفّس الضغط الداخلي للحمولة كي لا تحتاج فتحة الصيانة وصمامات التنفيس إلى أن تُفتح أثناء التحميل","تمنع البطارية من النفاد بينما تعمل المضخة والأضواء طوال عملية التحميل","تعادل الشحنة الكهربائية بين الشاحنة والرصيف كي لا يستطيع السائل المتدفق تجميع شحنة وإطلاق شرارة ساكنة"],"explanation":"الربط والتأريض يجمعان الشاحنة والرصيف على شحنة كهربائية مشتركة كي لا يستطيع السائل القابل للاشتعال المتدفق تجميع كهرباء ساكنة تقفز على شكل شرارة تشعل الأبخرة."},"145":{"q":"أثناء فحص قبل الرحلة لمقطورة خزان غير مألوفة، أريد التأكد من أن الخزان لا يزال معتمداً قانونياً لنقل السائل وأنه ليس متأخراً عن إعادة الاعتماد. أحدد موقع لوحة البيانات المعدنية (لوحة المواصفات) المثبتة على الخزان. أي معلومة مختومة على تلك اللوحة تخبرني مباشرة بما إذا كان اعتماد الخزان سارياً؟","options":["تاريخ آخر فحص/اختبار أُجري على الخزان","تاريخ آخر غسل وتعقيم للخزان لمنتجات الطعام","الحد الأقصى القانوني لمساحة الفراغ وكثافة المنتج المصنّف الخزان لنقلها","تاريخ آخر صيانة وضبط لنظام فرامل الخزان"],"explanation":"تُظهر لوحة البيانات/المواصفات للخزان تاريخ آخر فحص أو اختبار، مما يثبت أن اعتماد الخزان لا يزال سارياً وأنه صالح قانونياً لنقل السائل."},"146":{"q":"أقود صهريجاً محمّلاً بالكامل على طريق سريع مستوٍ وألاحظ المرور يتباطأ بعيداً أمامي. مقارنة بمقطورة الصندوق الجاف التي أسحبها عادة بنفس الوزن المحمّل والسرعة، ماذا ينبغي أن أتوقع من مركبة الخزان هذه؟","options":["ستتسارع مبتعدة عن التباطؤ أسرع، فيمكنني الانتظار أطول قبل رفع قدمي عن دواسة الوقود.","ستستغرق وقتاً أطول للتوقف، لذا أحتاج إلى زيادة مسافة اتباعي والكبح بلطف ومبكراً.","ستنعطف بأمان أكبر لأن الحمولة السائلة تخفض مركز الثقل على الأرض المستوية.","ستحافظ على خط مستقيم بشكل أفضل أثناء الكبح الشديد لأن السائل يبقي الوزن في المنتصف."],"explanation":"الخزان المحمّل يستغرق وقتاً أطول للتوقف لأن اندفاع السائل يدفعه للأمام، لذا زِد مسافة الاتباع واكبح بلطف ومبكراً."},"147":{"q":"أنقل صهريجاً أملس الجدار محمّلاً جزئياً وأرى لافتة تحذّر من منحدر حاد أمامي. مع معرفتي أن اندفاع السائل يطيل مسافة توقفي، متى ينبغي أن أتحقق من أن فراملي تعمل بشكل سليم؟","options":["بعد أن أكون قد بدأت النزول، كي أشعر كيف يؤثر الاندفاع على الكبح على المنحدر","فقط بمجرد وصولي إلى القاع وخروجي إلى أرض مستوية مرة أخرى","قبل أن أبدأ النزول، بينما أنا لا أزال على طريق مستوٍ","لا حاجة للاختبار مسبقاً؛ أكتفي بترك مسافة اتباع إضافية بدلاً من ذلك"],"explanation":"اختبر الفرامل قبل بدء النزول على المنحدر، بينما لا تزال على طريق مستوٍ، كي يمكن رصد أي عطل بأمان قبل أن يجعل اندفاع السائل التوقف أصعب."},"148":{"q":"أنقل حليباً في صهريج أملس الجدار ممتلئ جزئياً وقد تجاوزت للتو علامة توقف متمهلاً إلى طريق هادئ. وأنا أتقدم زحفاً ثم أكبح مرة أخرى، أي مما يلي ينبغي أن أتوقع الشعور به أكثر من السائل في هذا الخزان عديم الحواجز؟","options":["لا اندفاع تقريباً، لأن خزانات منتجات الطعام مبنية بحواجز إضافية للنظافة الصحية","اندفاع جانبي فقط، لأن الحواجز في هذا الخزان توقف كل الحركة الأمامية والخلفية","حمولة مقفلة صلبة تدفع بالتساوي ولا تدفع الشاحنة للأمام أبداً","اندفاع أمامي وخلفي قوي يمكن أن يدفع الشاحنة حتى بعد أن أظن أنني توقفت"],"explanation":"الخزان أملس الجدار الممتلئ جزئياً لا يحتوي على حواجز، لذا توقّع اندفاعاً أمامياً وخلفياً قوياً يمكن أن يدفع الشاحنة حتى بعد أن تظن أنك توقفت."},"149":{"q":"أنقل صهريجاً سائلاً محمّلاً جزئياً على طريق سريع ذي مسارين عندما يبدأ المرور أمامي بالتباطؤ. مع معرفتي بكيفية تصرّف الحمولة وكيف تُقاد هذه المركبة، أي نهج ينبغي أن يوجّه كل ما أفعله لبقية هذه الرحلة؟","options":["أبقَ مربوط الحزام، احتفظ بمسافة اتباع إضافية، وقُد بسلاسة ويقظة، متمهلاً في التوقف والتوجيه كي يبقى الاندفاع تحت السيطرة","أبقَ مربوط الحزام لكن قلّص المسافة عن المركبة التي أمامي، لأن السير لصق المصد يمنع الاندفاع من تجميع زخم خلفي","أبقَ مربوط الحزام وحافظ على مثبّت السرعة فوق الحد المعلن على المقاطع المفتوحة لتعويض الوقت، مبطئاً فقط عند وصولي إلى منحنى","أبقَ مربوط الحزام ووجّه بيد واحدة كي تكون الأخرى حرة لتشغيل ذراع فرملة المقطورة عند كل توقف"],"explanation":"لأن الحمولات السائلة تستقر عالياً وتندفع، أبقَ مربوط الحزام، واحتفظ بمسافة اتباع إضافية، وقُد بسلاسة ويقظة، متمهلاً في التوقف والتوجيه لإبقاء الاندفاع تحت السيطرة."},"150":{"q":"أنقل صهريجاً أملس الجدار ممتلئاً وأقترب من إشارة حمراء عند تقاطع مزدحم. أضغط على الفرامل بسلاسة وأشعر بالمركبة تستقر إلى توقف تام. بعد جزء من الثانية من ظني أنني توقفت تماماً، ماذا ينبغي أن أتوقع من الحمولة السائلة أن تفعل؟","options":["تضغط مباشرة للأسفل وتثبّت المركبة في مكانها","تندفع للأمام وتحاول دفع الشاحنة قُدُماً","تشد للخلف وتجذب الشاحنة بعيداً عن الخط","تستقر مستوية ولا تضيف أي قوة إضافية على الإطلاق"],"explanation":"الخزان أملس الجدار لا يحتوي على حواجز، لذا عندما تتوقف يندفع السائل المتحرك للأمام ويمكن أن يدفع الشاحنة قُدُماً، مثلاً إلى داخل التقاطع."},"151":{"q":"أنا أنقل حمولة كاملة من السائل على منحدر خروج من الطريق السريع محدد بسرعة 35 ميلاً في الساعة. تبدو مركبتي الصهريجية مستقرة على الطريق المستقيم، لذا أشعر برغبة في أخذ المنحدر المنحني بالسرعة المحددة لإبقاء حركة المرور خلفي سلسة. ما هو السبب الأهم للإبطاء إلى ما دون 35 ميلاً في الساعة بكثير قبل دخول هذا المنعطف؟","options":["الحفاظ على السرعة المحددة يهدر الوقود، ورفع القدم عن دواسة الوقود في المنعطف يحسّن من اقتصاد الوقود لدي مع حمولة كاملة","تموّج السائل داخل الصهريج الممتلئ سيدفع الشاحنة إلى الأمام، مما يجعل من الصعب الحفاظ على مسافة التوقف على المنحدر","المركز المرتفع للثقل الناتج عن الحمولة السائلة يجعل الصهريج ينقلب بسهولة، لذا يجب أخذ المنعطفات بسرعة أقل بكثير من السرعة المحددة","البقاء عند السرعة المحددة يعرّضك لخطر توقف قصير وعنيف في أسفل المنحدر قد يؤدي إلى قفل المكابح"],"explanation":"المركز المرتفع للثقل الناتج عن الحمولة السائلة يجعل الصهاريج تنقلب بسهولة، لذا خذ المنعطفات والمنحدرات والانعطافات بسرعة أقل بكثير من السرعة المحددة."},"152":{"q":"أنت تنقل صهريج حليب ناعم التجويف (بدون حواجز داخلية) محمّلاً جزئياً على طريق سريع مبلل بالمطر في تكساس، وفجأة تتباطأ حركة المرور أمامك. مع معرفتك بكيفية تصرف هذا الصهريج، ما هي الطريقة الأكثر أماناً لخفض سرعة شاحنتك إلى سرعة حركة المرور الجديدة؟","options":["حافظ على سرعتك ولا تتفاعل إلا إذا ضاقت المسافة، لأن الصهريج الفارغ يتوقف بسرعة على أي سطح","اضغط على المكابح بقوة الآن لتقليل السرعة بسرعة قبل أن يسلب الطريق المبلل قدرتك على التماسك","ابقَ قريباً خلف المركبة التي أمامك حتى تتمكن من مطابقة كبحها وتقصير مسافة توقفك","ارفع قدمك عن دواسة الوقود مبكراً وطبّق المكابح برفق وسلاسة للتحكم في تموّج السائل"],"explanation":"يتموّج الصهريج ناعم التجويف بقوة، لذا على الطريق المبلل ارفع قدمك عن دواسة الوقود مبكراً واكبح برفق وسلاسة للتحكم في التموّج واحترام التماسك المنخفض."},"153":{"q":"لقد اشتريت للتو مقطورة صهريج شحن مستعملة، وأخبرني زميل في العمل أن إعادة الاختبار والفحص \"تتولاها الورشة فقط عندما يبدو شيء ما خاطئاً، فلا تقلق بشأنها.\" قبل أن أنقل أي حمولة، ماذا يجب أن أفهم عن كيفية عمل إعادة اختبار وفحص صهريج الشحن في الواقع؟","options":["يُطلب إجراؤها وفق جدول زمني منتظم ومتكرر، بغض النظر عما إذا كانت هناك مشكلة ظاهرة حالياً","يُطلب إجراؤها مرة واحدة فقط، عند تصنيع الصهريج واعتماده لأول مرة","تُجرى بشكل عشوائي، كلما صادف أن وضع مفتش علامة على المركبة","لا يُطلب إجراؤها رسمياً على الإطلاق طالما أن فحص الدوران اليومي قبل الرحلة لا يُظهر أي تسريبات"],"explanation":"يجب إعادة اختبار وفحص صهاريج الشحن وفق جدول زمني منتظم ومتكرر بغض النظر عما إذا كانت هناك مشكلة ظاهرة حالياً."},"154":{"q":"أثناء فحصي قبل الرحلة، يشير المشرف إلى لوحة المواصفات المعدنية المثبتة بالبراشيم على جانب مقطورة الصهريج ويسألني عن المعلومات التي تقدمها له عن هذا الصهريج بالتحديد. أي مما يلي يخبره به لوحة المواصفات فعلاً؟","options":["السرعة القصوى على الطريق السريع التي يُصنّف الصهريج المحمّل للسير بها","نوع الصهريج وتاريخ آخر اختبار ضغط له","اسم الناقل والسائق المعيّن للرحلة","إجمالي الغالونات من المنتج المحمّل حالياً في الصهريج"],"explanation":"تحدد لوحة مواصفات الصهريج نوع الصهريج وتاريخ آخر اختبار ضغط له."},"155":{"q":"أنا أنقل سائلاً متطايراً يطلق بخاراً، والضغط داخل صهريجي يستمر في التزايد كلما تسخن الحمولة أثناء الرحلة. اجتاز غطاء فتحة الرجل والصمامات فحصي قبل الرحلة على أنها مغلقة ومحكمة. أي نهج للتعامل مع بخار الصهريج هو الصحيح لهذه الحمولة؟","options":["أبقِ كل صمامات البخار والتنفيس مغلقة بإحكام طوال الرحلة بحيث لا يمكن لأي بخار الإفلات من الصهريج إطلاقاً","أضِف حرارة إضافية إلى الشحنة حتى يحترق البخار بشكل أسرع وينخفض الضغط الداخلي من تلقاء نفسه","اسمح بتنفيس دقيق ومتحكم به بحيث يتم تخفيف ضغط البخار المتزايد بدلاً من تركه يرتفع دون ضابط","لا تفعل شيئاً على الإطلاق، لأن الصهريج المحكم الإغلاق لا يحتاج أبداً إلى أي تنفيس بمجرد اجتياز الأغطية للفحص"],"explanation":"يبني السائل المتطاير ضغط بخار كلما تسخن، لذا يجب تنفيسه بطريقة متحكم بها لتخفيف ذلك الضغط بأمان ومنع الضغط الزائد."},"156":{"q":"أثناء تحميل سائل قابل للاشتعال، يجب أن يكون الخرطوم:","options":["متروكاً مرتخياً","موصولاً كهربائياً بالصهريج","مقطوعاً قصيراً","ملفوفاً بورق القصدير"],"explanation":"اربط الخرطوم كهربائياً بالصهريج لمنع الشرر."},"157":{"q":"أنا أنقل صهريجاً محمّلاً جزئياً بحواجز داخلية، وكبحت للتو حتى التوقف عند إشارة حمراء. عندما يصل السائل بداخله إلى جدران الحواجز، ماذا يحدث في تلك اللحظة، ولماذا يجب أن يقلقني ذلك؟","options":["يفقد السائل طاقته عند الحواجز ويستقر على الفور، لذا يمكنني تحرير المكابح والتحرك للأمام دون أي قوة إضافية تؤثر على الشاحنة.","يُمتص السائل في ثقوب الحواجز ويختفي، مما يخفف الحمولة ويقصّر مسافة توقفي عند الإشارة التالية.","يغوص السائل ويتراص بشكل صلب ضد الحواجز، مما يضيف وزناً إلى المحور الأمامي ويساعد على تثبيت الشاحنة بقوة في مكانها.","يصطدم السائل بالحاجز ويرتد للخلف، مما يخلق تموّجاً قد يدفع الشاحنة إلى الأمام داخل التقاطع بعد أن أكون قد توقفت."],"explanation":"في الصهريج المحمّل جزئياً، يصطدم السائل المتموّج بالحاجز ويرتد للخلف، وذلك التموّج الأمامي قد يدفع الشاحنة إلى الأمام حتى بعد أن تظن أنك توقفت."},"158":{"q":"أنا أنقل صهريجاً ناعم التجويف محمّلاً جزئياً والسائل يتمايل من جانب إلى آخر. بناءً على كيفية تصرف هذا التموّج، في أي حالة أكون أكثر عرضة فعلاً لقلب الشاحنة؟","options":["عندما أتجه عبر انعطاف أو منعطف، لأن التموّج من جانب إلى آخر يضيف قوة نحو الخارج ويمكن أن يقلب المركز المرتفع للثقل","عندما أتسارع بقوة في خط مستقيم، لأن التموّج يلقي بالوزن إلى الخلف ويرفع العجلات الأمامية عن الطريق","عندما أكبح حتى التوقف في خط مستقيم، لأن التموّج الأمامي يدفع الشاحنة ويقلبها على جانبها","عندما أكون متوقفاً على أرض مستوية، لأن السائل المحتجز يستمر في التحرك ويقلب الصهريج ببطء"],"explanation":"التوجيه عبر انعطاف أو منعطف يسمح للسائل بالتموّج من جانب إلى آخر، مضيفاً قوة خارجية على المركز المرتفع للثقل قد تسبب الانقلاب."},"159":{"q":"أنا أنقل صهريج حليب ناعم التجويف محمّلاً جزئياً، وأضاءت الإشارة عند التقاطع بالأخضر للتو. بينما أبدأ في الانطلاق للأمام من التوقف التام، ما هي الطريقة الصحيحة لتحريك الشاحنة؟","options":["اضغط على دواسة الوقود بقوة حتى أعبر التقاطع بسرعة قبل أن يلحق بي التموّج","اضغط على دواسة الوقود برفق وابنِ السرعة تدريجياً حتى لا يتموّج السائل ضد الشاحنة","اثبت على المكابح بينما أضخ الوقود، ثم حرّر فجأة للانطلاق عبر التقاطع في حركة واحدة","تسارع بشكل طبيعي لأن الصهريج المحمّل جزئياً يتموّج أقل من الصهريج الممتلئ تماماً"],"explanation":"البدء بسلاسة وبناء السرعة تدريجياً يمنع السائل من التموّج إلى الأمام، مما يمنع الحمولة من دفع الشاحنة أو زعزعة مركزها المرتفع للثقل."},"160":{"q":"أنا أنقل صهريج منتج غذائي سائل ناعم التجويف محمّلاً جزئياً، وأقترب من إشارة حمراء عند تقاطع مزدحم يتبعه انعطاف حاد إلى اليسار بعده مباشرة. لإدارة تموّج السائل بأمان، متى يجب أن أبدأ الكبح؟","options":["تماماً عند خط التوقف وخلال الانعطاف، حتى أستخدم المحرك والمكابح معاً لامتصاص التموّج عند حدوثه","فقط عندما أشعر بالحمولة تبدأ بالدفع للأمام، ثم أكبح بقوة لاستعادة مسافة التوقف المفقودة","قبل التوقف بوقت كافٍ وقبل الانعطاف بوقت كافٍ، مع الكبح برفق ومبكراً حتى لا يدفعني التموّج للأمام أو يقلبني","متأخراً وبثبات عند التوقف، لأن الصهريج ناعم التجويف به حواجز تحبس التموّج من أجلي"],"explanation":"مع الصهريج المحمّل جزئياً، اكبح برفق ومبكراً قبل التوقفات والانعطافات بوقت كافٍ حتى لا يطيل التموّج مسافة التوقف أو يدفعك للأمام أو يسبب انقلاباً."},"161":{"q":"أنا أنقل صهريج سائل محمّلاً جزئياً، وأتبع نفس فجوة الثانيتين التي أحتفظ بها عادةً في سيارتي الشخصية. بينما أقترب من إشارة حمراء، كيف يجب أن أتوقع سلوك توقف هذه المركبة الصهريجية مقارنةً بالسيارة، وكيف يجب أن أتكيف؟","options":["تتوقف في مسافة تقارب مسافة السيارة، لذا فإن فجوة الثانيتين جيدة؛ فقط حافظ على ضغط ثابت على المكبح.","في الواقع تتوقف في مسافة أقصر من السيارة لأن الحمولة السائلة الثقيلة تضغط الإطارات للأسفل لمزيد من التماسك، لذا يمكنني المتابعة عن قرب.","مسافة التوقف هي نفسها أساساً بمجرد أن تسخن المكابح؛ الشاغل الحقيقي الوحيد هو أخذ الانعطاف بعد الإشارة ببطء.","يستغرق التوقف وقتاً أطول بكثير من السيارة، لذا أحتاج إلى مسافة اتباع إضافية ويجب أن أكبح برفق ومبكراً لأن التموّج قد يدفعني للأمام بعد أن أظن أنني توقفت."],"explanation":"تستغرق المركبة الصهريجية المحمّلة وقتاً أطول بكثير من السيارة للتوقف، لذا زِد مسافة الاتباع واكبح برفق ومبكراً لأن التموّج قد يدفعك للأمام بعد توقفك."},"162":{"q":"أنا أنقل صهريج حليب ناعم التجويف محمّلاً جزئياً عبر حركة مرور كثيفة متقطعة. تستمر الحمولة في التمايل في كل مرة أبطئ فيها. لإدارة تموّج السائل بأمان، أين يجب أن أكون أكثر حرصاً على إبقاء مساحة إضافية حول مركبتي؟","options":["أمام وخلف، لأن التموّج يطيل مسافة توقفي ويمكن أن يدفعني للأمام بعد توقفي","فقط إلى يساري ويميني، لأن التموّج في الصهريج يتحرك من جانب إلى آخر فقط","مباشرة فوق المقطورة، لأن المركز المرتفع للثقل يدفع الحمولة للأعلى","تحت الشاحنة، لإعطاء السائل المتموّج مجالاً ليستقر بين المحاور"],"explanation":"يطيل تموّج السائل مسافة توقفك ويمكن أن يدفع الشاحنة للأمام بعد توقفك، لذا احتفظ بمساحة إضافية أمام وخلف."},"163":{"q":"أنا أنقل صهريج سائل محمّلاً جزئياً وأتوقف توقفاً مفاجئاً عند إشارة حمراء. أشعر بالشاحنة تترنح حتى بعد توقف العجلات عن الدوران. في أي اتجاه يدفع تموّج السائل مركبتي على الأرجح مباشرةً بعد هذا التوقف المفاجئ؟","options":["من جانب إلى آخر، مائلاً بالمقطورة نحو الانقلاب","للأمام والخلف، دافعاً الشاحنة للأمام بعد أن أظن أنني توقفت","مباشرة للأسفل، ضاغطاً الصهريج بقوة أكبر على نظام التعليق","للخارج عبر فتحات التنفيس وأغطية فتحات الرجل على سطح الصهريج"],"explanation":"في الصهريج المحمّل جزئياً يتمايل السائل للأمام والخلف في اتجاه السير، وذلك التموّج الأمامي قد يدفع الشاحنة للأمام حتى بعد أن تظن أنك توقفت."},"164":{"q":"أنا أحمّل صهريجاً ناعم التجويف في محطة باردة في وقت مبكر من صباح شتوي، ويخبرني الموزّع أنني لا أستطيع ملؤه حتى الأعلى تماماً. لتحديد كمية الفراغ (المساحة الفارغة) التي يجب أن أتركها بالضبط، أي خاصية للسائل أحسب حسابها فعلاً؟","options":["مقدار تمايل السائل ذهاباً وإياباً، لأن التموّج هو ما يجبرني على ترك مساحة في الأعلى","سعر السائل لكل غالون، لأن الحمولات الأغلى ثمناً تُشحن مع مساحة أكبر للسلامة","مقدار تمدد السائل عندما يسخن، لأن الحمولة المملوءة باردة ستنمو وتحتاج إلى تلك المساحة الفارغة","وزن السائل لكل غالون، لأن الفراغ يُحدّد بحتاً حسب كثافة الشحنة ووزنها"],"explanation":"تترك الفراغ لأن السوائل تتمدد عندما تسخن، والحمولة المملوءة باردة ستنمو، فتحتاج إلى تلك المساحة العلوية الفارغة لمنع امتلاء الصهريج الزائد."},"165":{"q":"أنا أقود صهريجاً، وهذا الأسبوع أنقل سائلاً مختلفاً في كل رحلة. يخبرني الموزّع أن كمية المساحة الفارغة (الفراغ) التي يجب أن أتركها في أعلى الصهريج لن تكون نفسها في كل حمولة. لماذا يتغير الفراغ المطلوب من منتج إلى آخر؟","options":["الفراغ ثابت حسب حجم الصهريج، لذا يبقى كما هو بغض النظر عن السائل الذي أحمّله","الفراغ يتغير فقط مع الموسم، لذا فهو متطابق لكل منتج أنقله في يوم معيّن","يجب أن يكون الفراغ دائماً صفراً لأن الصهريج الممتلئ هو الطريقة الأكثر استقراراً وقانونية للسير","تتمدد السوائل المختلفة بمقادير مختلفة عندما تسخن، لذا يختلف الفراغ الذي تحتاجه حسب المنتج"],"explanation":"تتمدد السوائل المختلفة بمقادير مختلفة عندما تسخن، لذا يختلف الفراغ، أو المساحة الفارغة، اللازم للتمدد من منتج إلى آخر."},"166":{"q":"تم تكليفي بنقل حمولة جزئية من الحليب في شاحنة صهريج. لأن الحليب منتج غذائي، فإن الصهريج ناعم التجويف بلا حواجز داخلية. بينما أخطط لكيفية قيادة هذه الرحلة، أي نهج هو الأهم للحفاظ على السيطرة على الشاحنة؟","options":["وجّه وانطلق واكبح وغيّر المسارات بسلاسة إضافية، لأن السائل بلا حواجز يتموّج بقوة والحركات المفاجئة قد تدفعني للأمام أو تقلبني","اكبح بقوة ومتأخراً عند التوقفات حتى يُمتص التموّج الأمامي بسرعة قبل أن يدفع الشاحنة للأمام","خذ المنحدرات والمنعطفات بالسرعة المحددة، لأن الحواجز داخل الصهريج تحدّ بالفعل من التمايل من جانب إلى آخر","قُد بشكل طبيعي وعامله كأي حمولة صندوق جاف، لأن صهاريج الحليب الغذائية مصممة لإلغاء تموّج السائل"],"explanation":"الصهريج ناعم التجويف بلا حواجز ليس به فواصل، لذا يكون تموّج السائل قوياً في كل اتجاه، مما يتطلب انطلاقاً وكبحاً وتوجيهاً وتغيير مسارات بسلاسة إضافية."},"167":{"q":"أنا أجري فحصاً قبل الرحلة على مقطورة صهريج غاز مضغوط قبل نقل حمولة خطرة. أريد تركيز فحص الدوران على الأشياء التي تُبقي هذا الصهريج آمناً فعلاً على الطريق. أي مما يلي يجب أن أفحصه بأكبر دقة خلال هذا الفحص؟","options":["أن يكون طلاء المقطورة وحروف وزارة النقل لامعة ومُجدّدة حديثاً","أن لا توجد تسريبات حول الصمامات وفتحات الرجل وفتحات التنفيس، وأن تكون الصمامات في الوضع الصحيح","أن تكون المرايا الجانبية نظيفة ومضبوطة حتى أستطيع مراقبة المقطورة في حركة المرور","أن يكون بوق الهواء عالياً بما يكفي لتحذير حركة المرور عند التقاطعات والمنحدرات"],"explanation":"على صهريج الغاز المضغوط، افحص بحثاً عن تسريبات حول الصمامات وفتحات الرجل وفتحات التنفيس وتأكد من أن جميع الصمامات في الوضع الصحيح."},"168":{"q":"أنت تنقل صهريج غاز مضغوط على طريق ريفي في تكساس عندما تلاحظ رائحة قوية وصوت هسهسة خافتاً قادماً من قرب صمام في مؤخرة المقطورة. حركة المرور خفيفة وأنت لا تزال على بُعد بضعة أميال من أقرب مخرج. ما هو الإجراء الأكثر أماناً الذي تتخذه؟","options":["حافظ على سرعتك مرتفعة حتى يحمل الهواء المتحرك البخار المتسرب بعيداً عن المقصورة حتى تصل إلى المخرج التالي","توقف على جانب الطريق وافتح فوراً أقرب صمام لتخفيف الضغط المتزايد داخل الصهريج","انعطف خارج الطريق، وأوقف التشغيل، وابقَ بعيداً تماماً عن المركبة والتسريب المشتبه به","تابع القيادة بحذر إلى محطة الشاحنات المأهولة أمامك حتى يقوم ميكانيكي بإحكام الوصلة المتسربة"],"explanation":"تسريب غاز يُشم أو يُسمع هو خطر فوري للحريق والاستنشاق، لذا انعطف خارج الطريق، وأوقف التشغيل، وابقَ بعيداً تماماً عن المركبة والتسريب."},"169":{"q":"أنا أنقل صهريج سائل قابل للاشتعال محمّلاً جزئياً وأحتاج إلى التوقف والركن لاستراحتي المطلوبة. هناك أربعة أماكن مفتوحة على طول طريقي. للحفاظ على سلامة الحمولة، أي من هذه يجب أن أتجنب الركن بجانبه أكثر من غيره؟","options":["مكان توقف من الحصى خلف مستودع مغلق دون أي مركبات أخرى حوله","كتف عريض على طريق فرعي مرصوف ومستوٍ بعيداً عن حركة المرور","ساحة ترابية فارغة على الطرف البعيد من ممتلكات محطة شاحنات","بائع طعام على جانب الطريق يشغّل شواية ذات لهب مكشوف قرب الرصيف"],"explanation":"يجب إبقاء صهريج السائل القابل للاشتعال بعيداً عن أي مصدر اشتعال، وشواية ذات لهب مكشوف يمكن أن تشعل الأبخرة المنطلقة من الصمامات أو فتحات التنفيس أو فتحة الرجل."},"170":{"q":"أنا أنقل صهريجاً محمّلاً جزئياً وأقترب من منحدر خروج من طريق سريع محدد بسرعة 35 ميلاً في الساعة. تبدو شاحنتي مستقرة على الطريق المستقيم، وإطاراتي بحالة جيدة، وخزان وقودي ممتلئ. بينما أفكر في ما هو الأكثر احتمالاً إحصائياً لقلبي على جانبي أو تحطيم هذه الشاحنة، أي عامل يجب أن أكون أكثر قلقاً بشأن السيطرة عليه؟","options":["أخذ المنحدر المنحني بسرعة عالية، لأن المركز المرتفع للثقل في الصهريج يجعل الانقلاب السبب الرئيسي لحوادث الصهاريج","نفاد الوقود قبل المحطة التالية، لأن الصهريج الفارغ يغيّر كيفية تحرك الحمولة وتعاملها","انفجار إطار مفاجئ على المنحدر، لأن الإطارات البالية هي السبب الرئيسي لحوادث الصهاريج بسرعة الطريق السريع","فقدان الاتصال اللاسلكي بالموزّع، لأنك لا تستطيع الحصول على المساعدة بسرعة إذا تعطلت الشاحنة على المنحدر"],"explanation":"تركب الشحنة السائلة عالياً وتعطي الصهاريج مركزاً مرتفعاً للثقل، مما يجعل الانقلاب السبب الرئيسي لحوادث الصهاريج، عادةً من أخذ المنحدرات والمنعطفات بسرعة عالية."},"171":{"q":"أنا أقود شاحنة صهريج محمّلة وأقترب من منحدر خروج منحنٍ من طريق سريع محدد بسرعة 35 ميلاً في الساعة. الرصيف جاف وحركة المرور خفيفة. مع الأخذ في الاعتبار كيف تؤثر شحنتي على استقرار المركبة، كيف يجب أن آخذ هذا المنحدر؟","options":["بسرعة 35 ميلاً في الساعة المحددة، لأن سرعة المنحدر مضبوطة بالفعل للشاحنات والرصيف الجاف يعطيني تماسكاً جيداً","بسرعة أقل بكثير من 35 ميلاً في الساعة المحددة، لأن المركز المرتفع للثقل يجعل الصهريج عرضة للانقلاب","بسرعة 35 ميلاً في الساعة المحددة، لكن انقل إلى الوضع المحايد خلال المنعطف حتى لا يدفعني المحرك أوسع","أعلى قليلاً من 35 ميلاً في الساعة عند الدخول، ثم اكبح بقوة بمجرد أن أصل إلى المنعطف لتثبيت الحمولة"],"explanation":"يحمل الصهريج المحمّل سائله عالياً، مما يخلق مركزاً مرتفعاً للثقل، لذا يجب أخذ المنعطفات والمنحدرات بسرعة أقل بكثير من السرعة المحددة لتجنب الانقلاب."},"172":{"q":"أنا أنقل صهريجاً ناعم التجويف محمّلاً جزئياً على طريق سريع بمسارين عندما تتباطأ حركة المرور أمامي فجأة وأحتاج إلى تعديل سرعتي وموضعي في المسار. نظراً لكيفية تصرف السائل في هذا الصهريج، أي نهج يعطيني أكبر سيطرة على المركبة؟","options":["قم بتصحيحات توجيه سريعة وحاسمة حتى أعود إلى مساري قبل أن يتراكم التموّج","اكبح بقوة ومتأخراً بمجرد أن أتأكد أنه يجب أن أتوقف، ثم وجّه بثبات للحفاظ على خط سيري","طبّق مدخلات توجيه وكبح لطيفة وتدريجية وزِد مسافة اتباعي حتى يبقى التموّج قابلاً للإدارة","حافظ على سرعتي مرتفعة خلال التعديل واعتمد على انعطافات حادة ومتأخرة لتقليل الوقت الذي تكون فيه الحمولة في حركة"],"explanation":"لأن التموّج في صهريج ناعم التجويف محمّل جزئياً يطيل مسافة التوقف، فتحكم فيه بتوجيه وكبح لطيفين وتدريجيين ومسافة اتباع أكبر."},"173":{"q":"أنت تنقل صهريجاً ناعم التجويف محمّلاً جزئياً على طريق سريع عندما يبدأ رذاذ متجمد بتزجيج سطح الطريق. مقارنةً بقيادة نفس المركبة الصهريجية على رصيف جاف، ماذا يجب أن تتوقع على هذا الطريق الجليدي؟","options":["تعمل طبقة الجليد كوسادة تحت الإطارات، لذا سيكون من الأسهل إبقاء الصهريج مستقيماً وتوجيهه.","تقصُر مسافات التوقف لأن البرد يكثّف السائل ويقلل التموّج الأمامي تماماً.","يمكنك بأمان الحفاظ على السرعة المحددة لأن وزن الصهريج يضغط الإطارات بقوة في الجليد.","ينخفض التماسك بشدة، لذا يصبح الصهريج أصعب في السيطرة عليه ويجب أن تبطئ إلى ما دون سرعتك المعتادة بكثير."],"explanation":"على الجليد، ينخفض التماسك بشدة، ومع التموّج والمركز المرتفع للثقل يصبح الصهريج أصعب في السيطرة عليه، لذا أبطئ إلى ما دون سرعتك المعتادة بكثير."},"174":{"q":"أنا أنقل صهريج سائل محمّلاً جزئياً على شارع مدينة مستوٍ، وأضاءت إشارة مرور على بُعد مبنيين أمامي بالأصفر للتو. مقارنةً بقيادة شاحنة صندوق جاف محمّلة، ماذا يجب أن أفعل بشكل مختلف لإيقاف هذه الشاحنة بأمان وبتحكم؟","options":["ابدأ الإبطاء وخطط لكبحي مبكراً بكثير، لأن تموّج السائل يطيل مسافة توقفي ويمكن أن يدفعني للأمام بعد أن أظن أنني توقفت","انتظر حتى أقترب أكثر من الإشارة، ثم اكبح بقوة وسرعة حتى يستقر التموّج قبل الخط","حافظ على مسافة اتباعي المعتادة لأن الحمولة الجزئية أخف وتتوقف فعلاً أسرع من الحمولة الكاملة","اضخ المكابح بسرعة طوال الطريق إلى الإشارة حتى أمنع السائل من التمايل ضد الرأس الأمامي"],"explanation":"لأن تموّج السائل يطيل مسافة التوقف ويمكن أن يدفع الشاحنة للأمام بعد أن تظن أنك توقفت، ابدأ الإبطاء وخطط لكبحك مبكراً بكثير."},"175":{"q":"لقد حصلت للتو على تصريح المركبة الصهريجية (N)، ويسلّمني الموزّع مهمة موصوفة فقط بأنها \"شاحنة صهريج مركّبة.\" قبل أن أخرج إلى الساحة للعثور على المعدات المخصصة لي، أي تكوين يجب أن أتوقع توصيله وقيادته؟","options":["شاحنة مستقيمة بصهريج مثبت بشكل دائم مبني على هيكلها الخاص، دون أي مقطورة منفصلة","جرّار موصول بمقطورة صهريج منفصلة تحمل الحمولة السائلة خلفه","جرّار يسحب مقطورة مسطحة تحمل صهاريج محمولة مربوطة على السطح","جرّار يسحب مقطورة صندوق جاف قياسية مع صهريج ماء مساعد صغير مثبت في المقدمة"],"explanation":"شاحنة الصهريج المركّبة هي وحدة قوة تسحب مقطورة صهريج مسحوبة منفصلة، لذا يربط التوصيل جرّاراً بمقطورة صهريج تحمل الحمولة السائلة خلفها."},"176":{"q":"أنت تقود مقطورة صهريج محمّلة وتقترب من منعطف حاد بزاوية 90 درجة نحو اليمين عند تقاطع داخل المدينة. ولأن مؤخرة مقطورة الصهريج الطويلة تتبع مساراً أضيق من مسار القاطرة (الانحراف عن المسار)، فماذا يجب أن تفعل لتمنع مقطورتك من تسلّق حافة الرصيف أو الاصطدام بجسم ثابت؟","options":["التصق بحافة الرصيف بإحكام بالقاطرة بحيث تسير عجلات المقطورة الخلفية باستقامة عبر الزاوية","زِد سرعتك قليلاً خلال المنعطف بحيث تتبع مؤخرة المقطورة نفس خط المقدمة","انعطف على نطاق واسع واترك مساحة إضافية في المنعطف بحيث تتجاوز العجلات الخلفية حافة الرصيف والعوائق","حافظ على بقاء مؤخرة المقطورة في محاذاة القاطرة وتجاهل المسار الذي تسلكه العجلات الخلفية"],"explanation":"تنحرف عجلات المقطورة الخلفية عن المسار متبعةً مساراً أقصر، لذا انعطف على نطاق واسع لإبقائها بعيدة عن حواف الأرصفة والعوائق."},"177":{"q":"أنا أقود صهريجاً محمّلاً جزئياً على منحدر طريق سريع مبلل عندما تنغلق عجلات المقطورة الخلفية وتبدأ المقطورة في الانزلاق. بحكم العادة، أمدّ يدي إلى صمام المقطورة اليدوي (صمام العربة) لتطبيق فرامل المقطورة وحدها و«تدارك» الانزلاق. لماذا يعتبر مفتّش إدارة السلامة العامة (DPS) أن هذه هي الحركة الخاطئة في مركبة الصهريج؟","options":["لأن الصمام اليدوي يفرط في تطبيق فرامل محور التوجيه، مما يدفع مقدمة الصهريج خارج خطها المقصود عبر المنعطف","لأن الصمام اليدوي يحرّر الفرامل النابضية، مما يترك المقطورة بلا أي قوة فرملة بمجرد أن يدفعها الاندفاع إلى الأمام","لأن تطبيق الصمام اليدوي يقطع الهواء عن فرامل خدمة القاطرة، فلا يتبقى سوى فرملة المحرك لإبطاء الشاحنة","لأن تطبيق فرامل المقطورة وحدها يبقي تلك العجلات منغلقة وقد يسبب انزلاق المقطورة بدلاً من إيقاف الانزلاق القائم"],"explanation":"إن فرملة عجلات المقطورة وحدها تبقيها منغلقة على سطح زلق، مما يسبب أو يفاقم انزلاق المقطورة بدلاً من إيقافه."},"178":{"q":"أثناء فحصي قبل الرحلة على صهريج سائل محمّل، أنحني وأنظر إلى الأرض أسفل المقطورة قبل الانطلاق. بخلاف فحص الإطارات ونظام التعليق، ما هو الشيء الأهم الذي يُقصد من هذه النظرة أسفل المركبة اكتشافه؟","options":["البقع المبللة أو القطرات الطازجة على الأرض التي تشير إلى تسربات من الصمامات أو المضخات أو الخراطيم","ما إذا كانت أغطية فتحات التفتيش أعلى الصهريج مفتوحة للسماح بتنفيس الضغط","كمية اندفاع السائل التي ينبغي أن أتوقعها بمجرد أن تنطلق المقطورة على الطريق","أن مركز الثقل المرتفع قد انخفض بما يكفي لاجتياز المنحدرات بأمان"],"explanation":"يتجمّع السائل المتسرب من الصمامات والمضخات والخراطيم على الأرض، لذا تكشف البقع المبللة أو القطرات أسفل المركبة عن التسربات."},"179":{"q":"أثناء فحصي قبل الرحلة على مقطورة صهريج تنقل سائلاً قابلاً للاشتعال، يذكّرني مشرف منصة التحميل بالتحقق من أن معدات الصهريج الخاصة تعمل قبل أن أنطلق. إلى جانب نظام استرداد الأبخرة، ما الجهاز الذي يُطلب مني تحديداً فحصه كجزء من هذه المعدات الخاصة؟","options":["مصباح عطل نظام منع انغلاق الفرامل (ABS) للمقطورة على لوحة القيادة","نظام الإيقاف الطارئ الذي يوقف تدفق المنتج","مثلث العاكس وعدّة الشعلات التحذيرية الطارئة","محدد المُبطّئ الذي يتحكم في قوة فرامل المحرك"],"explanation":"يوقف نظام الإيقاف الطارئ تدفق المنتج إذا حدثت مشكلة أثناء التحميل أو التفريغ أو النقل."},"180":{"q":"أنا أقوم بالوصل بمقطورة صهريج محمّلة للمرة الأولى وأشعر بالقلق من أنني بحاجة إلى روتين وصل خاص بسبب الحمولة السائلة ومركز الثقل المرتفع. قبل أن أتراجع تحتها، أي نهج ينبغي أن أتبع فعلاً؟","options":["تخطَّ الفحوصات المعتادة للعجلة الخامسة ومسمار الارتكاز، لأن صهريج السائل المختوم يسير بشكل مختلف وتلك الخطوات مخصصة لمقطورات الصناديق الجافة","قم بالوصل فقط بعد تفريغ جزء من الحمولة، لأن الصهريج الممتلئ يضع قوة هبوطية كبيرة جداً على العجلة الخامسة بحيث لا تُقفل الفكوك بأمان","قم بالوصل باستخدام نفس الإجراء الدقيق خطوة بخطوة الذي تستخدمه مع أي مقطورة، ثم تحقق من الوصلة قبل التحرك","تراجع تحتها بسرعة وقوة بحيث يصفع مسمار الارتكاز الفكوك مغلقاً، لأن الوزن السائل الثقيل يتطلب قوة إضافية لإحكام القفل"],"explanation":"يتم وصل مقطورة الصهريج باستخدام نفس الإجراء الدقيق خطوة بخطوة المتبع مع أي مقطورة، مع التحقق من الوصلة قبل التحرك."},"181":{"q":"أنا أحمّل مقطورة الصهريج بمنتج كثيف في محطة، ويناديني عبر اللاسلكي مشغّل منصة التحميل أن «أقيس الحمولة» قبل أن أتقدم إلى ميزان الوزن. وأنا واقف على الممشى، ما الذي يُطلب مني فحصه بالضبط؟","options":["الضغط في كل إطار من إطارات القاطرة والمقطورة للتأكد من عدم انخفاض أي منها أثناء التعبئة","قراءة الوزن على ميزان المحاور المدمج في المنصة قبل أن أتقدم إلى الميزان العام","ختم وجلوس كل غطاء فتحة تفتيش ومنفذ أبخرة قبل أن أغلقها","مدى ارتفاع السائل داخل الصهريج كي لا أملأه بإفراط أو أتجاوز الوزن القانوني"],"explanation":"يعني القياس فحص مدى ارتفاع السائل داخل الصهريج كي تتجنب الملء المفرط أو تجاوز حد الوزن القانوني."},"182":{"q":"أنا أعمل في خط نقل بالصهاريج ويخبرني موزّع المهام أن عميلاً يريد دمج منتجين سائلين مختلفين في صهريج الشحن الواحد لتوفير رحلة ثانية. قبل أن أوافق على تحميل كلا المنتجين في الصهريج نفسه، أي شرط يجب أن يتحقق؟","options":["تحميل كلا المنتجين في الصهريج الواحد مسموح به ويمكن القيام به بأمان لتلك السوائل المحددة","الحمولة المجمّعة لا تزال تترك مساحة فراغ كافية لتمدد السوائل عند تسخّنها","الخلط بينهما يمكّنني من إنهاء الخط أسرع وإلغاء رحلة العودة للعميل","الصهريج من النوع المزوّد بحواجز، لذا ستمنع الجدران الداخلية المنتجين من الاندفاع معاً"],"explanation":"يجوز أن يتشارك منتجان مختلفان صهريجاً واحداً فقط عندما يكون ذلك مسموحاً به وآمناً لتلك السوائل المحددة."},"183":{"q":"لقد سلّمت للتو حمولة من عصير البرتقال في صهريجي الأملس المخصص للأغذية، ويريد موزّع المهام أن أحمّل مذيباً كيميائياً تالياً، ثم أعود إلى نقل الحليب بعد ذلك. قبل أن أحمّل كل منتج جديد، لماذا تشترط الشركة أن أمرّر صهريجي عبر منصة الغسيل؟","options":["لإزالة الرواسب كي يجتاز الصهريج فحص التسرب عند الصمامات وفتحات التفتيش والمنافذ قبل إعادة التحميل","لمنع الرواسب المتبقية من منتج سابق من تلويث الحمولة التالية التي أنقلها","لتقليل اندفاع السائل عبر إزالة التراكمات عن الجدران الملساء قبل الرحلة التالية","لخفض مركز ثقل الحمولة كي يتعامل الصهريج بشكل أفضل في المنعطفات والمنحدرات"],"explanation":"يمنع تنظيف الصهريج بين الحمولات الرواسب المتبقية من منتج سابق من تلويث الحمولة التالية."},"184":{"q":"أنا سائق صهريج جديد أحمّل منتجاً سائلاً في صباح شتوي قارس في منطقة بانهاندل بتكساس. يحذّرني موزّع المهام من أن المنتج نفسه يُحمَّل بشكل مختلف في الصيف. باستثناء واحدة من العبارات أدناه، تصف جميعها ما تفعله درجات الحرارة الباردة ببعض السوائل وكيف يؤثر ذلك على حمولتي. أي عبارة صحيحة حول كيفية تصرّف بعض السوائل في الطقس البارد؟","options":["تصبح أرق وأكثر سيولة، فيكون الاندفاع أقوى وعليّ أن أفرمل بلطف أكبر من المعتاد","تتمدد وتحتاج إلى مساحة فراغ أكبر بكثير، لذا يجب أن أترك الصهريج أكثر فراغاً مما أفعل في الطقس الدافئ","تصبح أكثر سماكة ولزوجة، مما يغيّر طريقة تعامل الحمولة مقارنةً بالسائل نفسه في الطقس الدافئ","تصبح أخف من الهواء قرب المنافذ، لذا عليّ أن أعيد فحص إحكام صمامات الأبخرة قبل القيادة"],"explanation":"تصبح بعض السوائل أكثر سماكة ولزوجة في الطقس البارد، فتتعامل الحمولة نفسها بشكل مختلف عمّا هي عليه في الطقس الدافئ."},"185":{"q":"أنا أحمّل صهريجي الأملس بالبنزين في فترة بعد ظهر صيفي في تكساس، مع درجات حرارة تتجاوز 90 درجة بكثير. وبينما أعمل حول القبة وفتحة التفتيش، ألاحظ رائحة وقود أقوى مما ألاحظه في الصباح البارد. ما السبب الأرجح لزيادة الخطر حول صهريجي المفتوح في هذه الحرارة؟","options":["هواء الصباح البارد المحبوس داخل الصهريج يتسرب حاملاً رائحة الوقود معه","يمتص البنزين الماء من هواء الصيف الرطب، مما يرفع مستوى السائل نحو القبة","تجعل الحرارة الرمل والشوائب الدقيقة تترسب في السائل، مما يدفع الأبخرة لأعلى عبر المنافذ","تجعل درجة الحرارة الدافئة السائل المتطاير يطلق المزيد من البخار، مما يزيد الأبخرة القابلة للاشتعال"],"explanation":"تجعل درجات الحرارة الدافئة السوائل المتطايرة كالبنزين تطلق المزيد من البخار، مما يزيد الأبخرة القابلة للاشتعال."},"186":{"q":"لقد فرّغت للتو صهريجاً نقل سائلاً خطراً مزوّداً باللافتات، لكن كمية صغيرة من الرواسب لا تزال عالقة داخل جدران الصهريج. قبل أن أقود الصهريج «الفارغ» عائداً إلى المحطة على الطرق العامة، ماذا تعني لي هذه الرواسب؟","options":["قد تظل الرواسب المتبقية تتطلب من الصهريج عرض اللافتات، لذا يجب أن أبقيها معروضة كما لو كان محمّلاً.","بمجرد ضخّ الصهريج يُعتبر فارغاً، لذا يمكنني قانونياً إزالة جميع اللافتات والقيادة عائداً دون علامات.","الرواسب تهم فقط قائمة الفحص، لذا أدوّنها في دفتر السجل ولا حاجة لأي لافتات.","لأنه لا يُسلَّم أي شيء، تجعل الرواسب الحمولة غير خطرة ولا تنطبق صلاحية H/X بعد الآن."],"explanation":"تظل رواسب السائل الخطر المتبقية بعد التفريغ تُحتسب كحمولة، لذا يجب أن تبقى اللافتات المطلوبة معروضة."},"187":{"q":"أنا أقود صهريجاً أملس محمّلاً جزئياً بالسائل عبر منطقة إنشاءات على طريق سريع حيث يتوقف المرور وينطلق باستمرار، وقد ضاقت المسارات، ويوجّه المنظّمون الجميع عبر مخاريط ضيقة. نظراً لكيفية تصرّف حمولتي، ما هو التعديل الوحيد الأهم الذي ينبغي أن أجريه مقارنةً بقيادة شاحنة صندوقية فارغة عبر المنطقة نفسها؟","options":["التزم بحد سرعة منطقة العمل المعلن تماماً، لأن تلك السرعة قانونياً محسوبة بالفعل لتكون آمنة لكل مركبة، بما في ذلك الصهاريج المحمّلة.","قلّل سرعتي إلى ما دون حد منطقة العمل المعلن وزِد مسافة اتباعي، لأن اندفاع السائل يطيل مسافة توقفي ومركز ثقلي المرتفع يجعل الحركات المفاجئة خطرة.","حافظ على سرعتي ثابتة وقلّص المسافة عن المركبة أمامي كي لا يتمكن السائقون الآخرون من الاندماج وإجباري على فرملة قوية مسببة للاندفاع.","حافظ على سرعة الطريق السريع المعتادة حتى أصل فعلاً إلى منظّم، ثم افرمل بقوة في اللحظة الأخيرة لإبقاء المرور يتدفق بسلاسة خلفي."],"explanation":"يطيل اندفاع السائل مسافة التوقف ويجعل مركز الثقل المرتفع الحركات المفاجئة خطرة، لذا أبطئ إلى ما دون الحد المعلن بكثير واترك مسافة اتباع إضافية."},"188":{"q":"أنت تقود صهريجاً محمّلاً جزئياً وتدرك، في منتصف منعطف منحدر خروج ضيق على طريق سريع، أنك دخلته بسرعة كبيرة. غريزتك أن تضغط الفرامل بقوة لتقليل السرعة هناك في المنعطف. وفقاً للأسلوب الآمن لمركبات الصهاريج، ما النتيجة الأرجح للفرملة بقوة وأنت لا تزال في المنعطف؟","options":["يضغط انتقال الوزن الإطارات إلى أسفل بقوة أكبر، مما يزيد التماسك ويشدّ خطك عبر المنعطف","يدفع اندفاع السائل ذهاباً وإياباً الشاحنة باستقامة بلطف، مما يساعدها على الاستقرار والسير بسلاسة","قد يؤدي الجمع بين الفرملة القوية ومركز الثقل المرتفع للصهريج إلى رمي المركبة في انزلاق أو انقلاب","تقلّل الفرامل وحدها السرعة بأمان لأن حمولة الصهريج المنخفضة الكثيفة تبقيه ثابتاً بإحكام في المنعطف"],"explanation":"يمكن أن يؤدي الجمع بين مركز الثقل المرتفع للصهريج والفرملة القوية إلى فقدان التماسك ويسبب انزلاقاً أو انقلاباً."},"189":{"q":"أنا أقود صهريجاً أملس محمّلاً على منحدر طويل وحاد في منطقة هيل كنتري بتكساس. يستوي الطريق في الأسفل عند تقاطع مزدحم. أي نهج يمنحني أفضل تحكم في مركبة الصهريج أثناء النزول؟","options":["انقل إلى أعلى غيار يمكنني سحبه واستخدم فرامل الخدمة بخفة طوال الطريق نزولاً للحفاظ على سرعتي تحت السيطرة","ابقَ في وضع الحياد واسرِ بالقصور الذاتي لتوفير الوقود والتآكل، مطبّقاً الفرامل بقوة فقط إذا بدأت سرعتي تزداد كثيراً","اضغط الفرامل تشغيلاً وإيقافاً على دفعات طويلة كي يتسنى لها التبرّد وعدم ارتفاع حرارتها على المنحدر الطويل","اختر غياراً منخفضاً قبل بدء النزول كي تثبّت فرملة المحرك سرعتي، وطبّق ضغط فرامل ثابتاً ومتساوياً"],"explanation":"على المنحدر الطويل الحاد اختر غياراً منخفضاً قبل بدء النزول كي تثبّت فرملة المحرك سرعتك، ثم أضف ضغط فرامل ثابتاً ومتساوياً لمنع فقدان فعالية الفرامل."},"190":{"q":"أنا أقود صهريجاً أملس محمّلاً جزئياً بالسائل على طريق سريع في تكساس وسط حركة مرور منتظمة. المركبة أمامي شاحنة صندوقية جافة عادية ونتحرك بالسرعة نفسها. مقارنةً بكيفية اتباعي للمركبة نفسها لو كنت في شاحنة صندوقية جافة خاصة بي، كيف ينبغي أن أحدد مسافة اتباعي خلفها بهذه الحمولة الصهريجية؟","options":["احتفظ بمسافة أكبر مما أفعل عادة، لأن اندفاع السائل يطيل مسافة توقفي وقد يدفعني إلى الأمام بعد الفرملة","احتفظ بالمسافة نفسها كشاحنة جافة، لأنني متطابق مع سرعة المرور والطريق جاف","احتفظ بمسافة أقل من المعتاد كي لا يتمكن السائقون الآخرون من اقتحام الفجوة وإجباري على الفرملة فجأة","ابقَ قريباً من المصدّ أمامي كي أنجرف خلفه ولا أضطر إلى استخدام فراملي كثيراً على الطريق السريع المستوي"],"explanation":"يطيل اندفاع السائل مسافة التوقف وقد يدفع الشاحنة إلى الأمام بعد الفرملة، لذا احتفظ بمسافة اتباع إضافية وافرمل بلطف ومبكراً."},"191":{"q":"أنا أقود صهريجاً أملس (بلا حواجز) محمّلاً جزئياً على طريق سريع ذي مسارين عندما يندفع غزال فجأة إلى مساري على بُعد نحو 150 قدماً أمامي. غريزتي أن أدير المقود بشدة للانعطاف حوله. لماذا تلك حركة خاطئة، وماذا ينبغي أن أفعل بالمقود بدلاً من ذلك؟","options":["الانحراف الحاد السريع لا بأس به لأن غياب الحواجز في الصهريج الأملس يخمد في الواقع الحركة الجانبية ويبقي الشاحنة ثابتة","يمكن أن يحوّل التوجيه المفاجئ اندفاع السائل الجانبي القوي إلى انقلاب، لذا عليّ أن أوجّه بلطف بحركات سلسة ومضبوطة وأتجنب النفضات المفاجئة","التوجيه السريع آمن طالما أضغط الفرامل بقوة في اللحظة نفسها، لأن الفرملة القوية تثبّت الحمولة وتلغي أي اندفاع جانبي","عليّ أن أنفض المقود بأسرع ما يمكن لأن مركز الثقل المرتفع للصهريج يجعله أكثر ثباتاً ومقاومة للانقلاب أثناء المناورات السريعة"],"explanation":"في الصهريج الأملس المملوء جزئياً، يمكن أن يحوّل التوجيه المفاجئ اندفاع السائل الجانبي إلى انقلاب، لذا وجّه بلطف بحركات سلسة ومضبوطة."},"192":{"q":"أنا أقود صهريجاً ممتلئاً نحو النصف فقط وقد توقفت للتو توقفاً عادياً عند إشارة حمراء. من بين الآتي، ما هو الخطر الأكبر الذي ينبغي أن أكون مستعداً له بسبب هذه الحمولة الجزئية؟","options":["يمنحني الوزن الأخف تماسكاً أفضل، لذا يمكنني الفرملة في وقت متأخر مقارنةً بصهريج ممتلئ","تتيح المساحة الفارغة للحمولة أن تستقر، مما يقصّر مسافة توقفي الإجمالية","يندفع السائل ذهاباً وإياباً وقد يدفع الشاحنة إلى الأمام بعد أن أظن أنني توقفت","الصهريج نصف الفارغ لا يحمل أي خطر حقيقي طالما أن أغطية فتحات التفتيش محكمة الإغلاق"],"explanation":"في الصهريج المملوء جزئياً يندفع السائل ذهاباً وإياباً وقد يدفع الشاحنة إلى الأمام حتى بعد أن تظن أنك توقفت."},"193":{"q":"أنا أقود صهريجاً محمّلاً جزئياً بزيت التدفئة، وفي كل مرة أفرمل عند إشارة يظل السائل يدفع شاحنتي إلى الأمام بعد أن أظن أنني توقفت. يخبرني سائق أن هذا الاندفاع ذهاباً وإياباً يُقلَّل بميزة تصميمية مبنية داخل كثير من صهاريج الشحن. أي ميزة يصفها؟","options":["أسطح مفتوحة أعلى الصهريج تسمح للضغط بالخروج كي لا تتمكن الحمولة من الدفع للأمام","سطح داخلي أملس بلا جدران داخلية كي يتدفق السائل بحرية","مساحة فراغ أكبر تُترك في الأعلى كي يتسع للسائل الدافئ مجال للتمدد","الحواجز أو الجدران الداخلية ذات الثقوب المبنية داخل الصهريج لإبطاء السائل"],"explanation":"الحواجز هي جدران داخلية ذات ثقوب مبنية داخل الصهريج لإبطاء اندفاع السائل من الأمام إلى الخلف."},"194":{"q":"أنا أنقل الحليب في صهريج مخصص للأغذية، وألاحظ أن الحمولة تندفع بقوة من الأمام إلى الخلف في كل مرة أفرمل، أكثر بكثير من صهريج المواد الكيميائية الذي قدته الأسبوع الماضي. استناداً إلى كيفية بناء صهاريج الأغذية عادةً، لماذا تندفع حمولتي بهذا القدر؟","options":["صهاريج الأغذية عادةً ملساء (بلا حواجز) لأغراض النظافة، فلا يوجد بداخلها ما يبطئ الاندفاع ذهاباً وإياباً","صهاريج الأغذية عادةً مزوّدة بحواجز كثيفة، لكن الحواجز متباعدة جداً بحيث لا تتحكم في الاندفاع ذهاباً وإياباً","صهاريج الأغذية عادةً مضغوطة، والضغط الداخلي يدفع السائل للأمام في كل مرة تفرمل","صهاريج الأغذية عادةً مفتوحة الأعلى، فيدفع الهواء الداخل من الأعلى السائل للأمام عند الإبطاء"],"explanation":"صهاريج الأغذية عادةً ملساء بلا حواجز لتسهيل التنظيف، فلا يوجد بداخلها ما يبطئ الاندفاع ذهاباً وإياباً."},"195":{"q":"أنا أقود حمولة كاملة من السائل في شاحنة صهريج وأقترب من منعطف خروج على طريق سريع معلن عليه 35 ميلاً في الساعة. الرصيف جاف وشاحنتي تتعامل جيداً على الطريق المستقيم. بسبب كيفية تصرّف الصهريج المحمّل، ما هو الافتراض الأكثر أماناً الذي ينبغي أن أتبناه حول خطر الانقلاب في هذا المنعطف؟","options":["لا يمكن أن ينقلب الصهريج إلا إذا تجاوزت سرعة المنحدر المعلنة 35 ميلاً في الساعة","يعني مركز الثقل المرتفع أن الصهريج يمكن أن ينقلب حتى عند سرعة أقل من 35 ميلاً في الساعة المعلنة","الصهريج الممتلئ ثابت ولا ينقلب إلا على المنعطفات المبللة أو الجليدية","الانقلاب مصدر قلق فقط عندما يكون الصهريج فارغاً جزئياً ويندفع"],"explanation":"تركب الحمولة السائلة عالياً، مما يمنح الصهريج مركز ثقل مرتفعاً يمكن أن يقلبه حتى عند سرعات أقل من الحد المعلن."},"196":{"q":"أنا أنهي الفحص قبل الرحلة على مقطورة صهريجي عند منصة التحميل وأوشك على الخروج إلى الطريق السريع. من بين العناصر التي فحصتها للتو أعلى الصهريج، أي واحد منها يجب أن يكون مغلقاً ومثبّتاً فعلياً قبل أن أحرّك المركبة لمنع الانسكاب وإبقاء الحمولة محتواة؟","options":["جدران الحواجز الداخلية في الصهريج، كي لا تندفع الحمولة للأمام عند الفرملة","مساحة الفراغ في الأعلى، كي لا يتبقى للسائل الدافئ مجال للتمدد","أغطية فتحات التفتيش وصمامات الأبخرة/التنفيس، كي تكون مغلقة ومحكمة","ذراع الفرملة الطارئة، كي أتمكن من التوقف بشكل متحكم به في حركة المرور"],"explanation":"يجب أن تكون أغطية فتحات التفتيش وصمامات الأبخرة/التنفيس مغلقة ومحكمة قبل القيادة كي لا يتسرب السائل والبخار ويسبب انسكاباً."},"197":{"q":"أنا أقوم بالفحص قبل الرحلة على مقطورة صهريج قبل تحميل حمولة سائلة. أنا أفحص مضخة المنتج وخراطيمها. أي من هذه الحالات يعني أنه ينبغي ألا أبدأ عملية التحميل أو التفريغ؟","options":["المضخة في حالة عمل جيدة لكن غطاء فتحة التفتيش مفتوح أثناء التحميل","المضخة في حالة عمل جيدة وصمام تنفيس الأبخرة محكم الإغلاق","المضخة في حالة عمل جيدة ولا توجد تسربات عند وصلات الخراطيم","المضخة ليست في حالة عمل جيدة وتتسرب حول جلبتها"],"explanation":"يجب أن تكون مضخة التحميل/التفريغ في حالة عمل جيدة دون تسربات حول جلبتها، وإلا فيجب عدم بدء العملية."},"198":{"q":"أنا أقوم بالفحص قبل الرحلة على صهريجي قبل نقل سائل قابل للاشتعال، وأمرّ على قائمة معدات الطوارئ المطلوبة. أي من العناصر الآتية يجب أن يكون موجوداً وصالحاً للعمل كي تكون مركبتي قانونية للتشغيل؟","options":["طفّاية حريق مشحونة ومصنّفة بشكل صحيح","جهاز لاسلكي (CB) احتياطي للتواصل في حالات الطوارئ","مجموعة احتياطية من مفاتيح المركبة مخزّنة في المقصورة","حقيبة إسعافات أولية معتمدة من ولاية تكساس"],"explanation":"طفّاية الحريق المشحونة والمصنّفة بشكل صحيح هي معدات طوارئ مطلوبة يجب أن تكون موجودة وصالحة للعمل على المركبة."},"199":{"q":"لقد التقطت للتو صهريجاً محمّلاً جزئياً وأتجه إلى منحدر منعطف على طريق سريع بسرعة معلنة 35 ميلاً في الساعة. بالنظر إلى مركز الثقل المرتفع واندفاع السائل، أي نهج يمنحني أفضل هامش أمان؟","options":["اسلك المنحدر بسرعة 35 ميلاً في الساعة المعلنة تماماً، لأن تلك السرعة حُددت كالحد الآمن للمنعطف","قُد بسلاسة وببطء وبيقظة بسلوك المنحدر بسرعة أقل بكثير من 35 ميلاً في الساعة المعلنة مع التوجيه والفرملة بلطف","حافظ على وتيرة تدفق المرور المحيط كي لا أُصدَم من الخلف على منحدر الدخول","افرمل بقوة وفي وقت متأخر أسفل المنحدر، ثم سرّع بحزم لتثبيت الحمولة قبل المنعطف"],"explanation":"يجعل مركز الثقل المرتفع للصهريج واندفاع السائل قلبه سهلاً، لذا اسلك المنحدرات والمنعطفات بسرعة أقل بكثير من المعلنة مع التوجيه والفرملة بلطف."}},"doubles":{"0":{"q":"أحمل حالياً رخصة قيادة تجارية من الفئة A وأنقل بانتظام نصف مقطورة محمّلة واحدة. تريد شركتي الآن أن أسحب مجموعة من مقطورتين متصلتين بعربة محوّل في رحلات بين الولايات. قبل أن أتمكن قانونياً من قيادة هذه التركيبة في تكساس، أي مما يلي يجب أن أحصل عليه؟","options":["صلاحية المقطورات المزدوجة/الثلاثية (T)، لأن سحب أكثر من مقطورة واحدة يتطلبها","صلاحية الصهريج (N)، لأن عربة المحوّل تضيف خزان هواء إلى التركيبة","لا شيء إضافي، لأن رخصتي من الفئة A تغطي بالفعل أي عدد من المقطورات","صلاحية المواد الخطرة (H)، لأن مجموعات المقطورات المتعددة تُعامَل كحمولات زائدة الحجم"],"explanation":"يتطلب سحب أكثر من مقطورة واحدة صلاحية المقطورات المزدوجة/الثلاثية (T)، بغض النظر عن فئة رخصتك."},"1":{"q":"لقد انتقلت للتو من قيادة شاحنة فان واحدة بطول 53 قدمًا إلى سحب مجموعة من المقطورات المزدوجة على نفس الطريق السريع بين الولايات في تكساس الذي قدته لسنوات. وأنا أفكر في كيفية تصرف هذه الشاحنة مقارنة بمقطورتي الواحدة القديمة، أي عبارة يجب أن تحدد طريقة قيادتي؟","options":["تتبع المقطورتان مسارًا أضيق خلال المنعطفات، لذا يمكنني الحفاظ على سرعاتي القديمة الخاصة بالمقطورة الواحدة وتوقيت تغيير المسار","المجموعة أصعب في التحكم وأكثر عرضة للانقلاب، لذا يجب أن أوجّه بلطف وأبطئ السرعة قبل المنعطفات","نظرًا لأن الحمولة موزعة بين صندوقين، فإن الشاحنة أخف وزنًا بشكل عام وأبطأ بشكل ملحوظ في الاستجابة","مع إضافة مقطورة ثانية تزيد من الطول، تؤثر الرياح الجانبية على المجموعة بدرجة أقل بكثير مما كانت تؤثر على شاحنتي الواحدة"],"explanation":"المقطورات المزدوجة والثلاثية أقل ثباتًا وأكثر عرضة للانقلاب، لذا وجّه بلطف وأبطئ السرعة قبل المنعطفات."},"2":{"q":"أقوم بربط مقطورة ثانية محمّلة خلف مقطورتي الأمامية في الساحة. قبل أن أتمكن من سحب المجموعة، يجب أن أضع قطعة المعدات التي تحمل قضيب جرّها الخاص، والعجلة الخامسة، والفكوك القافلة، وخطوط الهواء، وسلاسل الأمان، بحيث تتمكن المقطورة الخلفية من الركوب عليها. أي مكوّن أقوم بوصله لربط المقطورة الثانية بالأولى؟","options":["مسمار الملك (الكينغ بين)، الذي يُقفل داخل العجلة الخامسة للمقطورة التي أمامه","الأيادي المتشابكة (غلاد هاندز)، التي تربط المقطورتين وتسمح للهواء بالوصول إلى الفرامل الخلفية","عربة التحويل (كونفرتر دولي)، التي تحمل العجلة الخامسة وتربط المقطورة التالية","خطّاف البينتل، الذي يثبّت فيه قضيب جر العربة لتثبيت المقطورات معًا"],"explanation":"تحمل عربة التحويل (كونفرتر دولي) العجلة الخامسة وتربط مقطورة بأخرى، ولها قضيب جرّها الخاص، وفكوك قافلة، وخطوط هواء، وسلاسل أمان."},"3":{"q":"أسحب مجموعة من المقطورات المزدوجة على الطريق السريع بين الولايات بسرعة الطريق السريع عندما ينعطف فجأة سيارة إلى مساري، فأدير المقود بقوة لتفاديها. تبقى الجرّار والمقطورة الأمامية منتصبتين وتتبعان المسار بشكل جيد، لكن عليّ توقّع ما يحدث خلفي. أي مما يلي هو النتيجة الأكثر احتمالًا لإدارة المقود السريعة تلك؟","options":["تُقفل فرامل المقطورة الخلفية وتجرّها في خط مستقيم، مما يساعد المجموعة بأكملها على الإبطاء والثبات","تضيف المقطورات الإضافية وزنًا منخفضًا قرب الأرض، لذا تقاوم المجموعة الانقلاب فعليًا بشكل أفضل من المقطورة الواحدة","تُدفع المقطورة الخلفية للأسفل على نظام التعليق وتستقر، مما يبقيها ثابتة خلال المناورة","تنحرف المقطورة الخلفية إلى الخارج بشكل أوسع بكثير من الجرّار ويمكن أن تحدث تأثير السوط وتنقلب"],"explanation":"تتسبب حركة التوجيه السريعة في التضخيم الخلفي، مما يجعل المقطورة الخلفية تنحرف بشكل أوسع بكثير من الجرّار وربما تنقلب."},"4":{"q":"أنت تسحب مجموعة من المقطورات المزدوجة على طريق سريع ريفي في تكساس بسرعة 55 ميلاً في الساعة عندما تنحرف فجأة مركبة إلى مسارك أمامك. لتقليل خطر التضخيم الخلفي (تأثير \"ضرب السوط\") الذي يقلب مقطورتك الخلفية، ماذا يجب أن تفعل؟","options":["وجّه بلطف وتدريجيًا مع رفع قدمك عن دواسة الوقود للحفاظ على تتبّع المقطورة الخلفية بسلاسة","قم بتصحيح توجيه واحد سريع وحازم لتجاوز الخطر قبل أن تتفاعل المقطورة الخلفية","افرمل بقوة وحافظ على إدارة مقود حادة للتوقف قبل المركبة المنحرفة","حافظ على سرعتك ووجّه بقوة حتى تبقى المقطورات في خط واحد خلف الجرّار"],"explanation":"لأن التضخيم الخلفي يزداد مع كل مقطورة، وجّه بلطف وتدريجيًا وخفّف السرعة للحفاظ على تتبّع المقطورة الخلفية بسلاسة."},"5":{"q":"لقد انتهيت للتو من ربط مجموعة من المقطورات المزدوجة وأنا أتفقد الشاحنة قبل الانطلاق. أفتح صمامات الإغلاق (الفصل) بين الجرّار والمقطورة الأمامية، وبين المقطورتين، حتى يصل الهواء إلى مؤخرة المجموعة. عندما أصل إلى مؤخرة المقطورة الأخيرة تمامًا، في أي وضع يجب أن يكون صمام الإغلاق ذاك حتى تكون المجموعة مهيّأة بشكل صحيح؟","options":["مفتوح، حتى يتنفّس هواء الخدمة بحرية ويمنع جرّ الفرامل الخلفية أثناء القيادة","مغلق، لأنه آخر صمام في الخط وترك مفتوحًا سيُفرّغ الهواء ويمنع النظام من بناء الضغط","مفتوح، تمامًا مثل كل صمام إغلاق آخر في المجموعة، حتى يبقى ضغط الهواء متساويًا عبر جميع المقطورات","مغلق فقط في المقطورات الثلاثية، لكنه مفتوح في المجموعة ذات المقطورتين لأن الهواء يتوقف ببساطة عند المحور الخلفي"],"explanation":"يجب أن يكون صمام الإغلاق في مؤخرة المقطورة الأخيرة تمامًا مغلقًا، وإلا سيتسرّب الهواء من الخلف ولن يتمكن النظام من بناء ضغط الفرامل."},"6":{"q":"لقد انتهيت للتو من ربط مجموعة من المقطورات المزدوجة وأقوم بفحص الهواء النهائي قبل الانطلاق على الطريق السريع. وأنا أتفقد الشاحنة، أفحص صمامات الإغلاق (الفصل) في مؤخرة كل مقطورة. أي إعداد للصمام صحيح حتى يصل هواء الخدمة والطوارئ فعليًا إلى فرامل مقطورتي الخلفية؟","options":["يجب أن تكون صمامات الإغلاق بين المقطورتين مغلقة بإحكام حتى يبقى ضغط الهواء محتبسًا في خزانات المقطورة الأمامية","يجب أن تُترك جميع صمامات الإغلاق في المجموعة، بما في ذلك الصمام في مؤخرة المقطورة الأخيرة تمامًا، مفتوحة للحفاظ على تنفّس الخطوط","يجب أن تكون صمامات الإغلاق بين المقطورتين مفتوحة حتى يتدفق الهواء للخلف ويصل إلى الفرامل على المقطورة الخلفية","يجب فصل صمامات الإغلاق عن الخط بالكامل حتى يتحرك الهواء بحرية بين المقطورتين"],"explanation":"يجب أن تبقى صمامات الإغلاق بين المقطورات مفتوحة حتى يتدفق الهواء حتى الخلف ويصل إلى الفرامل على كل مقطورة."},"7":{"q":"لقد ربطت للتو مقطورتي الثانية باستخدام عربة التحويل ووصّلت الأيادي المتشابكة وسلك الإضاءة. قبل أن أسحب هذه المجموعة من المقطورات المزدوجة خارج الساحة، أي فحص يؤكد أن ربطي قد أدّى وظيفته فعلًا وأن الشاحنة بأكملها ستتوقف عندما أضغط على الفرامل؟","options":["تأكّد من توقّف جرس تحذير انخفاض الهواء على لوحة القيادة عن الرنين بمجرد شحن النظام إلى ضغط القطع","تحقّق من أن خزان هواء العربة ممتلئ وأن فرامل النوابض على العربة قد تحرّرت","اختبر خطّاف البينتل بالشد وتأكّد من أن سلاسل الأمان بين العربة والمقطورة الأمامية متقاطعة","افتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الأخيرة وتأكّد من تدفق الهواء، ثم أغلقه"],"explanation":"للتأكد من وصول الهواء إلى الفرامل الخلفية، افتح صمام خط الطوارئ في مؤخرة المقطورة الأخيرة، وتحقّق من خروج الهواء، ثم أغلقه."},"8":{"q":"أقود مجموعة محمّلة من المقطورات المزدوجة على الطريق السريع بين الولايات وتباطأت حركة المرور أمامي فجأة. مقارنة بشاحنة المقطورة الواحدة التي أقودها عادة، كيف يجب أن أعدّل مسافة المتابعة وأين أبدأ بالفرملة؟","options":["أزيد مسافة المتابعة وأبدأ بالفرملة مبكرًا، لأن المجموعة الأطول والأثقل تحتاج إلى مساحة أكبر للتوقف والمناورة","أحافظ على نفس مسافة المتابعة التي أستخدمها للمقطورة الواحدة، لأن المقطورات تتشارك نظام فرملة واحدًا على نفس مصدر الهواء","أقلّل مسافة المتابعة لأن المقطورة الإضافية تضيف محاور فرملة تتيح للمجموعة التوقف في مساحة أقل","أحافظ على نفس مسافة المتابعة لكن أعتمد على فرامل المقطورة لإيقاف المجموعة في حوالي نصف المسافة المعتادة"],"explanation":"تحتاج المجموعة الأطول والأثقل من المقطورات المزدوجة أو الثلاثية إلى مساحة أكبر للتوقف، لذا زِد مسافة المتابعة وابدأ بالفرملة مبكرًا."},"9":{"q":"أسحب مجموعة من المقطورات المزدوجة على الطريق السريع بين الولايات عندما تنعطف فجأة سيارة أمامي، فأدير المقود لتفاديها. يبقى الجرّار مستقيمًا ومنتصبًا، لكنني أشعر بترنّح عنيف يندفع عبر الشاحنة خلفي. بسبب التضخيم الخلفي (تأثير \"ضرب السوط\")، أي وحدة في أكبر خطر للانقلاب؟","options":["المقطورة الأمامية، لأنها تحمل أثقل حمولة وتنعطف بأشد قوة خلف الجرّار مباشرة","المقطورة الخلفية (الأخيرة)، لأن حركة السوط تتضخّم وتجعلها تنحرف بأوسع قدر","الجرّار، لأن إدارة السائق السريعة للمقود تضرب محور التوجيه وعجلات الدفع أولًا","عربة التحويل، لأن محورها الواحد وقضيب جرّها القصير يجعلانها الحلقة الأضعف في المجموعة"],"explanation":"يضخّم التضخيم الخلفي حركة السوط على طول الخط، لذا تنحرف المقطورة الخلفية بأوسع قدر وهي الأكثر احتمالًا للانقلاب."},"10":{"q":"أقوم بربط عربة تحويل تحت المقطورة الثانية في مجموعتي المزدوجة. لقد قمت برجوع العربة إلى موضعها والآن أرفعها حتى تشتبك العجلة الخامسة وتنغلق الفكوك القافلة. لكي يكون هذا الربط آمنًا، يجب أن تنغلق الفكوك القافلة للعربة بإحكام حول أي مكوّن؟","options":["حول قضيب جر العربة نفسه حيث يلتقي بخطّاف البينتل للجرّار","حول حلقة سلسلة الأمان على إطار المقطورة الأمامية","حول مسمار الملك (الكينغ بين) أسفل المقطورة الخلفية","حول وصلات الأيادي المتشابكة التي تنقل الهواء إلى المقطورة الخلفية"],"explanation":"تنغلق فكوك العجلة الخامسة لعربة التحويل حول مسمار الملك (الكينغ بين) للمقطورة الخلفية لتحمّل الحمولة وتثبيت المقطورة بالعربة."},"11":{"q":"أقوم بربط مقطورة ثانية بعربة تحويل لرحلة مزدوجة من أماريلو. وأنا أوصّل كل شيء، أفكر في سبب أهمية كل جزء. من بين ما يلي، ما هو الغرض الفعلي من سلاسل الأمان على عربة التحويل؟","options":["تمنع قضيب جر العربة من الالتواء حتى تبقى العجلة الخامسة مستوية تحت حمولة ثقيلة","توفّر مسارًا احتياطيًا لضغط الهواء إلى المقطورة الخلفية إذا تسرّبت الأيادي المتشابكة","تؤرّض النظام الكهربائي للعربة حتى تبقى أضواء المقطورة ونظام الفرامل المانعة للانغلاق تعمل","تثبّت العربة بالمقطورة التي أمامها إذا تحرّر خطّاف البينتل أو فشل الربط"],"explanation":"سلاسل الأمان هي احتياطي ميكانيكي يبقي العربة متصلة بالمقطورة التي أمامها إذا تحرّر خطّاف البينتل أو فشل الربط."},"12":{"q":"أنقل مجموعة من المقطورات المزدوجة من مركز توزيع في تكساس، ويسلّمني طاقم الرصيف مقطورتين بحمولتين مختلفتين جدًا: واحدة محمّلة بشدة والأخرى شبه فارغة. قبل أن أربطهما بعربة التحويل، أي مقطورة يجب أن أضعها أولًا، خلف الجرّار مباشرة؟","options":["المقطورة الأثقل المحمّلة بالكامل تأتي أولًا، خلف الجرّار مباشرة، مع الأخف في المؤخرة.","المقطورة الأخف شبه الفارغة تأتي أولًا خلف الجرّار، مع الثقيلة في المؤخرة.","لا فرق أيهما يأتي أولًا، طالما أن عربة التحويل والأيادي المتشابكة موصولة بشكل صحيح.","قسّم الشحنة بالتساوي بين المقطورتين بحيث تحمل كل واحدة نفس الوزن، عندها لا يهم الترتيب."],"explanation":"ضع المقطورة الأكثر تحميلًا أولًا، خلف الجرّار مباشرة، مع المقطورات الأخف في المؤخرة لتقليل الانقلاب الناجم عن التضخيم الخلفي."},"13":{"q":"لقد ربطت للتو عربة التحويل والمقطورة الخلفية بمجموعتك من المقطورات المزدوجة. قبل أن تنطلق، تريد التأكد من أن الهواء يصل فعليًا إلى نظام فرامل المقطورة الخلفية. أي مما يلي يتحقق من ذلك بشكل صحيح؟","options":["اضغط على دواسة الفرامل عدة مرات واستمع لمؤشر ضغط الهواء وهو يرتفع في الكابينة","افتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الخلفية وتحسّس تدفق الهواء للخارج","اسحب الجرّار للأمام مقابل فرامل المقطورة المقفلة للتأكد من ثبات الوحدة الخلفية بإحكام","أغلق جميع صمامات الفصل بين المقطورتين وراقب تفعيل تحذير انخفاض الهواء"],"explanation":"افتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الأخيرة وتحسّس تدفق الهواء للخارج للتأكد من وصول الهواء حتى المؤخرة."},"14":{"q":"أنت تقود مجموعة من المقطورات المزدوجة وتدخل ساحة تسليم ضيقة، لكنك تجاوزت الرصيف والآن تحتاج إلى إعادة تموضع الشاحنة عدة أقدام للخلف. أي مما يلي هو أفضل وصف لموقفك فيما يتعلق بالرجوع للخلف؟","options":["رجوع المقطورات المزدوجة يكون تقريبًا مثل رجوع مقطورة واحدة، لذا فقط أدر المقود عكس الاتجاه الذي تريد أن تذهب إليه المؤخرة.","الرجوع جيد طالما أبقيت صمامات الإغلاق لعربة التحويل مغلقة حتى لا تنحرف المقطورة الخلفية.","رجوع مجموعة من المقطورات المزدوجة صعب للغاية ويجب تجنّبه؛ إذا اضطررت لإعادة التموضع، افصل المقطورتين وحرّكهما بشكل منفصل.","الرجوع غير قانوني مع المقطورات المزدوجة في كل ولاية، لذا يجب أن تتصل بعامل ساحة لتحريك الشاحنة نيابة عنك."],"explanation":"لا يمكن رجوع المقطورات المزدوجة بأمان لأن العربة تضيف نقطة محورية ثانية تطويها على الفور تقريبًا، لذا افصل المقطورتين وأعد تموضعهما بشكل منفصل."},"15":{"q":"أقوم بتفكيك مجموعة من المقطورات المزدوجة في الساحة وأحتاج إلى سحب عربة التحويل من تحت المقطورة الخلفية. لا يزال الجرّار والمقطورة الأمامية مربوطين والهواء مشحون. قبل أن أزحف للخلف لتحرير الفكوك القافلة للعجلة الخامسة وفصل خطّاف البينتل، ما هو أول شيء يجب أن أفعله لمنع المقطورة الخلفية من السقوط أو التدحرج؟","options":["اسحب الجرّار والمقطورة الأمامية للأمام بضع أقدام حتى تنزلق العربة بحرية، ثم سِر للخلف لدعم المقطورة الخلفية","افتح صمامات الإغلاق (الفصل) في مؤخرة المقطورة الخلفية لتفريغ الهواء من العربة قبل فصلها","اقفص فرامل النوابض للعربة وفرّغ وسائد الهواء في نظام التعليق بالكامل حتى تستقر المقطورة الخلفية على إطارها","أنزل قاعدة الهبوط للمقطورة الخلفية حتى تحمل الوزن، ثم ثبّت عجلاتها بالكتل قبل تحرير العربة"],"explanation":"قبل تحرير العربة، أنزل قاعدة الهبوط للمقطورة الخلفية حتى تحمل الوزن وثبّت عجلاتها بالكتل حتى تبقى المقطورة مدعومة ولا يمكنها التدحرج."},"16":{"q":"أقوم بربط عربة تحويل لإضافة مقطورة ثانية إلى مجموعتي المزدوجة. بعد تأمين خطّاف البينتل وسلاسل الأمان، أمدّ يدي إلى الأيادي المتشابكة لإجراء الوصلة التالية. عندما أوصّل هذه الأيادي المتشابكة، ما الذي أوصّله فعليًا بين الوحدات؟","options":["خطّي هواء الخدمة والطوارئ اللذين ينقلان الهواء بين الوحدات","سلك الإضاءة الكهربائي الذي يشغّل أضواء المقطورة الخلفية","سلاسل الأمان التي تشكّل احتياطًا لوصلة خطّاف البينتل","خطوط إمداد الوقود الممتدة من الجرّار إلى المقطورة"],"explanation":"الأيادي المتشابكة هي أجهزة الربط التي تصل خطّي هواء الخدمة والطوارئ بين الوحدات لنقل الهواء إلى الفرامل بعد العربة."},"17":{"q":"أثناء ربط المقطورة الثانية في مجموعتي المزدوجة، أوصّل عن طريق الخطأ أيادي الخدمة والطوارئ المتشابكة بالوصلات الخاطئة، فأعكس خطوط الهواء. لا ألاحظ ذلك حتى أبدأ بالتحرك. بناءً على هذا الخطأ، ماذا يجب أن أتوقع من فرامل المقطورة الخلفية؟","options":["ستنطبق تلقائيًا وتقفل المقطورة الخلفية حتى أصحّح الخطوط","لن تتلقّى الهواء عبر النظام الصحيح وقد تفشل في العمل عندما أحتاجها","ستعمل بشكل طبيعي لأن خزان هواء العربة لا يزال يغذّي كلا الخطين بالتساوي","ستصبح أكثر عدوانية، وتمسك بقوة أكبر من فرامل المقطورة الأمامية"],"explanation":"عكس الأيادي المتشابكة يوجّه الهواء إلى النظام الخاطئ، لذا لا تحصل فرامل المقطورة على إمداد الهواء الصحيح أبدًا وقد تفشل في الانطباق عند الحاجة."},"18":{"q":"أنت تنقل مجموعة من المقطورات المزدوجة على طريق سريع بين الولايات في تكساس عندما يبدأ مطر ثابت ويصبح الطريق زلقًا. مقارنة بقيادة نفس الطريق في جرّار-مقطورة واحد جاف، كيف يجب أن تعدّل قيادتك لهذه الظروف؟","options":["حافظ على سرعتك المعتادة على الطريق السريع لكن اضغط على الفرامل بشكل متقطّع مبكرًا حتى لا تدفعك المقطورة الخلفية للأمام","حافظ على مسافة المتابعة المعتادة لأن المقطورات الإضافية تضيف وزنًا يحسّن جر إطاراتك على الرصيف المبلل","خفّض سرعتك أكثر مما تفعل عادة وافتح مسافة متابعة إضافية لتعويض انخفاض الجر والطول المضاف","حافظ على سرعتك وقم بضغطة فرملة واحدة حازمة وقوية قبل وقت كافٍ من أي تباطؤ لتثبيت المقطورات"],"explanation":"أبطئ أكثر من المعتاد وافتح مسافة متابعة إضافية لتعويض انخفاض الجر والطول المضاف ونقاط المحور الإضافية للمقطورات المزدوجة."},"19":{"q":"أسحب مجموعة من المقطورات المزدوجة على الطريق السريع بين الولايات بسرعة الطريق السريع عندما تنعطف فجأة سيارة إلى مساري، وغريزتي هي أن أشدّ المقود بقوة لتفاديها. لماذا يكون هذا التصرف بالذات أخطر شيء يمكن أن أفعله بهذه الشاحنة؟","options":["لأن المقطورات الإضافية تجعل مجموعة المقطورات المزدوجة تتوقف أسرع بشكل ملحوظ، لذا فإن انحرافًا قويًا سيخلّ بمسافة متابعتي ويسبّب اصطدامًا من الخلف","لأن التوجيه المفاجئ آمن عمومًا في مجموعة مزدوجة، لكن الجرّار والمقطورة الأمامية فقط يستجيبان، تاركين المقطورة الخلفية خلفي في مساري القديم","لأن المجموعة المزدوجة أكثر ثباتًا من المقطورة الواحدة، لذا فإن الإدخال السريع يهدر أفضل فرصة لي للفرملة بقوة والتوقف بشكل مستقيم بدلًا من ذلك","لأن التضخيم الخلفي يعني أن إدخال التوجيه السريع يجعل المقطورة الخلفية تنحرف بشكل أوسع بكثير من الجرّار، ويمكن أن تنقلب حتى وكابينتي تبقى منتصبة"],"explanation":"بسبب التضخيم الخلفي (ضرب السوط)، يجعل إدخال التوجيه السريع المقطورة الخلفية تنحرف بشكل أوسع بكثير من الجرّار ويمكن أن تنقلب بينما تبقى الكابينة منتصبة."},"20":{"q":"أقوم بربط عربة تحويل لسحب مقطورة ثانية. أُرجع العربة إلى مؤخرة المقطورة التي أمامها وأنظر إلى خطّاف البينتل المثبّت على إطار تلك المقطورة الأمامية. أي جزء من العربة صُمّم خطّاف البينتل هذا لالتقاطه وقفله حتى تُسحب العربة بواسطة المقطورة التي أمامها؟","options":["العين في نهاية قضيب جر العربة (عين قضيب الجر)","مسمار الملك (الكينغ بين) فوق العجلة الخامسة للعربة","حامل تثبيت خزان هواء العربة","الفكوك القافلة داخل العجلة الخامسة للعربة"],"explanation":"ينغلق خطّاف البينتل على الإطار الخلفي للمقطورة التي أمامها حول العين في نهاية قضيب جر العربة (عين قضيب الجر) لسحبها."},"21":{"q":"أقوم بفحص ما قبل الرحلة على مجموعة من المقطورات المزدوجة وألاحظ أن عربة التحويل لا تحتوي على نظام فرامل مانع للانغلاق. تخبرني الورشة أن العربة صُنعت في أوائل عام 1997. أي عبارة تفسّر بشكل صحيح ما إذا كانت هذه العربة قانونية للاستخدام بدون نظام الفرامل المانعة للانغلاق؟","options":["إنها قانونية، لأن شرط نظام الفرامل المانعة للانغلاق ينطبق فقط على العربات المصنوعة في عام 2005 أو بعده.","إنها قانونية، لأن نظام الفرامل المانعة للانغلاق مطلوب فقط على عربات التحويل المصنوعة في 1 مارس 1998 أو بعده.","إنها غير قانونية، لأن كل عربة تحويل على الطريق اليوم مطلوب أن تحتوي على نظام فرامل مانع للانغلاق بغض النظر عن تاريخ الصنع.","إنها قانونية، لأن قاعدة نظام الفرامل المانعة للانغلاق تنطبق فقط على العربات المصنوعة في عام 1990 أو بعده."],"explanation":"نظام الفرامل المانعة للانغلاق مطلوب فقط على عربات التحويل والمقطورات المصنوعة في 1 مارس 1998 أو بعده، لذا يمكن للوحدات الأقدم العمل قانونيًا بدونه."},"22":{"q":"أنقل مجموعة من المقطورات المزدوجة بسرعة الطريق السريع عندما ألاحظ أن مسار مخرجي يبعد مسارًا واحدًا إلى اليمين ويقترب بسرعة. بالنظر إلى كيفية تفاعل المقطورة الخلفية مع توجيهي، أي نهج هو الطريقة الأكثر أمانًا لإجراء تغيير المسار هذا؟","options":["قم بنقرة واحدة سريعة وحاسمة للمقود حتى تتجاوز الشاحنة بأكملها خط المسار قبل المخرج","افرمل بقوة لتقليل السرعة أولًا، ثم انقل الشاحنة بسرعة إلى المسار التالي وأنت مبطئ السرعة","ابدأ مبكرًا وانتقل تدريجيًا بحركة بطيئة وتدريجية، تاركًا مساحة كافية حول الشاحنة","وجّه بحدة لكن حافظ على ثبات الجرّار، لأن المقطورات ستتبع ببساطة مسار الجرّار"],"explanation":"مع المقطورات المزدوجة، وجّه بلطف وابدأ تغيير المسار مبكرًا، تاركًا مساحة كافية، لأن التوجيه المفاجئ يسبّب التضخيم الخلفي لتأثير ضرب السوط."},"23":{"q":"أسحب مجموعة من المقطورات المزدوجة وأقترب من منحدر مخرج على الطريق السريع بين الولايات ينعطف أضيق مما توقعت. أحمل سرعة كبيرة جدًا وأنا أدخل المنعطف. من بين ما يلي، ما هو أكبر خطر أواجهه إذا أخذت هذا المنعطف بسرعة كبيرة؟","options":["ستفقد محاور الدفع لديّ الجر وسينطوي الجرّار للأمام قبل أن تتفاعل أي مقطورة","ستفرط فرامل مقطورتي في السخونة وتضعف، تاركة إياي غير قادر على الإبطاء للمنحدر التالي","ستحتك إطاراتي الأمامية وتتآكل بشكل غير متساوٍ، مما يقلل من عمر محور التوجيه","سيجعل التضخيم الخلفي المقطورة الخلفية تنحرف بشكل واسع ويقلبها حتى لو بقي الجرّار منتصبًا"],"explanation":"يجعل التضخيم الخلفي (ضرب السوط) المقطورة الخلفية تنحرف بشكل أوسع بكثير ويمكن أن يقلبها حتى وهي الجرّار يبقى منتصبًا."},"24":{"q":"لقد ربطت للتو عربة التحويل بالمقطورة الثانية في مجموعتي المزدوجة. أغلقت الفكوك القافلة حول مسمار الملك (الكينغ بين) وأستطيع سماع أن الوصلة تبدو متينة. قبل أن أصعد إلى الكابينة وأنطلق خارج الساحة، ما هي الطريقة الصحيحة للتحقق من أن الربط قد اشتبك فعليًا؟","options":["ضع الجرّار في الترس المنخفض وتقدّم للأمام بلطف مقابل الفكوك المقفلة للتأكد من ثباتها قبل تحرير الفرامل","اسحب الشاحنة مباشرة إلى الطريق على الفور، لأن النقرة المسموعة أثبتت بالفعل أن الفكوك مقفلة","أطلق البوق مرتين كإشارة إلى أن خطوة الربط من الفحص قد انتهت","علّم الوحدة المربوطة حديثًا بالطلاء حتى يعرف السائق التالي أنها فُحصت اليوم"],"explanation":"مع ضبط فرامل المقطورة، تقدّم بالجرّار للأمام بلطف في الترس المنخفض مقابل الفكوك المقفلة؛ إذا ثبتت، فإن الربط آمن."},"25":{"q":"أحمل حاليًا تصريح المقطورات المزدوجة وأسحب مقطورتين، لكن المرسل يريد أن يكلّفني برحلة ثلاثية تنقل ثلاث مقطورات. مقارنة بالمجموعة ذات المقطورتين التي اعتدت عليها، كيف يجب أن أتوقع أن تتصرف مجموعة من ثلاث مقطورات على الطريق السريع؟","options":["تقريبًا مثل المقطورات المزدوجة، لأن كل مقطورة مربوطة بعربة تحويل مطابقة","أصعب حتى من المقطورات المزدوجة، لأن المقطورة المضافة تزيد من الطول وتجعل تأثير ضرب السوط يدفع المقطورة الخلفية إلى انحراف أوسع","أسهل من المقطورات المزدوجة، لأن توزيع الحمولة على ثلاث مقطورات يقلل من خطر الانقلاب","لا يختلف عن المقطورات المزدوجة بمجرد أن أضع المقطورة الأكثر تحميلًا أولًا في الصف"],"explanation":"كل مقطورة مضافة تزيد من الطول وتكثّف تأثير ضرب السوط، لذا تجعل المجموعة الثلاثية مقطورتها الخلفية تنحرف بشكل أوسع وأصعب في التحكم من المزدوجة."},"26":{"q":"أقوم بفحص ما قبل الرحلة لمجموعة مقطورات مزدوجة، وأصل إلى عربة الوصل (الدوللي) الموجودة بين المقطورتين. أريد أن أفحصها بنفس الدقة التي أفحص بها أي جزء آخر من الشاحنة. أي مجموعة من العناصر التالية يجب أن أفحصها على هذه العربة؟","options":["السلاسل الأمنية وخطاف الوصل (البينتل) فقط، لأن العربة ليس لها أجزاء عاملة خاصة بها","العجلة الخامسة وفكي القفل فقط، لأن العربة تشترك في كل شيء آخر مع القاطرة","إطاراتها وأضواؤها وخطوط الهواء فيها، بنفس الطريقة التي أفحصها بها على أي جزء آخر من المركبة","لا شيء على العربة نفسها، بل فقط فرامل المقطورة الأمامية وحمولة المقطورة الخلفية"],"explanation":"عربة الوصل (الدوللي) جزء حقيقي من التركيبة، لذا افحص إطاراتها وأضواءها وخطوط الهواء فيها تماماً كما تفعل مع أي جزء آخر من المركبة."},"27":{"q":"كُلِّفتُ بقيادة مجموعة مقطورات ثلاثية لأول مرة. قبل الخروج من الساحة، أمشي بطول الشاحنة لأعدّ كل مقطورة خلف القاطرة لأعرف كم عربة وصل وكم صمام إغلاق سيتعين عليّ فحصها. كم مقطورة يجب أن أتوقع وجودها في المجموعة الثلاثية؟","options":["مقطورتان، لأن العربة في المنتصف تُحسب كالوحدة الثالثة خلف القاطرة","مقطورة واحدة، لأن \"الثلاثية\" تشير إلى المحاور الثلاثة على المقطورة الواحدة","خمس مقطورات، بعدّ كل مقطورة بالإضافة إلى عربات الوصل بينها","ثلاث مقطورات، موصولة في خط واحد خلف القاطرة"],"explanation":"المجموعة الثلاثية هي بحكم التعريف ثلاث مقطورات موصولة في خط واحد خلف القاطرة."},"28":{"q":"كلما زاد عدد المقطورات التي تجرّها، أصبح إيقاف الشاحنة ___:","options":["أسهل","أصعب","أسرع","أخف"],"explanation":"المزيد من المقطورات يعني المزيد من الوزن والطول، لذا يصبح إيقافها أصعب."},"29":{"q":"أقوم بفحص ما قبل الرحلة لمجموعة مقطورات مزدوجة قبل الخروج من الساحة. وأنا أمشي حول الشاحنة، أريد التأكد من الشيء الوحيد الذي يؤكد لي مباشرةً أن كل مقطورة آمنة للقيادة على الطريق. أي نتيجة يجب أن أكون متأكداً منها أكثر من غيرها قبل أن أصعد وأقود؟","options":["أن كل مقطورة وعربة الوصل موصولة بإحكام، مع إغلاق فكي القفل وإقفالهما حول مسامير الارتكاز (الكينغ بين)","أن كلتا المقطورتين محمّلتان بنفس الوزن تماماً حتى تسير الشاحنة بشكل متوازن على الطريق","أن المقطورة الأخف والأقل تحميلاً موصولة أولاً، مباشرةً خلف القاطرة","أن جميع صمامات الإغلاق بين المقطورات وفي مؤخرة المقطورة الأخيرة متروكة مفتوحة بالكامل"],"explanation":"قبل قيادة المقطورات المزدوجة، تأكد من أن كل مقطورة وعربة الوصل موصولة بإحكام مع إغلاق فكي القفل وإقفالهما حول مسامير الارتكاز."},"30":{"q":"انتهيت للتو من وصل عربة الوصل ومقطورة ثانية بشاحنتي. قبل الخروج من الساحة، أريد التأكد من أن نظام الهواء الاحتياطي (الطوارئ) مُعدّ بشكل صحيح لهذه المجموعة المزدوجة. أي عبارة تصف إلى أين يجب أن يصل هواء الطوارئ قبل أن أكون آمناً للقيادة؟","options":["يحتاج فقط للوصول إلى المقطورة الأمامية، لأنها تحمل الحمولة الأثقل مباشرةً خلف القاطرة","يجب أن يصل إلى كل مقطورة في المجموعة، حتى تعمل الفرامل في جميعها قبل أن أقود","لا يحتاج للوصول إلى أي مقطورة حتى أقوم بأول توقف مفاجئ على الطريق","يحتاج فقط للوصول إلى مقصورة القاطرة حتى يتوقف صفير التحذير في لوحة القيادة"],"explanation":"يجب أن يصل هواء الطوارئ (الاحتياطي) إلى كل مقطورة في المجموعة حتى تعمل الفرامل في جميعها، ويُتحقق من ذلك بفتح صمام الإغلاق في مؤخرة المقطورة الأخيرة."},"31":{"q":"أقوم بتجميع مجموعة مقطورات مزدوجة في الساحة. القاطرة موصولة بالمقطورة الأولى، وأحتاج إلى إضافة المقطورة الثانية باستخدام عربة الوصل. عندما أضع عربة الوصل لإجراء هذا الاتصال، أين يكون موضعها في التركيبة؟","options":["خلف المقطورة الثانية، حتى يتمكن خطاف الوصل فيها من الإمساك بمؤخرة المجموعة","بين القاطرة والمقطورة الأولى لتوزيع الحمولة بالتساوي","أمام المقطورة الثانية، حتى تتصل عجلتها الخامسة بمسمار ارتكاز تلك المقطورة","تحت مؤخرة المقطورة الأولى، راكبةً مباشرةً على محاور المقطورة الأولى"],"explanation":"تُوضع عربة الوصل أمام المقطورة الثانية حتى تتصل عجلتها الخامسة وفكا القفل بمسمار ارتكاز تلك المقطورة."},"32":{"q":"أقوم بفصل المقطورة الخلفية من مجموعتي المزدوجة. فصلتُ بالفعل خطوط الهواء والكابل الكهربائي لعربة الوصل، وأنا مستعد لإنزال الأرجل الداعمة للمقطورة الخلفية. قبل أن أسحب المسمار وأحرر تلك المقطورة، إلى أي مدى يجب أن أنزل الأرجل الداعمة؟","options":["حتى المنتصف تقريباً فقط، حتى تستقر المقطورة بلطف بمجرد أن تبتعد العربة","اتركها مرفوعة بالكامل ودع عربة الوصل تحمل وزن المقطورة أثناء خروجي","فقط حتى تلمس القاعدتان الرصيف، مع إبقاء كامل الوزن مرتكزاً على العربة","حتى الأسفل تماماً حتى تدعم الأرجل الداعمة كامل وزن المقطورة بإحكام"],"explanation":"أنزل الأرجل الداعمة حتى الأسفل تماماً بحيث تدعم كامل وزن المقطورة بإحكام قبل أن تسحب المسمار وتُخرج العربة."},"33":{"q":"حصلتُ للتو على تصريح المقطورات المزدوجة/الثلاثية ووصلتُ مقطورة ثانية خلف قاطرتي لأول مرة. مقارنةً بقيادة مقطورة واحدة، ما الذي يجب أن أتوقع أن تمنحني إياه هذه التركيبة بقدر أكبر عند خروجي إلى الطريق السريع؟","options":["طولاً إجمالياً أكبر ونقاطاً عمياء أكثر يجب أن أتتبعها باستمرار أثناء الانعطاف وتغيير المسارات","ثباتاً أكبر عند السرعة العالية، بحيث تكون التصحيحات السريعة في التوجيه أكثر أماناً من المقطورة الواحدة","قوة كبح أكبر، تتيح لي التوقف في مسافة أقصر مما أستطيع بمقطورة واحدة","قدرة على المناورة أكبر في الأماكن الضيقة، مما يسهّل رجوع المجموعة إلى الرصيف"],"explanation":"المقطورات المزدوجة والثلاثية أطول ولها نقاط عمياء أكثر، لذا يجب أن تراقب مناطق أكثر حول الشاحنة عند الانعطاف وتغيير المسارات."},"34":{"q":"أقود مجموعة مقطورات مزدوجة فارغة عبر طريق سريع مستوٍ في غرب تكساس عندما تضرب الشاحنة رياح جانبية قوية وثابتة من الجانب. أي استجابة تعكس بشكل أفضل كيف يجب أن أتعامل مع الرياح؟","options":["الرياح تؤثر على القاطرة فقط، لذا أحافظ على سرعتي على الطريق السريع وأمسك المقود بإحكام أكثر قليلاً","يمكن للرياح أن تدفع الشاحنة الخفيفة جانبياً، لذا أخفف السرعة وأوجّه بسلاسة للبقاء في مساري","تعمل المقطورات كشراع يسحب الشاحنة للأمام، لذا أرفع قدمي عن دواسة الوقود وأنزلق خلالها","الرياح الجانبية تضغط الإطارات نحو الأسفل وتزيد قدرتي على التماسك، لذا يمكنني المتابعة بسرعتي المعتادة"],"explanation":"يمكن للرياح أن تدفع الشاحنة الخفيفة جانبياً، لذا خفّف السرعة ووجّه بسلاسة بتحريكات تدريجية للبقاء في مسارك."},"35":{"q":"أقوم بوصل مقطورتي الثانية بعربة الوصل في ساحة بتكساس. أثناء توصيل وصلات الهواء (غلاد هاندز) وتوصيل كابل الأضواء، يذكّرني شريكي بوضع خطوط الهواء والكهرباء بشكل صحيح قبل التقدّم للأمام. أي مما يلي يجب أن أحرص على ألّا أدع يحدث لتلك الخطوط؟","options":["تركها متدلية بشكل مرتخٍ بحيث يكون هناك ارتخاء كافٍ لامتصاص المنعطفات الحادة","تركها تمتد بطول قضيب الهيكل الخارجي حيث يسهل رؤيتها","تركها تُجرّ على الأرض أو تتشابك معاً أثناء حركة الشاحنة","تركها ملفوفة بإحكام بمحاذاة العربة لإبقائها قصيرة"],"explanation":"ثبّت خطوط الهواء والكهرباء بحيث لا يمكن أن تُجرّ أو تتشابك أو تنحشر، لأن ذلك قد يقطع الهواء عن الفرامل أو الطاقة عن الأضواء."},"36":{"q":"أقود مجموعة مقطورات مزدوجة والرصيف الوحيد المتاح موجود في أقصى طرف ساحة ضيقة تتطلب مني إرجاع الشاحنة كاملةً إلى المكان. لم يسبق لي أن أرجعتُ مقطورات مزدوجة. وفقاً لإرشادات إدارة السلامة العامة في تكساس (DPS)، ما أفضل طريقة للتعامل مع هذا الموقف؟","options":["أرجع بسرعة وثقة حتى لا يتاح للمقطورات وقت للانحراف عن الاستقامة","اضبط مرآتيك على نطاق واسع، وأبقِ كلتا يديك في أسفل المقود، وأرجع ببطء مع مراقبة المقطورة الخلفية","قم بتصحيح حاد في التوجيه مبكراً لإعادة الشاحنة إلى الاستقامة، ثم استقم","تجنب إرجاع المجموعة قدر الإمكان، أو استعن بموجّه ليرشدك إذا لم تستطع"],"explanation":"لا يمكن إرجاع مجموعة المقطورات المزدوجة بأمان، لذا تجنب إرجاعها كلما أمكن، واستعن بموجّه ليرشدك إن اضطررت."},"37":{"q":"أقوم بتوصيل عربة الوصل لإضافة مقطورة ثانية، وقد ثبّتُّ بالفعل خطاف الوصل وفحصتُ السلاسل الأمنية المتقاطعة. الآن أحتاج إلى إيصال الهواء إلى العربة والمقطورة خلفها. أي وصلة على العربة تنقل ذلك الهواء إلى المقطورة الأمامية؟","options":["وصلات الهواء (غلاد هاندز)، التي تربط خطوط هواء العربة بالمقطورة الأمامية","كابل الأضواء الكهربائي، الذي يغذّي كلاً من الطاقة والهواء إلى المقطورة الأمامية","السلاسل الأمنية، التي تنقل الهواء بمجرد إقفال خطاف الوصل","فكا قفل العجلة الخامسة، اللذان يُحكمان مسار الهواء إلى المقطورة الأمامية"],"explanation":"تتصل خطوط هواء العربة بالمقطورة الأمامية عبر وصلات الهواء (غلاد هاندز)، التي تربط خطوط فرامل الهواء دون تقاطع."},"38":{"q":"أقود مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات عندما تقطع سيارة الطريق أمامي، فأقوم غريزياً بتصحيح سريع واحد في التوجيه. ومع أن قاطرتي ومقطورتي الأمامية بقيتا مستقيمتين، شعرتُ بالمقطورة الخلفية تندفع بقوة إلى الجانب وكادت تنقلب. عندما أبلّغ مدربي بذلك، ما الخاصية الفيزيائية للمقطورات المزدوجة التي يجب أن أحددها كسبب لكون المقطورة الخلفية هي الأكثر عرضة للانقلاب؟","options":["العدد الأكبر من المحاور تحت المقطورة الخلفية الذي يمنحها تماسكاً وثباتاً أكبر","الطول الإضافي للتركيبة والتضخيم الخلفي، أو تأثير \"طقطقة السوط\"","التحميل الأخف الذي وضعته في المقطورة الأمامية مقارنةً بالمقطورة الخلفية","مركز الثقل الأعلى الناتج عن عربة الوصل بين المقطورتين"],"explanation":"التضخيم الخلفي، أي تأثير طقطقة السوط، يجعل المقطورة الخلفية تتأرجح أبعد بكثير من القاطرة بعد حركة توجيه سريعة وقد يقلبها."},"39":{"q":"أقود مجموعة مقطورات مزدوجة على طريق سريع من أربعة مسارات والمرور أمامي يتباطأ. ألاحظ أنني سمحت للفجوة بين شاحنتي والسيارة أمامي بأن تتقلص إلى نفس مسافة الاتباع التي كنت أستخدمها عندما قدتُ شاحنة مستقيمة. لماذا من المهم أن أحافظ على مساحة مفتوحة أكبر حول تركيبتي الطويلة مما أفعل مع مركبة أقصر؟","options":["حتى أتمكن قانونياً من السير أسرع من بقية المرور وأعوّض الوقت الضائع في الرحلات الطويلة","حتى أتمكن من السير قريباً خلف شاحنة أخرى لتوفير الوقود وتقليل مقاومة الرياح","حتى يكون لدي متسع كافٍ للتوقف والمناورة، لأن الشاحنة الأطول تحتاج إلى مسافة أكبر للقيام بكليهما بأمان","حتى أتمكن من تجاوز الإشارة عند تغيير المسارات لأن السائقين القريبين يمكنهم رؤية مقطوراتي بالفعل"],"explanation":"تحتاج الشاحنة الأطول إلى مسافة أكبر للتوقف وتمسح مساراً أعرض، لذا حافظ على وسادة مساحة أكبر للتوقف والمناورة بأمان."},"40":{"q":"حصلتُ للتو على تصريح المقطورات المزدوجة/الثلاثية وأخطط لرحلة طويلة تعبر عدة حدود بين الولايات وأنا أجرّ مجموعة من ثلاث مقطورات. قبل مغادرة الساحة، ما الذي يحدد ما إذا كان بإمكاني تشغيل هذه المقطورات الثلاثية قانونياً في كل مرحلة من رحلتي؟","options":["المقطورات الثلاثية قانونية على جميع الطرق تقريباً على مستوى البلاد بمجرد حصولك على التصريح الفيدرالي للمقطورات المزدوجة/الثلاثية، لذا فالمسار لا يهم","يمكن تشغيل المقطورات الثلاثية في أي مكان طالما تبقيها بعيدة عن الطريق خلال ساعات الليل وضعف الرؤية","المقطورات الثلاثية ممنوعة فعلياً على الطرق العامة دائماً، لذا يجب تفكيك المجموعة قبل أي سفر بين الولايات","المقطورات الثلاثية قانونية فقط على أجزاء الرحلة التي يسمح بها قانون الولاية المعنية، لذا يجب أن تتحقق من كل ولاية تمرّ بها"],"explanation":"المقطورات الثلاثية قانونية فقط حيث يسمح بها قانون كل ولاية، لذا تحقق من قانون كل ولاية تمرّ بها، فالتصريح وحده لا يلغي قيود الولايات."},"41":{"q":"أقود مجموعة مقطورات مزدوجة وأقترب من منعطف ضيق إلى اليمين على شارع مدينة ضيق. عجلات المقطورة الخلفية تنحرف إلى الداخل عن المسار الذي تتبعه قاطرتي. لإدارة الشاحنة كاملةً حول الزاوية دون أن تتسلق المقطورة الخلفية الرصيف أو تصطدم به، ماذا يجب أن أفعل؟","options":["أتسع أكثر في المنعطف وأستمر في مراقبة مسار المقطورة الخلفية في مرآتيّ بينما تنحرف العجلات الخلفية","أبدأ المنعطف مبكراً وأقطعه بحدة حتى يجتاز مقدّم القاطرة الزاوية أولاً","أحافظ على خط ضيق قريب من الرصيف حتى تبقى القاطرة في مسارها طوال الوقت","أزيد السرعة قليلاً خلال المنعطف حتى تسير المقطورات بشكل أكثر استقامة وتتبع القاطرة عن قرب"],"explanation":"في التركيبات الطويلة تنحرف العجلات الخلفية للمقطورة إلى الداخل، لذا اتسع أكثر وراقب مسار المقطورة في مرآتيك لتجنب الرصيف."},"42":{"q":"أنت تصل مجموعة مقطورات مزدوجة في الساحة. إحدى المقطورتين محمّلة بثقل والأخرى شبه فارغة. عند تحديد الترتيب، أي تنظيم يمنحك المجموعة الأكثر ثباتاً والأكثر أماناً في القيادة على الطريق السريع؟","options":["ضع المقطورة شبه الفارغة في المقدمة خلف القاطرة وضع الثقيلة في الخلف حتى يثبّت وزنها مؤخرة المجموعة.","صِل المقطورة المحمّلة بثقل أولاً، مباشرةً خلف القاطرة، وضع المقطورة الأخف في مؤخرة المجموعة.","قسّم الحمولة بحيث تحمل كلتا المقطورتين نفس الوزن تقريباً، عندها لن يؤثر الترتيب بينهما على الثبات إطلاقاً.","أبقِ المقطورة الثقيلة في الخلف ودع المقطورة الأمامية الأخف تمتص الارتداد حتى تسير الحمولة بسلاسة أكبر."],"explanation":"صِل المقطورة الأثقل تحميلاً أولاً مباشرةً خلف القاطرة وضع المقطورات الأخف في الخلف للحفاظ على ثبات المجموعة وتقليل خطر الانقلاب."},"43":{"q":"أنت تقود مجموعة مقطورات مزدوجة وتضربك رياح جانبية قوية. كيف تستجيب الشاحنة؟","options":["إنها أكثر ثباتاً من المقطورة الواحدة، لذا ليس للرياح أي تأثير حقيقي عليها هنا.","يمكن للمقطورة الخلفية أن تتأرجح و\"تطقطق كالسوط\"، لذا خفّف السرعة ووجّه بسلاسة.","تدفع الرياح المقطورة الأمامية نحو الأسفل بقوة شديدة بحيث لا تستطيع الخلفية الحركة إطلاقاً.","لا يحدث شيء لأن المقطورتين تلغيان أي قوة رياح بينهما."],"explanation":"يمكن للمقطورة الخلفية أن تتأرجح وتطقطق كالسوط؛ خفّف السرعة ووجّه بسلاسة."},"44":{"q":"أنا موصول بمجموعة مقطورات مزدوجة وأشحن نظام الهواء حتى تنطلق فرامل المقطورة الخلفية. وأنا أمشي حول الشاحنة وأفحص صمامات الإغلاق (القطع)، أي إعداد للصمام يخبرني بأن المقطورات موصولة بشكل صحيح ليتدفق الهواء حتى الخلف دون أن يتسرب من الطرف؟","options":["كل صمام إغلاق على المقطورتين مغلق، حتى يحافظ النظام المُحكم على أقصى ضغط قبل أن أنطلق.","صمامات الإغلاق في مؤخرة المقطورة الأخيرة متروكة مفتوحة حتى أسمع الهواء وأتأكد من شحن الخط.","صمامات الإغلاق بين المقطورات مفتوحة، وصمامات الإغلاق في مؤخرة المقطورة الأخيرة مغلقة.","إعدادات الصمامات لا تهم للشحن، لأن الهواء يصل تلقائياً إلى جميع المقطورات بمجرد فتح صمام حماية القاطرة."],"explanation":"تبقى صمامات الإغلاق بين المقطورات مفتوحة ليتدفق الهواء نحو الخلف، بينما تبقى الصمامات في مؤخرة المقطورة الأخيرة مغلقة حتى لا يتسرب الهواء."},"45":{"q":"أقود مجموعة مقطورات ثلاثية على الطريق بين الولايات بسرعة الطريق السريع عندما تقطع سيارة مساري فجأة أمامي. غريزتي هي أن أشد المقود بقوة لتفاديها. لماذا يكون رد الفعل هذا خطيراً بشكل خاص مع هذه التركيبة؟","options":["إنه ليس مصدر قلق حقيقي — فمع ثلاث مقطورات تسير الشاحنة كلها كوحدة صلبة واحدة، لذا فإن شد المقود السريع يؤثر على القاطرة فقط.","تفقد القاطرة التماسك وتنزلق أولاً، لذا تبقى المقطورات الخلفية ثابتة قبل وقت طويل من تفاعل مؤخرة الشاحنة.","المقطورة الخلفية تتحرك بالكاد عند هذه السرعة، لذا فإن تصحيحاً سريعاً واحداً للمقود وسيلة آمنة لتفادي السيارة.","التضخيم الخلفي (\"طقطقة السوط\") يجعل المقطورة الأخيرة تتأرجح أبعد بكثير وقد يقلبها — وجّه بلطف، وتجنب الحركة السريعة، وخفّف السرعة."],"explanation":"التضخيم الخلفي (طقطقة السوط) يجعل المقطورة الأخيرة تتأرجح أبعد بكثير وقد يقلبها، لذا وجّه بلطف وتدريجياً وخفّف السرعة."},"46":{"q":"أقود مجموعة مقطورات مزدوجة طويلة ومحمّلة بالكامل على طريق بين الولايات في تكساس وألاحظ أنني أحافظ على فجوة أكبر بكثير عن السيارة أمامي مما كنت أفعل بمقطورة واحدة الشهر الماضي. يسألني سائق أحدث في المقصورة لماذا أترك كل هذه المساحة. أي تفسير صحيح؟","options":["التركيبة أطول وأثقل من المقطورة الواحدة، لذا تحتاج إلى مساحة أكبر للتوقف، وهذا يعني ترك مسافة اتباع إضافية أمامها.","المقطورة الإضافية والعربة تضيفان سطح كبح في الخلف، لذا تتوقف المجموعة في مسافة أقصر من المقطورة الواحدة وفجوة أضيق أكثر أماناً فعلاً.","مسافة الاتباع تحددها مقصورة الشاحنة وليس طولها، لذا يجب أن تحافظ المجموعة المزدوجة على نفس الفجوة كأي شاحنة مستقيمة.","لأن المقطورة الخلفية تميل لطقطقة السوط، فإن التباطؤ مبكراً جداً محفوف بالمخاطر، لذا فالفجوة الأصغر تبقي المجموعة مستقيمة."],"explanation":"المجموعة المزدوجة أطول وأثقل من المقطورة الواحدة، لذا تحتاج إلى مسافة توقف أكبر، مما يعني ترك مسافة اتباع إضافية أمامها."},"47":{"q":"أنت تفحص مجموعة مقطورات مزدوجة وتفحص عربة الوصل. ماذا يجب أن تتأكد منه؟","options":["فقط أن العربة مطلية بلون مطابق، لأنها لا تؤثر على القطر الآمن إطلاقاً.","أن خطاف الوصل مقفل، والسلاسل الأمنية مثبّتة، وخطوط الهواء موصولة.","أن إطارات العربة ملساء تماماً حتى تسير المقطورة أوطأ لثبات أفضل الآن.","لا شيء؛ عربة الوصل لا تحتاج أبداً إلى الفحص قبل جرّ مجموعة مقطورات مزدوجة."],"explanation":"خطاف الوصل مقفل، والسلاسل الأمنية مثبّتة، وخطوط الهواء موصولة."},"48":{"q":"أقوم بإنزال مجموعة مقطورات مزدوجة محمّلة عند رصيف ضيق، والمكان الوحيد المتاح يتطلب مني إرجاع الشاحنة كاملةً عدة أقدام للاصطفاف. لدي مساحة كبيرة خلفي لكن المقطورات تستمر في الانطواء لحظة بدئي بالرجوع. أي مما يلي أفضل ممارسة في هذا الموقف؟","options":["أرجع المجموعة كحركة واحدة طويلة ومتواصلة لأن المقطورة المزدوجة الموصولة تسير في الرجوع تماماً كما تفعل المقطورة الواحدة.","تجنب إرجاع المجموعة كلما استطعت لأن المقطورات المزدوجة صعبة التحكم جداً عند الرجوع؛ تحرك ببطء وافصلها لإعادة وضعها إن اضطررت.","أرجع بسرعة ثابتة وحيوية حتى يبقي الزخم المقطورتين وعربة الوصل مستقيمة خلف القاطرة.","أضف وقوداً أثناء الرجوع حتى يدفع وزن المقطورة الخلفية نفسها لتوجيه نفسها بشكل مستقيم إلى مكان الرصيف المفتوح."],"explanation":"المقطورات المزدوجة صعبة التحكم جداً عند الرجوع لأن عربة الوصل تضيف نقطة ارتكاز ثانية تنطوي بسرعة، لذا تجنب الرجوع وتحرك ببطء وافصلها لإعادة وضعها."},"49":{"q":"وصلتَ للتو عربة وصل ومقطورة ثانية إلى مجموعتك المزدوجة. خطاف الوصل يبدو مستقراً، والسلاسل الأمنية مثبّتة، ووصلات الهواء وكابل الأضواء موصولة. قبل أن تصعد إلى المقصورة وتخرج من الساحة، ما الطريقة الصحيحة للتأكد من أن وصلة العربة بالمقطورة مقفلة فعلاً وستثبت؟","options":["تحقق من أن أضواء المقطورة الخلفية وإشارات الانعطاف تعمل؛ إذا كان الكابل الكهربائي يمرر الطاقة، فلا بد أن الوصلة مقفلة أيضاً.","تبدو موصولة بالكامل وكل شيء مثبّت، لذا لا حاجة لأي اختبار إضافي الآن — فقط تقدّم للأمام ببطء وانطلق.","قم باختبار شد لطيف بدفع القاطرة برفق للأمام عكس المقطورة المقفلة للتأكد من أن الوصلة ثابتة بإحكام قبل القيادة.","أمسك المقطورة بيدك وهزّها للأعلى والأسفل عدة مرات؛ إذا تحركت واستقرت، فتلك الحركة تثبت أنها مقفلة في مكانها."],"explanation":"بعد الوصل، أكّد القفل بإجراء اختبار شد — بدفع القاطرة برفق للأمام عكس المقطورة المقفلة للتأكد من أنها تثبت قبل القيادة."},"50":{"q":"أنت تقود مجموعة مقطورات ثلاثية على طريق جبلي بمسارين عندما تظهر أمامك سلسلة من المنعطفات الضيقة المعلَّمة بلافتات. تشعر بالثقة لأن القاطرة تسير بشكل جيد. لإدارة الشاحنة كاملةً عبر هذا الجزء المتعرج بأقصى أمان ممكن، ماذا يجب أن تفعل؟","options":["حافظ على سرعة المنعطف المعلَّمة ووجّه بشكل طبيعي، لأن المقطورات الثلاث تسير مستقيمة عبر الانحناءات خلف القاطرة.","احمل سرعة إضافية إلى كل منعطف حتى يسحب الزخم المقطورات إلى الاستقامة ويمنعها من الانحراف للخارج.","اكبح بقوة أثناء الدوران عبر كل منعطف حتى تُسحب المقطورة الخلفية لتتبع مسار القاطرة تماماً.","انخفض كثيراً دون السرعة المعلَّمة قبل كل منعطف ووجّه المقود بلطف وتدريجياً، لأن طقطقة السوط تجعل المقطورات الخلفية تتأرجح للخارج ويزداد هذا التأرجح مع كل مقطورة."],"explanation":"المقطورات الثلاثية تطقطق كالسوط، لذا تتأرجح المقطورات الخلفية أبعد مع كل مقطورة إضافية؛ انخفض كثيراً دون السرعة المعلَّمة قبل المنعطفات ووجّه بلطف وتدريجياً."},"51":{"q":"أنت تقود مجموعة مقطورات مزدوجة على طريق ريفي سريع بسرعة 55 ميلاً في الساعة عندما تنحرف سيارة فجأة أمامك. تدير المقود يساراً ثم يميناً لتفاديها. تبدأ كلتا المقطورتين بالشعور بعدم الاستقرار خلفك. أي مقطورة هي الأكثر احتمالاً للانحراف بعيداً والانقلاب، وماذا يجب أن تفعل؟","options":["المقطورة الخلفية هي الأكثر احتمالاً للانحراف بسبب التضخيم الخلفي (تأثير ضربة السوط)، لذا أدِر المقود برفق وأبطئ السرعة قبل أي حركة أخرى.","المقطورة الأمامية هي الأكثر احتمالاً للانحراف لأنها الأقرب إلى الجرار وتمتص أقوى شد، لذا اضغط على المكابح بقوة فوراً لتثبيتها.","لا يمكن لأي من المقطورتين الانحراف لأن عربة التحويل (الدوللي) تثبّت كلتا الوحدتين في خط مستقيم تماماً، لذا يمكنك الحفاظ على سرعتك والقيادة بشكل طبيعي عبر الفجوة.","الجرار ينحرف أولاً والمقطورات تتبع مساره بالضبط، لذا فقط قم بتصحيح اتجاه الجرار وستستقيم بقية المجموعة."],"explanation":"التضخيم الخلفي (تأثير ضربة السوط) يجعل المقطورة الخلفية تنحرف أكثر من غيرها وقد يقلبها، لذا أدِر المقود برفق وتدريجياً وأبطئ السرعة."},"52":{"q":"أنا أقوم بوصل مجموعة مقطورات مزدوجة في الساحة. بعد أن أُنزل عربة التحويل (الدوللي) تحت المقطورة الخلفية وأُرجع خطاف القرص (البنتل) للمقطورة الأولى عليها، ما الذي تفعله هذه العربة فعلياً في تركيبتي؟","options":["تربط العجلة الخامسة للجرار مباشرة بمقدمة مقطورتي الأمامية","تربط مؤخرة مقطورتي الأمامية بمقدمة المقطورة الثانية خلفها","تربط هيكل الجرار بمجموعة المحرك وناقل الحركة","تربط إمداد الهواء في الكابينة مباشرة بأدوات التحكم في مكان النوم"],"explanation":"عربة التحويل (الدوللي) هي جهاز الوصل الذي يملك ذراع جر خاص به، وعجلة خامسة، وفكوك إقفال، تربط مؤخرة المقطورة الأمامية بمقدمة المقطورة التي خلفها."},"53":{"q":"أنا أنقل البضائع على نفس الطريق السريع بين الولايات كل أسبوع، لكن في كل أسبوع تخصص لي إدارة التوزيع شاحنة مختلفة. للبقاء آمناً، أريد أن أكون حذراً جداً بشأن \"ضربة السوط\" (التضخيم الخلفي) — حيث يجعل تصحيح سريع للمقود المقطورة الأخيرة تنحرف بعيداً وربما تنقلب، حتى مع بقاء الجرار منتصباً. لأي من مهام هذا الأسبوع يجب أن أدير المقود بأكثر رفق وأبطئ السرعة أكثر قبل أي تغيير سريع للمسار؟","options":["جرار يسحب مقطورة واحدة بطول 53 قدماً محمّلة بالوزن القانوني","جرار بدون مقطورة (بوب تيل) لا يحمل أي مقطورة على الإطلاق","جرار يسحب مجموعة من ثلاث مقطورات (ثلاثية)","جرار يسحب مجموعة من مقطورتين (مزدوجة)"],"explanation":"التضخيم الخلفي (ضربة السوط) يزداد مع كل مقطورة إضافية، لذا فإن ثلاث مقطورات تجعل المقطورة الأخيرة تنحرف أوسع وتكون الأكثر احتمالاً للانقلاب."},"54":{"q":"لقد حصلت للتو على رخصة القيادة التجارية من الفئة A وعرض عمل لنقل مجموعة من مقطورتين متصلتين بعربة تحويل (دوللي) على طرق تكساس السريعة. رخصتي الحالية لا تحمل أي تصديقات (تظهيرات). قبل أن أتمكن قانونياً من القيام بهذه الرحلة، أي تصديق يجب أن أضيفه إلى رخصتي؟","options":["تصديق الصهاريج (N)، لأن الشاحنة متعددة المقطورات تحمل حمولة مجمّعة أكبر وتُنظَّم مثل مركبات الصهاريج","لا حاجة لأي تصديق جديد، لأن رخصة الفئة A بحد ذاتها تغطي أصلاً أي تركيبة من المقطورات أسحبها","تصديق المواد الخطرة (H)، لأن وصل مقطورات إضافية بعربة تحويل يُعامَل على أنه خطير","تصديق المقطورات المزدوجة/الثلاثية (T)، وهو مطلوب قبل سحب مقطورتين أو ثلاث"],"explanation":"سحب مقطورتين أو ثلاث مقطورات يتطلب تصديق المقطورات المزدوجة/الثلاثية (T)، بغض النظر عن البضاعة المنقولة."},"55":{"q":"أنا أقوم بفحص ما قبل الرحلة على مجموعة مقطوراتي المزدوجة وأصل إلى خطوط الهواء الممتدة بين المقطورة الأمامية والمقطورة الخلفية عبر عربة التحويل (الدوللي). لكي أجتاز الفحص وتعمل المكابح على كلتا المقطورتين، في أي حالة يجب أن تكون هذه الخطوط؟","options":["موصولة عند أكف الوصل (الغلاد هاند) مع ضبط صمامات الإغلاق (القطع) بين المقطورات بشكل صحيح بحيث يصل الهواء إلى المقطورة الخلفية","موصولة عند أكف الوصل لكن مع ترك جميع صمامات الإغلاق مغلقة لتبقى الخطوط مشحونة ومضغوطة","مفصولة عند المقطورة الخلفية لتفريغ الضغط وتوفير الهواء لنظام الجرار الأساسي","تُترك مرتخية وغير موصولة حتى يُشغَّل المحرك، ثم توصل بمجرد بناء ضغط النظام الكامل"],"explanation":"يجب أن تكون خطوط الهواء موصولة عند أكف الوصل (الغلاد هاند) ومع ضبط صمامات القطع بين المقطورات على وضع الفتح بحيث يصل الهواء فعلياً إلى المقطورة الخلفية."},"56":{"q":"أثناء وصل عربة تحويل (دوللي) لإضافة مقطورة ثانية في ساحة بتكساس، أُنزل عين القرص (البنتل) الخاصة بالعربة على خطاف القرص في الجرار-المقطورة وأشعر بها تستقر. قبل أن أزحف للخارج لربط سلاسل الأمان وأكف الوصل، في أي حالة يجب أن يكون خطاف القرص لكي يكون هذا الوصل آمناً؟","options":["متروكاً مفتوحاً لتتمكن العربة من الانفصال بسرعة إذا انزاحت الحمولة على الطريق","مُقفلاً ومثبّتاً مغلقاً بحيث لا يمكن للعربة الانفصال عن المقطورة","مشحّماً بخفة ومتروكاً مرتخياً بما يكفي لتدور العين بحرية","مشدوداً فقط بعد أن تُوصل خطوط الهواء والسلك الكهربائي بالكامل"],"explanation":"يجب أن يكون خطاف القرص (البنتل) مُقفلاً ومثبّتاً مغلقاً بحيث لا يمكن لعين ذراع جر العربة أن ترتفع أو تنزلق وتنفصل عن المقطورة."},"57":{"q":"لقد انتهيت للتو من وصل مجموعة مقطورات مزدوجة في الساحة. فتحت صمام الإغلاق في أقصى مؤخرة المقطورة الخلفية للتأكد من وصول الهواء إليها، سمعت الهواء يخرج، والآن أغلقه مجدداً. قبل أن أنطلق، ما هو الوضع النهائي الصحيح لصمام الإغلاق الخلفي ذاك في المقطورة الأخيرة؟","options":["متروكاً مفتوحاً بالكامل ليتمكن خط الهواء الطارئ من التنفيس بحرية أثناء القيادة","متروكاً نصف مفتوح تقريباً للحفاظ على تسرب كمية صغيرة من الهواء من المؤخرة","مغلقاً بالكامل بمجرد التأكد من وصول الهواء إلى المقطورة الخلفية","مُزالاً بالكامل بحيث لا يمكنه أبداً أن يحبس الضغط في الخط عن طريق الخطأ"],"explanation":"يجب أن يكون صمام الإغلاق في مؤخرة المقطورة الأخيرة مغلقاً بالكامل بعد فتحه بإيجاز للتأكد من وصول الهواء إلى المقطورة الخلفية."},"58":{"q":"أنا أقوم بفحص ما قبل الرحلة على مجموعة مقطورات مزدوجة قبل مغادرة الساحة. أثناء فحص عربة التحويل (الدوللي)، ألاحظ أن سلاسل الأمان بها صدئة بشدة وإحدى الحلقات متشققة، لكن كل شيء آخر في الوصل يبدو على ما يرام. يقول شريكي إن الأمر بسيط ما دام خطاف القرص يمسك العربة على أي حال. لماذا يجب أن أرفض القيادة حتى تُستبدل سلاسل الأمان؟","options":["إنها التي تنقل التيار الكهربائي إلى أضواء المقطورة الخلفية، لذا بدونها تنطفئ أضواء المقطورة الخلفية","إنها الوصلة الأساسية التي تمسك العربة بالجرار، تؤدي نفس عمل خطاف القرص","إنها تثبّت حمولة المقطورة الخلفية بإحكام حتى لا تنزاح البضاعة أثناء ضربة السوط","إنها الاحتياطي الذي يبقي العربة موصولة بالشاحنة إذا تعطّل خطاف القرص على الطريق"],"explanation":"سلاسل الأمان هي الاحتياطي الذي يبقي العربة والمقطورة الخلفية موصولتين إذا تعطّل خطاف القرص على الطريق، لذا لا يمكن لسلسلة متشققة أو صدئة أن تؤدي هذا الدور."},"59":{"q":"أنا أقود مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات عندما تنحرف سيارة أمامي، فأقوم بتصحيح سريع واحد للمقود لتفاديها. يبقى الجرار والمقطورة الأمامية متتبّعين للمسار جيداً، لكنني أشعر بشيء يضرب بقوة خلفي. بناءً على التضخيم الخلفي، أي وحدة هي الأكثر احتمالاً للانقلاب من تلك الحركة المفاجئة؟","options":["المقطورة الخلفية (الأخيرة)، لأن إدخال المقود السريع يتضخّم عبر المجموعة ويجعلها تنحرف أوسع","المقطورة الأمامية (الأولى)، لأنها تحمل أثقل حمولة خلف الجرار مباشرة","الجرار، لأنه يقود المجموعة ويمتص أكبر قوة أثناء التصحيح المفاجئ للمقود","لا شيء منها، لأنه ما دام الجرار يبقى متتبّعاً للمسار باستقامة فلا يمكن للمقطورات أن تنقلب بشكل مستقل"],"explanation":"التضخيم الخلفي (ضربة السوط) يضخّم حركة المقود السريعة على طول المجموعة، مما يجعل المقطورة الخلفية تنحرف أوسع وتكون الأكثر احتمالاً للانقلاب."},"60":{"q":"أنا أجمّع مجموعة مقطورات مزدوجة في الساحة. جراري موصول بالفعل بالمقطورة الأمامية، والآن أحتاج إلى إضافة مقطورة ثانية خلفها. أُدحرج عربة التحويل (الدوللي) إلى موضعها لأتمكن من إجراء الوصل. عندما أصل خطاف القرص للعربة وذراع الجر والعجلة الخامسة، ما الذي تربط به العربة المقطورة الثانية فعلياً؟","options":["مباشرة بالهيكل الخلفي للجرار الذي يسحب المجموعة بأكملها","بالمقطورة الأولى (الأمامية) الموصولة بالفعل بالجرار","بالعجلة الخامسة المركّبة على الجرار خلف الكابينة","بإمداد الهواء والوصلات الكهربائية للجرار فقط"],"explanation":"عربة التحويل (الدوللي) تجسر بين المقطورات، لذا في المقطورات المزدوجة تتصل المقطورة الثانية عبر العربة بالمقطورة الأولى الموصولة بالفعل بالجرار."},"61":{"q":"أنا أصل مقطورة ثانية بمجموعتي المزدوجة. لقد دحرجت عربة التحويل (الدوللي) إلى موضعها خلف مؤخرة مقطورتي الأولى، والآن أحتاج إلى وصل ذراع جر العربة بحيث تُسحب العربة من المقطورة التي أمامها. لإجراء هذا الوصل، يجب أن تستقر العين في نهاية ذراع جر العربة في أي جهاز في مؤخرة المقطورة التي أمامها؟","options":["فكوك إقفال العجلة الخامسة، التي تنغلق حول مسمار الملك (الكينغ بِن) لتثبيت الحمولة","مسمار الملك (الكينغ بِن) أسفل المقطورة، الذي ينزلق فوقه ذراع جر العربة","خطاف القرص (البنتل) في مؤخرة المقطورة التي أمامها، حيث تستقر عين ذراع الجر","أكف الوصل (الغلاد هاند)، التي تقفل ذراع الجر في مكانه مع إحكام خطوط الهواء"],"explanation":"تنزل عين ذراع جر العربة وتستقر داخل خطاف القرص (البنتل) في مؤخرة المقطورة التي أمامها، مكوّنة وصلة الجر الميكانيكية بين المقطورات."},"62":{"q":"أنت تصل مقطورة ثانية بمجموعتك المزدوجة. لقد أرجعت مقطورتك الأولى قريباً من عربة تحويل (دوللي) متروكة حرة على ساحة منحدرة قليلاً، وأنت على وشك النزول لدفعها إلى موضعها تحت خطاف القرص للمقطورة الخلفية. قبل أن تبدأ العمل حول العربة، ما هو السبب الأهم لتثبيت عجلاتها بالحوامل أو تأمينها بطريقة أخرى؟","options":["حتى لا يفقد خزان هواء العربة الضغط قبل أن توصل أكف الوصل","حتى تبقى العجلة الخامسة للعربة مستوية بما يكفي لتنغلق فكوك الإقفال على مسمار الملك","حتى تبقى سلاسل الأمان للعربة بعيدة عن خطاف القرص أثناء رجوعك إليها","حتى لا تتدحرج العربة أثناء الوصل فتسحقك أو تفلت منك"],"explanation":"عربة التحويل غير المؤمّنة يمكن أن تتدحرج بحرية على أي انحدار فتسحقك أو تفلت منك أثناء الوصل، لذا يجب تثبيت عجلاتها بالحوامل أو تأمينها بطريقة أخرى."},"63":{"q":"أنا أصل مجموعة مقطورات مزدوجة في الساحة. لقد دحرجت عربة التحويل (الدوللي) تحت المقطورة الخلفية والآن أُرجعها إلى موضعها لتُوصل المقطورات معاً. بينما تنزلق العجلة الخامسة للعربة إلى الأمام تحت المقطورة الخلفية، أي جزء من تلك المقطورة الخلفية يُفترض أن ينزل ويُقفل داخل العجلة الخامسة للعربة؟","options":["مسمار الملك (الكينغ بِن) للمقطورة الخلفية، الذي يستقر في العجلة الخامسة للعربة وتمسكه فكوك الإقفال","ساق عتاد الهبوط للمقطورة الخلفية، الذي ينزل على العجلة الخامسة للعربة لحمل الحمولة","خطاف القرص للعربة، الذي يستقر على العين في مقدمة المقطورة الخلفية","خط إمداد الهواء الطارئ للمقطورة الخلفية، الذي يغذّي آلية إقفال العجلة الخامسة"],"explanation":"ينزل مسمار الملك (الكينغ بِن) للمقطورة الخلفية في العجلة الخامسة لعربة التحويل وتمسكه فكوك الإقفال مغلقة."},"64":{"q":"أنا أقوم بفحص ما قبل الرحلة على مجموعة مقطورات مزدوجة وأفحص عربة التحويل (الدوللي) التي تربط مقطورتي الأمامية بالخلفية. ألاحظ أن كلتا سلسلتي الأمان الممتدتين من العربة سليمتان ومثبّتتان بشكل صحيح. إذا انفك جهاز الوصل الرئيسي الذي تحميانه أو تحطّم أثناء قيادتي، أي وصلة ستكون هاتان السلسلتان موجودتين لدعمها ومنع المقطورة الخلفية من الانفصال؟","options":["وصلة خط الهواء عند أكف الوصل (الغلاد هاند) بين المقطورتين","وصلة خطاف القرص (البنتل) حيث يتصل ذراع جر العربة","العجلة الخامسة وفكوك الإقفال تحت المقطورة الخلفية","سلك أضواء الكهرباء الموصول بالمقطورة الخلفية"],"explanation":"تعمل سلسلتا الأمان في العربة بمثابة الاحتياطي الميكانيكي لوصلة خطاف القرص (البنتل) إذا انفصلت أثناء القيادة."},"65":{"q":"لقد انتهيت للتو من وصل مجموعة مقطورات مزدوجة في الساحة. أُنزل عربة التحويل (الدوللي)، وأربط القرص وسلاسل الأمان، وأوصل أكف الوصل وسلك الأضواء، ثم أعود سيراً لإجراء فحصي النهائي قبل الانطلاق. عندما أفحص خطوط الهواء والكهرباء الممتدة إلى المقطورة الخلفية، أي حالة تخبرني أنها مهيّأة بشكل صحيح وآمنة للقيادة؟","options":["خطوط الهواء والكهرباء متدلية إلى الأسفل بحيث تتعلّق تحت الهيكل بكثير، مما يعطيها ارتخاءً للمنعطفات الحادة","سلك الأضواء محكم، لكن أحد خطوط الهواء مُترك مفصولاً بحيث تبقى مكابح المقطورة الخلفية مُحرَّرة لتسهيل المناورة","خطوط الهواء والكهرباء موصولة بإحكام بالمقطورة الخلفية وممدودة بحيث لا تجرّ على الأرض","الخطوط ملفوفة بإحكام وملصوقة معاً على الهيكل بحيث لا يمكنها التحرك إطلاقاً أثناء القيادة"],"explanation":"بعد الوصل، تأكد من أن خطوط الهواء والكهرباء موصولة بإحكام بالمقطورة الخلفية وممدودة بحيث لا تجرّ على الأرض."},"66":{"q":"أنا أصل مجموعة مقطورات مزدوجة في الساحة. خطوط الهواء والكهرباء للجرار ممتدة بالفعل إلى المقطورة الأمامية، وقد ثبّتُّ خطاف القرص وسلاسل الأمان لعربة التحويل (الدوللي) بالمقطورة الخلفية. لإيصال ضغط الهواء والأضواء إلى الوحدة الخلفية، أين لا تزال أكف الوصل وسلك الكهرباء بحاجة إلى أن تُوصل؟","options":["عند طرف الجرار فقط، لأن أكف الوصل عند المقطورة الأمامية تغذّي المجموعة بأكملها","فقط بين العربة والمحور الأمامي للمقطورة الأمامية، حيث تقع غرف المكابح","لا في أي مكان آخر؛ بمجرد إقفال خطاف القرص وسلاسل الأمان، تكون المقطورة الخلفية مخدومة بالكامل","بين كل مقطورة، بحيث تمتد خطوط الهواء والكهرباء من المقطورة الأمامية عبر العربة إلى المقطورة الخلفية"],"explanation":"في المقطورات المزدوجة يجب أن تُوصل خطوط الهواء والكهرباء بين كل مقطورة، ممتدة من المقطورة الأمامية عبر العربة إلى المقطورة الخلفية."},"67":{"q":"أنا أُرجع عربة التحويل (الدوللي) تحت المقطورة الخلفية لمجموعتي المزدوجة، وأضبط ارتفاع المقطورة الخلفية بعتاد الهبوط أولاً. للحصول على وصل متين بحيث يستقر مسمار الملك (الكينغ بِن) وتنغلق فكوك الإقفال حوله، يجب ضبط المقطورة على أي ارتفاع بالنسبة للعجلة الخامسة للعربة؟","options":["منخفضاً بما يكفي بحيث ترفع العربة المقطورة قليلاً وهي تتراجع تحتها","عالياً بما يكفي بحيث تنزلق العربة بالكامل تحتها دون أن تلمس المقطورة","مستوياً مع العجلة الخامسة بحيث ينزلق مسمار الملك مباشرة دون أي رفع","عالياً بما يكفي بحيث تتوقف العربة على بعد قدم تقريباً قبل مسمار الملك"],"explanation":"اضبط المقطورة الخلفية منخفضة بما يكفي بحيث ترفعها عربة التحويل قليلاً وهي تتراجع تحتها، مما يضمن استقرار مسمار الملك وإقفال الفكوك بالكامل."},"68":{"q":"لقد أرجعت للتو جراري تحت عربة التحويل (الدوللي) والمقطورة الثانية، وأنا على وشك شحن نظام الهواء للمقطورة الخلفية بفتح صمامات الإغلاق وإمداد الهواء. قبل أن أرسل الهواء إلى تلك المقطورة الخلفية، أي مما يلي يجب أن أتأكد منه أولاً؟","options":["أن أضواء العلامات والإيضاح للمقطورة الخلفية مشغّلة وتعمل","أن المقطورة الخلفية لا يمكن أن تتدحرج، لأن مكابح ركنها مضبوطة أو عجلاتها مثبّتة بالحوامل","أن المقطورة الخلفية هي الأثقل تحميلاً من الاثنتين وتقع أمام الأخف","أن أكف الوصل موصولة وصمام الإغلاق في مؤخرة المقطورة الأخيرة مفتوح"],"explanation":"قبل شحن الهواء إلى مقطورة، تأكد من أنها لا يمكن أن تتدحرج، لأن الشحن يحرّر مكابح الزنبرك/الركن وقد تتحرك المقطورة."},"69":{"q":"أنا أقوم بفحص ما قبل الرحلة على مجموعتي المزدوجة وأنا منحنٍ عند عربة التحويل (الدوللي) بين المقطورتين. لقد فحصت بالفعل إطاراتها وعجلاتها وأضواءها، لكنني أعلم أن العربة هي نقطة الوصل حيث تحدث معظم الأخطاء. أي مكوّن إضافي يكون الأكثر أهمية أن أفحصه هنا على العربة نفسها؟","options":["واقيات الطين للمقطورة وشريط الوضوح العاكس على طول الألواح الجانبية","ملصق فحص وزارة النقل ولوحة التسجيل المركّبة على سكة الهيكل","خطاف القرص (البنتل) وذراع الجر اللذان يثبّتان العربة بالمقطورة التي أمامها","ذراع تدوير عتاد الهبوط وضوء لوحة الترخيص الخلفية للمقطورة"],"explanation":"افحص خطاف القرص (البنتل) وذراع الجر، لأنهما العتاد الذي يمسك فعلياً عربة التحويل بالمقطورة التي أمامها."},"70":{"q":"أنا أقود مجموعة مقطورات مزدوجة ويشير لي مشرف الرصيف بأن أُرجع الشاحنة بشكل مستقيم إلى الحوض رقم 4. عندما أبدأ بالرجوع، تنحرف المقطورات فوراً عن الخط ولا تتتبّع معاً مهما أدرت المقود. لماذا يكون رجوع مجموعة مقطورات مزدوجة أصعب بكثير من رجوع مقطورة واحدة؟","options":["المقطورة الخلفية أخف وزناً، لذا تمسك مكابحها بشكل غير متساوٍ وتسحب المجموعة عن الخط أثناء الرجوع","المرايا الإضافية تخلق نقاطاً عمياء تخفي المقطورة الخلفية، مما يجعل تقدير مسار الرجوع مستحيلاً","المقطورات المزدوجة لا تملك مكابح مقطورة عاملة أثناء الرجوع، لذا تتدحرج المجموعة بحرية ولا يمكن توجيهها باستقامة","المجموعة تدور حول نقطتين منفصلتين — العربة والمفصل الخلفي — لذا تنثني في مكانين في آن واحد عند الرجوع"],"explanation":"مجموعة المقطورات المزدوجة تدور حول نقطتين منفصلتين، العربة والمفصل الخلفي، لذا تنثني في مكانين في آن واحد عند الرجوع."},"71":{"q":"أنا أسحب مجموعة مقطورات مزدوجة والرصيف الذي أحتاج الوصول إليه على بعد بضعة أقدام خلفي حيث تجاوزته. أخبرني مدرّبي أن أتقدّم، وأجد طريقاً آخر للالتفاف، أو أفك الوصل وأعيد التموضع بدلاً من مجرد إرجاع الشاحنة بشكل مستقيم. ما هو السبب الرئيسي الذي يجعل دائرة السلامة العامة (DPS) تطلب من سائقي المقطورات المزدوجة تجنّب الرجوع كلما أمكن؟","options":["مجموعة المقطورات المزدوجة صعبة التحكم جداً في الرجوع، لذا فإن إرجاعها يخاطر بانطواء الشاحنة","رجوع مجموعة المقطورات المزدوجة غير قانوني في كل ولاية وسيؤدي إلى مخالفة تلقائية","الرجوع يحكّ إطارات المقطورة جانبياً ويبليها أسرع بكثير من المعتاد","عربة التحويل لا يمكنها نقل الهواء إلى مكابح المقطورة الخلفية أثناء التحرك للخلف"],"explanation":"مجموعة المقطورات المزدوجة صعبة التحكم جداً في الرجوع، لذا فإن إرجاعها يخاطر بانطواء الشاحنة."},"72":{"q":"أنا أسحب مجموعة مقطورات مزدوجة وقد وصلت للتو عربة التحويل (الدوللي) بالمقطورة الخلفية. أثناء اختبار النظام، أضغط على دواسة المكابح في الكابينة فيتدفق الهواء عبر خط الهواء العابر (خط الخدمة). أي مكوّن في المقطورة الخلفية يغذّيه هذا الخط لإيقاف العجلات؟","options":["خط الطوارئ (الإمداد) الذي يشحن خزان هواء المقطورة","مكابح الخدمة، التي تنطبق عندما أضغط على دواسة المكابح","أضواء العلامات والإيضاح للمقطورة الموصولة عبر سلك الأضواء","مكابح الزنبرك (الركن) التي تتحرّر بمجرد شحن النظام"],"explanation":"خط الهواء (العابر) للخدمة ينقل الإشارة من الضغط على دواسة المكابح إلى مكابح الخدمة في المقطورة الخلفية لتطبيقها."},"73":{"q":"لقد وصلت للتو مجموعة مقطورات مزدوجة وضغط الهواء لديك يستمر في النزول ببطء حتى مع تشغيل ضاغط المحرك، والمقطورات لن تُشحن بالكامل. أثناء جولتك حول المركبة تلاحظ أن صمام إغلاق خط الطوارئ في أقصى مؤخرة المقطورة الأخيرة لم يُغلق أبداً بعد أن استخدمته للتحقق من تدفق الهواء. حتى تصحّح هذا، ماذا سيحدث؟","options":["ستنطبق مكابح الخدمة في المقطورة الخلفية بقوة أكبر، مما يمنحك قدرة توقف أقوى على ذلك المحور","سيُشحن النظام أسرع بكثير لأن الصمام المفتوح يساعد على دفع الهواء إلى المؤخرة بالكامل","سيستمر الهواء في التسرب من الصمام الخلفي المفتوح، لذا ستفقد ضغط الهواء ولا يمكن للنظام أن يبني الضغط","لن يتغير شيء، لأن ذلك الصمام يهمّ فقط عند فك عربة التحويل لاحقاً"],"explanation":"يجب إغلاق صمامات الإغلاق في مؤخرة المقطورة الأخيرة؛ إذا تُركت مفتوحة، يتسرب الهواء المضغوط باستمرار ولا يمكن للنظام أبداً أن يبني الضغط."},"74":{"q":"أنا أقوم بفحص ما قبل الرحلة على مجموعة مقطورات مزدوجة وأصل إلى صمامات الإغلاق (القطع) في خطوط الهواء. أريد أن يصل الهواء إلى مكابح المقطورة الخلفية بالكامل. بالتفكير في كيفية تدفق الهواء عبر المجموعة، أي وضع للصمام صحيح لصمامات الإغلاق الواقعة بين المقطورتين؟","options":["مغلقاً بإحكام، مثل الصمامات في أقصى مؤخرة المقطورة الخلفية، لإحكام النظام","نصف مفتوح، بحيث يبني ضغط الهواء تدريجياً ولا يندفع إلى المكابح الخلفية","مُزالاً بالكامل ومسدوداً، لأن عربة التحويل تغذّي المؤخرة بالهواء أصلاً","مفتوحاً، بحيث يمرّ الهواء عبر الوصلة ويصل إلى مكابح المقطورة الخلفية"],"explanation":"يجب أن تكون صمامات الإغلاق بين المقطورات مفتوحة بحيث يمرّ الهواء عبر الوصلة ويصل إلى مكابح المقطورة الخلفية."},"75":{"q":"لقد انتهيت للتو من وصل عربة تحويل (دوللي) لربط مقطورتي الثانية، وأنا أُجري فحوصاتي النهائية قبل الانطلاق من الساحة. عندما يتعلق الأمر بعتاد الإسناد (الهبوط) للعربة، ماذا يجب أن أفعل به قبل أن أبدأ القيادة؟","options":["أرفعه بالكامل بحيث يكون عتاد الإسناد مرفوعاً وبعيداً عن الأرض","أتركه منخفضاً ليحمل بعض وزن العربة على الطريق","أُزيل عتاد الإسناد بالكامل وأخزّنه على هيكل العربة","أُنزله على كتل خشبية لتثبيت العربة أثناء التحرك"],"explanation":"بمجرد وصل عربة التحويل وحملها للحمولة، ارفع عتاد الإسناد بالكامل بحيث يبتعد عن الأرض ولا يمكن أن يعلق بالطريق."},"76":{"q":"أنا متوقف في ساحة إنزال الحمولة ومعي مجموعة مقطورات مزدوجة محمّلة، وأحتاج إلى فك المجموعة كي تستطيع رافعة شوكية الوصول إلى الصندوق الخلفي. لقد وضعت بالفعل أسافين تحت العجلات وأنزلت عجلات الإسناد (الـ landing gear). لفصل المقطورات بأمان وإبقاء التشكيلة تحت السيطرة، أي مقطورة يجب أن أفصلها أولاً؟","options":["المقطورة الأمامية، لأن سحب الجرّار بعيداً عنها يحرّر بقية المجموعة خلفها","المقطورة الخلفية، بإخراجها مع عربة التحويل (الدوللي) أولاً قبل التقدم نحو الأمام","لا واحدة قبل الأخرى — حرّر كلا خطّافي القطر (pintle hooks) معاً كي تسقط الدوللي بشكل متساوٍ","المقطورة الأمامية، لأنها تحمل أثقل حمولة وينبغي دائماً فصلها أولاً عن التشكيلة"],"explanation":"عند فصل المقطورات المزدوجة اعمل من الخلف نحو الأمام بإزالة المقطورة الخلفية وعربة التحويل (الدوللي) أولاً، كي تبقى كل مقطورة متبقية مسنودة."},"77":{"q":"لقد ربطت للتو جرّاري بمجموعة مقطورات مزدوجة وخرجت إلى طريق مزدحم بأربع حارات. مقارنةً بالمقطورة المفردة التي أقودها عادةً، ما السبب الرئيسي الذي يجعل هذه التشكيلة الأطول تغيّر طريقة قيادتي عبر حركة المرور واقترابي من التقاطعات؟","options":["تتيح لي الانزلاق لمسافة أطول نزولاً، فأستطيع رفع قدمي عن الفرامل مبكراً على المنحدرات","تستهلك الوقود أسرع، فعليّ التخطيط لتوقفات أكثر تكراراً للتزود بالوقود على طول الطريق","إنها أطول إجمالاً، فأحتاج إلى مساحة أكبر للالتفاف وإلى مسافة أطول لإيقاف الوحدة بأكملها","تحجب مرايايّ أكثر، فعليّ أن أميل خارج النافذة لفحص النقاط العمياء"],"explanation":"مجموعة المقطورات المزدوجة أطول إجمالاً من المفردة، لذا تحتاج إلى مساحة أكبر للالتفاف ومسافة أطول لإيقاف الوحدة بأكملها."},"78":{"q":"أنت تقطر مجموعة مقطورات مزدوجة بسرعة الطريق السريع على الطريق I-35 حين تجبرك مركبة بطيئة أمامك على الانتقال إلى الحارة اليسرى. مع علمك بأن المقطورة الخلفية تضخّم حركة توجيهك، ما الطريقة الأكثر أماناً لتغيير الحارة هذا؟","options":["نفّذ إدخالاً واحداً حازماً وحاداً للمقود كي تجتاز الحارة قبل أن يتاح للمقطورة الخلفية وقت للتفاعل","اكبح بقوة لتخفيض السرعة أولاً، ثم أدر المقود بسرعة لإتمام المناورة","تسارع بحدّة لجعل التشكيلة كلها مستقيمة، ثم انتقل في حركة واحدة حاسمة","وجّه برفق وغيّر الحارة تدريجياً مع مراقبة مراياك طوال المناورة"],"explanation":"وجّه برفق وغيّر الحارة تدريجياً مع مراقبة المرايا، لأن الحركات السريعة تطلق التضخيم الخلفي الذي قد يدفع المقطورة الخلفية للانحراف عرضاً والانقلاب."},"79":{"q":"أنا أقطر مجموعة مقطورات ثلاثية على الطريق السريع بين الولايات بسرعة عالية حين تندفع سيارة أمامي فأقوم بنخسة توجيه واحدة سريعة وحادة لتفاديها. يبقى الجرّار منتصباً ويسير مستقيماً، لكنني أشعر بشيء يتأرجح بقوة خلفي. في حالة 'ضرب السوط' (crack-the-whip) هذه، أي وحدة هي الأكثر احتمالاً للانقلاب؟","options":["المقطورة الخلفية (الأخيرة)، لأن التضخيم الخلفي يجعلها تتأرجح إلى أوسع مدى","المقطورة الأمامية، لأنها تحمل أثقل حمولة مباشرةً خلف الجرّار","وحدة الجرّار، لأن إدخال التوجيه يبدأ عند المحور الأمامي","لا واحدة منها، ما دام الجرّار بقي منتصباً واستمر في السير مستقيماً"],"explanation":"التضخيم الخلفي، أي تأثير ضرب السوط، يجعل كل مقطورة تتأرجح إلى مدى أوسع، فالمقطورة الخلفية تتحرك أكثر ما يمكن عرضاً وهي الأكثر احتمالاً للانقلاب."},"80":{"q":"أنا أقطر مجموعة مقطورات مزدوجة بسرعة الطريق السريع حين تندفع سيارة فجأة أمامي، فأنخس المقود لتفاديها. بسبب التضخيم الخلفي (تأثير 'ضرب السوط')، ماذا ينبغي أن أتوقع أن تفعله حركة التوجيه الأمامية السريعة تلك؟","options":["تجعل المقطورة الخلفية تتبع مساراً أضيق وأصغر قليلاً من الجرّار","تجعل المقطورة الخلفية تنحرف عرضاً إلى مدى أوسع بكثير من مقدمتي، ما يهدد بالانقلاب","لا يكون لها أثر يُذكر على المقطورة الخلفية ما دام الجرّار يبقى في حارته","تدفع المقطورة الخلفية إلى الأمام أسرع، فترفع سرعة محركي وسرعتي على الطريق"],"explanation":"التضخيم الخلفي، أي تأثير ضرب السوط، يضخّم إدخال التوجيه السريع على طول التشكيلة فتنحرف المقطورة الخلفية إلى مدى أوسع بكثير من المقدمة وقد تنقلب."},"81":{"q":"أنا أقطر مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات حين تندفع سيارة فجأة إلى حارتي مباشرةً أمامي. غريزتي أن أتفاعل بسرعة وأبتعد عنها. لتقليل التضخيم الخلفي (تأثير 'ضرب السوط') ومنع المقطورة الخلفية من الانحراف عرضاً والانقلاب، كيف ينبغي أن أتعامل مع المقود في هذه اللحظة؟","options":["أنفّذ تصحيح توجيه واحداً سريعاً وحاداً لتجاوز الخطر، لأن الحركة السريعة تُخرج التشكيلة كلها من الخطر بأسرع وقت","أحافظ على ضغط ثابت بيد واحدة على المقود كي أتمكن من الكبح بقوة باليد الأخرى وأقصّر مسافة توقفي","أوجّه برفق وتدريجياً متجنباً أي حركة مفاجئة، لأن نخسة سريعة للمقود تجعل المقطورة الخلفية تنحرف إلى مدى أوسع بكثير","أوجّه بشكل طبيعي ولكن لا أخفّف إلا بعد وصولي لسرعة الطريق السريع، حيث تسير المقطورات أكثر استقامةً ولا يعود التضخيم مصدر قلق"],"explanation":"وجّه برفق وتدريجياً دون أي حركة مفاجئة، لأن نخسة المقود السريعة تتضخّم عبر المقطورات فتجعل المقطورة الخلفية تنحرف إلى مدى أوسع بكثير."},"82":{"q":"المقطورات المزدوجة والثلاثية تكون أكثر احتمالاً للانقلاب أثناء:","options":["القيادة البطيئة المستقيمة الثابتة","المنعطفات المفاجئة أو تغييرات الحارة السريعة","الوقوف الساكن عند إشارة التوقف","الكبح اللطيف الخفيف الهادئ"],"explanation":"المنعطفات المفاجئة وتغييرات الحارة السريعة تسبب الانقلابات."},"83":{"q":"أنت تقطر مجموعة مقطورات مزدوجة على طريق سريع بين الولايات حين يبدأ رذاذ بارد ويصبح سطح الطريق زلقاً. لا تزال حركة المرور أمامك تسير بالسرعة المحدّدة، وتود مجاراتها. مع مراعاة كيفية تصرف المقطورة المزدوجة على سطح زلق، ما الطريقة الأكثر أماناً للتعامل مع تشكيلتك الآن؟","options":["حافظ على السرعة المحدّدة لتبقى مع حركة المرور، ثم اكبح بحزم في اللحظة التي تشعر فيها بأن المقطورة الخلفية بدأت تنزلق","أبقِ سرعتك مرتفعة لكن التصق خلف الشاحنة أمامك مباشرةً كي يهيّئ رذاذ إطاراتها مساراً أكثر جفافاً لإطاراتك","حافظ على سرعتك ونفّذ تصحيحات توجيه سريعة وحاسمة كي تبقى المقطورات تسير مستقيمة خلفك","ارفع قدمك عن دواسة الوقود لتبطئ إلى ما دون سرعة حركة المرور بكثير، واستخدم إدخالات توجيه وكبح سلسة ولطيفة طوال الوقت"],"explanation":"على الطرق الزلقة تنخفض قوة التماسك، لذا أبطئ إلى ما دون سرعة حركة المرور بكثير واستخدم توجيهاً وكبحاً سلسين ولطيفين لتجنب فقدان التماسك وانقلاب المقطورة الخلفية."},"84":{"q":"أنا أقطر مجموعة مقطورات مزدوجة محمّلة على طريق سريع بين الولايات في تكساس خلف سيارة عادية (four-wheeler) قد أحتاج إلى الكبح بقوة من أجلها. مقارنةً بالمقطورة المفردة التي أقودها عادةً، السبب الرئيسي الذي يجعلني أترك مسافة اتباع أكبر هو أن تشكيلتي المزدوجة:","options":["أطول وأثقل، فتحتاج إلى مسافة أكبر للتوقف","تملك محاور وفرامل أكثر، فتتوقف في مسافة أقصر بكثير","ترتفع أعلى عن الطريق، ما يحجب رؤيتي لحركة المرور المتباطئة","تميل إلى الانحراف يساراً، فالمساحة الإضافية تمنحني مجالاً للتصحيح"],"explanation":"التشكيلة التي تقطر مقطورتين محمّلتين أطول وأثقل من المفردة، لذا تحتاج إلى مسافة توقف أكبر ومسافة اتباع أكبر."},"85":{"q":"أنا أقطر مجموعة مقطورات مزدوجة فارغة على امتداد من الرصيف المتشقق والمموّج (washboard)، وأستطيع أن أشعر بالمقطورة الخلفية الخفيفة ترتد وتقفز خلفي. لإبقاء المجموعة تحت السيطرة على هذا الطريق الوعر، ماذا ينبغي أن أفعل؟","options":["أسرّع كي تسير المقطورات أكثر استقامةً وتقفز عبر المطبات أسرع","أبطئ، لأن المقطورات المزدوجة الفارغة ترتد وتفقد المقطورة الخلفية التماسك","أكبح بقوة في اللحظة التي تبدأ فيها المقطورة الخلفية بالارتداد لتهدئتها","ألتصق قريباً خلف المركبة أمامي كي أقرأ خطّ سيرها عبر المقطع الوعر"],"explanation":"المقطورات المزدوجة الفارغة ترتد على الطرق الوعرة، والمقطورة الخلفية الخفيفة الحمولة قد تفقد التماسك أو تنقلب، لذا فالإبطاء يبقي الإطارات متماسكة."},"86":{"q":"أحمل رخصة قيادة تجارية (CDL) من تكساس مع تظهير المقطورات المزدوجة/الثلاثية، وأخطط لرحلة طويلة تعبر عدة حدود ولايات وأنا أقطر مجموعة مقطورات ثلاثية. يخبرني المرسل (الديسباتشر) أنه بما أن تظهيري سارٍ، فأنا مخوّل لقيادة الثلاثية طوال الطريق. ما الفهم الصحيح لأين يجوز لي قانونياً تشغيل المقطورات الثلاثية؟","options":["تظهيري يجعل الثلاثية قانونية على المستوى الوطني، فيجوز لي قطرها في كل ولاية على المسار","يجوز تشغيل الثلاثية على أي طريق سريع بين الولايات لكنها ممنوعة على جميع الطرق الأخرى","الثلاثية قانونية فقط على المسارات في الولايات التي تسمح قوانينها بها تحديداً","الثلاثية قانونية في جميع الولايات ما دمت أشغّلها فقط خلال ساعات النهار"],"explanation":"يجوز تشغيل المقطورات الثلاثية فقط على المسارات في الولايات التي تسمح قوانينها بها تحديداً، لأن التظهير لا يلغي قانون كل ولاية على حدة."},"87":{"q":"أنا أربط مجموعة مقطورات مزدوجة في المحطة. إحدى المقطورتين محمّلة بثقل بشحنة مكدّسة والأخرى محمّلة بخفّة. وأنا أخطط للترتيب خلف جرّاري، أي مما يلي هو الطريقة الصحيحة لترتيب المقطورتين؟","options":["ضع المقطورة الأخف خلف الجرّار مباشرةً كي تثبّت الثقيلة الجزء الخلفي وتسير أكثر استقامةً","لا فرق أي مقطورة تذهب أين، ما دامت كلتاهما محمّلتين دون حد الوزن","ضع أي مقطورة تم ربطها أولاً في المقدمة، لأن وزن الحمولة لا علاقة له بترتيب المقطورات","ضع المقطورة الأثقل حمولةً خلف الجرّار مباشرةً وأبقِ المقطورة الأخف نحو الخلف"],"explanation":"ضع المقطورة الأثقل حمولةً أولاً، خلف الجرّار مباشرةً، وأبقِ المقطورات الأخف نحو الخلف، لأن المقطورة الخلفية الخفيفة ترتد وتنقلب بسهولة أكبر."},"88":{"q":"أنا أربط مجموعة مقطورات مزدوجة في الساحة. إحدى المقطورتين محمّلة بالكامل وثقيلة؛ والأخرى فارغة. يخبرني زميل أن أضع المحمّلة في الخلف فحسب كي تسير الفارغة في المقدمة خلف جرّاري. إذا اتبعت نصيحته، ما التأثير الأرجح على تشكيلتي؟","options":["ستصبح التشكيلة أقل ثباتاً، لأن إعداد المقدمة الخفيفة والمؤخرة الثقيلة يجعل المقطورة الخلفية ترتد وتنقلب بسهولة أكبر.","ستصبح التشكيلة أكثر ثباتاً، لأن المقطورة الثقيلة في الخلف تبقي المؤخرة مثبّتة وتقاوم التأرجح.","ستتعامل التشكيلة بالشكل نفسه في كلتا الحالتين، لأن الوزن الإجمالي هو ما يهم، لا ترتيب المقطورات.","ستتوقف التشكيلة أسرع، لأن المقطورة الخلفية المحمّلة تضيف تماسكاً للكبح في مؤخرة التشكيلة."],"explanation":"وضع مقطورة خفيفة في المقدمة وأخرى ثقيلة في الخلف يعكس الترتيب الصحيح ويجعل المقطورة الخلفية ترتد وتنقلب بسهولة أكبر، ما يقلّل الثبات."},"89":{"q":"لقد ربطت للتو مقطورتي الثانية باستخدام عربة التحويل (الدوللي)، ووصلت أيدي المصافحة (glad hands)، وشحنت نظام الهواء. قبل أن أقود هذه المجموعة المزدوجة إلى الطريق السريع، ماذا ينبغي أن أفعل للتأكد من أن المقطورة الخلفية آمنة للقطر؟","options":["أفتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الخلفية وأتركه مفتوحاً كي يستمر تدفق الهواء أثناء القيادة","أضغط فرامل المقطورة وأتأكد من أن فرامل المقطورة الخلفية تمسك فعلاً وتثبّت قبل التحرك","أختبر بالشد خطّاف القطر (pintle hook) وسلاسل الأمان فقط، لأن وصلة الدوللي هي الجزء الذي يفشل عادةً","أراقب اشتعال أضواء فرامل المقطورة الخلفية، ما يثبت أن الفرامل الخلفية تعمل"],"explanation":"بعد شحن نظام الهواء يجب أن تختبر أن فرامل الخدمة للمقطورة الخلفية تمسك فعلاً وتثبّت، لأن الشحن وحده لا يثبت أن الفرامل تعمل ميكانيكياً."},"90":{"q":"لقد أنزلت مقطورتي الأمامية لتبديل الحمولات، وقبل أن أسحب الجرّار من تحتها أحتاج إلى إنزال الدعامات بالمرفاع كي تبقى المقطورة قائمة بذاتها. أي جزء من نصف المقطورة المتوقفة أنزله كي تبقى واقفة بمجرد فك العجلة الخامسة (fifth wheel)؟","options":["خطّاف القطر (pintle hook)، لأنه نقطة الوصل التي تحمل وزن المقطورة وهي متوقفة","سلاسل الأمان، لأنها تبقي المقطورة مرتفعة عن الأرض بعد ابتعاد الجرّار","عجلات الإسناد (landing gear)، لأنها الأرجل التي تُنزَل بالمرفاع وتسند المقطورة المتوقفة بذاتها","عربة التحويل (الدوللي)، لأنها الأداة المتروكة تحت المقطورة لإبقائها مرتفعة وهي متوقفة"],"explanation":"عجلات الإسناد (landing gear) هي الأرجل التي تُنزَل بالمرفاع وتسند نصف المقطورة المتوقفة بذاتها بمجرد فك العجلة الخامسة وسحب الجرّار."},"91":{"q":"أنا أقطر مجموعة مقطورات ثلاثية على الطريق السريع بين الولايات حين تندفع سيارة فجأة أمامي، فأنخس المقود بسرعة لتفاديها. يبقى الجرّار والمقطورتان الأماميتان منتصبين ويسيران بشكل سليم. بسبب التضخيم الخلفي (تأثير 'ضرب السوط')، أي نتيجة أنا الأكثر احتمالاً لمواجهتها؟","options":["ستفقد محاور الدفع في الجرّار التماسك وستنزلق المقصورة (الكابينة) خارجة أولاً","سيرتفع استهلاك الوقود بحدّة لأن التشكيلة تقاوم إدخال التوجيه المفاجئ","ستنفصل عربات التحويل (الدوللي)، فتسقط المقطورة الوسطى على الطريق","ستنحرف المقطورة الخلفية عرضاً إلى مدى أوسع بكثير من الجرّار وقد تنقلب"],"explanation":"التضخيم الخلفي (تأثير ضرب السوط) يجعل كل مقطورة تتأرجح إلى مدى أوسع من التي أمامها، فالمقطورة الخلفية تتأرجح أكثر ما يمكن وقد تنقلب."},"92":{"q":"أنت تقود مجموعة مقطورات مزدوجة محمّلة بسرعة الطريق السريع حين تنحرف سيارة فجأة إلى حارتك أمامك. تحتاج إلى الانتقال جانباً لتفاديها. لمنع المقطورة الخلفية من الانقلاب، كيف ينبغي أن تتعامل مع المقود؟","options":["وجّه بسلاسة وتدريجياً، مخفّفاً حركة المقود بدلاً من أي حركة سريعة متشنّجة","وجّه بقوة وسرعة لتجاوز الخطر قبل أن تتمكن المقطورات من التفاعل خلفك","أبقِ المقود مثبّتاً مستقيماً واعتمد فقط على الكبح الشديد لتفادي السيارة","انعطف بحدّة نحو الكتف، لأن الكتف المرصوف يمنح المقطورات مساحة أكبر"],"explanation":"وجّه بسلاسة وتدريجياً لأن الحركة السريعة المتشنّجة تطلق التضخيم الخلفي، فتجعل المقطورة الخلفية تنحرف إلى مدى أوسع بكثير وقد تنقلب."},"93":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة A (Class A CDL) وأقطر بانتظام مقطورة مفردة بطول 53 قدماً. تريد شركتي الآن أن أبدأ بقطر مجموعة مقطورات مزدوجة، مع عربة تحويل (دوللي) تربط مقطورتين. قبل أن أتمكن قانونياً من أخذ هذه المهمة، ماذا تطلب هيئة السلامة العامة في تكساس (Texas DPS) مني لإضافة تظهير المقطورات المزدوجة/الثلاثية (T)؟","options":["إتمام اختبار مهارات (طريق) ثانٍ خلف المقود باستخدام تشكيلة مزدوجة تحديداً","اجتياز اختبار المعرفة (التحريري) للمقطورات المزدوجة/الثلاثية في DPS","الخضوع لتقييم تهديد أمني للمواد الخطرة (HazMat) وفحص بصمات وخلفية","اجتياز اختبار معرفة الصهريج (N) الذي يغطي تموّج السائل والحواجز"],"explanation":"تظهير المقطورات المزدوجة/الثلاثية (T) معرفي فقط، لذا يتطلب مجرد اجتياز الاختبار التحريري للمقطورات المزدوجة/الثلاثية في DPS، دون اختبار طريق أو مهارات إضافي."},"94":{"q":"أنا أقطر مجموعة مقطورات ثلاثية على الطريق السريع بين الولايات حين تندمج سيارة فجأة في حارتي. غريزتي أن أنفّذ تصحيح توجيه سريعاً لتفاديها. قبل أن أتفاعل، ماذا ينبغي أن أتوقع أن تفعله المقطورة الثالثة (الخلفية) مقارنةً بكيفية تصرف مقطورة مفردة مع إدخال التوجيه السريع نفسه؟","options":["ستتأرجح بنفس المقدار تقريباً كمقطورة مفردة، لذا فتصحيح التوجيه السريع آمن للتنفيذ","لن تتحرك إلا بالكاد لأن عربات التحويل (الدوللي) تمتص معظم الحركة الجانبية","ستتأرجح عرضاً بحدّة أكبر بكثير وقد تنقلب، حتى مع بقاء جرّاري منتصباً","ستتخلف للخلف وتعيد استقامة نفسها، فيكون خطر الانقلاب الأكبر فعلاً على المقطورة القائدة"],"explanation":"التضخيم الخلفي (ضرب السوط) يضخّم أي حركة توجيه على طول المجموعة، فتتأرجح المقطورة الخلفية للثلاثية بحدّة أكبر بكثير وقد تنقلب بينما يبقى الجرّار منتصباً."},"95":{"q":"لقد أنهيت مساري وأدخلت مجموعة مقطوراتي المزدوجة إلى الساحة لليلة. الموقف فيه انحدار طفيف وسأترك التشكيلة دون مراقبة حتى الصباح. قبل أن أبتعد، أي مما يلي ينبغي أن أفعله لتأمين المركبة؟","options":["أترك ناقل الحركة في الوضع المحايد كي يتفرّغ نظام الهواء طوال الليل","أنزل جميع عجلات إسناد المقطورات (landing gear) إلى الأرض لإبقائها مستوية","أفصل تغذية بطارية المقطورة لمنع الأضواء من استنزاف الطاقة","أشغّل فرامل الانتظار وأضع أسافين تحت العجلات لمنع الوحدة من التدحرج"],"explanation":"عند ركن مجموعة مقطورات مزدوجة، شغّل فرامل الانتظار وضع أسافين تحت العجلات كي تمنع الفرامل المُشغّلة مع الأسافين الميكانيكية الوحدة فيزيائياً من التدحرج."},"96":{"q":"أنا أقطر مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات حين تندفع سيارة فجأة إلى حارتي مباشرةً أمامي. لمنع المقطورة الخلفية من الانقلاب، أي إجراء هو الاستجابة الأفضل؟","options":["أرفع قدمي عن دواسة الوقود وأوجّه برفق وتدريجياً إن اضطررت لتغيير مساري","أنفّذ حركة توجيه سريعة وحادة للابتعاد عن السيارة فوراً","أحافظ على سرعتي وأوجّه عكسياً بقوة لإبقاء كلتا المقطورتين تسيران مستقيمة","أكبح بقوة بينما أنعطف بالمقود بحدّة نحو الحارة المفتوحة بجانبي"],"explanation":"مع المقطورات المزدوجة، يجعل التضخيم الخلفي المقطورة الخلفية تنحرف عرضاً أوسع من الجرّار، لذا ارفع قدمك عن دواسة الوقود ووجّه بسلاسة وتدريجياً لتجنب انقلابها."},"97":{"q":"أنا أقطر مجموعة مقطورات مزدوجة على الطريق السريع حين تندفع سيارة فجأة إلى حارتي. غريزتي أن أنفّذ تصحيح توجيه سريعاً لتفاديها. لماذا تكون هذه بالضبط هي الاستجابة الخاطئة مع مجموعة مقطورات مزدوجة؟","options":["التوجيه السريع له أثر ضئيل على المقطورات المزدوجة لأنها تسير مستقيمة خلف الجرّار عند السرعة","تتضخّم حركة التوجيه السريعة على طول التشكيلة، فتنحرف المقطورة الخلفية عرضاً أوسع بكثير وقد تنقلب حتى لو بقي الجرّار منتصباً","تمتص المقطورة الأمامية الحركة وتتأرجح إلى أوسع مدى، فتنزاح الحمولة للأمام وتدفع الجرّار خارج مساره","تتوقف المقطورات المزدوجة في مسافة أقصر من المقطورة المفردة، فالانحراف الحاد أكثر أماناً من الكبح في تلك الحالة"],"explanation":"التضخيم الخلفي (ضرب السوط) يضخّم حركة التوجيه السريعة عبر كل وصلة، فتنحرف المقطورة الخلفية عرضاً أوسع بكثير وقد تنقلب حتى لو بقي الجرّار منتصباً."},"98":{"q":"أنا أجري فحصاً قبل الرحلة على مجموعة مقطوراتي المزدوجة، وقد مشيت إلى عربة التحويل (الدوللي) التي تربط مقطورتي الأمامية بالخلفية. يخبرني زميل أن الدوللي تحتاج فقط إلى نظرة سريعة لأنها 'ليس فيها أجزاء متحركة فعلية تستدعي القلق'. أي مما يلي يصف أفضل وصف لما أحتاج فعلاً إلى فحصه على الدوللي نفسها؟","options":["خطّاف القطر (pintle hook) فقط، لأن سلاسل الأمان وخطوط الهواء تخص المقطورات، لا الدوللي","بشكل رئيسي خطوط الهواء والسلك الكهربائي، لأن خطّاف القطر والسلاسل نادراً ما تفشل أثناء الرحلة","خطّاف القطر وسلاسل الأمان وخطوط الهواء، لأنها جميعاً جزء من وصلة الدوللي التي أنا مسؤول عنها","سلاسل الأمان فقط كاحتياطي، لأن خطّاف القطر يحمل الحمولة وخطوط الهواء تفحص نفسها ذاتياً"],"explanation":"لعربة التحويل (الدوللي) وصلتها الخاصة، فالفحص الكامل يعني فحص خطّاف القطر وسلاسل الأمان وخطوط الهواء معاً."},"99":{"q":"أنا أقطر مجموعة مقطورات ثلاثية محمّلة على الطريق السريع بين الولايات وأحتاج إلى مغادرة الطريق السريع. أود أخذ المنعطف بسرعة كي لا أبطئ حركة المرور خلفي. تحت أي شرط يكون من الآمن فعلاً تنفيذ منعطف سريع حاد بهذه التشكيلة؟","options":["على طريق ريفي مفتوح حيث لا توجد حركة مرور قادمة تستدعي القلق","على منحدر خروج طويل ومائل (banked) مصمّم لدعم سرعات انعطاف أعلى","في أي مكان يكون فيه الرصيف جافاً وإطاراتي ذات مداس جيد لأقصى تماسك","تحت أي شرط — المنعطف السريع الحاد ليس آمناً أبداً مع الثلاثية، لذا أبطئ أولاً"],"explanation":"المنعطف السريع الحاد ليس آمناً أبداً مع المقطورات الثلاثية لأن التضخيم الخلفي قد يقلب المقطورة الخلفية، لذا أبطئ دائماً ووجّه برفق وتدريجياً."},"100":{"q":"أنا أربط مجموعة مقطورات مزدوجة في الساحة، ويسلّمني المدرّب عربة التحويل (الدوللي) ويطلب مني وضعها في مكانها قبل أن أتمكن من قطر المجموعة. في تشكيلة المقطورات المزدوجة، ما المهمة المحدّدة التي تؤديها عربة التحويل هذه؟","options":["تربط مؤخرة المقطورة الأولى بمقدمة المقطورة الثانية","تربط العجلة الخامسة للجرّار بمقدمة المقطورة الأولى","تربط خطوط إمداد الهواء للمقطورة بأيدي المصافحة (glad hands) للجرّار","تربط مسمار الارتكاز (kingpin) بالفكوك القافلة داخل العجلة الخامسة"],"explanation":"تربط عربة التحويل (الدوللي) مقطورة بالتي تليها، فتصل مؤخرة المقطورة الأولى بمقدمة المقطورة الثانية."},"101":{"q":"أقوم بوصل عربة تحويل (دوللي) بالمقطورة الأمامية لتكوين مجموعة مزدوجة. لقد دفعت العربة إلى موضعها، والآن أحتاج إلى تثبيت ذراع القطر الخاص بها في مؤخرة المقطورة الأولى للجرّار. بأي جهاز يجب توصيل ذراع قطر العربة؟","options":["موصلات اليد الكفّية (glad hand) في مؤخرة المقطورة","خطّاف الدبوس (pintle hook) المثبّت في مؤخرة المقطورة","فكوك القفل في العجلة الخامسة على العربة","حامل واقي الطين أسفل الإطار الخلفي"],"explanation":"يُثبَّت ذراع قطر عربة التحويل على خطّاف الدبوس (pintle hook) المثبّت في مؤخرة المقطورة التي أمامها، ويجب إقفاله وتأمينه مع سلاسل الأمان."},"102":{"q":"أقوم بوصل عربة تحويل (دوللي) بمقطورتي الثانية لتكوين مجموعة مزدوجة. وبينما أوصّل قضيب جرّ العربة بخطّاف الدبوس وأمدّ يدي إلى سلاسل الأمان، يذكّرني مدرّبي بأن السلاسل ليست مجرد زينة، بل يجب تركيبها بحيث تتمكن فعلاً من إمساك الحمولة إذا انفلت خطّاف الدبوس. كيف يجب أن أؤمّن سلاسل أمان العربة؟","options":["أعلّقها برخاوة وكثير من الارتخاء حتى لا تشدّ عند انعطاف المركبة بحدّة","أمدّها مباشرةً إلى أقرب نقاط تثبيت، وأبقي كل سلسلة على جانبها","أثبّتها في إطار المقطورة وأعبّرها متقاطعةً أسفل قضيب الجرّ قبل الإقفال","أتركها غير موصولة حتى يتم توصيل واختبار خطوط الهواء وسلك الإضاءة"],"explanation":"ثبّت سلاسل أمان العربة في إطار المقطورة واجعلها متقاطعة أسفل قضيب الجرّ حتى تحتضن قضيب الجرّ وتمسكه مرفوعاً إذا انفلت خطّاف الدبوس."},"103":{"q":"أقود مجموعة مزدوجة على الطريق السريع بين الولايات بسرعة عالية، وفجأةً تنحرف سيارة أمامي فأشدّ المقود لأتفاداها. يبقى الجرّار والمقطورة الأمامية منتصبين ويسيران بشكل سليم، لكن هذه المناورة تُحدث تضخيماً خلفياً (\"ضرب السوط\"). في هذه الحالة، أي مقطورة هي الأكثر عرضةً للانقلاب؟","options":["المقطورة الأمامية، لأنها تحمل أثقل حمولة والعربة خلفها تضيف عزماً يقلبها أولاً","لا أي مقطورة، فطالما بقي الجرّار منتصباً ستسير المركبة كلها خلفه وتستعيد توازنها","كلتا المقطورتين بالتساوي، لأن وصلة خطّاف الدبوس الصلبة تجبرهما على الميل والانقلاب كوحدة واحدة","المقطورة الخلفية، لأن ضرب السوط يدفع الوحدة الأخيرة إلى مسافة أوسع بكثير من الجرّار وقد يقلبها"],"explanation":"يتزايد التضخيم الخلفي (ضرب السوط) مع كل مقطورة إلى الخلف، لذا فإن المقطورة الخلفية تتأرجح إلى أوسع مدى وهي الأكثر عرضةً للانقلاب بينما يبقى الجرّار منتصباً."},"104":{"q":"أقود مجموعة مزدوجة بسرعة عالية، وفجأةً تنحرف سيارة أمامي فأشدّ المقود لأنتقل إلى المسار التالي بسرعة. يبقى الجرّار والمقطورة الأمامية منتصبين، لكنني أرى في مرآتي المقطورة الخلفية تندفع إلى الخارج بمسافة أوسع بكثير من مقدار توجيهي. أي عبارة تفسّر بأفضل شكل ما حدث للتو؟","options":["تسبّب توجيهي السريع في تضخيم خلفي، فاندفعت المقطورة الخلفية إلى مسافة أوسع بكثير من الجرّار وكانت معرّضة لخطر الانقلاب","انحرفت المقطورة الخلفية إلى الخارج فقط لأنها الوحدة الأكثر تحميلاً وكان ينبغي وضعها أولاً خلف الجرّار","اندفعت المقطورة الخلفية إلى الخارج لأن صمام الإغلاق في عربة التحويل تُرك مفتوحاً، مما سمح للمقطورتين بالتحرك بشكل مستقل","بالغت المقطورة الخلفية في حركتي فقط لأن نظام منع انغلاق المكابح (ABS) حرّر مكابح ذلك المحور أثناء تغيير المسار"],"explanation":"تسبّب التوجيه السريع مع المركبات المزدوجة أو الثلاثية في تضخيم خلفي (ضرب السوط)، مما يجعل المقطورة الخلفية تندفع إلى مسافة أوسع بكثير وتُعرَّض لخطر الانقلاب."},"105":{"q":"أقود مجموعة مزدوجة بسرعة عالية، وفجأةً تنحرف سيارة أمامي وأحتاج إلى الانتقال إلى مسار آخر. مع علمي بأن التضخيم الخلفي قد يقلب المقطورة الخلفية حتى وإن بقي جرّاري منتصباً، كيف يجب أن أتعامل مع المقود لأمنع تلك المقطورة الأخيرة من ضرب السوط؟","options":["أوجّه توجيهاً واحداً حازماً وسريعاً لأتجاوز الخطر قبل أن تتفاعل المقطورات","أوجّه بلطف وتدرّج، مع الانتقال السلس إلى المسار وتخفيف السرعة","أوجّه عكسياً نحو الخطر لوهلة أولاً، ثم أعود لأستقر بالمقطورة الخلفية","أبقي يداً واحدة في أسفل المقود وأدير بحدّة لأقصّر زمن بقائي في المسار الآخر"],"explanation":"لتجنّب التضخيم الخلفي مع المركبات المزدوجة أو الثلاثية، وجّه بلطف وتدرّج، وتجنّب تغيير المسار السريع، وخفّف سرعتك قبل المناورة."},"106":{"q":"أقوم بتكوين مجموعة مزدوجة في الساحة باستخدام مقطورتين: إحداهما محمّلة قرب حدّ وزنها والأخرى فارغة تقريباً. يطلب منّي مشرف الرصيف أن أصلهما بأي ترتيب يكون أسرع. للحفاظ على المجموعة بأكبر قدر من الثبات وتقليل احتمال الانقلاب، كيف يجب أن أرتّبهما؟","options":["أضع المقطورة الفارغة أولاً خلف الجرّار لتثبّت الثقيلة مؤخرة المجموعة","أي ترتيب جيد طالما أن كلتيهما موصولتان بإحكام والعربة مؤمّنة","أضع المقطورة الأكثر تحميلاً أولاً مباشرةً خلف الجرّار، والأخفّ نحو المؤخرة","أضع المقطورة الأخفّ أولاً وأنقل جزءاً من حمولتها إلى الثقيلة للموازنة بينهما"],"explanation":"ضع المقطورة الأكثر تحميلاً أولاً مباشرةً خلف الجرّار، والمقطورات الأخفّ نحو المؤخرة، لأن المقطورة الخلفية الخفيفة ترتدّ وتنقلب بسهولة أكبر."},"107":{"q":"أدخلت مجموعتي المزدوجة إلى ساحة الإنزال وأستعدّ لفكّ المركبة يدوياً. الهواء موصول، والسطح مستوٍ، وأريد اتّباع التسلسل الصحيح حتى لا يتدحرج شيء أو يسقط عليّ. أي وحدة يجب أن أفصلها أولاً؟","options":["أفصل الجرّار عن المقطورة الأمامية أولاً، ثم أتعامل مع العربة والمقطورة الخلفية بعد ذلك","أسحب عربة التحويل من المنتصف قبل فعل أي شيء بأي من المقطورتين","أنزّل حامل المقطورة الأمامية وأفكّها عن الجرّار لأبدأ العملية","أفكّ المقطورة الخلفية أولاً، ثم أتقدّم للأمام عبر العربة فالمقطورة الأمامية"],"explanation":"افكّ مجموعة المركبات المزدوجة من الخلف إلى الأمام، بدءاً بالمقطورة الخلفية، ثم عربة التحويل، ثم المقطورة الأمامية، للحفاظ على ثبات المركبة في كل خطوة."},"108":{"q":"أقود مجموعة مزدوجة على طريق سريع بأربعة مسارات، وتفرمل السيارة التي أمامي بقوة. مقارنةً بقيادة مركبة بمقطورة واحدة في الظروف نفسها، كيف يجب أن أقدّر المساحة التي أحتاجها للتباطؤ والانعطاف وتغيير المسار؟","options":["أحتاج إلى مساحة أكبر لجميع هذه المناورات، لذا يجب أن أترك مسافة اتّباع إضافية وأتباطأ مبكراً أكثر مما أفعل مع مقطورة واحدة","أحتاج إلى مساحة تقارب مساحة المقطورة الواحدة، لأن المقطورة المضافة لا تغيّر احتياجاتي للتوقف والانعطاف كثيراً","أحتاج إلى مساحة أقل لأن المقطورة الثانية تضيف محاور كبح تساعدني على التوقف والانعطاف بسرعة أكبر","أحتاج إلى مساحة أكبر للتوقف فقط، أما الانعطاف وتغيير المسار فيستلزمان المساحة نفسها كالمقطورة الواحدة"],"explanation":"تحتاج المركبات المزدوجة والثلاثية إلى مساحة أكبر للتوقف والانعطاف وتغيير المسار من المقطورة الواحدة، لذا اترك مسافة اتّباع إضافية وتباطأ مبكراً لكل مناورة."},"109":{"q":"أقوم بوصل عربة تحويل (دوللي) بمقطورتي الثانية، وكانت العربة متوقفة وغير موصولة في الساحة دون مصدر هواء. قبل أن أرجع بالعربة تحت المقطورة وأقفل الفكوك، ماذا يجب أن أفعل بخزان هواء العربة؟","options":["أترك الخزان فارغاً ومُفرَّغاً، لأن الجرّار سيزوّده بالهواء بمجرد توصيل اليدين الكفّيتين بعد الوصل","أشحن خزان الهواء من الجرّار أولاً، ثم أتأكد من أنه يحتفظ بالضغط قبل الرجوع تحت المقطورة","أفرّغ الخزان تماماً حتى تبقى مكابح الزنبرك مقفلة فلا تتدحرج العربة أثناء الوصل","أنزع خزان الهواء من العربة حتى لا يعيق إجلاس العجلة الخامسة وإقفال الفكوك"],"explanation":"قبل الرجوع بعربة التحويل تحت المقطورة، اشحن خزان هوائها من الجرّار وتأكد من أنه يحتفظ بالضغط حتى تتحرّر مكابح الزنبرك."},"110":{"q":"لقد وصلت للتو مقطورة ثانية بمركبتي باستخدام عربة تحويل (دوللي). وبينما أعود سيراً لإنهاء فحص ما قبل الرحلة، أفكّر فيما تحمله كل من المقطورتين بشكل مستقل مقابل ما يوفّره الجرّار للمجموعة كلها. أي مما يلي تملك كل مقطورة في مزدوجتي نسختها الخاصة منه؟","options":["محرّك يشغّل محاور تلك المقطورة عندما يجهد الجرّار على المرتفع","مقود داخل مقصورة كي تتبع المقطورة الخلفية الانعطاف","مكابح وخطوط هواء يجب شحنها والتأكد من عملها حتى المؤخرة","سائق مكلَّف بمراقبة حمولة تلك المقطورة وضغط إطاراتها"],"explanation":"كل مقطورة في مجموعة مزدوجة تملك مكابحها وخطوط هوائها الخاصة التي يجب شحنها والتأكد من عملها حتى المقطورة الخلفية."},"111":{"q":"لقد أنهيت للتو وصل مجموعة مزدوجة وأمشي حول المركبة للتحقق من نظام الهواء قبل الانطلاق إلى الطريق السريع. تأكدت من وصول الهواء إلى المقطورة الخلفية بفتح صمام إغلاق خط الطوارئ لوهلة في مؤخرة المقطورة الأخيرة، وتحققت من أن صمامات القطع بين المقطورتين مفتوحة كي يستمر تدفق الهواء إلى الخلف. الآن أقف عند أقصى مؤخرة المقطورة الأخيرة ويدي على صمامات الإغلاق الخاصة بها. لإكمال إعداد النظام بشكل صحيح، كيف يجب أن أترك هذه الصمامات الخلفية في المقطورة الأخيرة؟","options":["مفتوحة بالكامل، حتى تُشحن مكابح المقطورة ويبقى باقي النظام مضغوطاً","مفتوحة بالطريقة نفسها كصمامات القطع بين المقطورتين، للحفاظ على استمرارية مسار الهواء","مفتوحة جزئياً، حتى يتسرّب الضغط الزائد بينما تتلقى المكابح ما يكفي من الهواء","مغلقة تماماً، حتى يبقى الهواء محبوساً في النظام بدلاً من خروجه من مؤخرة المركبة"],"explanation":"يجب أن تكون صمامات الإغلاق في مؤخرة المقطورة الأخيرة مغلقة تماماً حتى يبقى الهواء محبوساً في النظام بدلاً من خروجه من مؤخرة المركبة."},"112":{"q":"لقد وصلت للتو مقطورة ثانية بمجموعتي باستخدام عربة تحويل (دوللي)، وأجري فحص مصدر الهواء النهائي قبل الانطلاق. للتأكد من أن الهواء يصل فعلاً إلى المقطورة الخلفية وأن مكابحها ستعمل، كيف يجب ضبط صمامات الإغلاق (القطع) على المقطورة الواقعة بين الجرّار والمقطورة الخلفية؟","options":["مفتوحة، حتى يمرّ الهواء عبر نقطة الوصل ويستمر إلى الخلف نحو المقطورة الخلفية","مغلقة، حتى يبقى ضغط الهواء محبوساً في المقطورة الأمامية ويتراكم بسرعة أكبر","مغلقة، لأن صمامات المقطورة الخلفية وحدها هي التي يُفترض أن تكون مفتوحة","مفتوحة على المقطورة الأمامية لكن مُنزَعة تماماً بين المقطورتين لمنع التسرّبات"],"explanation":"يجب أن تكون صمامات الإغلاق بين المقطورتين مفتوحة حتى يمرّ الهواء عبر الوصل ويستمر إلى الخلف نحو مكابح المقطورة الخلفية."},"113":{"q":"لقد أنهيت للتو وصل عربة تحويل (دوللي) ومقطورة ثانية بمركبتي. قبل الانطلاق من الساحة، أريد التأكد من اكتمال الوصل. أي فحص يتحقق من أن نظام الهواء يعمل فعلاً عبر المجموعة بأكملها؟","options":["التأكد من أن مقياس هواء لوحة الجرّار يرتفع إلى الضغط الكامل بعد تحرير مكابح الانتظار","فتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الأخيرة للتأكد من تدفّق الهواء إلى الخلف، ثم إغلاقه","الإنصات إلى تحرّر مكابح الزنبرك عند دفعي لمقبض إمداد هواء المقطورة في المقصورة","التأكد من أن اليدين الكفّيتين على العربة موصولتان بإحكام وغير متقاطعتين قبل الصعود"],"explanation":"للتأكد من وصول الهواء إلى مكابح المقطورة الخلفية، افتح صمام إغلاق خط الطوارئ في مؤخرة المقطورة الأخيرة للتحقق من تدفّق الهواء، ثم أغلقه."},"114":{"q":"أقوم بوصل عربة تحويل (دوللي) بالمقطورة الثانية لمجموعتي المزدوجة، ويذكّرني المفتّش بتوصيل اليدين الكفّيتين بشكل صحيح. في هذه المركبة، ماذا توصّل اليدان الكفّيتان فعلاً؟","options":["سلك الإضاءة الكهربائي الذي يغذّي مصابيح المقطورة الخلفية ودائرة تحذير نظام منع انغلاق المكابح","سلاسل الأمان التي تؤمّن خطّاف الدبوس بين العربة والمقطورة الخلفية","خطوط الهواء التي تنقل هواء الكبح بين المقطورات في المجموعة","قضيب الجرّ الذي يربط ميكانيكياً لسان العربة بإطار المقطورة الأمامية"],"explanation":"اليدان الكفّيتان هما أداتا التوصيل اللتان توصّلان خطّي هواء الخدمة والطوارئ بين المقطورات حتى يصل هواء الكبح إلى المقطورة الخلفية."},"115":{"q":"أقود مجموعة مزدوجة في انعطاف ضيّق نحو اليمين عند تقاطع، وأنا قلق من أن تقطع مقطورتي الخلفية الزاوية وتصطدم بالرصيف. مقارنةً بقيادة مقطورة واحدة عبر الانعطاف نفسه، كيف سيتصرّف انحراف مسار (off-tracking) مزدوجتي؟","options":["انحراف المسار مطابق تماماً للمقطورة الواحدة، لذا يمكنني استخدام نقطة انعطافي المعتادة للمقطورة الواحدة","انحراف المسار أقل لأن عربة التحويل تجعل المقطورة الخلفية تتبع مسار الجرّار عن قرب أكبر","انحراف المسار منعدم لأن كل مقطورة توجّه نفسها بشكل مستقل حول الزاوية","انحراف المسار أكبر من المقطورة الواحدة، لذا أحتاج إلى الانعطاف أوسع وبدء انعطافي متأخراً لأبقي المقطورة الخلفية بعيداً عن الرصيف"],"explanation":"انحراف المسار أكبر مع المركبات المزدوجة من المقطورة الواحدة، لذا انعطف أوسع وابدأ الانعطاف متأخراً لتبقي المقطورة الخلفية بعيدةً عن الرصيف."},"116":{"q":"أقود مجموعة مزدوجة على الطريق السريع بين الولايات، وفجأةً تنحرف سيارة أمامي وأدرك أنني أقترب من منعطف بسرعة أكبر مما أرغب. مع علمي بأن مركبتي أقل ثباتاً من مقطورة واحدة، ما هي أفضل طريقة لإدارة قيادتي هنا؟","options":["أخفّض سرعتي مبكراً وأجعل أي توجيه سلساً ومتدرّجاً عبر المنعطف","أحافظ على سرعتي العالية لكن أشدّ المقود بسرعة لأتجاوز السيارة التي أمامي","أحافظ على سرعتي الحالية وأفرمل بقوة عند قمة المنعطف للبقاء في المسار","أزيد سرعتي قليلاً وأتّخذ خطاً حاداً حازماً كي تتبعني المقطورات بشكل أضيق"],"explanation":"المركبات المزدوجة أقل ثباتاً وعرضة للتضخيم الخلفي، لذا خفّف سرعتك مبكراً واجعل التوجيه سلساً ومتدرّجاً عبر المنعطفات."},"117":{"q":"أقوم بوصل عربة تحويل (دوللي) لإضافة مقطورة ثانية إلى مجموعتي، ولقد أنزلت للتو عين قضيب الجرّ الخاصة بالعربة على خطّاف الدبوس للجرّار-المقطورة. قبل أن أنتقل إلى توصيل خطوط الهواء وسلك الإضاءة، في أي حالة يجب أن يكون خطّاف الدبوس كي يكون هذا الوصل آمناً؟","options":["مفتوحاً حتى تستقر عين قضيب الجرّ وتتمركز ذاتياً تحت وزن المقطورة","مُقفلاً ومُغلقاً فوق عين قضيب الجرّ لتثبيت الوصلة بإحكام","مشحّماً ومتروكاً مفتوحاً حتى تدور العين بحرية أثناء الانعطافات الحادة","مُنزَعاً بمجرد عبور سلاسل الأمان وتثبيتها في إطار العربة"],"explanation":"يجب أن يكون خطّاف الدبوس مُقفلاً ومُغلقاً بالكامل فوق عين قضيب جرّ العربة لتثبيت الوصلة بإحكام."},"118":{"q":"أقوم بوصل عربة التحويل (دوللي) بمقدّمة المقطورة الخلفية في مجموعتي المزدوجة، ولقد رجعت بالعربة إلى موضعها تحت أنف المقطورة. وأنا أجري الوصل النهائي بين العربة وتلك المقطورة الخلفية، أي مكوّنين أحتاج إلى محاذاتهما كي يُقفل الوصل بشكل صحيح؟","options":["خطّاف الدبوس على قضيب جرّ العربة وعين القمر (lunette) على المقطورة الأمامية","سلاسل أمان العربة والخطّافات المثبّتة على إطار الجرّار","دبوس قفل (kingpin) المقطورة الخلفية والعجلة الخامسة للعربة","اليدان الكفّيتان وقابس السلك الكهربائي في مؤخرة العربة"],"explanation":"وصل عربة التحويل بالمقطورة الخلفية هو وصل بالعجلة الخامسة، حيث ينزلق دبوس القفل (kingpin) للمقطورة الخلفية داخل العجلة الخامسة للعربة ويُقفل فيها."},"119":{"q":"أثناء فحص ما قبل الرحلة لمجموعة مزدوجة، أنهيت وصل عربة التحويل والمقطورة الثانية، والآن أتنقّل على طول اليدين الكفّيتين وخطّاف الدبوس ووصلات خطوط الهواء. وأنا أفحص كلّاً من نقاط الوصل هذه، عن ماذا أفتّش بشكل أساسي؟","options":["أن الشريط العاكس وعلامات الطلاء الزاهية على العربة نظيفة وواضحة الرؤية","أن أضواء التخليص وإشارات الانعطاف على المقطورة تضيء جميعها عند اختبارها","أن خزان هواء العربة قد أُفرغ تماماً من أي رطوبة متراكمة قبل المغادرة","أن كل وصلة آمنة وأنه لا توجد تسرّبات هواء عند نقاط التقاء الخطوط"],"explanation":"يؤكّد فحص نقاط الوصل أن كل وصلة آمنة فعلياً وأنه لا توجد تسرّبات هواء عند نقاط التقاء الخطوط."},"120":{"q":"أقود مجموعة مزدوجة على الطريق السريع بين الولايات بسرعة عالية، وفجأةً تنحرف سيارة أمامي فأشدّ المقود لأغيّر المسار بسرعة تفادياً لها. أشعر أن الجرّار والمقطورة الأمامية سارا بشكل سليم. أي مما يلي هو الأرجح حدوثه لمقطورتي الخلفية نتيجة هذه الحركة المفاجئة؟","options":["تندفع المقطورة الخلفية إلى الخارج بمسافة أوسع بكثير من الجرّار وقد تنقلب، حتى وإن بقي جرّاري منتصباً.","تسير المقطورة الخلفية بمسار أضيق من الجرّار، فتقطع الزاوية وتهبط بعجلاتها عن الرصيف.","تنغلق مكابح المقطورة الخلفية وتجرّها بشكل مستقيم، فتحافظ على المركبة كلها في خط ثابت مستقر.","تبقى المقطورة الخلفية ثابتة لأن عربة التحويل تمتصّ الحركة وتخمد أي تأرجح."],"explanation":"مع التضخيم الخلفي، تتضاعف الحركة التوجيهية السريعة على طول المركبة فتندفع المقطورة الخلفية بمسافة أوسع بكثير وقد تنقلب حتى وإن بقي الجرّار منتصباً."},"121":{"q":"أقوم بوصل عربة تحويل (دوللي) لإضافة مقطورة ثانية إلى مجموعتي، وأنا متأخر عن جدولي. قبل أن أعود إلى المقصورة وأنطلق بهذه المجموعة المزدوجة إلى الطريق السريع، في أي حالة يجب أن تكون العربة؟","options":["موصولة برخاوة بخطّاف الدبوس حتى تنثني وتقلّل ضرب السوط في الانعطافات","موصولة ومؤمّنة بالكامل، مع إقفال خطّاف الدبوس، وتثبيت سلاسل الأمان، وتوصيل خطوط الهواء والكهرباء","موصولة عند العجلة الخامسة فقط، لأن سلاسل الأمان مجرد احتياط ويمكن وصلها لاحقاً","متروكة على الأرض تحت قضيب الجرّ حتى أصل إلى مكان مستوٍ لإكمال الوصل"],"explanation":"قبل القيادة، يجب أن تكون عربة التحويل موصولة ومؤمّنة بالكامل مع إقفال خطّاف الدبوس، وتثبيت سلاسل الأمان، وتوصيل خطوط الهواء والكهرباء."},"122":{"q":"أقود مجموعة مزدوجة على طريق سريع مزدحم بين الولايات في تكساس عندما تبدأ حركة المرور أمامي بالتباطؤ والازدحام. لأن هذه المركبة تتصرّف بشكل مختلف عن مقطورة واحدة، ماذا يجب أن أفعل بشأن المساحة أمامي مقارنةً بقيادة مقطورة واحدة؟","options":["أحافظ على المسافة نفسها التي أستخدمها مع مقطورة واحدة، لأن المركبتين تكبحان باستخدام نظام الهواء نفسه","أقصّر مسافتي قليلاً حتى لا تتمكن سيارة من التسلّل وتجبرني على الكبح بقوة أكبر","أحافظ على مساحة أكبر أمامي مما أفعل مع مقطورة واحدة","أحافظ على المسافة نفسها لكن أعتمد على مكابح المقطورة لتعويض مسافة التوقف الإضافية"],"explanation":"تحتاج المركبات المزدوجة إلى مساحة أكبر للتوقف والانعطاف وتغيير المسار، لذا حافظ على مسافة اتّباع أكبر أمامك مما تفعل مع مقطورة واحدة."},"123":{"q":"أحمل حالياً رخصة قيادة تجارية من الفئة (أ) وأقود مقطورة فان واحدة بطول 53 قدماً منذ عامين. الأسبوع المقبل تريد شركتي تكليفي بمسار يقوم فيه الجرّار بقطر مقطورة أمامية موصولة بعربة تحويل (دوللي) بمقطورة ثانية خلفها. قبل قبول الرحلة، أي تصريح يجب أن أضيفه إلى رخصتي؟","options":["لا تصريح إضافي، فرخصة الفئة (أ) تغطّي بالفعل أي تركيبة، بما في ذلك مجموعة بعربة تحويل","تصريح N، لأن عربة التحويل تحمل خزان هوائها الخاص الذي يضخّ سائلاً إلى المقطورة الخلفية","تصريح H، لأن وصل عربة بين مقطورتين يتضمّن عمل وصل خطر","تصريح T، لأن المسار يتطلّب قطر مركبات مزدوجة (أكثر من مقطورة واحدة)"],"explanation":"يتطلّب قطر مقطورتين أو ثلاث مقطورات تصريح T (المزدوجة/الثلاثية)، بغضّ النظر عن مدة حملك لرخصة الفئة (أ)."},"124":{"q":"أقود حالياً مجموعة مزدوجة وأوشك على إضافة تصريح المركبات الثلاثية كي أقطر ثلاث مقطورات. وأنا أفكّر في كيفية تأثير المقطورة الثالثة على تحكّم مركبتي وثباتها، أي عبارة يجب أن توجّه مدى حرصي في القيادة؟","options":["المركبات الثلاثية أصعب في التحكّم من المزدوجة، لذا يجب أن أوجّه بلطف أكبر وأخفّف سرعتي أكثر قبل الانعطافات","المركبات الثلاثية تتصرّف مثل المزدوجة تقريباً، لذا ستنتقل عاداتي الحالية في المسافات والتوجيه دون تغيير","المركبات الثلاثية أسهل في التحكّم من المزدوجة لأن المقطورة الإضافية تضيف وزناً يهدّئ المركبة","المركبات الثلاثية أكثر أماناً من المزدوجة في تغيير المسار السريع لأن الحمولة موزّعة على محاور أكثر"],"explanation":"كل مقطورة مضافة تزيد التضخيم الخلفي (ضرب السوط)، لذا فإن المركبات الثلاثية أقل ثباتاً من المزدوجة وتتطلّب توجيهاً ألطف وانعطافات أبطأ."},"125":{"q":"لقد أنزلت مقطورتي الأولى في الساحة وأوشك على الرجوع بعربة التحويل والجرّار تحتها لوصل مقطورة ثانية بمجموعتي. قبل أن أبدأ بمحاذاة العربة وإجراء الوصل، ماذا يجب أن أفعل بتلك المقطورة الأمامية المتوقفة أولاً حتى لا تتحرّك بينما أعمل تحتها؟","options":["أحرّر مكابح انتظارها حتى يستقر دبوس القفل بحرية على العجلة الخامسة أثناء الوصل","أوقف عجلاتها بإسفين حتى لا تتدحرج المقطورة بينما أضع العربة وأجري الوصل","أتركها تتدحرج ببطء إلى الأمام حتى أتمكن من إدخال العربة تحتها دون ارتطام بخطّاف الدبوس","أفتح أبواب الشحن الخلفية حتى أراقب انزياح الحمولة وأشعر بأي حركة للمقطورة"],"explanation":"قد تنزلق المقطورة المتوقفة أو تتدحرج، لذا فإن وضع إسفين تحت عجلاتها يمنعها من الحركة بينما تضع العربة وتجري الوصل."},"126":{"q":"أنا أوصِّل مجموعة مقطورتين مزدوجتين في ساحة بولاية تكساس. المقطورة الأولى موصولة بالفعل بالجرار، وقد سحبتُ عربة التحويل (الدوللي) وحرّرت فراملها كي أتمكن من دفعها إلى مكانها يدوياً. قبل أن أرجع المقطورة الخلفية فوقها، أين يجب أن أصطفّ بالدوللي؟","options":["موضوعة في المنتصف مباشرةً أسفل مقدمة المقطورة الأولى، خلف محاور القيادة في الجرار مباشرةً","إلى أقصى الخلف خلف المقطورة الخلفية كي يصل خطّاف القرص (البنتل هوك) إلى عمود الجرّ","في خط واحد وأمام مسمار الارتكاز (الكينغ بِن) للمقطورة الثانية مباشرةً، كي تستقر عجلتها الخامسة أسفل تلك المقطورة","تماماً أسفل هيكل الجرار كي تصل خطوط الهواء دون أن تتقاطع وصلات اليد (الغلاد هاند)"],"explanation":"تتصل العجلة الخامسة للدوللي بمسمار الارتكاز للمقطورة الخلفية، لذا ضع الدوللي في خط واحد أمام مسمار الارتكاز للمقطورة الثانية مباشرةً."},"127":{"q":"أنا أوصِّل عربة تحويل (دوللي) لإضافة مقطورة ثانية إلى مجموعتي. لقد دفعتُ الدوللي إلى مكانها خلف مقطورتي الأولى (الأمامية) وأنا مستعدٌّ لإجراء الوصلة الميكانيكية بين عمود جرّ الدوللي ومؤخرة تلك المقطورة الأولى. على أي نقطة في المقطورة الأولى يجب أن تثبت عين عمود جرّ الدوللي؟","options":["على وصلات اليد (الغلاد هاند)، كي ينغلق عمود جرّ الدوللي في وصلة إمداد الهواء","على فكَّي قفل العجلة الخامسة، كي يستقر عمود الجرّ بالطريقة نفسها التي يستقر بها مسمار الجرار","على مبيت صمام الإغلاق (القطع) الخلفي، كي يرتبط عمود الجرّ بمسار خط الهواء","على خطّاف القرص (البنتل هوك)، كي تثبت عين عمود الجرّ بإحكام في مؤخرة المقطورة الأولى"],"explanation":"تثبت عين عمود جرّ الدوللي على خطّاف القرص (البنتل هوك) المركّب في مؤخرة المقطورة الأمامية، وهو ما يربط الدوللي بالمقطورة التي أمامها."},"128":{"q":"أنا أوصِّل عربة تحويل (دوللي) بمقطورتي الثانية في الساحة. لقد أرجعتُ الدوللي أسفل المقطورة، ورفعتُ أرجل الإسناد، والآن أعمل عند خطّاف القرص (البنتل هوك) على المقطورة الأولى للجرار. بعد أن أُسقط عين عمود الجرّ على خطّاف القرص وأقفله، ما خطوة التثبيت التالية التي يجب أن أُكملها قبل توصيل خطوط الهواء وسلك الإضاءة؟","options":["توصيل سلاسل الأمان من الدوللي إلى المقطورة الأولى","توصيل الوصلة الكهربائية المرنة (البيغتيل) بصندوق توصيل الدوللي","خفض أرجل الإسناد لدعم عمود جرّ الدوللي","إغلاق صمامات القطع في مؤخرة المقطورة الأولى"],"explanation":"بعد إسقاط عين عمود الجرّ على خطّاف القرص وقفله، وصِّل سلاسل الأمان كاحتياطٍ ميكانيكيٍّ يمسك الدوللي إذا فشل الخطّاف."},"129":{"q":"أنا أوصِّل مقطورة ثانية إلى مجموعتي المزدوجة. لقد وضعتُ عربة التحويل (الدوللي) في مكانها والآن أُرجعها ببطء أسفل مقدمة المقطورة الخلفية. كيف أعرف أنني رجعتُ مسافةً كافيةً وأن الوصلة قد تمّت فعلاً؟","options":["كافية عندما يرتفع أنف المقطورة ويرفع مؤخرة الدوللي قليلاً عن الرصيف","كافية عندما تنزلق العجلة الخامسة للدوللي أسفل مسمار الارتكاز وينطبق فكّا القفل حوله","كافية عندما تلامس مئزر المقطورة العجلة الخامسة وتدفع الدوللي إلى الخلف نحو خطّاف القرص","كافية عندما يتجاوز مسمار الارتكاز العجلة الخامسة ويقفز حرّاً فوق فكَّي القفل"],"explanation":"أرجِع الدوللي حتى تنزلق عجلته الخامسة أسفل مسمار الارتكاز وينطبق فكّا القفل حوله — وهو القفل المؤكَّد الذي يؤكد تمام الوصلة."},"130":{"q":"أنا أوصِّل مجموعة مقطورتين مزدوجتين. عربة التحويل (الدوللي) موصولة بالفعل أسفل مقدمة المقطورة الخلفية، وخطّاف القرص وسلاسل الأمان مثبّتان، والهواء يصل إلى الدوللي. الآن أرفع وصلات اليد (الغلاد هاند) وسلك الكهرباء (الإضاءة) لإجراء التوصيلات النهائية. أين يجب أن تتصل خطوط الهواء والكهرباء هذه؟","options":["بمؤخرة الجرار، كي تمتد الخطوط إلى الأمام نحو الكابينة قبل أن تصل إلى المقطورتين","بمؤخرة المقطورة الأولى (الأمامية)، لأنها الوحدة التي تتلقى الهواء بالفعل من الجرار","بمقدمة المقطورة الثانية (الخلفية)، كي يصل الهواء والإضاءة إلى المقطورة التي تحملها الدوللي","بخزان هواء الدوللي نفسه، الذي يغذّي بعد ذلك بقية المقطورة الخلفية"],"explanation":"وصِّل وصلات اليد وسلك الإضاءة بمقدمة المقطورة الخلفية التي تحملها الدوللي، كي يصل الهواء المشحون والإضاءة إلى مؤخرة المجموعة."},"131":{"q":"لقد أوصلتُ للتو مقطورتي الثانية باستخدام عربة تحويل (دوللي)، وفرامل المقطورة الخلفية لا تزال مقفلة لأنه لا يصلها هواء. لكي أُمرِّر الهواء إلى تلك المقطورة الخلفية فتتحرّر فراملها، ماذا يجب أن أفعل؟","options":["أعكس وصلات اليد بين المقطورتين كي يغذّي خط الطوارئ وخط الخدمة كلٌّ منهما الآخر","أُغلق صمامات القطع في مؤخرة المقطورة الأخيرة لبناء الضغط","أحرّر فرامل انتظار الدوللي وأفصل خط خزان هواء الدوللي","أفتح صمامات القطع بين المقطورتين كي يتدفق الهواء إلى المقطورة الخلفية"],"explanation":"لا يصل الهواء إلى المقطورة الخلفية إلا عندما تكون صمامات القطع بين المقطورتين مفتوحة، فتشحن الفرامل حتى المؤخرة."},"132":{"q":"أنا أُنهي الفحص قبل الرحلة على مجموعتي المزدوجة وأسير حول كل مقطورة لفحص صمامات قطع الهواء. لقد تأكدتُ أن الصمام بين المقطورة الأمامية والخلفية مفتوح كي يتدفق الهواء عبر النظام. عندما أصل إلى صمام القطع في أقصى مؤخرة المقطورة الأخيرة، في أي وضع يجب أن يكون للقيادة العادية؟","options":["مغلق، كي يبقى نظام الهواء محكماً ويُحفظ الضغط الكامل حتى فرامل المقطورة الخلفية","مفتوح، مطابقاً للصمام بين المقطورتين كي يتدفق الهواء بحرية عبر المجموعة كلها","مفتوح، لتصريف الضغط الزائد باستمرار ومنع انغلاق الفرامل الخلفية","مفتوح إلى المنتصف، لموازنة ضغط الهواء بالتساوي بين المقطورتين الأمامية والخلفية"],"explanation":"يبقى صمام القطع في أقصى مؤخرة المقطورة الأخيرة مغلقاً كي يبقى نظام الهواء محكماً ويحفظ الضغط الكامل لفرامل المؤخرة."},"133":{"q":"لقد أوصلتُ للتو مقطورتي الثانية والدوللي، وقبل أن أخرج من الساحة أشحن نظام الهواء. وفقاً لإجراءات تكساس، ماذا يجب أن أفعل بعد ذلك للتأكد من أن المجموعة آمنة للقيادة؟","options":["أعكس وصلات اليد بين المقطورتين كي يصل هواء الطوارئ إلى خزان الدوللي بشكل أسرع","أتقدّم إلى الأمام بسرعة منخفضة وأشدّ صمام يد المقطورة للتأكد من أن فرامل المقطورة الخلفية تمسك","أُغلق كل صمامات القطع بين المقطورتين كي لا يتسرب الهواء أثناء القيادة","أُرجِع مجموعة المزدوجتين بشكل مستقيم لبضعة أقدام للتأكد من أن عربة التحويل تسير بشكل صحيح"],"explanation":"بعد شحن النظام، تقدّم إلى الأمام بسرعة منخفضة وطبّق صمام يد المقطورة للتأكد من أن فرامل المقطورة الخلفية تشتبك وتمسك قبل الدخول إلى حركة المرور."},"134":{"q":"أنا أوصِّل عربة تحويل (دوللي) لإضافة مقطورة ثانية إلى مجموعتي. أثناء الفحص قبل الرحلة، أتحقق مما تسهم به الدوللي نفسها في المركبة. أي مما يلي شيءٌ تُوفّره عربة التحويل بنفسها؟","options":["وحدة قدرة خاصة بها ومجموعة نقل حركة للمساعدة في سحب الحمولة","كابينة خاصة بها وعناصر تحكم في التوجيه للمناورة بسرعة منخفضة","فرامل وعجلات خاصة بها يجب فحصها وصيانتها بالهواء","وقود وإمداد كهربائي خاصان بها مستقلان عن الجرار"],"explanation":"تسير عربة التحويل على محورها الخاص بعجلاتها وفراملها الخاصة، لذا يجب فحص خزان هوائها وفراملها وصيانتها بالهواء."},"135":{"q":"لقد أنهيتُ رحلتي بالمزدوجتين وأنا أفصل المقطورة الخلفية عن عربة التحويل (الدوللي) في الساحة. لقد ثبّتُّ العجلات بالحوائل بالفعل وخفضتُ إسناد الدوللي كي يحمل الوزن. وفقاً لإجراء الفصل الصحيح، ما خطوتي التالية؟","options":["أسحب الجرار والمقطورة الأمامية إلى الأمام لكسر الالتحام قبل أي شيء آخر","أترك خطوط الهواء والكهرباء موصولة كي تبقى المقطورة الخلفية محتفظة بضغط الفرامل","أحرّر فرامل انتظار الدوللي كي يتحرّر الدوللي من المقطورة","أفصل خطوط الهواء وسلك الكهرباء بين الدوللي والمقطورة الخلفية"],"explanation":"بعد تثبيت العجلات بالحوائل وخفض إسناد الدوللي ليحمل الوزن، افصل خطوط الهواء وسلك الكهرباء قبل فصل الوحدتين."},"136":{"q":"أنا أفصل المقطورة الخلفية من مجموعتي المزدوجة. خطوط الهواء وسلك الكهرباء مفصولة، وسلاسل الأمان مرفوعة عن خطّاف القرص، وفكّا قفل العجلة الخامسة للدوللي محرَّران. قبل أن أسحب عربة التحويل من أسفل المقطورة، ماذا يجب أن أفعل أولاً لمنع المقطورة من التدحرج؟","options":["أثبّت عجلات المقطورة بالحوائل كي لا تتحرك بمجرد إزالة الدوللي","أخفض أرجل إسناد المقطورة حتى تدعم الحمولة بثبات","أفتح صمامات القطع في مؤخرة المقطورة لتصريف الهواء","أحرّر فرامل انتظار الدوللي كي يخرج بحرية"],"explanation":"ثبّت عجلات المقطورة بالحوائل قبل سحب الدوللي كي لا تتدحرج المقطورة بمجرد أن تفقد إسناد الدوللي وكبحه."},"137":{"q":"لقد أوصلتُ للتو مقطورتي الثانية باستخدام عربة التحويل (الدوللي)، لكني نسيتُ فتح صمامات القطع بين المقطورتين، فلا يصل أي هواء إلى نظام فرامل تلك المقطورة الخلفية. عندما أبدأ بالتقدم إلى الأمام في الساحة، ماذا يجب أن أتوقّع أن تفعله فرامل المقطورة الخلفية؟","options":["متحرّرة تماماً، لأن المقطورة لا يمكنها الحصول على أي هواء لتطبيقها","مقفلة، لأن فرامل الزنبرك تنطبق تلقائياً عند عدم وجود ضغط هواء","تعمل بشكل طبيعي من فرامل خدمة الجرار عبر سلك الكهرباء","تتحرّر ببطء من تلقاء نفسها مع تصريف الهواء المتبقي من الخطوط"],"explanation":"تُبقى فرامل الزنبرك مفتوحةً بفضل ضغط الهواء، لذا عند عدم وصول هواء إلى المقطورة تنطبق تلقائياً وتقفل الفرامل."},"138":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين على طريق سريع بين الولايات مزدحم، وألاحظ أن المقطورة الخلفية أصعب في المتابعة مما هي عليه عندما أقود مقطورة واحدة. كي أبقى واعياً بما تفعله المقطورة الخلفية وأرصد أي مشاكل في الإطارات أو التمايل مبكراً، ما الذي يجب أن أجعله عادةً أثناء القيادة؟","options":["أعتمد على كاميرا الرجوع في الجرار لأن المقطورتين تحجبان رؤيتي","أُسرع لوهلة لأشدّ المجموعة بشكل مستقيم كي تصطفّ المقطورة الخلفية","أتفقّد مراياي بشكل متكرر لمراقبة كلتا المقطورتين","أُعدّل مسافة المتابعة فقط عندما أشعر بتمايل المقطورة الخلفية"],"explanation":"تفقّد مراياك بشكل متكرر لمراقبة كلتا المقطورتين، ورصد إطار منخفض أو مدخّن، واكتشاف تمايل المقطورة."},"139":{"q":"أنا أقود مجموعة مقطورتين مزدوجتين وأقترب من منعطف يمين عند تقاطع في المدينة فيه رصيف على الزاوية. بالمقارنة مع المقطورة الواحدة التي أسحبها عادةً، كيف يجب أن أتعامل مع هذا المنعطف كي لا تركب مقطورتي الخلفية فوق الرصيف؟","options":["أقطع المنعطف أضيق وأبقى قريباً من الرصيف، لأن المقطورة الخلفية تتبع دائماً مسار الجرار بالضبط","آخذ المنعطف بسرعة أكبر كي تستقيم المقطورتان بسرعة وتبقيا مصطفّتين خلف الجرار","أنعطف بحدّة أكبر إلى الزاوية كي تتجاوز مؤخرة المقطورة الثانية داخل الرصيف","أجعل المنعطف أوسع من المعتاد، لأن المقطورة الخلفية تسير داخل مسار الجرار وتحتاج مساحة إضافية"],"explanation":"اجعل المنعطفات أوسع من المعتاد لأن عجلات المقطورة الخلفية تنحرف إلى داخل مسار الجرار وتحتاج مساحة إضافية."},"140":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين على امتداد مستوٍ ومفتوح من طريق I-10 عندما تضرب مركبتي رياحٌ جانبية قوية مفاجئة من الجانب. بالمقارنة مع كيفية دفع تلك العصفة نفسها لمركبة بمقطورة واحدة، كيف يجب أن أتوقّع استجابة المزدوجتين؟","options":["ستدفع الرياح الجانبية المزدوجتين أكثر مما تدفع المقطورة الواحدة، لذا ينبغي أن أُبطئ وأوجّه بلطف لأبقى في مساري.","ستؤثر الرياح الجانبية على المزدوجتين بنفس قدر تأثيرها على المقطورة الواحدة، لذا تكفي تصحيحاتي المعتادة للمقطورة الواحدة.","ستؤثر الرياح الجانبية على المزدوجتين أقل من المقطورة الواحدة، لأن المقطورة الإضافية تضيف وزناً يقاوم الرياح.","لا تأثير للرياح الجانبية تقريباً على مجموعة مزدوجتين محمّلة، لذا يمكنني الحفاظ على سرعتي والاستمرار في مساري."],"explanation":"تدفع الرياح الجانبية القوية المزدوجتين أكثر من المقطورة الواحدة، لذا أبطئ ووجّه بلطف لتبقى في مسارك."},"141":{"q":"أنا أقود مجموعة مقطورتين مزدوجتين محمّلتين وأقترب من منحدر خروج منحنٍ على طريق سريع. اللافتة عند المنحدر تُظهر سرعة مُحدّدة 35 ميلاً في الساعة. بالنظر إلى التضخيم الخلفي وخطر انقلاب مقطورتي الخلفية، ما السرعة الأكثر أماناً لأسلك بها هذا المنحدر؟","options":["تماماً عند 35 ميلاً في الساعة المُحدّدة، لأن سرعة المنحدر تأخذ مركبتي في الحسبان أصلاً","أقل بكثير من 35 ميلاً في الساعة المُحدّدة، لأن المزدوجتين قد تقلبان المقطورة الخلفية عند السرعة المُحدّدة","بضعة أميال فوق 35، طالما أنني أوجّه بسلاسة وأبقى في مساري","السرعة المُحدّدة بالضبط مقبولة إذا كانت مقطورتي الأثقل محمّلة في الخلف"],"explanation":"اسلك المنحدرات بسرعة أقل بكثير من السرعة المُحدّدة لأن التضخيم الخلفي قد يقلب المقطورة الخلفية للمزدوجتين حتى عند سرعة المنحدر المُحدّدة."},"142":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين محمّلتين على طريق I-35 بسرعة الطريق السريع عندما تقطع سيارةٌ الطريق أمامي فجأةً، فأقوم غريزياً بحركة توجيه سريعة واحدة لتفاديها. يبقى الجرار منتصباً ويسير بشكل جيد، لكن أي جزء من مركبتي في أكبر خطر من الانحراف بعيداً والانقلاب من تلك الحركة المفاجئة؟","options":["محور التوجيه للجرار، لأن هناك أدرتُ المقود ومن هناك تبدأ القوة","المقطورة الأمامية (الأولى)، لأنها تحمل أثقل حمولة خلف الجرار مباشرةً","المقطورة الخلفية (الأخيرة)، لأن التضخيم الخلفي يجعلها تنحرف أكثر","عربة التحويل (الدوللي)، لأنها نقطة الارتكاز التي تربط المقطورتين"],"explanation":"يضخّم التضخيم الخلفي، وهو تأثير «طقطقة السوط»، حركة التوجيه على امتداد المركبة فتنحرف المقطورة الأخيرة أكثر وتكون الأرجح للانقلاب."},"143":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين على الطريق السريع، ومنحدر خروج محدَّد أمامي يُظهر سرعة استرشادية للسيارات. لتقليل خطر انقلابي بهذه المركبة، أين أحتاج أكثر ما يكون إلى خفض سرعتي إلى ما دون ما يبدو آمناً لسيارة ركاب واحدة؟","options":["على الامتدادات المستقيمة الطويلة من الطريق المفتوح، حيث تسير المقطورتان خلفي","أثناء عبور ساحات محطات الوزن المستوية الفارغة قبل أن أعود إلى سرعتي","على الطرق العريضة متعددة المسارات حيث يكون لديّ مساحة وافرة على الجانبين","عبر المنحنيات وعلى منحدرات الدخول والخروج، حيث يمكن أن تنقلب المركبة"],"explanation":"يكون خطر الانقلاب أعلى ما يكون في المنحنيات وعلى منحدرات الدخول والخروج، حيث يمكن للقوى الجانبية و«طقطقة السوط» أن تقلب المركبة، لذا أبطئ قبلها بوقت كافٍ."},"144":{"q":"أنا أُشغّل مجموعة مقطورتين مزدوجتين وأقوم بجولة الفحص قبل الرحلة. بعد توصيل عربة التحويل (الدوللي) والمقطورة الخلفية، أريد التأكد من أن كل مقطورة في المركبة صالحة للسير قبل أن أنطلق. على كل مقطورة في المجموعة، أي العناصر يجب أن أفحص؟","options":["إطارات كل مقطورة وفراملها وأضواءها","فقط إطارات المقطورة الخلفية، لأن المقطورة الأمامية فُحصت بالفعل في المحطة","فقط وصلات اليد وخطوط الهواء بين المقطورتين","فقط فرامل المقطورة الأمامية وأضواءها، لأنها تحمل أثقل حمولة"],"explanation":"في مجموعة مزدوجتين أو ثلاث مقطورات، كل مقطورة وحدةٌ مستقلة صالحة للسير، لذا يجب أن تفحص إطارات وفرامل وأضواء كلٍّ منها."},"145":{"q":"أثناء فحصي قبل الرحلة لمجموعة مقطورتين مزدوجتين، أعمل على التوصيل الكهربائي عند المقطورة الخلفية. سلك الإضاءة (البيغتيل) الممتد إلى تلك المقطورة هو ما أفحصه. لكي يكون صالحاً للسير، كيف يجب أن يكون هذا السلك؟","options":["متروكاً بفائض كبير كي يتدلّى بحرية ولا يُشدّ في المنعطفات","موصولاً بإحكام في المقبس ومثبّتاً كي لا ينفكّ","ملفوفاً ومستقراً على عمود جرّ الدوللي حتى تُحتاج الأضواء ليلاً","ملفوفاً بإحكام بشريط كهربائي عند القابس لمنع دخول رطوبة الطريق"],"explanation":"يحمل سلك الإضاءة (البيغتيل) الطاقة إلى أضواء المقطورة الخلفية، لذا يجب أن يكون مثبّتاً بإحكام في المقبس ومؤمَّناً ضد اهتزاز الطريق."},"146":{"q":"أثناء فحصي قبل الرحلة لمجموعة مقطورتين مزدوجتين، أفحص عربة التحويل (الدوللي) التي تربط المقطورة الأمامية بالمقطورة الخلفية. وأنا أتفحّص لسان الدوللي (عمود الجرّ)، أي نتيجة تعني أنه في حالة آمنة وصالحة للسير ويمكنني المتابعة؟","options":["عمود الجرّ به انحناء طفيف، لكنه ما زال يصل إلى خطّاف القرص ويثبت","عمود الجرّ يُظهر شرخاً شعرياً قرب العين، لكن سلاسل الأمان سليمة","عمود الجرّ مستقيم، بلا انحناءات أو شقوق في أي مكان على امتداد طوله","عمود الجرّ مطليّ حديثاً، رغم أنني لا أستطيع رؤية المعدن تحته"],"explanation":"عمود جرّ عربة التحويل جزءٌ حامل للحمل يجب أن يكون مستقيماً بلا انحناءات أو شقوق، إذ إن أي تلف قد يؤدي إلى انفصال المقطورة الخلفية."},"147":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين كلتاهما محمّلتان بالكامل على الطريق السريع بين الولايات عندما تكبح حركة المرور أمامي بشدة فجأةً. بالمقارنة مع قيادة مقطورة واحدة فارغة، ما الذي يجب أن أتوقّعه أكثر من مجموعتي المزدوجة المحمّلة في هذا الموقف؟","options":["ستسير بإحكام أكبر داخل المسار، فيمكنني المتابعة من مسافة أقرب من المعتاد","ستستجيب بشكل أسرع لتوجيه المقود، مما يتيح لي الانحراف بعيداً عن التباطؤ","ستتشبّث بالطريق بشكل أفضل أثناء الكبح لأن الوزن الإضافي يضيف احتكاكاً","ستحتاج إلى مسافة أكبر بكثير للتوقف، لذا يجب أن أكبح أبكر من مركبة فردية فارغة"],"explanation":"تحمل المزدوجتان المحمّلتان وزن مقطورتين ممتلئتين، لذا تحتاجان مسافة أكبر بكثير للتوقف ويجب أن تكبح أبكر وتترك مسافة متابعة أكبر."},"148":{"q":"أنا أنقل مجموعة مقطورتين مزدوجتين بسرعة الطريق السريع عندما تقطع سيارةٌ الطريق أمامي فجأةً وأريد غريزياً أن أشدّ المقود بقوة لأنحرف إلى المسار التالي. لماذا تكون تلك الحركة المفاجئة الحادة في التوجيه خطرة بشكل خاص مع هذه المركبة؟","options":["يمكن للتضخيم الخلفي أن يقذف المقطورة الخلفية أبعد بكثير من الجرار ويقلبها، حتى مع بقاء الكابينة منتصبة","الحركة المفاجئة تنقل وزناً كبيراً إلى الأمام فيفقد محور التوجيه للجرار احتكاكه ويندفع للأمام مباشرةً","الحركة السريعة تجبر فكَّي قفل عربة التحويل على الانفكاك، فتسقط المقطورة الخلفية عن خطّاف القرص","المقطورة الخلفية الأخف ستسير ببساطة بشكل مستقيم خلفك وتُخمّد الحركة، فتُهدر المناورة وقت ردّ الفعل"],"explanation":"يمكن للتضخيم الخلفي، وهو تأثير «طقطقة السوط»، أن يقذف المقطورة الخلفية أبعد بكثير من الجرار ويقلبها حتى مع بقاء الكابينة منتصبة."},"149":{"q":"أنا أسحب مجموعة مقطورتين مزدوجتين على طريق ريفي في تكساس عندما تتباطأ حركة المرور أمامي فجأةً. بدأت مقطورتي الخلفية تشعرني بعدم الاستقرار وما زال أمامي منحنى قادم. أي نهج في القيادة يمنحني أفضل تحكم وأقل خطر للانقلاب مع هذه المركبة؟","options":["أُسرع لوهلة وأوجّه بحدّة لأستقيم بالمركبة قبل وصول المنحنى","أقود بسلاسة وثبات وببطء، موجّهاً بلطف وكابحاً مبكراً كي تبقى المقطورة الخلفية مستقرة","أحافظ على سرعة ثابتة وأقوم بتغيير مسار سريع واحد لأضع مساحة أكبر حول المقطورتين","أنقر الفرامل بقوة على دفعات قصيرة لخفض السرعة قبل بلوغ المنحنى"],"explanation":"المزدوجتان مُعرّضتان للتضخيم الخلفي، لذا قُد بسلاسة وثبات وببطء، موجّهاً بلطف وكابحاً مبكراً لإبقاء المقطورة الخلفية مستقرة."},"150":{"q":"أنت تسحب مجموعة مقطورتين مزدوجتين بسرعة الطريق السريع عندما تقطع سيارةٌ الطريق أمامك فجأةً فتشدّ المقود بسرعة إلى اليسار، ثم تعود إلى مسارك لتجنّب الاصطدام بها. يبقى الجرار والمقطورة الأمامية منتصبين ويسيران بشكل مستقيم. بناءً على التضخيم الخلفي، ما الأرجح أن يحدث للمقطورة الخلفية؟","options":["تسير بإحكام خلف المقطورة الأمامية وتُخمّد الحركة قبل أن تستقر مجدداً في المسار.","تدفع المقطورة الأمامية والجرار جانباً، وتجرّ الوحدة كلها نحو الانثناء (الجاك نايف).","تنحرف أوسع بكثير من الجرار ويمكن أن تنقلب رغم بقاء الجرار منتصباً.","تبقى مستوية وثابتة لأن عربة التحويل تُبقي المقطورة الخلفية في خط واحد بثبات."],"explanation":"بسبب التضخيم الخلفي، تجعل حركة التوجيه السريعة المقطورة الخلفية تنحرف أوسع بكثير من الجرار ويمكن أن تنقلب بينما يبقى الجرار منتصباً."},"151":{"q":"أقود مجموعة مقطورات مزدوجة على الطريق السريع بسرعة 55 ميلاً في الساعة عندما تنحرف سيارة فجأة إلى مساري أمامي مباشرة. من بين ردود الفعل أدناه، أيها الأكثر احتمالاً أن يتسبب في انقلاب مقطورتي الخلفية؟","options":["تخفيف الضغط عن دواسة الوقود تدريجياً لفتح مسافة أتباع أكبر","الحفاظ على سرعة ثابتة وترك المسافة إلى السيارة الأمامية تتسع من تلقاء نفسها","تطبيق ضغط فرامل خفيف وثابت قبل وقت كافٍ من الوصول إلى السيارة الأبطأ","سحب عجلة القيادة بسرعة للانحراف إلى المسار التالي لتجنب السيارة"],"explanation":"سحب عجلة القيادة لانحراف سريع يثير التضخيم الخلفي، مما يقذف المقطورة الخلفية أبعد بكثير من الجرار ويخاطر بانقلابها."},"152":{"q":"أقود مجموعة مقطورات مزدوجة محمّلة على منحدر خروج من طريق سريع مع منعطف مُعلَن أمامي. لمنع المقطورة الخلفية من الانقلاب عندما يضيق المنحدر، متى يجب أن أُنزل شاحنتي إلى سرعة آمنة؟","options":["قبل دخولي المنعطف، بينما لا تزال الشاحنة على الطريق المستقيم","أثناء المنعطف، مع تخفيف الضغط عن دواسة الوقود بينما تدور المقطورات حوله","بعد أن أشعر بالمقطورة الخلفية تبدأ بالميل، ثم أكبح بقوة","داخل قمة المنعطف، بمجرد أن يستقيم الجرار"],"explanation":"أنهِ كل الكبح على الطريق المستقيم قبل دخول المنعطف، لأن الكبح داخل المنعطف ينقل الوزن وقد يثير انقلاباً مع المقطورات المزدوجة."},"153":{"q":"أقوم بوصل مجموعة مقطورات مزدوجة في الساحة. إحدى المقطورات محمّلة بشدة بأكياس الأسمنت والأخرى تحمل حمولة خفيفة من المنصات الفارغة. وأنا أخطط للترتيب، أين يجب أن توضع مقطورة المنصات الأخف في المجموعة؟","options":["خلف الجرار مباشرة لتركب مقطورة الأسمنت الثقيلة في الخلف من أجل الجر","في مؤخرة المجموعة، خلف مقطورة الأسمنت الأثقل","لا فرق لأن عربة التحويل (الدوللي) تعادل الوزن بين المقطورتين","أي وضع يبقي المقطورة الأثقل بعيدة عن الدوللي، بغض النظر عن الأمام أو الخلف"],"explanation":"ضع المقطورة الأكثر تحميلاً أولاً خلف الجرار والمقطورات الأخف نحو الخلف، بحيث تذهب المقطورة الخفيفة إلى مؤخرة المجموعة."},"154":{"q":"أقوم بوصل مجموعة مقطورات مزدوجة في الساحة. إحدى المقطورات محمّلة بشدة والأخرى فارغة تقريباً وخفيفة. وأنا أقرر أي مقطورة تذهب خلف الجرار مباشرة وأيها إلى الخلف، أيٌّ من الترتيبات التالية هو الطريقة الأكثر أماناً لبناء مجموعتي؟","options":["ضع المقطورة الخفيفة شبه الفارغة أولاً خلف الجرار ليجر الجرار وزناً أقل في الأمام","ضع المقطورات بأي ترتيب رُكنت به، لأن عربة التحويل (الدوللي) تعادل الحمل بينها","ضع المقطورة المحمّلة بشدة أولاً خلف الجرار وأبقِ المقطورة الأخف نحو الخلف","حمّل كلتا المقطورتين إلى وزن متقارب أولاً، عندها لن يهم أيها يذهب في الأمام"],"explanation":"ضع المقطورة الأكثر تحميلاً أولاً خلف الجرار والمقطورات الأخف نحو الخلف، لأن المقطورة الخفيفة أمام مقطورة ثقيلة أكثر احتمالاً للانقلاب."},"155":{"q":"أُرسَل في أول رحلة مقطورات مزدوجة لي، ويبلّغني مدير الساحة عبر اللاسلكي أن شاحنتي مبنية من جرار ومقطورتين \"جرو\" (pup) موصولتين بعربة تحويل. وأنا أمشي للبحث عن معداتي في الموقف، عمّا يجب أن أبحث عندما يقول \"جراء\" (pups)؟","options":["مقطورة صندوقية مغلقة طويلة واحدة تُقسَّم إلى حمولتين في المحطة","صندوقا قلّاب مفتوحان من الأعلى مقيّدان بسلسلة معاً كي يفرغ أحدهما حمولته في الآخر","زوج من عربات سكك حديدية صهريجية مضغوطة موضوعة على شاحنة مسطحة للنقل على الطريق السريع","مقطورتان أقصر يُقصد بهما أن تُجرّا معاً كمجموعة خلف الجرار"],"explanation":"إن \"الجرو\" (pup) هو مقطورة أقصر تُجرّ كمجموعة، لذا فإن جراراً مع جروَين موصولين بعربة تحويل هو تكوين مقطورات مزدوجة."},"156":{"q":"أقوم بوصل مقطورة ثانية في مجموعتي المزدوجة، وعربة التحويل (الدوللي) التي أصلها تحتها تركب على محورين بدلاً من واحد. عندما أدوّن هذا في تقرير الفحص قبل الرحلة، كيف يجب أن أعرّف هذه القطعة من المعدات بشكل صحيح؟","options":["عربة تحويل ثنائية المحور","عربة تحويل ثنائية قضيب الجر","عربة تحويل أحادية المحور","عربة تحويل بعجلة خامسة مزدوجة (تاندم)"],"explanation":"تُصنَّف عربة التحويل حسب عدد محاورها، لذا فإن العربة التي تركب على محورين هي عربة تحويل ثنائية المحور."},"157":{"q":"أقوم بوصل مجموعة مقطورات مزدوجة. بعد تثبيت عربة التحويل (الدوللي) في مؤخرة مقطورتي الأولى بخطاف القرص (البنتل) وسلاسل الأمان، أحتاج إلى شحن نظام هواء الدوللي كي تنطلق فرامله وأتمكن من دحرجته للخلف لوصل المقطورة الثانية. عندما أصل خطوط هواء الدوللي، من أين يأتي ضغط الهواء الذي يشغّل الدوللي فعلاً؟","options":["من خزان هواء المقطورة الثانية، الذي يغذّي للأمام عبر مفاصل الدوللي بمجرد وصلها","من المقطورة الأولى، التي تزوّد الدوللي بالهواء عبر خطوط الهواء الموصولة بها","من خزان احتياطي مخصّص مثبّت على الدوللي يمتلئ قبل حتى تشغيل الجرار","من الخزان الرطب للجرار مباشرة، متجاوزاً كلتا المقطورتين عبر خط طوارئ مفتوح"],"explanation":"تحصل عربة التحويل (الدوللي) على هوائها من المقطورة الأولى التي أمامها عبر خطوط الهواء الموصولة."},"158":{"q":"انتهيت للتو من وصل مجموعتي المزدوجة وتراكم الهواء على كلتا المقطورتين. قبل أن أخرج من الساحة إلى الطريق السريع، أريد أن أتأكد من أن فرامل مقطورتي الثانية (الخلفية) تعمل فعلاً. ما الطريقة الصحيحة للتحقق من ذلك؟","options":["أتقدّم ببطء وأترك عجلة القيادة لأرى ما إذا كانت الشاحنة تنجرف باستقامة، مما يخبرني أن الفرامل الخلفية متوازنة","أخرج إلى الطريق السريع وأصل إلى السرعة بسرعة، لأن فرامل المقطورة الخلفية لا تهم إلا حين تكون المجموعة محمّلة بالكامل ومتحركة","أطبّق فرامل المقطورة وأحاول التحرك للأمام برفق، متأكداً من أنها تثبّت الشاحنة في مكانها قبل أن أغادر الساحة","أفتح وأغلق صمام إيقاف خط الطوارئ في مؤخرة المقطورة الخلفية وأستمع إلى الهواء، ثم أفترض أن الفرامل بخير"],"explanation":"اختبر فرامل المقطورة بتطبيقها ومحاولة التحرك للأمام برفق للتأكد من أنها تثبّت الشاحنة في مكانها."},"159":{"q":"أقود مجموعة مقطورات مزدوجة محمّلة بالكامل على طريق سريع في تكساس عندما تتباطأ حركة المرور أمامي فجأة وأحتاج إلى الكبح. مقارنةً بقيادة مقطورة واحدة بالسرعة نفسها، ماذا يجب أن أتوقع من مقطوراتي المزدوجة المحمّلة بالكامل؟","options":["تنعطف بشكل أضيق، فأستطيع الانعطاف إلى التقاطعات أبكر مما لو كانت مقطورة واحدة","أكثر ثباتاً في السرعة، فتغييرات المسار السريعة أكثر أماناً مما لو كانت مقطورة واحدة","تركب أقرب إلى الأرض، فالرياح الجانبية تؤثر فيها أقل من مقطورة واحدة","تحتاج إلى مسافة أطول لتتوقف توقفاً كاملاً مقارنةً بمقطورة واحدة"],"explanation":"تحمل مجموعة المقطورات المزدوجة المحمّلة وزناً وزخماً أكبر موزَّعاً على مقطورتين، فتحتاج إلى مسافة أطول للتوقف من مقطورة واحدة."},"160":{"q":"أنا مرخّص لقيادة المقطورات المزدوجة والآن أقود مجموعة مقطورات ثلاثية على طريق سريع بين الولايات في تكساس للمرة الأولى. مقارنةً بالشاحنة المزدوجة التي أجرّها عادةً، ماذا يجب أن أتوقع بشأن عدد المقطورات وعربات التحويل (الدوللي) المسؤول عن فحصها ووصلها؟","options":["يوجد مقطورات أكثر وعربات تحويل أكثر، لذا توجد نقاط وصل إضافية وخطاطيف قرص (بنتل) لفحصها.","يوجد مقطورات أكثر لكن عربة تحويل واحدة نفسها، لأن دوللي واحد يخدم المجموعة كلها.","يوجد نقاط وصل أقل إجمالاً، فمجموعة الثلاثية أسرع في الفحص من المزدوجة في الواقع.","عدد المقطورات نفسه؛ فقط وزن الحمولة يتغير بين المزدوجة والثلاثية."],"explanation":"المقطورات الثلاثية فيها ثلاث مقطورات موصولة بعربتي تحويل، مما يضيف نقاط وصل وخطاطيف قرص (بنتل) أكثر للفحص من المزدوجة."},"161":{"q":"أقوم بالفحص قبل الرحلة على مجموعتي المزدوجة وأتفقّد كل نقطة وصل على طول الشاحنة، وخطاف القرص (البنتل) على عربة التحويل، وسلاسل الأمان، ووصلات الهواء (مفاصل اليد)، والعجلة الخامسة وفكوك القفل. يسألني متدرّب لماذا أهتم بفحص كل من هذه المواضع بعناية. أيٌّ من التالي هو أفضل سبب أقدّمه لإيلاء كل نقطة وصل هذا الاهتمام الدقيق؟","options":["كل نقطة وصل هي المكان الذي يسحب فيه المحرك طاقة إضافية، فأي وصلة مرتخية ستقلّل قدرتي على الجر على المنحدرات","كل نقطة وصل هي مكان يمكن أن يتسرّب فيه الهواء أو يرتخي، مما قد يقطع الهواء عن المقطورة الخلفية أو يدعها تنفصل","كل نقطة وصل تساعد خزان الدوللي على تخزين هواء احتياطي أكثر، فالوصلة المحكمة تحسّن مسافة كبحي","كل نقطة وصل توجّه هواء التبريد إلى فرامل المقطورة، ففحصها يبقي الطبول من فرط السخونة"],"explanation":"كل نقطة وصل يمكن أن يتسرّب منها الهواء أو ترتخي، مما يقطع الهواء عن المقطورة الخلفية أو يدعها تنفصل."},"162":{"q":"أقوم بجولة الفحص قبل الرحلة حول مجموعة مقطورات مزدوجة وأصل إلى عربة التحويل (الدوللي) التي تربط المقطورة الأمامية بالخلفية. أريد أن أركّز فحصي على أجزاء الدوللي التي تبقي المقطورتين موصولتين ومتدحرجتين بأمان فعلاً. أي عناصر على الدوللي يجب أن أتفقّدها؟","options":["دواسة فرامل الدوللي ووصلة التوجيه التي تدير محوره أثناء المنعطفات الحادة","واقيات الطين على الدوللي والشريط العاكس على طول إطاره للرؤية الليلية","إطارات الدوللي ووصلة الخطاف لديه (خطاف القرص/قضيب الجر)","حامل الإطار الاحتياطي على الدوللي وصندوق التخزين حيث تُحفظ السلاسل"],"explanation":"افحص إطارات الدوللي ووصلة الخطاف لديه (خطاف القرص/قضيب الجر)، لأنها تبقي المقطورتين موصولتين ومتدحرجتين بأمان."},"163":{"q":"أقوم بالفحص قبل الرحلة على مجموعة مقطورات مزدوجة قبل مغادرة الساحة. تفقّدت ضغط الإطارات، وتأكّدت أن المقطورة الأخف محمّلة نحو الخلف، وخزان هواء الدوللي يبدو جيداً. وأنا أنهي جولتي، ما الشيء الوحيد الذي يجب أن أتحقّق منه عن كل المقطورات قبل أن أخرج؟","options":["أن المقطورتين الأمامية والخلفية تحملان وزناً متقارباً كي تركب المجموعة بمستوى","أن صمامات الإيقاف (القطع) في آخر مقطورة تماماً متروكة مفتوحة","أن كل مقطورة مطلية ومعلَّمة لتتطابق لسهولة التعريف","أن كل مقطورة موصولة بشكل صحيح، مع تثبيت خطاف القرص (البنتل) وسلاسل الأمان ومفاصل اليد"],"explanation":"تأكّد أن كل مقطورة موصولة بشكل صحيح مع إقفال خطاف القرص (البنتل) وتثبيت سلاسل الأمان ووصل مفاصل اليد."},"164":{"q":"تقود مجموعة مقطورات مزدوجة ويضعك مسار التسليم نفسه على أربعة أسطح مختلفة اليوم. على أيٍّ من هذه الأسطح يُرجَّح أن تفقد مقطوراتك المزدوجة الجر وتصبح أصعب في السيطرة عليها؟","options":["طريق ذو مسارين مكسوّ بمطر متجمّد خفيف","طريق سريع بين الولايات نظيف وجاف بمسارات معلَّمة عريضة","موقف تجهيز معبّد فارغ بلا حركة مرور أخرى","طريق ريفي محروق بالشمس بعد فترة جفاف طويلة"],"explanation":"تفقد المقطورات المزدوجة الجر بسهولة أكبر على أكثر الأسطح زلقاً، لذا فإن طريقاً مكسوّاً بمطر متجمّد خفيف يعطي أعلى خطر للانقلاب على شكل سكين والانقلاب."},"165":{"q":"أقود مجموعة مقطورات مزدوجة على الطريق السريع بسرعة الطريق عندما تنحرف سيارة فجأة أمامي فأهزّ عجلة القيادة لتجنبها. يبقى الجرار والمقطورة الأمامية في مساري، لكن ما الذي يُرجَّح أن تفعله المقطورة الخلفية نتيجةً لحركة التوجيه السريعة هذه؟","options":["تدفع الجرار للأمام وتجبرني على التسارع","تتأرجح بعرض كافٍ لتُقذف خارج الطريق أو تنقلب","تُسحب للخلف باستقامة وتساعد في إبطاء الشاحنة كلها","تنطبق مباشرة خلف المقطورة الأمامية وتصحّح نفسها"],"explanation":"تتسبب حركة التوجيه السريعة بسرعة الطريق في التضخيم الخلفي (ضربة السوط)، مما يجعل المقطورة الخلفية تتأرجح بعرض أكبر بكثير وتخاطر بأن تُقذف خارج الطريق أو تنقلب."},"166":{"q":"أقود مجموعة مقطورات مزدوجة على طريق سريع مقسوم بسرعة 60 ميلاً في الساعة عندما تندمج سيارة أبطأ في مساري أمامي مباشرة. بسبب التضخيم الخلفي (\"ضربة السوط\")، أي إجراء هو الأهم لتجنّبه كي لا تتأرجح المقطورة الخلفية بعرض وتنقلب؟","options":["تخفيف الضغط عن دواسة الوقود تدريجياً قبل أن تُغلَق المسافة","زيادة مسافة الأتباع لترك مجال أكبر للتفاعل","تغيير مسار مفاجئ وسريع للالتفاف حول المركبة الأبطأ","النظر في مراياي لتتبّع موضع المقطورة الخلفية"],"explanation":"يثير تغيير المسار المفاجئ السريع التضخيم الخلفي (ضربة السوط)، مما يؤرجح المقطورة الخلفية بعرض أكبر بكثير من الجرار وربما يقلبها حتى مع بقاء الجرار منتصباً."},"167":{"q":"أقوم بوصل مجموعة مقطورات مزدوجة ويخبرني المفتّش أن أتأكد من أن صمام الإيقاف بين المقطورتين مفتوح كي يصل الهواء إلى المقطورة الخلفية. أمشي للخلف، لكن الجهاز الذي يشير إليه أعرفه باسم مختلف على ورقة الفحص. أيٌّ من هذه اسم آخر للصمام نفسه؟","options":["مفصل اليد (الجلاد هاند)","خطاف القرص (البنتل)","العجلة الخامسة","حنفية القطع (كت-أوت كوك)"],"explanation":"صمام الإيقاف في مؤخرة المقطورة أو بين المقطورتين الموصولتين يُسمّى أيضاً حنفية القطع (كت-أوت كوك)."},"168":{"q":"إذا فقدت المقطورة الخلفية الهواء أثناء القيادة، فإن فراملها:","options":["تنطلق وتتحرّر","تنطبق","تتسارع","لا تفعل شيئاً"],"explanation":"تنطبق الفرامل إذا فُقد الهواء."},"169":{"q":"أقود مجموعة مقطورات مزدوجة على طريق سريع مزدحم بين الولايات ومركبة بطيئة أمامي تجبرني على الانتقال إلى المسار التالي. مقارنةً بقيادة مقطورة واحدة، لماذا كان ينبغي أن أخطّط لمساحة إضافية قبل وقت كافٍ من وصولي إلى هذه النقطة؟","options":["لأن المقطورات المزدوجة تحتاج إلى مجال أكبر لتغيير المسار، فيجب أن أبني فجوة أكبر قبل الإشارة والاندماج","لأن المقطورات المزدوجة تتيح لي تغيير المسار أسرع، فالمساحة الإضافية لتشغيل المحرك في الخمول وقتاً أطول فقط","لأن فرامل المقطورة الخلفية تنطبق أولاً، فالمساحة الإضافية تتيح للمجموعة التوقف في مسافة إجمالية أقصر","لأنني أستطيع ببساطة إرجاع المقطورات المزدوجة للخلف إن أُغلقت الفجوة، فالمساحة منطقة إعادة تموضع احتياطية"],"explanation":"المقطورات المزدوجة أطول وتحتاج إلى مجال أكبر لتغيير المسار، فيجب أن تبني فجوة أكبر قبل الإشارة والاندماج تدريجياً بدلاً من تغيير المسار بشكل مفاجئ."},"170":{"q":"أقود مجموعة مقطورات مزدوجة بسرعة الطريق وألحق بشاحنة أبطأ أودّ تجاوزها. مقارنةً بقيادة جرار-مقطورة واحدة، لأي مناورة تتطلب مجموعتي المزدوجة مسافة أكبر بشكل ملحوظ قبل أن أتمكّن من إكمالها بأمان؟","options":["التباطؤ إلى التوقف على طريق مستوٍ مع المقطورتين فارغتين","تجاوز الشاحنة الأبطأ والعودة إلى مساري","إطلاق البوق لتحذير الشاحنة بأنني أتجاوزها","ترك الشاحنة في الخمول على الكتف بينما أتفقّد الحمولة"],"explanation":"المقطورات المزدوجة أطول بكثير، لذا فإن التجاوز والعودة إلى مسارك يحتاجان إلى طريق صافٍ أكبر بكثير من التجاوز بمقطورة واحدة."},"171":{"q":"أُخرج مجموعة مقطورات مزدوجة من الساحة: إحدى المقطورات محمّلة بشدة والأخرى محمّلة بخفة. يجب أن تذهب كلتاهما في هذه الرحلة. لإبقاء الشاحنة ثابتة قدر الإمكان وتقليل فرصة الانقلاب، كيف يجب أن أرتّبهما؟","options":["ضع المقطورة الخفيفة أولاً، خلف الجرار مباشرة، والمقطورة الثقيلة في الخلف","لا فرق بأي ترتيب تذهبان، طالما أن كلتا المقطورتين موصولتان بشكل صحيح","ضع المقطورة الثقيلة أولاً، خلف الجرار مباشرة، والمقطورة الأخف نحو الخلف","قسّم الوزن بحيث تحمل كل مقطورة حملاً متساوياً قبل مغادرة الساحة"],"explanation":"ضع دائماً المقطورة الأكثر تحميلاً أولاً، خلف الجرار مباشرة، مع المقطورات الأخف نحو الخلف لتقليل الارتداد وخطر الانقلاب."},"172":{"q":"أقود مجموعة مقطورات مزدوجة محمّلة صعوداً على منحدر طويل وتباطأت شاحنتي إلى ما دون الحد المعلَن بكثير بينما تتكدّس حركة المرور خلفي. للتعامل مع مجموعتي البطيئة بأمان وقانونياً، أين يجب أن أضعها؟","options":["في أقصى المسار الأيسر، كي يكون لدي حاجز ولا أضطر إلى الاندماج مع حركة مرور المنحدرات الداخلة","فوق علامات الخط الأوسط كي تختار السيارات التالية جانباً لتتجاوزني منه","في أي مسار يتيح لي الحفاظ على سرعتي دون تغيير المسار أبداً على المنحدر","في المسار الأيمن، مع البقاء يميناً كي تتمكّن حركة المرور الأسرع من تجاوزي على اليسار"],"explanation":"يجب أن تبقى المركبة البطيئة في المسار الأيمن وأن تبقى يميناً كي تتجاوز حركة المرور الأسرع على اليسار، وهذا مهم بشكل خاص مع المقطورات المزدوجة الأقل ثباتاً."},"173":{"q":"أقوم بوصل عربة التحويل (الدوللي) لربط مقطورة ثانية بمجموعتي. بعد إرجاع الدوللي تحت مقدّمة المقطورة الخلفية وتثبيته في خطاف القرص (البنتل)، يذكّرني مدرّبي أن هذه الوصلة هي المكان الذي تحدث فيه معظم أخطاء الوصل. إلى جانب خطاف القرص نفسه، ماذا يجب أن أثبّت أيضاً عند هذه النقطة لإبقاء الدوللي مرتبطاً إن انفك الخطاف يوماً ما؟","options":["سلاسل الأمان","صمامات الإيقاف (القطع) في مؤخرة آخر مقطورة","ذراع مرفاع جهاز الهبوط (اللاندينغ غير)","حوامل واقيات الطين للمقطورة"],"explanation":"عند وصل عربة التحويل (الدوللي) يجب أن تثبّت كلاً من خطاف القرص (البنتل) وسلاسل الأمان، التي تمنع الدوللي والمقطورة من الانفصال إن فشل خطاف القرص."},"174":{"q":"أقود مجموعة مقطورات مزدوجة على طريق سريع بين الولايات بسرعة الطريق عندما تنحرف سيارة فجأة أمامي فأهزّ عجلة القيادة لتفاديها. في هذا الموقف بالضبط، ما الخطر الأكبر الذي أواجهه من حركة التوجيه السريعة تلك؟","options":["سيفقد المحور الأمامي للجرار الجر أولاً ويزلق المقصورة إلى المسار التالي","سيتسبب التضخيم الخلفي (\"ضربة السوط\") في تأرجح المقطورة الخلفية بعرض أكبر بكثير وقد يقلبها حتى مع بقاء جراري منتصباً","ستنفك خطوط هواء عربة التحويل (الدوللي)، مفرغةً فرامل المقطورة الخلفية","ستنطبق عجلات الدفع خلف المقصورة على شكل سكين وتدفع الشاحنة كلها جانبياً"],"explanation":"التضخيم الخلفي (ضربة السوط) هو أكبر خطر للمقطورات المزدوجة، مؤرجحاً المقطورة الخلفية بعرض أكبر بكثير وقادراً على قلبها حتى مع بقاء الجرار منتصباً."},"175":{"q":"أقود مجموعة مقطورات مزدوجة في المسار الأيمن من طريق سريع رباعي المسارات عندما ألحق بجرار بطيء خرج للتو من حقل. سيارة سيدان أسرع تقترب مني من الخلف في المسار الأيسر. مقارنةً بالمقطورة الواحدة التي أجرّها عادةً، ما الذي يؤثر فيه الطول الإضافي لمقطوراتي المزدوجة أكثر شيء في هذه المناورة؟","options":["لا شيء يتغير، لأن طول الشاحنة لا يهم إلا عند الركن وليس عند التحرك على الطريق السريع","أستطيع إكمال التجاوز أسرع، لأن المقطورة الثانية تضيف زخماً يساعدني على التسارع حول الجرار البطيء","أحتاج إلى فجوة أكبر بكثير ووقت أطول للخروج وتجاوز الجرار البطيء بالكامل والعودة إلى مساري","يجب أن أكبح بقوة وأبقى خلف الجرار، لأن المقطورات المزدوجة لا يُسمح لها أبداً بتغيير المسار للتجاوز على طريق سريع"],"explanation":"لأن المقطورات المزدوجة أطول من مقطورة واحدة، فإن التجاوز بأمان يتطلب فجوة أكبر ووقتاً أطول للخروج وتجاوز الشاحنة كلها والعودة."},"176":{"q":"أنا أقود مجموعة مقطورات مزدوجة محمّلة نحو منحدر طويل وشديد، وهناك لافتة تحذّر من منحدر بنسبة 6% أمامي. ومع وجود مقطورتين خلفي، تحتاج المجموعة بالفعل إلى مسافة أكبر للتوقف مقارنة بمقطورة واحدة. قبل أن أبدأ النزول، ماذا يجب أن أفعل بناقل الحركة للحفاظ على أكبر قدر من التحكّم أثناء النزول؟","options":["أن أرفع الترس إلى ترس أعلى لتبقى دورات المحرّك (RPM) منخفضة وتقوم المكابح بمهمة الحفاظ على سرعتي طوال الطريق نزولاً","أن أتركه في الوضع المحايد وأنزلق بحرّية كي لا يقاوم نظام نقل الحركة الانحدار، ثم أضغط المكابح برفق حسب الحاجة قرب الأسفل","أن أبقى على نفس الترس الذي كنت أستخدمه على الطريق المستوي، لأن تغيير التروس على المنحدر مع مقطورتين يهدّد بفقدان السيطرة","أن أخفّض الترس إلى ترس منخفض قبل النزول كي يساعد كبح المحرّك في التحكّم بسرعتي ولا أعتمد فقط على مكابح الخدمة"],"explanation":"خفّض إلى ترس منخفض قبل المنحدر كي يتحكّم كبح المحرّك في سرعتك وتبقى مكابح الخدمة باردة وفعّالة."},"177":{"q":"أنا أقود مجموعة مقطورات مزدوجة نزولاً على منحدر جبلي طويل، والمركبة تكتسب بعض السرعة، لذا فإن غريزتي تدفعني إلى الضغط على دواسة المكابح وإطلاقها بسرعة مراراً وتكراراً للسيطرة على سرعتي. لماذا يُعدّ الضغط المتكرر أو خفق مكابح الخدمة على هذا المنحدر خطأً؟","options":["كل دورة خفق تطلق هواءً أكثر مما يستطيع الضاغط تعويضه، لذا قد أستنزف ضغط الهواء لديّ وأفقد مكابحي","الخفق يسمح للهواء البارد بالدوران داخل الطبول، فترتفع حرارة المكابح وتضعف بشكل أسرع على المنحدر","الضغط المتكرر على الدواسة يمنع بطانات المكابح من الإمساك بالطبول، فتتحسّن قدرتي على التوقف فعلياً مع كل دورة","الضغط المتكرر يدفع هواءً إضافياً إلى الخطوط، مكوّناً ضغطاً زائداً خطيراً قد يؤدي إلى تمزّق خزّانات الهواء"],"explanation":"كل تطبيق للمكابح يطلق هواءً أكثر مما يستطيع الضاغط تعويضه، لذا فإن الخفق المتكرر يستنزف الضغط حتى تفشل المكابح."},"178":{"q":"أنا أقود مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات عندما تبدأ محاور الدفع في الانزلاق على بقعة مبلّلة وتبدأ المركبة في الانزلاق الجانبي. مقارنةً بقاطرة تسحب مقطورة واحدة، لماذا يصعب بشكل خاص استعادة السيطرة على هذا الانزلاق مع المقطورات المزدوجة؟","options":["تميل المقطورتان إلى استقامة نفسهما وتتبعان القاطرة تلقائياً","يمكن لأي من المقطورتين أن تنطوي (تنحرف) بشكل مستقل، مما يجعل تصحيح الانزلاق أصعب منه مع مقطورة واحدة","ستسحب قوة كبح المقطورة الخلفية المركبة بأكملها لتستقيم من تلقاء نفسها","يساعد وزن المقطورة الإضافي على التشبّث بالطريق وإبطاء المركبة فيتوقف الانزلاق بسرعة"],"explanation":"تحتوي المقطورات المزدوجة على نقاط تمفصل متعددة، لذا يمكن لأي من المقطورتين أن تنطوي من تلقاء نفسها، مما يجعل الانزلاق أصعب في التصحيح منه مع مقطورة واحدة."},"179":{"q":"أنت تسحب مجموعة مقطورات مزدوجة صعوداً على منحدر مدخل سريع زلق. وبينما تضغط على دواسة الوقود للاندماج، تشعر بعجلات الدفع الخلفية للقاطرة تبدأ بالدوران ومؤخرة القاطرة تبدأ بالانزلاق جانبياً. لاستعادة الجر وإعادة السيطرة على المركبة، ما هو إجراؤك الأول؟","options":["اضغط على المكابح بقوة لإبطاء عجلات الدفع الدائرة وإيقاف الانزلاق","وجّه المقود بقوة في الاتجاه المعاكس للانزلاق لمقاومة تأرجح المؤخرة","ارفع قدمك عن دواسة الوقود لتسمح لعجلات الدفع باستعادة الجر","اضغط أكثر قليلاً على دواسة الوقود لسحب المركبة لتستقيم مجدداً"],"explanation":"ينتج انزلاق عجلات الدفع عن قوة زائدة، لذا فإن رفع القدم عن دواسة الوقود يسمح لعجلات الدفع باستعادة الجر وإيقاف الانزلاق."},"180":{"q":"أنا أعيد مجموعة مقطورات مزدوجة إلى الساحة، وكلتا المقطورتين فارغتان تماماً، على طريق سريع جاف بين الولايات وحركة المرور خفيفة. أثناء القيادة، أي سلوك في التعامل ينبغي أن أكون أكثر حذراً منه بسبب كون المركبة فارغة؟","options":["تتشبّث المقطورات الفارغة بالطريق بشكل أفضل، لذا يمكنني الكبح بقوة أكبر وفي وقت متأخر عن المعتاد بأمان","تتوقف المركبة الفارغة في مسافة أقصر بكثير، لذا ينبغي أن أتوقّع خطر الاصطدام من الخلف من قِبل المتعقّبين","تتآكل الإطارات والمكابح بشكل أقل بكثير عندما تكون فارغة، لذا لا حاجة لمراقبة المقطورة الخلفية إطلاقاً","يمكن للمقطورات الخفيفة أن ترتد وتنزلق فوق المطبّات، لذا ينبغي أن أبطئ سرعتي وأوجّه المقود بسلاسة"],"explanation":"المقطورات الفارغة أو المحمّلة بخفّة يكون عليها وزن قليل على الإطارات، لذا فإنها ترتد وتنزلق فوق المطبّات، مما يستدعي سرعات أبطأ وتوجيهاً سلساً."},"181":{"q":"أنا أقود مجموعة مقطورات مزدوجة على الطريق السريع بين الولايات بسرعة الطريق السريع عندما تتقدّم سيارة فجأة أمامي، مما يجبرني على إجراء تصحيح توجيه سريع واحد لتجنّبها. تبقى القاطرة ومقطورتي الأمامية منتصبتين، لكنني أشعر بمؤخرة المركبة تنطلق بحدّة إلى الجانب. بسبب التضخيم الخلفي (تأثير \"ضرب السوط\")، أي وحدة هي الأكثر احتمالاً للانقلاب أولاً؟","options":["المقطورة الخلفية، لأن تأثير ضرب السوط يضخّم التأرجح نحو مؤخرة المجموعة","المقطورة الأمامية، لأنها تحمل أثقل حمولة وتقع في أعلى موضع خلف القاطرة","عربة التحويل (الدولّي)، لأنها أخفّ وحدة وتدور بين المقطورتين","القاطرة، لأن مُدخَل توجيه السائق يبدأ من الأمام وينتقل إلى الخلف"],"explanation":"يجعل التضخيم الخلفي، أي تأثير ضرب السوط، كل مقطورة تتأرجح بشكل أوسع، لذا فإن المقطورة الأخيرة تتأرجح بأعنف شكل وتنقلب أولاً."},"182":{"q":"عادةً ما أقود مقطورة واحدة طولها 53 قدماً، لكن غداً سيضعني مرسل الإرساليات على مجموعة مقطورات مزدوجة للمرة الأولى. وأنا أخطّط لكيفية اختلاف تعامل هذه المركبة، أي مما يلي ينبغي أن أتوقّعه مقارنةً بمقطورتي الواحدة؟","options":["ستتتبّع المسار بشكل أضيق خلال المنعطفات، لذا يمكنني الحفاظ على خطوط انعطافي المعتادة","ستكون أقل ثباتاً وأطول، لذا سأحتاج إلى مساحة أكبر للتوقف والانعطاف وتغيير المسار","ستكون أسهل في الرجوع إلى الرصيف لأن المقطورة الخلفية تدور بشكل مستقل","ستتوقف في مسافة أقصر لأن حمل الكبح موزّع على عدد أكبر من المحاور"],"explanation":"سحب مقطورتين أقل ثباتاً وأطول من سحب مقطورة واحدة، لذا تحتاج المقطورات المزدوجة إلى مساحة أكبر للتوقف والانعطاف وتغيير المسار."},"183":{"q":"أنا أسحب مجموعة مقطورات مزدوجة محمّلة على طريق سريع جاف عندما تبطئ حركة المرور فجأة أمامي. سيارة صغيرة (ذات أربع عجلات) كانت بجانبي تكبح بقوة وتنزوي إلى مساري، تاركةً فجوة كنت سأعتبرها آمنة لو كنت أقود سيارتي الشخصية. للاستجابة بشكل صحيح، أي افتراض ينبغي ألا أفترضه أبداً بشأن مركبتي؟","options":["أن مقطوراتها يمكن أن تتأرجح بشكل أوسع من مقطورة واحدة في مناورة سريعة","أنها تحتاج إلى مساحة أكبر للتوقف والانعطاف وتغيير المسار من مقطورة واحدة","أنها يمكن أن تتوقف في نفس مسافة سيارة الركاب التي أمامي","أنها أقل ثباتاً من سحب مقطورة واحدة فقط خلف القاطرة"],"explanation":"مجموعة المقطورات المزدوجة المحمّلة لها كتلة أكبر بكثير ومسافة كبح أطول، لذا لا تفترض أبداً أنها يمكن أن تتوقف بنفس سرعة سيارة الركاب."},"184":{"q":"أنا أسحب مجموعة مقطورات مزدوجة وأحتاج إلى ترك المركبة متوقّفة على منحدر هابط طفيف في محطة شاحنات بينما أدخل إلى الداخل. لا أفصل أي شيء وتبقى المجموعة موصولة. أي إجراء مطلوب للحفاظ على أمان المقطورتين المتوقّفتين؟","options":["اترك المقطورات في الترس كي يثبّتها نظام نقل الحركة في مكانها ضد المنحدر","اسحب مكبح الانتظار في القاطرة فقط وثق به لتثبيت المجموعة بأكملها","وجّه عجلات المقطورة الخلفية نحو الرصيف كي لا تتدحرج هابطةً","ضع حواجز (موانع) تحت العجلات أو فعّل مكابح المقطورة كي لا تتدحرج المجموعة"],"explanation":"عند ركن المقطورات المزدوجة، ضع حواجز تحت العجلات أو فعّل مكابح المقطورة كي لا تتدحرج المجموعة، خاصةً على أي منحدر."},"185":{"q":"أثناء فحصي قبل الرحلة لمجموعة مقطورات مزدوجة، ألاحظ أن الوصلة بين عربة التحويل (الدولّي) والمقطورة الخلفية مرتخية وغير مقفلة بالكامل. إذا تجاهلت هذا وسحبت المجموعة إلى الطريق السريع على أي حال، ما هي أخطر عاقبة أُخاطر بها؟","options":["قد تنفصل المقطورة الخلفية وتنفكّ عن بقية المجموعة أثناء قيادتي","ستتدحرج المقطورة الخلفية ببساطة بسلاسة أكبر بمجرد أن تستقر عند سرعة الطريق السريع","ستستهلك المجموعة وقوداً أقل بشكل ملحوظ لأن الوصلة المرتخية تقلّل السحب بين المقطورات","ستمسك مكابح المقطورة الخلفية وتوقف المجموعة بشكل أسرع في حالة الطوارئ"],"explanation":"يمكن أن تفشل الوصلة المرتخية أو المقفلة بشكل غير سليم تحت قوى الطريق وتسمح للمقطورة الخلفية بالانفصال عن المجموعة."},"186":{"q":"لقد وصلت للتوّ عربة تحويل (دولّي) بمقطورتي الثانية في الساحة. ثبّتُّ خطّاف القرن (البِنتل) وسلاسل الأمان، ووصلت اليدين الواصلتين (glad hands) وسلك الإضاءة، والآن أريد أن أتأكد من أن فكّي القفل في العجلة الخامسة قد أُغلقا فعلاً حول مسمار الارتكاز (الكنغ بِن) قبل أن أنطلق. أي إجراء يؤكّد أن هذه الوصلة آمنة؟","options":["ينبغي أن أجري هذا الفحص فقط بعد التزوّد بالوقود، لأن اهتزاز المضخة قد يرخي الفكّين","ينبغي أن أسحب برفق إلى الأمام ضد مكابح المقطورة المقفلة (اختبار الشدّ) للتحقق من أن فكّي القفل يمسكان بمسمار الارتكاز","ينبغي أن أجري هذا الفحص فقط بعد الركن في نهاية الرحلة، عندما لا يوجد حمل يحرّك الوصلة","ينبغي أن أفتح صمّام الإغلاق في مؤخرة المقطورة الأخيرة وأستمع لصوت الهواء للتأكد من أن الفكّين مستقرّان"],"explanation":"مع قفل مكابح المقطورة، فإن السحب برفق إلى الأمام (اختبار الشدّ) يؤكّد أن فكّي القفل قد أُغلقا حول مسمار الارتكاز."},"187":{"q":"أنا أقود مجموعة مقطورات مزدوجة عائداً فارغاً بعد التسليم، وهناك رياح جانبية قوية تدفع عبر الطريق السريع المكشوف. مع معرفتي بكيفية تصرّف المركبة الخفيفة في هذه الظروف، ما الذي أكون أكثر عرضةً لخطره إذا لم أبطئ سرعتي وأوجّه المقود برفق؟","options":["اقتصاد أفضل في الوقود، لأن المقطورات الفارغة تخلق سحباً أقل وتسمح لي بالانزلاق عبر الهبّات","ركوبة أكثر سلاسة وأكثر ثباتاً، لأن المقطورات الفارغة تتتبّع مساراً مستقيماً وتسير منخفضةً في الرياح","الانقلاب، لأن الرياح المؤثرة على المقطورة الخلفية الخفيفة الفارغة يمكن أن تقلب المجموعة","مسافة توقف أقصر، لأن المجموعة الفارغة أخفّ وتمسك المكابح بشكل أسرع بكثير"],"explanation":"يمكن للرياح الجانبية القوية أن تقلب بسهولة مقطورةً خلفيةً فارغةً أو محمّلةً بخفّة لأن وزناً قليلاً يثبّتها."},"188":{"q":"أنا أقود مجموعة مقطورات ثلاثية على طريق تكساس ريفي سريع عندما أرى سيارة معطّلة تسدّ جزءاً من مساري أمامي مباشرة. لمنع المقطورة الخلفية من التأرجح بشكل واسع والانقلاب بسبب التضخيم الخلفي، أي نهج يمنحني أفضل تحكّم في المركبة؟","options":["حافظ على سرعة الطريق السريع وأجرِ مُدخَل توجيه سريعاً وحاسماً واحداً للالتفاف حول العائق بسرعة","اكبح بقوة في اللحظة الأخيرة كي أستقيم وأوجّه المقود بحدّة لتجاوز المركبة المعطّلة","حافظ على سرعتك مرتفعة لكن أدِر المقود بحدّة مبكراً لأترك لنفسي مساحة إضافية بعيداً عن السيارة","قلّل سرعتك مبكراً واستخدم توجيهاً بطيئاً تدريجياً كي تتتبّع المقطورة الخلفية مساراً دون أن تنطلق كالسوط"],"explanation":"يمنع الإبطاء مبكراً والتوجيه برفق التضخيم الخلفي (ضرب السوط) الذي يمكن أن يجعل المقطورة الخلفية تتأرجح بشكل واسع وتنقلب."},"189":{"q":"أنا أجري فحصاً قبل الرحلة لمجموعة مقطورات مزدوجة قبل مغادرة الساحة. المقطورة الخلفية فارغة وأنا في عجلة من أمري للانطلاق على الطريق. بخصوص المكابح على كل مقطورة في مجموعتي، في أي حالة يجب أن تكون قبل أن أتمكّن من القيادة قانونياً وبأمان؟","options":["يجب أن تكون المكابح على كل مقطورة، بما فيها الخلفية الفارغة، مضبوطةً بشكل سليم وفي حالة عمل جيدة","يجب أن تعمل مكابح المقطورة القائدة (الأمامية) فقط، لأنها تحمل الحمولة الأثقل وتقوم بمعظم عملية التوقف","يجوز ترك مكابح المقطورة الخلفية الفارغة مفصولةً لتقليل التآكل، طالما كانت مكابح المقطورة الأمامية تعمل","المكابح تحتاج إلى العمل فقط إذا كانت أي من المقطورتين قد صُنعت في أو بعد 1 مارس 1998 ومزوّدة بنظام ABS"],"explanation":"يجب أن تكون المكابح في كل مقطورة في مجموعة مزدوجة أو ثلاثية، بما فيها الخلفية الفارغة، مضبوطةً بشكل سليم وتعمل قبل القيادة."},"190":{"q":"أنا أسحب مجموعة مقطورات مزدوجة على طريق تكساس ريفي ذي مسارين وأرى منعطفاً حادّاً أمامي بسرعة إرشادية معلنة. نظراً لكيفية تعامل المقطورات المزدوجة، متى ينبغي أن أقوم بمعظم عملية الكبح لإدارة سرعتي بأمان عبر هذا المنعطف؟","options":["اكبح بخفّة وأنا داخل المنعطف، مخفّفاً فقط عندما تتتبّع المقطورة الخلفية مسارها عبر قمة المنعطف","اكبح قبل دخولي المنعطف كي أكون بالفعل على سرعة آمنة عندما أبدأ بالانعطاف","انتظر حتى ما بعد المنعطف مباشرة، ثم اكبح بقوة لاستعادة أي مسافة تتبّع فقدتها","تجنّب الكبح تماماً وانزلق ببساطة عبر المنعطف، لأن الكبح في المقطورات المزدوجة لا يكاد يكون ضرورياً"],"explanation":"أنهِ الكبح قبل دخول المنعطف، لأن الكبح أثناء الانعطاف يجمع قوى ترفع خطر الانقلاب والانطواء مع المقطورات المزدوجة."},"191":{"q":"أنا أقود مجموعة مقطورات مزدوجة وأقترب من انعطاف يمين حادّ نحو شارع مدينة ضيّق، مع سيارة متوقّفة ورصيف قريب من الزاوية. وأنا أبدأ الانعطاف، ما الذي يجب أن أحسب حسابه كي لا تصطدم المقطورة الخلفية بالرصيف أو بالسيارة المتوقّفة؟","options":["ستتأرجح المقطورة الخلفية بشكل واسع إلى اليسار، لذا ينبغي أن ألتصق بالرصيف الأيمن بإحكام خلال الانعطاف","سترتفع المقطورة الخلفية وترتد إلى أعلى، لذا ينبغي أن أُسرع للحفاظ عليها مثبّتةً على الطريق","ستنحرف المقطورة الخلفية إلى الداخل، متّبعةً مساراً أضيق من القاطرة، لذا يجب أن أنعطف بشكل أوسع وأترك مساحة على اليمين","ستتوقف المقطورة الخلفية على مسافة قصيرة خلفي، لذا أحتاج فقط إلى مراقبة المسافة الأمامية للقاطرة"],"explanation":"في انعطاف اليمين تنحرف المقطورة الخلفية إلى الداخل، متّبعةً مساراً أضيق من القاطرة، لذا انعطف بشكل أوسع واحمِ المساحة على اليمين."},"192":{"q":"لقد سحبت للتوّ عربة التحويل (الدولّي) من تحت المقطورة الخلفية لمجموعتي المزدوجة، وأنا متوقّف على منحدر هابط طفيف في ساحة الإنزال. قبل أن أبتعد لإنجاز الأوراق، ما هو أهمّ شيء يجب أن أفعله بعربة التحويل نفسها؟","options":["اترك خطوط الهواء موصولةً بالمقطورة الخلفية كي تبقى مكابح عربة التحويل مشحونةً أثناء وقوفها","افتح صمّام تصريف خزّان الهواء في عربة التحويل لتنفيس الضغط كي ينفكّ مكبح الانتظار بالكامل","وجّه قضيب جرّ عربة التحويل نحو أسفل المنحدر كي تتتبّع مساراً مستقيماً إذا بدأت تنجرف على المنحدر","ضع حواجز تحت عجلات عربة التحويل واخفض دعامتها كي لا تتدحرج بعيداً على المنحدر"],"explanation":"عربة التحويل القائمة بذاتها هي جسم ثقيل غير مؤمّن، لذا ضع حواجز تحت عجلاتها واخفض دعامتها كي لا تتدحرج بعيداً على منحدر."},"193":{"q":"أنا أسحب مجموعة مقطورات مزدوجة على طريق سريع مزدحم بأربعة مسارات، وأمسح الطريق على مسافة 12 إلى 15 ثانية أمام مركبتي. ألاحظ تكدّس حركة المرور عند مخرج على بُعد ربع ميل تقريباً أمامي. لماذا يُعدّ النظر إلى هذه المسافة البعيدة مهمّاً بشكل خاص عندما أسحب مقطورتين؟","options":["كي أتمكّن من البدء بالكبح والتخطيط لتوقّفاتي مبكراً، لأن مجموعة المقطورات المزدوجة تحتاج إلى مسافة أكبر بكثير للتوقف بسلاسة من مقطورة واحدة","كي أتمكّن من إجراء تغيير مسار سريع في اللحظة التي أرى فيها التباطؤ، فأُخرج مركبتي إلى منطقة آمنة قبل أن تتفاعل بقية حركة المرور","كي أتمكّن من الإسراع وتجاوز الازدحام قبل أن يصل إليّ، مبقياً المقطورة الخلفية الأثقل من الارتداد","كي أتمكّن من رصد لافتات الطريق واللوحات الإعلانية مبكراً بما يكفي للتأكد من رقم مخرجي قبل أن ألتزم بالمنحدر الخارج"],"explanation":"تحتاج مجموعة المقطورات المزدوجة إلى مسافة أكبر بكثير للتوقف من مقطورة واحدة، لذا انظر بعيداً إلى الأمام لرصد التباطؤ والبدء بالكبح بسلاسة مبكراً."},"194":{"q":"أنا على وشك مغادرة الساحة وأنا أسحب مجموعة مقطورات مزدوجة. عربة التحويل والوصلة بين مقطورتيّ تمّ توصيلهما الليلة الماضية من قِبل الوردية الليلية، وبقيت المركبة متوقّفةً منذ ذلك الحين. للتشغيل بأمان وقانونياً، ماذا ينبغي أن أفعل بشأن الوصلة بين المقطورتين قبل أن أنطلق؟","options":["أثق بعمل الوردية الليلية لأن المقطورتين لم تتحركا، وأتخطّى إعادة فحص الوصلة لتوفير الوقت","أفحص الوصلة بين المقطورتين، بما فيها خطّاف القرن (البِنتل) وسلاسل الأمان وفكّي القفل، قبل هذه الرحلة","أفحص الوصلة فقط إذا لاحظت ارتداد المقطورة الخلفية بعد أن أكون بالفعل أتحرّك على الطريق","أترك صمّامات الفصل والوصلة وشأنها، لأن مركبةً متوقّفةً لا يمكن أن تفقد وصلتها أثناء الليل"],"explanation":"يجب فحص الوصلة بين المقطورتين، بما فيها خطّاف القرن وسلاسل الأمان وفكّي القفل، قبل كل رحلة بغضّ النظر عمّن قام بالتوصيل."},"195":{"q":"أنا أقود مجموعة مقطورات مزدوجة وأدخل إلى جزيرة وقود، لأكتشف أنني تجاوزت المضخة بمقدار طول شاحنة تقريباً. المسار خلفي خالٍ وبضع أقدام من إعادة التموضع ستصطفّني تماماً. ما هي أأمن طريقة للتعامل مع هذا؟","options":["ارجع للخلف ببطء في خط مستقيم، لأن الرجوع القصير اللطيف يمنع المقطورة الخلفية من التأرجح","ارجع للخلف بينما يراقب مرشد المقطورة الخلفية ويوجّهني بإشارات اليد","تجنّب الرجوع بالمجموعة تماماً؛ تقدّم إلى الأمام والتفّ مجدداً، أو افصل إذا كان يجب فعلاً أن أعيد التموضع","ارجع للخلف بعد تفعيل مكابح المقطورة على الوحدة الخلفية كي لا تنجرف"],"explanation":"لا يمكن إرجاع مجموعات المقطورات المزدوجة والثلاثية بأمان لأن نقاط التمفصل تنطوي وتنحرف على الفور تقريباً، لذا تقدّم إلى الأمام والتفّ مجدداً بدلاً من ذلك."},"196":{"q":"أنا أسحب مجموعة مقطورات مزدوجة على طريق سريع مستوٍ ذي مسارين، وأظلّ أتنقّل بين رفع قدمي عن دواسة الوقود والضغط عليها مجدداً بينما تتسارع حركة المرور أمامي وتتباطأ. سائق خلفي يبلّغني عبر اللاسلكي أن مقطورتي الخلفية تتمايل ذهاباً وإياباً. إن الحفاظ على سرعة ثابتة واحدة بدلاً من الإسراع والإبطاء المتكرر سيساعدني بشكل مباشر أكثر على منع أي مما يلي؟","options":["اقتصاد أفضل في الوقود وتكاليف ديزل أقل على طول الرحلة","فقدان ضغط الهواء في المقطورة الخلفية بسبب صمّام الإغلاق المفتوح","انزلاق الحمولة إلى الأمام لأن المقطورة الأثقل محمّلة أخيراً","الاندفاع والانطلاق كالسوط الذي يتراكم عبر المقطورات نحو الخلف"],"explanation":"يرسل الإسراع والإبطاء المتكرر اندفاعاً أمامياً خلفياً عبر مركبة متعددة المقطورات يتضخّم نحو الخلف، مما يجعل المقطورة الأخيرة تتمايل وتتأرجح."},"197":{"q":"أنا أحمّل مقطورتين في مجموعتي المزدوجة، وكل واحدة تستقبل منصّات نقل (بالتات) ثقيلة من المياه المعبّأة إلى جانب بعض الصناديق الأخفّ. وأنا أقرّر أين أضع المنصّات الثقيلة داخل كل مقطورة، ما هي أفضل طريقة لوضع تلك الحمولة الأثقل للحماية من الانقلاب؟","options":["أبقِ الحمولة الأثقل منخفضةً قرب الأرضية وموسّطةً من جانب إلى جانب في كل مقطورة","كدّس الحمولة الأثقل في الأعلى كي تسير الصناديق الأخفّ تحتها","ادفع الحمولة الأثقل بإحكام مقابل أحد الجدران الجانبية كي لا تنزلق","وزّع الحمولة الأثقل بالتساوي على طول مقدّمة ومؤخّرة كل مقطورة"],"explanation":"تحميل الحمولة الأثقل منخفضةً وموسّطةً من جانب إلى جانب يبقي مركز الثقل منخفضاً ومتوازناً، مما يساعد المقطورة على مقاومة الانقلاب الذي يمكن أن يسبّبه التضخيم الخلفي."},"198":{"q":"أنا أقود مجموعة مقطورات مزدوجة على طريق سريع ذي مسارين عندما تخرج سيارة فجأة من ممرّ خاص أمامي مباشرة، مما يجبرني على الكبح بقوة. وأنا أضغط على المكابح بكل قوّتي، ما الذي تكون المقطورة الخلفية لمركبتي أكثر احتمالاً لفعله؟","options":["دفع القاطرة إلى الأمام وتقصير مسافة توقّفي الإجمالية","الخروج عن المسار والانطواء (الانحراف)، مما يدفع المركبة خارج نطاق السيطرة","التتبّع باستقامة خلف المقطورة القائدة والاستقرار برفق حتى التوقف","الارتفاع عن سطح الطريق والطفو إلى أعلى بعيداً عن عربة التحويل"],"explanation":"المقطورات المزدوجة أقل ثباتاً من مقطورة واحدة، لذا فإن التوقف القوي السريع يمكن أن يقفل العجلات ويخرج المقطورتين عن المسار إلى انطواء (انحراف)."},"199":{"q":"أنا أقود مجموعة مقطورات مزدوجة على طريق ريفي سريع بسرعة 55 ميلاً في الساعة عندما يندفع غزال فجأة إلى مساري على بُعد نحو 150 قدماً أمامي. لأكون أأمن سائق مقطورات مزدوجة في هذه اللحظة، أي إجراء يناسب أفضل كيفية تعاملي مع مركبتي؟","options":["أدِر المقود بقوة إلى جانب واحد للابتعاد تماماً عن الغزال، لأن القاطرة ستبقى منتصبةً على أي حال","حافظ على سرعتي وأجرِ تغيير مسار سريعاً وحازماً كي تتتبّع المقطورات مساراً ضيّقاً خلفي","ارفع قدمك عن دواسة الوقود لتبطئ السرعة ووجّه المقود بسلاسة وتدريجياً، متجنّباً أي انحراف مفاجئ","اكبح بقوة مع إدارة المقود بحدّة، واثقاً بأن المقطورة الخلفية ستتبع الأمامية"],"explanation":"لأن التضخيم الخلفي يجعل المقطورة الخلفية تتأرجح بشكل أوسع بكثير من القاطرة، أبطئ سرعتك أولاً ووجّه المقود برفق وتدريجياً لتجنّب انقلابها."}},"passenger":{"0":{"q":"لقد نجحت للتوّ في اختبار مهارات رخصة القيادة التجارية (CDL) وسأبدأ أول رحلة مدفوعة لي غداً. يسلّمني مديري مفاتيح مركبة ويسألني أيّها يُسمح لي قانونياً بتشغيلها بمصادقة الركّاب (P) فقط فوق رخصتي التجارية. أي من هذه المركبات يتطلّب فعلاً مصادقة الركّاب (P)؟","options":["حافلة سياحية مصمَّمة لاستيعاب العدد الحدّي من الركّاب، حتى مع وجود قلّة من الراكبين اليوم","شاحنة صندوقية محمّلة تنقل شحنة عامة على مسار بين الولايات دون ركّاب على متنها","مركبة مركّبة مسطّحة تسحب مقطورة واحدة من مواد البناء المؤمّنة","شاحنة بيك أب ثقيلة بكابينة طاقم تجرّ مقطورة معدّات مغلقة إلى موقع عمل مع ثلاثة زملاء يركبون معها"],"explanation":"تُطلب مصادقة الركّاب (P) بناءً على السعة المقعدية المصمَّمة للمركبة، لا على عدد المقاعد المشغولة فعلياً في رحلة معينة."},"1":{"q":"أثناء فحص ما قبل الرحلة، تشمل عناصر الركاب التي يجب عليك فحصها:","options":["محطة الراديو المحلية المفضلة","الدرابزينات والمقاعد والمخارج وأجهزة الإشارة","لون طلاء الهيكل الخارجي","حاملات أكواب المشروبات البلاستيكية"],"explanation":"افحص معدات سلامة الركاب قبل القيادة."},"2":{"q":"حافلة النقل العام في مدينتي ممتلئة خلال ساعة الذروة وعلى عدة ركاب الوقوف في الممر. للحفاظ على الركاب الواقفين في موضع قانوني وتجنب حجب رؤيتي، أين يجب أن أتأكد من عدم وجود أي من هؤلاء الركاب الواقفين؟","options":["خلف خط الوقوف الأبيض بالقرب من الأبواب الخلفية","أمام خط الوقوف باتجاه مقدمة الحافلة","في متناول قضيب إمساك أو دعامة في الممر","بجانب صف نافذة مخرج الطوارئ الخلفي"],"explanation":"يجب أن يقف الركاب خلف خط الوقوف، فلا يجوز لأي راكب أن يقف أمامه باتجاه مقدمة الحافلة حيث تُحجب رؤية السائق."},"3":{"q":"يطلب مني راكب يصعد إلى حافلتي المستأجرة أن أخزّن برميلاً صغيراً من المواد الخطرة في مخزن الشحن خلال الرحلة. قبل أن أوافق، أي فهم للقواعد يجب أن يوجّه قراري؟","options":["يجوز نقل المواد الخطرة على أي حافلة طالما أبقيتها مغلقة ومخزّنة تحت مقاعد الركاب حيث يمكن للناس مراقبتها.","أي مادة خطرة لا بأس بحملها طالما بقي الحمل الإجمالي عند أو أقل من 500 رطل في مخزن الشحن.","معظم المواد الخطرة محظورة على الحافلة، وعدد قليل فقط من المواد المحددة بكميات صغيرة ومحدودة يجوز حملها على الإطلاق.","يُشترط نقل المواد الخطرة بالحافلة كلما طلب الراكب ذلك، شريطة أن يكون كل منها أقل من 100 رطل."],"explanation":"لا يجوز للحافلة حمل معظم المواد الخطرة، وعدد قليل فقط من المواد المحددة بكميات صغيرة ومحدودة هو المسموح به على متنها."},"4":{"q":"أثناء جولة فحص ما قبل الرحلة لحافلة مستأجرة محمّلة، يسلّمني راكب حقيبة سفر كبيرة ويطلب مني إيجاد مكان لها قبل أن ننطلق. وفقاً لقواعد إدارة السلامة العامة في تكساس لتأمين الأمتعة المحمولة، أي شرط هو السبب الأهم الذي يجب أن أرفض من أجله وضعها حيث اقترح الراكب أولاً؟","options":["ستضغط الحقيبة على تنجيد مقعدين قريبين","ستشعر الحقيبة بالبرودة وهي قريبة من فتحات التدفئة الأرضية","ستبدو الحقيبة غير مرتبة وهي مستقرة فوق وسادة المقعد","ستحجب الحقيبة جزئياً الممر الأوسط ومخرجاً جانبياً"],"explanation":"يجب تأمين الأمتعة المحمولة بحيث لا تحجب الممر أو أي مخرج أبداً، مما يبقي الركاب قادرين على التحرك والإخلاء بحرية في حالات الطوارئ."},"5":{"q":"أقود حافلة نقل محمّلة وأقترب من تقاطع سكة حديد نشط بدون إشارة أو بوابة أو موجّه. للتعامل معه بشكل صحيح، ماذا يجب أن أفعل عندما أصل إلى القضبان؟","options":["أتوقف بين 15 و50 قدماً قبل أقرب قضيب، أنظر وأستمع، ثم أعبر دون تغيير التروس","أبطئ، وأنزل إلى ترس أقل، وأمر بثبات فوق القضبان للحفاظ على الزخم","أتوقف تماماً عند أقرب قضيب إليّ، أنظر وأستمع، ثم أتسارع بقوة لاجتياز كلا المسارين","أتوقف فقط إذا كان هناك قطار في الأفق أو سمعت بوقاً؛ وإلا أتعامل معه كتقاطع عادي وأتابع"],"explanation":"عند تقاطع سكة حديد غير مُعلَّم، يجب على الحافلة أن تتوقف بين 15 و50 قدماً قبل أقرب قضيب، وتنظر وتستمع، وألا تغيّر التروس أبداً أثناء العبور."},"6":{"q":"أثناء عبور قضبان السكة الحديد، يجب عليك:","options":["التحويل إلى ترس أقل","عدم تغيير التروس","التوقف على القضبان","الرجوع للخلف فوقها"],"explanation":"لا تغيّر التروس أثناء وجودك على القضبان، لتجنب توقف المحرك."},"7":{"q":"أقود حافلة ركاب محمّلة وأقترب من جسر متحرك. لا توجد إشارة مرور عند المعبر، ولا يوجد عامل جسر أو إشارة مرئية توجّه حركة المرور. السيارة التي أمامي تعبر دون أن تبطئ. ماذا يُطلب مني فعله؟","options":["أحافظ على مسافة الاتباع وأعبر مباشرة خلف السيارة التي أمامي، لأنها عبرت للتو بأمان","أتوقف على بعد 50 قدماً على الأقل قبل الجزء المتحرك من الجسر وأتأكد من أنه مغلق وآمن قبل العبور","أبطئ إلى زحف بطيء، وأطلق بوقي، وأتابع العبور دون التوقف الكامل","أتوقف بين 15 و50 قدماً قبل الجسر، تماماً كما أفعل عند تقاطع سكة الحديد"],"explanation":"عند جسر متحرك بدون إشارة أو عامل، يجب على الحافلة أن تتوقف على بعد 50 قدماً على الأقل قبل الجزء المتحرك وتتأكد من أن الجسر مغلق وآمن قبل العبور."},"8":{"q":"أقود حافلة نقل حضري وأتوقف عند محطة مزدحمة على منحدر خفيف نزولاً. أفتح الأبواب الخلفية ليتمكن الركاب الواقفون من النزول إلى منطقة التحميل. وبينما تنفتح الأبواب، أشعر بالحافلة تثبّت نفسها في مكانها رغم أنني لم ألمس فرملة الانتظار. ماذا يفعل تعشيق الفرملة والباب في هذه اللحظة، وكيف يجب أن أتعامل معه؟","options":["يقفل عمود التوجيه بحيث لا تتمكن العجلات الأمامية من الدوران أثناء نزول الركاب، ويمكنني الاعتماد عليه لتثبيت الحافلة على هذا المنحدر","يقطع الطاقة عن الأبواب الخلفية لتبقى مفتوحة، ويجب أن أترك الحافلة في وضع التعشيق وأبتعد لمساعدة الركاب","يثبّت الحافلة تلقائياً بالفرامل أثناء فتح الأبواب الخلفية، لكن يجب ألا أعامله كفرملة انتظار وعليّ ضبط فرملة الانتظار إذا غادرت المقعد","يصدر صوت رنين إشارة التوقف لتحذير الركاب الصاعدين، وبمجرد توقفه أكون حراً في الانطلاق دون فحص الأبواب"],"explanation":"تعشيق الفرملة والباب يثبّت الفرامل مؤقتاً فقط أثناء فتح الأبواب الخلفية ولا يجب أبداً أن يحل محل فرملة الانتظار، التي يجب ضبطها عند مغادرة المقعد."},"9":{"q":"أقود حافلة نقل حضري على مسار ثابت مع عدة ركاب واقفين خلف الخط الأبيض وركاب سينزلون في المحطات القادمة. لمساعدة الركاب على الاستعداد للنزول بأمان دون الازدحام عند الباب أو الخطو في حركة المرور، كيف يجب أن أتعامل مع الإعلان عن المحطات على طول مساري؟","options":["أعلن عن كل محطة فقط لحظة فتح الأبواب، ليتفاعل الركاب مع الموقع الدقيق","أتخطى الإعلانات وأعتمد على الركاب الواقفين لمراقبة النوافذ والإشارة إلى المحطة بأنفسهم","أعلن عن الوجهة النهائية فقط، لأن المحطات الوسيطة لا تؤثر على سلامة الركاب","أعلن عن كل محطة بوضوح وقبل وصولي بوقت كافٍ ليكون الركاب مستعدين قبل أن أصل"],"explanation":"أعلن عن المحطات بوضوح وقبل وصولك بوقت كافٍ ليتمكن الركاب من الاستعداد والتحرك نحو الباب والتمسك قبل أن تصل الحافلة."},"10":{"q":"أنت تقود حافلة نقل حضري على طريق سريع مزدحم بأربعة مسارات عندما يصبح راكب قرب المؤخرة صاخباً ومسيئاً ويرفض أن يهدأ. الركاب الآخرون يتوترون، وتريد إنزال هذا الراكب المزعج من حافلتك. وفقاً لقواعد سلامة الركاب لإدارة السلامة العامة، ماذا يجب أن تفعل؟","options":["تابع إلى المحطة العادية التالية أو إلى موقع آمن ومضاء جيداً، ثم أنزل الراكب هناك","انعطف إلى الكتف الأيمن من الطريق السريع فوراً وأنزل الراكب ليشعر الركاب الآخرون بالأمان","توقف في أقرب مسار مروري، اضبط فرملة الانتظار، وأمر الراكب بالخروج فوراً","سرّع إلى منحدر المخرج التالي ليخاف الراكب فيلتزم الصمت"],"explanation":"لا يجوز إنزال الراكب المزعج إلا حيث يكون آمناً، لذا تابع إلى محطة عادية أو موقع آمن ومضاء جيداً قبل إنزاله."},"11":{"q":"حافلة النقل الحضري التي أقودها ممتلئة وعدة ركاب يقفون في الممر بينما أنطلق من المحطة. أحد الركاب ينجرف للأمام باتجاه المقدمة ويتوقف بعد الخط الأبيض المرسوم على الأرض قرب لوحة القيادة مباشرة. لماذا أحتاج إلى أن أطلب من ذلك الراكب التراجع خلف ذلك الخط؟","options":["إنه يفصل قسم الجلوس عن صف مخرج الطوارئ المخصص الذي يجب أن يبقى خالياً","إنه يحدد الحد الأمامي للركاب الواقفين، ولا يجوز لأحد أن يقف أمامه","إنه يبيّن نقطة الصعود حيث يجب على الركاب الواقفين الانتظار حتى أتوقف","إنه يشير إلى المكان الذي يجب فيه تأكيد قراءة صندوق الأجرة قبل المغادرة"],"explanation":"يحدد خط الوقوف الأبيض الحد الأمامي للركاب الواقفين، ولا يجوز لأحد أن يقف أمامه لأنه يحجب رؤية السائق."},"12":{"q":"لقد أدخلت للتو حافلتي السياحية إلى المحطة في نهاية رحلة مسائية طويلة، وضبطت فرملة الانتظار، ونزل آخر الركاب المرئيين. قبل أن أقفل الحافلة وأتوجه إلى المنزل، ماذا يجب أن أتفقده وأنا أسير على طول الحافلة؟","options":["ما إذا كانت الإطارات قد فقدت ضغطها أثناء الرحلة لأملأها قبل ركن الحافلة طوال الليل","ما إذا كانت أي أمتعة محمولة قد انزلقت إلى الممر لأعيد تأمينها للرحلة التالية","ما إذا كان أي ركاب ما زالوا نائمين في مقاعدهم وما إذا كان أحد قد ترك متعلقات شخصية","ما إذا كانت مخارج الطوارئ وأضواء المخارج ما زالت تعمل لتكون الحافلة جاهزة للفحص التالي"],"explanation":"بعد انتهاء الرحلة، سِر على طول الحافلة بالكامل للتحقق من وجود ركاب نائمين وأي متعلقات شخصية متروكة."},"13":{"q":"أقود مساراً مستأجراً في حافلتي السياحية ومؤشر الوقود منخفض. ركابي جالسون والمحطة المجدولة التالية لا تزال على بعد 30 ميلاً، لكن هناك محطة وقود ذات مضخة في الهواء الطلق أمامي مباشرة. وفقاً لقواعد إدارة السلامة العامة في تكساس، ما هي أفضل طريقة للتعامل مع التزود بالوقود؟","options":["ادخل إلى أي حوض تزود بالوقود مغلق ليبقى الركاب محتمين بينما أملأ الخزان","تابع القيادة متجاوزاً المحطة وتزوّد بالوقود فقط بعد عودة الحافلة إلى الحركة لتوفير الوقت","تزوّد بالوقود فوراً والركاب على متنها لأن المضخة في الهواء الطلق تجعل ذلك آمناً تماماً","انتظر حتى أصل إلى المحطة وأنزِل الركاب أولاً، متزوداً بالوقود دون ركاب على متن الحافلة كلما أمكن"],"explanation":"تجنب التزود بالوقود والركاب على متن الحافلة كلما أمكن، ولا تتزوّد بالوقود أبداً داخل مبنى مغلق والركاب على متن الحافلة."},"14":{"q":"أثناء فحص ما قبل الرحلة لحافلة نقل تتسع لـ47 راكباً، أجد أن نافذة مخرج الطوارئ الخلفية محجوبة جزئياً بكومة من الأمتعة المحمولة المؤمّنة وأن مقبض تحريرها مغطى بشريط لاصق من إصلاح سابق. يبدأ الصعود خلال عشر دقائق. قبل أن أقبل أي ركاب، أي شرط يجب أن يستوفيه مخرج الطوارئ هذا؟","options":["يجب أن يكون معلّماً بوضوح وقابلاً للتشغيل بالكامل، لذا عليّ إزالة الأمتعة ونزع الشريط ليُفتح المخرج قبل أن يصعد أحد","من المقبول تركه كما هو، لأن باب الركاب الأمامي والمخرج جانب الزجاج الأمامي العامل يوفران بالفعل مخرجين عاملين","يحتاج فقط إلى أن يكون قابلاً للتشغيل في نهاية المسار، لذا يمكنني صعود الركاب الآن وإخلاء المخرج أثناء أول محطة استراحة","يمكن أن يبقى مغطى بالشريط إذا وضعت لافتة توجّه الركاب إلى الباب الأمامي، لأن مخرجاً بديلاً معلّماً يفي بالمتطلب"],"explanation":"يجب أن تكون مخارج الطوارئ معلّمة بوضوح وقابلة للتشغيل بالكامل، مع إبقاء جميع المخارج والممر خالية من الأمتعة قبل أن يصعد أحد."},"15":{"q":"أنا أحمّل حافلتي المستأجرة قبل رحلة ويسلّمني شاحن أربع طرود لحملها في أحواض الشحن. وفقاً لقواعد المواد الخطرة في تكساس للحافلات، أيها يُمنع عليّ قبوله تحت أي ظرف؟","options":["كرتونة بوزن 60 رطلاً من ذخيرة الأسلحة الصغيرة مخزنة في حوض شحن مغلق بعيداً عن الركاب","صندوق متفجرات من الفئة 1.2 متجه إلى محجر على الطريق السريع","صندوق بوزن 40 رطلاً من المستلزمات الطبية الطارئة المعلّمة محفوظ خارج منطقة الركاب","طرد واحد مغلق من عينات تشخيصية للمستشفى محمّل في الحوض السفلي"],"explanation":"لا يجوز للحافلة أبداً حمل متفجرات الفئة 1.1 أو 1.2 أو 1.3، بغض النظر عن الكمية أو التغليف أو الوجهة."},"16":{"q":"أقود حافلة نقل حضري تقترب من محطة مزدحمة في وسط المدينة. يطلب مني راكب مسن قرب الباب الأمامي أن أبطئ بما يكفي ليتمكن من النزول بينما لا نزال نتدحرج نحو الرصيف، قائلاً إنه في عجلة. وفقاً لقواعد الركاب في تكساس، متى يجب أن أسمح لأي راكب بالصعود أو النزول من حافلتي؟","options":["كلما أبطأت الحافلة إلى ما يقارب الزحف، ليتجنب الركاب نافدو الصبر الانتظار","على كتف الطريق السريع عندما يطلب راكب المغادرة بين المحطات المجدولة","فقط بعد أن تتوقف الحافلة توقفاً كاملاً وتُؤمَّن","من خلال نافذة أو مخرج خلفي إذا كانت مقدمة الحافلة لا تزال تزحف للأمام"],"explanation":"لا يجوز للركاب الصعود أو النزول إلا بعد أن تتوقف الحافلة توقفاً كاملاً وتُؤمَّن."},"17":{"q":"أنت تقود مجموعة مستأجرة من 40 راكباً في رحلة مدتها 3 ساعات إلى وجهة واحدة. في منتصف الطريق تقريباً، يأتي راكب ويطلب منك التوقف عند مخرج قادم لينزل ويلتقي صديقاً بدلاً من ركوب الطريق كله. لا توجد حالة طارئة. ما الطريقة الصحيحة للتعامل مع هذا؟","options":["توقف عند المخرج الآمن التالي وأنزله، لأن راكب الرحلة المستأجرة يجوز له المغادرة متى شاء","أنزله فقط إذا وقّع إقراراً ووافق جميع الركاب المتبقين على التأخير","انعطف وأنزله، لكن أبقِ الباب مغلقاً أمام الركاب الآخرين حتى لا ينزل أحد غيره","أبقِه على متن الحافلة ولا تُنزِل أي راكب مستأجر حتى الوجهة المجدولة، ما لم تكن هناك حالة طارئة"],"explanation":"في الرحلة المستأجرة، لا تُنزِل الركاب في أي مكان غير الوجهة المجدولة ما لم تكن هناك حالة طارئة حقيقية."},"18":{"q":"لقد انتقلت للتو من قيادة سيارة سيدان إلى تشغيل حافلة نقل بطول 40 قدماً، وحركة المرور أمامي تتباطأ على طريق سريع مبلل. كيف يجب أن أفكر في سرعتي ومسافة الاتباع الآن وأنا خلف مقود الحافلة؟","options":["أديرها بالطريقة التي أديرها بها لأي مركبة تجارية كبيرة وثقيلة أخرى، تاركاً مساحة إضافية ومتحكماً في السرعة بحسب وزن الحافلة وطولها","أبقيها كما في سيارتي السيدان، لأنني ما زلت سائقاً واحداً يتفاعل مع نفس ظروف المرور","أقود برشاقة كسيارة رياضية صغيرة، مستخدماً تحكم الحافلة السريع للفرملة متأخراً والتعرج بين الفجوات","أتجاهل مسافة الاتباع وأحافظ ببساطة على السرعة القصوى المعلنة للطريق السريع لأبقى ضمن الجدول الزمني"],"explanation":"الحافلة مركبة تجارية كبيرة وثقيلة، لذا اترك مسافة اتباع إضافية وتحكم في السرعة بحسب وزنها وطولها."},"19":{"q":"أقود حافلة نقل حضري محمّلة قرب نهاية وردية عملي وأريد اتباع إجراءات تكساس بشكل صحيح من الاقتراب من تقاطع سكة حديد حتى إنهاء مساري. أي من هذه الإجراءات صحيح؟","options":["عند تقاطع السكة الحديد أنزل إلى ترس أقل أثناء التدحرج فوق القضبان لأحافظ على طاقة كافية لاجتيازها بسرعة","أتوقف بالحافلة بين 15 و50 قدماً قبل قضبان السكة الحديد، أنظر وأستمع دون تغيير التروس، وبعد مساري أفحص الحافلة بحثاً عن ركاب نائمين أو مرضى وأشياء متروكة","لأن رحلتي شارفت على الانتهاء، أسمح لبعض الركاب الواقفين بالتقدم أمام خط الوقوف لينزلوا بسرعة عند المحطة الأخيرة","أتخطى جولة فحص ما بعد الرحلة لأن الحافلة فارغة عند المحطة الأخيرة وأتوجه مباشرة للتزود بالوقود داخل المرآب المغلق والمحرك دافئ"],"explanation":"توقف بين 15 و50 قدماً قبل قضبان السكة الحديد، انظر واستمع دون تغيير التروس، وبعد المسار افحص بحثاً عن ركاب نائمين وأشياء متروكة."},"20":{"q":"أقود حافلة نقل حضري خلال ساعة الذروة، وهي مكتظة بالركاب الواقفين. ازدحم عدد قليل من الركاب قرب المقدمة، واقفين أمام خط الوقوف الأبيض ليتحدثوا مع أصدقائهم. لماذا تطلب مني تكساس إبقاء هؤلاء الركاب الواقفين خلف ذلك الخط؟","options":["الوقوف خلف الخط يمنع انسداد أبواب مخرج الطوارئ الخلفية بالحشد","إبقاء تلك المنطقة خالية يجعل الحافلة تسير بكفاءة أكبر قليلاً ويوفر قدراً يسيراً من الوقود","إذا اضطررت إلى الفرملة بقوة أو التوقف فجأة، فإن الركاب خلف الخط أقل عرضة بكثير لأن يُقذفوا للأمام ويُصابوا","يمنع الركاب من حجب مراياي حتى أتمكن من مراقبة الركاب الصاعدين عند كل محطة"],"explanation":"يبقي خط الوقوف الركاب الواقفين خلف نقطة آمنة بحيث تصبح الفرملة الشديدة أو التوقف المفاجئ أقل احتمالاً بكثير لقذفهم للأمام."},"21":{"q":"أقود حافلة ركاب محمّلة وأقترب من تقاطع سكة حديد بدون موجّه وبدون إشارة خضراء. حركة المرور خفيفة، لذا أبدأ بالإبطاء قبل وقت كافٍ وأبحث عن المكان المناسب لإيقاف الحافلة توقفاً كاملاً. للامتثال لمتطلبات تكساس، أين يجب أن أتوقف؟","options":["مباشرة عند أقرب قضيب لأرى بوضوح على طول المسار في كلا الاتجاهين","في أي مكان ضمن 100 قدم من أقرب قضيب، طالما توقفت توقفاً كاملاً","لا أقرب من 50 قدماً ولا أبعد من 75 قدماً من أقرب قضيب","لا أقرب من 15 قدماً ولا أبعد من 50 قدماً من أقرب قضيب"],"explanation":"يجب على الحافلة أن تتوقف على بعد لا يقل عن 15 قدماً ولا يزيد عن 50 قدماً من أقرب قضيب قبل عبور قضبان السكة الحديد."},"22":{"q":"أبدأ وردية صباحية بقيادة حافلة سياحية ركنها السائق السابق هنا الليلة الماضية، ويخبرني المرسل أنها اجتازت فحصها السنوي لوزارة النقل قبل أسبوعين. قبل أن أنطلق بالركاب، متى يُطلب مني فحص هذه الحافلة؟","options":["قبل هذه الرحلة، بما في ذلك مخارج الطوارئ وأضواء المخارج وإشارة التوقف والممر الخالي","ليس في هذه المرحلة، لأن الحافلة اجتازت بالفعل فحصها السنوي لوزارة النقل قبل أسبوعين","فقط بعد أن ألاحظ مشكلة مثل ضوء تحذير أو مخرج لا يُفتح أثناء القيادة","فقط إذا كنت سأعبر قضبان سكة حديد أو أقود أكثر من 50 ميلاً على المسار"],"explanation":"يُطلب فحص ما قبل الرحلة قبل كل رحلة، مع التحقق من عناصر سلامة الركاب مثل مخارج الطوارئ وأضواء المخارج وإشارة التوقف والممر الخالي."},"23":{"q":"التحدث مع الركاب أثناء القيادة يجب أن يكون:","options":["مستمراً ومفصّلاً","محدوداً لتبقى مركّزاً","بعيون مغلقة","عبر مكبر صوت دائماً"],"explanation":"تجنب المشتتات؛ أبقِ المحادثة في حدها الأدنى أثناء الحركة."},"24":{"q":"أقود حافلة نقل حضري على مسار مزدحم. لا يزال بعض الركاب الواقفين يتحركون ببطء نحو خط الوقوف الأبيض وراكب مسن يمد يده نحو مقعد بينما تتحول الإشارة أمامي إلى الأخضر وتبدأ السيارات خلفي بإطلاق الأبواق. وفقاً لقواعد إدارة السلامة العامة، ماذا يجب أن أتأكد منه قبل أن أفعل أي شيء آخر في هذه اللحظة؟","options":["أن كل راكب واقف قد تحرك خلف خط الوقوف وأمسك بمقبض، ثم أحرّك الحافلة للأمام بلطف لإبقاء حركة المرور سلسة","أن جميع الركاب جالسون أو مؤمّنون بطريقة أخرى، لأنه يجب عدم تحريك الحافلة حتى يكون الركاب آمنين على متنها","أن الأبواب مغلقة تماماً وإشارة التوقف معاد ضبطها قبل تحرير فرملة الانتظار والتسارع","أنني أعلنت عن المحطة التالية وفحصت مراياي حتى أتمكن من الانطلاق بسلاسة رغم الأبواق خلفي"],"explanation":"يجب عدم تحريك الحافلة حتى يكون جميع الركاب جالسين أو مؤمّنين بطريقة أخرى، مهما كان الضغط الخارجي للتحرك."},"25":{"q":"أنت تقود حافلة نقل حضري وتتوقف عند محطة مزدحمة في وسط المدينة. بعد أن تضبط فرملة الانتظار وتنفتح الأبواب، يبدأ عدة ركاب بالنزول بينما ينتظر آخرون للصعود على الرصيف. وأنت تستعد للانطلاق، ما الذي يجب أن تراقبه عن كثب أكثر من غيره لتجنب مأساة؟","options":["الركاب الواقفون الذين انجرفوا أمام خط الوقوف الأبيض داخل الحافلة","الأمتعة المحمولة التي قد يكون راكب صاعد تركها تسد الممر","الركاب الذين نزلوا للتو وهم الآن يعبرون أمام الحافلة","ما إذا كانت إشارة التوقف وأضواء مخرج الطوارئ لا تزال تعمل"],"explanation":"عند الانطلاق من محطة، يكون أكبر خطر هو الركاب الذين نزلوا للتو ويعبرون أمام الحافلة في نقطتك العمياء."},"26":{"q":"حافلة النقل العام التي تقودها مزدحمة خلال ساعة الذروة، ويقف عدة ركاب خلف خط الوقوف لأن جميع المقاعد مشغولة. عندما تنطلق من الرصيف وتندمج في حركة المرور، بماذا ينبغي أن توجّه هؤلاء الركاب الواقفين لحمايتهم من الحركات المفاجئة؟","options":["أن يستندوا إلى أقرب راكب جالس حتى لا يدفعهم التوقف المفاجئ إلى الأمام","أن يتقدموا نحو المقدمة ويسندوا أنفسهم على مقعد السائق لتحقيق الثبات","أن يقفوا مباعدين بين قدميهم مع تثبيت ركبهم، مع إبقاء كلتا اليدين حرتين","أن يمسكوا بقضيب الإمساك أو بحزام علوي وأن يستمروا في الإمساك به أثناء سير الحافلة"],"explanation":"ينبغي للركاب الواقفين أن يمسكوا بقضيب الإمساك أو بحزام علوي وأن يستمروا في الإمساك به حتى لا يقذفهم توقف مفاجئ أو منعطف حاد."},"27":{"q":"أثناء فحص ما قبل الرحلة لحافلتي قبل مسار الصباح، ألاحظ أن أحد مقاعد الركاب يتأرجح قليلاً عندما أدفع إطاره. أي من الخيارات التالية هو المعيار الصحيح الذي يجب أن أطبّقه قبل أن أتمكن من نقل الركاب؟","options":["يجب أن يكون المقعد وإطاره ثابتين ومثبتين بحيث لا يتحركان","قدر بسيط من حركة المقعد مقبول طالما أن الوسادة مثبتة بالبراغي","يجب إزالة المقعد بالكامل حتى لا يتمكن الركاب من استخدام إطار مفكوك","لا بأس باستخدام المقعد طالما لم توضع عليه أي أمتعة محمولة"],"explanation":"يجب أن تكون مقاعد الحافلة وإطاراتها ثابتة ومثبتة بحيث لا تتحرك قبل نقل الركاب."},"28":{"q":"أثناء فحص ما قبل الرحلة على حافلة نقل عام بالمدينة، يصعد راكب مبكراً حاملاً حقيبتين كبيرتين ويسأل أين يضعهما أثناء انتظارنا للانطلاق. بصفتي السائق، ما هي مسؤوليتي الأساسية بشأن مكان وضع تلك الأمتعة المحمولة؟","options":["يمكنني السماح بترك الحقائب في الممر طالما بقي الراكب جالساً بجانبها طوال الرحلة","يجب أن أتأكد من تأمين الحقائب بحيث لا تسد الممر أو أي مخرج ولا يمكن أن تسقط على أحد","ينبغي أن أكدّس الحقائب أمام باب الخروج الطارئ الخلفي حيث تكون بعيدة عن ممر المشي","يكفي أن أبقي درجات الصعود الأمامية خالية، لأنه المخرج الذي يفحصه المفتش فعلاً"],"explanation":"يجب تأمين الأمتعة المحمولة بحيث لا تسد الممر أو أي مخرج ولا يمكن أن تسقط على أحد."},"29":{"q":"أقود حافلة نقل عام بالمدينة خلال ساعة الذروة. يقف عدة ركاب خلف خط الوقوف لأن جميع المقاعد ممتلئة. عندما أقترب من محطة وأنطلق مجدداً، أي أسلوب في التسارع والكبح يحمي هؤلاء الركاب الواقفين على أفضل وجه؟","options":["أن أكبح بقوة ومتأخراً لأتوقف بدقة عند اللافتة، ثم أتسارع بسرعة للبقاء على الجدول","أن أتسارع بقوة من كل محطة وأضغط الكوابح بحدة حتى يشعر الواقفون باقتراب التوقف","أن أتسارع وأكبح بسلاسة ولطف حتى لا يفقد الركاب الواقفون توازنهم","أن أكبح فقط عند النزول على المنحدرات وأنساب نحو كل محطة حتى تكون الرحلة سلسة للركاب"],"explanation":"تسارع واكبح بسلاسة ولطف حتى لا يفقد الركاب الواقفون توازنهم."},"30":{"q":"أنت تقود حافلة نقل عام محمّلة على طريق رئيسي مزدحم بأربعة مسارات عندما يخبرك راكب واقف فجأة أن راكباً آخر قرب الخلف قد انهار ويبدو أنه يمر بحالة طبية طارئة. حركة المرور تسير ومحطتك المجدولة التالية لا تزال على بُعد عدة مربعات سكنية. ما الذي ينبغي أن تفعله أولاً؟","options":["أن تستمر في القيادة بسرعة إلى المحطة المجدولة التالية لتبقى على المسار، ثم تتفقد الراكب بعد فتح الأبواب","أن تواصل التوجه نحو وجهة المسار لكن تزيد السرعة لتقليص زمن الرحلة، لأن الوصول إلى النهاية أسرع يجلب المساعدة أبكر","أن تفتح فتحة الهروب السقفية وباب الخروج الطارئ الخلفي أثناء السير لتهوية الحافلة وطمأنة الركاب","أن تنحرف جانباً وتوقف الحافلة بأمان وسلاسة في أقرب وقت يمكنك فيه ذلك بأمان، وتشغّل فرملة الانتظار، وتطلب المساعدة"],"explanation":"إذا مرض راكب أو حدثت حالة طارئة، أوقف الحافلة بأمان وسلاسة، وشغّل فرملة الانتظار، واطلب المساعدة."},"31":{"q":"إنها فترة ظهيرة حارة ومكيف الحافلة ضعيف، فيفتح عدة ركاب النوافذ الجانبية للحصول على الهواء. يميل أحد الركاب بكوعه إلى الخارج ويترك آخر طفلته تخرج رأسها لتشعر بالنسيم. قبل أن أعود إلى حركة المرور، ماذا يجب أن أطلب من هؤلاء الركاب؟","options":["يجب أن يبقوا أذرعهم ورؤوسهم داخل الحافلة في كل الأوقات أثناء سيرها","يمكنهم إبقاء أذرعهم خارجاً طالما بقيت رؤوسهم داخل النوافذ","يمكنهم الميل إلى الخارج فقط أثناء توقف الحافلة عند محطة محددة","يجب أن يتحركوا خلف خط الوقوف (الأبيض) قبل أن تبدأ الحافلة بالحركة"],"explanation":"يجب على الركاب إبقاء أذرعهم ورؤوسهم داخل الحافلة في كل الأوقات أثناء سيرها لتجنب إصابة خطيرة."},"32":{"q":"أثناء فحص ما قبل الرحلة لحافلة نقل عام، أعثر على طفاية الحريق وأتأكد من أنها مشحونة ومثبتة. لإكمال فحصي لمعدات الطوارئ المطلوبة في الحافلة، ما الذي أنا مسؤول عن التحقق تحديداً من وجوده وعمله قبل أن أقبل الركاب؟","options":["جهاز لاسلكي ثنائي الاتجاه ومجموعة احتياطية من منصهرات المصابيح الأمامية","مخارج الطوارئ وأجهزة التحذير المطلوبة","حقيبة إسعافات أولية وسترة سلامة عاكسة للسائق","مثلثات عاكسة ومصدر احتياطي لسائل تبريد المحرك"],"explanation":"تشمل معدات الطوارئ المطلوبة في الحافلة طفاية الحريق إلى جانب مخارج الطوارئ وأجهزة التحذير المطلوبة."},"33":{"q":"أقود حافلة نقل عام بالمدينة على مساري وأرى محطة الركاب التالية على بُعد مربع سكني تقريباً، مع عدة ركاب ينتظرون عند الرصيف للصعود. عندما أقترب، ما الطريقة الصحيحة للتعامل مع الاقتراب؟","options":["أن أبقي سرعتي عالية للبقاء على الجدول وأكبح بقوة في اللحظة الأخيرة للوصول إلى الرصيف","أن أتوقف في مسار المرور بجانب الرصيف وأنتظر خروج الركاب إلى الباب","أن أبطئ مبكراً وأدخل الحافلة بالكامل إلى المحطة حتى يتمكن الركاب المنتظرون من الصعود بأمان","أن أضغط البوق لتنبيه الركاب المنتظرين وأمر ببطء حتى المحطة التالية"],"explanation":"أبطئ مبكراً وأدخل الحافلة بالكامل إلى المحطة حتى يتمكن الركاب المنتظرون من الصعود دون الخطو إلى حركة المرور."},"34":{"q":"أقود حافلة نقل عام بالمدينة خلال ساعة الذروة وتمتلئ الحافلة بسرعة. يزدحم المزيد من الركاب صاعدين، وكلهم يقفون خلف خط الوقوف الأبيض وبعيداً عن الممر والمخارج. أريد أن أعرف كم عدد الواقفين المسموح لي فعلاً بنقلهم. ما الذي يحدد الحد الأقصى لعدد الركاب الواقفين الذين يمكنني نقلهم؟","options":["وزن الحافلة الكلي المقدّر وحده يحدد كم شخصاً يمكنه الوقوف بأمان","لا يوجد حد ثابت طالما بقي كل واقف خلف خط الوقوف","يقرر السائق الحد الأقصى بناءً على مدى راحة الحمولة عند الكبح","قد تحدد القواعد الولائية والمحلية الحد الأقصى لعدد الواقفين المسموح به"],"explanation":"يمكن للقواعد الولائية والمحلية أن تحدد الحد الأقصى لعدد الركاب الواقفين المسموح به، وعلى السائق الالتزام بذلك الحد."},"35":{"q":"لقد انتهيت للتو من تحميل الركاب عند محطة حافلات في وسط المدينة وأنت مستعد للاندماج مجدداً في حركة المرور. تتحول الإشارة أمامك إلى الأخضر ويزمّر سائق آخر خلفك بنفاد صبر. قبل أن تحرر فرملة الانتظار وتنطلق من الرصيف، أي إجراء هو الأهم لإكماله أولاً؟","options":["أن تغلق الأبواب تماماً وتتفقد مراياك بحثاً عن حركة المرور والدراجات والمشاة قرب الحافلة","أن تضغط البوق وتتسارع بسرعة حتى يتمكن السائق نافد الصبر خلفك من التقدم","أن تقوم بإعلان أخير تذكّر فيه الركاب الواقفين بالتقدم أمام خط الوقوف للحصول على إمساك أفضل","أن تفتح الفتحة السقفية لتهوية المقصورة قبل بلوغ سرعة الطريق السريع في المربع التالي"],"explanation":"قبل الانطلاق من محطة، أغلق الأبواب تماماً وتفقد مراياك بحثاً عن حركة المرور والدراجات والمشاة قرب الحافلة."},"36":{"q":"حافلة النقل العام التي تقودها ممتلئة ويوجد على متنها عدة ركاب واقفين. عندما تنطلق من محطة مزدحمة في وسط المدينة، تنظر في مرآتك الداخلية للتأكد من أن الجميع في وضع آمن. أي من الخيارات التالية هو الشيء الوحيد الذي يجب ألا تسمح للراكب بفعله؟","options":["الوقوف خلف خط الوقوف (الأبيض) مع الإمساك بقضيب علوي","الوقوف على بئر الدرجات أو في منطقة المدخل أثناء سير الحافلة","البقاء جالساً بهدوء دون الإمساك بأي قضيب","الوقوف في الممر مواجهاً للأمام، بعيداً عن خط رؤيتك"],"explanation":"يجب ألا يقف الركاب أبداً في المدخل أو على بئر الدرجات أثناء سير الحافلة، لأن تلك المناطق لا يمكنها حمل شخص واقف بأمان."},"37":{"q":"أنت تقود حافلة نقل عام محمّلة على طريق سريع ريفي في تكساس عندما يتوقف المحرك وتنساب إلى الكتف. لن تعيد الحافلة التشغيل وحركة المرور تسير بسرعة في المسار المجاور لك. يبدأ عدة ركاب بالوقوف ويسألون عما ينبغي أن يفعلوه. ما أفضل تعليمة تعطيها لركابك؟","options":["أن تجعل الجميع يخرجون فوراً عبر باب الطوارئ الخلفي ويمشون على الكتف إلى أقرب بلدة طلباً للمساعدة","أن تفتح النوافذ وتدع الركاب يتسلقون للخروج حتى يبقى الممر خالياً بينما تستوقف المركبات المارة","أن تبقي الركاب جالسين وهادئين حتى تتأكد من أنه من الآمن نقلهم خارج الحافلة","أن توجّه أقوى الركاب للنزول والمساعدة في دفع الحافلة بعيداً نحو الكتف بعيداً عن حركة المرور"],"explanation":"عندما تتعطل الحافلة في حركة مرور سريعة، أبقِ الركاب جالسين وهادئين حتى تتأكد من أنه من الآمن نقلهم خارج الحافلة."},"38":{"q":"أقود حافلة نقل عام وأتوقف عند محطة اعتيادية حيث ينتظر عدة أشخاص على الرصيف. الحافلة متوقفة تماماً وفرملة الانتظار مشغّلة. وفقاً لقواعد إدارة السلامة العامة (DPS) لسلوك الركاب، كيف ينبغي أن يصعد هؤلاء الركاب إلى الحافلة؟","options":["يمكنهم الدخول عبر باب الخروج الطارئ الخلفي إذا كان الصف الأمامي مزدحماً","ينبغي أن ينتظروا حتى تسير الحافلة ببطء إلى الأمام، ثم يصعدون حتى لا أضيّع الوقت","يمكنهم استخدام أي مخرج مفتوح، لأن جميع المخارج تُفحص وتكون خالية أثناء فحص ما قبل الرحلة","ينبغي أن يصعدوا عبر المدخل المناسب فقط وأثناء توقف الحافلة تماماً"],"explanation":"لا يجوز للركاب الصعود والنزول إلا عبر مدخل الركاب المناسب وفقط أثناء توقف الحافلة تماماً."},"39":{"q":"أقود حافلة نقل عام بالمدينة على مسار مزدحم في وسط المدينة، وأظل أنظر إلى مراياي وأنظر بعيداً على الطريق كل بضع ثوانٍ. عندما أقترب من ممر مشاة مزدحم قرب محطة حافلات، ما السبب الأساسي لأهمية هذا المسح المستمر بالنسبة لسائق مركبة ركاب؟","options":["لرصد المخاطر والمشاة حول الحافلة مبكراً بما يكفي للكبح بسلاسة وتجنب توقف مفاجئ","لمراقبة الواقفين خلف الخط الأبيض حتى لا ينجرفوا أمامه بينما أراقب الطريق","لتحديد لحظة التحول إلى ترس أدنى حتى تفقد الحافلة سرعتها تدريجياً قبل ممر المشاة","للتأكد من أن مخارج الطوارئ وأضواء الخروج لا تزال خالية، لأن الأمتعة المحمولة قد تنزلق أثناء السير"],"explanation":"المسح المستمر للمرايا والطريق يرصد المخاطر والمشاة مبكراً بما يكفي للكبح بسلاسة بدلاً من القيام بتوقف مفاجئ."},"40":{"q":"أقود حافلة نقل عام ممتلئة على مساري عندما يتصل المرسل بهاتفي المحمول الشخصي بشأن تغيير في الجدول، ويلوّح راكب لجذب انتباهي من الممر. بينما لا تزال الحافلة تسير على الطريق، أي من الخيارات التالية غير مسموح لي بفعله؟","options":["أن أنظر إلى مراياي لمراقبة الواقفين خلف الخط الأبيض","أن أرفع هاتفي المحمول اليدوي لتلقي مكالمة المرسل","أن أخبر الراكب بإيجاز أن ينتظر حتى المحطة التالية","أن أبقي كلتا يدي على المقود وأكبح بسلاسة لحركة المرور"],"explanation":"يُحظر استخدام هاتف محمول يدوي أثناء قيادة حافلة متحركة، حتى لتلقي مكالمة من المرسل."},"41":{"q":"أنا متأخر بضع دقائق عن الجدول على مسار حافلتي، وعدة ركاب في المحطة التالية يبدون نافدي الصبر. للحفاظ على الخدمة الجيدة والسلامة معاً، ماذا ينبغي أن أفعل أثناء سير مساري؟","options":["أن أعوّض الوقت الضائع بالتسارع بقوة بين المحطات والكبح متأخراً حتى يبقى الجدول على المسار","أن أتخطى بهدوء المحطتين الأقل استخداماً لأستعيد التأخير وأبقي ركابي الأكثر ازدحاماً سعداء","أن أبقى لطيفاً مع ركابي مع الاستمرار في القيادة بسلاسة وأمان، حتى لو تأخرت قليلاً","أن أتحدث مع الركاب الصاعدين عن التأخير أثناء الانطلاق حتى يشعروا بالاهتمام والاطلاع"],"explanation":"الخدمة الجيدة تعني البقاء لطيفاً مع الركاب مع القيادة بسلاسة وأمان، حتى لو عنى ذلك التأخر قليلاً."},"42":{"q":"أنت تحمّل الركاب عند محطة ويريد أحدهم إحضار بطارية سيارة على متن الحافلة. ماذا ينبغي أن تفعل؟","options":["اسمح بها، لأن الركاب يمكنهم إحضار أي شيء قادرين على حمله معهم إلى الحافلة.","ارفضها؛ فبطاريات السيارات وغيرها من المواد الخطرة غير مسموح بها على متن الحافلة.","خزّنها بجانب خزان الوقود حيث تكون بعيدة عن الممر والركاب.","ضعها في رف علوي فوق مقعد راكب حتى تبقى بعيدة عن الممر هناك."],"explanation":"بطاريات السيارات وغيرها من المواد الخطرة غير مسموح بها على متن الحافلة مع الركاب."},"43":{"q":"يميل أحد الواقفين على حافلتك المتحركة إلى الأمام من خط الوقوف أثناء قيادتك. ماذا ينبغي أن تفعل؟","options":["استمر في القيادة لأن وقوف راكب أمام الخط لا يؤثر على السلامة.","لا تحرك الحافلة حتى يكون الراكب خلف خط الوقوف حيث يكون آمناً.","أسرع حتى تنتهي الرحلة أبكر ويتمكن الراكب من الجلوس في المحطة التالية.","افتح الباب الأمامي أثناء القيادة حتى يحصل الراكب على مساحة أكبر للتراجع للخلف."],"explanation":"لا تتحرك حتى يكون جميع الواقفين خلف خط الوقوف."},"44":{"q":"أنت تقود حافلة نقل عام محمّلة على مسار في المدينة وتقترب من ملتقى سكة حديد قياسي بلا عامل إشارة، ولا إشارة ضوئية، ولا ضوء أخضر يوجهك للعبور. أثناء إبطائك، تستعرض ذهنياً الإجراء الصحيح لإدارة السلامة العامة (DPS). أي إجراء مطلوب منك عند هذا الملتقى؟","options":["أن تتوقف بمصد حافلتك الأمامي مباشرة على القضيب الأول، وتفتح باب الخدمة لتتمكن من الإصغاء لقطار قادم، ثم تتقدم بترس منخفض.","أن تمر حتى مسافة نحو 10 أقدام من أقرب قضيب، وتبقي قدمك مغطية للفرملة، وتعبر برفق دون التوقف توقفاً تاماً.","أن توقف الحافلة توقفاً تاماً، وتحول إلى الترس الأول وأنت جالس على القضبان، ثم تتسارع للعبور لإخلاء الحافلة الثقيلة بسرعة.","أن تتوقف بين 15 و50 قدماً قبل أقرب قضيب، وتنظر وتصغي لقطار، ثم تعبر القضبان دون تغيير التروس."],"explanation":"توقف بين 15 و50 قدماً قبل أقرب قضيب، وانظر وأصغِ لقطار، ثم اعبر دون تغيير التروس لتجنب توقف المحرك على القضبان."},"45":{"q":"تدخل المحطة في نهاية مناوبتك. من مقعدك تبدو الحافلة فارغة تماماً، والرجل الذي نزل أخيراً قال لك: 'هذا الجميع يا سائق.' الوقت متأخر، وأنت متعب، وبديلك ينتظر. أي إجراء يلبّي على أفضل وجه مسؤوليتك في نهاية المسار قبل أن تؤمّن الحافلة وتغادر؟","options":["أن تمشي طول الممر بالكامل إلى الخلف، وتتفقد كل مقعد بحثاً عن راكب نائم وأي أغراض متروكة، قبل القفل.","أن تأخذ بكلام الراكب الأخير، وتشغّل فرملة الانتظار، وتقفل الأبواب، وتغادر لأنه أكد أن الحافلة خالية.","أن تمسح المقصورة من المرآة الداخلية مرة واحدة من مقعد السائق؛ فإن لم تظهر رؤوس أو حركة، فهذا كافٍ لتأكيد أن الحافلة فارغة.","أن تطفئ الأضواء الداخلية وتقفل فوراً، لأن الجميع وصلوا بوضوح إلى محطاتهم وخرجوا على طول الطريق."],"explanation":"في نهاية المسار يجب أن تمشي طول الحافلة بالكامل إلى الخلف، وتتفقد كل مقعد بحثاً عن ركاب نائمين وأغراض منسية قبل القفل."},"46":{"q":"أنت تقود حافلة مسارك على طريق مزدحم بأربعة مسارات عندما يصبح أحد الركاب صاخباً وعدوانياً، يدفع ركاباً آخرين ويخلق مشكلة سلامة خطيرة. لا تزال على بُعد عدة مربعات سكنية من محطتك المجدولة. ما الطريقة الصحيحة للتعامل مع هذا الراكب المزعج؟","options":["أن تفتح باب الركاب فوراً وتوجّه الراكب للخروج بينما تستمر الحافلة في السير ببطء إلى الأمام في حركة المرور.","أن تتابع إلى موقع آمن بعيداً عن مخاطر المرور، وتوقف الحافلة توقفاً تاماً، وتنزل الراكب هناك فقط.","أن تحافظ على مسارك وسرعتك المعتادين دون تدخل، لأن التوقف مبكراً قد يؤخرك عن الجدول لبقية الركاب.","أن تتسارع نحو محطة وجهتك حتى يتولى أفراد أمن المحطة أمر الراكب المزعج عند الوصول."],"explanation":"لا يجوز إنزال الراكب المزعج إلا في موقع آمن بعيداً عن مخاطر المرور، بعد إيقاف الحافلة توقفاً تاماً."},"47":{"q":"أنت تجري فحص ما قبل الرحلة على حافلتك. ما هي العناصر الخاصة بالركاب التي يجب أن تفحصها؟","options":["زيت المحرك والإطارات فقط، لأن الحافلة تُفحص مثل أي مركبة أخرى.","يجب أن تكون قضبان الإمساك والمقاعد ومخارج الطوارئ وأجهزة الإشارة كلها في حالة جيدة.","فقط الطلاء الخارجي ولافتة الوجهة حتى تبدو الحافلة جاهزة للخدمة الآن.","لا شيء خاص على الإطلاق؛ فحافلة الركاب تحتاج نفس فحوصات شاحنة صندوقية فارغة."],"explanation":"افحص قضبان الإمساك والمقاعد ومخارج الطوارئ وأجهزة الإشارة."},"48":{"q":"أنت تقود حافلة نقل عام بالمدينة على جدول ضيق بعد الظهر. عندما تقترب من محطتك المخصصة، ترى أنها مزدحمة بشاحنة توصيل والركاب المنتظرون يتدفقون نحو حافة الرصيف. لا يمكنك الدخول كاملاً إلى الرصيف دون ترك مؤخرتك بارزة في مسار المرور المتحرك. أي إجراء يتبع على أفضل وجه قواعد سلامة الركاب لإدارة السلامة العامة في تكساس (DPS)؟","options":["أن تتوقف في مسار المرور بمحاذاة الشاحنة وتدع الركاب يصعدون من بين المركبات المتوقفة، لأن المحطة المحددة مشغولة.","أن تلوّح للركاب المنتظرين بالخروج إلى المسار المفتوح حتى يصلوا إلى الباب أسرع ويبقوك على الجدول.","أن تتقدم أو تتراجع إلى أقرب موضع يمكنك فيه التوقف دون سد المسار، وتحمّل هناك فقط إن لم يعرّض ذلك الركاب للخطر.","أن تبقى في المسار مع تشغيل أضواء التحذير وتحمّل الجميع بأسرع ما يمكن حتى يتأخر المرور لأقصر فترة."],"explanation":"لا يجوز تحميل الركاب إلا حيث يكون آمناً ولا يسد مسار المرور، لذا انتقل إلى أقرب موضع يحقق كلا الشرطين."},"49":{"q":"أقود مساراً بين المدن في الريف عند الغسق عندما تتقدم راكبة إلى خط الوقوف وتطلب مني أن أنزلها هنا تماماً، على الكتف، لأن مدخل مزرعتها يقع بعد المنعطف التالي مباشرة والمحطة الاعتيادية على بُعد أربعة أميال أخرى. الكتف ضيق، ولا توجد إضاءة، وشاحنة تقترب من الخلف. أي من الخيارات التالية هو الطريقة الصحيحة للتعامل مع هذا الطلب؟","options":["أن تدخل إلى الكتف الضيق وتنزلها حيث طلبت، لأن الناقل العام يجب أن يلبّي طلب راكب دافع بالإنزال حيثما يكون مناسباً للراكب.","أن تبطئ الحافلة إلى زحف وتجعلها تنزل عبر الباب المفتوح دون توقف تام، حتى لا تُضطر الشاحنة خلفك للكبح بقوة لحافلة متوقفة.","أن ترفض رفضاً تاماً وتخبرها أنه تحت أي ظرف لا يجوز للحافلة إنزال الركاب إلا عند المحطة النهائية للمسار، وليس أبداً عند نقاط وسطية.","أن ترفض التوقف على الكتف غير الآمن، وتوضح أنه لا يمكنك إنزال الركاب إلا في مواقع آمنة ومناسبة، وتنزلها عند المحطة التالية أو موضع آمن وقانوني آخر."],"explanation":"يجب إنزال الركاب فقط في مواقع آمنة ومناسبة وقانونية، لذا ارفض الكتف غير الآمن وأنزل الراكبة عند المحطة الآمنة التالية."},"50":{"q":"تلاحظ مشكلة في الكوابح على حافلتك قبل الرحلة. ماذا ينبغي أن تفعل؟","options":["قد المسار على أي حال لأن حافلة مليئة بالركاب المنتظرين لا يمكن تأخيرها إطلاقاً.","لا تنقل الركاب حتى تُصلَح مشكلة الكوابح وتصبح الحافلة آمنة مجدداً.","انقل نصف عدد الركاب المعتاد فقط حتى تعوّض الحمولة الأخف عن ضعف الكوابح.","قد ببطء طوال الطريق واضغط الكوابح كثيراً لتعويض المشكلة اليوم."],"explanation":"لا تنقل الركاب أبداً حتى تُصلَح مشكلة الكوابح."},"51":{"q":"أنت تقود حافلة نقل عام مزدحمة خلال ساعة الذروة. عدة ركاب واقفين يمسكون بالقضبان العلوية خلف خط الوقوف، وترى محطة توقف للركاب قادمة أمامك. للحفاظ على سلامة الركاب الواقفين عند تباطؤك للوصول إلى المحطة، أي تقنية كبح ينبغي أن تستخدم؟","options":["ابدأ الكبح مبكرًا وطبّق الفرامل بسلاسة وتدرّج، حتى لا يُدفع الركاب الواقفون إلى الأمام ويفقدون توازنهم.","انتظر حتى تقترب من المحطة، ثم طبّق ضغطًا ثابتًا وحازمًا على الفرامل لإيقاف الحافلة بدقة عند العلامة.","اضغط على الفرامل بسلسلة من النبضات القصيرة بحيث تنبّه الهزّات الركاب الواقفين إلى إحكام قبضتهم على القضبان قبل المحطة.","حافظ على سرعتك واكبح بقوة في اللحظة الأخيرة، لأن التوقف السريع يقضي وقتًا أقل في السماح للركاب بالتحرك."],"explanation":"مع الركاب الواقفين يجب أن تكبح مبكرًا وبسلاسة، لأن التوقفات المفاجئة أو الحادة يمكن أن تدفع الواقفين إلى الأمام وتصيبهم بأذى."},"52":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة B وقد قبلت للتو وظيفة قيادة حافلة نقل عام بـ40 مقعدًا على مسار مدينة ثابت. قبل رحلتي الأولى، أي تصديق يجب أن يكون على رخصتي لكي أنقل هؤلاء الركاب بشكل قانوني؟","options":["صهريج (N)، لأن الحافلة تحتوي على نظام وقود كبير على متنها","الركاب (P)، لأن المركبة مصممة لنقل الركاب","المواد الخطرة (H)، لأن حافلات المدينة تعمل بالقرب من الوقود والمواد الكيميائية","المقطورات المزدوجة/الثلاثية (T)، لأن المسار يشمل عدة محطات"],"explanation":"يُشترط تصديق الركاب (P) لقيادة حافلة لأن المركبة مصممة ومستخدمة لنقل الركاب."},"53":{"q":"حافلة النقل العام في مدينتي ممتلئة بالكامل بالمقاعد وعدة ركاب يقفون الآن في الممر بينما نقترب من محطة مزدحمة في وسط المدينة. للحفاظ على الحافلة قانونية وآمنة، أين يجب أن أتأكد من بقاء هؤلاء الركاب الواقفين؟","options":["أمام خط الوقوف لكن بعيدًا عن مقعدي الخاص حتى أتمكن من مراقبتهم","في أي مكان في الممر، طالما يحافظون على قبضة محكمة ولا يعيقون مخرجًا","خلف خط الوقوف بحيث لا يقفون أبدًا أمامه أو يحجبون رؤيتي","بين الباب الأمامي والصف الأول من المقاعد حيث أستطيع رؤيتهم بأفضل شكل"],"explanation":"يجب أن يبقى الركاب الواقفون دائمًا خلف خط الوقوف للحفاظ على رؤية السائق الأمامية واضحة ومنطقة الدخول الأمامية مفتوحة."},"54":{"q":"أنا أحمّل الركاب على حافلة النقل العام ويصعد راكب بحقيبتين كبيرتين. الحافلة شبه ممتلئة ويسأل الراكب أين يضعهما. للبقاء ضمن لوائح تكساس، أين يجب أن أتأكد من عدم وضع هاتين الحقيبتين؟","options":["محمولتين على حِجر الراكب نفسه طوال الرحلة","مدسوستين بالكامل تحت المقعد الذي أمام الراكب","موضوعتين بشكل مسطح على مقعد واحد شاغر بجانب الراكب","موضوعتين في الممر أو أمام مخرج طوارئ"],"explanation":"يجب تأمين الأمتعة المحمولة بحيث لا تعيق أبدًا الممر أو أي مخرج طوارئ ولا يمكن أن تسقط على أحد."},"55":{"q":"أنت تقود حافلة نقل عام للمدينة على مسار ثابت مزدحم. عدة ركاب غير معتادين على المنطقة ويبدون غير متأكدين أين ينزلون. عند اقترابك من كل محطة ونقطة تحويل، ما أفضل ممارسة ينبغي اتباعها؟","options":["أعلن عن كل محطة ونقطة تحويل بوضوح حتى يتمكن الركاب من ترقّب وجهتهم والاستعداد لها","ابقَ صامتًا حتى لا تشتت الركاب الآخرين ودع الركاب يتتبعون محطاتهم بأنفسهم","أعلن فقط عن نقاط التحويل الرئيسية وتجاوز محطات الأحياء الصغيرة لتوفير الوقت","انتظر حتى يشير راكب قبل أن تقول أي شيء، ثم أعلن عن تلك المحطة فقط"],"explanation":"ينبغي على سائقي النقل العام الإعلان بوضوح عن كل محطة ونقطة تحويل حتى يتمكن الركاب من ترقّب وجهتهم والاستعداد لها."},"56":{"q":"أنا أقود حافلة سياحية محمّلة عندما يطلب مني رجل في محطة وسطية نقل أربعة أغراض في حجرة الشحن لرحلة قصيرة. ركابي جالسون ونحن مستعدون للانطلاق. أي غرض يجب أن أرفض تحميله لأن القواعد الفيدرالية تمنع حمله في حافلة بينما الركاب على متنها؟","options":["صندوق وزنه 90 رطلًا من فئة خطر مسموح بها، مُبقًى بعيدًا عن مساحة الركاب","صندوق من المتفجرات من الشعبة 1.2 متجه إلى موقع عمل على الطريق","كرسيان متحركان مطويان مربوطان بإحكام بحيث لا ينزلقان إلى الممر","صندوق تبريد محكم الإغلاق من مياه معبأة مخزّن في الحجرة تحت الأرضية"],"explanation":"لا يجوز لحافلة تحمل ركابًا أبدًا أن تنقل متفجرات من الشعبة 1.1 أو 1.2 أو 1.3، بغض النظر عن التعبئة أو مكان التخزين."},"57":{"q":"أنا أقود حافلة نقل عام محمّلة باتجاه معبر سكة حديد ليس به إشارات أو بوابة أو شخص يوجّه المرور وليس مُعلّمًا كمُعفى. أبدأ في التباطؤ مسبقًا بوقت كافٍ حتى أتمكن من التوقف التام والنظر والإصغاء قبل القضبان. للامتثال لقواعد تكساس، أين يجب أن تتوقف مقدمة حافلتي توقفًا تامًا بالنسبة لأقرب قضيب؟","options":["على مسافة لا تقل عن 5 أقدام ولا تزيد عن 10 أقدام من أقرب قضيب","على مسافة لا تقل عن 50 قدمًا ولا تزيد عن 80 قدمًا من أقرب قضيب","على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب","في أي مكان قبل المعبر، طالما تتحرك الحافلة ببطء وينظر السائق إلى الجانبين"],"explanation":"عند معبر سكة حديد غير مُعفى يجب أن تتوقف الحافلة على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب، ثم تنظر وتصغي."},"58":{"q":"أنت تشغّل حافلة نقل عام للمدينة عند محطة مزدحمة في وسط المدينة. أنهى راكب صعوده للتو، وأنت مستعد للمغادرة. عند استعدادك لإغلاق الأبواب والعودة إلى حركة المرور، أيًّا مما يلي ينبغي أن تفعله أولًا قبل أن تبدأ الحافلة في التحرك؟","options":["زِد دورات المحرك بضع مرات حتى يعرف الركاب المنتظرون على الرصيف أن الحافلة على وشك المغادرة","حرّر فرامل الانتظار وابدأ بالاندماج بينما لا يزال آخر الركاب يبحثون عن مقاعدهم","أطفئ أضواء المقصورة الداخلية حتى ترى مرايا الجانب بوضوح أكبر","تأكد من عدم وجود راكب واقف في المدخل أو يعبر منه قبل أن تُغلق الأبواب وتتحرك"],"explanation":"قبل إغلاق الأبواب والتحرك، تأكد من عدم وجود راكب واقف في المدخل أو يعبر منه حتى لا يُجَرّ أحد أو يُقذف."},"59":{"q":"أنت تقود حافلة نقل عام محمّلة في ظهيرة دافئة عندما يفتح راكب قرب المنتصف نافذة منزلقة ويبدأ في الانحناء للخارج، مستندًا بمرفقه على الإطار ليشعر بالنسيم. بصفتك السائق، ماذا يجب أن تطلب من هذا الراكب بخصوص ذراعيه ورأسه؟","options":["إبقاء كلتا الذراعين والرأس داخل الحافلة في جميع الأوقات أثناء حركتها","إبقاء الذراعين داخل الحافلة لكن السماح بإخراج الرأس لفترة وجيزة للهواء النقي في الأيام الحارة","يمكن أن تبقى الذراعان والرأس خارجًا طالما أن النافذة منخفضة بالكامل","الانتقال إلى مقعد قرب المخرج الخلفي قبل مدّ الذراعين خارج النافذة"],"explanation":"يجب على الركاب إبقاء ذراعيهم ورأسهم داخل الحافلة في جميع الأوقات أثناء حركتها، لأن الأجسام البارزة قد تصطدم بهم."},"60":{"q":"أنا أقود حافلة نقل عام محمّلة عندما يطلب مني رجل في محطة حمل أربعة أغراض في منطقة الركاب لرحلة قصيرة عبر المدينة. بصفتي السائق، أي غرض يجب أن أرفض إحضاره على متن الحافلة بينما الركاب على متنها؟","options":["صندوق محكم الإغلاق وزنه خمسة أرطال من الأطعمة المعلبة يوصله إلى صديق","أسطوانة مضغوطة موسومة بالشعبة 2.3 غاز سام","حقيبة ظهر لطفل سيحملها على حِجره طوال الرحلة","ترمس مغلق من القهوة الساخنة ينوي شربها لاحقًا"],"explanation":"لا يجوز لحافلة تحمل ركابًا أبدًا أن تنقل غاز الشعبة 2.3 السام، لذا يجب رفض أسطوانة مضغوطة منه."},"61":{"q":"أنا أحمّل حافلتي السياحية لرحلة مستأجرة عندما يطلب راكب عند الرصيف إحضار أربعة طرود صغيرة على متنها، كل منها موسوم بعلامة مواد خطرة مختلفة. الحافلة بخلاف ذلك ممتلئة بالركاب الجالسين. أيٌّ من هذه الطرود يمكنني قبوله ونقله قانونيًا بكمية محدودة؟","options":["صندوق موسوم بالشعبة 1.3 متفجرات، لأن الكمية صغيرة","وعاء موسوم بالغاز السام (الفئة 2.3)، طالما أنه محكم الإغلاق","صندوق من ذخيرة الأسلحة الصغيرة موسوم بـORM-D، بكمية محدودة","برميل موسوم بالإشعاع الأصفر-III، مُبقًى بعيدًا عن المقاعد"],"explanation":"يجوز للحافلة حمل كميات صغيرة فقط من المواد الخطرة، وذخيرة الأسلحة الصغيرة الموسومة بـORM-D بكمية محدودة مدرجة في القائمة المسموح بها."},"62":{"q":"أنا أشغّل حافلة نقل عام للمدينة خلال ساعة الذروة وكل مقعد مشغول، لذا يقف عدة أشخاص الآن في الممر. للحفاظ على سلامة ركابي الواقفين والبقاء ضمن قواعد إدارة السلامة العامة (DPS)، أين يجب أن أتأكد من عدم وجود أي منهم أثناء حركة الحافلة؟","options":["الوقوف في الممر مباشرة بجانب مقعد مشغول","الوقوف قرب نافذة جانبية بعيدًا عن الأبواب","الوقوف خلف خط الوقوف الأبيض مباشرة","الوقوف في أي مكان أمام خط الوقوف"],"explanation":"لا يجوز لأي راكب أن يقف أمام خط الوقوف، لأن الوقوف أمامه يهدد بأن يُقذف نحو الزجاج الأمامي أو يحجب رؤية السائق."},"63":{"q":"أثناء الصعود، تسأل راكبة أين يمكنها وضع حقيبتها المحمولة لأن الحافلة تمتلئ. وفقًا لقواعد رخصة القيادة التجارية في تكساس بشأن الأمتعة المحمولة، أيُّ مكان واحد يجب ألا تسمح لها بترك حقيبتها فيه؟","options":["موضوعة على أرضية الممر بجانب مقعدها، حيث تمتد جزئيًا نحو المخرج الخلفي","مدفوعة بالكامل تحت المقعد الذي أمامها بحيث تبقى خارج الممشى","مؤمّنة في الرف العلوي فوق مقعدها بحيث لا يمكن أن تسقط على أحد","محمولة على حِجرها أو مدسوسة بين قدميها مقابل قاعدة المقعد"],"explanation":"يجب تأمين الأغراض المحمولة بحيث لا يمكن أن تعيق الممر أو أي مخرج، لذا فإن حقيبة متروكة في الممر نحو مخرج غير مسموح بها."},"64":{"q":"أثناء فحصي قبل الرحلة، أنا مستعجل لأنني متأخر على مساري الصباحي. يطلب مني راكب أن أسرع وأحمّل فحسب. وفقًا لقواعد إدارة السلامة العامة في تكساس (DPS)، أي شرط يجب أن يتحقق بشأن مخارج الطوارئ في حافلتي قبل أن أبدأ القيادة؟","options":["يمكن أن تبقى المخارج مغلقة بمزلاج طالما أحتفظ بالمفتاح معي لفتحها بسرعة","يجب أن يعمل كل مخرج طوارئ بشكل سليم ويبقى غير معاق بالأمتعة أو الركاب","يجب أن يبقى مخرج خلفي واحد على الأقل مفتوحًا بالكامل أثناء صعود الركاب","لا حاجة لفحص المخارج إلا في نهاية اليوم، وليس قبل المغادرة"],"explanation":"قبل القيادة، يجب أن يعمل كل مخرج طوارئ بشكل سليم ويبقى غير معاق بالأمتعة أو الركاب."},"65":{"q":"أنا أقود حافلة مسار وقودها ينخفض، وركابي لا يزالون جالسين على متنها بينما أدخل إلى جزيرة تزويد بالوقود. وفقًا لقواعد إدارة السلامة العامة في تكساس (DPS)، في أي من هذه الحالات يُمنع علي بوضوح من تزويد الحافلة بالوقود الآن؟","options":["لا يزال خزان الوقود يشير إلى حوالي النصف على المقياس","إنها منتصف ظهيرة صافية وجيدة الإضاءة","أحد الركاب الجالسين قرب الخلف يدخّن","جهاز راديو الإرسال مُشغّل بمستوى صوت منخفض"],"explanation":"لا تزوّد حافلة بالوقود أبدًا والركاب على متنها إذا كان أحد يدخّن، لأن أبخرة الوقود شديدة الاشتعال والسيجارة المشتعلة مصدر إشعال."},"66":{"q":"أنا أشغّل مسارًا مستأجرًا مزدحمًا، وراكب يصعد عند المحطة الأخيرة لديه حقيبة كبيرة ذات عجلات لكن لا يوجد مقعد متاح لها. يسأل إن كان بإمكانه فقط وضعها في أحد المقاعد الفارغة أو إسنادها في الممر بجانبه للرحلة القصيرة. وفقًا لقواعد الركاب في تكساس، أيٌّ من هذه أمر يجب ألا أسمح به؟","options":["السماح له بحمل حقيبة أصغر على حِجره إذا كانت خفيفة بما يكفي ألا تنزلق","السماح له بالوقوف خلف خط الوقوف بمجرد امتلاء كل المقاعد","تخزين الحقيبة في رف علوي معتمد حيث تكون مؤمّنة","وضع الحقيبة في مقعد أو الممر حيث تعيق مقعدًا أو مخرجًا"],"explanation":"يجب تأمين الأمتعة المحمولة بحيث لا يمكن أن تعيق مقعدًا أو مخرجًا أو تسقط على أحد، لذا يجب عدم السماح بحقيبة تعيق مقعدًا أو مخرجًا."},"67":{"q":"أنا أقود مسار نقل عام ثابتًا، ويصعد راكب مسنّ جديد على المدينة، يبدو غير متأكد كيف يصل إلى خط متصل. أثناء قيادتي ووصولي إلى كل موقع مجدول، ماذا ينبغي أن أعلن إلى جانب اسم المحطة؟","options":["المكان الآمن للنزول وأين يمكن للركاب التحويل إلى مسارات أخرى","الدقائق المقدّرة المتبقية حتى تصل الحافلة إلى وجهتها النهائية","التقاطع التالي حتى يعرف الواقفون متى يتقدمون أمام خط الوقوف","مستوى الوقود الحالي وكم ساعة محرك استهلكت الرحلة حتى الآن"],"explanation":"يجب على سائقي الحافلات الإعلان عن نقاط النزول الآمنة وأين يمكن للركاب التحويل إلى مسارات أخرى حتى يعرف الركاب كيف ينزلون ويتصلون بأمان."},"68":{"q":"أنت تقود حافلة مسار على طريق مزدحم من أربعة مسارات عندما يصبح راكب قرب الخلف صاخبًا ومجادلًا مع راكب آخر. لا أحد مهدَّد ولا سلاح متورّط، لكن الإزعاج يضايق بقية الركاب. وفقًا لقواعد الركاب لإدارة السلامة العامة في تكساس (DPS)، ما الإجراء الأنسب؟","options":["افتح الباب عند إشارة المرور التالية وأمر الراكب المزعج بالنزول هناك","أوقف السلوك المزعج بهدوء بأن تطلب من الراكب أن يهدأ، ولا تُنزله إلا في مكان آمن ومناسب إذا لزم الأمر","تابع القيادة إلى المحطة المجدولة التالية دون معالجة الجدال، لأن الركاب سيهدؤون على الأرجح من تلقاء أنفسهم","اتصل بالإرسال عبر الراديو وتابع القيادة بشكل طبيعي، تاركًا الركاب يحلّون الجدال فيما بينهم"],"explanation":"بالنسبة لراكب مزعج لكن غير خطير، اطلب منه أن يهدأ أولًا ولا تُنزله إلا في مكان آمن ومناسب إذا لزم الأمر."},"69":{"q":"تبدأ نوبة حافلتي المستأجرة الساعة 6:00 مساءً الليلة. أثناء غداء متأخر مع الأصدقاء، يطلب أحدهم جولة من الجعة ويعرض عليّ واحدة. للبقاء ضمن قاعدة الكحول قبل بدء العمل، ما أحدث وقت على الساعة يمكنني فيه شرب جعة واحدة وما زلت أستطيع التبليغ لنوبتي قانونيًا؟","options":["الساعة 5:00 مساءً، لأن جعة واحدة قبل ساعة من العمل ضمن المسموح","أي وقت، لأن الحد ينطبق فقط بمجرد وجود الركاب فعليًا على متن الحافلة","الساعة 2:00 ظهرًا، لأنه لا يُسمح بأي كحول خلال 4 ساعات من بدء العمل","الساعة 6:00 صباحًا، لأن الكحول ممنوع لمدة 12 ساعة كاملة قبل العمل"],"explanation":"لا يجوز لسائق الحافلة تناول الكحول خلال 4 ساعات من بدء العمل، لذا فإن آخر لحظة قانونية قبل نوبة الساعة 6:00 مساءً هي الساعة 2:00 ظهرًا."},"70":{"q":"أنا أحمّل ركابًا على حافلة النقل العام، ويريد راكب إحضار حقيبة كبيرة على متنها. قبل أن أسمح بها، ما المعيار الذي يجب أن أطبّقه لأقرر ما إذا كان الغرض المحمول مقبولًا؟","options":["يمكن أن تستقر على مقعد فارغ طالما لا يحتاج راكب يدفع إلى ذلك المقعد في الوقت الحالي","يمكن وضعها قرب الأمام حتى أراقبها أثناء القيادة","يمكن أن تبرز جزئيًا في الممر طالما لا يزال الركاب الواقفون قادرين على تخطّيها","يجب أن تكون صغيرة بما يكفي ليتم تأمينها بحيث لا تعيق الممر أو أي مخرج"],"explanation":"تكون الأمتعة المحمولة مقبولة فقط إذا كانت صغيرة بما يكفي ليتم تأمينها بحيث لا تعيق الممر أو أي مخرج."},"71":{"q":"أنا على وشك إخراج حافلتي المستأجرة من المحطة لرحلة طويلة بين المدن بحمولة كاملة من الركاب. قبل أن أنطلق مباشرة، ما أهم شيء ينبغي أن أوجّه به ركابي؟","options":["موقع مخارج الطوارئ ومعلومات السلامة الأساسية","وقت الوصول المجدول والسرعة القصوى المعلنة لطراد الحافلة","عدد محطات الوقود المخطط لها ومتوسط استهلاك الوقود للحافلة","سياسة الاسترداد للشركة ومعدل أجري بالساعة كسائق"],"explanation":"قبل قيادة حافلة مستأجرة أو بين المدن، يجب على السائق توجيه الركاب إلى موقع مخارج الطوارئ ومعلومات السلامة الأساسية."},"72":{"q":"أنت تقود حافلة نقل عام للمدينة في حركة مرور معتدلة عندما يسحب راكب حبل طلب التوقف تمامًا وأنت تعبر تقاطعًا مزدحمًا بلا كتف للطريق. ما الطريقة الصحيحة للاستجابة لهذا الطلب؟","options":["توقف فورًا حيث أنت، في التقاطع، حتى لا يضطر الراكب إلى الانتظار","تابع عبر التقاطع وأوقف الحافلة بسلاسة عند المحطة الآمنة أو المحطة المخصصة التالية","انعطف وتوقف عند أول مكان تصل إليه، حتى لو حجب مسارًا مروريًا أو ممر مشاة","طبّق الفرامل بحزم على الفور حتى يعرف الراكب أنك استلمت الإشارة"],"explanation":"تتطلب إشارة طلب التوقف التوقف فقط عند المكان الآمن التالي، لذا تابع عبر التقاطع واكبح بسلاسة عند المحطة الآمنة أو المخصصة التالية."},"73":{"q":"أنا سائق حافلة نقل عام أُكمل فحصي قبل الرحلة قبل مسار صباحي، مركّزًا تحديدًا على أغراض الركاب التي يُطلب مني التحقق منها داخل الحافلة. أيٌّ من مجموعات الأغراض التالية يجب أن أؤكد أنها موجودة وتعمل؟","options":["راديو المقصورة، وميكروفون الإرسال، ووحدة عرض نظام تحديد المواقع (GPS)","حالة تنجيد المقاعد، ومحاذاة حصيرة الأرضية، وحاملات الأكواب","المقابض والقضبان، وإشارة التوقف/الباب، ومخارج الطوارئ","لوحات الإعلانات الداخلية، وصندوق الأجرة، ومصابيح القراءة العلوية"],"explanation":"يجب أن يتحقق فحص الحافلة قبل الرحلة من أغراض سلامة الركاب: المقابض والقضبان، وعمل إشارة التوقف والباب، ومخارج الطوارئ."},"74":{"q":"أنت تشغّل حافلة نقل عام للمدينة خلال ذروة الصباح. صعد آخر بضعة ركاب للتو ولا يزالون يتجهون نحو المقاعد المفتوحة، مع وقوف بضعة ركاب قرب الأمام وحقيبة واحدة موضوعة في الممر. يطلب منك راكب الانطلاق بسرعة حتى لا يفوته اتصاله. وفقًا لقواعد الركاب لإدارة السلامة العامة في تكساس (DPS)، يجب ألا تبدأ بتحريك الحافلة حتى يتحقق أيٌّ مما يلي؟","options":["أن يجد كل راكب مقعدًا، لأن الواقفين غير مسموح لهم أبدًا بالركوب في حافلة نقل عام","أن تُطفأ أضواء القبة الداخلية حتى يتمكن الركاب من الرؤية بوضوح عبر النوافذ","أن تكون قد أكدت الوجهة عبر راديو المقصورة وسجّلت وقت مغادرتك","أن يكون كل الواقفين خلف خط الوقوف (الأبيض) وأن يكون الممر والمخارج خالية من الأمتعة"],"explanation":"قبل التحرك، تأكد من أن كل الواقفين خلف خط الوقوف (الأبيض) وأن الممر والمخارج خالية من الأمتعة."},"75":{"q":"أنا أقود حافلة نقل عام للمدينة على مساري والركاب لا يزالون جالسين على متنها عندما أصل إلى محطة وسطية وأحتاج إلى النزول لفترة وجيزة لمساعدة راكب بمصعد كرسي متحرك على الرصيف. وفقًا لقواعد إدارة السلامة العامة (DPS)، أيٌّ مما يلي يجب ألا أفعله أبدًا في هذا الموقف؟","options":["ترك الحافلة المحمّلة دون مراقبة بإهمال، مع تشغيل المحرك والباب مفتوحًا بينما أنا بعيد عن أدوات التحكم","تفعيل فرامل الانتظار قبل أن يبدأ أي راكب بالتحرك من مقاعده","مراقبة الركاب الصاعدين الذين قد يخطون إلى حركة المرور العابرة","الإعلان عن المحطة بوضوح حتى يعرف الركاب الجالسون أن الحافلة تتوقف"],"explanation":"يجب ألا تترك أبدًا حافلة محمّلة دون مراقبة بإهمال مع تشغيل المحرك والباب مفتوحًا بينما أنت بعيد عن أدوات التحكم."},"76":{"q":"أنت تقود حافلة نقل عام محمّلة عندما تبدأ مجموعة من الركاب قرب المقدمة بالتجادل بصوت مرتفع وينادي عدد منهم عليك محاولين إقحامك في النزاع. وفقًا لقواعد إدارة السلامة العامة في تكساس (DPS)، في أيٍّ من هذه الحالات يكون من الأهمّ أن ترفض بحزم السماح للركاب بتشتيت انتباهك؟","options":["بينما الحافلة متوقفة عند محطة مجدولة مع تفعيل مكابح الانتظار وفتح الأبواب","بينما الحافلة تسير وسط مطر غزير أو ضباب أو ظروف قيادة خطرة أخرى","بينما الحافلة متوقفة عند استراحة وسطية والمحرّك مُطفأ","بينما الحافلة متوقفة عند الرصيف بانتظار موعد انطلاقها المجدول"],"explanation":"تجنّب أي شيء يصرف انتباهك عن القيادة بينما الحافلة تسير، خصوصًا في المطر الغزير أو الضباب أو الظروف الخطرة الأخرى."},"77":{"q":"أثناء قيادة حافلة تقلّ ركابًا، ينبغي على السائق ألّا:","options":["يفحص المرايا كثيرًا","يستخدم هاتفًا محمولًا باليد","يعلن عن المحطات التالية","يتفقّد مؤشرات لوحة القيادة"],"explanation":"لا تستخدم هاتفًا محمولًا باليد أثناء قيادة الحافلة."},"78":{"q":"أنت تقود حافلة نقل عام داخل المدينة وتصل إلى المحطة الأخيرة، حيث ينتظر نحو اثني عشر راكبًا للنزول وعدد منهم واقف بالفعل قرب المقدمة. الرصيف على منحدر هابط خفيف. قبل أن تشغّل أزرار التحكم بالباب للسماح لأي شخص بالنزول، ما الذي يجب أن تفعله أولًا؟","options":["تحريك الحافلة ببطء إلى الأمام لتستقر ملاصقة للرصيف بينما يبدأ الركاب بالنزول","تحرير مكابح الانتظار والاعتماد على دواسة مكابح التشغيل لكي يسمح مِزلاج الباب بفتحه","إيقاف الحافلة تمامًا وتفعيل مكابح الانتظار قبل تشغيل الباب","إطفاء الأضواء الداخلية والأمامية لإشعار الركاب بأن الرحلة انتهت وأنه يمكنهم النزول"],"explanation":"أوقف الحافلة تمامًا دائمًا وفعّل مكابح الانتظار قبل فتح الباب حتى يتمكن الركاب من التحرك والنزول بأمان دون أن تتدحرج الحافلة."},"79":{"q":"أثناء فحص ما قبل الرحلة في صباح صيفي حار، ألاحظ أن فتحات السقف في حافلة النقل العام لديّ مفتوحة قليلًا وأن بعض النوافذ الجانبية من النوع الذي يُدفع للخارج. يخبرني سائق جديد بأن أترك فتحات السقف مفتوحة طوال اليوم لإبقاء المقصورة باردة للركاب. قبل أن أقبل هذه النصيحة، ما الذي يجب أن أفهمه عن الغرض الأساسي من فتحات السقف هذه والنوافذ التي تُدفع للخارج؟","options":["إنها مصممة أساسًا كفتحات للتحكم بالمناخ، لذا فإن تركها مفتوحة لتدوير الهواء هو استخدامها اليومي المقصود","إنها مزايا راحة اختيارية يمكنني تركها مفتوحة أو مغلقة كما أشاء، لأنها لا تؤدي وظيفة حيوية للسلامة","إنها مقصورات تخزين داخلية مخصصة لحفظ الأمتعة المحمولة المؤمَّنة بعيدًا عن الممر","إنها مخارج طوارئ، لذا يجب إبقاؤها صالحة للتشغيل وغير معاقة حتى يتمكن الركاب من الهروب عند الحاجة"],"explanation":"فتحات السقف والنوافذ التي تُدفع للخارج هي مخارج طوارئ، لذا يجب إبقاؤها صالحة للتشغيل وغير معاقة حتى يتمكن الركاب من الهروب في حال وقوع تصادم أو حريق أو انقلاب."},"80":{"q":"أنت تقود حافلة نقل عام محمّلة بأربعين راكبًا وهناك منعطف حاد محدد بسرعة 35 ميلًا في الساعة قادم أمامك. مقارنةً بحركة السيارات من حولك، ما الذي يجب أن تفعله للتعامل مع هذا المنعطف بأمان؟","options":["خفّض سرعتك قبل دخول المنعطف، لأن مركز الثقل المرتفع للحافلة يجعلها عرضة للانقلاب","حافظ على سرعتك الحالية خلال المنعطف، لأن التباطؤ أولًا قد يجعل الحافلة تترنّح وتُفقد الركاب الواقفين توازنهم","اكبح بقوة أثناء الدوران في المنعطف لإبقاء الحافلة ملاصقة للجهة الداخلية من المسار","التزم تمامًا بالسرعة المحددة 35 ميلًا في الساعة، لأن الحافلة يمكنها اجتياز المنعطف بأمان بالسرعة نفسها التي تجتازه بها السيارة"],"explanation":"خفّض سرعتك قبل دخول المنعطف لأن مركز الثقل المرتفع للحافلة يجعلها عرضة للانقلاب."},"81":{"q":"أنت تقود حافلة نقل عام داخل المدينة وتقترب من محطتك التالية، وتلاحظ أن عدة ركاب قد وقفوا بالفعل ويتجهون نحو الأبواب الأمامية بينما لا تزال الحافلة تسير. للحفاظ على سلامة هؤلاء الركاب الواقفين أثناء إيقافك للحافلة، ما أفضل طريقة للتعامل مع الكبح؟","options":["حافظ على سرعتك واكبح بقوة في اللحظة الأخيرة لتتوقف بدقة عند علامة المحطة المحددة","ابدأ الكبح بسلاسة ومبكرًا حتى لا يُفقد التباطؤ التدريجي الركاب الواقفين توازنهم","اضغط على دواسة المكابح بسرعة على دفعات قصيرة حتى يشعر الركاب بتباطؤ الحافلة ويمسكوا بمقبض","انزلق وأنت في وضع التعشيق ثم اكبح بقوة مرة واحدة عند المحطة لإبقاء مسافة التوقف أقصر ما يمكن"],"explanation":"اكبح بسلاسة ومبكرًا لأن التوقف المفاجئ أو الحاد قد يفقد الركاب الواقفين توازنهم ويسبب لهم الإصابة."},"82":{"q":"أنا أقود حافلة نقل عام محمّلة عندما يبدأ رذاذ بارد بالتجمد على الإسفلت، ويبدو سطح الطريق أمامي زجاجيًا وزلقًا. للحفاظ على السيطرة وحماية ركابي الواقفين والجالسين، ما الذي يجب أن أفعله؟","options":["أحافظ على سرعتي المعتادة على الطريق السريع لكني أضغط على المكابح بسرعة لاختبار مقدار الاحتكاك المتبقي","أبقي مسافة الاتباع كما هي وأعتمد على تصحيحات توجيه سريعة وحازمة إذا بدأت الحافلة بالانزلاق","أخفّض سرعتي وأستخدم توجيهًا وكبحًا وتسارعًا سلسًا وتدريجيًا لتجنّب فقدان الاحتكاك","أزيد سرعتي قليلًا لاجتياز المقطع الجليدي أسرع وأكبح بقوة مرة واحدة فقط عند وصولي إلى رصيف جاف مجددًا"],"explanation":"على الأسطح الزلقة ينخفض الاحتكاك بشدة، لذا خفّض سرعتك واستخدم توجيهًا وكبحًا وتسارعًا سلسًا وتدريجيًا حتى لا تفقد التماسك مع الطريق."},"83":{"q":"أنت تقود حافلة نقل عام محمّلة وتوقفت على بُعد 30 قدمًا قبل معبر سكة حديد. بعد أن نظرت وأنصتّ وتأكدت من خلوّ القضبان، بدأت بالعبور. المعبر على منحدر صاعد خفيف وتشعر بالحافلة تفقد زخمها. أي إجراء يجب أن تتجنّبه بينما حافلتك على القضبان؟","options":["إبقاء الباب الأمامي مغلقًا أثناء عبورك القضبان","الاستمرار بالمسح في كلا الاتجاهين حتى يتجاوز مؤخرة الحافلة المعبر","الحفاظ على سرعة ثابتة وسلسة طوال العبور فوق القضبان","تغيير السرعة إلى تروس أدنى لاستعادة القوة أثناء صعودك المنحدر"],"explanation":"لا تغيّر التروس أبدًا أثناء عبور قضبان سكة الحديد؛ اختر ترسًا مناسبًا قبل المعبر وحافظ عليه طوال العبور لتجنّب توقّف المحرّك فوق القضبان."},"84":{"q":"أنا أقود حافلة نقل عام محمّلة وأقترب من معبر سكة حديد غير معفى لا يوجد فيه مُنظِّم مرور ولا إشارة تبيّن خلوّه. عليّ أن أتوقف وأنظر وأنصت قبل العبور. ضمن أي مسافة أمام أقرب قضيب يجب أن أوقف الحافلة توقفًا تامًا؟","options":["بين 15 و50 قدمًا قبل المعبر","على بُعد 50 قدمًا على الأقل قبل المعبر","بين 5 و10 أقدام قبل المعبر","بين 100 و200 قدم قبل المعبر"],"explanation":"يجب أن تتوقف الحافلة بين 15 و50 قدمًا قبل معبر سكة الحديد، ثم تنظر وتنصت قبل المتابعة."},"85":{"q":"أنا أقود حافلة نقل عام محمّلة على خط سيري وأقترب من معبر سكة حديد. في أيٍّ من هذه الحالات فقط يُسمح لي قانونًا بالعبور دون التوقف التام؟","options":["أجراس التحذير تدق وأضواء الإشارة الحمراء تومض كلما اقتربت","رجل شرطة يلوّح للمرور بالعبور، أو إشارة مرور خضراء توجّهني للأمام","أستطيع سماع قطار يقترب بوضوح لكن حواجز المعبر لم تبدأ بالنزول بعد","حواجز المعبر في طور النزول عبر الطريق"],"explanation":"التوقف المطلوب عند معبر سكة الحديد غير لازم عندما يوجّه رجل شرطة أو إشارة مرور خضراء الحافلة للعبور."},"86":{"q":"أنت تقود حافلة نقل عام محمّلة على منحدر شديد في وسط المدينة عندما يشير راكب للنزول عند المحطة التالية الواقعة في منتصف التلة. بعد أن تتوقف عند الرصيف وتقف الحافلة تمامًا، ما الذي يجب أن تفعله لمنعها من الانجراف قبل أن يبدأ الركاب بالتحرك؟","options":["انقل إلى الوضع المحايد وأمسك الحافلة بضغط ثابت على دواسة مكابح التشغيل","اترك ناقل الحركة في ترس منخفض وارفع قدمك عن جميع الدواسات","فعّل مكابح الانتظار بإحكام قبل أن يقف أي راكب أو يتجه نحو الباب","دع الحافلة تستقر للخلف قليلًا مقابل الرصيف ليعمل الرصيف ككابح للعجلة"],"explanation":"عند أي استراحة أو محطة وسطية، فعّل مكابح الانتظار بإحكام قبل أن يقف الركاب أو يتحركوا نحو الباب حتى تكون الحافلة مثبّتة في مكانها."},"87":{"q":"امتلأت كل مقاعد حافلتي داخل المدينة خلال ساعة الذروة، وأصبح عدة ركاب الآن واقفين في الممر. عند انطلاقي من الرصيف، أين يُطلب مني التأكد من بقاء هؤلاء الركاب الواقفين طوال الرحلة؟","options":["خلف مقعد السائق مباشرةً حتى أتمكن من مراقبتهم","في أي مكان من الممر، ما دام لا يسقط شيء في درج الدخول","أمام الخط الأبيض حيث يقع باب الخروج الأمامي","خلف خط الوقوف المرسوم على أرضية الحافلة"],"explanation":"يجب أن يبقى الركاب الواقفون دائمًا خلف خط الوقوف حتى لا يحجبوا رؤية السائق أو يعيقوا الخروج الأمامي."},"88":{"q":"أنا أقود حافلة نقل عام داخل المدينة خلال ساعة الذروة وعدة ركاب واقفون خلف الخط الأبيض للوقوف لأن جميع المقاعد مشغولة. حركة المرور أمامي كثيفة وقد تنعطف سيارة أمامي في أي لحظة. مع علمي بأنني قد أضطر للتفاعل بسرعة، أي خطر ينبغي أن يحكم أكثر طريقة تشغيلي للحافلة في هذا الموقف؟","options":["الركاب الواقفون قد يفقدون توازنهم ويُصابون، لذا يجب أن أترك مسافة إضافية أمامي وأكبح بسلاسة بدلًا من الكبح المفاجئ","التوقف المفاجئ قد يوقف المحرّك ويقطع الطاقة عن المكابح، لذا يجب أن أخفّض الترس مبكرًا قبل إبطاء الحافلة","الكبح المفاجئ قد يستنزف نظام الإضاءة ويُعتم الأضواء الداخلية، لذا يجب أن أبقي الأضواء الأمامية مطفأة","التوقف المفاجئ قد يُفعّل مِزلاج الباب ويقفل المخارج، لذا يجب أن أحرّر مكابح الانتظار قبل الكبح"],"explanation":"الركاب الواقفون قد يفقدون توازنهم ويُصابون بسبب التوقف المفاجئ، لذا اترك مسافة اتباع إضافية واكبح بسلاسة."},"89":{"q":"أنا أُجري فحص ما قبل الرحلة على حافلة نقل عام قبل صعود الركاب، وأضبط كلتا المرآتين الخارجيتين عند الرصيف. لأداء العمل الذي يحتاج إليه سائق الحافلة فعلًا، إلى ماذا ينبغي ضبط هاتين المرآتين لتمكينني من رؤيته؟","options":["بشكل رئيسي السماء المفتوحة والأسطح فوق الطريق، حتى أتمكن من قراءة لافتات الارتفاع العلوي عند اقترابي من الجسور المنخفضة","جوانب الحافلة ومنطقة الصعود، حتى أتمكن من مراقبة الركاب وهم يصعدون ويبتعدون عن الحافلة","فقط حجرة المحرّك وأقواس الإطارات، حتى أتمكن من رصد تسرّب سائل أو دخان قبل أن يصبح عطلًا","بشكل رئيسي الممر الداخلي والسقف، حتى أراقب الواقفين وأي أمتعة متروكة تسدّ مخرجًا"],"explanation":"اضبط المرايا الخارجية لتُظهر جوانب الحافلة ومنطقة الصعود حتى تتمكن من مراقبة الركاب وهم يصعدون ويبتعدون عن الحافلة."},"90":{"q":"بينما يصعد راكب أو ينزل، يجب أن تكون الحافلة:","options":["تسير ببطء","متوقفة تمامًا","في ترس الرجوع للخلف","تتسارع من جديد"],"explanation":"يجب أن تكون الحافلة متوقفة تمامًا أثناء صعود الركاب أو نزولهم."},"91":{"q":"أنا أقود حافلة نقل عام محمّلة وأنظر إلى المرآة الداخلية المثبّتة فوق الزجاج الأمامي. وفقًا لإرشادات إدارة السلامة العامة في تكساس (DPS)، ماذا ينبغي أن أستخدم هذه المرآة تحديدًا لمراقبته؟","options":["حركة المرور والمركبات القادمة من الخلف في المسار المجاور","الإطارات الخلفية والجانب الأيمن للحافلة أثناء الانعطاف","الركاب داخل الحافلة وما يجري في الممر","الطريق أمامي والمسافة إلى المركبة التي تسبقني"],"explanation":"تُستخدم المرآة الداخلية لمراقبة الركاب داخل الحافلة والنشاط في الممر."},"92":{"q":"أنا أقود خطًا مكتظًا خلال ساعة الذروة ويريد الصعود عدد من الناس أكبر من عدد المقاعد المتاحة لديّ. سيضطر بعضهم للوقوف في الممر خلف الخط الأبيض. قبل أن أسمح لأي شخص بالوقوف، أيٌّ مما يلي هو العامل الحاسم في ما إذا كان الوقوف مسموحًا قانونًا في حافلتي؟","options":["مسموح به ما دام كل واقف يبقى خلف خط الوقوف الأبيض ولا يحجب رؤيتي","مسموح به ما دمت أكبح بسلاسة وأعلن المحطات حتى لا يسقط الركاب الواقفون","مسموح به لأن الممر ومخارج الطوارئ خالية من أي أمتعة محمولة","مسموح به فقط إذا كانت حافلتي مصممة ومجهّزة خصيصًا لنقل الركاب الواقفين"],"explanation":"يجوز للركاب الوقوف فقط في حافلة مصممة ومجهّزة خصيصًا لنقل الواقفين، مثل حافلة النقل العام."},"93":{"q":"تستأجر مجموعة كنسية حافلتي ويصرّ قائد الرحلة على أنني أستطيع إضافة بضعة ركاب واقفين لأن «هناك مساحة أرضية وافرة والطقس لطيف لرحلة قصيرة». قبل أن أوافق، ما الذي يحدّد فعلًا الحد الأقصى لعدد الأشخاص المسموح لي قانونًا بنقلهم على هذه الحافلة؟","options":["تصميم الحافلة وتصنيف المصنّع لها، اللذان يحددان سعتها المقررة للركاب","مقدار المساحة الأرضية والممر المتاح بعد صعود الركاب الجالسين","مدى قِصر الرحلة وما إذا كانت ظروف الطريق والطقس مواتية","تقديري الشخصي كسائق لعدد الركاب الذين ما زالوا يشعرون بالراحة"],"explanation":"يحدّد الحد الأقصى لعدد الركاب تصميمُ الحافلة وتصنيف المصنّع لها، ولا يجوز للسائق تجاوزه."},"94":{"q":"أنا أُصعِد الركاب على حافلة الرحلات المستأجرة لديّ قبل رحلة طويلة. أثناء صعودهم، عليّ أن أقرر ما يمكنني السماح بإدخاله. أيٌّ من هذه الأشياء لا يُسمح لي بنقله على متن الحافلة بينما يكون الركاب على متنها؟","options":["عربة أطفال مطوية مخزّنة بحيث لا تسدّ الممر أو أي مخرج","سلاح ناري مذخّر يحمله راكب في حقيبته الشخصية","حقيبة محمولة صغيرة مؤمَّنة تحت مقعد بعيدًا عن الممر","قارورة ماء شخصية مغلقة يحتفظ بها راكب عند مقعده"],"explanation":"يجب ألّا يُسمح أبدًا بوجود سلاح ناري مذخّر على حافلة تقلّ ركابًا، بغضّ النظر عن صاحب الحقيبة أو طريقة تخزينه."},"95":{"q":"أنا أقود حافلة نقل عام على خط سيري المعتاد. الواقفون متجمّعون نحو المقدمة، وبينما أقترب من منعطف ضيّق في مخرج طريق سريع، أبدأ بالتفكير في سبب احتياج الحافلات إلى حذر إضافي في المنعطفات مقارنةً بالسيارات. أي عبارة تفسّر بأفضل شكل قلق التعامل الذي ينبغي أن أبقيه في ذهني هنا؟","options":["لأن الحافلة ثقيلة، فإن وزنها المنخفض التركيب يجعل من المستحيل تقريبًا أن تنقلب، لذا يمكنني اجتياز المنعطف بسرعتي المعتادة","الركاب الواقفون المتجمعون قرب المقدمة يخفضون نقطة توازن الحافلة، وهو ما يحسّن في الواقع استقرارها خلال المنعطف","تحمل الحافلة جزءًا كبيرًا من وزنها في الأعلى، ما يمنحها مركز ثقل مرتفعًا يرفع خطر الانقلاب في المنعطفات","الانقلاب مصدر قلق فقط للحافلات المحمّلة بالكامل، لذا مع حمولة ركاب خفيفة يمكنني تجاهل السرعة الاسترشادية المحددة للمنعطف"],"explanation":"تحمل الحافلة جزءًا كبيرًا من وزنها في الأعلى، ما يمنحها مركز ثقل مرتفعًا يجعلها أكثر عرضة للانقلاب في المنعطفات."},"96":{"q":"أنا أقود حافلة نقل عام محمّلة بالكامل والطريق أمامي يهبط إلى منحدر طويل وشديد. للحفاظ على السيطرة على الحافلة وتجنّب ارتفاع حرارة مكابحي قبل وصولي إلى الأسفل، ما الذي يجب أن أفعله؟","options":["أضغط على دواسة المكابح بقوة طوال الطريق إلى الأسفل لتقليل السرعة والبقاء بطيئًا","أضغط على القابض وأنزلق في الوضع المحايد حتى لا يقاوم المحرّك سرعتي","أدع الحافلة تكتسب السرعة مبكرًا، ثم أكبح بقوة قرب أسفل التلة","أختار ترسًا منخفضًا قبل المنحدر وأستخدم ضغطات مكابح خفيفة متقطعة"],"explanation":"اختر ترسًا منخفضًا قبل بدء النزول على منحدر طويل وشديد واستخدم كبحًا خفيفًا متقطعًا لمنع ارتفاع حرارة المكابح."},"97":{"q":"أنا سائق حافلة نقل عام جديد أُجري فحص ما قبل الرحلة قبل صعود الركاب. إلى جانب الإطارات والمكابح والأضواء، أي مجموعة من العناصر المتعلقة بالركاب يجب أن أتأكد من أنها تعمل وخالية قبل أن أنطلق؟","options":["مخارج الطوارئ وأضواء مخارجها، وآلية إشارة التوقف/الباب، وممر خالٍ مع عدم انسداد أي مخرج بالأمتعة","فقط مخارج الطوارئ وأضواء المخارج، لأن إشارة التوقف يمكن أن يختبرها الركاب بمجرد أن نتحرك","فقط إشارة التوقف وآلية الباب، لأن المخارج يفحصها ورشة الصيانة وليس السائق","فقط أن الممر خالٍ، لأن المخارج وأجهزة الإشارة تُفحص في محطة الفحص السابقة"],"explanation":"يجب أن يؤكد فحص ما قبل الرحلة للحافلة سلامة مخارج الطوارئ وأضواء المخارج، وآلية إشارة التوقف/الباب، وأن الممر وجميع المخارج خالية من الأمتعة."},"98":{"q":"أنا أنطلق من المحطة متأخرًا 20 دقيقة عن الجدول، والحافلة مكتظة إلى أقصى سعتها، ومطر بارد ينهمر بغزارة. في أيٍّ من هذه الظروف يكون لي مبرّر لتخطّي إحاطة سلامة الركاب قبل الانطلاق؟","options":["عندما أكون متأخرًا جدًا بحيث إن أي تأخير سيجعل كل راكب يفوّت موعد ربط رحلته","في أيٍّ من هذه الظروف — يجب تقديم إحاطة السلامة في كل رحلة","عندما تكون الحافلة محمّلة إلى أقصى سعتها ولا يوجد وقت لمخاطبة حشد","عندما يجعل طقس مثل المطر الغزير الظروف في الخارج غير آمنة للتأخير"],"explanation":"يجب تقديم إحاطة سلامة الركاب في كل رحلة، ولا يوجد أي ظرف تشغيلي يبرّر تخطّيها."},"99":{"q":"تفقد حافلتك القدرة وتتوقف متدحرجةً على كتف طريق ريفي سريع ذي مسارين. لديك حمولة كاملة من الركاب وحركة المرور تمر بسرعة الطريق السريع. ما أفضل طريقة للتعامل مع هذا الموقف؟","options":["اطلب من الجميع النزول والانتظار على حافة الطريق بينما توقف مركبة عابرة لطلب المساعدة","أبقِ جميع الركاب جالسين في الداخل دون وضع أي علامات، لأن الكتف هو المكان الأكثر أمانًا للانتظار","حافظ على سلامة الركاب وضع أجهزة التحذير من الطوارئ لتنبيه حركة المرور المقتربة","اترك الركاب على متن الحافلة، أقفلها، وامشِ إلى الأمام نحو أقرب مخرج للاتصال بشاحنة سحب"],"explanation":"حافظ على سلامة الركاب وضع أجهزة التحذير من الطوارئ حتى يتم تنبيه حركة المرور المقتربة إلى الحافلة المتوقفة."},"100":{"q":"أنا أُنهي فحص ما قبل الرحلة على حافلتي السياحية قبل رحلة مستأجرة عندما يسألني راكب لماذا أمضي كل هذا الوقت في مؤخرة الحافلة أفحص النوافذ والباب الخلفي. فيما يتعلق بمخارج الطوارئ، أيٌّ مما يلي يصف الحالة التي يجب أن تكون عليها قبل أن أنطلق من المحطة؟","options":["يجب أن يكون كل مخرج طوارئ مُحكم الإغلاق ومُغلقًا بإحكام حتى لا يدخل الريح والمطر أثناء سير الحافلة بسرعة الطريق السريع","لا حاجة لأن تكون مخارج الطوارئ صالحة للتشغيل إلا إذا كانت الحافلة تقلّ واقفين يركبون خلف الخط الأبيض","يكفي أن تُضيء أضواء تحذير المخارج، لأن الأضواء تؤكد أن المخارج ستنفتح عند التصادم","يجب أن ينفتح كل مخرج طوارئ ويعمل بشكل صحيح، ويجب أن يكون الممر وجميع المخارج خالية من الأمتعة التي قد تسدّها"],"explanation":"يجب أن ينفتح كل مخرج طوارئ ويعمل بشكل صحيح، ويجب إبقاء الممر وجميع المخارج خالية من أي أمتعة قد تسدّها."},"101":{"q":"حافلتي الحضرية ممتلئة وعدة ركاب يقفون في الممر بينما أنطلق من المحطة. للحفاظ على سلامة الجميع والالتزام بقواعد إدارة السلامة العامة (DPS)، أين يجب أن يتمركز هؤلاء الركاب الواقفون بالنسبة لخط الوقوف المرسوم على الأرضية؟","options":["خلف خط الوقوف، بحيث لا يقف أحد أمامه أو يحجب رؤيتي للأمام","في أي مكان في الممر، طالما أمسكوا بإحكام بمقبض أو مقعد","أمام خط الوقوف، حيث يمكنني مراقبتهم عن قرب أثناء القيادة","حيثما يتسعون، لأن الخط يحدد فقط مكان تكديس الأمتعة المحمولة"],"explanation":"يجب أن يبقى الواقفون خلف خط الوقوف بحيث لا يقف أحد أمامه ويحجب رؤيتك للأمام."},"102":{"q":"حافلة النقل الحضري لديك ممتلئة في ساعة الذروة وعدة ركاب يقفون في الممر. للحفاظ على سلامة الجميع والالتزام بالقانون، ما هو المكان الوحيد الذي يجب أن تتأكد من ألا يتقدم أمامه أي راكب واقف؟","options":["باب الخروج الخلفي، حتى يتمكن من الفتح بحرية في كل محطة","خط الوقوف الأبيض المرسوم على الأرضية بالقرب من المقدمة","الصف الأخير من المقاعد المواجهة للأمام في الخلف","أقرب نافذة من جهة الركاب يمكن فتحها للتهوية"],"explanation":"خط الوقوف الأبيض على الأرضية بالقرب من المقدمة يحدد الحد الذي يجب ألا يتجاوزه الركاب الواقفون أبدًا."},"103":{"q":"أثناء فحصك قبل الرحلة، تسألك راكبة منتظمة إن كان بإمكانها وضع حقيبتها الكبيرة ذات العجلات بجوار باب الخروج الطارئ الخلفي مباشرة، واعدةً بأنها ستبقيها 'بعيدة تمامًا عن الطريق' حتى محطتها. بموجب قواعد مركبات الركاب في تكساس، ما هو السبب الرئيسي الذي يلزمك برفض ذلك وجعلها تضعها في مكان آخر؟","options":["قد تنزلق حقيبة متروكة بالقرب من المخرج إلى الأمام وتخدش المقاعد، مما يترك الداخل يبدو غير مرتب للمجموعة التالية من الركاب","تتطلب قواعد تكساس وسم ووزن جميع الأمتعة المحمولة، ولا يمكن احتساب حقيبة غير موزونة بالقرب من الباب في سجل الرحلة","يجب تأمين الأمتعة المحمولة بحيث لا تسد الممر أو أي مخرج طارئ ولا تسقط على أحد أثناء الرحلة","تميل الأمتعة المتروكة بجوار الباب إلى تجميع الغبار والرطوبة، مما قد يتلف الحقيبة قبل أن تصل إلى محطتها"],"explanation":"يجب تأمين الأمتعة المحمولة بحيث لا تسد الممر أو أي مخرج طارئ ولا تسقط على أحد أثناء الرحلة."},"104":{"q":"أقود حافلة نقل محملة وأقترب من معبر سكة حديد غير معفى. لا يوجد رجل إشارة ولا إشارة خضراء، لذا أعلم أنني يجب أن أتوقف توقفًا تامًا وأنظر وأستمع قبل العبور. للتوقف على المسافة الصحيحة قانونيًا من أقرب قضيب، أين يجب أن أوقف الحافلة؟","options":["ليس أقرب من 100 قدم وليس أبعد من 200 قدم من أقرب قضيب","على بعد 50 قدمًا على الأقل، لكن ليس أقرب من 15 قدمًا من أقرب قضيب","ضمن قدم إلى قدمين من أقرب قضيب حتى أتمكن من الرؤية بوضوح على طول المسار","في مكان ما بين 15 و50 قدمًا من أقرب قضيب"],"explanation":"يجب أن تتوقف الحافلة بين 15 و50 قدمًا من أقرب قضيب عند معبر سكة حديد غير معفى."},"105":{"q":"أنت تقود حافلة نقل محملة وتقترب من معبر سكة حديد لا يوجد به رجل إشارة ولا إشارة ولا ضوء أخضر يأذن لك بالمتابعة. المعبر نشط، وليس معفى. أثناء إبطائك، ما هي الطريقة الصحيحة للتعامل مع هذا المعبر؟","options":["توقف بين 15 و50 قدمًا قبل أقرب قضيب، ثم انظر واستمع بعناية قبل العبور","أبطئ إلى الزحف دون التوقف التام، وانظر في كلا الاتجاهين، واعبر إن بدا المسار خاليًا","توقف بمحاذاة القضيب تمامًا، وانتقل إلى ترس أدنى، وتسارع بقوة طوال الطريق عبر السكة","حافظ على سرعتك ثابتة مباشرة عبر السكة حتى تجتازها بسرعة وتقضي وقتًا أقل على القضبان"],"explanation":"عند معبر سكة حديد نشط وغير معفى، توقف بين 15 و50 قدمًا قبل أقرب قضيب، ثم انظر واستمع قبل العبور."},"106":{"q":"يجب ألا تغير التروس أثناء العبور فوق:","options":["طريق مستوٍ","سكة حديد","جسر طويل","منحدر دخول"],"explanation":"لا تغير التروس فوق سكك الحديد."},"107":{"q":"أقود حافلة مساري نحو جسر متحرك فوق قناة ملاحية. لا توجد إشارة مرور عند الجسر، ولا إعفاء معلن، ولا موظف يلوح لي بالمرور. حركة المرور أمامي تسير بشكل طبيعي وسيارة أمامي مباشرة تعبر دون أن تبطئ. ماذا يُطلب مني أن أفعل؟","options":["أتبع تدفق حركة المرور وأعبر دون توقف، لأن السيارة أمامي عبرت ولم يخبرني شيء بالتوقف","أتوقف على بعد 50 قدمًا على الأقل قبل فتحة الجسر، لأنه لا يوجد ضوء أخضر أو موظف يشير إلى أن العبور آمن","أبطئ حتى أقترب من التوقف وأعبر فقط إن لم أرَ قوارب في القناة، لأن التوقف التام غير مطلوب","أتوقف بين 15 و50 قدمًا قبل الجسر، وأنظر وأستمع، ولا أغير التروس أبدًا أثناء العبور"],"explanation":"يجب أن تتوقف الحافلة على بعد 50 قدمًا على الأقل قبل الجسر المتحرك ما لم يشر ضوء أخضر أو موظف إلى أن العبور آمن."},"108":{"q":"أنا متوقف عند محطة نقل لإنزال الركاب. أحرر مكبح الانتظار وأضغط على دواسة الوقود، لكن حافلتي ترفض التحرك للأمام رغم أن المحرك يعمل بشكل جيد ولا شيء يعيق العجلات. قبل أن أتصل بميكانيكي، ما هي الحالة الأكثر احتمالًا التي تجعل قفل التعشيق بين المكبح والباب يبقي حافلتي في مكانها؟","options":["لا يزال حبل إشارة توقف الراكب مسحوبًا ومضاءً من طلب الراكب الأخير","لم يتحرر مكبح الانتظار بالكامل ولا يزال مشتبكًا جزئيًا","لا تزال أبواب الركاب الخلفية مفتوحة بعد الإنزال","تحرك الواقفون أمام خط الوقوف الأبيض بالقرب من المقدمة"],"explanation":"يمنع قفل التعشيق بين المكبح والباب الحافلة من التحرك كلما كان باب ركاب لا يزال مفتوحًا."},"109":{"q":"أنا أُصعّد الركاب على حافلتي المستأجرة ورف الأمتعة ممتلئ، فتسألني راكبة أين يمكنها وضع حقيبتها الرياضية للرحلة. للبقاء ملتزمًا أثناء فحصي قبل الرحلة وخلالها، أي وضعية يجب أن أرفض السماح بها لأنها محظورة؟","options":["وضعها تحت مقعدها بحيث تبقى بعيدة تمامًا عن الممشى","على حِجرها طالما أبقت كلتا يديها عليها طوال الرحلة","ضغطها على نافذة جانبية بحيث تضغط على الزجاج","وضعها في الممر بجوار قدميها، حتى لو كان جزئيًا فوق الممشى"],"explanation":"الأمتعة الموضوعة في الممر، حتى جزئيًا، محظورة لأنها تعيق الممشى الذي يحتاجه الركاب للوصول إلى المخارج في حالة الطوارئ."},"110":{"q":"أنا أُصعّد الركاب على حافلتي المستأجرة عندما يطلب راكب إحضار عدة أغراض على متنها. بموجب قواعد تكساس للمواد الخطرة على حافلة الركاب، أي غرض يجب أن أرفض تحميله؟","options":["حاوية غاز سام مصنفة من الفئة 2.3، وهي غير مسموح بها على الحافلة أبدًا","طرد صغير مغلق من مواد خطرة مسموح بها يزن حوالي 40 رطلًا، مخزن بعيدًا عن الركاب","أكسجين طبي شخصي لراكب يبقيه معه طوال الرحلة","بضع علب من مواد مسموح بها يقل مجموعها عن 100 رطل من تلك الفئة الواحدة"],"explanation":"غاز الفئة 2.3 السام ممنوع منعًا باتًا على الحافلة، لذا يجب ألا يُحمّل أبدًا بغض النظر عن الكمية."},"111":{"q":"أنت تقود حافلة نقل على مسارك المعتاد مع عدة واقفين يمسكون بقضبان الإمساك خلف خط الوقوف. أمامك، ينحني مسارك إلى منعطف حاد نحو اليمين. مقارنةً بكيفية تعاملك مع نفس المنعطف في حافلة فارغة، كيف ينبغي أن تأخذه الآن بوجود الركاب على متنها؟","options":["بنفس السرعة التي تستخدمها وهي فارغة، ثم تكبح بقوة عند ذروة المنعطف لإبقاء الحافلة ملتصقة بمسارها","أبطأ مما تفعل في حافلة فارغة، حتى لا تُفقد القوة الجانبية ركابك الواقفين توازنهم","أسرع عند الدخول، مستخدمًا زخم الحافلة لحملها بسلاسة عبر المنعطف وخارجه","بنفس السرعة، لكن مع الانتقال إلى الوضع المحايد عبر المنعطف حتى تتمكن عجلات الدفع من الانزلاق بحرية"],"explanation":"خذ المنعطفات أبطأ مما في حافلة فارغة حتى لا تُفقد القوة الجانبية الركاب الواقفين توازنهم."},"112":{"q":"أقود حافلة نقل ذات مسار ثابت خلال وردية مزدحمة بعد الظهر، ونقترب من المحطة المجدولة التالية حيث أرى عدة أشخاص جالسين بالقرب من الأبواب الخلفية. وفقًا لقواعد الركاب في رخصة القيادة التجارية بتكساس، ما هو السبب الرئيسي الذي يجعلني أعلن بوضوح عن هذه المحطة القادمة؟","options":["حتى أتمكن قانونيًا من تحصيل أجرة إضافية من كل راكب يصعد عند تلك المحطة","حتى يُطلب من الركاب الواقفين التحرك فورًا أمام خط الوقوف","حتى يكون لدى الركاب وقت لجمع أمتعتهم والاستعداد للنزول بأمان","حتى يعرف الركاب أنه يُسمح لهم بفتح النوافذ وإنزال الأبواب الخلفية"],"explanation":"أعلن عن المحطات مبكرًا حتى يكون لدى الركاب وقت لجمع أمتعتهم والاستعداد للنزول بأمان."},"113":{"q":"أنت تشغّل حافلة نقل حضري وتتوقف عند محطة مزدحمة في وسط المدينة حيث ينتظر حشد للصعود. بينما يبدأ الناس بالصعود، ما الذي يجب أن تراقبه بنشاط أيضًا عند نفس المحطة، وفقًا لإجراء إدارة السلامة العامة (DPS)؟","options":["الركاب المتجهون نحو المقدمة بحيث يقفون أمام خط الوقوف لرؤية أفضل","الركاب الصاعدون الذين يدفعون الأجرة بالضبط قبل أن يُسمح لأي راكب آخر بالصعود","الركاب الذين يجرون الأمتعة المحمولة إلى الممر حتى يتم الوصول إلى المحطة التالية أسرع","الركاب الذين يحاولون النزول من الحافلة عند نفس المحطة بينما يصعد آخرون"],"explanation":"عند محطة مزدحمة، راقب الركاب النازلين في نفس الوقت الذي يصعد فيه آخرون لمنع التصادمات والسقوط."},"114":{"q":"أنت تقود حافلة نقل محملة عندما يصبح أحد الركاب صاخبًا ومهددًا ويرفض الهدوء. تقرر أنه يجب على الراكب مغادرة الحافلة. وفقًا لقواعد إدارة السلامة العامة في تكساس (DPS)، أين يجب أن تنزل هذا الراكب المشاغب؟","options":["عند محطة عادية أو مكان آخر آمن وجيد الإضاءة حيث لا يتعرض الراكب للخطر","عند أقرب نقطة في أسرع وقت ممكن، حتى لو كان على جسر أو في نفق","على الكتف الأيمن للطريق السريع، لأن ذلك يبعد الإزعاج عن الحافلة بأسرع ما يمكن","في أي مكان يمكنك التوقف فيه، لأن إخراج راكب مهدد يفوق دائمًا أهمية مكان إنزاله"],"explanation":"أنزل الراكب المشاغب فقط عند محطة عادية أو مكان آخر آمن وجيد الإضاءة حيث لا يتعرض للخطر."},"115":{"q":"حافلتي السياحية المستأجرة على وشك نفاد الوقود بالقرب من نهاية المسار، ومعظم ركابي لا يزالون جالسين ولا يريدون النزول لتعبئة سريعة. أدخل لإعادة التزود بالوقود دون إنزالهم. بموجب قواعد الركاب في تكساس، المكان الوحيد الذي يجب ألا أتزود فيه بالوقود أبدًا بينما يبقى هؤلاء الركاب على المتن هو:","options":["جزيرة مضخة في الهواء الطلق حيث يراقب الموظفون الفوهة","مبنى مغلق محصور حيث تتم التعبئة في الداخل","موقف جانبي على الطريق مع تفعيل مكبح الانتظار ومرور حركة المرور","ممر وقود واسع في محطة شاحنات مع خلوص على كلا الجانبين"],"explanation":"لا تتزود بالوقود في حافلة بها ركاب على المتن داخل مبنى مغلق أو محصور أبدًا، لأن أبخرة الوقود المحتبسة تشكل خطر حريق وانفجار."},"116":{"q":"أقود حافلة سياحية مستأجرة على مسار طويل، وعند محطة وسطية يصعد راكب وهو يحمل سيجارة مشتعلة. يقول إنه سيبقي نافذته مفتوحة قليلًا ويجلس بالقرب من الخلف حتى لا يزعج الدخان أحدًا. بصفتي السائق، ما هي الطريقة الصحيحة للتعامل مع هذا الأمر بمجرد عودة الحافلة إلى الطريق؟","options":["السماح به فقط إن بقي جالسًا خلف خط الوقوف وأبقى نافذته مفتوحة طوال الوقت","السماح به لفترة وجيزة حتى محطة الاستراحة التالية، ثم أطلب من جميع المدخنين إنهاء سجائرهم بالخارج","عدم السماح به على الإطلاق، لأن على السائق إنفاذ قاعدة منع التدخين طوال الرحلة","السماح به طالما اعترض أقل من 100 راكب ولا توجد مواد خطرة على المتن"],"explanation":"التدخين غير مسموح به على الحافلة وعلى السائق إنفاذ قاعدة منع التدخين طوال الرحلة، دون استثناءات."},"117":{"q":"أُجري فحصي قبل الرحلة على حافلة نقل قبل مساري الصباحي. أثناء فحص مقدمة الحافلة، أركّز على قضبان الإمساك ودرجات الدخول، متأكدًا من أنها صلبة ونظيفة وغير مفككة. لماذا يُعد هذا الجزء من الفحص بالغ الأهمية لسلامة الركاب؟","options":["لأن الركاب يتكئون على قضبان الإمساك لتثبيت أنفسهم أثناء الوقوف أمام خط الوقوف خلال الرحلة","لأن الدرجات تعمل كمخارج طوارئ يستخدمها الركاب لإخلاء الحافلة عندما تتعطل الأبواب العادية","لأن الأمتعة المحمولة تُكدَّس على الدرجات وقضبان الإمساك تمنع تلك الأمتعة من الانزلاق إلى الممر","لأن الركاب يمسكون بقضبان الإمساك ويستخدمون الدرجات للصعود بأمان، لذا فإن المفككة أو التالفة منها قد تسبب السقوط"],"explanation":"افحص قضبان الإمساك والدرجات لأن الركاب يمسكونها ويستخدمونها للصعود والنزول، لذا فإن المفككة أو التالفة منها قد تسبب السقوط."},"118":{"q":"حافلة النقل لدي مكتظة في ساعة الذروة وعدة ركاب تقدموا، واقفين أمام خط الوقوف الأبيض بالقرب من المقدمة. لماذا تطالبني إدارة السلامة العامة في تكساس (DPS) بإبقاء هؤلاء الركاب خلف ذلك الخط قبل أن أنطلق من المحطة؟","options":["الواقفون أمام الخط يعيقون رؤيتي للأمام ويسدون المدخل الأمامي","الواقفون أمام الخط يتداخلون مع مستوى صوت الراديو ومكبر صوت النداء العام","الواقفون أمام الخط يضعون وزنًا إضافيًا فوق محور التوجيه وخزان الوقود","الواقفون أمام الخط يصعّبون قراءة مقياس الوقود في لوحة القيادة"],"explanation":"يحدد خط الوقوف المكان الذي يحجب فيه الركاب الواقفون أمامه رؤية السائق للأمام ويعيقون المدخل الأمامي."},"119":{"q":"أثناء فحصي قبل الرحلة على حافلة سعة 47 راكبًا، يطلب راكب ترك حقيبته الرياضية كبيرة الحجم على الأرض بجوار مقعده لأن الرف العلوي ممتلئ. ستبرز الحقيبة حوالي قدم واحدة داخل الممر المركزي. للبقاء ملتزمًا بقواعد سلامة الركاب في تكساس، ماذا يجب أن أفعل قبل أن أبدأ القيادة؟","options":["السماح بها على الأرض لأن الرف العلوي ممتلئ، طالما أبقى يده على الحزام أثناء تحركنا","رفض السماح بها هناك وأطالب بتأمين الحقيبة بحيث لا تسد الممر أو أي مخرج","السماح بها، ولكن فقط بعد نقل الحقيبة خلف خط الوقوف بحيث تبقى بعيدة عن رؤيتي","السماح بها على الأرض طالما لا يوجد ركاب واقفون على المتن في هذه الرحلة"],"explanation":"يجب أن يبقى الممر وجميع المخارج خالية، لذا يجب تأمين الأمتعة المحمولة في مكان لا تسد فيه الممر أو أي مخرج."},"120":{"q":"أثناء فحصي قبل الرحلة لحافلة نقل، ألاحظ أن إحدى فتحات السقف للخروج الطارئ قد ثُبتت بالبراغي على يد ميكانيكي سابق، وأن ذراع تحرير نافذة الخروج الطارئ الجانبية يبدو عالقًا. وفقًا لمعايير إدارة السلامة العامة في تكساس (DPS)، ما الذي يجب أن أتأكد منه بشأن مخارج الطوارئ هذه قبل أن أقبل الحافلة للخدمة؟","options":["طالما تفتح وتغلق أبواب الركاب العادية، فإن فتحات السقف المغلقة والنوافذ العالقة مقبولة للرحلة","لا حاجة لأن تكون مخارج الطوارئ عاملة إلا إذا توقعت حمل واقفين خلف الخط الأبيض في ذلك اليوم","يجب أن تعمل كل نافذة خروج طارئ وفتحة سقف بشكل صحيح وأن تكون قابلة للتشغيل بالكامل قبل دخول الحافلة الخدمة","لا بأس بترك المخارج مغلقة طالما أعلّمها بوضوح ويبقى الممر خاليًا من الأمتعة"],"explanation":"يجب أن تعمل نوافذ الخروج الطارئ وفتحات السقف بشكل صحيح وأن تكون قابلة للتشغيل بالكامل حتى يتمكن الركاب من الهروب في حالة حريق أو انقلاب أو انسداد الأبواب."},"121":{"q":"أُجري فحصي قبل الرحلة على حافلة نقل سعة 47 راكبًا قبل مساري الصباحي. أثناء سيري في الداخل، أريد التأكد من أن المقاعد تستوفي متطلبات إدارة السلامة العامة (DPS) قبل أن أسمح لأي شخص بالصعود. أي حالة تصف كيف ينبغي أن تكون مقاعد الركاب؟","options":["يمكن طي بعض المقاعد للخلف وإخفاؤها لتوسيع الممر المركزي للصعود","المقاعد المفككة مقبولة طالما لا تزال مخارج الطوارئ وأضواء المخارج تعمل","المقاعد التي تسد مخرجًا خلفيًا لا بأس بها إن أبقيت الواقفين خلف الخط الأبيض","كل مقعد ركاب مثبت بإحكام وغير تالف ومُؤمَّن في مكانه قبل الصعود"],"explanation":"يجب أن تكون مقاعد الركاب مثبتة بإحكام وغير تالفة ومثبتة بقوة في مكانها حتى لا يُقذف الركاب أو يُصابوا أثناء الكبح أو الاصطدام."},"122":{"q":"أقود مجموعة مستأجرة عبر تكساس عندما يبدأ بعض الركاب المرحين بالميل نحو مقعدي، يمزحون ويحاولون محادثتي حول المسار بينما الحافلة تسير على الطريق السريع. للبقاء ضمن قواعد التشغيل الآمن، أي استجابة هي الصحيحة؟","options":["أبقي عينيّ للأمام بأدب وأمتنع عن المحادثة، لأنه يجب ألا أدع الركاب يصرفون انتباهي عن القيادة أثناء تحرك الحافلة","الانخراط في المحادثة طالما بقيت المجموعة جالسة وأبقت أحزمة المقاعد مربوطة","السماح بالدردشة لأن التفاعل الودي يبقي ركاب الرحلات المستأجرة هادئين وجالسين","السماح لهم بالوقوف بالقرب من مقعدي حتى أتمكن من سماعهم بشكل أفضل فوق ضوضاء الطريق"],"explanation":"يجب ألا يدع السائق الركاب يصرفون انتباهه عن القيادة أثناء تحرك الحافلة، لأن التشتيت يشكل خطرًا."},"123":{"q":"أنا متأخر عن الجدول على مسار حافلتي الحضرية، وتطلب مني راكبة بالقرب من الخلف إنزالها هنا، قبل المحطة المحددة التالية بكثير، لأنها أقرب إلى عملها. حركة المرور خفيفة ويمكنني التوقف بسهولة. بموجب قواعد إدارة السلامة العامة في تكساس (DPS)، أين يُسمح لي بإنزال هذه الراكبة؟","options":["حيثما يطلب الراكب، طالما كانت حركة المرور خفيفة بما يكفي للتوقف","فقط عند المحطة المناسبة أو مكان آخر آمن مناسب للإنزال","في أي مكان على كتف الطريق السريع، لأن الحافلة خارج مسار السير","عند أي نقطة مناسبة للراكب، بما في ذلك في منتصف المنعطف"],"explanation":"لا يجوز إنزال الركاب إلا عند المحطة المخصصة المناسبة أو مكان آخر يرى السائق أنه آمن للإنزال."},"124":{"q":"حصلت للتو على رخصة القيادة التجارية من الفئة B وتعرض عليّ شركة رحلات مستأجرة عدة مسارات. تتيح لي رخصتي بالفعل قيادة هذه المركبات الكبيرة، لكن مسؤول التوظيف يحذرني من أن واحدة فقط من هذه المهام تتطلب قانونيًا تصديق P قبل أن أتمكن من قبولها. أي مهمة تجبرني على إضافة تصديق P؟","options":["نقل حمولة من الحصى المسحوق في شاحنة قلابة ذات محورين مزدوجين","توصيل الوقود في شاحنة صهريج مستقيمة بدون لوحات تحذير تحت الحد","قيادة حافلة مكوكية سعة 35 راكبًا تنقل الركاب من وإلى المطار","سحب مقطورة مسطحة فارغة إلى ساحة الشركة للتخزين"],"explanation":"تصديق P مطلوب لقيادة أي مركبة مصممة لنقل الركاب، مثل الحافلة."},"125":{"q":"أشغّل حافلة نقل سعة 47 راكبًا على مسار مزدحم في وسط المدينة، وألاحظ أن مرآتي الجانبية اليمنى مائلة منخفضة جدًا بحيث لا أرى الرصيف الذي يصعد منه الركاب. الركاب جالسون بالفعل وأنا أسير نحو محطتي المجدولة التالية. وفقًا لإجراء إدارة السلامة العامة في تكساس (DPS)، متى كان يجب أن أكون قد ضبطت ووجّهت جميع مراياي بشكل صحيح؟","options":["عند أول إشارة حمراء، حتى أتمكن من الوصول إليها بأمان بينما تكون الحافلة متوقفة في حركة المرور","فقط بعد انطلاقي من المحطة، عندما أتمكن من تقدير المرآة مقابل حركة المرور المتحركة","عند سرعة الطريق السريع، حيث تتيح لي الرؤية الأوسع ضبط كل مرآة بدقة أكبر","قبل بدء الرحلة، كجزء من الفحص قبل الرحلة وقبل صعود أي ركاب"],"explanation":"يجب ضبط المرايا قبل الرحلة كجزء من الفحص قبل الرحلة وقبل صعود أي ركاب."},"126":{"q":"أقود رحلة مستأجَرة وتنتظر مجموعة كبيرة الصعود إلى الحافلة. جميع المقاعد ممتلئة بالفعل، والحشد في الخارج يتدافع للصعود قبل أن ننطلق. بصفتي السائق، ما هو الحد الصحيح لعدد الأشخاص الذين يمكنني نقلهم في هذه الحافلة؟","options":["يجب ألا أحمّل الحافلة بما يتجاوز سعتها الآمنة والقانونية للجلوس والوقوف","يمكنني إضافة واقفين أمام خط الوقوف ما داموا يمسكون بقضبان الإمساك","يمكنني نقل أي عدد يتسع له المكان ما دام الممر والمخارج تبقى قابلة للاستخدام جزئيًا","يمكنني تجاوز السعة المقررة لفترة وجيزة لأنها رحلة مستأجَرة قصيرة"],"explanation":"يجب ألا تُحمَّل الحافلة أبدًا بما يتجاوز سعتها الآمنة والقانونية للجلوس والوقوف، بصرف النظر عن ضغط الحشد."},"127":{"q":"أثناء فحصي قبل الرحلة على حافلة نقل عام، ألاحظ أن مصعد الكراسي المتحركة عالق ولا يمتد، لكن مساري لا يضم أي ركاب مجدولين يستخدمونه اليوم. وفقًا لقواعد إدارة السلامة العامة في تكساس، ماذا يجب أن أفعل قبل إدخال هذه الحافلة في الخدمة؟","options":["يمكنني قيادة المسار ما دام لا يوجد ركاب على كراسي متحركة مجدولون للصعود اليوم","يجب أن أخرج الحافلة من الخدمة حتى يتم فحص مصعد الكراسي المتحركة والتأكد من أنه يعمل","يمكنني تشغيل الحافلة وأكتفي بتدوين عطل المصعد لورشة الصيانة لإصلاحه لاحقًا","يمكنني تسيير المسار إذا ثبّتُّ المصعد في وضع الطي بحيث لا يتحرك أثناء القيادة"],"explanation":"يجب أن تكون معدات السلامة الأساسية مثل مصعد الكراسي المتحركة صالحة للعمل قبل دخول الحافلة الخدمة، لذا فإن مصعدًا معطلًا يُخرج الحافلة من الخدمة حتى يُصلَح."},"128":{"q":"أُصعِد راكبًا يستخدم كرسيًا متحركًا إلى حافلة النقل العام عند موقف على حافة الرصيف. بعد أن أدفع الكرسي صعودًا على المصعد وإلى منطقة التثبيت، يتصل بي المُرسِل لاسلكيًا قائلًا إنني متأخر وعليّ الانطلاق بسرعة. قبل أن أحرر مكابح الانتظار وأحرّك الحافلة، ماذا يجب أن أفعل؟","options":["أنطلق بلطف وأترك الراكب يمسك بقضبان الإمساك حتى أبلغ سرعة الانطلاق، ثم أثبّت الكرسي","أترك الكرسي المتحرك حرًا ليتحرك بشكل طبيعي ويمتص المطبات أثناء الكبح والمنعطفات","أثبّت الكرسي المتحرك تمامًا في منطقة التثبيت قبل أن أحرر المكابح وأحرّك الحافلة","أطوي الكرسي المتحرك مسطحًا وأكدّسه مع بقية الأمتعة المحمولة قرب المخرج الخلفي"],"explanation":"يجب تثبيت الكرسي المتحرك تمامًا في منطقة التثبيت قبل تحرير المكابح والتحرك، لأن الكرسي غير المثبت قد ينزلق أو ينقلب ويصيب الراكب."},"129":{"q":"أوقف حافلتي عند محطة وينتظر للصعود راكب يستخدم مشّاية، لكنه يتحرك ببطء ويبدو غير متزن عند الدرجات. بصفتي السائق، ما هو التصرف الصحيح تجاه هذا الراكب ذي الإعاقة؟","options":["أُخبر الراكب أن ينتظر في الخارج الحافلة التالية كي لا يتأخر الجدول","أَسمح للراكب بالصعود لكنني أتقاضى أجرة أعلى لأن الصعود يستغرق وقتًا إضافيًا","أَسمح للراكب بالصعود لكنني أُلزمه بالجلوس في المقاعد الخلفية بعيدًا عن الآخرين","أُساعد الراكب كي يتمكن من الصعود والنزول من الحافلة بأمان وأمان تام"],"explanation":"يجب على السائقين مساعدة الركاب ذوي الإعاقة كي يتمكنوا من الصعود والنزول من الحافلة بأمان."},"130":{"q":"أقود حافلة نقل عام في المدينة خلال صباح مزدحم. صعد للتو عدة ركاب، وبعضهم لا يزال يسير نحو المقاعد الشاغرة، واثنان منهم يمدّان أيديهما نحو قضبان الإمساك العلوية قرب خط الوقوف. قبل أن أحرر مكابح الانتظار وأنطلق من حافة الرصيف، ما القاعدة التي يجب أن أتبعها بشأن ركابي؟","options":["يجب أن يكون جميع الركاب جالسين أو واقفين بأمان خلف خط الوقوف قبل أن أبدأ بتحريك الحافلة","يجب أن يكون جميع الركاب جالسين أو واقفين بأمان خلف خط الوقوف قبل أن أتوقف توقفًا تامًا عند المحطة التالية","يجب أن يكون جميع الركاب جالسين أو واقفين بأمان خلف خط الوقوف قبل أن أفتح الأبواب للسماح لهم بالصعود","يجب أن يكون جميع الركاب جالسين أو واقفين بأمان خلف خط الوقوف قبل أن أطفئ المحرك في نهاية المسار"],"explanation":"قبل التحرك، تأكد من أن كل راكب جالس أو واقف بأمان خلف خط الوقوف، لأن الانطلاق أو التوقف المفاجئ قد يفقد الركاب غير المستقرين توازنهم."},"131":{"q":"أُشغّل حافلة نقل عام وقد انتهيت من تحميل الركاب عند موقف مزدحم في وسط المدينة. لا يزال عدة ركاب يستقرون، وأحدهم يضع الأجرة في الصندوق، وآخر يمد يده نحو الرصيف. قبل أن أُفعّل أداة إغلاق الباب وأنطلق، ما الشيء الوحيد الذي يجب أن أتأكد منه؟","options":["أن كل راكب واقف قد انتقل بالفعل خلف خط الوقوف","ألا يكون أي راكب عالقًا بين لوحَي الباب أثناء إغلاقه","أن الراكب الذي يضع الأجرة في الصندوق قد أنهى الدفع","أن جميع الركاب الجالسين متجهون للأمام وينظرون من النوافذ"],"explanation":"قبل إغلاق الأبواب، تأكد من ألا يكون أي راكب عالقًا بين لوحَي الباب، لأن الشخص العالق قد يُسحَب أو يُجرّ تحت الحافلة."},"132":{"q":"انتهيت للتو من تحميل الركاب عند موقف وسيط في شارع مزدحم بالمدينة. مكابح الانتظار مفعّلة، وبابك مغلق، وأنت مستعد للاندماج مجددًا في مسار حركة المرور. قبل أن تحرر المكابح وتتسارع مبتعدًا عن الرصيف، أي إجراء هو الأهم لحماية ركابك ومستخدمي الطريق الآخرين؟","options":["تشغيل الراديو الداخلي والإعلان عن المحطة التالية كي يعرف الركاب الواقفون أن يتمسكوا","النظر إلى ساعتك للتأكد من أنك لا تزال ملتزمًا بالجدول المعلن","فحص مراياك لمسح حركة المرور وراكبي الدراجات والمشاة المقتربين من النقاط العمياء","إخبار الواقفين خلف الخط الأبيض بالجلوس قبل أن تبدأ بتحريك الحافلة"],"explanation":"قبل الانطلاق من الموقف، افحص مراياك لمسح مسارات المرور والنقاط العمياء بحثًا عن المركبات وراكبي الدراجات والمشاة المقتربين."},"133":{"q":"أنت توقف حافلة النقل العام عند موقف مجدول على حافة الرصيف في شارع مزدحم. يصطف عدد من الناس بالفعل عند المظلة، وآخرون يسرعون على الرصيف نحو الباب. وأنت توقف الحافلة توقفًا سلسًا وتستعد لفتح الباب، أي مجموعة من الركاب ينبغي أن تكون أكثر انتباهًا لها لتجنب الاصطدام أو الإصابة؟","options":["الركاب الجالسون على متن الحافلة، لأنهم قد يقفون قبل أن تتوقف تمامًا","الركاب الذين لا يزالون ينتظرون بهدوء داخل المظلة ولم يتحركوا بعد نحو الحافلة","الواقفون المتزاحمون أمام خط الوقوف الذين قد يحجبون رؤيتك الأمامية","الركاب المقتربون من الحافلة أو العابرون أمامها أو خلفها للوصول إلى الباب"],"explanation":"عند موقف الحافلة، انتبه للركاب المقتربين أو العابرين أمام الحافلة أو خلفها، لأن الأشخاص المتحركين قد يدخلون مسارك أو إلى حركة المرور."},"134":{"q":"يطلب راكب يصعد إلى حافلتي السياحية إحضار عدة أشياء معه. معظم المواد الخطرة ممنوعة على الحافلة، لكن يُسمح بكميات قليلة محدودة منها. أي صنف يمكنني السماح به قانونيًا على متن الحافلة، ما دام لا يُخزَّن في الحيز الذي يشغله الركاب؟","options":["كمية صغيرة من المستلزمات الطبية الطارئة محفوظة ضمن حدود الوزن المسموح بها","صندوق محكم الإغلاق من ألعاب نارية من الصنف 1.3 لاحتفال عيد","أسطوانة مُحكمة الإغلاق من غاز سام موسومة بالفئة 2.3","حاوية مدرّعة من مادة مشعة لتوصيلها إلى مستشفى"],"explanation":"يمكن للحافلة نقل كميات صغيرة مسموح بها فقط من المواد الخطرة ضمن حدود وزن صارمة، مثل كمية قليلة من المستلزمات الطبية الطارئة."},"135":{"q":"أثناء تحميل حافلتي السياحية، يصعد راكب حاملًا حقيبة كبيرة ويسأل أين يضعها. وفقًا لقواعد إدارة السلامة العامة في تكساس، ماذا ينبغي أن أخبر الراكب بأن يفعل بهذه الأمتعة المحمولة؟","options":["أن يضعها على درجات المدخل لتبقى في متناول يده أثناء الرحلة","أن يمسكها على حِجره أو يخزّنها بحيث لا تسد الممر أو أي مخرج","أن يمدّها مسطحة في الممر بجانب مقعده حيث يمكنني مراقبتها","أن يعلّقها على حبل إشارة التوقف لتبقى بعيدة عن الأرض والمقاعد"],"explanation":"يجب إمساك الأمتعة المحمولة على حِجر الراكب أو تخزينها بحيث لا تسد الممر أو أي مخرج أو تسقط على أحد."},"136":{"q":"تمتلئ حافلتي في المدينة عند موقف مزدحم في وسط المدينة، ولا يجد عدة ركاب صاعدين مقاعد شاغرة. يطلب أحدهم الوقوف على الدرجة السفلية قرب الباب الأمامي ليتمكن من النزول بسرعة، وآخر يريد الاتكاء في مدخل الباب الخلفي، وثالث على استعداد للوقوف في الممر. أي مما يلي يجب ألا أسمح به وأنا أعود إلى حركة المرور؟","options":["واقف يبقى خلف خط الوقوف (الأبيض) في الممر ممسكًا بقضيب إمساك","راكب جالس بشكل طبيعي ومعه حقيبة محمولة مخزّنة بحيث لا تسد الممر أو أي مخرج","راكب يقف على درجات المدخل أو في مدخل الباب لأن المقاعد كلها مشغولة","واقف في الممر لكنه يبقى متراجعًا بحيث لا يحجب رؤيتي للطريق"],"explanation":"يجب عدم السماح للركاب أبدًا بالوقوف على درجات المدخل أو في مدخل الباب، مهما بلغ الازدحام، لأن ذلك خطير ويسد مخرج طوارئ."},"137":{"q":"أقود مساري ويوجهني نظام تحديد المواقع تحت ممر سفلي منخفض لسكة حديد، ثم نحو مطعم وجبات سريعة بنظام الخدمة من السيارة بسقف مظلّل، ومحطة وقود بمظلة علوية. وأنا أقترب من كل منها، ما السبب الرئيسي الذي يجعلني يجب أن أراقب الخلوص العلوي؟","options":["لمنع الإطارات الأمامية من حكّ الرصيف أثناء دخولي ببطء","لمنع المرآة الجانبية من الاصطدام بأعمدة الدعم على الجانبين","لحماية خزان الوقود من الحافة المرتفعة لمنحدر الدخول","لحماية سقف الحافلة من الاصطدام بالهيكل المنخفض الذي فوقها"],"explanation":"يتعلق الخلوص العلوي بالسقف، وهو أعلى نقطة في الحافلة، الذي يصطدم به أولًا أي ممر سفلي أو سقف مظلّل أو مظلة منخفضة."},"138":{"q":"انتهيت للتو من مسار ركابي وأدخلت الحافلة إلى الساحة في نهاية نوبتي. قبل أن أنهي عملي وتُركَن الحافلة لليلة، على ماذا ينبغي أن يركّز فحصي بعد الرحلة؟","options":["السير على طول الحافلة للكشف عن أي أضرار وعن أغراض تركها الركاب","تعبئة خزان الوقود بالكامل بحيث تكون الحافلة ممتلئة وجاهزة للسائق التالي","اختبار البوق للتأكد من أنه عالٍ بما يكفي لمسار صباح الغد","إعادة طلاء أي ألواح مخدوشة لتبدو الحافلة جديدة للنوبة التالية"],"explanation":"الفحص بعد الرحلة يعني السير على طول الحافلة للكشف عن أي أضرار واسترداد الأغراض التي تركها الركاب."},"139":{"q":"أقود حافلة سياحية محمّلة على مساري عندما أقترب من جسر ذي مسارين يعرض لافتة تبيّن حدًا أقصى لوزن الحمولة. حافلتي، مع الركاب والوقود، قريبة من ذلك الرقم. ما الذي يحدد ما إذا كان يمكنني قانونيًا عبور حافلتي هذا الجسر؟","options":["لافتة حد السرعة المعلّقة عند الطرف البعيد للجسر، لأن المهم هو عبور المسافة بسرعة","حد الوزن المعلن على الجسر، الذي يجب ألا تتجاوزه حافلتي المحمّلة بالكامل","ارتفاع الخلوص العلوي المعلن، لأن الحافلة السياحية مرتفعة بما يكفي لتكون معرّضة للخطر","سعة المقاعد المدرجة على حافلتي، لأنها تحدد إجمالي الحمولة على الجسر"],"explanation":"يجب ألا تتجاوز الحافلة أبدًا حد الوزن المعلن على الجسر، لذا فإن العامل الحاسم هو ما إذا كان وزنها الإجمالي المحمّل الفعلي يبقى عند الحد المعلن أو دونه."},"140":{"q":"أُدخل حافلة النقل العام إلى محطة مزدحمة في وسط المدينة حيث ينتظر الركاب قرب الرصيف ولا يزال بعض الواقفين يتحركون نحو المقدمة. وأنا أقترب من منطقة التحميل، كيف ينبغي أن أتحكم في سرعتي؟","options":["أحافظ على سرعتي العادية على الطريق حتى اللحظة الأخيرة، ثم أكبح بقوة لأتوقف تمامًا عند الرصيف","أبقى متحركًا بوتيرة سريعة كالطريق السريع كي لا أعرقل حركة المرور الداخلة إلى المحطة","أبقي سرعتي بطيئة وأنا أقترب من الرصيف والمحطة كي أتوقف بسلاسة وأحمي الأشخاص القريبين من الحافلة","أتسارع لحظيًا لتجاوز التقاطع، ثم أنساب إلى الداخل دون لمس دواسة الوقود أو المكابح"],"explanation":"إبقاء السرعة بطيئة قرب الأرصفة والمحطات يتيح لك التوقف بسلاسة وحماية المشاة والركاب المنتظرين القريبين من الحافلة."},"141":{"q":"أقود حافلة نقل عام في المدينة وأتوقف لإقلال مجموعة صغيرة تضم رجلًا مسنًا يستخدم عصا وأمًّا مع طفلين صغيرين. وهم يصعدون، ما أفضل طريقة لأتعامل معهم بأمان؟","options":["أُشير لهم بالصعود بسرعة كي أبقى ملتزمًا بالجدول، لأن إبقاء الباب مفتوحًا يؤخر الركاب الموجودين بالفعل","أُخبرهم بأن يجدوا مقاعد بسرعة وأكبح كالمعتاد، لأن إبطاء روتيني من أجل بضعة ركاب مجحف بحق الجميع","أعاملهم تمامًا مثل أي راكب آخر، لأن إيلاء عناية خاصة لبعض الركاب ليس جزءًا من عملي","أمنحهم وقتًا إضافيًا للصعود والجلوس، وأنطلق بسلاسة فقط بعد أن يستقروا"],"explanation":"يتحرك الأطفال والمسنون ببطء، لذا امنحهم وقتًا إضافيًا للصعود والجلوس، ثم تسارع بسلاسة لمنع السقوط."},"142":{"q":"أُشغّل حافلة نقل عام مزدحمة في المدينة خلال ساعة الذروة، ويستمر عدة ركاب واقفين في الانجراف نحو المقدمة كلما صعد ركاب أكثر عند كل موقف. للحفاظ على أمان حافلتي وقانونيتها، أين يجب أن أتأكد من ألا يتجمع هؤلاء الواقفون؟","options":["في منطقة السائق أمام خط الوقوف (الأبيض)، حيث قد يحجبون رؤيتي","في الصف الخلفي مباشرة فوق حجرة المحرك","قرب النوافذ الجانبية على جهة الرصيف من الممر","في القسم الأوسط بين البابين الأمامي والخلفي"],"explanation":"يجب أن يبقى الواقفون خلف خط الوقوف (الأبيض) وألا يتزاحموا أبدًا في منطقة السائق، حيث قد يحجبون رؤيتك للطريق والمرايا والباب."},"143":{"q":"أقود مسارًا في المدينة ويمد راكب قرب المقدمة ورقة نقدية فئة 20 دولارًا، طالبًا مني أن أعطيه الباقي بينما نمر عبر إشارة خضراء. بموجب قواعد رخصة القيادة التجارية في تكساس بشأن إبقاء كلتا اليدين متاحتين للقيادة، أي مما يلي ينبغي أن أفعل؟","options":["آخذ الورقة بسرعة بيد واحدة وأقود بالأخرى كي يستمر الصف بالتحرك","أُخبر الراكب أنني سأتعامل مع الأجرة والباقي فقط بعد أن أوقف الحافلة بأمان","أنظر إلى الأسفل لأعدّ الباقي مع إبقاء المقود ثابتًا عبر التقاطع","أطلب من الراكب أن يسلّم النقود لواقف في المقدمة ليعدّها بينما أواصل القيادة"],"explanation":"لا تتعامل أبدًا مع الأجرة أو الباقي بينما الحافلة متحركة؛ انتظر حتى توقف الحافلة بأمان كي تبقى كلتا يديك وانتباهك على القيادة."},"144":{"q":"أُنهي مساري كسائق حافلة سياحية، وبينما أسير في الممر للتحقق من خلوّ المخارج، أجد أن راكبًا قد ترك هاتفًا ذكيًا باهظ الثمن محشورًا في مقعد بعد أن نزل الجميع. لا يوجد أحد حوله ليطالب به. وفقًا لقواعد إدارة السلامة العامة، ماذا ينبغي أن أفعل بهذا الغرض؟","options":["أحتفظ به لنفسي وأعيده مباشرة إذا صعد الراكب نفسه إلى حافلتي مجددًا في رحلة لاحقة","أتركه تمامًا في مكانه كي يتعامل معه الفحص التالي للحافلة أو طاقم التنظيف","أُسلّم الغرض إلى قسم المفقودات في شركتي كي يكون لدى صاحبه الشرعي وسيلة لاستعادته","أتخلص منه في نهاية اليوم لأن الغرض غير المطالَب به يُعامَل كممتلكات متروكة"],"explanation":"يجب تسليم أي غرض يتركه راكب إلى قسم المفقودات في الشركة كي يكون لدى صاحبه الشرعي وسيلة رسمية لاستعادته."},"145":{"q":"الركاب الواقفون أثناء تحرك الحافلة ينبغي أن:","options":["يتركوا الإمساك تمامًا","يمسكوا بقضيب","يتجولوا","يميلوا إلى الخارج"],"explanation":"ينبغي على الركاب الواقفين الإمساك بقضيب."},"146":{"q":"تمتلئ حافلتي للنقل العام عند موقف في وسط المدينة خلال ساعة الذروة، ويرغب عدة ركاب صاعدين في الوقوف للرحلة القصيرة. بصفتي السائق، كيف أحدد عدد الركاب الواقفين المسموح لي بنقلهم؟","options":["بعدد المقاعد الشاغرة المتبقية بعد أن يُحشَر راكب في كل مساحة من الممر","بإجمالي تصنيف الوزن الإجمالي للمركبة المدرج على لوحة اعتماد الحافلة","بأي عدد من الركاب يمكن أن يتسع دون أن يلمس أحد زجاج الحاجب الأمامي","بخط الوقوف المعلن والسعة القياسية للوقوف في الحافلة، مع إبقاء جميع الواقفين خلف ذلك الخط"],"explanation":"يُحدَّد عدد الواقفين المسموح به بالسعة القياسية للوقوف في الحافلة وبخط الوقوف (الأبيض)، مع إبقاء جميع الواقفين خلف ذلك الخط."},"147":{"q":"أقود حافلة نقل عام في المدينة خلال ساعة الذروة وعدة ركاب واقفين يمسكون بقضبان الإمساك خلف خط الوقوف. تتحول إشارة مرور أمامي إلى الأصفر وأحتاج إلى الإبطاء. لماذا من المهم أن أكبح بسلاسة وتدرّج بدلًا من التوقف بقوة؟","options":["الكبح السلس والتدريجي يمنع الركاب الواقفين من الاندفاع للأمام والسقوط","الكبح السلس يتيح للواقفين التقدم أمام خط الوقوف للحفاظ على توازنهم","الكبح بقوة مقبول ما دمت أعلن عن التوقف للركاب أولًا","الكبح التدريجي مطلوب فقط عندما تنقل الحافلة مواد خطرة"],"explanation":"الكبح السلس والتدريجي يمنع الركاب الواقفين من الاندفاع للأمام والسقوط، لأن التوقف المفاجئ والقوي قد يصيبهم."},"148":{"q":"أنت تُشغّل حافلة نقل عام وتقترب بحذر من موقف مزدحم على حافة الرصيف حيث ينتظر عدة ركاب ويمسك بعض الواقفين بالقضيب خلف خط الوقوف. للحفاظ على جدولك، تريد أن يتحرك الركاب فور وصولك إلى الرصيف. قبل أن تفتح باب الركاب، ينبغي أن تكون الحافلة:","options":["لا تزال تزحف للأمام بوتيرة مشي بطيئة كي يبدأ الركاب الصعود دون تأخير","قد توقفت توقفًا تامًا ومؤمَّنة قبل فتح الباب","شبه متوقفة، مع فتح الباب في القدم أو القدمين الأخيرتين كي يكون الركاب المنتظرون مستعدين للصعود","تنساب ببطء عبر المنعطف إلى الموقف كي يكون الباب مفتوحًا بالفعل عند وصولك إلى الرصيف"],"explanation":"لا تفتح الباب أبدًا حتى تتوقف الحافلة تمامًا وتُؤمَّن، كي لا يُجرّ الركاب أو يُطرحوا أرضًا ولا يُقذف الواقفون."},"149":{"q":"أقود حافلة نقل عام في المدينة على مساري المعتاد بحمولة كاملة من الركاب، وعدة أمور تتنافس على انتباهي. وفقًا لقواعد إدارة السلامة العامة في تكساس بشأن سلوك السائق أثناء تحرك الحافلة، أي مما يلي ينبغي أن أفعل للقيادة بأقصى درجات الأمان؟","options":["أستدير للإجابة على سؤال راكب حول المحطة التالية أثناء القيادة، لأن إبقاء الركاب على اطلاع جزء من عملي","أتحقق من رسالة نصية سريعة من المُرسِل وأرد عليها في نقطة بطيئة، لأن البقاء على تواصل يبقي المسار ملتزمًا بالجدول","أبقي انتباهي كاملًا على القيادة وأتجنب أي شيء يصرف تركيزي عن الطريق، وأتعامل مع احتياجات الركاب فقط عندما يكون ذلك آمنًا","أتناول غدائي المعبّأ عندما تكون حركة المرور خفيفة، لأن استراحة قصيرة تبقيني متيقظًا للجزء الأكثر ازدحامًا من الرحلة"],"explanation":"أبقِ انتباهك كاملًا على القيادة وتجنب أي شيء يشتت انتباهك، وتعامل مع احتياجات الركاب فقط عندما تكون الحافلة متوقفة ويكون ذلك آمنًا."},"150":{"q":"أنت تقود حافلة مسار عندما يطلب راكب قرب المؤخرة أن يُنزَل على الفور، قبل محطتك المجدولة التالية بكثير، على طريق مزدحم بأربعة مسارات. ماذا ينبغي أن تفعل؟","options":["توقف على جانب الطريق وأنزل الراكب فورًا، لأنه يحق للركاب طلب النزول في أي نقطة على طول المسار","تواصل التحرك دون إبطاء وأخبر الراكب أن عليه الانتظار حتى المحطة المجدولة التالية","أبطئ وافتح الباب وأنت لا تزال متحركًا كي يتمكن الراكب من النزول دون توقف كامل","تواصل حتى تصل إلى مكان يكون فيه التوقف على جانب الطريق آمنًا، ثم توقف وأنزل الراكب"],"explanation":"عندما يرغب راكب في النزول بين المحطات، تابع فقط حتى تصل إلى مكان آمن للتوقف على جانب الطريق، ثم توقف وأنزله."},"151":{"q":"أنت تقود حافلة نقل عام محمَّلة على طريق شرياني مزدحم بأربعة مسارات عندما يبدأ راكبان بالقرب من المؤخرة فجأة بالتدافع وتبادل اللكمات. يصرخ ركاب آخرون ويتزاحمون في الممر. أي من الإجراءات التالية هو الأفضل لك أن تتخذه؟","options":["توقّف بالحافلة في مكان آمن، ثم انتظر حتى تهدأ المشاجرة قبل المتابعة","استمر في القيادة بسرعتك المعتادة حتى تصل إلى المحطة المجدولة التالية وتُنزل المتشاجرين هناك","غادر مقعدك فورًا وعُد إلى الممر لتفصل بين الراكبين جسديًا","سرّع للوصول إلى المحطة الطرفية بشكل أسرع، لأن الوصول مبكرًا ينهي المشكلة بأسرع طريقة"],"explanation":"الحافلة المتحركة تحوّل الفوضى الداخلية إلى خطر أكبر، لذا توقّف في مكان آمن وانتظر حتى يصبح الوضع آمنًا قبل المتابعة."},"152":{"q":"إنها رحلة بعد الظهر مزدحمة وحافلة النقل لديك ممتلئة بالكامل بحيث لا تتوفر مقاعد. وأنت تنطلق من إحدى المحطات، تلاحظ عدة ركاب يتحركون بالقرب من المقدمة. وفقًا لقواعد تكساس، أي مما يلي يجب ألّا تسمح للراكب بفعله؟","options":["الوقوف خلف خط الوقوف (الأبيض) مع الإمساك بقضيب التثبيت","التزاحم إلى الأمام بحيث يحجبون رؤيتك للطريق والمرايا","حمل حقيبة صغيرة يبقونها على حِجرهم، بعيدًا عن الممر","البقاء جالسين بهدوء حتى يصلوا إلى محطتهم"],"explanation":"يجب ألّا يقف الركاب أبدًا أمام خط الوقوف أو يحجبوا رؤية السائق للطريق والمرايا."},"153":{"q":"أثناء فحص ما قبل الرحلة لحافلة نقل عام، أفحص نافذة مخرج الطوارئ الخلفي وفتحة السقف الجانبية قبل تحميل الركاب. اصطف بالفعل بضعة ركاب يحملون حقائب يدوية. أي حالة تجعل هذه الحافلة غير آمنة لوضعها في الخدمة؟","options":["مخرج الطوارئ مُعلَّم بوضوح بأحرف حمراء وملصق مرئي","يمكن فتح مخرج الطوارئ بسلاسة بضغط يدوي عادي","حقيبة يدوية لأحد الركاب محشورة أمام مخرج الطوارئ، تغطّيه جزئيًا","تم اختبار مخرج الطوارئ أثناء الفحص وأُغلق بإحكام تام"],"explanation":"يجب ألّا تُسدّ مخارج الطوارئ أبدًا، لذا فإن حقيبة يدوية محشورة أمام المخرج وتغطّيه جزئيًا تجعل الحافلة غير آمنة حتى يُزال العائق."},"154":{"q":"أقود حافلة المسار عبر شبكة شوارع وسط المدينة المزدحمة، وأريد أن أركّز رصدي للأخطار على المكان الذي تقع فيه معظم حوادث تصادم الحافلات فعليًا. وفقًا لإدارة السلامة العامة (DPS)، أين يجب أن أكون أكثر يقظة لاحتمال وقوع تصادم؟","options":["على الامتدادات الطويلة المفتوحة للطرق السريعة الريفية حيث تكون سرعتي أعلى","في الساحات الفارغة وحقول التجميع حيث أركن بين الرحلات","في مناطق الاستراحة المُعلَّمة حيث يصعد الركاب وينزلون","عند التقاطعات، حيث يتقاطع مساري مع حركة المرور الأخرى والانعطافات"],"explanation":"التقاطعات من أبرز مواقع حوادث الحافلات لأن حركة المرور المتقاطعة والمركبات المنعطفة والمشاة كلها تتعارض هناك."},"155":{"q":"أنا في محطة استراحة مجدولة مع حافلتي السياحية، وعدة ركاب ينزلون لاستخدام دورة المياه عبر الشارع بينما ينتظر آخرون لإعادة الصعود. وأنا أستعد للعودة إلى حركة المرور، أي مجموعة من الركاب يجب أن أراقبها بأقصى حذر لتجنب وقوع مأساة؟","options":["الركاب الذين يعبرون أمام الحافلة، حيث قد أفقدهم من نظري في نقطتي العمياء","الركاب الذين ينزلون ويمشون على جانب الحافلة بمحاذاة العجلات الخلفية","الركاب الذين يبقون جالسين وينتظرون بهدوء مغادرة الحافلة للمحطة","الركاب الذين يجلسون بثبات تام ويتجنبون التحرك في الممر أثناء الصعود"],"explanation":"راقب الركاب الذين يعبرون أمام الحافلة، لأنهم يقعون في النقطة العمياء الأمامية ويمكن أن يُصدَموا عند تحركك للأمام."},"156":{"q":"أقود حافلة نقل عام في المدينة مع عدة ركاب واقفين ممسكين بقضبان التثبيت، ومحطتي المجدولة التالية أمامي مباشرة. وأنا أستعد للتوقف، أي مما يلي يصف الطريقة الصحيحة للتعامل مع الاقتراب؟","options":["تجاهل إشارة الانعطاف لأن المحطة مجدولة معتادة والركاب يتوقعونها بالفعل","أعطِ الإشارة مبكرًا واكبح بلطف لأتوقف بسلاسة دون أن أُفقد الركاب الواقفين توازنهم","انتظر حتى آخر لحظة، ثم اكبح بقوة لأتوقف بدقة عند منطقة التحميل المُعلَّمة","أعطِ الإشارة وسرّع قليلًا لأتجاوز حركة المرور قبل توجيه الحافلة نحو الرصيف"],"explanation":"أعطِ الإشارة مبكرًا واكبح بلطف عند الاقتراب من المحطة حتى لا يفقد الركاب الواقفون توازنهم."},"157":{"q":"أقود حافلة نقل عام في المدينة خلال ساعة الذروة. كل المقاعد مشغولة وعدة ركاب يقفون في الممر خلف الخط الأبيض للوقوف. وأنا أقترب من تقاطع، تتحول الإشارة فجأة إلى الأصفر. من المناورات التالية، أي واحدة تخلق أكبر خطر لإفقاد ركابي الواقفين توازنهم والتسبب في إصابة؟","options":["رفع القدم عن دواسة الوقود مبكرًا والانزلاق بسلاسة نحو التقاطع","إجراء انعطاف بطيء ومُتحكَّم به عند الزاوية بعد تغير الإشارة","الضغط على الفرامل لتوقف مفاجئ وحاد عند الخط","الحفاظ على سرعة ثابتة على الامتداد المستقيم الطويل قبل الإشارة"],"explanation":"التوقفات المفاجئة هي الخطر الرئيسي على الركاب الواقفين لأن لا شيء يثبّتهم والقصور الذاتي يدفعهم إلى الأمام، لذا اكبح بسلاسة."},"158":{"q":"أُنهي فحص ما قبل الرحلة لحافلة نقل عام عندما يفتح راكب باب مخرج الطوارئ الخلفي لتحميل عربة أطفال، ثم يتركه مواربًا بينما تُغلق الأبواب وأنا أستعد للانطلاق إلى حركة المرور. أي من هذه الحالات يعني أنه يجب ألّا أبدأ القيادة حتى تُصحَّح؟","options":["نافذة جانب السائق مفتوحة جزئيًا للتهوية","واقي الشمس الداخلي فوق الزجاج الأمامي مطوي للأسفل","غطاء فتحة الوقود تُرك مُحكمًا بالكامل بعد التزود بالوقود","باب مخرج الطوارئ الخلفي لا يزال مفتوحًا"],"explanation":"يجب ألّا تُقاد الحافلة أبدًا ومخرج الطوارئ مفتوح، لذا فإن المخرج الخلفي المفتوح حالة تمنع القيادة حتى يُغلق."},"159":{"q":"أنا متأخر نحو خمس عشرة دقيقة عن الجدول على مسار حافلتي المستأجرة، والطريق صافٍ وجاف، والحد المنشور على هذا المقطع هو 55 ميلًا في الساعة. لتعويض الوقت الضائع، ماذا يتطلب قانون تكساس مني بخصوص الحد الأقصى للسرعة المنشور؟","options":["الالتزام بالحد المنشور 55 ميلًا في الساعة، لأن الحدود المنشورة تنطبق على حافلتي في جميع الأوقات","تجاوز الحد بما يصل إلى 10 أميال في الساعة لأن الطريق صافٍ والظروف مثالية","اعتبار الحد المنشور إرشادًا ومطابقة سرعة حركة المرور المحيطة","القيادة أسرع من الحد المنشور فقط حتى أعوّض الدقائق الخمس عشرة الضائعة"],"explanation":"الحدود القصوى المنشورة للسرعة هي حد قانوني ينطبق دائمًا، والتأخر عن الجدول لا يبرّر أبدًا تجاوزها."},"160":{"q":"أقود حافلة نقل عام بطول 40 قدمًا وأحتاج إلى الانعطاف يمينًا من شارع ضيق في وسط المدينة إلى شارع جانبي أضيق منه. ولأن الحافلة طويلة جدًا، ماذا يجب أن أفعل لإتمام الانعطاف بأمان دون أن أصطدم بالرصيف أو بالمركبات في المسار المجاور؟","options":["أدِر المقود بحدة والتصق بالرصيف الأيمن بإحكام عند بدء الانعطاف حتى يبقى مؤخر الحافلة داخل مساري","انعطف على نطاق واسع وامنح الحافلة مساحة إضافية، واترك مقدمة الحافلة تتجاوز الزاوية قبل الانعطاف حتى تتجنب العجلات الخلفية الرصيف","أجرِ انعطافًا سريعًا وضيقًا عند الزاوية لأقضي أقل وقت ممكن في عرقلة التقاطع لحركة المرور المتقاطعة","حافظ على نصف قطر ضيق ثابت طوال الانعطاف وسرّع قليلًا حتى يدفع الزخم الجسم الطويل حول المنعطف"],"explanation":"لأن العجلات الخلفية للحافلة تتبع مسارًا داخليًا عن العجلات الأمامية، انعطف على نطاق واسع واترك المقدمة تتجاوز الزاوية قبل الانعطاف حتى تتجنب العجلات الخلفية الرصيف."},"161":{"q":"وصلتُ إلى نهاية مساري وآخر راكب أستطيع رؤيته نزل للتو من الحافلة عند المحطة الطرفية. قبل أن أُقفل وأُطفئ المحرك وأتوجه إلى المرآب لاستراحتي، ماذا يجب أن أفعل؟","options":["لا حاجة لشيء إضافي بمجرد اختفاء الركاب المرئيين؛ يمكنني تأمين الحافلة والمغادرة فورًا","التقدم إلى محطة الوقود وملء الخزان حتى تكون الحافلة جاهزة لوردية السائق التالي","المشي على طول الممر بالكامل حتى المؤخرة، مع فحص كل مقعد بحثًا عن ركاب نائمين أو أغراض متروكة","تسجيل قراءة عدّاد المسافات النهائية ومسح شاشة المسار حتى تتم برمجة مسار جديد"],"explanation":"بعد نزول آخر راكب، امشِ في الممر حتى المؤخرة وافحص كل مقعد للعثور على الركاب النائمين والأغراض المتروكة قبل تأمين الحافلة."},"162":{"q":"أُدخل حافلتي المحمَّلة إلى ساحة محطة طرفية ضيقة وأدرك أنني تجاوزت موقفي المخصص. الطريقة الوحيدة لإعادة التموضع هي الرجوع بالحافلة للخلف. وفقًا لإجراءات إدارة السلامة العامة في تكساس (DPS)، ماذا يجب أن يوجّه قراري بالرجوع للخلف؟","options":["الرجوع للخلف مقبول هنا لأن الساحة مغلقة وحركة المرور خفيفة، لذا يمكنني الرجوع بسرعة عادية.","يمكنني الرجوع بحرية طالما الحافلة ممتلئة، لأن الحافلة المحمَّلة تسير بشكل أكثر استقامة عند الرجوع.","يجب أن أرجع للخلف فقط عندما يكون الظلام حالكًا أو الرؤية ضعيفة بما يكفي ليصبح التقدم للأمام غير آمن.","يجب أن أتجنب الرجوع للخلف كلما أمكن، وأرجع فقط عند الضرورة القصوى، وأن أفعل ذلك ببطء وحذر."],"explanation":"لأن سائق الحافلة لا يستطيع الرؤية مباشرة خلف المركبة، تجنّب الرجوع للخلف كلما أمكن وارجع فقط عند الضرورة القصوى، وافعل ذلك ببطء وحذر."},"163":{"q":"أركن حافلة نقل عام في ساحة ضيقة وأحتاج إلى الرجوع بها إلى مكان، لكن مؤخرة الحافلة بها نقاط عمياء كبيرة لا أستطيع رؤيتها بالكامل في مراياي. وفقًا لإجراءات إدارة السلامة العامة في تكساس (DPS)، ما هي أفضل ممارسة للرجوع بالحافلة بأمان؟","options":["استعن بمساعد خارج الحافلة يمكنه مراقبة النقاط العمياء وإعطائي الإشارة، كلما توفر أحد","اعتمد كليًا على مراياك، لأن الرجوع البطيء يجعل النقاط العمياء صغيرة بما يكفي لتجاهلها","ارجع بسرعة حتى تقضي الحافلة أقل وقت ممكن في منطقة الخطر خلفها","افتح باب مخرج الطوارئ الخلفي أثناء الرجوع حتى تسمع أي شخص خلف الحافلة"],"explanation":"للحافلة نقاط عمياء كبيرة مباشرة خلفها لا تغطّيها المرايا، لذا استعن بمساعد خارج الحافلة لمراقبة المنطقة العمياء وإعطائك الإشارة كلما توفر أحد."},"164":{"q":"أنا على وشك بدء رحلة استئجار صباحية بحمولة كاملة من الركاب. وأنا أُنهي جولة فحص ما قبل الرحلة، أريد أن أتأكد من أن الحافلة آمنة للقيادة. أي مما يلي يجب أن أفعله بالفرامل قبل أن أخرج من الساحة؟","options":["ملء خزان سائل الفرامل وتجاوز اختبار الطريق لأن الخطوط محكمة الإغلاق","اختبار الفرامل قبل الرحلة للتأكد من أنها تعمل بشكل صحيح","الانتظار حتى أول محطة ركاب لأشعر بكيفية استجابة الفرامل تحت الحمل","الاعتماد على فحص ما بعد رحلة الأمس لأن الحافلة بقيت طوال الليل دون استخدام"],"explanation":"اختبر الفرامل قبل الرحلة كجزء من فحص ما قبل الرحلة للتأكد من أنها تعمل بشكل صحيح قبل نقل الركاب."},"165":{"q":"أُشغّل حافلة نقل عام مزودة بنظام تعشيق بين الفرامل ودواسة الوقود عند محطة مزدحمة في وسط المدينة. ثبّت نظام التعشيق الحافلة في مكانها بينما صعد الركاب عبر البابين الأمامي والخلفي المفتوحين. وأنا أستعد للعودة إلى حركة المرور، أي إجراء سيجعل نظام التعشيق يحرّر الفرامل حتى تتمكن الحافلة من التحرك؟","options":["تفعيل فرملة الانتظار ثم تحريرها بعد توقف وجيز","الضغط على دواسة الوقود بقوة لتجاوز الفرامل المثبَّتة","إغلاق جميع أبواب الركاب","إطفاء أضواء السقف الداخلية وأضواء الممر"],"explanation":"نظام التعشيق بين الفرامل ودواسة الوقود يثبّت الفرامل طالما أي باب ركاب مفتوح ولا يحرّرها إلا بعد إغلاق جميع الأبواب."},"166":{"q":"أُوقف حافلة النقل عند محطة وهناك راكبة تستخدم كرسيًا متحركًا تنتظر الصعود. الرصيف به منحدر بسيط قريب وبضعة ركاب خلفها يعرضون المساعدة في حمل الكرسي صعودًا على درجات المدخل. لصعود هذه الراكبة بشكل صحيح، ماذا يجب أن أفعل؟","options":["أطلب من الركاب المنتظرين رفعها مع الكرسي صعودًا على درجات المدخل حتى تبقى الحافلة في موعدها، ثم أدعها تجلس في أي مكان شاغر","أنتظر امتلاء المنحدر القريب، ثم أدفع الكرسي صعودًا على الدرجات بنفسي بينما فرملة الانتظار محرَّرة حتى أتمكن من التحرك للأمام","أدعها تنتقل إلى مقعد عادي أولًا وأطوي الكرسي الفارغ في الممر بجوار خط الوقوف","أستخدم رافعة الكرسي المتحرك لإصعادها، ثم أُثبّت الكرسي المتحرك بأحزمة التثبيت قبل الانطلاق"],"explanation":"أصعِد الراكبة على الكرسي المتحرك باستخدام رافعة الكرسي المتحرك بالحافلة وثبّت الكرسي بأحزمة التثبيت قبل الانطلاق."},"167":{"q":"أثناء فحص ما قبل الرحلة لحافلة نقل عام، يطلب راكب معتاد ترك حقيبتين رياضيتين كبيرتين على أرضية الممر بالقرب من المخرج الخلفي \"لهذه الرحلة فقط\". أي رد يلبّي على أفضل وجه متطلبات إدارة السلامة العامة في تكساس (DPS) للحفاظ على نظافة الحافلة وسلامتها من الداخل؟","options":["ارفض، لأن الأمتعة المحمولة يجب أن تكون مثبَّتة بحيث لا تسد الممر أو أي مخرج","اسمح بذلك طالما بقيت الحقائب خلف خط الوقوف وخارج رؤية السائق","اسمح بذلك لأن المخرج الخلفي مخرج طوارئ فقط ونادرًا ما يُستخدم في الخدمة","اسمح بذلك طالما بقي الوزن الإجمالي للحقيبتين أقل من 100 رطل"],"explanation":"يجب أن يبقى الممر وجميع المخارج خالية، ويجب أن تكون الأمتعة المحمولة مثبَّتة بحيث لا تسد الممر أو أي مخرج أو تسقط على أحد."},"168":{"q":"أقود حافلة نقل عام في المدينة في فترة بعد الظهر الحارة، وتعطّل التكييف. خفّض عدة ركاب نوافذهم الجانبية للتخفيف، وألاحظ راكبًا يُسند مرفقه خارج النافذة المفتوحة بينما تميل راكبة أخرى رأسها نحو الفتحة لتنال نسمة الهواء. بصفتي السائق المسؤول عن سلامتهم، ما التعليمات التي يجب أن أعطيها لهؤلاء الركاب؟","options":["اسمح بذلك طالما الحافلة تسير ببطء، لأن السرعات البطيئة تجعل الميل خارج النافذة غير ضار","أخبرهم بإبقاء أذرعهم ورؤوسهم داخل الحافلة في جميع الأوقات أثناء حركتها","اسمح بذلك فقط على الجانب البعيد عن حركة المرور القادمة، لأن ذلك الجانب محمي من المركبات العابرة","دعهم يستمرون لكن اشترط بقاءهم خلف خط الوقوف أثناء الميل خارجًا"],"explanation":"يجب أن يُبقي الركاب أذرعهم ورؤوسهم داخل الحافلة في جميع الأوقات أثناء حركتها، لأن أي طرف ممتد خارجًا قد يصطدم بأجسام أو مركبات ويسبب إصابة بالغة."},"169":{"q":"أقود شاحنة صغيرة لـ14 راكبًا برخصتي من الفئة B دون أي مصادقات إضافية، وتريد شركتي نقلي إلى حافلة نقل عام لـ22 راكبًا تحمل ركابًا جالسين في معظمهم. يقول مشرفي إنه لا حاجة لشيء جديد لأنني أحمل بالفعل رخصة قيادة تجارية والمركبة الجديدة من نفس فئة الوزن. قبل أن أوافق، ماذا يتطلب قانون تكساس فعليًا حتى أقود تلك الحافلة لـ22 راكبًا بشكل قانوني؟","options":["لا شيء إضافي، لأن رخصتي من الفئة B تغطّي بالفعل أي مركبة واحدة في فئة الوزن تلك بغض النظر عن عدد الأشخاص المصممة لحملهم.","يجب أن أضيف مصادقة الصهريج (N)، لأن حافلة النقل العام تُعامل كمركبة مغلقة كبيرة بمجرد أن تكون مصممة لإجلاس 20 شخصًا أو أكثر.","يجب أن أحصل على مصادقة الركاب (P)، لأن الحافلة مصممة لحمل 16 شخصًا أو أكثر بمن فيهم السائق.","لا شيء إضافي بعد، لكن فقط إذا أبقيت جميع الركاب جالسين؛ تُطلب المصادقة فقط عندما يقف ركاب خلف خط الوقوف."],"explanation":"تُطلب مصادقة الركاب (P) لأي مركبة مصممة لحمل 16 شخصًا أو أكثر بمن فيهم السائق، لذا فإن رخصة القيادة التجارية وحدها لا تكفي."},"170":{"q":"أحمل بالفعل رخصة قيادة من الفئة C ويوظفني صديق لقيادة حافلة نقل صغيرة بأجرة لـ12 راكبًا حول المطار. المركبة أقل بكثير من الوزن الذي يتطلب رخصة قيادة تجارية، لذا أفترض أنني مؤهل للبدء. قبل أن أقبل العمل، ما الشيء الوحيد الذي لا تزال إدارة السلامة العامة في تكساس (DPS) تتطلب أن أحوزه لهذه المهمة؟","options":["لا حاجة لشيء آخر، لأن الحافلة أقل من حد الوزن المطلوب لرخصة القيادة التجارية وأنا أحمل بالفعل رخصة سارية من الفئة C","بطاقة فاحص طبي فيدرالي هي كل المطلوب، إذ لا تنطبق أي مصادقة على مركبات بهذا الصغر","تصريح سائق منفصل يُصدر فقط لشاحنات الفنادق والمطارات المجامِلة بأقل من 16 مقعدًا","مصادقة الركاب المناسبة، لأن حمل ركاب يدفعون أجرة قد يتطلبها حتى على حافلة أصغر تعمل بأجرة"],"explanation":"العامل المحدِّد هو حمل ركاب يدفعون أجرة، لا حجم المركبة أو وزنها، لذا حتى الحافلة الأصغر العاملة بأجرة قد تتطلب مصادقة الركاب."},"171":{"q":"أقود حافلة نقل عام على طريق مبتل بمسارين عندما تكبح السيارة أمامي بقوة. لديّ مساحة أكثر من كافية للتوقف بشكل طبيعي، لكنني أترك مسافة اتباع إضافية وأرفع قدمي عن الدواسة مبكرًا جدًا بدلًا من الكبح متأخرًا كما أفعل في سيارتي الخاصة. أي تفسير يوضح على أفضل وجه لماذا أحافظ على هذا الهامش الأعلى من الأمان خلف مقود حافلة؟","options":["الحافلة تحمل كثيرًا من الناس، لذا فإن خطأً واحدًا يعرّض أرواحًا أكثر بكثير للخطر من سيارة الركاب ويتطلب وسادة أمان أكبر","الحافلة عادة فارغة بين المحطات المجدولة، لذا فإن المساحة الإضافية تحمي فقط السائق والركاب الجالسين القلائل","الحافلة تحمل بضائع وأمتعة في معظمها، لذا فإن المسافة الإضافية مخصصة لمنع الشحنة من الانزلاق عند التوقف الحاد","الحافلة تعمل بالكامل تقريبًا على وزن الوقود، لذا فإن الوسادة لازمة فقط لتعويض حمل الكبح الأثقل"],"explanation":"الحافلة تحمل كثيرًا من الناس، لذا فإن خطأً واحدًا يعرّض أرواحًا كثيرة للخطر دفعة واحدة، مما يتطلب توقّعًا مبكرًا للأخطار ووسادة أمان أكبر."},"172":{"q":"أُشغّل حافلة نقل عام وانتهيت للتو من إصعاد آخر راكب عند محطة في وسط المدينة. قبل أن أحرّر فرملة الانتظار وأعود إلى حركة المرور، ما الذي يجب أن تكون عليه حالة باب الركاب؟","options":["مُبقى مفتوحًا على اتساعه حتى يتمكن الركاب المتأخرون من اللحاق بالحافلة في منتصف الطريق","مغلقًا بإحكام بحيث لا يستطيع أي راكب السقوط أو الصعود أثناء حركة الحافلة","منزوعًا عن مساره ومُخزَّنًا لأنه لم يعد لازمًا حتى المحطة التالية","مُبقى نصف مفتوح للحفاظ على تدفق الهواء النقي عبر الممر أثناء قيادتي"],"explanation":"يجب أن يكون باب الركاب مغلقًا بإحكام قبل التحرك بحيث لا يستطيع أحد السقوط أو محاولة الصعود أثناء حركة الحافلة."},"173":{"q":"أقود حافلة نقل عام محمَّلة على طريق سريع بمسارين عندما يفقد المحرك قدرته وأنزلق إلى الكتف الأيمن. عدة ركاب يشعرون بالقلق ويريدون معرفة ما يجب فعله. بخلاف تأمين الحافلة، أي إجراء يجب أن أتخذه مع ركابي؟","options":["أُبقي الجميع جالسين داخل الحافلة، لأن الكتف يحميهم من حركة المرور العابرة","أجعل الركاب ينتظرون بجوار الحافلة قرب جانب حركة المرور حتى تتمكن شاحنة القطر من رؤيتهم بسرعة","أنقل الركاب من الحافلة إلى مكان آمن بعيدًا عن الطريق وحركة المرور","أُرسل بضعة ركاب أعلى الطريق لإيقاف المركبات القادمة طلبًا للمساعدة"],"explanation":"إذا تعطلت الحافلة، انقل الركاب منها إلى مكان آمن بعيدًا عن الطريق وحركة المرور."},"174":{"q":"أقود حافلة نقل عام ممتلئة خلال ساعة الذروة، والممر مزدحم بالواقفين، وبضعة ركاب يستمرون في الانجراف للأمام متجاوزين الخط الأبيض للوقوف للدردشة قرب مقعدي. بصفتي السائق، عمَّ أنا مسؤول بشكل أساسي في هذا الموقف؟","options":["تحصيل الأجرة الصحيحة وإعطاء الباقي لكل راكب واقف قبل المحطة التالية","الإعلان عن كل محطة قادمة واسم الشارع بصوت عالٍ بما يكفي ليسمعني كل راكب","إبقاء الركاب مستمتعين ومرتاحين حتى لا يشتكي أحد من الازدحام","سلامة الركاب، بما في ذلك إبقاؤهم خلف خط الوقوف وخارج رؤيتي"],"explanation":"سلامة الركاب هي الواجب الأسمى للسائق، وهذا يعني إبقاء الركاب خلف خط الوقوف وخارج رؤية السائق."},"175":{"q":"أقود حافلة سياحية مستأجرة محمَّلة عندما يسكب راكب مشروبًا قرب المقدمة ويبدأ موزّع الراديو في الاتصال بي بشأن تغيير في الجدول. بصفتي السائق، أي من هذه هو الأهم الذي أنا مسؤول عن حمايته؟","options":["سلامة الركاب الموجودين على متن حافلتي","الأمتعة المحمولة والأغراض الشخصية المخزَّنة على متن الحافلة","الراديو ثنائي الاتجاه ومعدات الإرسال في المقدمة","المقاعد والحالة الداخلية لحافلة الشركة"],"explanation":"الركاب على متن الحافلة يأتون دائمًا في المقام الأول وهم المسؤولية الأهم للسائق على الإطلاق، فوق الجدول أو المعدات أو الممتلكات."},"176":{"q":"أنا أقود حافلة نقل عام محملة بالكامل على طريق جاف ومستوٍ، وفجأة تضغط سيارة أمامي على المكابح بقوة. أضغط على مكابحي عند النقطة نفسها التي كنت سأضغط عندها في سيارتي الشخصية، ومع ذلك تستغرق حافلتي وقتاً أطول بوضوح حتى تتوقف تماماً. أي خصائص الحافلة تفسّر على نحو أفضل لماذا أحتاج إلى مسافة توقف أكبر من السيارة؟","options":["للحافلة مركز ثقل أعلى، وهذا يطيل مسافة الكبح مباشرة","تحمل الحافلة وزناً أكبر بكثير، لذا تستغرق وقتاً أطول للتوقف من السيارة الأخف","تسير الحافلة أسرع من السيارة، مما يتطلب مسافة إضافية للتوقف","الحافلة أعلى صوتاً، لذا يتفاعل نظام كبحها بشكل أبطأ مع الضغط على الدواسة"],"explanation":"الحافلة المحملة لها وزن وزخم أكبر بكثير من السيارة، لذا تحتاج مكابحها إلى مسافة أكبر للتوقف."},"177":{"q":"أنا أقود حافلة نقل عام محملة على مساري عندما يترك صقيع الصباح الباكر طبقة رقيقة من الجليد على الطريق. وبينما أقترب من محطتي التالية وإشارة أمامي، أي تعديل على قيادتي هو الأهم للتوقف بأمان على هذا السطح الجليدي؟","options":["يمكنني الكبح عند نقطتي المعتادة لأن وزن الحافلة يضغط الإطارات عبر الجليد لتحقيق تماسك","ينبغي أن أكبح بقوة أكبر ومتأخراً أكثر من المعتاد لمنع الواقفين من الانزلاق إلى الأمام في الممر","أحتاج إلى البدء بالكبح مبكراً وإتاحة مسافة توقف أكبر بكثير من الرصيف الجاف","يمكنني الحفاظ على مسافة الأمان المعتادة لأن المكابح المانعة للانغلاق تقصّر مسافة توقفي على الجليد"],"explanation":"على الجليد، يقل التماسك بشكل كبير، لذا ابدأ الكبح مبكراً وأتح مسافة توقف أكبر بكثير من الرصيف الجاف."},"178":{"q":"أنا أقود حافلة نقل عام مدينية محملة عندما تقطع سيارة فجأة مساري، مما يجبرني على إجراء توقف طارئ مفاجئ. في نصف الثانية المتاح لي للتفاعل، أي وضع للركاب يمنح ركابي أفضل حماية من الاندفاع إلى الأمام أثناء ذلك التوقف؟","options":["الواقفون الممسكون بالقضيب العلوي خلف خط الوقوف مباشرة","الركاب المتجهون نحو الباب الأمامي لينزلوا بسرعة","الركاب الواقفون في الممر المستندون إلى ظهور المقاعد","الركاب الجالسون والمستقرون في مقاعدهم في جميع أنحاء الحافلة"],"explanation":"الركاب الجالسون والمستقرون هم الأكثر أماناً في التوقف المفاجئ، لأن التوقف المفاجئ يندفع بالركاب الواقفين إلى الأمام."},"179":{"q":"أنا أقود حافلة نقل عام مدينية على مسار مزدحم مع عدة ركاب واقفين خلف خط الوقوف. وبينما أقترب من محطة مزدحمة وأستعد للاندماج مجدداً في حركة المرور، ما الغرض الأساسي من فحص مراياي الخارجية والداخلية بانتظام أثناء الرحلة؟","options":["لمراقبة ركابي داخل الحافلة وحركة المرور والظروف المتطورة حول المركبة معاً","لمراقبة حركة المرور خلف الحافلة وبجانبها فقط، لأن الظروف الداخلية ليست مهمة المرآة","للتحقق من حرارة المحرك ومقاييس الوقود دون النظر إلى لوحة القيادة","لتأكيد السماء والمسافة العلوية أمامي حتى أتمكن من تقدير الجسور القادمة"],"explanation":"تؤدي المرايا دوراً مزدوجاً: مراقبة الركاب داخل الحافلة وحركة المرور والظروف المتطورة حول المركبة."},"180":{"q":"أنا أقود حافلة نقل عام مدينية وقد انتهيت للتو من تحميل الركاب في محطة وسط المدينة المزدحمة. لا يزال بعض الركاب يتنقلون في الممر بحثاً عن مقعد، وأحد الركاب قرب الباب الأمامي لا يزال يمد يده نحو المسكة ليثبّت نفسه. تتحول الإشارة إلى الأخضر وحركة المرور خلفي تطلق الأبواق. وفقاً لقواعد رخصة القيادة التجارية في تكساس، متى ينبغي أن أبدأ بإبعاد الحافلة عن الرصيف؟","options":["بمجرد أن تتحول الإشارة إلى الأخضر، لأنه يجب أن أبقي حركة المرور سائرة ولا يحق لي قانونياً إعاقة المركبات خلفي","فقط بعد أن يكون كل راكب جاهزاً وآمناً، أي جالساً أو ممسكاً وبعيداً عن الأبواب، حتى لو عنى ذلك الانتظار خلال الإشارة الخضراء","بمجرد إغلاق الأبواب الخلفية، لأن الباب المغلق يؤكد أن كل من على متن الحافلة قد انتهى من الصعود وأصبح آمناً","بمجرد انتقال الواقفين خلف خط الوقوف الأبيض، لأن ذلك الخط يحدد النقطة التي يكون عندها التسارع آمناً"],"explanation":"حرّك الحافلة فقط بعد أن يكون كل راكب جاهزاً وآمناً، أي جالساً أو ممسكاً وبعيداً عن الأبواب، حتى لو عنى ذلك الانتظار خلال إشارة خضراء."},"181":{"q":"أنا أقود حافلتي على شارع مديني بمسارين عندما أرى مجموعة من الأطفال يغادرون مدرسة ابتدائية، مع تجمّع عدة أطفال على الرصيف قرب الحافة. لا يوجد حراس عبور ولا إشارات تطلب مني التوقف. ما الطريقة الأكثر أماناً للتعامل مع هذا المقطع من الطريق؟","options":["الحفاظ على سرعتي المقررة المعتادة لأنه لا توجد إشارات أو حراس عبور يوجهونني للإبطاء","التسارع لفترة قصيرة لتجاوز المنطقة بسرعة وتقليل الوقت الذي أتعرض فيه للحشد","الإبطاء والقيادة ببطء شديد حتى أتمكن من التفاعل إذا خطا طفل فجأة إلى الشارع","التوقف تماماً في مسار السير والانتظار حتى يبتعد كل طفل عن الحافة"],"explanation":"قرب المدارس والحشود، قُد ببطء شديد حتى يكون لديك وقت تفاعل ومسافة توقف كافيان إذا خطا طفل فجأة إلى الشارع."},"182":{"q":"أنا أحمّل الركاب في حافلتي في محطة مزدحمة في وسط المدينة، وعدة ركاب يصعدون بحقائب يدوية وأكياس تسوق وعربة أطفال مطوية. وبينما أستعد للخروج إلى حركة المرور، أي شرط متعلق بالممر والمدخل يجب أن أتأكد من تحقيقه قبل أن أبدأ القيادة؟","options":["يمكن أن يحوي الممر حقائب مؤمّنة طالما بقي المدخل الأمامي مفتوحاً للتهوية","يمكن أن تستقر الحقائب اليدوية في المدخل بشرط أن يبقى الممر نفسه قابلاً للمشي","يمكن أن يملأ الركاب الواقفون الممر طالما بقوا خلف خط الوقوف","يجب أن يبقى كل من الممر والمدخل خاليين حتى لا يُسد أي مخرج"],"explanation":"قبل القيادة، أبقِ الممر وكل المخارج خالية وأمّن الأمتعة اليدوية حتى لا تسدّها."},"183":{"q":"أنا أقود حافلة نقل عام محملة عندما يبدأ رذاذ بارد فيصبح الرصيف زلقاً. حركة المرور أمامي تسير بثبات وأنا أواكب وتيرتها. للبقاء مسيطراً وتجنب الانزلاق أو التوقف المفاجئ الذي قد يندفع بالواقفين، ماذا ينبغي أن أفعل؟","options":["أخفّض سرعتي إلى ما دون الحد المقرر وأزيد مسافة الأمان لمراعاة السطح الزلق","أحافظ على سرعتي الحالية لكن أبقي قدمي قرب المكابح حتى أتمكن من التوقف فوراً إذا أبطأت حركة المرور","أضغط على المكابح بقوة وبشكل متكرر لاختبار التماسك ومنع العجلات من الانغلاق","أتسارع قليلاً لتجاوز المقطع المبلل بسرعة وتقليل وقتي على الرصيف الزلق"],"explanation":"على طريق زلق، خفّف السرعة إلى ما دون الحد المقرر وزد مسافة الأمان حتى تتماسك الإطارات وتتمكن من الكبح بسلاسة بدلاً من الكبح المفاجئ."},"184":{"q":"أنا أقود حافلة نقل عام بـ47 مقعداً على مسار مزدحم. عند المحطة الأخيرة، امتلأت كل المقاعد، وجميع الواقفين القانونيين متجمعون بالفعل خلف خط الوقوف الأبيض، وحشد من 20 شخصاً إضافياً يلوّحون لي لأدعهم يصعدون كي لا يتأخروا. أي حد يجب أن أرفض كسره، رغم أن هؤلاء الركاب منزعجون من تركهم؟","options":["يمكنني الاستمرار في التحميل طالما لا يقف أحد أمام خط الوقوف","يجب ألا أتجاوز سعة الجلوس والوقوف المقررة للحافلة","يمكنني إضافة ركاب طالما بقي إجمالي الأمتعة اليدوية أقل من 500 رطل","يمكنني تجاوز الحد لفترة قصيرة لأن الحافلة التالية بعد أكثر من 30 دقيقة"],"explanation":"يجب ألا تتجاوز الحافلة أبداً سعة الجلوس والوقوف المقررة لها، لذا بمجرد امتلائها يجب على السائق رفض الركاب الإضافيين."},"185":{"q":"أثناء فحصي قبل الرحلة، ألاحظ أن راكباً ترك حقيبة رياضية ثقيلة غير مؤمّنة على مقعد فارغ قرب مقدمة الحافلة. الممر والمخارج خالية، لذا أميل إلى تركها مكانها. لماذا يجب أن أؤمّن هذه الحقيبة أو أزيلها قبل القيادة؟","options":["الحقيبة غير المؤمّنة قرب المقدمة تحسّن توزيع الوزن فوق محور التوجيه وتجعل الحافلة في الواقع أسهل في التحكم عند الانعطاف","يتطلب قانون تكساس تخزين كل الأغراض اليدوية في الخلف حتى تبقى الحافلة متوازنة من الأمام إلى الخلف على سرعة الطريق السريع","إذا اضطررت إلى الكبح بقوة أو التوقف المفاجئ، يمكن أن تندفع الحقيبة السائبة إلى الأمام وتصطدم بي أو براكب","الجسم السائب المتروك في المقصورة سينزلق تدريجياً إلى الخلف بينما أتسارع، وقد يسدّ في النهاية مخرج الطوارئ الخلفي"],"explanation":"يجب تأمين الأمتعة اليدوية لأنه أثناء التوقف القوي أو المفاجئ يمكن أن تندفع الحقيبة السائبة إلى الأمام وتصطدم بالسائق أو براكب."},"186":{"q":"يصعد راكب منتظم إلى حافلتي السياحية حاملاً وعاءً محكم الإغلاق لمادة كيميائية خطرة وإبريقاً صغيراً من سائل، ويقول لي إنه يحضرهما كل أسبوع وإن «الحافلة يمكنها أن تنقل أي شيء يستطيع الشخص حمله معه». قبل أن أسمح بدخول هذه الأغراض، كيف ينبغي أن أتعامل مع المواد الخطرة والسوائل المماثلة التي يحملها الركاب؟","options":["أي شيء يحمله الراكب بيديه فعلياً يُعامل كأمتعة شخصية، لذا لا تنطبق عليه قواعد المواد الخطرة","يُشجَّع على هذه الأغراض لأن إبقاء الركاب لها بأيديهم يحرّر مخازن البضائع لأمتعة أخرى","لا يوجد قيد طالما أن الأوعية محكمة الإغلاق وتبقى على حِجر الراكب طوال الرحلة","إنها مقيّدة، لأن الحافلة قد تحمل كميات مسموحة محدودة فقط وبعض فئات المواد الخطرة محظورة تماماً"],"explanation":"يمكن للحافلة أن تحمل كميات محدودة فقط من المواد الخطرة، وبعض فئات المواد الخطرة مثل المتفجرات من الشُّعب 1.1 إلى 1.3 والغازات السامة محظورة تماماً."},"187":{"q":"أنا أقود حافلة سياحية عندما تصدمني سيارة ركاب من الجانب على الطريق السريع؛ هناك أضرار طفيفة لكن لا إصابات. وبينما أتوقف جانباً وأبدأ بالتعامل مع الموقع، أي معيار يخبرني كيف وإلى من يجب أن أبلّغ عن هذا الحادث؟","options":["أتّبع إجراءات الإبلاغ عن الحوادث الخاصة بشركة النقل التي أعمل لديها إلى جانب المتطلبات القانونية الفيدرالية والولائية المعمول بها","أحتاج فقط إلى اتّباع ما يخبرني به المرسل عبر اللاسلكي وقت الحادث","نظراً لعدم وجود إصابات ووجود أضرار طفيفة فقط، لا يُطلب مني تقرير حادث رسمي","أبلّغ الشرطة المحلية فقط، لأن أوراق الشركة لا تنطبق على عمليات الحافلات السياحية"],"explanation":"أبلِغ عن الحادث باتّباع كل من إجراءات شركة النقل التي تعمل لديها والمتطلبات القانونية الفيدرالية والولائية المعمول بها."},"188":{"q":"حافلة النقل العام المدينية التي أقودها ممتلئة في ساعة الذروة، لذا يقف عدة ركاب خلف خط الوقوف الأبيض أثناء قيادتي. يسألني راكب عن مدى خطورة الركوب واقفاً مقابل الجلوس. مقارنة بالراكب الجالس، كيف يؤثر الوقوف على سلامة ذلك الراكب إذا اضطررت إلى التوقف المفاجئ أو تعرضت لحادث؟","options":["الوقوف خلف خط الوقوف يزيل الخطر، لذا لا يواجه الراكب الواقف فعلياً أي خطر حقيقي في التوقف المفاجئ","يواجه الراكب الواقف خطراً أكبر من الجالس، لأن التوقف أو الحادث المفاجئ يمكن أن يندفع به إلى الأمام داخل الحافلة","الوقوف يضع الراكب في الواقع في خطر أقل، لأنه يستطيع أن يثبّت نفسه ويمتص الصدمة بشكل أفضل","يواجه الراكب الواقف خطراً مماثلاً تقريباً لخطر الراكب الجالس، طالما بقي خلف خط الوقوف"],"explanation":"الراكب الواقف في خطر أكبر من الجالس لأن التوقف أو الحادث المفاجئ يمكن أن يندفع به إلى الأمام داخل الحافلة."},"189":{"q":"أنا أقود حافلة نقل عام بطول 40 قدماً وأبطئ لإجراء انعطاف يمين ضيق عند تقاطع في وسط المدينة حيث تصطف الحافة بالمشاة وتقف شاحنة توصيل بعد الزاوية مباشرة. عند أي نقطة في هذه المناورة أحتاج أكثر إلى مراقبة مؤخرة حافلتي، لأنها قد تتأرجح إلى المسار التالي أو تصطدم بأجسام خلف نقطة الارتكاز؟","options":["فقط بينما تكون الحافلة متوقفة عند الحافة، لأن ذلك هو الوقت الذي يمشي فيه الناس أقرب إلى جسم الحافلة","فقط بينما أكون متوقفاً عند الإشارة الحمراء، لأن الركاب قد ينزلون إلى حركة المرور بجانبي","أثناء الانعطاف، لأن مؤخرة الحافلة الطويلة تتأرجح إلى الخارج بشكل واسع وقد تصطدم بمركبات أو أجسام أو أشخاص خلفي","فقط أثناء التزود بالوقود، لأن الجسم الطويل يمتد بعد المضخات وإلى المسار المجاور"],"explanation":"راقب المؤخرة أثناء الانعطاف لأن ذيل الحافلة الطويلة يتأرجح إلى الخارج بشكل واسع وقد يصطدم بمركبات أو أجسام أو أشخاص خلفك."},"190":{"q":"أنت تقود حافلة سياحية عالية على مسار غير مألوف، ويرسلك التحويلة نحو منطقة قديمة في وسط المدينة بها نفق سفلي ضيق ومدخل لمرآب سيارات وأغصان أشجار متدلية فوق مسار الحافة. بسبب سقف مركبتك العالي، أي خطر ينبغي أن تقلق منه أكثر بينما تقترب من هذه المنشآت؟","options":["المياه الراكدة العميقة المتجمعة تحت النفق السفلي بعد المطر","ضجيج المحرك العالي المتردد عن المباني المحيطة","وهج الشمس الساطع المنعكس عن نوافذ مرآب السيارات","انخفاض المسافة العلوية عند النفق السفلي ومدخل المرآب"],"explanation":"بسبب السقف العالي للحافلة، احذر من انخفاض المسافة العلوية عند الأنفاق السفلية ومداخل المرائب والأغصان المتدلية."},"191":{"q":"إنه مسار مزدحم في مساء الجمعة، وبينما يصعد كل راكب أرحّب به وأراقبه وهو يتحرك في الممر نحو مقعده. يسألني متدرب يركب معي لماذا أتكبد عناء فعل هذا عند كل صعود بدلاً من مجرد جمع الأجرة والمضي قدماً. ما السبب الأفضل للترحيب بركابي ومراقبتهم؟","options":["مراقبة الركاب وهم يصعدون تساعدني على الحفاظ على النظام في الحافلة ورصد مشكلات السلامة قبل أن تتفاقم","يسرّع جمع الأجرة حتى أبقى في الموعد وأعوّض أي وقت ضائع في المحطة التالية","إنه شرط مجاملة يفرضه القانون عند كل صعود بصرف النظر عن اعتبارات السلامة","يتيح لي أن أقرر أي الركاب قد يقفون أمام خط الوقوف خلال ذروة الازدحام"],"explanation":"مراقبة الركاب وهم يصعدون تتيح لك رصد المواقف المزعجة أو غير المستقرة أو الخطرة مبكراً والحفاظ على النظام في الحافلة."},"192":{"q":"أنا أقود حافلة نقل عام محملة وأتوقف عند محطة استراحة وسطية. أنوي النهوض من مقعدي لمساعدة راكب مسن على المصعد والتأكد من عدم خطو أحد إلى حركة المرور. أي إجراء يجب أن أكمله أولاً، قبل أن أغادر مقعد السائق؟","options":["النقر على البوق مرتين لتحذير الركاب القريبين من أن الأبواب على وشك الفتح","تفعيل مكبح الانتظار حتى تبقى الحافلة مؤمّنة قبل أن أنهض","تشغيل إشارة الانعطاف اليمنى لتنبيه حركة المرور بأنني سأنطلق","تحرير دواسة مكبح الخدمة حتى يتمكن نظام الهواء من إعادة الشحن"],"explanation":"فعّل مكبح الانتظار قبل مغادرة مقعدك حتى لا تتدحرج الحافلة بينما يصعد الركاب أو ينزلون أو يتحركون في الممر."},"193":{"q":"أنا أقود حافلة نقل عام وأتوقف عند محطة استراحة وسطية. أحوّل إلى الوضع المحايد، وأترك المحرك يعمل في وضع الخمول حتى يبقى مكيف الهواء يعمل، وأنهض لأتراجع وأساعد راكباً مسناً على الوصول إلى الباب قبل أن يبدأ أي راكب بالتحرك في الممر. فيما يخص مكبح الانتظار عند هذه النقطة، ماذا تتطلب مني إدارة السلامة العامة في تكساس؟","options":["تفعيل مكبح الانتظار اختياري هنا، لأن ناقل الحركة في الوضع المحايد بالفعل والحافلة على رصيف مستوٍ.","يمكنني ترك مكبح الانتظار غير مفعّل طالما بقي المحرك يعمل وقدمي تستطيع الوصول بسرعة إلى مكبح الخدمة.","يجب أن أفعّل مكبح الانتظار لتأمين الحافلة قبل أن أغادر مقعدي أو أدع أي راكب يبدأ بالتحرك.","تفعيل مكبح الانتظار غير محبّذ بينما يعمل المحرك في وضع الخمول، لأنه قد يسخّن أسطوانات المكابح الخلفية."],"explanation":"عند محطات الاستراحة والمحطات الوسطية يجب أن تفعّل مكبح الانتظار قبل مغادرة مقعدك أو السماح لأي راكب بالتحرك في الممر."},"194":{"q":"أنا أقود حافلة نقل عام محملة على الطريق السريع عندما يبدأ مطر مستمر فيصبح الرصيف زلقاً. حركة المرور حولي لا تزال تسير بحد السرعة المقرر البالغ 55 ميلاً في الساعة. للحفاظ على سلامة ركابي، كيف ينبغي أن أدير سرعتي في هذه الظروف؟","options":["مطابقة الحد المقرر تماماً، لأن القيادة أبطأ من تدفق حركة المرور هي ما يسبب الحوادث فعلاً","الحفاظ على سرعة ثابتة أعلى قليلاً من الحد لتجاوز المقطع المبلل والوصول إلى رصيف جاف أسرع","مواكبة حركة المرور المحيطة حتى لا أصبح عائقاً يضطر السائقون الآخرون إلى الكبح من أجله","تخفيض سرعتي إلى ما دون الحد المقرر لمراعاة مسافة التوقف الأطول على الطريق المبلل"],"explanation":"الرصيف المبلل يطيل مسافة التوقف ويقلل التماسك، لذا خفّض السرعة إلى ما دون الحد المقرر بصرف النظر عن حركة المرور المحيطة."},"195":{"q":"أنا أقود حافلة نقل عام محملة بالكامل وأوشك على بدء النزول على منحدر طويل وشديد الانحدار. للحفاظ على أكثر تحكّم متّسق في الكبح وتجنب فرط تسخين مكابح الخدمة أثناء النزول، أي وضع لناقل الحركة ينبغي أن أكون فيه قبل أن أبدأ النزول؟","options":["اختيار سرعة منخفضة قبل بدء النزول حتى يساعد كبح المحرك على التحكم في سرعتي طوال المنحدر","البقاء في أعلى سرعة حتى يدور المحرك ببطء وأتمكن من الانزلاق بسلاسة على المنحدر","التحويل إلى الوضع المحايد والضغط على مكابح الخدمة بخفة طوال الطريق نزولاً","الإبقاء على السرعة التي كانت لدي على المستوي والتخفيض فقط إذا ارتفعت سرعتي كثيراً في منتصف المنحدر"],"explanation":"اختر سرعة منخفضة قبل بدء النزول على منحدر حتى يساعد كبح المحرك على التحكم في السرعة طوال النزول ويوفّر مكابح الخدمة."},"196":{"q":"أنت تقود حافلة نقل عام محملة على مسارك المعتاد. خلال الميل التالي ستمر عبر أربعة مواقع. عند أي منها يُطلب منك إيقاف الحافلة تماماً والنظر والإصغاء قبل المتابعة؟","options":["تقاطع رباعي حيث لديك إشارة مرور خضراء ثابتة","معبر سكة حديد نشط دون إشارة خضراء أو حاجز أو موجّه يدير مرورك","معبر سكة حديد معفى مميّز بلافتة «معفى» رسمية","معبر فرعي صناعي حيث يلوّح لك موجّه متمركز بالعبور"],"explanation":"يجب أن تتوقف الحافلة على مسافة 15 إلى 50 قدماً قبل معبر سكة حديد نشط عندما لا يأذن لها شيء بالمتابعة، لا إشارة خضراء ولا حاجز ولا موجّه."},"197":{"q":"أنت تقود حافلة نقل عام مدينية مع عدة ركاب واقفين يمسكون القضبان العلوية خلف خط الوقوف. تتحول إشارة أمامك إلى الأصفر بينما تقترب من التقاطع. أي من الإجراءات التالية هو الأكثر احتمالاً لإفقاد ركابك الواقفين توازنهم أو التسبب بإصابة؟","options":["رفع قدمك عن دواسة الوقود مبكراً حتى تنزلق الحافلة إلى توقف سلس","الإعلان عن المحطة القادمة حتى يتمكن الواقفون من التثبت وتعديل قبضتهم","الضغط على دواسة المكابح بقوة للتوقف بسرعة، ثم التسارع بحدة عند تحول الإشارة","الحفاظ على سرعة ثابتة والتوجيه بسلاسة عبر تغييرات مسار لطيفة"],"explanation":"اكبح بسلاسة، لأن التوقفات القوية والتسارع الحاد يفقدان الركاب الواقفين توازنهم وقد يسببان إصابة."},"198":{"q":"أنا أقود حافلة نقل عام ممتلئة على مساري المعتاد. حركة المرور كثيفة، وأنا متأخر نحو ست دقائق عن الموعد، وبعض الركاب يقفون خلف خط الوقوف. بناءً على ما يحدّد السائق المحترف للحافلة، كيف ينبغي أن أتعامل مع بقية رحلتي؟","options":["التسارع بقوة بين المحطات والكبح بحزم عند كل محطة لاستعادة الدقائق الضائعة، لأن الواقفين خلف خط الوقوف بالفعل","البقاء مسترخياً عبر الدردشة مع الركاب الأماميين حول التأخير حتى تبدو بيئة الحافلة المتحركة أقل توتراً للجميع","تعويض الوقت بتخطي إعلانات الأخطار والمرور عبر المحطات أسرع، مع تركيز اهتمامي على الساعة فقط","البقاء هادئاً ومتيقظاً، وإبقاء عينيّ تمسحان الطريق أمامي، والكبح بسلاسة حتى لا يندفع الركاب الواقفون إلى الأمام"],"explanation":"ابقَ هادئاً ومتيقظاً، وامسح الطريق أمامك، واكبح بسلاسة حتى لا يندفع الركاب الواقفون إلى الأمام، فالتأخر عن الموعد لا يبرر تجاوز ذلك أبداً."},"199":{"q":"أنا سائق حافلة سياحية جديد، ومدربي يذكّرني باستمرار بأن أكبح بسلاسة وأعلن عن المحطات وأبقي الممر خالياً من الأمتعة اليدوية. عندما أسأل لماذا تشدّد الشركة على كل هذه الإجراءات، ما السبب النهائي لوجود قواعد الركاب هذه؟","options":["لحماية سلامة الركاب وراحتهم","للحفاظ على سرعة الجدول الزمني حتى لا تتأخر الرحلة أبداً","لتقليل الأعمال الورقية للسائق في نهاية كل مناوبة","للتأكد من أن الحافلة تستهلك أقل قدر ممكن من الوقود"],"explanation":"كل قاعدة من قواعد التعامل مع الركاب، الكبح السلس والإعلان عن المحطات وتأمين الأمتعة اليدوية، موجودة لحماية سلامة الركاب وراحتهم."}},"schoolbus":{"0":{"q":"أنا أحمل بالفعل رخصة قيادة تجارية من الفئة ب مع تصديق الحافلة المدرسية (S)، وغداً أبدأ مساراً لأقلّ الطلاب وأنزلهم. قبل أن أقود تلك الحافلة المدرسية المحملة قانونياً، أي تصديق إضافي يجب أن يكون على رخصتي؟","options":["تصديق الركاب (P)، لأن الحافلة المدرسية تحمل ركاباً ويُطلب تصديق P بالإضافة إلى تصديق S.","لا شيء آخر، لأن تصديق S وحده يغطّي بالفعل نقل الطلاب على حافلة مدرسية.","تصديق الصهريج (N)، لأن الحافلة تحمل إمداداً كبيراً من الوقود للمسارات اليومية الطويلة.","تصديق دراجة نارية (M) منفصل، لأنه يثبت مهارة إضافية في قيادة مركبة كبيرة."],"explanation":"يتطلب قيادة الحافلة المدرسية تصديق الركاب (P) بالإضافة إلى تصديق الحافلة المدرسية (S)، لأن الحافلة تحمل ركاباً."},"1":{"q":"أراجع إحصائيات السلامة أثناء تدريبي على قيادة الحافلة المدرسية وأريد أن أركز انتباهي حيث يواجه الطلاب أكبر خطر للوفاة أو الإصابة. وفقاً لإرشادات إدارة السلامة العامة في تكساس (DPS)، في أي جزء من مساري اليومي يجب أن أكون أكثر يقظة لمنع وفيات الطلاب؟","options":["أثناء عبور سكة الحديد، حيث يجب أن أتوقف على بعد 15 إلى 50 قدماً قبل القضبان","أثناء صعود الطلاب ونزولهم، عندما يكونون في منطقة الخطر بالقرب من الحافلة","أثناء القيادة على مسافات طويلة من الطريق السريع المفتوح، حيث تكون السرعات أعلى","أثناء رجوع الحافلة للخلف في موقف السيارات، حتى مع وجود مراقب يوجهني"],"explanation":"يُعدّ صعود الطلاب ونزولهم الجزء الأكثر خطورة من العمل، إذ تحدث معظم وفيات الحافلات المدرسية عندما يكون الطلاب في منطقة الخطر بالقرب من الحافلة."},"2":{"q":"توقفت لإنزال الركاب وأريد أن أبقي كل طالب بأمان ضمن منطقة يمكنني مراقبتها. مع معرفتي بمكان بداية منطقة الخطر حول حافلتي المدرسية، إلى أي مسافة من الحافلة يجب أن أعتبرها منطقة عالية الخطورة قد يقف فيها طفل ضمن نقطة عمياء؟","options":["حوالي قدم واحدة فقط، لأن مراياي تغطي كل شيء بعد خط المصد","حوالي 3 أقدام على كل جانب، بعد المكان الذي ينفتح فيه الباب بقليل","حوالي 10 أقدام على جميع جوانب الحافلة، الأمام والخلف والجانبين","لا توجد منطقة خطر محددة طالما أن أضوائي الحمراء وذراع التوقف مفعّلة"],"explanation":"تمتد منطقة الخطر حوالي 10 أقدام على جميع جوانب الحافلة—الأمام والخلف والجانبين—حيث قد يقف الأطفال دون أن يراهم السائق."},"3":{"q":"أقوم بفحص ما قبل الرحلة وأضبط مرايا حافلتي المدرسية حتى أتمكن من مراقبة منطقتي الخطر الأمامية والجانبية وإبقاء كل طالب ضمن مجال رؤيتي، خاصة الأطفال الذين يعبرون على بعد حوالي 10 أقدام أمام الحافلة. أي مجموعة من المرايا مصممة لمنحي تلك التغطية الكاملة؟","options":["المرآتان الجانبيتان المسطحتان الكبيرتان وحدهما، لأنهما تظهران الخلف وعلى طول جانبي الحافلة","المرايا المحدبة وحدها، لأن زاويتها الواسعة تغطي المنطقة بأكملها حول الحافلة","كاميرا رجوع خلفية ومرآة داخلية علوية، اللتان تراقبان معاً منطقة التحميل","المرايا الخارجية اليسرى واليمنى المسطحة والمحدبة مع مرايا العبور"],"explanation":"يجب استخدام المرايا الخارجية اليسرى/اليمنى المسطحة والمحدبة مع مرايا العبور، إذ لا توجد مرآة واحدة تغطي جميع مناطق الخطر الأمامية والجانبية."},"4":{"q":"عند اقترابك من محطة التوقف، فإنك تفعّل أولاً:","options":["الأضواء الحمراء الوامضة","الأضواء التحذيرية الكهرمانية (الصفراء)","ذراع التوقف","المنبه"],"explanation":"فعّل الأضواء الكهرمانية على بعد حوالي 200 قدم (أو حسب قانون الولاية) قبل المحطة، ثم الأضواء الحمراء عند المحطة."},"5":{"q":"تقترب من محطة توقف محددة لاصطحاب ثلاثة طلاب. كانت أضواؤك التحذيرية الكهرمانية تومض منذ ما قبل المحطة بكثير، وقد توقفت الآن توقفاً تاماً عند الرصيف. لكي تُلزم قانونياً حركة المرور القادمة من كلا الاتجاهين بالتوقف أثناء صعود الطلاب، أي إجراء يجب أن تتخذه الآن؟","options":["تشغيل الأضواء الحمراء الوامضة ومدّ ذراع التوقف","إطفاء الأضواء الكهرمانية وتشغيل أضواء الطوارئ الرباعية","الإبقاء على الأضواء التحذيرية الكهرمانية وامضة فقط وفتح باب الخدمة","إطلاق المنبه مرتين وتومض المصابيح الأمامية العالية للسيارات القادمة"],"explanation":"بمجرد التوقف لتحميل الطلاب أو إنزالهم، فعّل الأضواء الحمراء الوامضة ومدّ ذراع التوقف، فهما معاً يُلزمان قانونياً حركة المرور من كلا الاتجاهين بالتوقف."},"6":{"q":"أنا عند محطة توقف محددة مع تفعيل أضوائي الحمراء الوامضة وذراع التوقف، وتنتظر مجموعة من الطلاب على الرصيف للصعود. وفقاً لإجراءات تحميل الحافلات المدرسية في تكساس، متى يجب أن أسمح لهؤلاء الطلاب بالبدء بالاقتراب والصعود إلى الحافلة؟","options":["بمجرد أن تبطئ الحافلة وتبدأ الأضواء الحمراء بالوميض عند الاقتراب","فقط بعد أن تتوقف الحافلة توقفاً تاماً عند نقطة التحميل","بمجرد أن تتدحرج الحافلة ببطء نحو موضع التوقف النهائي","بمجرد تفعيل الأضواء التحذيرية الكهرمانية قبل المحطة"],"explanation":"يجب ألا يقترب الطلاب أو يصعدوا أبداً حتى تتوقف الحافلة توقفاً تاماً عند نقطة التحميل مع تفعيل مكابح التوقف."},"7":{"q":"توقفت لإنزال الركاب، والأضواء الحمراء وذراع التوقف مفعّلة، ويحتاج طالب يسكن على الجانب الآخر من الطريق إلى العبور. لإبقاء ذلك الطالب خارج منطقة الخطر حيث يمكنك إبقاؤه ضمن مجال رؤيتك، أين يجب أن توجهه ليعبر؟","options":["مباشرة عبر الباب، بمحاذاة جانب الحافلة","خلف المصد الخلفي بعد نزول بقية الركاب","من الأمام، على بعد حوالي 10 أقدام أمام الحافلة، حيث يمكنك رؤيته","على طول الكتف البعيد حتى يبتعد تماماً عن الحافلة"],"explanation":"وجّه الطالب الذي يعبر للمشي على بعد حوالي 10 أقدام أمام الحافلة، بمسافة كافية للابتعاد عن منطقة الخطر الأمامية مع بقائه ضمن مجال رؤيتك."},"8":{"q":"أخرج بحافلتي من موقف مدرسة مزدحم وأدرك أنني تجاوزت المدخل. المخرج خلفي مباشرة. أي إجراء يعكس الإجراء الصحيح للحافلة المدرسية وفقاً لإدارة السلامة العامة (DPS) في هذا الموقف؟","options":["الرجوع للخلف فوراً، لأن الرجوع في موقف السيارات هو الطريقة المتوقعة لإعادة وضع الحافلة","الرجوع للخلف بحرية طالما لا يوجد طلاب على متن الحافلة حالياً","الرجوع للخلف بسرعة عادية، معتمداً فقط على مراياك الخارجية المحدبة لتبقى بعيداً عن العوائق","تجنب الرجوع للخلف قدر الإمكان؛ وإن تعذر ذلك، فضع مراقباً، وتحرك ببطء، وتأكد من خلو المؤخرة"],"explanation":"تجنب رجوع الحافلة المدرسية للخلف كلما أمكن؛ وإن كان لا بد منه، فضع مراقباً، وارجع ببطء، وتأكد من خلو المؤخرة قبل التحرك."},"9":{"q":"تقود حافلة مدرسية خالية من الركاب وتقترب من معبر سكة حديد غير محكوم بإشارات على طريق ريفي. لا يوجد قطار في الأفق والطريق خلفك خالٍ. أي إجراء مطلوب قبل أن تعبر بالحافلة فوق القضبان؟","options":["التوقف على بعد 15 إلى 50 قدماً قبل القضبان، وفتح باب الخدمة والنافذة، ثم النظر والاستماع قبل العبور","بما أن الحافلة فارغة، فأبطئ وتحقق من الاتجاهين، لكن توقف تماماً فقط إذا رأيت أو سمعت قطاراً","التوقف بعد القضيب الأول بقليل بحيث تتجاوز مراياك المعبر، ثم افتح الباب واستمع لصوت بوق","التوقف عند القضبان، ثم خفّض إلى ترس أدنى أثناء العبور حتى تكون الحافلة أقوى على القضبان"],"explanation":"عند سكة الحديد، توقف على بعد 15 إلى 50 قدماً قبل أقرب قضيب، وافتح باب الخدمة والنافذة، وانظر واستمع قبل العبور."},"10":{"q":"إنه نهاية مساري بعد الظهر. أنزلت آخر طالب، ودخلت الموقف، وفعّلت مكبح التوقف. تبدو الحافلة فارغة من مقعد السائق وأنا متأخر بالفعل عن مهمتي التالية. قبل أن أغادر الحافلة وأسلّمها، ماذا يجب أن أفعل؟","options":["أقفل باب الركاب وأتوجه مباشرة إلى المكتب، لأنني تأكدت من خلو الحافلة من مقعدي","أمشي بطول الممر بالكامل حتى الخلف، وأفحص كل مقعد بحثاً عن أطفال نائمين وأغراض منسية قبل الخروج","أنقل الحافلة إلى محطة الوقود وأملأ الخزان حتى تكون جاهزة لمسار الصباح","أطفئ الأضواء التحذيرية والمحرك، ثم أقود الحافلة الفارغة عائداً إلى الساحة فوراً"],"explanation":"يتطلب فحص الأطفال بعد الرحلة المشي بطول الممر بالكامل من الأمام إلى الخلف، وفحص كل مقعد بحثاً عن أطفال نائمين وأغراض منسية."},"11":{"q":"توقفت لتحميل الطلاب وخطا طفل صغير كان ينتظر عند الرصيف فجأة نحو المصد الأمامي، فاختفى عن مجال رؤيتك خلف غطاء المحرك. من بين المرايا المثبتة على حافلتك، أي مجموعة مصممة خصيصاً لتمكينك من التحقق من أن المنطقة الواقعة أمام الحافلة مباشرة خالية قبل أن تنطلق؟","options":["المرايا الخارجية المسطحة (مرايا الساحل الغربي)، التي تمنحك الرؤية الطويلة مباشرة إلى الخلف على طول جانبي الحافلة","المرايا الخارجية المحدبة، التي تغطي منطقة الخطر على طول الجانب الأيمن والعجلات الخلفية","مرايا العبور، التي تتيح لك رؤية منطقة الخطر الأمامية حيث يمكن لطفل صغير أن يختبئ منخفضاً فوق غطاء المحرك","المرآة الداخلية الخلفية، التي تتيح لك مراقبة الطلاب في الممر والمقاعد خلفك"],"explanation":"مرايا العبور موجّهة نحو منطقة الخطر الأمامية، مما يتيح لك رصد طفل صغير يقف منخفضاً فوق غطاء المحرك والذي كان سيختفي عن مجال رؤيتك لولا ذلك."},"12":{"q":"أنزلت للتو عدة طلاب عند محطة بعد الظهر. وبينما تجري العدّ، تدرك أن أحد الطلاب الذين نزلوا قد اختفى عن مجال رؤيتك بالقرب من مقدمة الجانب الأيمن من الحافلة. لا تزال الأضواء الحمراء وذراع التوقف مفعّلة وحركة المرور تنتظر. ماذا ينبغي أن تفعل؟","options":["تتقدم للأمام بضعة أقدام ببطء شديد حتى تتمكن من رصد الطالب المفقود قبل الانطلاق تماماً","تضغط على المنبه مرتين لإشارة الطالب بإخلاء المنطقة، ثم تتابع بمجرد أن تنفرج حركة المرور","تسحب ذراع التوقف وتنطلق برفق، مراقباً مرآة العبور بحثاً عن الطالب أثناء سيرك","تبقي الحافلة متوقفة، وتفعّل مكبح التوقف، وتحدد مكان الطالب المفقود قبل أن تتحرك على الإطلاق"],"explanation":"يجب ألا تتحرك الحافلة المدرسية أبداً حتى يُحصى كل طالب، لذا أمّنها بمكبح التوقف وحدد مكان الطالب المفقود أولاً."},"13":{"q":"أقود في مساري وأبدأ بالكبح من أجل محطة توقف قادمة ينتظر فيها طالبان. وبينما أبطئ، تضيء أضوائي التحذيرية الكهرمانية (الصفراء) الوامضة تلقائياً. ماذا تخبر هذه الأضواء الكهرمانية حركة المرور من حولي؟","options":["أن حافلتي تستعد للتوقف قريباً لتحميل الطلاب أو إنزالهم","أن حافلتي متوقفة بالفعل تماماً وأن الطلاب يعبرون الطريق الآن","أن حافلتي بها عطل ميكانيكي ويجري سحبها من الخدمة","أن حافلتي تسير ببطء بسبب حد سرعة في منطقة مدرسية"],"explanation":"تُفعّل الأضواء التحذيرية الكهرمانية على بعد حوالي 100-300 قدم قبل المحطة لتحذير حركة المرور بأن الحافلة تستعد للتوقف لتحميل الطلاب أو إنزالهم."},"14":{"q":"أصطحب ستة طلاب عند محطة صباحية ريفية. الكتف ضيق والأطفال متجمعون معاً ينتظرون بالقرب من صندوق بريد. لتحميلهم بأمان كما تتوقع إدارة السلامة العامة (DPS)، أي نهج يجب أن أتبعه؟","options":["بمجرد أن أبطئ، أُشير للمجموعة بالركض نحو الباب حتى لا نعيق حركة المرور، ثم أنطلق بمجرد صعود آخر واحد منهم","أُبقيهم منتظرين خارج الطريق حتى تتوقف الحافلة تماماً مع تفعيل الأضواء الحمراء وذراع التوقف، ثم أجعلهم يصعدون ويعبرون على بعد حوالي 10 أقدام أمام الحافلة حيث يمكنني رؤيتهم","أسمح لهم بالاقتراب على طول الجانب الأيمن ومؤخرة الحافلة حتى يبتعدوا عن حركة المرور القادمة قبل الصعود إلى الباب","بمجرد صعود الجميع، أتقدم للأمام دون إحصاء العدد لأنني أعلم بالفعل أن ستة كانوا مجدولين عند هذه المحطة"],"explanation":"يجب أن ينتظر الطلاب خارج الطريق حتى تتوقف الحافلة تماماً مع تفعيل الأضواء الحمراء وذراع التوقف، ثم يصعدون ويعبرون على بعد حوالي 10 أقدام أمام الحافلة ضمن مجال رؤية واضح."},"15":{"q":"أُخرج حافلتي المدرسية من محطة توقف عند الرصيف وأحتاج إلى الانعطاف يساراً بشكل حاد للاندماج في حركة المرور. هناك مشاة وسيارة متوقفة قريبة من الجزء الخلفي الأيمن من حافلتي. بسبب اندفاع المؤخرة (tail swing)، ما الذي يجب أن أكون أكثر قلقاً بشأنه عند بدء الانعطاف؟","options":["ستبقى مؤخرة الحافلة تتبع نفس مسار العجلات الأمامية، لذا فإن الجانب الأيمن خالٍ","سيندفع المصد الأمامي نحو المسار المقابل ويصطدم بالسيارة المتوقفة أمامه","ستندفع مؤخرة الحافلة إلى اليمين وقد تصطدم بالسيارة المتوقفة أو بالمشاة","ستصبح الحافلة أقصر بعدة أقدام، مما يقلل من مخاوف التدلي والخلوص"],"explanation":"في الانعطاف الحاد تندفع مؤخرة الحافلة إلى الجهة المعاكسة للانعطاف، لذا فإن الانعطاف يساراً يدفع المؤخرة يميناً نحو السيارة المتوقفة والمشاة."},"16":{"q":"استخدام الهاتف المحمول باليد أثناء القيادة هو:","options":["مُشجَّع عليه","محظور وغير آمن","مطلوب بموجب القانون","لا بأس به عند التوقف فقط"],"explanation":"لا تستخدم الهاتف المحمول باليد؛ فهو إلهاء خطير ومحظور عموماً."},"17":{"q":"أثناء فحص ما قبل الرحلة، ألاحظ أن باب مخرج الطوارئ الخلفي يصعب دفعه للفتح، وأن أحد مخارج النوافذ الجانبية محجوب جزئياً بكومة من المعدات المخزّنة. قبل أن أستقبل الطلاب، ماذا يجب أن أفعل بشأن مخارج الطوارئ هذه؟","options":["أترك الباب الخلفي على حاله لأن باب الخدمة الأمامي هو الطريقة الأساسية لنزول الطلاب من الحافلة يومياً","أُحكم إغلاق الباب الخلفي وأضع لافتة حتى يبتعد الطلاب عنه أثناء سير الحافلة","أنقل المعدات لكن أترك الباب الخلفي المتيبس، لأن مخرجاً واحداً صالحاً يكفي للإخلاء","أُخلي مخرج النافذة المحجوب وأجعل الباب الخلفي يُفتح بسهولة، مع إبقاء كل مخارج الطوارئ مفحوصة وصالحة للاستخدام"],"explanation":"يجب إبقاء جميع مخارج الطوارئ صالحة للعمل وغير معاقة أثناء فحص ما قبل الرحلة، لذا يجب إصلاح مخرج النافذة المحجوب والباب الخلفي المتيبس كليهما قبل صعود الطلاب."},"18":{"q":"أنزلت للتو الركاب عند محطة توقف. لا يزال طالبان يمشيان عابرين أمام حافلتك، داخل منطقة الخطر تماماً، ولم يكتمل عدّك بعد. حركة المرور خلفك تطلق المنبهات وجدولك متأخر. ماذا ينبغي أن تفعل؟","options":["تبقي الحافلة متوقفة تماماً ولا تتحرك حتى يبتعد كل طالب عن منطقة الخطر ويُحصى","تبدأ بدفع الحافلة للأمام ببطء لأن الطلاب يرونك وسيتنحون جانباً أثناء سيرك","تتقدم للأمام بمجرد وصول الطلاب إلى الرصيف، حتى لو كان عدّك لا يزال ناقصاً واحداً","تُشير للطلاب بالإسراع، ثم تندمج في حركة المرور بمجرد أن تبدأ السيارات التي تطلق المنبهات بالمرور"],"explanation":"يُعدّ التحميل والإنزال المهمة الأكثر خطورة، لذا يجب أن تبقى الحافلة متوقفة تماماً حتى يبتعد كل طالب عن منطقة الخطر ويُحصى، بغض النظر عن الضغوط الخارجية."},"19":{"q":"أقود حافلتي المدرسية في مسار صباحي مع بداية الشتاء وقد حلّ ضباب كثيف يقلل الرؤية على الطريق السريع الريفي. حافلتي مزودة بضوء وامض (ستروب) مثبت على السقف. في أي من هذه الحالات يوفر الضوء الوامض أكبر فائدة للسلامة؟","options":["في رحلة صافية ومشرقة منتصف النهار حين تكون الشمس فوق الرأس مباشرة","في الضباب الكثيف أو غيره من ظروف انخفاض الرؤية، حتى يتمكن السائقون الآخرون من رؤية الحافلة من مسافة أبعد","عند عبور موقف سيارات خالٍ جيد الإضاءة حيث لا توجد حركة مرور أخرى","فقط أثناء المرور عبر أنفاق الطريق السريع حيث توجد إضاءة علوية بالفعل"],"explanation":"يجب استخدام الضوء الوامض (الستروب) المثبت على السقف في الضباب الكثيف أو غيره من ظروف انخفاض الرؤية حتى يتمكن السائقون الآخرون من رصد الحافلة من مسافة أبعد."},"20":{"q":"تشمّ رائحة دخان قادمة من مؤخرة حافلتك المدرسية المحمّلة وتتوقف على الكتف. بعد تفعيل مكبح التوقف، ما هي أفضل طريقة لإخراج طلابك بأمان؟","options":["إخبار الطلاب بالبقاء في مقاعدهم والحفاظ على هدوئهم بينما تنتظر وصول قسم الإطفاء","الخروج من الحافلة أولاً بنفسك حتى تقف في الخارج وتنادي كل طالب للنزول واحداً تلو الآخر","قيادة إخلاء منظم عبر أكثر المخارج أماناً وإبعاد الطلاب جيداً عن الحافلة إلى مكان آمن","فتح النوافذ على أحد جانبي الحافلة لإزالة الدخان قبل أن تقرر ما إذا كان أحد بحاجة للمغادرة"],"explanation":"عند وجود خطر حقيقي مثل الدخان أو الحريق، أمّن الحافلة وقُد إخلاءً منظماً عبر أكثر المخارج أماناً، مُبعداً الطلاب جيداً إلى مكان آمن."},"21":{"q":"أنزلت عدة طلاب عند محطة بعد الظهر، وعلى بعضهم العبور أمام حافلتي للوصول إلى الجانب الآخر من الطريق. قبل أن أُطفئ الأضواء الحمراء وأنطلق، لماذا يكون من الأهم أن أعدّ الطلاب؟","options":["حتى أسجّل كم راكباً صعد ونزل لتقرير الوقود والمسافة اليومي","حتى أبدأ بالتحرك أسرع بمجرد أن تبدأ الأضواء التحذيرية الكهرمانية بالوميض مجدداً","حتى أعتمد على العدّ بدلاً من إعادة فحص مرايا العبور والمرايا الجانبية","حتى أتأكد من أن كل طالب أنهى عبوره وابتعد عن منطقة الخطر قبل أن أتحرك"],"explanation":"يتيح لك عدّ الطلاب عند الصعود والنزول التأكد من أن كل طفل أنهى عبوره وابتعد عن منطقة الخطر قبل أن تتحرك، إذ يُقتل معظمهم بحافلتهم نفسها."},"22":{"q":"الساعة 6:15 صباحاً وأنا متأخر عن مساري الصباحي. لتوفير الوقت، أشعر بإغراء تخطي جزء من جولة الفحص حول الحافلة. وفقاً لمتطلبات فحص ما قبل الرحلة للحافلة المدرسية في تكساس، أي مجموعة من العناصر لا يزال يتعين عليّ التحقق من عملها قبل أن أخرج من الساحة؟","options":["المرايا، وجميع الأضواء التحذيرية، وذراع التوقف، ومخارج الطوارئ","المرايا، والإطارات والعجلات، وسخّان المقصورة فقط","فقط العناصر الفريدة للحافلة: ذراع التوقف والأضواء الحمراء الوامضة","لا شيء إضافي يتجاوز فحص ما قبل الرحلة لشاحنة عادية، لأن الحافلة اجتازت الفحص الأسبوع الماضي"],"explanation":"قبل كل مسار يجب أن تتحقق من أن المرايا، وجميع الأضواء التحذيرية، وذراع التوقف، ومخارج الطوارئ تعمل لحماية الركاب والأطفال."},"23":{"q":"توقفت لإنزال الركاب، والأضواء الحمراء وامضة وذراع التوقف ممدود. وبينما تنزل طفلة عمرها 7 سنوات، تسقط علبة غدائها فتتدحرج تحت الحافلة بالقرب من العجلة الأمامية اليمنى. تستدير وتنظر إليك تسألك عما تفعل. ماذا ينبغي أن تأمرها أن تفعل؟","options":["أخبرها أن تنحني وتمدّ ذراعها بسرعة تحت الحافلة لتمسك بها بينما تُبقي الحافلة ثابتة","أخبرها أن تتركها مكانها، وتبتعد عن منطقة الخطر، ودعها لك تستعيدها بعد أن تبتعد","أخبرها أن تنتظر خلف العجلات الخلفية حتى تُغلق الباب، ثم تمدّ يدها إليها","أخبرها أن تزحف من الأمام لتبقى ضمن مجال رؤية مرآة العبور طوال الوقت"],"explanation":"يجب ألا يمدّ الطالب يده تحت الحافلة أو بالقرب منها أو خلفها أبداً لالتقاط غرض ساقط؛ اجعلهم يبتعدون عن منطقة الخطر واستعد الغرض بنفسك."},"24":{"q":"أوقفت حافلتي المدرسية على طريق ثنائي المسار، وشغّلت أضوائي الحمراء الوامضة، ومددت ذراع التوقف بينما تبدأ مجموعة من الطلاب بعبور الطريق. سائق قادم من الاتجاه المعاكس يرى كل هذا. وفقاً لقوانين تكساس، ما الذي يُلزم به ذلك السائق القادم قانونياً؟","options":["الإبطاء إلى زحف والمرور بجانب الحافلة من الجهة البعيدة، لأن الأطفال يعبرون نحو بابي","المتابعة بسرعة منخفضة لأن حركة المرور القادمة من الجهة المقابلة لا تتأثر بذراع التوقف","التوقف توقفاً تاماً والبقاء متوقفاً حتى تنطفئ الأضواء الحمراء ويُطوى ذراع التوقف","التعامل مع الأضواء الحمراء كإشارة \"أعطِ الأولوية\" والمتابعة فقط بعد أن يخطو آخر طالب على الرصيف"],"explanation":"عند وميض الأضواء الحمراء للحافلة ومدّ ذراع التوقف، يجب على جميع حركة المرور المتأثرة التوقف توقفاً تاماً والبقاء متوقفة حتى تنطفئ الأضواء ويُطوى الذراع."},"25":{"q":"انتهيت للتو من إنزال الطلاب عند محطة سكنية. وبينما أجري العدّ بعد الإنزال، أدرك أن إحدى الطفلات اللواتي نزلن لم تعد في مكان ما ضمن مراياي ولا أستطيع رؤية أين ذهبت. لا تزال الأضواء الحمراء وذراع التوقف مفعّلة وحركة المرور تنتظر. ماذا ينبغي أن أفعل؟","options":["أفترض أنها وصلت بالفعل إلى الرصيف بأمان وأنطلق حتى لا تتأخر حركة المرور المنتظرة أكثر","أحرّك الحافلة للأمام ببطء شديد، لأن التحرك بسرعة الزحف يمنح أي طفل قرب الحافلة وقتاً للابتعاد","أضغط على المنبه مرتين كتحذير ثم أتابع، لأن الصوت سينبهها للابتعاد عن الحافلة","أُبقي الحافلة مؤمَّنة بالمكبح المفعّل ولا أتحرك على الإطلاق حتى أحدد مكانها بصرياً وتكون بعيدة عن منطقة الخطر"],"explanation":"إذا اختفى طالب عن مجال رؤيتك، أبقِ الحافلة مؤمَّنة بالمكبح المفعّل ولا تتحرك حتى تحدد مكان الطفل بصرياً بعيداً عن منطقة الخطر."},"26":{"q":"أنا متوقف عند محطة مع تشغيل أضواءي الحمراء وذراع التوقف ممدودة، وطالب أنزلته للتو سار باتجاه المصد الأمامي لكنه لم يعد مرئيًا في أي من مراياي. لماذا تكون المنطقة المحيطة مباشرة بحافلتي، أي منطقة الخطر، شديدة الخطورة في هذه اللحظة؟","options":["يمكن للأطفال الصغار الوقوف في منطقة الخطر قرب الحافلة حيث لا يمكنني ببساطة رؤيتهم من مقعد السائق","لا تصبح منطقة الخطر خطرة إلا بعد أن أحرر فرملة الانتظار وأبدأ بالتحرك للأمام","تلغي مراياي العابرة والمحدبة كل نقطة عمياء، لذا فإن الخطر ناتج فقط عن المرور العابر","منطقة الخطر خطرة فقط لأن سائقين آخرين قد يتجاوزون أضوائي الحمراء الوامضة بشكل غير قانوني"],"explanation":"يمكن للطفل الصغير الواقف قرب الحافلة أن ينخفض تحت خط نظر السائق وخارج المرايا، مما يجعل منطقة الخطر المكان الذي يكون فيه الأطفال أكثر عرضة للخطر."},"27":{"q":"أنا متوقف مع وميض أضوائي الحمراء وذراع التوقف ممدودة، ومجموعة من الطلاب بحاجة لعبور الطريق لركوب حافلتي. إنهم ينتظرون على الرصيف يراقبونني. بعد أن أتبادل النظر معهم، ماذا ينبغي أن أفعل قبل أن يخطوا إلى الطريق أمام الحافلة؟","options":["ألوّح لهم بالعبور فورًا لإبقاء التوقف قصيرًا، بما أن أضوائي الحمراء قد أوقفت المرور بالفعل","أتفحص جميع مراياي والمنطقة العابرة، وأتأكد من توقف المرور تمامًا، وعندها فقط أشير لهم بأن العبور آمن","أطلب منهم العبور خلف الحافلة حيث توفر لهم أضوائي الحمراء أكبر حماية من السيارات القادمة","أتقدم بضعة أقدام ليكون مسارهم أقصر، ثم أشير لهم بالعبور"],"explanation":"تبادل النظر وحده غير كافٍ؛ تفحص جميع المرايا والمنطقة العابرة، وتأكد من توقف كل المرور تمامًا، وعندها فقط أشر للطلاب بأن العبور آمن."},"28":{"q":"أثناء فحص المرايا قبل الرحلة، ألقي نظرة على المرايا المحدبة المثبتة أسفل المرايا الخارجية المسطحة. يبدو طالب واقف قرب الجانب الخلفي الأيمن من حافلتي صغيرًا ويبدو أبعد مما أتوقع. قبل أن أعتمد على هذه المرايا لإبقاء الطلاب في مجال الرؤية، ماذا ينبغي أن أفهم عن كيفية عرض المرآة المحدبة لما أراه؟","options":["تُظهر مجال رؤية أضيق لكن مُكبَّر، لذا فإن أي طالب فيها هو في الواقع أقرب مما يبدو","تُظهر نفس مجال رؤية المرآة المسطحة، فقط أكثر سطوعًا، لذا تظهر المسافات متطابقة تمامًا في كلتيهما","تُظهر مجال رؤية أوسع، لكن الأشياء تبدو أصغر وأبعد مما هي عليه في الواقع","تُظهر فقط المنطقة خلف المصد الخلفي مباشرة، لذا لن يظهر فيها طالب على الجانب"],"explanation":"تعطي المرآة المحدبة مجال رؤية أوسع، لكنها تضغط الصورة فتبدو الأشياء أصغر وأبعد مما هي عليه في الواقع."},"29":{"q":"أنت تقود حافلة مدرسية فارغة عائدًا إلى المرآب في نهاية مسارك وتقترب من معبر للسكة الحديد في فترة ما بعد ظهيرة صافية. تنظر في كلا الاتجاهين، وترى أن القضبان مستقيمة لمسافة طويلة، ولا يوجد أي قطار في الأفق. وفقًا لقواعد إدارة السلامة العامة في تكساس، ماذا يجب أن تفعل؟","options":["تمر ببطء عبر المعبر دون توقف كامل، بما أنك ترى بوضوح أنه لا يوجد قطار قادم","تتعامل معه كتقاطع عادي وتتابع، لأن الحافلة فارغة ولا تحمل أي طلاب","تتوقف فقط إذا كان المعبر مزودًا بأضواء أو بوابات مُفعَّلة وتشير إلى قدوم قطار","تتوقف بين 15 و50 قدمًا قبل القضبان، وتفتح الباب والنافذة، وتنظر وتستمع، حتى لو لم يكن هناك قطار في الأفق"],"explanation":"عند كل معبر للسكة الحديد يجب أن تتوقف بين 15 و50 قدمًا قبل القضبان، وتفتح الباب والنافذة، وتنظر وتستمع حتى لو لم يكن هناك قطار في الأفق."},"30":{"q":"أنا متوقف لتحميل ثلاثة طلاب عند محطة في زاوية مع تفعيل أضوائي الحمراء وذراع التوقف. يقف أحد الطلاب على الرصيف خلف المصد الخلفي، منتظرًا أن ألوّح له بالصعود. قبل أن أسمح لأي منهم بالصعود، إلى أين ينبغي أن أوجّه هذا الطالب؟","options":["إلى مكان أمام الحافلة على جهة الرصيف، يكون مرئيًا بوضوح عبر زجاجي الأمامي ومرآتي العابرة","أن يبقى قريبًا خلف المصد الخلفي حتى لا يتمكن المرور العابر على الطريق من الدخول بينه وبين الباب","إلى الجانب الأيسر قرب نافذة السائق حتى أتمكن من التحدث إليه مباشرة قبل أن يصعد","أن يمشي بين العجلتين الأماميتين بمحاذاة هيكل الحافلة حيث يحميه ذراع التوقف"],"explanation":"وجّه الطلاب للصعود من مكان أمام الحافلة على جهة الرصيف، يكون مرئيًا بوضوح عبر زجاجك الأمامي ومرآتك العابرة."},"31":{"q":"أنا متوقف على طريق ذي مسارين مع وميض أضوائي الحمراء وذراع التوقف ممدودة، وثلاثة طلاب على الرصيف بحاجة لعبور الطريق أمام حافلتي للوصول إلى منازلهم على الجانب الآخر. لا تزال سيارة قادمة من الاتجاه المعاكس تتحرك نحونا ولم تتوقف بعد. متى ينبغي أن أشير للطلاب بأنه يمكنهم البدء بالعبور؟","options":["بمجرد تفعيل أضوائي الحمراء وذراع التوقف، بما أن ذلك يُلزم قانونيًا كل المرور بالتوقف","فقط بعد أن أتأكد من أن السيارة القادمة وكل المرور الآخر قد توقفوا فعليًا توقفًا تامًا وأنه آمن","فورًا، لكن أطلب منهم العبور قريبًا خلف الحافلة حيث لا تستطيع السيارة القادمة الوصول إليهم","فورًا، طالما أنهم يمشون بسرعة ويبقون ضمن نحو 10 أقدام من الحافلة"],"explanation":"اسمح للطلاب بالعبور فقط بعد أن تتأكد بعينيك من أن السيارة القادمة وكل المرور قد توقفوا فعليًا توقفًا تامًا."},"32":{"q":"يُعثر على غرض تُرك على أحد المقاعد أثناء:","options":["أثناء التوقف للتزود بالوقود","جولة التفقد بعد الرحلة","أثناء منعطف حاد","أثناء الرجوع للخلف"],"explanation":"جولة التفقد بعد الرحلة تكشف الأغراض المتروكة."},"33":{"q":"أنا أقود في مساري ويقف طالب في الصف الخامس واقفًا في الممر لتغيير مقعده بينما لا نزال نتحرك بين المحطات. بموجب قواعد إدارة ركاب الحافلات المدرسية في تكساس، ما هو أفضل إجراء ينبغي أن أتخذه؟","options":["أسمح له بالانتقال بما أن الممر خالٍ ونحن بين المحطات، ثم أطلب منه الجلوس عند اقترابنا من المحطة التالية","أدعه يقف ويمسك بظهر مقعد للتوازن حتى أصل إلى المحطة المجدولة التالية لتحميل الطلاب","أوجّهه للجلوس فورًا وأُبقي جميع الطلاب جالسين طالما أن الحافلة تتحرك","أسمح بالوقوف القصير فقط بينما تسير الحافلة ببطء، وأطلب الجلوس بمجرد زيادة السرعة"],"explanation":"يجب أن يبقى كل طالب جالسًا طوال فترة تحرك الحافلة حتى لا يقذفه توقف مفاجئ أو انحراف، ويبقى الممر خاليًا للإخلاء."},"34":{"q":"أنا أقود في مساري على طريق من أربعة مسارات وأقترب من محطة سيصعد عندها طالبان. عدة سيارات تقترب من خلفي وفي المسار المجاور. لتحذير المرور بشكل صحيح وحماية الأطفال أثناء هذا التوقف، ماذا ينبغي أن يكون تسلسل إشارات التحذير لديّ؟","options":["أشغّل الأضواء الحمراء الوامضة وذراع التوقف فورًا، ثم أضيف الأضواء الكهرمانية فقط بعد صعود الطلاب","أترك جميع أضواء التحذير مطفأة على طريق متعدد المسارات وأستخدم بدلًا منها البوق لتنبيه السيارات خلفي","أومض بالأضواء العالية بضع مرات حتى يلاحظني السائقون خلفي، ثم أشغّل الأضواء الحمراء عند توقفي","أشغّل الأضواء الكهرمانية التحذيرية على بعد نحو 100 إلى 300 قدم قبل المحطة، ثم أنتقل إلى الأضواء الحمراء الوامضة وذراع التوقف بمجرد توقفي"],"explanation":"شغّل الأضواء الكهرمانية التحذيرية على بعد 100 إلى 300 قدم قبل المحطة لتحذير المرور خلفك، ثم انتقل إلى الأضواء الحمراء الوامضة وذراع التوقف بمجرد التوقف التام."},"35":{"q":"يسألني أحد الآباء عند محطة الحافلة المدرسية لماذا لا تحتوي حافلاتنا على أحزمة أمان للحضن والكتف على كل مقعد كما في سيارتها. أشرح أن الحافلة مصممة لحماية الطلاب أساسًا عبر ميزة مدمجة مختلفة. أي عبارة تصف على أفضل وجه كيف صُممت المقاعد نفسها للحفاظ على سلامة الطلاب في حادث تصادم؟","options":["تستخدم المقاعد مبدأ التقسيم إلى مقصورات: صفوف متقاربة بظهور مقاعد عالية ومبطّنة وماصة للطاقة تحمي الطلاب بينها.","تعتمد المقاعد على حزام أمان ثلاثي النقاط في كل موضع جلوس لتثبيت كل طالب بإحكام أثناء الاصطدام.","المقاعد متباعدة بظهور معدنية منخفضة حتى يتمكن الطلاب من إسناد أذرعهم للأمام قبل أي تصادم.","المقاعد مثبتة بالأرضية بشكل غير محكم فقط حتى تنزلق وتمتص قوة التصادم بحركتها."],"explanation":"تحمي الحافلات المدرسية الركاب عبر التقسيم إلى مقصورات: صفوف متقاربة بظهور مقاعد عالية ومبطّنة وماصة للطاقة تحمي الطلاب بينها."},"36":{"q":"أنت تقود حافلتك المدرسية المليئة بالطلاب وتقترب من معبر للسكة الحديد. بينما تبطئ للتوقف بين 15 و50 قدمًا من القضبان، تبدأ بوابة المعبر بالنزول وتبدأ أجراس التحذير بالرنين، لكنك لا ترى ولا تسمع أي قطار. الطريق على الجانب الآخر خالٍ وسيارة خلفك تطلق بوقها. ماذا يجب أن تفعل؟","options":["تلتف بحافلتك بحذر حول البوابة المنخفضة بما أن القضبان والجانب الآخر فارغان بوضوح","تبقى متوقفًا خلف البوابة وتنتظر حتى ترتفع تمامًا قبل عبور القضبان","تعبر بسرعة في ترس منخفض بينما لا تزال البوابة ترتفع حتى تجتاز القضبان قبل أي قطار","ترجع للخلف بعيدًا عن المعبر لتدع السيارة التي تطلق بوقها تمر، ثم تقترب مجددًا بعد ارتفاع البوابة"],"explanation":"لا تلتف أبدًا حول بوابة منخفضة؛ البوابة المنخفضة مع رنين الأجراس تعني أن قطارًا قادم، لذا ابقَ متوقفًا حتى ترتفع البوابة تمامًا قبل العبور."},"37":{"q":"أنت متوقف عند محطة حافلة مدرسية مع وميض أضوائك الحمراء وذراع التوقف ممدودة، تُنزل الطلاب. تمر شاحنة صغيرة مسرعة بجانب حافلتك من اليسار، متجاهلة ذراع التوقف، بينما لا يزال طفل يستعد للعبور. بعد أن تُؤمّن الموقف ويكون جميع الطلاب بأمان، ماذا يُطلب منك فعله بخصوص السائق الذي تجاوز بشكل غير قانوني؟","options":["لا تسجّل شيئًا رسميًا، بما أن الشاحنة لم تصدم طالبًا فعليًا ولم تقع أي إصابة","تخرج وتلاحق الشاحنة بنفسك للحصول على لوحتها قبل أن تهرب","تبلّغ عن التجاوز غير القانوني كما هو مطلوب، مع تقديم تفاصيل المخالفة للجهة المختصة","لا تتخذ أي إجراء ما لم يطلب منك أحد الآباء أو شاهد آخر تحديدًا تقديم شكوى"],"explanation":"تشترط إدارة السلامة العامة في تكساس على سائقي الحافلات الإبلاغ عن أي مركبة تتجاوز بشكل غير قانوني حافلة متوقفة بأضواء حمراء وذراع توقف، مع تقديم تفاصيل المخالفة للجهة المختصة."},"38":{"q":"أنا أقترب من محطة حافلة مدرسية مخصصة حيث ينتظر عدة طلاب للصعود. للحفاظ على أقصى درجات سلامتهم بينما أوقف الحافلة توقفًا تامًا، أين ينبغي أن أكون قد علّمت هؤلاء الطلاب أن يقفوا أثناء انتظارهم؟","options":["مصطفّين على طول الرصيف عند المكان الذي سيُفتح فيه الباب الأمامي للحافلة","خطوة قليلة داخل الطريق حتى أتمكن من رؤيتهم وعدّهم في مراياي","متجمّعين تمامًا عند المصد الأمامي حتى يبقوا بعيدًا عن المرور العابر","واقفين بعيدًا تمامًا عن الطريق حتى تتوقف الحافلة توقفًا تامًا"],"explanation":"يجب أن يقف الطلاب المنتظرون بعيدًا تمامًا عن الطريق حتى تتوقف الحافلة كليًا، لأن منطقة الخطر حول الحافلة تمتد حتى 30 قدمًا أمامها."},"39":{"q":"أنا أقوم بجولة التفقد قبل الرحلة على الحافلة المدرسية وأفحص فتحة السقف. للتأكيد على أنني أفهم غرضها أثناء اختبار مهارات رخصة القيادة التجارية، أي عبارة عن فتحة السقف صحيحة؟","options":["تُستخدم كمخرج طوارئ مخصص إذا توجّب إخلاء الحافلة وكانت المخارج الأخرى مسدودة","هي فتحة تهوية يجب أن تبقى محكمة الإغلاق متى كان الطلاب على متن الحافلة","هي مكان تخزين علوي لتثبيت الأغراض المتناثرة حتى يبقى الممر خاليًا أثناء المسار","هي نافذة سقفية يمكن فتحها فقط عندما تكون الحافلة متوقفة ومركونة تمامًا"],"explanation":"فتحة السقف هي مخرج طوارئ مخصص يتيح للركاب الهروب إذا كان باب الخدمة أو الباب الخلفي أو المخارج القياسية الأخرى مسدودة."},"40":{"q":"أنت تقود حافلة مدرسية محمّلة في مسارك بعد الظهر، متأخرًا نحو عشر دقائق عن الجدول. المرور خفيف والطريق أمامك خالٍ ومستقيم. أي من السلوكيات التالية ينبغي أن تتجنبها لأنها تشتيت خطير يصرف انتباهك عن القيادة؟","options":["إلقاء نظرة على مراياك الخارجية اليسرى واليمنى لإبقاء الطلاب في مجال الرؤية","تناول غدائك المعبّأ أو إرسال رسالة نصية سريعة إلى المرسل بشأن التأخير","مسح الطريق بعيدًا أمامك بحثًا عن المحطات والمخاطر القادمة","عدّ الطلاب بينما يبقون جالسين والممر يبقى خاليًا"],"explanation":"تناول الطعام أو إرسال الرسائل النصية سلوكيات قيادة مشتتة تصرف يديك وعينيك وعقلك عن تشغيل الحافلة، ولا يبرر أي جدول زمني المخاطرة بسلامة الطلاب."},"41":{"q":"أنا متأخر 12 دقيقة في مساري بعد الظهر، والحافلة موحلة من مطر الصباح، وبعض الطلاب يطلبون مني باستمرار رفع صوت الراديو. بينما أقترب من محطة التحميل التالية، أي مما يلي ينبغي أن يوجّه كل قرار أتخذه عند هذه المحطة؟","options":["تعويض الوقت الضائع بتقصير التوقف، بما أن الجدول الضيق يبقي المسار على المسار الصحيح لبقية الرحلة","إبقاء الراديو عند المستوى الذي يريده الطلاب حتى تبقى الرحلة هادئة ويحسن الأطفال التصرف أثناء الصعود","حماية الطلاب، وجعل سلامتهم الهدف الوحيد الذي يتقدم على الجدول والراحة ومظهر الحافلة","إبقاء الحافلة بمظهر لائق، بما أن حافلة نظيفة وذات مظهر مهني تعكس صورة جيدة عن المنطقة التعليمية والسائق"],"explanation":"سلامة الطلاب هي الهدف الأهم على الإطلاق وتتقدم على الجدول والراحة ومظهر الحافلة، لأن التحميل والتنزيل هو أخطر جزء في العمل."},"42":{"q":"أنت تقترب من محطة حافلة مدرسية لاصطحاب الأطفال. متى ينبغي أن تشغّل أضواءك الكهرمانية الوامضة؟","options":["فقط بعد أن يكون الأطفال قد بدؤوا بالفعل بالسير نحو الحافلة في الطريق.","على بعد نحو 200 قدم (أو حسب ما تتطلبه ولايتك) قبل المحطة لتحذير المرور بأنك ستتوقف.","لا تستخدم الأضواء الكهرمانية أبدًا؛ فقط توقف وانتقل مباشرة إلى الأضواء الحمراء الوامضة فورًا.","فقط ليلًا، لأن الأضواء الكهرمانية التحذيرية ليست ضرورية أثناء ساعات النهار إطلاقًا."],"explanation":"شغّل الأضواء الكهرمانية على بعد نحو 200 قدم قبل المحطة (أو حسب ما تتطلبه ولايتك)."},"43":{"q":"لقد انتهيت للتو من تنزيل الطلاب عند محطة بعد الظهر. وبينما ينزل آخر طفل، تُسقط فتاة كتابًا مدرسيًا ينزلق تحت المصد الأمامي، خارج خط نظرك المباشر، وتبدأ فورًا بالوصول إليه. قدمك تخفّف بالفعل عن الفرملة للانطلاق. ما هو الإجراء الصحيح؟","options":["تطلق البوق مرة واحدة وتبدأ بالتحرك للأمام برفق حتى تفهم الطفلة أنه عليها التقاط الكتاب بسرعة والابتعاد عن الحافلة.","تحرّر الفرملة وتنطلق ببطء، بما أن طفلًا واقفًا بهذا القرب من المقدمة سيتراجع طبيعيًا بمجرد أن تبدأ الحافلة بالتحرك.","تغلق باب الخدمة وتتابع مسارك، لأن كتابًا ساقطًا في منطقة الخطر هو مسؤولية الطالبة في استعادته، لا السائق.","تُبقي الحافلة مؤمّنة ولا تتحرك؛ تشير للطفلة بالتوجه إلى مكان آمن، ثم تتأكد من أنها بعيدة تمامًا عن منطقة الخطر ومرئية لك قبل الانطلاق."],"explanation":"إذا اختفى طالب عن مجال الرؤية قرب الحافلة، أبقِها مؤمّنة ولا تتحرك حتى تتأكد من أن الطفل بعيد تمامًا عن منطقة الخطر ومرئي لك."},"44":{"q":"أنت تحمّل الطلاب مع تشغيل الأضواء الحمراء الوامضة. متى يمكنك إطفاؤها والانطلاق؟","options":["بمجرد أن يصعد أول طالب إلى الحافلة، حتى لو كان آخرون لا يزالون يعبرون الآن.","فقط بعد أن يكون جميع الطلاب على متن الحافلة أو قد ابتعدوا وعبروا، وتكون منطقة الخطر خالية.","عندما ينفد صبر المرور خلفك ويبدأ بإطلاق البوق ليطلب منك التحرك.","فور أن تفتح الباب، بما أن الأضواء الحمراء ليست ضرورية إلا للثانية الأولى."],"explanation":"أبقِ الأضواء الحمراء مشتغلة حتى يصعد جميع الطلاب أو يعبروا بأمان."},"45":{"q":"تتوقف للتنزيل عند محطة سكنية مع وميض أضوائك الحمراء وذراع التوقف ممدودة. يجب على أحد الطلاب الوصول إلى الجانب الآخر من الطريق وهو ينتظر بجانب الباب لتعليماتك. للحفاظ على أقصى سلامة لهذا الطالب، ماذا ينبغي أن تطلب منه أن يفعل؟","options":["أن يمشي نحو 10 أقدام أمام الحافلة حيث يمكنك رؤيته، ثم ينتظر إشارة يدك قبل العبور.","أن يلتف حول مؤخرة الحافلة ويعبر هناك، بما أن ذراع التوقف يوقف المرور خلفك بالفعل.","أن يعبر فورًا بمفرده بمجرد تشغيل الأضواء الحمراء، دون انتظار أي إشارة منك.","أن يبقى ملاصقًا للجانب الأيمن من الحافلة ويمشي للأمام في ذلك المسار حتى يصل إلى المصد الأمامي."],"explanation":"يجب على الطلاب العابرين المشي نحو 10 أقدام أمام الحافلة ضمن مجال رؤيتك وانتظار إشارة يدك، لأنك وحدك من يستطيع تأكيد توقف المرور."},"46":{"q":"أنت تقوم بفحص الحافلة المدرسية قبل الرحلة. ما الذي من المهم بشكل خاص فحصه؟","options":["فقط مستوى الوقود والراديو، بما أن الحافلة المدرسية تُقاد مثل أي مركبة أخرى.","يجب أن تعمل المرايا وذراع التوقف والأضواء الوامضة ومخارج الطوارئ جميعها بشكل صحيح.","فقط لون الطلاء حتى تتطابق الحافلة مع بقية أسطول حافلات المنطقة في الخارج.","لا شيء إضافي؛ تحتاج الحافلة المدرسية لنفس فحوصات شاحنة بضائع عادية فارغة."],"explanation":"افحص المرايا وذراع التوقف والأضواء الوامضة ومخارج الطوارئ."},"47":{"q":"أثناء قيادتك في مسارك، يجب عليك عبور قضبان السكة الحديد والطلاب على متن الحافلة. ماذا يجب أن تفعل؟","options":["تعبر بسرعة عادية دون توقف بما أن الحافلة على جدول يومي ثابت الآن.","تتوقف، وتفتح الباب، وتنظر وتستمع، ثم تعبر في ترس منخفض دون تبديل التروس على القضبان.","تتوقف فوق القضبان مباشرة حتى تتمكن من إنزال النوافذ والاستماع لقدوم قطار.","تزيد السرعة عبر القضبان لأن حافلة مدرسية محمّلة ثقيلة وبطيئة في الانطلاق."],"explanation":"توقف، وافتح الباب، وانظر واستمع، ثم اعبر في ترس منخفض دون تبديل التروس."},"48":{"q":"تدرك أن طفلًا موجود في منطقة الخطر بجانب الحافلة مباشرة حيث لا يمكنك رؤيته. ماذا يجب أن تفعل؟","options":["تبدأ بتحريك الحافلة ببطء بما أن الطفل سيتراجع بمجرد أن تبدأ الحافلة بالتحرك.","لا تحرّك الحافلة إطلاقًا حتى تتأكد من أن الطفل خارج منطقة الخطر هناك.","تشغّل المحرك بصوت عالٍ حتى يفهم الطفل أن عليه الابتعاد عن جانب الحافلة الآن.","تغلق الباب وتتقدم للأمام؛ منطقة الخطر هي مسؤولية الطفل، لا مسؤوليتك."],"explanation":"لا تتحرك أبدًا حتى تتأكد من أن الطفل خارج منطقة الخطر."},"49":{"q":"إنها نهاية مسار طويل بعد الظهر وقد دخلت إلى المرآب، متعبًا ومستعدًا لإنهاء الدوام. أنت متأكد من أن كل طالب نزل عند محطته المخصصة، والحافلة تبدو فارغة من حيث تجلس. قبل أن تطفئها وتمشي بعيدًا، ماذا تشترط عليك إدارة السلامة العامة في تكساس أن تفعل؟","options":["تلقي نظرة في مرآتك الداخلية العلوية من مقعد السائق، بما أنها تمنحك رؤية واضحة لكامل طول الممر من الأمام إلى الخلف.","تمشي فعليًا على كامل طول الممر من الأمام إلى الخلف، متفقدًا كل مقعد للتأكد من عدم تخلّف أي طفل أو نومه.","تتأكد من آخر طالب نزل بأنه لم يبقَ أحد آخر على متن الحافلة، ثم تؤمّن الحافلة وتتوجه إلى المنزل واثقًا بكلامه.","تقفل الأبواب وتغادر، بما أنك عددت كل طالب نزل عند محطته والممر الفارغ المرئي من مقعدك يؤكد ذلك."],"explanation":"في نهاية كل مسار، امشِ فعليًا في الحافلة من الأمام إلى الخلف وتفقد كل مقعد، لأن طفلًا نائمًا أو مختبئًا قد لا يكون مرئيًا من مقعد السائق."},"50":{"q":"تتجاوز سيارة حافلتك المدرسية المتوقفة بشكل غير قانوني بينما تومض أضواؤك الحمراء ويعبر الأطفال. ماذا يجب أن تفعل؟","options":["تلوّح للأطفال بالعبور بسرعة أكبر حتى يسبقوا السيارة المتجاوزة ويخلوا الطريق بسرعة.","تُبقي الأطفال بعيدًا بأمان حتى يخلو الطريق، وتبلّغ عن المركبة لاحقًا.","تخرج وتلاحق السيارة حتى تحصل على رقم لوحتها وتواجه السائق الآن.","ترسل الأطفال على أي حال بما أن الأضواء الحمراء تعني أن كل سيارة ملزمة قانونيًا بالتوقف."],"explanation":"أبقِ الأطفال بعيدًا حتى يصبح الأمر آمنًا، ثم بلّغ عن المركبة."},"51":{"q":"أنت على وشك تشغيل حافلتك في الصباح والطلاب بانتظارك. ما الذي يجب أن تفحصه بخصوص المكابح؟","options":["تخطَّ فحص المكابح لتوفير الوقت بما أن الطلاب ينتظرون بالفعل في الخارج في البرد.","تأكد من أن المكابح تعمل بشكل سليم قبل تحميل الطلاب؛ لا تنقل الطلاب أبداً بمكابح معطلة.","حمّل الطلاب أولاً واختبر المكابح لاحقاً عندما تكون على الطريق المفتوح هناك.","ثق بأن مكابح الأمس بحالة جيدة وانطلق فحسب دون أي فحص هذا الصباح."],"explanation":"تأكد من أن المكابح تعمل قبل تحميل الطلاب؛ لا تنقل الطلاب أبداً بمكابح معطلة."},"52":{"q":"أنا أدرّب سائقة حافلة مدرسية جديدة وتسألني عن حجم \"منطقة الخطر\" حتى تعرف المنطقة التي يكون فيها الأطفال أكثر عرضة للاصطدام. بناءً على إرشادات إدارة السلامة العامة في تكساس (Texas DPS)، إلى أي مدى تمتد هذه المنطقة عموماً حول الحافلة؟","options":["فقط الشريط الواقع مباشرة خلف المصد الخلفي، لأنه النقطة العمياء الحقيقية الوحيدة لأي سائق حافلة مدرسية","حوالي 50 قدماً في كل اتجاه، وهي نفس أقصى مسافة توقف تُستخدم عند مزلقان السكة الحديدية","عموماً حوالي 10 أقدام حول الحافلة، من الأمام والجانبين والخلف، وتمتد إلى أبعد من ذلك أمام الحافلة","فقط القدم الأولى من الرصيف بجانب باب الدخول، المكان الذي يصعد منه الطلاب فعلياً إلى الحافلة"],"explanation":"تمتد منطقة الخطر حوالي 10 أقدام حول الجزء الأمامي والجانبين والخلفي من الحافلة، وتمتد إلى أبعد من ذلك أمام الحافلة، حيث يكون الأطفال أكثر عرضة للخطر."},"53":{"q":"أنا أقود حافلة مدرسية وتوقفت للتو لإنزال ثلاثة طلاب. وبينما ينزلون، أريد أن أبقيهم حيث أستطيع رؤيتهم وبعيداً عن المكان الذي يُصاب فيه معظم الأطفال. بناءً على قواعد سلامة الحافلات المدرسية في تكساس، أين يُصاب معظم الطلاب وما الذي ينبغي أن أفعله حيال ذلك؟","options":["معظمهم يُصابون بعيداً عن الحافلة، لذا يكفي أن أراقب حركة المرور على بُعد مربع سكني واحد قبل الانطلاق","معظمهم يُصابون وهم لا يزالون جالسين في الداخل، لذا ينبغي أن أُبقيهم مربوطين بالأحزمة حتى تُفتح الأبواب تماماً","معظمهم يُصابون عند المدخل الأمامي للمدرسة، لذا فإن موظفي الحرم المدرسي هم من يتعاملون مع هذا الخطر، وليس أنا","معظمهم يُصابون في منطقة الخطر القريبة من الحافلة، لذا أُبقيهم على بُعد حوالي 10 أقدام أمام الحافلة حيث أستطيع رؤيتهم"],"explanation":"يُصاب معظم الأطفال في منطقة الخطر القريبة من الحافلة، لذا وجّههم لعبور الطريق على بُعد حوالي 10 أقدام أمام الحافلة حيث تستطيع رؤيتهم."},"54":{"q":"أنا أقود حافلتي المدرسية على طريق ريفي بسرعة 45 ميلاً في الساعة، وعلى بُعد حوالي 200 قدم قبل توقف قادم، أُشغّل الأضواء التحذيرية الكهرمانية (الصفراء) الوامضة. تسألني مساعِدة جديدة ترافقني عمّا تخبر به هذه الأضواء الكهرمانية السائقين الآخرين. أي إجابة صحيحة؟","options":["إنها تحذّر من أنني على وشك التوقف لتحميل أو إنزال الطلاب، لذا ينبغي على حركة المرور الاستعداد للتوقف","تعني أنني انتهيت من التحميل وأن ذراع التوقف يتراجع بينما أنطلق","تشير إلى أنني متوقف بالفعل وأن الأضواء الحمراء وذراع التوقف نشطان الآن","تخبر السائقين بأن الحافلة خارج الخدمة وقد يتم نقلها دون توقفات اعتيادية"],"explanation":"الأضواء التحذيرية الكهرمانية هي إشارة مسبقة بأن الحافلة على وشك التوقف للتحميل أو الإنزال، تخبر حركة المرور بالاستعداد للتوقف."},"55":{"q":"أنا أقود حافلتي المدرسية المحمّلة بالكامل على طريق ذي حارتين وأتوقف على الجانب لإنزال الطلاب عند محطتهم. أُشغّل الأضواء الحمراء الوامضة ويخرج ذراع التوقف. يقترب سائق من خلفي، وآخر قادم نحوي في الحارة المقابلة. ماذا يُلزم القانون كلا السائقَين بفعله؟","options":["التباطؤ إلى سرعة زاحفة، والاستمرار في التحرك متجاوزَين الحافلة، ومراقبة الأطفال قرب الباب","التوقف التام والبقاء متوقفَين حتى تنطفئ الأضواء الحمراء ويُطوى ذراع التوقف إلى الداخل","فقط السائق خلف الحافلة عليه التوقف؛ أما حركة المرور المقابلة فيمكنها المتابعة بحذر","الانتقال إلى الحارة المفتوحة، وتجاوز الحافلة بحذر، والمتابعة دون توقف"],"explanation":"عندما تومض الأضواء الحمراء ويمتد ذراع التوقف، يجب على حركة المرور المقتربة التوقف التام والبقاء متوقفة حتى تنطفئ الأضواء ويُطوى الذراع إلى الداخل."},"56":{"q":"أنا أحمل بالفعل رخصة قيادة تجارية من الفئة B (Class B CDL) وتصديق نقل الركاب (P) من سنوات قيادتي لحافلة نقل عام داخل المدينة. والآن تريد إحدى المناطق التعليمية توظيفي لقيادة حافلة خط تُقلّ وتُنزل طلاب رياض الأطفال حتى الصف الثاني عشر (K-12). قبل أن أتمكن قانونياً من قيادة هذا الخط، أي مما يلي يجب أن يكون صحيحاً بشأن مؤهلاتي؟","options":["تصديق نقل الركاب (P) كافٍ، لأن الحافلة المدرسية ما هي إلا نوع من المركبات الناقلة للركاب.","أحتاج إلى إضافة تصديق المواد الخطرة (H)، بما أن الحافلات المدرسية تنقل أطفالاً يُعتبرون حمولة عالية الخطورة.","يجب أن أحمل كلاً من تصديق نقل الركاب (P) وتصديق الحافلات المدرسية (S) قبل أن أتمكن من قيادة الخط.","أحتاج إلى إضافة تصديق الصهاريج (N) وتصديق المقطورات المزدوجة/الثلاثية (T) لتغطية الحافلة الأكبر ذات المكابح الهوائية."],"explanation":"تتطلب قيادة حافلة مدرسية تنقل طلاب رياض الأطفال حتى الصف الثاني عشر (K-12) كلاً من تصديق نقل الركاب (P) وتصديق الحافلات المدرسية (S)."},"57":{"q":"أنا أُنزل مجموعة من الطلاب الذين يسكنون عبر الطريق، ويحتاج عدد منهم إلى العبور للوصول إلى الجانب الآخر. الأضواء الحمراء وذراع التوقف ظاهرة، وقد توقفت حركة المرور من الاتجاهين. لإبقاء هؤلاء الطلاب خارج منطقة الخطر وحيث أستطيع رؤيتهم، أين ينبغي أن أوجّههم للعبور؟","options":["قريباً خلف المصد الخلفي للحافلة، حيث لا تستطيع حركة المرور المتوقفة الوصول إليهم","بين العجلات الأمامية والخلفية على طول الجانب الأيمن للحافلة","حيثما تبدو الفجوة في حركة المرور أكثر أماناً لكل طالب","على بُعد حوالي 10 أقدام أمام الحافلة، في مرأى كامل مني، وعند إشارتي"],"explanation":"يجب على الطلاب العبور على بُعد حوالي 10 أقدام أمام الحافلة، في مرأى كامل منك، وعند إشارتك فقط، مما يُبقيهم خارج مناطق الخطر."},"58":{"q":"أنت تقود حافلة مدرسية محمّلة وتقترب من مزلقان سكة حديدية به إشارات ضوئية وامضة مطفأة حالياً. تتوقف على المسافة المناسبة قبل القضبان ولا ترى أي قطار يقترب. ما الذي يجب عليك فعله قبل السماح للحافلة بعبور القضبان؟","options":["افتح باب الخدمة ونافذة السائق، انظر واستمع للقطار، ثم اعبُر بترس منخفض دون تغيير السرعة","اعبُر فوراً بما أن الإشارات مطفأة ولا يوجد قطار مرئي من حيث توقفت","تقدّم وتوقف على القضيب الأول للحصول على رؤية أوضح للطريق في الاتجاهين","انتظر حتى يشير لك سائق متوقف خلفك بأنه من الآمن لك المتابعة عبر القضبان"],"explanation":"عند كل مزلقان سكة حديدية، توقف، وافتح باب الخدمة ونافذتك، وانظر واستمع للقطار، ثم اعبُر بترس منخفض دون تغيير السرعة."},"59":{"q":"لقد أنهيت للتو خط ما بعد الظهر وأعدت الحافلة المدرسية الفارغة إلى الموقف. قبل أن أُغلق كل شيء وأتوجه إلى المنزل، ما الغرض الرئيسي من فحص ما بعد الرحلة الذي يجب أن أُجريه؟","options":["لتوثيق تآكل الإطارات ومستوى الوقود حتى يتمكن المُرسِل من جدولة صيانة الحافلة","للمشي على طول الحافلة بالكامل والتأكد من عدم بقاء أي طفل نائماً أو مختبئاً","للتحقق من أن الأضواء التحذيرية الكهرمانية والحمراء لا تزال تعمل بشكل صحيح قبل الخط التالي","للتحقق من أن ذراع التوقف ومرايا العبور نظيفة ومضبوطة بشكل سليم"],"explanation":"الغرض الأهم من فحص ما بعد الرحلة هو المشي على طول الحافلة بالكامل والتأكد من عدم بقاء أي طفل نائماً أو مختبئاً."},"60":{"q":"أنت تُكمل فحوصات المرايا قبل خط الصباح وتريد التأكد من المكان الذي يواجه فيه الأطفال أكبر خطر للاصطدام حول حافلتك المدرسية. أي عبارة تحدد بشكل صحيح أين تكون منطقة الخطر أشد حدة؟","options":["إنها أشد خطورة مباشرة خلف الحافلة، حيث يملك السائق أقل قدر من الرؤية عبر النافذة الخلفية ولا يستطيع رؤية الطلاب بسهولة","إنها تتركز فقط على الجانب الأيسر، لأن ذلك هو المكان الذي تقترب منه حركة المرور المتجاوزة وتتسارع متجاوزةً الحافلة المتوقفة","إنها تحيط بالحافلة بأكملها، لكنها أشد خطورة مباشرة أمام الحافلة وعلى طول الجانب الأيمن والخلف","إنها محصورة في المنطقة فوق خط السقف وحوله، حيث تُركّب الأضواء التحذيرية الكهرمانية والحمراء على الحافلة"],"explanation":"تحيط منطقة الخطر بالحافلة بأكملها لكنها أشد فتكاً أمام الحافلة وعلى طول الجانب الأيمن والخلف، حيث يعبر الأطفال ويمكن أن ينزلوا تحت خط نظر السائق."},"61":{"q":"لقد توقفت لإنزال ثلاثة طلاب ابتدائيين يحتاجون إلى العبور إلى الجانب الآخر من الطريق. لإبقائهم خارج منطقة الخطر وحيث أستطيع رؤيتهم بوضوح، إلى أي مدى أمام الحافلة ينبغي أن أوجّههم للمشي قبل أن يبدأوا العبور؟","options":["حوالي قدمين أمامها، بعد المصد الأمامي مباشرة، حتى يعبروا بسرعة","حوالي 50 قدماً أمامها، بعيداً عن متناول منطقة الخطر","خلف الحافلة، حيث تحميهم أضوائي الحمراء الخلفية من حركة المرور","حوالي 10 أقدام أمامها، بمسافة كافية تجعلني أراهم بوضوح فوق غطاء المحرك"],"explanation":"ينبغي على الطلاب العبور على بُعد حوالي 10 أقدام أمام الحافلة، بمسافة كافية للبقاء خارج منطقة الخطر الأمامية مع البقاء ضمن رؤية السائق الواضحة فوق غطاء المحرك."},"62":{"q":"لقد وصلت إلى محطة صباحية ومجموعة من الطلاب ينتظرون على الرصيف. أضوائي الكهرمانية مطفأة، وأضوائي الحمراء وذراع التوقف ظاهرة، وأنا مستعد لفتح الباب. قبل أن أسمح لأي طالب بالصعود، أهم شيء على الإطلاق يجب أن أتأكد منه بشأن منطقة الصعود هو أنها:","options":["خالية من المخاطر وحركة المرور حتى يتمكن الطلاب من الاقتراب من الباب بأمان","مكنوسة وخالية من الحصى المتناثر حتى لا ينزلق أحد أثناء الصعود","على بُعد 10 أقدام من الرصيف حتى لا يضطر الطلاب للمشي مسافة بعيدة","معلَّمة بمخاريط حتى يعرف السائقون المتجاوزون مكان المحطة"],"explanation":"التحميل والإنزال هما أخطر جزء من العمل، لذا يجب على السائق التأكد من أن منطقة الصعود خالية من المخاطر وحركة المرور قبل فتح الباب."},"63":{"q":"لقد أنزلت للتو خط ما بعد الظهر عند محطة مدرسة ابتدائية. وبينما تنزل آخر مجموعة من الأطفال على الدرج إلى الرصيف، تُجري عدّاً لكل من نزل. ما السبب الرئيسي لعدّ الطلاب أثناء نزولهم؟","options":["للتحقق من أن كل طفل مرّر بطاقة الحافلة أو دفع الأجرة الصحيحة للرحلة","للتأكد من أن كل طالب قد نزل من الحافلة بأمان وأن لا أحد قد اختفى عن نظرك بالقرب منها","للتأكد من أن الطلاب بقوا جالسين بنظام حتى توقفت الحافلة تماماً","للتحقق من أن كل طالب أبقى حزام الأمان مربوطاً طوال مدة الرحلة"],"explanation":"عدّ الطلاب أثناء نزولهم يؤكد أن كل طفل قد نزل من الحافلة بأمان ويُحصي أي شخص قد يختفي عن النظر بالقرب من العجلات."},"64":{"q":"تتوقف للإنزال في خط ابتدائي. بعد أن ينزل ثلاثة طلاب ويبتعدون عن الرصيف، تُجري عدّك النهائي ويغيب طفل عن النظر — شُوهد آخر مرة وهو يمشي نحو مقدمة الحافلة. حركة المرور خلفك بدأت تتكدس وسيارة تُطلق بوقها. ماذا ينبغي أن تفعل؟","options":["تقدّم ببطء، لأن الطفل على الأرجح قد عبر بالفعل ويجب أن تُبقي حركة المرور متحركة","اضغط البوق مرتين لإشارة الطفل بالابتعاد، ثم حرّر المكبح بمجرد أن يبدو الطريق مفتوحاً","أبقِ الحافلة مؤمّنة بمكبح الانتظار مشدوداً ولا تتحرك حتى تعثر على الطالب المفقود","لوّح لحركة المرور المنتظرة بالالتفاف حول الحافلة وتابع بمجرد أن يصبح الطريق أمامك خالياً"],"explanation":"إذا اختفى طالب عن النظر بالقرب من الحافلة، أبقِها مؤمّنة بمكبح الانتظار مشدوداً ولا تتحرك حتى تعثر على ذلك الطالب."},"65":{"q":"المرايا المحدّبة على الحافلة المدرسية تساعدك على رؤية:","options":["الأفق البعيد","المنطقة القريبة من الحافلة","المحرك من الداخل","سقف المقصورة الداخلي"],"explanation":"تُظهر المرايا المحدّبة المنطقة القريبة من الحافلة (منطقة الخطر)."},"66":{"q":"أنت تُجري ضبط المرايا قبل الرحلة على حافلتك المدرسية وتريد التأكد من أن كل مرآة موجهة نحو المنطقة المصممة لها. لمراقبة حركة المرور المقتربة من الخلف والمركبات الأبعد على الطريق وأنت تستعد للاندماج، على أي مجموعة من المرايا ينبغي أن تعتمد؟","options":["المرايا المحدّبة، لأن زاويتها الواسعة مصممة لتتبع حركة المرور السريعة التي تلحق بك من الخلف البعيد","مرايا العبور المركبة في المقدمة، وهي مائلة لالتقاط المركبات المقتربة على الطريق","المرايا الجانبية اليمنى فقط، لأن ذلك هو الجانب الذي تتجاوزك منه حركة المرور قانونياً","المرايا المسطحة (المستوية)، وهي موجهة لإظهار مؤخرة الحافلة وحركة المرور الأبعد"],"explanation":"المرايا المسطحة (المستوية) الخارجية موجهة لإظهار مؤخرة الحافلة وحركة المرور الأبعد، وهو ما تحتاجه لتقدير المركبات المقتربة قبل الاندماج."},"67":{"q":"لقد وصلت إلى محطة وطفلة صغيرة نزلت للتو من حافلتي. أفقدها من نظري وهي منخفضة وقريبة من مقدمة الحافلة، تماماً حيث يحجب غطاء المحرك رؤيتي عبر الزجاج الأمامي. أي مرايا مصممة لتمنحني رؤية لهذه البقعة بالضبط — المصد الأمامي ومنطقة الخطر مباشرة أمام الحافلة؟","options":["مرايا العبور (المحدّبة) المركبة على الرفارف الأمامية، والتي تُظهر المصد الأمامي ومنطقة الخطر مباشرة أمام الحافلة","المرايا المسطحة والمحدّبة الجانبية اليمنى، والتي تُظهر منطقة الخطر الجانبية والإطارات الخلفية والطلاب المقتربين على طول الجانب الأيمن","المرآة الداخلية الخلفية (العلوية)، والتي تُظهر الممر وصفوف المقاعد الأخيرة حتى أتأكد من أن الحافلة فارغة","المرآة المسطحة الجانبية اليسرى، والتي تُظهر الحارة خلف الحافلة حتى أراقب حركة المرور المتجاوزة على جانب السائق"],"explanation":"تُظهر مرايا العبور (المحدّبة) على الرفارف الأمامية المصد الأمامي ومنطقة الخطر مباشرة أمام الحافلة، وهي المنطقة التي يحجبها غطاء المحرك عن مقعد السائق."},"68":{"q":"لقد أنهيت للتو خط ما بعد الظهر وأوقفت الحافلة في المستودع مع شد مكبح الانتظار. قبل أن تُسجّل خروجك وتترك الحافلة لذلك اليوم، ما الإجراء الوحيد الذي يجب أن تُكمله بالمشي إلى أقصى مؤخرة الحافلة؟","options":["اقفل كل نافذة ركاب حتى لا يتمكن أحد من فتحها بينما تكون الحافلة دون مراقبة طوال الليل","امشِ على طول الممر بالكامل إلى الخلف وتحقق من وجود أي أطفال نائمين أو مختبئين","اضبط وعدّل مقاعد الركاب حتى تكون الحافلة جاهزة لخط الصباح التالي","اكنس الأرضية المتسخة والتقط القمامة التي تركها الطلاب في المقاعد الخلفية"],"explanation":"في نهاية كل خط، امشِ على طول الممر بالكامل إلى الخلف للتأكد من عدم بقاء أي طفل نائماً أو مختبئاً."},"69":{"q":"أنت متوقف لإنزال الطلاب وأضوائك الحمراء وذراع التوقف ظاهرة. طفلة في السابعة من عمرها نزلت للتو تُسقط دفترها، فينزلق تحت المصد الأمامي بالقرب من الإطار الأمامي الأيمن. تستدير وتنظر إليك طلباً للإرشاد. ماذا ينبغي أن تخبرها أن تفعل؟","options":["مدّ يدها بسرعة تحت المصد لالتقاطه بينما تستمر في مراقبتها في مرآة العبور","الالتفاف إلى مؤخرة الحافلة حيث يكون الوضع أهدأ والتقاطه من خلف المصد الخلفي","ترك الدفتر حيث هو، والابتعاد عن الحافلة إلى مكان آمن، وترْكك تستعيده بمجرد ابتعاد الجميع","الزحف تحت مقدمة الحافلة بسرعة لالتقاطه قبل أن تُنهي بقية الإنزال"],"explanation":"يجب على الطالب ألا يمدّ يده أو يزحف أو يذهب تحت الحافلة أو خلفها أبداً لأجل غرض ساقط؛ بل يتركه، ويبتعد إلى مكان آمن، ويدع السائق يستعيده."},"70":{"q":"تصل إلى محطة صباحية، وتشد مكبح الانتظار، والأضواء الحمراء وذراع التوقف ظاهرة. مجموعة من حوالي ثمانية طلاب متجمعون على الرصيف، متلهفون للصعود. بينما تفتح باب الخدمة، أي تعليمات ينبغي أن تعطيهم حتى يصعدوا بأمان؟","options":["دعهم يصعدون معاً حتى تُخلي المجموعة منطقة الخطر بسرعة وتتمكن من الانطلاق أبكر","دعهم يصعدون عبر باب الطوارئ الخلفي حتى يبقى الممر الأمامي مفتوحاً ويتوزعون","لوّح لهم بالصعود بينما تُحرك الحافلة للأمام ببطء حتى يستمر الصف بالتحرك دون توقف تام","دعهم يصعدون واحداً تلو الآخر، كلٌّ منهم يمسك بالدرابزين أثناء صعود الدرجات"],"explanation":"ينبغي على الطلاب الصعود واحداً تلو الآخر، كلٌّ منهم يمسك بالدرابزين أثناء صعود الدرجات، حتى لا يُدفع أحد أو يتعثر أو يسقط في أخطر جزء من الخط."},"71":{"q":"أنا أُبطئ حافلتي المدرسية نحو محطة محددة حيث ينتظر طفلان على الكتف. وبينما أوقف الحافلة توقفاً تاماً للسماح لهما بالصعود، أي جهاز إشارة يُطلب مني تشغيله عند هذه النقطة؟","options":["الأضواء الحمراء الوامضة وذراع التوقف، الآن وقد توقفت الحافلة تماماً لتحميل الطلاب","الأضواء التحذيرية الكهرمانية (الصفراء)، لحجز حركة المرور المقتربة بينما يصعد الأطفال","فقط أضواء الطوارئ الرباعية، لأن ذراع التوقف ضروري فقط بعد حلول الظلام أو في المطر","الأضواء التحذيرية الكهرمانية مع ذراع التوقف، مع إبقاء كليهما نشطَين حتى تتحرك الحافلة"],"explanation":"بمجرد توقف الحافلة تماماً للتحميل أو الإنزال، يجب تشغيل الأضواء الحمراء الوامضة وذراع التوقف."},"72":{"q":"أنا أُحمّل الطلاب عند محطة وأريد توجيه الأطفال العابرين للطريق للمشي إلى مسافة كافية أمام الحافلة تُخليهم من منطقة الخطر مع بقائهم حيث أستطيع رؤيتهم في مرايا العبور. إلى أي مدى تقريباً أمام الحافلة ينبغي أن أجعلهم يعبرون؟","options":["حوالي قدم واحدة أمام المصد، مع إبقائهم ملاصقين للحافلة تماماً","حوالي 10 أقدام أمام الحافلة، خارج منطقة الخطر وضمن رؤيتي","حوالي 50 قدماً أمام الحافلة، بعيداً تماماً عن مقدمة المركبة","فقط خلف المصد الخلفي، حيث لا تزال حركة المرور المتجاوزة تراهم"],"explanation":"ينبغي على الطلاب العبور على بُعد حوالي 10 أقدام أمام الحافلة، خارج منطقة الخطر وضمن رؤية السائق."},"73":{"q":"كل طالب في خطي جالس الآن والممر خالٍ، وأنا مستعد للانطلاق من الرصيف. من بين الخطوات أدناه، أيها الأكثر أهمية أن أُكمله قبل أن أُحرّر المكبح وأبدأ التحرك؟","options":["تشغيل المحرك بقوة لحظياً حتى يسمع أي طلاب قريبين أن الحافلة على وشك التحرك","إطفاء الأضواء التحذيرية الكهرمانية والحمراء حتى تعرف حركة المرور التي خلفي أنني سأنطلق","مسح جميع مراياي المسطحة والمحدّبة ومرايا العبور والتأكد من عدم وجود أي طفل في أي مكان في منطقة الخطر","فتح النوافذ وباب الخدمة حتى أسمع أي طالب يناديني"],"explanation":"قبل الانطلاق، امسح جميع المرايا المسطحة والمحدّبة ومرايا العبور للتأكد من عدم وجود أي طفل في منطقة الخطر حول الحافلة."},"74":{"q":"أنا متوقف لإنزال طالب يجب أن يعبر الطريق أمام حافلتي. وبينما ينزل، أين ينبغي أن أوجّهه للعبور حتى أُدير هذا الموقف بأمان؟","options":["قريباً خلف المصد الخلفي، حيث يحميه ذراع التوقف على أفضل وجه","عند الباب مباشرة، حتى أُنزله على الدرجات بنفسي","في أي مكان أمام الحافلة، طالما أسرع قبل أن تتكدس حركة المرور","على بُعد حوالي 10 أقدام أمام الحافلة، حيث أستطيع رؤيته وأعطيه إشارة بالمتابعة"],"explanation":"ينبغي على الطلاب العبور على بُعد حوالي 10 أقدام أمام الحافلة، حيث يستطيع السائق رؤيتهم وإعطاءهم إشارة بالمتابعة."},"75":{"q":"أنت تقود حافلتك المدرسية على طريق ذي حارتين ومحطة الطالب التالية قادمة على بُعد حوالي 200 قدم أمامك. لقد شغّلت للتو أضواءك التحذيرية الكهرمانية. قبل أن تتوقف فعلاً وتُشغّل الأضواء الحمراء الوامضة وذراع التوقف، ما الذي ينبغي أن تفعله وأنت تتابع نحو المحطة؟","options":["تخفيض سرعتك ومسح مراياك للتحقق من حركة المرور والمنطقة المحيطة بالحافلة","الحفاظ على سرعتك حتى لا تتكدس حركة المرور خلفك قبل المحطة","إطفاء الأضواء الكهرمانية وتشغيل الأضواء الحمراء الوامضة مبكراً لتحذير السائقين","فتح باب الخدمة على بُعد بضع أقدام حتى يبدأ الطلاب المنتظرون الصعود أبكر"],"explanation":"الأضواء التحذيرية الكهرمانية تعني أنك تستعد للتوقف، لذا يجب أن تُبطئ وتمسح مراياك للتحقق من حركة المرور والمنطقة المحيطة بالحافلة."},"76":{"q":"أنا أقود مساري الصباحي وتوقفتُ للتو لإنزال ثلاثة طلاب مع تشغيل أضوائي الحمراء الوامضة وإخراج ذراع التوقف. اثنان منهم يعبران بأمان على بُعد نحو 10 أقدام أمام الحافلة ويصلان إلى الرصيف المقابل. قبل أن أُحرر فرامل الحافلة وأُدخل ذراع التوقف، ما الذي كان يجب أن أتأكد من أن يفعله هذان الطالبان بمجرد وصولهما إلى الجانب الآخر؟","options":["التوقف على الكتف والتلويح لي حتى أعرف أنهما ابتعدا عن الحافلة","الاستمرار في التحرك إلى مكان آمن بعيد تمامًا عن الطريق وحركة المرور","الانتظار عند حافة الطريق حتى تبتعد الحافلة تمامًا","العودة نحو الحافلة والسير من خلفها للوصول إلى ممر منزلهما"],"explanation":"بعد العبور، يجب على الطلاب الاستمرار في التحرك حتى يصلوا إلى مكان آمن بعيد تمامًا عن الطريق وحركة المرور."},"77":{"q":"أنا أقود مساري الصباحي وأتوقف عند محطة يكون فيها عدة طلاب بالفعل في انتظار الصعود. قبل أن أفتح الباب ويبدأوا في الصعود، أين كان يجب أن يقف هؤلاء الطلاب المنتظرون؟","options":["الوقوف تمامًا عند حافة الرصيف للصعود إلى الحافلة لحظة فتح الباب","الاصطفاف في صف واحد في مسار حركة المرور مباشرة بجانب باب الحافلة","الانتظار في مكان آمن بعيد عن الطريق حتى تتوقف الحافلة تمامًا","التجمع خلف المصد الخلفي مباشرة للابتعاد عن حركة المرور القادمة"],"explanation":"يجب على الطلاب المنتظرين للصعود البقاء في مكان آمن بعيد عن الطريق حتى تتوقف الحافلة تمامًا."},"78":{"q":"تنهي رحلة نشاط ما بعد الدوام المدرسي وتحتاج إلى إعادة تموضع حافلتك في موقف السيارات. لا تزال مجموعة من الطلاب متجمعة بالقرب من مؤخرة الحافلة في انتظار من سيأخذهم متأخرًا. وفقًا لإجراءات الحافلات المدرسية لدائرة السلامة العامة (DPS)، أي من الحالات التالية هي الحالة الوحيدة التي يجب أن تتجنب فيها الرجوع بالحافلة إلى الخلف أكثر من غيرها؟","options":["عندما يكون موقف السيارات فارغًا تمامًا وخاليًا من العوائق","عندما تقود في وضح النهار الكامل مع رؤية جيدة","عندما تكون مرايا الجانب والمرايا المتقاطعة نظيفة ومضبوطة بشكل صحيح","عندما يكون الطلاب موجودين في المنطقة خلف الحافلة أو بالقرب منها"],"explanation":"يكون الرجوع إلى الخلف أكثر خطورة عندما يكون الطلاب موجودين في المنطقة خلف الحافلة أو بالقرب منها، لأن الطفل قد يختفي عن النظر في ثوانٍ."},"79":{"q":"أنا أقوم بفحص ما قبل الرحلة على حافلة مدرسية وأضبط المرايا الخارجية المسطحة والمحدبة والمتقاطعة قبل صعود الطلاب. بخلاف مساعدتي على إبقاء كل طفل في مجال الرؤية، ما السبب الرئيسي لاشتراط وجود هذه المرايا الخاصة في حافلتي؟","options":["لتقليل النقاط العمياء حتى أتمكن من رؤية الأطفال في منطقة الخطر حول الحافلة","لتقليل وهج شمس الصباح حتى أتمكن من قراءة لافتات الطريق أمامي","للسماح لي بمراقبة حجرة المحرك الخلفية بحثًا عن ارتفاع درجة الحرارة أثناء المسار","للتأكد من أن الأضواء الحمراء الوامضة وذراع التوقف قد انتشرا بالكامل عند التوقف"],"explanation":"تُشترط المرايا المسطحة والمحدبة والمتقاطعة لتقليل النقاط العمياء حتى يتمكن السائق من رؤية الأطفال في منطقة الخطر حول الحافلة."},"80":{"q":"أنا أقود حافلة مدرسية محملة وأقترب من مزلقان سكة حديد غير محروس. أُبطئ سرعتي، وأستعد لفتح باب الخدمة والإنصات لأي قطار، وأبحث عن مكان آمن للتوقف قبل أقرب قضيب. وفقًا لقواعد دائرة السلامة العامة في تكساس (DPS)، أين يجب أن أُوقف الحافلة توقفًا تامًا؟","options":["في أي مكان بين 5 و10 أقدام قبل أقرب قضيب، طالما أن الحافلة خارج القضبان تمامًا","في مكان ما بين 15 و50 قدمًا قبل أقرب قضيب، ثم انظر وأنصت قبل العبور","في أي مكان بين 60 و90 قدمًا قبل أقرب قضيب لإعطاء حركة المرور خلفك مجالًا للتفاعل","في أي مكان بين 100 و150 قدمًا قبل أقرب قضيب حتى تحصل على رؤية واضحة على امتداد المسار"],"explanation":"عند كل مزلقان سكة حديد، يجب على الحافلة المدرسية أن تتوقف بين 15 و50 قدمًا قبل أقرب قضيب، ثم تنظر وتنصت قبل العبور."},"81":{"q":"أنا أقود حافلتي المدرسية نحو مزلقان سكة حديد غير مُتحكَّم فيه وتوقفتُ على مسافة آمنة قبل القضبان. قبل أن أُحرك الحافلة عبر القضبان، ماذا يتطلب مني قانون تكساس أن أفعل؟","options":["رفع جميع نوافذ الجانب وإيقاف المدفأة حتى أتمكن من التركيز الكامل على المزلقان","التحويل إلى ترس أعلى حتى تمتلك الحافلة قوة كافية لتجاوز القضبان بسرعة","فتح باب الخدمة ونافذتي بصفتي سائقًا، ثم النظر والإنصات لأي قطار قادم","البقاء جالسًا والباب مغلق والاعتماد على أضواء التحذير وبوابة المزلقان لتخبرني بأن الطريق آمن"],"explanation":"عند كل مزلقان سكة حديد، توقف، وافتح باب الخدمة ونافذة السائق، وانظر وأنصت لأي قطار قادم قبل العبور."},"82":{"q":"أثناء عبور القضبان، يجب ألا:","options":["تستمر في التحرك بثبات","تُغيّر التروس","تنظر في الاتجاهين","تبقى في مسارك"],"explanation":"لا تُغيّر التروس أثناء عبور القضبان."},"83":{"q":"أنا أقود حافلة مدرسية محملة عبر مزلقان سكة حديد عندما يتوقف المحرك فجأة وتتعطل الحافلة بينما لا يزال جزء منها فوق القضبان. لا أسمع قطارًا بعد، لكن المزلقان لا يحتوي على بوابات أو إشارات عاملة. ما أول شيء يجب أن أفعله؟","options":["إبقاء الطلاب جالسين وهادئين بينما أقوم بمحاولات متكررة لإعادة تشغيل المحرك وإخلاء القضبان","إطلاق البوق باستمرار، وتفعيل فرامل الانتظار، والبقاء في مقعدي لانتظار وصول المساعدة على الطريق","إخبار الطلاب بالبقاء هادئين في مقاعدهم بينما أخرج للتلويح لأي قطار أو حركة مرور قادمة","إخلاء كل طالب من الحافلة على الفور وقيادتهم إلى مسافة آمنة بعيدة تمامًا عن القضبان"],"explanation":"إذا تعطلت الحافلة أو علقت على قضبان السكة الحديد، أخلِ الجميع على الفور وانقلهم إلى مسافة آمنة بعيدة تمامًا عن القضبان."},"84":{"q":"حافلتي متوقفة على الكتف بعد عطل بسيط. أي من هذه الحالات سيتطلب مني إصدار أمر بإخلاء طارئ فوري لجميع الطلاب؟","options":["وجود حريق على متن الحافلة أو استقرار الحافلة في وضع غير آمن","اشتكاء بضعة طلاب بصوت عالٍ من أن الحافلة باردة جدًا وغير مريحة","تعطل الحافلة وانتظاري على الكتف لوصول شاحنة السحب","هطول مطر غزير وتوتر عدة طلاب بشأن التأخير الطويل"],"explanation":"أخلِ الحافلة عند وجود حريق على متنها أو عندما تستقر الحافلة في وضع غير آمن يُعرّض الطلاب للخطر."},"85":{"q":"أثناء الإخلاء، يجب على الطلاب الابتعاد عن الحافلة بمسافة لا تقل عن كم؟","options":["10 أقدام","100 قدم","قدمان","ميل كامل واحد"],"explanation":"انقل الطلاب إلى مسافة لا تقل عن 100 قدم بعيدًا، وخارج الطريق."},"86":{"q":"إنها بداية العام الدراسي وأنا أخطط للروتين الذي سأتبعه مع طلابي. قررتُ تخصيص وقت للتدرب وإطلاعهم على تدريبات إخلاء الحافلة. وفقًا لدائرة السلامة العامة (DPS)، ما الغرض الأساسي من إجراء جلسات الإطلاع والتدريبات على الإخلاء هذه؟","options":["حتى يبقى الطلاب أكثر هدوءًا وتسلية أثناء الرحلة الطويلة إلى المدرسة","حتى يعرف الطلاب بالضبط ما يجب فعله ويتمكنوا من الخروج بأمان إذا وقعت حالة طوارئ حقيقية","حتى يتعلم الطلاب الجلوس بهدوء وإبقاء الممر خاليًا أثناء الرحلات العادية","حتى يصعد الطلاب وينزلوا بشكل أسرع، مما يُبقي المسار في موعده"],"explanation":"يُعدّ التدرب على تدريبات الإخلاء الطلاب للتصرف والخروج بأمان في حالة طوارئ حقيقية بدلًا من الذعر."},"87":{"q":"أنا أقود حافلة مدرسية محملة والطريق أمامي ينحدر إلى منحدر طويل وشديد. أشعر بأن الحافلة تبدأ في الاندفاع بسرعة أكبر كلما زاد انحدار المنحدر. للحفاظ على الحافلة تحت السيطرة حتى أسفل المنحدر، ما أفضل طريقة لإدارة سرعتي؟","options":["التحويل إلى الوضع المحايد حتى لا يقاوم المحرك المنحدر، ثم الضغط الخفيف على الفرامل حسب الحاجة","البقاء في ترس عالٍ لقيادة سلسة والاستمرار في الضغط على الفرامل لإبقاء سرعتي منخفضة","اختيار ترس منخفض قبل بدء النزول واستخدام كبح خفيف ومتقطع للتحكم في سرعتي","الحفاظ على سرعتي العادية على الطريق وتطبيق ضغط قوي وثابت على الفرامل طوال الطريق إلى الأسفل"],"explanation":"على المنحدر الطويل والشديد، اختر ترسًا منخفضًا قبل بدء النزول حتى يساعد المحرك في كبح الحافلة، ثم استخدم كبحًا خفيفًا ومتقطعًا."},"88":{"q":"إنه صباح اثنين بارد وأنت تبدأ مسار حافلتك المدرسية. قمتَ بفحص كامل للفرامل بعد ظهر يوم الجمعة الماضي وظلت الحافلة متوقفة في الموقف طوال عطلة نهاية الأسبوع دون قيادة. قبل الانطلاق والطلاب على متنها، متى يجب أن تفحص الفرامل في هذه الرحلة؟","options":["يمكنك تخطيها هذا الصباح، لأن الفرامل خضعت لفحص كامل في نهاية الأسبوع الماضي ولم تتحرك الحافلة منذ ذلك الحين","فقط لأن الجو بارد اليوم؛ فحص الفرامل مطلوب في الشتاء لكنه اختياري في الطقس المعتدل","فقط إذا سمعتَها تصدر صريرًا أو شعرتَ بشيء خاطئ خلال أولى محطات التوقف في المسار","الآن، قبل هذه الرحلة، لأن الفرامل يجب أن تُفحص قبل كل رحلة بغض النظر عن آخر مرة تم فحصها فيها"],"explanation":"يجب فحص الفرامل قبل كل رحلة، لأن الفحص السابق صالح فقط للرحلة التي سبقها بغض النظر عن مدى حداثته."},"89":{"q":"أنت تقود حافلة مدرسية محملة بالكامل طولها 40 قدمًا على امتداد مستوٍ ومفتوح من الطريق السريع عندما تبدأ رياح جانبية قوية مفاجئة في الهبوب بقوة على الجانب المرتفع من الحافلة. سطح الطريق جاف ومسارك في موعده. أي إجراء يحمي سيطرتك على الحافلة بشكل أفضل في هذه الظروف؟","options":["تقليل سرعتك، لأن الهيكل المرتفع وعالي المظهر للحافلة يجعل التحكم بها أصعب في الرياح القوية","الحفاظ على سرعتك الحالية على الطريق السريع، لأن الطريق الجاف يمنحك ثباتًا كاملًا وللرياح تأثير ضئيل فعليًا","زيادة السرعة قليلًا لاختراق الهبات بشكل أسرع وقضاء وقت أقل معرضًا للرياح الجانبية","الحفاظ على سرعتك مع الضغط الخفيف المتقطع على الفرامل لتثبيت الحافلة في كل مرة تدفعها هبة رياح"],"explanation":"أبطئ السرعة في الرياح القوية لأن الهيكل المرتفع وعالي المظهر للحافلة يعمل كشراع ويصعب التحكم به."},"90":{"q":"أنت تقود حافلة مدرسية محملة على طريق سريع ريفي بمسارين عندما يتدفق ضباب كثيف وتنخفض الرؤية إلى بضع مئات من الأقدام. للحفاظ على سلامة الحافلة وطلابك قدر الإمكان، ماذا يجب أن تفعل؟","options":["الحفاظ على سرعتك المجدولة لكن مع تشغيل أضوائك العالية حتى يرى السائقون الآخرون حافلتك في وقت أبكر","تقليل سرعتك واستخدام أضوائك المنخفضة حتى لا ينعكس الضوء عليك ويُعميك","زيادة السرعة لاجتياز بنك الضباب بسرعة وتشغيل أضواء التحذير الرباعية","الحفاظ على سرعتك الحالية وإطفاء مصابيحك الأمامية حتى لا يشتت الوهج المنعكس عن الضباب انتباهك"],"explanation":"في الضباب، أبطئ السرعة واستخدم الأضواء المنخفضة لأن الأضواء العالية تنعكس عن قطرات الماء وترتد الضوء إليك، مما يقلل الرؤية."},"91":{"q":"إنها نهاية مساري بعد الظهر وقد دخلتُ ساحة الحافلات. أطفأتُ المحرك، وأمسكتُ بأوراقي، وتوجهتُ نحو المكتب لأنني متأخر. بعد ثلاثة أيام أعلم أن طفلًا نائمًا في رياض الأطفال ظل على متن الحافلة دون أن يلاحظه أحد لساعات بعد محطتي الأخيرة. أي تقصير من جانبي هو الأكثر تسببًا في ترك طفل على الحافلة؟","options":["اعتمدتُ فقط على عدّ الطلاب وهم يصعدون وينزلون عند كل محطة","ركنتُ الحافلة دون أن أُفعّل فرامل الانتظار أولًا في الساحة","تخطيتُ جولة ما بعد الرحلة إلى مؤخرة الحافلة قبل المغادرة","أطفأتُ أضواء التحذير الكهرمانية مبكرًا جدًا عند محطتي الأخيرة"],"explanation":"جولة ما بعد الرحلة إلى مؤخرة الحافلة هي الفحص الأخير الذي يكشف وجود طفل نائم أو مختبئ تُرك على متنها."},"92":{"q":"أنت متأخر على مسارك الصباحي وتريد التسرع في فحص ما قبل الرحلة لحافلتك المدرسية. تُلقي نظرة سريعة على الحافلة وتقرر الخطوة التي يمكنك تخطيها بأمان. للبقاء ملتزمًا بمتطلبات دائرة السلامة العامة في تكساس (DPS)، أي مما يلي ليس جزءًا مشروعًا من فحص ما قبل الرحلة يمكنك حذفه؟","options":["التأكد من أن ذراع التوقف يتحرك للخارج وغير تالف","التحقق من أن المرايا الداخلية والخارجية نظيفة ومضبوطة بشكل صحيح","التأكد من أن مخارج الطوارئ تُفتح وأن الممر خالٍ","تخطي أضواء التحذير الكهرمانية والحمراء لأنها كانت تعمل بالأمس"],"explanation":"يجب فحص أضواء التحذير الكهرمانية والحمراء فعليًا في كل رحلة وعدم افتراض أنها تعمل لمجرد أنها كانت تعمل من قبل."},"93":{"q":"أنا سائق حافلة مدرسية جديد وأحاول معرفة أين أحتاج إلى مراقبة الطلاب بأقصى عناية. يخبرني زميل أن \"منطقة الخطر\" هي المنطقة المحيطة بالحافلة مباشرة. بناءً على ما ينبغي أن أعرفه لاختبار تكساس، أي عبارة عن منطقة الخطر صحيحة؟","options":["تقع معظم إصابات الأطفال في منطقة الخطر، قرب الحافلة، لذا فهي تتطلب أقصى انتباهي","توجد منطقة الخطر فقط خلف الحافلة مباشرة، حيث يصعد الطلاب وينزلون","منطقة الخطر هي في الواقع أكثر مكان آمن للطلاب لأن الحافلة تحميهم","منطقة الخطر مهمة فقط عند مزالق السكك الحديدية، وليس أثناء المحطات العادية"],"explanation":"تقع معظم إصابات ووفيات الأطفال في منطقة الخطر قرب الحافلة، لذا فهي تتطلب أقصى انتباه السائق."},"94":{"q":"أضواؤك الحمراء الوامضة وذراع التوقف بالخارج، وقد أشرتَ للتو لثلاثة طلاب ينتظرون عند الرصيف ليبدأوا العبور أمام حافلتك. في تلك اللحظة تتجاهل شاحنة صغيرة (بيك أب) إشاراتك وتمر مسرعة على اليسار. ما أفضل إجراء يجب اتخاذه؟","options":["التلويح للطلاب بالعبور بسرعة قبل قدوم مركبة أخرى، لأن أضواءك الحمراء تمنحهم حق المرور","إبقاء الطلاب عند الرصيف حتى يكون الطريق خاليًا وآمنًا، ثم الإبلاغ عن المركبة المخالفة لموزع الحركة","التحرك للأمام لمتابعة الشاحنة حتى تتمكن من قراءة لوحة ترخيصها قبل أن تفر","إطلاق البوق والإشارة للطلاب بالإسراع في العبور حتى يتعلم سائق الشاحنة أن الأضواء تعني التوقف"],"explanation":"يثبت التجاوز غير القانوني أن المنطقة غير آمنة، لذا أبقِ الطلاب عند الرصيف حتى تتأكد من أن الطريق خالٍ، ثم أبلغ عن المخالف."},"95":{"q":"الساعة 5:45 صباحًا وأنا أقوم بفحص ما قبل الرحلة لحافلتي المدرسية قبل المسار الصباحي. وقتي ضيق وأريد التأكد من عدم تخطي أي شيء يحمي الأطفال عند المحطة. قبل الانطلاق، أي من أنظمة سلامة الطلاب هذه أحتاج فعلًا إلى التأكد من أنها تعمل؟","options":["فقط أضواء التحذير الكهرمانية والحمراء، لأنها ما يُحذّر حركة المرور بالتوقف","فقط ذراع التوقف وأضواء التحذير، لأن المرايا ميزة للراحة وليست جهاز سلامة","يجب التأكد من عمل أضواء التحذير وذراع التوقف والمرايا جميعها","فقط المرايا المتقاطعة، لأنها النظام الوحيد الذي يتيح لي رؤية منطقة الخطر"],"explanation":"أضواء التحذير وذراع التوقف والمرايا كلها أنظمة حيوية لسلامة الطلاب يجب التأكد من عملها أثناء فحص ما قبل الرحلة."},"96":{"q":"ما هو السبب الآمن لتحريك الحافلة بينما يوجد طفل في منطقة الخطر؟","options":["أنت متأخر","حركة المرور تنتظر","يبدو الطفل بخير","لا شيء مما سبق"],"explanation":"لا تتحرك أبدًا بينما يوجد طفل في منطقة الخطر؛ لا يوجد سبب آمن لذلك."},"97":{"q":"أحمل بالفعل رخصة قيادة تجارية من الفئة B مع تصديق الركاب (P) لأنني أقود حافلة سياحية، وقد عرضت عليّ منطقة تعليمية للتو مسارًا لقيادة حافلتها المدرسية كاملة الحجم. قبل أن أتمكن قانونيًا من قبول ذلك المسار، أي مما يلي يجب أن يكون صحيحًا بشأن تصديقات رخصتي؟","options":["تصديق الركاب (P) الخاص بي يغطي بالفعل الحافلات المدرسية، لذا فأنا مؤهل تمامًا ولا أحتاج إلى إضافة أي شيء آخر.","أحتاج فقط إلى إضافة تصديق المواد الخطرة (H)، لأن الحافلة المدرسية تُعامل كمركبة مواد خطرة.","يجب أن أُسقط تصديق الركاب (P) وأستبدله بتصديق الحافلة المدرسية (S)، لأنه لا يمكن حمل كليهما.","يجب أن أُضيف تصديق الحافلة المدرسية (S)، بحيث أحمل كلًا من تصديق الركاب (P) وتصديق الحافلة المدرسية (S)."],"explanation":"تتطلب قيادة حافلة مدرسية كلًا من تصديق الركاب (P) وتصديق الحافلة المدرسية (S)، لذا فحامل تصديق P يحتاج فقط إلى إضافة تصديق S."},"98":{"q":"أنت تقود حافلة مدرسية محملة عندما تشم رائحة دخان قادمة من حجرة المحرك وتقرر أن الإخلاء الفوري ضروري. قبل أن تطلب من أي طالب أن ينهض ويتجه نحو المخارج، ماذا يجب أن تفعل أولًا؟","options":["تفعيل فرامل الانتظار وإطفاء المحرك لتأمين الحافلة، ثم البدء في قيادة الطلاب للخارج","فتح مخرج الطوارئ الخلفي والبدء في عدّ الطلاب وهم ينزلون","الاتصال بموزع الحركة عبر اللاسلكي للإبلاغ عن الحريق وانتظار تعليماته","سحب الحافلة بعيدًا عن الطريق إلى مكان أكثر أمانًا قبل إنزال أي شخص"],"explanation":"قبل أن يتحرك أي طالب أثناء الإخلاء، أمّن الحافلة بتفعيل فرامل الانتظار وإطفاء المحرك حتى لا تتدحرج أو تُغذّي الحريق."},"99":{"q":"أثناء جولة ما قبل الرحلة، ألاحظ حقيبة ظهر وكرة قدم موضوعتين في ممر حافلتي المدرسية، على بُعد بضعة صفوف من الأمام. الحافلة لا تتحرك ولا يوجد طلاب على متنها بعد، لذا أشعر بإغراء تركهما والتعامل معهما لاحقًا. لماذا من الأهمية بمكان أن أُخلي هذه الأشياء السائبة من الممر قبل أن أبدأ في تحميل الطلاب؟","options":["لأن الأشياء السائبة المتروكة في الممر ستخدش وتُتلف غطاء الأرضية المطاطي تدريجيًا على مدار المسار","لأن الأشياء السائبة في الممر قد تتسبب في تعثر الطلاب المتجهين إلى مقاعدهم أو تسد المسار إلى مخرج الطوارئ","لأن الوزن الإضافي للأشياء في الممر يُغيّر توازن الحافلة ويجعل التوجيه أصعب بشكل ملحوظ في التحكم","لأن قانون الولاية يتطلب أن يكون الممر الأوسط خاليًا تمامًا قبل أن يمكن تشغيل أضواء التحذير الكهرمانية"],"explanation":"الممر الخالي يمنع الأشياء السائبة من التسبب في تعثر الطلاب ومن سد المسار إلى مخرج الطوارئ أثناء الإخلاء."},"100":{"q":"أنا متوقف عند محطة حافلة مدرسية وتطلب مني سائقة جديدة أن أُشير لها إلى \"منطقة الخطر\" حتى تعرف أين تراقب الأطفال بأقصى عناية. أي وصف يجب أن أعطيها إياه؟","options":["فقط شريط الطريق خلف المصد الخلفي مباشرة، لأنه المكان الوحيد الذي لا يستطيع السائق رؤيته","فقط الممر الداخلي ودرجة الصعود، حيث يتجمع الطلاب أثناء الصعود والنزول من الحافلة","المنطقة المحيطة بالحافلة بالكامل حيث يكون الطلاب في خطر، وتمتد نحو 10 أقدام على الجانبين والخلف وحتى 30 قدمًا في الأمام","فقط المسار المقابل البعيد الذي يجب على الطلاب عبوره، حيث تتجاهل حركة المرور المارة الأضواء الحمراء الوامضة"],"explanation":"منطقة الخطر هي المنطقة المحيطة بالحافلة بالكامل حيث يكون الأطفال في خطر، وتمتد نحو 10 أقدام على الجانبين والخلف وحتى 30 قدمًا في الأمام."},"101":{"q":"أنا متوقف عند محطة، وطالب نزل لتوه أسقط قفازاً بجوار حافلتي مباشرة. قبل أن أتحرك، عليّ أن أفكر في \"منطقة الخطر\" - وهي المساحة المحيطة بالحافلة حيث يكون الطفل الواقف فيها غير مرئي لي ومعرّضاً لأكبر خطر للاصطدام. إلى أي مسافة من الحافلة ينبغي أن أفترض أن منطقة الخطر هذه تمتد؟","options":["حوالي قدم واحدة فقط - بعرض درجة الباب لا أكثر، فيلزم أن يكون الطفل ملامساً للحافلة ليكون في خطر","ما يقارب 3 إلى 5 أقدام - أي بطول ذراع تقريباً حول جسم الحافلة من كل جانب","حتى نصف ميل، لأن أضواء التحذير مرئية للمرور من مسافة بعيدة","حوالي 10 أقدام أو أكثر حول الحافلة، وتمتد إلى مسافة أبعد مباشرة أمامها"],"explanation":"تمتد منطقة الخطر حوالي 10 أقدام أو أكثر حول الحافلة وتصل إلى مسافة أبعد مباشرة أمامها."},"102":{"q":"أراجع مسار حافلتي المدرسية وأحاول أن أحدد أين يجب أن أكون أكثر يقظة لتفادي وفيات الطلاب. خلال أي مرحلة من رحلتي يكون الأطفال الذين أنقلهم في أكبر خطر للوفاة من الناحية الإحصائية؟","options":["أثناء صعودهم إلى الحافلة أو نزولهم منها، حيث يُصاب معظمهم بحافلتي نفسها أو بمركبة عابرة","أثناء سير الحافلة بسرعة الطريق السريع بين محطتين مجدولتين","أثناء توقفي عند مزلقان سكة حديد والباب مفتوح، وأنا أنظر وأستمع","أثناء جلوسهم والحافلة متوقفة وفرملة الانتظار مشغّلة"],"explanation":"تحدث معظم وفيات طلاب الحافلات المدرسية أثناء صعود الأطفال أو نزولهم من الحافلة، إذ يُصابون بحافلتهم نفسها أو بمركبة عابرة."},"103":{"q":"أنت تُحمّل الطلاب عند محطة، وطفل يسكن في الجهة المقابلة من الشارع يجب أن يعبر الطريق أمام حافلتك. لإبقاء الطفل خارج منطقة الخطر وحيث تستطيع رؤيته بوضوح، على الأقل كم تكون المسافة أمام المصد الأمامي التي ينبغي أن يبدأ الطفل العبور عندها؟","options":["قدم واحدة أمام المصد","10 أقدام أمام المصد","50 قدماً أمام المصد","خلف الحافلة، حيث يكون المرور متوقفاً"],"explanation":"ينبغي على الطلاب العابرين أن يمشوا على بعد 10 أقدام على الأقل أمام الحافلة ليبقوا بعيداً عن منطقة الخطر الأمامية وضمن مجال رؤية السائق."},"104":{"q":"أقود حافلتي المدرسية نحو محطة محددة، وأشغّل أضواء التحذير الكهرمانية (الصفراء) على بعد حوالي 100 إلى 300 قدم قبلها. يرى المرور خلفي هذه الأضواء الكهرمانية الوامضة تُضاء. ماذا تشير هذه الأضواء الكهرمانية لي وللسائقين من حولي؟","options":["أن الحافلة توقفت بالكامل وأن الأضواء الحمراء وذراع التوقف قد امتدا الآن","أنه من الآمن زيادة السرعة وتجاوز المحطة قبل أن يبدأ الطلاب بالصعود","أن الحافلة تستعد للتوقف، لذا ينبغي على السائقين أن يبطئوا ويستعدوا للوقوف","أن منطقة الخطر خالية وأنه يمكن للطلاب الآن العبور خلف الحافلة"],"explanation":"تُشغّل أضواء التحذير الكهرمانية على بعد حوالي 100-300 قدم قبل المحطة للإشارة إلى أن الحافلة تستعد للتوقف، فيجب على المرور أن يبطئ ويستعد للوقوف."},"105":{"q":"أنا أشغّل حافلة مدرسية وتوقفت لتوي لإنزال الأطفال. أشغّل أضوائي الحمراء الوامضة وأمد ذراع التوقف. يرى سائق سيارة قادمة نحوي من الاتجاه المعاكس هذه الإشارات. بموجب قانون ولاية تكساس، ماذا يُلزَم هذا السائق القادم بفعله؟","options":["أن يبطئ ويتجاوز بحذر، لأن ذراع التوقف ينطبق فقط على المرور خلف الحافلة","أن يستمر بالسرعة الاعتيادية لأن الأضواء الحمراء مجرد تحذير للاستعداد للتوقف","أن يتابع بمجرد توقف أضواء التحذير الكهرمانية عن الوميض وإضاءة الأضواء الحمراء","أن يتوقف توقفاً تاماً ويبقى متوقفاً؛ ولا يجوز للسائق تجاوز الحافلة"],"explanation":"تُلزِم الأضواء الحمراء الوامضة وذراع التوقف الممتد قانونياً جميع المرور في كلا الاتجاهين بالتوقف التام والبقاء متوقفاً حتى يتم إطفاؤها."},"106":{"q":"أوقفت حافلتي المدرسية على طريق ذي مسارين لإنزال الأطفال، وأضوائي الحمراء وامضة وذراع التوقف ممتد. يحتاج طفل إلى عبور الطريق للوصول إلى المنزل في الجهة الأخرى. ماذا يجب على سائقي المركبات القادمة من كلا الاتجاهين فعله قانونياً؟","options":["أن يتوقف كلاهما توقفاً تاماً ويبقيا متوقفين حتى أسحب ذراع التوقف وأطفئ الأضواء الحمراء","أن يبطئا ويتابعا بحذر بمحاذاة الحافلة أثناء عبور الطفل","أن يتوقف فقط السائق الذي خلف حافلتي؛ ويمكن للمرور القادم أن يتابع","أن يتوقفا فقط إذا رأيا فعلاً طفلاً يخطو إلى الطريق"],"explanation":"أثناء التحميل والإنزال يجب أن يبقى المرور من كلا الاتجاهين متوقفاً تماماً حتى يُسحب ذراع التوقف وتُطفأ الأضواء الحمراء، لأن معظم الوفيات تحدث أثناء عبور الأطفال."},"107":{"q":"أنهيت تحميل الطلاب ووصل آخر طفل إلى مقعده. مرآتي المحدّبة على الجانب الأيمن ومرايا العبور الأمامية مضبوطة والممر خالٍ. في أي لحظة ينبغي أن أتفحص جميع مراياي للتحقق من مناطق الخطر حول الحافلة؟","options":["فقط بعد أن أحرر الفرملة وتبدأ الحافلة بالتدحرج إلى الأمام","قبل أن أحرّك الحافلة، وهي ما تزال متوقفة، للتأكد من خلو مناطق الخطر","لا حاجة لذلك، لأن مرايا العبور تبقي كل طالب ضمن الرؤية أصلاً","فقط عند القيادة ليلاً، لأن وضوح الرؤية نهاراً يجعل فحص المرايا غير ضروري"],"explanation":"استخدم المرايا الخارجية ومرايا العبور للتأكد من خلو منطقة الخطر حول الحافلة قبل التحرك، لأن طفلاً اختفى عن الرؤية قد يكون ما يزال هناك."},"108":{"q":"أقترب من محطة سكنية، وأنتقل من أضواء التحذير الكهرمانية إلى الأضواء الحمراء الوامضة، ويتأرجح ذراع التوقف إلى الخارج على جانب حافلتي بينما يبدأ الطلاب بالنزول. يراقب سائق في المسار المقابل ذراع التوقف الممتد ذاك. ماذا يوجّه هذا الذراع المرورَ القادم قانونياً بفعله؟","options":["أن يبطئ، ويتجه نحو الكتف، وينساب متجاوزاً حافلتي من اليسار","أن يفسح المجال لحافلتي أولاً، ثم يتابع بحذر بمجرد نزول الطلاب","أن يتوقف توقفاً تاماً ويبقى متوقفاً حتى يُطوى الذراع مرة أخرى","أن يزيد سرعته للحظة لإخلاء المنطقة قبل أن يصل الأطفال إلى الطريق"],"explanation":"ذراع التوقف الممتد أمر قانوني يُلزِم جميع المرور القادم في كلا الاتجاهين بالتوقف التام والبقاء متوقفاً حتى يُسحب الذراع وتُطفأ الأضواء الحمراء."},"109":{"q":"أقود حافلتي المدرسية نحو محطة ينتظر فيها ثلاثة طلاب على الكتف. ما زلت على بعد حوالي 200 قدم على طريق سرعته 35 ميلاً في الساعة. لبدء تسلسل التحميل بشكل صحيح وتحذير المرور من أنني على وشك التوقف، أي جهاز ينبغي أن أشغّله أولاً؟","options":["الأضواء الحمراء الوامضة وذراع التوقف، ليتوقف المرور بينما أنا ما زلت أتدحرج نحو الطلاب","أضواء الطوارئ الرباعية، لأنها الإشارة المعتادة على أن الحافلة تستعد للتوقف","مرايا العبور والمرايا المحدّبة، لأتأكد من خلو منطقة الخطر قبل إشارة أي مرور","أضواء التحذير الكهرمانية (الصفراء)، للإشارة إلى المرور الأمامي بأنني أستعد للتوقف للتحميل"],"explanation":"يبدأ تسلسل التحميل بتشغيل أضواء التحذير الكهرمانية على بعد حوالي 100-300 قدم قبل المحطة لتحذير المرور الأمامي بأن الحافلة تستعد للتوقف للتحميل."},"110":{"q":"إنه صباح ضبابي، وقد توقفت لتوي لإنزال ثمانية طلاب عند محطة حيّهم. بعد نزولهم، أعدّ رؤوسهم وهم يبتعدون عن الحافلة. لماذا يكون هذا العدّ أهم ما يكون قبل أن أحرر الفرملة وأنطلق؟","options":["للتأكد من حصر كل طالب وابتعاده عن منطقة الخطر، بحيث لا يبقى أي طفل بجانب الحافلة أو أمامها عند تحركي","للتحقق من تطابق العدد مع قائمتي حتى أسجّل حضوراً دقيقاً لمكتب المدرسة","للتأكد من أن لا أحد من الطلاب مشى خلف الحافلة، لأن طفلاً ينزلق إلى المنطقة العمياء الخلفية لن يكون مرئياً عند تحركي","لضبط توقيت التوقف حتى أبقى ضمن الجدول وأتجنب الوصول متأخراً إلى المحطة التالية"],"explanation":"يؤكد عدّ الطلاب صعوداً ونزولاً حصر كل طفل وابتعاده عن منطقة الخطر قبل التحرك، لأن معظم وفيات الحافلات المدرسية هي لطلاب أُصيبوا بحافلتهم نفسها."},"111":{"q":"أنزلت لتوك عدة طلاب عند محطة سكنية. وبينما تعدّ الرؤوس، تدرك أن طفلاً نزل من الحافلة لم يعد مرئياً من مقعدك - لا تستطيع رؤيته في أي من مراياك أو في منطقة الخطر. المرور يتكدّس خلفك وسيارة تطلق بوقها. ماذا ينبغي أن تفعل؟","options":["تتقدم ببطء بضع أقدام لإفساح المرور المُطلِق للبوق، ثم تتفحص مراياك مجدداً بحثاً عن الطفل","تبقي الحافلة مؤمَّنة ولا تتحرك حتى تجد الطفل المفقود وتتأكد من أنه بأمان خارج منطقة الخطر","تنقر البوق مرتين لتنبيه الطفل، وتتابع بمجرد انطفاء أضواء التحذير","تحرر الفرملة وتتقدم برفق، لأن الطفل غير المرئي على الأرجح قد وصل إلى الرصيف بالفعل"],"explanation":"إذا اختفى طالب عن الرؤية أثناء العدّ، أبقِ الحافلة مؤمَّنة ولا تتحرك حتى تجد الطفل وتتأكد من أنه بأمان خارج منطقة الخطر."},"112":{"q":"أقود حافلتي المدرسية الفارغة على مسار ريفي وأقترب من مزلقان سكة حديد لا توجد فيه إشارات تحذير ولا قطار في الأفق. المرور خفيف وأنا متأخر بضع دقائق عن الجدول. ماذا يُلزَم أن أفعل عند هذا المزلقان؟","options":["بما أن الحافلة فارغة ولا قطار مرئياً، يجوز لي أن أبطئ وأعبر دون توقف تام","أتوقف فقط إذا كانت بوابات المزلقان منخفضة أو أضواء التحذير وامضة لقطار قادم","أتوقف على بعد بين 15 و50 قدماً قبل القضبان، وأفتح باب الخدمة ونافذة السائق، وأنظر وأستمع، ثم أعبر بسرعة منخفضة","أتوقف عند القضبان، ثم أخفّض إلى سرعة أدنى بينما الحافلة على القضبان لأعبرها أسرع"],"explanation":"عند كل مزلقان سكة حديد يجب أن تتوقف الحافلة المدرسية على بعد 15 إلى 50 قدماً قبل القضبان، وتفتح الباب ونافذة السائق للنظر والاستماع، ثم تعبر بسرعة منخفضة دون تغيير السرعة."},"113":{"q":"أقود حافلة مدرسية محمّلة وأتوقف على بعد 30 قدماً قبل مزلقان سكة حديد على طريق ريفي صاخب. أشغّل فرملة الانتظار، ثم أمدّ يدي وأفتح باب الخدمة وأفتح نافذتي قليلاً على جانب السائق. تسألني مساعِدة جديدة تجلس في المقدمة لماذا عنيت بفتحهما عند توقف تام. قبل أن أحرر الفرملة وأعبر القضبان برفق، ما السبب الحقيقي الذي يُلزِمني فيه قسم السلامة العامة (DPS) بفتح ذلك الباب والنافذة هنا؟","options":["للسماح بخروج أبخرة الديزل والحرارة من مقصورة الحافلة قبل أن أبدأ العبور البطيء بسرعة منخفضة","للإشارة إلى أي طلاب يجلسون في المقدمة بأن يلتزموا الصمت ويبقوا جالسين أثناء عبورنا القضبان","لإتاحة مسار واضح لمراقب سكة حديد منتظر ليصعد ويؤكد بيده أن المعبر آمن","لإزالة حاجز الزجاج وضجيج المحرك حتى أتمكن من النظر في القضبان وسماع قطار قادم قبل العبور"],"explanation":"يزيل فتح الباب ونافذة السائق عند المزلقان حاجز الزجاج وضجيج المحرك حتى تتمكن من النظر في القضبان وسماع قطار قادم قبل العبور."},"114":{"q":"لا تغيّر السرعات أثناء عبور:","options":["ساحة مستوية","القضبان","موقف سيارة","ممر مدخل"],"explanation":"لا تغيّر السرعة على القضبان."},"115":{"q":"أنهيت لتوك الإنزال عند محطة سكنية وأنت على وشك تحرير الفرامل والانطلاق. قبل أن تحرّك الحافلة، تقوم بعدّ الطلاب الذين أنزلتهم. ما السبب الرئيسي لقيامك بهذا العدّ؟","options":["للتأكد من أن كل طالب أنزلته قد ابتعد تماماً عن الحافلة ومنطقة الخطر","للتحقق من أن كل طالب دفع الأجرة الصحيحة للرحلة","للتأكد من أن الطلاب الباقين على متن الحافلة انتقلوا إلى المقاعد الأمامية","للتحقق من أن الطلاب أغلقوا جميع النوافذ الجانبية قبل النزول"],"explanation":"بعد الإنزال، عُدّ الطلاب النازلين وأبقِهم ضمن الرؤية للتأكد من أن كل طالب قد ابتعد تماماً عن الحافلة ومنطقة الخطر قبل التحرك."},"116":{"q":"أنا أنزل الطلاب عند محطة بعد الظهر، وطفل نزل لتوه يحتاج إلى الوصول إلى الرصيف على الجانب نفسه الذي فيه الباب. لإبقاء الطفل آمناً وضمن رؤيتي طوال الوقت، إلى أين ينبغي أن أوجّه هذا الطالب ليمشي بعد مغادرة الحافلة؟","options":["مباشرة إلى الخلف بمحاذاة الجانب نحو العجلات الخلفية للوصول إلى الرصيف بسرعة","بعيداً إلى الجانب، مع البقاء في العراء حيث أستطيع رؤية الطالب من مقعدي","قريباً من إطارات الحافلة وجسمها ليبقى الطالب بعيداً عن المرور","تحت منطقة المصد الأمامي حيث تمنحني مرآة العبور التغطية"],"explanation":"يجب أن يتحرك الطالب النازل بعيداً إلى الجانب ويبقى في العراء حيث يستطيع السائق رؤيته من مقعده طوال الوقت."},"117":{"q":"أنهي مساري بعد الظهر، والمحطة التالية طريق مغلق ضيق (cul-de-sac) لا توجد فيه طريقة سهلة لإدارة الحافلة. عدة طلاب ينتظرون قرب الرصيف. وفقاً لإجراءات الحافلات المدرسية في تكساس، ما أفضل طريقة لي للتعامل مع المناورة عند هذه المحطة؟","options":["أن أرجع الحافلة بسرعة إلى الطريق المغلق لأخلي المنطقة قبل أن يبدأ الطلاب بالتحرك نحوي","أن أرجع للخلف وأنا أراقب المرآة المحدّبة اليمنى فقط، لأن ذلك الجانب يغطي الجزء الأخطر من منطقة الخطر","أن أتجنب الرجوع للخلف إن وُجدت أي طريقة لتخطيط المسار أو وضع الحافلة بحيث لا أضطر إلى ذلك، لأن الرجوع للخلف من أخطر المناورات","أن أرجع للخلف دون مساعِد ما دامت الأضواء الحمراء وذراع التوقف مشغّلة، لأن المرور القادم سيكون متوقفاً أصلاً"],"explanation":"تجنّب الرجوع بالحافلة المدرسية للخلف كلما أمكن بتخطيط المسار أو إعادة وضعها، لأن المنطقة العمياء الخلفية تجعل الرجوع للخلف من أخطر المناورات."},"118":{"q":"تُشير إليك إحدى الأمهات للتوقف في منتصف الطريق بين محطتين مجدولتين وتطلب منك إنزال طفلها هناك عند زاوية مدخل منزلها، لأن ذلك سيوفّر على الطفل مشياً قصيراً. وفقاً لقواعد قسم السلامة العامة (DPS) للحافلات المدرسية في تكساس، أين ينبغي أن تُحمّل الطلاب وتُنزلهم؟","options":["حيثما تنتظر إحدى الأمهات، لأن تسليم الطفل مباشرة إلى أحد الوالدين دائماً الخيار الأكثر أماناً","عند أقرب منعطف أو انحناء، لأن الإبطاء هناك يحذّر المرور القادم طبيعياً ليتوقف","عند أي مدخل خاص على طول المسار، ما دمت تشغّل الأضواء الحمراء الوامضة أولاً","فقط عند المحطات المخصصة المحددة للمسار، بغض النظر عن طلبات الوالدين"],"explanation":"حمّل الطلاب وأنزلهم فقط عند المحطات المخصصة المحددة للمسار، حتى لو طلب أحد الوالدين موقعاً آخر."},"119":{"q":"تساعدك المرايا الخارجية على رؤية:","options":["السماء فوقنا","الجوانب ومناطق الخطر","كتلة المحرك","قرص الراديو"],"explanation":"إنها تُظهر الجوانب ومناطق الخطر."},"120":{"q":"تتيح لك مرايا العبور رؤية:","options":["السماء البعيدة","المنطقة أمام الحافلة","المقعد الخلفي","عداد الوقود"],"explanation":"إنها تُظهر المنطقة أمام الحافلة."},"121":{"q":"أنهيت لتوي تحميل آخر مجموعة من الطلاب عند محطة صباحية مزدحمة. لا يزال بعض الأطفال يتحركون نحو مقاعدهم في الممر، وأحدهم واقف يضع حقيبة ظهر في منطقة الرفوف العلوية. قبل أن أحرر فرملة الانتظار وأنطلق من الرصيف، ما الشرط الذي يجب أن يتحقق؟","options":["أن يكون كل طالب جالساً، والممر خالياً، ولا أحد يتحرك في الحافلة.","أن يكون جميع الطلاب على المتن والباب مغلقاً، فيجوز لي أن أبدأ التدحرج ببطء.","أن يكون الطلاب القريبون من المقدمة جالسين، حتى لو كان بعضهم في الخلف ما زال واقفاً.","أن يقف الطلاب بأمان خلف الخط الأبيض حتى يبقى الممر مفتوحاً لهم."],"explanation":"لا تبدأ أبداً بتحريك الحافلة حتى يكون كل طالب جالساً والممر خالياً ولا أحد يتحرك، لأن الطالب الواقف قد يُقذف أو يسقط."},"122":{"q":"توقفت لإنزال الطلاب، وطفل يحتاج إلى عبور الطريق للوصول إلى المنزل ينزل من حافلتي. وفقاً لإجراءات الحافلات المدرسية في تكساس، متى ينبغي أن يبدأ هذا الطالب العبور أمام الحافلة؟","options":["بمجرد نزوله من الدرجة السفلى، لأن الأضواء الحمراء وذراع التوقف يحميانه أصلاً","فقط بعد أن أعطيه إشارة يد واضحة بأن العبور آمن، عابراً على بعد حوالي 10 أقدام أمام الحافلة حيث أستطيع رؤيته","متى بدا له الطريق خالياً من المرور، ماشياً قريباً خلف الحافلة ليبقى بعيداً عن المسارات القادمة","مباشرة بعد أن تبدأ أضواء التحذير الكهرمانية بالوميض وأنا أبطئ للتوقف عند المحطة"],"explanation":"يجب أن ينتظر الطالب العابر إشارة يد واضحة من السائق بأن العبور آمن، ثم يعبر على بعد حوالي 10 أقدام أمام الحافلة ضمن رؤية السائق."},"123":{"q":"توقفت لإنزال طلاب المرحلة الابتدائية الذين يجب أن يعبروا الطريق للوصول إلى منازلهم. أضواؤك الحمراء وذراع التوقف مشغّلة، وطالب يقف عند الرصيف منتظراً ليمشي إلى نقطة العبور على بعد حوالي 10 أقدام أمام حافلتك. ينبغي ألا يخطو الطالب إلى الطريق للعبور إلا عندما:","options":["تبدأ أضواء التحذير الكهرمانية بالوميض ويتأرجح ذراع التوقف إلى الخارج","تطلق نقرة بوق قصيرة لتُعلِم الطالب أن المرور قد توقف","تعطي الطالب إشارة يد واضحة تخبره بأن العبور آمن","تتوقف جميع المركبات الأخرى في كلا الاتجاهين توقفاً تاماً"],"explanation":"وجّه الطلاب ألا يعبروا إلا بإشارة يد واضحة منك، لأن السائق في موضع يتيح له رؤية منطقة الخطر كاملة والتأكد من أن المرور قد توقف."},"124":{"q":"أنا سائق حافلة مدرسية جديد أراجع أين يحدث فعلاً أكبر خطر على طلابي خلال رحلتي اليومية. أقود مسافات طويلة من الطريق السريع المفتوح، وأندمج عند منحدرات الدخول والخروج من الطريق السريع، وأعبر جسراً طويلاً فوق نهر. بناءً على إرشادات قسم السلامة العامة (DPS) في تكساس، خلال أي جزء من مساري يكون طلابي في أكبر خطر؟","options":["قيادة مقاطع الطريق السريع المفتوح، حيث تمنحني السرعات الأعلى وقتاً أقل للتفاعل مع أي مشكلة","عبور جسر النهر الطويل، حيث تقلل هبّات الرياح والمسارات الضيقة من هامش الخطأ لدي","الاندماج عند منحدرات الدخول والخروج من الطريق السريع، حيث يجب أن أمتزج بمرور سريع","التحميل والإنزال عند المحطات، حيث يصعد الطلاب وينزلون وقد يُصابون بحافلتي أو بمرور عابر"],"explanation":"التحميل والإنزال عند المحطات هو أخطر جزء من العمل، لأن معظم وفيات الحافلات المدرسية هي لطلاب أُصيبوا بحافلتهم نفسها أو بمرور عابر."},"125":{"q":"أقود مساري الصباحي حين أشمّ رائحة دخان قوية وأرى لهباً يخرج من حجرة المحرك في حافلتي المدرسية. الحافلة متوقفة على الكتف وجميع طلابي ما زالوا في مقاعدهم. وفقاً لإجراءات قسم السلامة العامة (DPS) في تكساس، أي وضع يُلزِمني بإخلاء الحافلة؟","options":["وجود حريق في الحافلة أو أي وضع خطير يجعل البقاء على متنها أخطر من النزول منها","تأخر الحافلة بضع دقائق عن الجدول وحاجتي إلى تعويض الوقت الضائع على المسار","بدء بعض الطلاب بالتململ والتذمر من أن الرحلة تستغرق وقتاً طويلاً","توقف الحافلة بأمان على الكتف والمحرك ما زال يعمل بشكل طبيعي"],"explanation":"أخلِ الحافلة كلما كان البقاء على متنها أخطر من مغادرتها، كحدوث حريق أو أبخرة أو وضع غير آمن أو خطر اصطدام."},"126":{"q":"أنا أقود حافلتي المدرسية المحمّلة وتحدث عدة حالات طارئة أثناء مساري. في أيٍّ من هذه المواقف يجب أن أُخلي جميع الطلاب من الحافلة فوراً بدلاً من إبقائهم في مقاعدهم؟","options":["بدأ المحرك يُصدِر دخاناً خفيفاً لكنني ما زلت أستطيع توجيه الحافلة والكبح بها","توقّفت الحافلة على سكة القطار وهي واقفة في مسار قطار قادم","يُبلِّغ طالب عن رائحة وقود خفيفة بينما ننتظر عند إشارة مرور حمراء","يفشل أحد المصابيح التحذيرية الكهرمانية في الإضاءة وأنا أقترب من محطة توقّف معلّمة"],"explanation":"أَخلِ الحافلة فوراً إذا كانت متوقفة في مسار قطار قادم، لأنك لا تستطيع تحريك الحافلة ولا يستطيع القطار التوقف في الوقت المناسب."},"127":{"q":"تتعطّل حافلتي المدرسية على الطريق ويبدأ الدخان يملأ المقصورة، فأُصدِر أمراً بالإخلاء الفوري. ومع انسداد باب الخدمة الأمامي بسبب العائق، إلى أي جزء من الحافلة تدرّبتُ على توجيه الطلاب باعتباره مخرج طوارئ مخصّصاً؟","options":["نافذة جانب السائق بجوار عجلة القيادة، لأنها الأقرب إلى مقعدي","فتحة مقصورة الأمتعة أسفل منطقة المقاعد، التي تُفتح من الداخل","باب الخروج الخلفي ونوافذ الطوارئ على جانبي الحافلة","لوحة التهوية في السقف فوق الممر الأوسط، التي تُرفع للأعلى مباشرة"],"explanation":"باب الطوارئ الخلفي ونوافذ الطوارئ الجانبية مصمَّمة ومعلَّمة كمخارج إخلاء عندما يكون الباب الأمامي مسدوداً."},"128":{"q":"لقد أنزلتَ آخر مجموعة من الطلاب ودخلتَ بالحافلة إلى ساحة الحافلات في نهاية مسارك بعد الظهر. قبل أن تُقفل الحافلة وتغادر منتهياً من يومك، ما هو الفحص الأمني الوحيد الذي يجب أن تؤديه بنفسك داخل الحافلة؟","options":["املأ خزان الوقود حتى يكون الحافلة جاهزة لرحلة الصباح","سجّل قراءة عدّاد المسافة النهائية في ورقة سجل الرحلة","أعِد ضبط مرايا التقاطع إلى وضعها الأصلي","امشِ على طول الممر كاملاً حتى المقعد الخلفي للتأكد من عدم بقاء أي طفل على متن الحافلة"],"explanation":"في نهاية كل مسار، امشِ على طول الممر كاملاً حتى الخلف للتأكد من عدم ترك أي طفل خلفك في الحافلة."},"129":{"q":"أنا أقود في مساري الصباحي وأقترب من محطة توقّف ريفية حيث يتجمّع خمسة طلاب في انتظاري. وأنا أقترب وقد شغّلتُ مصابيحي التحذيرية الكهرمانية، أين ينبغي أن يتمركز هؤلاء الطلاب ليكونوا في أأمن وضع بينما ينتظرون توقفي الكامل؟","options":["خارج الطريق، بعيداً للخلف عن حافة مسار السير","على كتف الطريق، تماماً عند خط الضباب المرسوم","على الطريق، مصطفّين حيث سيُفتح باب الخدمة","واقفين خلف المكان الذي ستتوقف فيه الحافلة مباشرة"],"explanation":"ينبغي أن ينتظر الطلاب خارج الطريق وبعيداً للخلف عن مسار السير، بعيداً عن منطقة الخطر وقت اقتراب الحافلة وتوقفها."},"130":{"q":"إنه صباح يوم اثنين مزدحم ويصعد إلى حافلتي المدرسية عدد من الطلاب أكثر من عدد المقاعد المتوفرة لديّ. يسأل بعضهم إن كان بإمكانهم فقط الإمساك بمساند المقاعد والركوب واقفين في الممر حتى المحطة التالية. وفقاً لقواعد الحافلات المدرسية في تكساس، أي إجابة صحيحة؟","options":["الوقوف مسموح به ما دام الممر يبقى خالياً لمخارج الطوارئ","لا يجوز لأي طالب الركوب واقفاً؛ يجب أن يجلس الجميع قبل أن أُحرّك الحافلة","الوقوف مسموح به للرحلات القصيرة التي تقل عن نحو 10 أقدام من السير بين محطات متقاربة","الوقوف لا بأس به إذا أبقى أولئك الطلاب حقائب ظهورهم على أحضانهم أثناء وقوفهم"],"explanation":"لا يجوز لأي طالب الركوب واقفاً؛ يجب أن يجلس كل طالب قبل تحريك الحافلة."},"131":{"q":"أنا أقود مساراً لذوي الاحتياجات الخاصة، ويدفع أحد الوالدين طفله إلى حافلتي على كرسي متحرك. يبقى الطفل جالساً في الكرسي طوال الرحلة لأن نقله إلى مقعد الحافلة غير ممكن. قبل أن أُحرّر فرملة الوقوف وأنطلق من المحطة، ماذا يجب أن أفعل بذلك الكرسي المتحرك؟","options":["أضعه في الممر المفتوح ليتمتع الطفل بأكبر مساحة للساقين وأسهل طريق إلى المخرج","أُفعّل فرامل الكرسي المتحرك نفسه وأتركه واقفاً حرّاً، لأن العجلات المقفلة ستثبّته في مكانه","أُثبّت الكرسي المتحرك بالحافلة بنظام التثبيت بحيث يكون كلٌّ من الكرسي وراكبه مقيَّداً","أطوي الكرسي مسطحاً وأخزّنه، ثم أنقل الطفل إلى مقعد ركّاب عادي للرحلة"],"explanation":"يجب تثبيت الكراسي المتحركة بالحافلة بنظام التثبيت بحيث يكون كلٌّ من الكرسي وراكبه مقيَّداً."},"132":{"q":"أنت تقود حافلتك المدرسية في مسار يمرّ بمنطقة مدرسية معلّمة. تومض أضواء منطقة المدرسة المنصوبة، ويسير بعض الطلاب على الرصيف باتجاه المبنى. خفّت حركة المرور أمامك وتشعر بإغراء تعويض الوقت لأنك متأخر بضع دقائق. أي إجراء هو الطريقة الصحيحة والأكثر أماناً لقيادة حافلتك عبر هذه المنطقة؟","options":["حافظ على سرعتك المعتادة في المسار لأن الأطفال على الرصيف وليسوا بعدُ على الطريق","سرّع لفترة وجيزة لتجاوز المنطقة سريعاً وتقليل الوقت الذي يكون فيه الأطفال قرب حافلتك المتحركة","أوقف حافلتك تماماً في مسار السير وانتظر حتى يدخل كل طفل إلى المبنى","خفّف سرعتك وقُد ببطء، وابقَ متيقظاً ومستعداً للتوقف من أجل الأطفال قرب الطريق"],"explanation":"قُد ببطء عبر منطقة المدرسة وابقَ متيقظاً ومستعداً للتوقف، لأن الأطفال قرب الطريق قد يخطون فجأة إلى حركة المرور."},"133":{"q":"تساعدك المرايا المحدّبة على رؤية:","options":["السماء البعيدة","منطقة واسعة قرب الحافلة","داخل المحرك","المقعد الخلفي فقط"],"explanation":"تُظهِر المرايا المحدّبة منطقة واسعة قريبة من الحافلة."},"134":{"q":"تساعدك المرايا المسطحة (West Coast) على رؤية:","options":["مباشرة إلى الأعلى","بعيداً للخلف على طول الجانبين","عدّادات لوحة القيادة","منطقة السقف"],"explanation":"تُظهِر المرايا المسطحة المنطقة البعيدة للخلف على طول الجانبين."},"135":{"q":"تتوقف عند محطة معلّمة وتُفعّل مصابيحك الحمراء الوامضة وذراع التوقف. ينتظر ستة طلاب عند الرصيف ويبدؤون الصعود إلى حافلتك. وهم يصعدون الدرجات تباعاً، أي إجراء يحميهم على أفضل وجه أثناء عملية الصعود هذه؟","options":["عُدّ كل طالب أثناء صعوده وواصِل مراقبتهم، حتى تتأكد من حصر الجميع ووجودهم في مرأى عينك قبل أن تتحرك.","انتظر حتى يجلس آخر طالب، ثم قُم بعدّ واحد للرؤوس من مقعد السائق قبل الانطلاق.","راقِب فقط مرآة التقاطع اليمنى لتتمكن من رصد من لا يزال واقفاً في منطقة الخطر بجوار الباب.","حرّر فرملة الوقوف وتقدّم ببطء أثناء صعود الطلاب لتبقى في الموعد المحدد للمحطة التالية."],"explanation":"عُدّ كل طالب أثناء صعوده وواصِل مراقبتهم حتى يبقى الجميع محصورين وفي مرأى عينك قبل أن تتحرك الحافلة."},"136":{"q":"أنا أقود مساري وأصل إلى محطة حيث ينتظر ثلاثة طلاب النزول. قبل أن أفتح الباب وأدعهم يخطون للنزول، في أي حالة يجب أن تكون الحافلة؟","options":["تتباطأ حتى الزحف تقريباً مع وميض المصابيح التحذيرية الكهرمانية ليعلم المرور أنني على وشك التوقف","متوقفة تماماً مع تفعيل المصابيح الحمراء الوامضة وذراع التوقف","محتجزة لفترة وجيزة عند المحطة مع تشغيل مصابيح الخطر الرباعية فقط أثناء فتح الباب","متوقفة لكنها تتقدم ببطء بالفعل بينما ينزل آخر طالب لتوفير قليل من الوقت"],"explanation":"يجب أن تكون الحافلة متوقفة تماماً مع تفعيل المصابيح الحمراء الوامضة وذراع التوقف قبل صعود أو نزول أي طالب."},"137":{"q":"بينما أقود حافلتي المدرسية المحمّلة نازلاً منحدراً مبتلّاً، تتوقف سيارة فجأة أمامي فأضطر إلى دوس دواسة الفرامل بقوة. حافلتي مزوّدة بفرامل مانعة للانغلاق (ABS). في هذه الحالة الطارئة، ماذا يتيح لي نظام ABS فعلاً أن أفعله مما لا أستطيع فعله بشكل موثوق بدونه؟","options":["إيقاف الحافلة على مسافة أقصر بشكل ملحوظ من حافلة بدون ABS","ضخّ دواسة الفرامل مراراً ليستعيد الإطارات تماسكها","الحفاظ على التحكّم في التوجيه لأتمكن من توجيه الحافلة حول السيارة أثناء الكبح بقوة","الكبح بنفس القوة على المنحدر المبتلّ كما لو كنت على رصيف جاف ومستوٍ"],"explanation":"يمنع نظام ABS انغلاق العجلات أثناء الكبح الشديد، فتحتفظ بالتحكّم في التوجيه لتوجيه الحافلة حول العائق."},"138":{"q":"أنا أقترب من محطة حافلة مدرسية معلّمة على طريق ذي مسارين وأحتاج إلى بدء التنبيه لحركة المرور بأنني على وشك التوقف لأقلّ الطلاب. عند هذه النقطة من اقترابي — قبل أن أوقف الحافلة فعلاً — أي المصابيح يُطلب مني تفعيلها؟","options":["المصابيح الحمراء الوامضة وذراع التوقف، ليعلم السائقون خلفي أن يتوقفوا فوراً","فقط مصابيح الخطر الرباعية المعتادة، لأن الحافلة لم تتوقف بعد","لا مصابيح تحذيرية على الإطلاق حتى تتوقف الحافلة تماماً ويُفتح الباب","المصابيح التحذيرية الكهرمانية (الصفراء)، على بُعد نحو 100 إلى 300 قدم قبل المحطة"],"explanation":"تُفعَّل المصابيح التحذيرية الكهرمانية على بُعد نحو 100 إلى 300 قدم قبل المحطة لتحذير المرور بأن الحافلة تستعد لإركاب أو إنزال الطلاب."},"139":{"q":"أنا أقود مساري وأقترب من محطة معلّمة حيث ينتظر طالبان عند الرصيف. وأنا أتباطأ، أُفعّل مصابيحي التحذيرية الكهرمانية (الصفراء) قبل المحطة بمسافة كافية. عند أي نقطة ينبغي أن تُضاء فعلاً مصابيحي الحمراء الوامضة وذراع التوقف؟","options":["فقط بعد أن أتوقف تماماً لإركاب أو إنزال الطلاب","بمجرد أن أُطفئ المصابيح التحذيرية الكهرمانية بينما لا تزال الحافلة تتدحرج نحو المحطة","على بُعد نحو 100 إلى 300 قدم قبل المحطة، في نفس وقت المصابيح الكهرمانية","باستمرار طوال المسار حتى يعلم السائقون الآخرون دائماً أنها حافلة مدرسية"],"explanation":"لا تُفعَّل المصابيح الحمراء الوامضة وذراع التوقف إلا بعد أن تتوقف الحافلة تماماً لإركاب أو إنزال الطلاب."},"140":{"q":"أنا أقود حافلتي المدرسية نحو معبر للسكك الحديدية. بعد أن توقفتُ ضمن المسافة القانونية، وفتحتُ نافذتي وباب الخدمة، وتأكدتُ من عدم قدوم أي قطار، أبدأ بعبور السكة. لأعبر فوق القضبان بأمان، ماذا يجب أن أفعل وأنا أتحرك عبرها؟","options":["أخفّض الترس بينما تكون عجلاتي الأمامية على القضبان لبناء قوة إضافية","أعبر بترس منخفض وأتجنّب تغيير الترس حتى تتجاوز الحافلة القضبان تماماً","أُبقي ناقل الحركة في وضع الحياد وأدع الحافلة تنزلق عبر القضبان","أُسرّع بقوة لتقضي الحافلة أقل وقت ممكن على القضبان"],"explanation":"اعبُر السكك الحديدية بترس منخفض ولا تُغيّر الترس حتى تتجاوز الحافلة السكة تماماً، حتى لا يتوقف المحرك على القضبان."},"141":{"q":"أنا أقود حافلتي المدرسية المحمّلة وأقترب من معبر سكة حديدية على مستوى الطريق. حركة المرور أمامي متكدّسة عند إشارة حمراء بعد القضبان مباشرة، وطابور السيارات يتقدّم بالكاد. لأبقى في الموعد، أين يجب أن أحرص على ألّا أوقف حافلتي؟","options":["على الكتف على بُعد 15 إلى 50 قدماً قبل المعبر، حيث يُطلب مني إجراء توقفي الإلزامي","قبل المعبر مباشرة، بترس منخفض، حتى أكون مستعداً للعبور دون تغيير الترس بمجرد أن يخلو","على قضبان السكة الحديدية نفسها، ولو للحظة، بينما أنتظر تحرّك المرور المتكدّس","خلف خط التوقف الأبيض، على بُعد عدة أطوال سيارات من منطقة المعبر المنخفضة"],"explanation":"يجب ألّا توقف الحافلة المدرسية أبداً على قضبان السكة الحديدية؛ تأكد من وجود مساحة لتجاوز الجانب الآخر تماماً قبل بدء العبور."},"142":{"q":"تتوقف لإنزال الطلاب عند مدرسة ابتدائية، وتُدرك طالبة في الصف الأول أثناء نزولها أن منزلها على الجانب المقابل من الشارع. عليها أن تعبر لتصل إلى بيتها. لإبقائها في مرأى عينك وبعيداً عن أخطر جزء من منطقة الخطر، أين ينبغي أن توجّهها للعبور؟","options":["مباشرة قبالة الباب، قريبةً على طول الجانب الأيمن من الحافلة","خلف الحافلة، حيث تُحذّر المصابيح الحمراء وذراع التوقف حركة المرور القادمة","حيثما يقف حارس العبور، حتى لو كان ذلك في الخلف","على بُعد نحو 10 أقدام أمام الحافلة، حيث تبقى في مرأى عينك بالكامل"],"explanation":"الطلاب الذين عليهم العبور ينبغي أن يسيروا على بُعد نحو 10 أقدام أمام الحافلة، بعيداً عن منطقة الخطر الأمامية لكن في مرأى السائق بالكامل."},"143":{"q":"أنا متوقف عند مدرسة في ساحة ضيّقة، والطريق الوحيد للخروج هو أن أرجع بحافلتي الفارغة للخلف خارج منطقة التحميل. لا يوجد بالغون أو طلاب آخرون لمساعدتي. وفقاً لإجراءات إدارة السلامة العامة في تكساس (DPS)، ماذا يجب أن أفعل قبل أن أبدأ الرجوع للخلف؟","options":["أحضِر شخصاً ليعمل مرشداً يوجّهني، أو تحقّق بعناية من خلوّ المنطقة خلف الحافلة قبل التحرك","أُطلق البوق مرتين وأبدأ الرجوع ببطء، لأن التحذير سينبّه أي شخص قريب لكي يبتعد","شغّل المصابيح التحذيرية الكهرمانية وذراع التوقف الأحمر الوامض ليعلم السائقون الآخرون أن الحافلة ترجع للخلف","أنزِل النوافذ الجانبية وأطفئ المذياع حتى أتمكن من الإصغاء إلى أي شخص يقترب من الخلف"],"explanation":"تجنّب الرجوع للخلف كلما أمكن، ولا ترجع أبداً دون مرشد يوجّهك أو تحقّق دقيق من خلوّ المنطقة خلف الحافلة."},"144":{"q":"أُسنِد إليّ مسار جديد يضم عدة ركّاب من رياض الأطفال والصف الأول عند محطاتي الصباحية. مقارنةً بطلابي الأكبر سناً في المرحلة المتوسطة، كيف ينبغي أن أُعدّل طريقة تعاملي مع هؤلاء الأطفال الأصغر عند الإركاب والإنزال؟","options":["عامِلهم تماماً مثل الطلاب الأكبر، لأن قواعد الإركاب والإنزال لا تتغيّر بالعمر","امنحهم إشرافاً إضافياً وراقبهم عن كثب أكثر، لأنهم أقل وعياً بمنطقة الخطر ويحتاجون مزيداً من المساعدة في الصعود والنزول بأمان","انقلهم عبر المحطة بسرعة أكبر ليقضوا وقتاً أقل قرب الحافلة ويغادروا منطقة الخطر أسرع","أجلِسهم في أقصى الخلف ليصعد الطلاب الأكبر والأكثر مسؤولية أولاً ويكونوا قدوة"],"explanation":"الأطفال الأصغر هم الأقل وعياً بمنطقة الخطر حول الحافلة، فيحتاجون إلى إشراف إضافي ومراقبة أوثق للصعود والعبور بأمان."},"145":{"q":"أنا أُشغّل مساري في صباح ممطر وأتوقف عند محطة حيث ينتظر ستة طلاب قرب الرصيف. وهم ينهون صعودهم، ما هي مسؤوليتي تجاه المنطقة المحيطة بمحطة التوقف؟","options":["دع الطلاب يتجمّعون متلاصقين قرب باب الدخول لأتمكن من إركابهم أسرع والبقاء في الموعد","اترك مصابيح المقصورة الداخلية مطفأة حتى يرى السائقون المارّون مصابيحي الحمراء الوامضة بوضوح","أبقِ منطقة المحطة آمنة وخالية حتى يتمكن الطلاب وحركة المرور من التحرك دون خطر","لوّح للمركبات القادمة بالمرور حول الحافلة سريعاً لإبقاء مساري مفتوحاً وحركة المرور سلسة"],"explanation":"الإركاب والإنزال هو أخطر جزء من العمل، لذا فإن الواجب الأساسي للسائق هو إبقاء منطقة المحطة آمنة وخالية للطلاب وحركة المرور."},"146":{"q":"لقد انتهيتُ للتوّ من إركاب آخر الطلاب عند محطة صباحية. الممر خالٍ، والباب مغلق، وأنا مستعد للانطلاق. قبل أن أُحرّر فرملة الوقوف وأُحرّك الحافلة، ما هو الأمر الأهم الوحيد الذي يجب أن أفعله؟","options":["أُطفئ المصابيح الحمراء الوامضة وذراع التوقف أولاً، ثم أُسرّع بسلاسة إلى مسار المرور","أُطلق تحذيراً قصيراً بالبوق لتنبيه أي طلاب لا يزالون قرب الحافلة بأنني على وشك التحرك","أُعيد عدّ الطلاب الجالسين فقط حتى أعرف أن الحافلة بحمولة الركّاب الصحيحة","تحقّق من جميع مراياي، خاصة مرايا التقاطع والمرايا اليمنى، للتأكد من عدم وجود أي طفل في منطقة الخطر قبل التحرك"],"explanation":"قبل التحرك، تحقّق من جميع المرايا — خاصة مرايا التقاطع والمرايا اليمنى — للتأكد من عدم وجود أي طفل في منطقة الخطر المخفية عن الزجاج الأمامي."},"147":{"q":"أنا أُخطّط لمسار حافلتي المدرسية وألاحظ أنه بإمكاني اختيار نقطة التفاف تتيح لي الالتفاف للأمام عبر الساحة، أو محطة في طريق مسدود يتعيّن عليّ فيها الرجوع للخلف للمغادرة. لماذا يدفعني دليل CDL في تكساس نحو اختيار المسار الذي يجنّبني الرجوع بالحافلة للخلف؟","options":["في كل مرة أتجنّب فيها الرجوع للخلف، أُزيل مناورة عالية الخطورة قد يختبئ فيها الأطفال والأجسام خلف الحافلة، فكلما قلّت مرات رجوعي كان ذلك أكثر أماناً","الرجوع للخلف يستهلك ناقل الحركة أسرع، لذا فإن تخطيط مسارات للأمام فقط يتعلق أساساً بتقليل تكاليف صيانة الحافلة","الرجوع للخلف غير آمن فقط عندما تكون الحافلة محمّلة بالطلاب، فالحافلة الفارغة يمكنها الرجوع بحرية دون الحاجة إلى مرشد","الرجوع للخلف مسموح فقط بعد إطلاق البوق ثلاث مرات، مما يحذّر الأطفال ويجعل المناورة آمنة مثل القيادة للأمام تماماً"],"explanation":"المنطقة العمياء خلف الحافلة مباشرة قد تُخفي طفلاً تماماً، مما يجعل الرجوع للخلف من أعلى المناورات خطورة، فكل مرة تتجنّبها تُزيل فرصة لوقوع مأساة."},"148":{"q":"أنا أقود حافلة مدرسية محمّلة ويتوقف المحرك فجأة بينما أنا أتدحرج على معبر سكة حديدية، فتبقى الحافلة فوق القضبان. يدور بادئ التشغيل لكن المحرك لا يعود للعمل. ماذا يجب أن تفعل أولاً؟","options":["واصِل إدارة بادئ التشغيل وضخّ دواسة الوقود لمحاولة إخلاء القضبان بقوة المحرك","أنزِل كل طالب من الحافلة فوراً وقُدهم بعيداً عن القضبان، متحركين بزاوية باتجاه أي قطار قادم حتى تكونوا في مأمن إذا اصطدم القطار بالحافلة","أبقِ الطلاب جالسين وهادئين بينما تتصل لاسلكياً بالمراقبة لطلب شاحنة قطر","فعّل فرملة الوقوف، وأمّن الحافلة، وابقَ على متنها لمراقبة القطارات في كلا الاتجاهين"],"explanation":"إذا توقف المحرك على معبر، أنزِل الجميع وأبعِدهم عن القضبان فوراً، قائداً إياهم بزاوية باتجاه أي قطار قادم حتى يكونوا في مأمن إذا اصطدم بالحافلة."},"149":{"q":"أنا سائق حافلة مدرسية جديد، وقد وضعتني مقاطعتي للتوّ على حافلة مطلية حديثاً بمذياع جديد، ومرايا تقاطع مُحدّثة، وبوق أعلى صوتاً. يقول لي زميل مخضرم: 'لا شيء من تلك المعدّات هو ما يُبقي أطفالك على قيد الحياة هناك.' وفقاً لدليل CDL في تكساس، على ماذا تعتمد سلامة الطلاب في مساري أكثر من أي شيء؟","options":["على حالة معدّات الحافلة وتحديثاتها الأخيرة، لأن المرايا والمصابيح الحديثة تتولّى المراقبة بدلاً عني","على عمل المصابيح الكهرمانية والحمراء التحذيرية بشكل صحيح في كل مرة أقترب فيها من محطة لإركاب أو إنزال","على عنايتي أنا وانتباهي وحُسن تقديري خلف عجلة القيادة طوال كل جزء من المسار","على ضبط مرايا التقاطع بشكل صحيح حتى تراقب منطقة الخطر نفسها بنفسها أثناء القيادة"],"explanation":"تعتمد سلامة الحافلة المدرسية أكثر ما تعتمد على عناية السائق وحُسن تقديره اليقظ، لأن المرايا والمصابيح وذراع التوقف لا تعمل إلا حين يستخدمها سائق منتبه."},"150":{"q":"وأنت تقترب من محطة توقّف، يجب أن تكون:","options":["تنظر بعيداً","تتفقّد مراياك","تكتب رسائل نصية بسرعة","تأكل وجبات خفيفة"],"explanation":"تفقّد مراياك وأنت تقترب."},"151":{"q":"أنا أقود حافلتي المدرسية على طريق ريفي سرعته 50 ميلاً في الساعة وأقترب من محطة توقف مخصصة سألتقط فيها الطلاب. لتحذير حركة المرور خلفي بأنني على وشك التوقف، أبدأ بتشغيل أضواء التحذير الكهرمانية الوامضة. على أي مسافة تقريباً قبل المحطة ينبغي أن أشغّلها؟","options":["على بُعد نحو 15 إلى 50 قدماً قبل المحطة، وهي نفس المسافة التي أتوقف عندها قبل سكة الحديد","على بُعد نحو 10 أقدام قبل المحطة، تماماً عند دخولي منطقة الخطر حول الحافلة","فقط بعد أن أكون قد توقفت وشغّلت الأضواء الحمراء الوامضة وذراع التوقف","على بُعد نحو 100 إلى 300 قدم قبل المحطة، حسب سرعتي وحالة الطريق"],"explanation":"شغّل أضواء التحذير الكهرمانية على بُعد نحو 100 إلى 300 قدم قبل المحطة، وتعتمد المسافة الدقيقة على سرعتك وظروف الطريق."},"152":{"q":"أنا أتوقف في محطتي الصباحية حيث تنتظر مجموعة من الطلاب بالفعل على كتف الطريق. لإبقائهم بعيدين عن منطقة الخطر مع تمكّني من رؤية كل منهم أثناء توقفي، على أي مسافة تقريباً من المجموعة المنتظرة ينبغي أن أوقف الحافلة؟","options":["على بُعد نحو 10 أقدام من الطلاب المنتظرين، بما يبقيهم خارج منطقة الخطر مع بقائهم في مرمى نظري","على بُعد نحو 30 قدماً من الطلاب المنتظرين، لأن منطقة الخطر قد تمتد إلى هذه المسافة أمام الحافلة","ملاصقاً للطلاب تماماً، على بُعد نحو قدم واحدة، حتى لا يدخل أي منهم نقطة عمياء","على بُعد نحو 300 قدم من الطلاب المنتظرين، وهي نفس المسافة التي أشغّل عندها الأضواء الكهرمانية"],"explanation":"توقف على بُعد نحو 10 أقدام من الطلاب المنتظرين حتى يبقوا خارج منطقة الخطر مع بقائهم في مرمى نظرك بالكامل قبل فتح الأبواب."},"153":{"q":"لقد شغّلت بالفعل أضواء التحذير الكهرمانية، وخفّفت السرعة، وأوقفت حافلتي المدرسية توقفاً تاماً لالتقاط طالبين ينتظران عند الرصيف. والآن وقد توقفت الحافلة تماماً، ماذا يجب أن أشغّل قبل أن يقترب الطلاب للصعود؟","options":["أستمر بالأضواء الكهرمانية فقط، لأنها كانت مشغّلة بالفعل أثناء الاقتراب","الأضواء الحمراء الوامضة وذراع التوقف، حتى تتوقف حركة المرور ويتمكن الطلاب من العبور بأمان","الأضواء العالية وأضواء الطوارئ الرباعية لجعل الحافلة المتوقفة أكثر وضوحاً للسائقين القادمين","البوق بنفخات قصيرة لإشعار الطلاب المنتظرين بأن الطريق أصبح آمناً لبدء الصعود"],"explanation":"بمجرد التوقف للتحميل أو الإنزال، استخدم الأضواء الحمراء الوامضة وذراع التوقف، اللذين يُلزمان حركة المرور قانونياً بالتوقف حتى يعبر الطلاب بأمان."},"154":{"q":"أنا أقود حافلتي المدرسية على طريق ريفي ذي مسارين وأقترب من معبر سكة حديد محدد بعلامة. لا توجد إشارات أو بوابات عبور، فقط علامة الصليب المعتادة. وفقاً لقواعد إدارة السلامة العامة في تكساس بشأن الحافلة المدرسية عند معبر سكة الحديد، ماذا يُطلب مني فعله قبل عبور السكة؟","options":["يمكنني العبور دون توقف ما دمت أخفّف السرعة وأنظر في الاتجاهين وما دام المعبر خالياً من الإشارات الوامضة","عليّ التوقف فقط إذا كانت الحافلة محمّلة بالطلاب؛ أما الحافلة المدرسية الفارغة فيمكنها العبور دون توقف","يجب أن أوقف الحافلة على بُعد بين 15 و50 قدماً قبل السكة، وأفتح باب الخدمة ونافذة السائق، وأنظر وأنصت، ثم أعبر بسرعة منخفضة دون تبديل التروس","يجب أن أوقف الحافلة عند السكة تماماً، ثم أبدّل إلى ترس أعلى لأتمكن من اجتياز السكة بأسرع ما يمكن أثناء العبور"],"explanation":"عند معبر سكة الحديد، توقف بين 15 و50 قدماً قبل السكة، وافتح باب الخدمة ونافذتك، وانظر وأنصت، ثم اعبر بسرعة منخفضة دون تبديل التروس."},"155":{"q":"أنا أحمّل الطلاب في محطة صباحية. لقد صعدت المجموعة الأخيرة للتو عبر باب الخدمة إلى الحافلة بينما ما زلت أؤمّن المركبة. لإبقاء الممر خالياً والتحميل آمناً، بماذا ينبغي أن أوجّه هؤلاء الطلاب عند دخولهم؟","options":["الوقوف قرب الدرجات الأمامية حتى أنتهي من عدّ الجميع على متن الحافلة","الانتظار في الممر حتى أتمكن من إعادة فحص كل طالب قبل أن ننطلق","التحرك نحو الباب الخلفي حتى يبقى خالياً للمجموعة التالية","التوجه مباشرة إلى مقاعدهم والجلوس"],"explanation":"ينبغي على الطلاب الصاعدين إلى الحافلة التوجه مباشرة إلى مقاعدهم والجلوس لإبقاء الممر ومنطقة الدرجات خالية قبل تحرك الحافلة."},"156":{"q":"أنا أُنزل طلاب حافلة ممتلئة في محطة بعد الظهر، وعدة أطفال يتزاحمون نحو الباب. للتأكد من أنني أحصيت كل طفل وأنه لم يبقَ أحد قرب الحافلة قبل أن أنطلق، ما هي أفضل طريقة لتتبّعهم؟","options":["عدّ كل طالب أثناء نزوله، وإذا اختفى أحدهم عن نظري، أؤمّن الحافلة وأعثر عليه قبل التحرك","مراقبة المرايا أثناء مغادرتهم والانطلاق بمجرد أن تتفرّق المجموعة على الرصيف","الانتظار حتى يهدأ الضجيج، ثم أفترض أن الحافلة خالية وأتحرك للأمام ببطء","سؤال الطلاب القريبين من المقدمة عما إذا كان الجميع قد نزل قبل تحرير الفرامل"],"explanation":"عُدّ كل طالب أثناء نزوله، وإذا اختفى أحدهم عن نظرك، أمّن الحافلة بفرامل الانتظار واعثر على الطفل قبل التحرك."},"157":{"q":"أنا متوقف عند محطة حافلة مدرسية لتحميل مجموعة من الطلاب، وأريد أن أُبقي عيني على الجزء من منطقة الخطر حيث يكون الطفل أكثر عرضة للاصطدام والاختفاء عن نظري. أي جزء من منطقة الخطر ينبغي أن أعتبره الأكثر خطورة وأراقبه عن كثب؟","options":["منطقة الـ10 أقدام مباشرة خلف المصد الخلفي","المنطقة الواقعة أمام الحافلة مباشرة وعلى طول الجانب الأيمن","الجانب الأيسر بجوار نافذة السائق وبابه","الفراغ الخالي تحت الحافلة بين العجلات الأمامية والخلفية"],"explanation":"راقب عن كثب المنطقة الواقعة أمام الحافلة مباشرة وعلى طول الجانب الأيمن، حيث يُرجَّح أن يخرج الأطفال الصاعدون والعابرون عن نظرك."},"158":{"q":"لقد أوقفت حافلتي لإنزال مجموعة من الطلاب. أحد الأطفال، وهي تسكن مباشرة عبر الشارع، تُسقط شيئاً وتمدّ يدها لالتقاطه أثناء نزولها. لإبقائها بعيدة بأمان عن مناطق الخطر حتى تتمكن من العبور، أي تعليمات كان ينبغي أن أعطيها لها قبل نزولها؟","options":["النزول والانتظار قرب المصد الخلفي حتى أشير لها بالعبور","السير ملاصقةً للجانب الأيمن من الحافلة نحو الخلف للعبور","السير على بُعد نحو 10 أقدام أمام الحافلة والعبور هناك حيث أستطيع رؤيتها","العبور بسرعة خلف الحافلة قبل أن تبدأ حركة المرور خلفي بالتحرك"],"explanation":"اطلب من الطلاب العبور على بُعد نحو 10 أقدام أمام الحافلة، مما يبقيهم خارج منطقة الخطر وضمن مرمى نظر السائق."},"159":{"q":"لقد انتهيت من إنزال الطلاب في محطة سكنية. وأثناء قيامك بالعدّ النهائي وفحص المرايا قبل الانطلاق، تدرك أن طفلاً واحداً أحصيته نازلاً من الحافلة لم يعد مرئياً في أي من مراياك أو من خلال الزجاج الأمامي. بدأت حركة المرور تتكدس خلفك وأخذ السائقون الآخرون ينفد صبرهم. ماذا ينبغي أن تفعل؟","options":["تحرير الفرملة والانطلاق ببطء، لأن الطفل المفقود قد وصل بالتأكيد تقريباً إلى الرصيف وغادر منطقة الخطر","تحريك الحافلة للأمام بضعة أقدام لإفساح الطريق لحركة المرور المتذمّرة خلفك، ثم إعادة فحص مرايا العبور بحثاً عن الطفل","إطلاق البوق مرتين لتحذير الطفل بالابتعاد، ثم المتابعة بمجرد أن يطول طابور حركة المرور المنتظرة أكثر من اللازم","إبقاء الحافلة متوقفة ومؤمّنة بفرملة الانتظار، وعدم التحرك حتى تعثر على الطفل المفقود"],"explanation":"أبقِ الحافلة متوقفة ومؤمّنة بفرملة الانتظار، ولا تتحرك حتى تعثر على الطفل المفقود الذي قد يكون داخل منطقة الخطر."},"160":{"q":"أنا أقود مساراً كاملاً من طلاب المرحلة الابتدائية، وحركة المرور خفيفة بما يكفي ليراودني الإغراء لتعويض الدقائق القليلة التي خسرتها. للحفاظ على أقصى سلامة لركّابي أثناء سير الحافلة، كيف ينبغي أن أقود الحافلة؟","options":["استخدام التسارع والكبح والتوجيه بلطف حتى تمنع القيادة السلسة تقاذف الطلاب الجالسين","القيادة بسرعة لتعويض الوقت الضائع، لأن الرحلة الأقصر تعني أن الطلاب يقضون وقتاً أقل معرّضين للخطر داخل الحافلة","الكبح بقوة ومبكراً عند كل محطة حتى يتعلّم الطلاب تثبيت أنفسهم قبل توقف الحافلة","النظر خلفي فوق كتفي بشكل متكرر للتأكد من بقاء كل طالب جالساً وفي مرمى النظر"],"explanation":"قُد بسلاسة مع التسارع والكبح والتوجيه بلطف حتى لا يتقاذف الطلاب غير المربوطين بالأحزمة أو المتحركون أو يفقدوا توازنهم."},"161":{"q":"أثناء قيادتي على مساري، يبدأ طالبان بالصراخ والتدافع في الممر خلفي. أعلم أنني يجب أن أعيد النظام بسرعة. من منظور سلامة إدارة السلامة العامة في تكساس، السبب الرئيسي لأهمية حفظ النظام في الحافلة هو أنه يتيح لي:","options":["تغطية الضجيج حتى لا يتشتت انتباه السائقين العابرين عند محطاتي","إبقاء انتباهي على الطريق وحركة المرور بدلاً من الاضطراب","تشغيل مساري بسرعة أكبر حتى أتمكن من تخطّي محطتين من المحطات اللاحقة","بيع الوجبات الخفيفة والمكافآت للطلاب حسني السلوك بسهولة أكبر"],"explanation":"إعادة النظام تزيل التشتيت حتى تتمكن من إبقاء انتباهك الكامل على الطريق والمرايا وحركة المرور أثناء القيادة بأمان."},"162":{"q":"لقد انتهيت للتو من تحميل آخر طالب في محطة صباحية. الأضواء الكهرمانية مُطفأة، وانكفأت أضوائي الحمراء وذراع التوقف، وبدأت حركة المرور خلفي بالتحرك من جديد. وبينما أمدّ يدي إلى ناقل الحركة للانطلاق من الرصيف، ما الشرط الذي يجب استيفاؤه قبل أن أدع الحافلة تتحرك؟","options":["أن يكون باب الخدمة مفتوحاً على مصراعيه حتى أسمع أي طالب متأخر يناديني قبل أن أتسارع","أن تكون مرآة العبور مطوية مسطّحة على هيكل الحافلة حتى لا تخدش مركبة عابرة","أن يكون باب الخدمة مغلقاً تماماً ومحكماً حتى لا يتمكن أي طالب من الوصول إلى الدرجات عند بدء تحرك الحافلة","أن يُترك الباب نصف مفتوح حتى أتجاوز التقاطع، ثم يُؤمَّن بمجرد بلوغي سرعة الطريق"],"explanation":"لا تحرّك الحافلة أبداً حتى يكون باب الخدمة مغلقاً تماماً ومحكماً حتى لا يتمكن أي طالب من الوصول إلى الدرجات أثناء حركتها."},"163":{"q":"صفّ من طلاب المرحلة الابتدائية يصعد الدرجات الحادة لمدخل حافلتي المدرسية في صباح ممطر، وأحد الأطفال يحمل حقيبة ظهر ثقيلة بينما يحاول الحفاظ على توازنه. وبينما أشرف على الصعود من مقعد السائق، ما أهم تعليمة واحدة ينبغي أن أعطيها لكل طالب لمنع الانزلاق والسقوط على الدرجات؟","options":["إبقاء كلتا اليدين على حزامي حقيبة الظهر حتى يبقى الحمل في الوسط أثناء الصعود","مراقبة مرآة العبور الخارجية للتأكد من أنني أستطيع رؤيتهم قبل أن يصعدوا","الصعود بسرعة حتى يستمر الطابور في التحرك ولا ينتظر أحد في منطقة الخطر","الإمساك بدرابزين اليد بيد واحدة أثناء صعود الدرجات للبقاء ثابتين"],"explanation":"اطلب من الطلاب الإمساك بدرابزين اليد بيد واحدة أثناء صعود الدرجات للبقاء ثابتين ومنع إصابات الانزلاق والسقوط."},"164":{"q":"أنت تقترب من محطتك الصباحية وقد شغّلت أضواء التحذير الكهرمانية. وأثناء تخفيفك للسرعة، أي سلوك ينبغي أن يجعلك أكثر يقظة لطفل قد يدخل منطقة الخطر على نحو غير متوقع؟","options":["طالب يركض عبر الفناء نحو الحافلة، محاولاً ألا يفوّت المحطة","طالب يقف ساكناً عند المحطة المخصصة، منتظراً خلف الرصيف","أحد الوالدين يلوّح من الشرفة بينما ينتظر الطالب بهدوء عند الرصيف","طالب يجلس على مقعد يقرأ حتى تتوقف الحافلة توقفاً تاماً"],"explanation":"راقب عن كثب أي طفل يركض نحو الحافلة، فهو غير متوقع، وقد لا ينظر إلى حركة المرور، وقد يندفع إلى منطقة الخطر."},"165":{"q":"أنت تقترب من محطة حافلة مدرسية حيث ينتظر الطلاب عند الرصيف. أضواء التحذير الكهرمانية وامضة وأنت ترفع قدمك عن الفرملة لتنساب الأقدام القليلة الأخيرة. يبدأ بعض الأطفال بالانجراف نحو حافة الرصيف. للتعامل مع الباب بشكل صحيح، ماذا ينبغي أن تفعل؟","options":["فتح باب الخدمة قليلاً بينما لا تزال الحافلة منسابة حتى يتمكن الطابور من بدء الصعود دون تأخير","إبقاء باب الخدمة مغلقاً حتى تتوقف الحافلة توقفاً تاماً، ثم فتحه","فتح الباب بمجرد تشغيل الأضواء الحمراء الوامضة وذراع التوقف، حتى لو كانت الحافلة لا تزال تتحرك","فتح الباب بمجرد أن تنخفض سرعتك دون سرعة المشي البطيء قرب الرصيف"],"explanation":"أبقِ باب الخدمة مغلقاً حتى تتوقف الحافلة توقفاً تاماً، ثم افتحه، لإبقاء الطلاب خارج منطقة الخطر بجوار حافلة متحركة."},"166":{"q":"أنا أقود حافلتي المدرسية على مسار بدأ فارغاً في الصباح لكنه أصبح الآن مكتظاً بالطلاب بعد كل محطة. ومع ازدياد ثقل الحافلة مع كل عملية التقاط، أي تعديل في قيادتي هو الأهم للبقاء آمناً؟","options":["يمكنني الكبح متأخراً عن المعتاد لأن وزن الطلاب المضاف يضغط الحافلة للأسفل ويمنح إطاراتي تماسكاً أكبر على الطريق","ينبغي أن أتبع المركبة التي أمامي عن قرب أكثر حتى لا يحاول السائقون المتذمّرون خلفي تجاوز الحافلة المحمّلة","أحتاج إلى ترك مسافة توقف أكبر، لأن الحافلة المحمّلة الأثقل تستغرق وقتاً أطول للتوقف التام","ينبغي أن أُبقي سرعتي كما هي عندما كانت فارغة، لأن الفرامل مصممة للحافلة سواء كانت محمّلة أم لا"],"explanation":"الحافلة المحمّلة أثقل بكثير وتستغرق وقتاً أطول للتوقف، لذا اترك مسافة متابعة وتوقف أكبر للتعويض."},"167":{"q":"أنا متوقف لإنزال طلاب المرحلة الابتدائية على طريق يعلو فوق تلة، وبعض الأطفال الذين ينزلون يحتاجون إلى العبور إلى الجهة الأخرى. بسبب الانحدار، لا أستطيع رؤية الرصيف عند مصدّي الأمامي مباشرة بالوضوح الذي أرغب فيه. لإبقاء الطلاب العابرين خارج منطقة الخطر وضمن مرمى نظري، على أي مسافة أمام الحافلة ينبغي أن أوجّههم للعبور؟","options":["عند المصد الأمامي تماماً، لأن التلة تجعل الفجوة الأوسع غير آمنة","خلف الحافلة، حيث يمنحهم الانحدار مساراً أقصر وأكثر أماناً","على بُعد نحو 5 أقدام أمام الحافلة، مع تقليص المسافة بسبب محدودية خط الرؤية","على بُعد لا يقل عن 10 أقدام أمام الحافلة، تماماً كما على الأرض المستوية"],"explanation":"يجب أن يعبر الطلاب دائماً على بُعد نحو 10 أقدام أمام الحافلة، بغض النظر عن التضاريس، حتى يبقوا خارج منطقة الخطر وضمن مرمى نظر السائق."},"168":{"q":"لقد أنهيت للتو مساري بعد الظهر وأكملت إنزال آخر طالب. عبر الطفل الأخير بأمان ووصل إلى الرصيف، ولم تتبقَّ أي محطات على رحلتي. وبينما أستعد لقيادة الحافلة الفارغة عائداً إلى المرآب، ما الوضع الصحيح لأضواء التحذير الخاصة بي؟","options":["ينبغي إطفاء جميع أضواء التحذير، لأنه لم يبقَ أي طلاب للتحميل أو الإنزال","ينبغي أن تبقى أضواء التحذير الكهرمانية (الصفراء) وامضة حتى أصل إلى مرآب الحافلات","ينبغي أن تبقى الأضواء الحمراء الوامضة وذراع التوقف مشغّلة خلال رحلة العودة الفارغة","ينبغي أن تبقى مؤشرات تحذير الانعطاف لليسار وامضة لتنبيه حركة المرور خلفي"],"explanation":"بمجرد أن يعبر آخر طالب بأمان ولم يبقَ أحد للتحميل أو الإنزال، أطفئ جميع أضواء التحذير قبل قيادة الحافلة الفارغة."},"169":{"q":"لقد توقفت للتو لتحميل الطلاب مع تشغيل أضوائك الحمراء وذراع التوقف. طفل صغير كان ينتظر عند المحطة ينزل فجأة عن الرصيف ويختفي منخفضاً مقابل المصد الأمامي، ولم يعد مرئياً في مرمى رؤيتك الأمامية عبر الزجاج. أي المرايا مصممة تحديداً لتتيح لك رؤية هذا الطفل في منطقة الخطر أمام مقدمة الحافلة وأسفلها مباشرة؟","options":["المرايا المسطحة الخارجية اليسرى واليمنى، التي تُظهر الجانبين والخلف على طول هيكل الحافلة","مرايا العبور (المحدّبة)، التي تُظهر منطقة الخطر أمام الحافلة مباشرة","المرآة الداخلية العلوية، التي تُظهر الممر والطلاب الجالسين خلفك","المرآة المحدّبة الخارجية اليمنى، التي تُظهر حركة المرور القادمة من بعيد خلف الحافلة"],"explanation":"استخدم مرايا العبور (المحدّبة) لرؤية منطقة الخطر أمام الحافلة وبجانبها مباشرة حيث يمكن لطفل صغير أن يختفي عن النظر."},"170":{"q":"أنت تحمّل الطلاب على طريق سريع مقسّم بحاجز وسطي مرتفع يفصل بين اتجاهي السير. أضواؤك الحمراء وامضة وذراع التوقف ممدود. سيارة تقترب مباشرة خلف حافلتك في نفس المسار الذي توقفت فيه. ماذا يُطلب من ذلك السائق قانونياً أن يفعل؟","options":["التباطؤ إلى سرعة الزحف والتجاوز من اليسار فقط إذا لم يكن هناك أطفال مرئيون","المتابعة بسرعة مخفّضة لأن الحاجز الوسطي المرتفع يعفي حركة المرور التابعة","التوقف توقفاً تاماً والبقاء متوقفاً حتى تتوقف الأضواء عن الوميض وينكفئ الذراع","التعامل معها كحركة مرور قادمة على طريق مقسّم والمتابعة دون توقف"],"explanation":"يجب على حركة المرور التابعة لحافلة مدرسية متوقفة بأضواء حمراء وامضة وذراع توقف ممدود أن تبقى متوقفة تماماً حتى تتوقف الأضواء وينكفئ الذراع."},"171":{"q":"لقد أوقفت حافلتي المدرسية لإنزال عدة طلاب يجب أن يصلوا إلى الجهة الأخرى من الطريق. أضوائي الحمراء الوامضة وذراع التوقف ممدودان وتوقفت حركة المرور. قبل أن أعطي الطلاب إشارة اليد، ما الشيء الوحيد الذي يجب أن تخبرهم به إشارتي بأنه آمن للقيام به؟","options":["الانتظار عند المصد الأمامي حتى أنهي أوراقي","السير حول مؤخرة الحافلة للوصول إلى الرصيف بسرعة","النزول والوقوف في منطقة الخطر بجوار الباب","العبور أمام الحافلة، على بُعد نحو 10 أقدام، حيث أستطيع رؤيتهم"],"explanation":"يجب أن يعبر الطلاب على بُعد نحو 10 أقدام أمام الحافلة، ضمن مرمى نظر السائق وخارج منطقة الخطر، فقط بعد أن يشير السائق بأنه آمن."},"172":{"q":"أنا أقود مساري بعد الظهر ولديّ خيار حول المكان الذي أُنزل فيه مجموعة من طلاب المرحلة الابتدائية. أي موقع ينبغي أن أختاره للمحطة؟","options":["مكان ذو خطوط رؤية واضحة حيث أستطيع رؤية الطلاب ويستطيعون هم رؤية حركة المرور القادمة","مكان بعد منعطف أعمى مباشرة، حتى تُجبَر السيارات المنتظرة على التباطؤ قبل أن تصل إلينا","منطقة مظللة خلف شاحنة توصيل متوقفة تُبقي الأطفال بعيدين عن الشمس","الجهة البعيدة من تقاطع مزدحم حتى لا يعبر الطلاب إلا مع الإشارة"],"explanation":"اختر محطات ذات خطوط رؤية واضحة حتى يتمكن السائق من إبقاء كل طالب في مرمى نظره ويتمكن الطلاب وحركة المرور القادمة من رؤية بعضهم البعض."},"173":{"q":"أنا أقود حافلة مدرسية ممتلئة وانتهيت للتو من الإنزال في محطة سكنية. وأثناء عدّي للطلاب، أدرك أن طفلاً واحداً نزل لم يعد في مرمى النظر. ماذا ينبغي أن أفعل قبل أن أحرّر الفرملة وأنطلق من المحطة؟","options":["إطلاق البوق مرتين لتحذير الطفل المفقود، ثم المتابعة ببطء حتى لا تعرقل الحافلة حركة المرور","إبقاء الحافلة مؤمّنة بفرملة الانتظار وتحديد موقع الطالب المفقود قبل تحريك الحافلة","فحص المرآة المحدّبة اليمنى فقط، وإذا بدت خالية، التحرك للأمام لأن ذلك هو الجانب الأكثر خطورة","التبديل من الأضواء الحمراء الوامضة إلى أضواء التحذير الكهرمانية والاندماج بحركة المرور بحذر"],"explanation":"احرص دائماً على حصر كل طالب قبل التحرك؛ وإذا اختفى أحدهم عن النظر، أمّن الحافلة بفرملة الانتظار وحدّد موقع الطالب أولاً."},"174":{"q":"لقد توقفت لإنزال ثلاثة طلاب. أضوائي الحمراء الوامضة وذراع التوقف ممدودان، وقد توقفت بضع سيارات خلفي. وبينما ينزل الطلاب، ما أهم مسؤولية واحدة لديّ الآن؟","options":["إعادة تشغيل محرك الحافلة بسرعة حتى أعود إلى الجدول الزمني فور خروج الطلاب من الباب","التلويح للطلاب للعبور بزاوية خلف المصد الخلفي مباشرة حيث تستطيع السيارات العابرة رؤيتهم بوضوح","إبقاء كل طالب في مرمى النظر وحصرهم جميعاً، والتأكد من بقائهم خارج منطقة الخطر قبل أن أحرّك الحافلة","الإشارة للسيارات المتوقفة خلفي بالالتفاف حول الحافلة أولاً حتى تتوقف عن عرقلة انسياب حركة المرور"],"explanation":"عند كل محطة أبقِ جميع الطلاب في مرمى النظر، واحصرهم، وتأكد من بقائهم خارج منطقة الخطر قبل تحريك الحافلة."},"175":{"q":"أنا أُنزل الطلاب في محطة بعد الظهر مع تشغيل أضوائي الحمراء وذراع التوقف الممدود. وبينما ينزل الأطفال ويتجهون عبر الطريق، ما الذي يشكّل الخطر الأكبر عليهم خلال هذه اللحظات؟","options":["تعثّر طالب بحزام حقيبة ظهر مرتخٍ أثناء نزوله من درجات الحافلة","إرباك أضواء التحذير الكهرمانية والحمراء لطفل بشأن متى يكون آمناً التحرك","دفع طالب آخر من الخلف بينما يتزاحم الجميع عند باب الخروج","التعرّض للاصطدام بحافلتي ذاتها أو بمركبات عابرة لا تتوقف"],"explanation":"السبب الرئيسي للوفيات المتعلقة بالحافلات المدرسية هو اصطدام الطلاب بحافلتهم ذاتها أو بمركبات عابرة أثناء صعودهم أو نزولهم."},"176":{"q":"أنت تُنزل الطلاب في محطة بعد الظهر. يُسقط أحد الأطفال ملفًا وينحني بالقرب من الحافلة ليلتقطه قبل العبور. من خبرتك وتدريبك، عندما يُصاب طالب في منطقة الخطر حول حافلة مدرسية متوقفة، ما هو السبب الأكثر شيوعًا لتلك الإصابة؟","options":["يُصدم الطالب بحافلته المدرسية نفسها عندما تبدأ بالتحرك","يُصدم الطالب بسيارة عابرة تتجاوز الحافلة المتوقفة بشكل غير قانوني","يُصدم الطالب بدراجة طالب آخر بالقرب من حافة الرصيف","يُصدم الطالب بمركبة متوقفة تتدحرج إلى الأمام عند المحطة"],"explanation":"معظم الطلاب الذين يُصابون في منطقة الخطر يُصدمون بحافلتهم نفسها عندما تبدأ بالتحرك، خاصةً عند انحنائهم خارج مجال رؤية السائق."},"177":{"q":"لقد توقفتَ للتو لإنزال الطلاب، والأضواء الحمراء وذراع التوقف مُفعّلان. وبينما تنزل إحدى الطالبات، يسقط هاتفها وينزلق تحت المصد الأمامي إلى منطقة الخطر. تنظر إليك طلبًا للإرشاد. ما هي أأمن تعليمات يجب أن تعطيها لها؟","options":["لوّح لها نحو الغرض وراقبها عن كثب وهي تمد يدها بسرعة تحت المصد الأمامي لالتقاطه","أخبرها أن تترك الغرض وتبتعد عن الحافلة وتُشير إليك قبل أن يحاول أي شخص استرجاعه","اجعلها تمشي إلى مؤخرة الحافلة وتلتقطه من الخلف حيث لا يمكن أن تصل إليها حركة المرور العابرة","أخبرها أن تزحف تحت الحافلة لاستعادته بينما تُبقي الفرامل مشدودة وتراقب المرايا"],"explanation":"يجب ألا يدخل الطالب منطقة الخطر أبدًا لاسترجاع غرض ساقط؛ بل ينبغي أن يبتعد ويُشير إلى السائق ويترك السائق يتولى الأمر."},"178":{"q":"لقد توقفتُ لإنزال عدة طلاب في محطة بعد الظهر. أضوائي الحمراء وذراع التوقف مُفعّلان، والأطفال ينزلون إلى الرصيف. قبل أن أحرر الفرامل وأنطلق، ماذا يجب أن أراقب الطلاب الذين نزلوا يفعلونه؟","options":["الانتظار بجانب الإطارات الخلفية حتى أُشير إليهم ببوق التنبيه","التوقف مباشرةً أمام المصد حتى أتمكن من عدّهم في مرآة العبور","الابتعاد تمامًا عن الحافلة وخارج منطقة الخطر","الوقوف تحت هيكل الحافلة ليبقوا محميين من حركة المرور العابرة"],"explanation":"قبل تحرير الفرامل، تأكد من أن كل طالب نزل قد ابتعد تمامًا عن الحافلة وخرج من منطقة الخطر."},"179":{"q":"أنا أقود حافلة مدرسية محمّلة على مساري بعد الظهر. عند أي من المحطات التالية يجب أن أكون أكثر يقظة لخطر اصطدام الطلاب، وأبقى شديد الانتباه أثناء صعودهم ونزولهم؟","options":["محطة في طريق مسدود سكني هادئ بلا حركة مرور عابرة","محطة في موقف سيارات فارغ حيث أخرج تمامًا عن الطريق","محطة عند مدخل مزرعة ريفية بحقول مفتوحة على الجانبين","محطة على كتف طريق مزدحم تمر المركبات بالقرب منها"],"explanation":"المحطات القريبة من حركة المرور العابرة هي الأكثر خطورة لأن السائقين قد يتجاهلون بشكل غير قانوني التوقف عند الأضواء الحمراء وذراع التوقف، مما يُعرّض الطلاب العابرين للخطر."},"180":{"q":"لقد توقفتُ على طريق ذي مسارين لإنزال الطلاب. أضوائي الحمراء تومض وذراع التوقف ممتد. بصفتك سائق حافلة مدرسية، مع من صُممت هذه المعدات للتواصل بشكل أساسي؟","options":["السائقون المقتربون والعابرون، حتى يتوقفوا ولا يقودوا إلى منطقة التحميل","الطلاب داخل الحافلة، لإشعارهم بأنه أصبح من الآمن الوقوف والنزول","الطلاب على جانب الطريق، لإخبارهم بأي اتجاه يكون آمنًا للعبور","نظام محرك الحافلة، الذي يخفّض دورانه تلقائيًا بمجرد انتشار الذراع"],"explanation":"تحذّر الأضواء الحمراء الوامضة وذراع التوقف الممتد السائقين المقتربين والعابرين بالتوقف حتى لا يقودوا إلى منطقة التحميل حيث يكون الطلاب أكثر عرضة للخطر."},"181":{"q":"حافلتك متوقفة بأضوائها الحمراء الوامضة وذراع التوقف ممتد، وعدة طلاب ينتظرون للعبور عندما تمر سيارة بسرعة بشكل غير قانوني من اليسار، متجاهلةً إشاراتك. ماذا يجب أن تفعل أولًا؟","options":["انطلق واتبع المركبة حتى تتمكن من إبلاغ مركز التحكم برقم لوحتها","أبقِ الطلاب عند حافة الرصيف وخارج منطقة الخطر حتى يكون الطريق خاليًا وآمنًا للعبور","لوّح للطلاب بالعبور بسرعة قبل أن تحظى مركبة أخرى بفرصة لتجاوز الحافلة","أطلق البوق مرارًا وأومض بالمصابيح الأمامية لتحذير السائق الذي عبر"],"explanation":"عندما تتجاوز مركبة حافلة متوقفة بشكل غير قانوني، أبقِ الطلاب عند حافة الرصيف وخارج منطقة الخطر حتى تتأكد من أن الطريق خالٍ وآمن للعبور."},"182":{"q":"إنه صباح شتوي ضبابي قبل الفجر وأنا أسير على مساري وسط ضباب كثيف ورذاذ مطر خفيف متقطع. حافلتي مزودة بأضواء وميض بيضاء مثبتة على السقف. في أي من هذه الظروف تكون أضواء الوميض هذه أكثر فائدة لتحذير السائقين الآخرين بوجود حافلتي؟","options":["في فترة بعد ظهر صافية ومشمسة عندما يستطيع السائقون القادمون رؤية الحافلة من بعيد بالفعل","أثناء التباطؤ بمفردي في موقف سيارات فارغ بلا أي حركة مرور حولي","أثناء الضباب أو المطر الغزير أو ظروف الرؤية المنخفضة الأخرى عندما لا يستطيع السائقون رؤية الحافلة بوضوح","عند سرعة الطريق السريع على طريق جاف ومفتوح حيث توجد مسافة كافية لرصد الحافلة"],"explanation":"أضواء الوميض المثبتة على السقف أكثر فائدة في ظروف الرؤية المنخفضة مثل الضباب أو المطر الغزير أو الثلج، عندما لا يستطيع السائقون الآخرون رؤية الحافلة بوضوح."},"183":{"q":"لقد أوقفتُ حافلتي المدرسية عند حافة الرصيف في محطة، والباب مفتوح، وأحتاج إلى مغادرة مقعد القيادة للحظة لمساعدة طالب في المقاعد الأمامية على تثبيت حقيبة ظهر فضفاضة قبل أن ننطلق مجددًا. من بين ما يلي، أي إجراء يجب أن أتخذه أولًا قبل أن أنهض من مقعدي؟","options":["إطفاء الأضواء الكهرمانية التحذيرية حتى لا أستنزف البطارية أثناء التوقف","ضبط مفتاح الماسحة الأمامية على وضع التشغيل المتقطع تحسبًا لمطر خفيف","مد يدي وضبط المدفأة لتبقى المقصورة مريحة للطلاب","شد فرملة الانتظار حتى لا تتحرك الحافلة بينما أكون بعيدًا عن أدوات التحكم"],"explanation":"اشدد دائمًا فرملة الانتظار قبل مغادرة مقعد القيادة حتى لا تتدحرج الحافلة بينما تكون بعيدًا عن أدوات التحكم."},"184":{"q":"لقد حصلتُ للتو على تصديق الحافلة المدرسية وأنا فخور بأن الإحصاءات تُظهر أن الحافلة المدرسية من أأمن المركبات على الطريق. وأنا أبدأ مساري، ما هو العامل الوحيد الذي يجعل الحافلة آمنة بهذا القدر فعليًا؟","options":["تبقى الحافلة من أأمن المركبات فقط طالما يتبع السائق باستمرار الإجراءات المعتمدة وقواعد السلامة","الحافلة آمنة بطبيعتها بسبب حجمها الكبير وهيكلها الفولاذي المُعزّز، لذا فإن الإجراءات أقل أهمية بكثير","الحافلة آمنة أساسًا بسبب طلائها الأصفر الزاهي وأضوائها التي تجعلها أكثر المركبات وضوحًا على الطريق","الحافلة آمنة أساسًا لأن الطُرز الأحدث مُجهّزة بأكثر تقنيات الكبح والتصادم تطورًا"],"explanation":"تبقى الحافلة المدرسية من أأمن المركبات فقط طالما يتبع السائق باستمرار إجراءات السلامة والقواعد المعتمدة."},"185":{"q":"لقد توقفتُ لإنزال الطلاب وأضوائي الحمراء تومض وذراع التوقف ممتد. عدة منهم أطفال صغار أعرف أنهم يميلون إلى سوء تقدير مدى بُعد وسرعة حركة المرور القادمة. وبينما ينزلون ويحتاجون إلى العبور إلى الجانب الآخر من الطريق، ما هي أأمن طريقة لي للتعامل مع هؤلاء الركاب الأصغر سنًا؟","options":["التلويح لهم بالعبور بسرعة وواحدًا تلو الآخر حتى يقضوا أقل وقت ممكن قرب حركة المرور المتحركة","إرشادهم بعناية، وتوجيههم للعبور على بُعد نحو 10 أقدام أمام الحافلة حيث أستطيع رؤيتهم، والتأكد من أن الطريق خالٍ قبل أن أُشير لهم بالعبور","ترك الطريق لهم للعبور بوتيرتهم خلف الحافلة، بما أن ذراع التوقف والأضواء الحمراء يوقفان حركة المرور لهم بالفعل","إخبارهم بالانتظار حتى أحرّك الحافلة إلى الأمام، ثم العبور خلفها بمجرد ابتعادي عن الطريق"],"explanation":"وجّه الطلاب للعبور على بُعد نحو 10 أقدام أمام الحافلة حيث تستطيع رؤيتهم، وتأكد من أن الطريق خالٍ قبل أن تُشير لهم بالعبور."},"186":{"q":"لقد توقفتُ لإنزال عدة طلاب يجب أن يعبروا الطريق أمام حافلتي. الأضواء الحمراء وذراع التوقف مُفعّلان، وحركة المرور في كلا الاتجاهين قد توقفت. الطلاب متجمعون عند باب الحافلة، ينظرون إليّ وينتظرون. ماذا يجب أن يحدث قبل أن يخرج أي منهم للعبور أمام الحافلة؟","options":["ينبغي أن يبدأوا العبور بمجرد تفعيل الأضواء الحمراء وذراع التوقف، لأن توقف حركة المرور يؤكد أنه آمن","ينبغي أن يعبروا في اللحظة التي تتوقف فيها كل حركة المرور المرئية في كلا الاتجاهين تمامًا عن الحركة","يجب أن ينتظروا حتى أعطيهم إشارة واضحة بالعبور، بعد أن أتأكد من أن الطريق آمن","ينبغي أن يطلقوا بوقًا أو ينادوا لتنبيه أي سائقين مقتربين قبل الخروج إلى الطريق"],"explanation":"يجب أن ينتظر الطلاب إشارة السائق الواضحة بالعبور، التي تُعطى فقط بعد أن يتأكد السائق شخصيًا من توقف كل حركة المرور ومن أن الطريق آمن."},"187":{"q":"لقد انتهيتَ للتو من تحميل الطلاب في محطة الصباح وأنت مستعد للانطلاق من حافة الرصيف. لا يزال بعض الأطفال يستقرون في مقاعدهم. قبل أن تحرر فرملة الانتظار وتحرّك الحافلة، ما هو أهم شيء يجب أن تفعله لحماية الطلاب؟","options":["إطفاء الأضواء الحمراء الوامضة وسحب ذراع التوقف قبل أي شيء آخر","إجراء عدّ نهائي للطلاب الجالسين للتأكد من تطابق العدد مع قائمتك","التأكد من أن كل طالب مربوط بالحزام وأن الممر خالٍ تمامًا من حقائب الظهر","فحص كل المرايا ومناطق الخطر حول الحافلة للتأكد من عدم بقاء أي طفل فيها"],"explanation":"قبل الانطلاق، افحص كل المرايا ومناطق الخطر حول الحافلة للتأكد من عدم بقاء أي طفل فيها، لأن تلك المنطقة هي الأصعب رؤيةً في تلك اللحظة."},"188":{"q":"أنا سائق حافلة مدرسية أقوم بجولة فحص قبل الرحلة، وأحاول تصور منطقة الخطر على الجانب الأيمن من حافلتي حتى أعرف أين يمكن أن يقف طفل ويستحيل عليّ رؤيته. تقريبًا، إلى أي مسافة تمتد منطقة الخطر تلك خارج الجانب الأيمن من الحافلة؟","options":["نحو 10 أقدام أو أكثر خارج الجانب الأيمن من الحافلة","نحو 3 أقدام، أي عرض باب الخدمة المفتوح تقريبًا فقط","فقط المنطقة التي أستطيع رؤيتها بالفعل في المرآة المحدبة اليمنى، لذا لا توجد منطقة عمياء حقيقية","حتى 30 قدمًا، نفس المسافة التي تصل إليها منطقة الخطر خارج المصد الأمامي"],"explanation":"على الجانب الأيمن من الحافلة، تمتد منطقة الخطر نحو 10 أقدام أو أكثر، وهي من أصعب المناطق رؤيةً."},"189":{"q":"أنا أنهي مساري ويسألني طالب نزل للتو إن كان بإمكانه التقاط حقيبة ظهر تركها على الأرض خلف المصد الخلفي لحافلتي مباشرةً. لماذا يجب أن أعامل المنطقة خلف الحافلة مباشرةً كمنطقة خطر جدية قبل أن أفكر حتى في التحرك؟","options":["لا توجد منطقة خطر حقيقية خلف الحافلة، لأن مرايايي وكاميرا الرجوع للخلف تتيح لي رؤية كل شيء خلفي بوضوح","تمتد منطقة الخطر مسافة طويلة خلف الحافلة، وهي من أصعب المناطق رؤيةً لي، لذا يمكن أن يُصدم طالب هناك عندما أنطلق","تصل منطقة الخطر الخلفية إلى قدم واحدة بالضبط خلف المصد، لذا طالما بقي الطالب بعد ذلك الخط فهو في أمان تام","منطقة الخطر خلف الحافلة تهم فقط حتى ارتفاع السقف، لأن هذا أقصى مدى تصل إليه منطقتي العمياء الخلفية"],"explanation":"تمتد منطقة الخطر مسافة طويلة خلف الحافلة وهي من أصعب المناطق رؤيةً، لذا يمكن أن يُصدم طالب هناك عندما تنطلق الحافلة."},"190":{"q":"أنا أقوم بتشغيل مساري خلال فترة استقبال صباحية مزدحمة. وأنا أقترب من المحطة، تكون مجموعة من الطلاب مصطفّة بالفعل عند حافة الرصيف ويبدأ أول طفل بالتقدم نحو الحافلة قبل أن أتوقف تمامًا. بموجب إجراءات الحافلات المدرسية لإدارة السلامة العامة في تكساس، عند أي نقطة ينبغي أن أسمح لأي طالب بالبدء في الصعود؟","options":["بمجرد أن تبدأ أضوائي الكهرمانية التحذيرية بالوميض عند الاقتراب، لأن ذلك يُشير للطلاب بأنه آمن للتقدم","بمجرد أن تتباطأ الحافلة إلى شبه توقف ويكون باب الخدمة مفتوحًا، حتى لو كنتُ لا أزال أزحف نحو حافة الرصيف","فقط بعد أن تتوقف الحافلة تمامًا ويكون باب الخدمة مفتوحًا، حتى لا يتقدم أي طالب نحو مركبة لا تزال متحركة","عند تفعيل الأضواء الحمراء الوامضة، بغض النظر عما إذا كانت الحافلة قد أنهت توقفها عند حافة الرصيف"],"explanation":"يجوز للطلاب الصعود فقط بعد توقف الحافلة تمامًا وفتح باب الخدمة، حتى لا يتقدم أحد نحو مركبة لا تزال متحركة."},"191":{"q":"أنا أقود على مساري وأرى محطتي التالية تقترب حيث ينتظر ثلاثة طلاب. لكي أقترب بأمان وأوقف الحافلة عند منطقة التحميل، كيف ينبغي أن أتحكم في سرعتي وأنا أقترب من المحطة؟","options":["الحفاظ على سرعتي الطبيعية على الطريق والكبح بقوة عند المحطة مباشرةً حتى لا تتباطأ حركة المرور خلفي مبكرًا","الانزلاق في الوضع المحايد حتى تتباطأ الحافلة من تلقاء نفسها دون لمس الفرامل إطلاقًا","التسارع لفترة وجيزة لاجتياز التقاطع، ثم التوقف فجأةً بمجرد وصولي إلى الطلاب","تقليل السرعة تدريجيًا وبسلاسة، والتخفيف جيدًا قبل المحطة حتى أتمكن من التوقف تحت سيطرة كاملة"],"explanation":"قلّل السرعة تدريجيًا وبسلاسة، مع التخفيف جيدًا قبل المحطة، للحفاظ على الحافلة تحت سيطرة كاملة أثناء الاقتراب."},"192":{"q":"إنه الصباح الباكر وأنا أقود حافلتي المدرسية المحمّلة بالكامل على مسار ريفي عندما يتحول سطح الطريق إلى جليد متماسك وتبدو الحافلة وكأنها تطفو. حركة المرور أمامي تسير بالسرعة المقررة الطبيعية. ما هي أأمن طريقة لي للتعامل مع الحافلة على هذا المقطع الجليدي؟","options":["تقليل سرعتي وزيادة مسافة المتابعة لأبعد بكثير مما أستخدمه على الرصيف الجاف","الحفاظ على السرعة المقررة لمواكبة تدفق حركة المرور وتجنب الاصطدام من الخلف","ضخ الفرامل بقوة وبشكل متكرر حتى أشعر بالضبط أين يكمن حد التماسك لديّ","تقليص المسافة مع المركبة أمامي حتى تُنظّف إطاراتها مسارًا جافًا لي لأتبعه"],"explanation":"على الجليد، ينخفض التماسك وقدرة التوقف بشدة، لذا أبطئ إلى أقل بكثير من سرعة الرصيف الجاف وزِد مسافة المتابعة بشكل كبير."},"193":{"q":"إنها فترة بعد ظهر حارة وحافلتك بلا تكييف هواء. يبدأ عدة طلاب من المرحلة الإعدادية بالاتكاء للخارج والتلويح بأذرعهم عبر النوافذ المفتوحة للسيارات العابرة. لإبقائهم آمنين داخل منطقة خطر حركة المرور، ما الذي يجب أن تصر على ألا يفعلوه؟","options":["الانزلاق إلى حافة مقاعدهم الأمامية","إخراج أذرعهم أو رؤوسهم من النوافذ","الإمساك بمقابض ظهر المقاعد","الانحناء نحو الأغراض تحت المقاعد"],"explanation":"يجب أن يُبقي الطلاب أذرعهم ورؤوسهم داخل الحافلة في كل الأوقات حتى لا يُصدموا بالمركبات العابرة أو الأجسام على جانب الطريق."},"194":{"q":"راقب مناطق الخطر بشكل خاص أثناء:","options":["السير على الطريق السريع","التحميل والتفريغ","محطات التزود بالوقود","مواقف السيارات"],"explanation":"الأكثر أهميةً أثناء التحميل والتفريغ."},"195":{"q":"أنت تقود سيارتك على طريق ذي مسارين وترى حافلة مدرسية متوقفة أمامك في مسارك بأضوائها الحمراء الوامضة وذراع التوقف ممتد. لا يوجد فاصل أوسط أو حاجز مادي يفصل بين اتجاهي السير. ماذا يُطلب منك أن تفعل؟","options":["أبطئ، ثم تجاوز الحافلة بحذر من اليسار إذا لم يكن هناك أطفال مرئيون على الطريق","تابع بسرعة منخفضة وأطلق بوقك لتحذير أي أطفال قرب الحافلة","توقف وابقَ متوقفًا حتى تتوقف الأضواء الحمراء عن الوميض ويُسحب ذراع التوقف","توقف فقط إذا كنت تسير في نفس اتجاه الحافلة، وإلا تابع سيرك"],"explanation":"على طريق ذي مسارين بلا فاصل أوسط، يجب أن تتوقف حركة المرور في كلا الاتجاهين وتبقى متوقفة حتى تتوقف الأضواء الحمراء عن الوميض ويُسحب ذراع التوقف."},"196":{"q":"أنت متوقف لإنزال الطلاب. بعد العدّ، يختفي أحد الأطفال الذين نزلوا عن مجال رؤيتك قرب مقدمة الحافلة ولا تستطيع تحديد موقعه بمرآة العبور أو المرايا الخارجية. حركة المرور تتراكم خلفك ويُطلق سائق آخر بوقه. ماذا يجب أن تفعل؟","options":["تقدّم ببطء، لأن منطقة الخطر تمتد نحو 10 أقدام فقط والطفل قد تجاوزها على الأرجح","حرر الفرامل وتقدّم بهدوء بينما تراقب مرآتك المحدبة لتعيد التحقق من الطفل أثناء تحركك","انقر البوق مرة لإشارة الطفل بالتحرك، ثم تابع عندما لا يظهر أحد في مراياك","أبقِ الحافلة مؤمّنة بفرملة الانتظار مشدودة ولا تتحرك حتى تحدد موقع الطفل بصريًا وتتأكد من ابتعاده"],"explanation":"إذا اختفى طفل عن مجال الرؤية، أبقِ فرملة الانتظار مشدودة ولا تتحرك حتى تحدد موقع الطفل بصريًا وتتأكد من ابتعاده عن الحافلة."},"197":{"q":"أنا أُنزل الطلاب في محطة بعد الظهر. عددتُ ستة طلاب نزلوا من الحافلة، لكن بينما أفحص مراياي أدرك أنني الآن أستطيع رؤية خمسة منهم فقط على الرصيف وطفل واحد لا يظهر في أي مكان. ماذا يجب أن أفعل قبل أن أنطلق من المحطة؟","options":["أبقي الحافلة مؤمّنة بفرملة الانتظار مشدودة ولا أتحرك حتى أحدد موقع الطفل المفقود وأحصي كل طالب","أتقدّم ببطء بينما أراقب مرآة العبور، لأن التقدم قليلًا يمنحني زاوية أفضل لرصد الطفل المفقود","أفترض أن الطفل قد ابتعد بالفعل عن منطقة الخطر متجهًا إلى المنزل، فأحرر الفرامل وأتابع مساري في الموعد","أطلق البوق مرتين لتحذير الطفل المفقود بالبقاء بعيدًا، ثم أتابع بمجرد وصول الطلاب الخمسة الآخرين إلى الرصيف"],"explanation":"إذا اختفى طالب عن مجال الرؤية، أبقِ فرملة الانتظار مشدودة ولا تتحرك حتى تجد الطفل المفقود وتحصي كل طالب."},"198":{"q":"إنه مساري الصباحي الأول وأنا أُعدّ داخل حافلتي قبل صعود الطلاب. أريد أن يكون الجزء الداخلي مُرتّبًا بالطريقة الصحيحة للإشراف الآمن على الطلاب. أي من هذه ينبغي أن أتأكد من أن الجزء الداخلي يتيح لي فعله؟","options":["إبقاء الداخل معتمًا وهادئًا حتى يبقى الطلاب هادئين وأتمكن من التركيز على الطريق","رؤية الطلاب وسماعهم في كل الأوقات حتى أتمكن من مراقبة سلوكهم والتفاعل بسرعة","حجب رؤيتي لمنطقة الركاب حتى لا يشتتني وهج المرايا أثناء القيادة","إخفاء الطلاب تحت مستوى النافذة حتى لا يتمكن السائقون العابرون من رؤية داخل الحافلة"],"explanation":"يجب ترتيب الجزء الداخلي من الحافلة بحيث يستطيع السائق رؤية الطلاب وسماعهم في كل الأوقات لمراقبة سلوكهم والتفاعل بسرعة."},"199":{"q":"أحمل بالفعل رخصة القيادة التجارية وأقود حاليًا حافلة نقل سعتها 52 راكبًا، لذا لديّ تصديق الركاب (P). الآن تريد منطقتي التعليمية تعييني على مسار لنقل الأطفال من وإلى المدرسة الابتدائية. قبل أن أتمكن قانونيًا من أداء تلك الوظيفة، أي تصديق يجب أن أضيفه إلى رخصتي؟","options":["لا شيء — تصديق الركاب (P) الذي أحمله بالفعل يغطي قيادة الأطفال على مسار مدرسي","تصديق (T)، لأن الحافلة تجر مقصورة أمتعة على شكل مقطورة في الرحلات الميدانية","تصديق (S)، وهو تصديق الحافلة المدرسية المحدد المطلوب لنقل الطلاب","تصديق (H)، لأن الحافلة المدرسية المحمّلة تُعامَل كمركبة حمولة خطرة"],"explanation":"يتطلب نقل الطلاب تصديق الحافلة المدرسية (S)، وهو منفصل عن تصديق الركاب (P) وإضافة إليه."}},"learn-general":{"0":{"q":"مسافة التوقف الإجمالية هي مجموع مسافة الكبح ومسافة رد الفعل وأي مسافة أخرى؟","options":["مسافة الإدراك","مسافة المتابعة","مسافة الرؤية","مسافة المداس"],"explanation":"مسافة التوقف الإجمالية هي مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الكبح."},"1":{"q":"عند السير بسرعة 55 ميلاً في الساعة في ظروف جيدة، ما هي مسافة التوقف الإجمالية؟","options":["حوالي 250 قدماً","حوالي 419 قدماً","حوالي 350 قدماً","حوالي 500 قدم"],"explanation":"عند السير بسرعة 55 ميلاً في الساعة في ظروف جيدة، تبلغ مسافة التوقف الإجمالية حوالي 419 قدماً، أي ما يقارب طول ملعب كرة القدم."},"2":{"q":"عند السير بسرعة 55 ميلاً في الساعة، كم تبلغ مسافة رد الفعل تقريباً؟","options":["30 قدماً","45 قدماً","60 قدماً","100 قدم"],"explanation":"عند السير بسرعة 55 ميلاً في الساعة، تبلغ مسافة رد الفعل حوالي 60 قدماً، أي ما يقارب ثلاثة أرباع الثانية."},"3":{"q":"إذا ضاعفت سرعتك، فبأي مقدار تزداد مسافة الكبح تقريباً؟","options":["تبقى كما هي","تتضاعف","تتضاعف ثلاث مرات","تتضاعف أربع مرات"],"explanation":"تزداد مسافة الكبح بمربع السرعة، لذا فإن مضاعفة سرعتك تضاعفها أربع مرات تقريباً."},"4":{"q":"مقارنةً بشاحنة محملة، ما نوع مسافة التوقف التي يمكن أن تكون لشاحنة فارغة؟","options":["أطول","أقصر","نفس المسافة","صفر دائماً"],"explanation":"يمكن أن تكون مسافة توقف الشاحنة الفارغة أطول من المحملة لأن لديها قوة احتكاك أقل."},"5":{"q":"عند سرعة أقل من 40 ميلاً في الساعة، كم ثانية من مسافة المتابعة يجب أن تتركها لكل 10 أقدام من طول المركبة؟","options":["0.5 ثانية","ثانية واحدة","ثانيتان","3 ثوانٍ"],"explanation":"اترك ثانية واحدة من مسافة المتابعة لكل 10 أقدام من طول المركبة عند السير بأقل من 40 ميلاً في الساعة."},"6":{"q":"إلى أي مدى يجب أن تنظر إلى الأمام أثناء القيادة؟","options":["من 5 إلى 8 ثوانٍ","من 1 إلى 3 ثوانٍ","من 12 إلى 15 ثانية","من 20 إلى 25 ثانية"],"explanation":"انظر إلى الأمام من 12 إلى 15 ثانية، أي ما يقارب ربع ميل عند سرعة الطريق السريع."},"7":{"q":"كم مرة يجب أن تتفقد مراياك أثناء القيادة؟","options":["كل 1 إلى 2 ثانية","كل 12 إلى 15 ثانية","كل 3 إلى 4 ثوانٍ","كل 5 إلى 8 ثوانٍ"],"explanation":"يجب أن تتفقد مراياك كل 5 إلى 8 ثوانٍ أثناء القيادة."},"8":{"q":"بعد أول 50 ميلاً، كم مرة يجب أن تعيد فحص تثبيت الحمولة؟","options":["كل 3 ساعات أو 150 ميلاً","كل ساعتين أو 100 ميل","كل 4 ساعات أو 200 ميل","كل ساعة واحدة أو 50 ميلاً"],"explanation":"بعد أول 50 ميلاً، أعد فحص الحمولة وتثبيتها كل 3 ساعات أو 150 ميلاً."},"9":{"q":"ما هو الحد الأدنى لعمق مداس إطارات محور التوجيه (الأمامية)؟","options":["2/32 بوصة","4/32 بوصة","6/32 بوصة","8/32 بوصة"],"explanation":"يجب أن يكون لإطارات محور التوجيه (الأمامية) حد أدنى لعمق المداس قدره 4/32 بوصة."},"10":{"q":"ما هو الحد الأدنى لعمق المداس للإطارات الأخرى غير إطارات محور التوجيه؟","options":["1/32 بوصة","3/32 بوصة","2/32 بوصة","4/32 بوصة"],"explanation":"يجب أن يكون لجميع الإطارات الأخرى غير إطارات محور التوجيه حد أدنى لعمق المداس قدره 2/32 بوصة."},"11":{"q":"يجب ألا يقل الحد الإجمالي لحمولة العمل لأدوات التثبيت عن أي نسبة من وزن الحمولة؟","options":["الربع","الثلث","الثلثان","النصف"],"explanation":"يجب ألا يقل الحد الإجمالي لحمولة العمل لأدوات التثبيت عن نصف وزن الحمولة."},"12":{"q":"كم قدماً من الحمولة تتطلب أداة تثبيت واحدة على الأقل؟","options":["10 أقدام","5 أقدام","15 قدماً","50 قدماً"],"explanation":"يجب أن تستخدم أداة تثبيت واحدة على الأقل لكل 10 أقدام من الحمولة."},"13":{"q":"كم عدد أدوات التثبيت المطلوبة لأي قطعة حمولة يزيد طولها عن 5 أقدام؟","options":["أداة تثبيت واحدة","أداتا تثبيت","3 أدوات تثبيت","4 أدوات تثبيت"],"explanation":"أي قطعة حمولة يزيد طولها عن 5 أقدام يجب أن يكون لها أداتا تثبيت على الأقل."},"14":{"q":"على طريق سريع مقسوم، على أي مسافات تضع المثلثات التحذيرية الثلاثة؟","options":["10 و50 و150 قدماً","10 و100 و150 قدماً","10 و100 و200 قدم","50 و100 و200 قدم"],"explanation":"ضع المثلثات العاكسة الثلاثة على بعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة."},"15":{"q":"متى يجب أن تختار ترساً منخفضاً لمنحدر طويل؟","options":["بعد أن تضعف الفرامل","في منتصف المنحدر","فقط إذا تعطلت الفرامل","قبل البدء بالنزول"],"explanation":"اختر ترساً منخفضاً قبل منحدر طويل؛ فالفرامل تكمّل كبح المحرك والترس فقط."},"16":{"q":"ماذا يمكن أن يحدث للفرامل إذا أُفرط في استخدامها على منحدر طويل؟","options":["يمكن أن تضعف","تصبح أقوى","تنغلق","تبرد"],"explanation":"يمكن أن تضعف الفرامل بسبب فرط السخونة إذا أُفرط في استخدامها على منحدر طويل."},"17":{"q":"كيف يؤثر نظام منع انغلاق المكابح (ABS) على مسافة توقفك؟","options":["يقلّلها إلى النصف","لا يقصّرها","يقصّرها كثيراً","يضاعفها"],"explanation":"يساعدك نظام ABS على الكبح بثبات والتوجيه، لكنه لا يقصّر مسافة توقفك."},"18":{"q":"ما هو السبب الرئيسي لمعظم حالات الانزلاق؟","options":["تآكل أقمشة الفرامل","نقص ضغط الإطارات","القيادة بسرعة كبيرة لا تناسب الظروف","تغيير المسارات المفاجئ"],"explanation":"تحدث معظم حالات الانزلاق لأن السائق يسير بسرعة كبيرة لا تناسب الظروف."},"19":{"q":"في حالة انزلاق العجلات الدافعة، ماذا يجب أن تفعل بالقابض (الدبرياج)؟","options":["اضغط عليه مرتين","اتركه خارجاً","حرّره ببطء","اضغط عليه للداخل"],"explanation":"في حالة انزلاق العجلات الدافعة، توقف عن التسارع، واضغط على القابض للداخل، ووجّه نحو المكان الذي تريد الذهاب إليه."},"20":{"q":"في حالة انزلاق العجلات الأمامية، متى يمكنك التوجيه مجدداً؟","options":["عند عودة الاحتكاك","عند الكبح بقوة","عند التسارع","عند خفض الترس"],"explanation":"في حالة انزلاق العجلات الأمامية، لا يمكنك توجيه المركبة حتى يعود الاحتكاك إلى الإطارات الأمامية."},"21":{"q":"ما الذي يجب ألا تفعله أبداً أثناء عبور سكك الحديد؟","options":["استخدام الفرامل","تبديل التروس","النظر إلى الجانبين","التباطؤ"],"explanation":"لا تبدّل التروس أبداً أثناء عبور سكك الحديد، حتى لا تعلق على القضبان."},"22":{"q":"لتجاوز سكك الحديد بالكامل، تحتاج إلى طول مركبتك بالإضافة إلى حوالي كم قدماً؟","options":["5 أقدام","10 أقدام","15 قدماً","20 قدماً"],"explanation":"لا تبدأ بعبور السكك إلا إذا كنت تستطيع تجاوزها بالكامل، وهو ما يحتاج إلى طول مركبتك بالإضافة إلى حوالي 15 قدماً."},"23":{"q":"عند مزلقان سكة الحديد، ما الذي يجب ألا تعتمد عليه وحده؟","options":["مراياك","ترسك المنخفض","فراملك","الإشارات"],"explanation":"عند مزلقان سكة الحديد، لا تعتمد أبداً على الإشارات وحدها لتقرير أن العبور آمن."},"24":{"q":"في الليل، ضمن أي مسافة يجب أن تكون قادراً على التوقف؟","options":["المسافة التي يمكنك رؤيتها أمامك","ضعف مدى مصابيحك الأمامية","طول ملعب كرة القدم","نصف ميل أمامك"],"explanation":"في الليل، لا تتجاوز أبداً مدى مصابيحك الأمامية؛ يجب أن تسمح لك سرعتك بالتوقف ضمن المسافة التي يمكنك رؤيتها أمامك."},"25":{"q":"تقريباً كم قدماً تضيء المصابيح الأمامية المنخفضة (الضوء الخافت)؟","options":["200 قدم","250 قدماً","350 قدماً","500 قدم"],"explanation":"تضيء الأضواء الخافتة حوالي 250 قدماً أمامك، بينما تصل الأضواء العالية إلى حوالي 350 إلى 500 قدم."},"26":{"q":"على بُعد كم قدمًا من مركبة قادمة في الاتجاه المعاكس يجب أن تخفِّض أضواءك العالية؟","options":["200 قدم","350 قدمًا","500 قدم","650 قدمًا"],"explanation":"خفِّض أضواءك العالية عندما تكون على بُعد 500 قدم من مركبة قادمة في الاتجاه المعاكس أو خلف مركبة أخرى."},"27":{"q":"في الضباب، أيَّ المصابيح الأمامية يجب أن تستخدم؟","options":["الأضواء العالية","أضواء الوقوف","لا أضواء","الأضواء المنخفضة"],"explanation":"في الضباب، خفِّف سرعتك واستخدم الأضواء المنخفضة، لأن الأضواء العالية تنعكس إليك وتقلل الرؤية."},"28":{"q":"في الشتاء، أيُّ جزء من الطريق يتجمد أولًا؟","options":["الجسور","الأنفاق","التلال","التقاطعات"],"explanation":"في الشتاء، تتجمد الجسور قبل سائر أجزاء الطريق، لذا خفِّف سرعتك عند عبورها."},"29":{"q":"في الطقس الحار، ماذا يحدث لضغط الإطارات؟","options":["ينخفض","يرتفع","يبقى كما هو","يختفي"],"explanation":"في الطقس الحار، ترفع الحرارة ضغط الإطارات وتزيد من خطر انفجارها."},"30":{"q":"ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) لسائق رخصة القيادة التجارية (CDL)؟","options":["0.01%","0.02%","0.04%","0.08%"],"explanation":"الحد الأقصى لتركيز الكحول في الدم لسائق رخصة القيادة التجارية هو 0.04%."},"31":{"q":"ما هو الشيء الوحيد الذي يزيل الكحول من الجسم؟","options":["القهوة","الطعام","الهواء النقي","الوقت"],"explanation":"الوقت وحده يزيل الكحول من الجسم؛ أما القهوة والطعام والهواء النقي فلا تفعل ذلك."},"32":{"q":"أيُّ فئة من رخص القيادة التجارية تخص مركبة مركّبة بوزن إجمالي مرتبط (GCWR) يبلغ 26,001 رطل أو أكثر مع وحدة مقطورة تزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تشمل الفئة A المركبات المركّبة ذات الوزن الإجمالي المرتبط (GCWR) البالغ 26,001 رطل أو أكثر عندما تتجاوز الوحدة المقطورة 10,000 رطل."},"33":{"q":"ما هو الحد الأدنى لوزن المركبة المفردة لرخصة القيادة التجارية من الفئة B؟","options":["10,000 رطل","26,001 رطل","16,000 رطل","36,000 رطل"],"explanation":"تشمل رخصة القيادة التجارية من الفئة B مركبة مفردة بوزن 26,001 رطل أو أكثر، أو مركبة تجرّ 10,000 رطل أو أقل."},"34":{"q":"أيُّ فئة من رخص القيادة التجارية مخصصة للمركبات الأصغر التي تنقل مواد خطرة (HazMat) أو 16 راكبًا أو أكثر؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"الفئة C مخصصة للمركبات الأصغر المستخدمة لنقل المواد الخطرة (HazMat) أو 16 راكبًا أو أكثر."},"35":{"q":"عند سرعة 55 ميلًا في الساعة، كم تبلغ تقريبًا مسافة التوقف الكلية لديك؟","options":["نحو طول ملعب كرة قدم، حوالي 6 ثوانٍ","نحو طول حافلة مدرسية، حوالي 6 ثوانٍ","نحو طول مجمّع سكني، حوالي 6 ثوانٍ","نحو طول مساري سيارتين، حوالي 6 ثوانٍ"],"explanation":"عند سرعة 55 ميلًا في الساعة، تبلغ مسافة التوقف الكلية لديك نحو طول ملعب كرة قدم بما في ذلك منطقتا التسجيل، وتستغرق حوالي 6 ثوانٍ."},"36":{"q":"عند سرعة 55 ميلًا في الساعة، كم تستغرق تقريبًا مسافة رد الفعل (نحو 60 قدمًا)؟","options":["نحو 1/2 ثانية","نحو 3/4 ثانية","نحو ثانية واحدة","نحو ثانيتين"],"explanation":"عند سرعة 55 ميلًا في الساعة، تبلغ مسافة رد الفعل نحو 60 قدمًا، وتستغرق حوالي 3/4 ثانية."},"37":{"q":"كلما زادت سرعتك، تتزايد مسافة الكبح بما يتناسب مع:","options":["نفس مقدار السرعة","مكعّب سرعتك","مربّع سرعتك","نصف سرعتك"],"explanation":"تتزايد مسافة الكبح بما يتناسب مع مربّع السرعة، لذا فإن مضاعفة سرعتك تزيدها أربعة أضعاف تقريبًا."},"38":{"q":"كم يجب أن تضيف إلى مسافة المتابعة عند تجاوز سرعة 40 ميلًا في الساعة؟","options":["أضف 3 ثوانٍ","لا تضف شيئًا","أضف ثانيتين","أضف ثانية واحدة"],"explanation":"عند تجاوز سرعة 40 ميلًا في الساعة يجب أن تضيف ثانية واحدة إلى مسافة المتابعة."},"39":{"q":"النظر إلى مسافة 12-15 ثانية أمامك يعادل أي مسافة تقريبًا عند سرعة الطريق السريع؟","options":["نحو 1/4 ميل","نحو 1/2 ميل","نحو ميل واحد","نحو 1/8 ميل"],"explanation":"النظر إلى مسافة 12-15 ثانية أمامك يعادل نحو 1/4 ميل عند سرعة الطريق السريع."},"40":{"q":"متى يجب أن تفحص حمولتك وتثبيتها لأول مرة بعد بدء الرحلة؟","options":["خلال أول 25 ميلًا","خلال أول 50 ميلًا","خلال أول 75 ميلًا","خلال أول 100 ميل"],"explanation":"يجب أن تفحص حمولتك وتثبيتها خلال أول 50 ميلًا من الرحلة."},"41":{"q":"ما هو الحد الأدنى لعدد روابط التثبيت المطلوبة لكل 10 أقدام من الحمولة؟","options":["3 روابط تثبيت","4 روابط تثبيت","رابط تثبيت واحد","رابطا تثبيت"],"explanation":"تحتاج إلى رابط تثبيت واحد على الأقل لكل 10 أقدام من الحمولة."},"42":{"q":"بعد التوقف، خلال كم دقيقة يجب أن تشغّل أضواء الخطر الوامضة وتضع مثلثات التحذير؟","options":["30 دقيقة","20 دقيقة","5 دقائق","10 دقائق"],"explanation":"بعد التوقف يجب أن تشغّل أضواء الخطر الوامضة وتضع المثلثات خلال 10 دقائق."},"43":{"q":"على طريق ذي مسارين أو طريق غير مقسّم، أين تضع مثلثات التحذير الثلاثة بعد التوقف؟","options":["نحو 10 أقدام، و100 قدم إلى الخلف، و100 قدم إلى الأمام","نحو 10 أقدام، و100 قدم، و200 قدم، جميعها إلى الخلف","نحو 50 قدمًا، و100 قدم، و150 قدمًا إلى الخلف","نحو 25 قدمًا، و75 قدمًا، و125 قدمًا إلى الأمام"],"explanation":"على طريق ذي مسارين أو طريق غير مقسّم، ضع المثلثات باتجاه حركة المرور القادمة، مع وضع واحد على بُعد نحو 100 قدم إلى الخلف وواحد إلى الأمام."},"44":{"q":"على منحدر طويل، يجب استخدام الفرامل من أجل:","options":["استبدال كبح المحرك والتروس","تعزيز كبح المحرك والتروس","تجنّب استخدام ترس منخفض","زيادة سرعة المركبة"],"explanation":"على المنحدر، تكون الفرامل مجرد مكمّل لكبح المحرك والتروس."},"45":{"q":"على ماذا تعتمد السرعة الآمنة على منحدر طويل؟","options":["على الوزن الإجمالي للمركبة فقط","على شدة انحدار الطريق فقط","على الانحدار والطقس وشكل الطريق والوزن","على الظروف الجوية الحالية فقط"],"explanation":"تعتمد السرعة الآمنة على المنحدر على طول الانحدار وشدته، والطقس، وشكل الطريق، والوزن الإجمالي."},"46":{"q":"في حالة توقف طارئ بدون نظام منع انغلاق الفرامل (ABS)، كيف يجب أن تكبح لتجنّب الانزلاق؟","options":["اضغط على الفرامل بخفة بشكل متقطع ثم انزلق بحرية","اضغط بقوة لإقفال العجلات","اكبح بفرملة الانتظار فقط","استخدم الكبح المتحكَّم فيه أو الكبح المتقطع دون إقفال العجلات"],"explanation":"في حالة طارئة بدون نظام منع انغلاق الفرامل (ABS)، استخدم الكبح المتحكَّم فيه أو الكبح المتقطع ولا تُقفِل العجلات."},"47":{"q":"عندما تكون مركبتك مزوّدة بنظام منع انغلاق الفرامل (ABS)، كيف يجب أن تكبح في حالة طارئة؟","options":["اكبح بثبات ووجِّه عجلة القيادة","اضغط على الفرامل بخفة بشكل متقطع","اسحب فرملة الانتظار","اكبح بلطف ثم انزلق بحرية"],"explanation":"مع نظام منع انغلاق الفرامل (ABS)، يجب أن تكبح بثبات وتوجّه عجلة القيادة."},"48":{"q":"عند انزلاق العجلات الدافعة، ماذا يجب أن تفعل؟","options":["اكبح بقوة وحافظ على الضغط","توقّف عن التسارع ووجِّه عجلة القيادة نحو حيث تريد الذهاب","زِد السرعة لاستعادة السيطرة","انحرف بعيدًا عن مسارك"],"explanation":"عند انزلاق العجلات الدافعة، توقّف عن التسارع ووجّه عجلة القيادة نحو حيث تريد الذهاب."},"49":{"q":"متى يمكنك البدء بعبور سكة الحديد؟","options":["عندما يبدأ الحاجز بالارتفاع","عندما لا تسمع بوق القطار","عندما تستطيع إخلاء السكة بالكامل","عندما يبدو الطريق خلفك خاليًا"],"explanation":"لا تبدأ بعبور السكة إلا إذا كنت تستطيع إخلاءها بالكامل (طول مركبتك زائد نحو 15 قدمًا)."},"50":{"q":"في الليل، يجب ألّا تقود أبدًا أسرع من ماذا؟","options":["المركبة التي أمامك","حد السرعة","حركة المرور الأخرى","ما تتيح لك أضواؤك الأمامية رؤيته"],"explanation":"في الليل يجب ألّا تتجاوز أبدًا مدى أضوائك الأمامية؛ فيجب أن تتيح لك سرعتك التوقف ضمن المسافة التي تستطيع رؤيتها أمامك."},"51":{"q":"إلى أي مسافة تقريباً تضيء الأضواء العالية (الكاشفة) الطريق أمامك؟","options":["350-500 قدم","150-200 قدم","600-750 قدم","800-1,000 قدم"],"explanation":"تضيء الأضواء العالية الطريق أمامك لمسافة 350-500 قدم تقريباً."},"52":{"q":"متى يجب أن تخفّض أضواءك العالية عندما تسير خلف مركبة أخرى؟","options":["ضمن 200 قدم","ضمن 500 قدم","ضمن 1,000 قدم","غير مطلوب أبداً عند السير خلفها"],"explanation":"يجب أن تخفّض أضواءك العالية ضمن مسافة 500 قدم من مركبة أخرى، سواء كانت قادمة باتجاهك أو كنت تسير خلفها."},"53":{"q":"كيف يجعل الجليد الأسود الطريق يبدو؟","options":["جافاً وصافياً","أبيض ومغبراً","متشققاً وخشناً","مبللاً"],"explanation":"الجليد الأسود طبقة رقيقة شفافة تجعل الطريق يبدو مبللاً."},"54":{"q":"في الطقس الحار، ماذا يحدث لضغط الإطارات وخطر الانفجار؟","options":["يرتفع الضغط فيزداد خطر الانفجار","يرتفع الضغط فيقل خطر الانفجار","ينخفض الضغط فيزداد خطر الانفجار","ينخفض الضغط فيقل خطر الانفجار"],"explanation":"في الطقس الحار، يؤدي ارتفاع ضغط الإطارات إلى زيادة خطر الانفجار."},"55":{"q":"في الطقس الحار، ما الذي يجعل الرصيف زلقاً؟","options":["ندى الصباح البارد","نزيف القار (الزفت)","الحصى المتناثر","خطوط الطلاء الجديدة"],"explanation":"في الطقس الحار، يجعل نزيف القار الرصيف زلقاً."},"56":{"q":"في الطقس الحار، أي مقياس يجب أن تراقبه عن كثب؟","options":["مقياس الوقود","مقياس ضغط الزيت","مقياس سائل التبريد/درجة الحرارة","مقياس ضغط الهواء"],"explanation":"في الطقس الحار، راقب مقياس سائل التبريد/درجة الحرارة."},"57":{"q":"ما الشيء الوحيد الذي يزيل الكحول من جسمك؟","options":["شرب القهوة","تناول وجبة طعام","استنشاق الهواء الطلق","مرور الوقت"],"explanation":"الوقت وحده يزيل الكحول من الجسم؛ أما القهوة والطعام والهواء الطلق فلا تفعل ذلك."},"58":{"q":"رخصة القيادة التجارية من الفئة B تتيح لك أيضاً قطر وحدة يبلغ وزنها كم؟","options":["10,000 رطل أو أقل","26,001 رطل أو أكثر","أكثر من 10,000 رطل","أكثر من 26,001 رطل"],"explanation":"رخصة القيادة التجارية من الفئة B تشمل أيضاً قطر وحدة وزنها 10,000 رطل أو أقل."},"59":{"q":"أي فئة من رخص القيادة التجارية تشمل المركبات التي تنقل 16 راكباً أو أكثر؟","options":["الفئة A","الفئة C","الفئة B","الفئة D"],"explanation":"الفئة C تشمل المركبات الأصغر التي تنقل 16 راكباً أو أكثر."},"60":{"q":"من كم مكوّن مسافي تتكوّن مسافة التوقف الإجمالية؟","options":["ثلاثة مكوّنات","مكوّنان","أربعة مكوّنات","خمسة مكوّنات"],"explanation":"تتكوّن مسافة التوقف الإجمالية من ثلاثة مكوّنات: مسافة الإدراك، ومسافة رد الفعل، ومسافة الكبح."},"61":{"q":"عند سرعة 55 ميلاً في الساعة وفي ظروف جيدة، تبلغ مسافة التوقف الإجمالية نحو 419 قدماً، فبماذا تعادل تقريباً؟","options":["مربّع سكني في المدينة","ملعب كرة قدم أمريكية (مع منطقتي النهاية)","ملعب كرة سلة","ملعب تنس"],"explanation":"عند سرعة 55 ميلاً في الساعة وفي ظروف جيدة، تبلغ مسافة التوقف الإجمالية نحو 419 قدماً، وهو ما يقارب طول ملعب كرة القدم الأمريكية بما في ذلك منطقتا النهاية."},"62":{"q":"لماذا تؤدي مضاعفة سرعتك إلى زيادة مسافة الكبح أربعة أضعاف تقريباً بدلاً من مضاعفتها فقط؟","options":["لأن مسافة الكبح تضيف زمن رد الفعل مرتين","لأن مسافة الكبح تنمو بشكل خطي مع السرعة","لأن مسافة الكبح تنمو مع مربّع السرعة","لأن مسافة الكبح تعتمد فقط على وزن المركبة"],"explanation":"تنمو مسافة الكبح مع مربّع السرعة، لذا فإن مضاعفة السرعة تزيد مسافة الكبح أربعة أضعاف تقريباً."},"63":{"q":"لماذا قد تتوقف الشاحنة الفارغة بعد مسافة أطول من الشاحنة المحمّلة؟","options":["لأن مركز ثقلها أعلى","لأن مكبح المحرك لديها أضعف","لأن إطاراتها أبرد","لأن تماسكها مع الطريق أقل"],"explanation":"الشاحنة الفارغة لديها تماسك أقل، لذا قد تحتاج إلى مسافة أطول للتوقف من الشاحنة المحمّلة."},"64":{"q":"مركبة بطول 40 قدماً تسير بسرعة أقل من 40 ميلاً في الساعة، كم ثانية من مسافة المتابعة تحتاج؟","options":["4 ثوانٍ","ثانيتان","5 ثوانٍ","3 ثوانٍ"],"explanation":"اترك ثانية واحدة لكل 10 أقدام من طول المركبة عند سرعة أقل من 40 ميلاً في الساعة، لذا تحتاج مركبة بطول 40 قدماً إلى 4 ثوانٍ."},"65":{"q":"مركبة بطول 60 قدماً تسير بسرعة أعلى من 40 ميلاً في الساعة، كم ثانية من مسافة المتابعة تحتاج؟","options":["6 ثوانٍ","7 ثوانٍ","8 ثوانٍ","5 ثوانٍ"],"explanation":"استخدم ثانية واحدة لكل 10 أقدام (6 ثوانٍ لـ60 قدماً) وأضف ثانية واحدة فوق 40 ميلاً في الساعة، ليصبح المجموع 7 ثوانٍ."},"66":{"q":"النظر إلى نحو ربع ميل أمامك عند سرعة الطريق السريع يعني النظر إلى كم ثانية أمامك؟","options":["2-3 ثوانٍ أمامك","5-8 ثوانٍ أمامك","12-15 ثانية أمامك","20-25 ثانية أمامك"],"explanation":"النظر إلى 12-15 ثانية أمامك يعادل نحو ربع ميل عند سرعة الطريق السريع."},"67":{"q":"كحد أقصى، كم من الوقت يجوز أن تمضي دون فحص مراياك؟","options":["نحو ثانيتين","نحو 15 ثانية","نحو 30 ثانية","نحو 8 ثوانٍ"],"explanation":"يجب أن تفحص مراياك كل 5 إلى 8 ثوانٍ، لذا فإن أطول فترة هي نحو 8 ثوانٍ."},"68":{"q":"بعد أول 50 ميلاً، يجب أن تعيد فحص تثبيت الحمولة بعد القيادة كم ميلاً؟","options":["كل 150 ميلاً","كل 100 ميل","كل 250 ميلاً","كل 300 ميل"],"explanation":"بعد أول 50 ميلاً، أعد فحص تثبيت الحمولة كل 3 ساعات أو 150 ميلاً."},"69":{"q":"بعد كم ساعة من القيادة يجب أن تعيد فحص تثبيت حمولتك؟","options":["ساعة واحدة","3 ساعات","5 ساعات","8 ساعات"],"explanation":"يجب أن تعيد فحص تثبيت الحمولة كل 3 ساعات من القيادة."},"70":{"q":"أي إطارات تتطلب عمق مداس أدنى أكبر؟","options":["جميع الإطارات تتطلب المداس نفسه","إطارات المحور الخلفي","إطارات محور التوجيه (الأمامية)","لا يوجد حد أدنى للمداس لأيٍّ منها"],"explanation":"تحتاج إطارات محور التوجيه (الأمامية) إلى عمق مداس لا يقل عن 4/32 من البوصة، بينما تحتاج جميع الإطارات الأخرى إلى 2/32 من البوصة فقط."},"71":{"q":"كم يزيد الحد الأدنى لعمق المداس للإطارات الأمامية (محور التوجيه) عنه لجميع الإطارات الأخرى؟","options":["العمق نفسه","أعمق بمقدار 1/32 بوصة","أعمق بمقدار 4/32 بوصة","أعمق بمقدار 2/32 بوصة"],"explanation":"تحتاج الإطارات الأمامية إلى حد أدنى من المداس قدره 4/32 من البوصة وتحتاج جميع الإطارات الأخرى إلى 2/32 من البوصة، لذا فإن الحد الأدنى الأمامي أعمق بمقدار 2/32 من البوصة."},"72":{"q":"لحمولة وزنها 4,000 رطل، كم يجب أن يكون الحد الأدنى لحد العمل الإجمالي لأدوات التثبيت؟","options":["2,000 رطل","1,000 رطل","3,000 رطل","4,000 رطل"],"explanation":"يجب أن يكون الحد الإجمالي لعمل أدوات التثبيت نصف وزن الحمولة على الأقل، لذا فإن حمولة وزنها 4,000 رطل تحتاج إلى 2,000 رطل على الأقل."},"73":{"q":"أي قطعة حمولة واحدة يزيد طولها عن أي مقدار تحتاج إلى أداتي تثبيت على الأقل؟","options":["3 أقدام","5 أقدام","8 أقدام","10 أقدام"],"explanation":"أي قطعة حمولة واحدة يزيد طولها عن 5 أقدام تتطلب أداتي تثبيت على الأقل."},"74":{"q":"بحسب قاعدة كل 10 أقدام، كم أداة تثبيت تحتاجها قطعة حمولة بطول 20 قدماً كحد أدنى؟","options":["أربع على الأقل","واحدة على الأقل","اثنتان على الأقل","ثلاث على الأقل"],"explanation":"تتطلب القاعدة حداً أدنى من أداة تثبيت واحدة لكل 10 أقدام، لذا تحتاج قطعة بطول 20 قدماً إلى أداتين على الأقل."},"75":{"q":"عند وضع مثلثات التحذير بعد التوقف، على أي مسافة إلى الخلف يوضع المثلث الأبعد؟","options":["10 أقدام","50 قدماً","100 قدم","200 قدم"],"explanation":"توضع المثلثات العاكسة الثلاثة على مسافات 10 أقدام و100 قدم و200 قدم، لذا يكون الأبعد على بعد 200 قدم."},"76":{"q":"كم عدد المثلثات العاكسة التي يجب أن تضعها بعد التوقف على الطريق؟","options":["3 مثلثات","مثلثان","4 مثلثات","مثلث واحد"],"explanation":"بعد التوقف، شغّل أضواء التحذير (الفلاشر) وضع خلال 10 دقائق 3 مثلثات عاكسة."},"77":{"q":"على طريق غير مقسوم، على أي مسافة أمام مركبتك المتوقفة تضع مثلث التحذير؟","options":["نحو 10 أقدام أمامها","نحو 100 قدم أمامها","نحو 250 قدمًا أمامها","نحو 500 قدم أمامها"],"explanation":"على طريق ذي مسارين أو غير مقسوم، يوضع مثلث واحد على بُعد نحو 100 قدم أمام المركبة."},"78":{"q":"على منحدرٍ طويل وشديد الانحدار، ما الذي ينبغي أن يقوم بمعظم عمل الكبح؟","options":["مكابح المقطورة فقط","مكبح الانتظار","كبح المحرك والتروس","المكابح الخدمية وحدها"],"explanation":"ينبغي أن يقوم كبح المحرك والتروس بالعمل الرئيسي على المنحدر، مع استخدام المكابح كعنصر مساعد فقط."},"79":{"q":"على منحدرٍ طويل، ما الذي يسبب ضعف المكابح (تلاشيها)؟","options":["هواء الصباح البارد","انخفاض ضغط الإطارات","دواسة قابض مهترئة","ارتفاع درجة الحرارة من فرط الاستخدام"],"explanation":"يمكن أن تتلاشى المكابح بسبب ارتفاع درجة حرارتها إذا أُفرط في استخدامها على منحدرٍ طويل."},"80":{"q":"هل يؤثر الوزن الإجمالي لمركبتك في السرعة الآمنة على المنحدر؟","options":["نعم، الوزن يؤثر في السرعة الآمنة","لا، فقط التروس هي المهمة","لا، فقط الطقس هو المهم","لا، الوزن لا يهم أبدًا"],"explanation":"تعتمد السرعة الآمنة على المنحدر على الوزن الإجمالي للمركبة إلى جانب طول المنحدر وشدته والطقس وشكل الطريق."},"81":{"q":"صحيح أم خطأ: يتيح لك نظام ABS التوقف على مسافة أقصر من المكابح غير المزودة بـ ABS.","options":["صحيح، فنظام ABS يقصّر مسافة التوقف دائمًا","خطأ، فنظام ABS لا يقصّر مسافة التوقف","صحيح، لكن فقط على الرصيف الجاف","خطأ، فنظام ABS يجعل التوقف يستغرق وقتًا أطول"],"explanation":"يساعدك نظام ABS على التوجيه أثناء الكبح بقوة، لكنه لا يقصّر مسافة التوقف."},"82":{"q":"أثناء الكبح الطارئ من دون نظام ABS، ما الذي يجب أن تتجنب فعله؟","options":["توجيه المركبة","ضخّ المكابح","قفل العجلات","استخدام المحرك"],"explanation":"أثناء الكبح الطارئ من دون نظام ABS، استخدم الكبح المتحكَّم به أو الكبح المتقطع ولا تقفل العجلات."},"83":{"q":"عند انزلاق العجلات الدافعة، ما أول ما ينبغي أن تفعله بدواسة الوقود؟","options":["اضغطها بقوة أكبر","انقرها بخفة","اضخّها مرتين","توقّف عن التسارع"],"explanation":"عند انزلاق العجلات الدافعة، أول خطوة هي التوقف عن التسارع."},"84":{"q":"عند انزلاق العجلات الأمامية، هل يمكنك توجيه المركبة أثناء انزلاقها؟","options":["لا، ليس حتى تعود قوة التماسك (الجر)","نعم، التوجيه يعمل بشكل طبيعي","نعم، إذا كبحت بقوة","نعم، إذا زدت السرعة"],"explanation":"عند انزلاق العجلات الأمامية لا يمكنك توجيه المركبة حتى تعود قوة التماسك (الجر)."},"85":{"q":"لتجنّب معظم حالات الانزلاق، ما الذي ينبغي أن يفعله السائق؟","options":["الكبح بقوة أكبر على المنعطفات","عدم القيادة بسرعة مفرطة بالنسبة للظروف","ضخّ المكابح كثيرًا","إبقاء المحرك على ترس عالٍ"],"explanation":"تنتج معظم حالات الانزلاق من القيادة بسرعة مفرطة بالنسبة للظروف، لذا فإن التمهّل يساعد على منعها."},"86":{"q":"كم تبلغ تقريبًا المساحة الكلية اللازمة لشاحنة طولها 50 قدمًا لعبور سكة الحديد بالكامل؟","options":["نحو 50 قدمًا","نحو 55 قدمًا","نحو 65 قدمًا","نحو 70 قدمًا"],"explanation":"لا تبدأ العبور إلا إذا كان بإمكانك تجاوز السكة بالكامل، أي طول مركبتك زائد نحو 15 قدمًا."},"87":{"q":"أثناء عبور سكة الحديد، كيف ينبغي أن تُبقي ناقل الحركة؟","options":["انتقل بترس أعلى","انتقل بترس أدنى","غيّر التروس بحرية","ابقَ على ترس واحد"],"explanation":"يجب ألا تغيّر التروس أبدًا أثناء عبور السكة، لذا ابقَ على ترس واحد طوال العبور."},"88":{"q":"عند مزلقان سكة حديد لا تظهر فيه أي إشارة تحذير، ما الذي ينبغي أن تفعله رغم ذلك؟","options":["انظر وأنصت بنفسك بحثًا عن القطارات","ثق بالإشارة واعبر","افترض ألا قطار قادم","أسرِع لتجتاز بسرعة أكبر"],"explanation":"لا تعتمد على الإشارات وحدها؛ انظر وأنصت دائمًا بنفسك بحثًا عن القطارات."},"89":{"q":"أيّ المصابيح الأمامية تضيء جزءًا أكبر من الطريق أمامك؟","options":["الأضواء المنخفضة","الأضواء العالية","أضواء التحذير","أضواء الضباب"],"explanation":"تضيء الأضواء العالية نحو 350-500 قدم، بينما تضيء الأضواء المنخفضة نحو 250 قدمًا فقط."},"90":{"q":"في الليل، ماذا يعني أن \"تتجاوز قدرة مصابيحك الأمامية\"؟","options":["القيادة مع تشغيل الأضواء العالية","نسيان تعتيم الأضواء أمام المركبات الأخرى","القيادة بسرعة تمنعك من التوقف ضمن المسافة المضاءة","ترك المصابيح الأمامية مطفأة ليلًا"],"explanation":"تجاوز قدرة مصابيحك الأمامية يعني القيادة بسرعة كبيرة بحيث لا يمكنك التوقف ضمن المسافة التي تراها أمامك."},"91":{"q":"ضمن كم قدمًا من مركبة أخرى يجب أن تعتّم أضواءك العالية، سواء عند ملاقاتها أو السير خلفها؟","options":["100 قدم","250 قدمًا","350 قدمًا","500 قدم"],"explanation":"يجب أن تعتّم أضواءك العالية ضمن 500 قدم من مركبة قادمة، وضمن 500 قدم خلف مركبة تسير خلفها."},"92":{"q":"في الضباب، لماذا ينبغي أن تتجنب استخدام الأضواء العالية؟","options":["لأن الضوء ينعكس عائدًا ويسبب الوهج","لأنها تستنزف البطارية أسرع","لأن استخدامها ليلًا غير قانوني","لأنها تجعل المحرك يسخن أكثر من اللازم"],"explanation":"في الضباب ينبغي أن تستخدم الأضواء المنخفضة لأن الأضواء العالية تنعكس عائدةً عن الضباب وتسبب الوهج."},"93":{"q":"ما هو الإجراء الأكثر أمانًا بخصوص القيادة في الضباب؟","options":["الإسراع لاجتياز الضباب بسرعة","تجنب القيادة فيه إن أمكن","القيادة دائمًا بالسرعة المحددة","السير على مقربة شديدة خلف مركبة أخرى"],"explanation":"في الضباب ينبغي أن تتجنب القيادة إن أمكن، وإذا اضطُررت للقيادة فخفّف السرعة."},"94":{"q":"ما هو الجليد الأسود؟","options":["كومة من الثلج المتراكم","رقعة من الوحل الذائب","طبقة رقيقة شفافة من الجليد","حافة من الطين المتجمد"],"explanation":"الجليد الأسود هو طبقة رقيقة شفافة من الجليد تجعل الطريق يبدو مبللًا."},"95":{"q":"في الشتاء، أيّ سطح يتجمد قبل بقية الطريق؟","options":["المسارات المستقيمة المستوية","المنحدرات الصاعدة","داخل الأنفاق","الجسور والمعابر العلوية"],"explanation":"في الشتاء، تتجمد الجسور والمعابر العلوية قبل بقية الطريق، لذا خفّف السرعة قبل عبورها."},"96":{"q":"في الطقس الحار، يزيد ارتفاع ضغط الإطارات من خطر ماذا؟","options":["انفجار إطار","تجمّد خط المكابح","نفاد البطارية","انسداد مرشّح الوقود"],"explanation":"في الطقس الحار، ترفع الحرارة ضغط الإطارات، مما يزيد من خطر الانفجار."},"97":{"q":"في الطقس الشديد الحرارة، ينتج الرصيف الزلق عن ماذا يطفو من الطريق؟","options":["الحصى السائب","نزيف القار أو ذوبانه","مياه الأمطار الراكدة","خطوط الطلاء الطازجة"],"explanation":"في الطقس الحار، ينزف القار الموجود في الرصيف أو يذوب إلى السطح فيجعل الطريق زلقًا."},"98":{"q":"هل يسرّع شرب القهوة من سرعة خروج الكحول من جسمك؟","options":["نعم، القهوة تزيل الكحول بسرعة","نعم، لكن القهوة السوداء فقط","لا، الوقت وحده يزيل الكحول","نعم، القهوة والطعام كلاهما يساعد"],"explanation":"الوقت وحده يزيل الكحول من جسمك، وليس القهوة أو الطعام أو الهواء المنعش."},"99":{"q":"ما هو حدّ تركيز الكحول في الدم (BAC) لرخصة القيادة التجارية (CDL)، بالنسبة المئوية؟","options":["0.08 بالمئة","0.10 بالمئة","0.02 بالمئة","0.04 بالمئة"],"explanation":"حدّ تركيز الكحول في الدم (BAC) لرخصة القيادة التجارية (CDL) هو 0.04 بالمئة."},"100":{"q":"بالنسبة لرخصة القيادة التجارية من الفئة A، يجب أن يزيد وزن الوحدة المقطورة عن كم؟","options":["10,000 رطل","26,001 رطل","5,000 رطل","16,000 رطل"],"explanation":"بالنسبة للفئة A، يجب أن يزيد وزن الوحدة المقطورة عن 10,000 رطل."},"101":{"q":"المركبة المفردة التي يبلغ وزنها 26,001 رطل أو أكثر وتقطر مقطورة وزنها 10,000 رطل أو أقل تنتمي إلى أي فئة من رخص القيادة التجارية؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تشمل الفئة B المركبة المفردة التي يبلغ وزنها 26,001 رطل أو أكثر، أو التي تقطر 10,000 رطل أو أقل."},"102":{"q":"ما هو الحد الأدنى لعمق مداس الإطارات الأمامية (إطارات التوجيه)؟","options":["2/32 بوصة","4/32 بوصة","6/32 بوصة","8/32 بوصة"],"explanation":"تحتاج إطارات التوجيه إلى 4/32 بوصة على الأقل؛ وباقي الإطارات إلى 2/32 بوصة."},"103":{"q":"الحد الأدنى لعمق مداس الإطارات غير الأمامية هو:","options":["1/32 بوصة","2/32 بوصة","4/32 بوصة","6/32 بوصة"],"explanation":"تحتاج الإطارات غير الموجهة إلى 2/32 بوصة على الأقل."},"104":{"q":"ما مقدار الخلل في عجلة القيادة (اللعب) الذي يجب أن يجعلك تشك في وجود مشكلة؟","options":["أكثر من 5 درجات","أكثر من 10 درجات","أكثر من 20 درجة","أكثر من 45 درجة"],"explanation":"أكثر من نحو 10 درجات (2 بوصة على عجلة قطرها 20 بوصة) يُعد مفرطًا."},"105":{"q":"كم عدد مثلثات التحذير العاكسة التي يجب أن تحملها؟","options":["واحد","اثنان","ثلاثة","ستة"],"explanation":"ثلاثة مثلثات عاكسة (أو 6 شُعل / 3 شعلات سائلة)."},"106":{"q":"أي تصنيف لطفايات الحريق يعمل على حرائق الوقود والكهرباء؟","options":["الفئة A","B:C","النوع المائي","لا يعمل أي منها"],"explanation":"تعمل طفاية الفئة B:C على السوائل المشتعلة والحرائق الكهربائية."},"107":{"q":"يجب أن تحمل مصاهر كهربائية احتياطية ما لم تكن المركبة مزودة بـ:","options":["قواطع دارة","بطارية احتياطية","أضواء LED","مولّدَين كهربائيين"],"explanation":"المصاهر الاحتياطية مطلوبة ما لم تستخدم المركبة قواطع دارة."},"108":{"q":"الخطوة الأولى في الفحص ذي السبع خطوات هي:","options":["فحص الأضواء","نظرة عامة على المركبة","تشغيل المحرك","فحص الفرامل"],"explanation":"الخطوة 1 هي إجراء نظرة عامة على المركبة."},"109":{"q":"عند إيقاف المحرك، يشمل الفحص التحقق من:","options":["ضغط الإطارات فقط","الزيت وسائل التبريد والأحزمة","شحم العجلة الخامسة","الراديو"],"explanation":"افحص الزيت وسائل التبريد وسائل توجيه القوة والأحزمة والتسربات."},"110":{"q":"التسارع على طريق زلق يجب أن يتم:","options":["بسلاسة وتدريجيًا","بأسرع ما يمكن","مع تحرير القابض","في غيار عالٍ"],"explanation":"زِد السرعة بسلاسة؛ فالقوة الزائدة قد تجعل العجلات المحركة تدور."},"111":{"q":"عند الرجوع للخلف، يجب عمومًا أن:","options":["ترجع نحو اليمين","ترجع نحو جهة السائق","ترجع بسرعة","تستخدم المرايا فقط"],"explanation":"ارجع نحو جهة السائق، واستعن بمساعد، وتحرك ببطء."},"112":{"q":"يجب أن تخفّض الغيار إلى الغيار المناسب:","options":["في المنعطف","قبل التل أو المنعطف","بعد المنعطف","أبدًا على المنحدرات"],"explanation":"اختر الغيار قبل التل أو المنعطف."},"113":{"q":"تتكوّن مسافة التوقف الكلية من:","options":["الكبح فقط","الإدراك + رد الفعل + الكبح","رد الفعل + الكبح","الإدراك + الكبح"],"explanation":"مسافة الإدراك زائد رد الفعل زائد الكبح."},"114":{"q":"عند سرعة 55 mph وفي ظروف جيدة، تبلغ مسافة التوقف الكلية نحو:","options":["140 قدمًا","220 قدمًا","320 قدمًا","420 قدمًا"],"explanation":"نحو 419 قدمًا عند سرعة 55 mph."},"115":{"q":"إذا ضاعفت سرعتك، تزداد مسافة الكبح بنحو:","options":["مرتين","3 مرات","4 مرات","10 مرات"],"explanation":"تزداد مسافة الكبح مع مربع السرعة — أي نحو 4 مرات."},"116":{"q":"على طريق مبلل يجب أن تخفّض سرعتك بنحو:","options":["العُشر","الثُلث","النصف","ثلاثة أرباع"],"explanation":"نحو الثُلث على الطرق المبللة (والنصف على الثلج المتراكم)."},"117":{"q":"مقارنةً بالشاحنة المحمّلة، فإن الشاحنة الفارغة عادةً:","options":["تتوقف أسرع","تحتاج مسافة توقف أطول","لا يمكن أن تنزلق","لديها قبضة أكبر"],"explanation":"الشاحنات الفارغة لديها قبضة أقل؛ وقد تنغلق العجلات وتنزلق."},"118":{"q":"إذا بدأت مركبتك بالانزلاق المائي (الهيدروبلانينج)، يجب أن:","options":["تكبح بقوة","تحرر دواسة الوقود","توجّه بحدة","تتسارع"],"explanation":"حرر دواسة الوقود واضغط القابض؛ ولا تكبح بقوة."},"119":{"q":"يحدث تلاشي الفرامل غالبًا بسبب:","options":["الطقس البارد","فرط السخونة من الاستخدام المفرط","انخفاض ضغط الإطارات","وجود هواء في الخطوط"],"explanation":"الحرارة الناتجة عن استخدام الفرامل أكثر من اللازم بدلًا من الكبح بالمحرك."},"120":{"q":"حدود السرعة المعلنة على المنعطفات مُحددة لأجل:","options":["الشاحنات المحمّلة","السيارات في الظروف الجيدة","الحافلات","الشاحنات الفارغة"],"explanation":"إنها مخصصة للسيارات؛ فأبطئ كثيرًا دونها عند قيادة شاحنة."},"121":{"q":"قاعدة مسافة المتابعة للمركبة الثقيلة هي:","options":["دائمًا ثانيتان ثابتتان","ثانية واحدة لكل 10 أقدام، + ثانية فوق 40 mph","نحو ثلاثة أطوال سيارة","100 قدم عند أي سرعة طريق"],"explanation":"ثانية واحدة لكل 10 أقدام من الطول؛ أضِف ثانية واحدة فوق 40 mph."},"122":{"q":"يجب أن تشير إلى الانعطاف:","options":["فقط إذا كانت السيارات قريبة","مبكرًا وباستمرار","بعد أن تبدأ الانعطاف","بيدك فقط"],"explanation":"أشِر مبكرًا واستمر في الإشارة طوال الانعطاف."},"123":{"q":"إذا كان أحد يلاصقك من الخلف، يجب أن:","options":["تزيد سرعتك","تفتح مسافة أمامك","تكبح فجأةً لتنبيهه","تبطئ في المسار الأيسر"],"explanation":"زِد المسافة أمامك كي تتمكن من الإبطاء تدريجيًا؛ وتجنب الحركات المفاجئة."},"124":{"q":"قبل الانعطاف يمينًا، يجب ألا:","options":["تنعطف ببطء","تنحرف يسارًا بعيدًا أولًا","تبقي المؤخرة قريبة من الرصيف","تتفقد مراياك"],"explanation":"الانحراف يسارًا يدعو غيرك لتجاوزك من اليمين؛ انعطف بشكل واسع عند إتمام الانعطاف."},"125":{"q":"ارتفاعات الخلوص المعلنة عند الجسور:","options":["دقيقة دائمًا","لا ينبغي الوثوق بها تمامًا","تنطبق على السيارات فقط","تزداد عند التحميل"],"explanation":"قد تقلل إعادة الرصف أو الثلج من الخلوص؛ وتسير الشاحنة الفارغة على ارتفاع أعلى."},"126":{"q":"المرايا المحدبة (المنحنية) تُظهر:","options":["صورة مكبّرة عن قرب","مساحة أوسع؛ وتبدو الأجسام أبعد","نفس ما تُظهره المرايا المسطّحة","المقصورة فقط"],"explanation":"رؤية أوسع، لكن الأجسام تبدو أصغر وأبعد."},"127":{"q":"'الخطر' على الطريق هو:","options":["سيارة مسرعة سريعة الحركة فقط","أي حالة أو مستخدم قد يشكّل خطراً","مجرد الطقس السيّئ","فقط حادث فعلي في الأمام"],"explanation":"أي شيء قد يتحول إلى حالة طارئة."},"128":{"q":"الاستجابة الصحيحة تجاه السائق العدواني هي:","options":["التسابق معه","الابتعاد عن طريقه","الفرملة المفاجئة أمامه لاختباره","حصره ومنعه من التحرك"],"explanation":"امنحه مساحة، وتجنّب التواصل البصري، ولا تشتبك معه."},"129":{"q":"إرسال الرسائل النصية أو حمل الهاتف أثناء قيادة مركبة تجارية هو:","options":["مسموح به دون 30 ميلاً في الساعة","ممنوع","لا بأس به في حركة المرور الخفيفة","ممنوع فقط على السائقين الجدد"],"explanation":"ممنوع؛ فهو يزيد كثيراً من خطر الحوادث وقد يؤدي إلى إسقاط أهليتك للقيادة."},"130":{"q":"عدم 'القيادة بسرعة تتجاوز مدى أضواءك الأمامية' ليلاً يعني:","options":["استخدام الأضواء المنخفضة فقط","التوقف ضمن المسافة المضاءة","اتباع مركبة أخرى","استخدام الأضواء العالية في الضباب"],"explanation":"قُد ببطء كافٍ بحيث تتمكن من التوقف ضمن المدى الذي تراه."},"131":{"q":"لتجنّب وهج الأضواء الأمامية القادمة، انظر:","options":["مباشرة نحوها","نحو الحافة اليمنى من مسارك","نحو لوحة القيادة أسفل","بعيداً نحو أسفل الطريق"],"explanation":"انظر نحو الحافة اليمنى/العلامات حتى تمر المركبة."},"132":{"q":"في الضباب الكثيف يجب أن تستخدم:","options":["أضواءك العالية الساطعة","الأضواء المنخفضة مع تخفيف السرعة","أضواء التحذير الوامضة فقط","عدم استخدام أي أضواء"],"explanation":"الأضواء العالية تنعكس إليك؛ استخدم الأضواء المنخفضة وخفّف السرعة."},"133":{"q":"في الشتاء، أي مما يلي يتجمد عادةً أولاً؟","options":["الطريق المكشوف","الجسور والممرات العلوية","التلال","الأنفاق"],"explanation":"الجسور تتجمد قبل الطريق."},"134":{"q":"يبدو الطريق مبللاً لكن الإطارات لا تتطاير منها رذاذاً في البرد. هذا على الأرجح:","options":["رصيف يجف","جليد أسود","إسفلت طازج","زجاج أمامي متسخ"],"explanation":"جليد أسود — خفّف السرعة، ولا توجيه أو فرملة مفاجئة."},"135":{"q":"في الطقس الحار جداً يجب أن تتفقد بشكل خاص:","options":["ضغط الإطارات","البوق","الراديو","تظليل النوافذ"],"explanation":"الحرارة ترفع ضغط الإطارات؛ تفقّد الإطارات وسائل التبريد."},"136":{"q":"على منحدر طويل، يتم التحكم بالسرعة أساساً عن طريق:","options":["الضغط المستمر على المكابح","استخدام ترس منخفض وكبح المحرك","فرملة الانتظار فقط","الانزلاق بالحياد"],"explanation":"كبح المحرك بترس منخفض؛ والمكابح تكمّل ذلك فقط."},"137":{"q":"يجب استخدام منحدر هروب الشاحنات المنفلتة عندما:","options":["تريد أخذ استراحة","تتعطل مكابحك على منحدر","تتجاوز السرعة قليلاً","تكون حركة المرور كثيفة"],"explanation":"استخدمه إذا تعطلت مكابحك ولم تتمكن من التوقف."},"138":{"q":"إذا انفجر إطار أمامي، فإن أول إجراء تقوم به هو:","options":["الفرملة بقوة فوراً","الإمساك بالمقود مع تجنّب الفرملة","التوجيه بحدّة جانباً","نقل الناقل إلى الحياد"],"explanation":"أمسك بالمقود بإحكام، وابتعد عن الفرملة، ودعها تبطئ، ثم اخرج عن الطريق بلطف."},"139":{"q":"إذا تعطلت مكابحك الهيدروليكية، فحاول أولاً:","options":["ضخّ دواسة المكابح","إيقاف المحرك","سحب مقبض المقطورة","التوجيه نحو حركة المرور"],"explanation":"اضخّ الدواسة لبناء الضغط، ثم خفّض الترس واستخدم فرملة الانتظار."},"140":{"q":"للتعافي من انزلاق العجلات الدافعة (الخلفية)، يجب أن:","options":["تفرمل بقوة أكبر","تتوقف عن التسارع وتوجّه المقود","تقفل جميع المكابح","تزيد السرعة للخروج من الانزلاق"],"explanation":"ارفع قدمك عن دواسة الوقود ووجّه نحو حيث تريد الذهاب."},"141":{"q":"عادةً ما يكون سبب انزلاق العجلات الأمامية هو:","options":["الفرملة بلطف مفرط","القيادة بسرعة تفوق ما تسمح به الظروف","ثقل زائد في الخلف","كبح المحرك"],"explanation":"القيادة بسرعة مفرطة (أو إطارات أمامية متآكلة/ناقصة الهواء)؛ خفّف السرعة."},"142":{"q":"الفائدة الرئيسية لنظام منع انغلاق المكابح (ABS) عند التوقف القوي هي:","options":["توقف أقصر في كل مرة","الحفاظ على التحكم بالتوجيه","عدم الحاجة لمسافة أمان عند الاتباع","التوجيه التلقائي"],"explanation":"يمنع انغلاق العجلات حتى تتمكن من التوجيه؛ وليس بالضرورة توقفاً أقصر."},"143":{"q":"عند وصولك أولاً إلى موقع حادث، يجب أن:","options":["تنقل المصابين","تؤمّن المنطقة بأجهزة التحذير","تغادر للبحث عن هاتف","تدفع الحطام جانباً بسرعة"],"explanation":"امنع وقوع حادث آخر أولاً؛ وعادةً لا تحرّك المصابين."},"144":{"q":"عند حدوث حريق في المحرك يجب أن:","options":["تفتح غطاء المحرك على اتساعه","تُبقي الغطاء مغلقاً إن أمكن","تضيف المزيد من وقود الديزل","تقود أسرع نحو الورشة"],"explanation":"فتح الغطاء يضيف أكسجيناً؛ أوقف المحرك."},"145":{"q":"حدّ نسبة الكحول في الدم لقيادة مركبة تجارية هو:","options":["0.10%","0.08%","0.04%","0.02%"],"explanation":"نسبة 0.04% أو أكثر تُعد مخالفة لسائقي المركبات التجارية."},"146":{"q":"ما الذي يُفيق شارب الكحول فعلاً؟","options":["القهوة","الاستحمام البارد","الهواء الطلق","الوقت"],"explanation":"الوقت وحده هو ما يُزيل الكحول من الجسم."},"147":{"q":"السائق الذي يُكتشف لديه كحول بنسبة أقل من 0.04% سيكون:","options":["يُحذَّر فقط","خارج الخدمة لمدة 24 ساعة","مسقَطة أهليته مدى الحياة","يُغرَّم ويُطلق سراحه"],"explanation":"خارج الخدمة 24 ساعة؛ ونسبة 0.04% أو أكثر تُعد جريمة قيادة تحت تأثير الكحول."},"148":{"q":"يجب أن تتفقد حمولتك خلال أول:","options":["10 أميال","50 ميلاً","100 ميل","150 ميلاً"],"explanation":"خلال 50 ميلاً، ثم كل 150 ميلاً أو كل 3 ساعات."},"149":{"q":"القاعدة الدنيا لربط الحمولة هي:","options":["رباط واحد فقط إجمالاً","رباط لكل 10 أقدام، رباطان على الأقل","رباط لكل 25 قدماً","فقط للحمولات التي تتجاوز 20 قدماً"],"explanation":"رباط واحد على الأقل لكل 10 أقدام، وبحد أدنى رباطان."},"150":{"q":"المركز المرتفع للثقل يجعل المركبة:","options":["أكثر استقراراً","أكثر عرضة للانقلاب","أسهل في التوقف","أفضل في المنعطفات"],"explanation":"أكثر ثِقلاً في الأعلى؛ احمل الحمولة الثقيلة في الأسفل."},"151":{"q":"رخصة القيادة التجارية من الفئة (أ) في تكساس مخصّصة للمركبات المركّبة التي يبلغ وزنها الإجمالي المركّب (GCWR):","options":["16,001 رطل أو أكثر إجمالاً","26,001 رطل أو أكثر مع قطر حمولة تزيد عن 10,000 رطل","10,000 رطل أو أكثر إجمالاً","40,000 رطل أو أكثر إجمالاً"],"explanation":"الوزن الإجمالي المركّب 26,001 رطل أو أكثر، حيث تزيد الوحدة المقطورة عن 10,000 رطل."},"152":{"q":"تحصل على قيد يمنعك من قيادة المركبات ذات الفرامل الهوائية إذا:","options":["نجحت في اختبار الفرامل الهوائية","أجريت الاختبار في مركبة بدون فرامل هوائية","قدت في الليل","كان سجلك نظيفاً"],"explanation":"الرسوب في اختبار الفرامل الهوائية أو تخطّيه (أو الاختبار بدونها) يفرض عليك هذا القيد."},"153":{"q":"عند مزلقان السكة الحديدية، يجب على الحافلات التي تحمل ركاباً والمركبات التي تحمل لافتات مواد خطرة أن:","options":["تبطئ فقط","تتوقف دائماً","تزيد سرعتها","تتجاهله"],"explanation":"يجب أن تتوقف، حتى عند عدم وجود قطار مرئي."},"154":{"q":"تستغرق الشاحنة المقطورة النموذجية لاجتياز سكة مفردة نحو:","options":["3 ثوانٍ","14 ثانية على الأقل","ثانية واحدة","الوقت لا يهم"],"explanation":"14 ثانية على الأقل (أكثر من 15 ثانية لسكة مزدوجة)."},"155":{"q":"في الإضاءة الخافتة أو المطر، شغّل المصابيح الأمامية أساساً لكي:","options":["توفّر الوقود","يراك الآخرون","تُدفّئ المحرك","تشحن البطارية"],"explanation":"المصابيح الأمامية (وليس مجرد أضواء التحديد) تجعلك مرئياً."},"156":{"q":"لوح الرأس (\"رف الصداع\") موجود من أجل:","options":["تثبيت الإطار الاحتياطي في مكانه","منع الحمولة من الانزلاق نحو المقصورة","توفير قليل من الوقود","تمييز حمولة عريضة جداً"],"explanation":"يحميك من الحمولة التي تنزلق إلى الأمام."},"157":{"q":"أيّ من حالات الإطارات يُعدّ عيباً؟","options":["عمق مداس يزيد عن 4/32 من البوصة في الأمام","تلامس الإطارات المزدوجة","تطابق مقاسات الإطارات","الضغط المناسب للهواء"],"explanation":"يجب ألا تتلامس الإطارات المزدوجة، ولا تخلط بين الإطارات الشعاعية والإطارات القطرية."},"158":{"q":"أيّ مما يلي علامة على أنك متعب جداً للقيادة؟","options":["الانحراف داخل مسارك","ثقل الجفون","عدم تذكّر الأميال القليلة الماضية","كل ما سبق"],"explanation":"كلها علامات خطر على الإرهاق؛ توقّف واسترح."},"159":{"q":"أيّ مما يلي ليس من معدات الطوارئ المطلوبة؟","options":["طفّاية حريق","منصهرات احتياطية (لا قواطع)","ثلاثة مثلثات تحذيرية","إطار احتياطي"],"explanation":"الإطار الاحتياطي غير مطلوب؛ أما البقية فمطلوبة."},"160":{"q":"أيّ مما يلي ليس طريقة صحيحة للتعامل مع الانزلاق؟","options":["التوقف عن الفرملة","التوجيه نحو المكان الذي تريد الذهاب إليه","الاستمرار في التسارع","التوجيه المعاكس عند استقامة المركبة"],"explanation":"لا تستمر في التسارع؛ خفّف الضغط ووجّه المركبة."},"161":{"q":"لماذا ينبغي أن تفحص المركبة قبل الرحلة؟","options":["لاكتشاف عيوب السلامة","لأن القانون يقتضي ذلك","لمنع الأعطال","كل ما سبق"],"explanation":"الأسباب الثلاثة جميعاً: السلامة، والواجب القانوني، وتجنّب الأعطال."},"162":{"q":"التوقف ليس دائماً الإجراء الأكثر أماناً لأن:","options":["إنه مجرد إضاعة لوقتك","التوجيه بعيداً قد يكون أسرع","الفرامل سترتفع حرارتها","إنه مخالف للقانون"],"explanation":"غالباً ما يمكنك التوجيه لتفادي خطر أسرع مما يمكنك التوقف."},"163":{"q":"ما الترتيب الصحيح لأجزاء مسافة التوقف؟","options":["الفرملة، ردّ الفعل، الإدراك","الإدراك، ردّ الفعل، الفرملة","ردّ الفعل، الفرملة، الإدراك","الإدراك، الفرملة، ردّ الفعل"],"explanation":"الإدراك، ثم ردّ الفعل، ثم الفرملة."},"164":{"q":"لتحذير السائقين خلفك بأنك تبطئ كثيراً، ينبغي أن:","options":["لا تفعل شيئاً على الإطلاق","تنقر على الفرامل لإيماض الأضواء","تشغّل الأضواء العالية","تطلق البوق مراراً"],"explanation":"انقر على الفرامل للإيماض مبكراً، أو استخدم أضواء التحذير إذا كنت بطيئاً جداً."},"165":{"q":"حدّ الكحول في الدم لرخصة القيادة التجارية أثناء قيادة مركبة تجارية هو:","options":["0.08%","0.04%","0.10%","0.02%"],"explanation":"يُعدّ سائق الرخصة التجارية مخموراً قانونياً عند نسبة 0.04% من الكحول في الدم، أي نصف الحد المسموح لسائقي السيارات."},"166":{"q":"إذا تعطّلت فراملك على منحدر طويل، فينبغي أن:","options":["تضغط بقوة أكبر وتأمل الأفضل","تستخدم منحدر الهروب إن وُجد","تنقل إلى الوضع المحايد","تفتح الباب وتقفز"],"explanation":"منحدرات الهروب للمركبات الجامحة مصمّمة لإيقاف المركبات التي تعطّلت فراملها."},"167":{"q":"يكون الانزلاق المائي أكثر احتمالاً عندما:","options":["يكون سطح الطريق جافاً","يوجد ماء وتقود بسرعة كبيرة","تقود ببطء شديد","تكون الإطارات جديدة تماماً"],"explanation":"يحدث الانزلاق المائي على الطرق المبتلّة عند السرعات العالية؛ خفّف سرعتك."},"168":{"q":"للتحقق من ضغط الإطارات بشكل صحيح، ينبغي أن:","options":["تركل الإطار بقوة","تستخدم مقياساً والإطارات باردة","تنظر إلى الإطار فقط","تضغط عليه بيدك"],"explanation":"استخدم مقياس ضغط وافحص الإطارات وهي باردة للحصول على قراءة دقيقة."},"169":{"q":"تشير \"المنطقة المعدومة\" (No-Zone) إلى:","options":["منطقة استراحة على الطريق السريع","النقاط العمياء الكبيرة للشاحنة","مسار للرسوم فقط","رصيف ممنوع الوقوف عليه"],"explanation":"المنطقة المعدومة هي المنطقة المحيطة بالشاحنة حيث تختفي المركبات الأخرى عن النظر."},"170":{"q":"عند الرجوع للخلف، الممارسة الأكثر أماناً هي أن:","options":["ترجع نحو الجانب الأيمن الأعمى","ترجع نحو جانبك الأيسر وتستعين بمساعد","ترجع بأسرع ما يمكنك","تتجاهل استخدام مراياك"],"explanation":"ارجع نحو جانب السائق إن أمكن واستعن بمساعد أو مراقب."},"171":{"q":"أحياناً تكون أفضل طريقة لتفادي الاصطدام هي أن:","options":["تفرمل دائماً بأقصى قوة ممكنة","توجّه المركبة حول الخطر","تغمض عينيك وتتحفّز للصدمة","تندفع مباشرة من خلاله"],"explanation":"غالباً ما يمكنك التوجيه حول العائق في مسافة أقصر مما يتطلبه التوقف."},"172":{"q":"السائق الآمن يعطي إشارات الانعطاف:","options":["مباشرة بعد الانعطاف","قبل الانعطاف بوقت كافٍ","في الليل فقط","على الطرق السريعة فقط"],"explanation":"أعطِ الإشارة مبكراً واستمر فيها ليعرف الآخرون نواياك."},"173":{"q":"على طريق زلق، ينبغي عادةً أن يكون مكبح المحرك أو المُبطئ:","options":["مشغّلاً بالكامل","مُطفأ","مستخدماً بأقصى درجة","مُزالاً تماماً"],"explanation":"يمكن أن تتسبب المُبطئات في انزلاق العجلات الدافعة على الطرق الزلقة، لذا أطفئها."},"174":{"q":"عند صعود منحدر طويل وشديد الانحدار، ينبغي أن:","options":["تبقى في الترس الفائق (overdrive)","تنقل إلى ترس أدنى للحصول على القوة","تنزلق في الوضع المحايد","تطفئ المحرك"],"explanation":"على المنحدر الصاعد الشديد، اختر ترساً أدنى للحفاظ على قوة المحرك وسرعة ثابتة."},"175":{"q":"إذا ضاعفت سرعتك، فإن مسافة الفرملة تقريباً:","options":["تبقى كما هي تقريباً","تزداد نحو أربعة أضعاف","تتضاعف فقط، لا أكثر","تُختزل إلى النصف تقريباً"],"explanation":"تزداد مسافة الفرملة بمربّع السرعة، أي نحو أربعة أضعاف عند مضاعفة السرعة."},"176":{"q":"العلاج الأكيد الوحيد للإرهاق أثناء القيادة هو:","options":["فتح النافذة على مصراعيها","التوقف والراحة أو النوم","رفع صوت الموسيقى","شرب القهوة ومواصلة القيادة"],"explanation":"الراحة أو النوم هما العلاج الحقيقي الوحيد للإرهاق؛ توقف في مكان آمن جانب الطريق."},"177":{"q":"إرسال الرسائل النصية أثناء قيادة مركبة تجارية هو:","options":["مسموح عند الإشارات الحمراء","ممنوع","مطلوب بموجب القانون","لا بأس به على الطريق السريع"],"explanation":"يُمنع على سائقي المركبات التجارية إرسال الرسائل النصية واستخدام الهاتف المحمول باليد."},"178":{"q":"في منطقة الأشغال يجب عليك:","options":["زيادة السرعة لتجاوزها بسرعة","تخفيف السرعة والانتباه للعمال","تغيير المسارات بسرعة","القيادة عن قرب لتوفير الوقت"],"explanation":"خفّف السرعة، واحتفظ بمسافة، وانتبه للعمال؛ غالبًا ما تتضاعف الغرامات."},"179":{"q":"الحمولة ذات مركز الثقل المرتفع تجعل المركبة:","options":["أكثر استقرارًا وثباتًا","أكثر عرضة للانقلاب","أسرع بشكل ملحوظ","أخف بكثير"],"explanation":"يرفع مركز الثقل المرتفع خطر الانقلاب؛ ضع الأشياء الثقيلة في الأسفل."},"180":{"q":"يجب أن يكون الحد الإجمالي لحمولة العمل لأربطة التثبيت على الأقل:","options":["ربع وزن الحمولة","نصف وزن الحمولة","ضعف وزن الحمولة","مساويًا لوزن الشاحنة"],"explanation":"يجب أن يكون الحد الإجمالي لحمولة عمل أربطة التثبيت على الأقل نصف وزن الحمولة المثبَّتة."},"181":{"q":"عند الانعطاف يمينًا، يجب عليك:","options":["الانحراف يسارًا بشكل واسع أولًا","البقاء على اليمين وعدم الانحراف الواسع","زيادة السرعة أثناءه","تجاهل إشارة الانعطاف"],"explanation":"لا تنحرف يسارًا قبل الانعطاف يمينًا؛ فذلك يتيح للآخرين محاولة التجاوز من اليمين."},"182":{"q":"سرعات المنعطفات المعلن عنها محددة من أجل:","options":["الشاحنات الثقيلة المحمَّلة","السيارات في الظروف الجيدة","الطرق الفارغة تمامًا","القيادة الليلية فقط"],"explanation":"سرعات المنعطفات المعلن عنها مخصصة للسيارات؛ على الشاحنات الثقيلة أن تسير بسرعة أبطأ."},"183":{"q":"يحدث ضعف الفرامل على المنحدر الطويل بسبب:","options":["فرامل باردة وجديدة","فرامل مفرطة السخونة والاستخدام","أحذية فرامل جديدة تمامًا","حمولة خفيفة جدًا"],"explanation":"الضغط المستمر على الفرامل يفرط في تسخينها حتى تضعف؛ استخدم غيارًا منخفضًا وكبح المحرك."},"184":{"q":"تساعدك الفرامل المانعة للانغلاق (ABS) بشكل أساسي على:","options":["التوقف دائمًا في مسافة أقصر","الحفاظ على التحكم في التوجيه أثناء التوقف الحاد","توفير الكثير من الوقود","تخطي فحص الفرامل"],"explanation":"تمنع الـABS انغلاق العجلات حتى تتمكن من التوجيه؛ لكنها لا تقصّر مسافة التوقف بالضرورة."},"185":{"q":"مقارنة بالشاحنات المحمَّلة، فإن الشاحنات الفارغة:","options":["تتوقف دائمًا بشكل أسرع","قد تستغرق وقتًا أطول للتوقف","لا يمكن أن تنزلق أبدًا","تتمتع بتماسك أكبر بكثير"],"explanation":"تتمتع الشاحنات الفارغة بتماسك أقل وقد ترتد، مما يطيل مسافة التوقف."},"186":{"q":"يجب عليك تشغيل المصابيح الأمامية:","options":["فقط في منتصف الليل تقريبًا","عند الغسق وفي المطر أو الضباب أو الإضاءة المنخفضة","أبدًا أثناء هطول المطر","فقط على الطريق السريع"],"explanation":"استخدم المصابيح الأمامية في الإضاءة المنخفضة والطقس السيئ حتى يراك الآخرون."},"187":{"q":"المرايا المحدبة (المنحنية):","options":["تجعل الأشياء تبدو أقرب بكثير","تُظهر مساحة أكبر لكن تجعل الأشياء تبدو أبعد","لا تُظهر شيئًا مفيدًا على الإطلاق","غير مسموح بها على الشاحنات الكبيرة"],"explanation":"تُظهر المرايا المحدبة مساحة أوسع، لكن الأشياء تبدو أصغر وأبعد مما هي عليه فعلًا."},"188":{"q":"أول ما يجب فعله عند رصد خطر في الأمام هو:","options":["تجاهله ومواصلة القيادة","الاستعداد للتفاعل والتكيف","زيادة السرعة لتجاوزه","الاكتفاء بإطلاق البوق"],"explanation":"رصد الخطر مبكرًا يمنحك الوقت للتخطيط والتصرف قبل وقوع حالة طارئة."},"189":{"q":"بماذا تساوي مسافة التوقف الإجمالية؟","options":["مسافة الإدراك + مسافة رد الفعل + مسافة الكبح","مسافة رد الفعل + مسافة التوجيه + مسافة الكبح","مسافة الإدراك + مسافة الكبح + مسافة الانزلاق","مسافة رد الفعل + مسافة الإدراك + مسافة التباطؤ"],"explanation":"مسافة التوقف الإجمالية هي مسافة الإدراك زائد مسافة رد الفعل زائد مسافة الكبح."},"190":{"q":"عند سرعة 55 ميلًا في الساعة في الظروف الجيدة، تعادل مسافة التوقف الإجمالية طول ماذا؟","options":["ملعب كرة قدم بما في ذلك منطقتا الهدف","مربع سكني في المدينة","موقف سيارات قياسي","امتداد جسر من أربعة مسارات"],"explanation":"عند سرعة 55 ميلًا في الساعة، تعادل مسافة التوقف الإجمالية تقريبًا طول ملعب كرة قدم بما في ذلك منطقتا الهدف."},"191":{"q":"عند سرعة 55 ميلًا في الساعة في الظروف الجيدة، كم ثانية تقريبًا تستغرق مسافة التوقف الإجمالية؟","options":["6 ثوانٍ","ثانيتان","10 ثوانٍ","14 ثانية"],"explanation":"يستغرق التوقف من سرعة 55 ميلًا في الساعة في الظروف الجيدة نحو 6 ثوانٍ."},"192":{"q":"كم تستغرق مسافة رد الفعل تقريبًا عند سرعة 55 ميلًا في الساعة؟","options":["نحو ثلاثة أرباع الثانية","نحو ثلاث ثوانٍ","نحو ثانية ونصف","نحو خمس ثوانٍ"],"explanation":"مسافة رد الفعل عند سرعة 55 ميلًا في الساعة هي نحو ثلاثة أرباع الثانية."},"193":{"q":"النظر من 12 إلى 15 ثانية في الأمام عند سرعة الطريق السريع يعادل أي مسافة تقريبًا؟","options":["ربع ميل","نصف ميل","ميل واحد","عُشر ميل"],"explanation":"عند سرعة الطريق السريع، يعادل النظر من 12 إلى 15 ثانية في الأمام نحو ربع ميل."},"194":{"q":"كم مسافة إضافية للمتابعة يجب إضافتها عند السير بسرعة تزيد عن 40 ميلًا في الساعة؟","options":["ثانية واحدة","3 ثوانٍ","5 ثوانٍ","ثانيتان"],"explanation":"أضف ثانية واحدة إلى مسافة المتابعة عند تجاوز سرعة 40 ميلًا في الساعة."},"195":{"q":"خلال كم ميل يجب عليك فحص حمولتك وتثبيتها لأول مرة؟","options":["50 ميلًا","150 ميلًا","100 ميل","25 ميلًا"],"explanation":"يجب فحص الحمولة وتثبيتها خلال أول 50 ميلًا."},"196":{"q":"بالنسبة لقطعة حمولة طولها 30 قدمًا، كم رباط تثبيت مطلوب كحد أدنى؟","options":["3 أربطة تثبيت","رباط تثبيت واحد","5 أربطة تثبيت","رباطا تثبيت"],"explanation":"بحد أدنى رباط تثبيت واحد لكل 10 أقدام، تحتاج قطعة طولها 30 قدمًا إلى 3 أربطة على الأقل."},"197":{"q":"يوضع أقرب المثلثات التحذيرية الثلاثة على بُعد نحو كم من المركبة؟","options":["10 أقدام","100 قدم","200 قدم","50 قدمًا"],"explanation":"يوضع أقرب مثلث تحذيري على بُعد نحو 10 أقدام من المركبة."},"198":{"q":"خلال كم دقيقة يجب وضع المثلثات التحذيرية بعد التوقف؟","options":["10 دقائق","30 دقيقة","5 دقائق","20 دقيقة"],"explanation":"يجب وضع المثلثات خلال 10 دقائق من التوقف."},"199":{"q":"على المنحدر الطويل، ما الدور الذي يُفترض أن تؤديه الفرامل؟","options":["مكمّل لكبح المحرك والغيار","الطريقة الوحيدة للتباطؤ","بديل عن الغيار المنخفض","وسيلة لتسريع تغيير الغيارات"],"explanation":"على المنحدر، تكون الفرامل مكمّلة لكبح المحرك والغيار."},"200":{"q":"تعتمد السرعة الآمنة على المنحدر الطويل على أي عامل؟","options":["الوزن الإجمالي للمركبة","لون الحمولة","عمر الفرامل","طول السائق"],"explanation":"الوزن الإجمالي هو أحد العوامل التي تحدد السرعة الآمنة على المنحدر."},"201":{"q":"في حالة طوارئ بدون نظام ABS، أي طرق الكبح تساعدك على تجنب الانزلاق؟","options":["الكبح المتحكم به أو الكبح المتقطع","قفل العجلات بالكامل","ضخ فرامل الوقوف","الانسياب في الوضع المحايد"],"explanation":"الكبح المتحكم به أو الكبح المتقطع يمنع العجلات من القفل في حالة طوارئ بدون نظام ABS."},"202":{"q":"مع نظام ABS في حالة الطوارئ، كيف يجب أن تكبح وماذا يجب أن تفعل أيضاً؟","options":["اكبح بقوة ووجّه المركبة","اضخ الدواسة وانسب","اكبح بخفة وحافظ على السير مستقيماً","حرّر الفرامل وأعد الضغط عليها مراراً"],"explanation":"مع نظام ABS تكبح بقوة وتوجّه المركبة."},"203":{"q":"قبل عبور السكك الحديدية، يجب ألا تنطلق ما لم تتمكن من اجتيازها بطول مركبتك زائد حوالي كم قدم؟","options":["15 قدماً","30 قدماً","50 قدماً","5 أقدام"],"explanation":"تحتاج إلى طول مركبتك زائد حوالي 15 قدماً لاجتياز السكك بالكامل."},"204":{"q":"إلى أي مدى تقريباً تضيء المصابيح الأمامية العالية الطريق؟","options":["حوالي 350 إلى 500 قدم","حوالي 100 إلى 150 قدماً","حوالي 600 إلى 750 قدماً","حوالي 250 إلى 300 قدم"],"explanation":"تضيء المصابيح العالية حوالي 350 إلى 500 قدم."},"205":{"q":"ضمن كم قدم من مركبة أخرى يجب أن تخفّض مصابيحك العالية؟","options":["500 قدم","250 قدماً","1,000 قدم","100 قدم"],"explanation":"خفّض المصابيح العالية ضمن 500 قدم أمام مركبة أخرى أو خلفها."},"206":{"q":"كيف يبدو الجليد الأسود على الطريق؟","options":["طبقة رقيقة شفافة تجعل الطريق يبدو رطباً","قشرة صقيعية بيضاء","غشاء رمادي مسحوقي","رقعة زرقاء لامعة"],"explanation":"الجليد الأسود طبقة رقيقة شفافة تجعل الطريق يبدو رطباً فحسب."},"207":{"q":"في الطقس الحار، ما الذي يصعد من سطح الطريق ويجعله زلقاً؟","options":["نزيف القار","الحصى المفكك","ملح الطرق","زيت المحرك"],"explanation":"نزيف القار في الطقس الحار يجعل سطح الطريق زلقاً."},"208":{"q":"إلى جانب ضغط الإطارات، ما الذي يجب أن تراقبه عن كثب في الطقس الحار؟","options":["سائل التبريد ودرجة حرارة المحرك","مستوى سائل المساحات","لمبات أضواء الفرامل","محاذاة المرايا"],"explanation":"في الطقس الحار راقب سائل التبريد ودرجة حرارة المحرك."}},"learn-special":{"0":{"q":"ما هو أقصى عرض مسموح به بدون تصريح خاص؟","options":["102 بوصة","96 بوصة","108 بوصات","120 بوصة"],"explanation":"بدون تصريح خاص، أقصى عرض قانوني للمركبة هو 102 بوصة، أي 8 أقدام و6 بوصات."},"1":{"q":"ما هو أقصى ارتفاع مسموح به بدون تصريح خاص؟","options":["12 قدماً","14 قدماً","16 قدماً","18 قدماً"],"explanation":"أقصى ارتفاع مسموح به بدون تصريح خاص هو 14 قدماً."},"2":{"q":"ما هو أقصى وزن إجمالي مسموح به بدون تصريح خاص؟","options":["20,000 رطل","34,000 رطل","80,000 رطل","26,001 رطل"],"explanation":"بدون تصريح خاص، أقصى وزن إجمالي للمركبة زائد الحمولة هو 80,000 رطل."},"3":{"q":"ما هو حد وزن المحور المفرد بدون تصريح خاص؟","options":["14,000 رطل","34,000 رطل","80,000 رطل","20,000 رطل"],"explanation":"بدون تصريح خاص، حد وزن المحور المفرد هو 20,000 رطل."},"4":{"q":"ما هو حد وزن المحور المزدوج؟","options":["34,000 رطل","20,000 رطل","40,000 رطل","80,000 رطل"],"explanation":"بدون تصريح خاص، حد وزن المحور المزدوج هو 34,000 رطل."},"5":{"q":"ما هو أقصى عدد من المركبات المسموح به في تركيبة واحدة؟","options":["2","3","4","5"],"explanation":"أقصى عدد من المركبات في تركيبة واحدة هو 3، مثل قاطرة شاحنة زائد مقطورتين."},"6":{"q":"ما الذي يجب أن يميّز حمولة تمتد أكثر من 4 أقدام خلف المؤخرة ليلاً؟","options":["علم برتقالي","عاكس كهرماني","ضوء أحمر","مصباح أصفر"],"explanation":"ليلاً أو في ضعف الرؤية، يجب أن تُظهر الحمولة الممتدة أكثر من 4 أقدام خلف المؤخرة ضوءاً أحمر."},"7":{"q":"تُشترط رخصة CDL لقيادة مركبة مفردة بوزن إجمالي مصرّح به (GVWR) يبلغ كم رطل أو أكثر؟","options":["10,000 رطل","16,000 رطل","20,000 رطل","26,001 رطل"],"explanation":"تُشترط رخصة CDL لقيادة مركبة مفردة بوزن إجمالي مصرّح به (GVWR) يبلغ 26,001 رطل أو أكثر."},"8":{"q":"تُشترط رخصة CDL لتركيبة يتجاوز وزنها الإجمالي المصرّح به (GCWR) 26,001 رطل وتقطر وحدة تتجاوز كم رطل؟","options":["10,000 رطل","20,000 رطل","26,001 رطل","34,000 رطل"],"explanation":"تُشترط رخصة CDL لتركيبة يتجاوز وزنها الإجمالي المصرّح به (GCWR) 26,001 رطل وتقطر وحدة تتجاوز 10,000 رطل."},"9":{"q":"تُشترط رخصة CDL لأي مركبة مصمّمة لنقل كم راكب، بما في ذلك السائق؟","options":["10 أو أكثر","16 أو أكثر","21 أو أكثر","26 أو أكثر"],"explanation":"تُشترط رخصة CDL لأي مركبة مصمّمة لنقل 16 راكباً أو أكثر، بما في ذلك السائق."},"10":{"q":"ما هو الحد الأدنى للسن لقيادة مركبة تجارية داخل ولاية تكساس؟","options":["16","17","18","21"],"explanation":"الحد الأدنى للسن لقيادة مركبة تجارية داخل ولاية تكساس فقط هو 18."},"11":{"q":"ما هو الحد الأدنى للسن لقيادة مركبة تجارية في التجارة بين الولايات؟","options":["16","18","19","21"],"explanation":"الحد الأدنى للسن هو 21 للقيادة بين الولايات أو المواد الخطرة أو نقل الركاب بين الولايات."},"12":{"q":"بالنسبة لرخصة CDL من الفئة A، يجب أن يزيد وزن الوحدة المقطورة عن كم رطل؟","options":["10,000 رطل","20,000 رطل","26,001 رطل","34,000 رطل"],"explanation":"الفئة A هي تركيبة بوزن إجمالي مصرّح به (GCWR) يبلغ 26,001 رطل أو أكثر مع وحدة مقطورة تتجاوز 10,000 رطل."},"13":{"q":"ما هو الحد الأدنى لوزن المركبة المفردة الذي يتطلب رخصة CDL من الفئة B؟","options":["20,000 رطل","26,001 رطل","10,000 رطل","80,000 رطل"],"explanation":"الفئة B هي مركبة مفردة بوزن 26,001 رطل أو أكثر، أو تقطر 10,000 رطل أو أقل."},"14":{"q":"أي فئة من رخص CDL مخصصة للمركبات الأصغر المستخدمة لنقل المواد الخطرة أو 16 راكباً أو أكثر؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"الفئة C تشمل المركبات الأصغر المستخدمة لنقل المواد الخطرة أو حمل 16 راكباً أو أكثر."},"15":{"q":"ما هو حد الكحول في الدم لسائق رخصة CDL؟","options":["0.08%","0.10%","0.02%","0.04%"],"explanation":"حد الكحول في الدم لرخصة CDL هو 0.04%، أي نصف حد سائق السيارة البالغ 0.08%."},"16":{"q":"لا يجوز لسائق رخصة CDL القيادة خلال كم ساعة من تناول الكحول؟","options":["4 ساعات","2 ساعة","6 ساعات","8 ساعات"],"explanation":"لا يجوز لسائق رخصة CDL القيادة خلال 4 ساعات من الشرب، ولا يجوز أن يكون لديه أي كحول قابل للكشف أثناء العمل."},"17":{"q":"بموجب الموافقة الضمنية، ماذا يحدث إذا رفضت إجراء فحص كيميائي؟","options":["تحذير كتابي","تعليق الرخصة","غرامة صغيرة","حجز المركبة"],"explanation":"القيادة في تكساس تعني أنك توافق على الفحص الكيميائي، ورفض الفحص يؤدي إلى تعليق الرخصة."},"18":{"q":"كم تبلغ مدة سحب رخصة القيادة التجارية (CDL) عند ارتكاب أول مخالفة كبرى؟","options":["60 يوماً","120 يوماً","سنة واحدة","3 سنوات"],"explanation":"أول مخالفة كبرى، مثل القيادة تحت تأثير الكحول أو رفض الفحص، تؤدي إلى سحب رخصة القيادة التجارية لمدة سنة واحدة."},"19":{"q":"كم تبلغ مدة سحب رخصة القيادة التجارية (CDL) عند ارتكاب أول مخالفة كبرى أثناء نقل مواد خطرة (HazMat) تحمل لافتات تحذيرية؟","options":["سنة واحدة","60 يوماً","120 يوماً","3 سنوات"],"explanation":"ارتكاب أول مخالفة كبرى أثناء نقل مواد خطرة (HazMat) تحمل لافتات تحذيرية يؤدي إلى سحب رخصة القيادة التجارية لمدة 3 سنوات."},"20":{"q":"كم تبلغ مدة سحب الرخصة عند ارتكاب مخالفة كبرى ثانية؟","options":["مدى الحياة","3 سنوات","سنة واحدة","120 يوماً"],"explanation":"ارتكاب مخالفة كبرى ثانية يؤدي إلى سحب رخصة القيادة التجارية مدى الحياة."},"21":{"q":"كم تبلغ مدة سحب الرخصة عند ارتكاب مخالفتين مروريتين خطيرتين خلال 3 سنوات في مركبة تجارية (CMV)؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"ارتكاب مخالفتين مروريتين خطيرتين خلال 3 سنوات في مركبة تجارية (CMV) يؤدي إلى سحب الرخصة لمدة 60 يوماً."},"22":{"q":"كم تبلغ مدة سحب رخصة القيادة التجارية (CDL) عند ارتكاب ثلاث مخالفات مرورية خطيرة خلال 3 سنوات؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"ارتكاب ثلاث مخالفات مرورية خطيرة خلال 3 سنوات يؤدي إلى سحب رخصة القيادة التجارية لمدة 120 يوماً."},"23":{"q":"بعد التوقف على الطريق، كم عدد المثلثات التحذيرية التي يجب أن تضعها؟","options":["مثلثان","4 مثلثات","5 مثلثات","3 مثلثات"],"explanation":"بعد التوقف على الطريق، شغّل أضواء التحذير المتقطعة وضع 3 مثلثات تحذيرية."},"24":{"q":"على طريق ذي مسارين باتجاهين، على أي مسافة أمام المركبة تضع المثلث التحذيري؟","options":["100 قدم","10 أقدام","200 قدم","50 قدماً"],"explanation":"على طريق ذي مسارين باتجاهين، ضع المثلث التحذيري على بعد نحو 100 قدم أمام المركبة."},"25":{"q":"على طريق باتجاه واحد أو طريق سريع مقسّم، على أي مسافات يجب أن تضع المثلثات التحذيرية الثلاثة؟","options":["10 أقدام و100 قدم و150 قدماً","10 أقدام و100 قدم و200 قدم","25 قدماً و100 قدم و200 قدم","10 أقدام و50 قدماً و100 قدم"],"explanation":"على طريق باتجاه واحد أو طريق سريع مقسّم، ضع المثلثات التحذيرية على بعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة."},"26":{"q":"شعار المركبة بطيئة الحركة (SMV) مطلوب للمركبات المصممة للسير بسرعة كم أو أقل؟","options":["15 ميلاً في الساعة","20 ميلاً في الساعة","25 ميلاً في الساعة","30 ميلاً في الساعة"],"explanation":"شعار المركبة بطيئة الحركة (SMV) ذو المثلث البرتقالي مطلوب للمركبات المصممة للسير بسرعة 25 ميلاً في الساعة أو أقل."},"27":{"q":"بموجب قانون التنحّي/إبطاء السرعة (Move Over / Slow Down)، كم يجب أن تنخفض سرعتك دون الحد المسموح إذا لم تتمكن من تغيير المسار؟","options":["5 أميال في الساعة دون الحد","10 أميال في الساعة دون الحد","15 ميلاً في الساعة دون الحد","20 ميلاً في الساعة دون الحد"],"explanation":"إذا لم تتمكن من التنحّي، خفّض سرعتك إلى 20 ميلاً في الساعة دون الحد المسموح (5 أميال في الساعة إذا كان الحد 25 أو أقل)."},"28":{"q":"متى تكون المصابيح الأمامية مطلوبة بعد غروب الشمس؟","options":["30 دقيقة","20 دقيقة","15 دقيقة","45 دقيقة"],"explanation":"المصابيح الأمامية مطلوبة من 30 دقيقة بعد غروب الشمس حتى 30 دقيقة قبل شروقها."},"29":{"q":"كيف يجوز لسائق رخصة القيادة التجارية (CDL) استخدام الهاتف أثناء قيادة مركبة تجارية (CMV)؟","options":["الرسائل النصية فقط","بدون استخدام اليدين فقط","باليد فقط","بأي طريقة"],"explanation":"يجوز لسائق رخصة القيادة التجارية استخدام الهاتف بدون استخدام اليدين فقط؛ أما الرسائل النصية والاستخدام باليد فممنوعان."},"30":{"q":"في تكساس، ماذا يلزم القانون سائق المركبة التجارية (CMV) بارتدائه؟","options":["سترة عاكسة","خوذة صلبة","حزام الأمان","قفازات أمان"],"explanation":"في تكساس، يُلزم سائقو المركبات التجارية بربط أحزمة الأمان في جميع الأوقات أثناء القيادة."},"31":{"q":"بموجب الحد الأدنى للمسؤولية في تكساس، ما مقدار التغطية المطلوبة للإصابة الجسدية لشخص واحد؟","options":["25,000 دولار","60,000 دولار","750,000 دولار","30,000 دولار"],"explanation":"يتطلب الحد الأدنى للمسؤولية في تكساس تغطية قدرها 30,000 دولار للإصابة الجسدية لشخص واحد."},"32":{"q":"في تكساس، ما الحد الأدنى لتغطية المسؤولية عن الإصابة الجسدية لكل حادث؟","options":["60,000 دولار","30,000 دولار","25,000 دولار","50,000 دولار"],"explanation":"الحد الأدنى للمسؤولية في تكساس هو 60,000 دولار للإصابة الجسدية لكل حادث."},"33":{"q":"ما الحد الأدنى لتغطية المسؤولية عن الأضرار المادية في تكساس؟","options":["15,000 دولار","25,000 دولار","30,000 دولار","60,000 دولار"],"explanation":"في تكساس، الحد الأدنى لتغطية المسؤولية عن الأضرار المادية هو 25,000 دولار."},"34":{"q":"ما الحد الأدنى الفيدرالي الشائع للمسؤولية في عمليات المركبات التجارية (CMV)؟","options":["25,000 دولار","60,000 دولار","750,000 دولار","30,000 دولار"],"explanation":"غالباً ما تتطلب عمليات المركبات التجارية (CMV) حدوداً فيدرالية أعلى بكثير، مثل 750,000 دولار أو أكثر."},"35":{"q":"قبل سكك الحديد، أين يجب أن تتوقف الحافلات ومركبات نقل المواد الخطرة (HazMat) التي تحمل لافتات تحذيرية؟","options":["من 5 إلى 15 قدماً","من 10 إلى 25 قدماً","من 15 إلى 40 قدماً","من 15 إلى 50 قدماً"],"explanation":"يجب أن تتوقف الحافلات ومركبات نقل المواد الخطرة (HazMat) التي تحمل لافتات تحذيرية على بعد من 15 إلى 50 قدماً قبل سكك الحديد."},"36":{"q":"قبل البدء بعبور سكك الحديد، مِمَّ يجب أن تتأكد من قدرتك عليه؟","options":["تجاوز السكك بالكامل","تغيير التروس أثناء العبور","التوقف على السكك","العبور خلال 15 قدماً"],"explanation":"لا تبدأ بعبور سكك الحديد إلا إذا كنت قادراً على تجاوزها بالكامل دون توقف."},"37":{"q":"الحمولة التي تمتد أكثر من 4 أقدام خلف المركبة يجب وضع علامة عليها نهاراً باستخدام ماذا؟","options":["راية حمراء أو برتقالية","ضوء أحمر","راية خضراء","مثلث تحذيري"],"explanation":"الحمولة التي تمتد أكثر من 4 أقدام خلف المركبة يجب وضع علامة عليها براية حمراء أو برتقالية أثناء النهار."},"38":{"q":"ما مقدار الكحول الذي يجوز لسائق رخصة القيادة التجارية (CDL) أن يكون لديه أثناء الخدمة؟","options":["حتى 0.04%","لا شيء على الإطلاق","حتى 0.08%","حتى 0.02%"],"explanation":"لا يجوز لسائق رخصة القيادة التجارية أن يكون لديه أي قدر يمكن اكتشافه من الكحول أثناء الخدمة."},"39":{"q":"على طريق ذي مسارين باتجاهين، على أي مسافة أمام مركبتك المتوقفة تضع المثلث التحذيري؟","options":["10 أقدام","50 قدماً","200 قدم","100 قدم"],"explanation":"على طريق ذي مسارين باتجاهين، يوضع المثلث التحذيري على بعد نحو 100 قدم أمام المركبة المتوقفة."},"40":{"q":"بموجب قانون التنحّي/إبطاء السرعة (Move Over / Slow Down)، إذا لم تتمكن من التنحّي، إلى أي سرعة بالميل في الساعة يجب أن تبطئ عندما يكون الحد المسموح 25 ميلاً في الساعة أو أقل؟","options":["5 أميال في الساعة","10 أميال في الساعة","15 ميلاً في الساعة","20 ميلاً في الساعة"],"explanation":"بموجب قانون التنحّي/إبطاء السرعة (Move Over / Slow Down)، تتنحّى عن المسار إن استطعت، وخيار إبطاء السرعة هو 5 أميال في الساعة عندما يكون الحد المسموح 25 ميلاً في الساعة أو أقل."},"41":{"q":"ينطبق قانون التنحّي/إبطاء السرعة (Move Over / Slow Down) على المركبات المتوقفة التي تعرض أضواءً وامضة من أيٍّ مما يلي؟","options":["أي سيارة ركاب متوقفة","مركبات الطوارئ أو الشرطة أو القطر أو إدارة النقل في تكساس (TxDOT)","الحافلات المدرسية أثناء صعود الأطفال","المعدات الزراعية بطيئة الحركة"],"explanation":"ينطبق قانون التنحّي/إبطاء السرعة (Move Over / Slow Down) على مركبات الطوارئ أو الشرطة أو القطر أو إدارة النقل في تكساس (TxDOT) المتوقفة التي تعرض أضواءً وامضة."},"42":{"q":"حتى أي وقت قبل شروق الشمس تكون المصابيح الأمامية مطلوبة؟","options":["10 دقائق قبل شروق الشمس","15 دقيقة قبل شروق الشمس","30 دقيقة قبل شروق الشمس","60 دقيقة قبل شروق الشمس"],"explanation":"تكون المصابيح الأمامية مطلوبة حتى 30 دقيقة قبل شروق الشمس، وكلما تعذّرت عليك الرؤية بوضوح لمسافة لا تقل عن 1000 قدم."},"43":{"q":"أثناء قيادة مركبة تجارية، أي نشاط هاتفي محظور؟","options":["استخدام هاتف بدون استخدام اليدين","الاستماع إلى الراديو","استخدام الأوامر الصوتية","إرسال الرسائل النصية واستخدام الهاتف باليد"],"explanation":"يُحظر إرسال الرسائل النصية واستخدام الهاتف باليد أثناء قيادة مركبة تجارية."},"44":{"q":"عند عبور سكك الحديد، ما الذي يجب ألّا تفعله الحافلة أو مركبة المواد الخطرة الحاملة للوحات تحذيرية إطلاقًا؟","options":["تبديل التروس أثناء العبور","تشغيل المصابيح الأمامية","استخدام مساحات الزجاج الأمامي","فحص المرايا الجانبية"],"explanation":"يجب على الحافلات ومركبات المواد الخطرة الحاملة للوحات تحذيرية ألّا تبدّل التروس إطلاقًا أثناء عبور سكك الحديد."},"45":{"q":"ماذا يجب على السائق أن يفعل قبل عبور سكك الحديد؟","options":["إطلاق البوق مرتين","النظر والإصغاء لقدوم القطارات","تشغيل الراديو","زيادة السرعة للعبور بسرعة"],"explanation":"عند معابر السكك الحديدية، يجب على السائقين النظر والإصغاء قبل العبور."},"46":{"q":"العرض الأقصى البالغ 102 بوصة يساوي كم قدمًا وبوصة؟","options":["8 أقدام و6 بوصات","9 أقدام و0 بوصة","8 أقدام و0 بوصة","7 أقدام و6 بوصات"],"explanation":"العرض الأقصى للمركبة هو 102 بوصة، وهو ما يعادل 8 أقدام و6 بوصات."},"47":{"q":"كم وزنًا إضافيًا يُسمح به للمحور المزدوج مقارنة بالمحور الفردي؟","options":["10,000 رطل","14,000 رطل","20,000 رطل","34,000 رطل"],"explanation":"حد المحور المزدوج البالغ 34,000 رطل يزيد بمقدار 14,000 رطل عن حد المحور الفردي البالغ 20,000 رطل."},"48":{"q":"في التركيبة القانونية القصوى، كم مقطورة يمكن سحبها خلف الشاحنة الجرّارة؟","options":["4 مقطورات","مقطورة واحدة","مقطورتان","3 مقطورات"],"explanation":"الحد الأقصى هو 3 مركبات في تركيبة واحدة، لذا يمكن للشاحنة الجرّارة سحب مقطورتين."},"49":{"q":"يجب وضع علم تحذيري على الحمولة إذا امتدّت خلف المركبة بأكثر من كم قدمًا؟","options":["قدمان","3 أقدام","6 أقدام","4 أقدام"],"explanation":"يجب وضع علم تحذيري على الحمولة التي تمتدّ بأكثر من 4 أقدام خلف المركبة."},"50":{"q":"ماذا يمثّل حد 80,000 رطل للمركبة التجارية؟","options":["الوزن المجمّع للمركبة مع الحمولة (الوزن الإجمالي)","الوزن المسموح به على محور فردي","الوزن المسموح به على محور مزدوج","وزن الحمولة فقط، دون المركبة"],"explanation":"رقم 80,000 رطل هو الوزن الإجمالي الأقصى، أي المركبة مع حمولتها مجتمعتين."},"51":{"q":"أي فئة من رخص القيادة التجارية هي تركيبة بوزن إجمالي مركّب 26,001 رطل أو أكثر تسحب وحدة يزيد وزنها عن 10,000 رطل؟","options":["الفئة C","الفئة A","الفئة B","الفئة D"],"explanation":"تشمل الفئة A تركيبة بوزن إجمالي مركّب 26,001 رطل أو أكثر مع وحدة مسحوبة يزيد وزنها عن 10,000 رطل."},"52":{"q":"أي فئة من رخص القيادة التجارية هي مركبة فردية ثقيلة (26,001 رطل أو أكثر) تسحب 10,000 رطل أو أقل؟","options":["الفئة A","الفئة C","الفئة B","لا حاجة لرخصة قيادة تجارية"],"explanation":"تشمل الفئة B مركبة فردية بوزن 26,001 رطل أو أكثر، بما في ذلك ما يسحب 10,000 رطل أو أقل."},"53":{"q":"ما الحد الأدنى للعمر المطلوب لنقل المواد الخطرة؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"يجب أن يكون عمرك 21 عامًا على الأقل لنقل المواد الخطرة."},"54":{"q":"في تكساس، كونك في عمر 18 عامًا على الأقل يتيح لك قيادة مركبة تجارية بأي طريقة؟","options":["داخل الولاية (ضمن تكساس فقط)","بين الولايات (عبر حدود الولايات)","نقل المواد الخطرة الحاملة للوحات تحذيرية","نقل الركاب بين الولايات"],"explanation":"الحد الأدنى للعمر لقيادة مركبة تجارية داخل الولاية (ضمن تكساس فقط) هو 18 عامًا."},"55":{"q":"هل يتطلّب حمل المواد الخطرة التي تستوجب لوحات تحذيرية رخصة قيادة تجارية؟","options":["لا، فقط إذا كانت المركبة ثقيلة","نعم، بغض النظر عن وزن المركبة","لا، رخصة عادية تكفي","نعم، لكن في الرحلات بين الولايات فقط"],"explanation":"رخصة القيادة التجارية مطلوبة لأي مركبة تحمل مواد خطرة تستوجب لوحات تحذيرية، بغض النظر عن وزنها."},"56":{"q":"حد الكحول في الدم لحامل رخصة القيادة التجارية هو أي نسبة من حد 0.08% لسائقي السيارات؟","options":["نفس الحد (0.08%)","ضعف الحد (0.16%)","نصف الحد (0.04%)","ثلاثة أضعاف الحد (0.24%)"],"explanation":"حد الكحول في الدم لحامل رخصة القيادة التجارية هو 0.04%، وهو نصف حد 0.08% لسائقي السيارات."},"57":{"q":"في تكساس، تعني القيادة أنك قد وافقت على ماذا؟","options":["فحص المركبة","فحص النظر","التحقق من سجل القيادة","الفحص الكيميائي"],"explanation":"بموجب الموافقة الضمنية في تكساس، تعني القيادة أنك توافق على الفحص الكيميائي."},"58":{"q":"أي مما يلي مثال على المخالفة الكبرى الأولى؟","options":["استخدام مركبة تجارية لارتكاب جناية","القيادة بسرعة تزيد 6 أميال في الساعة عن الحد","السير خلف مركبة أخرى بمسافة قريبة جدًا","تغيير المسار بشكل غير سليم"],"explanation":"استخدام مركبة تجارية في جناية هو مخالفة كبرى أولى، تؤدي إلى الحرمان من الرخصة لمدة عام واحد."},"59":{"q":"كم عدد المخالفات الكبرى التي تؤدي إلى الحرمان من رخصة القيادة التجارية مدى الحياة؟","options":["واحدة","اثنتان","ثلاث","أربع"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى الحرمان من رخصة القيادة التجارية مدى الحياة."},"60":{"q":"المخالفات المرورية الخطيرة في مركبة تجارية تُحتسب خلال كم عامًا؟","options":["عام واحد","عامان","3 أعوام","5 أعوام"],"explanation":"مخالفتان مروريتان خطيرتان خلال 3 أعوام في مركبة تجارية تؤديان إلى الحرمان من الرخصة لمدة 60 يومًا."},"61":{"q":"كم تطول مدة الحرمان للمخالفة الكبرى الأولى عند نقل المواد الخطرة الحاملة للوحات تحذيرية؟","options":["نفس المدة","أطول بـ 6 أشهر","أطول بعام واحد","أطول بعامين"],"explanation":"تؤدي المخالفة الكبرى الأولى إلى الحرمان لمدة عام واحد، أو 3 أعوام عند نقل المواد الخطرة الحاملة للوحات تحذيرية، أي أطول بعامين."},"62":{"q":"على طريق ذي مسارين باتجاهين، أين تضع المثلثين خلف مركبتك؟","options":["على بُعد نحو 10 أقدام و100 قدم خلفها","على بُعد نحو 10 أقدام و200 قدم خلفها","على بُعد نحو 50 قدمًا و100 قدم خلفها","على بُعد نحو 20 قدمًا و200 قدم خلفها"],"explanation":"على طريق ذي مسارين باتجاهين، ضع المثلثات على بُعد نحو 10 أقدام و100 قدم خلف المركبة."},"63":{"q":"بعد التوقف على الطريق، ماذا يجب أن تشغّل؟","options":["مصابيحك الأمامية العالية","أضواء التحذير (الفلاشر)","إشارة الانعطاف اليسرى","ضوء المقصورة الداخلي"],"explanation":"بعد التوقف على الطريق، شغّل أضواء التحذير وضع 3 مثلثات تحذيرية."},"64":{"q":"على طريق باتجاه واحد أو طريق سريع مقسوم، على أي بُعد يجب وضع أبعد مثلث تحذيري، وفي أي اتجاه؟","options":["100 قدم باتجاه حركة المرور القادمة","100 قدم خلف المركبة","200 قدم باتجاه حركة المرور القادمة","200 قدم خلف المركبة"],"explanation":"على طريق باتجاه واحد أو طريق سريع مقسوم، ضع المثلثات التحذيرية على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة."},"65":{"q":"يجب أن تشغّل مصابيحك الأمامية كلما تعذّرت عليك الرؤية بوضوح لمسافة لا تقل عن كم؟","options":["200 قدم","500 قدم","750 قدمًا","1000 قدم"],"explanation":"تكون المصابيح الأمامية مطلوبة كلما تعذّرت عليك الرؤية بوضوح لمسافة لا تقل عن 1000 قدم."},"66":{"q":"بموجب قانون التنحّي/إبطاء السرعة، ماذا يجب أن تفعل أولًا إذا كان هناك مسار متاح؟","options":["التنحّي إلى مسار آخر","التوقف تمامًا","إطلاق البوق","إطفاء أضوائك"],"explanation":"ينص قانون التنحّي/إبطاء السرعة على التنحّي إلى مسار آخر إن أمكنك، أو إبطاء السرعة إن لم تستطع."},"67":{"q":"ما هو شكل ولون شعار المركبة بطيئة الحركة (SMV)؟","options":["مربع أحمر","مثلث برتقالي","دائرة صفراء","معين أخضر"],"explanation":"شعار المركبة بطيئة الحركة (SMV) هو مثلث برتقالي."},"68":{"q":"هل يجوز لسائق رخصة القيادة التجارية (CDL) قانونيًا إجراء مكالمة هاتفية بدون استخدام اليدين أثناء قيادة مركبة تجارية (CMV)؟","options":["لا، جميع المكالمات الهاتفية ممنوعة","لا، يُسمح فقط بالمكالمات باستخدام اليد","نعم، يُسمح بالمكالمات بدون استخدام اليدين","نعم، لكن يُسمح فقط بالرسائل النصية"],"explanation":"يجوز لسائق رخصة القيادة التجارية استخدام الهاتف بدون استخدام اليدين فقط أثناء قيادة مركبة تجارية."},"69":{"q":"في الحد الأدنى للمسؤولية في تكساس \"30/60/25\"، ماذا تمثل الأرقام الثلاثة بالترتيب؟","options":["أضرار الممتلكات / لكل شخص / لكل حادث","لكل حادث / لكل شخص / أضرار الممتلكات","لكل شخص / أضرار الممتلكات / لكل حادث","لكل شخص / لكل حادث / أضرار الممتلكات"],"explanation":"في \"30/60/25\" تعني الأرقام: الإصابة الجسدية لكل شخص (30,000 دولار)، والإصابة الجسدية لكل حادث (60,000 دولار)، وأضرار الممتلكات (25,000 دولار)، بهذا الترتيب."},"70":{"q":"بموجب الحد الأدنى للمسؤولية في تكساس، ماذا يغطي مبلغ 60,000 دولار؟","options":["الإصابة الجسدية لكل حادث","الإصابة الجسدية لشخص واحد","أضرار الممتلكات لكل حادث","الحد الإجمالي للتغطية المجمعة"],"explanation":"في الحد الأدنى للمسؤولية في تكساس، يمثل مبلغ 60,000 دولار التغطية للإصابة الجسدية لكل حادث."},"71":{"q":"لماذا تحتاج العمليات التجارية (CMV) إلى تغطية أكبر من الحد الأدنى 30/60/25؟","options":["المركبات التجارية معفاة من جميع قواعد التأمين","الحدود الفيدرالية أعلى بكثير، مثل 750,000 دولار أو أكثر","الحدود الفيدرالية تساوي الحد الأدنى 30/60/25","الحدود الفيدرالية أقل من الحد الأدنى للولاية"],"explanation":"غالبًا ما تتطلب العمليات التجارية للمركبات التجارية حدود مسؤولية فيدرالية أعلى بكثير، مثل 750,000 دولار أو أكثر."},"72":{"q":"أي نوعين من المركبات يجب أن يتوقفا دائمًا عند معابر السكك الحديدية؟","options":["الصهاريج والشاحنات ذات الأرضية المسطحة","المقطورات المزدوجة والتركيبات الثلاثية","الحافلات والمركبات التي تحمل لافتات المواد الخطرة (HazMat)","شاحنات القلابة ومركبات السحب"],"explanation":"يجب على الحافلات والمركبات التي تحمل لافتات المواد الخطرة التوقف على مسافة من 15 إلى 50 قدمًا قبل القضبان."},"73":{"q":"متى يجب ألا تبدأ بعبور قضبان السكك الحديدية؟","options":["عندما تومض الأضواء الحمراء","عندما يقترب قطار","عندما تكون البوابة مخفوضة","عندما لا تستطيع تجاوز القضبان بالكامل"],"explanation":"لا تبدأ بالعبور إلا إذا كنت تستطيع تجاوز القضبان بالكامل."},"74":{"q":"الحد الأقصى القانوني لارتفاع المركبة في تكساس يساوي كم بوصة؟","options":["168 بوصة","102 بوصة","120 بوصة","144 بوصة"],"explanation":"الحد الأقصى للارتفاع هو 14 قدمًا، أي ما يعادل 168 بوصة."},"75":{"q":"الانتقال من مخالفتين إلى ثلاث مخالفات مرورية خطيرة خلال 3 سنوات يغير فترة الحرمان من 60 يومًا إلى ماذا؟","options":["90 يومًا","120 يومًا","60 يومًا","سنة واحدة"],"explanation":"ينتج عن ثلاث مخالفات مرورية خطيرة خلال 3 سنوات حرمان لمدة 120 يومًا."},"76":{"q":"ما هو معيار الكحول لسائق رخصة القيادة التجارية أثناء أداء الواجب؟","options":["أقل من 0.08%","أقل من 0.04%","عدم وجود أي كحول قابل للكشف","يُسمح بمشروب واحد"],"explanation":"لا يجوز لسائق رخصة القيادة التجارية أن يكون لديه أي كحول قابل للكشف أثناء أداء الواجب."},"77":{"q":"تُطلب رخصة القيادة التجارية لمركبة مركبة تقطر وحدة يزيد وزنها عن 10,000 رطل عندما يتجاوز وزنها الإجمالي المركّب للمركبة (GCWR) أي وزن؟","options":["10,000 رطل","20,000 رطل","80,000 رطل","26,001 رطل"],"explanation":"تُطلب رخصة القيادة التجارية لمركبة مركبة يزيد وزنها الإجمالي المركّب (GCWR) عن 26,001 رطل وتقطر وحدة يزيد وزنها عن 10,000 رطل."},"78":{"q":"المركبات المصنوعة بعد أي سنة يجب أن تحتوي على أضواء إشارة انعطاف كهربائية؟","options":["1959","1955","1965","1972"],"explanation":"تشترط تكساس وجود أضواء إشارة انعطاف كهربائية على جميع المركبات الآلية أو المقطورات أو نصف المقطورات أو مقطورات الأعمدة المصنوعة بعد سنة 1959."},"79":{"q":"سيارات الركاب أو الشاحنات التي يقل عرضها عن 80 بوصة تحتاج إلى إشارات انعطاف كهربائية فقط إذا صُنعت بعد أي سنة طراز؟","options":["1955","1959","1965","1972"],"explanation":"السيارات أو الشاحنات التي يقل عرضها عن 80 بوصة والمصنوعة قبل سنة طراز 1960 (أي 1959 أو قبلها) لا تحتاج إلى إشارات انعطاف كهربائية."},"80":{"q":"استثناء إشارة الانعطاف لما قبل عام 1960 لا ينطبق إذا امتد الهيكل أو الحمولة لأكثر من أي مسافة إلى جانب مركز عجلة القيادة؟","options":["14 بوصة","18 بوصة","24 بوصة","80 بوصة"],"explanation":"إذا امتد الهيكل أو الحمولة لأكثر من 24 بوصة إلى جانب مركز عجلة القيادة، فإن استثناء ما قبل عام 1960 لا ينطبق."},"81":{"q":"استثناء إشارة الانعطاف الكهربائية لما قبل عام 1960 لا ينطبق إذا كان مؤخر الهيكل أو الحمولة على مسافة أكبر من كم خلف مركز عجلة القيادة؟","options":["10 أقدام","12 قدمًا","13 قدمًا","14 قدمًا"],"explanation":"إذا كان مؤخر الهيكل أو الحمولة على مسافة أكبر من 14 قدمًا خلف مركز عجلة القيادة، فإن استثناء إشارة الانعطاف لما قبل عام 1960 لا ينطبق."},"82":{"q":"كم عدد المصابيح الخلفية المطلوبة على المركبات الآلية والمقطورات ونصف المقطورات ومقطورات الأعمدة؟","options":["اثنان على الأقل","واحد على الأقل","ثلاثة على الأقل","أربعة على الأقل"],"explanation":"يُطلب وجود مصباحين خلفيين على الأقل على المركبات الآلية والمقطورات ونصف المقطورات ومقطورات الأعمدة."},"83":{"q":"سيارات الركاب والشاحنات من أي سنة طراز وما قبلها تحتاج إلى مصباح خلفي واحد فقط؟","options":["1955","1959","1965","1972"],"explanation":"جميع سيارات الركاب والشاحنات من سنة طراز 1959 وما قبلها تحتاج إلى مصباح خلفي واحد فقط بدلًا من اثنين."},"84":{"q":"كم عدد المصابيح الخلفية التي تحتاجها الدراجات النارية والدراجات المزودة بمحرك والدراجات الآلية (الموبيد)؟","options":["أربعة","ثلاثة","واحد","اثنان"],"explanation":"تحتاج الدراجات النارية والدراجات المزودة بمحرك والدراجات الآلية (الموبيد) إلى مصباح خلفي واحد فقط."},"85":{"q":"العاكسات على المركبات المصنوعة قبل 1 يناير 1972 يجب أن تكون مرئية ليلًا من أي مسافة تحت المصابيح الأمامية ذات الشعاع العالي؟","options":["من 600 قدم إلى 300 قدم","من 500 قدم إلى 100 قدم","من 600 قدم إلى 200 قدم","من 600 قدم إلى 100 قدم"],"explanation":"على المركبات المصنوعة قبل عام 1972، يجب أن تكون العاكسات مرئية ليلًا من 600 قدم إلى 100 قدم عندما تكون مباشرة أمام المصابيح الأمامية القانونية ذات الشعاع العالي."},"86":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة التجارية أو حمولتها في تكساس؟","options":["96 بوصة","102 بوصة","108 بوصة","120 بوصة"],"explanation":"الحد الأقصى للعرض، بما في ذلك الحمولة، هو 102 بوصة (8.5 قدم)؛ وأي شيء أعرض من ذلك يتطلب تصريحًا."},"87":{"q":"ما هو الحد الأقصى لارتفاع المركبة والحمولة على الطرق السريعة في تكساس؟","options":["13 قدمًا","13 قدمًا و6 بوصات","14 قدمًا","15 قدمًا"],"explanation":"الحد الأقصى للارتفاع هو 14 قدمًا؛ والسائق مسؤول عن تجاوز جميع الجسور بأمان."},"88":{"q":"الحد الأقصى للوزن الإجمالي (المركبة بالإضافة إلى الحمولة) بدون تصريح هو:","options":["72,000 رطل","76,000 رطل","80,000 رطل","90,000 رطل"],"explanation":"الحد الأقصى للوزن الإجمالي هو 80,000 رطل بدون تصريح للحمولة الزائدة."},"89":{"q":"شعار المركبة بطيئة الحركة (SMV) مخصص للمركبات المصممة للسير بسرعة:","options":["15 ميلًا في الساعة أو أقل","25 ميلًا في الساعة أو أقل","35 ميلًا في الساعة أو أقل","45 ميلًا في الساعة أو أقل"],"explanation":"المثلث البرتقالي يحذر من المركبات المصممة للسير بسرعة 25 ميلًا في الساعة أو أقل."},"90":{"q":"على شاحنة عرضها 80 بوصة، يجب أن تكون مصابيح الخلوص الأمامية:","options":["كهرمانية","حمراء","بيضاء","خضراء"],"explanation":"مصابيح الخلوص الأمامية كهرمانية؛ والخلفية حمراء."},"91":{"q":"يجب أن تكون مصابيح الخلوص الخلفية على شاحنة عريضة:","options":["كهرمانية","بيضاء","حمراء","زرقاء"],"explanation":"مصابيح الخلوص الخلفية والعاكسات حمراء."},"92":{"q":"يجب أن يكون لون العاكسين المطلوبين في مؤخرة المركبة التجارية:","options":["كهرماني","أحمر","أبيض","أخضر"],"explanation":"العاكسات الخلفية يجب أن تكون حمراء."},"93":{"q":"ما اللون الذي يجب أن تُظهره مصابيح المؤخرة إلى الخلف؟","options":["أبيض","كهرماني","أحمر","أزرق"],"explanation":"تُظهر مصابيح المؤخرة اللون الأحمر إلى الخلف."},"94":{"q":"ما اللون الذي يجب أن تُظهره المصابيح الأمامية في المركبة التجارية؟","options":["كهرماني","أبيض","أصفر","أزرق"],"explanation":"يجب أن تُظهر المصابيح الأمامية ضوءًا أبيض."},"95":{"q":"يجب ألا تقل مساحة الراية الحمراء التي تُعلِّم الحمولة البارزة عن:","options":["6 بوصات مربعة","9 بوصات مربعة","12 بوصة مربعة","18 بوصة مربعة"],"explanation":"يجب ألا تقل مساحة الراية الحمراء عن 12 بوصة مربعة."},"96":{"q":"يجب وضع راية على الحمولة عندما تمتد إلى الخلف بأكثر من:","options":["2 قدم","3 أقدام","4 أقدام","6 أقدام"],"explanation":"تُطلب راية حمراء عندما تمتد الحمولة أكثر من 4 أقدام خلف المركبة."},"97":{"q":"لا يجوز أن تمتد الحمولة إلى أمام المركبة بأكثر من:","options":["3 أقدام","4 أقدام","6 أقدام","10 أقدام"],"explanation":"لا يجوز أن تمتد الحمولة أكثر من 3 أقدام أمام المركبة."},"98":{"q":"عند القطر بسلسلة، يجب أن تُظهر نقطة الوصل راية لونها:","options":["أحمر","أبيض","كهرماني","برتقالي"],"explanation":"تحتاج سلسلة/حبل/كابل القطر إلى راية بيضاء؛ أما الراية الحمراء فهي للحمولات البارزة."},"99":{"q":"لا يجوز أن يتجاوز طول وصلة القطر بين مركبتين:","options":["10 أقدام","15 قدمًا","20 قدمًا","25 قدمًا"],"explanation":"لا يجوز أن تتجاوز الوصلة 15 قدمًا (باستثناء العمود أو القضيب الصلب)."},"100":{"q":"تُطلب فرامل على المحور الخلفي للمقطورة عندما يتجاوز وزنها الإجمالي:","options":["2,500 رطل","3,000 رطل","4,500 رطل","10,000 رطل"],"explanation":"تُطلب الفرامل على المقطورات التي يزيد وزنها عن 4,500 رطل."},"101":{"q":"بعد أن تصبح مقيمًا في تكساس، يُعترف بلوحات الولايات الأخرى لمدة:","options":["10 أيام","20 يومًا","30 يومًا","60 يومًا"],"explanation":"تظل لوحات الولايات الأخرى صالحة لمدة 30 يومًا بعد الإقامة أو التوظيف."},"102":{"q":"تكون لوحة المشتري المؤقتة الكرتونية صالحة لمدة:","options":["20 يومًا","30 يومًا","45 يومًا","60 يومًا"],"explanation":"تكون لوحة المشتري المؤقتة صالحة لمدة 20 يومًا."},"103":{"q":"إلى أي مسافة من الطريق يجب أن تصل واقيات الطين؟","options":["4 بوصات","6 بوصات","8 بوصات","12 بوصة"],"explanation":"يجب أن تصل واقيات الطين إلى مسافة 8 بوصات من سطح الطريق."},"104":{"q":"عند تجاوز دراجة نارية، يجب أن تترك مسافة لا تقل عن:","options":["3 أقدام","6 أقدام","9 أقدام","12 قدمًا"],"explanation":"اترك مسافة لا تقل عن 6 أقدام وغيِّر المسار عند التجاوز."},"105":{"q":"لا يجوز أن يتجاوز طول المركبة المفردة (وليست الجرار-القاطرة):","options":["40 قدمًا","45 قدمًا","53 قدمًا","65 قدمًا"],"explanation":"يقتصر طول المركبة المفردة على 45 قدمًا."},"106":{"q":"أقصى عدد من المركبات المسموح به في القطار الواحد هو:","options":["2","3","4","5"],"explanation":"لا يجوز ربط أكثر من ثلاث مركبات معًا."},"107":{"q":"يجب أن تكون مصابيح المؤخرة واضحة الرؤية من الخلف على مسافة:","options":["300 قدم","500 قدم","750 قدمًا","1,000 قدم"],"explanation":"يجب أن تكون مصابيح المؤخرة مرئية من مسافة 1,000 قدم إلى الخلف."},"108":{"q":"يجب أن يكون مصباح التوقف مرئيًا في وضح النهار من مسافة لا تقل عن:","options":["100 قدم","300 قدم","500 قدم","1,000 قدم"],"explanation":"يجب أن تكون مصابيح التوقف مرئية من مسافة 300 قدم في وضح النهار العادي."},"109":{"q":"في الليل، يجب أن تُظهر الحمولة الممتدة أكثر من 4 أقدام خلف المركبة:","options":["راية بيضاء","راية حمراء","ضوءًا أحمر","ضوءًا كهرمانيًا"],"explanation":"في الليل استخدم ضوءًا أحمر (مرئيًا من 500 قدم) بدلًا من الراية."},"110":{"q":"يجب تركيب العاكسات الخلفية على ارتفاع:","options":["12–48 بوصة","24–54 بوصة","24–60 بوصة","12–60 بوصة"],"explanation":"تُركَّب العاكسات الخلفية على ارتفاع من 24 إلى 60 بوصة فوق سطح الطريق."},"111":{"q":"يجب تركيب المصابيح الأمامية على ارتفاع:","options":["12–48 بوصة","24–54 بوصة","24–60 بوصة","20–50 بوصة"],"explanation":"تُركَّب المصابيح الأمامية على ارتفاع من 24 إلى 54 بوصة."},"112":{"q":"خارج المدينة، لا يجوز أن تتبع شاحنة شاحنة أخرى على مسافة أقرب من:","options":["100 قدم","200 قدم","300 قدم","500 قدم"],"explanation":"اترك مسافة لا تقل عن 300 قدم بين الشاحنات (مع بقاء التجاوز مسموحًا)."},"113":{"q":"يجب أن تخفِّض الأضواء العالية لمركبة قادمة من الاتجاه المقابل ضمن مسافة:","options":["200 قدم","300 قدم","500 قدم","1,000 قدم"],"explanation":"خفِّض الأضواء العالية ضمن 500 قدم من المرور القادم (300 قدم عند السير خلف مركبة)."},"114":{"q":"يجب أن يتوقف القطار الذي يزيد وزنه عن 3,000 رطل من سرعة 20 ميلًا في الساعة ضمن:","options":["30 قدمًا","40 قدمًا","50 قدمًا","60 قدمًا"],"explanation":"ما يزيد عن 3,000 رطل يجب أن يتوقف ضمن 50 قدمًا؛ و3,000 رطل أو أقل ضمن 40 قدمًا."},"115":{"q":"أي لون من الأضواء لا يجوز إظهاره نحو مقدمة المركبة؟","options":["أبيض","كهرماني","أحمر","جميعها مسموح بها"],"explanation":"لا يجوز إظهار اللون الأحمر إلى الأمام؛ فهو مخصص للمؤخرة."},"116":{"q":"عند معبر السكة الحديدية، يجب على شاحنة المواد الخطرة الحاملة للافتات أن:","options":["تتوقف","تتأكد من خلو الطريق","تعبر دون تغيير التروس","جميع ما سبق"],"explanation":"يجب أن تتوقف، وتتأكد من خلو الطريق، وتعبر دون تغيير التروس."},"117":{"q":"أي من هذه ليس حداً قانونياً في تكساس (بدون تصريح)؟","options":["العرض 102 بوصة","الارتفاع 14 قدماً","الطول 45 قدماً (مفردة)","الوزن الإجمالي 100,000 رطل"],"explanation":"الحد الأقصى للوزن الإجمالي هو 80,000 رطل، وليس 100,000؛ أما البقية فهي حدود صحيحة."},"118":{"q":"تكون أضواء الخلف مرئية من مسافة ____؛ وتكون أضواء التوقف مرئية من مسافة ____.","options":["1,000 قدم / 300 قدم","500 قدم / 1,000 قدم","300 قدم / 1,000 قدم","1,000 قدم / 500 قدم"],"explanation":"أضواء الخلف من 1,000 قدم؛ وأضواء التوقف من 300 قدم في ضوء النهار."},"119":{"q":"تُركّب المصابيح الأمامية على ارتفاع ____؛ وتُركّب العاكسات الخلفية على ارتفاع ____.","options":["24–54 بوصة / 24–60 بوصة","24–60 بوصة / 24–54 بوصة","كلاهما 24–54 بوصة","كلاهما 24–60 بوصة"],"explanation":"المصابيح الأمامية 24–54 بوصة؛ والعاكسات 24–60 بوصة."},"120":{"q":"عند قطر مركبة بواسطة سلسلة، ما المطلوب؟","options":["راية بيضاء على نقطة الوصل","وصلة لا يزيد طولها عن 15 قدماً","سلاسل أمان كاحتياط","كل ما سبق"],"explanation":"يُشترط وجود راية بيضاء، ووصلة لا يزيد طولها عن 15 قدماً، وسلاسل أمان جميعها."},"121":{"q":"أي مما يلي قانوني في تكساس؟","options":["الانزلاق نزولاً على المنحدر في وضع التعشيق المحايد","إظهار ضوء أحمر إلى الأمام","تغطية حمولة الحصى","شاحنة مواد خطرة تتجاوز معبراً دون توقف"],"explanation":"تغطية الحمولات السائبة أمر مطلوب؛ أما الخيارات الثلاثة الأخرى فممنوعة."},"122":{"q":"في تكساس، كم يجب أن تحتفظ بتصريح المتعلم التجاري (CLP) على الأقل قبل اختبار المهارات؟","options":["يوم واحد","14 يوماً","6 أشهر","لا انتظار على الإطلاق"],"explanation":"يجب أن تحتفظ بتصريح المتعلم التجاري لمدة 14 يوماً على الأقل قبل اختبار المهارات."},"123":{"q":"الحد الأدنى للسن لقيادة مركبة تجارية عبر حدود الولايات (بين الولايات) هو:","options":["16","18","21","25"],"explanation":"تتطلب القيادة بين الولايات سن 21؛ ويُسمح بسن 18 فقط داخل الولاية (ضمن تكساس)."},"124":{"q":"ينطبق قانون 'التحرك جانباً / إبطاء السرعة' في تكساس عندما تتجاوز مركبة متوقفة من نوع:","options":["سيارة عادية متوقفة","مركبة طوارئ أو مركبة تابعة لإدارة النقل في تكساس (TxDOT) متوقفة","عمود صندوق بريد على جانب الطريق","دراجة هوائية على الكتف"],"explanation":"تحرك إلى مسار آخر أو خفّف السرعة إلى 20 ميلاً في الساعة أقل من الحد المسموح به لمركبات الطوارئ والقطر وإدارة النقل في تكساس المتوقفة وأضواؤها مشغّلة."},"125":{"q":"المركبة التجارية المتوقفة على الكتف يجب أن تضع أجهزة التحذير خلال:","options":["ساعة واحدة","10 دقائق","30 دقيقة","يوم كامل"],"explanation":"ضع أجهزة التحذير خلال 10 دقائق من التوقف."},"126":{"q":"على طريق ذي مسارين، تضع مثلثات التحذير الثلاثة تقريباً عند:","options":["كلها مجمّعة في موضع واحد","10 أقدام و100 قدم و100 قدم من المركبة","فقط خلفها مباشرة","عند 200 قدم فقط، لا غير"],"explanation":"واحد على بُعد نحو 10 أقدام، وواحد على بُعد نحو 100 قدم خلف المركبة، وواحد على بُعد نحو 100 قدم أمامها على طريق ذي اتجاهين."},"127":{"q":"تشمل معدات الطوارئ المطلوبة في المركبة التجارية:","options":["إطار احتياطي واحد فقط","طفاية حريق ومنصهرات ومثلثات","حقيبة إسعافات أولية أساسية فقط","لا توجد معدات خاصة على الإطلاق"],"explanation":"احمل طفاية حريق مشحونة، ومنصهرات احتياطية (إن استُخدمت)، وثلاثة مثلثات تحذير."},"128":{"q":"كم عدد مثلثات التحذير العاكسة التي يجب أن تحملها المركبة التجارية؟","options":["واحد","اثنان","ثلاثة","ستة"],"explanation":"احمل ثلاثة مثلثات عاكسة (أو أجهزة تحذير معادلة)."},"129":{"q":"في تكساس، تُطلب المصابيح الأمامية خلال أي ساعات؟","options":["من حوالي الظهر حتى منتصف الليل","من 30 دقيقة بعد الغروب إلى 30 دقيقة قبل الشروق","فقط حول منتصف الليل تماماً","من الشروق وحتى الغروب"],"explanation":"استخدم المصابيح الأمامية من 30 دقيقة بعد غروب الشمس إلى 30 دقيقة قبل شروقها، وعندما تكون الرؤية ضعيفة."},"130":{"q":"في تكساس يجب أيضاً استخدام المصابيح الأمامية عندما:","options":["فقط على الطرق الترابية الريفية","تكون مساحات الزجاج الأمامي تعمل في المطر","أبداً خلال النهار","فقط أثناء وقوفها"],"explanation":"يتطلب قانون تكساس تشغيل المصابيح الأمامية عندما يستلزم الطقس استخدام مساحات الزجاج الأمامي."},"131":{"q":"على طريق غير مقسوم، يجب أن تتوقف لحافلة مدرسية أضواؤها الحمراء تومض:","options":["فقط إذا كنت خلفها","من كلا الاتجاهين","أبداً على الإطلاق","فقط بعد حلول الظلام"],"explanation":"على الطرق غير المقسومة، يجب أن تتوقف حركة المرور من كلا الاتجاهين؛ ويُعفى المرور القادم في الاتجاه المعاكس إذا وُجد فاصل مادي."},"132":{"q":"الحمولة الأعرض أو الأعلى من الحدود القانونية في تكساس تتطلب:","options":["لا شيء إضافي على الإطلاق","تصريح حمولة كبيرة الحجم/زائدة الوزن","راية حمراء واحدة فقط","مرافقة شرطة في كل مرة"],"explanation":"الحمولات التي تتجاوز الحجم أو الوزن القانوني تحتاج إلى تصريح كبيرة الحجم/زائدة الوزن من إدارة المركبات الآلية في تكساس (TxDMV)."},"133":{"q":"أول مخالفة جسيمة مثل القيادة تحت تأثير الكحول في مركبة تجارية تؤدي إلى سحب رخصتك التجارية لمدة لا تقل عن:","options":["30 يوماً","سنة واحدة","أسبوع واحد","لا مدة على الإطلاق"],"explanation":"أول مخالفة جسيمة (مثل القيادة تحت تأثير الكحول) تؤدي إلى سحب الرخصة لمدة سنة واحدة على الأقل."},"134":{"q":"للحصول على رخصة قيادة تجارية في تكساس يجب أيضاً أن تجتاز:","options":["اختبار سباحة محدد بالوقت","فحص طبي (بدني) تابع لوزارة النقل (DOT)","اختبار طباعة سريع","اختبار طبخ أساسي"],"explanation":"يُشترط وجود شهادة طبية سارية من وزارة النقل (فحص بدني)."},"135":{"q":"في المدينة، يجب أن تشير إلى الانعطاف:","options":["عند الزاوية مباشرة","قبله بنحو 100 قدم","بعد أن تنعطف","لا حاجة إلى إشارة"],"explanation":"أشر باستمرار لمسافة نحو 100 قدم قبل الانعطاف."},"136":{"q":"عند تعطّل المركبة على الطريق السريع، يجب أن تشغّل:","options":["أضواءك العالية الساطعة","الأضواء الوامضة الرباعية (أضواء الخطر)","ضوء المقصورة الداخلي","إشارة الانعطاف فقط"],"explanation":"استخدم الأضواء الوامضة الرباعية للخطر وضع أجهزة التحذير."},"137":{"q":"في تكساس، يجب على السائق والركاب الأماميين:","options":["الوقوف منتصبين","ارتداء حزام الأمان","إبقاء النوافذ مفتوحة","إزالة مساند الرأس"],"explanation":"ارتداء حزام الأمان مطلوب بموجب قانون تكساس."},"138":{"q":"السائق التجاري الذي يستخدم هاتفاً محمولاً باليد أثناء القيادة يكون:","options":["مسموحاً له تماماً","مخالفاً للقوانين الفيدرالية/قوانين تكساس","ملزماً بذلك قانونياً","لا بأس به داخل المدينة"],"explanation":"يُمنع على سائقي المركبات التجارية استخدام الهاتف المحمول باليد وإرسال الرسائل النصية."},"139":{"q":"على طريق سريع مقسوم، يوضع مثلث التحذير باتجاه حركة المرور القادمة على بُعد نحو:","options":["10 أقدام للخلف","100 قدم للخلف","200 قدم للخلف","عند المصد مباشرة"],"explanation":"على طريق مقسوم أو ذي اتجاه واحد، ضع الأجهزة على بُعد نحو 10 و100 و200 قدم باتجاه حركة المرور القادمة."},"140":{"q":"تشترط تكساس على السائقين حمل إثبات:","options":["عضوية شهرية في نادٍ رياضي","المسؤولية المالية (التأمين)","جواز سفر ساري المفعول","بطاقة مكتبة عامة"],"explanation":"يُشترط إثبات المسؤولية المالية (تأمين المسؤولية المدنية)."},"141":{"q":"عندما تضطر إلى الوقوف، الخيار الأكثر أماناً هو:","options":["سد مسار السير","الوقوف بعيداً عن الطريق قدر الإمكان","تركها تعمل في مسار السير","الوقوف عند منعطف أعمى"],"explanation":"أخرج المركبة بالكامل عن الطريق المستخدم حيثما أمكن."},"142":{"q":"السائق الذي يرفض إجراء اختبار إلزامي للكحول أو المخدرات:","options":["يحصل فقط على تحذير كتابي","يُحرم من القيادة كما لو رسب في الاختبار","يحصل على خصم بسيط","لا يحدث له شيء على الإطلاق"],"explanation":"رفض إجراء اختبار إلزامي يستوجب نفس الحرمان الذي يستوجبه الرسوب فيه."},"143":{"q":"يجب حمل منصهرات كهربائية احتياطية ما لم تكن المركبة:","options":["مطلية بالأحمر الزاهي","تستخدم قواطع دارة بدلاً من المنصهرات","جديدة تماماً من المعرض","مزودة براديو يعمل"],"explanation":"المنصهرات الاحتياطية مطلوبة ما لم تكن المركبة تستخدم قواطع دارة."},"144":{"q":"في تكساس، حاويات الكحول المفتوحة داخل مقصورة المركبة التجارية تكون:","options":["مسموحة عموماً","ممنوعة","مطلوبة","لا بأس بها عند التوقف"],"explanation":"حيازة الكحول أو شربه في مركبة تجارية أثناء العمل أمر ممنوع."},"145":{"q":"يتم إكمال تقرير فحص السائق للمركبة (DVIR):","options":["مرة واحدة فقط في السنة","كل يوم، حسب المطلوب","لا يُكمل أبداً","فقط عند بيعها"],"explanation":"يكمل السائقون تقرير فحص المركبة حسب المطلوب (يومياً أو بعد الرحلة)."},"146":{"q":"مغادرة موقع الحادث مثال على أي نوع من المخالفات؟","options":["مخالفة جسيمة أولى","مخالفة مرورية خطيرة","خطأ بسيط في الأوراق","مخالفة وقوف"],"explanation":"مغادرة موقع الحادث مخالفة جسيمة أولى تتسبب في حرمان من رخصة القيادة التجارية لمدة سنة واحدة."},"147":{"q":"ما الحد الأدنى للسن لقيادة مركبة ركاب عبر حدود الولايات (بين الولايات)؟","options":["21 عاماً","18 عاماً","16 عاماً","25 عاماً"],"explanation":"يجب أن يكون عمرك 21 عاماً على الأقل للقيادة بين الولايات، بما في ذلك نقل الركاب بين الولايات، تماماً مثل القيادة بين الولايات ونقل المواد الخطرة."},"148":{"q":"في الليل، الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة يجب أن تُظهر ضوءاً بأي لون؟","options":["ضوء أخضر","ضوء أحمر","ضوء أزرق","ضوء أبيض"],"explanation":"الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة يجب أن تُظهر ضوءاً أحمر في الليل أو في حالة ضعف الرؤية."},"149":{"q":"في النهار، الحمولة التي تمتد أكثر من 4 أقدام خلف المؤخرة يجب أن تُعلَّم بعلم من أي لون؟","options":["أحمر أو برتقالي","أخضر أو أزرق","أبيض أو أصفر","أسود أو بني"],"explanation":"في النهار يجب تعليم الحمولة البارزة بعلم أحمر أو برتقالي."},"150":{"q":"للقيادة بين الولايات، يجب أن يكون عمر سائق رخصة القيادة التجارية على الأقل كم؟","options":["18","21","19","25"],"explanation":"يجب أن يكون عمرك 21 عاماً على الأقل لقيادة مركبة تجارية في التجارة بين الولايات."},"151":{"q":"ما الحد الأقصى للوزن الإجمالي المسموح به على محور واحد بدون تصريح خاص؟","options":["20,000 رطل","34,000 رطل","26,001 رطل","80,000 رطل"],"explanation":"حد وزن المحور الواحد هو 20,000 رطل."},"152":{"q":"كم مدة الحرمان من رخصة القيادة التجارية بسبب مخالفتين مروريتين خطيرتين خلال 3 سنوات في مركبة تجارية؟","options":["60 يوماً","120 يوماً","30 يوماً","سنة واحدة"],"explanation":"مخالفتان مروريتان خطيرتان خلال 3 سنوات تستوجبان الحرمان لمدة 60 يوماً."},"153":{"q":"على طريق باتجاه واحد أو طريق مقسوم، تُوضع مثلثات التحذير الثلاثة على بُعد 10 أقدام و100 قدم وما المسافة الثالثة؟","options":["200 قدم","250 قدماً","150 قدماً","300 قدم"],"explanation":"على طريق باتجاه واحد أو طريق مقسوم تُوضع المثلثات على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة."},"154":{"q":"المركبات المصنوعة بعد أي سنة يجب أن تكون مزودة بأضواء إشارة انعطاف كهربائية؟","options":["1959","1960","1972","1955"],"explanation":"جميع المركبات المصنوعة بعد عام 1959 يجب أن تحتوي على إشارات انعطاف كهربائية."},"155":{"q":"استثناء إشارة الانعطاف لما قبل عام 1960 ينطبق فقط على سيارات الركاب أو الشاحنات التي يقل عرضها عن كم؟","options":["80 إنشاً","102 إنش","96 إنشاً","60 إنشاً"],"explanation":"ينطبق الاستثناء فقط على المركبات التي يقل عرضها عن 80 إنشاً."},"156":{"q":"كم عدد المصابيح الخلفية المطلوبة في معظم المركبات الآلية والمقطورات وأنصاف المقطورات ومقطورات الأعمدة؟","options":["اثنان","واحد","ثلاثة","أربعة"],"explanation":"يُطلب وجود مصباحين خلفيين على الأقل في معظم هذه المركبات."},"157":{"q":"الدراجات النارية والدراجات المُحرَّكة والدراجات النارية الصغيرة تحتاج إلى كم مصباحاً خلفياً على الأقل؟","options":["واحد","اثنان","ثلاثة","أربعة"],"explanation":"الدراجات النارية والدراجات المُحرَّكة والدراجات النارية الصغيرة تحتاج إلى مصباح خلفي واحد فقط."},"158":{"q":"تُقاس عواكس المركبات المصنوعة قبل 1 يناير 1972 من حيث الرؤية تحت أي شعاع للمصباح الأمامي؟","options":["الشعاع العلوي","الشعاع السفلي","مصباح الضباب","مصباح الوقوف"],"explanation":"تُقاس عواكس ما قبل 1972 تحت المصابيح الأمامية ذات الشعاع العلوي."},"159":{"q":"عواكس المركبات المصنوعة قبل 1 يناير 1972 يجب أن تكون مرئية ليلاً من جميع المسافات ضمن أي مدى؟","options":["من 600 قدم إلى 100 قدم","من 1,000 قدم إلى 500 قدم","من 300 قدم إلى 50 قدماً","من 800 قدم إلى 200 قدم"],"explanation":"يجب أن تكون مرئية من 600 قدم إلى 100 قدم تحت المصابيح الأمامية ذات الشعاع العلوي."},"160":{"q":"أثناء عبور سكة الحديد، ما الذي يجب ألا تفعله الحافلة أو المركبة الحاملة للوحات المواد الخطرة أبداً؟","options":["تبديل التروس","استخدام المكابح","إطلاق البوق","تشغيل الأضواء الوامضة"],"explanation":"يجب على هذه المركبات ألا تبدل التروس أبداً أثناء عبور السكة."},"161":{"q":"الحافلات والمركبات الحاملة للوحات المواد الخطرة يجب أن تتوقف ضمن أي مدى قبل سكة الحديد؟","options":["من 15 إلى 50 قدماً","من 5 إلى 25 قدماً","من 50 إلى 100 قدم","من 10 إلى 40 قدماً"],"explanation":"يجب أن تتوقف من 15 إلى 50 قدماً قبل السكة."},"162":{"q":"بموجب قانون التغيير للمسار / تخفيف السرعة، عندما لا تستطيع تغيير المسار يجب أن تخفف السرعة إلى كم تحت حد السرعة؟","options":["20 ميلاً في الساعة تحت الحد","10 أميال في الساعة تحت الحد","30 ميلاً في الساعة تحت الحد","15 ميلاً في الساعة تحت الحد"],"explanation":"إذا لم تستطع التغيير للمسار الآخر، خفف السرعة إلى 20 ميلاً في الساعة تحت الحد."},"163":{"q":"بموجب قانون التغيير للمسار / تخفيف السرعة، ما السرعة التي يجب أن تخفف إليها حيث يكون الحد 25 ميلاً في الساعة أو أقل؟","options":["5 أميال في الساعة","20 ميلاً في الساعة","10 أميال في الساعة","15 ميلاً في الساعة"],"explanation":"حيث يكون الحد 25 أو أقل، خفف السرعة إلى 5 أميال في الساعة إذا لم تستطع تغيير المسار."},"164":{"q":"المصابيح الأمامية مطلوبة حتى كم من الوقت قبل شروق الشمس؟","options":["30 دقيقة","60 دقيقة","15 دقيقة","45 دقيقة"],"explanation":"المصابيح الأمامية مطلوبة حتى 30 دقيقة قبل شروق الشمس."},"165":{"q":"يجب استخدام المصابيح الأمامية كلما تعذرت عليك الرؤية بوضوح لمسافة لا تقل عن كم؟","options":["1,000 قدم","500 قدم","600 قدم","1,500 قدم"],"explanation":"المصابيح الأمامية مطلوبة عندما لا تستطيع الرؤية بوضوح لمسافة لا تقل عن 1,000 قدم."},"166":{"q":"الحد الأدنى للمسؤولية في تكساس عن الإصابة الجسدية لشخص واحد كم يبلغ؟","options":["30,000 دولار","60,000 دولار","25,000 دولار","50,000 دولار"],"explanation":"الحد الأدنى هو 30,000 دولار للإصابة الجسدية لشخص واحد."},"167":{"q":"كم عدد المركبات التي يمكن ربطها في تركيبة واحدة دون تصريح خاص؟","options":["3","2","4","5"],"explanation":"يمكن ربط 3 مركبات كحد أقصى."}},"learn-airbrakes":{"0":{"q":"ما هي أنظمة الكبح الثلاثة المدمجة في نظام الكبح الهوائي؟","options":["الخدمة، والركن، والطوارئ","الخدمة، والركن، والهيدروليكي","الأساسي، والثانوي، والطوارئ","الخدمة، والزنبرك، والتعديل"],"explanation":"يجمع نظام الكبح الهوائي بين ثلاثة أنظمة: مكابح الخدمة، ومكابح الركن، ومكابح الطوارئ."},"1":{"q":"كم عدد الأنظمة الهوائية المنفصلة التي يحتوي عليها نظام الكبح الهوائي المزدوج؟","options":["واحد","اثنان","ثلاثة","أربعة"],"explanation":"يحتوي نظام الكبح الهوائي المزدوج على نظامين هوائيين منفصلين، أساسي وثانوي، مع مجموعة واحدة من أدوات التحكم."},"2":{"q":"قبل قيادة مركبة بنظام كبح هوائي مزدوج، اترك الضغط يتراكم في كلا النظامين إلى أي نقطة؟","options":["نقطة بدء عمل المنظم","تحذير انخفاض الهواء","نقطة توقف المنظم","فتح صمام الأمان"],"explanation":"قبل قيادة مركبة بنظام كبح هوائي مزدوج، اترك الضغط يتراكم حتى نقطة توقف المنظم في كلا النظامين."},"3":{"q":"عند أي ضغط تقريباً يتوقف منظم ضاغط الهواء عن ضخ الهواء؟","options":["60 psi","100 psi","150 psi","125 psi"],"explanation":"تقوم نقطة توقف منظم ضاغط الهواء بإيقاف الضاغط عن ضخ الهواء عند حوالي 125 psi."},"4":{"q":"عند أي ضغط هواء تقريباً يبدأ المنظم العمل ويستأنف ضخ الهواء؟","options":["100 psi","125 psi","60 psi","150 psi"],"explanation":"تستأنف نقطة بدء عمل المنظم ضخ الضاغط للهواء عند حوالي 100 psi."},"5":{"q":"عند أي ضغط تقريباً يُفتح صمام تخفيف الأمان؟","options":["100 psi","150 psi","125 psi","60 psi"],"explanation":"صمام تخفيف الأمان في خزان الإمداد (الرطب) مضبوط ليُفتح عند حوالي 150 psi."},"6":{"q":"يجب أن يضيء تحذير انخفاض ضغط الهواء قبل أن ينخفض الضغط دون كم psi؟","options":["100 psi","45 psi","60 psi","125 psi"],"explanation":"يجب أن يضيء تحذير انخفاض ضغط الهواء قبل أن ينخفض ضغط الهواء دون 60 psi."},"7":{"q":"عند أي ضغط هواء تعمل مكابح الزنبرك تلقائياً؟","options":["60–85 psi","85–100 psi","100–125 psi","20–45 psi"],"explanation":"تعمل مكابح الزنبرك تلقائياً عندما ينخفض ضغط الهواء إلى نطاق 20–45 psi."},"8":{"q":"في نظام الكبح الهوائي المزدوج، يجب أن يتراكم الضغط من 85 إلى 100 psi في غضون كم ثانية؟","options":["45 ثانية","60 ثانية","30 ثانية","20 ثانية"],"explanation":"في النظام المزدوج، يجب أن يتراكم ضغط الهواء من 85 إلى 100 psi في غضون 45 ثانية."},"9":{"q":"يُفحص معدل تسرب الهواء والنظام مشحون بالكامل إلى أي ضغط تقريباً؟","options":["100 psi","125 psi","150 psi","60 psi"],"explanation":"يُفحص معدل تسرب الهواء والمحرك متوقف والنظام مشحون بالكامل إلى حوالي 125 psi."},"10":{"q":"مع تحرير المكابح، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مفردة؟","options":["1 psi/دقيقة","4 psi/دقيقة","2 psi/دقيقة","3 psi/دقيقة"],"explanation":"مع تحرير المكابح، يجب ألا تتسرب المركبة المفردة أكثر من 2 psi في الدقيقة."},"11":{"q":"مع تحرير المكابح، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مركّبة؟","options":["1 psi/دقيقة","2 psi/دقيقة","4 psi/دقيقة","3 psi/دقيقة"],"explanation":"مع تحرير المكابح، يجوز أن تتسرب المركبة المركّبة بما لا يزيد عن 3 psi في الدقيقة."},"12":{"q":"مع الضغط على المكابح، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مفردة؟","options":["3 psi في الدقيقة","2 psi في الدقيقة","4 psi في الدقيقة","5 psi في الدقيقة"],"explanation":"مع الضغط على المكابح، يجب ألا يزيد تسرب الهواء للمركبة المفردة عن 3 psi في الدقيقة."},"13":{"q":"مع الضغط على المكابح، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مركّبة؟","options":["3 psi/دقيقة","4 psi/دقيقة","5 psi/دقيقة","6 psi/دقيقة"],"explanation":"مع الضغط على المكابح، يجوز أن تتسرب المركبة المركّبة بما لا يزيد عن 4 psi في الدقيقة."},"14":{"q":"عند أي سرعة تقريباً تُجري اختبار توقف مكابح الخدمة؟","options":["10 mph","15 mph","5 mph","20 mph"],"explanation":"لاختبار توقف مكابح الخدمة، قُد بسرعة حوالي 5 mph، واضغط على المكابح، ويجب أن تتوقف المركبة بشكل مستقيم مع دواسة ثابتة."},"15":{"q":"أي اختبار يُعد جزءاً من فحص المكابح الهوائية قبل الرحلة؟","options":["عمق مداس الإطار","مستوى سائل التبريد","تصويب المصابيح الأمامية","اختبار التوقف عند 5 mph"],"explanation":"يتضمن فحص المكابح الهوائية قبل الرحلة اختبار التوقف عند 5 mph للتأكد من أن المكابح تعمل وتشعر بأنها ثابتة."},"16":{"q":"كم تبلغ مدة تأخر الكبح تقريباً في نظام الكبح الهوائي؟","options":["1/2 ثانية","1 ثانية","2 ثانية","1/4 ثانية"],"explanation":"تتمتع المكابح الهوائية بتأخر كبح يبلغ حوالي 1/2 ثانية، وهو الوقت اللازم لمرور الهواء عبر الخطوط."},"17":{"q":"ما هي مسافة تأخر الكبح المضافة عند سرعة 55 mph؟","options":["22 قدماً","32 قدماً","42 قدماً","52 قدماً"],"explanation":"عند سرعة 55 mph، تضيف المكابح الهوائية حوالي 32 قدماً من مسافة تأخر الكبح إلى إجمالي مسافة التوقف لديك."},"18":{"q":"عند سرعة 55 mph، كم تبلغ مسافة تأخر الكبح المضافة تقريباً؟","options":["20 قدماً","45 قدماً","32 قدماً","60 قدماً"],"explanation":"عند سرعة 55 mph تبلغ مسافة تأخر الكبح المضافة حوالي 32 قدماً."},"19":{"q":"كم مرة يجب عليك تصريف خزانات الهواء؟","options":["مرة في الشهر","مرة في الأسبوع","عند كل تغيير زيت","كل يوم"],"explanation":"صرّف خزانات الهواء يومياً لإزالة الماء والزيت ومنع التجمد والتلف."},"20":{"q":"ما هو العيب الأكثر شيوعاً في المكابح الهوائية؟","options":["المكابح غير المضبوطة","خطوط الهواء المتجمدة","أسطوانات المكابح البالية","ضاغط الهواء المتسرب"],"explanation":"المكابح غير المضبوطة هي العيب الأكثر شيوعاً في المكابح الهوائية."},"21":{"q":"ماذا يقلل الحركة المفرطة لقضيب الدفع (الخلوص الحر)؟","options":["تراكم ضغط الهواء","قوة الكبح","زمن تأخر الكبح","تراكم الماء في الخزان"],"explanation":"الحركة المفرطة لقضيب الدفع (الخلوص الحر) تعني أن المكابح غير مضبوطة، مما يقلل من قوة الكبح."},"22":{"q":"ما هو لون وشكل مقبض التحكم بمكابح الركن؟","options":["مثمن أحمر","دائري أزرق","معيّن أصفر","مربع أخضر"],"explanation":"التحكم بمكابح الركن هو مقبض أصفر على شكل معيّن تدفعه للداخل للتحرير وتسحبه للخارج للتفعيل."},"23":{"q":"ما هو شكل مقبض التحكم بإمداد الهواء للمقطورة؟","options":["دائري","على شكل معيّن","مربع","ثماني الأضلاع (مثمن)"],"explanation":"التحكم بإمداد الهواء للمقطورة هو مقبض أحمر ثماني الأضلاع (مثمن)."},"24":{"q":"أي صمام يسمح لك بتطبيق فرامل الزنبرك تدريجياً في حالة الطوارئ؟","options":["صمام التحكم المعدّل (المتغير)","صمام تنفيس الأمان","صمام قطع المنظّم","صمام إمداد هواء المقطورة"],"explanation":"يتيح لك صمام التحكم المعدّل تطبيق فرامل الزنبرك تدريجياً في حالة الطوارئ."},"25":{"q":"على منحدر طويل، ماذا يجب ألا تفعله بالفرامل؟","options":["استخدام غيار منخفض","تحريكها أو ضخّها بشكل متقطّع","الكبح الخفيف والثابت","تحريرها عند سرعة آمنة"],"explanation":"لا تحرّك الفرامل أو تضخّها بشكل متقطّع على منحدر طويل لأن ذلك يؤدي إلى انخفاض ضغط الهواء واستنزاف هوائك."},"26":{"q":"على منحدر طويل، حرّر الفرامل عندما تنخفض سرعتك بنحو كم تحت سرعتك الآمنة؟","options":["20 ميلاً في الساعة تحتها","10 أميال في الساعة تحتها","5 أميال في الساعة تحتها","2 ميل في الساعة تحتها"],"explanation":"على منحدر طويل، استخدم كبحاً خفيفاً وثابتاً وحرّر الفرامل عند نحو 5 أميال في الساعة تحت سرعتك الآمنة."},"27":{"q":"في توقف طارئ بدون نظام ABS، أي طريقة كبح يجب أن تستخدمها؟","options":["الكبح بالضخّ","تحريك الفرامل بشكل متقطّع","قفل العجلات","الكبح المتحكَّم به أو الكبح المتقطّع (stab braking)"],"explanation":"في حالة طوارئ بدون نظام ABS، استخدم الكبح المتحكَّم به أو الكبح المتقطّع ولا تقفل العجلات."},"28":{"q":"متى يجب أن تتجنّب تطبيق فرامل التوقف (فرامل الزنبرك)؟","options":["عندما تكون الفرامل ساخنة جداً","عندما تكون الفرامل باردة","عندما تكون الفرامل جافة","عندما تكون الخزانات مُفرَّغة"],"explanation":"لا تطبّق فرامل التوقف عندما تكون الفرامل ساخنة جداً، لأن الفرامل الساخنة قد تتعرّض للتلف."},"29":{"q":"متى يجب ألا تطبّق فرامل التوقف (فرامل الزنبرك)؟","options":["عندما تكون الفرامل جافة","عندما تكون مبتلّة في درجات حرارة متجمّدة","عندما تكون مُحرَّرة بالكامل","عندما تكون الخزانات مُفرَّغة"],"explanation":"لا تطبّق فرامل التوقف إذا كانت مبتلّة في درجات حرارة متجمّدة، لأن الفرامل المبتلّة قد تتجمّد."},"30":{"q":"نظام ABS مطلوب في الجرّارات المصنوعة في أو بعد أي تاريخ؟","options":["1 مارس 1995","1 مارس 1996","1 مارس 1997","1 مارس 1998"],"explanation":"نظام ABS مطلوب في الجرّارات المصنوعة في أو بعد 1 مارس 1997."},"31":{"q":"يجب أن تحتوي المقطورات والحافلات ذات الفرامل الهوائية على نظام ABS إذا صُنعت في أو بعد أي تاريخ؟","options":["1 مارس 1996","1 مارس 1997","1 مارس 1999","1 مارس 1998"],"explanation":"نظام ABS مطلوب في المقطورات والحافلات وغيرها من مركبات الفرامل الهوائية المصنوعة في أو بعد 1 مارس 1998."},"32":{"q":"ماذا يفعل نظام ABS عندما تكبح بقوة؟","options":["يتيح لك التوجيه","يقصّر مسافة التوقف","يضخّ خزانات الهواء","يرفع ضغط الهواء"],"explanation":"لا يقصّر نظام ABS مسافة التوقف؛ بل يمنع العجلات من القفل حتى تتمكّن من التوجيه أثناء الكبح بقوة."},"33":{"q":"لتحرير فرامل التوقف، ماذا تفعل بمقبض التحكم؟","options":["تدفعه للداخل","تسحبه للخارج","تديره يساراً","تضغطه للأسفل"],"explanation":"ادفع مقبض التحكم بفرامل التوقف للداخل لتحرير الفرامل واسحبه للخارج لتطبيقها."},"34":{"q":"ما لون مقبض التحكم بإمداد هواء المقطورة؟","options":["أزرق","أحمر","أصفر","أخضر"],"explanation":"مقبض التحكم بإمداد هواء المقطورة لونه أحمر."},"35":{"q":"إجمالي مسافة التوقف في الفرامل الهوائية هو مجموع أي أربع مسافات؟","options":["مسافة الإدراك + رد الفعل + الكبح + التوجيه","مسافة رد الفعل + تأخّر الفرامل + الكبح + الانزلاق","مسافة الإدراك + رد الفعل + تأخّر الفرامل + الكبح","مسافة الإدراك + رد الفعل + الكبح + التتابع (المسافة الآمنة)"],"explanation":"إجمالي مسافة التوقف في الفرامل الهوائية = مسافة الإدراك + مسافة رد الفعل + مسافة تأخّر الفرامل + مسافة الكبح الفعّالة."},"36":{"q":"عند فحص معدّل تسرّب الهواء، يجب أن يكون المحرّك:","options":["في وضع الخمول","مرفوع الدوران","في طور الإحماء","متوقّفاً"],"explanation":"يُفحص معدّل تسرّب الهواء والمحرّك متوقّف."},"37":{"q":"في اختبار توقف فرامل الخدمة، كيف يجب أن تتوقّف المركبة وكيف يجب أن تكون الدوّاسة عند الضغط؟","options":["تتوقّف بشكل مستقيم دون انحراف، والدوّاسة تبدو ثابتة","تتوقّف بشكل مستقيم دون انحراف، والدوّاسة تبدو لينة","تنحرف إلى جانب واحد، والدوّاسة تبدو ثابتة","تنحرف إلى جانب واحد، والدوّاسة تبدو لينة"],"explanation":"في اختبار توقف فرامل الخدمة، يجب أن تتوقّف المركبة دون أن تنحرف إلى جانب واحد، ويجب أن تبدو الدوّاسة ثابتة."},"38":{"q":"على منحدر طويل، ما هي تقنية الكبح الصحيحة؟","options":["ضخّ الفرامل بشكل متكرّر","استخدام غيار منخفض مع كبح خفيف وثابت","الضغط على الفرامل بقوة طوال الطريق","الانزلاق في الوضع المحايد والكبح بقوة عند الأسفل"],"explanation":"على منحدر طويل، استخدم غياراً منخفضاً مع كبح خفيف وثابت، محرّراً الفرامل عند نحو 5 أميال في الساعة تحت سرعتك الآمنة ثم أعد تطبيقها."},"39":{"q":"على منحدر طويل، ماذا يمكن أن يحدث عند تحريك الفرامل أو ضخّها بشكل متقطّع؟","options":["تبريد أسطوانات الفرامل بشكل أسرع","تحسين تحكّمك في التوجيه","انخفاض ضغط الهواء واستنزاف هوائك","إعادة شحن خزانات الهواء بسرعة"],"explanation":"تحريك الفرامل أو ضخّها بشكل متقطّع يؤدي إلى انخفاض ضغط الهواء ويمكن أن يستنزف هوائك."},"40":{"q":"لماذا يجب تفريغ خزانات الهواء يومياً؟","options":["لإعادة شحن البطارية","لتبريد زيت المحرّك","لرفع ضغط الهواء بشكل أسرع","لإزالة الماء والزيت اللذين يمكن أن يتجمّدا ويسبّبا تلفاً"],"explanation":"يتجمّع الماء وزيت الضاغط في خزانات الهواء، وتفريغها يمنع التجمّد والتلف."},"41":{"q":"كيف يمكن تفريغ خزانات الهواء؟","options":["بواسطة صمامات تفريغ يدوية أو أوتوماتيكية","بواسطة صمام قطع المنظّم","بواسطة تحذير انخفاض ضغط الهواء","بواسطة صمام تنفيس الأمان"],"explanation":"يمكن تفريغ خزانات الهواء بواسطة صمامات تفريغ يدوية أو أوتوماتيكية."},"42":{"q":"كم عدد أنظمة الكبح المدمجة في نظام الفرامل الهوائية؟","options":["ثلاثة","اثنان","أربعة","خمسة"],"explanation":"نظام الفرامل الهوائية هو في الواقع ثلاثة أنظمة كبح مدمجة: فرامل الخدمة، وفرامل التوقف، وفرامل الطوارئ."},"43":{"q":"ماذا يُطلق على النظامين الهوائيين المنفصلين في نظام الفرامل الهوائية المزدوج؟","options":["الأمامي والخلفي","الأساسي والثانوي","العلوي والسفلي","الأيسر والأيمن"],"explanation":"يحتوي نظام الفرامل الهوائية المزدوج على نظامين هوائيين منفصلين يُسمّيان الأساسي والثانوي، مع مجموعة واحدة من أدوات التحكم."},"44":{"q":"كم عدد مجموعات أدوات التحكم في نظام الفرامل الهوائية المزدوج؟","options":["ثلاث مجموعات","أربع مجموعات","مجموعة واحدة","مجموعتان"],"explanation":"يحتوي نظام الفرامل الهوائية المزدوج على نظامين هوائيين منفصلين لكن مجموعة واحدة فقط من أدوات التحكم."},"45":{"q":"عند نحو 125 psi، ماذا يفعل منظّم ضاغط الهواء؟","options":["يقطع الدخول (يستأنف الضخّ)","يفتح صمام تنفيس الأمان","يشغّل تحذير انخفاض الهواء","يقطع الخروج (يوقف الضخّ)"],"explanation":"قطع الخروج للمنظّم يوقف الضاغط عن ضخّ الهواء عند نحو 125 psi."},"46":{"q":"يستأنف المنظّم ضخّ الهواء عند نحو 100 psi. ماذا تُسمّى هذه النقطة؟","options":["قطع الدخول (Cut-in)","قطع الخروج (Cut-out)","نقطة التنفيس","التراكم (Build-up)"],"explanation":"النقطة التي يستأنف عندها المنظّم ضخّ الهواء، عند نحو 100 psi، تُسمّى قطع الدخول (Cut-in)."},"47":{"q":"أين يقع صمام تنفيس الأمان؟","options":["في دوّاسة الفرامل","في خزان الإمداد (الخزان الرطب)","في المنظّم","في مقبض فرامل التوقف"],"explanation":"يقع صمام تنفيس الأمان في خزان الإمداد (الخزان الرطب) ويفتح عند نحو 150 psi."},"48":{"q":"مِمَّ يتكوّن عادةً تحذير انخفاض ضغط الهواء؟","options":["ضوء فقط","جرس (صفّارة) فقط","ضوء وجرس (صفّارة)","مقياس فقط"],"explanation":"يتكوّن تحذير انخفاض ضغط الهواء عادةً من ضوء وجرس (صفّارة)."},"49":{"q":"ماذا يحدث عندما ينخفض ضغط الهواء إلى النطاق بين 20 و45 psi؟","options":["يتوقف تحذير انخفاض الهواء","يتوقف ضاغط الهواء عن الضخ","يفتح صمام تنفيس الأمان","تنطبق فرامل النابض تلقائيًا"],"explanation":"تنطبق فرامل النابض (الطوارئ/الانتظار) تلقائيًا عندما ينخفض ضغط الهواء إلى النطاق بين 20 و45 psi."},"50":{"q":"بحدود كم ينخفض ضغط الهواء بين قطع المنظِّم ووصله؟","options":["حوالي 25 psi","حوالي 50 psi","حوالي 10 psi","حوالي 75 psi"],"explanation":"يقطع المنظِّم عند حوالي 125 psi ويصل عند حوالي 100 psi، أي بانخفاض قدره حوالي 25 psi."},"51":{"q":"في نظام فرامل هوائية مزدوج، يجب أن يرتفع الضغط إلى أي نطاق خلال 45 ثانية؟","options":["60 إلى 85 psi","85 إلى 100 psi","100 إلى 125 psi","45 إلى 60 psi"],"explanation":"في النظام المزدوج، يجب أن يرتفع ضغط الهواء من 85 إلى 100 psi خلال 45 ثانية."},"52":{"q":"مع تحرير الفرامل، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مفردة مقابل مركبة مركّبة؟","options":["1 psi/دقيقة للمفردة، 2 psi/دقيقة للمركّبة","3 psi/دقيقة للمفردة، 4 psi/دقيقة للمركّبة","2 psi/دقيقة للمفردة، 3 psi/دقيقة للمركّبة","2 psi/دقيقة للمفردة، 4 psi/دقيقة للمركّبة"],"explanation":"مع تحرير الفرامل، يجب ألا يتجاوز تسرب الهواء 2 psi في الدقيقة للمركبة المفردة و3 psi في الدقيقة للمركبة المركّبة."},"53":{"q":"مع انطباق الفرامل، ما هو الحد الأقصى لمعدل تسرب الهواء لمركبة مفردة مقابل مركبة مركّبة؟","options":["2 psi/دقيقة للمفردة، 3 psi/دقيقة للمركّبة","4 psi/دقيقة للمفردة، 3 psi/دقيقة للمركّبة","2 psi/دقيقة للمفردة، 4 psi/دقيقة للمركّبة","3 psi/دقيقة للمفردة، 4 psi/دقيقة للمركّبة"],"explanation":"مع انطباق الفرامل، يجب أن يبقى تسرب الهواء عند أو دون 3 psi/دقيقة للمركبة المفردة و4 psi/دقيقة للمركبة المركّبة."},"54":{"q":"بالنسبة لمركبة مفردة، ما هي الحدود القصوى لمعدلات تسرب الهواء مع تحرير الفرامل مقابل انطباقها؟","options":["محررة 2 psi/دقيقة؛ منطبقة 3 psi/دقيقة","محررة 3 psi/دقيقة؛ منطبقة 4 psi/دقيقة","محررة 2 psi/دقيقة؛ منطبقة 4 psi/دقيقة","محررة 3 psi/دقيقة؛ منطبقة 2 psi/دقيقة"],"explanation":"بالنسبة لمركبة مفردة، يجب ألا يتجاوز تسرب الهواء 2 psi في الدقيقة مع تحرير الفرامل و3 psi في الدقيقة مع انطباقها."},"55":{"q":"للتحقق من معدل تسرب الهواء، ما هما الشرطان المطلوبان للإعداد؟","options":["المحرك يعمل والفرامل منطبقة","المحرك متوقف والنظام مشحون بالكامل","المحرك متوقف والخزانات مفرّغة بالكامل","المحرك يعمل والنظام مشحون بالكامل"],"explanation":"يُجرى اختبار تسرب الهواء الصحيح مع توقف المحرك وشحن النظام بالكامل (حوالي 125 psi)."},"56":{"q":"أي مما يلي يُعد فحصًا للفرامل الهوائية قبل الرحلة؟","options":["فحص محاذاة العجلات","فحص ضغط الإطارات","اختبار تثبيت فرامل الانتظار","فحص جهد البطارية"],"explanation":"تشمل فحوصات الفرامل الهوائية قبل الرحلة اختبار قدرة فرامل الانتظار على تثبيت المركبة."},"57":{"q":"أثناء فحص الفرامل الهوائية قبل الرحلة، ماذا يجب أن تتحقق من حدوثه مع فرامل النابض؟","options":["أنها تتحرر عند 60 psi","أنها تبقى متوقفة عند انخفاض الهواء","أنها لا تحتاج إلى هواء للعمل","أنها تنشط (تنطبق)"],"explanation":"يشمل فحص الفرامل الهوائية قبل الرحلة التحقق من أن فرامل النابض تنشط."},"58":{"q":"لماذا يوجد تأخير في الفرامل الهوائية؟","options":["يستغرق الهواء وقتًا للانتقال عبر الخطوط","تعود دواسة الفرامل ببطء إلى موضعها","تحتاج العجلات إلى وقت للإحماء أولًا","يجب أن يقلل المحرك سرعته أولًا"],"explanation":"تتأخر الفرامل الهوائية حوالي نصف ثانية لأن الهواء يستغرق وقتًا للانتقال عبر خطوط الفرامل."},"59":{"q":"أي مسافة تُضاف إلى مسافة التوقف الكلية بسبب الفرامل الهوائية؟","options":["مسافة الإدراك","مسافة تأخير الفرامل","مسافة رد الفعل","مسافة الكبح الفعّالة"],"explanation":"تضيف الفرامل الهوائية مسافة تأخير الفرامل إلى مسافة التوقف الكلية لأن الهواء يستغرق وقتًا للانتقال عبر الخطوط."},"60":{"q":"ما الذي يتجمع في خزانات الهواء ويستلزم تفريغها يوميًا؟","options":["سائل الفرامل والغبار","سائل التبريد والوقود","الماء وزيت الضاغط","الشحم والأوساخ"],"explanation":"يتجمع الماء وزيت الضاغط في خزانات الهواء، لذا يجب تفريغها يوميًا."},"61":{"q":"أي أجزاء الفرامل الهوائية معنية عندما تكون الفرامل \"خارج الضبط\"؟","options":["المنظِّم وصمام تنفيس الأمان","الضاغط وخزانات الهواء","المقبضان الأصفر والأحمر","ضوابط التراخي وحركة قضيب الدفع"],"explanation":"تتعلق الفرامل الخارجة عن الضبط بضوابط التراخي وحركة قضيب الدفع، وهي العيب الأكثر شيوعًا في الفرامل الهوائية."},"62":{"q":"أي حالة تقلل قوة الكبح بسبب خروج الفرامل عن الضبط؟","options":["حركة مفرطة لقضيب الدفع (خلوص زائد)","انخفاض مستوى زيت المحرك","خزان هواء ممتلئ زيادة عن الحد","ماسحة زجاج أمامي بالية"],"explanation":"تعني الحركة المفرطة لقضيب الدفع (الخلوص الزائد) أن الفرامل خارجة عن الضبط، مما يقلل قوة الكبح."},"63":{"q":"لتطبيق فرامل الانتظار، ماذا تفعل بالمقبض؟","options":["تدير المقبض","تسحب المقبض للخارج","تدفع المقبض للداخل","تضغط المقبض للأسفل"],"explanation":"تسحب المقبض الأصفر ذا الشكل المعيّن للخارج لتطبيق فرامل الانتظار (وتدفعه للداخل للتحرير)."},"64":{"q":"أي مقبض أحمر وثماني الأضلاع (مثمّن)؟","options":["مقبض فرامل الانتظار الأصفر","مقبض الانتظار ذو الشكل المعيّن","مقبض إمداد هواء المقطورة","دواسة قدم الفرامل الخدمية"],"explanation":"ضابط إمداد هواء المقطورة مقبض أحمر ثماني الأضلاع (مثمّن)، بينما ضابط فرامل الانتظار مقبض أصفر ذو شكل معيّن."},"65":{"q":"المقبض الأصفر ذو الشكل المعيّن يتحكم في أي فرامل؟","options":["إمداد هواء المقطورة","الفرامل الخدمية","فرامل الطوارئ","فرامل الانتظار"],"explanation":"ضابط فرامل الانتظار مقبض أصفر ذو شكل معيّن."},"66":{"q":"على منحدر طويل، بعد أن تحرر الفرامل، ماذا يجب أن تفعل بعد ذلك؟","options":["تعيد تطبيق الفرامل","تنتقل إلى ترس أعلى","تضغط القابض","تضخ الفرامل بسرعة"],"explanation":"على المنحدر تحرر الفرامل عند حوالي 5 mph دون سرعتك الآمنة، ثم تعيد تطبيقها."},"67":{"q":"لماذا يجب تجنب تطبيق فرامل الانتظار (النابض) عندما تكون الفرامل ساخنة جدًا؟","options":["سينخفض ضغط الهواء بسرعة كبيرة","قد تتلف الفرامل الساخنة","سيتوقف جرس التحذير عن العمل","ستنفصل المقطورة"],"explanation":"لا تطبّق فرامل الانتظار (النابض) عندما تكون الفرامل ساخنة جدًا لأن الفرامل الساخنة قد تتلف."},"68":{"q":"ماذا قد يحدث إذا طبّقت فرامل الانتظار (النابض) وهي مبتلة في درجات حرارة التجمد؟","options":["ستتوقف بشكل أسرع","ستتحرر ببطء","قد تتجمد","ستبني ضغط الهواء"],"explanation":"قد تتجمد الفرامل المبتلة في درجات حرارة التجمد إذا طُبّقت فرامل الانتظار (النابض)."},"69":{"q":"أي مما يلي لا يفعله نظام ABS؟","options":["يمنع العجلات من الانغلاق","يتيح لك التوجيه أثناء الكبح الشديد","يساعدك على تجنب الانزلاق في الكبح الشديد","يقصّر مسافة التوقف الكلية"],"explanation":"لا يقصّر نظام ABS مسافة التوقف؛ بل يمنع العجلات من الانغلاق حتى تتمكن من التوجيه أثناء الكبح الشديد."},"70":{"q":"أي المركبات كان لها تاريخ اشتراط ABS الأبكر؟","options":["الجرارات (1 مارس 1997)","المقطورات (1 مارس 1997)","الحافلات (1 مارس 1997)","المقطورات (1 مارس 1998)"],"explanation":"اشتُرط نظام ABS على الجرارات المصنوعة في/بعد 1 مارس 1997، بينما جاءت المقطورات والحافلات بعد عام واحد في 1 مارس 1998."},"71":{"q":"نظام الفرامل الهوائية هو في الواقع كم نظامًا منفصلًا؟","options":["واحد","اثنان","ثلاثة","أربعة"],"explanation":"ثلاثة: الخدمية والانتظار والطوارئ."},"72":{"q":"يوقف المنظِّم الضاغط (القطع) عند حوالي:","options":["100 psi","110 psi","125 psi","150 psi"],"explanation":"يكون القطع عادة حول 125 psi (والوصل حول 100 psi)."},"73":{"q":"يسمح المنظِّم للضاغط بالبدء من جديد (الوصل) عند حوالي:","options":["60 psi","100 psi","140 psi","150 psi"],"explanation":"يكون الوصل عند حوالي 100 psi."},"74":{"q":"عادةً ما يفتح صمام تنفيس الأمان عند:","options":["100 psi","125 psi","150 psi","200 psi"],"explanation":"يفتح عند نحو 150 psi لحماية النظام."},"75":{"q":"يجب أن يعمل تحذير انخفاض الهواء قبل أن ينخفض الضغط دون:","options":["40 psi","55 psi","60 psi","80 psi"],"explanation":"قبل 60 psi (دليل تكساس)."},"76":{"q":"تُطبَّق فرامل الزنبرك (الطوارئ) تلقائيًا عند نحو:","options":["5–10 psi","20–45 psi","60 psi","100 psi"],"explanation":"تعمل عند نحو 20–45 psi."},"77":{"q":"تُسمى دواسة الفرامل في النظام الهوائي أيضًا:","options":["المنظِّم (Governor)","صمام القدم (الدواسة)","ضابط الخَلَل (Slack adjuster)","وصلة الهواء (Glad hand)"],"explanation":"يرسل صمام القدم/الدواسة الهواء إلى الفرامل."},"78":{"q":"يجب تصريف خزانات الهواء لإزالة:","options":["الهواء","الماء والزيت","سائل الفرامل","سائل التبريد"],"explanation":"يتجمع الماء وبعض الزيت في الهواء المضغوط."},"79":{"q":"ما الذي يفعله مجفِّف الهواء؟","options":["يرفع الضغط","يزيل الرطوبة","يبرّد الفرامل","يحذّر من انخفاض الهواء"],"explanation":"يزيل الماء والملوّثات من الهواء."},"80":{"q":"يُظهر مقياس ضغط الإمداد:","options":["ضغط الخزان","الضغط المطبَّق على الفرامل","ضغط زيت المحرك","ضغط الإطارات"],"explanation":"يُظهر كمية الهواء الموجودة في الخزانات."},"81":{"q":"يُظهر مقياس ضغط التطبيق:","options":["ضغط خزان الهواء","الضغط المطبَّق على الفرامل","قراءة دورات المحرك (rpm)","ضغط نفخ الإطارات"],"explanation":"يُظهر مقدار الضغط الذي تطبّقه."},"82":{"q":"يؤدي الضغط على الفرامل إلى لَف الكامة على شكل S، مما:","options":["يصرّف الخزانات","يباعد بين أحذية الفرامل","يغلق المنظِّم","يرفع المقطورة"],"explanation":"تضغط الكامة على شكل S الأحذية ضد الطبلة."},"83":{"q":"يجب ألا يتحرك ضابط الخَلَل اليدوي أكثر من نحو:","options":["1 inch","3 inches","5 inches","يمكن أن يتحرك بحرية"],"explanation":"أكثر من نحو إنش واحد يعني أن الفرامل غير مضبوطة."},"84":{"q":"تأخّر الفرامل الهوائية يبلغ نحو:","options":["1/10 ثانية","1/2 ثانية","2 ثانية","5 ثوانٍ"],"explanation":"نحو نصف ثانية حتى يعمل الهواء بعد الدواسة."},"85":{"q":"تضيف مسافة التوقف بالفرامل الهوائية أي جزء إضافي؟","options":["الإدراك","رد الفعل","تأخّر الفرامل","لا شيء إضافي"],"explanation":"الإدراك + رد الفعل + تأخّر الفرامل + الكبح."},"86":{"q":"المحرك متوقف، الفرامل محرَّرة، مركبة مفردة: يجب أن يكون فقدان الهواء أقل من:","options":["2 psi/دقيقة","3 psi/دقيقة","4 psi/دقيقة","6 psi/دقيقة"],"explanation":"المفردة أقل من 2 psi/دقيقة؛ المركّبة أقل من 3."},"87":{"q":"المحرك متوقف، الفرامل محرَّرة، مركبة مركّبة: يجب أن يكون فقدان الهواء أقل من:","options":["2 psi/دقيقة","3 psi/دقيقة","4 psi/دقيقة","6 psi/دقيقة"],"explanation":"المركّبة أقل من 3 psi/دقيقة عند تحرير الفرامل."},"88":{"q":"مع تطبيق الفرامل، يجب أن تفقد المركبة المفردة أقل من:","options":["2 psi/دقيقة","3 psi/دقيقة","4 psi/دقيقة","6 psi/دقيقة"],"explanation":"عند التطبيق: المفردة أقل من 3، والمركّبة أقل من 4."},"89":{"q":"في النظام المزدوج، يجب أن يرتفع الضغط من 85 إلى 100 psi خلال:","options":["10 ثوانٍ","45 ثانية","3 دقائق","5 دقائق"],"explanation":"خلال 45 ثانية عند دورات التشغيل."},"90":{"q":"لاختبار تحذير انخفاض الهواء، عليك أن:","options":["ترفع الضغط بالضخ","تخفضه بالضغط المتكرر حتى يضيء","تصرّف كل الهواء بسرعة","تطفئ الأضواء"],"explanation":"اضغط الفرامل بشكل متكرر لخفض الهواء؛ يجب أن يضيء التحذير عند 60 psi."},"91":{"q":"لاختبار فرامل الخدمة، عليك أن:","options":["تكبح بقوة من سرعة الطريق السريع","تتحرك بسرعة 5 mph وتكبح بثبات","تختبر فرامل الانتظار فقط","تضخ عشر مرات"],"explanation":"عند 5 mph، اكبح بثبات؛ يجب أن تتوقف باستقامة دون انحراف."},"92":{"q":"تكون طبلة الفرامل غير آمنة إذا كان الشق أطول من:","options":["شعرة","نصف عرض الاحتكاك","أي طول","الطبلات لا تتشقق أبدًا"],"explanation":"الشقوق التي تتجاوز نصف عرض الاحتكاك تُخرج المركبة من الخدمة."},"93":{"q":"تكون بطانات الفرامل معيبة إذا كانت:","options":["سميكة وجافة","مشبعة بالزيت أو رقيقة جدًا","مستبدَلة حديثًا","مستقرة بشكل صحيح"],"explanation":"البطانات المرتخية أو المشبعة بالزيت أو الرقيقة بشكل خطير تكون سيئة."},"94":{"q":"على منحدر طويل، يجب أن تكون الفرامل:","options":["وسيلة التحكم الرئيسية في السرعة","مكمّلة لكبح المحرك","مضغوطة بخفة باستمرار","مضخوخة باستمرار"],"explanation":"كبح المحرك في غيار منخفض هو الأساس؛ والفرامل مكمِّلة."},"95":{"q":"في طريقة الكبح المتقطّع (snub)، عليك أن:","options":["تثبّت ضغطًا خفيفًا طوال الطريق","تكبح بثبات، ثم تحرّر، وتكرّر","تضخ بسرعة","تنزلق في الوضع المحايد"],"explanation":"اكبح حتى نحو 5 mph تحت سرعتك الآمنة، ثم حرّر، وكرّر."},"96":{"q":"الضغط المتكرر (الضخ) على الفرامل في منحدر طويل:","options":["يحافظ على الفرامل","يهدر الهواء وقد يفقد الضغط","يبني الضغط أسرع","يبرّد المحرك"],"explanation":"قد ينخفض الهواء حتى تتعطّل الفرامل؛ استخدم غيارًا منخفضًا بدلًا من ذلك."},"97":{"q":"يجب ألا تضبط فرامل الانتظار عندما:","options":["تركن طوال الليل","تكون الفرامل ساخنة جدًا","تكون على أرض مستوية","بعد رحلة قصيرة"],"explanation":"الفرامل الساخنة قد تتلف أو تتجمد؛ ضع موانع تحت العجلات."},"98":{"q":"إذا عمل تحذير انخفاض الهواء أثناء القيادة، عليك أن:","options":["تواصل حتى البلدة التالية","تتوقف وتركن بأمان في أقرب فرصة","تطفئ التحذير","تسرع لبناء الهواء"],"explanation":"قد يؤدي فقدان الهواء إلى تطبيق فرامل الزنبرك فجأة."},"99":{"q":"باستخدام نظام منع انغلاق المكابح (ABS)، تقوم بالتوقف الطارئ عن طريق:","options":["الضغط المتقطع على الدواسة","الكبح بقوة والاستمرار في الضغط","استخدام مكابح المقطورة فقط","تخفيف الضغط عند كل انزلاق"],"explanation":"اكبح بشكل كامل واستمر في التوجيه؛ يمنع نظام ABS انغلاق العجلات."},"100":{"q":"بدون نظام ABS، فإن أفضل طريقة للتوقف الحاد هي:","options":["إغلاق العجلات","الكبح المتحكم به أو الكبح بالطعن (stab braking)","الضغط حتى النهاية على الدواسة","الضغط المتقطع على عجلة القيادة"],"explanation":"امنع بقاء العجلات منغلقة حتى تتمكن من التوجيه."},"101":{"q":"في الكبح بالطعن (stab braking)، تعيد الضغط على المكابح:","options":["على الفور تقريباً","بعد أن تعود العجلات إلى الدوران","بعد حوالي 10 ثوانٍ","لا تعيد الضغط عليها أبداً"],"explanation":"خفّف الضغط عند الانغلاق؛ وأعد الضغط بمجرد عودة الدوران (خلال ثانية واحدة)."},"102":{"q":"إذا ظل مصباح عطل نظام ABS مضاءً، فإنك:","options":["لا تملك أي مكابح","تملك مكابح عادية؛ أصلح نظام ABS","يجب أن توقف المحرك","يجب أن تضغط على المكابح بشكل متقطع"],"explanation":"تفقد فقط وظيفة منع الانغلاق؛ قم بصيانته قريباً."},"103":{"q":"نظام ABS مطلوب في الجرارات الشاحنة المصنوعة في أو بعد:","options":["1995","1997","1998","2000"],"explanation":"الجرارات اعتباراً من 1997/3/1؛ والمركبات والمقطورات الأخرى اعتباراً من 1998/3/1."},"104":{"q":"إذا تعطلت إحدى دوائر النظام المزدوج أثناء القيادة:","options":["تفقد كل قدرة الكبح","لا تزال الدائرة الأخرى توقفك","يتوقف المحرك","تتعطل الأضواء فقط"],"explanation":"لا تزال الدائرة الأخرى تكبح المركبة؛ ويضيء مصباح التحذير."},"105":{"q":"لماذا تصرّف الماء من خزانات الهواء (أو تستخدم مصارف أوتوماتيكية)؟","options":["لرفع الضغط","لإزالة الماء الذي قد يتجمد","لتنظيف بطانات المكابح","لإعادة ضبط المنظم (governor)"],"explanation":"قد يتجمد الماء داخل المكابح في الطقس البارد."},"106":{"q":"قبل القيادة، اترك نظام الهواء يشحن حتى:","options":["ضغط منخفض حوالي 50 psi","المدى الطبيعي (حوالي 125 psi)","بالضبط 150 psi في كل مرة","أي مستوى ضغط تقريباً"],"explanation":"اشحن النظام حتى مدى التشغيل الطبيعي قبل التحرك."},"107":{"q":"لماذا تفحص حزام إدارة ضاغط الهواء (إذا كان يعمل بالحزام)؟","options":["إنه يشغّل راديو المقصورة بهدوء","الحزام المرتخي قد لا يبني هواءً كافياً","يساعد على تبريد مكابح العجلات","يشحن بطارية المقطورة"],"explanation":"انزلاق الحزام يعني أن الضاغط لا يستطيع مواكبة الطلب."},"108":{"q":"الفحص الكامل للمكابح الهوائية قبل الرحلة يشمل أي اختبار؟","options":["تحذير انخفاض الهواء","زمن بناء الضغط","معدل تسرب الهواء","كل ما سبق"],"explanation":"كل هذه الاختبارات جزء من فحص المكابح الهوائية."},"109":{"q":"أيٌ مما يلي ليس طريقة لاختبار المكابح الهوائية؟","options":["اختبار تسرب الهواء","زمن بناء الضغط","تصريف الرادياتير","تحذير انخفاض الهواء"],"explanation":"الرادياتير خاص بالتبريد، وليس بنظام المكابح الهوائية."},"110":{"q":"أيٌ مما يلي ليس صحيحاً عن نظام ABS؟","options":["يمنع انغلاق العجلات","يساعدك على التوجيه","يقصّر دائماً مسافة التوقف","يعمل في حالات التوقف الحاد"],"explanation":"لا يقصّر نظام ABS بالضرورة مسافة التوقف."},"111":{"q":"يتجمع الماء والزيت في خزانات الهواء، لذلك يجب أن تكون الخزانات:","options":["مطلية فوقها","مصرّفة بانتظام","مزالة بالكامل","مملوءة بالزيت"],"explanation":"صرّف الخزانات (يدوياً أو أوتوماتيكياً) لإزالة الماء والزيت اللذين يضران بالنظام."},"112":{"q":"يُدار ضاغط الهواء بواسطة:","options":["المقطورة","المحرك","السائق","الجاذبية فقط"],"explanation":"يُدير المحرك ضاغط الهواء بالحزام أو بشكل مباشر."},"113":{"q":"وظيفة مجفف الهواء هي:","options":["تبريد المقصورة","إزالة الرطوبة من الهواء","إضافة الزيت إلى الهواء","نفخ الإطارات"],"explanation":"يزيل مجفف الهواء الماء وبعض الزيت قبل وصول الهواء إلى الخزانات."},"114":{"q":"معظم المركبات الثقيلة تستخدم أي نوع من المكابح الأساسية؟","options":["مكابح دراجات صغيرة","مكابح طبلية بكامة على شكل S","ذراع مكبح يدوي","لا مكابح على الإطلاق"],"explanation":"المكابح الطبلية ذات الكامة على شكل S هي النوع الأكثر شيوعاً في المركبات ذات المكابح الهوائية."},"115":{"q":"عندما تضغط على دواسة المكابح بقوة أكبر، فإن المكابح:","options":["تصبح أضعف","تحصل على هواء وقوة أكبر","تنطلق بالكامل","تتوقف عن العمل"],"explanation":"يرسل صمام القدم (الدواسة) ضغط هواء أكبر لقوة كبح أكبر."},"116":{"q":"تأخر الكبح هو الزمن اللازم لـ:","options":["بدء تشغيل المحرك","قيام الهواء بتفعيل المكابح","تسخين الإطارات","وميض الأضواء"],"explanation":"للمكابح الهوائية تأخر يبلغ حوالي نصف ثانية قبل أن تبدأ بالعمل."},"117":{"q":"مع المكابح الهوائية، فإن مسافة التوقف الكلية تشمل أيضاً:","options":["حجم الإطار","مسافة تأخر الكبح","مستوى الوقود","زاوية المرآة"],"explanation":"أضف مسافة تأخر الكبح إلى مسافة الإدراك ورد الفعل والكبح."},"118":{"q":"لاختبار مكابح الخدمة، يجب أن:","options":["تطلق البوق مرتين","تتحرك بسرعة 5 mph وتكبح","ترفع دوران المحرك بقوة","تفتح غطاء المحرك"],"explanation":"تحرك ببطء، واضغط على المكابح، وتحسّس توقف المركبة فوراً دون انحراف."},"119":{"q":"أذرع الضبط (slack adjusters) تتحكم في:","options":["راديو المقصورة","شوط قضيب دفع المكبح","ضغط الإطارات","البوق الهوائي"],"explanation":"تضبط أذرع الضبط شوط قضيب الدفع؛ والشوط الزائد يعني أن المكابح بحاجة إلى ضبط."},"120":{"q":"صمام التصريف الذي يفرّغ الخزان من تلقاء نفسه يُسمى:","options":["صمام تصريف يدوي","صمام تصريف أوتوماتيكي","صمام ترحيل (relay valve)","وصلة الكف (glad hand)"],"explanation":"تطرد صمامات التصريف الأوتوماتيكية الماء والزيت دون تصريف يدوي."},"121":{"q":"يحتوي نظام المكابح الهوائية المزدوج على:","options":["خزان هواء واحد","نظامي هواء منفصلين","لا خزانات على الإطلاق","خط واحد مشترك"],"explanation":"تستخدم الأنظمة المزدوجة نظامين منفصلين أساسياً وثانوياً لأغراض السلامة."},"122":{"q":"إذا تعطل أحد النظامين في تركيب المكابح الهوائية المزدوج، فإن الآخر:","options":["يتعطل أيضاً بالكامل","لا يزال يعمل لإيقاف المركبة","يتسارع فجأة","ينغلق إلى الأبد"],"explanation":"لا يزال بإمكان النظام المتبقي إيقاف المركبة، وإن كانت مسافة التوقف أطول."},"123":{"q":"تُبقى المكابح الزنبركية (spring brakes) في وضع التحرر بواسطة:","options":["الجاذبية فقط","ضغط الهواء","حبل قوي","راديو المقصورة"],"explanation":"يبقي ضغط الهواء الزنبركات القوية مكبوحة؛ وإذا فُقد الهواء، تطبّق الزنبركات المكابح."},"124":{"q":"بما أن نوابض مكابح النابض قوية جدًا، فعليك أن:","options":["تحررها يدويًا بشكل متكرر","لا تحررها إلا إذا كنت مدربًا","تطليها بلون زاهٍ","تزيلها بالكامل"],"explanation":"تثبيت مكابح النابض (تقفيصها) أمر خطير؛ لا ينبغي القيام به إلا للأشخاص المدربين فقط."},"125":{"q":"للتأكد من أن مكابح الانتظار (النابض) تثبّت المركبة، عليك أن:","options":["ترفع دوران المحرك بصوت عالٍ","تدفع المركبة للأمام برفق مقابلها","تطلق البوق مرتين","تفتح باب المقصورة"],"explanation":"مع تفعيل مكبح الانتظار، اسحب المركبة برفق مقابله للتأكد من أنه يثبّتها."},"126":{"q":"على منحدر طويل بالمكابح الهوائية، عليك أن:","options":["تضغط المكابح وتحررها بشكل متقطع","تستخدم غيارًا منخفضًا مع كبح ثابت","تضغط المكابح بقوة طوال الوقت","تنزلق إلى الأسفل في الوضع المحايد"],"explanation":"اختر سرعة آمنة، واستخدم كبح المحرك بغيار منخفض، وطبّق المكابح بشكل ثابت."},"127":{"q":"المكبح الذي تتحكم فيه دواسة القدم هو:","options":["مكبح الانتظار","مكبح الخدمة","مكبح الطوارئ","صمام اليد للمقطورة"],"explanation":"دواسة القدم (صمام الدواسة) تُشغّل مكابح الخدمة."},"128":{"q":"تكون طبول أو أقراص المكابح خطيرة عندما تكون:","options":["نظيفة وباردة","متشققة أو بالية بشدة","مطلية حديثًا","باردة عند لمسها"],"explanation":"الطبول أو الأقراص المتشققة أو البطانات البالية قد تتعطل ويجب فحصها."},"129":{"q":"عند وجود تسرب هوائي يستمر في خفض الضغط، عليك أن:","options":["تواصل القيادة على أي حال","تتوقف وتصلح العطل","تقود بسرعة أكبر إلى الورشة","تتجاهل التسرب فحسب"],"explanation":"التسرب الهوائي المستمر خطير؛ توقف بأمان وأصلح العطل قبل القيادة."},"130":{"q":"بقاء مصباح عطل نظام منع انغلاق المكابح (ABS) الأصفر مضاءً يعني:","options":["أن المكابح متوقفة عن العمل","أن نظام ABS قد لا يعمل","أنه يجب عليك التوقف فورًا","أن راديو المقصورة قيد التشغيل"],"explanation":"إضاءة مصباح ABS تحذّر من أن نظام منع الانغلاق قد لا يعمل؛ لكن المكابح العادية لا تزال تعمل."},"131":{"q":"تستمر المكابح الهوائية في العمل طالما يوجد:","options":["وقود كافٍ","ضغط هواء كافٍ","ضوء شمس ساطع","راكب ثانٍ"],"explanation":"يحتاج النظام إلى ضغط هواء كافٍ لتطبيق المكابح وتحريرها."},"132":{"q":"بعد الشحن الكامل، يجب أن يستغرق بناء الضغط من 85 إلى 100 psi:","options":["عدة دقائق طويلة","وقتًا قصيرًا، خلال ثوانٍ","ساعة كاملة","بلا وقت، فوريًا"],"explanation":"الضاغط السليم يبني الضغط بسرعة؛ والبناء البطيء يعني وجود مشكلة."},"133":{"q":"بطانات المكابح الرقيقة جدًا يجب أن:","options":["تُطلى من فوقها","تُستبدل بأخرى جديدة","تُزيّت قليلًا","تُترك وتُتجاهل"],"explanation":"البطانات البالية تقلل من قوة الكبح ويجب استبدالها."},"134":{"q":"الضغط على المكابح وتحريرها مرات عديدة على منحدر ('الكبح المتقطع') قد:","options":["يساعد على تبريد المكابح","يستهلك الهواء أسرع مما يُبنى","يشحن خزان المقطورة","يوفر قليلًا من الوقود"],"explanation":"الكبح المتقطع للمكابح الهوائية قد يخفض ضغط الهواء أسرع مما يعيد الضاغط بناءه."},"135":{"q":"ماذا يتيح لك صمام التحكم التعديلي أن تفعل؟","options":["تطبيق مكابح النابض تدريجيًا في حالة الطوارئ","تصريف الماء من خزانات الهواء تلقائيًا","بناء ضغط الهواء بشكل أسرع بعد التشغيل","تشغيل مصباح تحذير انخفاض ضغط الهواء"],"explanation":"يتيح لك صمام التحكم التعديلي تطبيق مكابح النابض تدريجيًا في حالة الطوارئ."},"136":{"q":"أي مما يلي يُعد بندًا من بنود فحص المكابح الهوائية قبل الرحلة؟","options":["ضغط تشغيل وإيقاف المنظّم","عمق مداس الإطار","توجيه المصابيح الأمامية","مستوى سائل المساحات"],"explanation":"فحص ضغطي تشغيل وإيقاف المنظّم هو أحد فحوص المكابح الهوائية قبل الرحلة المُدرجة."},"137":{"q":"ما الذي يسبب تأخر المكابح الهوائية؟","options":["الوقت اللازم لانتقال الهواء عبر الخطوط","تآكل وسادات المكابح","انخفاض زيت المحرك","برودة المحرك"],"explanation":"تأخر المكابح الهوائية هو الوقت الذي يستغرقه الهواء للانتقال عبر خطوط المكابح، مما يسبب تأخيرًا يقارب نصف ثانية."},"138":{"q":"في نظام المكابح الهوائية، أي المكابح تستخدمها أثناء القيادة العادية للتباطؤ أو التوقف؟","options":["مكابح الخدمة","مكابح الانتظار","مكابح الطوارئ","مكابح النابض"],"explanation":"مكابح الخدمة هي النظام الذي يُطبّق للتباطؤ أو التوقف أثناء القيادة العادية."},"139":{"q":"نظام المكابح الهوائية المزدوج يستخدم كم مجموعة من أدوات التحكم؟","options":["واحدة","اثنتان","ثلاث","أربع"],"explanation":"يحتوي نظام المكابح الهوائية المزدوج على نظامين هوائيين منفصلين لكن مجموعة واحدة فقط من أدوات التحكم."},"140":{"q":"تقريبًا كم يسمح المنظّم للضغط بأن ينخفض قبل أن يعود إلى العمل لاستئناف الضخ؟","options":["حوالي 25 psi","حوالي 50 psi","حوالي 10 psi","حوالي 75 psi"],"explanation":"ضغط الإيقاف حوالي 125 psi وضغط التشغيل حوالي 100 psi، بفارق يقارب 25 psi."},"141":{"q":"صمام تنفيس الأمان الذي يفتح عند حوالي 150 psi يقع في أي خزان؟","options":["خزان الإمداد (الرطب)","خزان المقطورة","خزان الخدمة الثانوي","خزان مكبح النابض"],"explanation":"صمام تنفيس الأمان يُركّب في خزان الإمداد أو الخزان الرطب ويفتح عند حوالي 150 psi."},"142":{"q":"يتضمن تحذير انخفاض ضغط الهواء عادةً مصباحًا وأي إشارة أخرى؟","options":["جرس إنذار","ضوء وامض","مقعد اهتزازي","بوق"],"explanation":"تحذير انخفاض ضغط الهواء يكون عادةً مصباحًا بالإضافة إلى جرس إنذار."},"143":{"q":"عند أي نقطة تنطبق مكابح النابض من تلقاء نفسها مع استمرار انخفاض ضغط الهواء؟","options":["عندما ينخفض الضغط إلى نطاق 20 إلى 45 psi","عندما ينخفض الضغط إلى نطاق 50 إلى 75 psi","عندما ينخفض الضغط إلى نطاق 5 إلى 15 psi","عندما ينخفض الضغط إلى نطاق 60 إلى 85 psi"],"explanation":"تنطبق مكابح النابض تلقائيًا عندما ينخفض ضغط الهواء إلى نطاق 20 إلى 45 psi."},"144":{"q":"في اختبار بناء ضغط الهواء لنظام مزدوج، يجب أن يصل الضغط إلى 100 psi من أي ضغط ابتدائي خلال 45 ثانية؟","options":["85 psi","60 psi","100 psi","45 psi"],"explanation":"يجب أن يرتفع الضغط من 85 إلى 100 psi خلال 45 ثانية في النظام المزدوج."},"145":{"q":"عند فحص تسرب الهواء، في أي حالة يجب أن يكون المحرك؟","options":["متوقفًا","في وضع الخمول","يعمل بدوران مرتفع","يعمل وهو في الغيار"],"explanation":"يُفحص معدل تسرب الهواء والمحرك متوقف والنظام مشحون بالكامل."},"146":{"q":"بالنسبة لمركبة مركّبة مع تطبيق المكابح، يجب ألا يزيد معدل تسرب الهواء عن كم؟","options":["4 psi في الدقيقة","2 psi في الدقيقة","6 psi في الدقيقة","8 psi في الدقيقة"],"explanation":"المركبة المركّبة مع تطبيق المكابح يجب ألا تفقد أكثر من 4 psi في الدقيقة."},"147":{"q":"بالنسبة لمركبة مركّبة مع تحرير المكابح، يجب ألا يزيد معدل تسرب الهواء عن كم؟","options":["3 psi في الدقيقة","2 psi في الدقيقة","5 psi في الدقيقة","7 psi في الدقيقة"],"explanation":"المركبة المركّبة مع تحرير المكابح يجب ألا تفقد أكثر من 3 psi في الدقيقة."},"148":{"q":"أثناء اختبار توقف مكبح الخدمة عند سرعة 5 mph، كيف يجب أن تشعر بدواسة المكبح؟","options":["ثابتة","إسفنجية","رخوة","متصلبة ومقفلة"],"explanation":"في اختبار التوقف يجب أن تشعر بأن الدواسة ثابتة وألا تنحرف المركبة إلى أحد الجانبين."},"149":{"q":"في اختبار التوقف باستخدام فرامل الخدمة، يجب أن تتوقف المركبة دون أن تفعل ماذا؟","options":["الانحراف إلى أحد الجانبين","التدحرج إلى الخلف","توقف المحرك عن العمل","إصدار صوت الجرس التحذيري"],"explanation":"يجب أن تتوقف المركبة بشكل مستقيم دون الانحراف إلى أحد الجانبين."},"150":{"q":"ما الذي يسبب تأخر الفرامل في نظام الفرامل الهوائية؟","options":["الوقت اللازم لانتقال الهواء عبر الخطوط","الوقت اللازم لتباطؤ المحرك","الوقت اللازم لتحرر النوابض","الوقت اللازم لقراءة المقياس"],"explanation":"تأخر الفرامل هو الوقت الذي يستغرقه انتقال الهواء عبر خطوط الفرامل."},"151":{"q":"إلى جانب مسافة الإدراك ومسافة رد الفعل ومسافة الكبح الفعلي، ما المسافة الإضافية التي تشكل جزءًا من إجمالي مسافة التوقف للفرامل الهوائية؟","options":["مسافة تأخر الفرامل","مسافة الانزلاق الحر","مسافة المنحدر","مسافة التوجيه"],"explanation":"يضيف إجمالي مسافة التوقف للفرامل الهوائية مسافة تأخر الفرامل."},"152":{"q":"ما الذي يتجمع في خزانات الهواء ويجب إزالته بتصريفها يوميًا؟","options":["الماء وزيت الضاغط","سائل الفرامل والغبار","الوقود وسائل التبريد","الرمل والشحم"],"explanation":"يتجمع الماء وزيت الضاغط في الخزانات، لذا يجب تصريفها يوميًا."},"153":{"q":"إلى جانب التلف، ما الذي يساعد تصريف خزانات الهواء يوميًا على منعه في الطقس البارد؟","options":["التجمد","ارتفاع الحرارة المفرط","تآكل الدواسة","فقدان وصلة المقطورة"],"explanation":"يمنع تصريف الخزانات التجمد والتلف."},"154":{"q":"ما شكل مقبض التحكم الأصفر في فرامل الركن؟","options":["معيّن","مثمّن","مستدير","مربع"],"explanation":"مقبض التحكم في فرامل الركن أصفر اللون وعلى شكل معيّن."},"155":{"q":"لتفعيل فرامل الركن، ماذا تفعل بالمقبض الأصفر؟","options":["تسحبه للخارج","تدفعه للداخل","تديره إلى اليسار","تضغطه للأسفل"],"explanation":"تسحب المقبض الأصفر للخارج لتفعيل فرامل الركن، وتدفعه للداخل لتحريرها."},"156":{"q":"في حالة الطوارئ، ما الذي يتيح لك تفعيل فرامل النوابض تدريجيًا؟","options":["صمام تحكم تعديلي","المنظّم","صمام تخفيف الأمان","ضابط الخلوص"],"explanation":"يتيح لك صمام التحكم التعديلي تفعيل فرامل النوابض تدريجيًا في حالة الطوارئ."},"157":{"q":"على منحدر طويل، بعد تحرير الفرامل يجب إعادة تطبيقها عندما تزداد السرعة لتعود إلى سرعتك الآمنة؛ عند أي مقدار تقريبًا أدنى منها تقوم بتحريرها؟","options":["5 ميل/ساعة أدنى من سرعتك الآمنة","10 ميل/ساعة أدنى من سرعتك الآمنة","15 ميل/ساعة أدنى من سرعتك الآمنة","2 ميل/ساعة أدنى من سرعتك الآمنة"],"explanation":"حرّر الفرامل عند نحو 5 ميل/ساعة أدنى من سرعتك الآمنة، ثم أعد تطبيقها."}},"learn-combination":{"0":{"q":"ما الذي يسبب معظم حالات انقلاب المركبات المركّبة؟","options":["القيادة بسرعة كبيرة في المنعطف","الكبح بقوة مفرطة","القيادة بمسافة قريبة جدًا","قفل عجلات المقطورة"],"explanation":"تحدث معظم حالات انقلاب المركبات المركّبة بسبب القيادة بسرعة كبيرة في المنعطف."},"1":{"q":"لمنع الانقلاب، كيف يجب تحميل البضائع؟","options":["بأعلى ارتفاع ممكن","منخفضة وفي المنتصف","نحو الخلف","نحو أحد الجانبين"],"explanation":"احتفظ بالبضائع منخفضة للحفاظ على مركز ثقل منخفض والمساعدة في منع الانقلاب."},"2":{"q":"للمساعدة في منع الانقلاب، كيف يجب أن توزع الحمولة؟","options":["مكدّسة عاليًا","نحو الخلف","موزّعة في المنتصف من جانب إلى جانب","منزاحة نحو أحد الجانبين"],"explanation":"لمنع الانقلاب، احتفظ بالحمولة موزّعة في المنتصف من جانب إلى جانب والبضائع منخفضة."},"3":{"q":"لمنع الانقلاب، ماذا يجب أن تفعل قبل المنعطفات والمنحدرات؟","options":["زيادة السرعة","تحرير الفرامل","التوجيه بحدّة","تخفيف السرعة"],"explanation":"لمنع الانقلاب، خفّف السرعة قبل المنعطفات والمنحدرات."},"4":{"q":"ما نسبة وفيات سائقي الشاحنات في الحوادث التي تكون بسبب الانقلاب؟","options":["النصف","الثلث","الربع","الثلثان"],"explanation":"نصف جميع وفيات سائقي الشاحنات في الحوادث تكون بسبب الانقلاب."},"5":{"q":"في المنعطف، أي العجلات تتبع مسارًا أضيق بسبب التتبع المنحرف؟","options":["العجلات الأمامية للجرّار","العجلات الخلفية للمقطورة","عجلات الدفع في الجرّار","العجلات الأمامية للمقطورة"],"explanation":"يعني التتبع المنحرف أن العجلات الخلفية للمقطورة تتبع مسارًا داخليًا أضيق من العجلات الأمامية للجرّار."},"6":{"q":"بسبب التتبع المنحرف، متى يجب أن تتجه بشكل واسع أثناء المنعطف؟","options":["قبل المنعطف","في منتصف المنعطف","عند إتمام المنعطف","لا تتجه بشكل واسع أبدًا"],"explanation":"بسبب التتبع المنحرف، اتجه بشكل واسع عند إتمام المنعطف حتى تتمكن المقطورة من المرور، وليس قبله."},"7":{"q":"ما الذي يسببه التضخيم الخلفي (\"طقطقة السوط\")؟","options":["انزلاق الجرّار","قفل عجلات الدفع","ارتفاع عجلات المقطورة","تأرجح المقطورة الخلفية بشكل واسع"],"explanation":"يجعل التضخيم الخلفي حركة توجيه سريعة تؤدي إلى تأرجح المقطورة الخلفية بشكل أوسع بكثير من المقصورة."},"8":{"q":"كيف يجب أن توجّه لتجنب التضخيم الخلفي؟","options":["بلطف وتدريج","بسرعة وحدّة","بقوة وسرعة","متأخرًا وبشكل واسع"],"explanation":"لتجنب التضخيم الخلفي، وجّه بلطف وتدريج وغيّر المسارات ببطء."},"9":{"q":"في انثناء المقطورة، ماذا يحدث عندما تُقفل عجلات المقطورة؟","options":["يتأرجح الجرّار للخارج","تتأرجح المقطورة للخارج","تستعيد العجلات قوة الجر","تتحرر الفرامل"],"explanation":"في انثناء المقطورة، إذا قُفلت عجلات المقطورة، تتأرجح المقطورة للخارج إلى الجانب."},"10":{"q":"للتعافي من انثناء المقطورة، ماذا يجب أن تفعل عندما تبدأ المقطورة بالتأرجح للخارج؟","options":["الكبح بقوة أكبر","التوجيه بحدّة","تحرير الفرامل","زيادة السرعة"],"explanation":"عندما تتأرجح المقطورة للخارج، حرّر الفرامل حتى تدور العجلات مجددًا وتستعيد قوة الجر."},"11":{"q":"يحدث انثناء الجرّار عندما يؤدي الكبح بقوة مفرطة إلى قفل أي عجلات؟","options":["عجلات المقطورة","العجلات الأمامية","عجلات العربة المساعدة","عجلات الدفع"],"explanation":"يحدث انثناء الجرّار عندما يؤدي الكبح بقوة مفرطة إلى قفل عجلات الدفع، مما يجعل الجرّار يتأرجح."},"12":{"q":"مقارنة بالمركبات الأخرى، ما الذي تحتاجه المركبات المركّبة الأثقل والأطول بقدر أكبر؟","options":["مسافة الأمان للمتابعة","قوة المحرك","ضغط الإطارات","حجم المرآة"],"explanation":"المركبات المركّبة أثقل وأطول، لذا تحتاج إلى مسافة أمان أكبر للمتابعة ومجال أكبر للتوقف."},"13":{"q":"ما خطّا الهواء اللذان يصلان بين الجرّار والمقطورة؟","options":["خط الفرامل وخط الإمداد","خط الخدمة وخط الطوارئ","خط التحكم وخط الركن","الخط الأساسي وخط النوابض"],"explanation":"يتصل الجرّار والمقطورة بخطّي هواء: خط الخدمة (التحكم) وخط الطوارئ (الإمداد)."},"14":{"q":"ما الوصلات التي تربط خطّي الهواء بين الجرّار والمقطورة؟","options":["فكوك مسمار الارتكاز","مشابك الضفيرة","وصلات اليد المتصافحة","مزاليج العجلة الخامسة"],"explanation":"يُربط خطّا الهواء بوصلات اليد المتصافحة، ويجب ألا تعكسهما."},"15":{"q":"ما لون خط هواء الطوارئ في المركبة المركّبة؟","options":["أزرق","أخضر","أصفر","أحمر"],"explanation":"في الترميز اللوني لخطوط الهواء، الأزرق هو خط الخدمة والأحمر هو خط الطوارئ."},"16":{"q":"أي خط هواء يشحن خزانات هواء المقطورة ويتحكم في فرامل الطوارئ الخاصة بها؟","options":["خط الطوارئ","خط الخدمة","خط التحكم","خط اليد المفصلية (glad-hand)"],"explanation":"يشحن خط الطوارئ خزانات هواء المقطورة ويتحكم في فرامل الطوارئ أو الفرامل الزنبركية للمقطورة."},"17":{"q":"إذا فُقد الهواء في خط الطوارئ، فماذا تفعل الفرامل الزنبركية للمقطورة؟","options":["تتحرر بالكامل","تنطبق تلقائيًا","تبقى دون تغيير","تنبض بالتشغيل والإيقاف"],"explanation":"إذا فُقد الهواء في خط الطوارئ، فإن الفرامل الزنبركية للمقطورة تنطبق تلقائيًا."},"18":{"q":"ماذا يختبر صمام اليد للمقطورة (عتلة جونسون)؟","options":["العجلة الخامسة","الأرجل الداعمة (landing gear)","فرامل المقطورة","الأيدي المفصلية (glad hands)"],"explanation":"يُستخدم صمام اليد للمقطورة، ويُسمى أيضًا عتلة الترولي أو عتلة جونسون، لاختبار فرامل المقطورة."},"19":{"q":"لماذا يجب ألا تستخدم صمام اليد للمقطورة لركن المركبة؟","options":["لأنه يطبّق جميع الفرامل","لأنه يشحن خزانات الهواء","لأنه يعبّر خطوط الهواء","لأن الهواء قد يتسرب"],"explanation":"لا تستخدم صمام اليد للمقطورة لركن المركبة لأن الهواء قد يتسرب فيُحرر الفرامل."},"20":{"q":"صمام اليد للمقطورة يطبّق أي فرامل؟","options":["فرامل المقطورة فقط","فرامل القاطرة فقط","جميع فرامل المركبة","الفرامل الزنبركية للركن"],"explanation":"لا تستخدم صمام اليد للمقطورة لمنع الانثناء (jackknife) لأنه يطبّق فرامل المقطورة فقط."},"21":{"q":"على أي جزء من المقطورة تُغلق العجلة الخامسة؟","options":["الأرجل الداعمة (landing gear)","المسمار الملكي (kingpin)","الأيدي المفصلية (glad hands)","الضفيرة الكهربائية (pigtail)"],"explanation":"تُغلق العجلة الخامسة على المسمار الملكي للمقطورة بفكوك الإغلاق، ويثبتها مقبض التحرير ومزلاج الأمان."},"22":{"q":"في الاقتران الصحيح، أين تُغلق فكوك الإغلاق؟","options":["أعلى المسمار الملكي","على الطرف فقط","حول ساق المسمار الملكي","أسفل العجلة الخامسة"],"explanation":"في الاقتران الصحيح تكون فكوك الإغلاق مغلقة تمامًا حول ساق المسمار الملكي، وليس فوقه أو على طرفه."},"23":{"q":"في الاقتران الصحيح، في أي وضع يكون ذراع التحرير؟","options":["مفتوح قليلًا","مغلق إلى المنتصف","مرفوع بالكامل","في وضع الإغلاق"],"explanation":"في الاقتران الصحيح يكون ذراع التحرير في وضع الإغلاق مع تعشيق مزلاج الأمان."},"24":{"q":"في الاقتران الصحيح، ما مقدار الفجوة التي يجب أن تكون بين العجلة الخامسة العلوية والسفلية؟","options":["لا فجوة","1 بوصة","2 بوصة","فجوة صغيرة"],"explanation":"في الاقتران الصحيح لا توجد فجوة بين العجلة الخامسة العلوية والسفلية."},"25":{"q":"في الاقتران الصحيح، إلى أي مدى يجب أن تكون العجلة الخامسة إلى الأمام؟","options":["إلى أقصى مدى ممكن للأمام","ليست بعيدة لدرجة أن تصطدم المقطورة بالمقصورة","مركزية فوق المحور الخلفي","بعيدة بما يكفي لرفع المقطورة"],"explanation":"يجب ألا تكون العجلة الخامسة بعيدة جدًا إلى الأمام بحيث يمكن أن تصطدم المقطورة بالمقصورة."},"26":{"q":"ما الذي يدل على الاقتران الصحيح في العجلة الخامسة؟","options":["مسامير تثبيت مرتخية","شق صغير مرئي","المسامير موجودة ولا توجد شقوق","غياب مزلاج الأمان"],"explanation":"في الاقتران الصحيح تكون مسامير التثبيت موجودة ولا توجد شقوق في العجلة الخامسة."},"27":{"q":"أثناء اختبار الشد (tug test)، في أي ترس تتحرك للأمام برفق للتأكد من أن الاقتران مغلق؟","options":["ترس الرجوع للخلف","الترس المحايد","الترس العالي","الترس المنخفض"],"explanation":"لاختبار الشد، اقفل فرامل المقطورة وتحرك للأمام برفق في الترس المنخفض للتأكد من أن الاقتران مغلق."},"28":{"q":"قبل الرجوع للخلف أسفل المقطورة، كيف ينبغي أن يكون ارتفاع المقطورة مقارنة بمركز العجلة الخامسة؟","options":["أخفض قليلًا","أعلى قليلًا","مستوية تمامًا","أعلى بكثير"],"explanation":"يجب أن تكون المقطورة أخفض قليلًا من مركز العجلة الخامسة بحيث ترتفع قليلًا عندما ترجع للخلف أسفلها."},"29":{"q":"قبل قيادة مركبة مركّبة مقترنة، ماذا يجب أن تكون عليه الأرجل الداعمة (landing gear)؟","options":["ملامسة للأرض بالكاد","مرفوعة بالكامل","منزلة إلى المنتصف","محمّلة بشكل خفيف"],"explanation":"يجب أن تكون الأرجل الداعمة مرفوعة بالكامل ومقبض الإدارة مثبتًا قبل القيادة."},"30":{"q":"ماذا توصّل الضفيرة الكهربائية (pigtail) في المركبة المركّبة؟","options":["الفرامل الهوائية","الأرجل الداعمة (landing gear)","أضواء المقطورة","العجلة الخامسة"],"explanation":"تُوصّل الضفيرة الكهربائية لكي تعمل أضواء المقطورة، ويجب تثبيتها بحيث لا يمكن أن تُسحب على الأرض."},"31":{"q":"عند فك الاقتران، إلى أي مدى يجب أن تُنزل الأرجل الداعمة (landing gear)؟","options":["حتى ترفع المقطورة عن العجلة الخامسة","مرفوعة بالكامل ومثبتة","منزلة إلى المنتصف فقط","حتى تلامس الأرض بالكاد"],"explanation":"عند فك الاقتران، أنزل الأرجل الداعمة حتى تلامس الأرض بالكاد دون رفع المقطورة عن العجلة الخامسة."},"32":{"q":"نظام الفرامل المانع للانغلاق (ABS) مطلوب على المقطورات وعربات التحويل (converter dollies) المصنوعة في أو بعد أي تاريخ؟","options":["1 مارس 1998","1 مارس 1988","1 يناير 1998","1 مارس 2008"],"explanation":"نظام ABS مطلوب على المقطورات وعربات التحويل المصنوعة في أو بعد 1 مارس 1998."},"33":{"q":"بماذا يساعدك نظام الفرامل المانع للانغلاق (ABS)؟","options":["التوقف في مسافة أقصر","منع العجلات من الانغلاق حتى تتمكن من التوجيه","زيادة ضغط الهواء لديك","منع انحراف مسار المقطورة"],"explanation":"لا يقصّر نظام ABS مسافة التوقف؛ بل يمنع عجلاتك من الانغلاق حتى تتمكن من التوجيه."},"34":{"q":"لماذا يجب أن تبقي الحمولة منخفضة في المركبة المركّبة؟","options":["لأنها تمنح مركز ثقل منخفضًا مما يساعد على منع الانقلاب","لأنها تجعل فرامل المقطورة تعمل أسرع في المنعطفات","لأنها تتيح للقاطرة والمقطورة الانعطاف بشكل أحدّ","لأنها تقصّر مسافة التوقف على الطرق المبتلة"],"explanation":"إبقاء الحمولة منخفضة يمنح المركبة مركز ثقل منخفضًا، مما يساعد على منع الانقلاب."},"35":{"q":"في المركبات المزدوجة أو الثلاثية، ماذا يفعل التضخيم الخلفي (crack-the-whip)؟","options":["يُبطئ المقطورة الخلفية","يمكن أن يقلب المقطورة الخلفية","يقفل فرامل المقطورة","يبرّد الإطارات الخلفية"],"explanation":"يتضخم التضخيم الخلفي (crack-the-whip) في المركبات المزدوجة والثلاثية ويمكن أن يقلب المقطورة الخلفية."},"36":{"q":"لتجنب التضخيم الخلفي، كيف يجب أن تغيّر المسارات؟","options":["بالفرملة بقوة","بزيادة السرعة أولًا","ببطء ولطف","بالانعطاف بشكل حاد"],"explanation":"لتجنب التضخيم الخلفي، غيّر المسارات ببطء."},"37":{"q":"كيف يمكنك اكتشاف بداية انثناء المقطورة (jackknife)؟","options":["الإنصات إلى فقدان المحرك للقدرة","الشعور بشدّ قوي في عجلة القيادة","مراقبة أضواء التحذير في لوحة العدادات","مراقبة مراياك لانحراف المقطورة إلى الخارج"],"explanation":"لاكتشاف انثناء المقطورة، راقب مراياك لبداية انحراف المقطورة إلى الخارج."},"38":{"q":"في انثناء المقطورة، ماذا يفعل تحرير الفرامل؟","options":["يدع العجلات تدور مجددًا فتعود قوة الجر","يقفل العجلات بإحكام أكبر لمزيد من التماسك","يسرّع العجلات الأمامية للقاطرة","يرفع مركز ثقل المقطورة"],"explanation":"تحرير الفرامل في انثناء المقطورة يدع العجلات تدور مجددًا فتستعيد المقطورة قوة الجر."},"39":{"q":"مقارنة بالمركبات الأخرى، تحتاج المركبات المركّبة إلى:","options":["مساحة توقف أقل","مساحة توقف أكبر","نفس مساحة التوقف","لا حاجة لمساحة توقف إضافية"],"explanation":"لأنها أثقل وأطول، تحتاج المركبات المركّبة إلى مساحة توقف أكبر."},"40":{"q":"عند توصيل خطي الهواء بين القاطرة والمقطورة، يجب أن تتأكد من أنهما ليسا ماذا؟","options":["مطليين","ملفوفين","متعابرين","موسومين"],"explanation":"يجب ألا يكون خطا الهواء، خط الخدمة وخط الطوارئ، متعابرين عند توصيلهما."},"41":{"q":"ما هو اللون الذي يُميَّز به خط هواء الخدمة (التحكم)؟","options":["أخضر","أحمر","أصفر","أزرق"],"explanation":"يُميَّز خط هواء الخدمة (التحكم) باللون الأزرق."},"42":{"q":"هل يمكنك الاعتماد على صمام يد المقطورة لمنع انثناء المركبة (الجاك نايف)؟","options":["لا، فهو يُطبّق فرامل المقطورة فقط","نعم، فهو يُطبّق جميع فرامل المركبة","نعم، فهو يُقفل فكّي العجلة الخامسة","لا، فهو يرفع فقط أرجل الإسناد"],"explanation":"لا ينبغي الاعتماد على صمام يد المقطورة لمنع انثناء المركبة (الجاك نايف) لأنه يُطبّق فرامل المقطورة فقط."},"43":{"q":"ما الذي يُبقي العجلة الخامسة مقفلة على مسمار الارتكاز (الكينغ بِن)؟","options":["كفّ توصيل (غلاد هاند) وخط هواء","مقبض تحرير ومزلاج أمان","أرجل الإسناد ومقبض اللف","الوصلة المرنة ومشبك"],"explanation":"يُبقي مقبض التحرير ومزلاج الأمان العجلة الخامسة مقفلة على مسمار الارتكاز (الكينغ بِن)."},"44":{"q":"عند الوصل، أين يجب أن تُغلق فكّا قفل العجلة الخامسة؟","options":["أعلى مسمار الارتكاز","حول طرف مسمار الارتكاز","حول جذع مسمار الارتكاز","خلف قاعدة مسمار الارتكاز"],"explanation":"يجب أن تُغلق فكّا القفل حول جذع مسمار الارتكاز، وليس أعلاه أو ممسكة بالطرف فقط."},"45":{"q":"في الوصل الصحيح، كيف يجب أن يكون مزلاج الأمان؟","options":["مُزال","مُشحَّم","مفتوح","مُثبَّت (مُعشَّق)"],"explanation":"في الوصل الصحيح، يجب أن يكون مزلاج الأمان مُثبَّتاً (مُعشَّقاً)."},"46":{"q":"أثناء اختبار الشد، ما الذي يجب أن يكون مقفلاً قبل أن تتقدّم إلى الأمام؟","options":["فرامل المقطورة","عجلة القيادة","أرجل الإسناد","أبواب المقصورة"],"explanation":"أثناء اختبار الشد، يجب أن تكون فرامل المقطورة مقفلة بينما تتقدّم إلى الأمام."},"47":{"q":"قبل الرجوع للوصل، كيف ينبغي ضبط ارتفاع المقطورة مقارنةً بالعجلة الخامسة؟","options":["بنفس الارتفاع تماماً","أخفض قليلاً من العجلة الخامسة","أعلى قليلاً من العجلة الخامسة","أعلى بكثير من العجلة الخامسة"],"explanation":"ينبغي أن تكون المقطورة أخفض قليلاً من العجلة الخامسة حتى تُرفع قليلاً عندما ترجع تحتها."},"48":{"q":"قبل الرجوع تحت المقطورة للوصل، ما الذي يجب أن تتحقق منه بشأن ارتفاع المقطورة؟","options":["ينبغي أن تكون أعلى بكثير من العجلة الخامسة","الارتفاع لا يهم في عملية الوصل","ينبغي أن تكون أخفض قليلاً من العجلة الخامسة","ينبغي أن تكون بمستوى سقف المقصورة"],"explanation":"قبل الرجوع تحتها، ينبغي أن تكون المقطورة أخفض قليلاً من العجلة الخامسة حتى تُرفع قليلاً، ويجب ألّا ترجع أبداً تحت مقطورة مرتفعة أكثر من اللازم."},"49":{"q":"قبل قيادة مركبة مركّبة، يجب أن يكون مقبض لفّ أرجل الإسناد:","options":["متروكاً معلّقاً بحرّية","مُزالاً ومخزّناً","ممدوداً جزئياً","مُثبَّتاً في مكانه"],"explanation":"قبل القيادة، يجب أن يكون مقبض لفّ أرجل الإسناد مُثبَّتاً."},"50":{"q":"كيف يجب تثبيت الوصلة الكهربائية المرنة (البيغتيل)؟","options":["بحيث لا يمكن أن تنجرّ على الأرض","بحيث يمكن أن تنجرّ على الأرض","بحيث تبقى مرتخية","بحيث تتدلّى منخفضة"],"explanation":"يجب تثبيت الوصلة الكهربائية المرنة (البيغتيل) بحيث لا يمكن أن تنجرّ على الأرض."},"51":{"q":"ماذا يفعل نظام منع انغلاق الفرامل (ABS) لمركبتك؟","options":["يُقصّر مسافة التوقّف","يضغط الفرامل بدلاً عنك","يمنع العجلات من الانغلاق","يشحن خزّانات هواء المقطورة"],"explanation":"لا يُقصّر نظام منع انغلاق الفرامل (ABS) مسافة التوقّف؛ بل يمنع عجلاتك من الانغلاق حتى تتمكّن من التوجيه."},"52":{"q":"تجنّب أيّ تصرّف يمنع معظم حالات انقلاب المركبات المركّبة؟","options":["القيادة بسرعة مفرطة في المنعطف","الفرملة على طريق مستقيم","تبديل التروس كثيراً","استخدام المرايا كثيراً"],"explanation":"تحدث معظم حالات انقلاب المركبات المركّبة بسبب القيادة بسرعة مفرطة في المنعطف، لذا فإن الإبطاء يمنعها."},"53":{"q":"من الناحية الفيزيائية، ما الذي يحقّقه تحميل البضائع في وضع منخفض؟","options":["مسافة توقّف أقصر","مركز ثقل أخفض","نصف قطر دوران أوسع","استهلاك وقود أقل"],"explanation":"يمنح تحميل البضائع في وضع منخفض المركبة مركز ثقل أخفض، مما يساعد على منع الانقلاب."},"54":{"q":"متى ينبغي أن تُبطئ السرعة عند منعطف أو منحدر؟","options":["أثناء مرورك خلاله","بعد دخولك إليه","قبل دخولك إليه","فقط إذا بدا ضيّقاً"],"explanation":"أبطئ السرعة قبل دخول المنعطف أو المنحدر للمساعدة على منع الانقلاب."},"55":{"q":"نصف وفيات سائقي الشاحنات في الحوادث ناتجة عن الانقلاب. ماذا يُظهر هذا بشكل أساسي؟","options":["الانقلاب نادر جداً ولا داعي للقلق منه","مسافة الاتباع هي أهمّ قضية سلامة","الفرامل الهوائية هي السبب الرئيسي للحوادث","الوقاية من الانقلاب أمر حاسم للنجاة"],"explanation":"نصف وفيات سائقي الشاحنات في الحوادث ناتجة عن الانقلاب."},"56":{"q":"في المنعطف، أيّ العجلات تتّبع المسار الداخلي الأضيق؟","options":["العجلات الخلفية للمقطورة","العجلات الأمامية للقاطرة","كلاهما يتّبع المسار نفسه","لا تنعطف أيّ من العجلتين إلى الداخل"],"explanation":"في المنعطف، تتّبع العجلات الخلفية للمقطورة مساراً أضيق (داخلياً) من العجلات الأمامية للقاطرة."},"57":{"q":"لماذا يجب أن تنعطف بعرض كافٍ عند الانعطاف؟","options":["لإبقاء البضائع منخفضة","حتى تتجاوز المقطورة بأمان","لتقصير مسافة التوقّف","لاختبار فرامل المقطورة"],"explanation":"يجب أن تنعطف بعرض كافٍ حتى تتجاوز العجلات الخلفية للمقطورة بأمان عند إتمام الانعطاف."},"58":{"q":"عند الانعطاف بمركبة مركّبة، متى ينبغي أن تتمايل بعرض (تأخذ مساحة واسعة)؟","options":["قبل أن تبدأ الانعطاف","في منتصف الانعطاف","عند إتمام الانعطاف","قبل الإبطاء"],"explanation":"ينبغي أن تتمايل بعرض عند إتمام الانعطاف، وليس قبله، حتى تتجاوز العجلات الخلفية للمقطورة بأمان."},"59":{"q":"أيّ نوع من حركات التوجيه يُحدث ظاهرة \"ضربة السوط\" في المقطورة؟","options":["حركة بطيئة لطيفة","حركة تدريجية سلسة","حركة صغيرة ثابتة","حركة سريعة مفاجئة"],"explanation":"تجعل حركة التوجيه السريعة مؤخرة المقطورة تتأرجح بعرض أكبر بكثير من المقصورة."},"60":{"q":"التضخيم الخلفي (ظاهرة ضربة السوط) يكون أكبر في أيّ تكوين؟","options":["المقطورات المزدوجة والثلاثية","مقطورة واحدة","قاطرة بدون مقطورة (بوبتيل)","شاحنة مستقيمة فارغة"],"explanation":"يكون التضخيم الخلفي أكبر في المقطورات المزدوجة والثلاثية ويمكن أن يقلب المقطورة الخلفية."},"61":{"q":"ما نوع الانثناء (الجاك نايف) الذي يحدث عندما تنغلق عجلات المقطورة؟","options":["انثناء القاطرة","انثناء المقطورة","انثناء التوجيه","انثناء العجلة الأمامية"],"explanation":"عندما تنغلق عجلات المقطورة، تتأرجح المقطورة إلى الجانب، وهو ما يُسمّى انثناء المقطورة (انزلاق المقطورة)."},"62":{"q":"في انزلاق المقطورة، لماذا تحرّر الفرامل؟","options":["لإيقاف الشاحنة بسرعة أكبر","لتقويم عجلة القيادة","للسماح للعجلات بالدوران واستعادة التماسك","لتقليل وزن بضائع المقطورة"],"explanation":"عندما تبدأ المقطورة بالتأرجح إلى الخارج، فإن تحرير الفرامل يسمح للعجلات بالدوران مجدداً واستعادة التماسك."},"63":{"q":"أيّ نوع من الانثناء (الجاك نايف) يحدث عندما تتأرجح القاطرة؟","options":["انثناء المقطورة","انثناء الانقلاب","انثناء الانحراف عن المسار","انثناء القاطرة"],"explanation":"الفرملة بقوة مفرطة وانغلاق عجلات الدفع تجعل القاطرة تتأرجح، وهو انثناء القاطرة."},"64":{"q":"أيّ تصرّف من السائق يسبّب انثناء القاطرة؟","options":["الفرملة بقوة مفرطة وانغلاق عجلات الدفع","التوجيه بلطف حول منعطف واسع","زيادة مسافة الاتباع أمامك","إبقاء حمولة البضائع منخفضة وفي المنتصف"],"explanation":"الفرملة بقوة مفرطة وانغلاق عجلات الدفع تجعل القاطرة تتأرجح في انثناء."},"65":{"q":"في المركبة المركّبة، يُسمّى خط هواء الخدمة أيضاً بخط ماذا؟","options":["خط الإمداد","خط التحكم","خط الطوارئ","خط النابض"],"explanation":"يُسمّى خط هواء الخدمة أيضاً بخط التحكم."},"66":{"q":"عند توصيل وصلات خطوط الهواء (glad-hands) في الشاحنة بالمقطورة، ما الذي يجب ألا تفعله أبداً؟","options":["توصيلها في الطقس البارد","استخدام الوصلة الحمراء أولاً","عكس خط الخدمة وخط الطوارئ","توصيلها قبل وصلة الذيل (pigtail)"],"explanation":"عند توصيل وصلات الهواء (glad-hands)، يجب ألا تعكس أبداً خطي الهواء الخاصين بالخدمة والطوارئ."},"67":{"q":"على خطوط الهواء، اللون الأزرق يحدد أي خط؟","options":["خط الإمداد","خط الطوارئ","خط الكبح","خط الخدمة"],"explanation":"في رمز الألوان، يشير اللون الأزرق إلى خط الخدمة ويشير اللون الأحمر إلى خط الطوارئ."},"68":{"q":"ماذا يفعل خط الطوارئ في المقطورة بخزانات هواء المقطورة؟","options":["يملؤها بالهواء","يفرّغها من الهواء","يفحصها بحثاً عن التسريبات","يطلق هواءها إلى الخارج"],"explanation":"يملأ خط الطوارئ خزانات هواء المقطورة بالهواء ويتحكم في كبح الطوارئ/الكبح النابضي للمقطورة."},"69":{"q":"في المركبة المركّبة، يُسمى خط الطوارئ أيضاً بماذا؟","options":["خط التحكم","خط الإمداد","خط الخدمة","خط الوصلة (glad-hand)"],"explanation":"يُسمى خط الطوارئ أيضاً بخط الإمداد."},"70":{"q":"ما الذي يسبب تفعيل الكبح النابضي للمقطورة تلقائياً؟","options":["فقدان ضغط الهواء في خط الخدمة","عكس وصلتي الـ glad-hand","فقدان ضغط الهواء في خط الطوارئ","رفع جهاز هبوط المقطورة"],"explanation":"إذا فُقد هواء خط الطوارئ، يتم تفعيل الكبح النابضي للمقطورة تلقائياً."},"71":{"q":"صمام البكرة (trolley valve)، أو \"عمود جونسون\" (Johnson bar)، يُسمى رسمياً بماذا؟","options":["صمام خط الخدمة","صمام خط الطوارئ","صمام تحرير العجلة الخامسة","صمام اليد للمقطورة"],"explanation":"صمام البكرة أو \"عمود جونسون\" يُسمى رسمياً بصمام اليد للمقطورة، الذي يفعّل كبح المقطورة فقط."},"72":{"q":"إذا أوقفت المركبة باستخدام صمام اليد للمقطورة، فماذا قد يحدث للكبح؟","options":["قد يتسرب الهواء فيتحرر الكبح","سيبقى الكبح مقفلاً إلى الأبد","سيصبح الكبح أقوى بمرور الوقت","سينتقل الكبح إلى الشاحنة"],"explanation":"لا توقف المركبة باستخدام صمام اليد للمقطورة لأن الهواء قد يتسرب فيتحرر الكبح."},"73":{"q":"أي جزء من الشاحنة يُقفل على مسمار الملك (kingpin) في المقطورة؟","options":["جهاز الهبوط","العجلة الخامسة","وصلات الهواء (glad hands)","صمام اليد"],"explanation":"تُقفل العجلة الخامسة على مسمار الملك (kingpin) في المقطورة بواسطة فكوك القفل."},"74":{"q":"في العجلة الخامسة، أي جزء يمسك بمسمار الملك (kingpin) في المقطورة؟","options":["مقبض التحرير","مزلاج الأمان","فكوك القفل","جهاز الهبوط"],"explanation":"تُقفل العجلة الخامسة على مسمار الملك (kingpin) في المقطورة بواسطة فكوك القفل الخاصة بها."},"75":{"q":"أي من هذه يُظهر اقتراناً خاطئاً للعجلة الخامسة؟","options":["الفكوك مغلقة تماماً حول ساق مسمار الملك","ذراع التحرير مقفولة مع تعشيق مزلاج الأمان","لا توجد فجوة بين العجلة الخامسة العلوية والسفلية","الفكوك مستقرة فوق مسمار الملك"],"explanation":"الاقتران الخاطئ يكون فيه الفكوك فوق مسمار الملك أو ممسكة بطرفه فقط، وليست مغلقة تماماً حول ساق مسمار الملك."},"76":{"q":"في الاقتران الصحيح، كيف ينبغي أن تبدو ذراع التحرير ومزلاج الأمان؟","options":["ذراع التحرير مقفولة ومزلاج الأمان معشّق","ذراع التحرير مسحوبة للخارج ومزلاج الأمان معشّق","ذراع التحرير مقفولة ومزلاج الأمان مفتوح","ذراع التحرير مسحوبة للخارج ومزلاج الأمان مفتوح"],"explanation":"في الاقتران الصحيح، تكون ذراع التحرير في الوضع المقفول مع تعشيق مزلاج الأمان."},"77":{"q":"أثناء الفحص، ماذا تعني الفجوة المرئية بين العجلة الخامسة العلوية والسفلية؟","options":["المقطورة محمّلة بشكل صحيح","الاقتران سيئ أو غير صحيح","خطوط الهواء موصولة","جهاز الهبوط مرفوع بالكامل"],"explanation":"يجب ألا توجد أي فجوة بين العجلة الخامسة العلوية والسفلية، لذا فإن الفجوة المرئية تعني اقتراناً سيئاً."},"78":{"q":"ماذا قد يحدث إذا كانت العجلة الخامسة متقدمة جداً للأمام؟","options":["قد يُقفل كبح المقطورة","قد يهبط جهاز الهبوط","قد تصطدم المقطورة بالمقصورة","قد ينثني مسمار الملك للخلف"],"explanation":"إذا كانت العجلة الخامسة متقدمة جداً للأمام، فقد تصطدم المقطورة بالمقصورة."},"79":{"q":"ما الغرض من اختبار الشد (tug test) عند الاقتران؟","options":["لفحص ضغط هواء الإطارات","لرفع جهاز الهبوط بالكامل","لاختبار أضواء المقطورة","للتأكد من أن الاقتران مقفول"],"explanation":"يؤكد اختبار الشد أن الاقتران مقفول من خلال السحب برفق للأمام مع قفل كبح المقطورة."},"80":{"q":"في أي مرحلة من عملية الاقتران تُجري اختبار الشد؟","options":["قبل التوصيل الكامل والانطلاق","بعد الانطلاق من الرصيف","قبل الرجوع تحت المقطورة","بعد إنزال جهاز الهبوط بالكامل"],"explanation":"تُجري اختبار الشد قبل التوصيل الكامل والقيادة للتأكد من أن الاقتران مقفول."},"81":{"q":"لماذا ينبغي ضبط المقطورة أدنى قليلاً من مركز العجلة الخامسة قبل الرجوع تحتها؟","options":["كي ينزلق مسمار الملك فوق العجلة الخامسة","كي ترتفع المقطورة قليلاً أثناء رجوعك تحتها","كي يبقى جهاز الهبوط على الأرض","كي تتصل خطوط الهواء بسهولة أكبر"],"explanation":"تُضبط المقطورة منخفضة قليلاً كي ترتفع قليلاً أثناء رجوعك تحت العجلة الخامسة."},"82":{"q":"ما الذي يجب ألا تفعله أبداً عند الاقتران بمقطورة مضبوطة على ارتفاع زائد؟","options":["إنزال جهاز الهبوط","قفل كبح المقطورة","الرجوع تحت المقطورة","فحص مسمار الملك"],"explanation":"لا ترجع أبداً تحت مقطورة مرتفعة جداً."},"83":{"q":"في المقطورة، يُسمى جهاز الهبوط أيضاً بماذا؟","options":["وصلات الهواء (glad hands)","مسمار الملك (kingpin)","العجلة الخامسة","أرجل العربة (dolly legs)"],"explanation":"يُعرف جهاز الهبوط في المقطورة أيضاً بأرجل العربة (dolly legs)."},"84":{"q":"هل يُقبل في أي حال القيادة وجهاز الهبوط مرفوع جزئياً فقط؟","options":["لا، يجب رفعه بالكامل قبل القيادة","نعم، إذا كانت المقطورة محمّلة بشكل خفيف","نعم، إذا قدت ببطء","نعم، للمسافات القصيرة فقط"],"explanation":"لا تقد أبداً وجهاز الهبوط منزل جزئياً؛ يجب رفعه بالكامل أولاً."},"85":{"q":"عند إنزال جهاز الهبوط أثناء فك الاقتران، ما الذي يجب ألا تفعله؟","options":["تركه يلامس الأرض فقط","رفع المقطورة عن العجلة الخامسة","إضافة بضع لفّات لتحمّل الوزن","تأمين مقبض الكرنك بعد ذلك"],"explanation":"عند فك الاقتران، أنزل جهاز الهبوط حتى يلامس الأرض فقط، لكن لا ترفع المقطورة عن العجلة الخامسة."},"86":{"q":"عند فك الاقتران، بعد تأمين المقطورة، ما الخطوات النهائية؟","options":["القيادة للخارج بسرعة، ثم إنزال جهاز الهبوط","رفع جهاز الهبوط، ثم الرجوع للخلف ببطء","سحب مقبض التحرير، ثم القيادة للخارج ببطء","عكس خطوط الهواء، ثم القيادة للخارج"],"explanation":"بعد تأمين المقطورة، اسحب مقبض التحرير وقد للخارج ببطء."},"87":{"q":"نظام الكبح المانع للانغلاق (ABS) مطلوب في أي قطعتين من المعدات المصنّعة في أو بعد 1 مارس 1998؟","options":["الشاحنات والعربات المحوّلة (converter dollies)","الشاحنات والمقطورات","المقطورات والعجلات الخامسة","المقطورات والعربات المحوّلة (converter dollies)"],"explanation":"نظام الكبح المانع للانغلاق (ABS) مطلوب في المقطورات والعربات المحوّلة (converter dollies) المصنّعة في أو بعد 1 مارس 1998."},"88":{"q":"عند انعطاف مركبة طويلة، تتبع العجلات الخلفية:","options":["المسار نفسه الذي تتبعه العجلات الأمامية","مساراً داخل مسار العجلات الأمامية","مساراً أوسع من العجلات الأمامية","لا مسار يمكن التنبؤ به"],"explanation":"التتبع الخلفي (Off-tracking): تنحرف العجلات الخلفية إلى داخل مسار العجلات الأمامية."},"89":{"q":"لإبقاء المقطورة بعيدة عن الرصيف عند الانعطاف يميناً، فإنك:","options":["تنحرف بشكل واسع إلى اليسار أولاً","تنعطف بشكل واسع عند إنهاء الانعطاف","تنعطف بحدة في وقت مبكر","تسرع خلاله"],"explanation":"أبقِ المؤخرة قريبة من الرصيف؛ وانعطف بشكل واسع عند إكمال الانعطاف."},"90":{"q":"كم عدد خطوط الهواء التي تربط الشاحنة بالمقطورة؟","options":["واحد","اثنان","ثلاثة","أربعة"],"explanation":"اثنان: خط الخدمة وخط الطوارئ (الإمداد)."},"91":{"q":"لون وصلة \"كف اليد\" (glad-hand) لخط الطوارئ (الإمداد) هو:","options":["أزرق","أحمر","أخضر","أصفر"],"explanation":"الأحمر = الطوارئ؛ الأزرق = الخدمة."},"92":{"q":"المقبض الأحمر ذو الثمانية أضلاع داخل المقصورة يتحكم في:","options":["مكابح ركن الجرّار","إمداد هواء المقطورة","مكابح خدمة المقطورة","المصابيح الأمامية"],"explanation":"إنه مقبض إمداد هواء المقطورة / خط الطوارئ."},"93":{"q":"صمام حماية الجرّار موجود من أجل:","options":["نفخ إطارات الجرّار والمقطورة","الإبقاء على الهواء في الجرّار إذا انفصلت المقطورة","رفع وخفض عجلات الإسناد (landing gear)","قفل العجلة الخامسة على مسمار الارتكاز (kingpin)"],"explanation":"يُغلق للحفاظ على هواء الجرّار أثناء الانفصال أو التسرب."},"94":{"q":"يجب استخدام صمام المقطورة اليدوي:","options":["للركن","فقط لاختبار مكابح المقطورة","بدلاً من مكبح القدم","عند كل منحدر هابط"],"explanation":"استخدامه للقيادة قد يسبب انزلاق المقطورة."},"95":{"q":"بعد الوصل، يجب أن تُطبق الفكوك القافلة حول مسمار الارتكاز عند:","options":["الرأس (الأعلى)","الساق (العنق)","لوحة القاعدة","ذراع التحرير"],"explanation":"يجب أن تُطبق الفكوك حول الساق وليس الرأس."},"96":{"q":"ما مقدار الفجوة التي يجب أن تكون بين نصفي العجلة الخامسة؟","options":["لا فجوة","حوالي 1 بوصة (inch)","حوالي 2 بوصة (inch)","فجوة صغيرة مقبولة"],"explanation":"لا فجوة؛ وجود فجوة يعني أن مسمار الارتكاز قد لا يكون مقفولاً."},"97":{"q":"اختبار الشدّ (tug test) يفحص الوصل عن طريق:","options":["النقر برفق على المقطورة","السحب مقابل مكابح المقطورة المقفولة","فحص جميع مصابيح المقطورة","الإصغاء لصوت طقطقة خافتة"],"explanation":"اسحب للأمام برفق؛ يجب أن تبقى المقطورة متصلة."},"98":{"q":"قبل القيادة، يجب أن تكون عجلات الإسناد (landing gear):","options":["متروكة منخفضة جزئياً","مرفوعة بالكامل والمقبض مثبّت","ملامسة لسطح الطريق","منزوعة ومخزّنة بعيداً"],"explanation":"مرفوعة بالكامل كي لا تعلق؛ وثبّت ذراع التدوير."},"99":{"q":"لتوجيه المقطورة إلى اليمين أثناء الرجوع للخلف، أدر العجلة أولاً:","options":["يميناً","يساراً، ثم اتبعها","مستقيمة","لا يمكنك التوجيه أثناء الرجوع للخلف"],"explanation":"الرجوع بمقطورة عكسي؛ أدر يساراً أولاً ثم اتبعها."},"100":{"q":"يجب أن تكون أختام وصلات \"كف اليد\" (glad-hand):","options":["منزوعة لإحكام أفضل","بحالة جيدة","مغطاة بالزيت","موصولة بشكل متقاطع"],"explanation":"الأختام البالية تسرب الهواء وتقلل كبح المقطورة."},"101":{"q":"العاملان الرئيسيان لمنع الانقلاب هما خفض الحمولة و:","options":["السرعة العالية في المنعطفات","السرعة البطيئة في المنعطفات","الكبح الشديد","تغيير المسار السريع"],"explanation":"أبقِ الحمولة منخفضة ومتمركزة، وسر ببطء في المنعطفات."},"102":{"q":"بالمقارنة مع الشاحنة الفارغة، فإن الشاحنة المحمّلة بالكامل تكون:","options":["أقل عرضة للانقلاب بمقدار النصف","عرضة للانقلاب بالقدر نفسه","أكثر عرضة للانقلاب بعشر مرات","غير قادرة على الانقلاب"],"explanation":"الشاحنة المحمّلة لها مركز ثقل أعلى."},"103":{"q":"حركة توجيه سريعة وشديدة قد تسبب \"فرقعة السوط\" (crack the whip)، وهذا يعني:","options":["مقصورة الجرّار تدور خارجة عن السيطرة","المقطورة تتأرجح وقد تنقلب","مكابح الخدمة تفقد فعاليتها","محرك الديزل يتوقف"],"explanation":"التضخيم الخلفي (rearward amplification)؛ وجّه برفق وسلاسة."},"104":{"q":"إذا بدأت مقطورتك بالانزلاق، عليك أن:","options":["تستخدم الصمام اليدوي","تحرر المكابح","تكبح بقوة أكبر","تزيد السرعة"],"explanation":"حرر المكابح كي تستعيد عجلات المقطورة قبضتها."},"105":{"q":"انكسار الجرّار (jackknife) يبدأ عندما:","options":["تنقفل عجلات المقطورة","تنزلق عجلات الدفع","تتآكل إطارات التوجيه","تنزل عجلات الإسناد"],"explanation":"انزلاق عجلة الدفع يؤرجح الجرّار؛ خفف الضغط على المكبح."},"106":{"q":"الجرّار المنفرد (bobtail) بلا مقطورة عادة:","options":["يتوقف بمسافة أقصر بكثير","يستغرق وقتاً أطول للتوقف","لا يمكن أن ينزلق","لديه أفضل تماسك"],"explanation":"قلة الوزن على محور الدفع تعني تماسكاً ضعيفاً."},"107":{"q":"فقدان الضغط في خط الطوارئ يسبب:","options":["لا شيء على الإطلاق","تفعيل مكابح الطوارئ في المقطورة","تسارع المقطورة فوراً","تعطل مصابيح المقطورة"],"explanation":"الانفصال يفعّل مكابح الطوارئ في المقطورة."},"108":{"q":"خط الخدمة يحمل:","options":["إشارة دواسة المكابح","هواءً لنفخ الإطارات","إضاءة المقطورة","لا شيء أثناء القيادة"],"explanation":"يرسل الإشارة من دواسة المكابح أو الصمام اليدوي."},"109":{"q":"المقبض الأحمر لهواء المقطورة يخرج من تلقاء نفسه عند حوالي:","options":["55–60 رطل/بوصة مربعة (psi)","20–45 رطل/بوصة مربعة (psi)","5–10 رطل/بوصة مربعة (psi)","100 رطل/بوصة مربعة (psi)"],"explanation":"عند 20–45 رطل/بوصة مربعة (psi) يُغلق صمام حماية الجرّار."},"110":{"q":"إذا كانت وصلات \"كف اليد\" (glad hands) متقاطعة، فقد يكون لديك:","options":["مصابيح أكثر سطوعاً","لا مكابح للمقطورة","قيادة أكثر سلاسة","استهلاك وقود أفضل"],"explanation":"الخطوط المتقاطعة ترسل الهواء إلى المكان الخطأ."},"111":{"q":"تجهّز الجرّار للوصل عن طريق:","options":["الرجوع للخلف بزاوية","المحاذاة مباشرة أمامها","التقدم للأمام فوقها","الاقتراب من الجانب"],"explanation":"لا ترجع للخلف بزاوية أبداً؛ حاذِ بشكل مستقيم."},"112":{"q":"قبل الرجوع للخلف تحت المقطورة، يجب أن تكون المقطورة:","options":["مستندة على الأرض","منخفضة بما يكفي ليُرفعها قليلاً","أعلى من العجلة الخامسة","عند أي ارتفاع"],"explanation":"ينبغي أن يرفعها الجرّار قليلاً عند الرجوع للخلف تحتها."},"113":{"q":"يجب أن يكون ذراع تحرير العجلة الخامسة:","options":["مسحوباً ومفتوحاً بالكامل","مقفولاً والمزلاج الأماني مغلقاً","منزوعاً بالكامل","مرتخياً ويصدر صليلاً"],"explanation":"مشتبكاً/مقفولاً مع المزلاج الأماني فوقه."},"114":{"q":"العجلة الخامسة المنزلقة يجب أن تكون:","options":["إلى الأمام قدر الإمكان","مقفولة والمسامير مشتبكة","متروكة مرتخية","مضبوطة بالوزن فقط"],"explanation":"مقفولة في مكانها؛ المنزلق غير المقفول خطير."},"115":{"q":"العجلة الخامسة المنزلقة المضبوطة إلى الأمام أكثر من اللازم:","options":["تحسّن القيادة","تُحمّل محور التوجيه بشكل زائد","تخفف الوزن عن محور التوجيه","ليس لها أي تأثير"],"explanation":"تضع وزناً زائداً على محور التوجيه وتقلل الخلوص الأرضي."},"116":{"q":"يجب أن تكون خطوط الهواء والكهرباء:","options":["متروكة تتدلى لتوفير الارتخاء","مثبتة وغير متدلية","ملفوفة بإحكام شديد","مفصولة عند الانعطاف"],"explanation":"الخطوط المتدلية قد تتعرض للتلف أو الانتزاع."},"117":{"q":"واقيات الطين (واقيات الرذاذ) يجب أن تكون:","options":["مُزالة لتوفير الوقود","موجودة ومثبتة","متدلية على الطريق","مصنوعة من المعدن"],"explanation":"إنها تقلل من تطاير الرذاذ على المركبات التي تسير خلفك."},"118":{"q":"عند فك القطر، قبل أن تتحرك بالشاحنة للخارج يجب أن:","options":["ترفع عجلات الهبوط للأعلى","تخفض عجلات الهبوط لتدعم المقطورة","تحرر فرامل ركن المقطورة","تتقدم للأمام بسرعة مبتعداً"],"explanation":"اخفض عجلات الهبوط، ثم افصل الخطوط، ثم قم بإلغاء القفل."},"119":{"q":"مصباح خلل نظام منع انغلاق الفرامل (ABS) في المقطورة يكون عادةً:","options":["داخل المقصورة","أصفر، على الجانب الأيسر","على مسمار الارتكاز","غير موجود"],"explanation":"إذا ظل مضاءً، فإن نظام ABS في المقطورة لا يعمل."},"120":{"q":"لتجنب خطر ما في مركبة مركّبة، يكون الأفضل عادةً أن:","options":["تضغط الفرامل بقوة وتوجّه","توجّه بسلاسة، ثم تعود","تقفل الفرامل","تستخدم الصمام اليدوي"],"explanation":"وجّه بشكل مضاد بسلاسة؛ فالكبح القوي قد يسبب انثناء المقطورة."},"121":{"q":"الفحص الصحيح للقطر يتضمن:","options":["عدم وجود فجوة عند العجلة الخامسة","فكوك مطبقة حول مسمار الارتكاز","اختبار شد ناجح","كل ما سبق"],"explanation":"كل النقاط الثلاث تؤكد قطراً آمناً."},"122":{"q":"أي مما يلي ليس خطوة من خطوات القطر؟","options":["محاذاة الجرّار","الرجوع تحت المقطورة والقفل","تفريغ خزانات الهواء","توصيل خطوط الهواء"],"explanation":"تفريغ الخزانات ليس جزءاً من عملية القطر."},"123":{"q":"علقت مقطورتك المنخفضة على معبر سكة حديد. يجب أن:","options":["تحاول هزّها لتحريرها","تخرج وتتصل برقم الطوارئ المعلن","تفصل المقطورة فوق القضبان","تجلس وتنتظر داخل المقصورة"],"explanation":"غادر المركبة واتصل باستخدام رقم المعبر التابع لوزارة النقل (DOT)."},"124":{"q":"المركبة المركّبة هي:","options":["حافلة مدينة كبيرة واحدة","جرّار يقطر مقطورة واحدة أو أكثر","شاحنة بيك أب صغيرة فقط","دراجة نارية بعجلتين"],"explanation":"المركبة المركّبة هي وحدة قدرة (جرّار) مقترنة بمقطورة واحدة أو أكثر."},"125":{"q":"مسمار ارتكاز المقطورة يُقفل داخل:","options":["المصد الخلفي","فكوك العجلة الخامسة","واقي الطين","المصباح الخلفي"],"explanation":"ينزلق مسمار الارتكاز داخل العجلة الخامسة وتُطبق الفكوك القافلة حوله."},"126":{"q":"يجب الحفاظ على العجلة الخامسة:","options":["جافة وصدئة","مشحّمة (مزيّتة)","مطلية بألوان زاهية","مرتخية ومهترئة"],"explanation":"حافظ على تشحيم العجلة الخامسة بشكل صحيح لتدور بسلاسة وللحد من التآكل."},"127":{"q":"اللوح المسطح أسفل مقدمة المقطورة الذي يرتكز على العجلة الخامسة هو:","options":["المصد الأمامي","لوح الارتكاز (الأبرون)","غطاء المحرك","لوحة القيادة"],"explanation":"يرتكز لوح ارتكاز المقطورة بشكل مسطح على العجلة الخامسة؛ ويمتد مسمار الارتكاز للأسفل منه."},"128":{"q":"للتأكد من إطباق الفكوك القافلة، يجب أن:","options":["تطرق على جميع الإطارات","تنظر تحتها بمصباح يدوي","تنفخ بوق السيارة مرتين","تتفقد راديو المقصورة"],"explanation":"انظر مباشرةً تحت المقطورة بمصباح لترى الفكوك مطبقة حول مسمار الارتكاز."},"129":{"q":"قبل الرجوع تحت المقطورة، تضبط ارتفاعها بحيث يقوم الجرّار بـ:","options":["الضغط عليها بشدة للأسفل","رفع المقطورة قليلاً أثناء رجوعه تحتها","تفويتها بالكامل","قلبها إلى أحد الجانبين"],"explanation":"اضبط ارتفاع المقطورة بحيث يرفعها الجرّار قليلاً عندما تنزلق العجلة الخامسة تحتها."},"130":{"q":"خط الإمداد (الطوارئ) للهواء:","options":["يشغّل راديو المقصورة","يشحن خزانات هواء المقطورة","يفتح أبواب المقطورة","يبرّد المقصورة"],"explanation":"يرسل خط الإمداد الهواء لملء خزانات هواء المقطورة."},"131":{"q":"تعمل فرامل المقطورة النابضية (الطوارئ) عندما:","options":["يكون راديو المقصورة مشغّلاً","يفقد خط الإمداد الهواء","تنفخ بوق السيارة","تومض مصابيح التحديد"],"explanation":"فقدان الهواء في خط الإمداد يسمح لفرامل المقطورة النابضية بالتفعيل."},"132":{"q":"المركبة المركّبة الأطول تحتاج إلى مسافة اتباع ___:","options":["أقل بكثير","أكبر من المعتاد","بلا أي إضافة","صفر إضافة"],"explanation":"المركبات الأطول والأثقل تستغرق وقتاً أطول للتوقف وتحتاج إلى مسافة أكبر."},"133":{"q":"نظراً لأن المقطورة تنحرف للداخل أثناء الدوران، يجب أن تبدأ الانعطاف:","options":["أبكر مما تفعل السيارة","متأخراً قليلاً لتمر المقطورة بأمان","دون استخدام أي إشارة","بأقصى سرعة على الطريق المفتوح"],"explanation":"تنحرف عجلات المقطورة إلى داخل مسار الجرّار، لذا ابدأ الانعطاف متأخراً قليلاً وراقب المقطورة."},"134":{"q":"لركن مركبة مركّبة بأمان، يجب أن:","options":["تتركها مركونة في وضع الترس فقط","تشغّل الفرامل وتضع إسفيناً أسفل العجلات","تترك المحرك يعمل في وضع الخمول","تخفض سقف المقطورة للأسفل"],"explanation":"شغّل فرامل الركن؛ وضع إسفيناً أسفل العجلات عند المنحدر أو عند فك القطر."},"135":{"q":"الصمام اليدوي للمقطورة يجب ألا يُستخدم:","options":["لاختبار فرامل سريع","لتثبيت مقطورة مركونة","على منحدر شديد فقط","على أرض مستوية فقط"],"explanation":"لا تستخدم الصمام اليدوي للركن — فقد يتسرب الهواء وقد تتدحرج المقطورة."},"136":{"q":"استخدام الصمام اليدوي للمقطورة وحده أثناء الانزلاق قد يسبب:","options":["توقفاً سلساً ولطيفاً","انزلاق المقطورة أو انثناءها","رحلة أسرع بكثير","محركاً أبرد"],"explanation":"كبح المقطورة وحدها بالصمام اليدوي قد يجعلها تنزلق؛ استخدم فرامل القدم."},"137":{"q":"بالمقارنة مع المقطورات المحمّلة، فإن المقطورات الفارغة:","options":["تتشبث بالطريق بشكل أفضل","ترتد وتنزلق بسهولة أكبر","تتوقف دائماً بشكل أسرع","لا تنقلب أبداً"],"explanation":"المقطورات الخفيفة أو الفارغة تمتلك التصاقاً أقل بالطريق وترتد؛ اكبح بلطف."},"138":{"q":"الكابل الكهربائي (البِغتيل) بين الجرّار والمقطورة يغذّي:","options":["محرك الجرّار","مصابيح المقطورة ونظام ABS","إطارات الجرّار","العجلة الخامسة"],"explanation":"يوفر كابل البِغتيل الطاقة لمصابيح المقطورة ونظام منع الانغلاق."},"139":{"q":"يجب أن تفحص تثبيت العجلة الخامسة بحثاً عن:","options":["مظهر نظيف ولامع جميل","شقوق ومسامير مرتخية أو مفقودة","اللون الصحيح تماماً فقط","راديو مقصورة يعمل"],"explanation":"افحص منصة العجلة الخامسة ومسامير تثبيتها بحثاً عن شقوق أو ارتخاء."},"140":{"q":"العجلة الخامسة المنزلقة تتيح لك:","options":["تغيير لونها","نقل الوزن بين المحاور","إضافة مقاعد إضافية","تشغيل موسيقى صاخبة"],"explanation":"تحريكها يضبط توزيع الوزن على محاور الجرّار."},"141":{"q":"يجب أن تكون خزانات هواء المقطورة:","options":["مطلية باللون الأحمر الزاهي","مُصرّفة من الماء والزيت","مملوءة بالماء دائمًا","مُزالة بالكامل"],"explanation":"صرّف خزانات المقطورة مثل خزانات الجرار لإزالة الماء والزيت."},"142":{"q":"بعد شحن هواء المقطورة، يجب أن تقوم بعد ذلك بـ:","options":["تجاهل الفرامل تمامًا","اختبار عمل فرامل المقطورة","إزالة خطوط إمداد الهواء","إنزال المقطورة"],"explanation":"بعد الشحن، اختبر فرامل الخدمة وفرامل الطوارئ في المقطورة قبل الانطلاق على الطريق."},"143":{"q":"المركبة المركّبة أطول من السيارة، لذا انتبه إلى:","options":["انخفاض مستوى الوقود الشديد","الخلوص العلوي (الجسور، اللافتات)","صوت راديو الكابينة العالي","طقس الشتاء البارد"],"explanation":"تحقق من ارتفاعات الخلوص المُعلنة ولا تفترض أنها كافية للمرور؛ فقد تكون المركبة أعلى من اللازم."},"144":{"q":"يجب أن تكون أضواء التحديد والخلوص والأضواء الخلفية للمقطورة:","options":["مطفأة دائمًا","تعمل وبالألوان الصحيحة","مطلية بالكامل","مُزالة من المقطورة"],"explanation":"يجب أن تعمل أضواء المقطورة وتُظهر الألوان الصحيحة في الأمام والخلف."},"145":{"q":"إذا لم يكن مسمار الارتكاز (kingpin) مقفلًا في العجلة الخامسة، فإن المقطورة قد:","options":["تفرمل بشكل أفضل بكثير","تنفصل عن الجرار","تسير أسرع بكثير","توفّر وقودًا إضافيًا"],"explanation":"يمكن أن يؤدي مسمار الارتكاز غير المقفل إلى انفصال المقطورة — تحقق دائمًا من الفكوك."},"146":{"q":"مسافة توقف المركبة المركّبة المحمّلة هي:","options":["أقصر من مسافة توقف السيارة","أطول من مسافة توقف مركبة أخف","صفر قدم بالضبط","نفس مسافة توقف سيارة صغيرة"],"explanation":"تحتاج المركبات المركّبة الأثقل إلى مسافة أكبر للتوقف؛ فاترك مساحة أكبر."},"147":{"q":"يجب أن يشمل الفحص الدائري للمركبة المقترنة:","options":["منطقة كابينة الجرار فقط","إطارات المقطورة، الأضواء، الفرامل، الوصلات","زجاج مرآة جانبية واحدة فقط","لا حاجة لأي شيء إضافي حقًا"],"explanation":"افحص إطارات المقطورة، والأضواء، والفرامل، ووصلة الاقتران، وخطوط الهواء والكهرباء."},"148":{"q":"ماذا يفعل نظام ABS عندما تفرمل بقوة؟","options":["يمنع العجلات من الانغلاق حتى تتمكن من التوجيه","يقصّر مسافة التوقف","يوقف الشاحنة أسرع من الفرامل العادية","يتيح لك تجاوز التباطؤ عند المنعطفات"],"explanation":"لا يقصّر نظام ABS مسافة التوقف؛ بل يمنع فقط العجلات من الانغلاق حتى تتمكن من التوجيه."},"149":{"q":"ماذا يفعل نظام ABS لشاحنتك؟","options":["يمنع العجلات من الانغلاق حتى تتمكن من التوجيه","يقصّر مسافة التوقف","يوقف الشاحنة أسرع","يحل محل فرملة الانتظار"],"explanation":"لا يقصّر نظام ABS مسافة التوقف؛ بل يمنع فقط العجلات من الانغلاق حتى تتمكن من التوجيه."},"150":{"q":"في الاقتران الصحيح، أين يجب أن تُغلق الفكوك القافلة؟","options":["مغلقة تمامًا حول ساق مسمار الارتكاز","فوق مسمار الارتكاز","حول مقبض العجلة الخامسة","حول ساق عجلة الهبوط"],"explanation":"في الاقتران الصحيح تكون الفكوك القافلة مغلقة تمامًا حول ساق مسمار الارتكاز، وليس فوقه."},"151":{"q":"كيف يجب أن تمسك الفكوك القافلة بمسمار الارتكاز؟","options":["مغلقة تمامًا حول ساق مسمار الارتكاز","ممسكة بطرف مسمار الارتكاز فقط","مستقرة فوق مسمار الارتكاز","فضفاضة بجانب مسمار الارتكاز"],"explanation":"يجب أن تُغلق الفكوك القافلة تمامًا حول ساق مسمار الارتكاز، لا أن تمسك بالطرف فقط أو تستقر فوقه."},"152":{"q":"تحدث معظم حوادث انقلاب المركبات المركّبة أثناء أي جزء من القيادة؟","options":["المنعطف","المسافة المستقيمة","التوقف الكامل","الرجوع للخلف"],"explanation":"تحدث معظم حوادث انقلاب المركبات المركّبة بسبب السرعة الزائدة في المنعطف."},"153":{"q":"إبقاء الحمولة منخفضة يمنح المركبة المركّبة ماذا؟","options":["مركز ثقل منخفض","سرعة قصوى أعلى","خطوط هواء أقصر","استهلاكًا أفضل للوقود"],"explanation":"إبقاء الحمولة منخفضة يمنح المركبة مركز ثقل منخفضًا للمساعدة في منع الانقلاب."},"154":{"q":"في المنعطف، تتبع العجلات الخلفية للمقطورة مسارًا يكون كيف مقارنة بالعجلات الأمامية للجرار؟","options":["أضيق","أوسع","مطابق","أطول إجمالًا"],"explanation":"بسبب الانحراف عن المسار، تتبع العجلات الخلفية للمقطورة مسارًا أضيق وأكثر داخلية من العجلات الأمامية للجرار."},"155":{"q":"يمكن أن يتسبب التضخيم الخلفي في أن تقوم المقطورة الخلفية بـ:","options":["الانقلاب","تسريع السرعة","التوقف فجأة","السير بشكل أكثر استقامة"],"explanation":"يجعل التضخيم الخلفي المقطورة الخلفية تتأرجح بشكل أوسع بكثير ويمكن أن يقلبها."},"156":{"q":"ماذا يجب أن تراقب لاكتشاف بداية انثناء المقطورة (jackknife)؟","options":["مراياك","مقياس الوقود","عداد الدوران (التاكومتر)","وصلات اليد الباردة (glad hands)"],"explanation":"راقب مراياك حتى ترى متى تبدأ المقطورة في التأرجح للخارج."},"157":{"q":"إطلاق الفرامل أثناء انزلاق المقطورة يتيح للعجلات أن تقوم بـ:","options":["الدوران مجددًا واستعادة الالتصاق","الانغلاق بإحكام أكبر","التبريد بشكل أسرع","تطبيق فرامل الزنبرك"],"explanation":"إطلاق الفرامل يتيح للعجلات المنغلقة أن تدور مجددًا فتستعيد الالتصاق."},"158":{"q":"ينتج انثناء الجرار عن الفرملة بقوة شديدة وانغلاق أي عجلات؟","options":["عجلات الدفع","عجلات المقطورة","عجلات التوجيه","عجلات العربة المساعدة (dolly)"],"explanation":"انغلاق عجلات الدفع بسبب الفرملة بقوة شديدة يجعل الجرار يتأرجح ويحدث انثناء."},"159":{"q":"يتم وصل خطي الهواء في المركبة المركّبة بأي موصلات؟","options":["موصلات اليد الباردة (glad-hand)","موصلات مسمار الارتكاز","موصلات الضفيرة (pigtail)","موصلات العربة المساعدة (dolly)"],"explanation":"يتم وصل خطي هواء الخدمة والطوارئ بموصلات اليد الباردة (glad-hand)."},"160":{"q":"ما هو رمز اللون لخط هواء الخدمة (التحكم)؟","options":["أزرق","أحمر","أخضر","أصفر"],"explanation":"خط هواء الخدمة (التحكم) مرمّز بالون الأزرق."},"161":{"q":"أي خط هواء يتحكم في فرامل الطوارئ/الزنبرك في المقطورة؟","options":["خط الطوارئ","خط الخدمة","خط التحكم","ضفيرة الإمداد (supply pigtail)"],"explanation":"يشحن خط الطوارئ خزانات هواء المقطورة ويتحكم في فرامل الطوارئ/الزنبرك."},"162":{"q":"ما هو اللقب الآخر لصمام يد المقطورة؟","options":["عتلة جونسون (Johnson bar)","ذراع مسمار الارتكاز","اليد الباردة (glad hand)","ونش العربة المساعدة (dolly crank)"],"explanation":"صمام يد المقطورة هو ذراع الترولي أو عتلة جونسون (Johnson bar)."},"163":{"q":"لماذا يجب ألا تستخدم صمام يد المقطورة لمنع الانثناء (jackknife)؟","options":["لأنه يطبّق فرامل المقطورة فقط","لأنه يطبّق جميع الفرامل بقوة شديدة","لأنه يحرر فرامل الزنبرك","لأنه يشحن خزانات الهواء"],"explanation":"يطبّق صمام اليد فرامل المقطورة فقط، لذا لا يمكنه منع الانثناء."},"164":{"q":"تقفل العجلة الخامسة على مسمار الارتكاز باستخدام ماذا؟","options":["الفكوك القافلة","اليد الباردة (glad hands)","عجلة الهبوط","الضفيرة (pigtail)"],"explanation":"تقفل الفكوك القافلة في العجلة الخامسة على مسمار ارتكاز المقطورة."},"165":{"q":"إلى جانب مقبض التحرير، ما الذي يبقي العجلة الخامسة مقفلة؟","options":["مزلاج أمان","يد باردة (glad hand)","عربة محوّل مساعدة (converter dolly)","مشبك ضفيرة (pigtail clip)"],"explanation":"يبقي مقبض التحرير ومزلاج الأمان العجلة الخامسة مقفلة."},"166":{"q":"في عملية الوصل الصحيحة، يجب أن تُطبق الفكوك القافلة حول ماذا من المسمار الملكي (kingpin)؟","options":["الساق","الطرف فقط","الجزء العلوي فقط","لوحة القاعدة"],"explanation":"يجب أن تُطبق الفكوك القافلة بالكامل حول ساق المسمار الملكي (kingpin)، وليس حول الجزء العلوي أو الطرف."},"167":{"q":"في عملية الوصل الصحيحة، ما مقدار الفجوة بين العجلة الخامسة العلوية والسفلية؟","options":["لا توجد فجوة","فجوة صغيرة","فجوة واسعة","فجوة بمقدار نصف بوصة"],"explanation":"يجب ألا تكون هناك أي فجوة بين العجلة الخامسة العلوية والسفلية."},"168":{"q":"إذا كانت العجلة الخامسة متقدمة أكثر من اللازم، فماذا قد يحدث؟","options":["قد تصطدم المقطورة بالكابينة","ستجلس المقطورة منخفضة أكثر من اللازم","ستعلق أرجل الإسناد","سيُفصل القابس الكهربائي (pigtail)"],"explanation":"يجب ألا تكون العجلة الخامسة متقدمة إلى درجة قد تصطدم فيها المقطورة بالكابينة."},"169":{"q":"قبل الرجوع للوصل، كيف يجب ضبط ارتفاع المقطورة مقارنةً بمركز العجلة الخامسة؟","options":["أخفض قليلاً","أعلى قليلاً","بمستوى مساوٍ تماماً","أعلى بكثير"],"explanation":"يجب أن تكون المقطورة أخفض قليلاً من مركز العجلة الخامسة كي ترتفع قليلاً أثناء الرجوع للوصل."},"170":{"q":"قبل القيادة، في أي وضع يجب أن تكون أرجل الإسناد (landing gear)؟","options":["مرفوعة بالكامل","منخفضة جزئياً","ملامسة للأرض فقط","مرفوعة إلى المنتصف"],"explanation":"يجب أن تكون أرجل الإسناد مرفوعة بالكامل وذراع التدوير مثبتاً قبل القيادة."},"171":{"q":"عند الفصل، يجب خفض أرجل الإسناد حتى تفعل ماذا؟","options":["تلامس الأرض فقط","ترفع المقطورة بالكامل","تصل إلى منتصف المسافة","تبقى مرفوعة بالكامل"],"explanation":"اخفض أرجل الإسناد حتى تلامس الأرض فقط، دون رفع المقطورة عن العجلة الخامسة."}},"learn-hazmat":{"0":{"q":"ما التصريح المطلوب لنقل المواد الخطرة (HazMat) التي تتطلب لوحات تحذيرية؟","options":["H (أو X)","N (أو X)","التصريح T","التصريح P"],"explanation":"يتطلب نقل المواد الخطرة (HazMat) التي تستوجب لوحات تحذيرية التصريح H، أو X الذي يجمع بين تصريح الصهاريج وتصريح المواد الخطرة."},"1":{"q":"ماذا يتطلب التصريح H/X قبل إصداره؟","options":["فحص النظر والسمع","فحص خلفية أمنية من إدارة أمن النقل (TSA) وأخذ البصمات","إعفاء طبي من شركة النقل","اختبار مهارات الفرامل الهوائية"],"explanation":"يتطلب التصريح H/X تقييماً أمنياً للتهديدات من إدارة أمن النقل (TSA)، وفحص خلفية، وأخذ البصمات."},"2":{"q":"من الذي يصنّف ويغلّف ويعنون ويُعِدّ مستندات الشحن؟","options":["السائق","شركة النقل","الشاحن (المُرسِل)","المُستلِم"],"explanation":"يقوم الشاحن (المُرسِل) بتصنيف وتغليف وعنونة شحنة المواد الخطرة وإعداد مستندات الشحن لها."},"3":{"q":"من الذي ينقل المواد الخطرة ويبلّغ عن الحوادث؟","options":["الشاحن (المُرسِل)","السائق","المفتش","شركة النقل"],"explanation":"تتولى شركة النقل نقل المواد الخطرة والإبلاغ عن الحوادث."},"4":{"q":"ماذا يجب أن يفعل السائق بشحنة مواد خطرة مُسرِّبة؟","options":["يرفضها","يعنونها","يصنّفها","يغلّفها"],"explanation":"يجب على السائق أن يرفض شحنة المواد الخطرة المُسرِّبة أو غير المُعَلَّمة بشكل صحيح وألا ينقلها."},"5":{"q":"من المسؤول عن النقل الآمن للمواد الخطرة؟","options":["السائق فقط","الشاحن وشركة النقل والسائق","الشاحن فقط","شركة النقل فقط"],"explanation":"يتقاسم الشاحن وشركة النقل والسائق جميعاً المسؤولية عن النقل الآمن للمواد الخطرة."},"6":{"q":"ما هي فئة الخطر الخاصة بالمتفجرات؟","options":["الفئة 3","الفئة 7","الفئة 1","الفئة 2"],"explanation":"فئة الخطر 1 هي المتفجرات."},"7":{"q":"ما هي فئة الخطر الخاصة بالغازات؟","options":["الفئة 5","الفئة 8","الفئة 6","الفئة 2"],"explanation":"فئة الخطر 2 هي الغازات، وتنقسم إلى 2.1 القابلة للاشتعال، و2.2 غير القابلة للاشتعال، و2.3 الغازات السامة."},"8":{"q":"ما هي فئة الخطر الخاصة بالسوائل القابلة للاشتعال؟","options":["الفئة 3","الفئة 2","الفئة 4","الفئة 8"],"explanation":"فئة الخطر 3 هي السوائل القابلة للاشتعال."},"9":{"q":"ما فئة الخطر التي تشمل المواد الصلبة القابلة للاشتعال والمواد الخطرة عند البلل؟","options":["الفئة 3","الفئة 4","الفئة 5","الفئة 6"],"explanation":"تشمل فئة الخطر 4 المواد الصلبة القابلة للاشتعال والمواد القابلة للاشتعال التلقائي، بما في ذلك 4.3 المواد الخطرة عند البلل."},"10":{"q":"ما فئة الخطر التي تشمل المؤكسِدات والبيروكسيدات العضوية؟","options":["الفئة 3","الفئة 4","الفئة 5","الفئة 6"],"explanation":"تشمل فئة الخطر 5 المؤكسِدات والبيروكسيدات العضوية."},"11":{"q":"ما فئة الخطر التي تشمل المواد السامة أو المُعدِية؟","options":["الفئة 3","الفئة 4","الفئة 8","الفئة 6"],"explanation":"تشمل فئة الخطر 6 المواد السامة أو المُعدِية، بما في ذلك 6.1 المواد السامة (الضارة)."},"12":{"q":"ما هي فئة الخطر الخاصة بالمواد المشعّة؟","options":["الفئة 7","الفئة 5","الفئة 8","الفئة 9"],"explanation":"فئة الخطر 7 هي المواد المشعّة."},"13":{"q":"ما هي فئة الخطر الخاصة بالمواد الأكّالة؟","options":["الفئة 6","الفئة 8","الفئة 7","الفئة 9"],"explanation":"فئة الخطر 8 هي المواد الأكّالة."},"14":{"q":"ما هي فئة الخطر الخاصة بالمواد المتنوعة؟","options":["الفئة 6","الفئة 7","الفئة 9","الفئة 8"],"explanation":"فئة الخطر 9 هي المواد المتنوعة."},"15":{"q":"كيف يجب تعليم مدخلات المواد الخطرة في عمود HM في مستندات الشحن؟","options":["محاطة بدائرة حمراء","بزاوية مطوية","مختومة بكلمة \"OK\"","بعلامة \"X\" أو \"RQ\""],"explanation":"يجب تحديد مدخلات المواد الخطرة بوضوح، أو تظليلها أو تعليمها بعلامة \"X\" أو \"RQ\" في عمود HM."},"16":{"q":"بأي ترتيب يجب إدراج مدخل المواد الخطرة في مستندات الشحن؟","options":["اسم الشحن، فئة الخطر، رقم التعريف","فئة الخطر، اسم الشحن، رقم التعريف","رقم التعريف، اسم الشحن، فئة الخطر","اسم الشحن، رقم التعريف، فئة الخطر"],"explanation":"يجب أن تُدرَج مدخلات المواد الخطرة باسم الشحن الصحيح، ثم فئة الخطر، ثم رقم التعريف (UN/NA)، بهذا الترتيب."},"17":{"q":"أثناء القيادة، أين يجب الاحتفاظ بمستندات الشحن؟","options":["مقفلة في صندوق القفازات","في متناول يد السائق","تحت مقعد السائق","في حجرة النوم"],"explanation":"أثناء القيادة، يجب أن تكون مستندات الشحن في متناول يد السائق مع ربط حزام الأمان، وفوق المستندات الأخرى."},"18":{"q":"عند الخروج من الشاحنة، أين تترك مستندات الشحن؟","options":["في صندوق القفازات","تحت سجادة الأرضية","على مقعد السائق","في المقطورة"],"explanation":"عند الخروج من الشاحنة، اترك مستندات الشحن على مقعد السائق أو في جيب الباب."},"19":{"q":"على كم جانب من المركبة يجب عرض اللافتات التحذيرية (placards)؟","options":["جانب واحد","جانبان","ثلاثة جوانب","الجوانب الأربعة جميعها"],"explanation":"يجب وضع اللافتات التحذيرية على الجوانب الأربعة جميعها للمركبة وأن تكون قابلة للقراءة من الاتجاه الذي تواجهه."},"20":{"q":"ما المواد التي تتطلب لافتات تحذيرية بأي كمية كانت؟","options":["مواد الجدول 1","مواد الجدول 2","الفئة 9 فقط","المواد المسببة للتآكل فقط"],"explanation":"مواد الجدول 1، مثل الغاز السام 2.3 والمواد الخطرة عند البلل 4.3، تتطلب لافتات تحذيرية بأي كمية كانت."},"21":{"q":"عند أي وزن إجمالي كلي تتطلب مواد الجدول 2 لافتات تحذيرية؟","options":["501 رطل (lb) أو أكثر","1,001 رطل (lb) أو أكثر","1,001 رطل (lb) أو أقل","أي كمية"],"explanation":"تتطلب مواد الجدول 2 لافتات تحذيرية فقط عند نقل 1,001 رطل (lb) أو أكثر من الوزن الإجمالي الكلي."},"22":{"q":"على أي مسافة قبل سكة الحديد يجب أن تتوقف المركبة الحاملة للافتات التحذيرية؟","options":["5–25 قدماً (feet)","10–40 قدماً (feet)","15–50 قدماً (feet)","25–75 قدماً (feet)"],"explanation":"يجب أن تتوقف المركبة الحاملة للافتات التحذيرية على مسافة 15–50 قدماً (feet) قبل سكة الحديد، وألا تعبر إلا إذا كان بإمكانها اجتيازها بالكامل."},"23":{"q":"ما مدى قربك من الجزء المستخدَم للسير من الطريق الذي يُسمح لك بالتوقف فيه عند حمل حمولة تحمل لافتات تحذيرية؟","options":["مطلقاً ضمن قدمين (2 feet)","مطلقاً ضمن 3 أقدام (feet)","مطلقاً ضمن 4 أقدام (feet)","مطلقاً ضمن 5 أقدام (feet)"],"explanation":"لا تتوقف مطلقاً ضمن 5 أقدام (feet) من الجزء المستخدَم للسير من الطريق عند حمل حمولة تحمل لافتات تحذيرية."},"24":{"q":"المتفجرات من الشعبة 1.1 أو 1.2 أو 1.3 يجب ألا تُترك أبداً كيف؟","options":["دون مراقبة","حاملة للافتات تحذيرية","أثناء التزود بالوقود","مميَّزة بألوان"],"explanation":"يجب ألا تُترك المتفجرات من الشعبة 1.1 أو 1.2 أو 1.3 دون مراقبة أبداً."},"25":{"q":"المتفجرات من الشعبة 1.1 أو 1.2 أو 1.3 لا يجوز إيقافها ضمن كم قدماً من جسر أو نفق؟","options":["100 قدم (feet)","300 قدم (feet)","500 قدم (feet)","50 قدماً (feet)"],"explanation":"لا يجوز إيقاف المتفجرات من الشعبة 1.1 أو 1.2 أو 1.3 ضمن 300 قدم (feet) من جسر أو نفق أو مبنى."},"26":{"q":"ما الذي يجب على سائق المواد الخطرة اتباعه دائماً عند اختيار المسار؟","options":["أقصر مسار","المسار ذو المناظر الخلابة","مسارات المواد الخطرة المحددة","المسار الخالي من الرسوم"],"explanation":"يجب على سائقي المواد الخطرة تجنب الأنفاق والمناطق المأهولة واتباع مسارات المواد الخطرة المحددة."},"27":{"q":"ضمن كم قدماً من مركبة تحمل لافتات تحذيرية وتنقل متفجرات أو مؤكسِدات أو مواد قابلة للاشتعال يُمنع التدخين؟","options":["5 أقدام (feet)","15 قدماً (feet)","50 قدماً (feet)","25 قدماً (feet)"],"explanation":"لا يُسمح بالتدخين ضمن 25 قدماً (feet) من مركبة تحمل لافتات تحذيرية وتنقل متفجرات أو مؤكسِدات أو مواد قابلة للاشتعال."},"28":{"q":"عند تزويد مركبة تحمل لافتات تحذيرية بالوقود، ما الذي يجب أن يكون صحيحاً بشأن المحرك؟","options":["يجب أن يكون متوقفاً","يجب أن يكون في وضع الخمول","يجب أن يكون دافئاً","يجب أن تُرفع سرعته"],"explanation":"عند التزود بالوقود، يجب أن يكون المحرك متوقفاً وأن يبقى شخص عند الفوهة للتحكم في تدفق الوقود."},"29":{"q":"أي إشارة تحذيرية يجب أن تستخدمها بالقرب من مركبة تنقل سائلاً قابلاً للاشتعال أو متفجرات؟","options":["الشُّعَل (flares)","المثلثات العاكسة","الفيوزات المضيئة (fusees)","اللهب المكشوف"],"explanation":"لا تستخدم أبداً الشُّعَل أو الفيوزات المضيئة أو اللهب بالقرب من المواد القابلة للاشتعال أو المتفجرات؛ استخدم المثلثات العاكسة بدلاً من ذلك."},"30":{"q":"كم مرة يجب أن تفحص الإطارات بعد بدء الرحلة؟","options":["كل 30 دقيقة أو 25 ميلاً (miles)","كل ساعة أو 50 ميلاً (miles)","كل ساعتين أو 100 ميل (miles)","كل 3 ساعات أو 150 ميلاً (miles)"],"explanation":"افحص الإطارات عند بدء كل رحلة وكل ساعتين أو 100 ميل (miles)."},"31":{"q":"ما الذي يجب فعله بإطار يتسرب أو يفرط في السخونة على حمولة تحمل لافتات تحذيرية؟","options":["إعادة نفخه والمتابعة","تغطيته بمشمّع","تركه على المركبة","إزالته وتبريده بعيداً عن المركبة"],"explanation":"يجب إزالة الإطار الذي يتسرب أو يفرط في السخونة على حمولة تحمل لافتات تحذيرية وتبريده بعيداً عن المركبة."},"32":{"q":"أي كتاب يجب أن تحمله وتعرفه عند نقل المواد الخطرة؟","options":["دليل الاستجابة للطوارئ (Emergency Response Guidebook)","دليل الناقل الفيدرالي للمركبات الآلية","دليل سائق تكساس","دليل فحص المركبات"],"explanation":"يجب أن تحمل دليل الاستجابة للطوارئ (ERG) وتعرفه عند نقل المواد الخطرة."},"33":{"q":"في حادث متعلق بالمواد الخطرة، من يبلّغ عن الحادث؟","options":["الشاحن (المُرسِل)","الناقل","السائق","المُرسَل إليه"],"explanation":"في حادث المواد الخطرة يبلّغ الناقل عن الحادث، بينما يحذّر السائق الآخرين ويُخطر CHEMTREC."},"34":{"q":"ما الذي يجب على السائق فعله بشحنة مواد خطرة متسربة؟","options":["نقلها ببطء","إعادة تعبئتها","رفضها","الإبلاغ عنها لاحقاً"],"explanation":"يجب على السائق رفض شحنة المواد الخطرة المتسربة أو ذات العلامات غير الصحيحة وعدم نقلها."},"35":{"q":"ماذا تمثل فئة الخطر 2.3؟","options":["غاز سام","غاز قابل للاشتعال","غاز غير قابل للاشتعال","غاز مسبب للتآكل"],"explanation":"في غازات الفئة 2، تمثل 2.1 الغاز القابل للاشتعال، و2.2 الغاز غير القابل للاشتعال، و2.3 الغاز السام."},"36":{"q":"ضمن الفئة 4، أي شعبة تمثل المادة الخطرة عند البلل؟","options":["الشعبة 4.1","الشعبة 4.3","الشعبة 4.2","الشعبة 4.4"],"explanation":"الشعبة 4.3 هي المادة الخطرة عند البلل ضمن الفئة 4."},"37":{"q":"أي نوع من المواد هي الشعبة 6.1؟","options":["مادة مسببة للتآكل","مادة صلبة قابلة للاشتعال","مادة سامة","مادة مؤكسِدة"],"explanation":"الشعبة 6.1 هي مادة سامة ضمن الفئة 6."},"38":{"q":"كيف يجب أن تُبيَّن مدخلات المواد الخطرة على مستندات الشحن؟","options":["مكتوبة بالقلم الرصاص فقط","موضوعة في الصفحة الأخيرة","مطبوعة بخط صغير","محددة بوضوح أو مميّزة بألوان"],"explanation":"يجب أن تكون مدخلات المواد الخطرة على مستندات الشحن محددة بوضوح، مثل تمييزها بألوان أو وضع علامة X أو RQ في عمود HM."},"39":{"q":"في مدخل مستند شحن للمواد الخطرة، رقم التعريف هو أي نوع من الأرقام؟","options":["رقم UN/NA","رقم رخصة القيادة","رقم لوحة المركبة","رمز منطقة الهاتف"],"explanation":"رقم التعريف المدرج في مدخل مستند شحن المواد الخطرة هو رقم UN/NA."},"40":{"q":"أثناء القيادة، أين يجب الاحتفاظ بمستندات شحن المواد الخطرة؟","options":["مقفلة داخل صندوق القفازات","فوق المستندات الأخرى","تحت المستندات الأخرى","داخل منطقة حمولة المقطورة"],"explanation":"أثناء القيادة، يجب الاحتفاظ بمستندات الشحن فوق المستندات الأخرى."},"41":{"q":"عند مغادرتك للشاحنة، أين يجوز ترك مستندات شحن المواد الخطرة؟","options":["مقفلة داخل صندوق القفازات","داخل المقطورة مع الحمولة","مطوية تحت سجادة الأرضية","على مقعد السائق أو في جيب باب السائق"],"explanation":"عند الخروج من الشاحنة، يجوز ترك مستندات شحن المواد الخطرة على مقعد السائق أو في جيب باب السائق."},"42":{"q":"كيف يجب أن تُوضع اللافتات التحذيرية على المركبة؟","options":["قابلة للقراءة من الاتجاه الذي تواجهه","قابلة للقراءة من الخلف فقط","مخفية خلف أبواب المقصورة","مكدّسة داخل المقطورة"],"explanation":"يجب أن تكون اللافتات التحذيرية قابلة للقراءة من الاتجاه الذي تواجهه."},"43":{"q":"كيف يُقاس حد 1,001 رطل (lb) لمواد الجدول 2؟","options":["الوزن الصافي للمادة فقط","الوزن الإجمالي الكلي للمواد","وزن المركبة المحمّلة","حجم المادة المعبأة"],"explanation":"يُقاس حد 1,001 رطل (lb) لمواد الجدول 2 على أنه الوزن الإجمالي الكلي."},"44":{"q":"عند عبور سكك الحديد، ما الذي يجب على المركبة التي تحمل لافتات خطر ألا تفعله؟","options":["استخدام إشارة الانعطاف","إنزال النافذة","تغيير التروس","تشغيل الأضواء"],"explanation":"يجب على المركبة التي تحمل لافتات خطر ألا تغيّر التروس أثناء عبور سكك الحديد."},"45":{"q":"متى يجوز للمركبة التي تحمل لافتات خطر عبور سكك الحديد؟","options":["عندما ترتفع البوابات","عندما تتوقف على السكة أولاً","عندما تكون حركة المرور خفيفة","عندما يمكنها تجاوز السكة بالكامل"],"explanation":"لا يجوز للمركبة التي تحمل لافتات خطر عبور سكك الحديد إلا إذا كان بإمكانها تجاوزها بالكامل دون التوقف على السكة."},"46":{"q":"لا يجوز إيقاف المتفجرات من الأقسام 1.1 أو 1.2 أو 1.3 على بُعد كم قدم من مبنى أو مكان يتجمع فيه الناس؟","options":["300 قدم","150 قدم","50 قدم","500 قدم"],"explanation":"لا يجوز إيقاف المتفجرات من الأقسام 1.1 أو 1.2 أو 1.3 على بُعد 300 قدم من مبنى أو مكان يتجمع فيه الناس."},"47":{"q":"عند نقل حمولة من المواد الخطرة، ما الذي يجب على السائقين تجنبه؟","options":["الطرق السريعة العريضة","الأنفاق","مناطق الاستراحة","أكشاك الرسوم"],"explanation":"يجب على السائقين تجنب الأنفاق والمناطق المكتظة بالسكان عند نقل حمولة من المواد الخطرة."},"48":{"q":"عند تزويد مركبة تحمل لافتات خطر بالوقود، من يجب أن يكون عند فوهة التزويد؟","options":["لا يُشترط أحد","رجل إطفاء فقط","شخص يتحكم في تدفق الوقود","الشاحن فقط"],"explanation":"عند التزويد بالوقود، يجب أن يكون هناك شخص عند فوهة التزويد يتحكم في تدفق الوقود."},"49":{"q":"ماذا يجب أن تستخدم كإشارة تحذير بالقرب من مركبة تنقل سائلاً قابلاً للاشتعال أو غازاً أو متفجرات؟","options":["الشعلات (Flares)","الفتائل المضيئة (Fusees)","لهب مكشوف","المثلثات العاكسة"],"explanation":"استخدم المثلثات العاكسة، وليس الشعلات أو الفتائل المضيئة أو أي لهب مكشوف، بالقرب من مركبة تنقل سائلاً قابلاً للاشتعال أو غازاً أو متفجرات."},"50":{"q":"متى يجب فحص إطارات المركبة التي تحمل لافتات خطر؟","options":["في بداية كل رحلة وكل ساعتين أو 100 ميل","فقط كل ساعتين أو 100 ميل","فقط في بداية كل رحلة","مرة واحدة فقط في نهاية كل رحلة"],"explanation":"يجب فحص الإطارات في بداية كل رحلة، وليس فقط كل ساعتين أو 100 ميل."},"51":{"q":"في حادث يتعلق بالمواد الخطرة، ماذا يجب على السائق فعله؟","options":["نقل الحمولة ومواصلة القيادة","تحذير الآخرين وإبعاد الناس ومنع التدخين","فتح الحمولة للتحقق من المحتويات","مغادرة الموقع للبحث عن المساعدة بسرعة"],"explanation":"في حادث يتعلق بالمواد الخطرة، يجب على السائق تحذير الآخرين وإبعاد الناس ومنع التدخين."},"52":{"q":"في حادث يتعلق بالمواد الخطرة، من يجب على السائق إبلاغه؟","options":["الشاحن فقط","العميل التالي","جهات الاستجابة للطوارئ / CHEMTREC","مكتب الضرائب في الولاية"],"explanation":"في حادث يتعلق بالمواد الخطرة، يجب على السائق إبلاغ جهات الاستجابة للطوارئ / CHEMTREC."},"53":{"q":"ما التصديقان اللذان يجمع بينهما تصديق X؟","options":["مركبة الصهريج والمواد الخطرة","مركبة الصهريج والركاب","المواد الخطرة والركاب","مركبة الصهريج والمقطورات المزدوجة/الثلاثية"],"explanation":"يجمع تصديق X بين تصديق مركبة الصهريج وتصديق المواد الخطرة."},"54":{"q":"أي تصديق على رخصة القيادة التجارية يتطلب تقييماً أمنياً للتهديدات من إدارة أمن النقل (TSA) وفحصاً للسوابق وأخذ البصمات؟","options":["تصديق الركاب (P)","تصديق المواد الخطرة (H أو X)","تصديق الحافلة المدرسية (S)","تصديق المقطورات المزدوجة/الثلاثية (T)"],"explanation":"يتطلب تصديق المواد الخطرة (H أو X) تقييماً أمنياً للتهديدات من إدارة أمن النقل (TSA) وفحصاً للسوابق وأخذ البصمات."},"55":{"q":"من المسؤول عن وضع لافتات الخطر على مركبة المواد الخطرة؟","options":["الشاحن","الناقل","السائق","الوسيط"],"explanation":"السائق هو من يضع لافتات الخطر على المركبة ويقود بأمان."},"56":{"q":"من المسؤول عن وضع الملصقات على طرد المواد الخطرة؟","options":["السائق","الناقل","المستلم","الشاحن"],"explanation":"الشاحن هو من يصنّف المادة ويعبّئها ويضع عليها الملصقات ويعدّ أوراق الشحن."},"57":{"q":"أي مهمة هي من مسؤولية الناقل وليست من مسؤولية الشاحن؟","options":["النقل والإبلاغ عن الحوادث","تصنيف المادة الخطرة","تعبئة المادة الخطرة","وضع الملصقات على المادة الخطرة"],"explanation":"الناقل ينقل الحمولة ويبلّغ عن الحوادث، بينما يقوم الشاحن بتصنيف المادة وتعبئتها ووضع الملصقات عليها."},"58":{"q":"أي قسم من الفئة 2 (الغازات) هو الغاز القابل للاشتعال؟","options":["القسم 2.2","القسم 2.1","القسم 2.3","القسم 2.4"],"explanation":"في الفئة 2 (الغازات)، القسم 2.1 هو الغاز القابل للاشتعال."},"59":{"q":"أي نوع من الغاز يمثله القسم 2.2؟","options":["غاز قابل للاشتعال","غاز سام","غاز غير قابل للاشتعال","غاز مؤكسد"],"explanation":"القسم 2.2 هو قسم الغاز غير القابل للاشتعال ضمن فئة الخطر 2 (الغازات)."},"60":{"q":"أي فئة خطر تشمل المواد القابلة للاشتعال التلقائي؟","options":["الفئة 3","الفئة 5","الفئة 8","الفئة 4"],"explanation":"تشمل الفئة 4 المواد الصلبة القابلة للاشتعال والمواد القابلة للاشتعال التلقائي والمواد الخطرة عند البلل (4.3)."},"61":{"q":"أي فئة خطر تشمل المواد المُعدية؟","options":["الفئة 6","الفئة 7","الفئة 8","الفئة 9"],"explanation":"تشمل الفئة 6 المواد السامة والمواد المُعدية."},"62":{"q":"إلى أي فئة خطر تنتمي البيروكسيدات العضوية؟","options":["الفئة 3","الفئة 5","الفئة 7","الفئة 8"],"explanation":"تشمل الفئة 5 المواد المؤكسدة والبيروكسيدات العضوية."},"63":{"q":"ما نوع المواد التي تغطيها فئة الخطر 1؟","options":["الغازات","المواد الأكّالة","المتفجرات","المواد المشعة"],"explanation":"فئة الخطر 1 هي المتفجرات."},"64":{"q":"في فئة الخطر 8، ما نوع المادة؟","options":["الغازات","المتفجرات","المواد المؤكسدة","المواد الأكّالة"],"explanation":"فئة الخطر 8 هي المواد الأكّالة."},"65":{"q":"في نظام فئات الخطر، ما الفئة التي تمثلها الفئة 9؟","options":["المواد الخطرة المتنوعة","المواد الخطرة الأكّالة","المواد الخطرة المشعة","المواد الخطرة المتفجرة"],"explanation":"فئة الخطر 9 هي فئة المواد الخطرة المتنوعة."},"66":{"q":"في إدخال أوراق شحن المواد الخطرة، أي عنصر يُدرج أولاً؟","options":["فئة الخطر","اسم الشحن الصحيح","رقم التعريف (UN/NA)","الوزن الإجمالي"],"explanation":"يُدرج في إدخال المواد الخطرة اسم الشحن الصحيح أولاً، ثم فئة الخطر، ثم رقم التعريف."},"67":{"q":"في أوراق الشحن، ماذا يفعل وضع علامة 'X' أو 'RQ' على إدخال في عمود HM؟","options":["يحدد الحد الأقصى لسرعة الشاحنة","يسجل اسم السائق","يحدده كإدخال للمواد الخطرة","يُظهر عنوان التسليم"],"explanation":"تحدد علامة 'X' أو 'RQ' في عمود HM الإدخال بوضوح على أنه شحنة مواد خطرة."},"68":{"q":"أين يجب أن تكون أوراق الشحن أثناء القيادة؟","options":["مقفلة في صندوق القفازات","في مقصورة النوم","في أي مكان داخل المقصورة","في متناول اليد مع ربط حزام الأمان"],"explanation":"يجب أن تبقى أوراق الشحن في متناول يد السائق مع ربط حزام الأمان، أو في جيب على باب السائق."},"69":{"q":"أثناء القيادة، أين يمكن الاحتفاظ بأوراق الشحن إلى جانب وجودها في متناول السائق؟","options":["في جيب على باب السائق","في منطقة الشحن الخلفية","داخل صندوق أدوات مقفل","تحت مقعد الراكب"],"explanation":"أثناء القيادة، يمكن الاحتفاظ بأوراق الشحن في جيب على باب السائق."},"70":{"q":"عند الخروج من الشاحنة، أين يمكن ترك أوراق الشحن بدلاً من مقعد السائق؟","options":["في صندوق القفازات","في جيب الباب","تحت دواسة الأرضية","في مقصورة النوم"],"explanation":"عند الخروج من الشاحنة، يمكن ترك أوراق الشحن على مقعد السائق أو في جيب الباب."},"71":{"q":"لماذا يجب أن تواجه كل لافتة الاتجاه الصحيح على المركبة؟","options":["لكي تزن أقل","لكي تكلف أقل","لكي تكون قابلة للقراءة من ذلك الاتجاه","لكي تدوم أطول"],"explanation":"يجب أن تكون اللافتات قابلة للقراءة من الاتجاه الذي تواجهه."},"72":{"q":"هل يتطلب الغاز السام من الفئة 2.3 لافتة بأي كمية؟","options":["لا، فقط فوق 1,001 رطل","لا، اللافتات ليست مطلوبة أبداً","فقط إذا تسرب","نعم، بأي كمية"],"explanation":"الغاز السام من الفئة 2.3 هو مادة من الجدول 1، لذا فهو يتطلب لافتات بأي كمية."},"73":{"q":"هل تتطلب مواد الفئة 4.3 الخطرة عند البلل لافتات بأي كمية؟","options":["نعم، تتطلب لافتات بأي كمية","لا، فقط عند 1,001 رطل أو أكثر","لا، فقط عند 5,000 رطل أو أكثر","لا، اللافتات ليست مطلوبة أبداً"],"explanation":"مواد الفئة 4.3 الخطرة عند البلل هي مادة من الجدول 1، لذا فهي تتطلب لافتات بأي كمية."},"74":{"q":"أي مادة من مواد الجدول 1 هي مادة سامة بالاستنشاق من الفئة 6.1 وتتطلب لافتات بأي كمية؟","options":["سائل أكّال من الفئة 8","مادة سامة بالاستنشاق من الفئة 6.1","مادة متنوعة من الفئة 9","سائل قابل للاشتعال من الفئة 3"],"explanation":"تشمل مواد الجدول 1 التي تحتاج إلى لافتات بأي كمية المادة السامة بالاستنشاق من الفئة 6.1."},"75":{"q":"هل تتطلب المتفجرات من الفئات 1.1 و1.2 و1.3 لافتات بأي كمية؟","options":["لا، فقط فوق 1,001 رطل","لا، اللافتات ليست مطلوبة أبداً","نعم، بأي كمية","فقط إذا نُقلت في صهريج"],"explanation":"المتفجرات من الفئات 1.1 و1.2 و1.3 هي مواد من الجدول 1 تتطلب لافتات بأي كمية."},"76":{"q":"المواد التي تحتاج إلى لافتات فقط عند 1,001 رطل أو أكثر موجودة في أي جدول؟","options":["الجدول 1","جدول رقم التعريف","جدول فئة الخطر","الجدول 2"],"explanation":"المواد الأخرى (الجدول 2) تتطلب لافتات فقط عند نقل 1,001 رطل أو أكثر."},"77":{"q":"عند التوقف قبل سكة الحديد، ما مدى قرب توقف المركبة التي تحمل لافتات؟","options":["ليس أقرب من 15 قدماً","ليس أقرب من 5 أقدام","ليس أقرب من 25 قدماً","ليس أقرب من 50 قدماً"],"explanation":"يجب أن تتوقف المركبة التي تحمل لافتات على بعد 15 إلى 50 قدماً قبل سكة الحديد، أي ليس أقرب من 15 قدماً."},"78":{"q":"ما أقصى مسافة قبل سكة الحديد يجب أن تتوقف عندها المركبة التي تحمل لافتات؟","options":["25 قدماً","50 قدماً","75 قدماً","100 قدم"],"explanation":"يجب أن تتوقف المركبة التي تحمل لافتات في حدود 15 إلى 50 قدماً قبل سكة الحديد، أي ليس أبعد من 50 قدماً."},"79":{"q":"قاعدة الـ 5 أقدام للحمولة التي تحمل لافتات تقيس المسافة من ماذا؟","options":["أقرب جسر أو نفق","أقرب سكة حديد","الجزء المُستخدم للسير من الطريق","أقرب مبنى أو حشد"],"explanation":"لا توقف المركبة أبداً على بعد أقل من 5 أقدام من الجزء المُستخدم للسير من الطريق مع حمولة تحمل لافتات."},"80":{"q":"قاعدة الوقوف على بعد 300 قدم بالقرب من الجسور والأنفاق والمباني تنطبق على أي متفجرات؟","options":["القسم 1.4 فقط","القسم 1.5 فقط","القسم 1.6 فقط","القسم 1.1 أو 1.2 أو 1.3"],"explanation":"لا يجوز وقوف المتفجرات من القسم 1.1 أو 1.2 أو 1.3 على بعد أقل من 300 قدم من جسر أو نفق أو مبنى أو مكان يتجمع فيه الناس."},"81":{"q":"قاعدة منع التدخين على بعد 25 قدماً تنطبق على المركبات التي تحمل لافتات وتنقل أي حمولة؟","options":["المتفجرات أو المؤكسدات أو المواد القابلة للاشتعال","المواد الأكّالة أو الغازات أو المواد المشعة","السموم أو المواد المعدية أو الحمولات الرطبة","أي مواد خطرة بأي كمية"],"explanation":"يُمنع التدخين على بعد أقل من 25 قدماً من مركبة تحمل لافتات وتنقل متفجرات أو مؤكسدات أو مواد قابلة للاشتعال."},"82":{"q":"عند تزويد مركبة تحمل لافتات بالوقود، ما الشرطان اللذان يجب توفرهما؟","options":["إيقاف المحرك وقفل الأبواب","إيقاف المحرك ووجود شخص عند الفوهة","تشغيل المحرك ووجود شخص عند الفوهة","تشغيل المحرك وقفل الأبواب"],"explanation":"عند التزود بالوقود، يجب أن يكون المحرك متوقفاً ويجب أن يكون هناك شخص عند الفوهة يتحكم في التدفق."},"83":{"q":"أي إشارة تحذير يجب ألا تستخدمها بالقرب من مركبة تنقل سائلاً قابلاً للاشتعال أو غازاً أو متفجرات؟","options":["المثلثات العاكسة","مصابيح التحذير","الشعلات أو الشموع التحذيرية","أضواء الخطر للطوارئ"],"explanation":"لا تستخدم أبداً الشعلات أو الشموع التحذيرية أو أي لهب مكشوف كإشارة تحذير بالقرب من مركبة تنقل سائلاً قابلاً للاشتعال أو غازاً أو متفجرات."},"84":{"q":"في رحلة مواد خطرة بمركبة تحمل لافتات، بعد كم ميل يجب أن تفحص الإطارات؟","options":["كل 25 ميلاً","كل 50 ميلاً","كل 200 ميل","كل 100 ميل"],"explanation":"افحص الإطارات في بداية كل رحلة وكل ساعتين أو 100 ميل."},"85":{"q":"ماذا يعني الاختصار ERG؟","options":["دليل الاستجابة للطوارئ","دليل توجيه الطوارئ","إرشادات الإبلاغ عن الطوارئ","التوجيه على جانب الطريق في الطوارئ"],"explanation":"يرمز ERG إلى دليل الاستجابة للطوارئ (Emergency Response Guidebook)، الذي يجب على سائقي المواد الخطرة حمله ومعرفته."},"86":{"q":"في حادث مواد خطرة، أي جهة يجب أن تبلّغها للحصول على مساعدة الاستجابة للطوارئ؟","options":["OSHA","CHEMTREC","الشاحن","محطة الوزن"],"explanation":"في الحادث، حذّر الآخرين، وأبعد الناس، وامنع التدخين، وأبلغ المستجيبين للطوارئ أو CHEMTREC."},"87":{"q":"ماذا يجب على السائق أن يفعل بشحنة مواد خطرة معلّمة بشكل غير صحيح؟","options":["نقلها ببطء إلى الوجهة","إعادة تعليم الشحنة بنفسك","رفضها وعدم نقلها","تغطية العلامات قبل القيادة"],"explanation":"يجب على السائق رفض شحنة مواد خطرة متسربة أو معلّمة بشكل غير صحيح وعدم نقلها."},"88":{"q":"بعد إزالة إطار متسرب أو محموم من حمولة تحمل لافتات، أين يجب أن تبرّده؟","options":["داخل المقطورة","تحت خزان الوقود","بجانب الحمولة","بعيداً عن المركبة"],"explanation":"يجب إزالة الإطار المتسرب أو المحموم على حمولة تحمل لافتات وتبريده بعيداً عن المركبة."},"89":{"q":"أي فئة خطر تشمل الغازات؟","options":["الفئة 2","الفئة 4","الفئة 6","الفئة 8"],"explanation":"الفئة 2 هي الغازات، وتشمل القسم 2.3 الغاز السام."},"90":{"q":"بعض المواد المشعة (الفئة 7) تتطلب لافتات بأي كمية؟","options":["فقط عند 1,001 رطل أو أكثر","بأي كمية","فقط عند 5,000 رطل أو أكثر","لا تتطلب لافتات أبداً"],"explanation":"بعض المواد المشعة (الفئة 7) هي مواد من الجدول 1 تتطلب لافتات بأي كمية."},"91":{"q":"في حادث مواد خطرة، ماذا يجب أن يفعل السائق بالقرب من موقع الحادث؟","options":["إشعال الشعلات للتحذير","تحريك الطرد المتسرب","إبعاد الناس","غسل الانسكاب بالماء"],"explanation":"في حادث مواد خطرة، يجب على السائق تحذير الآخرين وإبعاد الناس عن موقع الحادث."},"92":{"q":"ماذا يجب على سائق المواد الخطرة أن يفعل بأوراق الشحن أثناء القيادة؟","options":["إبقاؤها في متناول اليد","إرسالها بالبريد إلى الشاحن","قفلها في المقطورة","التخلص منها"],"explanation":"يجب على السائق إبقاء أوراق الشحن في متناول اليد أثناء القيادة."},"93":{"q":"في أوراق شحن المواد الخطرة، بأي ترتيب يجب إدراج العناصر الثلاثة المطلوبة؟","options":["رقم التعريف، فئة الخطر، اسم الشحن","اسم الشحن الصحيح، فئة الخطر، رقم التعريف","فئة الخطر، اسم الشحن، رقم التعريف","اسم الشحن، رقم التعريف، فئة الخطر"],"explanation":"يجب أن تُدرج أوراق الشحن اسم الشحن الصحيح، وفئة الخطر، ورقم التعريف بهذا الترتيب المحدد."},"94":{"q":"ما الذي يجب أن تستخدمه كإشارة تحذير لمركبة مواد خطرة متوقفة تحمل لافتات؟","options":["شعلة مشتعلة","عود إشعال مضاء","أي لهب مكشوف","مثلثات عاكسة"],"explanation":"لا تستخدم أبدًا الشعلات أو أعواد الإشعال أو أي لهب مكشوف بالقرب من حمولات المواد الخطرة؛ استخدم المثلثات العاكسة بدلًا من ذلك."},"95":{"q":"عند نقل حمولة مواد خطرة تحمل لافتات، ما الذي يجب أن تتجنبه إلى جانب الأنفاق؟","options":["المناطق المكتظة بالسكان","الطقس المشمس الساطع","الطرق الريفية الخالية","محطات وزن الشاحنات"],"explanation":"عند نقل حمولة مواد خطرة تحمل لافتات، يجب أن تتجنب الأنفاق والمناطق المكتظة بالسكان معًا."},"96":{"q":"ما هي إحدى مسؤوليات السائق بشأن شحنة المواد الخطرة؟","options":["تصنيف المادة","فحص الشحنة","تعبئة المادة","إعداد أوراق الشحن"],"explanation":"يقوم السائق بفحص الشحنة، ويرفض الحمولات المتسربة، ويضع اللافتات، ويبقي الأوراق في متناول اليد، ويقود بأمان."},"97":{"q":"ما الذي يجب أن تكون كل لافتة قادرة على تحقيقه فيما يتعلق بالاتجاه الذي تواجهه؟","options":["أن تكون مقروءة من الاتجاه الذي تواجهه","أن تتوهج في الظلام ليلًا","أن تطابق لون المقطورة","أن تُزال قبل التفريغ"],"explanation":"يجب أن تكون اللافتات مقروءة من الاتجاه الذي تواجهه."},"98":{"q":"ما هو أدنى وزن إجمالي كلي تتطلب عنده مواد الجدول 2 وضع لافتات؟","options":["1,001 رطل","500 رطل","2,500 رطل","5,000 رطل"],"explanation":"تتطلب مواد الجدول 2 وضع لافتات عند وزن 1,001 رطل أو أكثر."},"99":{"q":"أثناء القيادة مع وجود أوراق الشحن في متناول اليد، أين يجب أن توضع بالنسبة إلى الأوراق الأخرى؟","options":["فوق الأوراق الأخرى","تحت الأوراق الأخرى","مطوية داخل الدليل","في صندوق القفازات فقط"],"explanation":"يجب أن تكون أوراق الشحن فوق الأوراق الأخرى أثناء القيادة."},"100":{"q":"ماذا يسمح تصديق X للسائق بنقله؟","options":["المركبات الصهريجية والمواد الخطرة","المقطورات المزدوجة والثلاثية فقط","الركاب والمواد الخطرة","الحافلات المدرسية والصهاريج"],"explanation":"يجمع تصديق X بين صلاحية المركبات الصهريجية والمواد الخطرة."},"101":{"q":"ما نوع الغاز المصنف ضمن الشعبة 2.1؟","options":["غاز قابل للاشتعال","غاز غير قابل للاشتعال","غاز سام","غاز خامل"],"explanation":"الشعبة 2.1 هي الغاز القابل للاشتعال."},"102":{"q":"ماذا تمثل الشعبة 2.2؟","options":["غاز غير قابل للاشتعال","غاز قابل للاشتعال","غاز سام","غاز مشع"],"explanation":"الشعبة 2.2 هي الغاز غير القابل للاشتعال."},"103":{"q":"ما الذي يجب أن يفعله السائق قبل نقل شحنة مواد خطرة موسومة بشكل غير صحيح؟","options":["يرفض نقلها","يغطي العلامات","يقودها ببطء","يبلغ عنها بعد التسليم"],"explanation":"يجب أن يرفض السائق شحنة المواد الخطرة الموسومة بشكل غير صحيح."},"104":{"q":"عند تزويد مركبة تحمل لافتات بالوقود، من الذي يجب أن يتحكم في التدفق عند الفوهة؟","options":["يجب أن يكون هناك شخص عند الفوهة","لا حاجة لوجود أي شخص","رجل إطفاء فقط","وكيل الشاحن"],"explanation":"يجب أن يكون هناك شخص عند الفوهة يتحكم في التدفق أثناء التزويد بالوقود."},"105":{"q":"ما نوع المادة في فئة الخطر 5؟","options":["المؤكسدات والبيروكسيدات العضوية","المواد الأكّالة","السوائل القابلة للاشتعال","المواد المشعة"],"explanation":"فئة الخطر 5 هي المؤكسدات والبيروكسيدات العضوية."},"106":{"q":"ما نوع المادة في الشعبة 4.3؟","options":["مادة خطرة عند البلل","مادة قابلة للاشتعال الذاتي","خطر سام بالاستنشاق","بيروكسيد عضوي"],"explanation":"الشعبة 4.3 هي مادة خطرة عند البلل."},"107":{"q":"في حادثة مواد خطرة، ما الذي يجب أن يفعله السائق بشأن الأشخاص القريبين من الموقع؟","options":["إبقاء الناس بعيدًا","جمع الناس للمساعدة","السماح للناس بالاقتراب من الحمولة","توجيه الناس نحو التسرب"],"explanation":"في الحادثة يجب على السائق إبقاء الناس بعيدًا."},"108":{"q":"ما نوع المادة التي تشملها فئة الخطر 8؟","options":["المواد الأكّالة","المتفجرات","الغازات","المتنوعات"],"explanation":"تشمل فئة الخطر 8 المواد الأكّالة."},"109":{"q":"إلى جانب التظليل، كيف يمكن تحديد إدخال المواد الخطرة في أوراق الشحن؟","options":["بوضع علامة X أو RQ في عمود HM","بالكتابة بالحبر الأحمر فقط","بالختم على الصفحة الخلفية","بوضعها في مظروف منفصل"],"explanation":"يمكن تحديد إدخالات المواد الخطرة بوضع علامة X أو RQ في عمود HM."},"110":{"q":"في ورقة الشحن، أي عنصر يأتي بعد اسم الشحن الصحيح؟","options":["فئة الخطر","عنوان الناقل","اسم السائق","تاريخ التسليم"],"explanation":"تُدرج فئة الخطر بعد اسم الشحن الصحيح."},"111":{"q":"ما هو الفحص الأمني المطلوب للحصول على تصديق H أو X؟","options":["تقييم تهديد أمني من هيئة TSA وأخذ البصمات","فحص للبصر والسمع","دورة في القيادة الدفاعية","صف عن المخدرات والكحول"],"explanation":"يتطلب تصديق H/X تقييم تهديد أمني من هيئة TSA وأخذ البصمات."},"112":{"q":"ما مدى قرب وقوف حمولة تحمل لافتات من الجزء المخصص للمرور في الطريق؟","options":["ليس أقرب من 5 أقدام","ليس أقرب من 15 قدمًا","ليس أقرب من 50 قدمًا","ليس أقرب من 25 قدمًا"],"explanation":"لا توقف المركبة أبدًا على بعد أقل من 5 أقدام من الجزء المخصص للمرور في الطريق عند حمل لافتات."},"113":{"q":"أثناء عبور سكك الحديد، ما الذي يجب ألا تفعله مركبة تحمل لافتات؟","options":["تبديل التروس أثناء العبور","إطلاق البوق","استخدام الفرامل","تشغيل المصابيح الأمامية"],"explanation":"يجب ألا تبدل المركبة التي تحمل لافتات التروس أثناء عبور السكك."},"114":{"q":"ما نوع إشارة التحذير التي يجب أن تستخدمها بالقرب من مركبة تنقل سائلًا قابلًا للاشتعال أو متفجرات؟","options":["مثلثات عاكسة","شعلات مضاءة","أعواد إشعال مشتعلة","مشعل بلهب مكشوف"],"explanation":"استخدم المثلثات العاكسة، وليس اللهب، بالقرب من الحمولات القابلة للاشتعال أو المتفجرة."},"115":{"q":"أين يجب أن تبرّد إطارًا متسربًا أو محمومًا أُزيل من حمولة تحمل لافتات؟","options":["بعيدًا عن المركبة","تحت المقطورة","بجوار خزان الوقود","داخل المقصورة"],"explanation":"يجب إزالة الإطار المتسرب أو المحموم وتبريده بعيدًا عن المركبة."},"116":{"q":"كم مرة يجب أن تفحص إطارات حمولة تحمل لافتات بعد بدء الرحلة؟","options":["كل ساعتين أو 100 ميل","كل 4 ساعات أو 200 ميل","كل ساعة أو 50 ميلًا","كل 3 ساعات أو 150 ميلًا"],"explanation":"افحص الإطارات كل ساعتين أو 100 ميل عند حمل لافتات."}},"learn-tanker":{"0":{"q":"لماذا تنقلب المركبات الصهريجية بسهولة؟","options":["مركز ثقل مرتفع","مركز ثقل منخفض","قاعدة عجلات عريضة","محور خلفي ثقيل"],"explanation":"تستقر الحمولة السائلة في الأعلى، مما يمنح المركبات الصهريجية مركز ثقل مرتفعًا، لذا تنقلب بسهولة."},"1":{"q":"ما السرعة التي يجب أن تسلك بها المنعطفات والمنحدرات والانعطافات في مركبة صهريجية؟","options":["بالسرعة المعلنة","أقل بكثير من السرعة المعلنة","أعلى من السرعة المعلنة","بالحد الأقصى للسرعة القانونية"],"explanation":"لأن المركبات الصهريجية ذات مركز ثقل مرتفع، اسلك المنعطفات والمنحدرات والانعطافات بسرعة أقل بكثير من السرعة المعلنة."},"2":{"q":"ما الذي يسبب معظم حوادث انقلاب الصهاريج؟","options":["الفرملة المفاجئة","انخفاض ضغط الإطارات","القيادة بسرعة عالية جدًا","تغيير المسارات المفاجئ"],"explanation":"تحدث معظم حوادث انقلاب الصهاريج لأن السائق يقود بسرعة عالية جدًا عند المنعطف أو المنحدر."},"3":{"q":"ما الذي يساعد على منع انقلاب الصهاريج؟","options":["التوجيه المفاجئ","الفرملة المفاجئة","تقليل مسافة التتابع","التوجيه والفرملة بسلاسة"],"explanation":"يساعد التوجيه والفرملة بسلاسة بالإضافة إلى زيادة مسافة التتابع على منع انقلاب الصهاريج."},"4":{"q":"في صهريج ممتلئ جزئيًا، ماذا يفعل السائل؟","options":["يتموج ذهابًا وإيابًا","يبقى ساكنًا تمامًا","يغوص إلى القاع","يتجمد في مكانه"],"explanation":"في صهريج ممتلئ جزئيًا، يتموج السائل ذهابًا وإيابًا ومن جانب إلى آخر."},"5":{"q":"بعد التوقف، ماذا يمكن أن يفعل تموج السائل إلى الأمام؟","options":["يسبب الانقلاب","يدفع الشاحنة إلى الأمام","يوقف المحرك","يقفل الفرامل"],"explanation":"بعد التوقف، يمكن أن يدفع التموج الأمامي الشاحنة إلى الأمام، مثل دفعها إلى داخل التقاطع."},"6":{"q":"ما الذي يمكن أن يسببه تموج السائل من جانب إلى آخر؟","options":["إطار مثقوب","دفعة إلى الأمام","انقلاب","تسرب في الصهريج"],"explanation":"يمكن أن يسبب التموج من جانب إلى آخر في صهريج ممتلئ جزئيًا انقلاب المركبة."},"7":{"q":"ما نوع التموج الذي تقلله الصهاريج المزودة بحواجز؟","options":["التموج من جانب إلى آخر","التموج لأعلى ولأسفل","كل أنواع التموج","التموج من الأمام إلى الخلف"],"explanation":"تحتوي الصهاريج المزودة بحواجز على فواصل بها ثقوب تقلل التموج من الأمام إلى الخلف لكنها لا تقلل التموج من جانب إلى آخر."},"8":{"q":"أي نوع من التموج لا تقلله الصهاريج المزودة بحواجز؟","options":["التموج من جانب إلى آخر","التموج من الأمام إلى الخلف","التموج الأمامي","التموج الخلفي"],"explanation":"تقلل الصهاريج المزودة بحواجز التموج من الأمام إلى الخلف لكنها لا تقلل التموج من جانب إلى آخر."},"9":{"q":"كم عدد الحواجز في الصهريج الأملس (غير المزود بحواجز)؟","options":["حاجز واحد","لا يوجد حواجز","حاجزان","عدة حواجز"],"explanation":"لا تحتوي الصهاريج الملساء (غير المزودة بحواجز) على أي حواجز، لذلك يكون تموج السائل قويًا."},"10":{"q":"غالبًا ما تُستخدم الصهاريج الملساء لنقل أي نوع من الحمولات؟","options":["السوائل القابلة للاشتعال","الغازات المضغوطة","المنتجات الغذائية","النفايات الخطرة"],"explanation":"لا تحتوي الصهاريج الملساء على حواجز وغالبًا ما تُستخدم للمنتجات الغذائية لأسباب صحية."},"11":{"q":"لماذا يجب ترك مساحة فارغة عند تحميل صهريج سائل؟","options":["السوائل تتجمد بالكامل","السوائل تتموج جانبيًا","السوائل تفقد وزنها","السوائل تتمدد عند تسخينها"],"explanation":"لا يمكنك ملء صهريج السائل بالكامل لأن السوائل تتمدد عند تسخينها، لذلك يجب ترك مساحة فارغة (outage)."},"12":{"q":"لماذا يجب ترك مساحة فارغة (outage) عند تحميل صهريج سائل؟","options":["السوائل تتمدد عند تسخينها","السوائل تتقلص عند تسخينها","لتقليل التموج من جانب إلى آخر","لاستيفاء حدود الوزن القانونية"],"explanation":"تترك مساحة فارغة (outage) لأن السوائل تتمدد عند تسخينها، لذلك لا يمكنك ملء الصهريج بالكامل."},"13":{"q":"تعتمد كمية السائل التي يمكنك تحميلها في الصهريج على حدود الوزن القانونية وعلى ماذا أيضًا؟","options":["لون الصهريج","ضغط الهواء الخارجي","وزن السائل (كثافته)","طول الصهريج"],"explanation":"تعتمد الكمية التي يمكنك تحميلها على وزن السائل (كثافته) وعلى حدود الوزن القانونية."},"14":{"q":"ما الذي يمكن أن يجعل السائل الكثيف يبلغ حد الوزن القانوني قبل امتلاء الصهريج؟","options":["تموج السائل","ارتفاع مركز الثقل","المساحة الفارغة (outage)","وزنه (كثافته)"],"explanation":"يمكن أن يبلغ وزن السائل الكثيف حد الوزن القانوني قبل امتلاء الصهريج بالكامل."},"15":{"q":"عند قيادة مركبة صهريج، ماذا يجب أن تفعل للفرملة بأمان؟","options":["زيادة مسافة التتابع والفرملة برفق","تقليل مسافة التتابع والفرملة بقوة","الحفاظ على المسافة العادية والفرملة فجأة","زيادة مسافة التتابع والفرملة متأخرًا"],"explanation":"زِد مسافة التتابع وافرمل برفق وفي وقت مبكر، لأن تموج السائل يطيل مسافة التوقف."},"16":{"q":"ماذا يفعل تموج السائل بمسافة التوقف لديك؟","options":["يقصّرها","يطيلها","ليس له تأثير","يلغيها"],"explanation":"يطيل التموج مسافة التوقف ويمكن أن يدفعك إلى الأمام بعد أن تظن أنك قد توقفت."},"17":{"q":"في حالة التوقف الطارئ بمركبة صهريج، أي طريقة فرملة يجب أن تستخدم؟","options":["الضغط المتقطع على الفرامل","الفرملة ثم التوجيه بقوة","الفرملة المتحكَّم بها أو الفرملة بالضغط المتكرر","الانزلاق في الوضع المحايد"],"explanation":"في حالة التوقف الطارئ، استخدم الفرملة المتحكَّم بها أو الفرملة بالضغط المتكرر وحافظ على استقامة مركبة الصهريج."},"18":{"q":"لتجنب الانقلاب الناتج عن التموج الجانبي، كيف يجب أن تنطلق وتبطئ وتوجه مركبة الصهريج؟","options":["بسرعة وثبات","بقوة وسرعة","فجأة وبحدة","بسلاسة وبلطف"],"explanation":"انطلق وأبطئ بسلاسة وتجنب التوجيه المفاجئ، لأن التموج الجانبي يمكن أن يتحول إلى انقلاب."},"19":{"q":"أين يجب أن تفحص مركبة الصهريج بحثًا عن التسربات؟","options":["الصمامات وفتحات الدخول والمنافذ والمضخات والخراطيم","المرايا والأضواء والمساحات والبوق","الإطارات والجنوط وصواميل العجلات وواقيات الطين","المقاعد والمقاييس والدواسات والأحزمة"],"explanation":"افحص بحثًا عن التسربات حول الصمامات وفتحات الدخول والمنافذ والمضخات والخراطيم."},"20":{"q":"أثناء الفحص، في أي حالة يجب أن تكون أغطية فتحات الدخول وصمامات البخار/التهوية؟","options":["مفتوحة وغير محكمة الإغلاق","مغلقة ومحكمة الإغلاق","مثبتة بشكل غير محكم","مفتوحة جزئيًا"],"explanation":"يجب أن تكون أغطية فتحات الدخول وصمامات البخار/التهوية مغلقة ومحكمة الإغلاق، مع وجود الصمامات في الوضع الصحيح."},"21":{"q":"أي تصديق يعادل الصهريج بالإضافة إلى المواد الخطرة مجتمعَين؟","options":["تصديق N","تصديق H","تصديق X","تصديق T"],"explanation":"يغطي تصديق X المدمج كلًا من مركبات الصهاريج والمواد الخطرة."},"22":{"q":"ما المطلوب عند الاقتضاء للصهاريج التي تحمل سوائل قابلة للاشتعال أو خطرة؟","options":["إسفينات العجلات","لافتات الحمولة العريضة","المثلثات العاكسة","لافتات الخطر (Placards)"],"explanation":"تتطلب الصهاريج التي تحمل سوائل قابلة للاشتعال أو خطرة لافتات الخطر (placards) عند الاقتضاء."},"23":{"q":"لماذا تتميز مركبات الصهاريج بمركز ثقل مرتفع؟","options":["الحمولة السائلة تستقر مرتفعة في الصهريج","الإطارات أكبر من المعتاد","المحرك مثبت في الأعلى","المقصورة أطول من المقطورة"],"explanation":"تتميز مركبات الصهاريج بمركز ثقل مرتفع لأن الحمولة السائلة تستقر مرتفعة."},"24":{"q":"كم مسافة تتابع يجب أن تحافظ عليها عند قيادة مركبة صهريج؟","options":["أقل من المعتاد","مسافة تتابع إضافية","مثل السيارة","لا توجد مسافة تتابع"],"explanation":"يجب أن تحافظ على مسافة تتابع إضافية عند قيادة مركبة صهريج."},"25":{"q":"كيف يتحرك السائل في صهريج ممتلئ جزئيًا؟","options":["إلى الأسفل مباشرة فقط","إلى الأمام والخلف فقط","ذهابًا وإيابًا ومن جانب إلى آخر","يبقى ساكنًا تمامًا"],"explanation":"في صهريج ممتلئ جزئيًا، يتموج السائل ذهابًا وإيابًا ومن جانب إلى آخر."},"26":{"q":"ماذا يوجد داخل الصهاريج المزودة بحواجز؟","options":["جدران صلبة بلا فتحات","مساحة مفتوحة واحدة كبيرة","حشوة إسفنجية على طول الجدران","فواصل بها ثقوب"],"explanation":"تحتوي الصهاريج المزودة بحواجز على فواصل بها ثقوب."},"27":{"q":"لماذا تُستخدم الصهاريج ذات السطح الداخلي الأملس (Smooth-bore) غالبًا لنقل المنتجات الغذائية؟","options":["لأسباب تتعلق بالنظافة الصحية","لإبطاء اندفاع السائل","لحمل أحمال أثقل","لتوفير تكاليف الوقود"],"explanation":"تُستخدم الصهاريج ذات السطح الداخلي الأملس للمنتجات الغذائية لأسباب تتعلق بالنظافة الصحية."},"28":{"q":"لماذا لا يمكنك عادةً ملء صهريج السوائل بالكامل؟","options":["لأن الصهريج يجب أن يبقى محكم الإغلاق","لأن السوائل تتمدد عندما تسخن","لأن المضخة لا تصل إلى الأعلى","لأن الفتحات يجب أن تبقى مفتوحة"],"explanation":"لا يمكنك عادةً ملء صهريج السوائل بالكامل لأن السوائل تتمدد عندما تسخن، لذا يجب ترك مساحة فارغة (outage)."},"29":{"q":"كيف ينبغي أن تكبح مركبة الصهريج؟","options":["الكبح بلطف فقط","الكبح بقوة فقط","الكبح في وقت متأخر فقط","الكبح بلطف وفي وقت مبكر"],"explanation":"مع مركبة الصهريج ينبغي أن تكبح بلطف وفي وقت مبكر لأن اندفاع السائل يزيد من مسافة التوقف."},"30":{"q":"ماذا يمكن أن يفعله اندفاع السائل بعد أن توقف مركبة الصهريج؟","options":["دفع الشاحنة إلى الأمام","خفض مركز الثقل","إيقاف المحرك","تبريد الحمولة السائلة"],"explanation":"يمكن أن يدفعك الاندفاع إلى الأمام بعد أن تظن أنك توقفت."},"31":{"q":"عند التوقف الطارئ مع نظام ABS، كيف ينبغي أن تكبح؟","options":["اضغط على المكابح بخفة","اكبح بثبات وقوة","انقر على المكابح بلطف","تجنب استخدام المكابح"],"explanation":"مع نظام ABS، ينبغي أن تكبح بثبات وقوة عند التوقف الطارئ."},"32":{"q":"أثناء التوقف الطارئ مع مركبة الصهريج، ينبغي أن تُبقي المركبة:","options":["تنعطف ببطء","تنحرف يمينًا","مستقيمة","تنزلق بحرية"],"explanation":"عند التوقف الطارئ مع مركبة الصهريج، أبقِ المركبة مستقيمة."},"33":{"q":"أثناء الفحص، ماذا ينبغي أن تتحقق منه بشأن الصمامات؟","options":["أنها مطلية باللون الأحمر الزاهي","أنها مُزالة للتنظيف","أنها متروكة مفتوحة بالكامل","أنها في الوضع الصحيح"],"explanation":"أثناء الفحص، تحقق من أن الصمامات في الوضع الصحيح."},"34":{"q":"الصهاريج التي تنقل سوائل قابلة للاشتعال أو خطرة قد تتطلب أي تصديق (endorsement)؟","options":["تصديق H","تصديق P","تصديق S","تصديق L"],"explanation":"الصهاريج التي تنقل سوائل قابلة للاشتعال أو خطرة قد تتطلب تصديق H."},"35":{"q":"في مركبة الصهريج، ما الذي يجعل الحمولة السائلة ذات مركز ثقل مرتفع؟","options":["تستقر في موضع عالٍ داخل الصهريج","أنها شديدة البرودة","أنها محكمة الإغلاق تمامًا","أنها خفيفة الوزن"],"explanation":"تستقر الحمولة السائلة في موضع عالٍ، مما يمنح مركبات الصهريج مركز ثقل مرتفعًا فتنقلب بسهولة."},"36":{"q":"على المنعطف أو المنحدر، ينبغي أن تكون سرعة سائق الصهريج:","options":["مساوية للسرعة المعلنة للمنحدر","أقل من السرعة المعلنة للمنحدر","أعلى من السرعة المعلنة للمنحدر","ضعف السرعة المعلنة للمنحدر"],"explanation":"بسبب مركز ثقلها المرتفع، ينبغي أن تأخذ مركبات الصهريج المنعطفات والمنحدرات بسرعة أقل بكثير من السرعة المعلنة."},"37":{"q":"ما الأمور الثلاثة الأساسية لمنع انقلاب الصهريج؟","options":["الكبح بقوة، والتوجيه السريع، ومسافة اتباع قصيرة","الكبح السلس، والصهاريج الممتلئة، ومسافة اتباع قصيرة","التوجيه السلس، والكبح السلس، ومسافة اتباع إضافية","التوجيه السريع، والكبح بقوة، ومسافة اتباع إضافية"],"explanation":"التوجيه السلس، والكبح السلس، ومسافة اتباع إضافية أمور أساسية لمنع انقلاب الصهريج."},"38":{"q":"في مركبة الصهريج، ماذا يعني مصطلح 'الاندفاع' (surge)؟","options":["مركز الثقل المرتفع للصهريج","المساحة الفارغة المتروكة لتمدد السائل","الحواجز الداخلية في الصهريج المزود بالحواجز (baffled)","تمايل السائل ذهابًا وإيابًا"],"explanation":"الاندفاع هو تمايل السائل في الصهريج المملوء جزئيًا ذهابًا وإيابًا ومن جانب إلى آخر."},"39":{"q":"بعد أن توقف صهريجًا مملوءًا جزئيًا، إلى أين يمكن أن يدفع الاندفاع الأمامي الشاحنة؟","options":["إلى داخل تقاطع","إلى الخلف في المسار خلفك","خارج الطريق إلى اليمين","فوق الرصيف بشكل جانبي"],"explanation":"بعد أن تتوقف، يمكن أن يدفع الاندفاع الأمامي الشاحنة إلى داخل تقاطع."},"40":{"q":"في الصهريج المزود بالحواجز (baffled)، أي اندفاع يُقلَّل وأيهما لا يُقلَّل؟","options":["يقلل الاندفاع من جانب إلى آخر؛ لا يقلل الاندفاع للأمام والخلف","يقلل الاندفاع للأمام والخلف؛ لا يقلل الاندفاع من جانب إلى آخر","يقلل كلا الاندفاعين للأمام والخلف ومن جانب إلى آخر","لا يقلل أيًا منهما؛ الحواجز لا تفعل شيئًا"],"explanation":"الصهاريج المزودة بالحواجز تقلل الاندفاع للأمام والخلف لكنها لا تقلل الاندفاع من جانب إلى آخر."},"41":{"q":"الصهريج ذو السطح الداخلي الأملس (smooth-bore) له اندفاع سائل قوي. كيف ينبغي أن تقوده؟","options":["اكبح بقوة ووجِّه بسرعة","زِد السرعة لتثبيت السائل","كن لطيفًا وثابتًا للغاية","خذ المنعطفات بسرعة أعلى من سرعة المنحدر"],"explanation":"الصهريج ذو السطح الداخلي الأملس (غير المزود بحواجز) لا يحتوي على حواجز، لذا فإن اندفاعه القوي يعني أنه يجب أن تكون لطيفًا وثابتًا للغاية."},"42":{"q":"أي نوع من الصهاريج ينتج أقوى اندفاع للسائل؟","options":["الصهريج المزود بالحواجز (baffled)","الصهريج ذو الحواجز الفاصلة (bulkheads)","الصهريج متعدد المقصورات","الصهريج ذو السطح الداخلي الأملس (غير المزود بحواجز)"],"explanation":"الصهاريج ذات السطح الداخلي الأملس (غير المزودة بحواجز) لا تحتوي على حواجز، لذا يكون اندفاع السائل قويًا."},"43":{"q":"في الصهريج المزود بالحواجز (baffled)، ماذا تحتوي الحواجز الفاصلة؟","options":["ثقوبًا","مضخات","سخانات","مغناطيسات"],"explanation":"الصهاريج المزودة بالحواجز تحتوي على حواجز فاصلة بها ثقوب."},"44":{"q":"ماذا تُسمى المساحة الفارغة التي تتركها في أعلى صهريج السوائل؟","options":["الاندفاع (surge)","المساحة الفارغة (outage)","الحاجز (baffle)","الحاجز الفاصل (bulkhead)"],"explanation":"يجب أن تترك مساحة فارغة (outage) لأن السوائل تتمدد عندما تسخن."},"45":{"q":"كيف تؤثر الحمولة السائلة الأكثر برودة وكثافة على المساحة الفارغة (outage)؟","options":["تُلغي الحاجة لأي مساحة فارغة","تتيح لك ملء الصهريج بأمان فوق سعته","تجعل ترك مساحة فارغة أكثر أهمية","ليس لها أي تأثير على المساحة الفارغة"],"explanation":"كلما كانت الحمولة السائلة أكثر برودة وكثافة، زادت أهمية ترك مساحة فارغة (outage)."},"46":{"q":"بالإضافة إلى سعة الصهريج، ما العاملان اللذان يحددان كمية السائل التي يمكنك تحميلها؟","options":["لون السائل وشكل الصهريج","طول الخرطوم ونوع الصمام","درجة الحرارة الخارجية وعمر الصهريج","كثافة السائل وحدود الوزن القانونية"],"explanation":"تعتمد كمية ما يمكنك تحميله على وزن السائل (الكثافة) وحدود الوزن القانونية."},"47":{"q":"عندما تنقل سائلًا عالي الكثافة، ماذا يمكن أن يحدث؟","options":["تبلغ حد الوزن القانوني قبل أن يمتلئ الصهريج","يمكنك دائمًا ملء الصهريج بالكامل","يمتلئ الصهريج قبل بلوغ أي حد للوزن","لم تعد حدود الوزن تنطبق على الحمولة"],"explanation":"يمكن للسائل عالي الكثافة أن يبلغ حد الوزن القانوني قبل أن يمتلئ الصهريج."},"48":{"q":"هل يمكنك عادةً ملء صهريج السوائل حتى الأعلى تمامًا؟","options":["نعم، املأه دائمًا بالكامل","لا، يجب أن تترك مساحة فارغة","نعم، إذا كان الصهريج مزودًا بحواجز","نعم، للسوائل الباردة فقط"],"explanation":"لا يمكنك عادةً ملء صهريج السوائل بالكامل لأن السوائل تتمدد عندما تسخن، لذا يجب ترك مساحة فارغة (outage)."},"49":{"q":"في مركبة الصهريج، ماذا يمكن أن يفعله اندفاع السائل حتى بعد أن تظن أنك توقفت؟","options":["خفض مركز ثقل الصهريج","تحسين استجابة التوجيه","دفع الشاحنة إلى الأمام","تقصير مسافة التوقف"],"explanation":"بعد أن تتوقف، يمكن أن يدفع الاندفاع الأمامي الشاحنة إلى الأمام، لذا زِد مسافة الاتباع واكبح بلطف وفي وقت مبكر."},"50":{"q":"لماذا ينبغي أن تزيد مسافة الاتباع وتكبح مبكرًا في مركبة الصهريج؟","options":["لأن المكابح أضعف من تلك الموجودة في الشاحنات الجافة","لأن شاحنات الصهاريج لا يمكنها استخدام المكابح إطلاقًا","لأن الحمولات السائلة تجعل المحرك أبطأ","لأن الاندفاع يزيد من مسافة التوقف"],"explanation":"الاندفاع يزيد من مسافة التوقف ويمكن أن يدفعك إلى الأمام بعد أن تظن أنك توقفت."},"51":{"q":"عند التوقف الطارئ بمركبة صهريج لا تحتوي على نظام ABS، أي طريقة كبح ينبغي أن تستخدم؟","options":["الكبح المتحكم به أو الكبح المتقطع (stab braking)","اضغط على المكابح بخفة","أبقِ المكابح مقفلة","اكبح ثم وجِّه بقوة"],"explanation":"عند التوقف الطارئ بمركبة صهريج لا تحتوي على نظام ABS، استخدم الكبح المتحكم به أو الكبح المتقطع وأبقِ المركبة مستقيمة."},"52":{"q":"في مركبة الصهريج، ما نوع التوجيه الذي يجب تجنبه؟","options":["التوجيه البطيء والثابت","التوجيه المفاجئ والحاد","التوجيه اللطيف والسلس","التوجيه المبكر والتدريجي"],"explanation":"تجنب التوجيه المفاجئ في مركبة الصهريج، لأن اندفاع السائل الجانبي قد يحولها إلى انقلاب."},"53":{"q":"كيف ينبغي أن تبدأ بتحريك مركبة الصهريج؟","options":["بسرعة للتغلب على اندفاع السائل","عن طريق رفع دوران المحرك أولاً","بسلاسة","فقط في الترس المنخفض"],"explanation":"ينبغي أن تبدأ بتحريك مركبة الصهريج وأن تبطئها بسلاسة."},"54":{"q":"عند الفحص حول الصمامات وفتحات الدخول والفتحات التهوية والمضخات والخراطيم، عمَّ تبحث؟","options":["لافتات مرتخية","تآكل الإطارات","ضوضاء المحرك","التسريبات"],"explanation":"تفحص حول الصمامات وفتحات الدخول وفتحات التهوية والمضخات والخراطيم للتحقق من وجود تسريبات."},"55":{"q":"في مركبة الصهريج، أي مكوّنين يجب التحقق من أنهما مغلقان ومحكمان؟","options":["أغطية فتحات الدخول وصمامات البخار/التهوية","غرف الفرامل ومُعدِّلات الخلوص","الأضواء الخلفية وإشارات الانعطاف","واقيات الطين والرفارف"],"explanation":"تحقق من أن أغطية فتحات الدخول وصمامات البخار/التهوية مغلقة ومحكمة."},"56":{"q":"أثناء فحص الصهريج، بالإضافة إلى كونها محكمة، ماذا ينبغي أن تتأكد منه بشأن الصمامات؟","options":["أنها مطلية","أنها في الوضع الصحيح","أنها دافئة","أنها مفكوكة"],"explanation":"أثناء الفحص، تحقق من أن صمامات الصهريج في الوضع الصحيح."},"57":{"q":"يجمع تصديق X بين أي تصديقين؟","options":["الصهريج والركاب","المواد الخطرة والحافلة المدرسية","الصهريج والمواد الخطرة","الركاب والمواد الخطرة"],"explanation":"يجمع تصديق X بين تصديق الصهريج وتصديق المواد الخطرة (H)."},"58":{"q":"نقل أي نوع من السوائل قد يستدعي الحاجة إلى تصديق H واللافتات؟","options":["سائل بارد أو كثيف","سائل صالح للطعام","سائل صهريج ذي تجويف أملس","سائل قابل للاشتعال أو خطر"],"explanation":"الصهاريج التي تنقل سوائل قابلة للاشتعال أو خطرة قد تتطلب أيضاً تصديق H واللافتات عند الاقتضاء."},"59":{"q":"ما العلامات التي قد تحتاج مركبة الصهريج إلى عرضها عند نقل سوائل قابلة للاشتعال أو خطرة؟","options":["اللافتات","واقيات الطين","العواكس","المرايا"],"explanation":"اللافتات مطلوبة عند الاقتضاء للصهاريج التي تنقل سوائل قابلة للاشتعال أو خطرة."},"60":{"q":"ما الذي يجعل مركز الثقل المرتفع لمركبة الصهريج مرجَّحاً لحدوثه؟","options":["الانقلاب بسهولة","التوقف بسرعة أكبر","التوجيه بإحكام أكبر","الحصول على اقتصاد أفضل في استهلاك الوقود"],"explanation":"مركز الثقل المرتفع يجعل مركبات الصهاريج تنقلب بسهولة."},"61":{"q":"أين يستقر الحمل السائل في مركبة الصهريج؟","options":["مرتفعاً في المركبة","منخفضاً تحت المحاور","خلف المقصورة فقط","بالتساوي عند مستوى الطريق"],"explanation":"يستقر الحمل السائل مرتفعاً في الصهريج، مما يرفع مركز الثقل."},"62":{"q":"أي نوع من الفتحات تحتويه الحواجز في الصهريج المزود بالحواجز؟","options":["فتحات تسمح بتدفق السائل عبرها","فتحات لتصريف الرواسب","فتحات لإضافة ضغط الهواء","فتحات لأضواء الفحص"],"explanation":"الصهاريج المزودة بالحواجز تحتوي على حواجز ذات فتحات تسمح بتدفق السائل عبرها."},"63":{"q":"في الصهريج ذي التجويف الأملس، ما مدى قوة اندفاع السائل؟","options":["قوي","خفيف","معدوم","مُبطَّأ بواسطة الحواجز"],"explanation":"بدون حواجز، يكون اندفاع السائل في الصهريج ذي التجويف الأملس قوياً."},"64":{"q":"ماذا يحدث للسوائل عندما تسخن؟","options":["تتمدد","تنكمش","تتجمد","تتصلب"],"explanation":"تتمدد السوائل عندما تسخن، ولهذا السبب يلزم ترك حيز فارغ."},"65":{"q":"ما الذي يؤثر على كمية السائل التي يمكنك تحميلها إلى جانب حدود الوزن القانونية؟","options":["وزن السائل (كثافته)","لون الصهريج","وقت اليوم","عمر الصهريج"],"explanation":"الكمية التي يمكنك تحميلها تعتمد على وزن السائل (كثافته)."},"66":{"q":"كيف ينبغي أن تكبح في مركبة الصهريج؟","options":["بلطف وفي وقت مبكر","بقوة وفي وقت متأخر","فجأة عند الحاجة","فقط باستخدام فرامل التوقف"],"explanation":"اكبح بلطف وفي وقت مبكر لأن اندفاع السائل يطيل مسافة التوقف."},"67":{"q":"ماذا ينبغي أن تفعل بمسافة الأمان خلف المركبة التي أمامك في مركبة الصهريج؟","options":["زيادتها","تقليلها","إبقاؤها مثل السيارة","إلغاؤها"],"explanation":"ينبغي أن تزيد مسافة الأمان خلف المركبة التي أمامك عند قيادة مركبة الصهريج."},"68":{"q":"أثناء التوقف الطارئ، كيف ينبغي أن تبقي مركبة الصهريج؟","options":["مستقيمة","مائلة","متجهة نحو الكتف","منحرفة إلى اليمين"],"explanation":"أبقِ المركبة مستقيمة أثناء التوقف الطارئ."},"69":{"q":"عند فحص الصهريج، في أي وضع ينبغي أن تكون الصمامات؟","options":["الوضع الصحيح","أي وضع مفتوح","مفتوحة بالكامل دائماً","مفكوكة دائماً"],"explanation":"ينبغي التحقق من أن الصمامات في الوضع الصحيح."},"70":{"q":"أي تصديق قد يكون مطلوباً للصهاريج التي تنقل سوائل قابلة للاشتعال أو خطرة؟","options":["H","P","S","T"],"explanation":"السوائل الخطرة قد تتطلب أيضاً تصديق H (المواد الخطرة)."},"71":{"q":"لأسباب صحية، تُستخدم الصهاريج ذات التجويف الأملس عادةً لأي غرض؟","options":["المنتجات الغذائية","زيت الوقود","الأحماض الصناعية","الغاز المضغوط"],"explanation":"غالباً ما تُستخدم الصهاريج ذات التجويف الأملس للمنتجات الغذائية لأسباب صحية."},"72":{"q":"كيف ينبغي أن توجّه مركبة الصهريج لتجنب الانقلاب؟","options":["بسلاسة، مع تجنب الحركات المفاجئة","بحدة وسرعة","فقط عند الكبح بقوة","بتصحيحات متكررة"],"explanation":"تجنب التوجيه المفاجئ، الذي قد يحوله اندفاع السائل الجانبي إلى انقلاب."},"73":{"q":"بالنسبة لحمل أبرد وأكثر كثافة، ما مدى أهمية الحيز الفارغ؟","options":["أكثر","أقل","غير مهم إطلاقاً","فقط في الصيف"],"explanation":"كلما كان الحمل أبرد وأكثر كثافة، زادت أهمية الحيز الفارغ."},"74":{"q":"ما الذي يمكن أن يبلغه السائل الكثيف قبل أن يمتلئ الصهريج؟","options":["حد الوزن القانوني","نقطة الغليان","سدادة ضغط البخار","خط التعبئة"],"explanation":"يمكن للسائل الكثيف أن يبلغ حد الوزن قبل أن يمتلئ الصهريج."},"75":{"q":"ماذا يتيح لك تصديق X المُدمج أن تنقل؟","options":["الصهريج بالإضافة إلى المواد الخطرة","المقطورات المزدوجة بالإضافة إلى الصهريج","الركاب بالإضافة إلى الصهريج","الحافلات بالإضافة إلى المواد الخطرة"],"explanation":"يجمع تصديق X بين الصهريج والمواد الخطرة."},"76":{"q":"اندفاع السائل إلى الأمام بعد التوقف يمكن أن يدفع الشاحنة إلى أين؟","options":["إلى داخل تقاطع طرق","إلى الرجوع للخلف","عن حوامل الرفع","إلى الخلف صعوداً"],"explanation":"اندفاع السائل إلى الأمام يمكن أن يدفع الشاحنة إلى داخل تقاطع طرق."},"77":{"q":"مقارنة بالسرعة المحددة على المنحدر، ما مدى السرعة التي ينبغي أن يسلك بها سائق الصهريج المنحدر؟","options":["أبطأ من السرعة المحددة","تماماً عند السرعة المحددة","أعلى قليلاً من السرعة المحددة","ضعف السرعة المحددة"],"explanation":"اسلك المنحدرات بسرعة أبطأ من السرعة المحددة على المنحدر."},"78":{"q":"كيف ينبغي أن تحرّك مركبة الصهريج من وضع التوقف؟","options":["بسلاسة","بسرعة","بانطلاق قوي","بهزات متكررة"],"explanation":"ابدأ التحرّك بسلاسة لتجنّب مشكلات اندفاع السائل."},"79":{"q":"مع وجود نظام منع انغلاق المكابح (ABS)، كيف ينبغي أن تكبح أثناء التوقف الطارئ في مركبة الصهريج؟","options":["بقوة","بخفة","بضغط متقطّع على الدوّاسة","لا تكبح إطلاقاً"],"explanation":"مع نظام ABS، اكبح بقوة عند التوقف الطارئ."}},"learn-doubles":{"0":{"q":"أي مقطورة ينبغي وضعها أولاً، مباشرة خلف الجرار؟","options":["الأكثر تحميلاً","الأقل تحميلاً","المقطورة الفارغة","الأقصر"],"explanation":"ضع المقطورة الأكثر تحميلاً أولاً، مباشرة خلف الجرار، مع وضع المقطورات الأخف نحو الخلف."},"1":{"q":"مقارنة بسحب مقطورة واحدة، فإن سحب مقطورتين أو ثلاث مقطورات يكون:","options":["أكثر ثباتاً","أقل ثباتاً","مساوياً في الثبات","أسهل في الرجوع للخلف"],"explanation":"سحب مقطورتين أو ثلاث مقطورات أقل ثباتاً من سحب مقطورة واحدة، ويزيد من خطر الانقلاب والانثناء (الجاك-نايف)."},"2":{"q":"في ظاهرة التضخيم الخلفي (\"ضرب السوط\")، أي مقطورة تتأرجح إلى أبعد مدى؟","options":["الجرار","المقطورة الأمامية","المقطورة الخلفية","عربة التحويل (الدوللي)"],"explanation":"في التضخيم الخلفي، تؤدي حركة توجيه سريعة إلى تأرجح المقطورة الخلفية بمدى أوسع بكثير وقد تنقلب."},"3":{"q":"على أي تركيبة يكون تأثير التضخيم الخلفي (ضرب السوط) أسوأ؟","options":["المقطورات الفردية","جميعها بالتساوي","المقطورات المزدوجة","المقطورات الثلاثية"],"explanation":"يزداد التضخيم الخلفي مع كل مقطورة إضافية، لذا فهو أسوأ على المقطورات الثلاثية منه على المزدوجة."},"4":{"q":"لتجنّب التضخيم الخلفي، كيف ينبغي أن توجّه المركبة؟","options":["بلطف وتدرّج","بسرعة وحدّة","بشدة في المنعطفات","بحركات مفاجئة"],"explanation":"لتجنّب التضخيم الخلفي، وجّه المركبة بلطف وتدرّج، وتجنّب تغييرات الحارة السريعة، وأبطئ قبل المنعطفات."},"5":{"q":"عند سرعة الطريق السريع، ماذا يمكن أن تقلب حركة توجيه مفاجئة؟","options":["الجرار","المقطورة الأخيرة","المقطورة الأمامية","لا شيء على الإطلاق"],"explanation":"يمكن لحركة مفاجئة عند سرعة الطريق السريع أن تقلب المقطورة الأخيرة حتى لو بقي الجرار منتصباً."},"6":{"q":"أين ينبغي أن توضع المقطورة الأكثر تحميلاً في مجموعة المقطورات المزدوجة أو الثلاثية؟","options":["نحو الخلف","في المنتصف","مباشرة خلف الجرار","خلف مقطورة فارغة"],"explanation":"ضع المقطورة الأكثر تحميلاً أولاً، مباشرة خلف الجرار، مع وضع المقطورات الأخف نحو الخلف."},"7":{"q":"عند تحميل مجموعة من المقطورات، أين يجب ألّا تضع أبداً مقطورة محمّلة؟","options":["أولاً في الصف","مباشرة خلف الجرار","في المنتصف","خلف مقطورة فارغة"],"explanation":"لا تضع أبداً مقطورة محمّلة خلف مقطورة فارغة، لأن المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب."},"8":{"q":"أين ينبغي أن توضع المقطورة الأخف في المجموعة؟","options":["نحو الخلف","مباشرة خلف الجرار","أولاً في المجموعة","خلف مقطورة محمّلة"],"explanation":"ضع المقطورات الأخف نحو الخلف، لأن المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب."},"9":{"q":"ما الذي يربط مقطورة بالأخرى؟","options":["خطّاف الجرّ (البنتل)","عربة التحويل (الدوللي)","العجلة الخامسة","وصلة الهواء (القفّاز)"],"explanation":"تربط عربة التحويل (الدوللي) مقطورة بالأخرى في تركيبة المقطورات المزدوجة أو الثلاثية."},"10":{"q":"ما الجزء الذي يربط مقطورة بالأخرى في مجموعة المقطورات المزدوجة أو الثلاثية؟","options":["خطّاف الجرّ (البنتل)","وصلات الهواء (القفّازات)","عربة التحويل (الدوللي)","العجلة الخامسة"],"explanation":"تربط عربة التحويل (الدوللي) مقطورة بالأخرى، ولها قضيب جرّ خاص بها وعجلة خامسة وفكوك إقفال وخطوط هواء وسلك كهربائي وسلاسل أمان."},"11":{"q":"عند توصيل المقطورات المزدوجة أو الثلاثية، أين تحدث معظم الأخطاء؟","options":["عند مسمار الارتكاز (الكينغ بين)","عند الجرار","عند المقطورة الأمامية","عند عربة التحويل (الدوللي)"],"explanation":"تحدث معظم أخطاء التوصيل عند ربط مقطورة ثانية أو ثالثة بعربة التحويل (الدوللي)."},"12":{"q":"عند توصيل عربة التحويل (الدوللي)، ماذا يجب أن تثبّت؟","options":["خطّاف الجرّ وسلاسل الأمان","العجلة الخامسة ومسمار الارتكاز","عجلات الإنزال والمكابح","واقيات الطين والعاكسات"],"explanation":"عند التوصيل، ثبّت خطّاف الجرّ (البنتل) وسلاسل الأمان."},"13":{"q":"عند التوصيل، كيف ينبغي أن توصّل وصلات الهواء (القفّازات)؟","options":["متقاطعة","غير متقاطعة","بشكل مرتخٍ","مغطّاة بالأغطية"],"explanation":"وصّل وصلات الهواء (القفّازات) دون تقاطعها، ووصّل سلك الإضاءة."},"14":{"q":"بعد التوصيل، أين تفتح صمام خط الطوارئ للتأكد من تدفّق الهواء؟","options":["عند عربة التحويل (الدوللي)","عند مقصورة الجرار","عند مؤخرة المقطورة الأخيرة","بين المقطورتين الأوليين"],"explanation":"افتح صمام خط الطوارئ عند مؤخرة المقطورة الأخيرة للتأكد من تدفّق الهواء، ثم أغلقه."},"15":{"q":"كيف ينبغي ضبط صمامات الإغلاق بين المقطورات؟","options":["جميعها مفتوحة، بما فيها صمامات المقطورة الأخيرة","جميعها مغلقة، بما فيها صمامات المقطورة الأخيرة","صمامات المقطورة الأمامية مغلقة والبقية مفتوحة","جميعها مفتوحة، وصمامات المقطورة الأخيرة مغلقة"],"explanation":"يجب أن تكون صمامات الإغلاق بين المقطورات مفتوحة، وأن تكون صمامات إغلاق المقطورة الأخيرة مغلقة."},"16":{"q":"أي خزان ينبغي أن تفحصه على عربة التحويل (الدوللي)؟","options":["خزان الهواء","خزان الوقود","خزان الماء","خزان الزيت"],"explanation":"عند فحص عربة التحويل (الدوللي)، تحقق من خزان الهواء إلى جانب خطّاف الجرّ وسلاسل الأمان ووصلات الهواء."},"17":{"q":"مقارنة بمقطورة واحدة، كم تحتاج المقطورات المزدوجة والثلاثية من مساحة للتوقف والانعطاف وتغيير الحارة؟","options":["مساحة أقل","مساحة أكبر","المساحة نفسها","لا تحتاج مساحة إضافية"],"explanation":"تحتاج المقطورات المزدوجة والثلاثية إلى مساحة أكبر للتوقف والانعطاف وتغيير الحارة مقارنة بمقطورة واحدة."},"18":{"q":"ماذا ينبغي أن تفعل إذا اضطررت إلى إعادة وضع مجموعة من المقطورات المزدوجة أو الثلاثية؟","options":["ارجع للخلف ببطء","وجّه بكلتا اليدين","افصل المقطورات","استعن بمساعد توجيه"],"explanation":"لا يمكنك عادةً الرجوع بالمقطورات المزدوجة أو الثلاثية بأمان، لذا افصلها إذا اضطررت إلى إعادة وضعها."},"19":{"q":"يُشترط وجود نظام ABS على عربات التحويل والمقطورات المصنّعة في أو بعد أي تاريخ؟","options":["1 مارس 1996","1 مارس 1997","1 مارس 2000","1 مارس 1998"],"explanation":"يُشترط وجود نظام ABS على عربات التحويل والمقطورات المصنّعة في أو بعد 1 مارس 1998."},"20":{"q":"مقارنة بمقطورة واحدة، هل يزيد سحب مقطورتين أو ثلاث مقطورات من خطر الانقلاب والانثناء (الجاك-نايف)؟","options":["نعم، يزيد من خطر الانقلاب والانثناء","لا، يقلّل من خطر الانقلاب والانثناء","لا، ليس له تأثير على الثبات","لا، يؤثر فقط على مسافة الكبح"],"explanation":"سحب مقطورتين أو ثلاث مقطورات أقل ثباتاً من سحب مقطورة واحدة، ويزيد من خطر الانقلاب والانثناء (الجاك-نايف)."},"21":{"q":"لتجنّب التضخيم الخلفي (ضرب السوط)، ماذا ينبغي أن تفعل؟","options":["اكبح بقوة ووجّه بحدّة","تجنّب تغييرات الحارة السريعة وأبطئ قبل المنعطفات","زد السرعة وغيّر الحارة بسرعة","وجّه بحدّة وحافظ على سرعتك"],"explanation":"لتجنّب التضخيم الخلفي، تجنّب تغييرات الحارة السريعة وأبطئ قبل المنعطفات."},"22":{"q":"لماذا يجب ألا تضع أبدًا مقطورة محمّلة خلف مقطورة فارغة؟","options":["المقطورة الفارغة تكبح بقوة مفرطة","المقطورة المحمّلة توجَّه بسهولة أكبر","المقطورة الخلفية الخفيفة ترتد وقد تنقلب","المقطورة الأمامية تحمل وزنًا أقل"],"explanation":"المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب، لذا يجب ألا تُوضع مقطورة محمّلة أبدًا خلف مقطورة فارغة."},"23":{"q":"ماذا تملك عربة التحويل (الدوللي)؟","options":["قضيب جرّ وعجلة خامسة فقط","خطوط هواء وسلك إضاءة فقط","فكوك قفل وسلاسل أمان فقط","قضيب جرّ، وعجلة خامسة، وفكوك، وخطوط هواء، وسلك، وسلاسل"],"explanation":"تملك عربة التحويل قضيب جرّ خاصًا بها، وعجلة خامسة، وفكوك قفل، وخطوط هواء، وسلكًا كهربائيًا، وسلاسل أمان."},"24":{"q":"عند وصل المقطورات، أي سلك يجب أن توصله؟","options":["سلك الإضاءة (السلك الكهربائي)","سلك بدء التشغيل","سلك الوقود","سلك الراديو"],"explanation":"عند الوصل، يجب أن توصل سلك الإضاءة (السلك الكهربائي)."},"25":{"q":"بعد فتح صمام خط الطوارئ في مؤخرة آخر مقطورة للتأكد من تدفق الهواء، ماذا تفعل؟","options":["تتركه مفتوحًا أثناء القيادة","تغلق الصمام","تفصل وصلات الأيدي (glad hands)","تفتحه مرة ثانية"],"explanation":"بعد فتح صمام خط الطوارئ في مؤخرة آخر مقطورة للتأكد من تدفق الهواء، تغلقه بعد ذلك."},"26":{"q":"ما الأجزاء التي يجب أن تفحصها في عربة التحويل ووصلة المقطورة؟","options":["طبول الفرامل، ورفارف الطين، والعاكسات","حواجز العجلات، والمرايا، وأحزمة الأمان","خطّاف السحب (pintle hook)، وسلاسل الأمان، ووصلات الأيدي (glad hands)","المصابيح الأمامية، والمساحات، ومفصلات الأبواب"],"explanation":"تشمل عناصر الفحص خطّاف السحب، وسلاسل الأمان، والعجلة الخامسة، وفكوك القفل، ووصلات الأيدي، بالإضافة إلى خزان هواء عربة التحويل."},"27":{"q":"هل يمكنك أن ترجع بأمان بمجموعة مقطورات مزدوجة أو ثلاثية إلى الخلف؟","options":["نعم، ببطء وبأي ترس","نعم، بوجود مراقب","نعم، على أرض مستوية فقط","لا، عمومًا لا يمكنك ذلك"],"explanation":"عمومًا لا يمكنك أن ترجع بأمان بمجموعة مقطورات مزدوجة أو ثلاثية إلى الخلف."},"28":{"q":"أي معدات يُشترط أن تحتوي على نظام ABS إذا صُنعت في 1 مارس 1998 أو بعده؟","options":["عربات التحويل والمقطورات","المحور الأمامي للجرّار فقط","المقطورة الخلفية فقط","وصلات الأيدي وأسلاك الإضاءة"],"explanation":"يُشترط وجود نظام ABS على عربات التحويل والمقطورات المصنوعة في 1 مارس 1998 أو بعده."},"29":{"q":"بسبب تأثير \"ضربة السوط\"، ماذا قد يحدث للمقطورة الخلفية عندما تنحرف بعيدًا؟","options":["قد تنقلب","تزداد سرعتها","تكبح بقوة أكبر","تستقيم"],"explanation":"التضخيم الخلفي (\"ضربة السوط\") يجعل المقطورة الخلفية تنحرف أبعد بكثير، وقد تنقلب."},"30":{"q":"كيف يتغير تأثير ضربة السوط (التضخيم الخلفي) كلما أضفت المزيد من المقطورات؟","options":["يبقى كما هو مع كل مقطورة","يزداد قوة مع كل مقطورة تُضاف","يضعف مع كل مقطورة تُضاف","يختفي مع زيادة عدد المقطورات"],"explanation":"يزداد التضخيم الخلفي مع كل مقطورة تُضاف، لذا يكون التأثير أسوأ في المقطورات الثلاثية منه في المزدوجة."},"31":{"q":"عندما تنقلب آخر مقطورة عند سرعة الطريق السريع، ماذا يحدث عادةً للجرّار؟","options":["ينقلب هو أيضًا","يدور إلى الخلف","يبقى منتصبًا","يفقد كل الفرامل"],"explanation":"حركة مفاجئة عند سرعة الطريق السريع قد تقلب آخر مقطورة حتى مع بقاء الجرّار منتصبًا."},"32":{"q":"مع المقطورات المزدوجة، ماذا يجب أن تفعل قبل المنعطفات؟","options":["تزيد السرعة قليلًا","تحافظ على السرعة نفسها","تنزلق بالترس المحايد","تبطئ أولًا"],"explanation":"مع المقطورات المزدوجة، أبطئ قبل المنعطفات للحفاظ على ثبات المقطورات."},"33":{"q":"ماذا يُسمى الأمر حين تجعل حركة توجيه سريعة المقطورة الخلفية تنحرف أبعد بكثير؟","options":["التضخيم الخلفي (ضربة السوط)","انجراف المقطورة","انثناء الجرّار (jackknife)","تلاشي الفرامل"],"explanation":"التضخيم الخلفي، أو ضربة السوط، هو عندما تجعل حركة توجيه سريعة المقطورة الخلفية تنحرف أبعد بكثير."},"34":{"q":"سحب مقطورتين أو ثلاث مقطورات يزيد من أي خطرين؟","options":["ارتفاع حرارة المحرك واستهلاك الوقود","الانقلاب والانثناء (jackknife)","تآكل الإطارات وتلاشي الفرامل","فقدان التوجيه والتوقف المفاجئ"],"explanation":"سحب مقطورتين أو ثلاث مقطورات يزيد من خطر الانقلاب والانثناء (jackknife)."},"35":{"q":"عند سحب المقطورات المزدوجة، أي مقطورة توضع مباشرةً خلف الجرّار؟","options":["أيًا كانت التي تصلها أولًا","المقطورة الفارغة","المقطورة الأثقل تحميلًا","المقطورة الأخف"],"explanation":"ضع المقطورة الأثقل تحميلًا أولًا، مباشرةً خلف الجرّار، مع المقطورات الأخف نحو المؤخرة."},"36":{"q":"مع مقطورة محمّلة وأخرى فارغة، أي ترتيب هو الصحيح؟","options":["كلا الترتيبين مقبول","الفارغة في الأمام، والمحمّلة في المؤخرة","جنبًا إلى جنب، لا على التوالي","المحمّلة في الأمام، والفارغة في المؤخرة"],"explanation":"لا تضع أبدًا مقطورة محمّلة خلف مقطورة فارغة، لأن المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب."},"37":{"q":"ماذا تميل المقطورة الخلفية الخفيفة إلى فعله؟","options":["الارتداد والانقلاب بسهولة أكبر","البقاء ثابتة على الطريق","إيقاف المجموعة بشكل أسرع بكثير","توجيه الجرّار نيابةً عنك"],"explanation":"المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب."},"38":{"q":"هل تملك عربة التحويل عجلة خامسة خاصة بها؟","options":["لا، إنها تشارك العجلة الخامسة للجرّار","نعم، لها عجلة خامسة خاصة بها","لا، العجلات الخامسة توجد على الجرّارات فقط","نعم، لكن فقط في المجموعات الثلاثية"],"explanation":"تملك عربة التحويل عجلة خامسة خاصة بها، إلى جانب قضيب جرّ، وفكوك قفل، وخطوط هواء، وسلك كهربائي، وسلاسل أمان."},"39":{"q":"ما الاسم الآخر لعربة التحويل التي تربط مقطورة بالتي تليها؟","options":["قضيب الخطّاف (pintle bar)","سكة الوصل","ترس التحويل (converter gear)","نير المقطورة"],"explanation":"عربة التحويل، التي تُسمى أيضًا ترس التحويل (converter gear)، تربط مقطورة بالتي تليها."},"40":{"q":"ماذا توصل وصلات الأيدي (glad hands) على المقطورة؟","options":["سلاسل الأمان","سلك الإضاءة الكهربائي","فكوك القفل","خطوط الهواء"],"explanation":"وصلات الأيدي (glad hands) هي الوصلات التي تربط خطوط الهواء بين الجرّار والمقطورة."},"41":{"q":"عند وصل المقطورات المزدوجة أو الثلاثية، في أي خطوة تحدث معظم الأخطاء؟","options":["وصل المقطورة الثانية أو الثالثة بعربة التحويل","فحص مستوى زيت محرك الجرّار","ضبط مقعد السائق والمرايا","ملء خزان الوقود الرئيسي للجرّار"],"explanation":"وصل أو فصل مقطورة ثانية أو ثالثة بعربة التحويل هو حيث تحدث معظم الأخطاء."},"42":{"q":"لماذا تفتح صمام خط الطوارئ في مؤخرة آخر مقطورة بعد الوصل؟","options":["لتصريف الماء من خزانات الهواء","للتأكد من وصول الهواء إلى المقطورة الخلفية","لاختبار أضواء فرامل المقطورة","لتحرير فرامل الانتظار"],"explanation":"فتح صمام خط الطوارئ في مؤخرة آخر مقطورة يؤكد وصول الهواء إلى المقطورة الخلفية."},"43":{"q":"في مجموعة مقطورات مزدوجة، كيف يجب أن تُضبط صمامات قطع التدفق (cut-out) في آخر مقطورة؟","options":["مفتوحة","نصف مفتوحة","مغلقة","مُزالة"],"explanation":"يجب أن تكون صمامات قطع التدفق (cut-out) في آخر مقطورة مغلقة، بينما تبقى الصمامات التي بين المقطورات مفتوحة."},"44":{"q":"بماذا تُسمى أيضًا صمامات قطع التدفق بين المقطورات؟","options":["صمامات وصلات الأيدي (glad-hand)","صمامات التتابع (relay)","صمامات الخطّاف (pintle)","صمامات قطع التدفق (cut-out)"],"explanation":"تُعرف صمامات قطع التدفق بين المقطورات أيضًا باسم صمامات القطع (cut-out)."},"45":{"q":"أثناء فحص المقطورات المزدوجة/الثلاثية، هل يجب أن تفحص فكوك القفل؟","options":["نعم، افحص فكوك القفل","لا، افحص الإطارات فقط","لا، السائق فقط هو من يفحص","لا، تجاوز فكوك القفل"],"explanation":"في المقطورات المزدوجة/الثلاثية، افحص خزان هواء عربة التحويل، وخطّاف السحب، وسلاسل الأمان، والعجلة الخامسة، وفكوك القفل، ووصلات الأيدي."},"46":{"q":"لأي إجراءات تحتاج المقطورات المزدوجة/الثلاثية إلى مساحة أكبر؟","options":["للتوقف فقط","للتوقف، والانعطاف، وتغيير المسارات","للانعطاف فقط","لتغيير المسارات فقط"],"explanation":"تحتاج المقطورات المزدوجة والثلاثية إلى مساحة أكبر للتوقف، والانعطاف، وتغيير المسارات."},"47":{"q":"بما أنك لا تستطيع الرجوع بأمان بمجموعة من المقطورات المزدوجة، فماذا يجب أن تفعل لإعادة وضعها؟","options":["ارجع للخلف ببطء شديد في خط مستقيم","قُد بشدة أثناء الرجوع بالمجموعة","افصل المقطورات وأعد وضعها","استعن بشخص يوجهك أثناء الرجوع للخلف"],"explanation":"لا يمكنك عمومًا الرجوع للخلف بمجموعة من المقطورات المزدوجة أو الثلاثية بأمان، لذا يجب عليك فصلها لإعادة وضعها."},"48":{"q":"في أي عام أصبح نظام الفرامل المانعة للانغلاق (ABS) مطلوبًا على عربات التحويل (الدوللي) والمقطورات؟","options":["1995","1996","1997","1998"],"explanation":"نظام الفرامل المانعة للانغلاق (ABS) مطلوب على عربات التحويل والمقطورات المصنوعة في أو بعد 1 مارس 1998."},"49":{"q":"إلى جانب العجلة الخامسة، والفكوك القافلة، وخطوط الهواء، والسلك الكهربائي، وسلاسل الأمان، ماذا تمتلك عربة التحويل (الدوللي) أيضًا؟","options":["قضيب جر خاص بها","محرك خاص بها","عجلة قيادة خاصة بها","خزان وقود خاص بها"],"explanation":"تمتلك عربة التحويل قضيب جر خاصًا بها بالإضافة إلى العجلة الخامسة والفكوك القافلة وخطوط الهواء والسلك الكهربائي وسلاسل الأمان."},"50":{"q":"في فحص المقطورات المزدوجة/الثلاثية، العجلة الخامسة التي تفحصها هي جزء من أي مكوّن؟","options":["دعامة الهبوط للمقطورة","عربة التحويل (الدوللي)","خزان هواء الجرار","مقبض خطاف البنتل"],"explanation":"تمتلك عربة التحويل عجلتها الخامسة الخاصة، والتي يجب عليك فحصها في مجموعة المقطورات المزدوجة/الثلاثية."},"51":{"q":"عند جر مقطورات ثلاثية، كيف يقارن تأثير \"ضربة السوط\" مع جر المقطورات المزدوجة؟","options":["يكون أسوأ في الثلاثية","يكون أخف في الثلاثية","يكون نفسه في كليهما","يختفي في الثلاثية"],"explanation":"يزداد تأثير التضخيم الخلفي مع كل مقطورة، لذا يكون أسوأ في المقطورات الثلاثية."},"52":{"q":"ماذا يمكن أن تسبّبه حركة القيادة السريعة للمقطورة الخلفية؟","options":["الانقلاب","الفرملة بقوة أكبر","التسارع","الاستقامة"],"explanation":"يمكن أن تجعل حركة القيادة السريعة المقطورة الخلفية تنحرف بعيدًا وتنقلب."},"53":{"q":"لتقليل خطر الانقلاب مع المقطورات المزدوجة والثلاثية، يجب أن تتجنّب:","options":["تغييرات المسار السريعة","السرعات الثابتة","المنعطفات الواسعة","القيادة اللطيفة"],"explanation":"يجب أن تتجنّب تغييرات المسار السريعة لتقليل خطر الانقلاب."},"54":{"q":"ماذا تستخدم عربة التحويل (الدوللي) للاتصال بالمقطورة التي أمامها؟","options":["قضيب جر","المسمار الملكي فقط","كرة وصلة المقطورة","دعامة الهبوط"],"explanation":"تمتلك عربة التحويل قضيب جر خاصًا بها للاتصال بالمقطورة التي أمامها."},"55":{"q":"أي من هذه يُعد جزءًا من عربة التحويل (الدوللي)؟","options":["الفكوك القافلة","عجلة القيادة","مقصورة النوم","باب الشحن"],"explanation":"تمتلك عربة التحويل فكوكها القافلة الخاصة بها."},"56":{"q":"عند توصيل وصلات الهواء (glad hands) بين المقطورات، يجب أن تحرص على عدم:","options":["تقاطعها","إحكام ربطها","طلائها","ترقيمها"],"explanation":"يجب أن توصّل وصلات الهواء دون تقاطعها."},"57":{"q":"على المقطورة الأخيرة في المجموعة، كيف يجب ضبط صمامات الإغلاق (الفصل)؟","options":["مغلقة","مفتوحة","منزوعة","نصف مفتوحة"],"explanation":"يجب أن تكون صمامات الإغلاق في المقطورة الأخيرة مغلقة."},"58":{"q":"أين تفتح صمام خط الطوارئ للتأكد من وصول الهواء إلى المقطورة الخلفية؟","options":["في مؤخرة المقطورة الأخيرة","في مقدمة الجرار","عند قضيب جر عربة التحويل","عند مقدمة المقطورة الأولى"],"explanation":"تفتح الصمام في مؤخرة المقطورة الأخيرة للتأكد من تدفق الهواء."},"59":{"q":"للتأكد من وصول الهواء إلى المقطورة الخلفية، ماذا يجب أن تتحقق منه بعد القرن (التوصيل)؟","options":["تدفق الهواء إلى المقطورة الخلفية","نزع الفرامل","أن المقطورة فارغة","فك عربة التحويل"],"explanation":"بعد التوصيل يجب أن تتأكد من وصول الهواء إلى المقطورة الخلفية."},"60":{"q":"المقطورة الخلفية الخفيفة تكون أكثر عرضة لـ:","options":["الانقلاب","التوقف بشكل أسرع","البقاء ملامسة للأرض","السير في خط مستقيم"],"explanation":"المقطورة الخلفية الخفيفة ترتد وتكون أكثر عرضة للانقلاب."},"61":{"q":"أي خطاف يجب أن تثبّته عند قرن (توصيل) عربة التحويل؟","options":["خطاف البنتل","خطاف الإمساك","خطاف القطر","خطاف الشحن"],"explanation":"يجب أن تثبّت خطاف البنتل عند توصيل عربة التحويل."},"62":{"q":"إلى جانب خطاف البنتل، ماذا يجب أن تثبّت أيضًا على عربة التحويل؟","options":["سلاسل الأمان","رفارف الطين","العاكسات","غطاء الوقود"],"explanation":"يجب أن تثبّت سلاسل الأمان إلى جانب خطاف البنتل."},"63":{"q":"بعد فتح صمام خط الطوارئ للتأكد من تدفق الهواء، ماذا يجب أن تفعل به؟","options":["أغلقه","اتركه مفتوحًا","انزعه","ضع شريطًا لاصقًا عليه"],"explanation":"بعد التأكد من تدفق الهواء، تغلق صمام خط الطوارئ."},"64":{"q":"بالمقارنة مع مقطورة واحدة، تحتاج المقطورات المزدوجة والثلاثية إلى مساحة أكبر لـ:","options":["التوقف","الدوران في وضع الخمول","الركن في منحدر","التزود بالوقود"],"explanation":"تحتاج المقطورات المزدوجة والثلاثية إلى مساحة أكبر للتوقف والانعطاف وتغيير المسارات."},"65":{"q":"عمومًا لا يمكن للمقطورات المزدوجة والثلاثية أن تكون بأمان:","options":["مرجوعة للخلف","مقودة صعودًا","منعطفة يمينًا","محمّلة"],"explanation":"لا يمكنك عمومًا الرجوع للخلف بمجموعة من المقطورات المزدوجة أو الثلاثية بأمان."},"66":{"q":"في مجموعة من المقطورات، يجب وضع المقطورات الأخف:","options":["نحو المؤخرة","مباشرة خلف الجرار","على عربة التحويل فقط","في الوسط فقط"],"explanation":"توضع المقطورات الأخف نحو مؤخرة المجموعة."},"67":{"q":"أي جزء من نظام الهواء تحمله عربة التحويل (الدوللي) خاصًا بها؟","options":["خطوط الهواء","ضاغط","مجفف هواء","منظّم"],"explanation":"تمتلك عربة التحويل خطوط الهواء الخاصة بها."},"68":{"q":"أثناء الفحص، أي جزء من عربة التحويل يجب أن تفحصه إلى جانب خطاف البنتل؟","options":["العجلة الخامسة","عداد المسافات","جهاز تسجيل السرعة","صندوق التوجيه"],"explanation":"يجب أن تفحص العجلة الخامسة على عربة التحويل."},"69":{"q":"جر مقطورتين أو ثلاث مقطورات يجعل المركبة:","options":["أقل استقرارًا","أكثر استقرارًا","أسهل في الرجوع للخلف","أسرع في التوقف"],"explanation":"جر مقطورتين أو ثلاث مقطورات يكون أقل استقرارًا من جر مقطورة واحدة."},"70":{"q":"أي جزء كهربائي تمتلكه عربة التحويل (الدوللي) خاصًا بها؟","options":["سلك كهربائي","مجموعة بطاريات","مولّد تيار متردد","محرك بدء التشغيل"],"explanation":"تمتلك عربة التحويل السلك الكهربائي الخاص بها."}},"learn-passenger":{"0":{"q":"أثناء فحص ما قبل الرحلة للحافلة، ماذا يجب أن تتحقق من أنه يعمل؟","options":["مخارج الطوارئ والأضواء","تكييف هواء المقصورة","حوض دورة المياه على متن الحافلة","مصابيح القراءة العلوية"],"explanation":"افحص الحافلة قبل الرحلة وتأكد من أن مخارج الطوارئ وأضواء المخارج وإشارة التوقف/الباب تعمل."},"1":{"q":"أثناء الفحص قبل الرحلة، ما الذي يجب أن يكون خالياً من الأمتعة؟","options":["مقعد السائق","الممر وجميع المخارج","غطاء خزان الوقود","خط الوقوف للركاب"],"explanation":"أثناء الفحص قبل الرحلة، يجب أن تتأكد من أن الممر وجميع المخارج خالية من الأمتعة."},"2":{"q":"يجب تأمين الأمتعة المحمولة باليد بحيث لا تسد ماذا؟","options":["مقعد السائق","صندوق الأجرة","الممر أو أي مخرج","ماسحات الزجاج الأمامي"],"explanation":"يجب تأمين الأمتعة المحمولة باليد بحيث لا تسد الممر أو أي مخرج."},"3":{"q":"يجب تأمين الأمتعة المحمولة باليد بحيث لا تفعل ماذا؟","options":["تحجب رؤية السائق","تتجاوز خط الوقوف للركاب","تلامس الأرضية","تسقط على أحد"],"explanation":"يجب تأمين الأمتعة المحمولة باليد بحيث لا تسقط على أحد أو تسد الممر أو المخارج."},"4":{"q":"أين يجب أن يبقى الركاب الواقفون في الحافلة؟","options":["خلف خط الوقوف للركاب","أمام خط الوقوف للركاب","خلف مقعد السائق","بجوار الباب الأمامي"],"explanation":"يجب أن يبقى الركاب الواقفون خلف خط الوقوف (الخط الأبيض) حتى لا يحجبوا رؤية السائق."},"5":{"q":"أين يجب أن يبقى الركاب الواقفون في الحافلة؟","options":["أمام خط الوقوف للركاب","خلف خط الوقوف للركاب","بجوار السائق","في الممر الأمامي"],"explanation":"يجب أن يبقى الركاب الواقفون خلف خط الوقوف وألا يحجبوا رؤية السائق أبداً."},"6":{"q":"ما الذي يجب أن يعلنه سائق الحافلة عند الحاجة؟","options":["أسعار التذاكر","وزن المركبة","المخاطر والتوقفات","سرعة المحرك"],"explanation":"يجب أن يعلن سائق الحافلة عن المخاطر والتوقفات عند الحاجة وأن يفرمل بسلاسة."},"7":{"q":"كيف يجب أن يفرمل سائق الحافلة لتجنب قذف الركاب الواقفين؟","options":["بسرعة","بشكل مفاجئ","بقوة","بسلاسة"],"explanation":"افرمل بسلاسة، لأن التوقفات المفاجئة قد تقذف الركاب الواقفين."},"8":{"q":"على أي مسافة يجب أن تتوقف الحافلة قبل تقاطع السكة الحديدية؟","options":["بين 15 و50 قدماً","بين 10 و40 قدماً","بين 25 و75 قدماً","بين 50 و100 قدم"],"explanation":"يجب أن تتوقف الحافلة على مسافة بين 15 و50 قدماً قبل تقاطع السكة الحديدية."},"9":{"q":"عند تقاطع السكة الحديدية، ما الذي يجب أن يفعله السائق؟","options":["يبوّق وينتظر","ينظر ويستمع","يخفض الغيار","يسرع للعبور"],"explanation":"عند تقاطع السكة الحديدية، يجب أن يتوقف السائق وينظر ويستمع قبل العبور."},"10":{"q":"أثناء عبور قضبان السكة الحديدية، ما الذي يجب على سائق الحافلة ألا يفعله أبداً؟","options":["النظر في الاتجاهين","الإصغاء للقطارات","تغيير الغيار","تخفيف السرعة"],"explanation":"يجب على سائق الحافلة ألا يغيّر الغيار أبداً أثناء عبور قضبان السكة الحديدية."},"11":{"q":"متى يجب على الحافلة ألا تتوقف عند تقاطع السكة الحديدية؟","options":["عند إشارة حمراء وامضة","عندما يكون الحاجز منخفضاً","عندما يكون القطار قريباً","عند تقاطع به ضوء أخضر"],"explanation":"لا تتوقف الحافلة عند التقاطعات المعفاة أو المهجورة أو الصناعية التي يوجد بها موجّه أو ضوء أخضر."},"12":{"q":"على بعد كم قدماً قبل الجسر المتحرك يجب أن تتوقف الحافلة عندما لا يوجد ضوء أخضر أو إشارة تدل على أن العبور آمن؟","options":["50 قدماً على الأقل","15 قدماً على الأقل","25 قدماً على الأقل","100 قدم على الأقل"],"explanation":"يجب أن تتوقف الحافلة على بعد 50 قدماً على الأقل قبل الجسر المتحرك ما لم يدل ضوء أخضر أو موظف على أن العبور آمن."},"13":{"q":"ما هو أقصى إجمالي للمواد الخطرة الذي يمكن أن تحمله الحافلة؟","options":["100 رطل","500 رطل","1000 رطل","50 رطلاً"],"explanation":"لا يجوز للحافلة أن تحمل أكثر من 500 رطل من المواد الخطرة إجمالاً."},"14":{"q":"ما هي المتفجرات التي لا يجوز للحافلة أن تحملها أبداً؟","options":["الصنف 1.4","الصنف 1.5","الصنف 1.1 و1.2 و1.3","الصنف 1.6"],"explanation":"لا يجوز للحافلة أبداً أن تحمل متفجرات الصنف 1.1 أو 1.2 أو 1.3."},"15":{"q":"ما نوع المادة التي لا يجوز للحافلة أن تحملها أبداً؟","options":["المواد الغذائية الصلبة","قوارير المياه المختومة","علب الأدوات الصغيرة","معظم المواد المشعة"],"explanation":"لا يجوز للحافلة أبداً أن تحمل معظم المواد المشعة."},"16":{"q":"ما المادة التي لا يجوز للحافلة أن تحملها أبداً؟","options":["الغاز أو السائل السام","مياه الشرب المعبأة","المواد الخطرة المسموح بها تحت 500 رطل","الأمتعة المحمولة باليد المؤمّنة"],"explanation":"لا يجوز للحافلة أبداً أن تحمل غازاً أو سائلاً ساماً (الصنف 2.3 أو 6.1)."},"17":{"q":"ما هو الحد الأقصى لإجمالي المواد الخطرة المسموح بها في الحافلة؟","options":["100 رطل","500 رطل","1000 رطل","50 رطلاً"],"explanation":"يجوز للحافلة أن تحمل إجمالاً لا يزيد عن 500 رطل من المواد الخطرة المسموح بها."},"18":{"q":"ما هو الحد الأقصى لوزن أي صنف واحد مسموح به من المواد الخطرة يمكن أن تحمله الحافلة؟","options":["50 رطلاً","75 رطلاً","100 رطل","500 رطل"],"explanation":"لا يجوز للحافلة أن تحمل أكثر من 100 رطل من أي صنف واحد مسموح به من المواد الخطرة."},"19":{"q":"في أي مكان من الحافلة لا يجوز أبداً حمل المواد الخطرة المسموح بها؟","options":["في مخزن البضائع","خلف المحور الخلفي","قرب المخرج الأمامي","حيث يجلس الناس"],"explanation":"لا يجوز أبداً حمل المواد الخطرة المسموح بها في المكان الذي يشغله الناس."},"20":{"q":"أين يجب ألا تتزود الحافلة بالوقود أبداً والركاب على متنها؟","options":["مبنى مغلق","موقف سيارات مفتوح","محطة وقود مخصصة","محطة استراحة خارجية"],"explanation":"لا تتزود الحافلة بالوقود أبداً والركاب على متنها داخل مبنى مغلق أو محصور."},"21":{"q":"أثناء سير الحافلة، ما الذي يجب على السائق تجنب فعله؟","options":["مراقبة الطريق","التحدث إلى الركاب","الفرملة بسلاسة","فحص المرايا"],"explanation":"لا تتحدث إلى الركاب أو تفعل أي شيء يصرف انتباهك عن القيادة أثناء سير الحافلة."},"22":{"q":"من المسؤول عن تطبيق قواعد منع التدخين في الحافلة؟","options":["المرسِل","الركاب","السائق","الميكانيكي"],"explanation":"يجب على سائق الحافلة تطبيق قواعد منع التدخين في الحافلة أثناء الرحلة."},"23":{"q":"عند توقفات الاستراحة والتوقفات الوسطية، ما الذي يجب أن تنتبه له؟","options":["الأمتعة المحمولة باليد غير المثبتة","الواقفون خلف الخط","المخارج الطارئة المفتوحة","الركاب الذين يخطون نحو حركة المرور"],"explanation":"عند توقفات الاستراحة والتوقفات الوسطية، انتبه للركاب الذين يخطون نحو حركة المرور."},"24":{"q":"عند توقفات الاستراحة والتوقفات الوسطية، ما الذي يجب ضبطه قبل أن يتحرك الركاب؟","options":["فرملة الانتظار","إشارة الانعطاف","أضواء التحذير","مثبت السرعة"],"explanation":"عند توقفات الاستراحة والتوقفات الوسطية، أبقِ الحافلة مؤمّنة بفرملة الانتظار المضبوطة قبل أن يتحرك الركاب."},"25":{"q":"أثناء الفحص قبل الرحلة، ما الذي يجب أن تتأكد من عمله بالإضافة إلى المخارج الطارئة وأضواء المخارج؟","options":["إشارة التوقف والباب","الراديو والبوق","مدفئات المقاعد","ضوء صندوق الأجرة"],"explanation":"أثناء الفحص قبل الرحلة، يجب أن تتأكد من عمل إشارة التوقف/الباب، بالإضافة إلى المخارج الطارئة وأضواء المخارج."},"26":{"q":"عند معبر سكة حديد معفى أو مهجور أو صناعي، متى يجوز للحافلة المرور دون التوقف؟","options":["فقط عندما تكون الحافلة فارغة","فقط بعد إطلاق البوق","عندما يشير عامل الإشارة أو الضوء الأخضر بالمرور","فقط ليلاً عندما لا توجد حركة مرور"],"explanation":"لا تحتاج الحافلة إلى التوقف عند المعابر المعفاة أو المهجورة أو الصناعية عندما يوجهها عامل الإشارة أو الضوء الأخضر بالمرور."},"27":{"q":"أي فئة خطر من الغاز السام أو السائل السام يُحظر على الحافلة نقلها؟","options":["الشعبة 1.3 / 1.1","الفئة 7 / 8","الشعبة 1.2 / 4.1","الفئة 2.3 / 6.1"],"explanation":"لا يجوز للحافلة أبداً نقل الغاز السام أو السائل السام، وهو من الفئة 2.3 / 6.1."},"28":{"q":"لماذا تتحقق من عمل إشارة التوقف والباب قبل القيادة؟","options":["لكي يعملا قبل أن تنقل الركاب","لكي تتمكن من إعادة التزود بالوقود والركاب على متن الحافلة","لكي تتمكن من تغيير التروس أثناء عبور السكك","لكي يتمكن الركاب من الوقوف أمام الخط الأبيض"],"explanation":"تقوم بفحص إشارة التوقف والباب قبل الرحلة لكي يعملا قبل أن تنقل الركاب."},"29":{"q":"لماذا يجب تأمين الأمتعة المحمولة باليد على الحافلة؟","options":["لإبقائها جافة ونظيفة للركاب","لكي لا تسد الممر أو المخارج أو تسقط على أحد","لجعل الصعود أسرع عند كل محطة","لكي يتمكن الركاب من الوصول إليها بسهولة أكبر"],"explanation":"يجب تأمين الأمتعة المحمولة باليد لكي لا تسد الممر أو أي مخرج ولا تسقط على أحد."},"30":{"q":"ما لون خط الوقوف (خط الواقفين) على الحافلة؟","options":["أحمر","أصفر","أبيض","أخضر"],"explanation":"يجب أن يبقى الواقفون خلف خط الواقفين، وهو أبيض اللون."},"31":{"q":"إلى جانب البقاء خلف خط الواقفين، ما الذي يجب على الركاب الواقفين أمامه عدم فعله؟","options":["الإمساك بالمقابض","التحدث مع الركاب الآخرين","الجلوس في المقاعد الفارغة","حجب رؤية السائق"],"explanation":"لا تسمح للركاب بالوقوف أمام خط الواقفين أو حجب رؤية السائق."},"32":{"q":"من الأكثر عرضة للخطر من التوقفات المفاجئة على الحافلة؟","options":["الركاب الواقفون","الركاب الجالسون الذين يرتدون أحزمة الأمان","السائق فقط","الركاب المغادرون للحافلة"],"explanation":"يمكن أن تقذف التوقفات المفاجئة الركاب الواقفين، لذا توقف بسلاسة."},"33":{"q":"ما أقرب مسافة يجوز للحافلة التوقف عندها قبل معبر سكة الحديد؟","options":["10 أقدام","15 قدماً","25 قدماً","50 قدماً"],"explanation":"يجب ألا تتوقف الحافلة على مسافة أقرب من 15 قدماً قبل معبر سكة الحديد."},"34":{"q":"عند التوقف قبل معبر سكة الحديد، ما أقصى مسافة يجوز للحافلة التوقف عندها من السكك؟","options":["15 قدماً","25 قدماً","50 قدماً","100 قدم"],"explanation":"يجب أن تتوقف الحافلة بين 15 و50 قدماً قبل معبر سكة الحديد، لذا فإن 50 قدماً هي أقصى مسافة."},"35":{"q":"عند معبر سكة الحديد، هل يجب على الحافلة التوقف التام؟","options":["فقط إذا كان القطار في مرمى البصر","فقط ليلاً","لا، فقط أبطئ السرعة","نعم، يجب أن تتوقف توقفاً تاماً"],"explanation":"يجب أن تتوقف الحافلة توقفاً تاماً بين 15 و50 قدماً قبل معبر سكة الحديد، ثم تنظر وتستمع."},"36":{"q":"لماذا يجب ألا تغير التروس أبداً أثناء عبور سكك الحديد؟","options":["لكي لا تتعطل الحافلة على السكك","لتوفير الوقود أثناء العبور","لتقليل ضوضاء المحرك بالقرب من السكك","لإبقاء الركاب جالسين على السكك"],"explanation":"يجب ألا تغير التروس أبداً أثناء عبور سكك الحديد لكي لا تتعطل الحافلة على السكك."},"37":{"q":"عند أي ثلاثة أنواع من المعابر يجوز للحافلة تخطي التوقف إذا أشار عامل الإشارة أو الضوء الأخضر بالمرور؟","options":["معابر المدارس والنقل العام والساحات","المعابر المعفاة والمهجورة والصناعية","المعابر الخاصة والريفية والطرق السريعة","المعابر المعلَّمة والمزودة بحواجز والمشار إليها بلافتات"],"explanation":"لا يتعين على الحافلة التوقف فقط عند المعابر المعفاة أو المهجورة أو الصناعية مع وجود عامل إشارة أو ضوء أخضر."},"38":{"q":"متى يجوز للحافلة عبور جسر متحرك دون التوقف؟","options":["عندما يكون الجسر فارغاً","عندما تكون حركة المرور خفيفة","عندما يشير ضوء أخضر أو موظف إلى أن العبور آمن","عندما تكون الحافلة في موعدها"],"explanation":"يجوز للحافلة عبور جسر متحرك دون التوقف عندما يُظهر ضوء أخضر أو موظف/إشارة أن العبور آمن."},"39":{"q":"كيف تختلف قاعدة التوقف عند الجسر المتحرك عن قاعدة معبر سكة الحديد؟","options":["كلاهما يجب أن يتوقف بين 15 و50 قدماً قبله","الجسر المتحرك يتوقف ضمن 15 قدماً؛ وسكة الحديد عند 50 قدماً","كلاهما يجب أن يتوقف على بعد 50 قدماً على الأقل قبله","الجسر المتحرك يتوقف على بعد 50 قدماً على الأقل؛ وسكة الحديد بين 15 و50 قدماً"],"explanation":"عند الجسر المتحرك يجب أن تتوقف على بعد 50 قدماً على الأقل قبله، بينما عند معبر سكة الحديد يجب أن تتوقف الحافلة بين 15 و50 قدماً قبله."},"40":{"q":"أي ثلاث فئات من المواد الخطرة لا يجوز للحافلة نقلها أبداً؟","options":["متفجرات الشعبة 1.1/1.2/1.3، ومعظم المواد المشعة، والغاز/السائل السام","السوائل القابلة للاشتعال، والمواد الأكّالة، والمؤكسدات","الغازات المضغوطة، والثلج الجاف، والبطاريات","البخاخات، والطلاء، ومواد التنظيف"],"explanation":"لا يجوز للحافلة أبداً نقل متفجرات الشعبة 1.1 و1.2 و1.3، ومعظم المواد المشعة، والغاز/السائل السام."},"41":{"q":"على الحافلة، كيف يرتبط حد 100 رطل للفئة الواحدة من المواد الخطرة بالحد الإجمالي البالغ 500 رطل؟","options":["100 رطل هو الإجمالي؛ و500 رطل لكل فئة","100 رطل يحدّ أي فئة واحدة؛ و500 رطل يحدّ الإجمالي","كلا الحدين 500 رطل","كلا الحدين 100 رطل"],"explanation":"إجمالي المواد الخطرة على الحافلة محدد بـ 500 رطل، بحد أقصى 100 رطل لأي فئة واحدة مسموح بها."},"42":{"q":"ما أقصى ما يمكن للحافلة نقله من أي فئة واحدة مسموح بها من المواد الخطرة؟","options":["50 رطلاً","75 رطلاً","100 رطل","150 رطلاً"],"explanation":"لا يجوز للحافلة نقل أكثر من 100 رطل من أي فئة واحدة مسموح بها من المواد الخطرة."},"43":{"q":"لماذا يجب إبقاء المواد الخطرة المسموح بها على الحافلة بعيداً عن المكان الذي يركب فيه الناس؟","options":["لإبقاء المواد الخطرة جافة ونظيفة","لموازنة وزن الحافلة","لتسهيل الوصول إلى المواد","لحماية الركاب من المواد"],"explanation":"يجب ألا تُنقل المواد الخطرة المسموح بها أبداً في المكان الذي يشغله الناس."},"44":{"q":"ما الحالة التي تجعل إعادة التزود بالوقود للحافلة داخل مبنى مغلق محظوراً؟","options":["وجود ركاب على متن الحافلة","استمرار عمل المحرك","تشغيل المصابيح الأمامية","تشغيل المدفأة"],"explanation":"لا تعد التزود بالوقود للحافلة أبداً والركاب على متنها داخل مبنى مغلق أو مسوَّر."},"45":{"q":"أثناء سير الحافلة، ما الذي يجب على السائق تجنبه؟","options":["مراقبة المرايا","أي شيء يصرف الانتباه عن القيادة","الكبح بسلاسة عند التوقف","التحقق من الطريق أمامه"],"explanation":"أثناء سير الحافلة، تجنب أي شيء يصرف انتباهك عن القيادة."},"46":{"q":"أي قاعدة يجب على سائق الحافلة فرضها على متن الحافلة؟","options":["قاعدة منع الأكل","قاعدة منع التحدث","قاعدة منع التدخين","قاعدة منع الوقوف"],"explanation":"يجب على سائق الحافلة فرض قواعد منع التدخين على متن الحافلة."},"47":{"q":"لماذا ينبغي تفعيل فرملة الانتظار قبل أن يتحرك الركاب عند محطة استراحة؟","options":["لتوفير الوقود أثناء التشغيل في وضع الخمول","لتبريد المحرك بشكل أسرع","للإشارة إلى وقت المغادرة التالي","لإبقاء الحافلة مؤمَّنة في مكانها"],"explanation":"عند محطات الاستراحة، فعّل فرملة الانتظار لإبقاء الحافلة مؤمَّنة قبل أن يتحرك الركاب."},"48":{"q":"ما الذي يجب على سائق الحافلة فحصه قبل القيادة للتأكد من قدرة الركاب على الخروج في حالة الطوارئ؟","options":["أن مخارج الطوارئ تعمل","أن جهاز الراديو يعمل","أن المدفأة تعمل","أن المقاعد تميل للخلف"],"explanation":"افحص الحافلة قبل الرحلة للتأكد من أن مخارج الطوارئ تعمل."},"49":{"q":"يجب تأمين الأمتعة المحمولة باليد على الحافلة بحيث لا تتمكن من فعل ماذا بشخص؟","options":["السقوط على أحد","أن تُعدّ","أن تُفتَّش","أن تُوزَن"],"explanation":"يجب تأمين الأمتعة المحمولة باليد بحيث لا تسقط على أحد."},"50":{"q":"الركاب الواقفون أمام خط الواقفين يجب ألا يحجبوا رؤية من؟","options":["رؤية السائق","رؤية أحد الركاب","رؤية المرسِل","رؤية المفتش"],"explanation":"لا تسمح للركاب بالوقوف أمام خط الواقفين أو حجب رؤية السائق."},"51":{"q":"ماذا يمكن أن يفعل التوقف المفاجئ بالركاب الواقفين في الحافلة؟","options":["يقذفهم","يجلسهم","يهدّئهم","يعدّهم"],"explanation":"يمكن أن يؤدي التوقف المفاجئ إلى قذف الركاب الواقفين."},"52":{"q":"يجب أن تتوقف الحافلة على مسافة لا تقل عن كم قدمًا قبل مزلقان السكة الحديدية؟","options":["15 قدمًا","5 أقدام","25 قدمًا","75 قدمًا"],"explanation":"يجب أن تتوقف الحافلة على مسافة تتراوح بين 15 و50 قدمًا قبل مزلقان السكة الحديدية."},"53":{"q":"عند مزلقان السكة الحديدية، ماذا يجب على سائق الحافلة أن يفعل بالإضافة إلى التوقف؟","options":["أن ينظر ويستمع","أن يطلق البوق ويمضي","أن يبدّل التروس","أن يفتح الباب"],"explanation":"عند مزلقان السكة الحديدية يجب على السائق أن يتوقف وينظر ويستمع."},"54":{"q":"عند مزلقان السكة الحديدية مع وجود عامل تنظيم مرور أو إشارة خضراء، ماذا يجوز للحافلة أن تفعل؟","options":["المتابعة دون توقف","التوقف دائمًا","الرجوع للخلف أولاً","إطلاق البوق ثلاث مرات"],"explanation":"لا يلزم أن تتوقف الحافلة عند المزلقانات المعفاة أو المهجورة أو الصناعية إذا وُجد عامل تنظيم مرور أو إشارة خضراء."},"55":{"q":"عند جسر متحرك لا توجد به إشارة خضراء أو ما يدل على أن العبور آمن، على أي مسافة قبله يجب أن تتوقف الحافلة؟","options":["50 قدمًا على الأقل","10 أقدام على الأقل","25 قدمًا على الأقل","75 قدمًا على الأقل"],"explanation":"عند الجسر المتحرك يجب أن تتوقف الحافلة على مسافة لا تقل عن 50 قدمًا قبله."},"56":{"q":"متى يجوز للحافلة عبور جسر متحرك دون توقف؟","options":["عند وجود إشارة خضراء","عند وجود إشارة حمراء","عند وجود إشارة صفراء وامضة","عند عدم وجود أي إشارة على الإطلاق"],"explanation":"لا يلزم أن تتوقف الحافلة عند الجسر المتحرك إذا وُجدت إشارة خضراء."},"57":{"q":"أي فئة من المتفجرات لا يجوز للحافلة أن تنقلها أبدًا؟","options":["متفجرات الفئة 1.1","متفجرات الفئة 4.1","متفجرات الفئة 5.2","متفجرات الفئة 9"],"explanation":"لا يجوز للحافلة أن تنقل أبدًا متفجرات الفئات 1.1 و1.2 و1.3."},"58":{"q":"يُمنع على الحافلة نقل معظم أي نوع من المواد؟","options":["المواد المشعة","المواد الصلبة القابلة للاشتعال","المواد المسببة للتآكل","المواد المؤكسِدة"],"explanation":"لا يجوز للحافلة أن تنقل أبدًا معظم المواد المشعة."},"59":{"q":"ما أقصى إجمالي للمواد الخطرة التي يجوز للحافلة أن تنقلها؟","options":["500 رطل","250 رطلاً","750 رطلاً","1000 رطل"],"explanation":"يجب ألا يتجاوز إجمالي المواد الخطرة في الحافلة 500 رطل."},"60":{"q":"المواد الخطرة المسموح بها في الحافلة يجب ألا تُنقل أبدًا في الحيّز الذي يشغله ماذا؟","options":["الناس","الأدوات","الوقود","الإطارات"],"explanation":"يجب ألا تُنقل المواد الخطرة المسموح بها أبدًا في الحيّز الذي يشغله الناس."},"61":{"q":"يجب ألا تتزود الحافلة بالوقود وعلى متنها ركاب داخل أي نوع من المباني؟","options":["مبنى مغلق","مبنى جديد","مبنى خشبي","مبنى كبير"],"explanation":"لا تتزود الحافلة بالوقود أبدًا وعلى متنها ركاب داخل مبنى مغلق."},"62":{"q":"أثناء سير الحافلة، ما الذي ينبغي ألا يفعله السائق؟","options":["التحدث إلى الركاب","مراقبة الطريق","الإمساك بالمقود","فحص المرايا"],"explanation":"لا تتحدث إلى الركاب أثناء سير الحافلة."},"63":{"q":"ما القاعدة التي يجب على سائق الحافلة أن يفرضها داخل الحافلة؟","options":["قواعد عدم التدخين","قواعد عدم التحدث","قواعد عدم الوقوف","قواعد عدم الجلوس"],"explanation":"يجب على السائق أن يفرض قواعد عدم التدخين."},"64":{"q":"عند محطات الاستراحة والتوقفات الوسيطة، ما الذي ينبغي أن يراقبه السائق لدى الركاب؟","options":["النزول إلى وسط حركة المرور","ترك الأمتعة","النوم","تناول الطعام"],"explanation":"عند محطات الاستراحة راقب الركاب الذين ينزلون إلى وسط حركة المرور."},"65":{"q":"عند محطات الاستراحة، ما الذي يجب تفعيله في الحافلة قبل أن يتحرك الركاب؟","options":["فرامل الانتظار","مثبّت السرعة","أضواء الطوارئ الوامضة","مستوى صوت الراديو"],"explanation":"أبقِ الحافلة مؤمَّنة بتفعيل فرامل الانتظار قبل أن يتحرك الركاب."},"66":{"q":"أثناء الفحص قبل الرحلة، يجب أن يكون الممر وجميع المخارج خالية من ماذا؟","options":["الأمتعة","الركاب","الغبار","اللافتات"],"explanation":"تأكد من أن الممر وجميع المخارج خالية من الأمتعة."},"67":{"q":"كيف ينبغي لسائق الحافلة أن يستخدم الفرامل لحماية الركاب الواقفين؟","options":["بسلاسة","بشكل مفاجئ","متأخرًا","بقوة"],"explanation":"استخدم الفرامل بسلاسة لحماية الركاب الواقفين."}},"learn-schoolbus":{"0":{"q":"إلى أي مسافة تمتد منطقة الخطر حول الحافلة؟","options":["10 أقدام","5 أقدام","15 قدمًا","50 قدمًا"],"explanation":"منطقة الخطر هي المساحة المحيطة بالحافلة من جميع الجهات، وتمتد نحو 10 أقدام، حيث يكون الأطفال في أشد حالات الخطر."},"1":{"q":"إلى أي مسافة تمتد منطقة الخطر من مقدمة الحافلة وجوانبها ومؤخرتها؟","options":["5 أقدام","10 أقدام","15 قدمًا","30 قدمًا"],"explanation":"تمتد منطقة الخطر نحو 10 أقدام من مقدمة الحافلة وجوانبها ومؤخرتها."},"2":{"q":"إلى أي مسافة يمكن أن تصل منطقة الخطر أمام الحافلة؟","options":["حتى 10 أقدام","حتى 20 قدمًا","حتى 30 قدمًا","حتى 50 قدمًا"],"explanation":"يمكن أن تصل منطقة الخطر إلى مسافة 30 قدمًا أمام الحافلة."},"3":{"q":"أي مناطق من منطقة الخطر هي الأكثر خطورة؟","options":["الجانب الأيسر والمقدمة","المؤخرة والجانب الأيسر","خلف الحافلة فقط","المقدمة والجانب الأيمن/المؤخرة"],"explanation":"أكثر المناطق خطورة هي المنطقة مباشرة أمام الحافلة والجانب الأيمن/المؤخرة."},"4":{"q":"أي المرايا تساعدك على رؤية مناطق الخطر الأمامية والجانبية؟","options":["المسطحة والمحدبة ومرايا العبور","المسطحة والمحدبة فقط","مرآة الرؤية الخلفية والجانبية","المحدبة ومرآة الرؤية الخلفية"],"explanation":"استخدم المرايا الخارجية المسطحة والمحدبة ومرايا العبور لمراقبة مناطق الخطر الأمامية والجانبية."},"5":{"q":"متى ينبغي أن تضبط مرايا الحافلة المدرسية؟","options":["مرة في الأسبوع","قبل كل رحلة","بعد كل رحلة","مرة في الشهر"],"explanation":"اضبط المرايا الخارجية ومرايا العبور قبل كل رحلة لإبقاء كل طالب ضمن مجال الرؤية."},"6":{"q":"ما الجزء الأكثر خطورة في عمل سائق الحافلة المدرسية؟","options":["الرجوع للخلف","مزلقانات السكك الحديدية","الصعود والنزول","القيادة على الطرق السريعة"],"explanation":"الصعود والنزول هو الجزء الأكثر خطورة في العمل، إذ تقع معظم الوفيات عند صعود الطلاب أو نزولهم."},"7":{"q":"متى يُرجَّح أن تقع معظم وفيات الحافلات المدرسية؟","options":["أثناء الرجوع للخلف","عند مزلقانات السكك الحديدية","أثناء القيادة على الطرق السريعة","أثناء الصعود أو النزول"],"explanation":"تقع معظم وفيات الحافلات المدرسية أثناء الصعود أو النزول، حين يُصدَم الطلاب بحافلتهم نفسها أو بالسيارات المارّة."},"8":{"q":"كم قدماً قبل التوقف يجب أن تُشغّل أضواء التحذير الكهرمانية (الصفراء)؟","options":["من 100 إلى 300 قدم","من 10 إلى 30 قدماً","من 15 إلى 50 قدماً","من 300 إلى 500 قدم"],"explanation":"شغّل أضواء التحذير الكهرمانية على بُعد نحو 100 إلى 300 قدم قبل التوقف، حسب السرعة وحالة الطريق."},"9":{"q":"عند التوقف لتحميل الطلاب أو إنزالهم، أي الأضواء تُضاء؟","options":["أضواء التحذير الكهرمانية","الأضواء الحمراء الوامضة","أضواء الخطر فقط","المصابيح الأمامية والأضواء العالية"],"explanation":"عند التوقف للتحميل أو الإنزال، تُضاء الأضواء الحمراء الوامضة ويخرج ذراع التوقف."},"10":{"q":"على بُعد كم قدماً تقريباً أمام الحافلة يجب أن يعبر الطلاب؟","options":["5 أقدام","30 قدماً","10 أقدام","15 قدماً"],"explanation":"ينبغي أن يعبر الطلاب على بُعد نحو 10 أقدام أمام الحافلة، خارج منطقة الخطر، حتى يمكنك رؤيتهم."},"11":{"q":"على أي بُعد أمام الحافلة يجب أن يعبر الطلاب؟","options":["قدم واحدة أمام الحافلة","3 أقدام أمام الحافلة","5 أقدام أمام الحافلة","10 أقدام أمام الحافلة"],"explanation":"ينبغي أن يعبر الطلاب على بُعد نحو 10 أقدام أمام الحافلة، حيث يمكنك رؤيتهم، وألا يمشوا خلفها أبداً."},"12":{"q":"ماذا ينبغي أن تفعل أثناء صعود الطلاب إلى الحافلة ونزولهم منها؟","options":["عُدّ الطلاب","انفخ البوق","افتح النوافذ","اقرع الجرس"],"explanation":"عُدّ الطلاب أثناء صعودهم إلى الحافلة ونزولهم منها، فهو أخطر الأوقات."},"13":{"q":"إذا اختفى طالب عن نظرك، فماذا ينبغي أن تفعل قبل تحريك الحافلة؟","options":["انفخ البوق","ثبّت الحافلة وابحث عنه","انتظر 30 ثانية","اسأل طالباً آخر"],"explanation":"إذا اختفى طالب عن نظرك، فثبّت الحافلة وابحث عنه قبل تحريكها."},"14":{"q":"عند مزلقان السكة الحديدية، على أي بُعد قبل القضبان يجب أن تتوقف؟","options":["من 5 إلى 15 قدماً","من 10 إلى 30 قدماً","من 15 إلى 50 قدماً","من 50 إلى 100 قدم"],"explanation":"عند مزلقان السكة الحديدية، توقّف على بُعد يتراوح بين 15 و50 قدماً قبل القضبان."},"15":{"q":"عند مزلقان السكة الحديدية، ماذا ينبغي أن تفتح قبل العبور؟","options":["كلتا النافذتين الجانبيتين","باب الطوارئ الخلفي","جميع نوافذ الركاب","باب الخدمة ونافذة السائق"],"explanation":"عند مزلقان السكة الحديدية، افتح باب الخدمة ونافذة السائق لتنظر وتستمع."},"16":{"q":"عند مزلقان السكة الحديدية، ماذا يجب على سائق الحافلة المدرسية أن يفعل قبل العبور؟","options":["ينظر ويستمع","ينفخ البوق","يومض بالأضواء","يُسرع بسرعة"],"explanation":"عند مزلقان السكة الحديدية، توقّف وانظر واستمع لقدوم القطارات قبل عبور القضبان."},"17":{"q":"كيف ينبغي أن تعبر الحافلة المدرسية قضبان السكة الحديدية؟","options":["بسرعة عالية مع تبديل التروس","بسرعة منخفضة دون تبديل التروس","في وضع التعشيق المحايد مع الانزلاق","بسرعة منخفضة مع تبديل التروس"],"explanation":"اعبر قضبان السكة الحديدية بسرعة منخفضة دون تبديل التروس أثناء وجودك على القضبان."},"18":{"q":"متى يجب على الحافلة المدرسية أن تتوقف عند مزلقان السكة الحديدية؟","options":["فقط عندما تكون محمّلة","فقط عندما تكون فارغة","سواء كانت محمّلة أم لا","فقط في الليل"],"explanation":"يجب على الحافلة المدرسية أن تتوقف عند مزلقانات السكة الحديدية سواء كانت محمّلة أم لا."},"19":{"q":"عند قيادة حافلة مدرسية، ماذا ينبغي أن تفعل بشأن الرجوع إلى الخلف؟","options":["ارجع بسرعة","ارجع دون مراقب","ارجع في أي وقت","تجنّبه كلما أمكن"],"explanation":"تجنّب الرجوع بالحافلة المدرسية إلى الخلف كلما أمكن بسبب منطقة الخطر الخفية خلفها."},"20":{"q":"إذا اضطررت إلى الرجوع بالحافلة المدرسية إلى الخلف، فمن ينبغي أن يرشدك؟","options":["طالب مساعد أو شخص بالغ","سائق حافلة آخر","سائق سيارة عابر","لا حاجة لأحد"],"explanation":"إذا اضطررت إلى الرجوع، فاستعن بطالب مساعد أو مراقب أو شخص بالغ ليرشدك، وارجع ببطء."},"21":{"q":"قبل الرجوع بالحافلة المدرسية إلى الخلف، ماذا يجب أن تعرف عن المنطقة الخلفية؟","options":["أنها خافتة الإضاءة","أنها خالية","أنها معبّدة","أنها منحدرة"],"explanation":"لا ترجع بالحافلة إلى الخلف أبداً دون أن تعرف أن المنطقة خلفها خالية."},"22":{"q":"ماذا يجب أن يعرف كل سائق حافلة مدرسية في حال وقوع طارئ؟","options":["أبعاد الحافلة","حجم خزان الوقود","مخارج الطوارئ وإجراءات الإخلاء","قيم ضغط الإطارات"],"explanation":"يجب أن يعرف كل سائق حافلة مدرسية مخارج الطوارئ وإجراءات الإخلاء."},"23":{"q":"ماذا يجب أن تُبقي خالياً في كل الأوقات في الحافلة المدرسية؟","options":["غطاء الوقود","لوحة القيادة","رف الأمتعة","الممر"],"explanation":"أبقِ الممر خالياً دائماً حتى يتمكن الطلاب من التحرك والإخلاء بأمان في حالة الطوارئ."},"24":{"q":"ماذا يجب أن تُفعّل لتثبيت الحافلة قبل أن يتحرك الطلاب؟","options":["فرامل الانتظار","ذراع التوقف","فرامل الخدمة","الأضواء الكهرمانية"],"explanation":"فعّل دائماً فرامل الانتظار لتثبيت الحافلة قبل أن يتحرك الطلاب."},"25":{"q":"أثناء التحميل والإنزال، ما الذي يقتل الطلاب في أغلب الأحيان؟","options":["حافلتهم نفسها أو المركبات العابرة","السقوط على درجات الحافلة","الانزلاق على الأرصفة المتجمدة","الاصطدام بالدراجات الهوائية"],"explanation":"الطلاب الذين يُقتلون أثناء التحميل والإنزال يُصدمون بحافلتهم نفسها أو بالمركبات العابرة."},"26":{"q":"عند التوقف للتحميل أو الإنزال، ما الذي يُضاء مع الأضواء الحمراء الوامضة؟","options":["أضواء التحذير الكهرمانية","ذراع التوقف","ضوء القبة الداخلي","أضواء الخطر"],"explanation":"عند التوقف للتحميل أو الإنزال، يخرج ذراع التوقف بالإضافة إلى الأضواء الحمراء الوامضة."},"27":{"q":"أين ينبغي أن يمشي الطلاب بعد نزولهم من الحافلة؟","options":["بمحاذاة الجانب الأيمن","خلف الحافلة مباشرة","على بُعد نحو 10 أقدام أمام الحافلة","حيثما كان أسرع لهم"],"explanation":"ينبغي أن يعبر الطلاب على بُعد نحو 10 أقدام أمام الحافلة حيث يمكنك رؤيتهم، ولا ينبغي أن يمشوا خلف الحافلة أبداً."},"28":{"q":"إذا اضطررت إلى الرجوع بالحافلة المدرسية إلى الخلف، فكيف ينبغي أن تفعل ذلك؟","options":["بسرعة","بصوت عالٍ","بحدّة","ببطء"],"explanation":"إذا اضطررت إلى الرجوع، فارجع ببطء."},"29":{"q":"تمتد منطقة الخطر نحو 10 أقدام حول الحافلة، لكن إلى أي مدى يمكن أن تصل أمامها؟","options":["حتى 30 قدماً","حتى 10 أقدام","حتى 15 قدماً","حتى 50 قدماً"],"explanation":"تمتد منطقة الخطر نحو 10 أقدام من الأمام والجانبين والخلف، ويمكن أن تصل حتى 30 قدماً أمام الحافلة."},"30":{"q":"ماذا يعني مصطلح \"منطقة الخطر\"؟","options":["المقاعد الأقرب إلى السائق","المنطقة المحيطة بالحافلة بالكامل حيث يكون الأطفال الأكثر عرضة للخطر","الطريق خلف الحافلة عند الرجوع إلى الخلف","المساحة المخصصة لمخارج الطوارئ"],"explanation":"منطقة الخطر هي المنطقة المحيطة بالحافلة بالكامل حيث يكون الأطفال الأكثر عرضة للخطر."},"31":{"q":"أمام الحافلة المدرسية مباشرة، أي بقعة هي الأخطر؟","options":["على بُعد نحو 50 قدماً أمامها","الزاوية الأمامية اليسرى البعيدة","المنطقة الواقعة أمامها مباشرة","بعد مرايا العبور مباشرة"],"explanation":"المنطقة الواقعة أمام الحافلة مباشرة هي أخطر بقعة في المقدمة مباشرة."},"32":{"q":"أي المرايا تساعدك على رؤية منطقتي الخطر الأمامية والجانبية للحافلة؟","options":["مرآة الرؤية الخلفية الداخلية","المرآة الجانبية اليسرى المسطحة","المرآة الجانبية اليمنى المحدّبة","مرايا العبور"],"explanation":"استخدم مرايا العبور لرؤية منطقتي الخطر الأمامية والجانبية."},"33":{"q":"لماذا تستخدم مرايا الحافلة؟","options":["لإبقاء كل طالب ضمن مجال الرؤية","للتحقق من مظهرك الخاص","لتتبع سرعة المرور العابر","لقراءة لافتات الطريق القادمة"],"explanation":"استخدم المرايا لإبقاء كل طالب ضمن مجال الرؤية، واضبطها قبل كل رحلة."},"34":{"q":"تحدث معظم الوفيات المرتبطة بالحافلات المدرسية أثناء قيام الطلاب بماذا؟","options":["أثناء جلوسهم في مقاعدهم","أثناء صعودهم إلى الحافلة أو نزولهم منها","أثناء سيرهم إلى صفهم الدراسي","أثناء انتظارهم داخل المدرسة"],"explanation":"تحدث معظم الوفيات المرتبطة بالحافلات المدرسية للطلاب أثناء صعودهم أو نزولهم، إذ تصدمهم حافلتهم نفسها أو المركبات العابرة."},"35":{"q":"ما لون الأضواء التحذيرية التي تشغّلها عند اقترابك من موقف؟","options":["الأضواء الحمراء الوامضة","الأضواء التحذيرية الخضراء","الأضواء التحذيرية الكهرمانية (الصفراء)","الأضواء التحذيرية الزرقاء"],"explanation":"شغّل الأضواء التحذيرية الكهرمانية (الصفراء) على بعد نحو 100 إلى 300 قدم قبل الموقف."},"36":{"q":"ما الذي يحدد بدقة المسافة التي تشغّل عندها الأضواء التحذيرية الكهرمانية قبل الموقف؟","options":["عدد الطلاب على متن الحافلة","الوقت من اليوم","لون الحافلة","سرعتك وظروف الطريق"],"explanation":"تشغّل الأضواء التحذيرية الكهرمانية على بعد نحو 100 إلى 300 قدم قبل الموقف، وتعتمد المسافة الدقيقة على سرعتك وظروف الطريق."},"37":{"q":"لماذا ينبغي أن يعبر الطلاب على بعد نحو 10 أقدام أمام الحافلة؟","options":["لكي تتمكن من رؤيتهم ويبقوا خارج منطقة الخطر","لكي يصلوا إلى الرصيف بسرعة أكبر","لكي تتوفر مساحة لامتداد ذراع التوقف بالكامل","لكي يتوفر للسيارات العابرة وقت للتباطؤ"],"explanation":"يعبر الطلاب على بعد نحو 10 أقدام أمام الحافلة لكي يتمكن السائق من رؤيتهم ويبقوا خارج منطقة الخطر."},"38":{"q":"أين يجب ألا يسير الطالب أبدًا بالقرب من الحافلة؟","options":["على بعد نحو 10 أقدام أمامها","خلف الحافلة","على الرصيف البعيد","باتجاه أبواب المدرسة"],"explanation":"يجب ألا يسير الطالب أبدًا خلف الحافلة، حيث لا يستطيع السائق رؤيته."},"39":{"q":"لماذا تعدّ الطلاب أثناء صعودهم إلى الحافلة ونزولهم منها؟","options":["للتأكد من قائمة الحضور","لقياس مدة عملية الصعود","لمعرفة ما إذا اختفى أحدهم عن النظر","لجمع أجرة الحافلة من كل طالب"],"explanation":"تعدّ الطلاب عند صعودهم ونزولهم لكي تتمكن، إذا اختفى أحدهم عن النظر، من العثور عليه قبل التحرك."},"40":{"q":"أي الأضواء تستخدمها عند الاقتراب من موقف مقابل تلك التي تستخدمها عند التوقف للتحميل أو التنزيل؟","options":["الأضواء الحمراء الوامضة عند الاقتراب، والأضواء الكهرمانية عند التوقف","الأضواء الكهرمانية في الحالتين عند الاقتراب وعند التوقف","الأضواء الحمراء الوامضة في الحالتين عند الاقتراب وعند التوقف","الأضواء الكهرمانية عند الاقتراب، والأضواء الحمراء الوامضة عند التوقف"],"explanation":"عند الاقتراب تشغّل الأضواء التحذيرية الكهرمانية، وعند التوقف للتحميل أو التنزيل تعمل الأضواء الحمراء الوامضة وذراع التوقف."},"41":{"q":"هل يجب أن تتوقف الحافلة المدرسية الفارغة عند مزلقان السكة الحديدية؟","options":["نعم، توقف سواء كانت محمّلة أم لا","لا، توقف فقط عند نقل الطلاب","لا، توقف فقط إذا كان القطار مرئيًا","لا، أبطئ السرعة لكن لا تتوقف"],"explanation":"يجب أن تتوقف الحافلة المدرسية عند مزلقان السكة الحديدية سواء كانت الحافلة محمّلة أم لا."},"42":{"q":"أثناء عبور قضبان السكة الحديدية بحافلة مدرسية، هل يجوز لك تغيير التروس؟","options":["نعم، انقل إلى ترس أعلى للحصول على قوة","لا، لا تغيّر التروس على القضبان","نعم، انقل إلى ترس أدنى للتحكم","فقط إذا كانت الحافلة فارغة"],"explanation":"اعبر بترس منخفض دون تغيير التروس أثناء وجودك على القضبان."},"43":{"q":"عند مزلقان السكة الحديدية، لماذا تفتح باب الخدمة ونافذة السائق؟","options":["لإدخال الهواء النقي إلى الحافلة","للاطمئنان على الطلاب","للنظر والإصغاء لرصد القطارات","لإشارة السائقين الآخرين"],"explanation":"تفتح باب الخدمة ونافذة السائق للنظر والإصغاء لرصد القطارات المقتربة."},"44":{"q":"عند مزلقان السكة الحديدية، ما أقرب مسافة يجوز لك التوقف عندها من القضبان؟","options":["5 أقدام","30 قدمًا","10 أقدام","15 قدمًا"],"explanation":"يجب أن تتوقف على مسافة تتراوح بين 15 و50 قدمًا قبل القضبان."},"45":{"q":"لماذا ينبغي لسائق الحافلة المدرسية تجنّب الرجوع إلى الخلف كلما أمكن؟","options":["لأنك لا تستطيع رؤية المنطقة خلفك، حيث قد يوجد أطفال","لأن الرجوع إلى الخلف يستهلك وقودًا أكثر من القيادة إلى الأمام","لأنه يسبب تآكلًا إضافيًا لناقل حركة الحافلة","لأنه يجعل الرحلة تستغرق وقتًا أطول قليلًا"],"explanation":"تجنّب الرجوع إلى الخلف كلما أمكن، وارجع ببطء، ولا ترجع أبدًا دون التأكد من خلو المنطقة خلفك."},"46":{"q":"عندما تضطر إلى الرجوع بالحافلة إلى الخلف، ماذا يفعل الطالب المساعد أو الشخص البالغ؟","options":["يعدّ الركاب","يعمل مراقبًا لإرشادك","يغلق باب الخروج الخلفي","يشغّل ذراع التوقف"],"explanation":"يعمل الطالب المساعد أو الشخص البالغ مراقبًا لإرشادك عندما تضطر إلى الرجوع بالحافلة إلى الخلف."},"47":{"q":"متى يجب أن تشدّ فرملة الانتظار لتأمين الحافلة؟","options":["بعد أن يتحرك الطلاب","أثناء تحرك الطلاب","قبل أن يتحرك الطلاب","فقط إذا تحرك الطلاب"],"explanation":"يجب أن تؤمّن الحافلة بفرملة الانتظار قبل أن يتحرك الطلاب."},"48":{"q":"لماذا يجب إبقاء ممر الحافلة المدرسية خاليًا؟","options":["لإفساح مكان لمقاعد إضافية","لتمكين الطلاب من الجلوس بسرعة أكبر","لإبقاء الأرضية أنظف","للسماح بالإخلاء السريع في حالات الطوارئ"],"explanation":"أبقِ الممر خاليًا لكي يتمكن الطلاب من الخروج بسرعة أثناء الإخلاء الطارئ."},"49":{"q":"إلى أي مدى أمام الحافلة يمكن أن تصل منطقة الخطر؟","options":["حتى 20 قدمًا","حتى 30 قدمًا","حتى 40 قدمًا","حتى 50 قدمًا"],"explanation":"يمكن أن تصل منطقة الخطر حتى 30 قدمًا أمام الحافلة."},"50":{"q":"إلى أي مسافة تقريبًا تمتد منطقة الخطر من مؤخرة الحافلة؟","options":["نحو 10 أقدام","نحو 15 قدمًا","نحو 25 قدمًا","نحو 30 قدمًا"],"explanation":"تمتد منطقة الخطر نحو 10 أقدام من الأمام والجانبين والمؤخرة."},"51":{"q":"أي المرايا تساعدك على رؤية المنطقة الواقعة مباشرة أمام الحافلة؟","options":["مرايا الرؤية الخلفية","المرايا العرضية (الأمامية)","مرايا لوحة القيادة","المرايا الداخلية"],"explanation":"تساعدك المرايا العرضية (الأمامية) على رؤية منطقة الخطر الأمامية."},"52":{"q":"في أغلب الأحيان، الطلاب الذين يُقتلون أثناء التحميل والتنزيل يصدمهم ماذا؟","options":["حافلتهم نفسها أو المركبات العابرة","المشاة على الرصيف","الدراجات في مسار الدراجات","مركبات الاستجابة للطوارئ"],"explanation":"معظم الوفيات تكون لطلاب تصدمهم حافلتهم نفسها أو المركبات العابرة."},"53":{"q":"ما لون الأضواء التحذيرية التي تشغّلها عند اقترابك من موقف؟","options":["أحمر","كهرماني (أصفر)","أخضر","أزرق"],"explanation":"تُشغَّل الأضواء التحذيرية الكهرمانية (الصفراء) عند اقترابك من موقف."},"54":{"q":"تشغيل الأضواء التحذيرية الكهرمانية على بعد كم تقريبًا قبل الموقف يُعدّ صحيحًا؟","options":["نحو 50 إلى 100 قدم","نحو 100 إلى 300 قدم","نحو 300 إلى 500 قدم","نحو 500 إلى 700 قدم"],"explanation":"شغّل الأضواء التحذيرية الكهرمانية على بعد نحو 100 إلى 300 قدم قبل الموقف."},"55":{"q":"ما الذي يُفعّل مع الأضواء الحمراء الوامضة عند توقفك للتحميل أو التنزيل؟","options":["ذراع التوقف","أضواء الخطر الوامضة","البوق","الأضواء الكهرمانية"],"explanation":"عند التوقف للتحميل أو التنزيل، تعمل الأضواء الحمراء الوامضة وذراع التوقف."},"56":{"q":"أين ينبغي أن يعبر الطلاب لكي يتمكن السائق من رؤيتهم؟","options":["خلف الحافلة مباشرة","على بعد نحو 10 أقدام أمام الحافلة","على طول الجانب الأيسر للحافلة","حيثما يكون المرور خاليًا"],"explanation":"ينبغي أن يعبر الطلاب على بعد نحو 10 أقدام أمام الحافلة، خارج منطقة الخطر."},"57":{"q":"ما الذي يجب ألا تسمح أبدًا لطالب بفعله بالقرب من الحافلة؟","options":["السير خلف الحافلة","العبور أمام الحافلة","الانتظار على الرصيف","الصعود بعد الآخرين"],"explanation":"يجب ألا تسمح أبدًا لطالب بالسير خلف الحافلة."},"58":{"q":"ماذا يجب أن تفعل مع الطلاب في كل مرة يصعدون فيها إلى الحافلة وينزلون منها؟","options":["عدّهم","تصويرهم","مناداتهم بأسمائهم بصوت عالٍ","إجلاسهم حسب الصف الدراسي"],"explanation":"عُدّ الطلاب عند صعودهم إلى الحافلة ونزولهم منها."},"59":{"q":"عند معبر السكة الحديدية، ما هو أقرب مكان يمكن أن تتوقف فيه الحافلة المدرسية من القضبان؟","options":["10 أقدام","15 قدمًا","25 قدمًا","35 قدمًا"],"explanation":"توقف على مسافة تتراوح بين 15 و50 قدمًا قبل القضبان، لذا فإن 15 قدمًا هي الأقرب."},"60":{"q":"عند معبر السكة الحديدية، ما هو أبعد مكان يجب أن تتوقف فيه الحافلة المدرسية عن القضبان؟","options":["50 قدمًا","60 قدمًا","75 قدمًا","100 قدم"],"explanation":"توقف على مسافة تتراوح بين 15 و50 قدمًا قبل القضبان، لذا فإن 50 قدمًا هي الأبعد."},"61":{"q":"أثناء وجود الحافلة على قضبان السكة الحديدية، ما الذي يجب أن تتجنب فعله؟","options":["تغيير التروس","مراقبة المرايا","القيادة في خط مستقيم","إبقاء الباب مغلقًا"],"explanation":"اعبر القضبان بترس منخفض دون تغيير التروس أثناء وجودك على القضبان."},"62":{"q":"بأي ترس يجب أن تعبر الحافلة المدرسية قضبان السكة الحديدية؟","options":["ترس مرتفع","ترس منخفض","الوضع المحايد","الرجوع للخلف"],"explanation":"اعبر القضبان بترس منخفض دون تغيير التروس."},"63":{"q":"بالإضافة إلى نافذة السائق، ما الذي يجب أن تفتحه عند معبر السكة الحديدية؟","options":["باب الخدمة","فتحة الطوارئ","المخرج الخلفي","غطاء المحرك"],"explanation":"افتح باب الخدمة ونافذة السائق عند معبر السكة الحديدية."},"64":{"q":"بعد فتح الباب والنافذة عند المعبر، ماذا يجب أن تفعل قبل العبور؟","options":["انظر وأنصت","أطلق البوق","عُدّ الطلاب","اضبط المؤقت"],"explanation":"انظر وأنصت قبل عبور القضبان."},"65":{"q":"ما هي الممارسة الأفضل فيما يتعلق بالرجوع للخلف بالحافلة المدرسية؟","options":["تجنبه كلما أمكن ذلك","الرجوع للخلف بالسرعة المعتادة","الرجوع للخلف دون مراقب","الرجوع للخلف على الطرق السريعة فقط"],"explanation":"تجنب الرجوع للخلف بالحافلة كلما أمكن ذلك."},"66":{"q":"إذا اضطررت إلى الرجوع للخلف بالحافلة، كيف يجب أن تفعل ذلك؟","options":["بسرعة لإخلاء حركة المرور","ببطء مع وجود مرشد","دون النظر للخلف","باستخدام البوق فقط"],"explanation":"إذا اضطررت إلى الرجوع للخلف، فاستعن بمراقب وتراجع ببطء."},"67":{"q":"من يمكنه أن يعمل كمراقب عندما تضطر إلى الرجوع للخلف بالحافلة؟","options":["طالب مساعد أو شخص بالغ","ضابط شرطة فقط","سائق حافلة آخر فقط","ميكانيكي فقط"],"explanation":"استعن بطالب مساعد أو شخص بالغ لإرشادك عند الرجوع للخلف."},"68":{"q":"قبل الرجوع للخلف، ما الذي يجب أن يكون صحيحًا بشأن المنطقة خلف الحافلة؟","options":["يجب أن تكون خالية","يجب أن تكون معبّدة","يجب أن تكون منحدرة","يجب أن تكون محددة بعلامات"],"explanation":"لا تتراجع للخلف أبدًا دون التأكد من أن المنطقة خلفك خالية."}}};
